  function cerrarOpsDetalleOverlay(ev) {
    if (ev && ev.target && ev.target.id !== 'almOpsDetalleOverlay') return;
    const overlay = $('almOpsDetalleOverlay');
    if (overlay) {
      overlay.classList.add('hidden');
      overlay.classList.remove('is-costos-mode'); // [v2.43.12] limpiar look slate
    }
    S._opsExpanded = {};
    S._opsModoCostos = false;
    S._opsOverlayKey = null;
  }

  // [v41.22] Selector de impresora para reporte de costos de guía.
  // Reusa listarImpresorasPN (mismo endpoint del modal liq) pero con
  // un modal propio chico y un handler distinto.
  S._opsImpCtx = S._opsImpCtx || null;

  // [v2.41.82] Selector de impresora para costos de guía — DELEGA al
  // PrinterPicker universal. Antes era un modal aparte con render propio
  // de estado simple (online/offline). Ahora usa el componente unificado
  // con 12 estados granulares + verify on-click + filtro por zona.
  async function abrirSelPrinterCostos(fuente, idGuia) {
    _opsBeep('tac');
    S._opsImpCtx = { fuente, idGuia, formato: null };
    const printerId = await abrirPrinterPicker({
      titulo:    '🖨 Imprimir costos de guía',
      subtitulo: idGuia + ' · costos de proveedor',
      filtroTipo: 'TICKET',
      flowKey:   'costos'   // [v2.43.3] recordar última impresora
    });
    if (printerId) {
      await _opsEnviarPrintCostos(printerId, null);
    } else {
      S._opsImpCtx = null;
    }
  }

  // [v2.42.07] Ticket profesional "para la jefa" con cuadros, AUTO/DECIDIR/
  // REVISAR. Reusa picker de impresora — pasa formato='jefa' en el payload.
  // ════════════════════════════════════════════════════════════
  // [v2.42.07] OCR comprobante proveedor → pre-puebla costos
  // ──────────────────────────────────────────────────────────
  // Paso 2-3 del flow: el admin tiene la guía abierta en modo costos
  // y aprieta este botón. El sistema llama a Claude OCR (vía bridge a
  // WH) sobre la foto del comprobante ya subida, obtiene items línea
  // por línea con confidence, hace fuzzy-match con las líneas de la
  // guía actual, y pre-puebla los inputs de costo. Reduce ~90% el
  // tipeo del admin. Si algo no calza, el admin corrige a mano.
  // ════════════════════════════════════════════════════════════
  function _opsFuzzyScore(a, b) {
    // Score simple basado en palabras en común (Jaccard, ignora <3 chars)
    const wa = new Set(String(a || '').toLowerCase().split(/\s+/).filter(w => w.length >= 3));
    const wb = new Set(String(b || '').toLowerCase().split(/\s+/).filter(w => w.length >= 3));
    if (wa.size === 0 || wb.size === 0) return 0;
    let common = 0;
    wa.forEach(w => { if (wb.has(w)) common++; });
    const union = new Set([...wa, ...wb]).size;
    return common / union;
  }

  async function opsOcrComprobantePrepoblar(idGuia) {
    if (!S._costosGuiaState || S._costosGuiaState.idGuia !== idGuia) {
      toast('Abre primero el modo costos de esta guía', 'warning');
      return;
    }
    if (S._opsOcrEnVuelo) {
      toast('Ya hay un OCR en proceso · esperá', 'warning');
      return;
    }
    S._opsOcrEnVuelo = true;
    // [v2.43.20] Marcar EN VUELO en map por guía (el flag global S._opsOcrEnVuelo
    // sigue funcionando, pero el chip del render usa este map).
    S._opsOcrEnVueloMap = S._opsOcrEnVueloMap || {};
    S._opsOcrEnVueloMap[idGuia] = true;
    // Forzar update del chip al estado "Leyendo IA..." (por si el render
    // anterior fue antes de marcar el flag)
    _opsActualizarChipOcr(idGuia);
    _opsBeep('tac');
    toast('🤖 Procesando OCR del comprobante... 5-15s', 'info', 15000);
    try {
      const r = await API.post('ocrComprobanteGuia', { idGuia });
      const d = (r && r.data) || r || {};
      const items = d.items || [];
      if (!items.length) {
        toast('⚠ OCR no detectó items en la foto del comprobante', 'warning', 6000);
        return;
      }
      const lineas = S._costosGuiaState.lineas;
      const usados = new Set();
      let aplicados = 0, dudosos = 0, sinMatch = 0;
      // Por cada item OCR busca la mejor línea de la guía por fuzzy
      items.forEach(it => {
        let bestIdx = -1, bestScore = 0;
        lineas.forEach((l, idx) => {
          if (usados.has(idx)) return;
          const s = _opsFuzzyScore(it.descripcion, l.descripcion || '');
          if (s > bestScore) { bestScore = s; bestIdx = idx; }
        });
        if (bestIdx < 0 || bestScore < 0.30) { sinMatch++; return; }
        // Subtotal preferido si existe; si no, cantidad × precioUnit
        const subt = it.subtotal > 0 ? it.subtotal : (it.precioUnitario || 0) * (it.cantidad || 1);
        // Si la línea ya tiene un valor ingresado, NO sobrescribir
        if (parseFloat(lineas[bestIdx].inputValue) > 0) return;
        lineas[bestIdx].inputValue = +subt.toFixed(2);
        lineas[bestIdx]._ocrConfidence = it.confidence;
        usados.add(bestIdx);
        if (it.confidence >= 80) aplicados++; else dudosos++;
      });
      // Re-render del panel para mostrar valores nuevos
      try { almRenderOps(); } catch(_) {}
      const total = items.length;
      const msg = `🤖 OCR: ${aplicados} ✓ · ${dudosos} ⚠ · ${sinMatch} sin match (${total} items detectados)`;
      toast(msg, aplicados > 0 ? 'success' : 'warning', 9000);
      try { _opsBeep(aplicados > 0 ? 'cliclic' : 'tac'); } catch(_) {}
    } catch(e) {
      toast('⚠ Error OCR comprobante: ' + (e.message || e), 'error', 8000);
    } finally {
      // [v2.43.20/21] SIEMPRE limpiar flag en vuelo + actualizar chip directo +
      // re-render del modal de costos unificado si está abierto para esta guía.
      S._opsOcrEnVuelo = false;
      if (S._opsOcrEnVueloMap) S._opsOcrEnVueloMap[idGuia] = false;
      S._opsOcrYaCorrido = S._opsOcrYaCorrido || {};
      S._opsOcrYaCorrido[idGuia] = true;
      _opsActualizarChipOcr(idGuia);
      // [v2.43.21] Re-render del modal unificado si activo en esta guía
      try {
        const modal = document.getElementById('modalCostosGuiaUnif');
        if (modal && !modal.classList.contains('hidden')
            && S._costosGuiaState && S._costosGuiaState.idGuia === idGuia) {
          const op = _findOpByKey(S._costosGuiaState.fuente + '_' + idGuia);
          if (op) _renderModalCostosCompleto(op);
        }
      } catch(_){}
      // Por compat (overlay viejo si está abierto)
      try { _opsRefreshOverlayIfMatches('WH_' + idGuia); } catch(_) {}
    }
  }

  // [v2.43.20] Update DIRECTO del chip "Leyendo IA"/"OCR procesado" por ID
  // estable. No depende de re-renderizar todo el voucher. Si el chip no existe
  // (overlay cerrado o de otra guía), no-op.
  function _opsActualizarChipOcr(idGuia) {
    const chip = document.getElementById('opsChipOcrStatus');
    if (!chip) return;
    // Solo si estamos en esta guía (S._costosGuiaState)
    if (!S._costosGuiaState || S._costosGuiaState.idGuia !== idGuia) return;
    const st = S._costosGuiaState;
    const tieneFoto = !!(st.foto && String(st.foto).trim());
    const enVuelo = !!(S._opsOcrEnVueloMap && S._opsOcrEnVueloMap[idGuia]);
    const yaCorrio = !!(S._opsOcrYaCorrido && S._opsOcrYaCorrido[idGuia]);
    const totalLineas = (st.lineas || []).length;
    const conCosto = (st.lineas || []).filter(l => parseFloat(l.precioUnitario) > 0 || (l.inputValue !== '' && l.inputValue != null && parseFloat(l.inputValue) > 0)).length;
    const pct = totalLineas > 0 ? Math.round((conCosto / totalLineas) * 100) : 0;
    if (!tieneFoto) {
      chip.outerHTML = `<div id="opsChipOcrStatus" style="display:inline-flex;align-items:center;gap:6px;padding:5px 10px;background:rgba(107,114,128,.15);border:1px solid rgba(107,114,128,.3);border-radius:999px;font-size:11px;color:#9ca3af;font-weight:600;margin-bottom:8px">📷 Sin foto · escribe los costos manual abajo</div>`;
      return;
    }
    if (enVuelo) {
      chip.outerHTML = `<div id="opsChipOcrStatus" style="display:inline-flex;align-items:center;gap:6px;padding:5px 10px;background:rgba(34,211,238,.15);border:1px solid rgba(34,211,238,.4);border-radius:999px;font-size:11px;color:#22d3ee;font-weight:600;margin-bottom:8px"><span style="animation:opsSpin 1s linear infinite;display:inline-block">🤖</span> Leyendo foto con IA...</div>`;
      return;
    }
    const color = pct >= 80 ? '#34d399' : pct >= 50 ? '#fbbf24' : '#f87171';
    const bg    = pct >= 80 ? 'rgba(52,211,153,.15)' : pct >= 50 ? 'rgba(251,191,36,.15)' : 'rgba(248,113,113,.15)';
    const bd    = pct >= 80 ? 'rgba(52,211,153,.45)' : pct >= 50 ? 'rgba(251,191,36,.45)' : 'rgba(248,113,113,.45)';
    chip.outerHTML = `<div id="opsChipOcrStatus" style="display:inline-flex;align-items:center;gap:6px;padding:5px 10px;background:${bg};border:1px solid ${bd};border-radius:999px;font-size:11px;color:${color};font-weight:700;margin-bottom:8px">
      🤖 ${yaCorrio ? 'OCR procesado' : 'Sin OCR'} · ${conCosto}/${totalLineas} ítems (${pct}% coincidencia)
      <button onclick="MOS.opsOcrComprobantePrepoblar('${idGuia}')" title="${yaCorrio ? 'Re-procesar foto' : 'Procesar foto'}" style="background:transparent;border:0;cursor:pointer;color:${color};font-size:11px;padding:0 0 0 4px;opacity:.7">🔄</button>
    </div>`;
  }

  // [v2.43.18] Re-renderiza el body del overlay de detalle si está abierto
  // para la guía indicada. Si está cerrado o es de otra guía, no-op.
  function _opsRerenderOverlayDetalle(idGuia) {
    const overlay = document.getElementById('almOpsDetalleOverlay');
    if (!overlay || overlay.classList.contains('hidden')) return;
    if (!S._opsOverlayKey || !String(S._opsOverlayKey).endsWith('_' + idGuia)) return;
    const cont = document.getElementById('almOpsDetalleContent');
    if (!cont) return;
    const op = _findOpByKey(S._opsOverlayKey.replace('_PRE', ''));
    if (!op) return;
    cont.innerHTML = _renderVoucher(op, 0);
  }

  async function abrirSelPrinterJefa(fuente, idGuia) {
    _opsBeep('tac');
    S._opsImpCtx = { fuente, idGuia, formato: 'jefa' };
    const printerId = await abrirPrinterPicker({
      titulo:    '🖨 Imprimir reporte para jefa',
      subtitulo: idGuia + ' · cuadros para decidir costos/precios',
      filtroTipo: 'TICKET',
      flowKey:   'jefa'   // [v2.43.3] recordar última impresora de este flow
    });
    if (printerId) {
      await _opsEnviarPrintCostos(printerId, null);
    } else {
      S._opsImpCtx = null;
    }
  }

  // ════════════════════════════════════════════════════════════
  // [v2.42.07] MODAL "Aplicar respuesta jefa"
  // ──────────────────────────────────────────────────────────
  // Paso 6-9 del flow: admin sube foto del ticket lleno por la jefa,
  // OCR Claude extrae los cambios, modal muestra resultados con
  // confidence híbrido (auto-aplica si TODO ≥95, muestra dudosos si
  // 80-95, modal completo si <80). Admin confirma con PIN admin, se
  // actualiza catálogo + propaga a presentaciones + imprime ticket de
  // confirmación.
  // ════════════════════════════════════════════════════════════
  const _opsJefaState = {
    idGuia: null,
    contexto: [],          // [{skuBase, descripcion, costo, ventaActual, margenActualPct}]
    correcciones: [],      // resultado del OCR + edición manual del admin
    confidenceGlobal: 0,
    procesando: false
  };

  // [v2.43.19] Revalidación silenciosa del contexto (no toca la UI a menos que
  // detecte cambios). Se usa cuando ya servimos cache stale.
  async function _opsJefaRevalidarContextoBg(idGuia) {
    try {
      const r = await API.post('getContextoTicketJefa', { idGuia });
      const items = (r && r.items) || (r && r.data && r.data.items) || [];
      if (!items.length) return;
      const prevHash = JSON.stringify((_opsJefaState.contexto || []).map(c => c.skuBase + '|' + c.costo));
      const newHash  = JSON.stringify(items.map(c => c.skuBase + '|' + c.costo));
      S._opsJefaContextoCache = S._opsJefaContextoCache || {};
      S._opsJefaContextoCache[idGuia] = { items, ts: Date.now() };
      // Solo re-render si cambió Y todavía estamos en esa guía Y modal abierto
      if (prevHash !== newHash
          && _opsJefaState.idGuia === idGuia
          && !document.getElementById('modalAplicarRespuestaJefa')?.classList.contains('hidden')) {
        _opsJefaState.contexto = items;
        // Si admin no tocó nada, refrescar. Si ya editó, no pisar.
        const algoEditado = (_opsJefaState.correcciones || []).some(c => c.editado || c.opcion !== 'A');
        if (!algoEditado) {
          _opsJefaState.correcciones = [];
          _opsJefaRenderBody();
          try { toast('✓ Contexto actualizado', 'info', 2000); } catch(_){}
        }
      }
    } catch(_) { /* silencioso — es bg */ }
  }

  // [v2.43.19] PRECARGA: al expandir un voucher en la lista de ops, dispara
  // fetch de contexto en background. Si el admin tap "Actualizar precios"
  // después, el modal abre instantáneo desde cache.
  function _opsJefaPrecargarContexto(idGuia) {
    if (!idGuia) return;
    S._opsJefaContextoCache = S._opsJefaContextoCache || {};
    const cached = S._opsJefaContextoCache[idGuia];
    if (cached && (Date.now() - cached.ts < 300000)) return; // ya hay cache reciente
    // Fire-and-forget — no esperamos respuesta, solo poblamos cache
    API.post('getContextoTicketJefa', { idGuia })
      .then(r => {
        const items = (r && r.items) || (r && r.data && r.data.items) || [];
        if (items.length) {
          S._opsJefaContextoCache[idGuia] = { items, ts: Date.now() };
        }
      })
      .catch(() => { /* silencioso */ });
  }

  async function opsAbrirAplicarRespuestaJefa(idGuia) {
    _opsBeep('tac');
    _opsJefaState.idGuia = idGuia;
    _opsJefaState.contexto = [];
    _opsJefaState.correcciones = [];
    _opsJefaState.confidenceGlobal = 0;
    _opsJefaState.modoOrigen = 'manual';  // [v2.43.15] manual es DEFAULT siempre
    _opsJefaState.ocrCorrido = false;
    _opsJefaState.procesando = false;
    _opsJefaState.cargandoContexto = true;  // [v2.43.17] flag race-condition
    // [v2.43.17] Modal UNIFICADO con 3 vías de input OCR (cámara/archivo/
    // drag-drop + paste), y spinner mientras carga contexto inicial.
    let modal = document.getElementById('modalAplicarRespuestaJefa');
    if (!modal) {
      modal = document.createElement('div');
      modal.id = 'modalAplicarRespuestaJefa';
      modal.className = 'fixed inset-0 z-[1100] bg-black/70 backdrop-blur-md flex items-center justify-center p-4 hidden';
      modal.innerHTML = `
        <div class="bg-slate-900 border-2 border-emerald-500/50 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] flex flex-col">
          <div class="flex items-center gap-3 px-5 py-4 border-b border-slate-700/60">
            <span class="text-2xl">🏷</span>
            <div class="flex-1 min-w-0">
              <div class="font-black text-emerald-300">Actualizar precios</div>
              <div class="text-xs text-slate-400" id="opsJefaSubtitle">Guía: —</div>
            </div>
            <button onclick="MOS.opsCerrarAplicarRespuestaJefa()" class="w-9 h-9 rounded-full bg-slate-800 hover:bg-rose-500/40 transition-all text-slate-300">✕</button>
          </div>
          <!-- Botón OCR opcional arriba (cámara/archivo/drop/paste) -->
          <div class="px-5 pt-4 pb-3 border-b border-slate-800">
            <!-- 2 inputs ocultos: uno con cámara, otro libre -->
            <input type="file" id="opsJefaFotoCam"  accept="image/*" capture="environment" class="hidden">
            <input type="file" id="opsJefaFotoFile" accept="image/*" class="hidden">
            <div id="opsJefaCardsOrigen"></div>
          </div>
          <div class="px-5 py-4 overflow-y-auto flex-1" id="opsJefaBody"></div>
        </div>`;
      document.body.appendChild(modal);
      modal.querySelector('#opsJefaFotoCam').addEventListener('change', _opsJefaOnFotoSelected);
      modal.querySelector('#opsJefaFotoFile').addEventListener('change', _opsJefaOnFotoSelected);
      // [v2.43.17] Paste clipboard image (Ctrl+V cuando el modal está abierto)
      modal.addEventListener('paste', _opsJefaOnPaste);
      // [v2.43.17] Drag & drop sobre TODO el modal (no solo el botón) — UX
      // generosa: tirar la foto desde el explorador funciona en cualquier
      // punto del modal.
      modal.addEventListener('dragover', _opsJefaOnDragOver);
      modal.addEventListener('dragleave', _opsJefaOnDragLeave);
      modal.addEventListener('drop', _opsJefaOnDrop);
    }
    document.getElementById('opsJefaSubtitle').textContent = 'Guía: ' + idGuia;
    modal.classList.remove('hidden');
    // [v2.43.19] Stale-while-revalidate: si tenemos cache reciente del
    // contexto, lo usamos INSTANT (sin spinner), y revalidamos en bg.
    // Si no hay cache → spinner de carga + await.
    S._opsJefaContextoCache = S._opsJefaContextoCache || {};
    const cached = S._opsJefaContextoCache[idGuia];
    const cacheFresca = cached && (Date.now() - cached.ts < 300000); // 5 min
    if (cacheFresca && cached.items && cached.items.length) {
      _opsJefaState.contexto = cached.items;
      _opsJefaState.cargandoContexto = false;
      _opsJefaRenderCards();
      _opsJefaRenderBody();
      // Revalidar silenciosamente — si trae más items, re-render
      _opsJefaRevalidarContextoBg(idGuia);
      return;
    }
    // Sin cache → spinner inicial
    _opsJefaRenderCards();
    _opsJefaRenderBody();
    // Cargar contexto en background — al terminar re-render del body
    try {
      const r = await API.post('getContextoTicketJefa', { idGuia });
      _opsJefaState.contexto = (r && r.items) || (r && r.data && r.data.items) || [];
      // Persistir en cache
      if (_opsJefaState.contexto.length) {
        S._opsJefaContextoCache[idGuia] = { items: _opsJefaState.contexto, ts: Date.now() };
      }
    } catch(e) {
      console.warn('[opsJefa] getContextoTicketJefa fall:', e);
      _opsJefaState.contexto = [];
    }
    // [v2.43.14] Fallback WH si backend vacío
    if (!_opsJefaState.contexto.length) {
      try {
        const opLocal = _findOpByKey('WH_' + idGuia);
        const cacheKey = 'WH_' + idGuia;
        const cached = S._opsDetCache && S._opsDetCache[cacheKey];
        const lineasGuia = (cached && cached.lineas) || (opLocal && opLocal.lineas) || [];
        if (lineasGuia.length) {
          _opsJefaState.contexto = lineasGuia.map(l => ({
            skuBase:     l.codigoProducto || l.codigoBarra || l.skuBase || '',
            descripcion: l.descripcion || l.nombre || '',
            costo:       parseFloat(l.precioUnitario) || 0,
            ventaActual: 0,
            margenActualPct: 0
          })).filter(it => it.skuBase);
          if (_opsJefaState.contexto.length) {
            console.log('[opsJefa] contexto cargado desde fallback WH:', _opsJefaState.contexto.length, 'items');
          }
        }
      } catch(eF) { console.warn('[opsJefa] fallback WH fall:', eF); }
    }
    _opsJefaState.cargandoContexto = false;
    _opsJefaRenderCards();
    _opsJefaRenderBody();
  }

  // [v2.43.17] Picker INTELIGENTE de fuente de imagen:
  //   📸 Cámara · 📁 Archivo · 🖼 Pegar (Ctrl+V) · ⬇ Arrastrar
  // 3 botones explícitos + dropzone activa sobre todo el modal + paste listener.
  // Manual sigue siendo el default — esto es solo si el admin quiere acelerar.
  function _opsJefaRenderCards() {
    const cont = document.getElementById('opsJefaCardsOrigen');
    if (!cont) return;
    const procesando = !!_opsJefaState.procesando;
    const yaCorrioOcr = !!_opsJefaState.ocrCorrido;
    if (procesando) {
      cont.innerHTML = `
        <div class="w-full py-3 px-4 rounded-2xl flex items-center justify-center gap-3 select-none text-white font-bold"
             style="background:linear-gradient(135deg,#10b981,#059669);opacity:.7">
          <span class="text-xl" style="animation:opsSpin 1.4s linear infinite">🤖</span>
          <span class="text-sm">Procesando con IA…</span>
        </div>`;
      return;
    }
    const checkBadge = yaCorrioOcr
      ? `<span style="position:absolute;top:-6px;right:-6px;background:#10b981;color:#fff;font-size:9px;font-weight:900;padding:2px 6px;border-radius:999px;box-shadow:0 2px 6px rgba(16,185,129,.5)">✓ OCR</span>`
      : '';
    cont.innerHTML = `
      <div class="rounded-2xl p-2.5 relative" style="background:linear-gradient(135deg,rgba(16,185,129,.12),rgba(5,150,105,.08));border:1.5px dashed rgba(16,185,129,.45)">
        ${checkBadge}
        <div class="text-center text-[11px] font-bold text-emerald-300 mb-2 flex items-center justify-center gap-1.5">
          <span>📷</span><span>Subir foto del ticket de la jefa (opcional)</span>
        </div>
        <div class="grid grid-cols-3 gap-1.5">
          <button onclick="MOS._opsJefaAbrirCamara()"
                 class="ops-cta-jefa cursor-pointer py-2.5 px-2 rounded-xl flex flex-col items-center justify-center gap-0.5 transition select-none text-white font-bold text-center border-0"
                 style="background:linear-gradient(135deg,#10b981,#059669);box-shadow:0 4px 10px -2px rgba(16,185,129,.45)">
            <span class="text-lg">📸</span>
            <span class="text-[10px] leading-tight">Cámara</span>
          </button>
          <label for="opsJefaFotoFile"
                 class="ops-cta-jefa cursor-pointer py-2.5 px-2 rounded-xl flex flex-col items-center justify-center gap-0.5 transition select-none text-white font-bold text-center"
                 style="background:linear-gradient(135deg,#0891b2,#0e7490);box-shadow:0 4px 10px -2px rgba(8,145,178,.45)">
            <span class="text-lg">📁</span>
            <span class="text-[10px] leading-tight">Archivo</span>
          </label>
          <button onclick="MOS._opsJefaPedirPaste()"
                  class="ops-cta-jefa cursor-pointer py-2.5 px-2 rounded-xl flex flex-col items-center justify-center gap-0.5 transition select-none text-white font-bold text-center border-0"
                  style="background:linear-gradient(135deg,#7c3aed,#6d28d9);box-shadow:0 4px 10px -2px rgba(124,58,237,.45)">
            <span class="text-lg">🖼</span>
            <span class="text-[10px] leading-tight">Pegar</span>
          </button>
        </div>
        <p class="text-[9px] text-center text-slate-400 mt-1.5 leading-tight">
          o <b>arrastra</b> una imagen aquí · <kbd style="background:rgba(124,58,237,.2);padding:0 4px;border-radius:3px;font-family:ui-monospace,monospace">Ctrl+V</kbd> para pegar
        </p>
      </div>
    `;
  }

  // [v2.43.19] Cámara real con getUserMedia. En PC abre la webcam, no el
  // explorador. En móvil/tablet también usa getUserMedia → cámara nativa.
  // Si getUserMedia no soporta → fallback al input file con capture.
  async function _opsJefaAbrirCamara() {
    try { _opsBeep('tac'); } catch(_){}
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      // Fallback: input nativo con capture (móvil suele tener mejor UX nativo)
      document.getElementById('opsJefaFotoCam').click();
      return;
    }
    // Pedir stream — facingMode environment = cámara trasera en móvil
    let stream;
    try {
      stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: { ideal: 'environment' }, width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false
      });
    } catch(e) {
      console.warn('[opsJefa] getUserMedia denied/fail:', e);
      try { toast('No se pudo abrir cámara · usa Archivo o Pegar', 'warning', 4500); } catch(_){}
      // Fallback al input nativo
      document.getElementById('opsJefaFotoCam').click();
      return;
    }
    // Construir overlay de captura
    let camOv = document.getElementById('opsJefaCamOverlay');
    if (!camOv) {
      camOv = document.createElement('div');
      camOv.id = 'opsJefaCamOverlay';
      camOv.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(2,6,23,.95);display:flex;flex-direction:column;align-items:center;justify-content:center;padding:16px';
      camOv.innerHTML = `
        <div style="position:relative;width:100%;max-width:720px;background:#000;border-radius:18px;overflow:hidden;border:2px solid rgba(16,185,129,.5);box-shadow:0 25px 60px -10px rgba(0,0,0,.7)">
          <video id="opsJefaCamVideo" autoplay playsinline style="width:100%;display:block;background:#000"></video>
          <div style="position:absolute;top:12px;right:12px;display:flex;gap:8px">
            <button id="opsJefaCamFlip" style="width:44px;height:44px;border-radius:50%;background:rgba(15,23,42,.85);color:#fff;border:1px solid rgba(148,163,184,.3);cursor:pointer;font-size:18px;backdrop-filter:blur(8px)" title="Cambiar cámara">🔄</button>
            <button id="opsJefaCamClose" style="width:44px;height:44px;border-radius:50%;background:rgba(220,38,38,.85);color:#fff;border:0;cursor:pointer;font-size:18px;font-weight:900" title="Cerrar">✕</button>
          </div>
        </div>
        <div style="display:flex;gap:14px;margin-top:18px;align-items:center">
          <button id="opsJefaCamCapture" style="width:80px;height:80px;border-radius:50%;background:linear-gradient(135deg,#10b981,#059669);color:#fff;border:4px solid #fff;cursor:pointer;font-size:32px;box-shadow:0 8px 20px -4px rgba(16,185,129,.6);transition:transform .15s ease" title="Capturar">📸</button>
        </div>
        <p style="color:#cbd5e1;font-size:11px;margin-top:10px;text-align:center">Encuadra el ticket de la jefa y tap el botón verde</p>
      `;
      document.body.appendChild(camOv);
    } else {
      camOv.style.display = 'flex';
    }
    const video = document.getElementById('opsJefaCamVideo');
    video.srcObject = stream;
    S._opsJefaCamStream = stream;
    S._opsJefaCamFacing = 'environment';
    // Handlers
    document.getElementById('opsJefaCamClose').onclick = _opsJefaCerrarCamara;
    document.getElementById('opsJefaCamCapture').onclick = _opsJefaCapturarFoto;
    document.getElementById('opsJefaCamFlip').onclick = _opsJefaFlipCamara;
  }

  function _opsJefaCerrarCamara() {
    try { _opsBeep('tac'); } catch(_){}
    const stream = S._opsJefaCamStream;
    if (stream) {
      stream.getTracks().forEach(t => { try { t.stop(); } catch(_){} });
      S._opsJefaCamStream = null;
    }
    const ov = document.getElementById('opsJefaCamOverlay');
    if (ov) ov.style.display = 'none';
  }

  async function _opsJefaFlipCamara() {
    try { _opsBeep('tac'); } catch(_){}
    const stream = S._opsJefaCamStream;
    if (stream) stream.getTracks().forEach(t => { try { t.stop(); } catch(_){} });
    S._opsJefaCamFacing = (S._opsJefaCamFacing === 'environment') ? 'user' : 'environment';
    try {
      const ns = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: { ideal: S._opsJefaCamFacing }, width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false
      });
      const video = document.getElementById('opsJefaCamVideo');
      if (video) video.srcObject = ns;
      S._opsJefaCamStream = ns;
    } catch(e) {
      try { toast('Sin segunda cámara disponible', 'warning', 3000); } catch(_){}
    }
  }

  function _opsJefaCapturarFoto() {
    try { _opsBeep('ok'); } catch(_){}
    const video = document.getElementById('opsJefaCamVideo');
    if (!video || !video.videoWidth) {
      try { toast('Cámara aún no lista · esperá 1s', 'warning', 2500); } catch(_){}
      return;
    }
    // Flash visual rápido
    const cap = document.getElementById('opsJefaCamCapture');
    if (cap) {
      cap.style.transform = 'scale(.85)';
      setTimeout(() => { cap.style.transform = ''; }, 150);
    }
    const canvas = document.createElement('canvas');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    canvas.toBlob(blob => {
      if (!blob) {
        try { toast('Error al capturar foto', 'error', 3000); } catch(_){}
        return;
      }
      const file = new File([blob], 'camara.jpg', { type: 'image/jpeg' });
      _opsJefaCerrarCamara();
      _opsJefaOnFotoSelected({ target: { files: [file], value: '' } });
    }, 'image/jpeg', 0.92);
  }

  // [v2.43.17] Paste image desde portapapeles (Ctrl+V dentro del modal abierto)
  function _opsJefaOnPaste(ev) {
    if (_opsJefaState.procesando) return;
    const items = (ev.clipboardData && ev.clipboardData.items) || [];
    for (let i = 0; i < items.length; i++) {
      const it = items[i];
      if (it.type && it.type.indexOf('image') === 0) {
        const file = it.getAsFile();
        if (file) {
          ev.preventDefault();
          try { _opsBeep('tac'); } catch(_){}
          try { toast('🖼 Imagen pegada · procesando OCR...', 'info', 2500); } catch(_){}
          _opsJefaOnFotoSelected({ target: { files: [file], value: '' } });
          return;
        }
      }
    }
  }

  // [v2.43.17] Trigger manual para que el browser pida permiso de clipboard.
  // En PCs modernas, navigator.clipboard.read() permite leer imágenes sin
  // depender del foco en input. Fallback: toast con instrucción.
  async function _opsJefaPedirPaste() {
    if (_opsJefaState.procesando) return;
    try { _opsBeep('tac'); } catch(_){}
    if (navigator.clipboard && navigator.clipboard.read) {
      try {
        const items = await navigator.clipboard.read();
        for (const item of items) {
          const imgType = item.types.find(t => t.indexOf('image') === 0);
          if (imgType) {
            const blob = await item.getType(imgType);
            const file = new File([blob], 'pegado.png', { type: blob.type });
            try { toast('🖼 Imagen pegada · procesando OCR...', 'info', 2500); } catch(_){}
            _opsJefaOnFotoSelected({ target: { files: [file], value: '' } });
            return;
          }
        }
        try { toast('No hay imagen en el portapapeles · copia una primero', 'warning', 4000); } catch(_){}
      } catch(e) {
        // Permiso denegado o no soportado → fallback instructivo
        try { toast('Presiona Ctrl+V para pegar la imagen', 'info', 4000); } catch(_){}
      }
    } else {
      try { toast('Presiona Ctrl+V para pegar la imagen', 'info', 4000); } catch(_){}
    }
  }

  // [v2.43.17] Drag & drop sobre cualquier parte del modal
  function _opsJefaOnDragOver(ev) {
    if (_opsJefaState.procesando) return;
    if (!ev.dataTransfer || !ev.dataTransfer.types) return;
    if (Array.from(ev.dataTransfer.types).indexOf('Files') < 0) return;
    ev.preventDefault();
    const modal = document.getElementById('modalAplicarRespuestaJefa');
    if (modal) modal.classList.add('ops-jefa-dragover');
  }
  function _opsJefaOnDragLeave(ev) {
    // Solo quitar si realmente salió del modal (no entró a un hijo)
    const modal = document.getElementById('modalAplicarRespuestaJefa');
    if (!modal) return;
    const rect = modal.getBoundingClientRect();
    if (ev.clientX <= rect.left || ev.clientX >= rect.right || ev.clientY <= rect.top || ev.clientY >= rect.bottom) {
      modal.classList.remove('ops-jefa-dragover');
    }
  }
  function _opsJefaOnDrop(ev) {
    if (_opsJefaState.procesando) return;
    ev.preventDefault();
    const modal = document.getElementById('modalAplicarRespuestaJefa');
    if (modal) modal.classList.remove('ops-jefa-dragover');
    const files = ev.dataTransfer && ev.dataTransfer.files;
    if (!files || !files.length) return;
    const file = files[0];
    if (!file.type || file.type.indexOf('image') !== 0) {
      try { toast('Solo imágenes (JPG/PNG)', 'warning', 3500); } catch(_){}
      return;
    }
    try { _opsBeep('tac'); } catch(_){}
    try { toast('🖼 Imagen recibida · procesando OCR...', 'info', 2500); } catch(_){}
    _opsJefaOnFotoSelected({ target: { files: [file], value: '' } });
  }

  // [v2.43.17] Render del body — manual es el DEFAULT.
  // Estados en orden de prioridad:
  //   1. procesando OCR → spinner OCR
  //   2. cargandoContexto → spinner de carga inicial (race-fix)
  //   3. tieneCorrecciones → lista A/B/C
  //   4. tieneContexto → auto-cargar manual
  //   5. nada → mensaje warning
  function _opsJefaRenderBody() {
    const body = document.getElementById('opsJefaBody');
    if (!body) return;
    const tieneContexto = (_opsJefaState.contexto || []).length > 0;
    const tieneCorrecciones = (_opsJefaState.correcciones || []).length > 0;
    if (_opsJefaState.procesando) {
      body.innerHTML = `<div class="text-center py-12">
        <div class="text-5xl mb-3" style="animation:opsSpin 1.4s linear infinite;display:inline-block">🤖</div>
        <p class="text-sm text-slate-300 font-bold">Procesando con Claude OCR...</p>
        <p class="text-xs text-slate-500 mt-2">5-15 segundos · espera por favor</p>
      </div>`;
      return;
    }
    // [v2.43.17] Spinner de carga inicial — evita el flash "sin productos"
    // mientras llega la respuesta del backend (getContextoTicketJefa puede
    // tardar 1-3 segundos en guías grandes).
    if (_opsJefaState.cargandoContexto) {
      body.innerHTML = `<div class="text-center py-12">
        <div class="text-5xl mb-3" style="animation:opsSpin 1.4s linear infinite;display:inline-block">⏳</div>
        <p class="text-sm text-slate-300 font-bold">Cargando productos de la guía...</p>
        <p class="text-[11px] text-slate-500 mt-2">consultando backend</p>
      </div>`;
      return;
    }
    if (tieneCorrecciones) {
      // Render la lista A/B/C (función existente, ahora solo el body)
      _opsJefaRenderResultados();
      return;
    }
    // Sin correcciones — si hay contexto, auto-cargar en modo manual (default).
    if (tieneContexto) {
      _opsJefaIniciarManual();
      return;
    }
    body.innerHTML = `<div class="text-center py-12 text-slate-400">
      <div class="text-4xl mb-3">⚠</div>
      <p class="text-sm text-amber-400">Esta guía aún no tiene productos cargados.</p>
      <p class="text-[11px] mt-2 text-slate-500">
        Primero pasa por '💰 Actualizar costos' y guarda al menos 1 ítem.<br>
        Después vuelve aquí para actualizar precios.
      </p>
    </div>`;
  }

  function opsCerrarAplicarRespuestaJefa() {
    const m = document.getElementById('modalAplicarRespuestaJefa');
    if (m) m.classList.add('hidden');
    _opsJefaState.idGuia = null;
    _opsJefaState.contexto = [];
    _opsJefaState.correcciones = [];
  }

  async function _opsJefaOnFotoSelected(ev) {
    const file = ev.target.files && ev.target.files[0];
    if (!file) return;
    if (_opsJefaState.procesando) return;
    _opsJefaState.procesando = true;
    // [v2.43.15] Sin modoOrigen — manual sigue siendo default. OCR solo
    // pre-puebla los inputs y deja la lista A/B/C lista para ajustar.
    try { _opsJefaRenderCards(); } catch(_){}
    const body = document.getElementById('opsJefaBody');
    body.innerHTML = `
      <div class="text-center py-12">
        <div class="text-5xl mb-3" style="animation:opsSpin 1.4s linear infinite;display:inline-block">🤖</div>
        <p class="text-sm text-slate-300 font-bold">Procesando con Claude OCR...</p>
        <p class="text-xs text-slate-500 mt-2">Esto tarda ~5-15 segundos</p>
      </div>`;
    try {
      const fotoBase64 = await _opsFileToBase64(file);
      const r = await API.post('ocrTicketJefa', {
        fotoBase64:    fotoBase64,
        contextoItems: _opsJefaState.contexto
      });
      const d = (r && r.data) || r || {};
      _opsJefaState.correcciones = (d.correcciones || []).map(c => ({
        ...c,
        // Hidratar info del contexto para mostrar nombre + costo
        descripcion: (_opsJefaState.contexto.find(x => x.skuBase === c.skuBase) || {}).descripcion || c.skuBase,
        costo:       (_opsJefaState.contexto.find(x => x.skuBase === c.skuBase) || {}).costo || 0,
        editado:     false
      }));
      _opsJefaState.confidenceGlobal = d.confidenceGlobal || 0;
      _opsJefaState.ocrCorrido = true;
      try { _opsBeep('ok'); } catch(_){}
      try { toast('🤖 OCR listo — revisa los valores y ajusta lo que necesites', 'success', 3500); } catch(_){}
      _opsJefaRenderCards();
      _opsJefaRenderResultados();
    } catch(e) {
      try { _opsBeep('warn'); } catch(_){}
      body.innerHTML = `<div class="text-center py-10 text-rose-400">
        <div class="text-4xl mb-2">⚠</div>
        <p class="text-sm">Error OCR: ${_escapeHtml(e.message || e)}</p>
        <p class="text-xs text-slate-400 mt-2">Puedes seguir escribiendo manualmente abajo.</p>
        <button onclick="MOS._opsJefaIniciarManual()" class="mt-4 px-4 py-2 bg-emerald-500 hover:bg-emerald-400 rounded-lg text-white font-bold">✏️ Continuar manual</button>
      </div>`;
    } finally {
      _opsJefaState.procesando = false;
    }
    // Reset input para permitir re-seleccionar la misma foto si quieren reintentar
    try { ev.target.value = ''; } catch(_){}
  }

  function _opsFileToBase64(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  }

  function _opsJefaRenderResultados() {
    const body = document.getElementById('opsJefaBody');
    const corr = _opsJefaState.correcciones;
    const cg = _opsJefaState.confidenceGlobal;
    // Determinar modo según confidence híbrido
    const tieneDudosos = corr.some(c => c.confidence < 95);
    const tieneCriticos = corr.some(c => c.confidence < 80);
    const banner = tieneCriticos
      ? `<div class="bg-rose-900/40 border border-rose-500/50 rounded-xl p-3 mb-4 text-xs">
           <strong class="text-rose-300">⚠ Confianza baja</strong> — revisa TODOS los valores manualmente antes de aplicar.
         </div>`
      : tieneDudosos
      ? `<div class="bg-amber-900/40 border border-amber-500/50 rounded-xl p-3 mb-4 text-xs">
           <strong class="text-amber-300">⚠ Algunos valores dudosos</strong> — revisa los marcados en ámbar.
         </div>`
      : `<div class="bg-emerald-900/40 border border-emerald-500/50 rounded-xl p-3 mb-4 text-xs">
           <strong class="text-emerald-300">✓ Lectura confiable</strong> — verifica visualmente y aplica.
         </div>`;
    if (!corr.length) {
      body.innerHTML = `${banner}
        <div class="text-center py-8 text-slate-400 text-sm">
          OCR no detectó cambios en el ticket. ¿Probar otra foto?
        </div>
        <button onclick="document.getElementById('opsJefaFotoInput').click()" class="w-full bg-slate-700 text-slate-200 py-2 rounded-lg">📷 Subir otra foto</button>`;
      return;
    }
    // [v2.43.4] Inicializar opción A/B/C por correción basado en lo que vino del OCR.
    // A = sin cambio (default cuando OCR no detectó nada)
    // B = nuevo precio venta (cuando jefa escribió precio nuevo)
    // C = nuevo margen % (cuando jefa escribió margen nuevo)
    corr.forEach(c => {
      if (c._opcionInicializada) return;
      if (c.ventaNueva != null && c.ventaNueva > 0) c.opcion = 'B';
      else if (c.margenNuevoPct != null && c.margenNuevoPct > 0) c.opcion = 'C';
      else c.opcion = 'A';
      c._opcionInicializada = true;
      // Default: propagar a presentaciones (lo que admin espera, casi siempre)
      if (c.propagar === undefined) c.propagar = true;
    });

    body.innerHTML = banner + corr.map((c, idx) => {
      const confCls = c.confidence >= 95 ? 'border-emerald-500/40 bg-emerald-950/30'
                    : c.confidence >= 80 ? 'border-amber-500/50 bg-amber-950/30'
                    : 'border-rose-500/50 bg-rose-950/30';
      const confTxt = c.confidence >= 95 ? '✓ alta'
                    : c.confidence >= 80 ? '⚠ media'
                    : '⚠ baja';
      const costo = parseFloat(c.costo) || 0;
      // Buscar precio venta y margen actual del catálogo (si producto existe)
      const prodCat = (S.productos || []).find(p => String(p.SKU_Base || p.skuBase || '').trim() === String(c.skuBase || '').trim());
      const ventaActual  = prodCat ? (parseFloat(prodCat.precioVenta) || 0) : 0;
      const margenActual = (costo > 0 && ventaActual > 0) ? ((ventaActual - costo) / ventaActual) * 100 : null;
      // [v2.43.19/20] Margen OBJETIVO registrado en master (puede ser null).
      // Opción A:
      //  - Si hay objetivo registrado → respetar margen, venta = costo/(1-marg)
      //  - Si NO hay objetivo PERO hay venta + costo nuevo → aceptar el margen
      //    actual calculado y grabarlo como objetivo (no cambia precio venta)
      let margenObj = null;
      if (prodCat) {
        const oMargRaw = prodCat.margenPct;
        if (oMargRaw !== '' && oMargRaw != null && !isNaN(parseFloat(oMargRaw))) {
          margenObj = parseFloat(oMargRaw) / 100;
        } else if (prodCat.categoria) {
          const cat = (S.categorias || []).find(ct => ct.nombre === prodCat.categoria);
          if (cat && cat.margenPct !== '' && cat.margenPct != null && !isNaN(parseFloat(cat.margenPct))) {
            margenObj = parseFloat(cat.margenPct) / 100;
          }
        }
      }
      const ventaAutoA = (margenObj !== null && costo > 0 && margenObj > 0 && margenObj < 0.99)
        ? +(costo / (1 - margenObj)).toFixed(2)
        : null;
      // [v2.43.20] Sub-caso A2: sin objetivo pero PUEDO calcular margen actual
      // y grabarlo como objetivo manteniendo el precio. margenAGrabar = (venta-costo)/venta.
      const margenAGrabar = (margenObj === null && ventaActual > 0 && costo > 0)
        ? (ventaActual - costo) / ventaActual
        : null;
      c._margenObj = margenObj;
      c._ventaAutoA = ventaAutoA;
      c._margenAGrabar = margenAGrabar;   // [v2.43.20] fracción (no %)
      // Live calc según opción
      const ventaB = c.opcion === 'B' && c.ventaNueva ? parseFloat(c.ventaNueva) : null;
      const margenB = (ventaB && costo > 0) ? ((ventaB - costo) / ventaB) * 100 : null;
      const margenC = c.opcion === 'C' && c.margenNuevoPct ? parseFloat(c.margenNuevoPct) * 100 : null;
      const ventaC = (margenC && costo > 0) ? +(costo / (1 - margenC / 100)).toFixed(2) : null;
      const colorM = (m) => m === null ? '#94a3b8' : m < 10 ? '#f87171' : m < 20 ? '#fbbf24' : '#34d399';
      const ventaFinal = c.opcion === 'A' ? (ventaAutoA || ventaActual)
                       : c.opcion === 'B' ? ventaB
                       : c.opcion === 'C' ? ventaC : ventaActual;
      const margenFinal = c.opcion === 'A' ? (margenObj !== null ? margenObj * 100 : margenActual)
                        : c.opcion === 'B' ? margenB
                        : c.opcion === 'C' ? margenC : margenActual;
      return `<div class="rounded-xl border ${confCls} p-3 mb-3" style="animation:opsBadgeIn .25s cubic-bezier(.34,1.56,.64,1) ${idx * 0.04}s both">
        <div class="flex items-center justify-between mb-2">
          <div class="font-bold text-slate-100 text-sm">#${idx+1} ${_escapeHtml(c.descripcion || c.skuBase)}</div>
          <span class="text-[10px] text-slate-400">${confTxt} · ${c.confidence}%</span>
        </div>
        <div class="text-[11px] text-slate-500 mb-2 flex items-center gap-2 flex-wrap">
          <span>SKU: ${_escapeHtml(c.skuBase)}</span>
          <span>·</span>
          <span>💰 Costo: <b class="text-amber-300">S/ ${costo.toFixed(2)}</b></span>
          ${ventaActual > 0 ? `<span>·</span><span>📊 Venta actual: <b class="text-slate-300">S/ ${ventaActual.toFixed(2)}</b></span>` : ''}
          ${margenActual !== null ? `<span>·</span><span>Margen actual: <b style="color:${colorM(margenActual)}">${margenActual.toFixed(1)}%</b></span>` : ''}
        </div>
        ${c.tachado ? `<div class="text-rose-300 text-xs">⊘ Tachado por jefa — NO se aplicará</div>` : `
          <!-- [v2.43.4/19] 3 opciones A/B/C con radio buttons elegantes.
               A AHORA = respetar margen objetivo registrado en master:
               si el costo sube, el precio sube proporcional para mantener
               el margen. Si no hay margen registrado → A es no-op real. -->
          <div class="space-y-1.5 mt-2">
            <label class="flex items-center gap-2 cursor-pointer p-2 rounded-lg ${c.opcion === 'A' ? 'bg-emerald-900/30 border border-emerald-500/50' : 'hover:bg-slate-800/40'}" onclick="MOS._opsJefaSetOpcion(${idx},'A')">
              <input type="radio" name="opcJefa${idx}" ${c.opcion === 'A' ? 'checked' : ''} class="accent-emerald-400">
              <span class="text-xs text-slate-300 flex-1"><b>A.</b> ${
                c._margenObj !== null && c._margenObj !== undefined
                  ? `Mantener margen objetivo <b class="text-emerald-300">${(c._margenObj*100).toFixed(1)}%</b>`
                  : c._margenAGrabar !== null && c._margenAGrabar !== undefined
                    ? `Aceptar margen actual <b class="text-emerald-300">${(c._margenAGrabar*100).toFixed(1)}%</b> <span class="text-[9px] text-slate-400" title="Queda registrado como objetivo">(se grabará)</span>`
                    : 'Sin cambio (sin datos suficientes)'
              }</span>
              ${c._ventaAutoA !== null && c._ventaAutoA !== undefined
                ? `<span class="text-[11px] text-emerald-300 font-bold">→ S/${c._ventaAutoA.toFixed(2)}</span>`
                : c._margenAGrabar !== null && c._margenAGrabar !== undefined
                  ? `<span class="text-[11px] text-emerald-300 font-bold">= S/${ventaActual.toFixed(2)}</span>`
                  : ''}
            </label>
            <label class="flex items-center gap-2 cursor-pointer p-2 rounded-lg ${c.opcion === 'B' ? 'bg-emerald-900/40 border border-emerald-500/50' : 'hover:bg-slate-800/40'}" onclick="MOS._opsJefaSetOpcion(${idx},'B')">
              <input type="radio" name="opcJefa${idx}" ${c.opcion === 'B' ? 'checked' : ''} class="accent-emerald-400">
              <span class="text-xs text-slate-300 flex-1"><b>B.</b> Nuevo precio:</span>
              <input type="number" step="0.01" value="${c.ventaNueva != null ? c.ventaNueva : ''}"
                     oninput="MOS._opsJefaEditar(${idx},'ventaNueva',this.value)"
                     onclick="event.stopPropagation();MOS._opsJefaSetOpcion(${idx},'B')"
                     placeholder="S/ ___"
                     class="w-24 bg-slate-900 border border-slate-600 rounded px-2 py-1 text-sm text-slate-100 font-bold text-right">
              ${margenB !== null ? `<span class="text-[10px]" style="color:${colorM(margenB)}">→ ${margenB.toFixed(1)}%</span>` : ''}
            </label>
            <label class="flex items-center gap-2 cursor-pointer p-2 rounded-lg ${c.opcion === 'C' ? 'bg-cyan-900/40 border border-cyan-500/50' : 'hover:bg-slate-800/40'}" onclick="MOS._opsJefaSetOpcion(${idx},'C')">
              <input type="radio" name="opcJefa${idx}" ${c.opcion === 'C' ? 'checked' : ''} class="accent-cyan-400">
              <span class="text-xs text-slate-300 flex-1"><b>C.</b> Nuevo margen:</span>
              <input type="number" step="0.1" value="${c.margenNuevoPct != null ? (c.margenNuevoPct * 100).toFixed(1) : ''}"
                     oninput="MOS._opsJefaEditar(${idx},'margenNuevoPct',this.value/100)"
                     onclick="event.stopPropagation();MOS._opsJefaSetOpcion(${idx},'C')"
                     placeholder="___%"
                     class="w-20 bg-slate-900 border border-slate-600 rounded px-2 py-1 text-sm text-slate-100 font-bold text-right">
              ${ventaC !== null ? `<span class="text-[10px] text-cyan-300">→ S/${ventaC.toFixed(2)}</span>` : ''}
            </label>
          </div>
          <!-- [v2.43.6] Propagación a presentaciones — lista expandida con
               checkboxes por presentación + cálculo del precio nuevo según
               opción elegida (B → ventaCanónico × factor · C → costo / (1-m)).
               El canónico va primero, luego presentaciones ordenadas por factor. -->
          ${c.opcion !== 'A' ? _opsJefaRenderPresentaciones(idx, c, costo) : ''}
          ${c.notas ? `<div class="text-[10px] text-slate-500 italic mt-2">"${_escapeHtml(c.notas)}"</div>` : ''}
        `}
      </div>`;
    }).join('') + `
      <div class="sticky bottom-0 bg-slate-900 pt-3 mt-2 border-t border-slate-700/60">
        <button onclick="MOS._opsJefaConfirmarAplicar()"
                class="ops-cta-jefa w-full bg-gradient-to-r from-emerald-500 to-emerald-600 hover:from-emerald-400 active:scale-95 text-white font-black py-3 rounded-xl shadow-lg shadow-emerald-500/40"
                style="transition:transform .15s ease,box-shadow .2s ease">
          🔐 Aplicar + imprimir comprobante
        </button>
        <p class="text-[10px] text-slate-500 text-center mt-2">Requiere PIN admin · auto-imprime ticket de auditoría con cambios resaltados</p>
      </div>`;
  }

  // [v2.43.5] Entrada manual sin OCR: llena correcciones desde el contexto
  // de la guía (los items que existen) con valores vacíos. Admin elige opción
  // y tipea precio/margen para los que corresponda. Mucho más rápido cuando
  // la foto no está clara o se quiere ir directo.
  // [v2.43.15] DEFAULT del modal. Llamada automática desde _opsJefaRenderBody
  // cuando hay contexto. Inicializa correcciones manual (opcion='A',
  // ventaNueva=null) para que el admin escriba directo. Sin toast warning —
  // si no hay contexto, el renderBody ya muestra el mensaje claro arriba.
  function _opsJefaIniciarManual() {
    const ctx = _opsJefaState.contexto || [];
    if (!ctx.length) {
      _opsJefaRenderBody();
      return;
    }
    _opsJefaState.correcciones = ctx.map(item => ({
      skuBase:        item.skuBase,
      descripcion:    item.descripcion,
      costo:          item.costo || 0,
      ventaNueva:     null,
      margenNuevoPct: null,
      tachado:        false,
      confidence:     100,
      notas:          '',
      editado:        false,
      opcion:         'A',
      _opcionInicializada: true,
      propagar:       true
    }));
    _opsJefaState.confidenceGlobal = 100;
    _opsJefaRenderCards();
    _opsJefaRenderResultados();
  }

  // [v2.43.4] Cambia la opción A/B/C de un item — con sonido suave + re-render
  function _opsJefaSetOpcion(idx, opcion) {
    const c = _opsJefaState.correcciones[idx];
    if (!c) return;
    if (c.opcion === opcion) return; // no-op
    c.opcion = opcion;
    try { _opsBeep('tac'); } catch(_){}
    _opsJefaRenderResultados();
  }

  // [v2.43.4] Toggle propagar a presentaciones (global — legacy compat)
  function _opsJefaTogglePropagar(idx, val) {
    const c = _opsJefaState.correcciones[idx];
    if (!c) return;
    c.propagar = !!val;
    try { _opsBeep('tac'); } catch(_){}
  }

  // [v2.43.6] Render expandido de presentaciones del canónico con checkbox
  // por presentación + precio nuevo calculado en vivo según opción B/C.
  // El canónico aparece primero, luego presentaciones ordenadas por factor.
  function _opsJefaRenderPresentaciones(idx, c, costo) {
    try {
      const skuBase = String(c.skuBase || '').trim();
      if (!skuBase) return '';
      // Buscar canónico (factorConversion=1 o igual al skuBase)
      const canonico = (S.productos || []).find(p =>
        String(p.SKU_Base || p.skuBase || '').trim() === skuBase
        && (parseFloat(p.factorConversion) === 1 || p.idProducto === skuBase || p.skuBase === p.idProducto)
      );
      // Buscar presentaciones (mismo skuBase, factor != 1)
      const presentaciones = (S.productos || []).filter(p =>
        String(p.SKU_Base || p.skuBase || '').trim() === skuBase
        && parseFloat(p.factorConversion) > 1
      ).sort((a, b) => parseFloat(a.factorConversion) - parseFloat(b.factorConversion));

      // Lista combinada: canónico primero + presentaciones
      const todas = [];
      if (canonico) todas.push({ ...canonico, _esCanon: true, factor: 1 });
      presentaciones.forEach(p => {
        todas.push({ ...p, _esCanon: false, factor: parseFloat(p.factorConversion) || 1 });
      });
      if (!todas.length) {
        // Sin productos en cat — mostrar mensaje simple con check global compat
        return `<label class="flex items-center gap-2 mt-2 px-2 py-1.5 rounded-lg bg-purple-900/20 border border-purple-500/30 cursor-pointer">
          <input type="checkbox" ${c.propagar ? 'checked' : ''} onchange="MOS._opsJefaTogglePropagar(${idx}, this.checked)" class="accent-purple-400">
          <span class="text-[11px] text-purple-200">📦 Propagar a presentaciones (no se encontraron en cat)</span>
        </label>`;
      }

      // Inicializar mapa de propagación por presentación si no existe
      if (!c.presPropagar) {
        c.presPropagar = {};
        todas.forEach(p => { c.presPropagar[p.idProducto] = true; });
      }
      // Asegurar que productos nuevos tengan default true
      todas.forEach(p => {
        if (c.presPropagar[p.idProducto] === undefined) c.presPropagar[p.idProducto] = true;
      });

      // Calcular precio nuevo del canónico según opción
      let precioCanonicoNuevo = null;
      if (c.opcion === 'B' && c.ventaNueva > 0) {
        precioCanonicoNuevo = parseFloat(c.ventaNueva);
      } else if (c.opcion === 'C' && c.margenNuevoPct > 0 && costo > 0) {
        precioCanonicoNuevo = +(costo / (1 - parseFloat(c.margenNuevoPct))).toFixed(2);
      }

      const totalSeleccionados = todas.filter(p => c.presPropagar[p.idProducto]).length;
      const totalDisponibles = todas.length;

      // Render
      const filasHtml = todas.map(p => {
        const precioActual = parseFloat(p.precioVenta) || 0;
        const precioNuevo = (precioCanonicoNuevo !== null) ? +(precioCanonicoNuevo * p.factor).toFixed(2) : null;
        const cambio = (precioNuevo !== null && Math.abs(precioNuevo - precioActual) > 0.005);
        const checked = c.presPropagar[p.idProducto];
        const factorLabel = p._esCanon ? 'CANÓNICO' : `×${p.factor}`;
        const factorCls = p._esCanon ? 'bg-amber-500/20 text-amber-300 border border-amber-500/40' : 'bg-slate-700 text-slate-300';
        return `<label class="flex items-center gap-2 px-2 py-1.5 rounded-lg cursor-pointer ${checked ? 'bg-purple-900/30 border border-purple-500/40' : 'bg-slate-900/40 border border-slate-700 opacity-60'}" style="transition:all .15s ease">
          <input type="checkbox" ${checked ? 'checked' : ''} onchange="MOS._opsJefaTogglePresentacion(${idx}, '${_escapeHtml(p.idProducto)}', this.checked)" class="accent-purple-400 shrink-0">
          <span class="text-[10px] font-bold px-1.5 py-0.5 rounded ${factorCls} shrink-0">${factorLabel}</span>
          <span class="text-[11px] text-slate-200 flex-1 truncate" title="${_escapeHtml(p.descripcion || p.idProducto)}">${_escapeHtml(p.descripcion || p.idProducto)}</span>
          <span class="text-[10px] text-slate-400 font-mono shrink-0">S/${precioActual.toFixed(2)}</span>
          ${cambio ? `<span class="text-[10px] text-purple-300 shrink-0">→</span><span class="text-[11px] font-bold text-purple-200 shrink-0" style="animation:opsNumPulse .4s cubic-bezier(.34,1.56,.64,1)">S/${precioNuevo.toFixed(2)}</span>` : ''}
        </label>`;
      }).join('');

      return `<div class="mt-2 p-2 rounded-lg bg-purple-950/30 border border-purple-500/30">
        <div class="flex items-center justify-between mb-1.5 px-1">
          <span class="text-[11px] font-bold text-purple-200">📦 Propagar a presentaciones (${totalSeleccionados}/${totalDisponibles})</span>
          <button onclick="MOS._opsJefaTodasPresentaciones(${idx}, ${totalSeleccionados !== totalDisponibles})"
                  class="text-[10px] text-purple-300 hover:text-purple-100 underline">
            ${totalSeleccionados === totalDisponibles ? 'Ninguno' : 'Todos'}
          </button>
        </div>
        <div class="space-y-1">${filasHtml}</div>
      </div>`;
    } catch(e) {
      console.warn('[_opsJefaRenderPresentaciones]', e);
      return '';
    }
  }

  // [v2.43.6] Toggle propagación de UNA presentación específica
  function _opsJefaTogglePresentacion(idx, idProducto, val) {
    const c = _opsJefaState.correcciones[idx];
    if (!c || !c.presPropagar) return;
    c.presPropagar[idProducto] = !!val;
    try { _opsBeep('tac'); } catch(_){}
    _opsJefaRenderResultados();
  }

  // [v2.43.6] Toggle masivo: todos los checkboxes a true (selectAll=true) o false
  function _opsJefaTodasPresentaciones(idx, selectAll) {
    const c = _opsJefaState.correcciones[idx];
    if (!c || !c.presPropagar) return;
    Object.keys(c.presPropagar).forEach(k => { c.presPropagar[k] = !!selectAll; });
    try { _opsBeep('ok'); } catch(_){}
    _opsJefaRenderResultados();
  }

  function _opsJefaEditar(idx, campo, valor) {
    const c = _opsJefaState.correcciones[idx];
    if (!c) return;
    if (valor === '' || isNaN(parseFloat(valor))) c[campo] = null;
    else c[campo] = parseFloat(valor);
    c.editado = true;
    // [v2.43.4] Live re-render con debounce para actualizar el cálculo
    // de margen/precio resultante mientras el admin escribe.
    clearTimeout(_opsJefaState._renderTimer);
    _opsJefaState._renderTimer = setTimeout(() => {
      try { _opsJefaRenderResultados(); } catch(_){}
    }, 250);
  }

  async function _opsJefaConfirmarAplicar() {
    // [v2.43.19] Semántica REVISADA de opciones:
    //   A → RESPETAR margen objetivo (auto: venta = costo / (1-margenObj))
    //        Si producto NO tiene margen registrado → no se envía (no-op real)
    //   B → ventaNueva explícita (backend calcula margen)
    //   C → margenNuevoPct explícito (backend calcula precio)
    //   propagar → flag para que backend afecte presentaciones
    const items = _opsJefaState.correcciones
      .filter(c => !c.tachado && c.opcion)
      .filter(c => {
        if (c.opcion === 'A') {
          // A1: tiene margen objetivo → recalcular precio
          // A2: sin objetivo pero margen calculable → grabar margen (precio igual)
          return (c._margenObj !== null && c._margenObj !== undefined && c._ventaAutoA > 0)
              || (c._margenAGrabar !== null && c._margenAGrabar !== undefined);
        }
        if (c.opcion === 'B') return c.ventaNueva != null && c.ventaNueva > 0;
        if (c.opcion === 'C') return c.margenNuevoPct != null && c.margenNuevoPct > 0;
        return false;
      })
      .map(c => {
        const presentacionesPropagar = c.presPropagar
          ? Object.keys(c.presPropagar).filter(k => c.presPropagar[k])
          : null;
        // [v2.43.19/20] A → backend lo procesa como C (margen) para que el
        // backend grabe el margenPct nuevo en master. Sub-casos:
        //   A1 (objetivo registrado): venta nueva = costo/(1-margenObj) ya
        //       calculada, mandamos margenNuevoPct = margenObj para grabarlo
        //       Y ventaNueva como pista de la venta exacta.
        //   A2 (sin objetivo, hay margen actual): grabar margen actual.
        //       Precio venta queda igual (backend lo deriva del margen + costo).
        if (c.opcion === 'A') {
          const margenFinal = c._margenObj !== null && c._margenObj !== undefined
            ? c._margenObj
            : c._margenAGrabar;
          return {
            skuBase:        c.skuBase,
            descripcion:    c.descripcion,
            costoNuevo:     c.costo,
            ventaNueva:     c._ventaAutoA || null,
            margenNuevoPct: margenFinal,
            opcion:         'A',
            _origenA:       true,
            _origenA_sub:   c._margenObj !== null ? 'A1_objetivo' : 'A2_grabar',
            propagar:       c.propagar !== false,
            presentacionesPropagar: presentacionesPropagar
          };
        }
        return {
          skuBase:        c.skuBase,
          descripcion:    c.descripcion,
          costoNuevo:     c.costo,
          ventaNueva:     c.opcion === 'B' ? c.ventaNueva     : null,
          margenNuevoPct: c.opcion === 'C' ? c.margenNuevoPct : null,
          opcion:         c.opcion,
          propagar:       c.propagar !== false,
          presentacionesPropagar: presentacionesPropagar
        };
      });
    if (!items.length) {
      try { _opsBeep('warn'); } catch(_){}
      toast('No hay cambios para aplicar', 'warning');
      return;
    }
    try { _opsBeep('tac'); } catch(_){}
    // Pedir PIN admin con el modal universal
    const auth = await pedirAuth({
      accion: 'APLICAR_RESPUESTA_JEFA',
      refDocumento: _opsJefaState.idGuia,
      contexto: `Aplicar ${items.length} cambios al catálogo · guía ${_opsJefaState.idGuia}`
    });
    if (!auth) return;
    // Elegir impresora para el ticket de confirmación (recordada por flowKey)
    const printerId = await abrirPrinterPicker({
      titulo: '🖨 Impresora para ticket de confirmación',
      subtitulo: 'Auditoría visual de los cambios aplicados',
      filtroTipo: 'TICKET',
      flowKey:    'jefa_conf'   // [v2.43.4] memorizar última impresora
    }).catch(() => null);
    try { _toast?.('info', '⚙ Aplicando cambios al catálogo...'); } catch(_){}
    try {
      const r = await API.post('aplicarRespuestaJefa', {
        idGuia:     _opsJefaState.idGuia,
        claveAdmin: auth.clave,
        items:      items,
        printerId:  printerId || ''
      });
      const d = (r && r.data) || r || {};
      if (!d.autorizado) {
        try { _opsBeep('warn'); } catch(_){}
        toast(d.error || 'Clave incorrecta', 'error');
        return;
      }
      try { _opsBeep('ok'); } catch(_){}
      // [v2.43.10/11] Marcar localStorage que precios fueron actualizados.
      // Formato: "ts|aplicados|totalContexto" para que el botón muestre barra
      // proporcional. 'aplicados' = items con cambio real (B o C). 'total' =
      // items del ticket original (incluye los que la jefa dejó vacíos).
      try {
        var _totCtx = (_opsJefaState.correcciones || []).length || (_opsJefaState.contexto || []).length || items.length;
        localStorage.setItem('mos_jefa_aplicada_' + _opsJefaState.idGuia, Date.now() + '|' + items.length + '|' + _totCtx);
      } catch(_){}
      toast(`✓ ${d.aplicados} cambio(s) aplicados al catálogo` +
            (d.ticketImpreso ? ' · ticket impreso' : ''), 'success', 6000);
      if (d.errores && d.errores.length) {
        console.warn('Errores al aplicar:', d.errores);
        toast(`⚠ ${d.errores.length} con error — revisa consola`, 'warning', 8000);
      }
      opsCerrarAplicarRespuestaJefa();
    } catch(e) {
      try { _opsBeep('warn'); } catch(_){}
      toast('Error: ' + (e.message || e), 'error');
    }
  }
  function cerrarSelPrinterCostos() {
    closeModal('modalSelPrinterCostos');
    closeModal('modalSelPrinterLiq');
    S._opsImpCtx = null;
  }
  function _opsRecargarPrinters() { _opsCargarPrinters(true); }

  async function _opsCargarPrinters(force) {
    const cont = $('selPrCostosList');
    if (!cont) return;
    // Cache simple en S._opsPrintersCache
    if (!force && S._opsPrintersCache && S._opsPrintersCache.length) {
      _opsRenderPrinters(S._opsPrintersCache);
      return;
    }
    cont.innerHTML = `<div class="text-center text-xs text-slate-500 py-8">
      <div class="inline-block animate-spin">⏳</div> Consultando PrintNode...
    </div>`;
    try {
      const data = await API.get('listarImpresorasPN', {});
      const list = Array.isArray(data) ? data : (data && data.data) || [];
      S._opsPrintersCache = list;
      _opsRenderPrinters(list);
    } catch(e) {
      cont.innerHTML = `<div class="text-center text-xs text-rose-400 py-8">⚠ Error: ${e.message || e}</div>`;
    }
  }

  function _opsRenderPrinters(list) {
    const cont = $('selPrCostosList');
    if (!cont) return;
    if (!list.length) {
      cont.innerHTML = `<div class="text-center text-xs text-slate-500 py-8">
        <div class="text-3xl mb-2 opacity-50">🖨</div>
        No hay impresoras registradas.<br>
        <span class="text-[10px]">Configúralas en Infraestructura.</span>
      </div>`;
      return;
    }
    // Agrupado por zona/estación (mismo patrón que liq)
    const zonas = {};
    list.forEach(p => {
      const zk = p.idZona || '_sin';
      if (!zonas[zk]) zonas[zk] = { label: p.zonaNombre || p.idZona || '(sin zona)', items: [] };
      zonas[zk].items.push(p);
    });
    const pCard = (p, idx) => {
      const offCls = p.online ? '' : 'opacity-60';
      const dotColor = p.online ? '#34d399' : '#f87171';
      const offTag = p.online
        ? '<span class="text-[9px] text-emerald-400 ml-1 font-semibold">online</span>'
        : '<span class="text-[9px] text-rose-400 ml-1">offline</span>';
      const subMeta = [
        (p.tipo === 'ADHESIVO' ? '🏷' : '🧾') + ' ' + (p.tipo || 'TICKET'),
        p.estacionNombre ? '· ' + p.estacionNombre : '',
        p.computer ? '· 💻 ' + p.computer : ''
      ].filter(Boolean).join(' ');
      return `<button onclick="MOS._opsEnviarPrintCostos(${p.id}, this)"
        class="w-full text-left rounded-lg p-2 ${offCls}"
        style="background:linear-gradient(135deg,#060d1f,#0a1428);border:1px solid #1e293b;
               cursor:pointer;transition:all .15s;
               animation: checklistItemIn .35s cubic-bezier(.34,1.56,.64,1) backwards;
               animation-delay:${idx*40}ms"
        onmouseover="this.style.borderColor='#0ea5e9';this.style.transform='translateY(-1px)'"
        onmouseout="this.style.borderColor='#1e293b';this.style.transform=''">
        <div class="flex items-center gap-2">
          <span style="width:10px;height:10px;border-radius:999px;background:${dotColor};box-shadow:0 0 8px ${dotColor}"></span>
          <span class="text-sm text-slate-100 font-semibold flex-1">${_escapeHtml(p.nombre || 'Impresora')}</span>
          ${offTag}
        </div>
        ${subMeta ? `<div class="text-[10px] text-slate-500 mt-1 pl-4">${subMeta}</div>` : ''}
      </button>`;
    };
    let idx = 0;
    cont.innerHTML = Object.keys(zonas).sort((a,b) => zonas[a].label.localeCompare(zonas[b].label)).map(zk => {
      const z = zonas[zk];
      return `<div>
        <div class="text-[10px] uppercase font-bold text-cyan-400 mb-1 mt-2 px-1">📍 ${_escapeHtml(z.label)}</div>
        <div class="space-y-1.5">${z.items.map(p => pCard(p, idx++)).join('')}</div>
      </div>`;
    }).join('');
  }

  async function _opsEnviarPrintCostos(printerId, btn) {
    const ctx = S._opsImpCtx;
    if (!ctx) return;
    if (btn) {
      btn.disabled = true;
      btn.style.opacity = '0.5';
      btn.style.pointerEvents = 'none';
      btn.innerHTML += '<div class="text-[10px] text-cyan-400 mt-1 pl-4">⏳ Enviando...</div>';
    }
    try {
      const payload = { idGuia: ctx.idGuia, printerId: printerId };
      if (ctx.formato === 'jefa') payload.formato = 'jefa';
      const r = await API.post('imprimirCostosGuia', payload);
      const ok = r && (r.ok === true || (r.data && r.data.ok === true));
      if (ok) {
        toast('🖨 Reporte enviado a impresora', 'ok');
        cerrarSelPrinterCostos();
      } else {
        const err = (r && (r.error || (r.data && r.data.error))) || 'Error desconocido';
        toast('⚠ Error: ' + err, 'error');
        if (btn) {
          btn.disabled = false;
          btn.style.opacity = '';
          btn.style.pointerEvents = '';
        }
      }
    } catch(e) {
      toast('⚠ Error: ' + (e.message || e), 'error');
      if (btn) {
        btn.disabled = false;
        btn.style.opacity = '';
        btn.style.pointerEvents = '';
      }
    }
  }

  // [v2.43.21] ──────── MODAL COSTOS UNIFICADO ─────────────────────────────
  // Estructura espejo del modal jefa: header / sub-header / body / footer.
  // Cero overrides — diseño 1:1 con el de precios.

  function _abrirModalCostosUnificado(op) {
    _opsInyectarKeyframes();
    _opsInyectarCSSModalCostosUnificado();
    let modal = document.getElementById('modalCostosGuiaUnif');
    if (!modal) {
      modal = document.createElement('div');
      modal.id = 'modalCostosGuiaUnif';
      modal.className = 'fixed inset-0 z-[1100] bg-black/70 backdrop-blur-md flex items-center justify-center p-4 hidden';
      modal.innerHTML = `
        <div class="bg-slate-900 border-2 border-emerald-500/50 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] flex flex-col">
          <div class="flex items-center gap-3 px-5 py-4 border-b border-slate-700/60">
            <span class="text-2xl">💰</span>
            <div class="flex-1 min-w-0">
              <div class="font-black text-emerald-300">Actualizar costos</div>
              <div class="text-xs text-slate-400" id="opsCostosSubtitle">Guía: —</div>
            </div>
            <button onclick="MOS.opsSalirModoCostos()" class="w-9 h-9 rounded-full bg-slate-800 hover:bg-rose-500/40 transition-all text-slate-300" title="Cerrar">✕</button>
          </div>
          <div class="px-5 pt-3 pb-3 border-b border-slate-800" id="opsCostosSubheader"></div>
          <div class="px-5 py-4 overflow-y-auto flex-1 ops-costos-scroll" id="opsCostosBody"></div>
          <div class="px-5 pt-3 pb-4 border-t border-slate-700/60 bg-slate-900 rounded-b-2xl" id="opsCostosFooter"></div>
        </div>`;
      document.body.appendChild(modal);
    }
    document.getElementById('opsCostosSubtitle').textContent =
      'Guía: ' + op.idGuia + ' · ' + (op.tipo || '').replace(/_/g,' ');
    modal.classList.remove('hidden');
    _renderModalCostosCompleto(op);
  }

  // Re-render completo del modal (subheader + body + footer). Usado tras
  // OCR, cambios de toggle, etc.
  function _renderModalCostosCompleto(op) {
    const st = S._costosGuiaState;
    if (!st) return;
    const sub = document.getElementById('opsCostosSubheader');
    const body = document.getElementById('opsCostosBody');
    const foot = document.getElementById('opsCostosFooter');
    if (!sub || !body || !foot) return;
    sub.innerHTML  = _renderCostosSubheader(op);
    body.innerHTML = _renderCostosBody(op);
    foot.innerHTML = _renderCostosFooter(op);
  }

  function _renderCostosSubheader(op) {
    const st = S._costosGuiaState;
    const tieneFoto = !!(st.foto && String(st.foto).trim());
    const enVuelo = !!(S._opsOcrEnVueloMap && S._opsOcrEnVueloMap[st.idGuia]);
    const yaCorrio = !!(S._opsOcrYaCorrido && S._opsOcrYaCorrido[st.idGuia]);
    const totLin = (st.lineas || []).length;
    const conCosto = (st.lineas || []).filter(l => parseFloat(l.precioUnitario) > 0 || (l.inputValue !== '' && l.inputValue != null && parseFloat(l.inputValue) > 0)).length;
    const pct = totLin > 0 ? Math.round((conCosto / totLin) * 100) : 0;
    // Chip OCR
    let chipOcr = '';
    if (!tieneFoto) {
      chipOcr = `<div id="opsChipOcrStatus" class="ops-chip-info">📷 Sin foto · escribe los costos manual</div>`;
    } else if (enVuelo) {
      chipOcr = `<div id="opsChipOcrStatus" class="ops-chip-cyan"><span style="animation:opsSpin 1s linear infinite;display:inline-block">🤖</span> Leyendo foto con IA…</div>`;
    } else {
      const cls = pct >= 80 ? 'ops-chip-ok' : pct >= 50 ? 'ops-chip-warn' : 'ops-chip-err';
      chipOcr = `<div id="opsChipOcrStatus" class="${cls}">🤖 ${yaCorrio ? 'OCR procesado' : 'Sin OCR'} · ${conCosto}/${totLin} (${pct}%)
        <button onclick="MOS.opsOcrComprobantePrepoblar('${_escapeHtml(op.idGuia)}')" title="${yaCorrio ? 'Re-procesar foto' : 'Procesar foto'}" class="ops-chip-btn">🔄</button>
      </div>`;
    }
    // Progreso visual
    const progCls = pct === 100 ? 'alm-v-prog-ok' : (conCosto > 0 ? 'alm-v-prog-parcial' : 'alm-v-prog-empty');
    const progreso = `<div id="costosGuiaProgreso" class="ops-prog-bar">
      <div class="ops-prog-fill" style="width:${pct}%"></div>
      <div class="ops-prog-text">
        <span class="${progCls}"><b>${pct === 100 ? '✓ ' : ''}${conCosto}/${totLin}</b> con costo · ${pct}%</span>
        ${pct < 100 ? `<span class="alm-v-progreso-faltan">⚠ faltan ${totLin - conCosto}</span>` : ''}
      </div>
    </div>`;
    // Toggles modo input + IGV
    const toggles = `<div class="ops-toggles-grid">
      <div class="ops-tg-group">
        <span class="ops-tg-lbl">Ingreso</span>
        <button onclick="MOS._costosGuiaSetMode('TOTAL')"    class="ops-tg-btn ${st.inputMode === 'TOTAL' ? 'is-active' : ''}">Total</button>
        <button onclick="MOS._costosGuiaSetMode('UNITARIO')" class="ops-tg-btn ${st.inputMode === 'UNITARIO' ? 'is-active' : ''}">Unit</button>
      </div>
      <div class="ops-tg-group">
        <span class="ops-tg-lbl">IGV</span>
        <button onclick="MOS._costosGuiaSetIgv('INCLUIDO')" class="ops-tg-btn ${st.igvMode === 'INCLUIDO' ? 'is-active' : ''}">Incluido</button>
        <button onclick="MOS._costosGuiaSetIgv('SIN_IGV')"  class="ops-tg-btn ${st.igvMode === 'SIN_IGV'  ? 'is-active' : ''}">Sin IGV</button>
      </div>
      <label class="ops-tg-check">
        <input type="checkbox" id="costosGuiaUpdMaster" checked>
        <span>Actualizar catálogo</span>
      </label>
    </div>`;
    return `<div class="flex flex-col gap-2">${chipOcr}${progreso}${toggles}</div>`;
  }

  function _renderCostosBody(op) {
    const st = S._costosGuiaState;
    const lineas = (st && st.lineas) || [];
    if (!lineas.length) {
      return `<div class="text-center py-12 text-slate-400">
        <div class="text-4xl mb-3 opacity-50">📦</div>
        <p class="text-sm">Sin líneas registradas en esta guía</p>
      </div>`;
    }
    return `<input type="hidden" id="costosGuiaInfo" value="${_escapeHtml(op.idGuia)}">
      <div class="flex flex-col gap-2">${_renderCostosLineasInner(op)}</div>`;
  }

  // Solo las cards de productos — reutiliza la lógica de filas existente
  function _renderCostosLineasInner(op) {
    const st = S._costosGuiaState;
    const lineas = st.lineas || [];
    return lineas.map((l, i) => _renderCostosLineaItem(op, l, i, st)).join('');
  }

  function _renderCostosLineaItem(op, l, i, st) {
    const cant = parseFloat(l.cantidad) || 0;
    const brutoUnit = _costosGuiaCalcularBruto(l, st);
    const netoUnit  = brutoUnit / (1 + _IGV_RATE);
    const desc = _escapeHtml(String(l.descripcion || l.codigoProducto || l.codigoBarra || ''));
    const cod  = _escapeHtml(String(l.codigoBarra || l.codigoProducto || ''));
    const equivBadge = l.esEquivalencia ? '<span class="alm-v-equiv-badge">EQUIV</span>' : '';
    const placeholder = st.inputMode === 'TOTAL' ? 'Total' : 'Unit';
    const helper = brutoUnit > 0
      ? `<span class="alm-v-costo-helper-bruto">S/ ${brutoUnit.toFixed(4)}</span><span class="alm-v-costo-helper-u">/u</span>${netoUnit > 0 ? `<div class="alm-v-costo-helper-neto">neto S/ ${netoUnit.toFixed(4)}</div>` : ''}`
      : '<span class="alm-v-costo-helper-empty">sin costo</span>';
    const _ocrCorrido = S._opsOcrYaCorrido && S._opsOcrYaCorrido[st.idGuia];
    const _conFoto = st.foto && String(st.foto).trim() !== '';
    const _ocrFallo = !brutoUnit && _ocrCorrido && _conFoto;
    const marcaIni = brutoUnit > 0
      ? '<span title="Costo registrado" class="alm-v-marca-ok">✓</span>'
      : (_ocrFallo
          ? '<span title="OCR no pudo leer este ítem" class="alm-v-marca-ocr">🤖⚠</span>'
          : '<span title="Falta costo" class="alm-v-marca-falta">⚠</span>');
    const faltaCls = brutoUnit > 0 ? '' : ' alm-v-costo-line--falta';
    const ocrNoEntendioBadge = _ocrFallo
      ? '<div class="ops-badge-ocr-fail">🤖 OCR no entendió — escribe el costo a mano</div>'
      : '';
    // Bloque IMPACTO (margen actual + sugerido)
    let margenInfoHtml = '';
    try {
      const codStr = String(l.codigoBarra || l.codigoProducto || '').trim();
      if (codStr) {
        const prodCat = (S.productos || []).find(p => String(p.codigoBarra || '').trim() === codStr);
        if (prodCat) {
          const ventaActual = parseFloat(prodCat.precioVenta) || 0;
          let margenObjetivo = null;
          const oMargRaw = prodCat.margenPct;
          if (oMargRaw !== '' && oMargRaw != null && !isNaN(parseFloat(oMargRaw))) {
            margenObjetivo = parseFloat(oMargRaw);
          } else if (prodCat.categoria) {
            const cat = (S.categorias || []).find(c => c.nombre === prodCat.categoria);
            if (cat && cat.margenPct !== '' && cat.margenPct != null && !isNaN(parseFloat(cat.margenPct))) {
              margenObjetivo = parseFloat(cat.margenPct);
            }
          }
          const margenConCostoNuevo = (ventaActual > 0 && brutoUnit > 0)
            ? ((ventaActual - brutoUnit) / ventaActual) * 100 : null;
          const ventaSugerida = (margenObjetivo !== null && brutoUnit > 0 && margenObjetivo > 0 && margenObjetivo < 99)
            ? brutoUnit / (1 - margenObjetivo / 100) : null;
          const colorM = (m) => m === null ? '#9ca3af' : m < 10 ? '#f87171' : m < 20 ? '#fbbf24' : '#34d399';
          if (ventaActual > 0 || margenObjetivo !== null) {
            let filaMargen = '';
            if (margenObjetivo !== null) {
              const diff = (margenConCostoNuevo !== null) ? (margenConCostoNuevo - margenObjetivo) : null;
              const alerta = (diff !== null && diff < -2) ? ' ⚠' : '';
              filaMargen = `<div class="alm-v-impacto-fila">
                <span class="alm-v-impacto-label">Margen</span>
                <span class="alm-v-impacto-actual"><b>${margenObjetivo.toFixed(1)}%</b><span class="alm-v-impacto-hint">objetivo</span></span>
                <span class="alm-v-impacto-flecha">→</span>
                <span class="alm-v-impacto-nuevo"><b style="color:${colorM(margenConCostoNuevo)};${margenConCostoNuevo !== null ? 'animation:opsNumPulse .4s cubic-bezier(.34,1.56,.64,1)' : ''}">${margenConCostoNuevo !== null ? margenConCostoNuevo.toFixed(1) + '%' : '— sin costo'}</b>${alerta ? `<span style="color:#f87171">${alerta}</span>` : ''}</span>
              </div>`;
            } else if (margenConCostoNuevo !== null) {
              filaMargen = `<div class="alm-v-impacto-fila">
                <span class="alm-v-impacto-label">Margen</span>
                <span class="alm-v-impacto-actual" style="opacity:.7"><b>—</b><span class="alm-v-impacto-hint">sin objetivo</span></span>
                <span class="alm-v-impacto-flecha">→</span>
                <span class="alm-v-impacto-nuevo"><b style="color:${colorM(margenConCostoNuevo)};animation:opsNumPulse .4s cubic-bezier(.34,1.56,.64,1)">${margenConCostoNuevo.toFixed(1)}%</b><span class="alm-v-impacto-hint" title="Si aceptas en precios, queda como objetivo">se grabará ⓘ</span></span>
              </div>`;
            } else if (ventaActual > 0) {
              const costoCat = parseFloat(prodCat.precioCosto) || 0;
              const margenCat = (costoCat > 0) ? ((ventaActual - costoCat) / ventaActual) * 100 : null;
              if (margenCat !== null) {
                filaMargen = `<div class="alm-v-impacto-fila">
                  <span class="alm-v-impacto-label">Margen</span>
                  <span class="alm-v-impacto-actual"><b style="color:${colorM(margenCat)}">${margenCat.toFixed(1)}%</b><span class="alm-v-impacto-hint">actual (catálogo)</span></span>
                  <span class="alm-v-impacto-hint" style="margin-left:auto;opacity:.5">escribe el costo →</span>
                </div>`;
              }
            }
            let filaPrecio = '';
            if (ventaActual > 0) {
              let bloqueSugerido = '';
              if (ventaSugerida !== null) {
                const diffPct = ((ventaSugerida - ventaActual) / ventaActual) * 100;
                const signo = diffPct >= 0 ? '+' : '';
                const colorDiff = Math.abs(diffPct) < 1 ? '#94a3b8' : (diffPct > 0 ? '#fbbf24' : '#34d399');
                bloqueSugerido = `<span class="alm-v-impacto-flecha">→</span>
                  <span class="alm-v-impacto-nuevo"><b style="animation:opsNumPulse .4s cubic-bezier(.34,1.56,.64,1)">S/ ${ventaSugerida.toFixed(2)}</b><span class="alm-v-impacto-hint" style="color:${colorDiff}">${signo}${diffPct.toFixed(1)}%</span></span>`;
              } else if (margenConCostoNuevo !== null) {
                bloqueSugerido = `<span class="alm-v-impacto-flecha">=</span>
                  <span class="alm-v-impacto-nuevo"><b>S/ ${ventaActual.toFixed(2)}</b><span class="alm-v-impacto-hint">mantener</span></span>`;
              }
              filaPrecio = `<div class="alm-v-impacto-fila">
                <span class="alm-v-impacto-label">Precio</span>
                <span class="alm-v-impacto-actual"><b>S/ ${ventaActual.toFixed(2)}</b><span class="alm-v-impacto-hint">actual</span></span>
                ${bloqueSugerido || '<span class="alm-v-impacto-hint" style="margin-left:auto;opacity:.5">escribe el costo →</span>'}
              </div>`;
            }
            margenInfoHtml = `<div class="alm-v-impacto">${filaMargen}${filaPrecio}</div>`;
          }
        }
      }
    } catch(_) {}
    return `<div class="alm-v-costo-line${faltaCls}" style="animation-delay:${Math.min(i,12)*30}ms">
      <div class="alm-v-costo-head">
        <span id="costoGuiaMarca_${i}" class="alm-v-costo-marca">${marcaIni}</span>
        <div class="alm-v-costo-head-text">
          <div class="alm-v-costo-desc">${desc}${equivBadge}</div>
          <div class="alm-v-costo-cod">▌ ${cod}</div>
        </div>
      </div>
      <div class="alm-v-costo-controls">
        <div class="alm-v-costo-cant">${cant}u</div>
        <input type="number" step="0.01" min="0" class="alm-v-costo-input"
               value="${l.inputValue || ''}"
               oninput="MOS._costosGuiaUpdLinea(${i}, this.value)"
               placeholder="${placeholder}">
        <div class="alm-v-costo-helper" id="costoGuiaSubtot_${i}">${helper}</div>
      </div>
      ${ocrNoEntendioBadge}
      ${margenInfoHtml}
    </div>`;
  }

  function _renderCostosFooter(op) {
    const st = S._costosGuiaState;
    const lineas = (st && st.lineas) || [];
    let totalBruto = 0;
    lineas.forEach(l => { totalBruto += _costosGuiaCalcularBruto(l, st) * (parseFloat(l.cantidad) || 0); });
    const totalNeto = totalBruto / (1 + _IGV_RATE);
    return `<div class="ops-costos-totales">
      <span class="ops-tot-lbl">Neto</span> <b id="costosGuiaTotalNeto">S/ ${totalNeto.toFixed(2)}</b>
      <span class="ops-tot-sep">·</span>
      <span class="ops-tot-lbl">IGV</span>  <b id="costosGuiaTotalIgv">S/ ${(totalBruto - totalNeto).toFixed(2)}</b>
      <span class="ops-tot-sep">·</span>
      <span class="ops-tot-lbl ops-tot-bruto">Total</span> <b id="costosGuiaTotalBruto" class="ops-tot-bruto">S/ ${totalBruto.toFixed(2)}</b>
    </div>
    <div class="ops-costos-actions">
      <button onclick="MOS.guardarCostosEImprimirJefa()" class="ops-cta-jefa ops-btn-primary" title="Guarda costos y manda el ticket a la jefa para que decida precios">
        💾📋 Guardar e imprimir comprobante jefa
      </button>
      <button onclick="MOS.opsOcrComprobantePrepoblar('${_escapeHtml(op.idGuia)}')" class="ops-btn-ghost" title="Re-procesar foto con OCR">🔄 Re-OCR</button>
    </div>`;
  }

