  // [v41.21] Conmutar el modo costos dentro del MISMO overlay del voucher
  function opsEntrarModoCostos(fuente, idGuia) {
    _opsBeep('tac');
    // Inicializar state ANTES de abrir el modal (necesita las líneas)
    const op = _findOpByKey(fuente + '_' + idGuia);
    if (!op) { toast('Operación no encontrada', 'error'); return; }
    S._opsModoCostos = true;
    _opsCostosInitState(op);
    _abrirModalCostosUnificado(op);
    // [v2.43.0+2] AUTO-OCR: si la guía tiene foto y ninguna línea tiene costo
    // todavía, disparar OCR automático al entrar (sin botón manual).
    // Si el admin ya tocó costos antes, NO sobreescribir.
    setTimeout(() => {
      try {
        const st = S._costosGuiaState;
        if (!st || String(st.idGuia) !== String(idGuia)) return;
        if (!st.foto || String(st.foto).trim() === '') return;  // sin foto, nada que OCR
        const algunoTieneCosto = (st.lineas || []).some(l => parseFloat(l.precioUnitario) > 0 || (l.inputValue !== '' && l.inputValue !== null));
        if (algunoTieneCosto) return; // admin ya tocó, no auto-overrite
        if (S._opsOcrYaCorrido && S._opsOcrYaCorrido[idGuia]) return; // ya corrió en esta sesión
        // [v2.43.20] NO seteamos _opsOcrYaCorrido aquí — eso ahora lo hace el
        // finally de opsOcrComprobantePrepoblar. Sí seteamos enVuelo para que
        // el chip se actualice a 'Leyendo IA...'.
        S._opsOcrEnVueloMap = S._opsOcrEnVueloMap || {};
        S._opsOcrEnVueloMap[idGuia] = true;
        _opsActualizarChipOcr(idGuia);
        // [v2.43.2] Feedback visual + sonoro elegante para que se sienta vivo
        _opsBeep('shimmer');
        _opsMostrarBadgeOcrAuto('procesando');
        opsOcrComprobantePrepoblar(idGuia).then(() => {
          _opsMostrarBadgeOcrAuto('listo');
          _opsBeep('ok');
        }).catch(() => {
          _opsMostrarBadgeOcrAuto('error');
          _opsBeep('warn');
        });
      } catch(e) { console.warn('[auto-OCR costos]', e); }
    }, 600); // delay 600ms para que el overlay termine de renderizar
  }

  // [v2.43.2] Badge flotante elegante para indicar estado del auto-OCR.
  // 'procesando' = anillo girando con shimmer · 'listo' = check verde con pulse
  // · 'error' = X roja · todos se auto-ocultan tras 3s salvo 'procesando' que
  // dura hasta que termine el fetch.
  function _opsMostrarBadgeOcrAuto(estado) {
    try {
      let badge = document.getElementById('opsBadgeOcrAuto');
      if (!badge) {
        badge = document.createElement('div');
        badge.id = 'opsBadgeOcrAuto';
        badge.style.cssText = 'position:fixed;top:18px;right:18px;z-index:9999;padding:10px 14px;border-radius:14px;font-size:13px;font-weight:700;font-family:system-ui,-apple-system,sans-serif;display:flex;align-items:center;gap:8px;box-shadow:0 10px 30px -8px rgba(0,0,0,.4);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);animation:opsBadgeIn .3s cubic-bezier(.34,1.56,.64,1) both;';
        document.body.appendChild(badge);
      }
      if (estado === 'procesando') {
        badge.style.background = 'linear-gradient(135deg,rgba(34,211,238,.95),rgba(8,145,178,.95))';
        badge.style.color = '#fff';
        badge.innerHTML = '<span style="display:inline-block;animation:opsSpin 1s linear infinite">🤖</span> Leyendo factura...';
      } else if (estado === 'listo') {
        badge.style.background = 'linear-gradient(135deg,rgba(16,185,129,.95),rgba(5,150,105,.95))';
        badge.style.color = '#fff';
        badge.innerHTML = '<span style="display:inline-block;animation:opsBadgeCheck .5s cubic-bezier(.34,1.56,.64,1)">✓</span> OCR procesado';
        setTimeout(() => _opsOcultarBadgeOcrAuto(), 3000);
      } else if (estado === 'error') {
        badge.style.background = 'linear-gradient(135deg,rgba(239,68,68,.95),rgba(220,38,38,.95))';
        badge.style.color = '#fff';
        badge.innerHTML = '⚠ OCR falló — ajusta manual';
        setTimeout(() => _opsOcultarBadgeOcrAuto(), 4000);
      }
    } catch(_){}
  }
  function _opsOcultarBadgeOcrAuto() {
    try {
      const badge = document.getElementById('opsBadgeOcrAuto');
      if (badge) {
        badge.style.animation = 'opsBadgeOut .25s ease forwards';
        setTimeout(() => { try { badge.remove(); } catch(_){} }, 280);
      }
    } catch(_){}
  }

  // [v2.43.8] Handlers de las 2 cards de origen del overlay de costos.
  // El admin elige explícitamente si quiere usar OCR de foto o llenar manual.
  // Sigue el mismo patrón visual/UX que el modal jefa (📷 foto · ✏️ manual).
  function costosUsarOrigenFoto(fuente, idGuia) {
    try { _opsBeep('tac'); } catch(_){}
    const st = S._costosGuiaState;
    if (!st) return;
    if (!st.foto || !String(st.foto).trim()) {
      try { _opsBeep('warn'); } catch(_){}
      try { _toast?.('warn', '📷 Esta guía no tiene foto. Sube una desde WH primero.'); } catch(_){}
      return;
    }
    S._costosModoOrigen = 'foto';
    // Disparar / re-disparar OCR — opsOcrComprobantePrepoblar ya maneja el feedback visual
    opsOcrComprobantePrepoblar(idGuia);
  }
  async function costosUsarOrigenManual() {
    try { _opsBeep('tac'); } catch(_){}
    const st = S._costosGuiaState;
    if (!st) return;
    // Confirmar si hay costos ya tipeados — no perder data por accidente
    const algunoConDato = (st.lineas || []).some(l => l.inputValue !== '' && l.inputValue != null && parseFloat(l.inputValue) > 0);
    if (algunoConDato) {
      // [Lote4 · M3-MOS] _modalConfirm en vez de confirm() nativo
      if (!await _modalConfirm('Hay costos ya escritos. ¿Vaciar todo para empezar manual?', { warning: true, titulo: 'Vaciar costos' })) return;
    }
    // Vaciar todos los inputValue y limpiar sugerencias
    (st.lineas || []).forEach(l => { l.inputValue = ''; l._sugerencia = null; });
    S._costosModoOrigen = 'manual';
    try { _opsBeep('ok'); } catch(_){}
    try { _toast?.('info', '✏️ Modo manual · escribe cada costo abajo'); } catch(_){}
    // Re-render del voucher actual
    try {
      const op = S._costosGuiaState && _findOpByKey(S._costosGuiaState.fuente + '_' + S._costosGuiaState.idGuia);
      if (op) {
        const cont = $('almOpsDetalleContent');
        if (cont) cont.innerHTML = _renderVoucher(op, 0);
      }
    } catch(e) { console.warn('[costosUsarOrigenManual] re-render falló:', e); }
  }

  // [v2.43.0+2] CTA combinado: guardar costos + abrir picker de impresora +
  // imprimir ticket para jefa, todo en una sola acción.
  // [v2.43.2] OPTIMISTA: toast inmediato + sonido al click. Si falla, se nota
  // por el toast de error que ya emite guardarCostosGuia internamente.
  async function guardarCostosEImprimirJefa() {
    const st = S._costosGuiaState;
    if (!st) return;
    _opsBeep('tac');
    try { _toast?.('info', '💾 Guardando costos...'); } catch(_){}
    try {
      await guardarCostosGuia();
      _opsBeep('ok');
      // Esperar un tick para que el guardado persista antes de imprimir
      await new Promise(r => setTimeout(r, 300));
      abrirSelPrinterJefa(st.fuente, st.idGuia);
    } catch(e) {
      console.error('[guardarCostosEImprimirJefa]', e);
      _opsBeep('warn');
      try { _toast?.('error', '❌ Error al guardar costos: ' + (e.message || e)); } catch(_){}
    }
  }
  function opsSalirModoCostos() {
    S._opsModoCostos = false;
    // [v2.43.21] Cerrar el modal unificado de costos
    const modal = document.getElementById('modalCostosGuiaUnif');
    if (modal) modal.classList.add('hidden');
    // Por compat (overlay viejo si quedó abierto en algún flow)
    const overlay = $('almOpsDetalleOverlay');
    if (overlay) overlay.classList.remove('is-costos-mode');
    // Re-render del overlay viejo si tiene la guía abierta en lectura
    const op = S._costosGuiaState && _findOpByKey(S._costosGuiaState.fuente + '_' + S._costosGuiaState.idGuia);
    if (op) {
      const cont = $('almOpsDetalleContent');
      if (cont) cont.innerHTML = _renderVoucher(op, 0);
    }
  }

  // Inicializa S._costosGuiaState para una op + carga líneas en cache
  function _opsCostosInitState(op) {
    const k = op.fuente + '_' + op.idGuia;
    const cached = (S._opsDetCache[k] && S._opsDetCache[k].lineas) || op.lineas || [];
    // Hidratar inputValue desde precioUnitario existente
    const lineas = cached.map(l => {
      const bruto = parseFloat(l.precioUnitario) || 0;
      return {
        ...l,
        inputValue: bruto > 0 ? +(bruto * (parseFloat(l.cantidad) || 1)).toFixed(2) : '',
        _sugerencia: null
      };
    });
    S._costosGuiaState = {
      idGuia: op.idGuia,
      fuente: op.fuente,
      lineas,
      foto: op.foto || '',
      idProveedor: op.idProveedor || '',
      nombreProveedor: op.nombreProveedor || op.idProveedor || '',
      inputMode: 'TOTAL',
      igvMode: 'INCLUIDO'
    };
  }

  // [v41.16] Overlay para ver foto de la guía en grande
  function abrirFotoOverlay(url) {
    if (!url) return;
    _opsBeep('tac');
    let overlay = $('almFotoOverlay');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.id = 'almFotoOverlay';
      overlay.className = 'alm-foto-overlay';
      overlay.onclick = (e) => {
        if (e.target.id === 'almFotoOverlay' || e.target.classList.contains('alm-foto-close')) {
          overlay.classList.add('hidden');
        }
      };
      document.body.appendChild(overlay);
    }
    overlay.innerHTML = `
      <button class="alm-foto-close" title="Cerrar">✕</button>
      <img class="alm-foto-grande" src="${_escapeHtml(url)}" alt="Foto de la guía">
      <a class="alm-foto-link" href="${_escapeHtml(url)}" target="_blank" rel="noopener">↗ Abrir en pestaña nueva</a>`;
    overlay.classList.remove('hidden');
  }

  // ── Llenar costos de guía (con foto de factura) ──
  // Toggles del modal:
  //   inputMode: 'TOTAL'     → el usuario escribe el total de la línea (factura típica)
  //              'UNITARIO'  → el usuario escribe el precio por unidad
  //   igvMode:   'INCLUIDO'  → el valor ingresado YA incluye IGV
  //              'SIN_IGV'   → el valor ingresado NO incluye IGV (se le agrega)
  // Política: precioCosto siempre se guarda CON IGV (bruto). Si el usuario
  // declaró Sin IGV, le sumamos el IGV antes de guardar.
  // Defaults: TOTAL + INCLUIDO (formato más común en facturas).
  S._costosGuiaState = S._costosGuiaState || {
    idGuia: null, fuente: null, lineas: [], foto: '',
    inputMode: 'TOTAL', igvMode: 'INCLUIDO'
  };
  const _IGV_RATE = 0.18;

  // Convierte el valor que tipeó el usuario en precio UNITARIO BRUTO (con IGV).
  // Es el valor que se guarda como precioCosto.
  function _costosGuiaCalcularBruto(linea, st) {
    const v = parseFloat(linea.inputValue) || 0;
    if (v <= 0) return 0;
    const cant = parseFloat(linea.cantidad) || 1;
    // 1) Si el usuario declaró "Sin IGV", el valor que metió es neto → agregarle IGV
    const valorConIgv = st.igvMode === 'INCLUIDO' ? v : v * (1 + _IGV_RATE);
    // 2) Si era el TOTAL de la línea, dividir entre la cantidad
    return st.inputMode === 'TOTAL' ? (valorConIgv / cant) : valorConIgv;
  }

  // [v41.21] Redirigir abrirCostosGuia al overlay del voucher en modo costos.
  // Mantengo la firma por compat con el botón 💰 viejo si lo llama otro lugar.
  async function abrirCostosGuia(idGuia, fuente) {
    if (!idGuia || !fuente) return;
    opsEntrarModoCostos(fuente, idGuia);
  }

  // Función vieja (modal split) — mantenida como _legacy por si algún code path
  // antiguo la llama. NO se invoca desde el flow nuevo.
  async function abrirCostosGuiaLegacy(idGuia, fuente) {
    if (!idGuia) return;
    let foto = '', idProveedor = '', nombreProveedor = '';
    const data = S._opsData || {};
    (data.porDia || []).forEach(d => d.operaciones.forEach(op => {
      if (op.idGuia === idGuia && op.fuente === fuente) {
        foto = op.foto || '';
        idProveedor = op.idProveedor || '';
        nombreProveedor = op.nombreProveedor || op.idProveedor || '';
      }
    }));
    // Mantener defaults TOTAL + INCLUIDO en cada apertura
    S._costosGuiaState = {
      idGuia, fuente, lineas: [], foto, idProveedor, nombreProveedor,
      inputMode: 'TOTAL', igvMode: 'INCLUIDO'
    };
    $('costosGuiaInfo').textContent = idGuia + (nombreProveedor ? ' · ' + nombreProveedor : '');
    // [v41.20] Poblar foto en el lado izquierdo del overlay split
    const fImg = $('cguFotoImg');
    const fEmp = $('cguFotoEmpty');
    if (fImg && fEmp) {
      if (foto) {
        fImg.style.display = 'block';
        fImg.src = foto;
        fEmp.style.display = 'none';
        S._cguFotoUrl = foto;
        fImg.onclick = () => abrirFotoOverlay(foto);
      } else {
        fImg.style.display = 'none';
        fEmp.style.display = 'flex';
        S._cguFotoUrl = '';
      }
    }
    // El botón Pantalla completa lee de S._cguFotoUrl
    const fBtn = $('cguFotoFullBtn');
    if (fBtn) fBtn.onclick = () => abrirFotoOverlay(S._cguFotoUrl || '');
    // Ocultar sección sugerencias al abrir (queda inline por producto)
    _ocultarSeccionSugerencias && _ocultarSeccionSugerencias();
    const body = $('costosGuiaBody');
    openModal('modalCostosGuia');

    // Helper: inicializa inputValue y pinta. Reusado por prefetch y fetch.
    const _hidratarLineas = (lineas) => {
      lineas.forEach(l => {
        const bruto = parseFloat(l.precioUnitario) || 0;
        l.inputValue = bruto > 0 ? +(bruto * (parseFloat(l.cantidad) || 1)).toFixed(2) : '';
      });
      S._costosGuiaState.lineas = lineas;
      _renderCostosGuiaBody();
    };

    // 🚀 Si hay prefetch fresco (<5 min) → pintar INSTANTÁNEO sin esperar red.
    const pfKey = fuente + '_' + idGuia;
    const pf = S._costosGuiaPrefetch && S._costosGuiaPrefetch[pfKey];
    const pfFresco = pf && pf.lineas && (Date.now() - (pf.ts || 0) < 5 * 60 * 1000);
    if (pfFresco) {
      _hidratarLineas(pf.lineas.map(l => ({ ...l })));
    } else {
      body.innerHTML = `
        <div class="liq-skel-stage">
          <div class="liq-skel-row"></div>
          <div class="liq-skel-row" style="animation-delay:.12s"></div>
          <div class="liq-skel-row" style="animation-delay:.24s"></div>
          <div class="liq-skel-stage-hint">
            <span class="liq-skel-hint-dot"></span> Cargando líneas de la guía...
          </div>
        </div>`;
    }

    // Fetch fresco siempre (actualiza prefetch + corrige si cambió algo).
    // Si ya pintamos desde prefetch, esto es refresh silencioso en background.
    try {
      const r = await API.get('getOperacionDetalle', { fuente, idGuia });
      const lineas = (r && r.lineas) || [];
      if (S._costosGuiaPrefetch) S._costosGuiaPrefetch[pfKey] = { lineas, ts: Date.now() };
      // Solo re-pintar si el modal sigue en esta guía (user no cerró/cambió)
      if (S._costosGuiaState && S._costosGuiaState.idGuia === idGuia) {
        _hidratarLineas(lineas.map(l => ({ ...l })));
      }
    } catch(e) {
      if (!pfFresco) body.innerHTML = `<div class="text-xs text-rose-400 py-4">Error: ${e.message}</div>`;
    }
  }

  function _costosGuiaSetMode(modo) {
    const st = S._costosGuiaState;
    if (st.inputMode === modo) return;
    st.lineas.forEach(l => {
      const brutoUnit = _costosGuiaCalcularBruto(l, st);
      const cant = parseFloat(l.cantidad) || 1;
      const valorBase = st.igvMode === 'INCLUIDO' ? brutoUnit : (brutoUnit / (1 + _IGV_RATE));
      l.inputValue = brutoUnit > 0 ? +(modo === 'TOTAL' ? valorBase * cant : valorBase).toFixed(2) : '';
    });
    st.inputMode = modo;
    _costosGuiaReRender();
  }

  function _costosGuiaSetIgv(modo) {
    const st = S._costosGuiaState;
    if (st.igvMode === modo) return;
    st.lineas.forEach(l => {
      const brutoUnit = _costosGuiaCalcularBruto(l, st);
      const cant = parseFloat(l.cantidad) || 1;
      const valorBase = modo === 'INCLUIDO' ? brutoUnit : (brutoUnit / (1 + _IGV_RATE));
      l.inputValue = brutoUnit > 0 ? +(st.inputMode === 'TOTAL' ? valorBase * cant : valorBase).toFixed(2) : '';
    });
    st.igvMode = modo;
    _costosGuiaReRender();
  }

  // [v2.43.21] Re-render según contexto: modo costos usa el modal unificado
  // nuevo; modal viejo (legacy) re-pinta el body del modal antiguo.
  function _costosGuiaReRender() {
    if (S._opsModoCostos) {
      const st = S._costosGuiaState;
      const op = st && _findOpByKey(st.fuente + '_' + st.idGuia);
      if (op && document.getElementById('modalCostosGuiaUnif')) {
        _renderModalCostosCompleto(op);
        return;
      }
      // Fallback al overlay viejo (compat)
      const cont = $('almOpsDetalleContent');
      if (op && cont) cont.innerHTML = _renderVoucher(op, 0);
    } else {
      _renderCostosGuiaBody();
    }
  }

  function _renderCostosGuiaBody() {
    const body = $('costosGuiaBody');
    if (!body) return;
    const st = S._costosGuiaState;
    const { lineas, foto, inputMode, igvMode } = st;
    if (!lineas.length) {
      body.innerHTML = '<div class="text-xs text-slate-500 italic py-4">Esta guía no tiene líneas registradas.</div>';
      return;
    }
    // [v41.20] Nuevo layout: cada línea es una card individual con su propio
    // slot para sugerencia inline (slide-down al detectar costo llenado).
    // La foto ya no va embebida acá (vive en el lado izquierdo del overlay
    // split). En mobile (<820px) el overlay hace stack vertical y la foto
    // va arriba — igualmente cubierto sin duplicar.
    const togglesHtml = `
      <div class="alm-cu-toggles">
        <div class="alm-cu-toggle-group">
          <span>Ingreso:</span>
          <button onclick="MOS._costosGuiaSetMode('TOTAL')"
                  class="alm-cu-seg-btn ${inputMode === 'TOTAL' ? 'active' : ''}">Total línea</button>
          <button onclick="MOS._costosGuiaSetMode('UNITARIO')"
                  class="alm-cu-seg-btn ${inputMode === 'UNITARIO' ? 'active' : ''}">Por unidad</button>
        </div>
        <div class="alm-cu-toggle-group">
          <span>IGV:</span>
          <button onclick="MOS._costosGuiaSetIgv('INCLUIDO')"
                  class="alm-cu-seg-btn ${igvMode === 'INCLUIDO' ? 'active' : ''}">Incluido (18%)</button>
          <button onclick="MOS._costosGuiaSetIgv('SIN_IGV')"
                  class="alm-cu-seg-btn ${igvMode === 'SIN_IGV' ? 'active' : ''}">Sin IGV</button>
        </div>
      </div>`;

    let totalBruto = 0, totalNeto = 0;
    const placeholderIn = inputMode === 'TOTAL' ? 'Total' : 'P. unit.';

    const filasHtml = lineas.map((l, i) => {
      const cant = parseFloat(l.cantidad) || 0;
      const brutoUnit = _costosGuiaCalcularBruto(l, st);
      const netoUnit  = brutoUnit / (1 + _IGV_RATE);
      const subBruto  = brutoUnit * cant;
      totalBruto += subBruto;
      totalNeto  += netoUnit * cant;
      const equivBadge = l.esEquivalencia ? ' <span style="font-size:9px;color:#a855f7;background:rgba(168,85,247,.1);padding:1px 5px;border-radius:999px">EQUIV</span>' : '';
      const helperTxt = brutoUnit > 0
        ? `<div><span class="alm-cu-line-helper-bruto">S/ ${brutoUnit.toFixed(4)}</span>/u</div>
           <div style="opacity:.65">neto S/ ${netoUnit.toFixed(4)}</div>`
        : '<span style="opacity:.4">—</span>';
      // Slot vacío para sugerencia — se rellena al cambiar el costo.
      // Estado preservado entre renders en S._costosGuiaState.lineas[i]._sugerencia
      const sugCache = l._sugerencia;
      const sugHtml = sugCache
        ? _renderSugerenciaInline(i, sugCache)
        : '';
      const sugOpen = sugCache ? ' is-open' : '';
      const marcaIni = brutoUnit > 0
        ? '<span title="Costo registrado" style="color:#34d399;font-weight:700">✓</span>'
        : '<span title="Falta costo" style="color:#f87171;font-weight:700;animation:pulse 1.6s infinite">⚠</span>';
      const faltaCls = brutoUnit > 0 ? '' : ' alm-cu-line--falta';
      return `<div class="alm-cu-line${faltaCls}">
        <div class="alm-cu-line-row">
          <div>
            <div class="alm-cu-line-desc">
              <span id="costoGuiaMarca_${i}" style="margin-right:6px;display:inline-block;min-width:14px">${marcaIni}</span>
              ${l.descripcion}${equivBadge}
            </div>
            <div class="alm-cu-line-cod">▌ ${l.codigoProducto || '—'}</div>
          </div>
          <div class="alm-cu-line-cant">${cant}u</div>
          <div>
            <input type="number" step="0.01" min="0" class="alm-cu-input"
                   value="${l.inputValue || ''}"
                   oninput="MOS._costosGuiaUpdLinea(${i}, this.value)"
                   onblur="MOS._costosGuiaSugerirDebounce(${i})"
                   placeholder="${placeholderIn}">
          </div>
          <div class="alm-cu-line-helper" id="costoGuiaSubtot_${i}">${helperTxt}</div>
        </div>
        <div class="alm-cu-sug${sugOpen}" id="sugSlot_${i}">${sugHtml}</div>
      </div>`;
    }).join('');

    // [v2.41.54] Header con progreso "X de Y con costo" + autoguardado hint
    const totalLin = lineas.length;
    let conCostoIni = 0;
    lineas.forEach(l => { if (_costosGuiaCalcularBruto(l, st) > 0) conCostoIni++; });
    const progresoIni = totalLin > 0 ? Math.round((conCostoIni / totalLin) * 100) : 0;
    const completoIni = conCostoIni === totalLin;
    const progresoHtml = `
      <div id="costosGuiaProgreso" style="font-size:11px;display:flex;align-items:center;gap:4px;flex-wrap:wrap">
        <span style="color:${completoIni ? '#34d399' : (conCostoIni > 0 ? '#fbbf24' : '#94a3b8')};font-weight:800">
          ${completoIni ? '✓ ' : ''}${conCostoIni}/${totalLin} producto${totalLin === 1 ? '' : 's'} con costo
        </span>
        <span style="color:#64748b;margin-left:6px">· ${progresoIni}%</span>
        ${!completoIni ? '<span style="color:#f87171;margin-left:6px;font-size:10px">⚠ faltan ' + (totalLin - conCostoIni) + '</span>' : ''}
      </div>
      <div style="font-size:9px;color:#64748b;font-style:italic;margin-top:2px">
        💾 Autoguardado activo · los costos se persisten al instante
      </div>`;

    body.innerHTML = `${togglesHtml}
      ${progresoHtml}
      ${filasHtml}
      <div class="alm-cu-totales">
        <div><span style="color:#94a3b8">Neto:</span> <b id="costosGuiaTotalNeto">S/ ${totalNeto.toFixed(2)}</b></div>
        <div><span style="color:#94a3b8">IGV:</span>  <b id="costosGuiaTotalIgv">S/ ${(totalBruto - totalNeto).toFixed(2)}</b></div>
        <div><span style="color:#fbbf24">Total:</span> <b id="costosGuiaTotalBruto">S/ ${totalBruto.toFixed(2)}</b></div>
      </div>`;
  }

  // [v41.20] Render de la sugerencia inline debajo de una línea de costo
  function _renderSugerenciaInline(idx, sug) {
    const actual = parseFloat(sug.precioVentaActual) || 0;
    const sugVal = sug._precioEditado != null ? sug._precioEditado : (parseFloat(sug.precioVentaSugerido) || 0);
    // [v2.41.54] Default OFF — admin decide manualmente si aplicar.
    const seleccionado = sug._seleccionado === true;
    let deltaHtml = '';
    if (actual <= 0) {
      deltaHtml = '<span class="alm-cu-sug-delta new">NUEVO</span>';
    } else {
      const deltaPct = ((sugVal - actual) / actual) * 100;
      const sign = deltaPct >= 0 ? '+' : '';
      const cls = deltaPct > 0 ? 'up' : 'down';
      deltaHtml = `<span class="alm-cu-sug-delta ${cls}">${sign}${deltaPct.toFixed(0)}%</span>`;
    }
    return `<div class="alm-cu-sug-inner">
      <span class="alm-cu-sug-icon">💡</span>
      <div>
        <div class="alm-cu-sug-label">Precio venta sugerido ${deltaHtml}</div>
        <div class="alm-cu-sug-actual">Actual: ${actual > 0 ? 'S/ ' + actual.toFixed(2) : '— sin precio anterior'}</div>
      </div>
      <input type="number" step="0.01" min="0" class="alm-cu-sug-input"
             value="${sugVal.toFixed(2)}"
             oninput="MOS._costosGuiaSugUpdate(${idx}, this.value)">
      <label class="alm-cu-sug-check">
        <input type="checkbox" ${seleccionado ? 'checked' : ''}
               onchange="MOS._costosGuiaSugToggle(${idx}, this.checked)">
        <span>Aplicar</span>
      </label>
    </div>`;
  }

  // Editar precio sugerido inline
  function _costosGuiaSugUpdate(idx, valor) {
    const l = S._costosGuiaState.lineas[idx];
    if (!l || !l._sugerencia) return;
    l._sugerencia._precioEditado = parseFloat(valor) || 0;
  }
  // Toggle de aplicar la sugerencia
  function _costosGuiaSugToggle(idx, checked) {
    const l = S._costosGuiaState.lineas[idx];
    if (!l || !l._sugerencia) return;
    l._sugerencia._seleccionado = checked;
  }

  // [v41.20] Debounce 600ms al perder foco / cambiar costo: pide sugerencia
  // al backend para ese producto específico.
  const _sugDebounceTimers = {};
  function _costosGuiaSugerirDebounce(idx) {
    // [v2.43.16] En el overlay nuevo (modo costos en voucher) NO debe aparecer
    // sugerencia de precio venta — eso pertenece al modal de PRECIOS jefa.
    // El user reportó: "sigo viendo el PRECIO venta sugerido en el modal de
    // costos xq? se supone que son solo costos". Detectamos si el slot está
    // dentro de #almOpsDetalleOverlay y si sí, abortamos.
    const slot = $('sugSlot_' + idx);
    if (slot && slot.closest && slot.closest('#almOpsDetalleOverlay')) return;
    clearTimeout(_sugDebounceTimers[idx]);
    _sugDebounceTimers[idx] = setTimeout(() => _costosGuiaFetchSugerencia(idx), 600);
  }

  async function _costosGuiaFetchSugerencia(idx) {
    // [v2.43.16] Defensa adicional — si el slot está en el overlay nuevo, salir.
    const slotPre = $('sugSlot_' + idx);
    if (slotPre && slotPre.closest && slotPre.closest('#almOpsDetalleOverlay')) return;
    const st = S._costosGuiaState;
    const l = st.lineas[idx];
    if (!l) return;
    const brutoUnit = _costosGuiaCalcularBruto(l, st);
    if (brutoUnit <= 0) {
      // Sin costo → ocultar sugerencia
      l._sugerencia = null;
      const slot = $('sugSlot_' + idx);
      if (slot) { slot.classList.remove('is-open'); setTimeout(() => slot.innerHTML = '', 300); }
      return;
    }
    // Mostrar loading en el slot
    const slot = $('sugSlot_' + idx);
    if (slot) {
      slot.innerHTML = `<div class="alm-cu-sug-inner" style="grid-template-columns:auto 1fr;justify-content:start">
        <span class="alm-cu-sug-icon">⏳</span>
        <span class="alm-cu-sug-label">Calculando sugerencia...</span>
      </div>`;
      slot.classList.add('is-open');
    }
    try {
      const r = await API.get('getSugerenciaPrecioIndividual', {
        idGuia: st.idGuia,
        codigoProducto: l.codigoProducto,
        costoUnitarioBruto: brutoUnit
      });
      const data = (r && (r.data || r)) || {};
      if (data.ok === false || !data.precioVentaSugerido) {
        // Backend respondió pero sin sugerencia útil → calcular fallback frontend
        l._sugerencia = _costosGuiaSugFallback(l, brutoUnit);
      } else {
        l._sugerencia = {
          precioVentaActual: data.precioVentaActual || 0,
          precioVentaSugerido: data.precioVentaSugerido || 0,
          _seleccionado: false,  // [v2.41.54] default OFF
          _precioEditado: data.precioVentaSugerido || 0
        };
      }
    } catch(e) {
      // Sin backend / falla → fallback frontend (margen 25%)
      l._sugerencia = _costosGuiaSugFallback(l, brutoUnit);
    }
    // Pintar
    if (slot) {
      slot.innerHTML = _renderSugerenciaInline(idx, l._sugerencia);
      slot.classList.add('is-open');
    }
  }

  // Cálculo fallback frontend: costo bruto × 1.25 (25% margen)
  // [v2.43.3] Margen objetivo fallback unificado a 40% (antes 25%).
  // Coincide con MARGEN_OBJETIVO del backend (Almacen.gs:1840). Antes
  // había inconsistencia: front usaba 25%, back usaba 40% — generaba
  // sugerencias distintas según quién respondía primero.
  // Cálculo precio = costo / (1 - margen) → margen 40% = costo / 0.60.
  function _costosGuiaSugFallback(l, brutoUnit) {
    const MARGEN_FALLBACK = 0.40;
    const sug = +(brutoUnit / (1 - MARGEN_FALLBACK)).toFixed(2);
    return {
      precioVentaActual: parseFloat(l.precioVentaActual) || 0,
      precioVentaSugerido: sug,
      _seleccionado: false,  // [v2.41.54] default OFF
      _precioEditado: sug,
      _fallback: true
    };
  }

  function _costosGuiaUpdLinea(idx, valor) {
    const st = S._costosGuiaState;
    const linea = st.lineas[idx];
    if (!linea) return;
    linea.inputValue = parseFloat(valor) || 0;
    const brutoUnit = _costosGuiaCalcularBruto(linea, st);
    const netoUnit  = brutoUnit / (1 + _IGV_RATE);
    const cell = $('costoGuiaSubtot_' + idx);
    if (cell) {
      cell.innerHTML = brutoUnit > 0
        ? `<div><span class="alm-cu-line-helper-bruto">S/ ${brutoUnit.toFixed(4)}</span>/u</div>
           <div style="opacity:.65">neto S/ ${netoUnit.toFixed(4)}</div>`
        : '<span style="opacity:.4">—</span>';
    }
    // Recalcular totales
    let totalBruto = 0;
    st.lineas.forEach(l => { totalBruto += _costosGuiaCalcularBruto(l, st) * (parseFloat(l.cantidad) || 0); });
    const totalNeto = totalBruto / (1 + _IGV_RATE);
    const elN = $('costosGuiaTotalNeto');  if (elN) elN.textContent = 'S/ ' + totalNeto.toFixed(2);
    const elI = $('costosGuiaTotalIgv');   if (elI) elI.textContent = 'S/ ' + (totalBruto - totalNeto).toFixed(2);
    const elB = $('costosGuiaTotalBruto'); if (elB) elB.textContent = 'S/ ' + totalBruto.toFixed(2);
    // [v41.20] Dispara debounce para refrescar sugerencia inline
    _costosGuiaSugerirDebounce(idx);
    // [v2.41.54] Marca visual: el ✓/⚠ de esta línea se recalcula
    _costosGuiaUpdMarca(idx);
    _costosGuiaUpdProgreso();
    // [v2.41.54] Autoguardado por línea debounced 1.5s — el user no tiene
    // que pulsar "Guardar" para que el costo persista. El backend acepta
    // upsert por idDetalle/codigoProducto, idempotente.
    _costosGuiaAutosaveDebounce(idx);
  }

  // [v2.41.54] Marca visual ✓/⚠ por línea según si tiene costo > 0
  function _costosGuiaUpdMarca(idx) {
    const st = S._costosGuiaState;
    if (!st) return;
    const linea = st.lineas[idx];
    if (!linea) return;
    const marca = $('costoGuiaMarca_' + idx);
    if (!marca) return;
    const bruto = _costosGuiaCalcularBruto(linea, st);
    if (bruto > 0) {
      marca.innerHTML = '<span title="Costo registrado" style="color:#34d399;font-weight:700">✓</span>';
    } else {
      marca.innerHTML = '<span title="Falta costo" style="color:#f87171;font-weight:700;animation:pulse 1.6s infinite">⚠</span>';
    }
  }

  // [v2.41.54] Contador en el header: "X de Y con costo"
  function _costosGuiaUpdProgreso() {
    const st = S._costosGuiaState;
    if (!st) return;
    const total = st.lineas.length;
    let conCosto = 0;
    st.lineas.forEach(l => { if (_costosGuiaCalcularBruto(l, st) > 0) conCosto++; });
    const cont = $('costosGuiaProgreso');
    if (!cont) return;
    const pct = total > 0 ? Math.round((conCosto / total) * 100) : 0;
    const completo = (conCosto === total);
    cont.innerHTML = `
      <span style="color:${completo ? '#34d399' : (conCosto > 0 ? '#fbbf24' : '#94a3b8')};font-weight:800">
        ${completo ? '✓ ' : ''}${conCosto}/${total} producto${total === 1 ? '' : 's'} con costo
      </span>
      <span style="color:#64748b;margin-left:6px">· ${pct}%</span>
      ${!completo ? '<span style="color:#f87171;margin-left:6px;font-size:10px">⚠ faltan ' + (total - conCosto) + '</span>' : ''}`;
  }

  // [v2.41.54] Autoguardado por línea — debounce 1.5s tras último cambio
  const _costosAutosaveTimers = {};
  function _costosGuiaAutosaveDebounce(idx) {
    clearTimeout(_costosAutosaveTimers[idx]);
    _costosAutosaveTimers[idx] = setTimeout(() => _costosGuiaAutosaveLinea(idx), 1500);
  }
  async function _costosGuiaAutosaveLinea(idx) {
    const st = S._costosGuiaState;
    if (!st || !st.idGuia) return;
    const l = st.lineas[idx];
    if (!l) return;
    const bruto = _costosGuiaCalcularBruto(l, st);
    if (bruto <= 0) return; // sin costo: no enviar (evitar borrar)
    const marca = $('costoGuiaMarca_' + idx);
    if (marca) marca.innerHTML = '<span title="Guardando…" style="color:#fbbf24">⏳</span>';
    try {
      await API.post('llenarCostosGuia', {
        idGuia: st.idGuia,
        items: [{
          idDetalle: l.idDetalle,
          codigoProducto: l.codigoProducto,
          precioUnitario: bruto
        }],
        actualizarPrecioCosto: false,
        usuario: S.session?.nombre || '',
        sugerenciasInline: [],
        _autosave: true
      });
      // Restaurar marca ✓ tras éxito
      _costosGuiaUpdMarca(idx);
      if (marca) {
        marca.classList.add('autosave-flash');
        setTimeout(() => marca.classList.remove('autosave-flash'), 600);
      }
    } catch(e) {
      if (marca) marca.innerHTML = '<span title="Error guardando · reintenta editando" style="color:#f87171">✗</span>';
    }
  }

  function cerrarCostosGuia() { closeModal('modalCostosGuia'); }

  async function guardarCostosGuia() {
    const st = S._costosGuiaState;
    const { idGuia, lineas } = st;
    if (!idGuia) return;
    const items = lineas
      .map(l => ({
        idDetalle: l.idDetalle,
        codigoProducto: l.codigoProducto,
        precioUnitario: _costosGuiaCalcularBruto(l, st) // bruto c/IGV
      }))
      .filter(it => it.precioUnitario > 0);
    if (!items.length) {
      toast('No hay precios para guardar', 'error');
      return;
    }
    const updateMaster = !!$('costosGuiaUpdMaster')?.checked;

    // [v41.20] Capturar sugerencias inline marcadas para aplicar
    const sugerenciasInline = lineas
      .filter(l => l._sugerencia && l._sugerencia._seleccionado && (l._sugerencia._precioEditado > 0))
      .map(l => ({
        codigoProducto: l.codigoProducto,
        precioVentaSugerido: l._sugerencia._precioEditado
      }));

    // [v41.21] Cerrar el modo correcto: voucher overlay o modal legacy
    if (S._opsModoCostos) {
      // Cerrar overlay del voucher al guardar exitoso
      cerrarOpsDetalleOverlay();
    } else {
      closeModal('modalCostosGuia');
    }

    try {
      const resp = await API.post('llenarCostosGuia', {
        idGuia, items, actualizarPrecioCosto: updateMaster,
        usuario: S.session?.nombre || '',
        sugerenciasInline                       // [v41.20] aplica directo desde inline
      });
      const respData = (resp && resp.data) || resp || {};
      const ventaAuto = parseInt(respData.productosVentaAutoActualizada || 0, 10);
      toast('✓ ' + items.length + ' costos guardados'
            + (updateMaster ? ' + catálogo MOS' : '')
            + (ventaAuto > 0 ? ' · ✨ ' + ventaAuto + ' precios auto-recalc. con margen objetivo' : '')
            + (sugerenciasInline.length ? ' · ' + sugerenciasInline.length + ' precios aplicados' : ''),
            'ok');
      // [v2.43.10] Marcar localStorage que costos fueron actualizados (✓ en botón)
      try { localStorage.setItem('mos_costos_aplicada_' + idGuia, String(Date.now())); } catch(_){}
      await almLoadOps(true);

      // [v41.20] Las sugerencias ya se aplicaron inline; no abrir modal viejo.
      // Mantengo la lógica de getter por compat (algunos endpoints siguen devolviéndolas).
      const sugerencias = (resp && resp.sugerenciasPrecioVenta) || (resp && resp.data && resp.data.sugerenciasPrecioVenta) || [];
      const relevantes = sugerencias.filter(s => {
        // Mostrar solo si hay sugerencia activa Y precio sugerido difiere significativamente del actual
        if (s.precioVentaSugerido === null || s.precioVentaSugerido === undefined) return false;
        const actual = parseFloat(s.precioVentaActual) || 0;
        const sug = parseFloat(s.precioVentaSugerido) || 0;
        if (sug <= 0) return false;
        if (actual <= 0) return true; // sin precio antes → sugerir
        const deltaPct = Math.abs((sug - actual) / actual) * 100;
        return deltaPct >= 1; // ≥ 1% de diferencia
      });
      if (relevantes.length) {
        _mostrarPanelImpacto(relevantes, idGuia);
      } else {
        // No hay cambios relevantes → ocultar sección sugerencias
        _ocultarSeccionSugerencias();
        toast('✓ Costos guardados · sin cambios de precio sugeridos', 'ok');
      }
    } catch(e) {
      _ocultarSeccionSugerencias();
      toast('Error: ' + e.message, 'error');
    }
  }

  // [v41.19] Mostrar/ocultar la sección embebida de sugerencias dentro del
  // overlay unificado de costos (reemplaza al modalImpactoCostos standalone).
  function _mostrarSeccionSugerencias() {
    const sec = $('cguSugerenciasSection');
    if (sec) {
      sec.classList.remove('hidden');
      setTimeout(() => { try { sec.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); } catch(_){} }, 100);
    }
  }
  function _ocultarSeccionSugerencias() {
    const sec = $('cguSugerenciasSection');
    if (sec) sec.classList.add('hidden');
  }

  // ── Panel: Impacto de costos en precios de venta ─────────
  S._impactoState = S._impactoState || { sugerencias: [], idGuia: null };

  // Abre el modal de impacto INMEDIATAMENTE con skeleton shimmer, antes de
  // que el backend termine de calcular las sugerencias FIFO. Se reemplaza
  // por _renderImpactoBody cuando llegan los datos reales.
  function _mostrarPanelImpactoSkeleton(idGuia) {
    const info = $('impactoCostosInfo');
    if (info) info.textContent = `Guía ${idGuia} · calculando impacto en precios...`;
    const body = $('impactoCostosBody');
    if (body) {
      body.innerHTML = `
        <div class="liq-skel-stage">
          <div class="liq-skel-card"></div>
          <div class="liq-skel-card" style="animation-delay:.14s"></div>
          <div class="liq-skel-card" style="animation-delay:.28s"></div>
          <div class="liq-skel-stage-hint">
            <span class="liq-skel-hint-dot"></span>
            Analizando costos y lotización FIFO...
          </div>
        </div>`;
    }
    const resEl = $('impactoCostosResumen');
    if (resEl) resEl.textContent = '';
    openModal('modalImpactoCostos');
  }

  function _mostrarPanelImpacto(sugerencias, idGuia) {
    // Inicializar cada una con seleccionado=true por default (excepto FIJO/LIBRE sin sugerencia)
    sugerencias.forEach(s => {
      s._seleccionado = (s.precioVentaSugerido !== null && s.precioVentaSugerido > 0);
      s._precioCustom = s.precioVentaSugerido; // editable
    });
    S._impactoState = { sugerencias, idGuia };
    const info = $('impactoCostosInfo');
    if (info) info.textContent = `Guía ${idGuia} · ${sugerencias.length} producto${sugerencias.length === 1 ? '' : 's'} con cambio relevante`;
    _renderImpactoBody();
    openModal('modalImpactoCostos');
  }

  function _renderImpactoBody() {
    const body = $('impactoCostosBody');
    if (!body) return;
    const { sugerencias } = S._impactoState;
    if (!sugerencias.length) {
      body.innerHTML = '<div class="text-xs text-slate-500 italic">Sin sugerencias relevantes.</div>';
      return;
    }
    body.innerHTML = sugerencias.map((s, i) => {
      const costoAnt = parseFloat(s.costoAnterior) || 0;
      const costoNue = parseFloat(s.costoNuevo) || 0;
      const deltaCosto = costoAnt > 0 ? ((costoNue - costoAnt) / costoAnt) * 100 : null;
      const deltaCostoStr = deltaCosto === null ? 'nuevo' : (deltaCosto >= 0 ? '+' : '') + deltaCosto.toFixed(1) + '%';
      const deltaCls = deltaCosto === null ? 'text-slate-500' : (deltaCosto > 0 ? 'text-rose-400' : 'text-emerald-400');

      const ventaAct = parseFloat(s.precioVentaActual) || 0;
      const ventaSug = parseFloat(s.precioVentaSugerido) || 0;
      const margenSug = s.margenSugerido !== null && s.margenSugerido !== undefined ? s.margenSugerido : null;
      const margenAct = s.margenActual !== null && s.margenActual !== undefined ? s.margenActual : null;

      // Lotización
      const lot = s.lotizacion || {};
      const desglose = lot.desglose || [];
      const lotHtml = (lot.hayLoteAnterior && desglose.length > 0)
        ? `<div class="mt-2 p-2 rounded text-[10px] text-amber-300" style="background:rgba(251,191,36,.07);border:1px dashed rgba(251,191,36,.3)">
             <div class="font-semibold mb-1">⚠️ Hay stock del lote anterior</div>
             <table class="w-full text-[10px]">
               <thead class="text-amber-500 opacity-70">
                 <tr><th class="text-left">Lote</th><th class="text-right">Cant</th><th class="text-right">Costo c/IGV</th></tr>
               </thead>
               <tbody>
                 ${desglose.map(d => `<tr ${d.esActual ? 'class="font-semibold"' : ''}>
                   <td class="py-0.5">${d.esActual ? 'Nuevo (esta guía)' : new Date(d.fecha).toLocaleDateString('es-PE', { month: 'short', day: 'numeric' })}</td>
                   <td class="text-right py-0.5">${d.cantidad}u</td>
                   <td class="text-right py-0.5 font-mono">S/ ${parseFloat(d.costo).toFixed(2)}</td>
                 </tr>`).join('')}
               </tbody>
             </table>
             <div class="mt-1 text-amber-400">Costo ponderado real: <span class="font-mono font-semibold">S/ ${(parseFloat(lot.costoPonderado) || 0).toFixed(4)}</span> · stock total ${lot.stockTotal || 0}u</div>
           </div>`
        : '';

      const sinSugerencia = (s.modoEfectivo === 'FIJO' || s.modoEfectivo === 'LIBRE' || ventaSug <= 0);
      const checked = s._seleccionado ? 'checked' : '';
      const disabledCheck = sinSugerencia ? 'disabled' : '';

      return `<div class="card-sm p-3 mb-2" style="border-left:3px solid ${sinSugerencia ? '#475569' : (deltaCosto && deltaCosto > 0 ? '#f43f5e' : '#10b981')}">
        <div class="flex items-start gap-3">
          <input type="checkbox" ${checked} ${disabledCheck} onchange="MOS._impactoTogglesel(${i}, this.checked)" class="mt-1">
          <div class="flex-1 min-w-0">
            <div class="text-sm font-semibold text-slate-200 truncate">${s.descripcion}</div>
            <div class="text-[10px] text-slate-500 font-mono">▌ ${s.codigoProducto}</div>
            <div class="grid grid-cols-2 gap-2 mt-2 text-[11px]">
              <div>
                <span class="text-slate-500">Costo:</span>
                <span class="font-mono">${costoAnt > 0 ? 'S/ ' + costoAnt.toFixed(2) : '—'} → <span class="text-amber-400 font-semibold">S/ ${costoNue.toFixed(2)}</span></span>
                <span class="${deltaCls}">(${deltaCostoStr})</span>
              </div>
              <div>
                <span class="text-slate-500">Margen:</span>
                <span>${margenAct !== null ? margenAct.toFixed(1) + '%' : '—'} → <span class="${margenSug !== null ? 'text-emerald-400 font-semibold' : 'text-slate-500'}">${margenSug !== null ? margenSug.toFixed(1) + '%' : '—'}</span></span>
              </div>
            </div>
            <div class="mt-2 flex items-center gap-2 text-[11px]">
              <span class="text-slate-500">Precio venta:</span>
              <span class="font-mono">${ventaAct > 0 ? 'S/ ' + ventaAct.toFixed(2) : '—'}</span>
              <span class="text-slate-600">→</span>
              ${sinSugerencia
                ? `<span class="text-slate-500 italic text-[10px]">${s.modoEfectivo} — sin sugerencia automática</span>`
                : `<input type="number" step="0.01" min="0" value="${(s._precioCustom || ventaSug).toFixed(2)}"
                   oninput="MOS._impactoSetPrecio(${i}, this.value)"
                   class="inp text-xs text-right" style="width:90px">
                   <span class="text-[9px] text-slate-600">obj. ${(parseFloat(s.margenObjetivo) || 0).toFixed(0)}% (${s.origenPolitica})</span>`}
            </div>
            ${lotHtml}
          </div>
        </div>
      </div>`;
    }).join('');

    // Resumen del footer
    const seleccionadas = sugerencias.filter(s => s._seleccionado).length;
    const resEl = $('impactoCostosResumen');
    if (resEl) resEl.textContent = `${seleccionadas} de ${sugerencias.length} seleccionados`;
  }

  function _impactoTogglesel(idx, checked) {
    if (S._impactoState.sugerencias[idx]) {
      S._impactoState.sugerencias[idx]._seleccionado = !!checked;
      _renderImpactoBody();
    }
  }

  function _impactoSetPrecio(idx, valor) {
    if (S._impactoState.sugerencias[idx]) {
      S._impactoState.sugerencias[idx]._precioCustom = parseFloat(valor) || 0;
    }
  }

  function cerrarImpactoCostos() { closeModal('modalImpactoCostos'); }

  async function aplicarSugerenciasSeleccionadas() {
    const { sugerencias, idGuia } = S._impactoState;
    const items = sugerencias
      .filter(s => s._seleccionado && s._precioCustom > 0)
      .map(s => ({
        idProducto: s.idProducto,
        precioNuevo: s._precioCustom,
        motivo: 'Ajuste por costo guía ' + (idGuia || '')
      }));
    if (!items.length) {
      toast('No hay sugerencias seleccionadas', 'error');
      return;
    }
    closeModal('modalImpactoCostos');
    toast('Aplicando precios…', 'info');
    try {
      const r = await API.post('aplicarPreciosVentaSugeridos', { items, usuario: S.session?.nombre || '' });
      const aplicados = (r && r.aplicados) || (r && r.data && r.data.aplicados) || 0;
      const propagadas = (r && r.presentacionesPropagadas) || (r && r.data && r.data.presentacionesPropagadas) || 0;
      const errores = (r && r.errores) || (r && r.data && r.data.errores) || [];
      const propTxt = propagadas > 0 ? ` (+${propagadas} presentaciones propagadas)` : '';
      toast(`✓ ${aplicados} precios actualizados${propTxt}${errores.length ? ' · ' + errores.length + ' errores' : ''}`, errores.length ? 'error' : 'ok');
      // Refrescar catálogo si está cargado
      if (S.productos && S.productos.length) {
        await loadCatalogo(true);
      }
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  function _formatFechaCorta(yyyymmdd) {
    if (!yyyymmdd) return '';
    const parts = yyyymmdd.split('-');
    if (parts.length !== 3) return yyyymmdd;
    const d = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
    const hoy = new Date(); hoy.setHours(0,0,0,0);
    const ayer = new Date(hoy.getTime() - 86400000);
    const dms = d.getTime();
    if (dms === hoy.getTime()) return 'Hoy';
    if (dms === ayer.getTime()) return 'Ayer';
    return d.toLocaleDateString('es-PE', { weekday: 'short', day: 'numeric', month: 'short' });
  }

  // ── ALMACÉN: ZONAS (ranking + sin venta) ──
  async function almLoadZonas(forceRefresh) {
    // 1. Pintar inmediato desde cache local (si existe)
    if (S._almRankingZonas) { try { _almRenderRankingZonas(S._almRankingZonas); } catch {} }
    if (S._almSinVenta) {
      const v = S._almSinVenta;
      try { _almRenderSinVenta(Array.isArray(v) ? v : (v.productos || [])); } catch {}
    }
    // 2. Fetch fresco
    const dias = parseInt($('almZonasRango')?.value) || 30;
    const params = { dias };
    if (forceRefresh) params._refresh = 'true';
    try {
      const [rankRes, sinVentaRes] = await Promise.allSettled([
        API.get('getRankingZonas', params),
        API.get('getProductosSinVenta', params)
      ]);
      const warnEl = $('almZonasGasVersionWarn');
      let gasOld = false;
      if (rankRes.status === 'fulfilled') {
        const v = rankRes.value || {};
        if (!v._almV || v._almV < 2) gasOld = true;
        S._almRankingZonas = v;
        _almSaveCache('rankingZonas', v);
        _almRenderRankingZonas(v);
      }
      if (sinVentaRes.status === 'fulfilled') {
        const v = sinVentaRes.value || {};
        if (!v._almV || v._almV < 2) gasOld = true;
        S._almSinVenta = v;
        _almSaveCache('sinVenta', v);
        _almRenderSinVenta(v.productos || []);
      }
      if (warnEl) warnEl.classList.toggle('hidden', !gasOld);
    } catch(e) {
      console.warn('[almLoadZonas] error:', e);
    }
  }

  async function almRefreshZonas() {
    toast('Refrescando zonas (ignora cache)…', 'info');
    await almLoadZonas(true);
  }

  function _almRenderRankingZonas(data) {
    const el = $('almZonasRanking'); if (!el) return;
    const zonas = data.zonas || [];
    if (!zonas.length) {
      el.innerHTML = '<div class="text-xs text-slate-600 italic py-3 text-center">Sin zonas registradas en MOS o sin ventas en el rango</div>';
      return;
    }
    const max = Math.max(...zonas.map(z => z.ventas), 1);
    const totalStr = data.totalVentas ? 'S/ ' + data.totalVentas.toLocaleString('es-PE', { maximumFractionDigits: 0 }) : 'S/ 0';
    const fueraZonas = parseFloat(data.ventasFueraDeZonasRegistradas) || 0;
    const fueraTickets = parseInt(data.ticketsFueraDeZonasRegistradas) || 0;
    el.innerHTML = `
      <div class="card-sm p-4 mb-2">
        <div class="text-xs text-slate-500 uppercase mb-1">Total vendido (${data.rangoDias}d)</div>
        <div class="text-2xl font-bold text-emerald-400">${totalStr}</div>
        <div class="text-xs text-slate-500 mt-1">${data.totalTickets || 0} tickets · ticket prom S/ ${(data.ticketProm || 0).toFixed(2)}</div>
      </div>
      <div class="space-y-2">
        ${zonas.map(z => {
          const pct = (z.ventas / max) * 100;
          return `<div class="card-sm p-3">
            <div class="flex items-center justify-between mb-1.5 gap-2">
              <div class="text-sm font-semibold text-slate-200 truncate">${z.nombre}</div>
              <div class="text-sm font-bold text-amber-400 whitespace-nowrap">S/ ${z.ventas.toLocaleString('es-PE', { maximumFractionDigits: 0 })}</div>
            </div>
            <div class="h-2 bg-slate-800 rounded overflow-hidden">
              <div class="h-full" style="width:${pct}%;background:linear-gradient(to right,#10b981,#34d399)"></div>
            </div>
            <div class="flex items-center justify-between text-xs text-slate-500 mt-1.5">
              <span>${z.tickets} tickets · ${z.vendedores} vendedor${z.vendedores !== 1 ? 'es' : ''}</span>
              <span>${z.pctTotal}%</span>
            </div>
          </div>`;
        }).join('')}
        ${fueraZonas > 0 ? `<div class="card-sm p-3 border border-amber-500/30">
          <div class="flex items-center justify-between gap-2">
            <div class="min-w-0 flex-1">
              <div class="text-sm font-semibold text-amber-400">⚠ Ventas fuera de zonas registradas</div>
              <div class="text-xs text-slate-500 mt-0.5">${fueraTickets} tickets atribuidos a zonas que no existen en MOS.ZONAS — revisar configuración de estaciones</div>
            </div>
            <div class="text-sm font-bold text-amber-400 whitespace-nowrap">S/ ${fueraZonas.toLocaleString('es-PE', { maximumFractionDigits: 0 })}</div>
          </div>
        </div>` : ''}
      </div>
    `;
  }

  function _almRenderSinVenta(productos) {
    const el = $('almSinVenta'); if (!el) return;
    if (!productos.length) {
      el.innerHTML = '<div class="text-xs text-slate-600 italic py-3 text-center">✅ Todos los productos con stock se vendieron</div>';
      return;
    }
    // Hint para el usuario sobre el propósito
    const intro = '<div class="text-[11px] text-slate-500 italic mb-2 px-1">💡 Estos productos tienen stock pero no rotan — candidatos a promo o a botar</div>';
    el.innerHTML = intro + productos.slice(0, 30).map(p => {
      const breakdown = (p.breakdownZonas || []);
      const breakdownStr = breakdown.length
        ? breakdown.map(b => `<span class="text-slate-400">${b.nombre}: <span class="text-orange-300">${b.cantidad}u</span></span>`).join(' · ')
        : '<span class="text-slate-600 italic">sin desglose</span>';
      return `
        <div class="card-sm p-3 cursor-pointer hover:border-orange-500/40 transition-colors" onclick="MOS.almAbrirStockDetalle('${p.idProducto}')">
          <div class="flex items-center justify-between gap-2 mb-1">
            <div class="min-w-0 flex-1">
              <div class="text-sm font-semibold text-slate-200 truncate">${p.descripcion || p.idProducto}</div>
              <div class="text-xs text-slate-500 mt-0.5 font-mono truncate">▌ ${p.codigoBarra || '—'} · ${fmtMoney(p.precioVenta)}</div>
            </div>
            <div class="text-right shrink-0">
              <div class="text-sm font-bold text-orange-400">${p.stockEnZonas}u</div>
              <div class="text-[10px] text-slate-600">total en zonas</div>
            </div>
          </div>
          <div class="text-[11px] mt-1 pt-1 border-t border-slate-800/50">${breakdownStr}</div>
        </div>`;
    }).join('') + (productos.length > 30 ? `<div class="text-xs text-slate-600 italic text-center py-2">+ ${productos.length - 30} más…</div>` : '');
  }

  // ── ALMACÉN: STOCK detalle modal (WH + zonas) ──
  async function almAbrirStockDetalle(idProducto, forceRefresh) {
    if (!idProducto) return;
    S._stockDetCurrentId = idProducto;
    openModal('modalStockDetalle');
    const body = $('stockDetBody');
    if (body) body.innerHTML = '<div class="skel h-32 rounded"></div>';
    try {
      const params = { idProducto };
      if (forceRefresh) params._refresh = 'true';
      const r = await API.get('getStockUnificado', params);
      if (!r) throw new Error('Sin respuesta');
      const p = r.producto || {};
      $('stockDetTitle').textContent = '📦 ' + (p.descripcion || idProducto);
      $('stockDetSku').textContent = 'SKU ' + (p.skuBase || '—') + (p.codigoBarra ? ' · ▌ ' + p.codigoBarra : '');
      const zonasHtml = (r.zonas || []).map(z => {
        const isNeg = z.cantidad < 0;
        const isCero = z.cantidad === 0;
        const sinRegistro = !z.tieneRegistroStock;  // NO existe fila en STOCK_ZONAS para este producto
        // Stock display: distinguir sin registro / 0 / negativo / positivo
        let stockColor, stockDisplay;
        if (sinRegistro) {
          stockColor = 'text-slate-600 italic';
          stockDisplay = '— sin registro';
        } else if (isNeg) {
          stockColor = 'text-rose-500';
          stockDisplay = `⚠ ${z.cantidad}u`;
        } else if (isCero) {
          stockColor = 'text-slate-500';
          stockDisplay = '0u';
        } else {
          stockColor = (z.diasParaAcabar !== null && z.diasParaAcabar < 7)  ? 'text-rose-400' :
                       (z.diasParaAcabar !== null && z.diasParaAcabar < 14) ? 'text-amber-400' :
                       'text-slate-200';
          stockDisplay = z.cantidad + 'u';
        }
        // Línea de detalle: ventas / rotación
        let detailLine = '';
        if (sinRegistro && z.sinVentas) {
          detailLine = '<span class="text-slate-600 italic">Producto nunca registrado en esta zona</span>';
        } else if (z.sinVentas) {
          detailLine = '<span class="text-slate-600">Sin ventas en ' + (r.total?.rangoDiasConsultado || 7) + 'd</span>';
        } else {
          detailLine = 'Vende ' + z.rotacionDia + '/d';
          if (z.diasParaAcabar !== null) {
            const cls = z.diasParaAcabar < 7 ? 'text-rose-400' : z.diasParaAcabar < 14 ? 'text-amber-400' : 'text-slate-500';
            detailLine += ` · <span class="${cls}">alcanza ${z.diasParaAcabar}d</span>`;
          } else if (sinRegistro) {
            detailLine += ' · <span class="text-rose-400">⚠ vendiéndose sin estar registrado en stock</span>';
          } else if (isCero) {
            detailLine += ' · <span class="text-rose-400">⚠ stock agotado, reponer</span>';
          }
        }
        // Badge de alerta cuando hay ventas pero stock=0
        const warningBadge = (!sinRegistro && isCero && !z.sinVentas)
          ? '<span class="text-[10px] text-rose-400 ml-1">📍 stock agotado con ventas</span>' : '';
        return `<div class="flex items-center justify-between py-2 border-b border-slate-800/50 gap-2">
          <div class="min-w-0 flex-1">
            <div class="text-sm text-slate-200 truncate">🏪 ${z.nombre}${warningBadge}</div>
            <div class="text-xs text-slate-500">${detailLine}</div>
          </div>
          <div class="text-right shrink-0">
            <div class="text-base font-bold ${stockColor}">${stockDisplay}</div>
          </div>
        </div>`;
      }).join('');
      const insightsHtml = (r.insights || []).map(i => {
        const sevColor = { CRITICA: 'border-rose-500/40 bg-rose-500/5', ALTA: 'border-amber-500/40 bg-amber-500/5', MEDIA: 'border-indigo-500/40 bg-indigo-500/5' };
        return `<div class="card-sm p-2.5 border-l-2 ${sevColor[i.severidad] || 'border-slate-700'}">
          <div class="text-xs font-semibold text-slate-200">${i.mensaje}</div>
          ${i.accion ? `<div class="text-[11px] text-slate-500 mt-1">→ ${i.accion}</div>` : ''}
        </div>`;
      }).join('');
      const total = r.total || {};
      const minimo = p.stockMinimo || 0;
      const maximo = p.stockMaximo || (minimo * 2);
      const pct = maximo > 0 ? Math.min(100, (total.cantidad / maximo) * 100) : 0;
      const colorBar = total.cantidad < minimo ? '#f43f5e' : total.cantidad < minimo * 1.2 ? '#f59e0b' : '#10b981';
      $('stockDetBody').innerHTML = `
        <!-- Total + barra -->
        <div class="card-sm p-4">
          <div class="text-xs text-slate-500 uppercase mb-2">Total (WH + zonas)</div>
          <div class="grid grid-cols-2 gap-3 mb-3">
            <div>
              <div class="text-[10px] text-slate-500 uppercase">Stock total</div>
              <div class="text-2xl font-bold text-white">${total.cantidad}u</div>
            </div>
            <div>
              <div class="text-[10px] text-slate-500 uppercase">Rotación total</div>
              <div class="text-2xl font-bold ${total.rotacionDia > 0 ? 'text-emerald-400' : 'text-slate-600'}">${total.rotacionDia || 0}<span class="text-xs">/d</span></div>
            </div>
          </div>
          <div class="h-3 bg-slate-800 rounded overflow-hidden">
            <div class="h-full transition-all" style="width:${pct}%;background:${colorBar}"></div>
          </div>
          <div class="flex justify-between text-[10px] text-slate-500 mt-1">
            <span>mín ${minimo}u</span><span>máx ${maximo}u</span>
          </div>
          <div class="text-xs text-slate-400 mt-3 pt-2 border-t border-slate-800">
            ${(() => {
              if (total.cantidad < 0) {
                return '🚨 <span class="text-rose-500 font-semibold">Stock negativo (' + total.cantidad + 'u)</span> — discrepancia entre lo recibido y lo vendido. Auditar urgente.';
              }
              if (total.cantidad === 0) {
                return total.rotacionDia > 0
                  ? '🚨 <span class="text-rose-400">Stock total en 0 pero hay ventas activas</span> — reposición urgente'
                  : '⏸ <span class="text-slate-500">Stock total en 0 · Sin ventas en ' + (total.rangoDiasConsultado || 7) + 'd</span>';
              }
              if (total.diasParaAcabar !== null) {
                const cls = total.diasParaAcabar < 7 ? 'text-rose-400' : total.diasParaAcabar < 14 ? 'text-amber-400' : 'text-emerald-400';
                return `⏰ Al ritmo actual alcanza para <span class="${cls} font-semibold">${total.diasParaAcabar} días</span>`;
              }
              return '⏸ <span class="text-slate-500">Stock estable, sin ventas en ' + (total.rangoDiasConsultado || 7) + 'd</span>';
            })()}
          </div>
        </div>
        <!-- WH -->
        <div>
          <div class="text-xs text-slate-500 uppercase mb-2">🏭 Almacén central</div>
          <div class="card-sm p-3 ${(r.wh || {}).cantidad < 0 ? 'border-rose-500/40' : ''}">
            <div class="flex items-center justify-between">
              <div class="min-w-0 flex-1">
                <div class="text-sm text-slate-200">Stock disponible</div>
                <div class="text-xs text-slate-500 mt-0.5">
                  ${(r.wh || {}).cantidad < 0
                    ? '<span class="text-rose-400">⚠ Stock negativo: vendiste/saliste más de lo recibido</span>'
                    : (total.rotacionDia > 0
                      ? 'Despacha aprox. ' + total.rotacionDia + '/d (= venta total zonas)'
                      : 'Sin movimiento de salida en ' + (total.rangoDiasConsultado || 7) + 'd')}
                </div>
                ${((r.wh && r.wh.detalle) || []).length > 1 ? `<div class="text-[10px] text-slate-600 font-mono mt-1">${r.wh.detalle.length} entradas en WH STOCK</div>` : ''}
              </div>
              <div class="text-lg font-bold ${(r.wh || {}).cantidad > 0 ? 'text-blue-400' : (r.wh || {}).cantidad < 0 ? 'text-rose-500' : 'text-slate-500'} shrink-0">
                ${(r.wh || {}).cantidad > 0 ? ((r.wh || {}).cantidad + 'u') :
                  (r.wh || {}).cantidad < 0 ? ('⚠ ' + (r.wh || {}).cantidad + 'u') :
                  ((r.wh || {}).detalle && (r.wh || {}).detalle.length > 0 ? '0u' : '— sin registro')}
              </div>
            </div>
          </div>
        </div>
        <!-- Zonas -->
        ${zonasHtml ? `
        <div>
          <div class="text-xs text-slate-500 uppercase mb-1">🏪 Distribución por zona (rot ${total.rangoDiasConsultado || 7}d)</div>
          <div class="card-sm p-3">${zonasHtml}</div>
        </div>` : ''}
        <!-- Insights -->
        ${insightsHtml ? `
        <div>
          <div class="text-xs text-slate-500 uppercase mb-2">💡 Sugerencias</div>
          <div class="space-y-2">${insightsHtml}</div>
        </div>` : ''}
        <!-- Debug (colapsado por default) -->
        ${r._debug ? `
        <details class="text-[10px] text-slate-600 mt-2">
          <summary class="cursor-pointer hover:text-slate-400">🔍 Debug · ver qué leyó del backend</summary>
          <div class="mt-2 p-2 rounded font-mono whitespace-pre-wrap" style="background:#060d1f;border:1px solid #1e293b">
            <div class="text-slate-500 mb-1">Zonas leídas de tabla ZONAS:</div>
            ${(r._debug.zonasLeidasDeTablaZONAS || []).map(z =>
              `· idZona="${z.idZona}" · nombre="${z.nombre}" · estado=${z.estado} · canon→${z.canonResolved?.id}/${z.canonResolved?.nombre}`
            ).join('<br>') || '<span class="text-rose-400">⚠ Tabla ZONAS vacía o no leída</span>'}
            <div class="text-slate-500 mt-2 mb-1">IDs canónicos finales mostrados:</div>
            ${(r._debug.idsTodasFinales || []).join(', ')}
            <div class="text-slate-500 mt-2 mb-1">Nombres por canon:</div>
            ${Object.entries(r._debug.nombreCanonMap || {}).map(([k,v]) => `${k} → ${v}`).join('<br>')}
            <div class="text-slate-500 mt-2 mb-1">Stock encontrado por zona (canon):</div>
            ${(r._debug.zonaAcumKeys || []).join(', ') || '(ninguno)'}
            <div class="text-slate-500 mt-2 mb-1">Ventas por zona (canon):</div>
            ${(r._debug.ventasZonaKeys || []).join(', ') || '(ninguno)'}
          </div>
        </details>` : ''}
      `;
    } catch(e) {
      $('stockDetBody').innerHTML = `<div class="text-rose-400 text-sm">Error: ${e.message}</div>`;
    }
  }
  function cerrarStockDetalle() { closeModal('modalStockDetalle'); }

  async function almRefreshStockDetalle() {
    if (!S._stockDetCurrentId) return;
    toast('Refrescando datos…', 'info');
    await almAbrirStockDetalle(S._stockDetCurrentId, true);
  }

  // Cache local de detalles expandidos (skuBase → datos)
  S._stockDetCache = S._stockDetCache || {};
  S._stockExpanded = S._stockExpanded || {};

  function renderStockTable() {
    const list = $('almStockList');
    const stats = $('almStockStats');
    const warn = $('almStockGasVersionWarn');
    if (!list) return;
    if (warn) warn.classList.toggle('hidden', !S._catalogoGasOld);
    const items = S.catalogoStock || [];
    if (!items.length) {
      list.innerHTML = '<div class="text-xs text-slate-600 italic py-6 text-center">Sin productos activos en catálogo.</div>';
      if (stats) stats.textContent = '';
      return;
    }
    // Filtros
    const q = (S.almStockFilter || '').trim().toLowerCase();
    const filtroAlerta = $('almStockFiltroAlerta')?.value || '';
    let filtered = items;
    if (q) {
      filtered = filtered.filter(p =>
        (p.descripcion || '').toLowerCase().includes(q) ||
        (p.skuBase || '').toLowerCase().includes(q) ||
        (p.codigoBarra || '').toLowerCase().includes(q) ||
        (p.idProducto || '').toLowerCase().includes(q)
      );
    }
    if (filtroAlerta) filtered = filtered.filter(p => p.alerta === filtroAlerta);

    if (stats) stats.textContent = `${filtered.length} de ${items.length} productos`;

    if (!filtered.length) {
      list.innerHTML = '<div class="text-xs text-slate-600 italic py-6 text-center">Sin coincidencias' + (q ? ' para "' + q + '"' : '') + '</div>';
      return;
    }

    list.innerHTML = filtered.slice(0, 100).map(p => _renderStockCard(p)).join('') +
      (filtered.length > 100 ? `<div class="text-xs text-slate-600 italic text-center py-2">+ ${filtered.length - 100} productos más, refina la búsqueda</div>` : '');
  }

  function _renderStockCard(p) {
    const expanded = !!S._stockExpanded[p.skuBase];
    const total = p.totalCantidad;
    const minimo = p.stockMinimo || 0;
    const maximo = p.stockMaximo || (minimo * 2) || 100;
    const pct = Math.min(100, maximo > 0 ? Math.max(0, total) / maximo * 100 : 0);
    const colorBar = total < 0 ? '#f43f5e' :
                     total < minimo ? '#f43f5e' :
                     total < minimo * 1.2 ? '#f59e0b' :
                     '#10b981';
    // Mensaje de estado
    let alertMsg = '', alertColor = 'text-slate-400';
    if (p.alerta === 'NEGATIVO') {
      alertMsg = `🚨 Stock negativo (${total}u) — discrepancia entre lo recibido y lo vendido. Auditar urgente.`;
      alertColor = 'text-rose-500 font-semibold';
    } else if (p.alerta === 'BAJO_MINIMO') {
      alertMsg = `🚨 Stock total (${total}u) por debajo del mínimo (${minimo}u)`;
      alertColor = 'text-rose-400';
    } else if (p.alerta === 'AGOTAR_PRONTO' && p.diasParaAcabar !== null) {
      alertMsg = `⏰ Al ritmo actual alcanza para ${p.diasParaAcabar} días`;
      alertColor = 'text-amber-400';
    } else if (p.alerta === 'SIN_ROTACION') {
      alertMsg = `⏸ Stock sin movimiento en ${p.diasParaAcabar !== null ? p.diasParaAcabar + ' días' : 'el rango consultado'}`;
      alertColor = 'text-slate-500';
    } else if (p.alerta === 'CERCA_MINIMO') {
      alertMsg = `🟡 Cerca del mínimo (${total}u / mín ${minimo}u)`;
      alertColor = 'text-amber-400';
    } else if (p.diasParaAcabar !== null) {
      alertMsg = `✅ Alcanza para ${p.diasParaAcabar} días`;
      alertColor = 'text-emerald-400';
    } else if (total > 0) {
      alertMsg = '✅ Stock estable';
      alertColor = 'text-emerald-400';
    }
    const stockColor = total < 0 ? 'text-rose-500' : total === 0 ? 'text-slate-500' : 'text-slate-100';
    const stockDisplay = total < 0 ? `⚠ ${total}u` : `${total}u`;

    return `<div class="card-sm p-4">
      <!-- Header del card: nombre + código + total + rotación + barra + alerta -->
      <div class="flex items-start justify-between gap-3 mb-2">
        <div class="min-w-0 flex-1">
          <div class="text-sm font-semibold text-slate-100 truncate">📦 ${p.descripcion || p.skuBase}</div>
          <div class="text-[11px] text-slate-500 font-mono mt-0.5 truncate">SKU <span class="text-emerald-300/70">${p.skuBase}</span>${p.codigoBarra ? ' · ▌ ' + p.codigoBarra : ''}${p.countPresentaciones > 1 ? ' <span class="text-slate-600">+ ' + (p.countPresentaciones - 1) + ' pres.</span>' : ''}${p.countEquivalencias > 0 ? ' <span class="text-purple-400/70">+ ' + p.countEquivalencias + ' equiv.</span>' : ''}</div>
        </div>
        <div class="text-right shrink-0">
          <div class="text-lg font-bold ${stockColor}">${stockDisplay}</div>
          <div class="text-[10px] text-slate-500">${p.rotacionDia > 0 ? p.rotacionDia + '/d' : '0/d'}</div>
        </div>
      </div>
      <div class="h-2 bg-slate-800 rounded overflow-hidden mb-1">
        <div class="h-full transition-all" style="width:${pct}%;background:${colorBar}"></div>
      </div>
      <div class="flex justify-between text-[10px] text-slate-500 mb-2">
        <span>mín ${minimo}u</span>
        <span class="text-slate-600">WH ${p.whCantidad}u · zonas ${p.zonasCantidad}u</span>
        <span>máx ${maximo}u</span>
      </div>
      ${alertMsg ? `<div class="text-xs ${alertColor} mb-1">${alertMsg}</div>` : ''}
      <!-- Toggle expandir / colapsar -->
      <button onclick="MOS.almToggleStockExpand('${p.skuBase}', '${p.idProducto}')"
              class="text-[11px] text-slate-500 hover:text-slate-300 mt-1 w-full text-center py-1 rounded transition-colors"
              style="background:rgba(255,255,255,0.02)">
        ${expanded ? '▴ Ocultar detalle' : '▾ Ver detalle (WH + zonas + sugerencias)'}
      </button>
      <!-- Sección expandible -->
      <div id="stockExp_${p.skuBase}" class="${expanded ? '' : 'hidden'} mt-3 pt-3 border-t border-slate-800/50">
        ${expanded ? _renderStockExpandedContent(p.skuBase) : ''}
      </div>
    </div>`;
  }

  function _renderStockExpandedContent(skuBase) {
    const cached = S._stockDetCache[skuBase];
    if (!cached) {
      // Disparar fetch en background
      _fetchStockDetail(skuBase);
      return '<div class="text-xs text-slate-500 italic py-2">Cargando detalle…</div>';
    }
    if (cached.error) return `<div class="text-xs text-rose-400 italic py-2">Error: ${cached.error}</div>`;
    const r = cached;
    const wh = r.wh || {};
    const zonas = r.zonas || [];
    const insights = r.insights || [];
    const total = r.total || {};
    const codigosBarra = r.codigosBarra || [];
    // Matriz código × zona (solo si hay >1 código y al menos 1 zona con stock)
    let matrizHtml = '';
    if (codigosBarra.length > 1 && zonas.length) {
      const cabZonas = zonas.map(z => `<th class="text-right pl-2 pb-1 text-[10px] text-slate-500 font-normal">${z.nombre}</th>`).join('');
      const filasMatriz = codigosBarra.map(c => {
        const cells = zonas.map(z => {
          const q = (c.porZona && c.porZona[z.idZona]) || 0;
          const cls = q < 0 ? 'text-rose-500' : q === 0 ? 'text-slate-700' : 'text-slate-300';
          return `<td class="text-right pl-2 ${cls}">${q !== 0 ? q + 'u' : '·'}</td>`;
        }).join('');
        const tipoBadge = c.tipo === 'principal' ? '🟢' : '🟣';
        return `<tr><td class="text-[10px] font-mono text-slate-400 py-1 pr-2 truncate" style="max-width:120px">${tipoBadge} ${c.codigoBarra}</td>${cells}</tr>`;
      }).join('');
      matrizHtml = `
        <div class="text-xs">
          <div class="font-semibold text-slate-300 mb-1">📊 Matriz código × zona</div>
          <div class="card-sm p-2 overflow-x-auto">
            <table class="text-[11px] w-full" style="border-collapse:collapse">
              <thead><tr><th class="text-left pb-1 text-[10px] text-slate-500 font-normal">Código</th>${cabZonas}</tr></thead>
              <tbody>${filasMatriz}</tbody>
            </table>
          </div>
        </div>
      `;
    }
    // Códigos asociados (principal + equivalencias)
    const codigosHtml = codigosBarra.length > 1 ? `
      <div class="text-xs">
        <div class="font-semibold text-slate-300 mb-1">🏷️ Códigos asociados (${codigosBarra.length}: ${codigosBarra.filter(c => c.tipo === 'principal').length} principal + ${(r.countEquivalencias || 0)} equivalencia${(r.countEquivalencias || 0) === 1 ? '' : 's'})</div>
        <div class="card-sm p-2 space-y-1">
          ${codigosBarra.map(c => {
            const tipoBadge = c.tipo === 'principal'
              ? '<span class="text-[9px] text-emerald-400 bg-emerald-500/10 px-1 rounded">PRINCIPAL</span>'
              : '<span class="text-[9px] text-purple-400 bg-purple-500/10 px-1 rounded">EQUIV</span>';
            const totalCb = c.stockTotal || 0;
            const cls = totalCb < 0 ? 'text-rose-500' : totalCb === 0 ? 'text-slate-500' : 'text-slate-200';
            return `<div class="flex items-center justify-between gap-2 py-0.5">
              <div class="min-w-0 flex-1 flex items-center gap-2">
                ${tipoBadge}
                <span class="font-mono text-slate-300 truncate">▌ ${c.codigoBarra}</span>
              </div>
              <div class="text-[10px] text-slate-500 whitespace-nowrap">WH ${c.stockWh}u · zonas ${c.stockZonas}u · <span class="${cls} font-semibold">total ${totalCb}u</span></div>
            </div>`;
          }).join('')}
        </div>
      </div>
    ` : '';
    // WH detail
    const whHtml = `
      <div class="text-xs">
        <div class="font-semibold text-slate-300 mb-1">🏭 Almacén central</div>
        <div class="card-sm p-2 ${wh.cantidad < 0 ? 'border-rose-500/40' : ''}">
          <div class="flex items-center justify-between">
            <div class="min-w-0 flex-1">
              <div class="text-slate-300">Stock disponible</div>
              <div class="text-[10px] text-slate-500 mt-0.5">
                ${wh.cantidad < 0 ? '<span class="text-rose-400">⚠ Stock negativo: vendiste/saliste más de lo recibido</span>' :
                  total.rotacionDia > 0 ? 'Despacha aprox. ' + total.rotacionDia + '/d' : 'Sin movimiento'}
              </div>
            </div>
            <div class="font-bold ${wh.cantidad > 0 ? 'text-blue-400' : wh.cantidad < 0 ? 'text-rose-500' : 'text-slate-500'}">
              ${wh.cantidad > 0 ? wh.cantidad + 'u' : wh.cantidad < 0 ? '⚠ ' + wh.cantidad + 'u' : (wh.detalle && wh.detalle.length > 0 ? '0u' : '— sin registro')}
            </div>
          </div>
        </div>
      </div>
    `;
    // Zonas
    const zonasHtml = `
      <div class="text-xs">
        <div class="font-semibold text-slate-300 mb-1">🏪 Distribución por zona (rot ${total.rangoDiasConsultado || 7}d)</div>
        <div class="card-sm p-2 space-y-1">
          ${zonas.map(z => {
            const sinReg = !z.tieneRegistroStock;
            const isNeg = z.cantidad < 0;
            const isCero = z.cantidad === 0;
            let stockStr, stockCls;
            if (sinReg) { stockStr = '— sin registro'; stockCls = 'text-slate-600 italic'; }
            else if (isNeg) { stockStr = `⚠ ${z.cantidad}u`; stockCls = 'text-rose-500'; }
            else if (isCero) { stockStr = '0u'; stockCls = 'text-slate-500'; }
            else { stockStr = z.cantidad + 'u'; stockCls = 'text-slate-200'; }
            let detail;
            if (sinReg && z.sinVentas) detail = '<span class="text-slate-600 italic">Producto no registrado en zona</span>';
            else if (z.sinVentas) detail = '<span class="text-slate-600">Sin ventas en ' + (total.rangoDiasConsultado || 7) + 'd</span>';
            else {
              detail = 'Vende ' + z.rotacionDia + '/d';
              if (z.diasParaAcabar !== null) detail += ` · alcanza ${z.diasParaAcabar}d`;
              else if (sinReg) detail += ' · <span class="text-rose-400">⚠ vendiéndose sin registro</span>';
              else if (isCero) detail += ' · <span class="text-rose-400">⚠ stock agotado</span>';
            }
            return `<div class="flex items-center justify-between gap-2 py-1">
              <div class="min-w-0 flex-1">
                <div class="text-slate-300">🏪 ${z.nombre}</div>
                <div class="text-[10px] text-slate-500">${detail}</div>
              </div>
              <div class="font-bold ${stockCls} shrink-0">${stockStr}</div>
            </div>`;
          }).join('')}
        </div>
      </div>
    `;
    // Insights
    const insightsHtml = insights.length ? `
      <div class="text-xs">
        <div class="font-semibold text-slate-300 mb-1">💡 Sugerencias</div>
        <div class="space-y-1">
          ${insights.map(i => {
            const cls = i.severidad === 'CRITICA' ? 'border-rose-500/40' : i.severidad === 'ALTA' ? 'border-amber-500/40' : 'border-slate-700';
            return `<div class="card-sm p-2 border-l-2 ${cls}">
              <div class="text-slate-200">${i.mensaje}</div>
              ${i.accion ? `<div class="text-[10px] text-slate-500 mt-0.5">→ ${i.accion}</div>` : ''}
            </div>`;
          }).join('')}
        </div>
      </div>
    ` : '';
    return `<div class="space-y-3">${codigosHtml}${matrizHtml}${whHtml}${zonasHtml}${insightsHtml}</div>`;
  }

  async function _fetchStockDetail(skuBase) {
    if (!skuBase) return;
    if (S._stockDetCache[skuBase] && !S._stockDetCache[skuBase].error) return;
    try {
      const r = await API.get('getStockUnificado', { skuBase });
      S._stockDetCache[skuBase] = r;
      // Re-render solo si la sección sigue expandida
      if (S._stockExpanded[skuBase]) {
        const cont = $('stockExp_' + skuBase);
        if (cont) cont.innerHTML = _renderStockExpandedContent(skuBase);
      }
    } catch(e) {
      S._stockDetCache[skuBase] = { error: e.message };
      if (S._stockExpanded[skuBase]) {
        const cont = $('stockExp_' + skuBase);
        if (cont) cont.innerHTML = _renderStockExpandedContent(skuBase);
      }
    }
  }

  function almToggleStockExpand(skuBase, idProducto) {
    if (!skuBase) return;
    S._stockExpanded[skuBase] = !S._stockExpanded[skuBase];
    // Re-render solo esa card (más rápido que renderStockTable completo)
    renderStockTable();
    // Si abrió y aún no tiene cache, ya disparó el fetch dentro del render
  }

  // Resuelve un código (idProducto, codigoBarra o equivalencia) al canónico.
  // Retorna { producto, descripcion, badge } para mostrar en tablas. Cae al código
  // crudo si no se puede resolver.
  // Resuelve un código a un producto del catálogo.
  // Por default sube al canónico (útil para stock/ventas que quieren ver
  // el agregado). Pasar `exacto=true` cuando necesitas el producto específico
  // (ej. envasados: el código apunta a la presentación, no al granel base).
  function _resolverCodigoAProducto(cod, exacto) {
    if (!cod || !S.productos || !S.productos.length) return null;
    const ref = String(cod).toUpperCase().trim();
    // 1. Match directo por idProducto o codigoBarra
    let p = S.productos.find(x =>
      String(x.idProducto || '').toUpperCase() === ref ||
      String(x.codigoBarra || '').toUpperCase() === ref
    );
    if (p) {
      if (exacto) return p;
      // Si es presentación o derivado, subir al canónico
      const canon = _buscarCanonicoFrontend(p) || p;
      return canon;
    }
    // 2. Buscar en equivalencias
    if (S.equivMap) {
      for (const sku in S.equivMap) {
        if ((S.equivMap[sku] || []).some(cb => String(cb).toUpperCase() === ref)) {
          const canon = S.productos.find(x => {
            const f = parseFloat(x.factorConversion);
            const esCanon = (f === 1 || isNaN(f) || x.factorConversion === '' || x.factorConversion === null) &&
                            !String(x.codigoProductoBase || '').trim();
            return esCanon && String(x.skuBase || '').toUpperCase() === String(sku).toUpperCase();
          });
          if (canon) return canon;
        }
      }
    }
    return null;
  }

  // Devuelve un label "DESCRIPCIÓN · cod" para mostrar al usuario.
  // exacto=true → mantiene el producto exacto (no sube al canónico).
  function _labelProducto(cod, exacto) {
    const p = _resolverCodigoAProducto(cod, exacto);
    if (!p) return `<span class="text-slate-500 font-mono">${cod}</span>`;
    const desc = p.descripcion || cod;
    return `<span class="text-slate-200">${desc}</span> <span class="text-[10px] text-slate-600 font-mono">▌${cod}</span>`;
  }

  // Helper: agrupa una lista por una clave de fecha (yyyy-MM-dd extraída del campo dado)
  function _almGroupByFecha(items, fechaKey) {
    const map = {};
    items.forEach(it => {
      const f = String(it[fechaKey] || '').substring(0, 10) || 'Sin fecha';
      if (!map[f]) map[f] = [];
      map[f].push(it);
    });
    const fechas = Object.keys(map).sort((a, b) => b.localeCompare(a));
    return { map, fechas };
  }
  function _almFechaLarga(s) {
    if (!s || s === 'Sin fecha') return 'Sin fecha';
    const d = new Date(s + 'T00:00:00');
    if (isNaN(d.getTime())) return s;
    const dias = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
    const meses = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
    return `${dias[d.getDay()]} ${d.getDate()} ${meses[d.getMonth()]} ${d.getFullYear()}`;
  }

  function renderVencTable() {
    const listC = $('listVencCrit');
    const listA = $('listVencAlerta');
    const criticos = S.vencimientos.criticos || [];
    const alertas  = S.vencimientos.alertas  || [];
    if (listC) {
      if (!criticos.length) {
        listC.innerHTML = '<p class="text-slate-500 text-sm py-4 text-center">✓ Sin vencimientos críticos</p>';
      } else {
        const { map, fechas } = _almGroupByFecha(criticos, 'fechaVencimiento');
        listC.innerHTML = fechas.map(f => {
          const items = map[f];
          return `
            <div class="alm-fecha-grupo critico">
              <div class="alm-fecha-head">
                <span class="alm-fecha-label">${_almFechaLarga(f)}</span>
                <span class="alm-fecha-count critico">${items.length} ${items.length === 1 ? 'lote' : 'lotes'}</span>
              </div>
              <div class="alm-fecha-items">
                ${items.map(l => `
                  <div class="alm-fecha-item critico">
                    <div class="min-w-0 flex-1">
                      <div class="text-xs text-slate-200 truncate">${_labelProducto(l.codigoProducto)}</div>
                      <div class="text-[10px] text-slate-500 mt-0.5">Lote ${l.idLote || '—'}${l.cantidad ? ' · ' + l.cantidad + ' un' : ''}</div>
                    </div>
                    <span class="badge badge-red shrink-0">${l.diasRestantes}d</span>
                  </div>
                `).join('')}
              </div>
            </div>`;
        }).join('');
      }
    }
    if (listA) {
      if (!alertas.length) {
        listA.innerHTML = '<p class="text-slate-500 text-sm py-4 text-center">✓ Sin alertas de vencimiento</p>';
      } else {
        const { map, fechas } = _almGroupByFecha(alertas, 'fechaVencimiento');
        listA.innerHTML = fechas.map(f => {
          const items = map[f];
          return `
            <div class="alm-fecha-grupo alerta">
              <div class="alm-fecha-head">
                <span class="alm-fecha-label">${_almFechaLarga(f)}</span>
                <span class="alm-fecha-count alerta">${items.length} ${items.length === 1 ? 'lote' : 'lotes'}</span>
              </div>
              <div class="alm-fecha-items">
                ${items.map(l => `
                  <div class="alm-fecha-item alerta">
                    <div class="min-w-0 flex-1">
                      <div class="text-xs text-slate-200 truncate">${_labelProducto(l.codigoProducto)}</div>
                      <div class="text-[10px] text-slate-500 mt-0.5">Lote ${l.idLote || '—'}${l.cantidad ? ' · ' + l.cantidad + ' un' : ''}</div>
                    </div>
                    <span class="badge badge-yellow shrink-0">${l.diasRestantes}d</span>
                  </div>
                `).join('')}
              </div>
            </div>`;
        }).join('');
      }
    }
  }

  function renderMermasTable() {
    // Buscar contenedor: si existe el viejo tbodyMermas, montamos arriba.
    // El host real será el panel almPanelMerma — vaciamos su contenido y
    // ponemos cards agrupadas por día.
    const panel = $('almPanelMerma');
    if (!panel) {
      const tbody = $('tbodyMermas');
      if (tbody) tbody.innerHTML = '';
      return;
    }
    let host = $('almMermasList');
    if (!host) {
      // Reemplazar la tabla vieja por un contenedor de cards
      const oldTable = panel.querySelector('table');
      if (oldTable) oldTable.style.display = 'none';
      host = document.createElement('div');
      host.id = 'almMermasList';
      host.className = 'space-y-3';
      panel.appendChild(host);
    }
    if (!S.mermas.length) {
      host.innerHTML = '<p class="text-slate-500 text-sm py-8 text-center">Sin mermas registradas</p>';
      return;
    }
    const { map, fechas } = _almGroupByFecha(S.mermas, 'fechaIngreso');
    host.innerHTML = fechas.map(f => {
      const items = map[f];
      const totalCant = items.reduce((s, m) => s + (parseFloat(m.cantidadPendiente) || 0), 0);
      const pendientes = items.filter(m => m.estado === 'PENDIENTE').length;
      return `
        <div class="alm-fecha-grupo merma">
          <div class="alm-fecha-head">
            <span class="alm-fecha-label">${_almFechaLarga(f)}</span>
            <div class="flex items-center gap-2 shrink-0">
              ${pendientes > 0 ? `<span class="alm-fecha-count alerta">${pendientes} pend</span>` : ''}
              <span class="alm-fecha-count">${items.length} item${items.length === 1 ? '' : 's'} · ${totalCant} un</span>
            </div>
          </div>
          <div class="alm-fecha-items">
            ${items.map(m => {
              const badge = m.estado === 'PENDIENTE' ? '<span class="badge badge-yellow">Pendiente</span>'
                          : m.estado === 'PROCESADA' ? '<span class="badge badge-green">Procesada</span>'
                          : '<span class="badge badge-gray">' + (m.estado || '—') + '</span>';
              return `
                <div class="alm-fecha-item">
                  <div class="min-w-0 flex-1">
                    <div class="text-xs text-slate-200 truncate">${_labelProducto(m.codigoProducto)}</div>
                    <div class="text-[10px] text-slate-500 mt-0.5">${m.origen || '—'}${m.cantidadPendiente ? ' · ' + m.cantidadPendiente + ' un' : ''}</div>
                  </div>
                  ${badge}
                </div>`;
            }).join('')}
          </div>
        </div>`;
    }).join('');
  }

  // ── Estado de filtros Envasados ────────────────────────────
  const _envFiltros = { rango: 'hoy', operador: '', agrupar: 'fecha', desde: '', hasta: '' };
  function _envHoyStr() {
    const d = new Date(); const z = n => String(n).padStart(2,'0');
    return `${d.getFullYear()}-${z(d.getMonth()+1)}-${z(d.getDate())}`;
  }
  function _envCalcularRango() {
    const hoy = new Date();
    const z = n => String(n).padStart(2,'0');
    const fmt = d => `${d.getFullYear()}-${z(d.getMonth()+1)}-${z(d.getDate())}`;
    if (_envFiltros.rango === 'todo')   return { desde: '0000-01-01',         hasta: '9999-12-31' };
    if (_envFiltros.rango === 'custom') return { desde: _envFiltros.desde || '0000-01-01', hasta: _envFiltros.hasta || '9999-12-31' };
    if (_envFiltros.rango === 'hoy')    return { desde: fmt(hoy),             hasta: fmt(hoy) };
    if (_envFiltros.rango === 'ayer') {
      const a = new Date(hoy); a.setDate(hoy.getDate() - 1);
      return { desde: fmt(a), hasta: fmt(a) };
    }
    if (_envFiltros.rango === 'semana') {
      const a = new Date(hoy); a.setDate(hoy.getDate() - 6);
      return { desde: fmt(a), hasta: fmt(hoy) };
    }
    if (_envFiltros.rango === 'mes') {
      const a = new Date(hoy); a.setDate(hoy.getDate() - 29);
      return { desde: fmt(a), hasta: fmt(hoy) };
    }
    return { desde: '0000-01-01', hasta: '9999-12-31' };
  }
  function envSetRango(r) {
    _envFiltros.rango = r;
    document.querySelectorAll('.env-pill').forEach(b => b.classList.toggle('active', b.dataset.rango === r));
    if (r !== 'custom') {
      const cr = $('envCustomRange'); if (cr) cr.classList.add('hidden');
    }
    renderEnvTable();
  }
  function envToggleCustom() {
    _envFiltros.rango = 'custom';
    document.querySelectorAll('.env-pill').forEach(b => b.classList.toggle('active', b.dataset.rango === 'custom'));
    const cr = $('envCustomRange'); if (cr) cr.classList.remove('hidden');
    const today = _envHoyStr();
    if ($('envDesde') && !$('envDesde').value) $('envDesde').value = today;
    if ($('envHasta') && !$('envHasta').value) $('envHasta').value = today;
    envSetCustom();
  }
  function envSetCustom() {
    _envFiltros.desde = $('envDesde')?.value || '';
    _envFiltros.hasta = $('envHasta')?.value || '';
    renderEnvTable();
  }
  function envSetOperador(op) { _envFiltros.operador = op; renderEnvTable(); }
  function envSetAgrupar(g) {
    _envFiltros.agrupar = g;
    document.querySelectorAll('.env-toggle').forEach(b => b.classList.toggle('active', b.dataset.agrupar === g));
    renderEnvTable();
  }

  // [v41.24] Estado tracking de IDs vistos para animar nuevos en polling
  S._envIdsVistos = S._envIdsVistos || new Set();

  function renderEnvTable() {
    const cont = $('envList');
    const summaryEl = $('envSummary');
    if (!cont) return;
    if (!S.envasados.length) {
      cont.innerHTML = '<div class="text-center py-12 text-slate-500 text-sm"><div class="text-4xl opacity-40 mb-2">🏷️</div>Sin envasados recientes</div>';
      if (summaryEl) summaryEl.textContent = '';
      _envRenderKpis({uds:0, env:0, ops:0, efi:0});
      return;
    }

    // Poblar selector de operadores
    const selOp = $('envFiltroOperador');
    if (selOp && selOp.options.length <= 1) {
      const opsSet = new Set();
      S.envasados.forEach(e => { if (e.usuario && _envEsCompleto(e)) opsSet.add(e.usuario.trim()); });
      Array.from(opsSet).sort().forEach(u => {
        const opt = document.createElement('option');
        opt.value = u; opt.textContent = '👤 ' + u;
        selOp.appendChild(opt);
      });
    }

    // Filtros (rango + operador). NOTA: incluyo anulados acá para poder
    // mostrarlos tachados, pero NO se cuentan en KPIs ni en totales.
    const { desde, hasta } = _envCalcularRango();
    const opFiltro = String(_envFiltros.operador || '').toLowerCase().trim();
    const filtrados = S.envasados.filter(e => {
      const f = String(e.fecha || '').substring(0, 10);
      if (!f) return false;
      if (f < desde || f > hasta) return false;
      if (opFiltro && String(e.usuario || '').toLowerCase().trim() !== opFiltro) return false;
      return true;
    });
    const completos = filtrados.filter(_envEsCompleto);

    if (!filtrados.length) {
      cont.innerHTML = '<div class="text-center py-12 text-slate-500 text-sm"><div class="text-4xl opacity-40 mb-2">📭</div>Sin envasados en este rango</div>';
      if (summaryEl) summaryEl.textContent = '0 envasados';
      _envRenderKpis({uds:0, env:0, ops:0, efi:0});
      return;
    }

    // KPIs: solo COMPLETADOS
    const totUds = completos.reduce((s, e) => s + (parseFloat(e.unidadesProducidas) || 0), 0);
    const opsSet = new Set();
    completos.forEach(e => { if (e.usuario) opsSet.add(e.usuario.trim()); });
    const efPromedio = completos.length
      ? completos.reduce((s, e) => s + (parseFloat(e.eficienciaPct) || 0), 0) / completos.length
      : 0;
    _envRenderKpis({uds: totUds, env: completos.length, ops: opsSet.size, efi: efPromedio});
    if (summaryEl) {
      const anulados = filtrados.length - completos.length;
      summaryEl.innerHTML = `${completos.length} envasado${completos.length === 1 ? '' : 's'} completado${completos.length === 1 ? '' : 's'}`
        + (anulados ? ` · <span class="text-rose-400">${anulados} anulado${anulados === 1 ? '' : 's'} (no cuentan)</span>` : '');
    }

    // [v41.24] Detectar nuevos para animar
    const idsActuales = new Set(filtrados.map(e => e.idEnvasado));
    const esPrimerRender = S._envIdsVistos.size === 0;
    const nuevos = [];
    idsActuales.forEach(id => { if (!S._envIdsVistos.has(id)) nuevos.push(id); });
    S._envIdsVistos = idsActuales;

    // Doble agrupación según vista: fecha→usuario o usuario→fecha
    const esPorOp = _envFiltros.agrupar === 'operador';
    const grupos = _envAgruparDoble(filtrados, esPorOp);
    cont.innerHTML = grupos.map(g => _envRenderGrupo(g, esPorOp, nuevos)).join('');

    // Beep + bounce si hay nuevos (no primer render)
    if (!esPrimerRender && nuevos.length > 0) {
      try { _opsBeep && _opsBeep('ping'); } catch(_){}
    }
  }

  // ── Helpers v41.24 ──
  function _envEsCompleto(e) {
    return String(e.estado || '').toUpperCase() === 'COMPLETADO';
  }

  // [v41.26] Extrae HH:mm SOLO via regex. Antes había fallback a new Date()
  // que con strings tipo "2026-05-15" sin hora daba 19:00 falso (UTC midnight
  // → Lima UTC-5 = 19:00 día anterior). Si el string no tiene hora explícita,
  // mejor mostrar vacío que mostrar una hora incorrecta.
  function _envExtraerHora(fechaStr) {
    if (!fechaStr) return '';
    const s = String(fechaStr);
    const m = s.match(/(\d{1,2}):(\d{2})/);
    if (m) return m[1].padStart(2, '0') + ':' + m[2];
    return '';
  }

  // Count-up animado en KPI numérico
  function _envRenderKpis({uds, env, ops, efi}) {
    _envCountUp('envKpiUds', uds);
    _envCountUp('envKpiEnv', env);
    _envCountUp('envKpiOps', ops);
    const el = $('envKpiEfi');
    if (el) el.textContent = efi > 0 ? Math.round(efi) + '%' : '—';
  }
  function _envCountUp(id, target) {
    const el = $(id);
    if (!el) return;
    const from = parseInt(el.textContent.replace(/\D/g, ''), 10) || 0;
    if (from === target) { el.textContent = target; return; }
    const duration = 600, start = Date.now();
    const tick = () => {
      const p = Math.min(1, (Date.now() - start) / duration);
      const ease = 1 - Math.pow(1 - p, 3);
      const val = Math.round(from + (target - from) * ease);
      el.textContent = val;
      if (p < 1) requestAnimationFrame(tick);
    };
    requestAnimationFrame(tick);
  }

  // Agrupa por [primaria, secundaria]. Si esPorOp: usuario→fecha. Si no: fecha→usuario.
  function _envAgruparDoble(items, esPorOp) {
    const map = {};
    items.forEach(e => {
      const fecha = String(e.fecha || '').substring(0, 10);
      const usuario = String(e.usuario || '— sin operador').trim();
      const k1 = esPorOp ? usuario : fecha;
      const k2 = esPorOp ? fecha : usuario;
      if (!k1 || !k2) return;
      if (!map[k1]) map[k1] = { key: k1, esPorOp, sub: {} };
      if (!map[k1].sub[k2]) map[k1].sub[k2] = { key: k2, items: [] };
      map[k1].sub[k2].items.push(e);
    });
    // Sort de grupos primarios
    return Object.values(map).sort((a, b) => {
      if (esPorOp) return a.key.localeCompare(b.key);
      return b.key.localeCompare(a.key);
    });
  }

  // Avatar: iniciales del usuario con color hash
  function _envAvatarHTML(usuario) {
    const iniciales = String(usuario || '?').split(/\s+/).map(p => (p[0] || '')).slice(0, 2).join('').toUpperCase() || '??';
    const colores = ['#6366f1', '#22d3ee', '#10b981', '#f59e0b', '#ec4899', '#a855f7', '#0ea5e9', '#84cc16'];
    let h = 0;
    for (let i = 0; i < usuario.length; i++) h = (h * 31 + usuario.charCodeAt(i)) | 0;
    const color = colores[Math.abs(h) % colores.length];
    return `<div class="env-avatar" style="background:linear-gradient(135deg,${color},${color}88)">${iniciales}</div>`;
  }

  // Render de un grupo primario
  function _envRenderGrupo(g, esPorOp, nuevos) {
    // Métricas del grupo primario (solo completos)
    const completos = [];
    const todos = [];
    Object.values(g.sub).forEach(s => s.items.forEach(it => {
      todos.push(it);
      if (_envEsCompleto(it)) completos.push(it);
    }));
    const totUds = completos.reduce((s, e) => s + (parseFloat(e.unidadesProducidas) || 0), 0);
    const totEnv = completos.length;
    const titulo = esPorOp
      ? `${_envAvatarHTML(g.key)}<div><div class="env-grupo-nombre">${_escapeHtml(g.key)}</div><div class="env-grupo-sub">operador</div></div>`
      : `<div class="env-grupo-fecha-emoji">📅</div><div><div class="env-grupo-nombre">${_envFmtFechaLarga(g.key)}</div><div class="env-grupo-sub">${Object.keys(g.sub).length} operador${Object.keys(g.sub).length === 1 ? '' : 'es'}</div></div>`;

    // Render sub-grupos
    const subKeys = Object.keys(g.sub).sort((a, b) => esPorOp ? b.localeCompare(a) : a.localeCompare(b));
    const subsHtml = subKeys.map(sk => _envRenderSubGrupo(g.sub[sk], !esPorOp, nuevos)).join('');

    return `<section class="env-grupo">
      <header class="env-grupo-head">
        <div class="env-grupo-titulo">${titulo}</div>
        <div class="env-grupo-stats">
          <div class="env-grupo-stat-uds">${totUds}<span>uds</span></div>
          <div class="env-grupo-stat-env">${totEnv} env${totEnv === 1 ? '' : 's'}</div>
        </div>
      </header>
      <div class="env-grupo-body">${subsHtml}</div>
    </section>`;
  }

  // Sub-grupo (segundo nivel) + timeline interno
  function _envRenderSubGrupo(s, esUsuario, nuevos) {
    const completos = s.items.filter(_envEsCompleto);
    const totUds = completos.reduce((sum, e) => sum + (parseFloat(e.unidadesProducidas) || 0), 0);
    const titulo = esUsuario
      ? `<div class="env-sub-head-user">${_envAvatarHTML(s.key)}<span class="env-sub-head-name">${_escapeHtml(s.key)}</span></div>`
      : `<div class="env-sub-head-fecha">📅 ${_envFmtFechaLarga(s.key)}</div>`;

    // Items ordenados cronológicamente
    const sorted = s.items.slice().sort((a, b) => String(a.fecha || '').localeCompare(String(b.fecha || '')));
    const timeline = sorted.map((e, i) => _envRenderTimelineItem(e, i, nuevos)).join('');

    return `<div class="env-sub">
      <div class="env-sub-head">
        ${titulo}
        <div class="env-sub-stats">${completos.length} env · <b>${totUds}</b> uds</div>
      </div>
      <div class="env-timeline">${timeline}</div>
    </div>`;
  }

  // Item del timeline (envasado individual)
  function _envRenderTimelineItem(e, idx, nuevos) {
    const completo = _envEsCompleto(e);
    const esNuevo = nuevos && nuevos.indexOf(e.idEnvasado) !== -1;
    const baseLbl = _labelProducto(e.codigoProductoBase, true);
    const envLbl = e.codigoProductoEnvasado
      ? _labelProducto(e.codigoProductoEnvasado, true)
      : '<span class="text-slate-600 italic">sin código envasado</span>';
    // [v41.25] Parser robusto: acepta "4/24/2026 15:04:33", ISO, etc.
    const hora = _envExtraerHora(e.fecha) || '—:—';
    const cantBase = parseFloat(e.cantidadBase) || 0;
    const cantBaseTxt = cantBase > 0 ? `${cantBase} ${e.unidadBase || ''}` : '—';
    const uds = parseFloat(e.unidadesProducidas) || 0;
    const efic = parseFloat(e.eficienciaPct) || 0;
    const obs = e.observacion ? `<div class="env-tl-obs">📝 ${_escapeHtml(String(e.observacion).substring(0, 80))}</div>` : '';

    const stateClass = completo ? '' : 'env-tl-item-anulado';
    const dotClass = completo ? 'env-tl-dot-ok' : 'env-tl-dot-anul';
    const nuevoClass = esNuevo ? ' env-tl-item-nuevo' : '';

    // [v2.43.108] Botón Imprimir adhesivo (solo si completo + tiene codigoBarra envasado)
    // [v2.43.109 BUG #4] Escapar idEnvasado para HTML/JS (defensivo: hoy nunca
    // tiene comillas pero blindamos por si el formato cambia).
    const puedeImprimir = completo && e.codigoProductoEnvasado;
    const idEnvSafe = String(e.idEnvasado || '').replace(/['"\\]/g, '');
    const btnAdhesivo = puedeImprimir
      ? `<button onclick="MOS.abrirModalImprimirAdhesivo('${idEnvSafe}')"
           class="env-tl-btn-adhesivo"
           title="Imprimir adhesivos para este envasado">
          🏷 <span>Imprimir adhesivo</span>
        </button>`
      : '';

    return `<div class="env-tl-item ${stateClass}${nuevoClass}" style="animation-delay:${Math.min(idx, 12) * 40}ms">
      <div class="${dotClass}"></div>
      <div class="env-tl-content">
        <div class="env-tl-row">
          <div class="env-tl-hora">${hora}</div>
          <div class="env-tl-trans">
            <div class="env-tl-base">${baseLbl} <span class="env-tl-base-cant">· ${cantBaseTxt}</span></div>
            <div class="env-tl-arrow">⬇</div>
            <div class="env-tl-out">${envLbl}</div>
          </div>
          <div class="env-tl-uds">
            <span class="env-tl-uds-num">${uds}</span>
            <span class="env-tl-uds-lbl">uds</span>
            ${efic && completo ? `<div class="env-tl-efi ${_envEfColor(efic)}">${Math.round(efic)}% efic</div>` : ''}
          </div>
          ${btnAdhesivo}
        </div>
        ${obs}
        ${!completo ? `<div class="env-tl-anul-tag">✕ ANULADO · no cuenta</div>` : ''}
      </div>
    </div>`;
  }

  function _envEfColor(pct) {
    return pct >= 98 ? 'text-emerald-400'
         : pct >= 90 ? 'text-amber-400'
         : 'text-rose-400';
  }

  // ═══════════════════════════════════════════════════════════════════
  // [v2.43.108] MÓDULO ADHESIVOS — Modal "Imprimir adhesivo" para envasados
  // ───────────────────────────────────────────────────────────────────
  // Replica del backend WH (_detectHighlightsEtq, _wrapTokensEtq) para
  // generar el preview visual coincidente con el TSPL2 real que imprimirá
  // la TSC TTP-244CE. El barcode usa JsBarcode (CDN ya incluido).
  //
  // Flujo:
  //   1. Click "🏷 Imprimir adhesivo" en card → abrirModalImprimirAdhesivo
  //   2. Pre-render con cantidad default = unidadesProducidas + check estado impresora
  //   3. User ajusta cantidad si quiere → preview se actualiza en vivo
  //   4. Click Imprimir → optimista: deshabilita, fire-and-forget
  //   5. Toast confirmación + cierre con animación
  // ═══════════════════════════════════════════════════════════════════

  // Estado del modal (1 a la vez)
  let _adhesivoState = null;

  // [v2.43.187 REFACTOR] _adhesivoNormalize, _adhesivoCalcVto, _envFmtMesAnio,
  // _adhesivoDetectHighlights, _adhesivoWrap → DELEGADOS al módulo compartido
  // AdhesivoPreview (asset cargado desde /assets/adhesivo/preview.js).
  // Antes eran ~150 LOC duplicadas con WH. Ahora un solo source of truth.

  // _adhesivoExtraerDatos: solo construye la lista de siblings y llama al módulo.
  function _adhesivoExtraerDatos(env) {
    const codigoBarra = env.codigoProductoEnvasado;
    if (!codigoBarra) return null;
    if (!window.AdhesivoPreview) {
      console.error('[MOS] AdhesivoPreview module no cargado');
      return null;
    }
    // Buscar el producto en el catálogo de stock (S.catalogoStock)
    const stockArr = S.catalogoStock || [];
    const prod = stockArr.find(p =>
      String(p.codigoBarra || p.idProducto || '').trim() === String(codigoBarra).trim()
    );
    const descripcion = prod ? (prod.descripcion || codigoBarra) : codigoBarra;

    // Construir lista de siblings: tokens de otros envasables (códigos que
    // empiezan con WH) para que el módulo detecte highlights diferenciales.
    const siblings = [];
    const norm = AdhesivoPreview.normalize;
    stockArr.forEach(p => {
      const c = String(p.codigoBarra || p.idProducto || '').toUpperCase();
      if (c.indexOf('WH') !== 0) return;
      const desc = p.descripcion || '';
      if (!desc) return;
      siblings.push(norm(desc).toUpperCase().split(/\s+/).filter(Boolean));
    });

    const proc = AdhesivoPreview.procesar({
      codigoBarra:   codigoBarra,
      descripcion:   descripcion,
      fechaEnvasado: env.fecha,
      siblings:      siblings
    });
    if (!proc) return null;

    // Mantener forma antigua del objeto (defaultCantidad, idEnvasado) para no
    // romper código que consume el retorno.
    return Object.assign(proc, {
      defaultCantidad: parseInt(env.unidadesProducidas) || 1,
      idEnvasado:      env.idEnvasado
    });
  }

  // ── ABRIR MODAL ────────────────────────────────────────────────
  // [v2.43.110 FIX TDZ] Las funciones se exponen al final del IIFE en el
  // return { ... } (igual que el resto de MOS). Acá las declaramos como
  // funciones normales del scope del IIFE.
  let _adhesivoSeq = 0;
  function abrirModalImprimirAdhesivo(idEnvasado) {
    const env = (S.envasados || []).find(x => x.idEnvasado === idEnvasado);
    if (!env) { toast('Envasado no encontrado', 'error'); return; }
    const datos = _adhesivoExtraerDatos(env);
    if (!datos) { toast('Sin código envasado para imprimir adhesivos', 'warn'); return; }
    // [v2.43.109 BUG #3] Validar descripción mínima para que el preview tenga sentido
    if (!datos.descripcion || datos.descripcion === datos.codigoBarra) {
      toast('Producto sin descripción cargada en catálogo. Refrescá Almacén primero.', 'warn', 6000);
      return;
    }
    // [v2.43.187] Inyectar CSS del módulo (idempotente — guard interno).
    // Asegura las clases .adhesivo-* generadas por AdhesivoPreview.renderHtml.
    if (window.AdhesivoPreview) AdhesivoPreview.inyectarCss();
    const sessionId = ++_adhesivoSeq;
    _adhesivoState = {
      sessionId,                                         // [BUG #1] identificador único
      env, datos,
      cantidad: datos.defaultCantidad,
      imprimiendo: false,
      impresoraEstado: 'verificando',
      // [BUG #2] Idempotency key ESTABLE durante esta sesión del modal.
      // Si el user reintenta el mismo botón, la key incluye sessionId+cantidad
      // así que reintentos con misma cantidad → mismo print (dedup backend).
      // Cambio de cantidad → key distinta → nuevo print.
      sessionTs: Date.now()
    };
    _adhesivoRenderModal();
    _adhesivoVerificarImpresora(sessionId);
  }

  function _adhesivoRenderModal() {
    const st = _adhesivoState;
    if (!st) return;
    const { datos, cantidad } = st;
    const old = document.getElementById('adhesivoModal');
    if (old) old.remove();
    const html = `
      <div id="adhesivoModal" class="adhesivo-backdrop"
           onclick="if(event.target===this) MOS.cerrarModalImprimirAdhesivo()">
        <div class="adhesivo-modal" onclick="event.stopPropagation()">
          <header class="adhesivo-head">
            <div class="adhesivo-head-titulo">
              <span class="adhesivo-head-emoji">🏷</span>
              <div>
                <div class="adhesivo-head-h1">IMPRIMIR ADHESIVO</div>
                <div class="adhesivo-head-sub">${_escapeHtml(datos.descripcion)}</div>
              </div>
            </div>
            <button onclick="MOS.cerrarModalImprimirAdhesivo()" class="adhesivo-close" title="Cerrar (ESC)">✕</button>
          </header>

          <section class="adhesivo-preview-wrap">
            <div class="adhesivo-preview-lbl">Vista previa · 50×25mm reales (escala 2:1)</div>
            <div class="adhesivo-preview" id="adhesivoPreview">
              ${_adhesivoRenderEtiquetaHTML(datos, cantidad)}
            </div>
          </section>

          <section class="adhesivo-controles">
            <div class="adhesivo-control-group">
              <label class="adhesivo-label">Cantidad a imprimir</label>
              <div class="adhesivo-cantidad">
                <button onclick="MOS.adhesivoCantidadDelta(-1)" class="adhesivo-cant-btn">−</button>
                <input type="number" id="adhesivoInput" value="${cantidad}" min="1" max="500"
                       oninput="MOS.adhesivoCantidadInput(this.value)"
                       class="adhesivo-cant-input">
                <button onclick="MOS.adhesivoCantidadDelta(1)" class="adhesivo-cant-btn">+</button>
              </div>
              <div class="adhesivo-hint">Por defecto = ${datos.defaultCantidad} (unidades envasadas)</div>
            </div>

            <div class="adhesivo-impresora" id="adhesivoImpresoraInfo">
              <span class="adhesivo-imp-dot adhesivo-imp-dot-verificando"></span>
              <span class="adhesivo-imp-txt">Verificando impresora…</span>
            </div>
          </section>

          <footer class="adhesivo-foot">
            <button onclick="MOS.cerrarModalImprimirAdhesivo()" class="adhesivo-btn-secondary">Cancelar</button>
            <button id="adhesivoBtnCalibrar"
                    onclick="MOS.adhesivoCalibrar()"
                    class="adhesivo-btn-calibrar"
                    title="Calibra el sensor de gap. Úsalo si las impresiones salen corridas o al cambiar el rollo. Consume ~3 etiquetas en blanco.">
              🎯 Calibrar
            </button>
            <button id="adhesivoBtnImprimir"
                    onclick="MOS.adhesivoImprimir()"
                    class="adhesivo-btn-primary"
                    disabled
                    title="Esperando estado de impresora…">
              <span id="adhesivoBtnImprimirTxt">🖨 Imprimir</span>
            </button>
          </footer>
        </div>
      </div>`;
    document.body.insertAdjacentHTML('beforeend', html);
    // Render barcode después de insertar (JsBarcode necesita el SVG en el DOM)
    requestAnimationFrame(() => _adhesivoDibujarBarcode(datos.codigoBarra));
    // ESC cierra · Enter dispara imprimir (si habilitado)
    document.addEventListener('keydown', _adhesivoKeydown);
  }

  // [v2.43.187 REFACTOR] _adhesivoRenderEtiquetaHTML y _adhesivoDibujarBarcode
  // delegados al módulo compartido AdhesivoPreview. ~130 LOC eliminadas.
  // El logo bitmap (_ADHESIVO_LOGO_DATAURI) también vive en el módulo.
  // El svgId queda fijo como 'adhesivoBarcodeSVG' por compat con código existente.
  function _adhesivoRenderEtiquetaHTML(datos, cantidad) {
    if (!window.AdhesivoPreview) return '<div style="color:#dc2626">Módulo AdhesivoPreview no cargado</div>';
    return AdhesivoPreview.renderHtml(datos, {
      cantidad: cantidad,
      svgId:    'adhesivoBarcodeSVG'  // ID fijo para que _adhesivoDibujarBarcode lo encuentre
    });
  }

  function _adhesivoDibujarBarcode(codigoBarra) {
    if (!window.AdhesivoPreview) return;
    const svg = document.getElementById('adhesivoBarcodeSVG');
    AdhesivoPreview.dibujarBarcode(svg, codigoBarra);
  }

  function adhesivoCantidadDelta(d) {
    if (!_adhesivoState) return;
    const nv = Math.max(1, Math.min(500, _adhesivoState.cantidad + d));   // tope 500 por impresion
    _adhesivoState.cantidad = nv;
    _adhesivoActualizarCantidadUI();
  }
  function adhesivoCantidadInput(v) {
    if (!_adhesivoState) return;
    const n = Math.max(1, Math.min(500, parseInt(v) || 1));   // tope 500 por impresion
    _adhesivoState.cantidad = n;
    const tag = document.querySelector('#adhesivoPreview .adhesivo-cantidad-tag');
    if (tag) tag.textContent = '×' + n;
  }
  function _adhesivoActualizarCantidadUI() {
    const input = document.getElementById('adhesivoInput');
    if (input) input.value = _adhesivoState.cantidad;
    const tag = document.querySelector('#adhesivoPreview .adhesivo-cantidad-tag');
    if (tag) tag.textContent = '×' + _adhesivoState.cantidad;
  }

  // [v2.43.109 BUG #1] Recibe sessionId — descarta respuesta si el modal
  // se cerró y se abrió otro con datos distintos en el intermedio.
  // [v2.43.109 BUG #6] Distingue error de red ('error') de offline real.
  // Antes una respuesta null se tomaba como offline → mensaje engañoso al user.
  async function _adhesivoVerificarImpresora(sessionId) {
    try {
      const r = await API.post('wh_estadoImpresoraAdhesivo', {});
      if (!_adhesivoState || _adhesivoState.sessionId !== sessionId) return;
      if (r && typeof r.esOnline === 'boolean') {
        _adhesivoState.impresoraEstado = r.esOnline ? 'online' : 'offline';
        _adhesivoState.impresoraInfo = r;
      } else {
        _adhesivoState.impresoraEstado = 'error';
        _adhesivoState.impresoraInfo = { error: 'Backend no respondió formato esperado' };
      }
      _adhesivoActualizarChipImpresora();
    } catch(e) {
      if (!_adhesivoState || _adhesivoState.sessionId !== sessionId) return;
      _adhesivoState.impresoraEstado = 'error';
      _adhesivoState.impresoraInfo = { error: e?.message || 'error red' };
      _adhesivoActualizarChipImpresora();
    }
  }

  function _adhesivoActualizarChipImpresora() {
    const wrap = document.getElementById('adhesivoImpresoraInfo');
    const btn = document.getElementById('adhesivoBtnImprimir');
    if (!wrap) return;
    const st = _adhesivoState;
    const estado = st.impresoraEstado;
    const info = st.impresoraInfo || {};
    if (estado === 'online') {
      wrap.innerHTML = `<span class="adhesivo-imp-dot adhesivo-imp-dot-online"></span>
        <span class="adhesivo-imp-txt">🟢 <b>${_escapeHtml(info.nombre || 'Impresora ADHESIVO')}</b> · online</span>`;
      if (btn) { btn.disabled = false; btn.title = ''; }
    } else if (estado === 'offline') {
      wrap.innerHTML = `<span class="adhesivo-imp-dot adhesivo-imp-dot-offline"></span>
        <span class="adhesivo-imp-txt">🔴 <b>${_escapeHtml(info.nombre || 'Impresora')}</b> offline · revisá PrintNode Client</span>`;
      if (btn) { btn.disabled = true; btn.title = 'Impresora offline'; }
    } else {
      wrap.innerHTML = `<span class="adhesivo-imp-dot adhesivo-imp-dot-error"></span>
        <span class="adhesivo-imp-txt">⚠ No se pudo verificar (${_escapeHtml(info.error || 'sin detalles')})</span>`;
      // Si no se pudo verificar igual permitimos intentar — el backend valida real
      if (btn) { btn.disabled = false; btn.title = 'Intentar igual'; }
    }
  }

  // ─────────────────────────────────────────────────────────────────
  // [v2.43.119] Sistema de impresión por LOTES con sub-jobs.
  //
  // Flujo:
  //   1. adhesivoImprimir() — crea el lote en backend + abre modal de progreso
  //   2. _loteOrquestar() — itera mandando sub-jobs uno a uno
  //   3. Estado se actualiza en modal en tiempo real
  //   4. Si OUT_OF_PAPER → muestra modal cambio de rollo → continuar
  //   5. Si COMPLETADO → cierra modal con celebración
  //
  // Reemplaza el "1 sola request a wh_imprimirEtiqueta". Beneficios:
  //   - Drift acumulativo controlado (GAPDETECT al inicio)
  //   - Detección de fin de rollo automática
  //   - Reanudación con calibración nueva
  //   - Tracking visual del progreso (47/200)
  // ─────────────────────────────────────────────────────────────────
  let _loteState = null;
  // _loteState = { idLote, total, completadas, status, polling, cantConfirmacionRollo }

  async function adhesivoImprimir() {
    const st = _adhesivoState;
    if (!st || st.imprimiendo) return;
    st.imprimiendo = true;

    // [v2.43.123 OPTIMISTIC] Cerrar modal de imprimir + abrir modal de
    // progreso INMEDIATAMENTE, sin esperar al backend. El operario ve
    // feedback instantáneo. El idLote se completa cuando responde.
    const totalSnapshot     = st.cantidad;
    const descSnapshot      = st.datos.descripcion;
    const codigoSnapshot    = st.datos.codigoBarra;
    const idEnvSnapshot     = st.env.idEnvasado;
    const fechaSnapshot     = st.env.fecha;
    const sessionTsSnapshot = st.sessionTs;
    cerrarModalImprimirAdhesivo(true /* rápido sin animación */);
    _loteAbrirModalProgreso({
      idLote:      '',  // placeholder mientras backend crea
      total:       totalSnapshot,
      completadas: 0,
      subJobSize:  10,
      descripcion: descSnapshot,
      codigoBarra: codigoSnapshot,
      vto:         ''
    });
    _loteSetStatus('CREADO');

    try {
      const idempotencyKey = 'adh_lote_' + idEnvSnapshot + '_' + totalSnapshot + '_' + sessionTsSnapshot;
      // [v2.43.159] Fallback robusto del nombre — los lotes desde MOS quedaban con usuario='' .
      const _usrAdmin = (window.S?.session?.nombre || '').trim()
                     || (window.S?.session?.idPersonal || '').trim()
                     || 'admin-MOS';

      // [v2.43.300 · 100% Supabase] PRIMARIO: Edge print-adhesivo (mode:'crear') → crea el lote ATÓMICO +
      // imprime server-side. La cantidad EXACTA marcada = total = lo impreso (reserve-first + CHECK
      // completadas<=total → over-print imposible, mismo motor que WH envasado). Si el flag server
      // WH_LOTE_ADHESIVO_DIRECTO está OFF → la RPC devuelve *_OFF → FALLBACK al path GAS histórico.
      _loteSetStatus('IMPRIMIENDO');
      let viaSupabase = false;
      try {
        const ed = await API.adhesivoImprimirEdge({
          codigoBarra: codigoSnapshot, descripcion: descSnapshot, total: totalSnapshot,
          fechaEnvasado: fechaSnapshot, usuario: _usrAdmin, idempotencyKey
        });
        if (ed && ed.ok && ed.data) {
          viaSupabase = true;
          if (!_loteState) return;
          const d = ed.data;
          _loteState.idLote = d.idLote || _loteState.idLote;
          _loteState.total  = d.total  || totalSnapshot;
          const st = String(d.status || '');
          if (st === 'COMPLETADO') {
            _loteState.completadas = _loteState.total;
            _loteState.status = 'COMPLETADO';
            _loteRenderProgreso();
            _loteCelebrarCompletado();
          } else if (st.indexOf('PAUSADO') === 0) {
            _loteState.completadas = d.completadas || _loteState.completadas;
            _loteSetStatus(st, d.error || 'Pausado');
            if (st === 'PAUSADO_OUT_PAPER') _loteMostrarRolloAgotado();
          } else {
            // PRESUPUESTO_AGOTADO (lote enorme): el cron retoma lo que falte.
            _loteState.completadas = d.completadas || _loteState.completadas;
            _loteState.status = 'IMPRIMIENDO';
            _loteRenderProgreso();
          }
        } else if (ed && ed.ok === false && !/_OFF/.test(String(ed.error || ''))) {
          // Error REAL de la Edge (no flag OFF) → NO caer a GAS (la Edge pudo reservar/imprimir parte).
          // El usuario reintenta (idempotencyKey estable → dedup, sin doble).
          if (!_loteState) return;
          viaSupabase = true;
          _loteSetStatus('PAUSADO_ERROR', 'Edge: ' + (ed.error || 'error'));
        }
        // ed.ok===false con *_OFF → viaSupabase queda false → cae a GAS abajo (kill-switch).
      } catch (eEdge) {
        // Red/timeout de la Edge: la Edge PUDO imprimir → NO caer a GAS. Pausar; reintento por idempotencyKey.
        if (!_loteState) return;
        viaSupabase = true;
        _loteSetStatus('PAUSADO_ERROR', 'Sin confirmación de impresión: ' + (eEdge?.message || 'red') + ' — reintenta');
      }

      if (!viaSupabase) {
        // FALLBACK GAS (flag server OFF) — path histórico con orquestación de sub-jobs.
        const r = await API.post('wh_crearLoteAdhesivo', {
          codigoBarra: codigoSnapshot, descripcion: descSnapshot, total: totalSnapshot,
          usuario: _usrAdmin, origen: 'MOS', fechaEnvasado: fechaSnapshot, idempotencyKey
        });
        if (r && r.ok === false) throw new Error(r.error || 'Backend rechazó');
        if (!_loteState) return;
        _loteState.idLote      = r.idLote;
        _loteState.total       = r.total || totalSnapshot;
        _loteState.subJobSize  = r.subJobSize || 10;
        _loteState.descripcion = r.descripcion || _loteState.descripcion;
        _loteState.vto         = r.vto || _loteState.vto;
        _loteRenderProgreso();
        _loteOrquestar(r.idLote);
      }
    } catch(e) {
      _loteSetStatus('PAUSADO_ERROR', 'No se pudo crear el lote: ' + (e?.message || 'desconocido'));
      if (_adhesivoState) _adhesivoState.imprimiendo = false;
    }
  }

  // Orquestador: manda sub-jobs uno a uno hasta completar/pausar/cancelar.
  // Re-entrante: si llamamos durante un sub-job en curso, no duplica.
  async function _loteOrquestar(idLote, opts) {
    if (!_loteState || _loteState.idLote !== idLote) return;
    if (_loteState.orquestando) return;  // ya hay un loop activo
    _loteState.orquestando = true;
    // [v2.43.120 AUDIT FIX #2] requireGapDetect debe consumirse SOLO en el
    // primer ciclo. Antes era `const` constante → todos los sub-jobs
    // siguientes hacían GAPDETECT también, perdiendo ~1 etq por cada 10.
    let pendingGapDetect = !!(opts && opts.requireGapDetect);
    try {
      while (_loteState && _loteState.idLote === idLote) {
        if (['CANCELADO', 'COMPLETADO', 'PAUSADO_USUARIO', 'PAUSADO_OUT_PAPER', 'PAUSADO_ERROR'].indexOf(_loteState.status) >= 0) {
          break;
        }
        // Mostrar "calibrando" si vamos a GAPDETECT
        const necesitaCal = pendingGapDetect || _loteState.completadas === 0;
        if (necesitaCal) _loteSetStatus('CALIBRANDO');
        let r;
        try {
          r = await API.post('wh_imprimirSubLoteAdhesivo', {
            idLote:            idLote,
            requireGapDetect:  necesitaCal
          });
          // Reset del flag para los siguientes sub-jobs del mismo loop.
          if (necesitaCal) pendingGapDetect = false;
        } catch (e) {
          _loteSetStatus('PAUSADO_ERROR', 'Sin conexión: ' + (e?.message || ''));
          break;
        }
        if (!_loteState || _loteState.idLote !== idLote) break;
        if (r && r.ok === false) {
          // Backend ya marcó el lote como PAUSADO_OUT_PAPER o PAUSADO_ERROR
          _loteSetStatus(r.status || 'PAUSADO_ERROR', r.error || 'Error desconocido');
          if ((r.status || '') === 'PAUSADO_OUT_PAPER') _loteMostrarRolloAgotado();
          break;
        }
        // OK — actualizar contador y status
        _loteState.completadas = r.completadas || _loteState.completadas;
        _loteState.status      = r.status      || 'IMPRIMIENDO';
        _loteRenderProgreso();
        if (_loteState.status === 'COMPLETADO') {
          _loteCelebrarCompletado();
          break;
        }
        // Pequeño respiro entre sub-jobs (la impresora ya está procesando el anterior)
        await new Promise(res => setTimeout(res, 250));
      }
    } finally {
      if (_loteState) _loteState.orquestando = false;
    }
  }

  function _loteSetStatus(status, errMsg) {
    if (!_loteState) return;
    _loteState.status = status;
    if (errMsg) _loteState.ultimoError = errMsg;
    _loteRenderProgreso();
  }

  function _loteAbrirModalProgreso(meta) {
    _loteState = {
      idLote:      meta.idLote,
      total:       meta.total,
      completadas: 0,
      subJobSize:  meta.subJobSize || 10,
      descripcion: meta.descripcion || '',
      codigoBarra: meta.codigoBarra || '',
      vto:         meta.vto || '',
      status:      'CREADO',
      ultimoError: '',
      orquestando: false,
      tInicio:     Date.now()
    };
    const html = `
      <div class="adhesivo-backdrop" id="loteOverlay" style="z-index:99995">
        <div class="lote-modal">
          <div class="lote-head">
            <div class="lote-head-emoji">🏭</div>
            <div class="lote-head-text">
              <div class="lote-head-h1">LOTE DE IMPRESIÓN</div>
              <div class="lote-head-sub" id="loteSub">${_escapeHtml(_loteState.descripcion)}</div>
            </div>
          </div>
          <div class="lote-body">
            <div class="lote-stat-row">
              <div class="lote-status-chip" id="loteStatusChip">⏳ creando…</div>
              <div class="lote-counter" id="loteCounter">0 / ${_loteState.total}</div>
            </div>
            <div class="lote-progress">
              <div class="lote-progress-bar" id="loteBar" style="width:0%"></div>
            </div>
            <div class="lote-info-row">
              <span id="loteVelocidad">— etq/min</span>
              <span id="loteRestante">estimado: —</span>
            </div>
            <div class="lote-error" id="loteError" style="display:none"></div>
            <div class="lote-actions" id="loteActions">
              <button onclick="MOS.loteCancelar()" class="lote-btn lote-btn-warn">⊘ Cancelar lote</button>
            </div>
          </div>
        </div>
      </div>`;
    document.body.insertAdjacentHTML('beforeend', html);
    _loteRenderProgreso();
  }

  function _loteRenderProgreso() {
    if (!_loteState) return;
    const pct = _loteState.total > 0 ? (_loteState.completadas / _loteState.total * 100) : 0;
    const bar = document.getElementById('loteBar');
    if (bar) bar.style.width = pct.toFixed(1) + '%';
    const counter = document.getElementById('loteCounter');
    if (counter) counter.textContent = _loteState.completadas + ' / ' + _loteState.total;
    const chip = document.getElementById('loteStatusChip');
    if (chip) {
      const map = {
        CREADO:            { cls: 'lote-chip-info',   txt: '<span class="adhesivo-spin">◐</span> preparando lote…' },
        CALIBRANDO:        { cls: 'lote-chip-warn',   txt: '<span class="adhesivo-spin">◐</span> calibrando rollo…' },
        IMPRIMIENDO:       { cls: 'lote-chip-ok',     txt: '🖨 imprimiendo' },
        PAUSADO_USUARIO:   { cls: 'lote-chip-warn',   txt: '⏸ pausado' },
        PAUSADO_OUT_PAPER: { cls: 'lote-chip-error',  txt: '🛑 rollo agotado' },
        PAUSADO_ERROR:     { cls: 'lote-chip-error',  txt: '❌ error' },
        COMPLETADO:        { cls: 'lote-chip-ok',     txt: '✅ completado' },
        CANCELADO:         { cls: 'lote-chip-warn',   txt: '⊘ cancelado' }
      };
      const m = map[_loteState.status] || { cls: 'lote-chip-info', txt: _loteState.status };
      chip.className = 'lote-status-chip ' + m.cls;
      chip.innerHTML = m.txt;
    }
    // Velocidad y restante (estimado)
    const elapsedSec = (Date.now() - _loteState.tInicio) / 1000;
    if (_loteState.completadas > 0 && elapsedSec > 1) {
      const velMin = (_loteState.completadas / elapsedSec * 60).toFixed(0);
      const restante = _loteState.total - _loteState.completadas;
      const segRestantes = restante / (_loteState.completadas / elapsedSec);
      const elVel = document.getElementById('loteVelocidad');
      const elRest = document.getElementById('loteRestante');
      if (elVel) elVel.textContent = velMin + ' etq/min';
      if (elRest) elRest.textContent = 'estimado: ' + Math.ceil(segRestantes) + ' seg';
    }
    // Error
    const elErr = document.getElementById('loteError');
    if (elErr) {
      if (_loteState.ultimoError) {
        elErr.style.display = 'block';
        elErr.textContent = '⚠ ' + _loteState.ultimoError;
      } else {
        elErr.style.display = 'none';
      }
    }
  }

  function _loteMostrarRolloAgotado() {
    const actions = document.getElementById('loteActions');
    if (!actions || !_loteState) return;
    const restante = _loteState.total - _loteState.completadas;
    actions.innerHTML = `
      <div class="lote-alert">
        <div class="lote-alert-titulo">🛑 Rollo agotado</div>
        <div class="lote-alert-msg">
          Se imprimieron <b>~${_loteState.completadas}</b> de ${_loteState.total}. Faltan <b>${restante}</b>.<br>
          Cambiá el rollo y dale a Continuar.<br>
          <span class="lote-alert-warn">⚠ Hasta ${_loteState.subJobSize} etiquetas pueden duplicarse del rollo viejo (caso del sub-job interrumpido).</span>
        </div>
        <div class="lote-alert-btns">
          <button onclick="MOS.loteContinuar()" class="lote-btn lote-btn-primary">✓ Continuar (rollo nuevo)</button>
          <button onclick="MOS.loteCancelar()" class="lote-btn lote-btn-warn">⊘ Cancelar lote</button>
        </div>
      </div>`;
  }

  function _loteCelebrarCompletado() {
    try { toast('✅ Lote completado: ' + _loteState.total + ' adhesivos impresos', 'success', 6000); } catch(_){}
    try {
      if (typeof _decirEnVoz === 'function') _decirEnVoz('Lote completado, ' + _loteState.total + ' adhesivos impresos');
    } catch(_){}
    // Cerrar modal después de 2.5s
    setTimeout(() => { loteCerrarModal(); }, 2500);
  }

  async function loteContinuar() {
    if (!_loteState) return;
    // Forzar nuevo GAPDETECT al reanudar
    _loteSetStatus('CALIBRANDO');
    const actions = document.getElementById('loteActions');
    if (actions) actions.innerHTML = '<button onclick="MOS.loteCancelar()" class="lote-btn lote-btn-warn">⊘ Cancelar lote</button>';
    _loteOrquestar(_loteState.idLote, { requireGapDetect: true });
  }

  async function loteCancelar() {
    if (!_loteState) return;
    if (!await _modalConfirm('¿Cancelar el lote de impresión?\n\n' + _loteState.completadas + ' de ' + _loteState.total + ' ya impresas no se borran del rollo.', { warning: true, titulo: 'Cancelar lote' })) return;  // [Lote4 · M3-MOS]
    try {
      await API.post('wh_cancelarLoteAdhesivo', { idLote: _loteState.idLote });
    } catch(_){}
    _loteSetStatus('CANCELADO');
    setTimeout(loteCerrarModal, 800);
  }

  function loteCerrarModal() {
    const ov = document.getElementById('loteOverlay');
    if (ov) {
      ov.style.animation = 'adhesivoOut .22s ease-out forwards';
      setTimeout(() => ov.remove(), 220);
    }
    _loteState = null;
  }

  // [v2.43.111] Calibrar impresora — GAPDETECT + FORMFEED en TSPL puro.
  // Recomendado al cambiar rollo de etiquetas o cuando las impresiones
  // empiezan a salir corridas. Consume ~3 etiquetas en blanco mientras
  // la impresora mide el sensor de gap.
  async function adhesivoCalibrar() {
    const btn = document.getElementById('adhesivoBtnCalibrar');
    if (btn && btn.disabled) return;
    if (!await _modalConfirm('¿Calibrar la impresora ahora?\n\nLa impresora va a sacar ~3 etiquetas en blanco mientras mide el sensor de gap. Úsalo si las impresiones salen corridas del adhesivo o si recién cambiaste el rollo.', { titulo: 'Calibrar impresora' })) return;  // [Lote4 · M3-MOS]
    if (btn) { btn.disabled = true; btn.textContent = '⏳ Calibrando…'; }
    try {
      const r = await API.post('wh_calibrarImpresoraAdhesivo', {});
      if (r && r.ok === false) throw new Error(r.error || 'Backend rechazó');
      if (btn) btn.textContent = '✅ Calibrada';
      try { toast('🎯 Calibración enviada · ya podés imprimir alineado', 'success', 6000); } catch(_){}
      setTimeout(() => { if (btn) { btn.textContent = '🎯 Calibrar'; btn.disabled = false; } }, 3000);
    } catch(e) {
      if (btn) { btn.textContent = '❌ Error'; btn.disabled = false; }
      try { toast('Error al calibrar: ' + (e?.message || 'desconocido'), 'error', 6000); } catch(_){}
      setTimeout(() => { if (btn) btn.textContent = '🎯 Calibrar'; }, 3000);
    }
  }

  function cerrarModalImprimirAdhesivo(rapido) {
    const modal = document.getElementById('adhesivoModal');
    if (modal) {
      if (rapido) {
        modal.remove();
      } else {
        modal.style.animation = 'adhesivoOut .22s ease-out forwards';
        setTimeout(() => modal.remove(), 220);
      }
    }
    document.removeEventListener('keydown', _adhesivoKeydown);
    _adhesivoState = null;
  }

  function _adhesivoKeydown(ev) {
    if (ev.key === 'Escape') { cerrarModalImprimirAdhesivo(); return; }
    if (ev.key === 'Enter') {
      const btn = document.getElementById('adhesivoBtnImprimir');
      if (btn && !btn.disabled) adhesivoImprimir();
    }
  }
  function _envFmtFechaLarga(yyyymmdd) {
    if (!yyyymmdd) return '—';
    const m = String(yyyymmdd).match(/^(\d{4})-(\d{2})-(\d{2})/);
    if (!m) return yyyymmdd;
    const d = new Date(parseInt(m[1]), parseInt(m[2]) - 1, parseInt(m[3]));
    const hoy = new Date(); hoy.setHours(0,0,0,0);
    const dms = d.getTime();
    const ayer = new Date(hoy.getTime() - 86400000);
    if (dms === hoy.getTime())  return 'Hoy ' + m[3] + '/' + m[2];
    if (dms === ayer.getTime()) return 'Ayer ' + m[3] + '/' + m[2];
    return d.toLocaleDateString('es-PE', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' });
  }

  // ── PROVEEDORES ─────────────────────────────────────────────
  const PROV_CACHE_KEY = 'mos_prov_cache';
  function _provLoadCache() {
    try {
      const raw = localStorage.getItem(PROV_CACHE_KEY);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (Date.now() - (parsed.ts || 0) > 86400000) return null; // 24h
      return parsed.data;
    } catch { return null; }
  }
  function _provSaveCache(data) {
    try { localStorage.setItem(PROV_CACHE_KEY, JSON.stringify({ ts: Date.now(), data })); } catch {}
  }

  // ── Cache de productos enriquecidos por proveedor ───────────
  // Key única por proveedor → { ts, data }. TTL: 30 min.
  const PROV_PRODS_CACHE_KEY = 'mos_prov_prods_cache';
  const PROV_PRODS_TTL = 30 * 60 * 1000; // 30 min
  function _provProdsLoadCache(idProveedor) {
    try {
      const raw = localStorage.getItem(PROV_PRODS_CACHE_KEY);
      if (!raw) return null;
      const all = JSON.parse(raw);
      const entry = all && all[idProveedor];
      if (!entry) return null;
      if (Date.now() - (entry.ts || 0) > PROV_PRODS_TTL) return null;
      return entry.data;
    } catch { return null; }
  }
  function _provProdsSaveCache(idProveedor, data) {
    try {
      const raw = localStorage.getItem(PROV_PRODS_CACHE_KEY);
      const all = raw ? JSON.parse(raw) : {};
      all[idProveedor] = { ts: Date.now(), data };
      localStorage.setItem(PROV_PRODS_CACHE_KEY, JSON.stringify(all));
    } catch {}
  }
  // Hidratar S.provProductos desde localStorage al inicio (todos los proveedores)
  function _provProdsHidratarTodos() {
    try {
      const raw = localStorage.getItem(PROV_PRODS_CACHE_KEY);
      if (!raw) return;
      const all = JSON.parse(raw) || {};
      S.provProductos = S.provProductos || {};
      Object.keys(all).forEach(idProv => {
        const entry = all[idProv];
        if (entry && entry.data && Date.now() - (entry.ts || 0) <= PROV_PRODS_TTL) {
          S.provProductos[idProv] = entry.data;
        }
      });
    } catch {}
  }

  async function loadProveedores() {
    if (!API.isConfigured()) {
      $('listProveedores').innerHTML = '<p class="text-slate-500 text-sm text-center py-8">Configura el GAS URL.</p>';
      return;
    }
    // Hidratar productos por proveedor desde localStorage para render instantáneo
    _provProdsHidratarTodos();
    // Render desde cache (instantáneo)
    const cached = _provLoadCache();
    if (cached && (!S.proveedores || !S.proveedores.length)) {
      S.proveedores = cached;
      renderProveedores();
    }
    // Fetch fresco
    try {
      const fresh = await API.get('getProveedores', {});
      const lista = Array.isArray(fresh) ? fresh : (fresh && fresh.data) || [];
      const changed = JSON.stringify(lista) !== JSON.stringify(S.proveedores);
      S.proveedores = lista;
      _provSaveCache(lista);
      if (changed || !cached) renderProveedores();
      // Pre-fetch de productos en background (silencioso, no bloquea UI)
      _provProdsPrefetchEnBackground(lista);
    } catch(e) {
      if (!S.proveedores || !S.proveedores.length) {
        $('listProveedores').innerHTML = `<p class="text-red-400 text-sm text-center py-8">${e.message}</p>`;
      }
    }
  }

  // Pre-fetch en background de productos por proveedor.
  // Estrategia: arranca por el último proveedor visitado (si existe) y
  // luego itera secuencialmente con un pequeño throttle. Salta proveedores
  // que ya tienen cache fresco (TTL).
  let _provProdsPrefetching = false;
  function _provProdsPrefetchEnBackground(proveedores) {
    if (_provProdsPrefetching) return;
    if (!Array.isArray(proveedores) || !proveedores.length) return;
    const lista = _filtrarReales(proveedores);
    if (!lista.length) return;
    _provProdsPrefetching = true;
    iconBusy('proveedores', true);
    let lastId = null;
    try { lastId = localStorage.getItem('mos_prov_last_sel'); } catch {}
    // Ordenar: último visitado primero, después por orden natural
    const orden = lista.slice().sort((a, b) => {
      if (a.idProveedor === lastId) return -1;
      if (b.idProveedor === lastId) return 1;
      return 0;
    });
    let i = 0;
    function siguiente() {
      if (i >= orden.length) { _provProdsPrefetching = false; iconBusy('proveedores', false); return; }
      const prov = orden[i++];
      const idProv = prov.idProveedor;
      // Skip si ya hay cache fresco
      if (_provProdsLoadCache(idProv)) {
        setTimeout(siguiente, 50);
        return;
      }
      API.get('getProductosProveedorConStock', { idProveedor: idProv, rangoDias: 30 })
        .then(r => {
          const items = Array.isArray(r) ? r : (r && r.data) || [];
          S.provProductos = S.provProductos || {};
          S.provProductos[idProv] = items;
          _provProdsSaveCache(idProv, items);
          // Refrescar badge X/Y del card del proveedor en la lista
          _refreshProvPendientesBadge(idProv);
          // Si el usuario está viendo este proveedor en este momento, refrescar UI
          if (S.provSelId === idProv && S.provTab === 'productos') _renderProvProductos();
        })
        .catch(() => {})
        .finally(() => { setTimeout(siguiente, 800); });
    }
    siguiente();
  }

  // Filtra proveedores excluyendo cargadores (nombre prefijo CARGADOR)
  function _filtrarReales(lista) {
    return (lista || []).filter(p => !String(p.nombre || '').toUpperCase().startsWith('CARGADOR'));
  }
  function _filtrarCargadores(lista) {
    return (lista || []).filter(p => String(p.nombre || '').toUpperCase().startsWith('CARGADOR'));
  }

  // Refresh silencioso periódico (igual que catalogo)
  let _provRefreshTimer = null;
  function _startProvRefresh() {
    if (_provRefreshTimer) clearInterval(_provRefreshTimer);
    _provRefreshTimer = setInterval(() => {
      loadProveedores().catch(() => {});
    }, 120000); // cada 2 minutos
  }

  // ── Cargadores (proveedores con prefijo CARGADOR) ─────────
  function abrirVistaCargadores() {
    _renderCargadores();
    openModal('modalCargadores');
  }

  function _renderCargadores() {
    const cargadores = _filtrarCargadores(S.proveedores);
    const cnt = $('cargCount');
    if (cnt) cnt.textContent = cargadores.length;
    const list = $('listCargadores');
    if (!list) return;
    if (!cargadores.length) {
      list.innerHTML = '<p class="text-sm text-slate-500 text-center py-6">No hay cargadores registrados.</p>';
      return;
    }
    list.innerHTML = cargadores.map(c => `
      <div class="card-sm p-3 cursor-pointer hover:border-amber-500/30 transition-colors" onclick="MOS.editarCargador('${c.idProveedor}')">
        <div class="flex items-center justify-between">
          <div class="min-w-0 flex-1">
            <div class="text-sm font-semibold text-slate-100 truncate">${c.nombre}</div>
            <div class="text-xs text-slate-500 mt-0.5">${c.telefono || ''} ${c.dni ? '· DNI ' + c.dni : ''}</div>
          </div>
          <span class="text-xs text-slate-400">✏️</span>
        </div>
      </div>
    `).join('');
  }

  // Cierra el modal de cargadores y abre el modal de edición de proveedor
  function editarCargador(idProveedor) {
    closeModal('modalCargadores');
    setTimeout(() => abrirModalProveedor(idProveedor), 100);
  }

  function nuevoCargador() {
    closeModal('modalCargadores');
    abrirModalProveedor(null);
    // Pre-llenar el nombre con prefijo
    setTimeout(() => {
      const inp = $('provNombre');
      if (inp && !inp.value) inp.value = 'CARGADOR ';
    }, 50);
  }

  // ── Buscador de proveedores ─────────────────────────────────
  const _DIA_LABELS = {
    LUNES: 'Lun', MARTES: 'Mar', MIERCOLES: 'Mié', JUEVES: 'Jue',
    VIERNES: 'Vie', SABADO: 'Sáb', DOMINGO: 'Dom',
    DIARIO: 'Diario', SEGUN_DEMANDA: 'Según demanda',
    MISMO_DIA: 'Mismo día', '24H': '24 h', '48H': '48 h',
    CONTRA_ENTREGA: 'Contra entrega', FIN_DE_MES: 'Fin de mes'
  };
  function _provDiaLabel(v) {
    if (!v) return '—';
    return _DIA_LABELS[String(v).toUpperCase()] || v;
  }

  // Mapa día-de-semana → número (1=Lun, 7=Dom). null si no es un día semanal.
  const _DIA_NUM = { LUNES:1, MARTES:2, MIERCOLES:3, JUEVES:4, VIERNES:5, SABADO:6, DOMINGO:7 };
  function _provDiaANumero(v) {
    if (!v) return null;
    const n = _DIA_NUM[String(v).toUpperCase()];
    return n || null;  // DIARIO/SEGUN_DEMANDA/etc → null (no aplica urgencia)
  }
  // Devuelve día de hoy 1=Lun..7=Dom
  function _provHoyNum() {
    const d = new Date().getDay();   // 0=Dom..6=Sab
    return d === 0 ? 7 : d;
  }
  // Días faltantes hasta el próximo "diaSemana" (1..7). 0 si es hoy. NaN si dia inválido.
  function _provDiasHastaProx(diaSemana) {
    if (!diaSemana) return NaN;
    const hoy = _provHoyNum();
    let d = diaSemana - hoy;
    if (d < 0) d += 7;
    return d;
  }

  // Categoriza la urgencia de pedido de un proveedor.
  // Devuelve { estado, dias, label, cls } donde estado es:
  //   'hoy'      — diaPedido cae hoy (urgente)
  //   'proximo'  — en 1..3 días
  //   'lejano'   — en 4..6 días o sin día específico (DIARIO/SEGUN_DEMANDA)
  //   'sinDia'   — sin diaPedido configurado
  //   'inactivo' — estado del proveedor != '1'
  function _provUrgenciaPedido(p) {
    if (!p) return { estado: 'lejano', dias: NaN, label: '—', cls: '' };
    if (String(p.estado || '0') !== '1') {
      return { estado: 'inactivo', dias: NaN, label: 'Inactivo', cls: 'prov-urg-inactivo' };
    }
    const num = _provDiaANumero(p.diaPedido);
    if (!num) {
      // DIARIO se trata como "siempre puedes pedir" → lejano (no urgente, no rojo)
      const upper = String(p.diaPedido || '').toUpperCase();
      if (upper === 'DIARIO' || upper === 'SEGUN_DEMANDA' || upper === 'MISMO_DIA') {
        return { estado: 'lejano', dias: 0, label: 'Diario', cls: 'prov-urg-lejano' };
      }
      return { estado: 'sinDia', dias: NaN, label: 'Sin día', cls: 'prov-urg-sindia' };
    }
    const dias = _provDiasHastaProx(num);
    if (dias === 0)        return { estado: 'hoy',     dias: 0, label: 'PEDIR HOY',                    cls: 'prov-urg-hoy' };
    if (dias <= 3)         return { estado: 'proximo', dias,    label: `en ${dias} día${dias>1?'s':''}`, cls: 'prov-urg-proximo' };
    return                       { estado: 'lejano',  dias,    label: `en ${dias} días`,                cls: 'prov-urg-lejano' };
  }

  // Avatar con imagen real si existe, fallback a iniciales con color hash
  function _provAvatarHtmlFull(prov, sizeCls) {
    const cls = sizeCls || 'prov-avatar';
    const txt = String(prov.nombre || '?').trim();
    const img = (prov.imagen || '').trim();
    if (img) {
      // Logo del proveedor: img redonda
      const safe = img.replace(/"/g, '&quot;');
      return `<div class="${cls} prov-avatar-img"><img src="${safe}" alt="" loading="lazy" onerror="this.parentElement.innerHTML='${_provAvatarInicialesInner(txt)}'"></div>`;
    }
    return _provAvatarHtml(prov.nombre).replace('class="prov-avatar"', `class="${cls}"`);
  }
  // Helper: HTML interno (sin wrapper) para el fallback en onerror
  function _provAvatarInicialesInner(nombre) {
    const partes = String(nombre || '?').split(/\s+/);
    const ini = ((partes[0] || '?')[0] + (partes[1] ? partes[1][0] : '')).toUpperCase();
    return ini.replace(/'/g, '&#39;');
  }

  // Sparkline simple de los últimos 30 días de compras del proveedor.
  // Si no hay datos cached, devuelve vacío (no rompe).
  function _provSparkBars(idProveedor) {
    const hist = (S.provHistorico && S.provHistorico[idProveedor]) || null;
    const fuente = hist && Array.isArray(hist.guiasPorDia) ? hist.guiasPorDia : null;
    if (!fuente || !fuente.length) return '';
    const dias = fuente.slice(-30);
    const max = dias.reduce((m, d) => Math.max(m, parseFloat(d.totalDia || 0)), 1);
    const bars = dias.map(d => {
      const v = parseFloat(d.totalDia || 0);
      const h = Math.max(2, Math.round((v / max) * 18));
      const cls = v === 0 ? 'zero' : '';
      return `<div class="prov-spark-bar ${cls}" style="height:${h}px" title="${d.fecha}: S/ ${v.toFixed(2)}"></div>`;
    }).join('');
    return `<div class="prov-spark">${bars}</div>`;
  }

  // ── Filtro de urgencia: pills arriba de la lista ──────────────
  // S.provUrgFiltro persistido en sessionStorage para no perderlo al navegar.
  function _provGetFiltroUrg() {
    if (S.provUrgFiltro) return S.provUrgFiltro;
    try { S.provUrgFiltro = sessionStorage.getItem('mos_prov_urg') || 'todos'; }
    catch { S.provUrgFiltro = 'todos'; }
    return S.provUrgFiltro;
  }
  function provSetFiltroUrgencia(filtro) {
    S.provUrgFiltro = filtro;
    try { sessionStorage.setItem('mos_prov_urg', filtro); } catch {}
    _finBeep?.('click');
    renderProveedores();
  }

  // Aplica filtro de urgencia a la lista (se llama después del filtro de búsqueda)
  function _provAplicarFiltroUrgencia(lista) {
    const f = _provGetFiltroUrg();
    if (f === 'todos') return lista;
    return lista.filter(p => {
      const u = _provUrgenciaPedido(p);
      if (f === 'hoy')        return u.estado === 'hoy';
      if (f === 'proximos')   return u.estado === 'hoy' || u.estado === 'proximo';
      if (f === 'atrasados')  return u.estado === 'inactivo';   // hoy no hay "atrasado real" por modelo
      return true;
    });
  }

  // Ordena por urgencia (HOY → próximos asc por días → lejano → sinDia → inactivo)
  function _provOrdenarPorUrgencia(lista) {
    const orden = { hoy: 0, proximo: 1, lejano: 2, sinDia: 3, inactivo: 4 };
    return lista.slice().sort((a, b) => {
      const ua = _provUrgenciaPedido(a);
      const ub = _provUrgenciaPedido(b);
      const oa = orden[ua.estado] ?? 9;
      const ob = orden[ub.estado] ?? 9;
      if (oa !== ob) return oa - ob;
      // Mismo estado: el de menor días faltantes primero (NaN al final)
      const da = isNaN(ua.dias) ? 99 : ua.dias;
      const db = isNaN(ub.dias) ? 99 : ub.dias;
      if (da !== db) return da - db;
      // Empate total: alfabético por nombre
      return String(a.nombre || '').localeCompare(String(b.nombre || ''));
    });
  }

  // Píldora decisional para el header: pedido o entrega.
  // diaCampo: valor del campo del proveedor (LUNES, DIARIO, etc.)
  // titulo: texto del header (PEDIDO, ENTREGA)
  // emoji: icon
  // opts.contextDia: para entrega — calcula "+N días después del pedido"
  function _provPildoraDia(diaCampo, titulo, emoji, opts) {
    if (!diaCampo) return _provPildoraVacia(titulo, emoji, '—', '');
    const upper = String(diaCampo).toUpperCase();
    // Casos no-semanales
    if (upper === 'DIARIO')           return _provPildoraVacia(titulo, emoji, 'Diario', 'prov-pild-neutral');
    if (upper === 'SEGUN_DEMANDA')    return _provPildoraVacia(titulo, emoji, 'Según demanda', 'prov-pild-neutral');
    if (upper === 'MISMO_DIA')        return _provPildoraVacia(titulo, emoji, 'Mismo día', 'prov-pild-neutral');
    if (upper === 'CONTRA_ENTREGA')   return _provPildoraVacia(titulo, emoji, 'Contra entrega', 'prov-pild-neutral');
    if (upper === '24H')              return _provPildoraVacia(titulo, emoji, '24 horas', 'prov-pild-neutral');
    if (upper === '48H')              return _provPildoraVacia(titulo, emoji, '48 horas', 'prov-pild-neutral');
    if (upper === 'FIN_DE_MES')       return _provPildoraVacia(titulo, emoji, 'Fin de mes', 'prov-pild-neutral');
    // Día semanal: calcular distancia
    const dias = _provDiasHastaProx(_provDiaANumero(diaCampo));
    if (isNaN(dias)) return _provPildoraVacia(titulo, emoji, _provDiaLabel(diaCampo), '');
    const labelDia = _provDiaLabel(diaCampo);
    let texto, cls;
    if (dias === 0)     { texto = `🔥 HOY (${labelDia})`;            cls = 'prov-pild-hoy'; }
    else if (dias === 1){ texto = `Mañana (${labelDia})`;            cls = 'prov-pild-proximo'; }
    else if (dias <= 3) { texto = `en ${dias} días (${labelDia})`;   cls = 'prov-pild-proximo'; }
    else                { texto = `en ${dias} días (${labelDia})`;   cls = 'prov-pild-lejano'; }
    return `
      <div class="prov-pild ${cls}">
        <div class="prov-pild-head">${emoji} ${titulo}</div>
        <div class="prov-pild-body">${texto}</div>
      </div>`;
  }

  function _provPildoraVacia(titulo, emoji, texto, cls) {
    return `
      <div class="prov-pild ${cls || ''}">
        <div class="prov-pild-head">${emoji} ${titulo}</div>
        <div class="prov-pild-body">${texto}</div>
      </div>`;
  }

  // Píldora de PAGO: combina diaPago semanal + plazoCredito.
  function _provPildoraPago(prov) {
    const dia   = prov.diaPago;
    const plazo = parseInt(prov.plazoCredito || 0, 10);
    const fp    = String(prov.formaPago || '').toUpperCase();
    if (fp === 'CONTADO') {
      return _provPildoraVacia('PAGO', '💸', 'Al contado', 'prov-pild-neutral');
    }
    if (dia) {
      const upper = String(dia).toUpperCase();
      if (upper === 'FIN_DE_MES') return _provPildoraVacia('PAGO', '💸', 'Fin de mes', 'prov-pild-neutral');
      const num = _provDiaANumero(dia);
      if (num) {
        const ddiff = _provDiasHastaProx(num);
        const label = _provDiaLabel(dia);
        const sufijo = plazo ? ` · plazo ${plazo}d` : '';
        let txt, cls;
        if (ddiff === 0)        { txt = `🔥 HOY (${label})${sufijo}`;            cls = 'prov-pild-hoy'; }
        else if (ddiff === 1)   { txt = `Mañana (${label})${sufijo}`;            cls = 'prov-pild-proximo'; }
        else if (ddiff <= 3)    { txt = `en ${ddiff} días (${label})${sufijo}`;  cls = 'prov-pild-proximo'; }
        else                    { txt = `en ${ddiff} días (${label})${sufijo}`;  cls = 'prov-pild-lejano'; }
        return `<div class="prov-pild ${cls}"><div class="prov-pild-head">💸 PAGO</div><div class="prov-pild-body">${txt}</div></div>`;
      }
    }
    if (plazo) return _provPildoraVacia('PAGO', '💸', `Plazo ${plazo} días`, 'prov-pild-neutral');
    return _provPildoraVacia('PAGO', '💸', '—', '');
  }

  // Abre el modal de Histórico (reemplaza la pestaña). Usa data ya cargada o pide.
  // Renderiza directamente al body del modal usando el render legacy detrás de
  // una redirección temporal — evitamos duplicar IDs (provHistFilter, etc).
  async function provAbrirHistorico(id) {
    const prov = S.proveedores.find(p => p.idProveedor === id);
    if (!prov) return;
    _finBeep?.('click');
    const sub = $('provHistModalSub');
    if (sub) sub.textContent = prov.nombre + ' · últimos 60 días';
    openModal('modalProvHistorico');
    const body = $('provHistModalBody');
    if (!body) return;
    body.innerHTML = '<p class="text-center py-8 text-slate-500 text-xs">Cargando...</p>';
    try {
      // Asegurar data cacheada
      if (!S.provHistorico[id]) {
        const r = await API.get('getHistoricoProveedor', { idProveedor: id, dias: 60 });
        S.provHistorico[id] = (r && r.data) ? r.data : r;
      }
      const data = S.provHistorico[id];
      // Renderizar histórico (reusa _renderProvHistorico → escribe en provTabHistorico oculto)
      _renderProvHistorico();
      // Mover el body interior (sin filtro/select para evitar IDs duplicados) al modal
      const sourceBody = document.querySelector('#provTabHistorico #provHistoricoBody');
      if (sourceBody && sourceBody.innerHTML.trim()) {
        body.innerHTML = sourceBody.innerHTML;
      } else if (data && (data.totalGuias || (data.guiasPorDia && data.guiasPorDia.length))) {
        // El render aún no terminó (fetch async) — mostrar resumen mínimo
        body.innerHTML = `<p class="text-center py-6 text-slate-400 text-sm">Cargando detalle…</p>`;
        setTimeout(() => {
          const sb = document.querySelector('#provTabHistorico #provHistoricoBody');
          if (sb && sb.innerHTML.trim()) body.innerHTML = sb.innerHTML;
        }, 400);
      } else {
        body.innerHTML = '<p class="text-center py-8 text-slate-500 text-xs italic">Sin compras en los últimos 60 días</p>';
      }
    } catch (e) {
      body.innerHTML = `<p class="text-center py-8 text-rose-400 text-xs">Error: ${e.message}</p>`;
    }
  }

  // Abre el pop-down con datos secundarios del proveedor (banco, CCI, email, etc).
  function provAbrirInfo(id) {
    const prov = S.proveedores.find(p => p.idProveedor === id);
    if (!prov) return;
    _finBeep?.('click');
    const sub = $('provInfoModalSub');
    if (sub) sub.textContent = prov.nombre;
    const body = $('provInfoModalBody');
    if (!body) return;
    const row = (label, val, emoji) => val ? `
      <div class="prov-info-row">
        <span class="prov-info-row-label">${emoji || ''} ${label}</span>
        <span class="prov-info-row-val">${val}</span>
      </div>` : '';
    body.innerHTML =
      row('RUC',           prov.ruc,            '🪪') +
      row('Teléfono',      prov.telefono,       '📞') +
      row('Email',         prov.email,          '📧') +
      row('Banco',         prov.banco,          '🏦') +
      row('Nº Cuenta',     prov.numeroCuenta,   '🔢') +
      row('CCI',           prov.cci,            '🔢') +
      row('Forma de pago', (prov.formaPago === 'CREDITO' ? 'Crédito ' + (prov.plazoCredito||0) + 'd' : prov.formaPago) || '', '💳') +
      row('Día pedido',    _provDiaLabel(prov.diaPedido),  '📋') +
      row('Día entrega',   _provDiaLabel(prov.diaEntrega), '📦') +
      row('Día pago',      _provDiaLabel(prov.diaPago),    '💸') +
      row('Plazo crédito', prov.plazoCredito ? prov.plazoCredito + ' días' : '', '⏱') +
      row('Categoría',     prov.categoriaProducto, '🏷') +
      row('Responsable',   prov.responsable,    '👤') +
      row('Estado',        prov.estado === '1' ? 'Activo' : 'Inactivo', '⚙');
    openModal('modalProvInfo');
  }

  function _provRenderFiltrosUrgencia(lista) {
    const cont = $('provFiltrosUrgencia');
    if (!cont) return;
    // Conteo por estado
    const cnt = { hoy: 0, proximo: 0, lejano: 0, sinDia: 0, inactivo: 0 };
    lista.forEach(p => { cnt[_provUrgenciaPedido(p).estado] = (cnt[_provUrgenciaPedido(p).estado] || 0) + 1; });
    const f = _provGetFiltroUrg();
    const total = lista.length;
    const proximos = cnt.hoy + cnt.proximo;

    const pill = (key, label, count, color) => {
      const active = f === key;
      const cls = active ? 'prov-urg-pill active ' + color : 'prov-urg-pill ' + color;
      return `<button class="${cls}" onclick="MOS.provSetFiltroUrgencia('${key}')">${label} <span class="prov-urg-pill-cnt">${count}</span></button>`;
    };

    let html = '';
    html += pill('hoy',       '🔥 Pedir hoy',  cnt.hoy,    'rojo');
    html += pill('proximos',  '⏳ Próximos 3d', proximos,   'amber');
    html += pill('todos',     '📋 Todos',      total,      'neutral');
    if (cnt.inactivo > 0) html += pill('atrasados', '⚠ Inactivos', cnt.inactivo, 'gris');

    cont.innerHTML = html;
  }

  function _normaliza(s) {
    return String(s || '').toLowerCase()
      .normalize('NFD').replace(/[̀-ͯ]/g, '');
  }

  function _provFiltrarPorQuery(lista, q) {
    const qn = _normaliza(q).trim();
    if (!qn) return lista;
    const tokens = qn.split(/\s+/).filter(Boolean);
    return lista.filter(p => {
      const blob = _normaliza([
        p.nombre, p.ruc, p.telefono, p.email,
        p.categoriaProducto, p.banco, p.responsable,
        p.diaPedido, p.diaEntrega, p.diaPago, p.formaPago
      ].filter(Boolean).join(' '));
      return tokens.every(t => blob.indexOf(t) >= 0);
    });
  }

  function provBuscar(q) {
    S.provQuery = q || '';
    const inp = $('provSearch');
    if (inp && inp.value !== S.provQuery) inp.value = S.provQuery;
    const clr = $('provSearchClear');
    if (clr) clr.classList.toggle('hidden', !S.provQuery);
    // Toggle estado del contenedor: si hay query, ensancha el input y oculta pills
    const wrap = $('provFilasFiltro');
    if (wrap) wrap.classList.toggle('has-query', !!S.provQuery);
    renderProveedores();
  }

  // Avatar de iniciales con color hash estable por nombre
  function _provAvatarHtml(nombre) {
    const txt = String(nombre || '?').trim();
    const partes = txt.split(/\s+/);
    const ini = ((partes[0] || '?')[0] + (partes[1] ? partes[1][0] : '')).toUpperCase();
    let h = 0;
    for (let i = 0; i < txt.length; i++) h = (h * 31 + txt.charCodeAt(i)) >>> 0;
    const colors = [
      ['#fbbf24', '#78350f'], ['#a78bfa', '#3b0764'], ['#34d399', '#064e3b'],
      ['#f87171', '#7f1d1d'], ['#60a5fa', '#1e3a8a'], ['#fb923c', '#7c2d12'],
      ['#4ade80', '#14532d'], ['#e879f9', '#581c87'], ['#22d3ee', '#164e63']
    ];
    const [bg, fg] = colors[h % colors.length];
    return `<div class="prov-avatar" style="background:${bg};color:${fg}">${ini}</div>`;
  }

  function _provTelLimpio(tel) {
    const d = String(tel || '').replace(/\D/g, '');
    return d.length === 9 ? '51' + d : d;
  }

  // Cuenta productos del proveedor que necesitan reposición:
  // - alerta NEGATIVO / BAJO_MINIMO / AGOTAR_PRONTO / CERCA_MINIMO
  // - o sugerencia > 0
  function _provContarPendientes(idProveedor) {
    const lista = (S.provProductos && S.provProductos[idProveedor]) || null;
    if (!lista) return null;
    let pend = 0;
    for (let i = 0; i < lista.length; i++) {
      const pp = lista[i];
      const a = (pp.alerta || '').toUpperCase();
      if (a === 'NEGATIVO' || a === 'BAJO_MINIMO' || a === 'AGOTAR_PRONTO' || a === 'CERCA_MINIMO') {
        pend++;
      } else if ((pp.sugerencia || 0) > 0) {
        pend++;
      }
    }
    return { pend, total: lista.length };
  }

  // Refresca solo el badge X/Y del card de un proveedor (sin re-render completo)
  function _refreshProvPendientesBadge(idProveedor) {
    if (!idProveedor) return;
    const card = document.querySelector(`[data-prov-card="${idProveedor}"]`);
    if (!card) return;
    const slot = card.querySelector('[data-prov-pend]');
    if (!slot) return;
    const stats = _provContarPendientes(idProveedor);
    slot.outerHTML = _provPendBadgeHtml(idProveedor, stats);
  }

  function _provPendBadgeHtml(idProv, stats) {
    if (!stats) {
      return `<span class="prov-pend-badge muted" data-prov-pend="${idProv}" title="Aún sin datos de stock — abriendo cargará">·/·</span>`;
    }
    if (!stats.total) {
      return `<span class="prov-pend-badge muted" data-prov-pend="${idProv}" title="Sin productos en el catálogo del proveedor">0/0</span>`;
    }
    if (stats.pend > 0) {
      return `<span class="prov-pend-badge alerta" data-prov-pend="${idProv}" title="${stats.pend} de ${stats.total} productos necesitan reposición — toca para ver">${stats.pend}/${stats.total}</span>`;
    }
    return `<span class="prov-pend-badge ok" data-prov-pend="${idProv}" title="Stock OK en los ${stats.total} productos">${stats.total}/${stats.total}</span>`;
  }

  function provLlamar(idProveedor, ev) {
    if (ev) ev.stopPropagation();
    const p = S.proveedores.find(x => x.idProveedor === idProveedor);
    if (!p || !p.telefono) { toast('Sin teléfono', 'error'); return; }
    window.location.href = 'tel:' + p.telefono;
  }
  function provWhatsApp(idProveedor, ev) {
    if (ev) ev.stopPropagation();
    const p = S.proveedores.find(x => x.idProveedor === idProveedor);
    if (!p || !p.telefono) { toast('Sin teléfono', 'error'); return; }
    window.open('https://wa.me/' + _provTelLimpio(p.telefono), '_blank');
  }

  function renderProveedores() {
    const el = $('listProveedores');
    if (!el) return;
    const reales = _filtrarReales(S.proveedores);
    const filtradosTexto = _provFiltrarPorQuery(reales, S.provQuery || '');
    // Pills de urgencia se computan sobre lo filtrado por texto (no por urgencia)
    _provRenderFiltrosUrgencia(filtradosTexto);
    // Filtro de urgencia + orden por urgencia
    const filtrados = _provOrdenarPorUrgencia(_provAplicarFiltroUrgencia(filtradosTexto));
    const cnt = $('provCount');
    if (cnt) cnt.textContent = filtrados.length + (S.provQuery ? ' / ' + reales.length : '');
    if (!reales.length) {
      el.innerHTML = '<p class="text-slate-500 text-sm text-center py-8">Sin proveedores</p>';
      return;
    }
    if (!filtrados.length) {
      el.innerHTML = `<p class="text-slate-500 text-sm text-center py-8">Sin resultados</p>`;
      return;
    }
    // Card minimalista: el detalle ya repite todos los datos secundarios
    // (RUC, forma pago, día pago, botones llamar/whatsapp). Aquí solo lo
    // estrictamente necesario para responder "¿lo abro o no?".
    el.innerHTML = filtrados.map((p, idx) => {
      const sel = S.provSelId === p.idProveedor;
      const urg = _provUrgenciaPedido(p);
      const pendStats = _provContarPendientes(p.idProveedor);
      const pendBadge = _provPendBadgeHtml(p.idProveedor, pendStats);
      const cartStats = _provCarritoResumen(p.idProveedor);
      const cartBadge = cartStats
        ? `<span class="prov-cart-badge" data-prov-cart-badge="${p.idProveedor}" title="Carrito: ${cartStats.count} prods · ${fmtMoney(cartStats.monto)}">🛒 ${cartStats.count}</span>`
        : `<span data-prov-cart-badge="${p.idProveedor}" style="display:none"></span>`;
      // Stagger fade-up suave: max 12 cards animados (después es CSS instantáneo)
      const staggerDelay = idx < 12 ? (idx * 30) : 0;
      const staggerStyle = staggerDelay > 0 ? `style="animation-delay:${staggerDelay}ms"` : '';

      return `
        <div class="prov-card-modern ${urg.cls} ${sel ? 'prov-card-active' : ''} ${p._tmp ? 'opacity-60' : ''}"
             data-prov-card="${p.idProveedor}"
             ${staggerStyle}
             onclick="MOS.selectProveedor('${p.idProveedor}')">
          ${urg.estado === 'hoy' ? '<div class="prov-card-corona" title="Hoy es día de pedido">👑</div>' : ''}
          <div class="prov-card-head">
            ${_provAvatarHtmlFull(p, 'prov-avatar')}
            <div class="min-w-0 flex-1">
              <div class="prov-card-nombre">${p.nombre}</div>
              ${p.categoriaProducto ? `<div class="prov-card-cat">${p.categoriaProducto}</div>` : ''}
            </div>
            <div class="prov-card-badges">
              ${cartBadge}
              ${pendBadge}
            </div>
          </div>
          <div class="prov-card-urg-row">
            <span class="prov-urg-chip ${urg.cls}">
              ${urg.estado === 'hoy' ? '🔥' : urg.estado === 'proximo' ? '⏳' : urg.estado === 'inactivo' ? '⚠' : '📅'}
              ${urg.label}
            </span>
          </div>
          ${_provSparkBars(p.idProveedor)}
        </div>`;
    }).join('') +
    // Inline-detail único (legacy, el detalle real va al panel desktop).
    `<div id="provInlineDetail" class="prov-inline-detail lg:hidden" style="display:none"></div>`;

    if (S.provSelId) {
      _provPosicionarInlineDetail(S.provSelId);
      _provViewToggleConDetalle(true);
    } else {
      _provViewToggleConDetalle(false);
    }
    _provInerciaActualizar();
  }

  // Re-evaluar layout al cambiar tamaño de pantalla
  window.addEventListener('resize', () => {
    if (S.view === 'proveedores') _provInerciaActualizar();
  }, { passive: true });

  // Toggle de la clase con-detalle del view (afecta layout grid)
  function _provViewToggleConDetalle(activo) {
    const view = $('view-proveedores');
    if (!view) return;
    view.classList.toggle('con-detalle', !!activo);
    // Re-attachear/detacher inercia del carrusel según corresponda
    setTimeout(_provInerciaActualizar, 0);
  }

  // ── Inercia del carrusel horizontal de proveedores ─────────
  // Drag con pointer (touch + mouse), trackea velocidad, en pointerup
  // aplica deceleración exponencial → efecto Apple-like.
  let _inerciaState = null;  // { startX, startScroll, lastX, lastT, vel, dragging, target }
  function _provInerciaActualizar() {
    const list = $('listProveedores');
    if (!list) return;
    // Carrusel horizontal SIEMPRE en mobile/tablet (con o sin selección).
    const isHoriz = window.matchMedia('(max-width: 1023px)').matches;
    if (isHoriz) _provInerciaAttach(list);
    else         _provInerciaDetach(list);
  }
  function _provInerciaAttach(el) {
    if (el._inerciaAttached) return;
    el._inerciaAttached = true;
    el.addEventListener('pointerdown',  _onInerciaDown,  { passive: true });
    el.addEventListener('pointermove',  _onInerciaMove);
    el.addEventListener('pointerup',    _onInerciaUp);
    el.addEventListener('pointercancel',_onInerciaUp);
    el.addEventListener('pointerleave', _onInerciaUp);
  }
  function _provInerciaDetach(el) {
    if (!el._inerciaAttached) return;
    el._inerciaAttached = false;
    el.removeEventListener('pointerdown',  _onInerciaDown);
    el.removeEventListener('pointermove',  _onInerciaMove);
    el.removeEventListener('pointerup',    _onInerciaUp);
    el.removeEventListener('pointercancel',_onInerciaUp);
    el.removeEventListener('pointerleave', _onInerciaUp);
  }
  function _onInerciaDown(e) {
    if (e.pointerType === 'mouse' && e.button !== 0) return;
    const t = e.currentTarget;
    if (_inerciaState && _inerciaState.raf) {
      cancelAnimationFrame(_inerciaState.raf); _inerciaState.raf = 0;
    }
    _inerciaState = {
      target: t, startX: e.clientX, startScroll: t.scrollLeft,
      lastX: e.clientX, lastT: performance.now(), vel: 0,
      dragging: false, moved: false, raf: 0
    };
  }
  function _onInerciaMove(e) {
    const s = _inerciaState;
    if (!s || s.target !== e.currentTarget) return;
    const dx = e.clientX - s.startX;
    if (!s.dragging) {
      if (Math.abs(dx) < 6) return;
      s.dragging = true;
      s.target.classList.add('dragging');
      try { s.target.setPointerCapture(e.pointerId); } catch {}
    }
    s.target.scrollLeft = s.startScroll - dx;
    const now = performance.now();
    const dt = Math.max(1, now - s.lastT);
    // Velocidad en px/ms (positiva = avanza derecha en scroll, negativa izq)
    s.vel = (s.lastX - e.clientX) / dt;
    s.lastX = e.clientX;
    s.lastT = now;
    s.moved = true;
    e.preventDefault();
  }
  function _onInerciaUp(e) {
    const s = _inerciaState;
    if (!s) return;
    if (!s.dragging || !s.moved) { _inerciaState = null; return; }
    s.target.classList.remove('dragging');
    try { s.target.releasePointerCapture(e.pointerId); } catch {}
    // Aplicar inercia: cada frame escalamos la velocidad por un factor
    let v = s.vel * 16; // px/frame ≈ vel(px/ms) * 16ms/frame
    if (Math.abs(v) < 0.5) { _inerciaState = null; return; }
    const target = s.target;
    function step() {
      if (Math.abs(v) < 0.4) {
        // Snap final al card más cercano
        target.style.scrollSnapType = '';  // re-habilita snap
        _inerciaState = null;
        return;
      }
      target.scrollLeft += v;
      v *= 0.93;  // factor de fricción
      s.raf = requestAnimationFrame(step);
    }
    target.style.scrollSnapType = 'none';  // permite scroll libre durante inercia
    s.raf = requestAnimationFrame(step);
  }

  // El inline-detail ya no se usa (era para tablet, ahora todo va al panel).
  // Función mantenida no-op para compatibilidad con llamadas existentes.
  function _provPosicionarInlineDetail(_idProv) { /* no-op */ }
  function _provAplicarSeleccion(idAnt, idNuevo) {
    const list = $('listProveedores');
    if (!list) return;
    // Quitar active del anterior (si seguía visible)
    if (idAnt) {
      const cardAnt = list.querySelector(`[data-prov-card="${idAnt}"]`);
      if (cardAnt) cardAnt.classList.remove('prov-card-active');
    }
    // Marcar nuevo
    if (idNuevo) {
      const cardNuevo = list.querySelector(`[data-prov-card="${idNuevo}"]`);
      if (cardNuevo) cardNuevo.classList.add('prov-card-active');
      _provPosicionarInlineDetail(idNuevo);
      _provViewToggleConDetalle(true);
    } else {
      const inline = $('provInlineDetail');
      if (inline) { inline.style.display = 'none'; inline.innerHTML = ''; }
      _provViewToggleConDetalle(false);
    }
  }

  // Breakpoint actual: 'mobile' (<768) | 'tablet' (768-1023) | 'desktop' (≥1024)
  function _provBreakpoint() {
    if (window.matchMedia('(min-width: 1024px)').matches) return 'desktop';
    if (window.matchMedia('(min-width: 768px)').matches)  return 'tablet';
    return 'mobile';
  }
  // Target donde se renderiza el detalle: SIEMPRE el panel principal
  // (#proveedorDetail). En mobile/tablet aparece debajo del carrusel,
  // en desktop al lado en master-detail.
  function _provDetailTargetEl() {
    return $('proveedorDetail');
  }

  async function selectProveedor(id) {
    const bp = _provBreakpoint();
    const isMobile = bp !== 'desktop';

    // Toggle: en mobile/tablet, click en el card ya activo lo cierra
    if (isMobile && S.provSelId === id) {
      cerrarDetalleProveedor();
      return;
    }

    // Reset filtros si se cambia de proveedor
    if (S.provSelId !== id) {
      S.provProdFilter = '';
      S.provHistFilter = '';
    }
    const idAnterior = S.provSelId;
    S.provSelId = id;
    try { localStorage.setItem('mos_prov_last_sel', id); } catch {}
    if (!S.provTab || S.provTab === 'info' || S.provTab === 'pedidos') S.provTab = 'productos';

    const prov = S.proveedores.find(p => p.idProveedor === id);
    if (!prov) return;

    // Mover selección sin re-render de toda la lista (evita parpadeo)
    if (!$('listProveedores')?.querySelector('[data-prov-card]')) {
      // Lista todavía no renderizada → render inicial
      renderProveedores();
    } else {
      _provAplicarSeleccion(idAnterior, id);
    }

    const detailEl = _provDetailTargetEl();
    if (!detailEl) return;
    // Limpiar contenido del detail INMEDIATO para evitar mostrar el del proveedor
    // anterior mientras se monta el nuevo. Render del header debajo va sincrónico.
    detailEl.innerHTML = '';

    // Pre-carga en paralelo (no espera para mostrar la UI)
    _precargarProvData(id);
    const safeNombre = (prov.nombre || '').replace(/"/g, '&quot;');
    const tieneTel = !!prov.telefono;
    const urg      = _provUrgenciaPedido(prov);
    // Calculamos las 3 píldoras decisionales del header
    const pildoraPedido  = _provPildoraDia(prov.diaPedido,  'PEDIDO',  '📅');
    const pildoraPago    = _provPildoraPago(prov);
    const pildoraEntrega = _provPildoraDia(prov.diaEntrega, 'ENTREGA', '🚚', { contextDia: prov.diaPedido });

    detailEl.innerHTML = `
      <div class="prov-detail-modern ${urg.cls}">
        <div class="prov-detail-head">
          ${_provAvatarHtmlFull(prov, 'prov-avatar-xl')}
          <div class="prov-detail-nombre-wrap">
            <h3 class="prov-detail-nombre">${safeNombre}</h3>
            <p class="prov-detail-ruc">${prov.ruc || '—'}${prov.categoriaProducto ? ' · ' + prov.categoriaProducto : ''}</p>
          </div>
          <div class="prov-detail-actions-icons">
            <button class="prov-icon-btn" onclick="event.stopPropagation();MOS.provAbrirHistorico('${id}')" title="Histórico de compras">📊</button>
            <button class="prov-icon-btn" onclick="event.stopPropagation();MOS.provAbrirInfo('${id}')" title="Datos completos del proveedor">ⓘ</button>
            <button class="prov-icon-btn" onclick="event.stopPropagation();MOS.abrirModalProveedor('${id}')" title="Editar proveedor">✏️</button>
            <button class="prov-icon-btn lg:hidden" onclick="event.stopPropagation();MOS.cerrarDetalleProveedor()" title="Cerrar">×</button>
          </div>
        </div>

        <!-- 3 píldoras decisionales: pedido / pago / entrega -->
        <div class="prov-pildoras">
          ${pildoraPedido}
          ${pildoraPago}
          ${pildoraEntrega}
        </div>

        <!-- Chips compactos: forma pago + responsable (datos secundarios en ⓘ) -->
        <div class="prov-detail-chips">
          ${prov.formaPago ? `<span class="prov-chip-mini">${prov.formaPago === 'CREDITO' ? '💳 Crédito ' + (prov.plazoCredito || 0) + 'd' : '💵 Contado'}</span>` : ''}
          ${prov.responsable ? `<span class="prov-chip-mini">👤 ${prov.responsable}</span>` : ''}
        </div>

        <!-- Acciones -->
        <div class="prov-action-row">
          ${tieneTel ? `<button class="prov-action-btn whatsapp" onclick="MOS.provWhatsApp('${id}', event)">💬 WhatsApp</button>` : ''}
          ${tieneTel ? `<button class="prov-action-btn" onclick="MOS.provLlamar('${id}', event)">📞 Llamar</button>` : ''}
          <button class="prov-action-btn" onclick="MOS.abrirModalPago('${id}')">💰 + Pago</button>
          <button class="prov-action-btn primary" data-prov-carrito-btn="${id}" onclick="MOS.provAccionPedido()">${(_provCarritoResumen(id) || {}).count ? `🛒 Ver carrito (${_provCarritoResumen(id).count})` : '🛒 Armar pedido'}</button>
        </div>
      </div>
      <!-- Productos: contenido directo (ya no es tab) -->
      <div id="provTabProductos" class="prov-tab-content prov-productos-direct"></div>
      <!-- Histórico: legacy hidden — ahora vive en modal #modalProvHistorico. -->
      <div id="provTabHistorico" class="prov-tab-content hidden"></div>
    `;
    // Mostrar productos siempre (no hay tabs)
    S.provTab = 'productos';
    provSetTab('productos');

    // En mobile/tablet:
    //  1. Scroll del CARRUSEL para anclar el card seleccionado
    //  2. Scroll de la página al detail (que está abajo) para que el user lo vea
    if (isMobile) {
      requestAnimationFrame(() => {
        const list = $('listProveedores');
        const card = document.querySelector(`[data-prov-card="${id}"]`);
        if (list && card) {
          const lr = list.getBoundingClientRect();
          const cr = card.getBoundingClientRect();
          // Centrar el card en el viewport horizontal del carrusel
          const offset = (cr.left - lr.left) - (lr.width - cr.width) / 2;
          list.scrollBy({ left: offset, behavior: 'smooth' });
        }
        // Después scroll suave al detail
        setTimeout(() => {
          const det = $('proveedorDetail');
          if (det) {
            const dr = det.getBoundingClientRect();
            if (dr.top > window.innerHeight * 0.6) {
              det.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }
          }
        }, 300);
      });
    }
  }

  // ── Pre-carga paralela de los 4 tabs del proveedor ─────────
  S.provPagos     = S.provPagos     || {};
  S.provProductos = S.provProductos || {};
  S.provHistorico = S.provHistorico || {};
  S.provPedidos   = S.provPedidos   || {};

  function _precargarProvData(id) {
    if (!id) return;
    // Pagos (sin tab info — sólo cache para modal de pago)
    API.get('getPagos', { idProveedor: id })
      .then(r => { S.provPagos[id] = Array.isArray(r) ? r : (r && r.data) || []; })
      .catch(() => {});
    // Productos enriquecidos (con stock + zonas + min/max + sugerencia)
    API.get('getProductosProveedorConStock', { idProveedor: id, rangoDias: 30 })
      .then(r => {
        const items = Array.isArray(r) ? r : (r && r.data) || [];
        S.provProductos[id] = items;
        _provProdsSaveCache(id, items);
        if (S.provSelId === id && S.provTab === 'productos') _renderProvProductos();
      }).catch(() => {});
    // Histórico (60 días default)
    API.get('getHistoricoProveedor', { idProveedor: id, dias: 60 })
      .then(r => {
        S.provHistorico[id] = (r && r.data) ? r.data : r;
        if (S.provSelId === id && S.provTab === 'historico') _renderProvHistorico();
      }).catch(() => {});
  }

  function cerrarDetalleProveedor() {
    const ant = S.provSelId;
    S.provSelId = null;
    // Solo togglear clases — sin re-render (evita parpadeo)
    _provAplicarSeleccion(ant, null);
    // Reset del panel desktop por si venía con contenido
    const detailEl = $('proveedorDetail');
    if (detailEl) detailEl.innerHTML = '<p class="text-center p-6">Selecciona un proveedor para ver pagos y pedidos</p>';
  }

  function provSetTab(tab) {
    S.provTab = tab;
    document.querySelectorAll('.prov-tab').forEach(b => b.classList.toggle('active', b.dataset.tab === tab));
    document.querySelectorAll('.prov-tab-content').forEach(c => c.classList.add('hidden'));
    const targetMap = { productos: 'provTabProductos', historico: 'provTabHistorico' };
    const target = $(targetMap[tab]);
    if (target) target.classList.remove('hidden');
    if (tab === 'productos') _renderProvProductos();
    if (tab === 'historico') _renderProvHistorico();
  }

  function _renderProvInfo() {
    const id = S.provSelId;
    const prov = S.proveedores.find(p => p.idProveedor === id);
    const cont = $('provTabInfo');
    if (!cont || !prov) return;
    cont.innerHTML = `
      <div class="grid sm:grid-cols-2 gap-3 mb-4">
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">Teléfono: </span><span class="text-slate-200">${prov.telefono || '—'}</span></div>
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">Email: </span><span class="text-slate-200">${prov.email || '—'}</span></div>
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">Banco: </span><span class="text-slate-200">${prov.banco || '—'}</span></div>
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">Cuenta: </span><span class="text-slate-200">${prov.numeroCuenta || '—'}</span></div>
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">Forma pago: </span><span class="text-slate-200">${prov.formaPago || '—'}${prov.plazoCredito ? ' · ' + prov.plazoCredito + 'd' : ''}</span></div>
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">Categoría: </span><span class="text-slate-200">${prov.categoriaProducto || '—'}</span></div>
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">📋 Pedido: </span><span class="text-slate-200">${_provDiaLabel(prov.diaPedido)}</span></div>
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">📦 Entrega: </span><span class="text-slate-200">${_provDiaLabel(prov.diaEntrega)}</span></div>
        <div class="card-sm p-3 text-sm"><span class="text-slate-500">💸 Pago: </span><span class="text-slate-200">${_provDiaLabel(prov.diaPago)}</span></div>
      </div>
      <div class="flex items-center justify-between mb-3">
        <h4 class="font-semibold text-sm text-slate-300">💰 Pagos registrados</h4>
        <button class="btn-primary text-xs px-3 py-1.5" onclick="MOS.abrirModalPago('${id}')">+ Pago</button>
      </div>
      <div id="listPagos" class="text-sm text-slate-400"></div>
    `;
    // Render desde cache primero (instantáneo); sino fetch fresco
    if (S.provPagos[id]) {
      renderPagos(S.provPagos[id]);
    } else {
      $('listPagos').textContent = 'Cargando...';
      API.get('getPagos', { idProveedor: id }).then(r => {
        S.provPagos[id] = Array.isArray(r) ? r : (r && r.data) || [];
        renderPagos(S.provPagos[id]);
      }).catch(() => {});
    }
  }

  function _filtrarPP(items, q) {
    if (!q) return items;
    const qn = _norm(q);
    const palabras = qn.split(/\s+/).filter(Boolean);
    return items.filter(pp => {
      const hay = _norm((pp.descripcion || '') + ' ' + (pp.skuBase || '') + ' ' + (pp.codigoBarra || '') + ' ' + (pp.notas || ''));
      return palabras.every(w => hay.indexOf(w) >= 0);
    });
  }

  // ── Estado del carrito (modelo único) ──────────────────────────
  // S.provCarritos: PERSISTENTE en localStorage. Uno por proveedor.
  //   { [idProveedor]: { items: { [idPP]: {idPP, sku, desc, codigoBarra, precio, qty, upb} }, ts } }
  // S.provCarritoActivoId: id del último carrito modificado (para FAB global).
  // Los steppers en cada card del producto escriben DIRECTAMENTE al carrito —
  // no hay estado intermedio. La sugerencia se ofrece como botón "Pedir N".
  S.provCarritos       = S.provCarritos       || {};
  S.provCarritoActivoId = S.provCarritoActivoId || null;

  const PROV_CARRITOS_KEY      = 'mos_prov_carritos';
  const PROV_CARRITO_ACTIVO_KEY = 'mos_prov_carrito_activo';

  function _provCarritosLoad() {
    try {
      const raw = localStorage.getItem(PROV_CARRITOS_KEY);
      if (raw) S.provCarritos = JSON.parse(raw) || {};
      const act = localStorage.getItem(PROV_CARRITO_ACTIVO_KEY);
      if (act) S.provCarritoActivoId = act;
    } catch {}
  }
  function _provCarritosSave() {
    try {
      localStorage.setItem(PROV_CARRITOS_KEY, JSON.stringify(S.provCarritos || {}));
      if (S.provCarritoActivoId) localStorage.setItem(PROV_CARRITO_ACTIVO_KEY, S.provCarritoActivoId);
      else localStorage.removeItem(PROV_CARRITO_ACTIVO_KEY);
    } catch {}
  }
  // Hidratar al iniciar el módulo
  _provCarritosLoad();

  function _provCarritoDe(idProveedor) {
    if (!idProveedor) return null;
    return (S.provCarritos[idProveedor] && S.provCarritos[idProveedor].items) || null;
  }
  function _provCarritoVacioOCrear(idProveedor) {
    if (!idProveedor) return null;
    if (!S.provCarritos[idProveedor]) S.provCarritos[idProveedor] = { items: {}, ts: Date.now() };
    return S.provCarritos[idProveedor];
  }
  function _provCarritoTotalItems() {
    return Object.values(S.provCarritos || {}).filter(c => c && c.items && Object.keys(c.items).length > 0).length;
  }

  // Resumen del carrito de un proveedor — para badge y FAB
  function _provCarritoResumen(idProveedor) {
    const c = S.provCarritos[idProveedor];
    if (!c || !c.items) return null;
    const items = Object.values(c.items);
    if (!items.length) return null;
    let qty = 0, monto = 0;
    items.forEach(it => {
      qty += parseFloat(it.qty) || 0;
      monto += (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0);
    });
    return { count: items.length, qty, monto, ts: c.ts };
  }

  // Refresca el badge 🛒N en el card del proveedor en la lista
  function _refreshProvCarritoBadge(idProveedor) {
    if (!idProveedor) return;
    const card = document.querySelector(`[data-prov-card="${idProveedor}"]`);
    if (!card) return;
    const slot = card.querySelector('[data-prov-cart-badge]');
    const stats = _provCarritoResumen(idProveedor);
    const html = stats
      ? `<span class="prov-cart-badge" data-prov-cart-badge="${idProveedor}" title="Carrito: ${stats.count} prods · ${fmtMoney(stats.monto)}">🛒 ${stats.count}</span>`
      : '';
    if (slot) slot.outerHTML = html || `<span data-prov-cart-badge="${idProveedor}" style="display:none"></span>`;
    _provFabRender();
  }

  // ── FAB global del carrito + selector multi-carrito ─────────
  S._fabSelectorOpen = false;

  function _provListarCarritosActivos() {
    return Object.entries(S.provCarritos || {})
      .map(([id, c]) => ({ id, items: Object.values((c && c.items) || {}), ts: (c && c.ts) || 0 }))
      .filter(c => c.items.length > 0)
      .sort((a, b) => (b.ts || 0) - (a.ts || 0));
  }

  function _provFabRender() {
    let fab = $('provCarritoFAB');
    const carritos = _provListarCarritosActivos();
    if (!carritos.length) {
      if (fab) fab.style.display = 'none';
      _provFabSelectorClose();
      return;
    }
    if (!fab) {
      fab = document.createElement('button');
      fab.id = 'provCarritoFAB';
      fab.className = 'prov-cart-fab';
      document.body.appendChild(fab);
    }
    fab.style.display = '';

    if (carritos.length === 1) {
      // Modo single — click abre el modal directamente
      const c = carritos[0];
      const prov = (S.proveedores || []).find(p => p.idProveedor === c.id) || {};
      const nombre = prov.nombre || c.id;
      const totalUds = c.items.reduce((s, it) => s + (parseFloat(it.qty) || 0), 0);
      const monto    = c.items.reduce((s, it) => s + (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0), 0);
      fab.onclick = () => provAbrirCarrito(c.id);
      fab.innerHTML = `
        <span class="prov-cart-fab-avatar-wrap">
          ${_provAvatarHtml(nombre)}
          <span class="prov-cart-fab-count">${c.items.length}</span>
        </span>
        <span class="prov-cart-fab-info">
          <span class="prov-cart-fab-prov">${nombre}</span>
          <span class="prov-cart-fab-monto">${totalUds} unds · <b>${fmtMoney(monto)}</b></span>
        </span>
        <span class="prov-cart-fab-arrow">›</span>
      `;
    } else {
      // Modo multi — avatares apilados, click toggle del selector
      const totalProds = carritos.reduce((s, c) => s + c.items.length, 0);
      const totalMonto = carritos.reduce((s, c) =>
        s + c.items.reduce((sm, it) => sm + (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0), 0), 0);
      // Hasta 4 avatares visibles, el resto en chip "+N"
      const avatarsVisible = carritos.slice(0, 4);
      const overflow = carritos.length - avatarsVisible.length;
      const stack = avatarsVisible.map((c, i) => {
        const prov = (S.proveedores || []).find(p => p.idProveedor === c.id) || {};
        return `<span class="prov-cart-fab-avatar-stacked" style="z-index:${10 - i}">${_provAvatarHtml(prov.nombre || c.id)}</span>`;
      }).join('');
      fab.onclick = () => _provFabToggleSelector();
      fab.innerHTML = `
        <span class="prov-cart-fab-avatars-stack">
          ${stack}
          ${overflow > 0 ? `<span class="prov-cart-fab-stack-more">+${overflow}</span>` : ''}
        </span>
        <span class="prov-cart-fab-info">
          <span class="prov-cart-fab-prov">${carritos.length} carritos activos</span>
          <span class="prov-cart-fab-monto">${totalProds} prods · <b>${fmtMoney(totalMonto)}</b></span>
        </span>
        <span class="prov-cart-fab-arrow">${S._fabSelectorOpen ? '▾' : '▸'}</span>
      `;
      // Si el selector estaba abierto y los carritos cambiaron, re-render
      if (S._fabSelectorOpen) _provFabSelectorRender(carritos);
    }
  }

  // Selector flotante (panel) que aparece al click del FAB en modo multi
  function _provFabToggleSelector() {
    S._fabSelectorOpen = !S._fabSelectorOpen;
    if (S._fabSelectorOpen) {
      const carritos = _provListarCarritosActivos();
      _provFabSelectorRender(carritos);
      // Listener click-outside para cerrar
      setTimeout(() => document.addEventListener('click', _provFabSelectorClickOutside, true), 0);
    } else {
      _provFabSelectorClose();
    }
    _provFabRender();
  }

  function _provFabSelectorRender(carritos) {
    let panel = $('provCarritoSelector');
    if (!panel) {
      panel = document.createElement('div');
      panel.id = 'provCarritoSelector';
      panel.className = 'prov-cart-selector';
      document.body.appendChild(panel);
    }
    panel.innerHTML = `
      <div class="prov-cart-selector-head">
        <span>${carritos.length} carritos activos</span>
        <button onclick="MOS._provFabSelectorCloseClick()" class="prov-cart-selector-close" aria-label="Cerrar">×</button>
      </div>
      <div class="prov-cart-selector-list">
        ${carritos.map(c => {
          const prov = (S.proveedores || []).find(p => p.idProveedor === c.id) || {};
          const nombre = prov.nombre || c.id;
          const totalUds = c.items.reduce((s, it) => s + (parseFloat(it.qty) || 0), 0);
          const monto    = c.items.reduce((s, it) => s + (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0), 0);
          const tsLabel = c.ts ? _carritoTimestampHumano(c.ts) : '';
          return `
            <button class="prov-cart-selector-item" onclick="MOS._provFabSelectorPick('${c.id}')">
              <span class="prov-cart-selector-avatar">${_provAvatarHtml(nombre)}</span>
              <span class="prov-cart-selector-info">
                <span class="prov-cart-selector-name">${nombre}</span>
                <span class="prov-cart-selector-meta">${c.items.length} prods · ${totalUds} unds · ${tsLabel}</span>
              </span>
              <span class="prov-cart-selector-monto">${fmtMoney(monto)}</span>
            </button>
          `;
        }).join('')}
      </div>
    `;
    panel.style.display = '';
    requestAnimationFrame(() => panel.classList.add('open'));
  }

  function _provFabSelectorClose() {
    const panel = $('provCarritoSelector');
    if (panel) {
      panel.classList.remove('open');
      setTimeout(() => { if (panel) panel.style.display = 'none'; }, 180);
    }
    S._fabSelectorOpen = false;
    document.removeEventListener('click', _provFabSelectorClickOutside, true);
  }

  function _provFabSelectorCloseClick() {
    _provFabSelectorClose();
    _provFabRender();
  }

  function _provFabSelectorClickOutside(ev) {
    const panel = $('provCarritoSelector');
    const fab   = $('provCarritoFAB');
    if (panel && panel.contains(ev.target)) return;
    if (fab   && fab.contains(ev.target))   return;
    _provFabSelectorClose();
    _provFabRender();
  }

  function _provFabSelectorPick(idProv) {
    _provFabSelectorClose();
    provAbrirCarrito(idProv);
    _provFabRender();
  }

  // Qty actual en el stepper = qty del carrito persistente (0 si no está)
  function _provStepperQty(idProveedor, pp) {
    const c = S.provCarritos[idProveedor];
    if (!c || !c.items || !c.items[pp.idPP]) return 0;
    return parseFloat(c.items[pp.idPP].qty) || 0;
  }

  // Marcar el carrito como activo (para el FAB global) + persistir
  function _provCarritoMarcarActivo(idProveedor) {
    if (!idProveedor) return;
    S.provCarritoActivoId = idProveedor;
    _provCarritosSave();
    _provFabRender();
  }

  // Aplica todas las sugerencias al carrito (botón "Aplicar sugerencias").
  // No reemplaza el carrito vacío — completa los productos sin item.
  function _provAplicarSugerenciasACarrito(idProveedor) {
    if (!idProveedor) return;
    const productos = (S.provProductos && S.provProductos[idProveedor]) || [];
    _provCarritoVacioOCrear(idProveedor);
    productos.forEach(pp => {
      const sug = parseFloat(pp.sugerencia) || 0;
      if (sug > 0) {
        S.provCarritos[idProveedor].items[pp.idPP] = {
          idPP:        pp.idPP,
          sku:         pp.skuBase,
          desc:        pp.descripcion,
          codigoBarra: pp.codigoBarra,
          precio:      parseFloat(pp.precioReferencia) || 0,
          qty:         sug,
          upb:         parseInt(pp.unidadesPorBulto) || 1
        };
      }
    });
    S.provCarritos[idProveedor].ts = Date.now();
    _provCarritoMarcarActivo(idProveedor);
  }

  function _provAlertaInfo(a) {
    switch ((a || '').toUpperCase()) {
      case 'NEGATIVO':      return { color: '#ef4444', label: '⚠ NEGATIVO' };
      case 'BAJO_MINIMO':   return { color: '#f59e0b', label: '⬇ Bajo mín' };
      case 'AGOTAR_PRONTO': return { color: '#fb923c', label: '⏱ Agotar pronto' };
      case 'CERCA_MINIMO':  return { color: '#eab308', label: '~ Cerca mín' };
      case 'SIN_ROTACION':  return { color: '#64748b', label: '· Sin rotación' };
      default:              return { color: '#10b981', label: 'OK' };
    }
  }

  function _pintaProvProductos(items) {
    const list = $('provProductosList');
    if (!list) return;
    if (!items.length) {
      const filtro = S.provProdFilter || '';
      list.innerHTML = filtro
        ? `<p class="text-slate-500 text-sm py-6 text-center">Sin coincidencias para "${filtro}".</p>`
        : '<p class="text-slate-500 text-sm py-6 text-center">Sin productos registrados.<br>Pulsa <b>⬇️ Jalar</b> para importar desde guías o <b>+ Producto</b> para agregar manual.</p>';
      // toolbar eliminado — los steppers escriben directo al carrito
      return;
    }
    // El stepper qty refleja el carrito persistente (0 si no está).
    // La sugerencia se ofrece como botón "Pedir N" si el producto NO está
    // en carrito todavía.
    const idProvActual = S.provSelId;
    list.innerHTML = items.map(pp => {
      const alert = _provAlertaInfo(pp.alerta);
      const qtyActual = _provStepperQty(idProvActual, pp);
      const tienePresentaciones = (pp.countPresentaciones || 1) > 1;
      const tieneEquiv = (pp.countEquivalencias || 0) > 0;

      // Chips de stock: almacén + zonas REGISTRADAS + (si hay) huérfanas
      const huerfanas = pp.zonasHuerfanas;
      const stockChips = [];
      stockChips.push({ nombre: 'Almacén', cant: pp.stockWh || 0, icon: '🏬' });
      (pp.zonas || []).forEach(z => {
        stockChips.push({ nombre: z.nombre, cant: z.cantidad, icon: '🏪' });
      });
      if (huerfanas && huerfanas.cantidad !== 0) {
        stockChips.push({ nombre: 'Sin zona registrada', cant: huerfanas.cantidad, icon: '⚠', huerf: true });
      }
      const stockChipsHtml = stockChips.map(c =>
        `<span class="prov-loc-chip${c.cant < 0 ? ' neg' : c.cant === 0 ? ' zero' : ''}${c.huerf ? ' huerf' : ''}" ${c.huerf ? 'title="Stock en una zona/estación que no está registrada en la tabla ZONAS de MOS — corrige el dato"' : ''}><span class="prov-loc-ic">${c.icon}</span>${c.nombre}: <b>${c.cant}</b></span>`
      ).join('');

      // Chips de rotación: solo si hay rotación total > 0.
      // El chip "Reposición sugerida" usa el TOTAL como referencia
      // (lo que el almacén debería despachar/día para sostener las ventas).
      // No es venta del almacén — el almacén no vende.
      const rotTotal = pp.rotacionDia || 0;
      const rotChips = [];
      if (rotTotal > 0) {
        rotChips.push({ nombre: 'Reposición sugerida', rot: rotTotal, icon: '🏬', tip: 'Lo que el almacén debe despachar por día = suma de ventas en zonas. Aproximación.' });
        (pp.zonas || []).forEach(z => {
          if (z.rotacionDia > 0 || z.ventasRango > 0) {
            rotChips.push({ nombre: z.nombre, rot: z.rotacionDia || 0, icon: '🏪', tip: 'Ventas/día en ' + z.nombre });
          }
        });
        if (huerfanas && huerfanas.rotacionDia > 0) {
          rotChips.push({ nombre: 'Sin zona registrada', rot: huerfanas.rotacionDia, icon: '⚠', huerf: true, tip: 'Ventas registradas en una estación cuya zona no está en la tabla ZONAS' });
        }
      }
      const rotChipsHtml = rotChips.map(c =>
        `<span class="prov-rot-chip${c.huerf ? ' huerf' : ''}" title="${c.tip}"><span class="prov-loc-ic">${c.icon}</span>${c.nombre}: <b>↻ ${c.rot}/d</b></span>`
      ).join('');

      // Bulto del proveedor (cuántas unidades vienen por caja/paquete)
      const upb = parseInt(pp.unidadesPorBulto) || 1;
      const bultoChipHtml = `
        <span class="prov-bulto-chip" onclick="MOS.provEditarBulto('${pp.idPP}', ${upb})" title="Click para editar — el proveedor vende en bultos de N unidades">
          📦 Bulto × <b>${upb}</b> un
        </span>`;

      // Dual-range Mín/Máx con marker en la reposición sugerida (rot × 7)
      const sugRep = Math.max(0, Math.ceil((pp.rotacionDia || 0) * 7));
      const minVal = parseInt(pp.stockMinimo) || 0;
      const maxVal = parseInt(pp.stockMaximo) || 0;
      // Escala del slider: dejar margen suficiente para el sugerido y los valores actuales
      const escala = Math.max(20, sugRep * 4 || 0, maxVal * 1.3 || 0, minVal * 1.3 || 0, 30);
      const sugDentro = sugRep > 0 && sugRep >= minVal && (maxVal === 0 || sugRep <= maxVal);
      const minPctRange = (minVal / escala) * 100;
      const maxPctRange = (maxVal / escala) * 100;
      const sugPctRange = sugRep > 0 ? (sugRep / escala) * 100 : 0;

      return `
      <div class="prov-prod-card${pp._tmp ? ' opacity-60' : ''}${qtyActual > 0 ? ' en-pedido' : ''}" data-idpp="${pp.idPP}" style="border-left:3px solid ${alert.color}">
        <div class="flex items-start justify-between gap-2 mb-1.5">
          <div class="min-w-0 flex-1 cursor-pointer" onclick="MOS.abrirModalProvProducto('${pp.idPP}')">
            <div class="text-sm font-semibold text-slate-100 truncate">${pp.descripcion || pp.skuBase}</div>
            <div class="text-[10px] text-slate-500 mt-0.5 truncate" style="font-family:monospace">SKU ${pp.skuBase}${pp.codigoBarra ? ' · ▌' + pp.codigoBarra : ''}${tienePresentaciones ? ' · ' + pp.countPresentaciones + ' pres' : ''}${tieneEquiv ? ' · ' + pp.countEquivalencias + ' eq' : ''}</div>
          </div>
          <div class="text-right shrink-0 flex flex-col items-end gap-0.5">
            <div class="text-sm font-bold text-amber-400 whitespace-nowrap">${fmtMoney(pp.precioReferencia || 0)}</div>
            <span class="text-[9px] font-bold" style="color:${alert.color}">${alert.label}</span>
          </div>
        </div>

        <!-- Stock total con sus chips por ubicación + bulto del proveedor -->
        <div class="prov-metric-block">
          <div class="prov-metric-head">
            <span class="prov-stock-label">Stock</span>
            <span class="prov-stock-num" style="color:${alert.color}">${pp.stockTotal}</span>
            ${bultoChipHtml}
          </div>
          <div class="prov-loc-chips">
            ${stockChipsHtml}
          </div>
        </div>

        <!-- Rotación total con sus chips por ubicación -->
        ${rotTotal > 0 ? `
        <div class="prov-metric-block">
          <div class="prov-metric-head">
            <span class="prov-stock-label">Rotación</span>
            <span class="prov-rot-num">↻ ${rotTotal}/d</span>
          </div>
          <div class="prov-loc-chips">
            ${rotChipsHtml}
          </div>
        </div>` : ''}

        <!-- Dual-range Mín-Máx con marker en reposición sugerida (rot × 7d) -->
        <div class="prov-range-block" data-idpp="${pp.idPP}" data-idprod="${pp.idProducto}" data-scale="${escala}" data-sug="${sugRep}">
          <div class="prov-range-headline">
            <div class="prov-range-extreme">
              <span class="prov-range-extreme-lbl">Mín</span>
              <span class="prov-range-extreme-val" data-vfor="min-${pp.idPP}">${minVal}</span>
            </div>
            ${sugRep > 0 ? `
              <div class="prov-range-mid${sugDentro ? '' : ' off'}" data-mid="${pp.idPP}" title="Reposición sugerida: ${sugRep} (rot × 7d)">
                <span data-mid-lbl="${pp.idPP}">${sugDentro ? '✓ Sugerido (' + sugRep + ') dentro' : '⚠ Sugerido (' + sugRep + ') fuera'}</span>
              </div>
            ` : `<div class="prov-range-mid muted">Sin rotación</div>`}
            <div class="prov-range-extreme">
              <span class="prov-range-extreme-lbl">Máx</span>
              <span class="prov-range-extreme-val" data-vfor="max-${pp.idPP}">${maxVal}</span>
            </div>
          </div>
          <div class="prov-range-track-wrap">
            <div class="prov-range-track-bg"></div>
            <div class="prov-range-fill" data-fill="${pp.idPP}" style="left:${minPctRange}%;right:${100 - maxPctRange}%"></div>
            ${sugRep > 0 ? `
              <div class="prov-range-mark${sugDentro ? '' : ' off'}" data-mark="${pp.idPP}" style="left:${sugPctRange}%" title="Sugerido: ${sugRep}/sem">
                <span class="prov-range-mark-num">≈ ${sugRep}</span>
              </div>
            ` : ''}
            <input type="range" min="0" max="${escala}" step="1" value="${minVal}"
              class="prov-range prov-range-min" data-idpp="${pp.idPP}" data-idprod="${pp.idProducto}" data-bound="min"
              oninput="MOS.provRangeInput(this)" onchange="MOS.provRangeChange(this)">
            <input type="range" min="0" max="${escala}" step="1" value="${maxVal}"
              class="prov-range prov-range-max" data-idpp="${pp.idPP}" data-idprod="${pp.idProducto}" data-bound="max"
              oninput="MOS.provRangeInput(this)" onchange="MOS.provRangeChange(this)">
          </div>
        </div>
        ${pp.razonSugerencia ? `<div class="prov-sugerencia-txt">${pp.razonSugerencia}</div>` : ''}

        <!-- Acción única: agregar a carrito (sugerencia individual) -->
        <div class="prov-card-action">
          ${qtyActual > 0 ? `
            <button onclick="event.stopPropagation();MOS.provAbrirCarrito('${idProvActual}')" class="prov-en-carrito-chip" title="Click para ver/editar en el carrito">
              ✓ En carrito: <b>${qtyActual} un</b>${upb > 1 ? ` <span class="prov-en-carrito-bultos">· ${(qtyActual/upb).toFixed(qtyActual % upb === 0 ? 0 : 1)} bulto${qtyActual === upb ? '' : 's'}</span>` : ''}
            </button>
          ` : pp.sugerencia > 0 ? `
            <button onclick="event.stopPropagation();MOS.provPedidoUsarSugerencia('${pp.idPP}', ${pp.sugerencia})" class="prov-sug-cta" title="${pp.razonSugerencia || ''}">
              🛒 Agregar al pedido: <b>${pp.sugerencia} un</b>${upb > 1 ? ` (${pp.sugerenciaBultos} bulto${pp.sugerenciaBultos === 1 ? '' : 's'} × ${upb})` : ''}
            </button>
          ` : `
            <span class="prov-sin-accion">— Sin sugerencia · stock OK —</span>
          `}
          <button onclick="event.stopPropagation();MOS.eliminarProvProductoRapido('${pp.idPP}')" class="prov-card-del" title="Eliminar del catálogo">🗑️</button>
        </div>
      </div>`;
    }).join('');
  }

  // Aplicar sugerencias al carrito + animar FAB + abrir modal
  function provAplicarTodasSugerencias() {
    const id = S.provSelId;
    if (!id) return;
    _provAplicarSugerenciasACarrito(id);
    _provCarritosSave();
    _refreshProvCarritoBadge(id);
    _provFabBump();
    _pintaProvProductos(_filtrarPP((S.provProductos && S.provProductos[id]) || [], S.provProdFilter));
    toast(`${Object.keys((S.provCarritos[id] || {}).items || {}).length} productos agregados al carrito`, 'ok');
  }

  // Acción del botón principal del header del detalle.
  // Si carrito vacío → aplica todas las sugerencias y abre modal.
  // Si carrito con items → solo abre modal (para revisar/editar).
  function provAccionPedido() {
    const id = S.provSelId;
    if (!id) return;
    const resumen = _provCarritoResumen(id);
    if (!resumen || resumen.count === 0) {
      // Carrito vacío: aplicar sugerencias y abrir modal
      provAplicarTodasSugerencias();
    }
    provAbrirCarrito(id);
  }

  // Línea de desglose del pedido: "1 bulto × 12 un · S/2.50 c/u → S/30.00"
  function _renderDesgloseLine(qty, upb, precio) {
    const q = parseFloat(qty) || 0;
    const sub = q * (parseFloat(precio) || 0);
    if (q <= 0) {
      return `<span class="prov-pedido-sub-empty">— sin pedido —</span>`;
    }
    let descCantidad;
    if (upb > 1) {
      const bultos = q / upb;
      const bultosTxt = (Math.abs(bultos - Math.round(bultos)) < 0.001)
        ? Math.round(bultos)
        : bultos.toFixed(2);
      descCantidad = `<b>${bultosTxt}</b> bulto${Math.round(bultos) === 1 ? '' : 's'} × ${upb} un = <b>${q}</b> un`;
    } else {
      descCantidad = `<b>${q}</b> un`;
    }
    return `${descCantidad} · ${fmtMoney(precio)} c/u → <b class="prov-pedido-sub-total">${fmtMoney(sub)}</b>`;
  }

  // ── Editar unidadesPorBulto inline (prompt nativo, simple) ──
  async function provEditarBulto(idPP, current) {
    const nuevoStr = await _modalPrompt('¿Cuántas unidades vienen por bulto/caja del proveedor?', String(current || 1), { titulo: 'Unidades por bulto', inputMode: 'numeric', maxlength: 5 });
    if (nuevoStr === null) return;
    const nuevo = Math.max(1, parseInt(nuevoStr) || 1);
    if (nuevo === current) return;
    const id = S.provSelId;
    const lista = (S.provProductos && S.provProductos[id]) || [];
    const item = lista.find(x => x.idPP === idPP);
    if (item) item.unidadesPorBulto = nuevo;

    // Sincronizar el carrito de ESE proveedor: actualizar upb del item y
    // re-redondear la qty al nuevo múltiplo (siempre arriba).
    if (S.provCarritos[id] && S.provCarritos[id].items[idPP]) {
      const ci = S.provCarritos[id].items[idPP];
      const qtyAnt = parseFloat(ci.qty) || 0;
      const qtyRedondeada = Math.ceil(qtyAnt / nuevo) * nuevo;
      ci.upb = nuevo;
      ci.qty = qtyRedondeada;
      S.provCarritos[id].ts = Date.now();
      _provCarritosSave();
      _renderCarritoIfOpen();
      _refreshProvCarritoBadge(id);
      _provFabRender();
    }
    // Re-render para que la sugerencia se recalcule visualmente
    _pintaProvProductos(_filtrarPP(lista, S.provProdFilter));
    try {
      await API.post('actualizarProductoProveedor', { idPP, unidadesPorBulto: nuevo });
      toast('Bulto actualizado: ' + nuevo + ' un', 'ok');
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  // ── Dual-range Mín/Máx (una sola barra con dos handles + marker) ──
  // oninput: actualiza visual + valida que min ≤ max
  function provRangeInput(inp) {
    const block = inp.closest('.prov-range-block');
    if (!block) return;
    const idPP  = block.dataset.idpp;
    const escala = parseInt(block.dataset.scale) || 100;
    const sug    = parseInt(block.dataset.sug) || 0;
    const minInp = block.querySelector('.prov-range-min');
    const maxInp = block.querySelector('.prov-range-max');
    let minV = parseInt(minInp.value) || 0;
    let maxV = parseInt(maxInp.value) || 0;
    // Clamp: el handle que mueves no puede cruzar al otro
    if (inp.dataset.bound === 'min' && minV > maxV) {
      minV = maxV; minInp.value = minV;
    } else if (inp.dataset.bound === 'max' && maxV < minV) {
      maxV = minV; maxInp.value = maxV;
    }
    // Etiquetas
    const minLbl = block.querySelector(`[data-vfor="min-${idPP}"]`);
    const maxLbl = block.querySelector(`[data-vfor="max-${idPP}"]`);
    if (minLbl) minLbl.textContent = minV;
    if (maxLbl) maxLbl.textContent = maxV;
    // Fill (zona entre min y max)
    const fill = block.querySelector(`[data-fill="${idPP}"]`);
    if (fill) {
      fill.style.left  = (minV / escala * 100) + '%';
      fill.style.right = (100 - maxV / escala * 100) + '%';
    }
    // ¿El sugerido cae dentro? Pintar marker y pill verde/rojo
    if (sug > 0) {
      const dentro = sug >= minV && (maxV === 0 || sug <= maxV);
      const mark = block.querySelector(`[data-mark="${idPP}"]`);
      const mid  = block.querySelector(`[data-mid="${idPP}"]`);
      const lbl  = block.querySelector(`[data-mid-lbl="${idPP}"]`);
      if (mark) mark.classList.toggle('off', !dentro);
      if (mid)  mid.classList.toggle('off', !dentro);
      if (lbl)  lbl.textContent = dentro ? `✓ Sugerido (${sug}) dentro` : `⚠ Sugerido (${sug}) fuera`;
    }
  }
  // onchange: cuando suelta el handle, persistir al GAS
  function provRangeChange(inp) {
    const campo = inp.dataset.bound === 'min' ? 'stockMinimo' : 'stockMaximo';
    provProductoEditarStockMinMax({
      dataset: {
        idprod: inp.dataset.idprod,
        campo:  campo,
        idpp:   inp.dataset.idpp
      },
      value: inp.value
    });
  }

  function provProductoEditarStockMinMax(inp) {
    const idProducto = inp.dataset.idprod;
    const campo      = inp.dataset.campo;
    const idPP       = inp.dataset.idpp;
    const valor      = parseFloat(inp.value) || 0;
    if (!idProducto || !campo) return;
    // Optimista: actualizar localmente
    const id = S.provSelId;
    const lista = (S.provProductos && S.provProductos[id]) || [];
    const item = lista.find(x => x.idPP === idPP);
    if (item && item[campo] === valor) return; // sin cambio
    if (item) item[campo] = valor;
    // POST al GAS (silencioso). _source autoriza la mutación en _validarSource.
    API.post('actualizarProductoMaster', {
      _source:    'MOS_PROV_MINMAX',
      idProducto: idProducto,
      [campo]:    valor
    }).then(() => {
      toast(campo === 'stockMinimo' ? 'Mín actualizado' : 'Máx actualizado', 'ok');
    }).catch(e => {
      toast('Error: ' + e.message, 'error');
    });
  }

  // Edición del stepper en el card del producto.
  // ESCRIBE DIRECTAMENTE al carrito persistente del proveedor activo.
  function provPedidoSetQty(idPP, val) {
    const idProv = S.provSelId;
    if (!idProv) return;
    const lista = (S.provProductos && S.provProductos[idProv]) || [];
    const item = lista.find(x => x.idPP === idPP);
    if (!item) return;
    let qty = parseFloat(val);
    if (isNaN(qty) || qty < 0) qty = 0;
    const upb = parseInt(item.unidadesPorBulto) || 1;
    _provCarritoVacioOCrear(idProv);
    if (qty <= 0) {
      delete S.provCarritos[idProv].items[idPP];
    } else {
      S.provCarritos[idProv].items[idPP] = {
        idPP:        item.idPP,
        sku:         item.skuBase,
        desc:        item.descripcion,
        codigoBarra: item.codigoBarra,
        precio:      parseFloat(item.precioReferencia) || 0,
        qty:         qty,
        upb:         upb
      };
    }
    S.provCarritos[idProv].ts = Date.now();
    _provCarritoMarcarActivo(idProv);
    // Animar el FAB (efecto bump) para que el user note el cambio
    _provFabBump();
    // Actualizar visual del card sin re-render
    const card = document.querySelector(`.prov-prod-card[data-idpp="${idPP}"]`);
    if (card) {
      card.classList.toggle('en-pedido', qty > 0);
      const inp = card.querySelector('.prov-stepper-input');
      if (inp && document.activeElement !== inp) inp.value = qty;
      const desglose = card.querySelector(`[data-desglose="${idPP}"]`);
      if (desglose) desglose.innerHTML = _renderDesgloseLine(qty, upb, item.precioReferencia || 0);
      // Pulso sutil al card que cambió
      card.classList.remove('cart-flash');
      void card.offsetWidth;
      card.classList.add('cart-flash');
    }
    _refreshProvCarritoBadge(idProv);
    _renderCarritoIfOpen();
  }

  function provPedidoStep(idPP, delta) {
    const idProv = S.provSelId;
    if (!idProv) return;
    const lista = (S.provProductos && S.provProductos[idProv]) || [];
    const item = lista.find(x => x.idPP === idPP);
    if (!item) return;
    const cur = _provStepperQty(idProv, item);
    const next = Math.max(0, cur + delta);
    provPedidoSetQty(idPP, next);
  }

  function provPedidoUsarSugerencia(idPP, sug) {
    provPedidoSetQty(idPP, sug);
  }

  // Animación bump del FAB del carrito
  function _provFabBump() {
    const fab = $('provCarritoFAB');
    if (!fab) return;
    fab.classList.remove('bump');
    void fab.offsetWidth;
    fab.classList.add('bump');
  }

  // ── Modal carrito de pedido ─────────────────────────────────
  S.provCarritoTab = S.provCarritoTab || 'sel'; // 'sel' | 'all'

  function provCarritoSetTab(t) {
    S.provCarritoTab = t;
    _renderCarrito();
  }

  // Abre el modal carrito. Sin args → usa proveedor activo o el último tocado.
  // Con idProveedor → fuerza el carrito de ese proveedor (para FAB cross-vista).
  function provAbrirCarrito(idProveedor) {
    const id = idProveedor || S.provSelId || S.provCarritoActivoId;
    if (!id) { toast('Selecciona un proveedor primero', 'error'); return; }
    S._carritoModalProvId = id;     // a quién pertenece la vista del modal
    _provCarritoVacioOCrear(id);
    const prov = (S.proveedores || []).find(p => p.idProveedor === id) || {};
    const nameEl = $('carritoProvNombre');
    if (nameEl) nameEl.textContent = prov.nombre || id;
    const filt = $('carritoFiltro');
    if (filt) filt.value = '';
    const items = _provCarritoDe(id) || {};
    if (!Object.keys(items).length) S.provCarritoTab = 'all';
    _renderCarrito();
    openModal('modalCarritoPedido');
  }
  function provCerrarCarrito() { closeModal('modalCarritoPedido'); }
  function _renderCarritoIfOpen() {
    const m = $('modalCarritoPedido');
    if (m && !m.classList.contains('hidden')) _renderCarrito();
  }

  function _carritoTimestampHumano(ts) {
    if (!ts) return '';
    const diff = Date.now() - ts;
    const hr  = Math.floor(diff / 3600000);
    const min = Math.floor(diff / 60000);
    if (min < 1)   return 'recién';
    if (min < 60)  return `hace ${min} min`;
    if (hr  < 24)  return `hace ${hr} h`;
    const dias = Math.floor(hr / 24);
    return `hace ${dias} d`;
  }

  function _renderCarrito() {
    const id = S._carritoModalProvId || S.provSelId;
    if (!id) return;
    const lista = (S.provProductos && S.provProductos[id]) || [];
    const cont  = $('carritoLista');
    const tabSel = $('carritoTabSel');
    const tabAll = $('carritoTabAll');
    if (tabSel && tabAll) {
      const isSel = S.provCarritoTab === 'sel';
      tabSel.style.background = isSel ? '#6366f1' : 'transparent';
      tabSel.style.color      = isSel ? '#fff'    : '#94a3b8';
      tabAll.style.background = !isSel ? '#6366f1' : 'transparent';
      tabAll.style.color      = !isSel ? '#fff'    : '#94a3b8';
    }
    const q = ($('carritoFiltro')?.value || '').trim();
    const carritoItems = _provCarritoDe(id) || {};
    let filtrados = _filtrarPP(lista, q);
    if (S.provCarritoTab === 'sel') {
      filtrados = filtrados.filter(pp => carritoItems[pp.idPP]);
    }
    if (!cont) return;
    if (!filtrados.length) {
      cont.innerHTML = S.provCarritoTab === 'sel'
        ? '<p class="text-slate-500 text-sm py-8 text-center">Aún no agregas productos al pedido.<br>Cambia a "Todos" y aumenta cantidades.</p>'
        : '<p class="text-slate-500 text-sm py-8 text-center">Sin productos.</p>';
    } else {
      cont.innerHTML = filtrados.map(pp => _carritoFila(pp, id)).join('');
    }
    _renderCarritoFooter(id);
  }

  function _carritoFila(pp, idProveedor) {
    const alert = _provAlertaInfo(pp.alerta);
    const carritoItems = _provCarritoDe(idProveedor) || {};
    const enCarrito = carritoItems[pp.idPP];
    const qty = enCarrito ? enCarrito.qty : 0;
    // upb viene del item del carrito si está, sino del producto (puede haber
    // sido actualizado en el catálogo y aún no se sincronizó al carrito)
    const upb = parseInt((enCarrito && enCarrito.upb) || pp.unidadesPorBulto) || 1;
    const bultos = upb > 1 ? Math.round((qty / upb) * 100) / 100 : 0;
    const subt = qty * (pp.precioReferencia || 0);
    const bultoChip = upb > 1
      ? `<span class="carrito-bulto-chip" title="${upb} unidades por bulto">📦 ×${upb}</span>`
      : '';
    return `
    <div class="carrito-fila${qty > 0 ? ' en-pedido' : ''}" data-idpp="${pp.idPP}">
      <div class="flex-1 min-w-0">
        <div class="flex items-center gap-2 flex-wrap">
          <div class="text-sm font-semibold text-slate-100 truncate flex-1 min-w-0">${pp.descripcion || pp.skuBase}</div>
          ${bultoChip}
        </div>
        <div class="text-[10px] text-slate-500 truncate" style="font-family:monospace">SKU ${pp.skuBase}${pp.codigoBarra ? ' · ▌' + pp.codigoBarra : ''}</div>
        <div class="flex items-center gap-2 text-[11px] mt-1" style="color:${alert.color}">
          <span>📦 Stock <b>${pp.stockTotal}</b></span>
          ${pp.stockMinimo > 0 ? `<span class="text-slate-500">· mín ${pp.stockMinimo}</span>` : ''}
          ${pp.sugerencia > 0 ? `<button onclick="MOS.carritoSetQty('${pp.idPP}', ${pp.sugerencia})" class="prov-sug-btn-mini" title="${pp.razonSugerencia || ''}">Sug ${pp.sugerencia}</button>` : ''}
        </div>
      </div>
      <div class="text-right shrink-0 mr-2">
        <div class="text-[11px] text-slate-500">${fmtMoney(pp.precioReferencia || 0)}</div>
        <div class="text-sm font-bold ${qty > 0 ? 'text-amber-400' : 'text-slate-600'}">${fmtMoney(subt)}</div>
        ${qty > 0 && upb > 1 ? `<div class="text-[10px] text-slate-500">${bultos} bulto${Math.round(bultos) === 1 ? '' : 's'}</div>` : ''}
      </div>
      <div class="prov-stepper shrink-0">
        <button onclick="MOS.carritoStep('${pp.idPP}', -${upb})" class="prov-stepper-btn" title="${upb > 1 ? `Quitar 1 bulto (−${upb})` : 'Quitar 1'}">−</button>
        <input type="number" min="0" step="${upb}" value="${qty}" class="prov-stepper-input" data-idpp="${pp.idPP}"
          oninput="MOS.carritoSetQty('${pp.idPP}', this.value)">
        <button onclick="MOS.carritoStep('${pp.idPP}', ${upb})" class="prov-stepper-btn" title="${upb > 1 ? `Sumar 1 bulto (+${upb})` : 'Sumar 1'}">+</button>
      </div>
    </div>`;
  }

  function _renderCarritoFooter(idProveedor) {
    const carrito = S.provCarritos[idProveedor] || { items: {}, ts: null };
    const items = Object.values(carrito.items || {});
    const totalQty = items.reduce((s, it) => s + (parseFloat(it.qty) || 0), 0);
    const totalMonto = items.reduce((s, it) => s + (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0), 0);
    const f = $('carritoFooter');
    if (!f) return;
    const ageH = carrito.ts ? Math.floor((Date.now() - carrito.ts) / 3600000) : null;
    const stale = ageH !== null && ageH >= 24;
    const tsHtml = carrito.ts
      ? `<div class="text-[10px] ${stale ? 'text-amber-400' : 'text-slate-500'}">${stale ? '⚠ ' : ''}Última edición: ${_carritoTimestampHumano(carrito.ts)}${stale ? ' · stock pudo cambiar' : ''}</div>`
      : '';
    f.innerHTML = `
      <div class="w-full flex flex-wrap items-center gap-2">
        <div class="min-w-0 flex-1">
          <div class="text-[10px] text-slate-500 uppercase">Total</div>
          <div class="text-sm font-bold text-slate-100">${items.length} prods · ${totalQty} unds</div>
          ${tsHtml}
        </div>
        <div class="text-right">
          <div class="text-[10px] text-slate-500 uppercase">Monto</div>
          <div class="text-base font-bold text-amber-400">${fmtMoney(totalMonto)}</div>
        </div>
      </div>
      <div class="w-full flex flex-wrap gap-2 mt-2">
        <button onclick="MOS.carritoAplicarSugerencias()" class="btn-ghost text-xs px-3 py-1.5" title="Reemplaza el carrito con las sugerencias actuales del backend">↻ Aplicar sugerencias</button>
        <button onclick="MOS.carritoLimpiar()" class="btn-ghost text-xs px-3 py-1.5" ${items.length ? '' : 'disabled style="opacity:.4"'}>Limpiar</button>
        <button onclick="MOS.provPedidoExportar()" class="btn-primary text-xs px-3 py-1.5 whitespace-nowrap ml-auto" ${items.length ? '' : 'disabled style="opacity:.4"'}>📄 Generar</button>
      </div>
    `;
  }

  // Operaciones del carrito (PERSISTEN al localStorage)
  function carritoSetQty(idPP, val) {
    const id = S._carritoModalProvId || S.provSelId;
    if (!id) return;
    const lista = (S.provProductos && S.provProductos[id]) || [];
    const item = lista.find(x => x.idPP === idPP);
    if (!item) return;
    let qty = parseFloat(val);
    if (isNaN(qty) || qty < 0) qty = 0;
    _provCarritoVacioOCrear(id);
    if (qty <= 0) {
      delete S.provCarritos[id].items[idPP];
    } else {
      S.provCarritos[id].items[idPP] = {
        idPP, sku: item.skuBase, desc: item.descripcion,
        codigoBarra: item.codigoBarra, precio: parseFloat(item.precioReferencia) || 0,
        qty: qty,
        upb: parseInt(item.unidadesPorBulto) || 1
      };
    }
    S.provCarritos[id].ts = Date.now();
    _provCarritoMarcarActivo(id);
    _renderCarrito();
    _refreshProvCarritoBadge(id);
  }
  function carritoStep(idPP, delta) {
    const id = S._carritoModalProvId || S.provSelId;
    if (!id) return;
    const cur = (S.provCarritos[id] && S.provCarritos[id].items[idPP] && S.provCarritos[id].items[idPP].qty) || 0;
    carritoSetQty(idPP, Math.max(0, cur + delta));
  }
  async function carritoLimpiar() {
    const id = S._carritoModalProvId || S.provSelId;
    if (!id) return;
    if (!Object.keys((S.provCarritos[id] && S.provCarritos[id].items) || {}).length) return;
    if (!await _modalConfirm('¿Limpiar el carrito de este proveedor?', { warning: true, titulo: 'Limpiar carrito' })) return;
    S.provCarritos[id] = { items: {}, ts: Date.now() };
    _provCarritosSave();
    _renderCarrito();
    _refreshProvCarritoBadge(id);
    _provFabRender();
  }
  async function carritoAplicarSugerencias() {
    const id = S._carritoModalProvId || S.provSelId;
    if (!id) return;
    if (!await _modalConfirm('¿Reemplazar el carrito con las sugerencias actuales?\n\nPierdes ajustes manuales.', { warning: true, titulo: 'Aplicar sugerencias' })) return;
    const productos = (S.provProductos && S.provProductos[id]) || [];
    const items = {};
    productos.forEach(pp => {
      const sug = parseFloat(pp.sugerencia) || 0;
      if (sug > 0) {
        items[pp.idPP] = {
          idPP: pp.idPP, sku: pp.skuBase, desc: pp.descripcion,
          codigoBarra: pp.codigoBarra, precio: parseFloat(pp.precioReferencia) || 0,
          qty: sug, upb: parseInt(pp.unidadesPorBulto) || 1
        };
      }
    });
    S.provCarritos[id] = { items, ts: Date.now() };
    _provCarritoMarcarActivo(id);
    _renderCarrito();
    _refreshProvCarritoBadge(id);
    toast(`Carrito actualizado · ${Object.keys(items).length} prods`, 'ok');
  }

  function _pedidoCabeceraTexto() {
    const id = S._carritoModalProvId || S.provSelId;
    const prov = (S.proveedores || []).find(p => p.idProveedor === id) || {};
    const fecha = today();
    return { prov, fecha };
  }

  function _pedidoTextoWhatsApp() {
    const { prov, fecha } = _pedidoCabeceraTexto();
    const id = S._carritoModalProvId || S.provSelId;
    const items = Object.values((S.provCarritos[id] && S.provCarritos[id].items) || {});
    const totalMonto = items.reduce((s, it) => s + (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0), 0);
    const lines = [
      `*PEDIDO — ${prov.nombre || 'Proveedor'}*`,
      `Fecha: ${fecha}`,
      ``,
      ...items.map((it, i) => {
        const sub = (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0);
        return `${i+1}. ${it.desc}\n   ${it.qty} und × ${fmtMoney(it.precio)} = *${fmtMoney(sub)}*`;
      }),
      ``,
      `*Total estimado: ${fmtMoney(totalMonto)}*`,
      ``,
      `_Generado desde MOS_`
    ];
    return lines.join('\n');
  }

  function provPedidoExportar() {
    const id = S._carritoModalProvId || S.provSelId;
    if (!id) { toast('No hay carrito activo', 'error'); return; }
    const items = Object.values((S.provCarritos[id] && S.provCarritos[id].items) || {});
    if (!items.length) { toast('El carrito está vacío', 'error'); return; }
    const { prov, fecha } = _pedidoCabeceraTexto();
    const totalMonto = items.reduce((s, it) => s + (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0), 0);
    const totalQty = items.reduce((s, it) => s + (parseFloat(it.qty) || 0), 0);
    const cont = $('pedidoExportContent');
    if (!cont) return;
    cont.innerHTML = `
      <div class="pedido-doc">
        <div class="pedido-doc-header">
          <div>
            <div class="text-xs text-slate-500 uppercase tracking-wider">Pedido</div>
            <h2 class="text-xl font-bold text-slate-100">${prov.nombre || 'Proveedor'}</h2>
            <div class="text-xs text-slate-500 mt-0.5">${[prov.ruc, prov.telefono].filter(Boolean).join(' · ') || ''}</div>
          </div>
          <div class="text-right">
            <div class="text-xs text-slate-500">Fecha</div>
            <div class="text-sm font-semibold text-slate-100">${fecha}</div>
          </div>
        </div>
        <table class="pedido-tabla">
          <thead>
            <tr>
              <th>#</th>
              <th>Producto</th>
              <th class="text-right">Cant.</th>
              <th class="text-right">Precio</th>
              <th class="text-right">Subtotal</th>
            </tr>
          </thead>
          <tbody>
            ${items.map((it, i) => {
              const sub = (parseFloat(it.qty) || 0) * (parseFloat(it.precio) || 0);
              return `<tr>
                <td>${i+1}</td>
                <td>
                  <div class="font-medium">${it.desc}</div>
                  <div class="text-[10px] text-slate-500" style="font-family:monospace">${it.sku}${it.codigoBarra ? ' · ' + it.codigoBarra : ''}</div>
                </td>
                <td class="text-right font-bold">${it.qty}</td>
                <td class="text-right">${fmtMoney(it.precio)}</td>
                <td class="text-right font-bold">${fmtMoney(sub)}</td>
              </tr>`;
            }).join('')}
          </tbody>
          <tfoot>
            <tr>
              <td colspan="2" class="font-bold">TOTAL (${items.length} prods · ${totalQty} unds)</td>
              <td colspan="3" class="text-right font-bold text-amber-400">${fmtMoney(totalMonto)}</td>
            </tr>
          </tfoot>
        </table>
      </div>
    `;
    openModal('modalPedidoExport');
  }

  function provPedidoImprimir() {
    const cont = $('pedidoExportContent');
    if (!cont) return;
    const win = window.open('', '_blank', 'width=800,height=900');
    if (!win) { toast('Permite popups para imprimir', 'error'); return; }
    win.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>Pedido</title>
      <style>
        body { font-family: system-ui, sans-serif; padding: 20px; color: #111; }
        .pedido-doc-header { display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 16px; padding-bottom: 8px; border-bottom: 2px solid #333; }
        .pedido-doc-header h2 { margin: 4px 0; font-size: 22px; }
        .pedido-tabla { width: 100%; border-collapse: collapse; font-size: 12px; }
        .pedido-tabla th, .pedido-tabla td { padding: 6px 8px; border-bottom: 1px solid #ccc; text-align: left; }
        .pedido-tabla th { background: #f3f4f6; font-weight: 700; }
        .pedido-tabla .text-right { text-align: right; }
        .pedido-tabla tfoot td { font-weight: 700; padding-top: 12px; border-top: 2px solid #333; border-bottom: none; }
        @media print { body { padding: 0; } }
      </style>
    </head><body>${cont.innerHTML}</body></html>`);
    win.document.close();
    setTimeout(() => { win.print(); _carritoOfrecerLimpiar(); }, 400);
  }
  // Pregunta tras imprimir/WhatsApp: ¿marcar como enviado y limpiar carrito?
  function _carritoOfrecerLimpiar() {
    const id = S._carritoModalProvId || S.provSelId;
    if (!id) return;
    const items = (S.provCarritos[id] && S.provCarritos[id].items) || {};
    if (!Object.keys(items).length) return;
    setTimeout(async () => {
      if (await _modalConfirm('¿Marcar el pedido como enviado y limpiar el carrito de este proveedor?', { titulo: 'Limpiar tras envío' })) {
        S.provCarritos[id] = { items: {}, ts: Date.now() };
        _provCarritosSave();
        _renderCarritoIfOpen();
        _refreshProvCarritoBadge(id);
        _provFabRender();
        toast('Carrito limpiado', 'ok');
      }
    }, 600);
  }

  function provPedidoWhatsApp() {
    const items = Object.values(S.provPedido.items || {});
    if (!items.length) { toast('No hay items', 'error'); return; }
    const prov = S.proveedores.find(p => p.idProveedor === S.provSelId) || {};
    const tel = String(prov.telefono || '').replace(/\D/g, '');
    const texto = encodeURIComponent(_pedidoTextoWhatsApp());
    const url = tel
      ? `https://wa.me/${tel.length === 9 ? '51' + tel : tel}?text=${texto}`
      : `https://wa.me/?text=${texto}`;
    window.open(url, '_blank');
    _carritoOfrecerLimpiar();
  }

  function _filtrarProvProductos(q) {
    S.provProdFilter = q || '';
    const id = S.provSelId;
    if (!id) return;
    const items = _filtrarPP(S.provProductos[id] || [], S.provProdFilter);
    _pintaProvProductos(items);
  }

  async function _renderProvProductos() {
    const id = S.provSelId;
    const cont = $('provTabProductos');
    if (!cont) return;
    S.provProductos = S.provProductos || {};
    S.provProdFilter = S.provProdFilter || '';

    // Asegurar contenedor (con buscador + botón)
    if (!cont.querySelector('#provProductosList')) {
      cont.innerHTML = `
        <div class="flex items-center gap-2 mb-3 flex-wrap">
          <h4 class="font-semibold text-sm text-slate-300 shrink-0">📦 Catálogo</h4>
          <input id="provProdFilter" class="inp text-xs flex-1" style="min-width:120px;max-width:200px"
            placeholder="🔍 Filtrar..." oninput="MOS._filtrarProvProductos(this.value)" value="${S.provProdFilter}">
          <button id="btnJalarProds" class="btn-ghost text-xs px-3 py-1.5 shrink-0" onclick="MOS.jalarProductosProveedor()" title="Importa al catálogo todos los productos comprados a este proveedor según el histórico de guías">⬇️ Jalar</button>
          <button class="btn-primary text-xs px-3 py-1.5 shrink-0" onclick="MOS.abrirModalProvProducto(null)">+ Producto</button>
        </div>
        <div id="provProductosList" class="space-y-2"></div>
      `;
    }
    const list = $('provProductosList');

    // Render cache si existe en memoria (ya hidratado del localStorage al login)
    if (!S.provProductos[id]) {
      // Por si el render se llama antes de la hidratación
      const localCached = _provProdsLoadCache(id);
      if (localCached) S.provProductos[id] = localCached;
    }
    if (S.provProductos[id]) {
      _pintaProvProductos(_filtrarPP(S.provProductos[id], S.provProdFilter));
    } else {
      list.innerHTML = '<div class="skel h-24 rounded-lg"></div><div class="skel h-24 rounded-lg mt-2"></div>';
    }

    // Fetch fresco con stock + min/max + sugerencia
    try {
      const lista = await API.get('getProductosProveedorConStock', { idProveedor: id, rangoDias: 30 });
      const items = Array.isArray(lista) ? lista : (lista && lista.data) || [];
      S.provProductos[id] = items;
      _provProdsSaveCache(id, items);
      _refreshProvPendientesBadge(id);
      // Si entre el fetch y la respuesta el usuario cambió de proveedor, NO pintar:
      // pintaríamos productos del proveedor anterior sobre el detalle del nuevo.
      if (S.provSelId !== id) return;
      _pintaProvProductos(_filtrarPP(items, S.provProdFilter));
    } catch(e) {
      if (!S.provProductos[id]) list.innerHTML = `<p class="text-red-400 text-sm">Error: ${e.message}</p>`;
    }
  }

  function _filtrarHist(productos, q) {
    if (!q) return productos;
    const qn = _norm(q);
    const palabras = qn.split(/\s+/).filter(Boolean);
    return productos.filter(it => {
      const hay = _norm((it.descripcion || '') + ' ' + (it.codigoBarra || ''));
      return palabras.every(w => hay.indexOf(w) >= 0);
    });
  }

  function _fmtFechaLarga(fechaStr) {
    if (!fechaStr) return '';
    const d = new Date(fechaStr + 'T00:00:00');
    if (isNaN(d.getTime())) return fechaStr;
    const dias = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
    const meses = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
    return `${dias[d.getDay()]} ${d.getDate()} ${meses[d.getMonth()]} ${d.getFullYear()}`;
  }

  // Estado de días expandidos (key = idProveedor:fecha)
  S.provHistDiasOpen = S.provHistDiasOpen || {};

  function provHistToggleDia(fecha) {
    const key = (S.provSelId || '') + ':' + fecha;
    S.provHistDiasOpen[key] = !S.provHistDiasOpen[key];
    const id = S.provSelId;
    if (id && S.provHistorico[id]) _pintaProvHistorico(S.provHistorico[id]);
  }

  function _pintaProvHistorico(data) {
    const body = $('provHistoricoBody');
    if (!body) return;
    const tieneDias = data && Array.isArray(data.guiasPorDia) && data.guiasPorDia.length;
    if (!data || (!tieneDias && (!data.productos || !data.productos.length))) {
      body.innerHTML = '<p class="text-slate-500 text-sm py-6 text-center">Sin compras registradas en el rango.</p>';
      return;
    }

    const filtro = (S.provHistFilter || '').toLowerCase().trim();
    const _matchItem = (it) => {
      if (!filtro) return true;
      const hay = ((it.descripcion || '') + ' ' + (it.codigoBarra || '') + ' ' + (it.skuBase || '')).toLowerCase();
      return filtro.split(/\s+/).every(w => hay.indexOf(w) >= 0);
    };

    let htmlDias = '';
    if (tieneDias) {
      const dias = data.guiasPorDia
        .map(d => ({ ...d, items: (d.items || []).filter(_matchItem) }))
        .filter(d => !filtro || d.items.length > 0);
      if (!dias.length) {
        htmlDias = '<p class="text-slate-500 text-sm py-6 text-center italic">Sin coincidencias para "' + filtro + '".</p>';
      } else {
        htmlDias = `<div class="space-y-2">${dias.map(d => {
          const key = (S.provSelId || '') + ':' + d.fecha;
          const open = !!S.provHistDiasOpen[key];
          return `
            <div class="hist-dia-card">
              <div class="hist-dia-header" onclick="MOS.provHistToggleDia('${d.fecha}')">
                <div class="flex-1 min-w-0">
                  <div class="text-sm font-bold text-slate-100">${_fmtFechaLarga(d.fecha)}</div>
                  <div class="text-[11px] text-slate-500 mt-0.5">${d.numItems} producto${d.numItems === 1 ? '' : 's'} · ${d.numGuias} guía${d.numGuias === 1 ? '' : 's'}</div>
                </div>
                <div class="text-right shrink-0">
                  <div class="text-sm font-bold text-amber-400 whitespace-nowrap">${fmtMoney(d.totalDia)}</div>
                </div>
                <span class="hist-chevron" style="transform:rotate(${open ? 180 : 0}deg)">▾</span>
              </div>
              <div class="hist-dia-body" style="max-height:${open ? 1200 : 0}px">
                <div class="px-3 pb-3 pt-2 space-y-1.5">
                  ${d.items.map(it => `
                    <div class="hist-item-row">
                      <div class="min-w-0 flex-1">
                        <div class="text-[13px] text-slate-100 truncate">${it.descripcion || '—'}</div>
                        <div class="text-[10px] text-slate-500 truncate" style="font-family:monospace">${it.skuBase || ''}${it.codigoBarra ? ' · ▌' + it.codigoBarra : ''}</div>
                      </div>
                      <div class="text-right shrink-0">
                        <div class="text-sm font-bold text-slate-100">${it.cantidad}u</div>
                        <div class="text-[10px] text-slate-500">× ${fmtMoney(it.precio)} = <b class="text-amber-400">${fmtMoney(it.monto)}</b></div>
                      </div>
                    </div>
                  `).join('')}
                </div>
              </div>
            </div>`;
        }).join('')}</div>`;
      }
    }

    body.innerHTML = `
      <div class="grid grid-cols-3 gap-2 mb-3">
        <div class="card-sm p-2 text-center"><div class="text-[10px] text-slate-500 uppercase tracking-wide">Guías</div><div class="text-base sm:text-lg font-bold text-slate-100">${data.totalGuias || 0}</div></div>
        <div class="card-sm p-2 text-center"><div class="text-[10px] text-slate-500 uppercase tracking-wide">Gastado</div><div class="text-base sm:text-lg font-bold text-amber-400 truncate">${fmtMoney(data.totalGastado || 0)}</div></div>
        <div class="card-sm p-2 text-center"><div class="text-[10px] text-slate-500 uppercase tracking-wide">Por pagar</div><div class="text-base sm:text-lg font-bold ${(data.porPagar || 0) > 0 ? 'text-rose-400' : 'text-green-400'} truncate">${fmtMoney(data.porPagar || 0)}</div></div>
      </div>
      ${htmlDias || '<p class="text-slate-500 text-xs py-2 italic">Tu GAS aún no devuelve histórico por día — redespliega para ver el timeline.</p>'}
    `;
  }

  function _filtrarProvHistorico(q) {
    S.provHistFilter = q || '';
    const id = S.provSelId;
    if (id && S.provHistorico[id]) _pintaProvHistorico(S.provHistorico[id]);
  }

  async function _renderProvHistorico() {
    const id = S.provSelId;
    const cont = $('provTabHistorico');
    if (!cont) return;
    S.provHistFilter = S.provHistFilter || '';
    // Asegurar contenedor base (con filtro)
    if (!cont.querySelector('#provHistoricoBody')) {
      cont.innerHTML = `
        <div class="flex items-center gap-2 mb-3 flex-wrap">
          <h4 class="font-semibold text-sm text-slate-300 shrink-0">📊 Histórico</h4>
          <input id="provHistFilter" class="inp text-xs flex-1" style="min-width:100px;max-width:180px"
            placeholder="🔍 Filtrar..." oninput="MOS._filtrarProvHistorico(this.value)" value="${S.provHistFilter}">
          <select id="provHistoricoDias" class="inp text-xs shrink-0" style="max-width:90px" onchange="MOS._refetchHistoricoProv()">
            <option value="30">30d</option>
            <option value="60" selected>60d</option>
            <option value="90">90d</option>
            <option value="180">180d</option>
          </select>
        </div>
        <div id="provHistoricoBody"></div>
      `;
    }

    // Render desde cache si existe (instantáneo)
    if (S.provHistorico[id]) {
      _pintaProvHistorico(S.provHistorico[id]);
    } else {
      $('provHistoricoBody').innerHTML = '<div class="skel h-32 rounded-lg"></div>';
    }

    // Fetch fresco
    try {
      const dias = parseInt($('provHistoricoDias')?.value) || 60;
      const r = await API.get('getHistoricoProveedor', { idProveedor: id, dias });
      const data = r && r.data ? r.data : r;
      S.provHistorico[id] = data;
      _pintaProvHistorico(data);
    } catch(e) {
      if (!S.provHistorico[id]) {
        $('provHistoricoBody').innerHTML = `<p class="text-red-400 text-sm">Error: ${e.message}</p>`;
      }
    }
  }

  // Forzar refetch al cambiar el rango de días
  function _refetchHistoricoProv() {
    const id = S.provSelId;
    if (id) S.provHistorico[id] = null;
    _renderProvHistorico();
  }

  async function _renderProvPedidos() {
    const id = S.provSelId;
    const cont = $('provTabPedidos');
    if (!cont) return;
    cont.innerHTML = `
      <div class="flex items-center justify-between mb-3">
        <h4 class="font-semibold text-sm text-slate-300">🛒 Pedidos de compra</h4>
        <button class="btn-primary text-xs px-3 py-1.5" onclick="MOS.abrirModalPedido('${id}')">+ Nuevo pedido</button>
      </div>
      <div id="listPedidos" class="text-sm text-slate-400"></div>
    `;
    // Render desde cache primero
    if (S.provPedidos[id]) {
      renderPedidos(S.provPedidos[id]);
    } else {
      $('listPedidos').textContent = 'Cargando...';
      try {
        const r = await API.get('getPedidos', { idProveedor: id });
        S.provPedidos[id] = Array.isArray(r) ? r : (r && r.data) || [];
        renderPedidos(S.provPedidos[id]);
      } catch(e) {
        $('listPedidos').innerHTML = `<p class="text-red-400">Error: ${e.message}</p>`;
      }
    }
  }

  function renderPagos(pagos) {
    const el = $('listPagos');
    if (!el) return;
    if (!pagos.length) { el.innerHTML = '<p class="text-slate-600">Sin pagos registrados</p>'; return; }
    const total = pagos.reduce((s, p) => s + parseFloat(p.monto || 0), 0);
    el.innerHTML = `<p class="text-xs text-slate-500 mb-2">Total: <span class="text-indigo-400 font-semibold">${fmtMoney(total)}</span></p>` +
      pagos.slice(-5).reverse().map(p => `
        <div class="flex justify-between items-center gap-2 py-1.5 border-b border-slate-800/50">
          <div class="min-w-0 flex-1">
            <span class="text-slate-300 text-xs">${fmtDate(p.fecha)}</span>
            ${p.numeroFactura ? `<span class="text-slate-500 ml-2 text-xs truncate">${p.numeroFactura}</span>` : ''}
          </div>
          <span class="font-semibold text-green-400 text-sm whitespace-nowrap shrink-0">${fmtMoney(p.monto)}</span>
        </div>
      `).join('');
  }

  function renderPedidos(pedidos) {
    const el = $('listPedidos');
    if (!el) return;
    if (!pedidos.length) { el.innerHTML = '<p class="text-slate-600">Sin pedidos registrados</p>'; return; }
    el.innerHTML = pedidos.slice(-5).reverse().map(p => {
      const badge = p.estado === 'BORRADOR' ? 'badge-gray' : p.estado === 'CONFIRMADO' ? 'badge-blue' : 'badge-green';
      return `<div class="flex justify-between items-center gap-2 py-1.5 border-b border-slate-800/50">
        <div class="min-w-0 flex-1">
          <div class="text-slate-300 text-xs truncate">${p.idPedido}</div>
          <div class="text-slate-500 text-[10px]">${fmtDate(p.fechaCreacion)}</div>
        </div>
        <div class="flex flex-col items-end gap-0.5 shrink-0">
          <span class="text-slate-300 text-sm whitespace-nowrap">${fmtMoney(p.montoEstimado)}</span>
          <span class="badge ${badge} text-[10px]">${p.estado}</span>
        </div>
      </div>`;
    }).join('');
  }

  // ── MODALS ──────────────────────────────────────────────────
  function openModal(id)  { const el = $(id); if (el) { el.classList.remove('hidden'); el.classList.add('open'); } }
  function closeModal(id) { const el = $(id); if (el) { el.classList.remove('open'); el.classList.add('hidden'); } }

  // ════════════════════════════════════════════════════════════
  // [v2.41.83] ADMIN AUTH MODAL — UNIVERSAL (las 3 apps usan esto)
  //
  // Uso:
  //   const auth = await pedirAuth({
  //     accion:        'VETAR_LIQUIDACION',
  //     refDocumento:  'idPersonal|fecha',
  //     contexto:      'Vetar día de Javier · 2026-05-19',
  //     tier:          2,                  // opcional; lo infiere del catálogo
  //     allowCache:    true                // default true
  //   });
  //   if (!auth) return; // user canceló o falló
  //   // → auth = { clave, validadoPor, idPersonal, nombre, rol, cacheHit }
  // ════════════════════════════════════════════════════════════
  const _AAM_CACHE_KEY = 'mos_admin_auth_cache_v1';
  const _AAM_TIER_TTL  = { 1: 10 * 60 * 1000, 2: 5 * 60 * 1000, 3: 0 };
  let _aamState = null;  // { resolve, accion, refDocumento, tier, value, t0 }
  let _aamCatalogo = null; // {ACCION: {tier, label}}

  function _aamLoadCatalogo() {
    if (_aamCatalogo) return Promise.resolve(_aamCatalogo);
    return API.get('getAuthCatalogo', {}).then(r => {
      // [v2.42.04 fix] API.get devuelve d.data — r ya es el catálogo, no envuelto
      _aamCatalogo = r || {};
      return _aamCatalogo;
    }).catch(() => ({}));
  }

  function _aamCacheGet(accion, tier) {
    if (!tier || _AAM_TIER_TTL[tier] === 0) return null;
    try {
      const raw = localStorage.getItem(_AAM_CACHE_KEY);
      if (!raw) return null;
      const cache = JSON.parse(raw);
      const entry = cache[accion];
      if (!entry) return null;
      if (Date.now() > entry.expires) {
        delete cache[accion];
        localStorage.setItem(_AAM_CACHE_KEY, JSON.stringify(cache));
        return null;
      }
      return entry;
    } catch(_) { return null; }
  }
  function _aamCacheSet(accion, tier, auth) {
    const ttl = _AAM_TIER_TTL[tier] || 0;
    if (!ttl) return;
    try {
      const raw = localStorage.getItem(_AAM_CACHE_KEY);
      const cache = raw ? JSON.parse(raw) : {};
      cache[accion] = {
        clave: auth.clave,
        validadoPor: auth.validadoPor,
        idPersonal: auth.idPersonal,
        nombre: auth.nombre,
        rol: auth.rol,
        tier: tier,
        expires: Date.now() + ttl
      };
      localStorage.setItem(_AAM_CACHE_KEY, JSON.stringify(cache));
    } catch(_){}
  }
  function _aamCacheClear(accion) {
    try {
      const raw = localStorage.getItem(_AAM_CACHE_KEY);
      if (!raw) return;
      const cache = JSON.parse(raw);
      if (accion) delete cache[accion];
      else Object.keys(cache).forEach(k => delete cache[k]);
      localStorage.setItem(_AAM_CACHE_KEY, JSON.stringify(cache));
    } catch(_){}
  }

  async function pedirAuth(opts) {
    opts = opts || {};
    const accion = String(opts.accion || 'GENERICA').toUpperCase();
    const allowCache = opts.allowCache !== false;
    await _aamLoadCatalogo();
    const catEntry = _aamCatalogo[accion] || { tier: 2, label: opts.accion };
    const tier = parseInt(opts.tier, 10) || catEntry.tier || 2;

    // ── Verificar cache ──
    if (allowCache) {
      const hit = _aamCacheGet(accion, tier);
      if (hit) {
        // Auditar cache_hit en bg (fire-and-forget)
        try {
          API.post('verificarClaveAdmin', {
            clave: hit.clave,
            accion: accion,
            refDocumento: opts.refDocumento || '',
            appOrigen: 'MOS',
            detalle: opts.contexto || '',
            tier: tier,
            cache_hit: 1,
            tiempo_verify_ms: 0,
            deviceId: (S.session && S.session.deviceId) || ''
          }).catch(() => {});
        } catch(_){}
        return Object.assign({}, hit, { cacheHit: true });
      }
    }

    return new Promise(resolve => {
      _aamState = {
        resolve, accion, tier,
        refDocumento: opts.refDocumento || '',
        contexto:     opts.contexto || '',
        value:        '',
        t0:           Date.now(),
        allowCache
      };
      _aamMostrar(catEntry.label || opts.accion, opts.contexto || '', tier);
    });
  }
  function _aamMostrar(label, contexto, tier) {
    const tit = document.getElementById('aamTitle');
    const sub = document.getElementById('aamSubtitle');
    const ctx = document.getElementById('aamContext');
    const sess = document.getElementById('aamSessionName');
    const tierBadge = document.getElementById('aamTierBadge');
    const msg = document.getElementById('aamMessage');
    if (tit) tit.textContent = label || 'Autorización requerida';
    if (sub) sub.textContent = 'Acción protegida · 8 dígitos';
    if (ctx) ctx.textContent = contexto || '';
    if (sess) sess.textContent = ((S.session && S.session.nombre) || '—') + ' (' + ((S.session && S.session.rol) || '?') + ')';
    if (tierBadge) {
      const tierLbl = tier === 1 ? 'Tier 1 · cache 10 min'
                    : tier === 2 ? 'Tier 2 · cache 5 min'
                    : 'Tier 3 · sin cache';
      tierBadge.textContent = tierLbl;
    }
    if (msg) { msg.className = 'aam-message hidden'; msg.textContent = ''; }
    _aamState.value = '';
    _aamRenderDots();
    const box = document.querySelector('#modalAdminAuth .aam-box');
    if (box) { box.classList.remove('shake', 'success'); }
    openModal('modalAdminAuth');
    try { _evalSfx && _evalSfx('open'); } catch(_){}
    // Focus hidden input para keyboard input
    setTimeout(() => {
      const inp = document.getElementById('aamHiddenInput');
      if (inp) inp.focus();
    }, 80);
    // Listener ESC
    document.addEventListener('keydown', _aamEscHandler, true);
  }
  function _aamEscHandler(e) {
    if (!_aamState) return;
    if (e.key === 'Escape') {
      e.stopImmediatePropagation();
      _aamCancelar();
    }
  }
  function _aamRenderDots() {
    const dots = document.querySelectorAll('#aamDots .aam-dot');
    const v = (_aamState && _aamState.value) || '';
    dots.forEach((d, i) => {
      d.classList.remove('filled', 'error', 'success');
      if (i < v.length) d.classList.add('filled');
    });
  }
  function _aamPress(digit) {
    if (!_aamState) return;
    if (_aamState.value.length >= 8) return;
    _aamState.value += String(digit);
    _aamRenderDots();
    try { _evalSfx && _evalSfx('tap'); } catch(_){}
    try { if (navigator.vibrate) navigator.vibrate(15); } catch(_){}
    if (_aamState.value.length === 8) {
      // Auto-confirmar al 8º dígito
      setTimeout(_aamConfirmar, 120);
    }
  }
  function _aamDelete() {
    if (!_aamState) return;
    if (!_aamState.value.length) return;
    _aamState.value = _aamState.value.slice(0, -1);
    _aamRenderDots();
    try { _evalSfx && _evalSfx('tap'); } catch(_){}
  }
  function _aamOnKey(e) {
    if (!_aamState) return;
    if (e.key === 'Backspace') { e.preventDefault(); _aamDelete(); return; }
    if (e.key === 'Enter') { e.preventDefault(); _aamConfirmar(); return; }
    if (/^[0-9]$/.test(e.key)) { e.preventDefault(); _aamPress(e.key); return; }
  }
  async function _aamConfirmar() {
    if (!_aamState) return;
    if (_aamState.value.length !== 8) {
      _aamMostrarError('Ingresa 8 dígitos');
      return;
    }
    const ico = document.getElementById('aamLockIcon');
    if (ico) ico.classList.add('spin');
    const t0 = _aamState.t0;
    const tiempo_verify_ms = Date.now() - t0;
    try {
      const r = await API.post('verificarClaveAdmin', {
        clave: _aamState.value,
        accion: _aamState.accion,
        refDocumento: _aamState.refDocumento,
        appOrigen: 'MOS',
        detalle: _aamState.contexto,
        tier: _aamState.tier,
        cache_hit: 0,
        tiempo_verify_ms: tiempo_verify_ms,
        deviceId: (S.session && S.session.deviceId) || ''
      });
      // [v2.42.00 fix] API.post devuelve d.data directamente — NO hay r.data anidado.
      // Bug histórico: el modal siempre mostraba "Clave incorrecta" porque buscaba
      // r.data.autorizado cuando r ya ERA el data desempaquetado.
      const d = r || {};
      if (ico) ico.classList.remove('spin');
      if (!d.autorizado) {
        _aamMostrarError(d.error || 'Clave incorrecta');
        return;
      }
      // Éxito
      try { _evalSfx && _evalSfx('success'); } catch(_){}
      try { if (navigator.vibrate) navigator.vibrate([20, 30, 40]); } catch(_){}
      document.querySelectorAll('#aamDots .aam-dot').forEach(dot => dot.classList.add('success'));
      const box = document.querySelector('#modalAdminAuth .aam-box');
      if (box) box.classList.add('success');
      const auth = {
        clave:       _aamState.value,
        validadoPor: d.validadoPor,
        idPersonal:  d.idPersonal,
        nombre:      d.nombre,
        rol:         d.rol,
        cacheHit:    false
      };
      if (_aamState.allowCache) {
        _aamCacheSet(_aamState.accion, _aamState.tier, auth);
      }
      const resolveFn = _aamState.resolve;
      setTimeout(() => {
        closeModal('modalAdminAuth');
        document.removeEventListener('keydown', _aamEscHandler, true);
        _aamState = null;
        resolveFn(auth);
      }, 500);
    } catch(e) {
      if (ico) ico.classList.remove('spin');
      _aamMostrarError('Error: ' + (e.message || e));
    }
  }
  // ════════════════════════════════════════════════════════════════════
  // [v2.42.04] HELPERS genéricos para reemplazar confirm/prompt nativos.
  // Cumplen regla feedback-modales-optimistas-modernos: backdrop blur,
  // animación scale entrada, beep al abrir, paleta MOS (slate + accent).
  // Drop-in:
  //    if (!confirm('texto')) return     →    if (!await _modalConfirm('texto')) return
  //    const v = prompt('label', def)    →    const v = await _modalPrompt('label', def)
  // Devuelven Promise — la función caller debe ser async.
  // ════════════════════════════════════════════════════════════════════
  function _modalConfirm(msg, opts) {
    opts = opts || {};
    return new Promise((resolve) => {
      const _esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
      const accent  = opts.danger ? 'danger' : (opts.warning ? 'warn' : 'primary');
      const icoMap  = { danger: '⚠', warn: '🟡', primary: '❓' };
      const titulo  = opts.titulo || (opts.danger ? 'Confirmar acción' : '¿Continuar?');
      const okTxt   = opts.okText || (opts.danger ? 'Sí, continuar' : 'Aceptar');
      const cancelTxt = opts.cancelText || 'Cancelar';
      const backdrop = document.createElement('div');
      backdrop.className = 'mos-modal-generic-backdrop';
      backdrop.innerHTML = `
        <div class="mos-modal-generic mos-modal-generic-${accent}" role="dialog" aria-modal="true">
          <div class="mos-modal-generic-head">
            <span class="mos-modal-generic-ico">${icoMap[accent]}</span>
            <strong>${_esc(titulo)}</strong>
            <button class="mos-modal-generic-close" data-cancel aria-label="Cerrar">✕</button>
          </div>
          <div class="mos-modal-generic-body">${(msg || '').split('\n\n').map(p => '<p>' + _esc(p).replace(/\n/g, '<br>') + '</p>').join('')}</div>
          <div class="mos-modal-generic-foot">
            <button class="mos-modal-generic-btn mos-modal-generic-btn-ghost" data-cancel>${_esc(cancelTxt)}</button>
            <button class="mos-modal-generic-btn mos-modal-generic-btn-ok mos-modal-generic-btn-${accent}" data-ok>${_esc(okTxt)}</button>
          </div>
        </div>`;
      const cerrar = (val) => {
        backdrop.classList.remove('is-open');
        setTimeout(() => { try { backdrop.remove(); } catch(_){} }, 200);
        resolve(val);
      };
      backdrop.addEventListener('click', (ev) => {
        const t = ev.target;
        if (t === backdrop || (t.closest && t.closest('[data-cancel]'))) cerrar(false);
        else if (t.closest && t.closest('[data-ok]')) {
          try { _finBeep?.(opts.danger ? 'warn' : 'success'); } catch(_){}
          cerrar(true);
        }
      });
      document.body.appendChild(backdrop);
      requestAnimationFrame(() => backdrop.classList.add('is-open'));
      try { _finBeep?.('tap'); } catch(_){}
      setTimeout(() => { try { backdrop.querySelector('[data-ok]')?.focus(); } catch(_){} }, 220);
    });
  }

  function _modalPrompt(label, defaultValue, opts) {
    opts = opts || {};
    return new Promise((resolve) => {
      const _esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
      const titulo = opts.titulo || 'Ingresar dato';
      const okTxt  = opts.okText || 'Aceptar';
      const ph     = opts.placeholder || '';
      const isLong = opts.textarea === true;
      const inputHtml = isLong
        ? `<textarea class="mos-modal-generic-input" rows="3" maxlength="${opts.maxlength || 240}" placeholder="${_esc(ph)}">${_esc(defaultValue || '')}</textarea>`
        : `<input type="${opts.inputType || 'text'}" inputmode="${opts.inputMode || ''}" maxlength="${opts.maxlength || ''}" class="mos-modal-generic-input" value="${_esc(defaultValue || '')}" placeholder="${_esc(ph)}" />`;
      const backdrop = document.createElement('div');
      backdrop.className = 'mos-modal-generic-backdrop';
      backdrop.innerHTML = `
        <div class="mos-modal-generic mos-modal-generic-primary" role="dialog" aria-modal="true">
          <div class="mos-modal-generic-head">
            <span class="mos-modal-generic-ico">✏</span>
            <strong>${_esc(titulo)}</strong>
            <button class="mos-modal-generic-close" data-cancel>✕</button>
          </div>
          <div class="mos-modal-generic-body">
            <label class="mos-modal-generic-label">${_esc(label || '')}</label>
            ${inputHtml}
          </div>
          <div class="mos-modal-generic-foot">
            <button class="mos-modal-generic-btn mos-modal-generic-btn-ghost" data-cancel>Cancelar</button>
            <button class="mos-modal-generic-btn mos-modal-generic-btn-ok mos-modal-generic-btn-primary" data-ok>${_esc(okTxt)}</button>
          </div>
        </div>`;
      const cerrar = (val) => {
        backdrop.classList.remove('is-open');
        setTimeout(() => { try { backdrop.remove(); } catch(_){} }, 200);
        resolve(val);
      };
      const getVal = () => {
        const i = backdrop.querySelector('.mos-modal-generic-input');
        return i ? String(i.value || '') : '';
      };
      backdrop.addEventListener('click', (ev) => {
        const t = ev.target;
        if (t === backdrop || (t.closest && t.closest('[data-cancel]'))) cerrar(null);
        else if (t.closest && t.closest('[data-ok]')) {
          try { _finBeep?.('success'); } catch(_){}
          cerrar(getVal());
        }
      });
      backdrop.addEventListener('keydown', (ev) => {
        if (ev.key === 'Enter' && !isLong) {
          try { _finBeep?.('success'); } catch(_){}
          cerrar(getVal());
        } else if (ev.key === 'Escape') cerrar(null);
      });
      document.body.appendChild(backdrop);
      requestAnimationFrame(() => backdrop.classList.add('is-open'));
      try { _finBeep?.('tap'); } catch(_){}
      setTimeout(() => {
        try { backdrop.querySelector('.mos-modal-generic-input')?.focus(); } catch(_){}
        try { backdrop.querySelector('.mos-modal-generic-input')?.select(); } catch(_){}
      }, 220);
    });
  }

  function _aamMostrarError(txt) {
    try { _evalSfx && _evalSfx('error'); } catch(_){}
    try { if (navigator.vibrate) navigator.vibrate([60, 50, 60]); } catch(_){}
    const msg = document.getElementById('aamMessage');
    if (msg) {
      msg.className = 'aam-message error';
      msg.textContent = '⚠ ' + txt;
    }
    document.querySelectorAll('#aamDots .aam-dot').forEach(dot => dot.classList.add('error'));
    const box = document.querySelector('#modalAdminAuth .aam-box');
    if (box) {
      box.classList.add('shake');
      setTimeout(() => box.classList.remove('shake'), 420);
    }
    setTimeout(() => {
      if (_aamState) {
        _aamState.value = '';
        _aamRenderDots();
        _aamState.t0 = Date.now(); // reset timer
      }
    }, 600);
  }
  function _aamCancelar() {
    if (!_aamState) return;
    const resolveFn = _aamState.resolve;
    closeModal('modalAdminAuth');
    document.removeEventListener('keydown', _aamEscHandler, true);
    _aamState = null;
    try { _evalSfx && _evalSfx('tap'); } catch(_){}
    resolveFn(null);
  }
  function _aamUsarCache() { /* placeholder — el cache se aplica antes del modal */ }

  function openEcoModal(app) {
    const eco = S._ecoData;
    const titleEl = $('ecoModalTitle');
    const bodyEl  = $('ecoModalBody');
    if (!titleEl || !bodyEl) return;

    // Si aún no llegaron datos (primera carga), esperar y reintentar
    if (!eco) {
      titleEl.textContent = app === 'wh' ? 'warehouseMos' : 'MosExpress';
      bodyEl.innerHTML = `<div class="flex items-center gap-3 py-4 text-slate-400 text-sm">
        <span class="dot-loading" style="width:10px;height:10px"></span>Cargando datos...</div>`;
      openModal('modalEcosistema');
      // Reintentar en 2s por si la llamada GAS aún está en vuelo
      setTimeout(() => {
        if (S._ecoData && $('modalEcosistema')?.classList.contains('open')) {
          closeModal('modalEcosistema');
          openEcoModal(app);
        }
      }, 2000);
      return;
    }

    const _fmt = n => new Intl.NumberFormat('es-PE', { minimumFractionDigits: 2 }).format(n || 0);
    const _dot = c => `<span class="inline-block w-2.5 h-2.5 rounded-full ${c === 'green' ? 'bg-green-400' : c === 'yellow' ? 'bg-yellow-400' : c === 'red' ? 'bg-red-400' : 'bg-slate-500'}"></span>`;

    // Paleta de colores para zonas (se repite si hay muchas)
    const ZONA_PALETA = [
      { bg: 'bg-indigo-900/60',  border: 'border-indigo-500/40',  badge: 'bg-indigo-500/20 text-indigo-300',  dot: 'bg-indigo-400' },
      { bg: 'bg-emerald-900/50', border: 'border-emerald-500/40', badge: 'bg-emerald-500/20 text-emerald-300', dot: 'bg-emerald-400' },
      { bg: 'bg-amber-900/40',   border: 'border-amber-500/40',   badge: 'bg-amber-500/20 text-amber-300',    dot: 'bg-amber-400'  },
      { bg: 'bg-rose-900/40',    border: 'border-rose-500/40',    badge: 'bg-rose-500/20 text-rose-300',      dot: 'bg-rose-400'   },
      { bg: 'bg-cyan-900/40',    border: 'border-cyan-500/40',    badge: 'bg-cyan-500/20 text-cyan-300',      dot: 'bg-cyan-400'   },
    ];

    if (app === 'me') {
      const d = eco.me;
      titleEl.innerHTML = `🛒 MosExpress &nbsp;${_dot(d?.color)}`;
      if (!d || d.error) {
        bodyEl.innerHTML = `<p class="text-red-400 text-sm">${d?.error || 'Sin datos'}</p>`;
      } else {
        // ── KPIs globales ──
        let html = `
          <div class="grid grid-cols-2 gap-3 mb-5">
            <div class="bg-slate-800 rounded-xl p-3">
              <div class="text-2xl font-bold text-white">${d.ventasHoy}</div>
              <div class="text-xs text-slate-400 mt-0.5">Ventas hoy</div>
            </div>
            <div class="bg-slate-800 rounded-xl p-3">
              <div class="text-2xl font-bold text-white">S/ ${_fmt(d.totalHoy)}</div>
              <div class="text-xs text-slate-400 mt-0.5">Total hoy · ${d.ultimaVenta}</div>
            </div>
          </div>`;

        // ── Zonas ──
        const zonas = d.zonas || [];
        if (zonas.length) {
          html += `<div class="text-xs text-slate-400 uppercase tracking-widest font-semibold mb-2">Por zona</div>
          <div class="space-y-2 mb-5">`;
          zonas.forEach((z, idx) => {
            const pal = ZONA_PALETA[idx % ZONA_PALETA.length];
            html += `
            <div class="rounded-xl border ${pal.bg} ${pal.border} p-3">
              <div class="flex items-center justify-between mb-2">
                <div class="flex items-center gap-2">
                  <span class="w-2 h-2 rounded-full ${pal.dot} inline-block"></span>
                  <span class="text-sm font-semibold text-slate-100">${z.zona}</span>
                </div>
                <span class="text-xs px-2 py-0.5 rounded-full ${pal.badge}">${z.ventas} venta${z.ventas !== 1 ? 's' : ''}</span>
              </div>
              <div class="flex items-center justify-between">
                <span class="text-lg font-bold text-white">S/ ${_fmt(z.total)}</span>
                <span class="text-xs text-slate-400">${z.ultimaVenta}</span>
              </div>
            </div>`;
          });
          html += `</div>`;
        }

        // ── Personal del día ──
        const personal = d.personal || [];
        const activos  = personal.filter(p => p.estado === 'activo');
        const cerrados = personal.filter(p => p.estado === 'cerrado');

        html += `<div class="text-xs text-slate-400 uppercase tracking-widest font-semibold mb-2">
          Personal hoy <span class="ml-1 text-slate-500 normal-case">(${personal.length} turno${personal.length !== 1 ? 's' : ''})</span>
        </div>`;

        if (!personal.length) {
          html += `<p class="text-xs text-slate-500 py-2">Sin registros hoy</p>`;
        } else {
          html += `<div class="space-y-1.5">`;
          // Activos primero
          personal.forEach(p => {
            const zonaPal = ZONA_PALETA[zonas.findIndex(z => z.zona === p.zona) % ZONA_PALETA.length] || ZONA_PALETA[0];
            const esActivo = p.estado === 'activo';
            html += `
            <div class="flex items-center gap-2.5 rounded-lg px-3 py-2 ${esActivo ? 'bg-slate-700/60' : 'bg-slate-800/40'}">
              <span class="inline-block w-2 h-2 rounded-full flex-shrink-0 ${esActivo ? 'bg-green-400' : 'bg-slate-500'}"></span>
              <div class="flex-1 min-w-0">
                <div class="text-sm text-slate-100 font-medium truncate">${p.nombre}</div>
                <div class="text-xs text-slate-400">${p.estacion}${p.zona && p.zona !== '—' ? ' · <span class="' + zonaPal.badge.split(' ')[1] + '">' + p.zona + '</span>' : ''}</div>
              </div>
              <div class="text-right flex-shrink-0">
                ${esActivo
                  ? `<span class="text-xs text-green-400 font-medium">Activo</span><div class="text-xs text-slate-500">desde ${p.desde}</div>`
                  : `<span class="text-xs text-slate-500">Cerró ${p.hasta || '—'}</span><div class="text-xs text-slate-600">abrió ${p.desde}</div>`
                }
              </div>
            </div>`;
          });
          html += `</div>`;
        }

        bodyEl.innerHTML = html;
      }
    } else {
      const d = eco.wh;
      titleEl.innerHTML = `🏭 warehouseMos &nbsp;${_dot(d?.color)}`;
      if (!d || d.error) {
        bodyEl.innerHTML = `<p class="text-red-400 text-sm">${d?.error || 'Sin datos'}</p>`;
      } else {
        const sesion = d.sesionActiva
          ? `<span class="text-green-300">${d.sesionActiva.usuario} (${d.sesionActiva.rol}) · desde ${d.sesionActiva.desde}</span>`
          : '<span class="text-slate-500">Ninguna activa</span>';
        bodyEl.innerHTML = `
          <div class="grid grid-cols-3 gap-3 mb-4">
            <div class="bg-slate-800 rounded-xl p-3">
              <div class="text-2xl font-bold text-white">${d.entradasHoy}</div>
              <div class="text-xs text-slate-400 mt-0.5">Entradas hoy</div>
            </div>
            <div class="bg-slate-800 rounded-xl p-3">
              <div class="text-2xl font-bold text-white">${d.salidasHoy}</div>
              <div class="text-xs text-slate-400 mt-0.5">Salidas hoy</div>
            </div>
            <div class="bg-slate-800 rounded-xl p-3">
              <div class="text-2xl font-bold ${d.stockCritico > 0 ? 'text-red-400' : 'text-white'}">${d.stockCritico}</div>
              <div class="text-xs text-slate-400 mt-0.5">Stock crítico</div>
            </div>
          </div>
          <div class="mb-1 text-xs text-slate-400 uppercase tracking-widest font-semibold">Última guía</div>
          <p class="text-sm text-slate-200 mb-4">${d.ultimaGuia || '—'}</p>
          <div class="mb-1 text-xs text-slate-400 uppercase tracking-widest font-semibold">Sesión activa</div>
          <p class="text-sm mb-0">${sesion}</p>`;
      }
    }
    openModal('modalEcosistema');
  }

  function openConfig() {
    const inp = $('cfgGasUrl');
    if (inp) inp.value = API.getUrl();
    const tr = $('cfgTestResult');
    if (tr) { tr.classList.add('hidden'); tr.textContent = ''; }
    openModal('modalConfig');
  }

  function saveConfig() {
    const url = ($('cfgGasUrl')?.value || '').trim();
    API.setUrl(url);
    closeModal('modalConfig');
    setStatus(!!url);
    if (url) {
      toast('URL guardada. Actualizando datos...', 'ok');
      S.loaded = {};
      loadView(S.view);
    } else {
      const b = $('bannerNoUrl'); if (b) b.classList.remove('hidden');
    }
  }

  async function testConnection() {
    const url = ($('cfgGasUrl')?.value || '').trim();
    if (!url) { toast('Ingresa la URL primero', 'error'); return; }
    API.setUrl(url);
    const tr = $('cfgTestResult');
    if (tr) { tr.classList.remove('hidden'); tr.style.background = '#0f172a'; tr.textContent = 'Probando...'; }
    try {
      const d = await API.get('getConfig', {});
      if (tr) {
        tr.style.background = '#052e16'; tr.style.border = '1px solid #14532d'; tr.style.color = '#86efac';
        tr.textContent = '✓ Conexión exitosa — ' + (d?.EMPRESA_NOMBRE || 'MOS');
      }
    } catch (e) {
      if (tr) {
        tr.style.background = '#450a0a'; tr.style.border = '1px solid #7f1d1d'; tr.style.color = '#fca5a5';
        tr.textContent = '✗ Error: ' + e.message;
      }
    }
  }

  // ── Product modal — helpers ────────────────────────────────
  let _prodTipo = 'normal';

  function setProdTipo(tipo) {
    // tipo: 'normal' | 'envasable' | 'derivado' | 'presentacion'
    _prodTipo = tipo;
    // Sincronizar checkboxes
    const cbPres = $('cbEsPresentacion');
    const cbDer  = $('cbEsDerivado');
    const cbEnv  = $('cbEsEnvasable');
    if (cbPres) cbPres.checked = (tipo === 'presentacion');
    if (cbDer)  cbDer.checked  = (tipo === 'derivado');
    if (cbEnv)  cbEnv.checked  = (tipo === 'envasable');
    // Mostrar / ocultar secciones
    $('prodSecDerivado')?.classList.toggle('hidden', tipo !== 'derivado');
    $('prodSecPresentacion')?.classList.toggle('hidden', tipo !== 'presentacion');
    if (tipo === 'derivado')     _poblarEnvasablesSelect();
    if (tipo === 'presentacion') _poblarBasesSelect();
  }

  // Handler de los checkboxes mutex (presentación/derivado)
  function onTipoCheck(tipo, checked) {
    if (!checked) { setProdTipo('normal'); return; }
    // Mutex: si marca presentacion, desmarca derivado y viceversa
    setProdTipo(tipo);
  }
  // Handler del checkbox independiente "es envasable"
  function onEnvasableCheck(checked) {
    // envasable es independiente de presentacion/derivado
    if (checked) {
      // Si tenía presentación o derivado activo, lo desmarca (envasable es base)
      const cbPres = $('cbEsPresentacion');
      const cbDer  = $('cbEsDerivado');
      if (cbPres) cbPres.checked = false;
      if (cbDer)  cbDer.checked  = false;
      _prodTipo = 'envasable';
      $('prodSecDerivado')?.classList.add('hidden');
      $('prodSecPresentacion')?.classList.add('hidden');
    } else {
      _prodTipo = 'normal';
    }
  }

  function _esEnvasable(p) {
    const v = p.esEnvasable;
    return v === 1 || v === '1' || v === true || v === 'true' || v === 'Sí';
  }

  // Normaliza unidades legacy a códigos SUNAT (consistencia con prodUnidadMedida)
  // Aceptamos códigos SUNAT directos: NIU, KGM, LTR, BG, BX, PR, PK, ZZ
  // Mapeamos legacy: UNIDAD→NIU, KG→KGM, LITRO→LTR, BOLSA/SOBRE/SACO→BG, CAJA→BX
  const _UNIDAD_LEGACY_MAP = {
    'UNIDAD': 'NIU', 'UND': 'NIU', 'U': 'NIU', '': 'NIU',
    'KG': 'KGM', 'KILO': 'KGM', 'KILOGRAMO': 'KGM',
    'LITRO': 'LTR', 'LT': 'LTR', 'L': 'LTR',
    'BOLSA': 'BG', 'SOBRE': 'BG', 'SACO': 'BG',
    'CAJA': 'BX',
    'PAR': 'PR',
    'PAQUETE': 'PK', 'PACK': 'PK',
    'SERVICIO': 'ZZ'
  };
  function _normalizarUnidad(u) {
    if (!u) return 'NIU';
    const up = String(u).trim().toUpperCase();
    return _UNIDAD_LEGACY_MAP[up] || up;  // si ya es SUNAT, lo deja igual
  }
  // Display de unidad con ícono — ⚖️ para KGM (granel), × para el resto
  function _unidadDisplay(u) {
    const norm = _normalizarUnidad(u);
    return norm === 'KGM' ? `⚖️ ${norm}` : `× ${norm}`;
  }

  // Producto activo si estado NO es explícitamente 0/'0'/false.
  // Importante: Sheets convierte '0' en número 0; el check viejo usaba !p.estado,
  // que con estado=0 (número) daba true incorrectamente — producto se veía activo.
  function _isProdActivo(p) {
    if (!p) return false;
    const e = p.estado;
    if (e === 0 || e === '0' || e === false) return false;
    if (typeof e === 'string' && e.toLowerCase() === 'false') return false;
    return true;
  }

  function _poblarEnvasablesSelect() {
    const sel = $('prodCodigoProductoBase');
    if (!sel) return;
    const cur = sel.value;
    const items = S.productos.filter(p => _esEnvasable(p));
    if (!items.length) {
      sel.innerHTML = '<option value="">— sin productos envasables registrados —</option>';
      toast('No hay productos marcados como Envasable aún', 'error');
      return;
    }
    sel.innerHTML = '<option value="">— seleccionar envasable —</option>'
      + items.map(p => { const val = p.skuBase || p.idProducto; return `<option value="${val}"${cur===val?' selected':''}>${p.descripcion||p.idProducto}</option>`; }).join('');
    if (cur) sel.value = cur;
    sel.onchange = () => _heredarTributariosDeBase(sel.value);
  }

  function _poblarBasesSelect() {
    const sel = $('prodSkuBase');
    if (!sel) return;
    const cur = sel.value;
    const bases = S.productos.filter(p => !p.skuBase || p.skuBase === p.idProducto);
    sel.innerHTML = '<option value="">— seleccionar producto base —</option>'
      + bases.map(p => `<option value="${p.idProducto}"${cur===p.idProducto?' selected':''}>${p.descripcion||p.idProducto}</option>`).join('');
    if (cur) sel.value = cur;
    sel.onchange = () => _heredarTributariosDeBase(sel.value);
  }

  // Hereda Tipo_IGV, IGV%, Cod_Tributo, Cod_SUNAT, Unidad_Medida del producto padre seleccionado
  // (presentación o derivado). Editable después si se requiere.
  function _heredarTributariosDeBase(idBase) {
    if (!idBase) return;
    const padre = (S.productos || []).find(p =>
      p.idProducto === idBase || p.skuBase === idBase
    );
    if (!padre) return;
    // Migrar legacy gravado/exonerado/inafecto → 1/2/3
    const tipoLegacy = { 'gravado': '1', 'exonerado': '2', 'inafecto': '3' };
    const tipoVal = tipoLegacy[String(padre.Tipo_IGV || '').toLowerCase()] || (padre.Tipo_IGV ? String(padre.Tipo_IGV) : '1');
    if ($('prodTipoIGV'))     $('prodTipoIGV').value     = tipoVal;
    if ($('prodCodTributo'))  $('prodCodTributo').value  = padre.Cod_Tributo || (tipoVal === '1' ? '1000' : tipoVal === '2' ? '9997' : '9998');
    if ($('prodIGV'))         $('prodIGV').value         = (padre.IGV_Porcentaje !== undefined && padre.IGV_Porcentaje !== '') ? padre.IGV_Porcentaje : (tipoVal === '1' ? 18 : 0);
    if ($('prodCodSUNAT'))    $('prodCodSUNAT').value    = padre.Cod_SUNAT || '10000000';
    if ($('prodUnidadMedida')) $('prodUnidadMedida').value = padre.Unidad_Medida || 'NIU';
    // Solo herendar idCategoria si no se ha llenado
    if ($('prodCategoria') && !$('prodCategoria').value && padre.idCategoria) {
      $('prodCategoria').value = padre.idCategoria;
    }
    if ($('prodMarca') && !$('prodMarca').value && padre.marca) {
      $('prodMarca').value = padre.marca;
    }
    _actualizarResumenSunat();
    toast('🧬 Datos tributarios heredados de "' + (padre.descripcion || padre.idProducto) + '" — editables si requiere', 'info');
  }

  // Si silencioso=true: solo regenera (uso interno, ej. al guardar con campo vacío).
  // Si silencioso=false (click del botón): confirma antes de sobrescribir si hay contenido.
  async function prodAutogenBarcode(silencioso) {
    const cb = $('prodCodigoBarra');
    if (!cb) return;
    const actual = String(cb.value || '').trim();
    if (!silencioso && actual) {
      if (!await _modalConfirm(`El código actual "${actual}" será reemplazado por uno automático.\n\n¿Continuar?`, { warning: true, titulo: 'Autogenerar código' })) {
        return;
      }
    }
    const ts   = Date.now().toString().slice(-6);
    const rand = Math.floor(Math.random() * 900 + 100);
    cb.value = 'NMLEV' + ts + rand;
    prodValidarCodigoBarra();
  }

  function prodValidarCodigoBarra() {
    const inp = $('prodCodigoBarra');
    const fb  = $('prodCodigoBarraFeedback');
    if (!inp || !fb) return true;
    const val   = inp.value.trim();
    const curId = $('prodId')?.value || '';
    if (!val) {
      fb.className = 'hidden text-xs mt-1';
      inp.classList.remove('!border-red-500');
      return true;
    }
    const dup = (S.productos || []).find(p =>
      p.codigoBarra && p.codigoBarra === val && String(p.idProducto) !== curId
    );
    if (dup) {
      fb.textContent = `⚠ Ya existe en: ${dup.descripcion} (${dup.idProducto})`;
      fb.className   = 'text-xs mt-1 text-red-400';
      inp.classList.add('!border-red-500');
      return false;
    }
    fb.textContent = '✓ Disponible';
    fb.className   = 'text-xs mt-1 text-green-400';
    inp.classList.remove('!border-red-500');
    return true;
  }

  function prodToggleEstado() {
    const hidden = $('prodEstado');
    const btn    = $('prodEstadoToggle');
    if (!hidden || !btn) return;
    const activo = hidden.value !== '1';
    hidden.value = activo ? '1' : '0';
    btn.classList.toggle('on', activo);
    btn.querySelector('.prod-toggle-lbl').textContent = activo ? 'Activo' : 'Inactivo';
  }

  function prodToggleCosto() {
    const row = $('prodCostoRow');
    const ch  = $('costoChevron');
    if (!row) return;
    const wasHidden = row.classList.toggle('hidden');
    if (ch) ch.textContent = wasHidden ? '▶' : '▼';
  }

  function prodCalcMargen() {
    const v    = parseFloat($('prodPrecioVenta')?.value)  || 0;
    const c    = parseFloat($('prodPrecioCosto')?.value)  || 0;
    const bar  = $('prodMargenBar');
    const lbl  = $('prodMargenLabel');
    const fill = $('prodMargenFill');
    if (!bar) return;
    if (v > 0 && c > 0 && v >= c) {
      const m = (v - c) / v * 100;
      bar.classList.remove('hidden');
      if (lbl)  lbl.textContent  = m.toFixed(1) + '%';
      if (fill) { fill.style.width = Math.min(m, 100) + '%'; fill.style.background = m > 30 ? '#22c55e' : m > 15 ? '#f59e0b' : '#ef4444'; }
    } else {
      bar.classList.add('hidden');
    }
  }

  function prodOnRange() {
    const minEl = $('prodStockMinRange');
    const maxEl = $('prodStockMaxRange');
    if (!minEl || !maxEl) return;
    let min = parseInt(minEl.value), max = parseInt(maxEl.value);
    if (min > max) { if (document.activeElement === minEl) { minEl.value = max; min = max; } else { maxEl.value = min; max = min; } }
    if ($('prodStockMin')) $('prodStockMin').value = min;
    if ($('prodStockMax')) $('prodStockMax').value = max;
    if ($('stockMinLabel')) $('stockMinLabel').textContent = min;
    if ($('stockMaxLabel')) $('stockMaxLabel').textContent = max;
    const rMax = parseInt(minEl.max) || 500;
    const fill = $('prodRangeFill');
    if (fill) { fill.style.left = (min/rMax*100)+'%'; fill.style.width = ((max-min)/rMax*100)+'%'; }
  }

  function _setStockSlider(min, max) {
    const minEl = $('prodStockMinRange');
    const maxEl = $('prodStockMaxRange');
    if (minEl) minEl.value = min;
    if (maxEl) maxEl.value = max;
    if ($('prodStockMin')) $('prodStockMin').value = min;
    if ($('prodStockMax')) $('prodStockMax').value = max;
    if ($('stockMinLabel')) $('stockMinLabel').textContent = min;
    if ($('stockMaxLabel')) $('stockMaxLabel').textContent = max;
    const rMax = minEl ? parseInt(minEl.max) : 500;
    const fill = $('prodRangeFill');
    if (fill) { fill.style.left = (min/rMax*100)+'%'; fill.style.width = ((max-min)/rMax*100)+'%'; }
  }

  function prodToggleSunat() {
    const sec = $('prodSecSunat');
    const ch  = $('sunatChevron');
    if (!sec) return;
    const h = sec.classList.toggle('hidden');
    if (ch) ch.textContent = h ? '⚙️ ajustar' : '▴ ocultar';
  }

  // Cuando cambia Tipo IGV: autorrellenar los campos relacionados (Cod_Tributo, IGV%)
  function prodOnTipoIGVChange() {
    const tipo = $('prodTipoIGV')?.value || '1';
    if (tipo === '1') {
      $('prodCodTributo').value = '1000';
      $('prodIGV').value = '18';
    } else if (tipo === '2') {
      $('prodCodTributo').value = '9997';
      $('prodIGV').value = '0';
    } else if (tipo === '3') {
      $('prodCodTributo').value = '9998';
      $('prodIGV').value = '0';
    }
    _actualizarResumenSunat();
  }
  function _actualizarResumenSunat() {
    const tipo = $('prodTipoIGV')?.value;
    const igv = $('prodIGV')?.value || '0';
    const r = $('sunatResumen'); if (!r) return;
    let txt = '—';
    if (tipo === '1') txt = 'Gravado ' + igv + '%';
    else if (tipo === '2') txt = 'Exonerado';
    else if (tipo === '3') txt = 'Inafecto';
    r.textContent = txt;
    r.className = (tipo === '1') ? 'text-emerald-400 font-normal' : 'text-amber-400 font-normal';
  }

  function prodToggleEquiv() {
    const sec = $('equivContent');
    const ch  = $('equivChevron');
    if (!sec) return;
    const h = sec.classList.toggle('hidden');
    if (ch) ch.textContent = h ? '▶' : '▼';
  }

  // ═══════════════════════════════════════════════════════════════
  // [v2.41.97] PRICING POR SEGMENTOS — Editor de tramos para graneles
  // ═══════════════════════════════════════════════════════════════
  let _segState = {
    idProducto: null,
    skuBase: null,          // [tramos por sku_base] los tramos viven por GRUPO (canónico+presentaciones+equivalentes)
    precioCanonico: 0,
    segmentos: [],
    editandoId: null,    // si null, modal es "nuevo"
    modalUnidad: 'g',    // 'g' | 'kg' para el modal CRUD
    modalMinIncl: true,
    modalMaxIncl: false
  };

  function prodToggleSegmentos() {
    const sec = $('segmentosContent');
    const ch  = $('segChevron');
    if (!sec) return;
    const h = sec.classList.toggle('hidden');
    if (ch) ch.textContent = h ? '▶' : '▼';
  }

  // Mostrar u ocultar la sección de segmentos según unidad del producto.
  // Llamado desde el modal de producto al cargar/cambiar unidad.
  function segActualizarVisibilidad() {
    const unidad = ($('prodUnidad')?.value || '').toUpperCase();
    const factorConv = parseFloat($('prodFactorConversion')?.value || 1);
    const sec = $('modalSegmentosSection');
    if (!sec) return;
    // Solo visible si es KGM y es el canónico (factor=1)
    if (unidad === 'KGM' && factorConv === 1) {
      sec.classList.remove('hidden');
    } else {
      sec.classList.add('hidden');
    }
  }

  // Cargar segmentos del producto activo en el modal
  function segCargarParaProducto(producto) {
    if (!producto) return;
    _segState.idProducto = producto.idProducto;
    _segState.skuBase = producto.skuBase || producto.sku_base || null;
    _segState.precioCanonico = parseFloat(producto.precioVenta) || 0;
    let segs = [];
    try {
      const raw = producto.segmentos_precio || producto.segmentosPrecio || '';
      if (raw && typeof raw === 'string') segs = JSON.parse(raw);
      else if (Array.isArray(raw)) segs = raw;
    } catch(_) { segs = []; }
    _segState.segmentos = segs;
    segRenderEditor();
  }

  // Render del editor principal (línea visual + cards)
  function segRenderEditor() {
    segRenderLineaVisual();
    segRenderLista();
    segCalcular();
  }

  function _segFmtRango(s) {
    const lo = s.minIncl ? '[' : '(';
    const hi = s.maxIncl ? ']' : ')';
    const maxLbl = s.max === null ? '∞' : (s.max >= 1000 ? (s.max/1000) + 'kg' : s.max + 'g');
    const minLbl = s.min >= 1000 ? (s.min/1000) + 'kg' : s.min + 'g';
    return lo + minLbl + ' — ' + maxLbl + hi;
  }

  function segRenderLineaVisual() {
    const cont = $('segLineaVisual');
    if (!cont) return;
    const pc = _segState.precioCanonico || 0;
    const segs = _segState.segmentos;
    const cmap = _segColorMap(segs);
    // Escala: si todos tienen max definido, usar el max global como 100%; si hay infinito, +20% para él.
    const segConMax = segs.filter(s => s.max !== null);
    const maxFinito = segConMax.length ? Math.max(...segConMax.map(s => s.max)) : 1000;
    const escalaMax = maxFinito * 1.2;

    // ── Banda BASE: el canónico es el "segmento de 0 a ∞" que aplica donde NO hay tramo → se MANTIENE. ──
    const base = `<div class="seg-banda seg-banda-base"
         title="Precio base (canónico) — aplica donde no hay tramo · el precio se mantiene">
        <span class="seg-banda-lbl">⬚ Base · S/ ${pc.toFixed(2)}/kg · 0% (se mantiene)</span>
      </div>`;

    // ── Tramos encima de la base: color por identidad + FLECHA de dirección + precio resultante. ──
    const bandas = segs.map(s => {
      const left  = (s.min / escalaMax) * 100;
      const widthRaw = s.max === null ? (100 - left) : ((s.max - s.min) / escalaMax) * 100;
      const width = Math.max(3, Math.min(widthRaw, 100 - left));
      const aj    = parseFloat(s.ajustePct) || 0;
      const sign  = aj > 0 ? '+' : '';
      const flecha = aj > 0 ? '▲' : (aj < 0 ? '▼' : '=');     // ▲ más caro · ▼ más barato · = igual
      const efecto = aj > 0 ? 'sube' : (aj < 0 ? 'baja' : 'igual');
      const color = cmap[s.id] || '#6366f1';
      const precioAj = pc * (1 + aj / 100);
      const sidEsc = String(s.id).replace(/'/g, '&#39;');
      return `<div class="seg-banda seg-banda-tramo seg-dir-${efecto}" style="left:${left}%; width:${width}%; background:${color}"
                   title="${_escapeHtml(s.nombre || 'tramo')} · ${_escapeHtml(_segFmtRango(s))} · ${flecha} ${sign}${aj}% → S/ ${precioAj.toFixed(2)}/kg · click para editar"
                   onclick="MOS.segEditar('${sidEsc}')">
        <span class="seg-banda-pct">${flecha} ${sign}${aj}%</span>
        <span class="seg-banda-lbl">S/ ${precioAj.toFixed(2)}/kg</span>
      </div>`;
    }).join('');

    cont.innerHTML = base + bandas + `<div class="seg-linea-eje"><span>0g</span><span>${maxFinito/2}g</span><span>${maxFinito}g+</span></div>`;
  }

  function segRenderLista() {
    const cont = $('segListaSegmentos');
    if (!cont) return;
    if (!_segState.segmentos.length) { cont.innerHTML = ''; return; }
    const pc = _segState.precioCanonico;
    const cmap = _segColorMap(_segState.segmentos);
    cont.innerHTML = _segState.segmentos.map(s => {
      const aj = parseFloat(s.ajustePct) || 0;
      const cls = aj > 0 ? 'positivo' : (aj < 0 ? 'negativo' : 'neutro');
      const sign = aj > 0 ? '+' : '';
      const precioAjustado = pc * (1 + aj / 100);
      const dir = aj > 0 ? '▲ más caro' : (aj < 0 ? '▼ más barato' : '= se mantiene');
      return `<div class="seg-card">
        <div class="seg-card-color" style="background:${cmap[s.id] || '#6366f1'}"></div>
        <div class="seg-card-info">
          <div class="seg-card-nombre">${_escapeHtml(s.nombre || 'Sin nombre')}</div>
          <div class="seg-card-rango">${_escapeHtml(_segFmtRango(s))}</div>
          <div class="seg-card-resultado"><span class="seg-card-dir ${cls}">${dir}</span> · S/ ${precioAjustado.toFixed(2)}/kg</div>
        </div>
        <div class="seg-card-pct ${cls}">${sign}${aj}%</div>
        <div class="seg-card-acciones">
          <button onclick="MOS.segEditar('${s.id}')" class="seg-card-btn" title="Editar">✏</button>
          <button onclick="MOS.segEliminar('${s.id}')" class="seg-card-btn danger" title="Eliminar">🗑</button>
        </div>
      </div>`;
    }).join('');
  }

  function segCalcular() {
    const inp = $('segCalcInput');
    const sel = $('segCalcUnidad');
    const res = $('segCalcResultado');
    const sug = $('segCalcSugerencias');
    if (!inp || !res) return;
    const valor = parseFloat(inp.value);
    const unidad = sel?.value || 'g';
    if (!valor || valor <= 0) {
      res.classList.remove('activo');
      res.textContent = 'Ingresa una cantidad para ver el precio';
      sug.innerHTML = '';
      return;
    }
    const gramos = unidad === 'kg' ? valor * 1000 : valor;
    const calc = _segCalcularPrecio(gramos);
    res.classList.add('activo');
    const segTxt = calc.segmento
      ? '🎯 Cae en <strong>' + _escapeHtml(calc.segmento.nombre || 'segmento') + '</strong> (' + (calc.ajustePct > 0 ? '+' : '') + calc.ajustePct + '%)'
      : '⚪ Sin segmento · usa <strong>canónico</strong>';
    res.innerHTML = '💰 <strong>S/ ' + calc.precio.toFixed(2) + '</strong> · ' + segTxt;
    // Sugerencias en otros gramajes
    const sugs = [50, 100, 250, 500, 1000, 2500, 5000].filter(g => g !== gramos);
    sug.innerHTML = sugs.map(g => {
      const c = _segCalcularPrecio(g);
      const lbl = g >= 1000 ? (g/1000) + 'kg' : g + 'g';
      return `<span class="seg-calc-sug-btn" onclick="document.getElementById('segCalcInput').value=${g};document.getElementById('segCalcUnidad').value='g';MOS.segCalcular()">${lbl} → S/${c.precio.toFixed(2)}</span>`;
    }).join('');
  }

  function _segCalcularPrecio(gramos) {
    const pc = _segState.precioCanonico;
    let aplicado = null;
    for (const s of _segState.segmentos) {
      const cumpleMin = s.minIncl ? gramos >= s.min : gramos > s.min;
      if (!cumpleMin) continue;
      const cumpleMax = s.max === null ? true : (s.maxIncl ? gramos <= s.max : gramos < s.max);
      if (cumpleMax) { aplicado = s; break; }
    }
    const ajuste = aplicado ? aplicado.ajustePct : 0;
    const precioKg = pc * (1 + ajuste / 100);
    const precio = Math.round(precioKg * (gramos / 1000) * 100) / 100;
    return { precio, precioKg, ajustePct: ajuste, segmento: aplicado };
  }

  // ── Modal CRUD ──
  function segNuevo() {
    _segState.editandoId = null;
    _segState.modalUnidad = 'g';
    _segState.modalMinIncl = true;
    _segState.modalMaxIncl = false;
    $('segModalTitulo').textContent = '➕ Nuevo segmento';
    $('segInputNombre').value = '';
    $('segInputMin').value = '';
    $('segInputMax').value = '';
    $('segInputAjuste').value = 10;
    segOnSliderAjuste(10);
    segToggleUnidad('g');
    _segActualizarBracketsUI();
    { const be = $('segBtnEliminar'); if (be) be.style.display = 'none'; }   // nuevo → sin eliminar
    openModal('modalSegmento');
    setTimeout(() => $('segInputMin')?.focus(), 100);
  }

  function segEditar(idSeg) {
    const s = _segState.segmentos.find(x => x.id === idSeg);
    if (!s) return;
    _segState.editandoId = idSeg;
    _segState.modalMinIncl = s.minIncl;
    _segState.modalMaxIncl = s.maxIncl;
    // Detectar unidad razonable: si min y max son múltiplos de 1000 grandes, usar kg
    const usarKg = (s.min >= 1000 || (s.max && s.max >= 1000));
    _segState.modalUnidad = usarKg ? 'kg' : 'g';
    $('segModalTitulo').textContent = '✏ Editar segmento';
    $('segInputNombre').value = s.nombre || '';
    $('segInputMin').value = usarKg ? s.min / 1000 : s.min;
    $('segInputMax').value = s.max === null ? '' : (usarKg ? s.max / 1000 : s.max);
    $('segInputAjuste').value = s.ajustePct;
    segOnSliderAjuste(s.ajustePct);
    segToggleUnidad(_segState.modalUnidad);
    _segActualizarBracketsUI();
    { const be = $('segBtnEliminar'); if (be) be.style.display = ''; }   // editar → mostrar eliminar
    openModal('modalSegmento');
  }

  // Eliminar el tramo que se está editando, desde el botón dentro del modal.
  function segEliminarDesdeModal() {
    const id = _segState.editandoId;
    if (!id) return;
    segCerrarModal();        // cerrar el modal del tramo primero
    segEliminar(id);         // confirma + elimina (optimista)
  }

  function segCerrarModal() { closeModal('modalSegmento'); }

  function segToggleUnidad(u) {
    _segState.modalUnidad = u;
    $('segUnidadG').classList.toggle('active', u === 'g');
    $('segUnidadKg').classList.toggle('active', u === 'kg');
    const lbl = u === 'g' ? 'g' : 'kg';
    $('segUnidadMinLbl').textContent = lbl;
    $('segUnidadMaxLbl').textContent = lbl;
    $('segInputMin').step = u === 'g' ? '1' : '0.01';
    $('segInputMax').step = u === 'g' ? '1' : '0.01';
    segValidarLive();
  }

  function segToggleBracket(lado, incl) {
    if (lado === 'min') {
      _segState.modalMinIncl = incl;
    } else {
      _segState.modalMaxIncl = incl;
    }
    _segActualizarBracketsUI();
    segValidarLive();
  }

  function _segActualizarBracketsUI() {
    $('segMinIncl').classList.toggle('active', _segState.modalMinIncl);
    $('segMinExcl').classList.toggle('active', !_segState.modalMinIncl);
    $('segMaxIncl').classList.toggle('active', _segState.modalMaxIncl);
    $('segMaxExcl').classList.toggle('active', !_segState.modalMaxIncl);
    $('segMinHelp').textContent = _segState.modalMinIncl ? 'cerrado · incluye' : 'abierto · no incluye';
    $('segMaxHelp').textContent = _segState.modalMaxIncl ? 'cerrado · incluye' : 'abierto · no incluye';
  }

  function segAtajo(minG, maxG) {
    const u = _segState.modalUnidad;
    $('segInputMin').value = u === 'kg' ? minG/1000 : minG;
    $('segInputMax').value = maxG === null ? '' : (u === 'kg' ? maxG/1000 : maxG);
    // Brackets típicos: min cerrado, max abierto
    _segState.modalMinIncl = true;
    _segState.modalMaxIncl = false;
    _segActualizarBracketsUI();
    segValidarLive();
  }

  function _segPintarPct(n) {
    const color = n > 0 ? '#fbbf24' : (n < 0 ? '#34d399' : '#94a3b8');
    const inp = $('segPctInput'); if (inp) inp.style.color = color;
    const suf = $('segPctDisplay')?.querySelector('.seg-pct-sufijo'); if (suf) suf.style.color = color;
  }
  // Slider movido → sincroniza el input editable (salvo que el user lo esté tipeando) y repinta.
  function segOnSliderAjuste(v) {
    const n = parseFloat(v) || 0;
    const inp = $('segPctInput');
    if (inp && document.activeElement !== inp) inp.value = n;
    _segPintarPct(n);
    segValidarLive();
  }
  // Input editable → acepta decimales (10.5); sincroniza el slider (clamp a su rango) y repinta.
  function segOnPctInput(v) {
    let n = parseFloat(v); if (isNaN(n)) n = 0;
    const sl = $('segInputAjuste');
    if (sl) sl.value = Math.max(-50, Math.min(50, n));
    _segPintarPct(n);
    segValidarLive();
  }

  function _segValoresModalEnGramos() {
    const u = _segState.modalUnidad;
    const minRaw = parseFloat($('segInputMin').value);
    const maxRaw = $('segInputMax').value.trim();
    const min = u === 'kg' ? minRaw * 1000 : minRaw;
    const max = maxRaw === '' ? null : (u === 'kg' ? parseFloat(maxRaw) * 1000 : parseFloat(maxRaw));
    // [%] el valor preciso (con decimales) vive en el input editable; el slider es solo para arrastrar
    const ajuste = parseFloat(($('segPctInput') || {}).value);
    return { min, max, minIncl: _segState.modalMinIncl, maxIncl: _segState.modalMaxIncl, ajustePct: isNaN(ajuste) ? 0 : ajuste };
  }

  function segValidarLive() {
    const v = _segValoresModalEnGramos();
    const msg = $('segValidacionMsg');
    const btn = $('segBtnGuardar');
    const pc = _segState.precioCanonico;

    // Preview
    $('segPreviewCanonico').textContent = 'S/ ' + pc.toFixed(2) + ' / kg';
    const ajustado = pc * (1 + (v.ajustePct || 0) / 100);
    $('segPreviewAjustado').textContent = 'S/ ' + ajustado.toFixed(2) + ' / kg';

    // [v2.41.98] Ejemplos auto-calculados según los breakpoints actuales:
    //   - El min y max del segmento que se está editando (frontera)
    //   - 1g antes y después de cada borde (transición)
    //   - 1 punto central del rango (medio típico)
    //   - Los breakpoints de OTROS segmentos del producto (para ver el efecto cruzado)
    let puntos = new Set();
    // bordes propios
    if (!isNaN(v.min)) {
      puntos.add(Math.max(0, v.min));
      if (v.min > 0) puntos.add(v.min - 1);
      puntos.add(v.min + 1);
    }
    if (v.max !== null && !isNaN(v.max)) {
      if (v.max > 0) puntos.add(v.max - 1);
      puntos.add(v.max);
      puntos.add(v.max + 1);
    }
    // centro del rango si es finito
    if (v.max !== null && !isNaN(v.min) && !isNaN(v.max)) {
      puntos.add(Math.round((v.min + v.max) / 2));
    } else if (v.max === null && !isNaN(v.min)) {
      puntos.add(v.min * 2 || 500); // un valor "típico" más allá del min abierto
    }
    // breakpoints de otros segmentos
    _segState.segmentos.filter(s => s.id !== _segState.editandoId).forEach(s => {
      puntos.add(s.min);
      if (s.max !== null) puntos.add(s.max);
    });
    // ordenar ascendente, descartar negativos y duplicados
    const puntosArr = Array.from(puntos)
      .filter(p => p >= 0 && p <= 100000)
      .sort((a, b) => a - b)
      .slice(0, 8); // top 8 ejemplos
    let ejemplos = '';
    puntosArr.forEach(g => {
      const enRango = (v.minIncl ? g >= v.min : g > v.min) &&
                      (v.max === null ? true : (v.maxIncl ? g <= v.max : g < v.max));
      const lbl = g >= 1000 ? (g/1000) + 'kg' : g + 'g';
      const precio = enRango
        ? (ajustado * (g/1000)).toFixed(2)
        : (pc * (g/1000)).toFixed(2);
      const tag = enRango ? '🎯' : '⚪';
      const cls = enRango ? 'seg-preview-ej-row enRango' : 'seg-preview-ej-row';
      ejemplos += `<div class="${cls}"><span>${tag} ${lbl}</span><span>S/ ${precio}</span></div>`;
    });
    $('segPreviewEjemplos').innerHTML = ejemplos;

    // Validar
    let err = null;
    if (isNaN(v.min) || v.min < 0) err = 'Indica el mínimo';
    else if (v.max !== null && (isNaN(v.max) || v.max <= v.min)) err = 'El máximo debe ser mayor que el mínimo';
    else if (isNaN(v.ajustePct)) err = 'Indica el ajuste';
    else if (v.ajustePct === 0) err = 'El ajuste no puede ser 0% (sin sentido)';
    else if (v.ajustePct < -50 || v.ajustePct > 50) err = 'Ajuste fuera de rango (-50% a +50%)';
    else {
      // Check solapamiento con otros segmentos (excluyendo el que se está editando)
      const otros = _segState.segmentos.filter(s => s.id !== _segState.editandoId);
      const conflicto = otros.find(s => _segDosSegmentosSolapan(v, s));
      if (conflicto) err = 'Solapa con "' + (conflicto.nombre || 'otro segmento') + '"';
    }

    if (err) {
      msg.className = 'seg-validacion err';
      msg.textContent = '⚠ ' + err;
      if (btn) btn.disabled = true;
    } else {
      msg.className = 'seg-validacion ok';
      msg.textContent = '✓ Listo para guardar';
      if (btn) btn.disabled = false;
    }
  }

  function _segDosSegmentosSolapan(a, b) {
    const aMax = a.max === null ? Infinity : a.max;
    const bMax = b.max === null ? Infinity : b.max;
    if (aMax < b.min) return false;
    if (aMax === b.min) { if (!a.maxIncl || !b.minIncl) return false; }
    if (bMax < a.min) return false;
    if (bMax === a.min) { if (!b.maxIncl || !a.minIncl) return false; }
    return true;
  }

  async function segGuardar() {
    const v = _segValoresModalEnGramos();
    const nombre = $('segInputNombre').value.trim();
    const id = _segState.editandoId || ('seg-' + Date.now());
    const nuevo = {
      id,
      nombre,
      min: Math.round(v.min),
      max: v.max === null ? null : Math.round(v.max),
      minIncl: v.minIncl,
      maxIncl: v.maxIncl,
      ajustePct: v.ajustePct,           // [%] acepta decimales (10.5, etc.) — parseFloat
      creadoEn: new Date().toISOString()
    };
    const prev = _segState.segmentos.slice();   // snapshot para rollback optimista
    if (_segState.editandoId) {
      const idx = _segState.segmentos.findIndex(s => s.id === id);
      if (idx >= 0) _segState.segmentos[idx] = nuevo;
    } else {
      _segState.segmentos.push(nuevo);
    }
    segCerrarModal();
    segRenderEditor();
    _segReflejarEnCatalogo();      // [optimista] card + cache local YA, sin esperar la API
    _finBeep && _finBeep('success');
    const ok = await segPersistirSiCambio();   // persiste en background
    if (ok) toast('💾 Tramo guardado', 'success');
    else { _segState.segmentos = prev; segRenderEditor(); _segReflejarEnCatalogo(); }   // rollback
  }

  async function segEliminar(idSeg) {
    if (!await _modalConfirm('¿Eliminar este segmento?', { danger: true, titulo: 'Eliminar segmento', okText: 'Eliminar' })) return;
    const prev = _segState.segmentos.slice();
    _segState.segmentos = _segState.segmentos.filter(s => s.id !== idSeg);
    segRenderEditor();
    _segReflejarEnCatalogo();      // [optimista] YA
    _finBeep && _finBeep('tap');
    const ok = await segPersistirSiCambio();   // persiste en background
    if (ok) toast('🗑 Tramo eliminado', 'info');
    else { _segState.segmentos = prev; segRenderEditor(); _segReflejarEnCatalogo(); }   // rollback
  }

  // [optimista] Refleja los tramos actuales en el catálogo local (S.productos) + repinta la card
  // si se editó desde ahí. Se llama ANTES de esperar la API → el cambio se ve al instante.
  function _segReflejarEnCatalogo() {
    try {
      const p0 = S.productos.find(x => x.idProducto === _segState.idProducto);
      const sku = _segState.skuBase || p0?.skuBase || p0?.sku_base || null;
      const json = JSON.stringify(_segState.segmentos);
      S.productos.forEach(x => {
        if (sku && (x.skuBase === sku || x.sku_base === sku)) x.segmentos_precio = json;
        else if (!sku && x.idProducto === _segState.idProducto) x.segmentos_precio = json;
      });
      if (_segState._desdeCard) renderCatalogo();
    } catch(_) {}
  }

  // Helper: persistir segmentos al guardar producto. Llamado desde el flujo
  // de guardar producto del modal (después del save normal).
  async function segPersistirSiCambio() {
    if (!_segState.idProducto) return false;
    try {
      const audit = (typeof _auditCtx === 'function') ? _auditCtx() : {};
      const res = await API.post('actualizarSegmentosPrecio', {
        _source: 'MOS_SEGMENTOS_PRECIO',
        _audit: audit,
        skuBase: _segState.skuBase,        // [tramos por sku_base] el grupo entero, no la fila
        idProducto: _segState.idProducto,  // compat: la RPC resuelve el sku_base si no vino skuBase
        segmentos: _segState.segmentos
      });
      if (res?.ok) {
        // Reflejar en TODO el grupo (canónico + presentaciones comparten sku_base) → se ve al instante,
        // sin esperar el re-pull del catálogo.
        const p0 = S.productos.find(x => x.idProducto === _segState.idProducto);
        const sku = _segState.skuBase || p0?.skuBase || p0?.sku_base || null;
        const json = JSON.stringify(_segState.segmentos);
        S.productos.forEach(x => {
          if (sku && (x.skuBase === sku || x.sku_base === sku)) x.segmentos_precio = json;
          else if (!sku && x.idProducto === _segState.idProducto) x.segmentos_precio = json;
        });
        // (el repintado de la card ya se hizo optimista en _segReflejarEnCatalogo, antes de la API)
        return true;
      } else {
        toast('⚠ Segmentos no guardados: ' + (res?.error || 'error'), 'warn');
        return false;
      }
    } catch(e) {
      toast('Error guardando segmentos: ' + (e.message || e), 'error');
      return false;
    }
  }

  // ── LOG de cambios de productos (master) ──────────────────
  // Estado del log (UI compacta)
  let _logProdState = {
    fecha: null,             // 'YYYY-MM-DD' (local) o '' = sin filtro de fecha
    sinFiltroFecha: false,   // true cuando user clickea "ver todo"
    filtroBuscar: '',
    filtroUsuario: '',
    filtroAccion: '',
    diasConActividad: new Set(),
    calMes: null,
  };

  // Convierte un timestamp ISO a 'YYYY-MM-DD' en HORA LOCAL del browser.
  // Crítico: comparar contra today() que también es local. Sin esto, los
  // cambios hechos al final del día PE caen en UTC del día siguiente y
  // desaparecen del filtro "hoy".
  function _logFechaLocal(ts) {
    if (!ts) return '';
    const d = new Date(ts);
    if (isNaN(d.getTime())) return '';
    return d.getFullYear() + '-' +
           String(d.getMonth() + 1).padStart(2, '0') + '-' +
           String(d.getDate()).padStart(2, '0');
  }

  async function abrirLogProductos() {
    openModal('modalLogProductos');
    // Inicializar fecha = hoy si no hay
    if (!_logProdState.fecha) {
      _logProdState.fecha = today();
    }
    _logProdActualizarFechaUI();
    await refreshLogProductos();
    // Atajos teclado ←/→
    if (!_logProdState._kbd) {
      _logProdState._kbd = e => {
        const modal = document.getElementById('modalLogProductos');
        if (!modal || modal.classList.contains('hidden')) return;
        // Si está enfocado un input/select, no interceptar
        const tag = (document.activeElement?.tagName || '').toLowerCase();
        if (tag === 'input' || tag === 'select' || tag === 'textarea') return;
        if (e.key === 'ArrowLeft')  { e.preventDefault(); _logProdFechaOffset(-1); }
        if (e.key === 'ArrowRight') { e.preventDefault(); _logProdFechaOffset(+1); }
      };
      document.addEventListener('keydown', _logProdState._kbd);
    }
  }

  function _logProdActualizarFechaUI() {
    const lbl = $('logFechaLabel');
    if (lbl) {
      if (_logProdState.sinFiltroFecha) {
        lbl.textContent = 'Todos';
      } else {
        const f = _logProdState.fecha;
        const hoy = today();
        const d = new Date(f + 'T00:00:00');
        const txt = d.toLocaleDateString('es-PE', { day:'2-digit', month:'short' });
        lbl.textContent = (f === hoy) ? `Hoy · ${txt}` : txt;
      }
    }
    // Marcar iconos activos según filtros
    const ic = (id, on) => {
      const b = $(id); if (!b) return;
      b.classList.toggle('active', !!on);
      const dot = b.querySelector('.log-icon-dot');
      if (dot) dot.classList.toggle('hidden', !on);
    };
    ic('logIconUsuario', !!_logProdState.filtroUsuario);
    ic('logIconAccion',  !!_logProdState.filtroAccion);
    ic('logIconBuscar',  !!_logProdState.filtroBuscar);
    // Mostrar botón limpiar si hay algún filtro
    const limpiar = $('logBtnLimpiar');
    const hay = !!(_logProdState.filtroBuscar || _logProdState.filtroUsuario || _logProdState.filtroAccion || _logProdState.sinFiltroFecha);
    if (limpiar) limpiar.classList.toggle('hidden', !hay);
  }

  async function refreshLogProductos(force) {
    const cont = $('logProductosList');
    if (!cont) return;
    // Render INMEDIATO desde cache si existe (TTL 60s)
    const cache = S._logProdCache;
    if (!force && cache && Array.isArray(cache.data) && (Date.now() - cache.ts) < 60 * 1000) {
      _logProdConstruirIndices(cache.data);
      _logProdFiltrar();
    } else {
      cont.innerHTML = '<div class="text-center py-6 text-slate-500 text-sm">Cargando log...</div>';
    }
    try {
      const data = await API.get('getProductosEditadosRecientes', { limit: 200 });
      S._logProdCache = { ts: Date.now(), data };
      if (!Array.isArray(data) || !data.length) {
        cont.innerHTML = '<div class="text-center py-8 text-slate-500 text-sm italic">Sin ediciones registradas todavía</div>';
        return;
      }
      _logProdConstruirIndices(data);
      _logProdFiltrar();
    } catch(e) {
      if (!cache) cont.innerHTML = '<div class="text-center py-6 text-red-400 text-sm">Error: ' + e.message + '</div>';
    }
  }

  // Construye el índice de días con actividad (en hora LOCAL) y dropdown usuarios
  function _logProdConstruirIndices(data) {
    const dias = new Set();
    const usuarios = new Set();
    data.forEach(p => {
      const hist = Array.isArray(p.historial) ? p.historial : [];
      hist.forEach(e => {
        const f = _logFechaLocal(e.ts);
        if (f) dias.add(f);
        if (e.usuario) usuarios.add(String(e.usuario).trim());
      });
    });
    _logProdState.diasConActividad = dias;
    _logProdState.usuariosDisponibles = Array.from(usuarios).sort();
    const sel = $('logFiltroUsuario');
    if (sel) {
      const cur = sel.value;
      sel.innerHTML = '<option value="">Todos</option>' +
        _logProdState.usuariosDisponibles.map(u => `<option value="${u}">${u}</option>`).join('');
      sel.value = cur;
    }
  }

  function _logProdFechaOffset(delta) {
    // Si estaba en "todos", al navegar volvemos a fecha hoy ± delta
    if (_logProdState.sinFiltroFecha) {
      _logProdState.sinFiltroFecha = false;
      _logProdState.fecha = today();
    }
    const f = _logProdState.fecha || today();
    // Construir fecha LOCAL evitando UTC drift
    const [yy, mm, dd] = f.split('-').map(Number);
    const d = new Date(yy, mm - 1, dd);
    d.setDate(d.getDate() + delta);
    const newFecha = d.getFullYear() + '-' +
                     String(d.getMonth() + 1).padStart(2, '0') + '-' +
                     String(d.getDate()).padStart(2, '0');
    _logProdState.fecha = newFecha;
    _logProdActualizarFechaUI();
    _logProdFiltrar();
    _logProdSlide(delta < 0 ? 'left' : 'right');
  }
  function _logProdIrHoy() {
    _logProdState.fecha = today();
    _logProdState.sinFiltroFecha = false;
    _logProdActualizarFechaUI();
    _logProdFiltrar();
  }
  function _logProdVerTodo() {
    _logProdState.sinFiltroFecha = true;
    _logProdActualizarFechaUI();
    _logProdFiltrar();
  }
  function _logProdLimpiarFiltros() {
    _logProdState.filtroBuscar = '';
    _logProdState.filtroUsuario = '';
    _logProdState.filtroAccion = '';
    _logProdState.sinFiltroFecha = false;
    if (!_logProdState.fecha) _logProdState.fecha = today();
    const inp = $('logFiltroBuscar'); if (inp) inp.value = '';
    const su = $('logFiltroUsuario'); if (su) su.value = '';
    const sa = $('logFiltroAccion');  if (sa) sa.value = '';
    // Si la barra estaba en modo búsqueda, volver al modo normal
    const bar = $('logBarraBuscar');
    const norm = $('logBarraNormal');
    if (bar && !bar.classList.contains('hidden')) {
      bar.classList.add('hidden');
      norm?.classList.remove('hidden');
    }
    _logProdActualizarFechaUI();
    _logProdFiltrar();
  }
  function _logProdLimpiarBuscar() {
    const inp = $('logFiltroBuscar');
    if (inp) { inp.value = ''; inp.focus(); }
    _logProdState.filtroBuscar = '';
    _logProdActualizarFechaUI();
    _logProdFiltrar();
  }
  function _logProdToggleBusqueda() {
    const bar = $('logBarraBuscar');
    const norm = $('logBarraNormal');
    if (!bar || !norm) return;
    const abriendo = bar.classList.contains('hidden');
    bar.classList.toggle('hidden', !abriendo);
    norm.classList.toggle('hidden', abriendo);
    if (abriendo) {
      setTimeout(() => $('logFiltroBuscar')?.focus(), 50);
    }
  }
  // Popover unificado: usuario / acción
  function _logProdAbrirFiltro(tipo, anchorBtn) {
    const pop = $('logFiltroPopover');
    if (!pop) return;
    if (!pop.classList.contains('hidden') && pop.dataset.tipo === tipo) {
      pop.classList.add('hidden');
      return;
    }
    pop.dataset.tipo = tipo;
    let html = '';
    if (tipo === 'usuario') {
      const cur = _logProdState.filtroUsuario;
      const usuarios = _logProdState.usuariosDisponibles || [];
      html = '<div class="log-popover-title">Usuario</div>';
      html += `<div class="log-popover-opt ${!cur ? 'selected' : ''}" onclick="MOS._logProdSetFiltro('usuario','')">
        <div class="log-popover-opt-radio"></div><span>Todos</span>
      </div>`;
      usuarios.forEach(u => {
        const safe = u.replace(/'/g, "\\'");
        html += `<div class="log-popover-opt ${cur === u ? 'selected' : ''}" onclick="MOS._logProdSetFiltro('usuario','${safe}')">
          <div class="log-popover-opt-radio"></div><span>👤 ${u}</span>
        </div>`;
      });
    } else if (tipo === 'accion') {
      const cur = _logProdState.filtroAccion;
      const opts = [
        ['', 'Todas las acciones'],
        ['crear', '🆕 Crear'],
        ['editar', '✏️ Editar'],
        ['precio', '💰 Cambio de precio'],
        ['codigo', '🔢 Corrección código'],
        ['equivalencia', '🔗 Equivalencia']
      ];
      html = '<div class="log-popover-title">Tipo de acción</div>';
      opts.forEach(([v, lbl]) => {
        html += `<div class="log-popover-opt ${cur === v ? 'selected' : ''}" onclick="MOS._logProdSetFiltro('accion','${v}')">
          <div class="log-popover-opt-radio"></div><span>${lbl}</span>
        </div>`;
      });
    }
    pop.innerHTML = html;
    // Posicionar bajo el botón
    const r = anchorBtn.getBoundingClientRect();
    pop.style.left = Math.max(8, Math.min(window.innerWidth - 290, r.left)) + 'px';
    pop.style.top  = (r.bottom + 6) + 'px';
    pop.classList.remove('hidden');
    // Cerrar al click fuera
    setTimeout(() => {
      const closer = e => {
        if (!pop.contains(e.target) && !anchorBtn.contains(e.target)) {
          pop.classList.add('hidden');
          document.removeEventListener('click', closer);
        }
      };
      document.addEventListener('click', closer);
    }, 50);
  }
  function _logProdSetFiltro(tipo, valor) {
    if (tipo === 'usuario') _logProdState.filtroUsuario = valor;
    if (tipo === 'accion')  _logProdState.filtroAccion = valor;
    const sel = $(tipo === 'usuario' ? 'logFiltroUsuario' : 'logFiltroAccion');
    if (sel) sel.value = valor;
    $('logFiltroPopover')?.classList.add('hidden');
    _logProdActualizarFechaUI();
    _logProdFiltrar();
  }

  function _logProdFiltrar() {
    const data = S._logProdCache?.data || [];
    if (!Array.isArray(data) || !data.length) return;

    // Recoger filtros desde DOM (puede haberlos cambiado el user)
    _logProdState.filtroBuscar  = ($('logFiltroBuscar')?.value || '').trim().toLowerCase();

    // Una sola vista: agrupada por canónico, filtrada por fecha activa
    _logProdRenderPorProducto(data);
    _logProdActualizarFechaUI();
  }

  function _logProdSlide(dir) {
    const cont = $('logProductosList');
    if (!cont) return;
    const cls = dir === 'left' ? 'fin-slide-out-right' : 'fin-slide-out-left';
    cont.classList.add(cls);
    setTimeout(() => cont.classList.remove(cls), 280);
  }

  // ── Filtra una entrada según los filtros activos ──
  function _logProdEntradaCoincide(entrada) {
    // Filtro fecha (hora local)
    if (!_logProdState.sinFiltroFecha && _logProdState.fecha) {
      const fLocal = _logFechaLocal(entrada.ts);
      if (fLocal !== _logProdState.fecha) return false;
    }
    if (_logProdState.filtroUsuario) {
      const u = String(entrada.usuario || '').trim();
      if (u !== _logProdState.filtroUsuario) return false;
    }
    if (_logProdState.filtroAccion) {
      const a = String(entrada.accion || '').toLowerCase();
      const src = String(entrada.source || '').toLowerCase();
      const filt = _logProdState.filtroAccion;
      if (filt === 'crear' && a !== 'crear') return false;
      if (filt === 'editar' && a !== 'editar' && a !== 'editar (auto)') return false;
      if (filt === 'precio' && !src.includes('precio')) return false;
      if (filt === 'codigo' && !src.includes('codigo')) return false;
      if (filt === 'equivalencia' && !src.includes('equiv')) return false;
    }
    return true;
  }
  function _logProdProductoCoincide(p) {
    if (_logProdState.filtroBuscar) {
      const q = _logProdState.filtroBuscar;
      const txt = (p.descripcion + ' ' + (p.skuBase || '') + ' ' + (p.codigoBarra || '')).toLowerCase();
      if (!txt.includes(q)) return false;
    }
    return true;
  }

  // ── Vista única: agrupada por canónico, filtrada por fecha activa ──
  function _logProdRenderPorProducto(data) {
    _logProdRender(data);
    const cont = $('logProductosList');
    const cant = cont ? cont.querySelectorAll('.log-card').length : 0;
    const cantEl = $('logCantResultados');
    if (cantEl) {
      cantEl.textContent = cant > 0 ? `${cant} ⚡` : '0';
      // Pulso al actualizar
      cantEl.style.transition = 'color 0.4s';
      cantEl.style.color = cant > 0 ? '#a5b4fc' : '#64748b';
      setTimeout(() => { cantEl.style.color = '#94a3b8'; }, 400);
    }
    const sub = $('logModalSubtitle');
    if (sub) {
      const fechaTxt = _logProdState.sinFiltroFecha ? 'todo el historial'
        : (_logProdState.fecha === today() ? 'hoy' : _logProdState.fecha);
      sub.textContent = `${cant} producto${cant !== 1 ? 's' : ''} con cambios · ${fechaTxt}`;
    }
    if (!cant && cont) {
      const haceFiltro = !!(_logProdState.filtroBuscar || _logProdState.filtroUsuario || _logProdState.filtroAccion);
      const linkVerTodo = !_logProdState.sinFiltroFecha && !haceFiltro
        ? `<button onclick="MOS._logProdVerTodo()" class="text-indigo-400 hover:text-indigo-300 text-xs mt-2 underline">Ver todo el historial →</button>`
        : '';
      cont.innerHTML = `<div class="text-center py-10 text-slate-500 text-sm italic">
        Sin cambios ${haceFiltro ? 'con esos filtros' : (_logProdState.sinFiltroFecha ? '' : 'este día')}
        <div>${linkVerTodo}</div>
      </div>`;
    }
  }

  // ── Vista por día: agrupado por hora ──
  function _logProdRenderPorDia(data) {
    const cont = $('logProductosList');
    if (!cont) return;
    const fechaSel = _logProdState.fecha;
    // Construir mapa skuBase → canónico para resolver títulos correctos
    const canonicoPorSku = {};
    data.forEach(p => {
      const sku = p.skuBase;
      if (!sku) return;
      const esCan = !p.codigoProductoBase && (parseFloat(p.factorConversion) === 1 || !p.factorConversion);
      if (esCan) canonicoPorSku[sku] = p;
    });
    // Aplanar todas las entradas del día
    const eventos = [];
    data.forEach(p => {
      // Filtro búsqueda: si no coincide ni este producto ni su canónico (mismo skuBase), saltar
      const can = p.skuBase ? canonicoPorSku[p.skuBase] : null;
      const coincideAlguno = _logProdProductoCoincide(p) || (can && _logProdProductoCoincide(can));
      if (!coincideAlguno) return;
      const hist = Array.isArray(p.historial) ? p.historial : [];
      const esCanonico = !p.codigoProductoBase && (parseFloat(p.factorConversion) === 1 || !p.factorConversion);
      hist.forEach(e => {
        if (!e.ts) return;
        if (_logFechaLocal(e.ts) !== fechaSel) return;
        if (!_logProdEntradaCoincide(e)) return;
        eventos.push({
          ts: e.ts,
          // Título mostrado = canónico (si existe), para agrupar visualmente
          titulo: can ? (can.descripcion || p.descripcion) : (p.descripcion || '—'),
          // Sub-título = la presentación específica si no es canónico
          esCanonico,
          presentacion: esCanonico ? '' : (p.descripcion || ''),
          factor: p.factorConversion || '',
          idProducto: p.idProducto || '',
          skuBase: p.skuBase || '',
          entrada: e
        });
      });
    });
    // Ordenar desc
    eventos.sort((a, b) => new Date(b.ts).getTime() - new Date(a.ts).getTime());

    const cantEl = $('logCantResultados');
    if (cantEl) cantEl.textContent = `${eventos.length} cambio${eventos.length !== 1 ? 's' : ''}`;
    const sub = $('logModalSubtitle');
    const fHoyTxt = new Date(fechaSel + 'T00:00:00').toLocaleDateString('es-PE', { weekday:'long', day:'numeric', month:'long' });
    if (sub) sub.textContent = `${eventos.length} cambios · ${fHoyTxt}`;

    if (!eventos.length) {
      cont.innerHTML = '<div class="log-dia-empty">Sin actividad este día</div>';
      return;
    }

    // Agrupar por hora
    const porHora = {};
    eventos.forEach(ev => {
      const d = new Date(ev.ts);
      const hh = String(d.getHours()).padStart(2, '0');
      const key = hh;
      if (!porHora[key]) porHora[key] = [];
      porHora[key].push(ev);
    });
    const horas = Object.keys(porHora).sort((a, b) => b.localeCompare(a));
    cont.innerHTML = horas.map(h => {
      const evs = porHora[h];
      return `<div class="log-dia-hour">
        <div class="log-dia-hour-col">
          ${h}h
          <div class="log-dia-hour-col-sub">${evs.length} ev</div>
        </div>
        <div class="log-dia-events">
          ${evs.map(ev => {
            const e = ev.entrada;
            const d = new Date(e.ts);
            const mm = String(d.getMinutes()).padStart(2, '0');
            const ss = String(d.getSeconds()).padStart(2, '0');
            let cuerpo = '';
            if (e.accion === 'crear') {
              cuerpo = `<span class="log-action log-action-crear">🆕 creó</span>`;
            } else if (Array.isArray(e.cambios) && e.cambios.length) {
              cuerpo = `<span class="log-action log-action-editar">✏️ editó</span> ` + e.cambios.map(c =>
                `<strong style="color:#fbbf24">${c.campo}</strong>: <span class="log-antes">${_logFmtVal(c.antes)}</span> → <span class="log-despues">${_logFmtVal(c.despues)}</span>`
              ).join(' · ');
            } else {
              cuerpo = `<span class="log-action log-action-editar">${e.accion || 'cambio'}</span>`;
            }
            const safeId = String(ev.idProducto || '').replace(/'/g, '&#39;');
            const origenChip = ev.esCanonico
              ? `<span class="log-origen log-origen-canonico">📦 base</span>`
              : `<span class="log-origen log-origen-presentacion">📐 ${ev.presentacion || 'presentación'}${ev.factor ? ' · f=' + ev.factor : ''}</span>`;
            return `<div class="log-dia-event" onclick="MOS.closeModal('modalLogProductos');MOS.abrirModalProducto('${safeId}')">
              <div class="log-dia-event-prod">${ev.titulo}</div>
              <div class="flex items-center gap-2 flex-wrap" style="margin:3px 0">
                ${origenChip}
                <span style="flex:1;min-width:0">${cuerpo}</span>
              </div>
              <div class="log-dia-event-meta">${h}:${mm}:${ss} · 👤 ${e.usuario || '—'} ${e.source ? '· ' + e.source : ''}${e.motivo ? ' · ' + e.motivo : ''}</div>
            </div>`;
          }).join('')}
        </div>
      </div>`;
    }).join('');
  }

  // ── DATEPICKER ──
  function _logProdAbrirCalendario(btn) {
    const dp = $('logDatepicker');
    if (!dp) return;
    if (!dp.classList.contains('hidden')) {
      dp.classList.add('hidden');
      return;
    }
    // Posicionar bajo el botón
    const r = btn.getBoundingClientRect();
    dp.style.left = (r.left) + 'px';
    dp.style.top  = (r.bottom + 6) + 'px';
    // Mes inicial = mes de la fecha seleccionada
    const f = _logProdState.fecha || today();
    const d = new Date(f + 'T00:00:00');
    _logProdState.calMes = { y: d.getFullYear(), m: d.getMonth() };
    _logProdRenderCalendario();
    dp.classList.remove('hidden');
    // Click fuera cierra
    setTimeout(() => {
      const closer = e => {
        if (!dp.contains(e.target) && e.target.id !== 'logFechaBtn' && !btn.contains(e.target)) {
          dp.classList.add('hidden');
          document.removeEventListener('click', closer);
        }
      };
      document.addEventListener('click', closer);
    }, 50);
  }
  function _logProdCalNavMes(delta) {
    if (!_logProdState.calMes) return;
    let { y, m } = _logProdState.calMes;
    m += delta;
    if (m < 0)   { m = 11; y--; }
    if (m > 11)  { m = 0;  y++; }
    _logProdState.calMes = { y, m };
    _logProdRenderCalendario();
  }
  function _logProdRenderCalendario() {
    const grid = $('logCalGrid');
    const lbl  = $('logCalMesAnio');
    if (!grid || !_logProdState.calMes) return;
    const { y, m } = _logProdState.calMes;
    const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
    if (lbl) lbl.textContent = `${meses[m]} ${y}`;
    // Primer día del mes
    const primero = new Date(y, m, 1);
    let primerDow = primero.getDay(); // 0=dom..6=sab
    primerDow = primerDow === 0 ? 6 : primerDow - 1; // L=0..D=6
    const ultimo = new Date(y, m + 1, 0).getDate();
    const hoy = today();
    const sel = _logProdState.fecha;
    const dias = _logProdState.diasConActividad;
    let html = '';
    for (let i = 0; i < primerDow; i++) html += '<button class="log-cal-day empty"></button>';
    for (let dia = 1; dia <= ultimo; dia++) {
      const f = `${y}-${String(m + 1).padStart(2, '0')}-${String(dia).padStart(2, '0')}`;
      const cls = ['log-cal-day'];
      if (dias.has(f)) cls.push('has-activity');
      if (f === hoy)   cls.push('today');
      if (f === sel)   cls.push('selected');
      html += `<button class="${cls.join(' ')}" onclick="MOS._logProdElegirFecha('${f}')">${dia}</button>`;
    }
    grid.innerHTML = html;
  }
  function _logProdElegirFecha(f) {
    _logProdState.fecha = f;
    _logProdActualizarFechaUI();
    const dp = $('logDatepicker');
    if (dp) dp.classList.add('hidden');
    _logProdFiltrar();
  }

  // Agrupa productos por skuBase. El representante es el canónico
  // (factorConversion=1 sin codigoProductoBase). Las presentaciones quedan
  // como sub-productos cuyas entradas se mezclan en el historial combinado
  // del grupo, etiquetadas con el origen.
  function _logProdAgruparPorCanonico(data) {
    const grupos = {};
    data.forEach(p => {
      const key = String(p.skuBase || p.codigoProductoBase || p.idProducto || '');
      if (!key) return;
      if (!grupos[key]) grupos[key] = { canonico: null, miembros: [], historial: [] };
      const esCanonico = !p.codigoProductoBase && (parseFloat(p.factorConversion) === 1 || !p.factorConversion);
      if (esCanonico) grupos[key].canonico = p;
      grupos[key].miembros.push(p);
      const hist = Array.isArray(p.historial) ? p.historial : [];
      hist.forEach(e => {
        grupos[key].historial.push(Object.assign({}, e, {
          _origenIdProducto: p.idProducto,
          _origenDescripcion: p.descripcion,
          _origenEsCanonico: esCanonico,
          _origenFactor: p.factorConversion
        }));
      });
    });
    Object.keys(grupos).forEach(k => {
      // Si no hay canónico identificado, usar el miembro con factor más bajo
      if (!grupos[k].canonico) {
        grupos[k].canonico = grupos[k].miembros.slice().sort((a, b) =>
          (parseFloat(a.factorConversion) || 1) - (parseFloat(b.factorConversion) || 1)
        )[0];
      }
      grupos[k].historial.sort((a, b) => new Date(b.ts || 0).getTime() - new Date(a.ts || 0).getTime());
    });
    return grupos;
  }

  function _logProdRender(data) {
    const cont = $('logProductosList');
    if (!cont || !Array.isArray(data)) return;
    const grupos = _logProdAgruparPorCanonico(data);
    // Ordenar grupos por timestamp del último cambio descendente
    const claves = Object.keys(grupos).sort((a, b) => {
      const ta = grupos[a].historial[0]?.ts ? new Date(grupos[a].historial[0].ts).getTime() : 0;
      const tb = grupos[b].historial[0]?.ts ? new Date(grupos[b].historial[0].ts).getTime() : 0;
      return tb - ta;
    });

    cont.innerHTML = claves.map(key => {
      const g = grupos[key];
      const c = g.canonico;
      // Filtro de búsqueda: aplica al GRUPO (cualquier miembro coincide).
      // Esto permite buscar "TRIPACK" y aún ver el grupo del canónico ACONCAGUA.
      const grupoCoincide = g.miembros.some(_logProdProductoCoincide);
      if (!grupoCoincide) return '';
      // Filtrar entradas individuales con _logProdEntradaCoincide
      const histFiltrado = g.historial.filter(_logProdEntradaCoincide);
      if (!histFiltrado.length) return '';
      const ult = histFiltrado[0];
      const f = ult.ts ? new Date(ult.ts) : null;
      const fmt = f ? f.toLocaleString('es-PE', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit' }) : '—';
      const mins = f ? Math.floor((Date.now() - f.getTime()) / 60000) : Infinity;
      let badge = '';
      if (mins < 5)         badge = `<span class="log-badge log-badge-live">🟢 hace ${mins}m</span>`;
      else if (mins < 60)   badge = `<span class="log-badge log-badge-recent">hace ${mins}m</span>`;
      else if (mins < 1440) badge = `<span class="log-badge log-badge-hours">hace ${Math.floor(mins/60)}h</span>`;
      else                  badge = `<span class="log-badge log-badge-old">hace ${Math.floor(mins/1440)}d</span>`;
      const safeId = String(c.idProducto || '').replace(/'/g, '&#39;');
      const numPresentaciones = g.miembros.filter(m => !!m.codigoProductoBase || (parseFloat(m.factorConversion) > 1)).length;
      const tipoChip = numPresentaciones > 0
        ? `<span class="text-[9px] uppercase font-bold text-emerald-300">CANÓNICO + ${numPresentaciones} pres.</span>`
        : `<span class="text-[9px] uppercase font-bold text-emerald-300">CANÓNICO</span>`;

      const entries = histFiltrado.slice(0, 12).map(e => {
        const fe = e.ts ? new Date(e.ts).toLocaleString('es-PE', { day:'2-digit', month:'short', year:'2-digit', hour:'2-digit', minute:'2-digit' }) : '—';
        // Chip de origen: si la entrada viene de una presentación, indicar cuál
        const origenChip = e._origenEsCanonico
          ? `<span class="log-origen log-origen-canonico" title="Cambio en el producto canónico">📦 base</span>`
          : `<span class="log-origen log-origen-presentacion" title="Cambio en la presentación">📐 ${e._origenDescripcion || 'presentación'}${e._origenFactor ? ' · f=' + e._origenFactor : ''}</span>`;
        let cuerpo = '';
        if (e.accion === 'crear') {
          cuerpo = `<span class="log-action log-action-crear">🆕 creó</span> ${e.descripcion || ''}${e.codigoBarra ? ' · cód ' + e.codigoBarra : ''}${e.precioVenta ? ' · S/ ' + parseFloat(e.precioVenta).toFixed(2) : ''}`;
        } else if (Array.isArray(e.cambios) && e.cambios.length) {
          cuerpo = '<span class="log-action log-action-editar">✏️ editó</span> ' + e.cambios.map(c =>
            `<span class="log-cambio"><strong>${c.campo}</strong>: <span class="log-antes">${_logFmtVal(c.antes)}</span> → <span class="log-despues">${_logFmtVal(c.despues)}</span></span>`
          ).join(' · ');
        } else {
          cuerpo = `<span class="log-action log-action-editar">✏️ ${e.accion || 'cambio'}</span>`;
        }
        if (e.motivo) cuerpo += ` <span class="log-motivo">— ${e.motivo}</span>`;
        const evIdSafe = String(e._origenIdProducto || '').replace(/'/g, '&#39;');
        return `<div class="log-entry">
          <div class="log-entry-head">
            <span class="log-usuario">👤 ${e.usuario || 'desconocido'}</span>
            ${origenChip}
            <span class="log-source">${e.source || ''}</span>
            <span class="log-fecha">${fe}</span>
          </div>
          <div class="log-entry-body">${cuerpo}</div>
          ${!e._origenEsCanonico && evIdSafe ? `<button onclick="event.stopPropagation();MOS.closeModal('modalLogProductos');MOS.abrirModalProducto('${evIdSafe}')" class="log-entry-link">→ abrir presentación</button>` : ''}
        </div>`;
      }).join('');

      return `<div class="log-card">
        <div class="log-card-head" onclick="MOS._logToggleCard(this)">
          <div class="flex-1 min-w-0">
            <div class="log-card-title">${c.descripcion || '—'} <span class="log-toggle">▾</span></div>
            <div class="log-card-meta">
              ${tipoChip}
              <span class="text-[10px] text-slate-500">${c.skuBase || '—'}</span>
              <span class="text-[10px] text-amber-400 font-bold">S/ ${parseFloat(c.precioVenta || 0).toFixed(2)}</span>
              <span class="text-[10px] text-slate-500">· ${histFiltrado.length} cambio${histFiltrado.length !== 1 ? 's' : ''}</span>
            </div>
            <div class="log-card-last">
              Último: ${ult.usuario || '—'} · ${fmt}${!ult._origenEsCanonico ? ' · en ' + (ult._origenDescripcion || 'presentación') : ''}
            </div>
          </div>
          ${badge}
        </div>
        <div class="log-card-entries hidden">
          ${entries}
          <button onclick="MOS.closeModal('modalLogProductos');MOS.abrirModalProducto('${safeId}')" class="log-btn-edit">✏️ Abrir canónico</button>
        </div>
      </div>`;
    }).filter(Boolean).join('');
  }

  function _logFmtVal(v) {
    if (v === null || v === undefined || v === '') return '<em class="text-slate-600">vacío</em>';
    const s = String(v);
    return s.length > 40 ? s.substring(0, 40) + '...' : s;
  }

  function _logToggleCard(headEl) {
    const card = headEl?.closest('.log-card');
    if (!card) return;
    card.querySelector('.log-card-entries')?.classList.toggle('hidden');
    const t = card.querySelector('.log-toggle');
    if (t) t.textContent = card.querySelector('.log-card-entries').classList.contains('hidden') ? '▾' : '▴';
  }

  // ── Product modal — abrir ─────────────────────────────────
  function abrirModalProducto(id, opts) {
    opts = opts || {};
    try { _opsBeep && _opsBeep('tac'); } catch(_){}
    // [v2.43.54] Aplicar halo de categoría al modal box (efecto premium)
    setTimeout(() => {
      const prod = id && Array.isArray(S.productos) ? S.productos.find(p => p.idProducto === id) : null;
      const box = document.querySelector('#modalProducto .modal-box, #productModal .modal-box');
      if (box && prod) _aplicarHaloCategoria(box, prod);
    }, 50);
    // [v2.43.3] Si llamaron con focusPolitica, scroll + expandir sección política
    // tras 250ms (después de renderizar el modal). Ahorra 3 taps al cajero.
    if (opts.focusPolitica) {
      setTimeout(() => {
        try {
          const sec = document.querySelector('[id*="Politica"],[data-section="politica"],.prod-sec-politica,#prodSecPolitica');
          if (sec && sec.classList.contains('hidden')) {
            (typeof prodTogglePolitica === 'function') && prodTogglePolitica();
          }
          if (sec) sec.scrollIntoView({ behavior: 'smooth', block: 'center' });
          _opsBeep?.('tac');
        } catch(_){}
      }, 280);
    }
    // Reset
    ['prodDescripcion','prodCodigoBarra','prodMarca','prodPrecioVenta','prodPrecioCosto',
     'prodFactorConvBase','prodMerma','prodFactor','prodIGV','prodCodSUNAT'].forEach(i => { const el=$(i); if(el) el.value=''; });
    $('prodId').value = '';
    $('prodEstado').value = '1';
    const toggle = $('prodEstadoToggle');
    if (toggle) { toggle.classList.add('on'); toggle.querySelector('.prod-toggle-lbl').textContent = 'Activo'; }
    const fb = $('prodCodigoBarraFeedback');
    if (fb) { fb.className = 'hidden text-xs mt-1'; fb.textContent = ''; }
    $('prodCodigoBarra')?.classList.remove('!border-red-500');
    $('prodCostoRow')?.classList.add('hidden');
    const ch = $('costoChevron'); if (ch) ch.textContent = '▶';
    $('prodMargenBar')?.classList.add('hidden');
    _setStockSlider(0, 0);
    setProdTipo('normal');
    $('modalEquivSection')?.classList.add('hidden');
    $('equivContent')?.classList.add('hidden');
    const ech = $('equivChevron'); if (ech) ech.textContent = '▶';
    $('equivList') && ($('equivList').innerHTML = '');
    $('equivAddForm')?.classList.add('hidden');
    $('prodSecSunat')?.classList.add('hidden');
    const sch = $('sunatChevron'); if (sch) sch.textContent = '▶';

    if (id) {
      const p = S.productos.find(x => x.idProducto === id);
      if (!p) return;
      $('modalProdTitle').textContent = 'Editar Producto';
      $('prodId').value          = p.idProducto;
      $('prodDescripcion').value = p.descripcion   || '';
      $('prodCodigoBarra').value = p.codigoBarra   || '';
      $('prodMarca').value       = p.marca         || '';
      $('prodCategoria').value   = p.idCategoria   || '';
      // Migración: valores legacy (KG, LITRO, BOLSA, etc.) → códigos SUNAT
      // El campo Unidad_Medida (SUNAT autoritativo) prima sobre unidad
      const _unidadProd = _normalizarUnidad(p.Unidad_Medida || p.unidad) || 'NIU';
      $('prodUnidad').value      = _unidadProd;
      $('prodUnidadMedida').value = _unidadProd; // hidden sincronizado

      // Estado
      const activo = _isProdActivo(p);
      $('prodEstado').value = activo ? '1' : '0';
      if (toggle) { toggle.classList.toggle('on', activo); toggle.querySelector('.prod-toggle-lbl').textContent = activo ? 'Activo' : 'Inactivo'; }

      // Precios
      $('prodPrecioVenta').value = p.precioVenta || '';
      if (p.precioCosto) {
        $('prodPrecioCosto').value = p.precioCosto;
        $('prodCostoRow')?.classList.remove('hidden');
        if (ch) ch.textContent = '▼';
      }
      prodCalcMargen();

      // Stock
      _setStockSlider(parseFloat(p.stockMinimo)||0, parseFloat(p.stockMaximo)||0);

      // SUNAT con migración legacy gravado→1, exonerado→2, inafecto→3
      const tipoIgvLegacy = { 'gravado': '1', 'exonerado': '2', 'inafecto': '3' };
      const tipoIgvVal = String(p.Tipo_IGV || '1').toLowerCase();
      $('prodTipoIGV').value     = tipoIgvLegacy[tipoIgvVal] || (p.Tipo_IGV ? String(p.Tipo_IGV) : '1');
      $('prodCodTributo').value  = p.Cod_Tributo     || '1000';
      $('prodIGV').value         = (p.IGV_Porcentaje !== undefined && p.IGV_Porcentaje !== '') ? p.IGV_Porcentaje : 18;
      // prodUnidadMedida ya se sincronizó arriba con prodUnidad (campo unificado)
      $('prodCodSUNAT').value    = p.Cod_SUNAT       || '10000000';
      _actualizarResumenSunat();

      // Determinar tipo correctamente según el modelo de datos:
      // - Envasable (granel): esEnvasable = 1
      // - Derivado (envasado del granel): tiene codigoProductoBase
      // - Presentación (variante del base, ej tripack): factorConversion > 1
      // - Normal/Base (canónico): factor = 1 o vacío, sin codigoProductoBase
      // OJO: skuBase y idProducto siempre son distintos en formato (IDPRO vs LEV),
      // por eso NO sirven como criterio para distinguir base de presentación.
      let tipo = 'normal';
      const factor = parseFloat(p.factorConversion);
      if (_esEnvasable(p)) {
        tipo = 'envasable';
      } else if (p.codigoProductoBase && String(p.codigoProductoBase).trim()) {
        tipo = 'derivado';
      } else if (factor && factor > 0 && factor !== 1) {
        tipo = 'presentacion';
      }
      // else: factor=1 o vacío + sin codigoProductoBase = base/normal/canónico
      setProdTipo(tipo);

      if (tipo === 'derivado') {
        $('prodCodigoProductoBase').value = p.codigoProductoBase || '';
        $('prodFactorConvBase').value     = p.factorConversionBase || '';
        $('prodMerma').value              = p.mermaEsperadaPct || '';
      }
      if (tipo === 'presentacion') {
        $('prodSkuBase').value = p.skuBase || '';
        $('prodFactor').value  = p.factorConversion || '';
      }

      // Equivalencias
      $('modalEquivSection')?.classList.remove('hidden');
      _loadEquivModal(p.skuBase || p.idProducto);

      // Política de precios (override del producto si tiene)
      const tieneOverride = !!(p.modoVenta && String(p.modoVenta).trim());
      $('prodPoliticaOverride').checked = tieneOverride;
      if (tieneOverride) {
        $('prodModoVenta').value = String(p.modoVenta).toUpperCase();
        $('prodMargenPct').value = (p.margenPct !== '' && p.margenPct !== undefined && p.margenPct !== null) ? p.margenPct : '';
        $('prodPrecioTope').value = (parseFloat(p.precioTope) > 0) ? p.precioTope : '';
      } else {
        $('prodModoVenta').value = 'MARGEN';
        $('prodMargenPct').value = '';
        $('prodPrecioTope').value = '';
      }
      _prodOnPoliticaOverride();
      _prodActualizarPoliticaEfectiva();
    } else {
      $('modalProdTitle').textContent = 'Nuevo Producto';
      // Defaults autorrelleno (típico abarrote: gravado 18%)
      $('prodUnidad').value       = 'NIU';
      $('prodUnidadMedida').value = 'NIU';
      $('prodTipoIGV').value      = '1';   // 1 = Gravado
      $('prodCodTributo').value   = '1000';
      $('prodIGV').value          = '18';
      $('prodCodSUNAT').value     = '10000000';
      _actualizarResumenSunat();
      // Política: por default heredar
      $('prodPoliticaOverride').checked = false;
      $('prodModoVenta').value = 'MARGEN';
      $('prodMargenPct').value = '';
      $('prodPrecioTope').value = '';
      _prodOnPoliticaOverride();
      _prodActualizarPoliticaEfectiva();
    }
    // [v2.41.97] Cargar segmentos del producto + mostrar sección si KGM
    try {
      const prodCargar = id ? S.productos.find(x => x.idProducto === id) : null;
      if (prodCargar) {
        segCargarParaProducto(prodCargar);
      } else {
        _segState.idProducto = null;
        _segState.precioCanonico = 0;
        _segState.segmentos = [];
      }
      segActualizarVisibilidad();
    } catch(_) {}
    openModal('modalProducto');
  }

  // ── Modal producto: política de precios ───────────────────
  function prodTogglePolitica() {
    const sec = $('prodSecPolitica');
    const ch  = $('politicaChevron');
    if (!sec) return;
    const oculta = sec.classList.contains('hidden');
    sec.classList.toggle('hidden');
    if (ch) ch.textContent = oculta ? '▼' : '▶';
  }

  function _prodOnPoliticaOverride() {
    const on = $('prodPoliticaOverride')?.checked;
    $('prodPoliticaCampos')?.classList.toggle('hidden', !on);
    if (on) _prodOnModoChange();
  }

  function _prodOnModoChange() {
    const modo = $('prodModoVenta')?.value;
    $('prodMargenWrap')?.classList.toggle('hidden', modo === 'FIJO' || modo === 'LIBRE');
    $('prodTopeWrap')?.classList.toggle('hidden', modo !== 'COMPETITIVO');
  }

  function _prodActualizarPoliticaEfectiva() {
    const el = $('prodPoliticaEfectiva');
    if (!el) return;
    const idCat = $('prodCategoria')?.value;
    const cat = (cfgData.categorias || []).find(c => String(c.idCategoria).toUpperCase() === String(idCat || '').toUpperCase());
    const override = $('prodPoliticaOverride')?.checked;
    if (override) {
      const modo = $('prodModoVenta')?.value || 'MARGEN';
      const margen = parseFloat($('prodMargenPct')?.value);
      const detalle = (modo === 'MARGEN' || modo === 'COMPETITIVO') && !isNaN(margen)
        ? `${modo} ${margen}%` : modo;
      el.innerHTML = `Política efectiva: <span class="text-amber-400 font-semibold">${detalle}</span> <span class="text-slate-600">(override del producto)</span>`;
    } else if (cat) {
      const detalle = (cat.modoVenta === 'MARGEN' || cat.modoVenta === 'COMPETITIVO')
        ? `${cat.modoVenta} ${parseFloat(cat.margenPct).toFixed(1)}%` : cat.modoVenta;
      el.innerHTML = `Política efectiva: <span class="text-emerald-400 font-semibold">${detalle}</span> <span class="text-slate-600">(de categoría ${cat.nombre || cat.idCategoria})</span>`;
    } else {
      el.innerHTML = `Política efectiva: <span class="text-slate-400 italic">${idCat ? 'categoría sin política configurada' : 'selecciona una categoría primero'}</span>`;
    }
  }

  // Carga y renderiza equivalencias dentro del modal
  async function _loadEquivModal(skuBase) {
    const list = $('equivList');
    if (!list) return;
    list.innerHTML = '<div class="text-xs text-slate-600 italic py-1 px-1">Cargando...</div>';
    try {
      const rows = (await API.get('getEquivalencias', { skuBase })) || [];
      // Actualizar equivMap también
      S.equivMap[skuBase] = rows.filter(r => String(r.activo) === '1').map(r => r.codigoBarra).filter(Boolean);
      _renderEquivList(rows, skuBase);
    } catch(e) {
      list.innerHTML = `<div class="text-xs text-red-400 py-1 px-1">Error: ${e.message}</div>`;
    }
  }

  function _renderEquivList(rows, skuBase) {
    const list = $('equivList');
    if (!list) return;
    if (!rows.length) {
      list.innerHTML = '<div class="text-xs text-slate-600 italic py-1 px-1">Sin equivalencias registradas</div>';
      return;
    }
    list.innerHTML = rows.map(r => {
      const on = String(r.activo) === '1';
      return `<div class="equiv-row${on ? '' : ' inactive'}" data-id="${r.idEquiv}">
        <span class="equiv-code">▌${r.codigoBarra}</span>
        <span class="equiv-desc truncate">${r.descripcion || ''}</span>
        <button class="equiv-toggle ${on ? 'on' : 'off'}"
                onclick="MOS.toggleEquivActivo('${r.idEquiv}','${skuBase}','${on ? '0' : '1'}')"
                title="${on ? 'Desactivar' : 'Activar'}">
          ${on ? '✓ Activo' : '✗ Inactivo'}
        </button>
      </div>`;
    }).join('');
  }

  function toggleAddEquiv() {
    const form = $('equivAddForm');
    if (!form) return;
    const opening = form.classList.toggle('hidden');
    if (!opening) { // se acaba de mostrar
      const inp = $('equivCodigo');
      if (inp) { inp.value = ''; inp.focus(); }
      const d = $('equivDesc'); if (d) d.value = '';
    }
  }

  async function crearEquivalenciaModal() {
    const skuBase  = S.productos.find(p => p.idProducto === $('prodId')?.value);
    const sku      = skuBase ? (skuBase.skuBase || skuBase.idProducto) : '';
    const codigo   = ($('equivCodigo')?.value || '').trim();
    const desc     = ($('equivDesc')?.value   || '').trim();
    if (!sku)    { toast('Abre un producto primero', 'error'); return; }
    if (!codigo) { toast('Ingresa el código de barras', 'error'); return; }

    const btn = $('equivAddForm')?.querySelector('button');
    if (btn) btn.disabled = true;
    try {
      await API.post('crearEquivalencia', { _source: 'MOS_EQUIV_MODAL', skuBase: sku, codigoBarra: codigo, descripcion: desc });
      toast('Equivalencia guardada', 'ok');
      const f = $('equivAddForm'); if (f) f.classList.add('hidden');
      await _loadEquivModal(sku);
      renderCatalogo(); // actualiza badges en tarjetas
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    } finally {
      if (btn) btn.disabled = false;
    }
  }

  // ── Update visual surgical (sin re-renderizar) ────────────────
  function _actualizarVisualProducto(idProducto, activo) {
    // Toggle button
    const toggle = document.querySelector(`.toggle-sw[data-pid="${idProducto}"]`);
    if (toggle) {
      toggle.classList.toggle('on', activo);
      toggle.title = activo ? 'Apagar' : 'Prender';
    }
    // Si es presentación: pres-chip
    const presChip = document.querySelector(`.pres-chip[data-pres-id="${idProducto}"]`);
    if (presChip) {
      presChip.classList.toggle('pres-inactive', !activo);
    }
    // Si es base: cat-card
    const catCard = document.querySelector(`.cat-card[data-cat-id="${idProducto}"]`);
    if (catCard) {
      catCard.classList.toggle('cat-inactive', !activo);
    }
  }

  // [v2.41.95] Set de IDs con toggle en flight — protege el optimistic UI
  // contra el polling silencioso de catálogo que corre cada 60s. Sin esto,
  // si el polling corre entre el optimistic y la confirmación del POST,
  // sobrescribe con el estado viejo y el producto "vuelve a activarse".
  const _togglesEnVuelo = new Set();
  // También: timestamp por idProducto para que el refresh ignore por X seg
  // tras un toggle, incluso si el POST ya respondió (Sheets puede tardar
  // hasta unos segundos en reflejar el cambio en lecturas posteriores).
  const _togglesRecientes = new Map(); // idProducto → timestamp
  const _TOGGLE_PROTECCION_MS = 8000; // 8s post-POST

  function _toggleEstaProtegido(idProducto) {
    if (_togglesEnVuelo.has(idProducto)) return true;
    const ts = _togglesRecientes.get(idProducto);
    if (ts && (Date.now() - ts) < _TOGGLE_PROTECCION_MS) return true;
    return false;
  }
  function _marcarToggleReciente(idProducto) {
    _togglesRecientes.set(idProducto, Date.now());
    // Cleanup automático tras la protección
    setTimeout(() => _togglesRecientes.delete(idProducto), _TOGGLE_PROTECCION_MS + 1000);
  }

  // ── Toggle estado activo/inactivo de producto ────────────────
  // esBase=true: si apagas → flip visual + confirmación. Si prendes → cascada directa.
  // esBase=false: solo toggle local (presentación independiente).
  async function toggleProductoActivo(idProducto, esBase) {
    const p = S.productos.find(x => x.idProducto === idProducto);
    if (!p) return;
    const activoActual = _isProdActivo(p);

    if (esBase && activoActual) {
      // Apagar base con confirmación: flip visual inmediato + abrir modal
      _actualizarVisualProducto(idProducto, false);
      _pedirApagarBase(idProducto);
      return;
    }

    const nuevoEstado = activoActual ? '0' : '1';

    // OPTIMISTIC: actualizar UI primero
    p.estado = nuevoEstado;
    _actualizarVisualProducto(idProducto, nuevoEstado === '1');
    _togglesEnVuelo.add(idProducto); // proteger del polling
    // Toast más claro con flash visual del cambio
    toast(nuevoEstado === '1' ? '🟢 Activado · ' + (p.descripcion || idProducto).substring(0, 30)
                              : '⚫ Apagado · ' + (p.descripcion || idProducto).substring(0, 30),
          'ok', 1800);

    // Si es base prendiendo, cascadear visualmente a las presentaciones del grupo
    if (esBase && nuevoEstado === '1') {
      const skuBase = p.skuBase || idProducto;
      S.productos.forEach(pp => {
        if ((pp.skuBase || pp.idProducto) === skuBase && pp.idProducto !== idProducto) {
          if (!_isProdActivo(pp)) {
            pp.estado = '1';
            _actualizarVisualProducto(pp.idProducto, true);
            _togglesEnVuelo.add(pp.idProducto);
          }
        }
      });
    }

    // POST en background sin bloquear UI
    try {
      const res = await API.post('actualizarProducto', { _source: 'MOS_TOGGLE', idProducto, estado: nuevoEstado });
      if (res && res.ok === false) {
        throw new Error(res.error || 'GAS rechazó el cambio');
      }
      if (esBase && nuevoEstado === '1') {
        // Prender hijos en backend (presentaciones + equivalencias)
        _prenderHijos(p).catch(() => {});
      }
      // Marcar como reciente para que el polling siga respetando este cambio
      _marcarToggleReciente(idProducto);
      if (esBase && nuevoEstado === '1') {
        const skuBase = p.skuBase || idProducto;
        S.productos.forEach(pp => {
          if ((pp.skuBase || pp.idProducto) === skuBase) _marcarToggleReciente(pp.idProducto);
        });
      }
    } catch(e) {
      // Revertir en caso de error
      p.estado = activoActual ? '1' : '0';
      _actualizarVisualProducto(idProducto, activoActual);
      toast('⚠ No se pudo guardar: ' + (e.message || e), 'error');
    } finally {
      _togglesEnVuelo.delete(idProducto);
    }
  }

  async function _prenderHijos(baseProd) {
    const skuBase = baseProd.skuBase || baseProd.idProducto;
    const presentaciones = S.productos.filter(p =>
      (p.skuBase || p.idProducto) === skuBase && p.idProducto !== baseProd.idProducto
    );
    await Promise.all(presentaciones.map(async pp => {
      if (_isProdActivo(pp)) return;
      await API.post('actualizarProducto', { _source: 'MOS_TOGGLE_CASCADA', idProducto: pp.idProducto, estado: '1' });
      pp.estado = '1';
    }));
    try {
      const equivs = await API.get('getEquivalencias', { skuBase });
      const inactivas = (equivs || []).filter(e => {
        const v = e.activo;
        return !(v === '1' || v === 1 || v === true || String(v).toLowerCase() === 'true');
      });
      await Promise.all(inactivas.map(e =>
        API.post('actualizarEquivalencia', { _source: 'MOS_TOGGLE_CASCADA', idEquiv: e.idEquiv, activo: '1' })
      ));
    } catch(_) {}
  }

  function _pedirApagarBase(idProducto) {
    const p = S.productos.find(x => x.idProducto === idProducto);
    if (!p) return;
    const skuBase = p.skuBase || idProducto;
    const presentaciones = S.productos.filter(pp =>
      (pp.skuBase || pp.idProducto) === skuBase && pp.idProducto !== idProducto
    );
    $('apagarBaseId').value = idProducto;
    $('apagarBaseSku').value = skuBase;
    $('apagarBaseTitle').textContent = p.descripcion || idProducto;
    $('apagarBasePresCount').textContent = presentaciones.length;
    $('apagarBasePresList').innerHTML = presentaciones.length > 0
      ? presentaciones.map(pp => `<li>— ${pp.descripcion || pp.idProducto}</li>`).join('')
      : '<li class="italic">— sin presentaciones —</li>';
    $('apagarBaseEqCount').textContent = '…';
    $('apagarBaseEqList').innerHTML = '<li class="italic">— cargando —</li>';
    const modal = $('modalApagarBase');
    modal.dataset.equivs = '[]';
    openModal('modalApagarBase');

    API.get('getEquivalencias', { skuBase }).then(equivs => {
      const activas = (equivs || []).filter(e => {
        const v = e.activo;
        return v === '1' || v === 1 || v === true || String(v).toLowerCase() === 'true';
      });
      $('apagarBaseEqCount').textContent = activas.length;
      $('apagarBaseEqList').innerHTML = activas.length > 0
        ? activas.map(e => `<li>— ▌${e.codigoBarra}${e.descripcion ? ' (' + e.descripcion + ')' : ''}</li>`).join('')
        : '<li class="italic">— sin equivalencias activas —</li>';
      modal.dataset.equivs = JSON.stringify(activas.map(e => e.idEquiv));
    }).catch(() => {
      $('apagarBaseEqCount').textContent = '?';
      $('apagarBaseEqList').innerHTML = '<li class="italic text-red-400">— error al cargar —</li>';
    });
  }

  async function confirmarApagarBase() {
    const idProducto = $('apagarBaseId').value;
    const skuBase    = $('apagarBaseSku').value;
    const equivIds   = JSON.parse($('modalApagarBase').dataset.equivs || '[]');
    if (!idProducto) return;

    const productos = S.productos.filter(pp =>
      (pp.skuBase || pp.idProducto) === skuBase || pp.idProducto === idProducto
    );

    // OPTIMISTIC: marcar todos como apagados visualmente y cerrar modal de inmediato
    productos.forEach(pp => {
      pp.estado = '0';
      _actualizarVisualProducto(pp.idProducto, false);
    });
    closeModal('modalApagarBase');
    toast('Apagado ' + productos.length + ' producto(s) ✓', 'ok');

    // Marcador de "no revertir" en el modal (la confirmación procedió)
    $('modalApagarBase').dataset.confirmado = '1';

    // POST en background
    try {
      await Promise.all(productos.map(pp =>
        API.post('actualizarProducto', { _source: 'MOS_TOGGLE_CASCADA', idProducto: pp.idProducto, estado: '0' })
      ));
      await Promise.all(equivIds.map(idEquiv =>
        API.post('actualizarEquivalencia', { _source: 'MOS_TOGGLE_CASCADA', idEquiv, activo: '0' })
      ));
    } catch(e) {
      toast('Error de sincronización: ' + e.message, 'error');
    }
  }

  // Cerrar modal apagar base SIN confirmar → revertir flip visual del toggle base
  function cerrarApagarBaseRevertir() {
    const modal = $('modalApagarBase');
    if (modal && modal.dataset.confirmado !== '1') {
      const idProducto = $('apagarBaseId').value;
      if (idProducto) _actualizarVisualProducto(idProducto, true);
    }
    if (modal) delete modal.dataset.confirmado;
    closeModal('modalApagarBase');
  }

  async function toggleEquivActivo(idEquiv, skuBase, nuevoActivo) {
    try {
      await API.post('actualizarEquivalencia', { _source: 'MOS_EQUIV_MODAL', idEquiv, activo: nuevoActivo });
      await _loadEquivModal(skuBase);
      renderCatalogo();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  async function guardarProducto() {
    const desc = ($('prodDescripcion')?.value || '').trim();
    // Validaciones de campos OBLIGATORIOS
    if (!desc) {
      toast('⚠ La descripción es requerida', 'error');
      $('prodDescripcion')?.focus();
      return;
    }
    let codigoBarra = ($('prodCodigoBarra')?.value || '').trim();
    // Si no hay codigoBarra, autogenerar uno NMLEV en el momento (no permitir vacío)
    if (!codigoBarra) {
      prodAutogenBarcode(true); // silencioso: el campo está vacío, no hay que confirmar
      codigoBarra = ($('prodCodigoBarra')?.value || '').trim();
      if (!codigoBarra) {
        toast('⚠ El código de barras es requerido', 'error');
        $('prodCodigoBarra')?.focus();
        return;
      }
      toast('Código de barras autogenerado: ' + codigoBarra, 'info');
    }
    const precioVenta = parseFloat($('prodPrecioVenta')?.value);
    if (!precioVenta || precioVenta <= 0) {
      toast('⚠ El precio de venta es requerido (> 0)', 'error');
      $('prodPrecioVenta')?.focus();
      return;
    }

    const overridePolitica = !!$('prodPoliticaOverride')?.checked;
    const params = {
      idProducto:    $('prodId')?.value     || undefined,
      descripcion:   desc,
      codigoBarra:   $('prodCodigoBarra')?.value  || '',
      marca:         $('prodMarca')?.value        || '',
      idCategoria:   $('prodCategoria')?.value    || '',
      unidad:        $('prodUnidad')?.value       || 'NIU',
      precioVenta:   parseFloat($('prodPrecioVenta')?.value) || 0,
      precioCosto:   $('prodPrecioCosto')?.value  ? parseFloat($('prodPrecioCosto').value) : '',
      stockMinimo:   parseInt($('prodStockMin')?.value)  || 0,
      stockMaximo:   parseInt($('prodStockMax')?.value)  || 0,
      estado:        $('prodEstado')?.value       || '1',
      Tipo_IGV:      $('prodTipoIGV')?.value      || '',
      Cod_Tributo:   $('prodCodTributo')?.value   || '',
      IGV_Porcentaje:$('prodIGV')?.value          ? parseFloat($('prodIGV').value) : '',
      Unidad_Medida: $('prodUnidadMedida')?.value || 'NIU',
      Cod_SUNAT:     $('prodCodSUNAT')?.value     || '',
      // Política override (vacío = hereda de categoría)
      modoVenta:     overridePolitica ? ($('prodModoVenta')?.value || '') : '',
      margenPct:     overridePolitica && $('prodMargenPct')?.value ? parseFloat($('prodMargenPct').value) : '',
      precioTope:    overridePolitica && $('prodPrecioTope')?.value ? parseFloat($('prodPrecioTope').value) : ''
    };

    // Campos según tipo
    if (_prodTipo === 'envasable') {
      params.esEnvasable = '1'; params.codigoProductoBase = ''; params.factorConversion = ''; params.factorConversionBase = ''; params.mermaEsperadaPct = '';
    } else if (_prodTipo === 'derivado') {
      params.esEnvasable = '0';
      params.codigoProductoBase  = $('prodCodigoProductoBase')?.value || '';
      params.factorConversionBase= $('prodFactorConvBase')?.value ? parseFloat($('prodFactorConvBase').value) : '';
      params.mermaEsperadaPct    = $('prodMerma')?.value           ? parseFloat($('prodMerma').value)          : '';
      params.factorConversion = '';
    } else if (_prodTipo === 'presentacion') {
      params.esEnvasable = '0';
      // Solo mandar skuBase si el input tiene valor — evita borrar el SKU existente
      const skuVal = ($('prodSkuBase')?.value || '').trim();
      if (skuVal) params.skuBase = skuVal;
      params.factorConversion = $('prodFactor')?.value  ? parseFloat($('prodFactor').value) : '';
      params.codigoProductoBase = ''; params.factorConversionBase = ''; params.mermaEsperadaPct = '';
    } else { // normal (base): factorConversion = 1
      params.esEnvasable = '0'; params.codigoProductoBase = ''; params.factorConversionBase = ''; params.mermaEsperadaPct = '';
      // Solo asignar factorConversion=1 al CREAR (sin idProducto). En edición no se toca para no romper data.
      if (!params.idProducto) params.factorConversion = 1;
    }

    // BLOQUEO: si codigoBarra duplicado, no permitir guardar
    if (!prodValidarCodigoBarra()) {
      toast('El código de barras ya pertenece a otro producto. No se puede guardar.', 'error');
      $('prodCodigoBarra')?.focus();
      return;
    }

    // OPTIMISTIC FLOW: cerrar modal de inmediato + pulse visual al guardarse
    const isEdit = !!params.idProducto;
    params._source = 'MOS_MODAL_PRODUCTO';
    closeModal('modalProducto');
    toast(isEdit ? 'Actualizando…' : 'Creando producto…', 'info');

    try {
      const action = isEdit ? 'actualizarProducto' : 'crearProducto';
      const r = await API.post(action, params);
      toast(isEdit ? 'Producto actualizado ✓' : 'Producto creado ✓', 'ok');
      // [v2.41.97] Si es KGM canónico y el editor de segmentos está cargado,
      // persistir también los segmentos. Silencioso, no bloquea el flujo.
      if (isEdit && _segState && _segState.idProducto === params.idProducto) {
        const um = String(params.Unidad_Medida || params.unidad || '').toUpperCase();
        const fc = parseFloat(params.factorConversion || 1);
        if (um === 'KGM' && fc === 1) {
          segPersistirSiCambio().catch(() => {});
        }
      }
      // Refresh catálogo
      S.loaded['catalogo'] = false;
      await loadCatalogo(true);
      // Pulse en la card del producto creado/editado
      const targetId = (r && r.idProducto) || params.idProducto || '';
      if (targetId) _pulseCatalogoCard(targetId);
    } catch(e) {
      toast('Error: ' + e.message, 'error');
      // Revertir abriendo el modal de nuevo con los datos para corregir
      // (no implementado por simplicidad — el usuario puede reintentar manualmente)
    }
  }

  // Hace scroll a la card del producto y le aplica un pulso visual breve
  function _pulseCatalogoCard(idProducto) {
    setTimeout(() => {
      const eid = CSS.escape(idProducto);
      const card = document.getElementById('fc-' + eid);
      if (!card) return;
      // Scroll suave
      card.scrollIntoView({ behavior: 'smooth', block: 'center' });
      // Aplicar clase de pulso
      card.classList.remove('cat-card-pulse');
      void card.offsetWidth;  // force reflow
      card.classList.add('cat-card-pulse');
      // Quitarla cuando termine
      setTimeout(() => card.classList.remove('cat-card-pulse'), 2200);
    }, 200);
  }

  // Price modal
  function abrirModalPrecio(id) {
    const p = S.productos.find(x => x.idProducto === id);
    if (!p) { toast('Producto no encontrado', 'error'); return; }
    $('precioIdProducto').value = id;
    $('precioInfoProd').textContent = p.descripcion + (p.codigoBarra ? ' — ' + p.codigoBarra : '');
    $('precioActual').textContent = fmtMoney(p.precioVenta);
    $('precioNuevo').value = p.precioVenta || '';
    $('precioMotivo').value = '';
    $('precioMembretes').checked = false;
    openModal('modalPrecio');
  }

  async function publicarPrecio() {
    const id     = $('precioIdProducto')?.value;
    const nuevo  = parseFloat($('precioNuevo')?.value || 0);
    const motivo = $('precioMotivo')?.value || '';
    const memb   = $('precioMembretes')?.checked;

    if (!nuevo || nuevo <= 0) { toast('Ingresa un precio válido', 'error'); return; }

    const p = S.productos.find(x => x.idProducto === id);
    const prevPrecio = p?.precioVenta;
    // Optimistic update
    if (p) { p.precioVenta = nuevo; _catSaveCache({ productos: S.productos, equivMap: S.equivMap }); renderCatalogo(); }
    closeModal('modalPrecio');
    try {
      await API.post('publicarPrecio', {
        _source: 'MOS_MODAL_PRECIO',
        idProducto: id, skuBase: p?.skuBase, codigoBarra: p?.codigoBarra,
        descripcion: p?.descripcion, precioNuevo: nuevo,
        motivo, imprimirMembretes: memb
      });
      toast('Precio publicado: ' + fmtMoney(nuevo), 'ok');
      S.loaded['catalogo'] = false;
      loadCatalogo(true); // background refresh
    } catch (e) {
      if (p && prevPrecio !== undefined) { p.precioVenta = prevPrecio; renderCatalogo(); }
      toast('Error: ' + e.message, 'error');
    }
  }

  // Proveedor modal
  function abrirModalProveedor(id) {
    ['Id','Nombre','Ruc','Tel','Email','FormaPago','Plazo','Categoria','Banco','Cuenta','DiaPedido','DiaEntrega','DiaPago'].forEach(c => {
      const el = $('prov' + c);
      if (!el) return;
      if (el.tagName === 'SELECT') el.value = '';
      else el.value = '';
    });
    if (id) {
      const p = S.proveedores.find(x => x.idProveedor === id);
      if (!p) return;
      $('modalProvTitle').textContent = 'Editar Proveedor';
      $('provId').value         = p.idProveedor;
      $('provNombre').value     = p.nombre || '';
      $('provRuc').value        = p.ruc || '';
      $('provTel').value        = p.telefono || '';
      $('provEmail').value      = p.email || '';
      $('provFormaPago').value  = p.formaPago || 'CONTADO';
      $('provPlazo').value      = p.plazoCredito || '';
      $('provCategoria').value  = p.categoriaProducto || '';
      $('provBanco').value      = p.banco || '';
      $('provCuenta').value     = p.numeroCuenta || '';
      if ($('provDiaPedido'))  $('provDiaPedido').value  = (p.diaPedido  || '').toUpperCase();
      if ($('provDiaEntrega')) $('provDiaEntrega').value = (p.diaEntrega || '').toUpperCase();
      if ($('provDiaPago'))    $('provDiaPago').value    = (p.diaPago    || '').toUpperCase();
    } else {
      $('modalProvTitle').textContent = 'Nuevo Proveedor';
      $('provId').value = '';
      $('provFormaPago').value = 'CONTADO';
    }
    openModal('modalProveedor');
  }

  async function guardarProveedor() {
    const params = {
      idProveedor:      $('provId')?.value || undefined,
      nombre:           $('provNombre')?.value || '',
      ruc:              $('provRuc')?.value || '',
      telefono:         $('provTel')?.value || '',
      email:            $('provEmail')?.value || '',
      formaPago:        $('provFormaPago')?.value || 'CONTADO',
      plazoCredito:     $('provPlazo')?.value || 0,
      categoriaProducto:$('provCategoria')?.value || '',
      banco:            $('provBanco')?.value || '',
      numeroCuenta:     $('provCuenta')?.value || '',
      diaPedido:        $('provDiaPedido')?.value  || '',
      diaEntrega:       $('provDiaEntrega')?.value || '',
      diaPago:          $('provDiaPago')?.value    || ''
    };
    if (!params.nombre) { toast('El nombre es requerido', 'error'); return; }
    const isEdit = !!params.idProveedor;
    // OPTIMISTA: actualizar lista local + cerrar modal de inmediato
    const backup = (S.proveedores || []).map(p => ({ ...p }));
    if (isEdit) {
      const idx = (S.proveedores || []).findIndex(p => p.idProveedor === params.idProveedor);
      if (idx >= 0) {
        S.proveedores[idx] = { ...S.proveedores[idx],
          nombre: params.nombre, ruc: params.ruc, telefono: params.telefono,
          email: params.email, formaPago: params.formaPago, plazoCredito: params.plazoCredito,
          categoriaProducto: params.categoriaProducto, banco: params.banco, numeroCuenta: params.numeroCuenta,
          diaPedido: params.diaPedido, diaEntrega: params.diaEntrega, diaPago: params.diaPago
        };
      }
    }
    let tmpId = '';
    if (!isEdit) {
      // Insert provisional con id temporal (se reconcilia con el id real al volver el backend).
      tmpId = 'TMP_' + Date.now();
      S.proveedores = [{ idProveedor: tmpId, estado: '1', _tmp: true, ...params }, ...(S.proveedores || [])];
    }
    closeModal('modalProveedor');
    renderProveedores();
    if (S.provSelId && S.provSelId === params.idProveedor) selectProveedor(S.provSelId);
    // Efecto suave de adición (sin parpadeo): pulse en la card recién insertada.
    if (!isEdit) {
      try { if (navigator.vibrate) navigator.vibrate([20, 30, 40]); } catch (_) {}
      requestAnimationFrame(() => {
        const card = document.querySelector('[data-prov-card="' + tmpId + '"]');
        if (card) { card.classList.add('prov-card-nuevo'); setTimeout(() => card.classList.remove('prov-card-nuevo'), 900); }
      });
    }
    toast(isEdit ? 'Proveedor actualizado' : 'Proveedor creado', 'ok');
    // Sync en background (fire-and-forget con reconciliación quirúrgica, sin re-render global que parpadee)
    try {
      const action = isEdit ? 'actualizarProveedor' : 'crearProveedor';
      const r = await API.post(action, params);
      // Si fue creación: reemplazar el id temporal por el id real EN SITIO (sin recargar toda la lista,
      // así no se pierde el orden optimista ni se produce flash). API.post devuelve data directo.
      if (!isEdit) {
        const realId = r && (r.idProveedor || (r.data && r.data.idProveedor));
        const rec = (S.proveedores || []).find(p => p.idProveedor === tmpId);
        if (rec) { if (realId) rec.idProveedor = realId; delete rec._tmp; }
        if (S.provSelId === tmpId && realId) S.provSelId = realId;
        renderProveedores();
      }
    } catch (e) {
      // Revertir en error
      S.proveedores = backup;
      if (S.provSelId === tmpId) S.provSelId = null;
      renderProveedores();
      toast('Error de sincronización: ' + e.message, 'error');
    }
  }

  // Pago modal
  function abrirModalPago(idProveedor) {
    $('pagoIdProveedor').value = idProveedor;
    $('pagoMonto').value  = '';
    $('pagoFactura').value = '';
    $('pagoFecha').value  = today();
    $('pagoObs').value    = '';
    openModal('modalPago');
  }

  async function guardarPago() {
    const params = {
      idProveedor:    $('pagoIdProveedor')?.value,
      monto:          $('pagoMonto')?.value,
      numeroFactura:  $('pagoFactura')?.value || '',
      fecha:          $('pagoFecha')?.value || today(),
      observacion:    $('pagoObs')?.value || ''
    };
    if (!params.monto || parseFloat(params.monto) <= 0) { toast('Ingresa un monto válido', 'error'); return; }
    // OPTIMISTA: cerrar modal + insertar pago temporal en cache
    const id = params.idProveedor;
    S.provPagos = S.provPagos || {};
    const tmpPago = {
      idPago:        'PAG_TMP_' + Date.now(),
      idProveedor:   id,
      monto:         parseFloat(params.monto),
      fecha:         params.fecha,
      numeroFactura: params.numeroFactura,
      estado:        'PAGADO',
      observacion:   params.observacion,
      _tmp:          true
    };
    const backup = (S.provPagos[id] || []).slice();
    S.provPagos[id] = [tmpPago, ...(S.provPagos[id] || [])];
    closeModal('modalPago');
    if (S.provSelId === id && S.provTab === 'info') _renderProvInfo();
    toast('Pago registrado: ' + fmtMoney(params.monto), 'ok');
    try {
      await API.post('registrarPago', params);
      // Refresh real
      const r = await API.get('getPagos', { idProveedor: id });
      S.provPagos[id] = Array.isArray(r) ? r : (r && r.data) || [];
      if (S.provSelId === id && S.provTab === 'info') _renderProvInfo();
    } catch (e) {
      S.provPagos[id] = backup;
      if (S.provSelId === id && S.provTab === 'info') _renderProvInfo();
      toast('Error de sincronización: ' + e.message, 'error');
    }
  }

  // ── PEDIDO MODAL ────────────────────────────────────────────
  let _pedidoState = { items: [], idProveedor: null };

  async function abrirModalPedido(idProveedor) {
    if (!idProveedor) return;
    _pedidoState = { items: [], idProveedor: idProveedor };
    const prov = (S.proveedores || []).find(p => p.idProveedor === idProveedor);
    $('pedidoIdProveedor').value = idProveedor;
    $('pedidoProveedorNombre').textContent = prov ? prov.nombre : idProveedor;
    $('pedidoBuscar').value = '';
    $('pedidoBuscarRes').style.display = 'none';
    $('pedidoFechaEst').value = '';
    $('pedidoNotas').value = '';
    _renderPedidoItems();
    // Si vino con producto sugerido (desde insight), pre-cargar
    if (S._pedidoSugerido) {
      _pedidoState.items.push({
        skuBase:     S._pedidoSugerido.skuBase || S._pedidoSugerido.idProducto,
        codigoBarra: S._pedidoSugerido.codigoBarra || '',
        descripcion: S._pedidoSugerido.descripcion || '',
        cantidad:    1,
        precio:      S._pedidoSugerido.precioReferencia || 0
      });
      S._pedidoSugerido = null;
      _renderPedidoItems();
    }
    openModal('modalPedido');
  }

  function cerrarModalPedido() { closeModal('modalPedido'); }

  let _pedidoBuscarTimer = null;
  async function pedidoBuscarItem() {
    clearTimeout(_pedidoBuscarTimer);
    _pedidoBuscarTimer = setTimeout(async () => {
      const q = ($('pedidoBuscar').value || '').trim();
      const resBox = $('pedidoBuscarRes');
      if (!q) { resBox.style.display = 'none'; return; }
      try {
        const items = await API.get('getProveedorProductos', { idProveedor: _pedidoState.idProveedor });
        const lista = Array.isArray(items) ? items : (items && items.data) || [];
        const qn = _norm(q);
        const palabras = qn.split(/\s+/).filter(Boolean);
        const filtered = lista.filter(pp => {
          const hay = _norm((pp.descripcion || '') + ' ' + (pp.skuBase || '') + ' ' + (pp.codigoBarra || ''));
          return palabras.every(w => hay.indexOf(w) >= 0);
        }).slice(0, 8);
        if (!filtered.length) {
          resBox.innerHTML = '<div class="pn-result text-slate-500 italic">Sin coincidencias</div>';
          resBox.style.display = 'block';
          return;
        }
        resBox.innerHTML = filtered.map(pp => {
          const safeDesc = (pp.descripcion || pp.skuBase).replace(/'/g, "\\'");
          return `<div class="pn-result" onclick="MOS.pedidoAgregarItem('${pp.skuBase}', '${pp.codigoBarra || ''}', '${safeDesc}', ${pp.precioReferencia || 0})">
            <div class="text-slate-200 font-medium text-sm">${pp.descripcion || pp.skuBase}</div>
            <div class="text-slate-500 text-xs flex justify-between"><span style="font-family:monospace">${pp.skuBase}</span><span class="text-amber-400">${fmtMoney(pp.precioReferencia || 0)}</span></div>
          </div>`;
        }).join('');
        resBox.style.display = 'block';
      } catch(_){}
    }, 200);
  }

  function pedidoAgregarItem(sku, cb, desc, precio) {
    const existe = _pedidoState.items.find(it => it.skuBase === sku);
    if (existe) { existe.cantidad++; }
    else _pedidoState.items.push({ skuBase: sku, codigoBarra: cb, descripcion: desc, cantidad: 1, precio: parseFloat(precio) || 0 });
    $('pedidoBuscar').value = '';
    $('pedidoBuscarRes').style.display = 'none';
    _renderPedidoItems();
  }

  function pedidoQuitarItem(idx) {
    _pedidoState.items.splice(idx, 1);
    _renderPedidoItems();
  }

  function pedidoCambiarQty(idx, qty) {
    const q = Math.max(0, parseInt(qty) || 0);
    if (q === 0) { _pedidoState.items.splice(idx, 1); }
    else _pedidoState.items[idx].cantidad = q;
    _renderPedidoItems();
  }

  function _renderPedidoItems() {
    const list = $('pedidoItemsList');
    const cnt = $('pedidoItemsCount');
    if (!list) return;
    if (cnt) cnt.textContent = '(' + _pedidoState.items.length + ')';
    if (!_pedidoState.items.length) {
      list.innerHTML = '<div class="text-xs text-slate-600 italic text-center py-3">Sin items aún. Busca productos arriba.</div>';
      $('pedidoTotal').value = 'S/ 0.00';
      return;
    }
    let total = 0;
    list.innerHTML = _pedidoState.items.map((it, i) => {
      const sub = (it.cantidad || 0) * (it.precio || 0);
      total += sub;
      return `<div class="flex items-center gap-2 p-2 rounded" style="background:#0d1526">
        <div class="min-w-0 flex-1">
          <div class="text-sm text-slate-200 truncate">${it.descripcion}</div>
          <div class="text-[10px] text-slate-500 font-mono">${it.skuBase} · ${fmtMoney(it.precio)}</div>
        </div>
        <input type="number" min="0" step="1" class="inp text-xs" style="width:60px;text-align:center" value="${it.cantidad}" onchange="MOS.pedidoCambiarQty(${i}, this.value)">
        <div class="text-xs text-amber-400 font-semibold whitespace-nowrap" style="width:60px;text-align:right">${fmtMoney(sub)}</div>
        <button onclick="MOS.pedidoQuitarItem(${i})" class="text-rose-400 text-base p-1" title="Quitar">×</button>
      </div>`;
    }).join('');
    $('pedidoTotal').value = fmtMoney(total);
  }

  async function guardarPedido() {
    if (!_pedidoState.idProveedor) { toast('Falta proveedor', 'error'); return; }
    if (!_pedidoState.items.length) { toast('Agrega al menos 1 item', 'error'); return; }
    const total = _pedidoState.items.reduce((s, it) => s + (it.cantidad || 0) * (it.precio || 0), 0);
    try {
      await API.post('crearPedido', {
        idProveedor:    _pedidoState.idProveedor,
        items:          _pedidoState.items,
        montoEstimado:  total,
        fechaEstimada:  $('pedidoFechaEst').value || '',
        notas:          $('pedidoNotas').value || '',
        usuario:        S.session?.nombre || ''
      });
      toast('Pedido borrador creado ✓', 'ok');
      closeModal('modalPedido');
      // Refrescar pedidos del proveedor si la vista está abierta
      if (S.provSelId === _pedidoState.idProveedor && S.provTab === 'pedidos') {
        S.provPedidos[_pedidoState.idProveedor] = null;
        _renderProvPedidos();
      }
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  // ── Selector de proveedor desde insight de almacén ──
  async function _almGenerarPedidoFromInsight(idProducto, descripcion, skuBase, codigoBarra) {
    try {
      const r = await API.get('getProveedoresQueVenden', { skuBase: skuBase || idProducto, codigoBarra: codigoBarra || '' });
      const provs = (r && r.data) ? r.data : (r || []);
      if (!provs.length) {
        toast('Este producto no tiene proveedores registrados. Agrégalo en Proveedores → Productos.', 'error');
        return;
      }
      // Guardar producto sugerido para pre-cargar en el modal
      S._pedidoSugerido = {
        idProducto, descripcion, skuBase: skuBase || idProducto, codigoBarra: codigoBarra || '',
        precioReferencia: provs[0].precioReferencia
      };
      if (provs.length === 1) {
        // Directo al modal de pedido
        await abrirModalPedido(provs[0].idProveedor);
        return;
      }
      // Mostrar selector
      $('selProvProducto').textContent = descripcion || idProducto;
      $('selProvList').innerHTML = provs.map(p => `
        <div class="card-sm p-3 cursor-pointer hover:border-amber-500/40 transition-colors" onclick="MOS._almPickProveedor('${p.idProveedor}')">
          <div class="flex items-center justify-between gap-2">
            <div class="min-w-0 flex-1">
              <div class="text-sm font-semibold text-slate-200 truncate">${p.nombreProveedor}</div>
              <div class="text-xs text-slate-500">mín ${p.minimoCompra || 0} · ${p.diasEntrega || 0}d entrega</div>
            </div>
            <div class="text-amber-400 text-sm font-bold whitespace-nowrap shrink-0">${fmtMoney(p.precioReferencia)}</div>
          </div>
        </div>
      `).join('');
      openModal('modalSelProveedor');
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }
  async function _almPickProveedor(idProveedor) {
    closeModal('modalSelProveedor');
    await abrirModalPedido(idProveedor);
  }
  function cerrarSelProveedor() { closeModal('modalSelProveedor'); }

  // ── CONFIGURACIÓN ────────────────────────────────────────────
  let cfgData = { zonas: [], estaciones: [], impresoras: [], personal: [], personalMOS: [], series: [], dispositivos: [], categorias: [], personalMaster: [] };

  // ════════════════════════════════════════════════════════
  // CONFIGURACIÓN — sistema cache + prefetch + auto-refresh
  // (mismo patrón que Almacén)
  // ════════════════════════════════════════════════════════
  const CFG_CACHE_PFX = 'mos_cfg_';
  const CFG_CACHE_TTL = 30 * 60 * 1000; // 30 min

  function _cfgLoadCache(key) {
    try {
      const raw = localStorage.getItem(CFG_CACHE_PFX + key);
      if (!raw) return null;
      const p = JSON.parse(raw);
      if (Date.now() - (p.ts || 0) > CFG_CACHE_TTL) return null;
      return p.data;
    } catch { return null; }
  }
  function _cfgSaveCache(key, data) {
    try { localStorage.setItem(CFG_CACHE_PFX + key, JSON.stringify({ ts: Date.now(), data })); } catch {}
  }

  // Hidrata cfgData desde localStorage (instantáneo)
  function _cfgHidratarTodos() {
    const z = _cfgLoadCache('zonas');        if (z) cfgData.zonas        = z;
    const e = _cfgLoadCache('estaciones');   if (e) cfgData.estaciones   = e;
    const i = _cfgLoadCache('impresoras');   if (i) cfgData.impresoras   = i;
    const p = _cfgLoadCache('personal');     if (p) cfgData.personal     = p;
    const m = _cfgLoadCache('personalMOS');  if (m) cfgData.personalMOS  = m;
    const b = _cfgLoadCache('bloqueosME');   if (b) cfgData.bloqueosME   = b;
    const s = _cfgLoadCache('series');       if (s) cfgData.series       = s;
    const d = _cfgLoadCache('dispositivos'); if (d) cfgData.dispositivos = d;
    const c = _cfgLoadCache('categorias');   if (c) cfgData.categorias   = c;
    const f = _cfgLoadCache('config');       if (f) cfgData.config       = f;
    return !!(z || e || i || p || m || b || s || d || c || f);
  }

  // Prefetch al login: descarga TODO en paralelo y cachea (corre en background)
  function _cfgPrefetch() {
    setTimeout(() => {
      if (!S.session) return;
      iconBusy('config', true);
      const tasks = [
        API.get('getZonas', {}).then(r => { if (r) { cfgData.zonas = r; _cfgSaveCache('zonas', r); } }).catch(() => {}),
        API.get('getEstaciones', {}).then(r => { if (r) { cfgData.estaciones = r; _cfgSaveCache('estaciones', r); } }).catch(() => {}),
        API.get('getImpresoras', {}).then(r => { if (r) { cfgData.impresoras = r; _cfgSaveCache('impresoras', r); } }).catch(() => {}),
        API.get('getPersonalMaster', { appOrigen: 'warehouseMos' }).then(r => { if (r) { cfgData.personal = r; _cfgSaveCache('personal', r); } }).catch(() => {}),
        API.get('getPersonalMaster', { appOrigen: 'MOS' }).then(r => { if (r) { cfgData.personalMOS = r; _cfgSaveCache('personalMOS', r); } }).catch(() => {}),
        API.get('getVendedoresMEBloqueados', {}).then(r => { if (r) { cfgData.bloqueosME = r; _cfgSaveCache('bloqueosME', r); } }).catch(() => {}),
        API.get('getSeries', {}).then(r => { if (r) { cfgData.series = r; _cfgSaveCache('series', r); } }).catch(() => {}),
        API.get('getDispositivos', {}).then(r => { if (r) { cfgData.dispositivos = _dispAplicarShield(r); _cfgSaveCache('dispositivos', cfgData.dispositivos); } }).catch(() => {}),
        API.get('getCategorias', {}).then(r => { if (r) { cfgData.categorias = r; _cfgSaveCache('categorias', r); } }).catch(() => {}),
        API.get('getConfig', {}).then(r => { if (r) { cfgData.config = r; _cfgSaveCache('config', r); } }).catch(() => {})
      ];
      Promise.all(tasks).finally(() => {
        iconBusy('config', false);
        S._cfgPrecargado = true;
        // Si el usuario ya está viendo configuración, re-renderizar
        if (S.view === 'config') renderCfgTab(S.cfgTab || 'infra');
      });
    }, 1500);
  }

  // Auto-refresh global cada 60s mientras módulo configuración visible
  let _cfgAutoTimer = null;
  function _cfgIniciarAutoRefresh() {
    if (_cfgAutoTimer) clearInterval(_cfgAutoTimer);
    _cfgAutoTimer = setInterval(() => {
      if (!S.session || S.view !== 'config') return;
      if (document.visibilityState !== 'visible') return;
      _cfgRefreshSilencioso();
    }, 60 * 1000);
  }
  function _cfgDetenerAutoRefresh() {
    if (_cfgAutoTimer) { clearInterval(_cfgAutoTimer); _cfgAutoTimer = null; }
  }
  // Refresh silencioso — solo recarga lo que afecta la pestaña activa
  async function _cfgRefreshSilencioso() {
    iconBusy('config', true);
    try {
      const tab = S.cfgTab || 'infra';
      const tasks = [];
      // Datos compartidos (siempre)
      tasks.push(API.get('getZonas', {}).then(r => { if (r) { cfgData.zonas = r; _cfgSaveCache('zonas', r); } }).catch(() => {}));
      tasks.push(API.get('getEstaciones', {}).then(r => { if (r) { cfgData.estaciones = r; _cfgSaveCache('estaciones', r); } }).catch(() => {}));
      // Por pestaña
      if (tab === 'infra') {
        tasks.push(API.get('getImpresoras', {}).then(r => { if (r) { cfgData.impresoras = r; _cfgSaveCache('impresoras', r); } }).catch(() => {}));
        tasks.push(API.get('getDispositivos', {}).then(r => { if (r) { cfgData.dispositivos = _dispAplicarShield(r); _cfgSaveCache('dispositivos', cfgData.dispositivos); } }).catch(() => {}));
        tasks.push(API.get('getSeries', {}).then(r => { if (r) { cfgData.series = r; _cfgSaveCache('series', r); } }).catch(() => {}));
      }
      if (tab === 'personal') {
        tasks.push(API.get('getPersonalMaster', { appOrigen: 'warehouseMos' }).then(r => { if (r) { cfgData.personal = r; _cfgSaveCache('personal', r); } }).catch(() => {}));
        tasks.push(API.get('getPersonalMaster', { appOrigen: 'MOS' }).then(r => { if (r) { cfgData.personalMOS = r; _cfgSaveCache('personalMOS', r); } }).catch(() => {}));
        tasks.push(API.get('getVendedoresMEBloqueados', {}).then(r => { if (r) { cfgData.bloqueosME = r; _cfgSaveCache('bloqueosME', r); } }).catch(() => {}));
        tasks.push(API.get('getDispositivos', {}).then(r => { if (r) { cfgData.dispositivos = _dispAplicarShield(r); _cfgSaveCache('dispositivos', cfgData.dispositivos); } }).catch(() => {}));
      }
      if (tab === 'categorias') {
        tasks.push(API.get('getCategorias', {}).then(r => { if (r) { cfgData.categorias = r; _cfgSaveCache('categorias', r); } }).catch(() => {}));
      }
      await Promise.all(tasks);
      // Re-render solo si la pestaña sigue activa
      if (S.view === 'config') renderCfgTab(S.cfgTab || 'infra');
    } finally {
      iconBusy('config', false);
    }
  }

  async function loadConfig() {
    S.cfgTab = S.cfgTab || 'infra';
    // [v2.43.32] Pre-carga horarios en background (no espera) — para que al
    // abrir el tab Personal o el modal, ya estén disponibles instantáneos.
    if (!S._horariosAppsCache) {
      _cargarHorariosApps(true).catch(() => {});
    }
    // [v2.43.37] Pre-cargar rotación semanal WH para el catálogo.
    // Esto hace que al entrar a Catálogo el sparkline aparezca instantáneo.
    if (!S._rotacionSemanalCache) {
      _cargarRotacionSemanal(true).catch(() => {});
    }
    // 1) Hidratar inmediato desde cache (zero spinner para usuarios recurrentes)
    const huboCache = _cfgHidratarTodos();
    if (huboCache) renderCfgTab(S.cfgTab);
    // 2) Si ya se prefetcheó al login, no reabrir red — lo nuevo viene del auto-refresh
    if (S._cfgPrecargado) {
      _cfgIniciarAutoRefresh();
      return;
    }
    // 3) Primera vez: pedir fresh en paralelo (con loading icon)
    iconBusy('config', true);
    try {
      const [zonRes, estRes, impRes, persRes, persMOSRes, bloqMERes, serRes, dispRes, catRes, cfgRes] = await Promise.allSettled([
        API.get('getZonas', {}),
        API.get('getEstaciones', {}),
        API.get('getImpresoras', {}),
        API.get('getPersonalMaster', { appOrigen: 'warehouseMos' }),
        API.get('getPersonalMaster', { appOrigen: 'MOS' }),
        API.get('getVendedoresMEBloqueados', {}),
        API.get('getSeries', {}),
        API.get('getDispositivos', {}),
        API.get('getCategorias', {}),
        API.get('getConfig', {})
      ]);
      const _set = (k, res) => {
        if (res.status === 'fulfilled') {
          cfgData[k] = res.value || (k === 'config' ? {} : []);
          _cfgSaveCache(k, cfgData[k]);
        } else if (cfgData[k] === undefined) {
          cfgData[k] = (k === 'config' ? {} : []);
        }
      };
      _set('zonas', zonRes);
      _set('estaciones', estRes);
      _set('impresoras', impRes);
      _set('personal', persRes);
      _set('personalMOS', persMOSRes);
      _set('bloqueosME', bloqMERes);
      _set('series', serRes);
      _set('dispositivos', dispRes);
      _set('categorias', catRes);
      _set('config', cfgRes);
      S._cfgPrecargado = true;
      renderCfgTab(S.cfgTab);
    } finally {
      iconBusy('config', false);
      _cfgIniciarAutoRefresh();
    }
  }

  function setCfgTab(tab) {
    S.cfgTab = tab;
    const tabs = ['infra','personal','categorias','notifs'];
    tabs.forEach(t => {
      const btn = $('cfgTab' + t.charAt(0).toUpperCase() + t.slice(1));
      if (btn) btn.classList.toggle('active', t === tab);
      const panel = $('cfgPanel' + t.charAt(0).toUpperCase() + t.slice(1));
      if (panel) panel.classList.toggle('hidden', t !== tab);
    });
    renderCfgTab(tab);
  }

  function renderCfgTab(tab) {
    if (tab === 'infra')        _arrancarRefreshInfra();
    else                        _detenerRefreshInfra();
    if (tab === 'personal')     _arrancarRefreshPersonal();
    else                        _detenerRefreshPersonal();
    switch (tab) {
      case 'infra':        renderInfra(); break;
      case 'personal':     renderPersonal();     break;
      case 'categorias':   renderCategorias();   break;
      case 'notifs':       renderNotifsPanel();  break;
    }
  }

  // ── Tarjeta de presentación: modal de números WhatsApp (+51 fijo, solo 9 dígitos) ──
  // Guardado: se prepende '51' (Perú) → se almacena 51XXXXXXXXX (formato wa.me). En pantalla solo los 9 dígitos.
  function abrirTarjetaModal() { openModal('modalTarjetaWA'); cargarTarjetaWA(); }
  function _twaLocal(v) {       // 51XXXXXXXXX -> XXXXXXXXX (oculta placeholder de ceros)
    v = String(v || '').replace(/\D/g, '');
    if (v.slice(0, 2) === '51' && v.length >= 11) v = v.slice(2);
    return /^0*$/.test(v) ? '' : v;
  }
  // [Lote3-A · A2-MOS] estado de la última carga: si falló, NO se puede guardar a
  // ciegas (guardar con campos vacíos BORRARÍA los números en producción). _twaOrig
  // guarda lo cargado para detectar si un número con valor se está vaciando.
  let _twaCargaOk = false;
  let _twaOrig = { com: '', prov: '', marca: '' };
  async function cargarTarjetaWA() {
    _twaCargaOk = false;
    const sb = $('btnTwaSave'); if (sb) { sb.disabled = false; sb.title = ''; }
    try {
      const d = await API.get('getTarjetaWA', {});   // d = { TARJETA_WA_COMERCIAL, TARJETA_WA_COMPRAS, TARJETA_MARCA }
      const com = _twaLocal(d && d.TARJETA_WA_COMERCIAL);
      const prov = _twaLocal(d && d.TARJETA_WA_COMPRAS);
      const mar = (d && d.TARJETA_MARCA) || '';
      const c = $('twaComercial'); if (c) c.value = com;
      const p = $('twaCompras');   if (p) p.value = prov;
      const m = $('twaMarca');     if (m) m.value = mar;
      _twaOrig = { com, prov, marca: mar };
      _twaCargaOk = true;
    } catch (_) {
      // Carga falló → bloquear Guardar (reabrir el modal con red reintenta).
      if (sb) { sb.disabled = true; sb.title = 'No se pudo cargar — reabre con conexión'; }
      toast('No se pudo cargar la tarjeta. Reintenta con conexión antes de guardar.', 'warn');
    }
  }
  function _twaFeedbackOk(btn) {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const o = ctx.createOscillator(), g = ctx.createGain();
      o.connect(g); g.connect(ctx.destination); o.type = 'sine';
      o.frequency.setValueAtTime(660, ctx.currentTime);
      o.frequency.exponentialRampToValueAtTime(990, ctx.currentTime + 0.12);
      g.gain.setValueAtTime(0.25, ctx.currentTime);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.18);
      o.start(); o.stop(ctx.currentTime + 0.19);
    } catch (_) {}
    try { if (navigator.vibrate) navigator.vibrate([30, 40, 30]); } catch (_) {}
    if (btn) {
      btn.disabled = false; btn.innerHTML = '✓ ¡Guardado!';
      btn.style.background = 'linear-gradient(135deg,#059669,#047857)';
      setTimeout(() => { btn.innerHTML = '💾 Guardar'; btn.style.background = 'linear-gradient(135deg,#4f46e5,#7c3aed)'; }, 1600);
    }
  }
  async function guardarTarjetaWA() {
    const btn = $('btnTwaSave');
    // [Lote3-A · A2-MOS] no guardar si la carga falló: los inputs no reflejan el
    // estado real → guardar los borraría. Forzar reabrir con red.
    if (!_twaCargaOk) { toast('Reabre el modal con conexión antes de guardar (la carga falló)', 'error'); return; }
    const dig = id => (($(id) || {}).value || '').replace(/\D/g, '');
    const comLocal = dig('twaComercial'), provLocal = dig('twaCompras');
    const marca = (($('twaMarca') || {}).value || '').trim();
    if (comLocal && comLocal.length !== 9)  { toast('El número de clientes debe tener 9 dígitos', 'error'); return; }
    if (provLocal && provLocal.length !== 9) { toast('El número de proveedores debe tener 9 dígitos', 'error'); return; }
    // [Lote3-A · A2-MOS] si un número que TENÍA valor quedó vacío, confirmar (borrado accidental)
    const vaciaCom = _twaOrig.com && !comLocal;
    const vaciaProv = _twaOrig.prov && !provLocal;
    if (vaciaCom || vaciaProv) {
      const cuales = [vaciaCom ? 'clientes' : '', vaciaProv ? 'proveedores' : ''].filter(Boolean).join(' y ');
      const ok = await _modalConfirm('Vas a dejar SIN número de WhatsApp de ' + cuales + '.\n\nLas tarjetas impresas ya no tendrán a quién enviar. ¿Continuar?', { warning: true, titulo: 'Borrar número' });
      if (!ok) return;
    }
    const full = n => n ? ('51' + n) : '';
    if (btn) { btn.disabled = true; btn.innerHTML = '⏳ Guardando…'; }
    try {
      // [Lote3-A · A1-MOS] r = data desempaquetado = { comercial, compras, marca, supabaseOk }.
      // supabaseOk=false → CONFIG_MOS se guardó pero mos.config (lo que leen las tarjetas
      // del POS) NO → antes el toast decía "¡Listo!" igual y el POS imprimía el número viejo.
      const r = await API.post('guardarTarjetaWA', { comercial: full(comLocal), compras: full(provLocal), marca });
      if (r && r.supabaseOk === false) {
        toast('⚠ Guardado en MOS pero NO llegó a las tarjetas del POS. Reintenta con red.', 'error');
        if (btn) { btn.disabled = false; btn.innerHTML = '💾 Guardar'; }
        return;   // NO cerrar el modal: el cambio no está completo
      }
      // refrescar el snapshot original (lo guardado es ahora la verdad)
      _twaOrig = { com: comLocal, prov: provLocal, marca };
      _twaFeedbackOk(btn);
      toast('¡Listo! Las tarjetas ya usan los números nuevos ✅', 'ok');
      setTimeout(() => closeModal('modalTarjetaWA'), 900);
    } catch (e) {
      toast((e && e.message) || 'No se pudo guardar', 'error');
      if (btn) { btn.disabled = false; btn.innerHTML = '💾 Guardar'; }
    }
  }

  // ════════════════════════════════════════════════════════════
  // NOTIFICACIONES — pestaña Configuraciones (solo Master edita)
  // ════════════════════════════════════════════════════════════
  const _notifState = {
    items: [],
    filtroOrigen: 'all',
    filtroEstado: 'all',
    log: [],
    expandido: {},
    cargado: false
  };
  const NOTIF_ROLES_DISP = [
    { key: 'MASTER',     label: 'Master',     cls: 'master' },
    { key: 'ADMIN',      label: 'Admin',      cls: 'admin' },
    { key: 'CAJERO',     label: 'Cajeros',    cls: 'cajero' },
    { key: 'VENDEDOR',   label: 'Vendedores', cls: 'cajero' },
    { key: 'ALMACENERO', label: 'Almaceneros',cls: 'almacen' },
    { key: 'ENVASADOR',  label: 'Envasadores',cls: 'almacen' }
  ];

  function _notifIsMaster() {
    const rol = String(S.session?.rol || '').toUpperCase();
    return rol === 'MASTER';
  }

  async function renderNotifsPanel() {
    const cont = $('notifsList');
    if (!cont) return;
    // Mostrar permiso badge
    const badge = $('notifsPermisoBadge');
    if (badge) {
      if (_notifIsMaster()) {
        badge.textContent = '✓ Modo edición Master';
        badge.style.color = '#34d399';
      } else {
        badge.textContent = 'Solo Master puede editar (estás en modo lectura)';
        badge.style.color = '#fbbf24';
      }
    }
    if (!_notifState.cargado) {
      cont.innerHTML = `<div class="text-center py-12 text-slate-500 text-sm">
        <div class="inline-block animate-spin">⏳</div> Cargando catálogo...
      </div>`;
      try {
        const res = await API.get('getNotificacionesConfig', {});
        _notifState.items = Array.isArray(res) ? res : ((res && res.data) || []);
        _notifState.cargado = true;
      } catch(e) {
        cont.innerHTML = `<div class="text-center py-12 text-rose-400 text-sm">⚠ Error: ${e.message || e}</div>`;
        return;
      }
    }
    _renderNotifs();
  }

  async function refreshNotifs(ev) {
    if (ev && typeof _evalRipple === 'function') _evalRipple(ev);
    _notifState.cargado = false;
    if (typeof _evalSfx === 'function') _evalSfx('tap');
    await renderNotifsPanel();
  }

  function notifSetFiltro(origen, ev) {
    _notifState.filtroOrigen = origen;
    document.querySelectorAll('#notifsFilterBar [data-f]').forEach(b =>
      b.classList.toggle('active', b.dataset.f === origen));
    if (typeof _evalSfx === 'function') _evalSfx('switch');
    _renderNotifs();
  }
  function notifSetEstado(estado, ev) {
    _notifState.filtroEstado = estado;
    document.querySelectorAll('#notifsFilterBar [data-e]').forEach(b =>
      b.classList.toggle('active', b.dataset.e === estado));
    if (typeof _evalSfx === 'function') _evalSfx('switch');
    _renderNotifs();
  }

  function _notifFiltrar(items) {
    return items.filter(it => {
      if (_notifState.filtroOrigen !== 'all' && String(it.origen).toUpperCase() !== _notifState.filtroOrigen) return false;
      const activa = !!it.activa;
      if (_notifState.filtroEstado === 'ON'  && !activa) return false;
      if (_notifState.filtroEstado === 'OFF' &&  activa) return false;
      return true;
    });
  }

  function _renderNotifs() {
    const cont = $('notifsList');
    if (!cont) return;
    const items = _notifFiltrar(_notifState.items || []);
    if (!items.length) {
      cont.innerHTML = `<div class="text-center py-10 text-slate-500 text-sm">
        <div class="text-3xl mb-2 opacity-50">🔕</div>
        Sin notificaciones que coincidan con el filtro
      </div>`;
      return;
    }
    // Agrupar por origen
    const grupos = { MOS: [], ME: [], WH: [] };
    items.forEach(it => {
      const o = String(it.origen).toUpperCase();
      (grupos[o] || (grupos[o] = [])).push(it);
    });
    const titulos = { MOS: '🎯 MOS · Sistema y administración', ME: '🛒 MosExpress · POS', WH: '🏭 warehouseMos · Almacén' };
    let html = '';
    let idx = 0;
    ['MOS','ME','WH'].forEach(o => {
      const arr = grupos[o] || [];
      if (!arr.length) return;
      html += `<div class="text-[10px] font-bold uppercase tracking-wider text-slate-400 mt-3 mb-2 px-1">${titulos[o]}</div>`;
      arr.forEach(it => { html += _notifCard(it, idx++); });
    });
    cont.innerHTML = html;
  }

  function _notifCard(n, idx) {
    const isOn = !!n.activa;
    const expandido = !!_notifState.expandido[n.idNotif];
    const silenciada = n.silenciada_hasta && new Date(n.silenciada_hasta).getTime() > Date.now();
    const prioridad = String(n.prioridad || 'normal').toLowerCase();
    const cardCls = [
      'notif-card',
      !isOn ? 'silenciada' : '',
      prioridad === 'alta' ? 'alta' : '',
      expandido ? 'expanded' : ''
    ].filter(Boolean).join(' ');
    const silenciaTxt = silenciada ? `<span class="text-[10px] text-amber-400 ml-1">🔕 hasta ${new Date(n.silenciada_hasta).toLocaleString('es-PE', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit' })}</span>` : '';
    const rolesSet = new Set(String(n.audiencia_roles || '').split(',').map(s => s.trim().toUpperCase()).filter(Boolean));
    const usuariosExtra = String(n.audiencia_usuarios || '').split(',').map(s => s.trim()).filter(Boolean);

    const chipsRoles = NOTIF_ROLES_DISP.map(r => {
      const on = rolesSet.has(r.key);
      return `<span class="notif-rol-chip ${r.cls}${on ? ' on' : ''}"
                onclick="MOS._notifToggleRol('${n.idNotif}', '${r.key}', event)">${r.label}</span>`;
    }).join(' ');

    // Body SIEMPRE renderizado — se oculta/muestra con CSS (sin reflow ni parpadeo)
    return `
      <div class="${cardCls}" style="--i:${Math.min(idx,18)}" data-id="${n.idNotif}">
        <div class="flex items-center gap-3 cursor-pointer" onclick="MOS._notifToggleExpand('${n.idNotif}', event)">
          <span style="font-size:22px">${n.icono || '🔔'}</span>
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-2 flex-wrap">
              <span class="font-semibold text-slate-100 text-sm truncate">${n.titulo}</span>
              ${prioridad === 'alta' ? '<span class="text-[9px] text-rose-400 font-bold">🚨 ALTA</span>' : ''}
              ${silenciaTxt}
            </div>
            <div class="text-[11px] text-slate-500 mt-0.5">${n.descripcion || ''}</div>
            <div class="flex items-center gap-1 mt-1 flex-wrap">
              ${Array.from(rolesSet).slice(0,3).map(r => `<span class="text-[9px] text-slate-500">· ${r}</span>`).join('')}
              ${usuariosExtra.length ? `<span class="text-[9px] text-emerald-400">+${usuariosExtra.length} usuario(s) extra</span>` : ''}
            </div>
          </div>
          <div class="notif-toggle ${isOn ? 'on' : ''}"
               onclick="event.stopPropagation();MOS._notifToggleActiva('${n.idNotif}', event)"
               title="${isOn ? 'Activa' : 'Silenciada'}"></div>
          <span class="notif-card-chevron">▸</span>
        </div>
        <div class="notif-card-body space-y-3">
          <div>
            <div class="text-[10px] uppercase tracking-wider text-slate-500 font-bold mb-1.5">👥 Audiencia por rol</div>
            <div class="flex flex-wrap gap-1.5">${chipsRoles}</div>
          </div>
          <div>
            <div class="text-[10px] uppercase tracking-wider text-slate-500 font-bold mb-1.5">➕ Usuarios específicos (extra)</div>
            <input type="text" class="inp text-xs"
                   id="notifExtra_${n.idNotif}"
                   placeholder="Nombres separados por coma (ej: Carlos, Jorgenis)"
                   value="${usuariosExtra.join(', ').replace(/"/g, '&quot;')}"
                   onchange="MOS._notifSetExtra('${n.idNotif}', this.value)">
          </div>
          <div class="grid grid-cols-2 gap-3">
            <div>
              <div class="text-[10px] uppercase tracking-wider text-slate-500 font-bold mb-1.5">⚡ Prioridad</div>
              <div class="flex gap-1">
                ${['baja','normal','alta'].map(p => {
                  const on = prioridad === p ? ' on ' + p + '-on' : ' ' + p + '-on';
                  return `<span class="notif-priority-pill${on}" onclick="MOS._notifSetPrioridad('${n.idNotif}', '${p}', event)">${p.toUpperCase()}</span>`;
                }).join('')}
              </div>
            </div>
            <div>
              <div class="text-[10px] uppercase tracking-wider text-slate-500 font-bold mb-1.5">🚫 Excluir origen</div>
              <label class="flex items-center gap-2 text-xs cursor-pointer">
                <input type="checkbox" ${n.excluir_origen ? 'checked' : ''}
                       style="width:14px;height:14px;accent-color:#fbbf24;cursor:pointer"
                       onchange="MOS._notifSetExcluir('${n.idNotif}', this.checked)">
                <span class="text-slate-300">Quien dispara no recibe</span>
              </label>
            </div>
          </div>
          <div>
            <div class="text-[10px] uppercase tracking-wider text-slate-500 font-bold mb-1.5">🔕 Silenciar temporal</div>
            <div class="flex gap-1 flex-wrap">
              <button onclick="MOS._notifSilenciar('${n.idNotif}','1h', event)"     class="btn-ghost btn-ripple text-[10px] px-2 py-1">1 hora</button>
              <button onclick="MOS._notifSilenciar('${n.idNotif}','manana', event)" class="btn-ghost btn-ripple text-[10px] px-2 py-1">Mañana 8am</button>
              <button onclick="MOS._notifSilenciar('${n.idNotif}','lunes', event)"  class="btn-ghost btn-ripple text-[10px] px-2 py-1">Lunes 7am</button>
              ${silenciada ? `<button onclick="MOS._notifSilenciar('${n.idNotif}','', event)" class="btn-ghost btn-ripple text-[10px] px-2 py-1" style="color:#34d399;border-color:rgba(34,197,94,.4)">↺ Quitar silencio</button>` : ''}
            </div>
          </div>
          <div class="flex gap-2 flex-wrap pt-2 border-t border-slate-800">
            <button onclick="MOS._notifRestaurarDefault('${n.idNotif}', event)" class="btn-ghost btn-ripple text-xs flex-1">↺ Restaurar default</button>
            <button onclick="MOS._notifProbar('${n.idNotif}', event)" class="btn-primary btn-ripple text-xs flex-1">🧪 Probar a mí</button>
          </div>
        </div>
      </div>`;
  }

  // ── Handlers ──
  function _notifToggleExpand(id, ev) {
    if (ev && ev.target.closest('.notif-toggle, input, button, .notif-rol-chip')) return;
    const nuevo = !_notifState.expandido[id];
    _notifState.expandido[id] = nuevo;
    if (typeof _evalSfx === 'function') _evalSfx(nuevo ? 'expand' : 'collapse');
    // Toggle SOLO la clase de esa card → CSS hace la animación, sin re-render
    const card = document.querySelector(`.notif-card[data-id="${id}"]`);
    if (card) card.classList.toggle('expanded', nuevo);
  }
  // Mutación quirúrgica: actualiza solo los nodos visibles afectados de UNA card
  function _notifPatchCard(id) {
    const it = _notifState.items.find(x => x.idNotif === id);
    if (!it) return;
    const card = document.querySelector(`.notif-card[data-id="${id}"]`);
    if (!card) return;
    const isOn = !!it.activa;
    const silenciada = it.silenciada_hasta && new Date(it.silenciada_hasta).getTime() > Date.now();
    card.classList.toggle('silenciada', !isOn);
    card.classList.toggle('alta', String(it.prioridad || 'normal').toLowerCase() === 'alta');
    const toggle = card.querySelector('.notif-toggle');
    if (toggle) toggle.classList.toggle('on', isOn);
  }

  async function _notifToggleActiva(id, ev) {
    if (!_notifIsMaster()) { toast('Solo Master puede editar', 'error'); if (typeof _evalSfx === 'function') _evalSfx('error'); return; }
    const it = _notifState.items.find(x => x.idNotif === id);
    if (!it) return;
    const nuevoEstado = !it.activa;
    it.activa = nuevoEstado;
    if (typeof _evalSfx === 'function') _evalSfx(nuevoEstado ? 'add' : 'remove');
    if (ev && typeof _evalRipple === 'function') _evalRipple(ev);
    _notifPatchCard(id);  // mutación quirúrgica, sin re-render global
    try {
      await API.post('actualizarNotifConfig', { idNotif: id, activa: nuevoEstado, actualizado_por: S.session?.nombre || 'admin' });
      toast(`${nuevoEstado ? '✓ Activada' : '🔕 Silenciada'} · ${it.titulo}`, 'ok');
    } catch(e) {
      it.activa = !nuevoEstado;
      _notifPatchCard(id);
      toast('Error: ' + e.message, 'error');
      if (typeof _evalSfx === 'function') _evalSfx('error');
    }
  }
  async function _notifToggleRol(id, rol, ev) {
    if (!_notifIsMaster()) { toast('Solo Master puede editar', 'error'); if (typeof _evalSfx === 'function') _evalSfx('error'); return; }
    const it = _notifState.items.find(x => x.idNotif === id);
    if (!it) return;
    const rolesSet = new Set(String(it.audiencia_roles || '').split(',').map(s => s.trim().toUpperCase()).filter(Boolean));
    if (rolesSet.has(rol)) rolesSet.delete(rol); else rolesSet.add(rol);
    const nuevoCsv = Array.from(rolesSet).join(',');
    it.audiencia_roles = nuevoCsv;
    if (typeof _evalSfx === 'function') _evalSfx('tap');
    // Toggle solo el chip clickeado (no re-render)
    const card = document.querySelector(`.notif-card[data-id="${id}"]`);
    const chip = card?.querySelector(`.notif-rol-chip[onclick*="'${rol}'"]`);
    if (chip) chip.classList.toggle('on', rolesSet.has(rol));
    try {
      await API.post('actualizarNotifConfig', { idNotif: id, audiencia_roles: nuevoCsv, actualizado_por: S.session?.nombre || 'admin' });
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }
  async function _notifSetExtra(id, valor) {
    if (!_notifIsMaster()) return;
    const csv = String(valor || '').split(',').map(s => s.trim()).filter(Boolean).join(',');
    const it = _notifState.items.find(x => x.idNotif === id);
    if (it) it.audiencia_usuarios = csv;
    try {
      await API.post('actualizarNotifConfig', { idNotif: id, audiencia_usuarios: csv, actualizado_por: S.session?.nombre || 'admin' });
      if (typeof _evalSfx === 'function') _evalSfx('add');
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }
  async function _notifSetPrioridad(id, prio, ev) {
    if (!_notifIsMaster()) return;
    const it = _notifState.items.find(x => x.idNotif === id);
    if (!it) return;
    it.prioridad = prio;
    if (typeof _evalSfx === 'function') _evalSfx('switch');
    // Mutación quirúrgica: solo cambia clases del card + pills
    _notifPatchCard(id);
    const card = document.querySelector(`.notif-card[data-id="${id}"]`);
    if (card) {
      card.querySelectorAll('.notif-priority-pill').forEach(pill => {
        const txt = (pill.textContent || '').trim().toLowerCase();
        pill.classList.toggle('on', txt === prio);
      });
    }
    try {
      await API.post('actualizarNotifConfig', { idNotif: id, prioridad: prio, actualizado_por: S.session?.nombre || 'admin' });
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }
  async function _notifSetExcluir(id, val) {
    if (!_notifIsMaster()) return;
    const it = _notifState.items.find(x => x.idNotif === id);
    if (it) it.excluir_origen = val;
    if (typeof _evalSfx === 'function') _evalSfx('tap');
    try {
      await API.post('actualizarNotifConfig', { idNotif: id, excluir_origen: val, actualizado_por: S.session?.nombre || 'admin' });
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }
  async function _notifSilenciar(id, preset, ev) {
    if (!_notifIsMaster()) return;
    let hastaIso = '';
    if (preset === '1h')     hastaIso = new Date(Date.now() + 3600*1000).toISOString();
    if (preset === 'manana') {
      const d = new Date(); d.setDate(d.getDate() + 1); d.setHours(8, 0, 0, 0);
      hastaIso = d.toISOString();
    }
    if (preset === 'lunes') {
      const d = new Date();
      const dia = d.getDay() || 7;
      d.setDate(d.getDate() + (8 - dia)); d.setHours(7, 0, 0, 0);
      hastaIso = d.toISOString();
    }
    const it = _notifState.items.find(x => x.idNotif === id);
    if (it) it.silenciada_hasta = hastaIso;
    if (typeof _evalSfx === 'function') _evalSfx(hastaIso ? 'switch' : 'success');
    if (ev && typeof _evalRipple === 'function') _evalRipple(ev);
    // Para silenciar/quitar mantenemos re-render (cambia texto del badge silenciada)
    _renderNotifs();
    try {
      await API.post('actualizarNotifConfig', { idNotif: id, silenciada_hasta: hastaIso, actualizado_por: S.session?.nombre || 'admin' });
      toast(hastaIso ? `🔕 Silenciada` : `✓ Reactivada`, 'ok');
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }
  async function _notifRestaurarDefault(id, ev) {
    if (!_notifIsMaster()) return;
    if (ev && typeof _evalRipple === 'function') _evalRipple(ev);
    try {
      await API.post('restaurarNotifDefault', { idNotif: id, actualizado_por: S.session?.nombre || 'admin' });
      _notifState.cargado = false;
      if (typeof _evalSfx === 'function') _evalSfx('pop');
      toast('↺ Restaurada al default', 'ok');
      renderNotifsPanel();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }
  async function _notifProbar(id, ev) {
    if (ev && typeof _evalRipple === 'function') _evalRipple(ev);
    try {
      await API.post('probarNotificacion', { idNotif: id, soloAMi: true, miUsuario: S.session?.nombre || '' });
      if (typeof _evalSfx === 'function') _evalSfx('success');
      try {
        const r = ev?.target?.getBoundingClientRect();
        if (r && typeof _evalConfetti === 'function') _evalConfetti(r.left + r.width/2, r.top + r.height/2, '#a78bfa');
      } catch(_){}
      toast('🧪 Push de prueba enviada · revisa tu device', 'ok');
    } catch(e) {
      if (typeof _evalSfx === 'function') _evalSfx('error');
      toast('Error: ' + e.message, 'error');
    }
  }

  // ── Historial ──
  async function abrirNotifLog() {
    if (typeof _evalSfx === 'function') _evalSfx('open');
    // Llenar select de notifIds
    const sel = $('notifLogFiltroId');
    if (sel) {
      sel.innerHTML = '<option value="">Todas</option>' +
        (_notifState.items || []).map(n => `<option value="${n.idNotif}">${n.icono || ''} ${n.titulo}</option>`).join('');
    }
    openModal('modalNotifLog');
    refreshNotifLog();
  }
  async function refreshNotifLog(ev) {
    if (ev && typeof _evalRipple === 'function') _evalRipple(ev);
    const body = $('notifLogBody');
    if (!body) return;
    body.innerHTML = `<div class="text-center text-xs text-slate-500 py-8"><div class="inline-block animate-spin">⏳</div> Cargando...</div>`;
    const params = { limit: 100 };
    const idF = $('notifLogFiltroId')?.value || '';
    const desde = $('notifLogDesde')?.value || '';
    if (idF) params.idNotif = idF;
    if (desde) params.desde = desde;
    try {
      const res = await API.get('getNotifLog', params);
      const rows = Array.isArray(res) ? res : ((res && res.data) || []);
      _notifState.log = rows;
      if (!rows.length) {
        body.innerHTML = `<div class="text-center py-10 text-slate-500 text-sm">
          <div class="text-3xl mb-2 opacity-50">📭</div>
          Sin notificaciones en el rango
        </div>`;
        return;
      }
      body.innerHTML = rows.map((r, i) => {
        const ts = new Date(r.ts).toLocaleString('es-PE', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit', second:'2-digit' });
        const esError = String(r.estado || '').toUpperCase() === 'ERROR' || String(r.estado).indexOf('silenc') >= 0;
        return `<div class="notif-log-row${esError ? ' error' : ''}" style="--i:${Math.min(i,18)};animation-delay:${Math.min(i,18)*20}ms">
          <div class="flex items-center justify-between gap-2 mb-1">
            <span class="text-xs font-semibold text-slate-200 truncate">${r.titulo || '—'}</span>
            <span class="text-[10px] text-slate-500 shrink-0">${ts}</span>
          </div>
          <div class="text-[10px] text-slate-500 mb-1">${(r.cuerpo || '').substring(0, 120)}</div>
          <div class="flex items-center gap-2 flex-wrap text-[10px]">
            <span class="font-mono text-slate-600">${r.idNotif || ''}</span>
            ${r.entregadas > 0 ? `<span class="text-emerald-400">✓ ${r.entregadas} entregadas</span>` : ''}
            ${r.errores > 0 ? `<span class="text-rose-400">⚠ ${r.errores} error${r.errores!==1?'es':''}</span>` : ''}
            ${r.estado && r.estado !== 'OK' ? `<span class="text-amber-400">${r.estado}</span>` : ''}
            <button onclick="MOS._notifReenviar('${r.idLog}', event)"
                    class="text-[10px] px-2 py-0.5 rounded ml-auto"
                    style="background:rgba(99,102,241,.1);color:#a5b4fc;border:1px solid rgba(99,102,241,.3)">🔄 Reenviar</button>
          </div>
        </div>`;
      }).join('');
    } catch(e) {
      body.innerHTML = `<div class="text-center text-xs text-rose-400 py-8">⚠ Error: ${e.message || e}</div>`;
    }
  }
  async function _notifReenviar(idLog, ev) {
    if (ev && typeof _evalRipple === 'function') _evalRipple(ev);
    try {
      await API.post('reenviarNotificacion', { idLog });
      if (typeof _evalSfx === 'function') _evalSfx('success');
      toast('🔄 Reenviada', 'ok');
      refreshNotifLog();
    } catch(e) {
      if (typeof _evalSfx === 'function') _evalSfx('error');
      toast('Error: ' + e.message, 'error');
    }
  }

  // Estado en vivo de impresoras (PrintNode). Mapa printNodeId → {online, computer}.
  // Lo llena _refrescarEstadoImpresoras; lo consume _renderInfraEstacion.
  let _impPNEstado = {};
  let _impPNCargado = false;
  async function _refrescarEstadoImpresoras(reRender) {
    try {
      const r = await API.get('getPrintNodePrinters', {});
      const lista = Array.isArray(r) ? r : ((r && r.data) || []);
      if (!Array.isArray(lista)) return;
      const prev = _impPNEstado;
      const nuevo = {};
      let hayCaidaNueva = false;
      lista.forEach(p => {
        // [v2.41.81] Indexamos por printNodeId (string) — para SIN_ID el id
        // viene null, así que usamos un id sintético por idEstacion para no
        // colisionar. El render mira pnSt por printNodeId, si no hay key,
        // cae al SIN_ID por defecto.
        const pid = p.printNodeId ? String(p.printNodeId) : '';
        if (!pid) return; // SIN_ID no se indexa, el frontend lo detecta solo
        nuevo[pid] = {
          // Retro-compat
          online:   p.state === 'ONLINE',
          computer: p.computer || '',
          nombre:   p.nombre || '',
          // [v2.41.81] Diagnóstico semántico nuevo
          state:    p.state    || 'UNKNOWN',
          reason:   p.reason   || '',
          icon:     p.icon     || '',
          color:    p.color    || '',
          computerState:    p.computerState    || '',
          printerStateRaw:  p.printerStateRaw  || ''
        };
        // Detectar transición ONLINE → no-ONLINE para alerta sonora
        if (_impPNCargado && prev[pid] && prev[pid].state === 'ONLINE' && p.state !== 'ONLINE') {
          hayCaidaNueva = true;
        }
      });
      _impPNEstado = nuevo;
      _impPNCargado = true;
      if (hayCaidaNueva) {
        try { _evalSfx && _evalSfx('error'); } catch(_){}
        try {
          const caidas = lista.filter(p => p.state !== 'ONLINE' && p.printNodeId)
                              .map(p => `${p.nombre || p.printNodeId} (${p.reason || p.state})`)
                              .join(', ');
          toast('🖨 Impresora con problema: ' + caidas, 'error', 6000);
        } catch(_){}
      }
      if (reRender && S.cfgTab === 'infra') { try { renderInfra(); } catch(_){} }
    } catch(_) { /* tolerar — PrintNode puede tardar o no responder */ }
  }

  // Auto-refresh dinámico de dispositivos (cada 30s mientras Infra esté visible)
  let _intervalInfra = null;
  function _arrancarRefreshInfra() {
    // Carga inicial del estado de impresoras + sonido si al ABRIR ya hay caídas
    _refrescarEstadoImpresoras(true).then(() => {
      if (S.cfgTab === 'infra') {
        const offline = Object.values(_impPNEstado).filter(e => !e.online);
        if (offline.length) {
          try { _evalSfx && _evalSfx('error'); } catch(_){}
        }
      }
    });
    if (_intervalInfra) return;
    _intervalInfra = setInterval(async () => {
      if (S.cfgTab !== 'infra' || document.hidden) return;
      try {
        const data = await API.get('getDispositivos', {});
        if (Array.isArray(data)) {
          // Detectar cambios para no re-renderizar inútilmente
          const prevJson = JSON.stringify(cfgData.dispositivos || []);
          // [v2.43.348 fix] aplicar el shield optimista también en el poll de 15s — sin esto un poll
          // dentro de la ventana de aprobación traía el estado viejo (PENDIENTE) y el card parpadeaba.
          const _shielded = _dispAplicarShield(data);
          const newJson = JSON.stringify(_shielded);
          if (prevJson !== newJson) {
            cfgData.dispositivos = _shielded;
            renderInfra();
          }
        }
      } catch(_) { /* tolerar */ }
    }, 15 * 1000); // cada 15s para sentir tiempo real
    // Estado de impresoras PrintNode cada 25s mientras Infra esté abierto
    setInterval(() => {
      if (S.cfgTab !== 'infra' || document.hidden) return;
      _refrescarEstadoImpresoras(true);
    }, 25 * 1000);
    // Re-render local cada 10s para que los "hace Xs" se actualicen sin esperar fetch
    setInterval(() => {
      if (S.cfgTab !== 'infra' || document.hidden) return;
      try { renderInfra(); } catch(_) {}
    }, 10 * 1000);
  }
  function _detenerRefreshInfra() {
    if (_intervalInfra) { clearInterval(_intervalInfra); _intervalInfra = null; }
  }

  // Auto-refresh Personal cada 30s (Ultima_Conexion + dispositivos para online ME)
  let _intervalPersonal = null;
  function _arrancarRefreshPersonal() {
    if (_intervalPersonal) return;
    _intervalPersonal = setInterval(async () => {
      if (S.cfgTab !== 'personal' || document.hidden) return;
      try {
        const [personRes, mosRes, dispRes] = await Promise.allSettled([
          API.get('getPersonalMaster', { appOrigen: 'warehouseMos' }),
          API.get('getPersonalMaster', { appOrigen: 'MOS' }),
          API.get('getDispositivos', {})
        ]);
        let cambios = false;
        // [v2.43.36] Helper: preservar mutaciones optimistas pendientes.
        // Si el operador acaba de guardar un horario custom y la API aún no
        // confirmó, NO queremos que el polling pise el cambio con datos viejos.
        // Reglas:
        //   - Si la fila vieja tiene _horCustomPendiente=true → conservar
        //     horarioCustom local + flag en la fila nueva (no pisar mientras
        //     se está guardando)
        const preservarPendientes = (oldArr, newArr) => {
          const oldByid = {};
          (oldArr || []).forEach(x => {
            if (x._horCustomPendiente) oldByid[String(x.idPersonal)] = x;
          });
          (newArr || []).forEach(n => {
            const old = oldByid[String(n.idPersonal)];
            if (old) {
              n.horarioCustom = old.horarioCustom;
              n._horCustomPendiente = true;
            }
          });
          return newArr;
        };
        if (personRes.status === 'fulfilled') {
          const newJson = JSON.stringify(personRes.value || []);
          if (JSON.stringify(cfgData.personal || []) !== newJson) {
            cfgData.personal = preservarPendientes(cfgData.personal, personRes.value || []);
            cambios = true;
          }
        }
        if (mosRes.status === 'fulfilled') {
          const newJson = JSON.stringify(mosRes.value || []);
          if (JSON.stringify(cfgData.personalMOS || []) !== newJson) {
            cfgData.personalMOS = preservarPendientes(cfgData.personalMOS, mosRes.value || []);
            cambios = true;
          }
        }
        if (dispRes.status === 'fulfilled') {
          const _shieldedP = _dispAplicarShield(dispRes.value || []);   // [v2.43.348 fix] shield en poll de Personal
          const newJson = JSON.stringify(_shieldedP);
          if (JSON.stringify(cfgData.dispositivos || []) !== newJson) {
            cfgData.dispositivos = _shieldedP;
            cambios = true;
          }
        }
        if (cambios) renderPersonal();
      } catch(_) {}
    }, 30 * 1000);
  }
  function _detenerRefreshPersonal() {
    if (_intervalPersonal) { clearInterval(_intervalPersonal); _intervalPersonal = null; }
  }

  // ── TUTORIAL TICKETS (módulo Cajas) ──────────────────────
  const _TUT_TIC_TOTAL = 8;
  let _tutTicSlide = 1;
  function tutTicketsOpen() { _tutTicSlide = 1; _tutTicRender(); openModal('modalTutTickets'); }
  function tutTicketsClose() { closeModal('modalTutTickets'); }
  function tutTicketsNext() { if (_tutTicSlide < _TUT_TIC_TOTAL) { _tutTicSlide++; _tutTicRender(); } else tutTicketsClose(); }
  function tutTicketsPrev() { if (_tutTicSlide > 1) { _tutTicSlide--; _tutTicRender(); } }
  function tutTicketsGoto(n) {
    n = parseInt(n) || 1;
    if (n < 1 || n > _TUT_TIC_TOTAL) return;
    _tutTicSlide = n; _tutTicRender();
  }
  function _tutTicRender() {
    document.querySelectorAll('#modalTutTickets .tut-slide').forEach(el => {
      el.classList.toggle('active', parseInt(el.dataset.tslide) === _tutTicSlide);
    });
    document.querySelectorAll('#tutTicDots .tut-dot').forEach((el, i) => {
      el.classList.toggle('active', i + 1 === _tutTicSlide);
    });
    const bar = $('tutTicProgressBar');
    if (bar) bar.style.width = (_tutTicSlide * 100 / _TUT_TIC_TOTAL).toFixed(2) + '%';
    const lbl = $('tutTicSlideLabel');
    if (lbl) lbl.textContent = `Slide ${_tutTicSlide} de ${_TUT_TIC_TOTAL}`;
    const btnPrev = $('tutTicBtnPrev'); if (btnPrev) btnPrev.disabled = _tutTicSlide === 1;
    const btnNext = $('tutTicBtnNext'); if (btnNext) btnNext.textContent = (_tutTicSlide === _TUT_TIC_TOTAL) ? 'Cerrar ✓' : 'Siguiente →';
    const body = $('tutTicBody'); if (body) body.scrollTop = 0;
  }

  // ── TUTORIAL flotante en catálogo ────────────────────────
  const _TUT_TOTAL = 8;
  let _tutSlide = 1;

  function tutorialOpen() {
    _tutSlide = 1;
    _tutRender();
    openModal('modalTutorial');
  }
  function tutorialClose() { closeModal('modalTutorial'); }
  function tutorialNext() {
    if (_tutSlide < _TUT_TOTAL) { _tutSlide++; _tutRender(); }
    else tutorialClose();
  }
  function tutorialPrev() {
    if (_tutSlide > 1) { _tutSlide--; _tutRender(); }
  }
  function tutorialGoto(n) {
    n = parseInt(n) || 1;
    if (n < 1 || n > _TUT_TOTAL) return;
    _tutSlide = n;
    _tutRender();
  }
  function _tutRender() {
    document.querySelectorAll('#modalTutorial .tut-slide').forEach(el => {
      el.classList.toggle('active', parseInt(el.dataset.slide) === _tutSlide);
    });
    document.querySelectorAll('#tutDots .tut-dot').forEach((el, i) => {
      el.classList.toggle('active', i + 1 === _tutSlide);
    });
    const bar = $('tutProgressBar');
    if (bar) bar.style.width = (_tutSlide * 100 / _TUT_TOTAL).toFixed(2) + '%';
    const lbl = $('tutSlideLabel');
    if (lbl) lbl.textContent = `Slide ${_tutSlide} de ${_TUT_TOTAL}`;
    const btnPrev = $('tutBtnPrev');
    if (btnPrev) btnPrev.disabled = _tutSlide === 1;
    const btnNext = $('tutBtnNext');
    if (btnNext) btnNext.textContent = (_tutSlide === _TUT_TOTAL) ? 'Cerrar ✓' : 'Siguiente →';
    // Scroll body al inicio
    const body = $('tutBody');
    if (body) body.scrollTop = 0;
  }

  // ── Pestaña Configuración → Evaluación ─────────────────
  async function renderConfigEvalPanel() {
    try {
      const res = await API.get('getConfig', {});
      const cfg = res || {};
      $('cfgPanelMetaCajero').value     = cfg.evalMetaCajero     || 2000;
      $('cfgPanelMetaEnvasador').value  = cfg.evalMetaEnvasador  || 500;
      $('cfgPanelMetaAlmacenero').value = cfg.evalMetaAlmacenero || 15;
      $('cfgPanelMetaAuditorias').value = cfg.evalMetaAuditorias || 30;
      $('cfgPanelBonoMetaBase').value   = cfg.evalBonoMetaBase   || 8;
      $('cfgPanelBonoMetaDoble').value  = cfg.evalBonoMetaDoble  || 15;
    } catch(_) {}
  }

  async function guardarConfigEvalPanel() {
    const btn = $('cfgPanelEvalSaveBtn');
    if (btn) { btn.disabled = true; btn.textContent = 'Guardando...'; }
    const pares = [
      ['evalMetaCajero',     $('cfgPanelMetaCajero').value],
      ['evalMetaEnvasador',  $('cfgPanelMetaEnvasador').value],
      ['evalMetaAlmacenero', $('cfgPanelMetaAlmacenero').value],
      ['evalMetaAuditorias', $('cfgPanelMetaAuditorias').value],
      ['evalBonoMetaBase',   $('cfgPanelBonoMetaBase').value],
      ['evalBonoMetaDoble',  $('cfgPanelBonoMetaDoble').value]
    ];
    try {
      await Promise.all(pares.map(([clave, valor]) =>
        API.post('setConfig', { clave, valor: String(valor) })
      ));
      toast('Configuración guardada ✓', 'ok');
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = '💾 Guardar configuración'; }
    }
  }

  // ── CATEGORÍAS / política de precios ─────────────────────
  async function renderCategorias(skipFetch) {
    const cont = $('catGridContainer');
    if (!cont) return;
    // Pintar desde cache instantáneamente si ya está en cfgData
    const cached = cfgData.categorias || [];
    if (cached.length > 0) _renderCategoriasCards(cont, cached);
    else cont.innerHTML = `<div class="col-span-full text-center py-8 text-slate-500 text-sm"><div class="inline-block animate-spin">⏳</div> Cargando...</div>`;
    if (!skipFetch) {
      try {
        const r = await API.get('getCategorias', {});
        cfgData.categorias = r || [];
        _renderCategoriasCards(cont, cfgData.categorias);
      } catch(e) {
        if (!cached.length) cont.innerHTML = `<div class="col-span-full text-center py-8 text-rose-400 text-sm">Error: ${e.message}</div>`;
      }
    }
  }

  function _renderCategoriasCards(cont, rows) {
    if (!rows.length) {
      cont.innerHTML = `<div class="col-span-full text-center py-10 text-slate-500 text-sm">
        <div class="text-3xl mb-2 opacity-50">🏷️</div>
        Sin categorías. Crea una con "+ Nueva categoría"
      </div>`;
      return;
    }
    cont.innerHTML = rows.map((c, idx) => {
      const activa = String(c.estado) === '1';
      const modo = String(c.modoVenta || '').toUpperCase();
      const modoCls = modo === 'MARGEN' ? 'modo-margen' :
                      modo === 'FIJO' ? 'modo-fijo' :
                      modo === 'COMPETITIVO' ? 'modo-comp' : 'modo-libre';
      const modoIco = modo === 'MARGEN' ? '📈'
                    : modo === 'FIJO'   ? '🔒'
                    : modo === 'COMPETITIVO' ? '🎯'
                    : '🆓';
      const margenStr = (modo === 'MARGEN' || modo === 'COMPETITIVO')
        ? (parseFloat(c.margenPct) || 0).toFixed(1) + '%' : '—';
      const topeStr = parseFloat(c.precioTope) > 0 ? 'S/ ' + parseFloat(c.precioTope).toFixed(2) : '';
      return `
        <div class="cat-card-modern ${!activa ? 'inactiva' : ''} ${modoCls}"
             style="--i:${Math.min(idx, 20)}"
             onclick="MOS.abrirModalCategoria('${c.idCategoria}', event)">
          <div class="flex items-start justify-between gap-2 mb-1">
            <div class="flex items-center gap-2 min-w-0 flex-1">
              <span style="font-size:18px">${modoIco}</span>
              <div class="min-w-0 flex-1">
                <div class="text-sm font-semibold text-slate-100 truncate">${c.nombre || c.idCategoria}</div>
                <div class="text-[9px] text-slate-600 font-mono truncate">${c.idCategoria}</div>
              </div>
            </div>
            <span class="cat-modo-pill ${modoCls}">${modo}</span>
          </div>
          <div class="flex items-center gap-3 text-xs mt-2">
            <div>
              <div class="text-[9px] uppercase text-slate-500 font-bold tracking-wider">Margen</div>
              <div class="font-mono font-bold text-amber-400">${margenStr}</div>
            </div>
            ${topeStr ? `<div>
              <div class="text-[9px] uppercase text-slate-500 font-bold tracking-wider">Tope</div>
              <div class="font-mono text-slate-300">${topeStr}</div>
            </div>` : ''}
            <div class="ml-auto">
              <span class="text-[9px] ${activa ? 'text-emerald-400' : 'text-slate-500'}">${activa ? '● Activa' : '○ Inactiva'}</span>
            </div>
          </div>
          ${c.descripcion ? `<div class="text-[10px] text-slate-500 mt-1.5 truncate">${c.descripcion}</div>` : ''}
        </div>
      `;
    }).join('');
  }

  function abrirModalCategoria(idCategoria, ev) {
    if (typeof _evalSfx === 'function') _evalSfx('open');
    if (ev && typeof _evalRipple === 'function') {
      // Ripple en el card si existe el target
      try {
        const card = ev.target && ev.target.closest('.cat-card-modern');
        if (card) {
          const rect = card.getBoundingClientRect();
          const size = Math.max(rect.width, rect.height) * 0.7;
          const r = document.createElement('span');
          r.className = 'cat-ripple';
          r.style.width = r.style.height = size + 'px';
          r.style.left = (ev.clientX - rect.left - size/2) + 'px';
          r.style.top  = (ev.clientY - rect.top  - size/2) + 'px';
          card.appendChild(r);
          setTimeout(() => { try { r.remove(); } catch(_){} }, 700);
        }
      } catch(_){}
    }
    const cat = idCategoria
      ? (cfgData.categorias || []).find(c => String(c.idCategoria) === String(idCategoria))
      : null;
    $('modalCategoriaTitle').textContent = cat ? 'Editar categoría' : 'Nueva categoría';
    $('catId').value = cat ? cat.idCategoria : '';
    $('catNombre').value = cat ? (cat.nombre || cat.idCategoria) : '';
    $('catModo').value = cat ? (cat.modoVenta || 'MARGEN') : 'MARGEN';
    $('catMargen').value = cat && cat.margenPct !== '' && cat.margenPct !== undefined ? cat.margenPct : 25;
    $('catTope').value = cat && parseFloat(cat.precioTope) > 0 ? cat.precioTope : '';
    $('catDesc').value = cat ? (cat.descripcion || '') : '';
    $('catEstado').value = cat ? String(cat.estado || '1') : '1';
    // Si es nueva, dejar nombre editable — si es edición, bloquear nombre/ID (lo identifica el sistema)
    $('catNombre').disabled = !!cat;
    _catOnModoChange();
    openModal('modalCategoria');
  }

  function _catOnModoChange() {
    const modo = $('catModo')?.value;
    const margenWrap = $('catMargenWrap');
    const topeWrap = $('catTopeWrap');
    if (margenWrap) margenWrap.classList.toggle('hidden', modo === 'FIJO' || modo === 'LIBRE');
    if (topeWrap)   topeWrap.classList.toggle('hidden', modo !== 'COMPETITIVO');
  }

  async function guardarCategoria() {
    const id = $('catId').value;
    const nombre = $('catNombre').value.trim();
    if (!nombre) { toast('Nombre requerido', 'error'); return; }
    const modo = $('catModo').value;
    const margen = parseFloat($('catMargen').value);
    const tope = parseFloat($('catTope').value);
    if ((modo === 'MARGEN' || modo === 'COMPETITIVO') && (isNaN(margen) || margen < 0 || margen >= 100)) {
      toast('Margen debe ser 0-99', 'error'); return;
    }
    if (modo === 'COMPETITIVO' && (!tope || tope <= 0)) {
      toast('Precio tope requerido para modo COMPETITIVO', 'error'); return;
    }
    const params = {
      nombre, modoVenta: modo,
      margenPct: isNaN(margen) ? '' : margen,
      precioTope: isNaN(tope) ? '' : tope,
      descripcion: $('catDesc').value.trim(),
      estado: $('catEstado').value
    };
    try {
      if (id) {
        await API.post('actualizarCategoria', { ...params, idCategoria: id });
        toast('Categoría actualizada ✓', 'ok');
      } else {
        await API.post('crearCategoria', params);
        toast('Categoría creada ✓', 'ok');
      }
      if (typeof _evalSfx === 'function') _evalSfx('success');
      try {
        const btn = $('btnGuardarCategoria');
        if (btn && typeof _evalConfetti === 'function') {
          const r = btn.getBoundingClientRect();
          _evalConfetti(r.left + r.width/2, r.top + r.height/2, '#fbbf24');
        }
      } catch(_){}
      closeModal('modalCategoria');
      await renderCategorias(); // refetch
    } catch(e) {
      if (typeof _evalSfx === 'function') _evalSfx('error');
      toast('Error: ' + e.message, 'error');
    }
  }

  // ── Integridad / Auditoría de PRODUCTOS_MASTER + EQUIVALENCIAS ───
  async function renderIntegridad(skipFetch) {
    const cont = $('auditAlertas');
    const resumenEl = $('auditResumen');
    if (!cont || !resumenEl) return;
    if (!skipFetch) resumenEl.innerHTML = '<span class="text-slate-500">Cargando…</span>';
    try {
      const r = await API.get('getAuditoriaIntegridad', {});
      const data = (r && r.data) ? r.data : r;
      const alertas = (data && data.alertas) || [];
      const ultimaLimpia = data && data.ultimaAuditoriaLimpia;

      if (!alertas.length) {
        resumenEl.innerHTML = `
          <div class="flex items-start gap-3">
            <div class="text-2xl">✅</div>
            <div class="flex-1">
              <div class="text-sm font-semibold text-green-400">Catálogo íntegro</div>
              <div class="text-xs text-slate-500 mt-0.5">${ultimaLimpia ? 'Última auditoría limpia: ' + new Date(ultimaLimpia).toLocaleString() : 'Sin alertas activas. Corre una auditoría para verificar.'}</div>
            </div>
          </div>`;
        cont.innerHTML = '';
        return;
      }
      const criticas = alertas.filter(a => a.urgencia === 'CRITICA').length;
      const altas    = alertas.filter(a => a.urgencia === 'ALTA').length;
      resumenEl.innerHTML = `
        <div class="flex items-start gap-3">
          <div class="text-2xl">${criticas > 0 ? '🚨' : '⚠️'}</div>
          <div class="flex-1">
            <div class="text-sm font-semibold ${criticas > 0 ? 'text-rose-400' : 'text-amber-400'}">${alertas.length} alertas activas</div>
            <div class="text-xs text-slate-500 mt-0.5">${criticas} críticas · ${altas} altas · ${alertas.length - criticas - altas} medias/info</div>
          </div>
        </div>`;
      cont.innerHTML = alertas.map(a => {
        const colorBorder = a.urgencia === 'CRITICA' ? 'border-rose-500/40' : a.urgencia === 'ALTA' ? 'border-amber-500/40' : 'border-slate-700';
        const colorTipo   = a.urgencia === 'CRITICA' ? 'text-rose-400' : a.urgencia === 'ALTA' ? 'text-amber-400' : 'text-slate-400';
        let detalleExtra = '';
        // MOD_NO_AUTORIZADA → mostrar accion, tabla, source, params, contexto auditoría
        if (a.tipo === 'MOD_NO_AUTORIZADA' && a.datos) {
          const d = a.datos;
          let paramsObj = {};
          try { paramsObj = typeof d.params === 'string' ? JSON.parse(d.params) : (d.params || {}); } catch(_) { paramsObj = {}; }
          const idProd = paramsObj.idProducto || paramsObj.codigoBarra || paramsObj.idEquiv || '—';
          const camposEditados = Object.keys(paramsObj).filter(k => k !== '_source' && k !== '_audit' && k !== 'idProducto' && k !== 'idEquiv').join(', ') || '—';
          // Contexto auditoría
          const usuario = d.usuario ? `${d.usuario} (${d.rol || 'sin rol'})` : '— sin sesión —';
          const idSesion = d.idSesion || '—';
          const dispositivo = d.idDispositivo ? d.idDispositivo.slice(0, 16) + '…' : '— sin device ID —';
          const appOrigen = d.appOrigen || '—';
          // userAgent simplificado (extrae plataforma/browser)
          const ua = d.userAgent || '';
          const uaSimple = ua.match(/(iPhone|iPad|Android|Windows|Mac|Linux)[^;)]*/)?.[0]?.slice(0, 40) || (ua ? ua.slice(0, 40) : '—');
          const tsApp = d.timestampApp ? new Date(d.timestampApp).toLocaleString() : '—';
          detalleExtra = `
            <div class="mt-2 space-y-2">
              <!-- Qué intentó hacer -->
              <div class="text-[11px] font-mono space-y-0.5" style="background:rgba(244,63,94,.05);border-left:2px solid #f43f5e;padding:6px 8px;border-radius:4px">
                <div class="text-rose-300 font-semibold">⛔ Operación bloqueada</div>
                <div><span class="text-slate-500">Acción:</span> <span class="text-slate-300">${d.accion || '—'} en ${d.tabla || '—'}</span></div>
                <div><span class="text-slate-500">Origen reportado:</span> <span class="text-rose-300">${d.source || 'sin _source'}</span></div>
                <div><span class="text-slate-500">Producto/registro:</span> <span class="text-slate-300">${idProd}</span></div>
                <div><span class="text-slate-500">Campos:</span> <span class="text-slate-300">${camposEditados}</span></div>
              </div>
              <!-- Quién / Dónde / Cuándo -->
              <div class="text-[11px] font-mono space-y-0.5" style="background:rgba(99,102,241,.05);border-left:2px solid #6366f1;padding:6px 8px;border-radius:4px">
                <div class="text-indigo-300 font-semibold">🔎 Contexto del intento</div>
                <div><span class="text-slate-500">👤 Usuario:</span> <span class="text-slate-300">${usuario}</span></div>
                <div><span class="text-slate-500">🔑 idSesión:</span> <span class="text-slate-300">${idSesion}</span></div>
                <div><span class="text-slate-500">📱 Dispositivo:</span> <span class="text-slate-300">${dispositivo}</span></div>
                <div><span class="text-slate-500">🌐 App origen:</span> <span class="text-slate-300">${appOrigen}</span></div>
                <div><span class="text-slate-500">💻 Plataforma:</span> <span class="text-slate-300">${uaSimple}</span></div>
                <div><span class="text-slate-500">⏰ Hora cliente:</span> <span class="text-slate-300">${tsApp}</span></div>
              </div>
            </div>
            <div class="text-[10px] text-slate-600 mt-2 italic">💡 Si reconoces el usuario y la acción (cambió un precio, etc.) seguramente venga de una pestaña/dispositivo con la PWA antigua. Recárgala y marca la alerta como resuelta. Si NO reconoces nada, investigar.</div>
          `;
        } else if (a.datos && a.datos.primeras) {
          // AUDIT_INTEGRIDAD → primeras 5 anomalías
          detalleExtra = '<div class="text-[10px] text-slate-500 mt-2 font-mono whitespace-pre-wrap">'
            + (a.datos.primeras || []).slice(0, 5).map(p => '· ' + (p.detalle || JSON.stringify(p))).join('\n')
            + '</div>';
        }
        const fechaStr = a.fecha ? new Date(a.fecha).toLocaleString() : '';
        return `
          <div class="card-sm border ${colorBorder} p-3">
            <div class="flex items-start justify-between gap-2">
              <div class="min-w-0 flex-1">
                <div class="flex items-center gap-2">
                  <span class="text-xs font-bold ${colorTipo}">${a.urgencia}</span>
                  <span class="text-xs text-slate-500 font-mono">${a.tipo}</span>
                </div>
                <div class="text-sm text-slate-200 mt-1">${a.mensaje}</div>
                <div class="text-[10px] text-slate-600 mt-1">${fechaStr}</div>
                ${detalleExtra}
              </div>
              <button onclick="MOS.auditResolver('${a.idAlerta}')" class="btn-ghost text-xs px-2 py-1 shrink-0" title="Marcar como resuelta">✓</button>
            </div>
          </div>`;
      }).join('');
    } catch(e) {
      resumenEl.innerHTML = `<div class="text-rose-400 text-sm">Error: ${e.message}</div>`;
      cont.innerHTML = '';
    }
  }

  async function auditCorrer() {
    const resumenEl = $('auditResumen');
    if (resumenEl) resumenEl.innerHTML = '<span class="text-slate-500">Auditando…</span>';
    try {
      const r = await API.get('getAuditoriaIntegridad', { run: 'true' });
      const data = (r && r.data) ? r.data : r;
      const totalAnomalias = (data && data.anomalias) ? data.anomalias.length : 0;
      toast(totalAnomalias === 0 ? 'Auditoría limpia ✓' : totalAnomalias + ' anomalías detectadas', totalAnomalias === 0 ? 'ok' : 'error');
      await renderIntegridad();
      _auditCheckBanner();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
      if (resumenEl) resumenEl.innerHTML = `<div class="text-rose-400 text-sm">Error: ${e.message}</div>`;
    }
  }

  async function auditResolver(idAlerta) {
    if (!idAlerta) return;
    try {
      await API.post('resolverAlertaAuditoria', { idAlerta });
      await renderIntegridad();
      _auditCheckBanner();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  async function auditResolverTodas() {
    try {
      const r = await API.get('getAuditoriaIntegridad', {});
      const data = (r && r.data) ? r.data : r;
      const alertas = (data && data.alertas) || [];
      if (!alertas.length) { toast('No hay alertas activas', 'info'); return; }
      if (!await _modalConfirm('¿Marcar las ' + alertas.length + ' alertas como resueltas?', { titulo: 'Resolver alertas' })) return;
      await Promise.all(alertas.map(a => API.post('resolverAlertaAuditoria', { idAlerta: a.idAlerta }).catch(() => {})));
      toast(alertas.length + ' alertas archivadas', 'ok');
      await renderIntegridad();
      _auditCheckBanner();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  // Banner de alertas en el catálogo
  async function _auditCheckBanner() {
    const banner = $('auditBannerCat');
    if (!banner) return;
    try {
      const r = await API.get('getAuditoriaIntegridad', {});
      const data = (r && r.data) ? r.data : r;
      const alertas = (data && data.alertas) || [];
      if (!alertas.length) { banner.classList.add('hidden'); banner.innerHTML = ''; return; }
      const criticas = alertas.filter(a => a.urgencia === 'CRITICA').length;
      const cls = criticas > 0 ? 'border-rose-500/40 bg-rose-500/5 text-rose-300' : 'border-amber-500/40 bg-amber-500/5 text-amber-300';
      const icon = criticas > 0 ? '🚨' : '⚠️';
      banner.classList.remove('hidden');
      banner.innerHTML = `
        <div class="card-sm border ${cls} p-3 flex items-center gap-3 cursor-pointer" onclick="MOS.nav('config');setTimeout(()=>MOS.setCfgTab('integridad'),50)">
          <span class="text-xl">${icon}</span>
          <div class="flex-1 min-w-0">
            <div class="text-sm font-semibold">${alertas.length} alerta${alertas.length === 1 ? '' : 's'} de integridad de catálogo</div>
            <div class="text-xs opacity-80">Click para ver detalle en Configuración → Integridad</div>
          </div>
          <span class="text-xl opacity-60">→</span>
        </div>`;
    } catch(_) { banner.classList.add('hidden'); }
  }

  // ════════════════════════════════════════════════════════════
  // INFRAESTRUCTURA — vista jerárquica Zona > Estación > Impresora
  // ════════════════════════════════════════════════════════════
  function renderInfra() {
    const cont = $('infraContenedor');
    if (!cont) return;
    const zonas = cfgData.zonas || [];
    const estaciones = cfgData.estaciones || [];
    const impresoras = cfgData.impresoras || [];

    // ── A: Header summary con contadores en vivo ──
    const dispActivos = (cfgData.dispositivos || []).filter(d => String(d.Estado).toUpperCase() === 'ACTIVO');
    const onlineCount = dispActivos.filter(d => _dispActividad(d.Ultima_Conexion).minutos < 5).length;
    const totalZ = zonas.filter(z => String(z.estado) === '1' || z.estado === 1).length;
    const totalE = estaciones.filter(e => String(e.activo) === '1').length;
    const summaryHTML = `<div class="card p-3 mb-4" style="background:linear-gradient(135deg,#0c1a2e 0%,#0d1526 100%);border:1px solid #1e3a8a;">
      <div class="flex items-center gap-3 flex-wrap">
        <div class="flex items-center gap-2">
          <span class="relative inline-block" style="width:14px;height:14px;">
            <span class="absolute inset-0 rounded-full" style="background:${onlineCount > 0 ? '#10b981' : '#475569'};"></span>
            ${onlineCount > 0 ? '<span class="disp-dot-pulse" style="position:absolute;inset:0;width:14px;height:14px;top:0;right:0;"></span>' : ''}
          </span>
          <div>
            <div class="text-xl font-black ${onlineCount > 0 ? 'text-emerald-300' : 'text-slate-500'} leading-none">${onlineCount}</div>
            <div class="text-[9px] uppercase text-slate-500 tracking-wider mt-0.5">online ahora</div>
          </div>
        </div>
        <div class="text-slate-700 text-lg">·</div>
        <div class="flex items-center gap-2">
          <span class="text-lg">📱</span>
          <div>
            <div class="text-base font-bold text-slate-200 leading-none">${dispActivos.length}</div>
            <div class="text-[9px] uppercase text-slate-500 tracking-wider mt-0.5">dispositivos</div>
          </div>
        </div>
        <div class="text-slate-700 text-lg">·</div>
        <div class="flex items-center gap-2">
          <span class="text-lg">🏬</span>
          <div>
            <div class="text-base font-bold text-slate-200 leading-none">${totalZ}</div>
            <div class="text-[9px] uppercase text-slate-500 tracking-wider mt-0.5">zonas</div>
          </div>
        </div>
        <div class="text-slate-700 text-lg">·</div>
        <div class="flex items-center gap-2">
          <span class="text-lg">🛒</span>
          <div>
            <div class="text-base font-bold text-slate-200 leading-none">${totalE}</div>
            <div class="text-[9px] uppercase text-slate-500 tracking-wider mt-0.5">estaciones</div>
          </div>
        </div>
        <button onclick="MOS.infraToggleHeatmap()"
                class="ml-auto text-xs px-3 py-1.5 rounded-lg transition-all"
                style="background:${_infraHeatmapActivo ? 'linear-gradient(90deg,#dc2626,#f59e0b)' : '#1e293b'};color:${_infraHeatmapActivo ? '#fff' : '#94a3b8'};border:1px solid ${_infraHeatmapActivo ? '#dc2626' : '#334155'};font-weight:700;">
          🔥 Heatmap ${_infraHeatmapActivo ? 'ON' : 'OFF'}
        </button>
      </div>
    </div>`;

    // Card punteado para crear primera/nueva zona
    const cardNuevaZona = `<button onclick="MOS.abrirModalZona(null)"
        class="w-full py-6 rounded-xl border-2 border-dashed border-slate-700 hover:border-sky-600 hover:bg-sky-900/10 transition-all text-slate-500 hover:text-sky-300 group">
        <div class="flex items-center justify-center gap-2 text-sm font-semibold">
          <span class="text-xl">🏬</span>
          <span>+ agregar nueva zona</span>
        </div>
        <p class="text-[10px] text-slate-600 group-hover:text-sky-500 mt-1">Crea otro punto de venta físico</p>
      </button>`;

    if (!zonas.length) {
      cont.innerHTML = summaryHTML + `<div class="card p-12 text-center text-slate-500">
        <div class="text-6xl mb-3">🏗️</div>
        <p class="font-bold text-slate-300 mb-1">Sin zonas todavía</p>
        <p class="text-xs mb-4">Crea tu primera zona para empezar a configurar la infraestructura.</p>
        <button class="btn-primary text-sm px-4 py-2" onclick="MOS.abrirModalZona(null)">+ Crear primera zona</button>
      </div>`;
      return;
    }

    const zonasHTML = zonas.map(z => {
      const zonaActiva = String(z.estado) === '1' || z.estado === 1 || z.estado === true;
      const estZona = estaciones.filter(e => e.idZona === z.idZona);
      const totalImp = estZona.reduce((acc, e) =>
        acc + impresoras.filter(i => i.idEstacion === e.idEstacion).length, 0);
      // C: Contador de dispositivos online en esta zona
      const onlineEnZona = estZona.reduce((acc, e) => acc + _dispOnlineEnEstacion(e.idEstacion), 0);

      const estadoBadge = zonaActiva
        ? '<span class="inline-flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full bg-emerald-900/60 text-emerald-300 font-bold"><span class="w-1.5 h-1.5 rounded-full bg-emerald-400"></span>activa</span>'
        : '<span class="inline-flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full bg-slate-700 text-slate-400 font-bold">inactiva</span>';
      const onlineBadge = onlineEnZona > 0
        ? `<span class="inline-flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full font-bold disp-chip-live" style="background:rgba(16,185,129,0.18);color:#6ee7b7;border:1px solid rgba(16,185,129,0.5);"><span class="w-1.5 h-1.5 rounded-full bg-emerald-400"></span>${onlineEnZona} online</span>`
        : '';

      const estsHTML = estZona.map(e => _renderInfraEstacion(e, impresoras)).join('');
      const seriesHTML = _renderInfraSeries(z, estZona);

      return `<div class="card p-4" style="background:linear-gradient(135deg,#0d1f3a 0%,#0d1526 100%);border:1px solid ${zonaActiva ? '#1e3a8a' : '#334155'};${zonaActiva ? '' : 'opacity:0.7;'}">
        <!-- Header zona -->
        <div class="flex items-start justify-between gap-3 mb-3 pb-3" style="border-bottom:1px solid #1e293b;">
          <div class="flex items-start gap-3 flex-1 min-w-0">
            <div class="w-12 h-12 rounded-xl flex items-center justify-center text-2xl shrink-0" style="background:linear-gradient(135deg,#1e3a8a,#0c4a6e);">🏬</div>
            <div class="flex-1 min-w-0">
              <div class="flex items-center gap-2 flex-wrap">
                <h3 class="text-base font-black text-white truncate">${z.nombre}</h3>
                ${estadoBadge}
                ${onlineBadge}
                <span class="font-mono text-[10px] text-slate-500">${z.idZona}</span>
              </div>
              <p class="text-xs text-slate-400 mt-0.5 truncate">${z.direccion ? '📍 ' + z.direccion : ''}${z.responsable ? '  ·  👤 ' + z.responsable : ''}</p>
              <p class="text-[11px] text-slate-500 mt-1">${estZona.length} estación${estZona.length === 1 ? '' : 'es'} · ${totalImp} impresora${totalImp === 1 ? '' : 's'}</p>
            </div>
          </div>
          <div class="flex items-center gap-1 shrink-0">
            <label class="pers-switch" title="${zonaActiva ? 'Desactivar zona' : 'Activar zona'}" onclick="event.stopPropagation()">
              <input type="checkbox" ${zonaActiva ? 'checked' : ''} onchange="MOS.toggleZonaActiva('${z.idZona}', event)">
              <span class="pers-switch-slider"></span>
            </label>
            <button onclick="MOS.abrirModalZona('${z.idZona}')" class="text-xs text-slate-400 hover:text-white px-2 py-1 rounded border border-slate-700" title="Editar zona">✏️</button>
          </div>
        </div>

        <!-- Series documentales (chips) -->
        ${seriesHTML}

        <!-- Chips de política de la zona (meta + comisión + auditorías o
             tarifa de almacén) — muestran lo configurado en politicaJSON -->
        ${_renderChipsPoliticaZona(z)}

        <!-- Grid de estaciones -->
        ${estZona.length > 0
          ? `<div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">${estsHTML}</div>`
          : `<div class="text-center py-6 text-slate-500 text-xs italic">Esta zona no tiene estaciones aún.</div>`}

        <!-- Botón agregar estación -->
        <button onclick="MOS.abrirModalEstacion(null,'${z.idZona}')"
                class="mt-3 w-full text-xs text-slate-400 hover:text-white py-2 rounded-lg border border-dashed border-slate-700 hover:border-emerald-700 hover:bg-emerald-900/20 transition-colors">
          + estación a esta zona
        </button>
      </div>`;
    }).join('');

    // Sección de dispositivos pendientes de aprobación (arriba si hay alguno)
    const pendientes = _dispPendientes();
    const pendHTML = pendientes.length ? `
      <div class="card p-4 mb-4" style="background:linear-gradient(135deg,#3b1010 0%,#0d1526 100%);border:2px solid #ef4444;animation:pulse 2s ease-in-out infinite;">
        <div class="flex items-center gap-2 mb-3">
          <span class="text-2xl">🔔</span>
          <div class="flex-1">
            <h3 class="font-black text-base text-white">Dispositivos esperando aprobación</h3>
            <p class="text-[11px] text-red-200">Estos equipos intentaron conectarse pero aún no están autorizados.</p>
          </div>
          <span class="badge badge-red text-xs">${pendientes.length}</span>
        </div>
        <div class="space-y-2">
          ${pendientes.map(d => {
            const ico = _dispIcono(d.Nombre_Equipo);
            const idAttr = String(d.ID_Dispositivo).replace(/'/g, '&#39;');
            const act = _dispActividad(d.Ultima_Conexion);
            return `<div class="disp-pend-card flex items-center gap-3 p-3 rounded-lg" data-pend-card="${idAttr}" style="background:#0a1424;border:1px solid #7f1d1d;">
              <span class="text-3xl shrink-0">${ico}</span>
              <div class="flex-1 min-w-0">
                <div class="flex items-center gap-2 flex-wrap">
                  <span class="font-bold text-sm text-white truncate">${d.Nombre_Equipo || 'Dispositivo nuevo'}</span>
                  ${_appBadge(d.App)}
                </div>
                <div class="text-[10px] text-slate-500 font-mono truncate mt-0.5">${d.ID_Dispositivo}</div>
                <div class="text-[10px] mt-0.5" style="color:${act.color};">${act.dot} ${act.label}${d.Ultima_Sesion ? ' · 👤 ' + d.Ultima_Sesion : ''}</div>
              </div>
              <button onclick="MOS.aprobarDispositivo('${idAttr}')"
                      class="btn-primary text-xs px-3 py-1.5 shrink-0"
                      style="background:#10b981" title="Aprobar con el nombre actual">✓ Aprobar</button>
              <button onclick="MOS.aprobarDispositivoConNombre('${idAttr}')"
                      class="btn-ghost text-xs px-2 py-1.5 shrink-0"
                      style="color:#a5b4fc;border:1px solid #312e81" title="Renombrar antes de aprobar">✎</button>
              <button onclick="MOS.rechazarDispositivo('${idAttr}')"
                      class="btn-ghost text-xs px-2 py-1.5 shrink-0"
                      style="color:#f87171;border:1px solid #7f1d1d" title="Rechazar">✕</button>
            </div>`;
          }).join('')}
        </div>
      </div>` : '';

    // Sección de dispositivos sin estación asignada todavía
    const moviles = _dispMoviles();
    const movHTML = moviles.length ? `
      <div class="card p-4 mt-4" style="background:linear-gradient(135deg,#0d1526 0%,#0a1424 100%);border:1px solid #334155;">
        <div class="flex items-center gap-2 mb-3">
          <span class="text-xl">📱</span>
          <div class="flex-1">
            <h3 class="font-bold text-sm text-white">Sin estación asignada</h3>
            <p class="text-[10px] text-slate-500">Dispositivos aprobados que aún no han hecho login en ninguna estación. Aparecerán en la zona/estación que escojan al ingresar.</p>
          </div>
          <span class="badge badge-gray text-xs">${moviles.length}</span>
        </div>
        <div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-2">
          ${moviles.map(d => _renderDispositivoChip(d)).join('')}
        </div>
      </div>` : '';

    // Zona Premium · admins+master con app=MOS (sin estación/impresora asignada)
    const premiumHTML = _renderInfraPremium();

    cont.innerHTML = summaryHTML + premiumHTML + pendHTML + zonasHTML + movHTML + cardNuevaZona;

    // Guardar mapa de estaciones para detectar movimientos en próximo render
    _dispActualizarMapa();
  }

  // ── Series documentales por zona (chips) ─────────────────
  const _SERIE_TIPOS = [
    { tipo: 'NOTA_VENTA', icon: '📋', color: '#94a3b8', bg: 'rgba(148,163,184,0.12)', border: 'rgba(148,163,184,0.4)' },
    { tipo: 'BOLETA',     icon: '🧾', color: '#60a5fa', bg: 'rgba(96,165,250,0.12)',  border: 'rgba(96,165,250,0.4)' },
    { tipo: 'FACTURA',    icon: '🧮', color: '#a78bfa', bg: 'rgba(167,139,250,0.12)', border: 'rgba(167,139,250,0.4)' }
  ];

  function _renderInfraSeries(zona, estZona) {
    const series = (cfgData.series || []).filter(s => s.idZona === zona.idZona);
    const chips = _SERIE_TIPOS.map(t => {
      const seriesTipo = series.filter(s => s.tipoDocumento === t.tipo);
      if (!seriesTipo.length) {
        // Chip vacío: + serie de este tipo
        return `<button onclick="MOS.abrirModalSerieZona('${zona.idZona}','${t.tipo}')"
          class="inline-flex items-center gap-1.5 px-3 py-2 rounded-lg border border-dashed text-[11px] hover:bg-slate-800/50 transition-colors"
          style="border-color:#334155;color:#64748b;"
          title="Crear serie ${t.tipo} para esta zona">
          <span>${t.icon}</span>
          <span class="font-bold">+ ${t.tipo}</span>
        </button>`;
      }
      // Determinar nombre representativo
      const nombres = [...new Set(seriesTipo.map(s => s.serie))];
      const tieneDiversidad = nombres.length > 1;
      const nombreShow = tieneDiversidad ? '⚠ ' + nombres.join('/') : nombres[0];
      const corrMax = Math.max(...seriesTipo.map(s => parseInt(s.correlativo, 10) || 0));
      const todasActivas = seriesTipo.every(s => String(s.activo) === '1');
      const cubre = seriesTipo.length;
      const total = estZona.length;
      const cobertura = (cubre === total) ? '' : ` · ${cubre}/${total} est.`;

      return `<button onclick="MOS.abrirModalSerieZona('${zona.idZona}','${t.tipo}',true)"
        class="inline-flex items-center gap-2 px-3 py-2 rounded-lg border text-[11px] hover:brightness-125 transition-all ${todasActivas ? '' : 'opacity-60'}"
        style="background:${t.bg};border-color:${t.border};color:${t.color};"
        title="${tieneDiversidad ? 'Diversidad de nombres entre estaciones' : 'Editar serie ' + t.tipo}">
        <span>${t.icon}</span>
        <div class="flex flex-col items-start leading-tight">
          <span class="font-black">${nombreShow}</span>
          <span class="text-[9px] opacity-70">corr ${corrMax}${cobertura}</span>
        </div>
        ${todasActivas ? '' : '<span class="text-[9px] text-slate-500">⏸</span>'}
      </button>`;
    }).join('');

    return `<div class="mb-3 pb-3" style="border-bottom:1px dashed #1e293b;">
      <div class="flex items-center gap-2 mb-2">
        <span class="text-[10px] font-bold text-slate-500 uppercase tracking-wider">📄 Series documentales</span>
        ${estZona.length === 0 ? '<span class="text-[9px] text-amber-500 italic">⚠ agrega estaciones primero</span>' : ''}
      </div>
      <div class="flex flex-wrap gap-2">${chips}</div>
    </div>`;
  }

  function _renderInfraEstacion(e, impresoras) {
    const activa = String(e.activo) === '1' || e.activo === 1 || e.activo === true;
    const imps = impresoras.filter(i => i.idEstacion === e.idEstacion);
    const tipoIcon = { CAJA: '🛒', ALMACEN: '🏭', ENVASADO: '🍶' }[e.tipo] || '📍';
    const appColor = e.appOrigen === 'mosExpress' ? '#818cf8' : '#fb923c';
    const appBadge = e.appOrigen === 'mosExpress'
      ? '<span class="text-[9px] font-bold px-1.5 py-0.5 rounded" style="background:rgba(99,102,241,0.2);color:#a5b4fc;">ME</span>'
      : '<span class="text-[9px] font-bold px-1.5 py-0.5 rounded" style="background:rgba(249,115,22,0.2);color:#fdba74;">WH</span>';
    const safeId = String(e.idEstacion).replace(/'/g, '&#39;');

    const impsHTML = imps.length
      ? imps.map(i => {
          const impActiva = String(i.activo) === '1' || i.activo === 1 || i.activo === true;
          const impIcon = { TICKET: '🖨️', ADHESIVO: '🏷️', ZPL: '📄' }[i.tipo] || '🖨️';
          // [v2.41.81] Estado semántico de PrintNode con 11 diagnósticos
          // distintos (SIN_ID, ID_INVALIDO, PC_OFFLINE, SIN_PAPEL, SIN_TINTA,
          // ATASCO, TAPA_ABIERTA, PAUSED, DISABLED, ERROR, ONLINE, UNKNOWN).
          // El backend devuelve {state, reason, icon, color}. El frontend
          // solo mapea a clase CSS — no decide el diagnóstico.
          const pnSt = _impPNEstado[String(i.printNodeId)];
          const _impStateMap = {
            ONLINE:          { cls: 'imp-on',       tx: 'online' },
            PC_OFFLINE:      { cls: 'imp-pc-off',   tx: 'PC apagada' },
            PRINTER_OFFLINE: { cls: 'imp-off',      tx: 'apagada' },
            SIN_PAPEL:       { cls: 'imp-warn',     tx: 'sin papel' },
            SIN_TINTA:       { cls: 'imp-warn',     tx: 'sin tinta' },
            ATASCO:          { cls: 'imp-err',      tx: 'atasco' },
            TAPA_ABIERTA:    { cls: 'imp-warn',     tx: 'tapa abierta' },
            PAUSED:          { cls: 'imp-paused',   tx: 'pausada' },
            DISABLED:        { cls: 'imp-disabled', tx: 'deshabilitada' },
            ERROR:           { cls: 'imp-err',      tx: 'error' },
            SIN_ID:          { cls: 'imp-noid',     tx: 'sin ID' },
            ID_INVALIDO:     { cls: 'imp-err',      tx: 'ID inválido' },
            UNKNOWN:         { cls: 'imp-noinfo',   tx: 'sin señal' }
          };
          let estadoBadge = '';
          if (_impPNCargado) {
            // Si no hay printNodeId, el badge "SIN_ID" igualmente debe verse
            // (lo trae el backend ahora). Si por algún motivo no llegó info,
            // sigue cayendo a UNKNOWN.
            const st = (pnSt && pnSt.state) ? pnSt.state : (i.printNodeId ? 'UNKNOWN' : 'SIN_ID');
            const cfg = _impStateMap[st] || _impStateMap.UNKNOWN;
            const icon = (pnSt && pnSt.icon) || '❔';
            const reason = (pnSt && pnSt.reason) || cfg.tx;
            estadoBadge = `<span class="imp-estado ${cfg.cls}" title="${_escapeHtml(reason)}">${icon} ${cfg.tx}</span>`;
          }
          const stCur = pnSt && pnSt.state;
          const offlineCls = (_impPNCargado && stCur && stCur !== 'ONLINE') ? ' imp-row-off' : '';
          return `<div class="flex items-center gap-2 px-2 py-1.5 rounded ${impActiva ? '' : 'opacity-50'}${offlineCls}" style="background:#0a1424;border:1px solid #1e293b;">
            <span class="text-sm shrink-0">${impIcon}</span>
            <div class="flex-1 min-w-0">
              <div class="text-xs font-medium text-slate-200 truncate">${i.nombre} ${estadoBadge}</div>
              <div class="text-[10px] text-slate-500 truncate">PN ${i.printNodeId || '—'} · ${i.tipo}${pnSt && pnSt.computer ? ' · ' + pnSt.computer : ''}</div>
            </div>
            <label class="pers-switch" style="transform:scale(0.7);" title="${impActiva ? 'Desactivar' : 'Activar'}" onclick="event.stopPropagation()">
              <input type="checkbox" ${impActiva ? 'checked' : ''} onchange="MOS.toggleImpresoraActiva('${i.idImpresora}', event)">
              <span class="pers-switch-slider"></span>
            </label>
            <button onclick="MOS.abrirModalImpresora('${i.idImpresora}')" class="text-[10px] text-slate-500 hover:text-white p-1" title="Editar">✏️</button>
          </div>`;
        }).join('')
      : `<div class="text-[10px] text-amber-500 italic px-2 py-1.5">⚠ sin impresoras</div>`;

    // Dispositivos asignados a esta estación (última sesión, sin límite de tiempo)
    const dispEnEst = _dispEnEstacion(e.idEstacion);
    const dispsHTML = dispEnEst.length
      ? `<div class="mt-2 pt-2" style="border-top:1px dashed #1e293b;">
          <div class="text-[9px] font-bold text-slate-500 uppercase tracking-wider mb-1.5">📱 Asignados a esta estación</div>
          <div class="space-y-1.5">
            ${dispEnEst.map(d => {
              const ico = _dispIcono(d.Nombre_Equipo);
              const act = _dispActividad(d.Ultima_Conexion);
              const idAttr = String(d.ID_Dispositivo).replace(/'/g, '&#39;');
              const movio = _dispSeMovio(d);
              const isFresh = act.minutos < 5;
              const claseAnim = movio ? 'disp-chip-moved' : (_dispRenderCount === 0 ? 'disp-chip-arrived' : '');
              const claseFresh = isFresh ? 'disp-chip-live' : '';
              const bgColor = movio ? 'rgba(99,102,241,0.12)' : (isFresh ? 'rgba(16,185,129,0.10)' : 'rgba(16,185,129,0.06)');
              const bordColor = movio ? 'rgba(99,102,241,0.5)' : (isFresh ? 'rgba(16,185,129,0.5)' : 'rgba(16,185,129,0.25)');
              const movedBadge = movio ? '<span class="text-[8px] font-bold text-indigo-300 ml-1" title="Recién movido a esta estación">📍 movido</span>' : '';
              const dotPulse = isFresh ? '<span class="disp-dot-pulse"></span>' : '';
              const _pinBtn = '';
              const _yoBadge = '';
              return `<div class="disp-chip flex items-center gap-1.5 px-2 py-1.5 rounded ${claseAnim} ${claseFresh}"
                style="background:${bgColor};border:1px solid ${bordColor};transition:all 0.2s;">
                <span class="text-sm shrink-0 relative cursor-pointer" onclick="MOS.abrirModalDispositivo('${idAttr}')" title="Editar">${ico}${dotPulse}</span>
                <div class="flex-1 min-w-0 cursor-pointer" onclick="MOS.abrirModalDispositivo('${idAttr}')">
                  <div class="text-xs font-medium text-slate-200 truncate">${d.Nombre_Equipo || '—'}${movedBadge}${_yoBadge}</div>
                  <div class="text-[9px] truncate" style="color:${act.color};">${act.dot} ${act.label}${d.Ultima_Sesion ? ' · 👤 <span class="text-emerald-400 font-bold">' + d.Ultima_Sesion + '</span>' : ''}</div>
                </div>
                ${_pinBtn}
                <button onclick="event.stopPropagation();MOS.abrirDetalleDispositivo('${idAttr}')" class="shrink-0 w-6 h-6 rounded-full flex items-center justify-center hover:scale-110 transition-all" style="background:rgba(251,191,36,0.18);border:1px solid rgba(251,191,36,0.5);color:#fcd34d;font-size:10px;" title="Permisos y acciones del dispositivo">🛡️</button>
                <button onclick="event.stopPropagation();MOS.abrirEspiaDispositivo('${idAttr}')" class="shrink-0 w-6 h-6 rounded-full flex items-center justify-center hover:scale-110 transition-all" style="background:rgba(99,102,241,0.18);border:1px solid rgba(99,102,241,0.5);color:#a5b4fc;font-size:10px;" title="Espiar (audio + GPS — clásico)">🕵️</button>
                ${_esMasterSession() ? `<button onclick="event.stopPropagation();MOS.abrirEspiaV2('${idAttr}')" class="shrink-0 w-6 h-6 rounded-full flex items-center justify-center hover:scale-110 transition-all" style="background:linear-gradient(135deg,rgba(99,102,241,0.25),rgba(168,85,247,0.25));border:1px solid rgba(168,85,247,0.55);color:#c084fc;font-size:10px;animation:espiaBreath 3s infinite" title="Espía V2 · WebRTC live (Master)">🛰️</button>` : ''}
                ${_esMasterSession() ? `<button onclick="event.stopPropagation();MOS.abrirTimelineBufferEspia('${idAttr}')" class="shrink-0 w-6 h-6 rounded-full flex items-center justify-center hover:scale-110 transition-all" style="background:rgba(168,85,247,0.15);border:1px solid rgba(168,85,247,0.4);color:#c084fc;font-size:10px" title="Timeline buffer (12h histórico)">📼</button>` : ''}
                <span class="text-[10px] text-slate-500 p-1 cursor-pointer" onclick="event.stopPropagation();MOS.abrirModalDispositivo('${idAttr}')" title="Editar">✏️</span>
              </div>`;
            }).join('')}
          </div>
        </div>`
      : '';

    // B/F: Decoración según dispositivos online + modo heatmap
    const onlineEnEst = _dispOnlineEnEstacion(e.idEstacion);
    const fantasmasAqui = _dispFantasmasDeEstacion(e.idEstacion);
    let cardBg = '#0d1526';
    let cardBorder = activa ? '#1e293b' : '#475569';
    let cardExtra = '';
    if (_infraHeatmapActivo && activa) {
      const hm = _heatmapColor(_dispEnEstacion(e.idEstacion).length);
      cardBg = hm.bg !== 'transparent' ? hm.bg : cardBg;
      cardBorder = hm.border;
      cardExtra = `box-shadow: inset 0 0 20px ${hm.bg};`;
    } else if (activa && onlineEnEst > 0) {
      // B: borde verde sutil cuando hay dispositivos online
      cardBorder = 'rgba(16,185,129,0.5)';
      cardExtra = 'box-shadow: 0 0 12px rgba(16,185,129,0.18);';
    }

    // D: Trail fantasma — dispositivos que se fueron de aquí en los últimos 5s
    const fantasmasHTML = fantasmasAqui.length ? `
      <div class="mt-2 px-2 py-1.5 rounded text-[10px] disp-fantasma" style="background:rgba(99,102,241,0.05);border:1px dashed rgba(99,102,241,0.4);">
        ${fantasmasAqui.map(f => {
          const estDest = (cfgData.estaciones || []).find(es => es.idEstacion === f.hacia);
          return `<div class="flex items-center gap-1 italic opacity-80">
            <span>${f.ico}</span>
            <span class="text-slate-400">${f.nombre}</span>
            <span class="text-indigo-300">→</span>
            <span class="text-indigo-300 font-bold">${estDest?.nombre || '...'}</span>
            <span class="text-[8px] text-slate-600 ml-auto">se mudó hace momentos</span>
          </div>`;
        }).join('')}
      </div>` : '';

    return `<div class="rounded-lg p-3 ${activa ? '' : 'opacity-60'}" style="background:${cardBg};border:1px solid ${cardBorder};${cardExtra}transition:all 0.4s ease;">
      <div class="flex items-start gap-2 mb-2">
        <span class="text-xl shrink-0" style="line-height:1;">${tipoIcon}</span>
        <div class="flex-1 min-w-0">
          <div class="flex items-center gap-1.5 flex-wrap">
            <span class="text-sm font-bold text-white truncate">${e.nombre}</span>
            ${appBadge}
          </div>
          <div class="text-[10px] text-slate-500 font-mono truncate">${e.idEstacion}</div>
        </div>
        <label class="pers-switch shrink-0" style="transform:scale(0.85);" title="${activa ? 'Desactivar estación' : 'Activar estación'}" onclick="event.stopPropagation()">
          <input type="checkbox" ${activa ? 'checked' : ''} onchange="MOS.toggleEstacionActiva('${safeId}', event)">
          <span class="pers-switch-slider"></span>
        </label>
        <button onclick="MOS.abrirModalEstacion('${safeId}')" class="text-xs text-slate-400 hover:text-white p-1" title="Editar estación">✏️</button>
      </div>
      <div class="space-y-1.5">
        ${impsHTML}
      </div>
      <button onclick="MOS.abrirModalImpresora(null,'${safeId}')"
              class="mt-2 w-full text-[10px] text-slate-500 hover:text-white py-1.5 rounded border border-dashed border-slate-700 hover:border-purple-700 hover:bg-purple-900/20 transition-colors">
        + impresora
      </button>
      ${dispsHTML}
      ${fantasmasHTML}
    </div>`;
  }

  // ════════════════════════════════════════════════════════════
  // ZONA PREMIUM · ADMIN & MASTER (app=MOS, sin estación/impresora)
  // ════════════════════════════════════════════════════════════
  function _isAppMOS(d) {
    const a = String(d.App || '').toLowerCase();
    return a === 'mos';
  }

  function _renderInfraPremium() {
    const dispMOS = (cfgData.dispositivos || []).filter(_isAppMOS);
    if (!dispMOS.length) return '';
    const activos    = dispMOS.filter(d => String(d.Estado).toUpperCase() === 'ACTIVO');
    const pendientes = dispMOS.filter(d => String(d.Estado).toUpperCase() === 'PENDIENTE_APROBACION');
    const inactivos  = dispMOS.filter(d => ['INACTIVO','SUSPENDIDO'].indexOf(String(d.Estado).toUpperCase()) >= 0);
    const onlineNow  = activos.filter(d => _dispActividad(d.Ultima_Conexion).minutos < 5).length;

    const cardsHTML = dispMOS.map(d => {
      const ico   = _dispIcono(d.Nombre_Equipo);
      const act   = _dispActividad(d.Ultima_Conexion);
      const idAttr = String(d.ID_Dispositivo).replace(/'/g, '&#39;');
      const est   = String(d.Estado || '').toUpperCase();
      const isFresh = est === 'ACTIVO' && act.minutos < 5;
      const dotPulse = isFresh ? '<span class="disp-dot-pulse"></span>' : '';
      const estBadge = est === 'ACTIVO'
        ? '<span class="text-[9px] font-black px-1.5 py-0.5 rounded" style="background:rgba(16,185,129,0.18);color:#6ee7b7;border:1px solid rgba(16,185,129,0.4)">ACTIVO</span>'
        : (est === 'PENDIENTE_APROBACION'
          ? '<span class="text-[9px] font-black px-1.5 py-0.5 rounded" style="background:rgba(251,191,36,0.18);color:#fcd34d;border:1px solid rgba(251,191,36,0.4)">PENDIENTE</span>'
          : (est === 'SUSPENDIDO'
            ? '<span class="text-[9px] font-black px-1.5 py-0.5 rounded" style="background:rgba(148,163,184,0.18);color:#cbd5e1;border:1px solid rgba(148,163,184,0.4)">SUSPENDIDO</span>'
            : '<span class="text-[9px] font-black px-1.5 py-0.5 rounded" style="background:rgba(248,113,113,0.18);color:#fca5a5;border:1px solid rgba(248,113,113,0.4)">INACTIVO</span>'));

      // Mini-chips de permisos (parsea JSON)
      const permsMini = _renderDispPermisosChipsMini(d.Permisos_JSON);

      return `<div class="rounded-xl p-3 cursor-pointer transition-all hover:scale-[1.01] hover:shadow-lg"
        onclick="MOS.abrirDetalleDispositivo('${idAttr}')"
        style="background:linear-gradient(135deg,rgba(251,191,36,0.06),rgba(99,102,241,0.04));border:1px solid rgba(251,191,36,0.35);box-shadow:0 0 12px rgba(251,191,36,0.08);">
        <div class="flex items-start gap-2.5">
          <div class="relative shrink-0 text-2xl">${ico}${dotPulse}</div>
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-1.5 flex-wrap">
              <span class="font-black text-sm text-amber-100 truncate">${d.Nombre_Equipo || '—'}</span>
              ${estBadge}
            </div>
            <div class="text-[10px] text-amber-300/60 font-mono truncate mt-0.5">${String(d.ID_Dispositivo).substring(0,18)}...</div>
            <div class="text-[10px] mt-0.5" style="color:${act.color};">${act.dot} ${act.label}</div>
            ${permsMini}
          </div>
          <span class="text-amber-400/40 text-lg shrink-0">›</span>
        </div>
      </div>`;
    }).join('');

    return `<div class="card p-4 mb-4" style="background:linear-gradient(135deg,#1a1410 0%,#0d1526 50%,#1a1410 100%);border:2px solid rgba(251,191,36,0.45);box-shadow:0 0 24px rgba(251,191,36,0.12);">
      <div class="flex items-center gap-2 mb-3 pb-3" style="border-bottom:1px dashed rgba(251,191,36,0.25)">
        <span class="text-2xl">🏆</span>
        <div class="flex-1 min-w-0">
          <h3 class="font-black text-base text-amber-200">Zona Premium · Admin & Master</h3>
          <p class="text-[10px] text-amber-300/70">Dispositivos del panel MOS · sin estación ni impresora asignada</p>
        </div>
        <div class="flex items-center gap-2 text-[11px]">
          <span class="px-2 py-1 rounded-full font-bold" style="background:rgba(16,185,129,0.18);color:#6ee7b7;">${onlineNow} online</span>
          <span class="px-2 py-1 rounded-full font-bold" style="background:rgba(251,191,36,0.18);color:#fcd34d;">${activos.length} activos</span>
          ${pendientes.length ? `<span class="px-2 py-1 rounded-full font-bold animate-pulse" style="background:rgba(248,113,113,0.18);color:#fca5a5;">${pendientes.length} pend</span>` : ''}
          ${inactivos.length ? `<span class="px-2 py-1 rounded-full font-bold" style="background:rgba(148,163,184,0.15);color:#cbd5e1;">${inactivos.length} off</span>` : ''}
        </div>
      </div>
      <div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-2.5">${cardsHTML}</div>
    </div>`;
  }

  // Mini-chips de permisos para preview en cards (4 más relevantes)
  function _renderDispPermisosChipsMini(permsJson) {
    if (!permsJson) return '';
    let p = {};
    try { p = (typeof permsJson === 'string') ? JSON.parse(permsJson) : permsJson; } catch(_) { return ''; }
    const items = [
      { k: 'notif',   i: '🔔' },
      { k: 'cam',     i: '📸' },
      { k: 'mic',     i: '🎤' },
      { k: 'geo',     i: '📍' },
      { k: 'storage', i: '💾' }
    ];
    const chips = items.map(it => {
      const st = p[it.k];
      if (!st) return '';
      let bg, border, color;
      if (st === 'granted')          { bg='rgba(16,185,129,0.20)'; border='rgba(16,185,129,0.5)';  color='#6ee7b7'; }
      else if (st === 'denied')      { bg='rgba(248,113,113,0.20)'; border='rgba(248,113,113,0.5)'; color='#fca5a5'; }
      else if (st === 'unsupported') { bg='rgba(100,116,139,0.20)'; border='rgba(100,116,139,0.5)'; color='#94a3b8'; }
      else                            { bg='rgba(251,191,36,0.20)'; border='rgba(251,191,36,0.5)';  color='#fcd34d'; }
      return `<span class="inline-flex items-center text-[9px] px-1 py-0.5 rounded" style="background:${bg};border:1px solid ${border};color:${color};">${it.i}</span>`;
    }).filter(Boolean).join(' ');
    return chips ? `<div class="mt-1 flex gap-0.5">${chips}</div>` : '';
  }

  // Render completo de chips (en modal de detalle): muestra todos los permisos con label
  function _renderDispPermisosChipsFull(permsJson, lastUpdate) {
    let p = {};
    if (permsJson) {
      try { p = (typeof permsJson === 'string') ? JSON.parse(permsJson) : permsJson; } catch(_) { p = {}; }
    }
    const labels = {
      notif:   { i: '🔔', n: 'Notificaciones',   d: 'Pickups, anulaciones, alertas y avisos del admin llegan al dispositivo aunque la app esté cerrada.' },
      cam:     { i: '📸', n: 'Cámara',           d: 'Escaneo de códigos de barra de productos y guías. Sin esto, hay que digitar manualmente.' },
      mic:     { i: '🎤', n: 'Micrófono',        d: 'Búsqueda por voz y escucha remota del admin (espía 🕵️). Sin esto, sólo búsqueda por texto.' },
      geo:     { i: '📍', n: 'Geolocalización',  d: 'Ubica el dispositivo en su zona y rastrea repartos. Útil para auditoría de ruta del cajero móvil.' },
      audio:   { i: '🔊', n: 'Audio',            d: 'Alertas sonoras (nueva venta, error, pickup listo) y voz sintética que anuncia eventos.' },
      install: { i: '📱', n: 'App instalada',    d: 'PWA instalada en el escritorio/inicio. Funciona offline, abre más rápido y sin barra del navegador.' },
      storage: { i: '💾', n: 'Almacenamiento',   d: 'El sistema no borra automáticamente tus ventas/datos offline aunque ande corto de espacio. Crítico para no perder pendingSales.' }
    };
    const orden = ['notif','cam','mic','geo','audio','install','storage'];
    const tieneDatos = Object.keys(p).length > 0;
    if (!tieneDatos) {
      return `<div class="rounded-lg p-3 text-center text-xs text-slate-500 italic" style="background:#0a1424;border:1px dashed #334155;">
        Aún no se han reportado permisos desde este dispositivo. <br>
        <span class="text-[10px]">Se reportarán automáticamente al abrir la app.</span>
      </div>`;
    }
    const ts = lastUpdate ? `<span class="text-[10px] text-slate-500 italic">Actualizado: ${_dispActividad(lastUpdate).label}</span>` : '';
    const cards = orden.map(k => {
      const st = p[k];
      const lab = labels[k];
      if (!lab) return '';
      let bg, border, color, txt;
      if (!st)                       { bg='rgba(100,116,139,0.10)'; border='#334155';                color='#64748b'; txt='—'; }
      else if (st === 'granted')     { bg='rgba(16,185,129,0.12)';  border='rgba(16,185,129,0.45)'; color='#6ee7b7'; txt='✓ activo'; }
      else if (st === 'denied')      { bg='rgba(248,113,113,0.12)'; border='rgba(248,113,113,0.45)';color='#fca5a5'; txt='✗ denegado'; }
      else if (st === 'unsupported') { bg='rgba(100,116,139,0.10)'; border='rgba(100,116,139,0.4)'; color='#94a3b8'; txt='no soportado'; }
      else                            { bg='rgba(251,191,36,0.12)';  border='rgba(251,191,36,0.45)'; color='#fcd34d'; txt='⏳ pendiente'; }
      const info = (lab.d || '').replace(/"/g, '&quot;');
      return `<div class="flex items-center gap-2 p-2 rounded-lg" style="background:${bg};border:1px solid ${border};">
        <span class="text-lg shrink-0">${lab.i}</span>
        <div class="flex-1 min-w-0">
          <div class="flex items-center gap-1">
            <div class="text-xs font-bold truncate" style="color:${color}">${lab.n}</div>
            ${info ? `<span title="${info}" class="cursor-help text-[10px] opacity-60 hover:opacity-100" style="color:${color}">ⓘ</span>` : ''}
          </div>
          <div class="text-[10px] opacity-80" style="color:${color}">${txt}</div>
        </div>
      </div>`;
    }).join('');
    return `<div>
      <div class="flex items-center justify-between mb-2">
        <span class="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Permisos del dispositivo</span>
        ${ts}
      </div>
      <div class="grid grid-cols-2 gap-2">${cards}</div>
    </div>`;
  }

  // ════════════════════════════════════════════════════════════
  // MODAL DETALLE DISPOSITIVO — moderno con permisos + acciones
  // ════════════════════════════════════════════════════════════
  function abrirDetalleDispositivo(id) {
    const d = (cfgData.dispositivos || []).find(x => String(x.ID_Dispositivo) === String(id));
    if (!d) { toast('Dispositivo no encontrado', 'error'); return; }
    const ico = _dispIcono(d.Nombre_Equipo);
    const act = _dispActividad(d.Ultima_Conexion);
    const est = String(d.Estado || '').toUpperCase();
    const isMOS = _isAppMOS(d);
    const idAttr = String(d.ID_Dispositivo).replace(/'/g, '&#39;');

    const estChip = est === 'ACTIVO'
      ? '<span class="text-[10px] font-black px-2 py-1 rounded" style="background:rgba(16,185,129,0.20);color:#6ee7b7;border:1px solid rgba(16,185,129,0.5)">● ACTIVO</span>'
      : (est === 'PENDIENTE_APROBACION'
        ? '<span class="text-[10px] font-black px-2 py-1 rounded animate-pulse" style="background:rgba(251,191,36,0.20);color:#fcd34d;border:1px solid rgba(251,191,36,0.5)">⏳ PENDIENTE</span>'
        : (est === 'SUSPENDIDO'
          ? '<span class="text-[10px] font-black px-2 py-1 rounded" style="background:rgba(148,163,184,0.20);color:#e2e8f0;border:1px solid rgba(148,163,184,0.5)">💤 SUSPENDIDO</span>'
          : '<span class="text-[10px] font-black px-2 py-1 rounded" style="background:rgba(248,113,113,0.20);color:#fca5a5;border:1px solid rgba(248,113,113,0.5)">⛔ INACTIVO</span>'));

    const headerBg = isMOS
      ? 'linear-gradient(135deg,rgba(251,191,36,0.18),rgba(99,102,241,0.10))'
      : 'linear-gradient(135deg,rgba(99,102,241,0.10),transparent)';

    const html = `
      <div class="modal-box flex flex-col" style="max-width:560px;max-height:92vh">
        <div class="px-5 py-4 flex items-start gap-3 flex-shrink-0" style="border-bottom:1px solid #1e293b;background:${headerBg}">
          <div class="w-14 h-14 rounded-xl flex items-center justify-center text-3xl flex-shrink-0" style="background:${isMOS ? 'linear-gradient(135deg,#7c2d12,#f59e0b)' : 'linear-gradient(135deg,#1e3a8a,#6366f1)'};">
            ${ico}
          </div>
          <div class="min-w-0 flex-1">
            <div class="flex items-center gap-2 flex-wrap">
              <h2 class="font-bold text-base text-white truncate">${d.Nombre_Equipo || 'Sin nombre'}</h2>
              ${estChip}
            </div>
            <p class="text-[11px] text-slate-500 mt-1 font-mono truncate">${d.ID_Dispositivo}</p>
            <p class="text-[11px] mt-1" style="color:${act.color}">${act.dot} ${act.label}${d.Ultima_Sesion ? ' · 👤 ' + d.Ultima_Sesion : ''}</p>
          </div>
          <button onclick="MOS.cerrarDetalleDispositivo()" class="modal-close-x">×</button>
        </div>

        <div class="overflow-y-auto px-5 py-4 flex-1 space-y-4">
          <!-- App + Zona/Estación -->
          <div class="grid grid-cols-2 gap-2 text-xs">
            <div class="p-2.5 rounded-lg" style="background:#0a1424;border:1px solid #1e293b">
              <div class="text-[9px] uppercase text-slate-500 tracking-wider mb-1">App</div>
              <div class="font-bold text-slate-200">${(d.App || '—').toUpperCase()}</div>
            </div>
            <div class="p-2.5 rounded-lg" style="background:#0a1424;border:1px solid #1e293b">
              <div class="text-[9px] uppercase text-slate-500 tracking-wider mb-1">Última zona/estación</div>
              <div class="font-bold text-slate-200 truncate">${d.Ultima_Zona || '—'}${d.Ultima_Estacion ? ' · ' + d.Ultima_Estacion : ''}</div>
            </div>
          </div>

          <!-- Permisos -->
          ${_renderDispPermisosChipsFull(d.Permisos_JSON, d.Permisos_LastUpdate)}

          <!-- Acciones -->
          <div class="space-y-2">
            <div class="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Acciones (requieren clave admin 8 dig)</div>
            <button onclick="MOS.forzarWizardRemoto('${idAttr}')"
              class="w-full flex items-center gap-3 p-3 rounded-lg text-left transition-all hover:scale-[1.01]"
              style="background:linear-gradient(135deg,rgba(99,102,241,0.10),rgba(168,85,247,0.08));border:1px solid rgba(99,102,241,0.4)">
              <span class="text-2xl">🪄</span>
              <div class="flex-1 min-w-0">
                <div class="text-sm font-black text-indigo-200">Forzar re-wizard</div>
                <div class="text-[10px] text-indigo-300/70">Al próximo arranque, mostrarle el wizard de permisos</div>
              </div>
            </button>
            <button onclick="MOS.forzarPushRemoto('${idAttr}')"
              class="w-full flex items-center gap-3 p-3 rounded-lg text-left transition-all hover:scale-[1.01]"
              style="background:linear-gradient(135deg,rgba(16,185,129,0.10),rgba(45,212,191,0.08));border:1px solid rgba(16,185,129,0.4)">
              <span class="text-2xl">🔄</span>
              <div class="flex-1 min-w-0">
                <div class="text-sm font-black text-emerald-200">Reforzar registro push</div>
                <div class="text-[10px] text-emerald-300/70">Si no le llegan notifs/comandos/espía, fuerza re-registro del FCM token</div>
              </div>
            </button>
            <button onclick="MOS.verUltimaUbicacionDispositivo('${idAttr}')"
              class="w-full flex items-center gap-3 p-3 rounded-lg text-left transition-all hover:scale-[1.01]"
              style="background:linear-gradient(135deg,rgba(59,130,246,0.10),rgba(14,165,233,0.08));border:1px solid rgba(59,130,246,0.4)">
              <span class="text-2xl">🗺️</span>
              <div class="flex-1 min-w-0">
                <div class="text-sm font-black text-blue-200">Ver última ubicación GPS</div>
                <div class="text-[10px] text-blue-300/70">Última posición conocida (no necesita espía activo) · abre en Google Maps</div>
              </div>
            </button>
            <button onclick="MOS.revocarDispositivoUUID('${idAttr}')"
              class="w-full flex items-center gap-3 p-3 rounded-lg text-left transition-all hover:scale-[1.01]"
              style="background:linear-gradient(135deg,rgba(248,113,113,0.10),rgba(220,38,38,0.08));border:1px solid rgba(248,113,113,0.4)">
              <span class="text-2xl">🚫</span>
              <div class="flex-1 min-w-0">
                <div class="text-sm font-black text-red-200">Revocar acceso (UUID)</div>
                <div class="text-[10px] text-red-300/70">Bloquea este dispositivo físico — el usuario no podrá usar la app</div>
              </div>
            </button>
            <button onclick="MOS.cerrarDetalleDispositivo();MOS.abrirModalDispositivo('${idAttr}')"
              class="w-full flex items-center gap-3 p-3 rounded-lg text-left transition-all hover:scale-[1.01]"
              style="background:#0a1424;border:1px solid #334155">
              <span class="text-2xl">✏️</span>
              <div class="flex-1 min-w-0">
                <div class="text-sm font-bold text-slate-200">Editar detalles</div>
                <div class="text-[10px] text-slate-400">Renombrar, cambiar app, estado…</div>
              </div>
            </button>
          </div>
        </div>
      </div>`;

    let backdrop = $('modalDispDetalle');
    if (!backdrop) {
      backdrop = document.createElement('div');
      backdrop.id = 'modalDispDetalle';
      backdrop.className = 'modal-backdrop';
      backdrop.onclick = (e) => { if (e.target === backdrop) cerrarDetalleDispositivo(); };
      document.body.appendChild(backdrop);
    }
    backdrop.innerHTML = html;
    // El CSS .modal-backdrop tiene display:none por defecto. Mostramos con .open
    // (no solo quitar .hidden). Antes el modal NUNCA aparecía por este bug.
    backdrop.classList.remove('hidden');
    backdrop.classList.add('open');
  }

  function cerrarDetalleDispositivo() {
    const bd = $('modalDispDetalle');
    if (bd) {
      bd.classList.add('hidden');
      bd.classList.remove('open');
    }
  }

  // [v2.41.83] DEPRECATED — usar pedirAuth(opts) en lugar de prompt()
  async function _pedirClaveAdmin(accion) {
    const auth = await pedirAuth({ accion: accion, contexto: 'Acción protegida' });
    return auth ? auth.clave : '';
  }

  async function revocarDispositivoUUID(id) {
    const d = (cfgData.dispositivos || []).find(x => String(x.ID_Dispositivo) === String(id));
    if (!d) return;
    if (!await _modalConfirm(`¿Revocar el acceso de "${d.Nombre_Equipo}"?\n\nEl dispositivo quedará bloqueado y no podrá usar la app.`, { danger: true, titulo: 'Revocar dispositivo', okText: 'Sí, revocar' })) return;
    // [v2.41.83] AdminAuthModal universal (antes prompt() nativo)
    const auth = await pedirAuth({
      accion: 'REVOCAR_DISPOSITIVO',
      refDocumento: id,
      contexto: `Revocar "${d.Nombre_Equipo}" (${d.App}) · acción crítica`,
      allowCache: false  // tier 3 ya no cachea, pero forzamos por claridad
    });
    if (!auth) return;
    try {
      const r = await API.post('revocarDispositivo', { deviceId: id, claveAdmin: auth.clave, app: d.App });
      // [v2.42.00 fix] API.post devuelve data directo, no envuelto en r.data
      if (!r?.autorizado) {
        toast(r?.error || 'Clave incorrecta', 'error');
        return;
      }
      toast('Dispositivo revocado por ' + r.revocadoPor, 'ok');
      d.Estado = 'INACTIVO';
      cerrarDetalleDispositivo();
      renderInfra();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  async function forzarWizardRemoto(id) {
    const d = (cfgData.dispositivos || []).find(x => String(x.ID_Dispositivo) === String(id));
    if (!d) return;
    if (!await _modalConfirm(`Al próximo arranque de "${d.Nombre_Equipo}" se mostrará el wizard de permisos.\n\n¿Continuar?`, { warning: true, titulo: 'Forzar wizard remoto' })) return;
    // [v2.41.83] AdminAuthModal universal
    const auth = await pedirAuth({
      accion: 'FORZAR_WIZARD',
      refDocumento: id,
      contexto: `Forzar wizard en "${d.Nombre_Equipo}" (${d.App})`
    });
    if (!auth) return;
    try {
      const r = await API.post('forzarWizardDispositivo', { deviceId: id, claveAdmin: auth.clave, app: d.App });
      // [v2.42.00 fix] API.post devuelve data directo, no envuelto en r.data
      if (!r?.autorizado) {
        toast(r?.error || 'Clave incorrecta', 'error');
        return;
      }
      toast('Wizard forzado por ' + r.forzadoPor, 'ok');
      cerrarDetalleDispositivo();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  // [v2.43.71] Ver última ubicación GPS del dispositivo (sin necesidad
  // de espía activo). Útil cuando el device está bloqueado/cerrado pero
  // queremos saber dónde anduvo por última vez. Consulta la hoja
  // UBICACIONES_HISTORIAL que llenan _gpsRegistrarWH/_gpsRegistrar cada 5min.
  async function verUltimaUbicacionDispositivo(id) {
    const d = (cfgData.dispositivos || []).find(x => String(x.ID_Dispositivo) === String(id));
    if (!d) return;
    toast('🗺 Consultando última ubicación…', 'info', 2000);
    try {
      const r = await API.post('getUltimaUbicacionDispositivo', { deviceId: id });
      if (!r) {
        await _modalConfirm(`"${d.Nombre_Equipo}" no tiene ubicaciones registradas.\n\nEl device debe abrir la app y autorizar geolocalización para empezar a registrar (cada 5min auto).`, { warning: true, titulo: '🗺 Sin ubicaciones', okText: 'Entendido', cancelText: '' });
        return;
      }
      const lat = parseFloat(r.lat || r.latitude || 0);
      const lng = parseFloat(r.lng || r.longitude || 0);
      const acc = parseFloat(r.accuracy || r.acc || 0);
      const ts  = r.timestamp || r.ts || '';
      if (!lat || !lng) {
        toast('Última ubicación incompleta (sin lat/lng)', 'warn');
        return;
      }
      const cuandoMs = new Date(ts).getTime();
      const hace = isNaN(cuandoMs) ? '?' : (() => {
        const minutos = Math.round((Date.now() - cuandoMs) / 60000);
        if (minutos < 60) return 'hace ' + minutos + 'min';
        const horas = Math.round(minutos / 60);
        if (horas < 24) return 'hace ' + horas + 'h';
        return 'hace ' + Math.round(horas / 24) + 'd';
      })();
      const ok = await _modalConfirm(
        `📍 Última posición de "${d.Nombre_Equipo}":\n\n` +
        `🕐 ${hace} (${ts})\n` +
        `📍 ${lat.toFixed(6)}, ${lng.toFixed(6)}\n` +
        `🎯 Precisión: ±${Math.round(acc)} m`,
        { titulo: '🗺 Última ubicación GPS', okText: 'Abrir Google Maps', cancelText: 'Cerrar' }
      );
      if (ok) {
        const url = `https://www.google.com/maps?q=${lat},${lng}`;
        window.open(url, '_blank');
      }
    } catch(e) {
      toast('Error consultando ubicación: ' + e.message, 'error', 5000);
    }
  }

  // [v2.43.69] Forzar re-registro del FCM token remoto.
  // Usado cuando el device no aparece en PUSH_TOKENS y el espía/push directo
  // no le llega. Cliente al próximo poll consultarEstadoDispositivo verá
  // forzar_push=true y ejecuta _pushInit + limpia el flag.
  async function forzarPushRemoto(id) {
    const d = (cfgData.dispositivos || []).find(x => String(x.ID_Dispositivo) === String(id));
    if (!d) return;
    if (!await _modalConfirm(`"${d.Nombre_Equipo}" re-registrará su token de notificaciones en el próximo arranque.\n\nÚtil cuando el device no recibe pushes (espía no conecta, comandos no llegan).\n\n¿Continuar?`, { warning: true, titulo: 'Reforzar registro push' })) return;
    const auth = await pedirAuth({
      accion: 'FORZAR_PUSH',
      refDocumento: id,
      contexto: `Reforzar push en "${d.Nombre_Equipo}" (${d.App})`
    });
    if (!auth) return;
    try {
      const r = await API.post('forzarPushDispositivo', { deviceId: id, claveAdmin: auth.clave, app: d.App });
      if (!r?.autorizado) {
        toast(r?.error || 'Clave incorrecta', 'error');
        return;
      }
      toast('🔄 Push se re-registrará al próximo arranque del device · por ' + r.forzadoPor, 'ok', 6000);
      cerrarDetalleDispositivo();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

