  // ────────────────────────────────────────────────────────
  // MODAL NOTIFICACIONES UNIFICADAS
  // ────────────────────────────────────────────────────────
  function abrirModalNotificaciones() {
    openModal('modalNotificaciones');
    _renderNotificaciones();
  }

  function _renderNotificaciones() {
    const cont = $('notifContenido');
    if (!cont) return;
    const partes = [];
    let total = 0;

    // 1) Dispositivos pendientes
    const pendDisp = (cfgData.dispositivos || []).filter(d => String(d.Estado).toUpperCase() === 'PENDIENTE_APROBACION');
    if (pendDisp.length) {
      total += pendDisp.length;
      partes.push(`<div class="card p-3" style="background:#3b1010;border:1px solid #ef4444;">
        <div class="flex items-center gap-2 mb-2">
          <span class="text-xl">📱</span>
          <strong class="text-white text-sm">Dispositivos esperando aprobación</strong>
          <span class="badge badge-red text-[10px] ml-auto">${pendDisp.length}</span>
        </div>
        <div class="space-y-1.5">
          ${pendDisp.slice(0, 5).map(d => `<div class="text-[11px] text-slate-300 px-2 py-1 rounded flex items-center gap-1.5 flex-wrap" style="background:#0a1424;">
            <span>${_dispIcono(d.Nombre_Equipo)} ${d.Nombre_Equipo || 'Nuevo'}</span>
            ${_appBadge(d.App, { compact: false })}
            <span class="text-slate-600">·</span>
            <span class="text-slate-500 font-mono">${String(d.ID_Dispositivo).substring(0, 8)}...</span>
          </div>`).join('')}
        </div>
        <button onclick="MOS.closeModal('modalNotificaciones');MOS.nav('config');MOS.setCfgTab('infra')" class="mt-2 text-[10px] text-red-300 hover:text-red-200">Ver en Infraestructura →</button>
      </div>`);
    }

    // 2) Bloqueos vendedores ME activos
    const bloqs = (cfgData.bloqueosME || []).filter(b => b.fechaBloqueo && !b.unlockVigente);
    if (bloqs.length) {
      total += bloqs.length;
      partes.push(`<div class="card p-3" style="background:#3b2410;border:1px solid #f59e0b;">
        <div class="flex items-center gap-2 mb-2">
          <span class="text-xl">🔒</span>
          <strong class="text-white text-sm">Cajeros bloqueados</strong>
          <span class="badge badge-yellow text-[10px] ml-auto">${bloqs.length}</span>
        </div>
        <div class="space-y-1.5">
          ${bloqs.slice(0, 5).map(b => `<div class="text-[11px] text-slate-300 px-2 py-1 rounded" style="background:#0a1424;">
            👤 ${b.nombre} <span class="text-slate-600">·</span> <span class="text-slate-500">${b.motivo || ''}</span>
          </div>`).join('')}
        </div>
      </div>`);
    }

    // 3) Integridad alertas
    if (_personalIntegCount > 0) {
      total += _personalIntegCount;
      partes.push(`<div class="card p-3" style="background:#3b1010;border:1px solid #dc2626;">
        <div class="flex items-center gap-2 mb-2">
          <span class="text-xl">🛡️</span>
          <strong class="text-white text-sm">Integridad de catálogo</strong>
          <span class="badge badge-red text-[10px] ml-auto">${_personalIntegCount}</span>
        </div>
        <p class="text-[11px] text-slate-400">Hay alertas de seguridad en PRODUCTOS_MASTER o EQUIVALENCIAS.</p>
        <button onclick="MOS.closeModal('modalNotificaciones');MOS.abrirModalIntegridad()" class="mt-2 text-[10px] text-red-300 hover:text-red-200">Revisar →</button>
      </div>`);
    }

    if (total === 0) {
      cont.innerHTML = `<div class="text-center py-12 text-slate-500">
        <div class="text-5xl mb-3">✨</div>
        <p class="font-bold text-emerald-400">Todo en orden</p>
        <p class="text-xs">Sin notificaciones pendientes.</p>
      </div>`;
      $('notifSubtitle').textContent = 'Sin pendientes';
    } else {
      cont.innerHTML = partes.join('');
      $('notifSubtitle').textContent = `${total} pendiente${total === 1 ? '' : 's'}`;
    }
  }

  // ────────────────────────────────────────────────────────
  // MODAL ENVIAR PUSH a usuario
  // ────────────────────────────────────────────────────────
  function abrirModalEnviarPush(idPersonal, nombre) {
    $('pushDestinoUsuario').value = nombre || '';
    $('pushDestinoNombre').textContent = `a ${nombre || 'usuario'}`;
    $('pushTitulo').value = '📢 Mensaje del admin';
    $('pushCuerpo').value = '';
    openModal('modalEnviarPush');
    setTimeout(() => $('pushCuerpo')?.focus(), 100);
  }

  async function enviarPushUsuario() {
    const titulo = String($('pushTitulo')?.value || '').trim();
    const cuerpo = String($('pushCuerpo')?.value || '').trim();
    const dest = String($('pushDestinoUsuario')?.value || '').trim();
    if (!titulo || !cuerpo) { toast('Título y mensaje son requeridos', 'error'); return; }
    if (!dest) { toast('Destinatario no encontrado', 'error'); return; }
    closeModal('modalEnviarPush');
    try {
      // [F6 push dispatch · cero-GAS] select audiencia + Edge; null → GAS.
      const r = (await API.enviarPushSB(titulo, cuerpo, { soloUsuarios: [dest], incluirCompanions: true }))
             || (await API.post('enviarPushUsuario', { usuario: dest, titulo, cuerpo }));
      if (r?.tokensAlcanzados) {
        toast(`✓ Mensaje enviado a ${dest} (${r.tokensAlcanzados} dispositivo${r.tokensAlcanzados === 1 ? '' : 's'})`, 'ok');
      } else {
        toast(`✓ Mensaje enviado a ${dest}`, 'ok');
      }
    } catch(e) {
      // Si el usuario no tiene tokens, mostrar error claro
      const msg = e?.message || 'Error';
      if (msg.includes('no tiene dispositivos')) {
        toast(`⚠ ${dest} no tiene notificaciones activas. Pídele que las habilite al iniciar sesión.`, 'warn', 8000);
      } else {
        toast('Error: ' + msg, 'error');
      }
    }
  }

  // ────────────────────────────────────────────────────────
  // ACTUALIZAR BADGES (notif + integridad) en header de Personal
  // ────────────────────────────────────────────────────────
  async function _actualizarBadgesPersonal() {
    // Notificaciones unificadas
    const pendDisp = (cfgData.dispositivos || []).filter(d => String(d.Estado).toUpperCase() === 'PENDIENTE_APROBACION').length;
    const bloqs = (cfgData.bloqueosME || []).filter(b => b.fechaBloqueo && !b.unlockVigente).length;
    _personalNotifCount = pendDisp + bloqs + _personalIntegCount;
    const bN = $('personalNotifBadge');
    if (bN) {
      if (_personalNotifCount > 0) {
        bN.classList.remove('hidden');
        bN.textContent = _personalNotifCount;
      } else {
        bN.classList.add('hidden');
      }
    }
    // Integridad
    try {
      const r = await API.get('getAuditoriaIntegridad', {});
      const alertas = r?.alertas || r?.data || [];
      _personalIntegCount = Array.isArray(alertas) ? alertas.filter(a => !a.resuelto).length : 0;
    } catch(_) { _personalIntegCount = 0; }
    const bI = $('personalIntegBadge');
    if (bI) {
      if (_personalIntegCount > 0) {
        bI.classList.remove('hidden');
        bI.textContent = _personalIntegCount;
      } else {
        bI.classList.add('hidden');
      }
    }
  }

  async function guardarMetaChip(configKey, valor) {
    const v = String(valor || '').trim();
    if (!cfgData.config) cfgData.config = {};
    cfgData.config[configKey] = v;
    renderPersonal();
    try {
      await API.post('setConfig', { clave: configKey, valor: v });
      toast(`Meta actualizada · ${configKey} = ${v}`, 'ok');
    } catch(e) {
      toast('Error al guardar meta: ' + e.message, 'error');
    }
  }

  // Pinta el card "🛒 Vendedores — MosExpress" en Config → Personal.
  // Lee del cache localStorage de liquidaciones pendientes (mismo source
  // que la pantalla de Liquidaciones, ya prefetcheado al login).
  function _cfgRenderMeCajeros() {
    const cont = $('listMeCajeros');
    if (!cont) return;
    let pendientes = null;
    try {
      const raw = localStorage.getItem('mos_liq_pendientes');
      if (raw) {
        const p = JSON.parse(raw);
        pendientes = p && p.data;
      }
    } catch {}

    let cajeros = (pendientes && Array.isArray(pendientes.personal))
      ? pendientes.personal.filter(p => {
          const app = String(p.appOrigen || '').toLowerCase();
          return app === 'mosexpress' || app === 'mexpress' || app.indexOf('express') >= 0;
        })
      : [];
    // Agregar bloqueados que no aparecen en jornadas de la semana
    const _normN = s => String(s || '').trim().toLowerCase();
    const yaListados = new Set(cajeros.map(c => _normN(c.nombre)));
    (cfgData.bloqueosME || []).forEach(b => {
      if (!yaListados.has(_normN(b.nombre))) {
        cajeros.push({
          nombre: b.nombre,
          rol: 'CAJERO',
          appOrigen: 'mosExpress',
          montoTotal: 0, diasPendientes: 0, diasAuditados: 0,
          esVirtual: false
        });
      }
    });

    const cnt = $('cfgMeCajerosCount');
    if (cnt) {
      cnt.textContent = cajeros.length + (cajeros.length === 1 ? ' activo' : ' activos');
      cnt.className = 'badge ' + (cajeros.length ? 'badge-green' : 'badge-gray') + ' text-xs';
    }
    if (!cajeros.length) {
      cont.innerHTML = '<p class="text-xs text-slate-500 italic text-center py-3">Sin cajeros activos esta semana.</p>';
      return;
    }
    // Map por nombre normalizado: el bloqueo vive en BLOQUEOS_USUARIO (no toca PERSONAL_MASTER)
    const _norm = s => String(s || '').trim().toLowerCase();
    const bloqMap = {};
    (cfgData.bloqueosME || []).forEach(b => { bloqMap[_norm(b.nombre)] = b; });

    // Cruzar con DISPOSITIVOS para detectar última conexión + zona principal
    // del cajero (via Ultima_Zona del dispositivo donde tiene Ultima_Sesion).
    const dispPorCajero = {};
    (cfgData.dispositivos || []).forEach(d => {
      if (String(d.Estado).toUpperCase() !== 'ACTIVO') return;
      const sesNorm = _norm(d.Ultima_Sesion);
      if (!sesNorm) return;
      const t = new Date(d.Ultima_Conexion || 0).getTime() || 0;
      const prev = dispPorCajero[sesNorm];
      if (!prev || (new Date(prev.Ultima_Conexion || 0).getTime() || 0) < t) {
        dispPorCajero[sesNorm] = d;
      }
    });

    // Agrupar cajeros por zona inferida (Ultima_Zona del dispositivo)
    // Si no tiene dispositivo / Ultima_Zona → grupo "Sin zona"
    const grupos = {};
    cajeros.forEach(c => {
      const disp = dispPorCajero[_norm(c.nombre)];
      const zonaId = String(disp?.Ultima_Zona || '').trim() || '__SIN_ZONA__';
      if (!grupos[zonaId]) grupos[zonaId] = [];
      grupos[zonaId].push(c);
    });

    // Función render de una persona (común a todos los grupos)
    const renderPersona = (c) => {
      const initials = String(c.nombre || '?').split(/\s+/).map(s => s[0] || '').join('').slice(0, 2).toUpperCase();
      const monto = parseFloat(c.montoTotal) || 0;
      const dias = parseInt(c.diasPendientes) || 0;
      const aud  = parseInt(c.diasAuditados) || 0;
      const virt = c.esVirtual
        ? '<span class="badge badge-yellow text-[9px] ml-1" title="Detectado de ventas (no en PERSONAL_MASTER)">virtual</span>'
        : '';
      const reg = bloqMap[_norm(c.nombre)];
      const bloqueado = !!(reg && reg.fechaBloqueo && !reg.unlockVigente);
      const safeNombre = String(c.nombre || '').replace(/'/g, '&#39;');
      // Indicador de actividad cruzando con DISPOSITIVOS
      const dispActivo = dispPorCajero[_norm(c.nombre)];
      const act = dispActivo ? _personaActividad(dispActivo.Ultima_Conexion) : { color: '#64748b', label: 'sin sesión', dot: '⚫', minutos: Infinity };
      const isFresh = act.minutos < 5;
      const opacity = bloqueado ? 'opacity:0.6;' : '';
      const borderCol = bloqueado ? '#7f1d1d' : (isFresh ? 'rgba(16,185,129,0.5)' : '#1e293b');
      const bgChip = isFresh ? 'rgba(16,185,129,0.06)' : '#0d1526';
      const dotPulse = isFresh ? '<span class="disp-dot-pulse"></span>' : '';
      const claseFresh = isFresh ? 'disp-chip-live' : '';
      const lockBadge = bloqueado
        ? '<span class="badge badge-red text-[9px] ml-1" title="Cajero bloqueado — al iniciar MosExpress con este nombre, ve pantalla de candado">🔒 bloqueado</span>'
        : '';
      return `<div class="flex items-center gap-3 p-3 rounded-lg ${claseFresh}" style="background:${bgChip};border:1px solid ${borderCol};${opacity}transition:all 0.2s;">
        <div class="relative shrink-0">
          <div class="w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold"
               style="background:linear-gradient(135deg,#fbbf24,#f59e0b);color:#0b1220">${initials}</div>
          ${dotPulse}
        </div>
        <div class="flex-1 min-w-0">
          <div class="font-medium text-sm text-slate-200 truncate">${c.nombre}${virt}${lockBadge}</div>
          <div class="flex items-center gap-2 mt-0.5 flex-wrap">
            <span class="badge badge-gray text-[9px] uppercase">${c.rol || 'CAJERO'}</span>
            <span class="text-[9px]" style="color:${act.color};">${act.dot} ${act.label}</span>
            <span class="text-[9px] text-slate-500">${dias}d · ${aud}/${dias} aud</span>
          </div>
        </div>
        <div class="text-right shrink-0 mr-2">
          <div class="text-sm font-bold text-amber-400">S/ ${monto.toFixed(2)}</div>
          <div class="text-[10px] text-slate-500">esta semana</div>
        </div>
        <button onclick="event.stopPropagation();MOS.abrirEspiaPorUsuario('${safeNombre}')"
                class="shrink-0 w-8 h-8 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                style="background:rgba(99,102,241,0.18);border:1px solid rgba(99,102,241,0.5);color:#a5b4fc;font-size:13px;"
                title="Espiar a ${c.nombre} (audio + GPS)">🕵️</button>
        <button onclick="event.stopPropagation();MOS.abrirModalEnviarPush('','${safeNombre}')"
                class="shrink-0 w-8 h-8 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                style="background:rgba(59,130,246,0.15);border:1px solid rgba(59,130,246,0.5);color:#60a5fa;font-size:13px;"
                title="Enviar mensaje push a ${c.nombre}">💬</button>
        <label class="pers-switch shrink-0" title="${bloqueado ? 'Activar cajero — desbloquea pantalla de candado en su dispositivo' : 'Bloquear cajero — solo el dispositivo donde está logueado verá pantalla de candado'}">
          <input type="checkbox" ${bloqueado ? '' : 'checked'} onchange="MOS.toggleVendedorME('${safeNombre}', event)">
          <span class="pers-switch-slider"></span>
        </label>
      </div>`;
    };

    // Render por grupo (zona). Ordena las zonas alfabéticamente y deja
    // "Sin zona" al final.
    const zonaNombres = {};
    (cfgData.zonas || []).forEach(z => { zonaNombres[String(z.idZona)] = z.nombre || z.idZona; });
    const keys = Object.keys(grupos).sort((a,b) => {
      if (a === '__SIN_ZONA__') return 1;
      if (b === '__SIN_ZONA__') return -1;
      return (zonaNombres[a] || a).localeCompare(zonaNombres[b] || b);
    });
    cont.innerHTML = keys.map(zKey => {
      const lista = grupos[zKey];
      const nombreZona = zKey === '__SIN_ZONA__' ? '🌫 Sin zona asignada' : ('🏬 ' + (zonaNombres[zKey] || zKey));
      const rolesEnGrupo = {};
      lista.forEach(c => {
        const r = (c.rol || 'CAJERO').toUpperCase();
        rolesEnGrupo[r] = (rolesEnGrupo[r] || 0) + 1;
      });
      const desgloseRol = Object.keys(rolesEnGrupo)
        .map(r => `${rolesEnGrupo[r]} ${r.toLowerCase()}${rolesEnGrupo[r] !== 1 ? 's' : ''}`)
        .join(' · ');
      return `<div class="mb-3">
        <div class="flex items-center justify-between px-1 mb-1.5">
          <span class="text-[10px] uppercase tracking-wider text-amber-300/70 font-bold">${nombreZona}</span>
          <span class="text-[10px] text-slate-500">${desgloseRol}</span>
        </div>
        <div class="space-y-2">${lista.map(renderPersona).join('')}</div>
      </div>`;
    }).join('');
  }

  // Activa/bloquea un vendedor ME por NOMBRE en BLOQUEOS_USUARIO
  // (no toca PERSONAL_MASTER — los cajeros ME comparten el usuario plantilla)
  async function toggleVendedorME(nombre, ev) {
    if (ev) ev.stopPropagation();
    const checked = ev?.target?.checked;
    // checked=true → activar (sin bloqueo) ; checked=false → bloquear
    const accion = checked ? 'activar' : 'BLOQUEAR (mostrar pantalla de candado en su dispositivo)';
    if (!await _modalConfirm(`¿${accion.charAt(0).toUpperCase() + accion.slice(1)} a ${nombre}?\n\nSolo afecta al dispositivo donde "${nombre}" esté logueado en MosExpress. Otros cajeros siguen vendiendo normal.`, { warning: !checked, titulo: checked ? 'Activar vendedor' : 'Bloquear vendedor' })) {
      if (ev?.target) ev.target.checked = !checked;
      return;
    }
    try {
      await API.post('bloquearVendedorME', {
        nombre: nombre,
        appOrigen: 'mosExpress',
        bloquear: !checked,
        bloqueadoPor: S.session?.nombre || 'admin'
      });
      toast(`${nombre} ${checked ? 'activado' : 'bloqueado'} ✓`, 'ok');
      // Refrescar lista de bloqueos
      const bloq = await API.get('getVendedoresMEBloqueados', {});
      cfgData.bloqueosME = bloq || [];
      _cfgRenderMeCajeros();
    } catch(e) {
      console.error('[toggleVendedorME]', e);
      toast('Error: ' + e.message, 'error');
      if (ev?.target) ev.target.checked = !checked;
    }
  }

  // (renderSeries() obsoleto — series ahora viven dentro de Infraestructura como chips)

  function renderSeguridad() {
    // Reset panel a estado login
    seg_ocultar();
    // Renderizar lista de admins (de cfgData.usuarios MOS o llamar API)
    const listaEl = $('segListaAdmins');
    if (listaEl) {
      const admins = (cfgData.personalMOS || []).filter(u => {
        const r = String(u.rol || '').toUpperCase();
        return (r === 'MASTER' || r === 'ADMIN' || r === 'ADMINISTRADOR') && String(u.estado) === '1';
      });
      if (!admins.length) {
        listaEl.innerHTML = '<p class="text-slate-500 text-sm text-center py-4">Sin admins activos. Crea uno en pestaña Personal.</p>';
      } else {
        listaEl.innerHTML = admins.map(a => `
          <div class="flex items-center gap-3 p-3 rounded-lg" style="background:#0d1526;border:1px solid #1e293b;">
            <div class="w-9 h-9 rounded-full flex items-center justify-center text-white font-bold text-sm" style="background:${a.color || '#6366f1'}">
              ${(a.nombre || '?')[0]}${(a.apellido || '')[0] || ''}
            </div>
            <div class="flex-1 min-w-0">
              <div class="text-sm font-medium text-slate-200 truncate">${a.nombre} ${a.apellido || ''}</div>
              <div class="text-xs text-slate-500 uppercase tracking-wider">${a.rol}</div>
            </div>
          </div>
        `).join('');
      }
    }
  }

  // ── Seguridad: Clave Admin Global ──────────────────────
  let _segDataActual = null;

  function seg_ocultar() {
    const login = $('segPanelLogin');
    const clave = $('segPanelClave');
    if (login) login.classList.remove('hidden');
    if (clave) clave.classList.add('hidden');
    const inp = $('segPinAdmin');
    if (inp) inp.value = '';
    const err = $('segError');
    if (err) err.textContent = '';
    _segDataActual = null;
  }

  async function seg_consultarClave() {
    const inp = $('segPinAdmin');
    const err = $('segError');
    const pin = String(inp?.value || '').trim();
    if (!/^\d{4}$/.test(pin)) {
      if (err) err.textContent = 'Ingresa tu PIN de 4 dígitos';
      return;
    }
    if (err) err.textContent = '';
    try {
      const data = await API.get('getClaveAdminGlobal', { pinAdmin: pin });
      if (!data?.autorizado) {
        if (err) err.textContent = data?.error || 'PIN incorrecto';
        if (inp) inp.value = '';
        return;
      }
      _segDataActual = data;
      _segActualizarCacheLocal(data);
      _segPintar(data);
      seg_cargarAuditoria();
    } catch(e) {
      console.error('[seg_consultarClave]', e);
      if (err) err.textContent = e?.message || 'Sin conexión';
    }
  }

  function _segPintar(data) {
    const claveDig = $('segClaveDigits');
    if (claveDig) claveDig.textContent = (data.pin || '----').split('').join(' ');
    const dr = $('segDiasRestantes');
    if (dr) {
      const dias = data.diasParaProximaRotacion;
      dr.textContent = data.vencida ? '⚠ Vencida — rota ahora'
                       : (dias === 0 ? 'Hoy' : (dias + ' días'));
      dr.style.color = data.vencida ? '#f87171' : (dias <= 5 ? '#fbbf24' : '#10b981');
    }
    const barra = $('segBarraProgreso');
    if (barra) {
      const pct = Math.max(0, Math.min(100, ((30 - data.diasParaProximaRotacion) / 30) * 100));
      barra.style.width = pct + '%';
      if (data.vencida) barra.style.background = '#ef4444';
    }
    const fp = $('segFechaProxima');
    if (fp && data.fechaProximaRotacion) {
      const f = new Date(data.fechaProximaRotacion);
      fp.textContent = 'Próxima rotación: ' + f.toLocaleDateString('es-PE', { day: 'numeric', month: 'long', year: 'numeric' });
    }
    $('segPanelLogin')?.classList.add('hidden');
    $('segPanelClave')?.classList.remove('hidden');
  }

  async function seg_rotarManual() {
    const inp = $('segPinAdmin');
    const pin = String(inp?.value || '').trim();
    let pinUsar = pin;
    if (!/^\d{4}$/.test(pinUsar)) {
      pinUsar = await _modalPrompt('Ingresa tu PIN admin (4 dígitos) para confirmar la rotación:', '', { titulo: '🔐 Confirmar rotación', inputType: 'tel', inputMode: 'numeric', maxlength: 4 });
      if (!pinUsar || !/^\d{4}$/.test(pinUsar.trim())) {
        toast('Rotación cancelada · PIN inválido', 'warn');
        return;
      }
      pinUsar = pinUsar.trim();
    }
    if (!await _modalConfirm('¿Generar una nueva clave global aleatoria?\n\nLa clave actual dejará de funcionar inmediatamente en MosExpress y warehouseMos.', { danger: true, titulo: 'Rotar clave admin global', okText: 'Rotar ahora' })) return;
    try {
      const data = await API.post('rotarClaveAdminGlobal', { manual: true, pinAdmin: pinUsar });
      if (!data?.autorizado && data?.error) { toast(data.error, 'danger'); return; }
      _segDataActual = {
        pin: data.pin,
        fechaUltimaRotacion: data.fechaUltimaRotacion,
        fechaProximaRotacion: data.fechaProximaRotacion,
        diasDesdeRotacion: 0,
        diasParaProximaRotacion: 30,
        vencida: false
      };
      _segActualizarCacheLocal(_segDataActual);
      _segPintar(_segDataActual);
      seg_cargarAuditoria();
      toast('Clave rotada · ' + data.pin, 'ok', 5000);
    } catch(e) {
      console.error('[seg_rotarManual]', e);
      toast(e?.message || 'Sin conexión', 'danger');
    }
  }

  async function seg_cargarAuditoria() {
    const tbody = $('tbodyAuditoria');
    if (!tbody) return;
    tbody.innerHTML = '<tr><td colspan="5" class="text-center py-4 text-slate-500">Cargando...</td></tr>';
    try {
      const data = await API.get('getAuditoriaAdmin', { limit: 30 });
      if (!Array.isArray(data)) {
        tbody.innerHTML = '<tr><td colspan="5" class="text-center py-4 text-slate-500">Sin auditoría disponible.</td></tr>';
        return;
      }
      if (!data.length) {
        tbody.innerHTML = '<tr><td colspan="5" class="text-center py-6 text-slate-500">Aún no hay acciones registradas.</td></tr>';
        return;
      }
      tbody.innerHTML = data.map(a => {
        const fecha = a.fecha ? new Date(a.fecha) : null;
        const fmtFecha = fecha ? fecha.toLocaleDateString('es-PE', { day: '2-digit', month: '2-digit' }) + ' ' + fecha.toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit' }) : '—';
        const accColor = {
          'ANULACION': 'text-red-400',
          'CREDITO': 'text-amber-400',
          'CAMBIO_METODO': 'text-blue-400',
          'REABRIR_GUIA': 'text-purple-400',
          'DESBLOQUEO_USUARIO': 'text-emerald-400',
          'ROTACION_PIN_GLOBAL': 'text-pink-400'
        }[String(a.accion || '').toUpperCase()] || 'text-slate-400';
        return `<tr>
          <td class="text-slate-500">${fmtFecha}</td>
          <td class="${accColor} font-semibold text-xs uppercase tracking-wider">${a.accion || '—'}</td>
          <td class="text-slate-200">${a.nombreAutoriza || '—'}</td>
          <td class="text-slate-500 text-xs">${a.appOrigen || '—'}</td>
          <td class="text-slate-500 text-xs hidden sm:table-cell font-mono">${a.refDocumento || '—'}</td>
        </tr>`;
      }).join('');
    } catch(e) {
      tbody.innerHTML = '<tr><td colspan="5" class="text-center py-4 text-slate-500">Sin conexión</td></tr>';
    }
  }

  // (renderDispositivos() obsoleto — ahora viven dentro de Infraestructura)
  // Helpers compartidos para iconos / actividad de dispositivos
  function _dispIcono(nombre) {
    const n = String(nombre || '').toLowerCase();
    if (n.includes('tablet') || n.includes('ipad'))      return '📲';
    if (n.includes('celular') || n.includes('movil') || n.includes('phone')) return '📱';
    if (n.includes('laptop') || n.includes('notebook'))  return '💻';
    if (n.includes('pc ') || n.startsWith('pc') || n.includes('desktop')) return '🖥️';
    return '📱';
  }

  // Pill con la app de origen del dispositivo (ME / WH / MOS) — útil para que
  // el admin sepa de qué cliente viene la solicitud antes de aprobar.
  function _appBadge(appRaw, opts) {
    const app = String(appRaw || '').toLowerCase();
    let icon = '❓', label = 'desconocida', bg = 'rgba(148,163,184,0.15)', border = '#475569', fg = '#cbd5e1';
    if (app === 'mosexpress' || app === 'me' || app.indexOf('express') >= 0) {
      icon = '🛒'; label = 'MosExpress'; bg = 'rgba(16,185,129,0.15)'; border = '#10b981'; fg = '#6ee7b7';
    } else if (app === 'warehousemos' || app === 'wh' || app.indexOf('warehouse') >= 0) {
      icon = '📦'; label = 'warehouseMos'; bg = 'rgba(251,146,60,0.15)'; border = '#fb923c'; fg = '#fdba74';
    } else if (app === 'mos') {
      icon = '👑'; label = 'MOS panel'; bg = 'rgba(168,85,247,0.15)'; border = '#a855f7'; fg = '#d8b4fe';
    } else if (!app || app === '') {
      icon = '❓'; label = '?';
    }
    const compact = opts && opts.compact;
    const cls = compact ? 'text-[9px] px-1.5 py-0.5' : 'text-[10px] px-2 py-0.5';
    return `<span class="${cls} rounded font-bold inline-flex items-center gap-1" style="background:${bg};border:1px solid ${border};color:${fg};white-space:nowrap;">${icon} ${compact ? '' : label}</span>`;
  }

  function _dispActividad(ultimaConexion) {
    if (!ultimaConexion) return { color: '#64748b', label: 'sin conexión', dot: '⚫', minutos: Infinity };
    const t = _parseTsUtc(ultimaConexion);
    if (isNaN(t)) return { color: '#64748b', label: ultimaConexion, dot: '⚫', minutos: Infinity };
    const seg = Math.floor((Date.now() - t) / 1000);
    const min = Math.floor(seg / 60);
    if (seg < 0)       return { color: '#10b981', label: '🔴 LIVE · ahora', dot: '🟢', minutos: 0 };
    if (seg < 90)      return { color: '#10b981', label: `🔴 LIVE · hace ${seg}s`, dot: '🟢', minutos: min };
    if (min < 5)       return { color: '#10b981', label: `online · hace ${min}m`,  dot: '🟢', minutos: min };
    if (min < 60)      return { color: '#10b981', label: `hace ${min}m`,     dot: '🟢', minutos: min };
    if (min < 60*24)   return { color: '#fbbf24', label: `hace ${Math.floor(min/60)}h`, dot: '🟡', minutos: min };
    if (min < 60*24*7) return { color: '#f97316', label: `hace ${Math.floor(min/60/24)}d`, dot: '🟠', minutos: min };
    return { color: '#ef4444', label: `inactivo ${Math.floor(min/60/24)}d`, dot: '🔴', minutos: min };
  }

  // Tracking de movimientos entre renders para animar transiciones
  let _dispUltimaEstacionMap = {};
  let _dispRenderCount = 0;
  // Trails: fantasmas que se quedan 5s en la estación de origen tras un movimiento
  let _dispFantasmas = {}; // { deviceId: { desde, hacia, ico, nombre, expira } }
  let _dispCleanupTimer = null;
  // Modo heatmap: colorea estaciones según cantidad de dispositivos online
  let _infraHeatmapActivo = false;

  // Devuelve dispositivos cuya ÚLTIMA sesión fue en esta estación
  // (sin importar cuánto tiempo, mantiene "viviendo" donde estuvo último)
  function _dispEnEstacion(idEstacion) {
    return (cfgData.dispositivos || []).filter(d => {
      if (String(d.Estado).toUpperCase() !== 'ACTIVO') return false;
      return String(d.Ultima_Estacion || '') === String(idEstacion);
    });
  }

  // Devuelve solo dispositivos que NUNCA se han logueado en una estación
  // (recién aprobados o registrados a mano sin sesión todavía)
  function _dispMoviles() {
    return (cfgData.dispositivos || []).filter(d => {
      const estado = String(d.Estado).toUpperCase();
      if (estado === 'PENDIENTE_APROBACION') return false; // van en sección aparte
      if (estado === 'INACTIVO') return false;             // bloqueados no se muestran como móviles
      // [v2.43.68] Excluir dispositivos del MOS Admin — ya aparecen en
      // "Zona Premium · Admin & Master". Antes el mismo dispositivo se mostraba
      // duplicado en ambas listas (App=mos siempre cumple !Ultima_Estacion).
      if (_isAppMOS(d)) return false;
      return !d.Ultima_Estacion; // solo los que nunca tuvieron estación
    });
  }

  // Detectar si el dispositivo se movió de estación entre renders
  function _dispSeMovio(d) {
    if (_dispRenderCount === 0) return false; // primer render, no animar
    const prev = _dispUltimaEstacionMap[d.ID_Dispositivo];
    const ahora = String(d.Ultima_Estacion || '');
    return prev !== undefined && prev !== ahora;
  }

  function _dispActualizarMapa() {
    let huboMovimientos = false;
    (cfgData.dispositivos || []).forEach(d => {
      const prev = _dispUltimaEstacionMap[d.ID_Dispositivo];
      const ahora = String(d.Ultima_Estacion || '');
      // Detectar movimiento real (entre 2 renders, ambas estaciones definidas)
      if (_dispRenderCount > 0 && prev !== undefined && prev !== '' && prev !== ahora && ahora) {
        const ico = _dispIcono(d.Nombre_Equipo);
        const nombre = d.Nombre_Equipo || 'Dispositivo';
        _dispFantasmas[d.ID_Dispositivo] = {
          desde: prev,
          hacia: ahora,
          ico,
          nombre,
          expira: Date.now() + 5000
        };
        // E: Toast notif del movimiento
        const estDest = (cfgData.estaciones || []).find(e => e.idEstacion === ahora);
        const nombreDest = estDest?.nombre || ahora;
        try { toast(`📍 ${nombre} se movió a ${nombreDest}`, 'ok'); } catch(_) {}
        huboMovimientos = true;
      }
      _dispUltimaEstacionMap[d.ID_Dispositivo] = ahora;
    });
    _dispRenderCount++;
    // Programar re-render para que los fantasmas desaparezcan a los 5s
    if (huboMovimientos) {
      if (_dispCleanupTimer) clearTimeout(_dispCleanupTimer);
      _dispCleanupTimer = setTimeout(() => {
        _dispCleanupTimer = null;
        if (S.cfgTab === 'infra') renderInfra();
      }, 5200);
    }
  }

  // Devuelve fantasmas vigentes que partieron de esta estación
  function _dispFantasmasDeEstacion(idEstacion) {
    const ahora = Date.now();
    return Object.entries(_dispFantasmas)
      .filter(([id, f]) => f.desde === idEstacion && f.expira > ahora)
      .map(([id, f]) => ({ id, ...f }));
  }

  // Cuenta dispositivos online (ACTIVO + actividad <5 min) en una estación
  function _dispOnlineEnEstacion(idEstacion) {
    return _dispEnEstacion(idEstacion).filter(d =>
      _dispActividad(d.Ultima_Conexion).minutos < 5
    ).length;
  }

  // Toggle heatmap
  function infraToggleHeatmap() {
    _infraHeatmapActivo = !_infraHeatmapActivo;
    renderInfra();
  }

  // Color del borde según densidad de dispositivos en estación (modo heatmap)
  function _heatmapColor(cantOnline) {
    if (cantOnline === 0) return { bg: 'transparent', border: '#1e293b', label: '' };
    if (cantOnline === 1) return { bg: 'rgba(14,165,233,0.10)',  border: '#0284c7', label: '🟦' };
    if (cantOnline === 2) return { bg: 'rgba(16,185,129,0.12)',  border: '#10b981', label: '🟩' };
    if (cantOnline === 3) return { bg: 'rgba(251,191,36,0.14)',  border: '#f59e0b', label: '🟨' };
    if (cantOnline <= 5)  return { bg: 'rgba(249,115,22,0.16)',  border: '#ea580c', label: '🟧' };
    return                       { bg: 'rgba(239,68,68,0.18)',   border: '#dc2626', label: '🟥' };
  }

  function _dispPendientes() {
    return (cfgData.dispositivos || []).filter(d =>
      String(d.Estado).toUpperCase() === 'PENDIENTE_APROBACION'
    );
  }

  // Render compacto de un chip de dispositivo (dentro de estación o lista global)
  function _renderDispositivoChip(d, opts) {
    opts = opts || {};
    const ico = _dispIcono(d.Nombre_Equipo);
    const act = _dispActividad(d.Ultima_Conexion);
    const idAttr = String(d.ID_Dispositivo).replace(/'/g, '&#39;');
    const isFresh = act.minutos < 5;
    const sesion = d.Ultima_Sesion ? ` · 👤 <span class="text-emerald-400 font-bold">${d.Ultima_Sesion}</span>` : '';
    const cls = opts.compact ? 'text-[10px] px-2 py-1.5' : 'text-[11px] px-3 py-2';
    const claseFresh = isFresh ? 'disp-chip-live' : '';
    const dotPulse = isFresh ? '<span class="disp-dot-pulse"></span>' : '';
    const pinBtn = '';
    const yaSoyBadge = '';
    return `<div class="disp-chip flex items-center gap-2 rounded-lg ${cls} ${claseFresh}"
      style="background:#0a1424;border:1px solid #1e293b;transition:all 0.2s;">
      <span class="text-base shrink-0 relative cursor-pointer" onclick="MOS.abrirModalDispositivo('${idAttr}')" title="Editar">${ico}${dotPulse}</span>
      <div class="flex-1 min-w-0 cursor-pointer" onclick="MOS.abrirModalDispositivo('${idAttr}')">
        <div class="font-medium text-slate-200 truncate">${d.Nombre_Equipo || '—'} ${yaSoyBadge}</div>
        <div class="text-[9px] truncate" style="color:${act.color};">
          ${act.dot} ${act.label}${sesion}
        </div>
      </div>
      ${pinBtn}
      <button onclick="event.stopPropagation();MOS.abrirEspiaDispositivo('${idAttr}')" class="shrink-0 w-7 h-7 rounded-full flex items-center justify-center hover:scale-110 transition-all" style="background:rgba(99,102,241,0.18);border:1px solid rgba(99,102,241,0.5);color:#a5b4fc;font-size:11px;" title="Espiar dispositivo (audio + GPS)">🕵️</button>
      <button onclick="event.stopPropagation();MOS.abrirModalDispositivo('${idAttr}')" class="text-[10px] text-slate-500 hover:text-white p-1" title="Editar">✏️</button>
    </div>`;
  }

  // Config CRUD
  function _estActualizarPreview() {
    const nom = ($('estNombre')?.value || '').trim();
    const tipo = $('estTipo')?.value || 'CAJA';
    const app = $('estApp')?.value || 'mosExpress';
    const idZona = $('estZona')?.value || '';
    const zonaName = idZona ? (cfgData.zonas.find(z => z.idZona === idZona)?.nombre || '—') : 'Sin zona';
    const tipoIcon = { CAJA: '🛒', ALMACEN: '🏭', ENVASADO: '🍶' }[tipo] || '📍';
    const appLbl = app === 'mosExpress' ? 'ME' : 'WH';
    const sub = $('modalEstSubtitle');
    if (sub) sub.textContent = nom ? `${tipo} · ${appLbl} · ${zonaName}` : 'Caja / almacén';
    const ico = $('estIconPreview');
    if (ico) ico.textContent = tipoIcon;
  }

  function abrirModalEstacion(id, presetIdZona) {
    ['Id','Nombre','Tipo','App','Pin','Desc'].forEach(f => {
      const el = $('est' + f); if (el && el.tagName !== 'SELECT') el.value = '';
    });
    // Poblar select de zonas dinámicamente
    const zonaSelect = $('estZona');
    if (zonaSelect) {
      zonaSelect.innerHTML = '<option value="">— Sin zona —</option>' +
        cfgData.zonas.filter(z => z.estado === '1' || z.estado === 1).map(z =>
          `<option value="${z.idZona}">${z.nombre}</option>`
        ).join('');
    }
    const estadoWrap = $('estEstadoWrap');
    const btnElim = $('estBtnEliminar');
    const tg = $('estEstadoToggle');
    if (id) {
      const e = cfgData.estaciones.find(x => x.idEstacion === id);
      if (!e) return;
      $('modalEstTitle').textContent = 'Editar Estación';
      $('estId').value     = e.idEstacion;
      $('estNombre').value = e.nombre || '';
      if (zonaSelect) zonaSelect.value = e.idZona || '';
      $('estTipo').value   = e.tipo || 'CAJA';
      $('estApp').value    = e.appOrigen || 'mosExpress';
      $('estDesc').value   = e.descripcion || '';
      if (tg) tg.checked = String(e.activo) === '1' || e.activo === 1 || e.activo === true;
      if (estadoWrap) estadoWrap.classList.remove('hidden');
      if (btnElim)    btnElim.classList.remove('hidden');
    } else {
      $('modalEstTitle').textContent = 'Nueva Estación';
      $('estId').value = '';
      $('estTipo').value = 'CAJA';
      $('estApp').value = 'mosExpress';
      if (tg) tg.checked = true;
      if (estadoWrap) estadoWrap.classList.add('hidden');
      if (btnElim)    btnElim.classList.add('hidden');
      // Preset de zona si se está creando desde dentro de una zona
      if (presetIdZona && zonaSelect) zonaSelect.value = presetIdZona;
    }
    _estActualizarPreview();
    openModal('modalEstacion');
  }

  async function guardarEstacion() {
    const idEdit = $('estId')?.value || undefined;
    const tg = $('estEstadoToggle');
    const params = {
      idEstacion:  idEdit,
      nombre:      ($('estNombre')?.value || '').trim(),
      idZona:      $('estZona')?.value || '',
      tipo:        $('estTipo')?.value || 'CAJA',
      appOrigen:   $('estApp')?.value || 'mosExpress',
      descripcion: $('estDesc')?.value || ''
    };
    if (idEdit) params.activo = (tg && tg.checked) ? '1' : '0';
    if (!params.nombre) { toast('Nombre requerido', 'error'); return; }
    if (!params.idEstacion) delete params.idEstacion;
    // OPTIMISTA
    const list = cfgData.estaciones;
    const backup = list.slice();
    if (idEdit) {
      const idx = list.findIndex(x => x.idEstacion === idEdit);
      if (idx >= 0) list[idx] = { ...list[idx], ...params };
    } else {
      list.push({ ...params, idEstacion: 'EST_TMP' + Date.now(), activo: '1', _tmp: true });
    }
    closeModal('modalEstacion');
    renderInfra();
    try {
      const res = await API.post(idEdit ? 'actualizarEstacion' : 'crearEstacion', params);
      if (!idEdit && res?.idEstacion) {
        const tmp = list.findIndex(x => x._tmp);
        if (tmp >= 0) { list[tmp].idEstacion = res.idEstacion; delete list[tmp]._tmp; }
      }
      toast('Estación guardada ✓', 'ok');
      renderInfra();
      // Auto-replicación: si es nueva y la zona ya tiene series, crearlas para esta estación
      if (!idEdit && res?.idEstacion && params.idZona) {
        await _replicarSeriesParaNuevaEstacion(res.idEstacion, params.idZona);
      }
    } catch(e) {
      cfgData.estaciones = backup;
      renderInfra();
      toast('Error: ' + e.message, 'error');
    }
  }

  // Si la zona ya tiene series configuradas, crear las filas correspondientes
  // para la nueva estación. Cada nueva fila empieza con correlativo=1.
  // El nombre de la serie se toma de la mayoría existente en la zona.
  async function _replicarSeriesParaNuevaEstacion(idEstacion, idZona) {
    if (!idEstacion || !idZona) return;
    const seriesZona = (cfgData.series || []).filter(s =>
      s.idZona === idZona && s.idEstacion !== idEstacion
    );
    if (!seriesZona.length) return; // zona sin series — no hay nada que replicar

    // Agrupar por tipoDocumento → escoger el nombre más frecuente
    const porTipo = {};
    seriesZona.forEach(s => {
      const k = s.tipoDocumento;
      if (!porTipo[k]) porTipo[k] = [];
      porTipo[k].push(s);
    });

    const nuevasFilas = [];
    Object.keys(porTipo).forEach(tipo => {
      const grupos = porTipo[tipo];
      const conteo = {};
      grupos.forEach(s => { conteo[s.serie] = (conteo[s.serie] || 0) + 1; });
      const nombreMasComun = Object.entries(conteo).sort((a, b) => b[1] - a[1])[0][0];
      // Verificar si ya existe (defensa contra duplicados)
      const yaExiste = (cfgData.series || []).some(s =>
        s.idEstacion === idEstacion && s.tipoDocumento === tipo
      );
      if (!yaExiste) {
        nuevasFilas.push({
          idEstacion,
          idZona,
          tipoDocumento: tipo,
          serie: nombreMasComun,
          correlativo: 1,
          activo: '1'
        });
      }
    });

    if (!nuevasFilas.length) return;

    // OPTIMISTA: agregar a cfgData.series con id temporal
    nuevasFilas.forEach(f => {
      cfgData.series.push({ ...f, idSerie: 'SER_TMP' + Date.now() + '_' + f.tipoDocumento, _tmp: true });
    });
    renderInfra();

    try {
      await Promise.all(nuevasFilas.map(f =>
        API.post('crearSerie', f).then(res => {
          if (res?.idSerie) {
            const tmp = cfgData.series.find(s => s._tmp && s.idEstacion === idEstacion && s.tipoDocumento === f.tipoDocumento);
            if (tmp) { tmp.idSerie = res.idSerie; delete tmp._tmp; }
          }
        })
      ));
      toast(`✓ Auto-replicadas ${nuevasFilas.length} serie${nuevasFilas.length === 1 ? '' : 's'} desde la zona`, 'ok');
      renderInfra();
    } catch(e) {
      console.error('[replicar series]', e);
      // Quitar las _tmp que no pudieron sincronizarse
      cfgData.series = cfgData.series.filter(s => !s._tmp);
      renderInfra();
      toast('La estación se creó pero falló la replicación de series', 'warn');
    }
  }

  async function eliminarEstacion() {
    const id = $('estId')?.value;
    if (!id) return;
    const e = cfgData.estaciones.find(x => x.idEstacion === id);
    if (!e) return;
    const numImp = cfgData.impresoras.filter(i => i.idEstacion === id).length;
    const msg = numImp > 0
      ? `¿Desactivar la estación "${e.nombre}"?\n\nTiene ${numImp} impresora${numImp === 1 ? '' : 's'} asociada${numImp === 1 ? '' : 's'}. Puedes reactivarla luego.`
      : `¿Desactivar la estación "${e.nombre}"?\n\nPodrás reactivarla cuando quieras.`;
    if (!await _modalConfirm(msg, { warning: true, titulo: 'Desactivar estación' })) return;
    closeModal('modalEstacion');
    const previo = e.activo;
    e.activo = '0';
    renderInfra();
    try {
      await API.post('actualizarEstacion', { idEstacion: id, activo: '0' });
      toast('Estación desactivada', 'ok');
    } catch(err) {
      e.activo = previo;
      renderInfra();
      toast('Error: ' + err.message, 'error');
    }
  }

  function _impActualizarPreview() {
    const nom = ($('impNombre')?.value || '').trim();
    const tipo = $('impTipo')?.value || 'TICKET';
    const app = $('impApp')?.value || 'mosExpress';
    const idEst = $('impEstacion')?.value || '';
    const estName = idEst ? (cfgData.estaciones.find(e => e.idEstacion === idEst)?.nombre || '—') : 'Sin estación';
    const tipoIcon = { TICKET: '🖨️', ADHESIVO: '🏷️', ZPL: '📄', AMBAS: '🖨️' }[tipo] || '🖨️';
    const appLbl = app === 'mosExpress' ? 'ME' : 'WH';
    const sub = $('modalImpSubtitle');
    if (sub) sub.textContent = nom ? `${tipo} · ${appLbl} · ${estName}` : 'PrintNode endpoint';
    const ico = $('impIconPreview');
    if (ico) ico.textContent = tipoIcon;
  }

  function abrirModalImpresora(id, presetIdEstacion) {
    ['Id','Nombre','PrintNodeId','Estacion','Zona','Desc'].forEach(f => {
      const el = $('imp' + f); if (el && el.tagName !== 'SELECT') el.value = '';
    });
    // Poblar select de estaciones dinámicamente
    const estSelect = $('impEstacion');
    if (estSelect) {
      estSelect.innerHTML = '<option value="">— Sin estación —</option>' +
        cfgData.estaciones.filter(e => String(e.activo) === '1').map(e => {
          const tipoIc = { CAJA: '🛒', ALMACEN: '🏭', ENVASADO: '🍶' }[e.tipo] || '📍';
          return `<option value="${e.idEstacion}">${tipoIc} ${e.nombre}</option>`;
        }).join('');
    }
    const estadoWrap = $('impEstadoWrap');
    const btnElim = $('impBtnEliminar');
    const tg = $('impEstadoToggle');
    if (id) {
      const imp = cfgData.impresoras.find(x => x.idImpresora === id);
      if (!imp) return;
      $('modalImpTitle').textContent = 'Editar Impresora';
      $('impId').value          = imp.idImpresora;
      $('impNombre').value      = imp.nombre || '';
      $('impPrintNodeId').value = imp.printNodeId || '';
      $('impTipo').value        = imp.tipo || 'TICKET';
      if (estSelect) estSelect.value = imp.idEstacion || '';
      $('impZona').value        = imp.idZona || '';
      $('impApp').value         = imp.appOrigen || 'mosExpress';
      $('impDesc').value        = imp.descripcion || '';
      if (tg) tg.checked = String(imp.activo) === '1' || imp.activo === 1 || imp.activo === true;
      if (estadoWrap) estadoWrap.classList.remove('hidden');
      if (btnElim)    btnElim.classList.remove('hidden');
    } else {
      $('modalImpTitle').textContent = 'Nueva Impresora';
      $('impId').value = '';
      $('impTipo').value = 'TICKET';
      $('impApp').value = 'mosExpress';
      if (tg) tg.checked = true;
      if (estadoWrap) estadoWrap.classList.add('hidden');
      if (btnElim)    btnElim.classList.add('hidden');
      // Preset desde la card de estación
      if (presetIdEstacion) {
        const e = cfgData.estaciones.find(x => x.idEstacion === presetIdEstacion);
        if (e) {
          if (estSelect)        estSelect.value         = e.idEstacion;
          if ($('impZona'))     $('impZona').value      = e.idZona || '';
          if ($('impApp'))      $('impApp').value       = e.appOrigen || 'mosExpress';
        }
      }
    }
    _impActualizarPreview();
    openModal('modalImpresora');
  }

  async function guardarImpresora() {
    const idEdit = $('impId')?.value || undefined;
    const tg = $('impEstadoToggle');
    const idEstSel = $('impEstacion')?.value || '';
    // Si seleccionó estación, deducir idZona y app
    let idZona = $('impZona')?.value || '';
    let appOrigen = $('impApp')?.value || 'mosExpress';
    if (idEstSel) {
      const e = cfgData.estaciones.find(x => x.idEstacion === idEstSel);
      if (e) { idZona = e.idZona || idZona; appOrigen = e.appOrigen || appOrigen; }
    }
    const params = {
      idImpresora:  idEdit,
      nombre:       ($('impNombre')?.value || '').trim(),
      printNodeId:  $('impPrintNodeId')?.value || '',
      tipo:         $('impTipo')?.value || 'TICKET',
      idEstacion:   idEstSel,
      idZona,
      appOrigen,
      descripcion:  $('impDesc')?.value || ''
    };
    if (idEdit) params.activo = (tg && tg.checked) ? '1' : '0';
    if (!params.nombre) { toast('Nombre requerido', 'error'); return; }
    if (!params.idImpresora) delete params.idImpresora;
    // OPTIMISTA
    const list = cfgData.impresoras;
    const backup = list.slice();
    if (idEdit) {
      const idx = list.findIndex(x => x.idImpresora === idEdit);
      if (idx >= 0) list[idx] = { ...list[idx], ...params };
    } else {
      list.push({ ...params, idImpresora: 'IMP_TMP' + Date.now(), activo: '1', _tmp: true });
    }
    closeModal('modalImpresora');
    renderInfra();
    try {
      const res = await API.post(idEdit ? 'actualizarImpresora' : 'crearImpresora', params);
      if (!idEdit && res?.idImpresora) {
        const tmp = list.findIndex(x => x._tmp);
        if (tmp >= 0) { list[tmp].idImpresora = res.idImpresora; delete list[tmp]._tmp; }
      }
      toast('Impresora guardada ✓', 'ok');
      renderInfra();
    } catch(e) {
      cfgData.impresoras = backup;
      renderInfra();
      toast('Error: ' + e.message, 'error');
    }
  }

  async function eliminarImpresora() {
    const id = $('impId')?.value;
    if (!id) return;
    const i = cfgData.impresoras.find(x => x.idImpresora === id);
    if (!i) return;
    if (!await _modalConfirm(`¿Desactivar la impresora "${i.nombre}"?\n\nDejará de recibir trabajos de impresión. Puedes reactivarla luego.`, { warning: true, titulo: 'Desactivar impresora' })) return;
    closeModal('modalImpresora');
    const previo = i.activo;
    i.activo = '0';
    renderInfra();
    try {
      await API.post('actualizarImpresora', { idImpresora: id, activo: '0' });
      toast('Impresora desactivada', 'ok');
    } catch(e) {
      i.activo = previo;
      renderInfra();
      toast('Error: ' + e.message, 'error');
    }
  }

  // Paleta de colores neón para avatares
  const _PERS_COLORS = [
    '#22c55e', '#10b981', '#06b6d4', '#0ea5e9', '#3b82f6',
    '#6366f1', '#8b5cf6', '#a855f7', '#d946ef', '#ec4899',
    '#f43f5e', '#ef4444', '#f97316', '#f59e0b', '#eab308',
    '#84cc16', '#14b8a6', '#22d3ee', '#fb7185', '#fbbf24'
  ];

  function _persColoresEnUso(excluirId) {
    const all = [...(cfgData.personalMOS || []), ...(cfgData.personal || [])];
    return new Set(
      all.filter(p => String(p.estado) === '1' && p.idPersonal !== excluirId)
         .map(p => String(p.color || '').toLowerCase())
    );
  }

  function _persPinsEnUsoAdmin(excluirId) {
    return new Set(
      (cfgData.personalMOS || [])
        .filter(p => p.idPersonal !== excluirId)
        .map(p => String(p.pin || ''))
        .filter(Boolean)
    );
  }

  function _persRandomColor() {
    const enUso = _persColoresEnUso($('persId')?.value);
    const disponibles = _PERS_COLORS.filter(c => !enUso.has(c.toLowerCase()));
    const pool = disponibles.length ? disponibles : _PERS_COLORS;
    const elegido = pool[Math.floor(Math.random() * pool.length)];
    const hidden = $('persColor');
    if (hidden) hidden.value = elegido;
    _persRenderChips();
    _persActualizarPreview();
  }

  function _persSeleccionarColor(c) {
    const hidden = $('persColor');
    if (hidden) hidden.value = c;
    _persRenderChips();
    _persActualizarPreview();
  }

  function _persRenderChips() {
    const cont = $('persColorChips');
    if (!cont) return;
    const sel = String($('persColor')?.value || '').toLowerCase();
    const enUso = _persColoresEnUso($('persId')?.value);
    cont.innerHTML = _PERS_COLORS.map(c => {
      const isSel = c.toLowerCase() === sel;
      const ocupado = enUso.has(c.toLowerCase()) && !isSel;
      const cls = `inline-block w-6 h-6 rounded-full transition-all`;
      const ring = isSel ? 'box-shadow:0 0 0 2px #fff,0 0 12px ' + c + ';transform:scale(1.15);' : '';
      const dim  = ocupado ? 'opacity:0.25;' : '';
      const cursor = ocupado ? 'cursor:not-allowed;' : 'cursor:pointer;';
      return `<button type="button" class="${cls}" style="background:${c};${ring}${dim}${cursor}border:2px solid #0d1526;"
              ${ocupado ? 'disabled' : ''}
              title="${ocupado ? 'En uso por otro usuario activo' : c}"
              onclick="MOS._persSeleccionarColor('${c}')"></button>`;
    }).join('');
  }

  function _persRandomPin() {
    const enUso = _persPinsEnUsoAdmin($('persId')?.value);
    let intentos = 0;
    let pin;
    do {
      pin = String(Math.floor(1000 + Math.random() * 9000));
      intentos++;
    } while (enUso.has(pin) && intentos < 100);
    const inp = $('persPin');
    if (inp) {
      inp.type = 'text';
      inp.value = pin;
      // ocultar después de 3s
      setTimeout(() => { if (inp.value === pin) inp.type = 'password'; }, 3000);
    }
  }

  function _persActualizarPreview() {
    const ini = ($('persNombre')?.value || '').trim().charAt(0).toUpperCase()
              + ($('persApellido')?.value || '').trim().charAt(0).toUpperCase();
    const av = $('persAvatarPreview');
    if (av) {
      av.textContent = ini || '??';
      av.style.background = $('persColor')?.value || '#6366f1';
    }
    const sub = $('modalPersSubtitle');
    if (sub) {
      const rol = $('persRol')?.value || '';
      const app = $('persAppOrigen')?.value || '';
      sub.textContent = (rol || '—') + (app ? ' · ' + app : '');
    }
  }

  // Selecciona option case-insensitive — devuelve el value real del select
  function _selectOptionCI(selectEl, value) {
    if (!selectEl || !value) return false;
    const v = String(value).trim().toUpperCase();
    for (const opt of selectEl.options) {
      if (String(opt.value).trim().toUpperCase() === v) {
        selectEl.value = opt.value;
        return true;
      }
    }
    return false;
  }

  function abrirModalPersonal(id, appOrigen = 'warehouseMos') {
    ['Nombre','Apellido','Pin','Tarifa','Monto'].forEach(f => {
      const el = $('pers' + f); if (el && el.tagName !== 'SELECT') el.value = '';
    });
    $('persId').value = '';
    $('persAppOrigen').value = appOrigen;
    const isMOS = appOrigen === 'MOS';
    const pagoWrap = $('persPagoWrap'); if (pagoWrap) pagoWrap.style.display = isMOS ? 'none' : '';
    // Set rol options based on app — todos en MAYÚSCULAS para coincidir con DB
    const rolSel = $('persRol');
    if (rolSel) {
      rolSel.innerHTML = isMOS
        ? '<option value="MASTER">MASTER (acceso total)</option><option value="ADMIN">ADMIN (sin configuración)</option>'
        : '<option value="ALMACENERO">ALMACENERO</option><option value="ENVASADOR">ENVASADOR</option>';
    }
    const pinInp = $('persPin');
    if (pinInp) pinInp.type = 'password';

    const source = isMOS ? cfgData.personalMOS : cfgData.personal;
    const estadoWrap = $('persEstadoWrap');
    const btnElim = $('persBtnEliminar');
    const pinHint = $('persPinHint');

    if (id) {
      const p = source.find(x => x.idPersonal === id);
      if (!p) return;
      $('modalPersTitle').textContent = isMOS ? 'Editar Usuario MOS' : 'Editar Operador';
      $('persId').value       = p.idPersonal;
      $('persNombre').value   = p.nombre || '';
      $('persApellido').value = p.apellido || '';
      // Match rol case-insensitive (la DB puede tener "MASTER" / "master" / "Admin"/etc.)
      if (rolSel && !_selectOptionCI(rolSel, p.rol)) {
        rolSel.value = isMOS ? 'ADMIN' : 'ALMACENERO';
      }
      $('persColor').value    = p.color || '#6366f1';
      if (!isMOS) {
        $('persMonto').value  = p.montoBase  || '';
      }
      // Toggle activo + botón eliminar visibles en edición
      if (estadoWrap) estadoWrap.classList.remove('hidden');
      if (btnElim)    btnElim.classList.remove('hidden');
      if (pinHint)    { pinHint.textContent = '(opcional al editar)'; pinHint.className = 'text-slate-500 text-[10px]'; }
      const tg = $('persEstadoToggle');
      if (tg) tg.checked = String(p.estado) === '1' || p.estado === true;
    } else {
      $('modalPersTitle').textContent = isMOS ? 'Nuevo Usuario MOS' : 'Nuevo Operador';
      if (rolSel) rolSel.value = isMOS ? 'ADMIN' : 'ALMACENERO';
      if (estadoWrap) estadoWrap.classList.add('hidden');
      if (btnElim)    btnElim.classList.add('hidden');
      if (pinHint)    { pinHint.textContent = 'requerido al crear', pinHint.className = 'text-amber-400 text-[10px]'; }
      // Auto: color random no-repetido + (si MOS) PIN random no-repetido
      _persRandomColor();
      if (isMOS) _persRandomPin();
    }
    _persRenderChips();
    _persActualizarPreview();
    openModal('modalPersonal');
  }

  async function guardarPersonal() {
    const appOrigen = $('persAppOrigen')?.value || 'warehouseMos';
    const isMOS = appOrigen === 'MOS';
    const idEdit = $('persId')?.value || undefined;
    const params = {
      idPersonal:  idEdit,
      nombre:      ($('persNombre')?.value || '').trim(),
      apellido:    ($('persApellido')?.value || '').trim(),
      rol:         $('persRol')?.value || (isMOS ? 'ADMIN' : 'ALMACENERO'),
      color:       $('persColor')?.value || '#6366f1',
      tipo:        'OPERADOR',
      appOrigen:   appOrigen
    };
    if (!isMOS) {
      params.montoBase  = $('persMonto')?.value  || 0;
    }
    const pin = $('persPin')?.value;
    if (pin) params.pin = pin;
    // Estado del toggle (solo aplica al editar)
    if (idEdit) {
      const tg = $('persEstadoToggle');
      params.estado = (tg && tg.checked) ? '1' : '0';
    }
    if (!params.nombre) { toast('Nombre requerido', 'error'); return; }
    if (!params.idPersonal && !pin) { toast('PIN requerido al crear', 'error'); return; }

    // [v2.43.30] OPTIMISTA REFORZADO: card temp persiste hasta que el real llegue
    // Bug previo: loadConfig() sobrescribía la lista entera antes de que el real
    // llegara → la card temp se perdía y el user "no veía nada hasta salir/volver".
    // Fix: mergeamos la respuesta del API directo en la lista sin esperar loadConfig.
    const list = isMOS ? (cfgData.personalMOS || []) : (cfgData.personal || []);
    const backup = list.slice();
    const tmpId = 'TMP_' + Date.now();
    if (idEdit) {
      const idx = list.findIndex(x => x.idPersonal === idEdit);
      if (idx >= 0) list[idx] = { ...list[idx], ...params };
    } else {
      list.unshift({ idPersonal: tmpId, estado: '1', _tmp: true, ...params });
    }
    closeModal('modalPersonal');
    renderPersonal();
    toast(idEdit ? 'Actualizado ✓' : 'Creado ✓', 'ok');
    try {
      const r = await API.post(idEdit ? 'actualizarPersonalMaster' : 'crearPersonalMaster', params);
      const d = (r && r.data) || r || {};
      // Si el backend devuelve el idPersonal real, reemplazar el TMP localmente
      // sin esperar loadConfig (evita el flicker y la card vacía).
      if (!idEdit && d.idPersonal) {
        const idxTmp = list.findIndex(x => x.idPersonal === tmpId);
        if (idxTmp >= 0) {
          list[idxTmp] = { ...list[idxTmp], idPersonal: d.idPersonal, _tmp: false };
          renderPersonal();
        }
      }
      // Refresh en bg sin invalidar lo que tenemos
      setTimeout(() => { S.loaded['config'] = false; loadConfig().catch(() => {}); }, 1500);
    } catch(e) {
      // Revertir
      if (isMOS) cfgData.personalMOS = backup; else cfgData.personal = backup;
      renderPersonal();
      toast('Error: ' + e.message, 'error');
    }
  }

  // Toggle inline en card — activa/desactiva sin abrir modal
  async function togglePersonalActivo(idPersonal, appOrigen, ev) {
    if (ev) ev.stopPropagation();
    const isMOS = appOrigen === 'MOS';
    const list = isMOS ? (cfgData.personalMOS || []) : (cfgData.personal || []);
    const p = list.find(x => x.idPersonal === idPersonal);
    if (!p) return;
    const nuevoEstado = String(p.estado) === '1' ? '0' : '1';
    const accion = nuevoEstado === '1' ? 'activar' : 'desactivar';
    if (!await _modalConfirm(`¿${accion.charAt(0).toUpperCase() + accion.slice(1)} a ${p.nombre} ${p.apellido || ''}?`, { titulo: nuevoEstado === '1' ? 'Activar personal' : 'Desactivar personal' })) return;
    // OPTIMISTA
    const previo = p.estado;
    p.estado = nuevoEstado;
    renderPersonal();
    try {
      await API.post('actualizarPersonalMaster', {
        idPersonal: idPersonal,
        estado:     nuevoEstado,
        appOrigen:  appOrigen
      });
      toast(`${p.nombre} ${nuevoEstado === '1' ? 'activado' : 'desactivado'}`, 'ok');
    } catch(e) {
      p.estado = previo;
      renderPersonal();
      toast('Error: ' + e.message, 'error');
    }
  }

  async function eliminarPersonal() {
    const id = $('persId')?.value;
    const appOrigen = $('persAppOrigen')?.value || 'warehouseMos';
    if (!id) return;
    const isMOS = appOrigen === 'MOS';
    const list = isMOS ? cfgData.personalMOS : cfgData.personal;
    const p = (list || []).find(x => x.idPersonal === id);
    if (!p) return;
    if (!await _modalConfirm(`¿Eliminar a ${p.nombre} ${p.apellido || ''}?\n\nEsta acción no se puede deshacer.`, { danger: true, titulo: 'Eliminar personal', okText: 'Sí, eliminar' })) return;
    closeModal('modalPersonal');
    // OPTIMISTA
    const backup = list.slice();
    const idx = list.findIndex(x => x.idPersonal === id);
    if (idx >= 0) list.splice(idx, 1);
    renderPersonal();
    toast('Eliminado ✓', 'ok');
    try {
      await API.post('eliminarPersonalMaster', { idPersonal: id, appOrigen });
    } catch(e) {
      if (isMOS) cfgData.personalMOS = backup; else cfgData.personal = backup;
      renderPersonal();
      toast('Error: ' + e.message, 'error');
    }
  }

  function _serieActualizarPreview() {
    const tipo = $('serieTipo')?.value || 'NOTA_VENTA';
    const serie = ($('serieSerie')?.value || '').trim();
    const ico = { NOTA_VENTA: '📋', BOLETA: '🧾', FACTURA: '🧮' }[tipo] || '📋';
    const sub = $('modalSerieSubtitle');
    if (sub) sub.textContent = serie ? `${tipo} · ${serie}` : 'NubeFact / SUNAT';
    const ip = $('serieIconPreview');
    if (ip) ip.textContent = ico;
  }

  // Abre modal para crear/editar serie de una zona+tipoDocumento
  // Si edicion=true, pre-llena con la serie actual; si no, modo crear
  function abrirModalSerieZona(idZona, tipoDocumento, edicion) {
    const z = cfgData.zonas.find(x => x.idZona === idZona);
    if (!z) return;
    const estZona = (cfgData.estaciones || []).filter(e => e.idZona === idZona && String(e.activo) === '1');

    $('serieZonaId').value = idZona;
    $('serieTipo').value = tipoDocumento;
    $('serieTipoOriginal').value = tipoDocumento;
    $('serieZonaNombre').textContent = z.nombre;

    if (estZona.length === 0) {
      toast('Crea estaciones en esta zona antes de configurar series', 'warn');
      return;
    }

    // Lista de estaciones afectadas
    const tipoIc = { CAJA: '🛒', ALMACEN: '🏭', ENVASADO: '🍶' };
    $('serieEstacionesCount').textContent = estZona.length;
    $('serieEstacionesList').innerHTML = estZona.map(e =>
      `<div>${tipoIc[e.tipo] || '📍'} ${e.nombre} <span class="text-slate-600 font-mono text-[10px]">${e.idEstacion}</span></div>`
    ).join('');

    const wrap = $('serieEstadoWrap');
    const btnElim = $('serieBtnEliminar');
    const tg = $('serieEstadoToggle');

    if (edicion) {
      // Encontrar series existentes de este tipo en esta zona
      const seriesActuales = (cfgData.series || []).filter(s => s.idZona === idZona && s.tipoDocumento === tipoDocumento);
      $('modalSerieTitle').textContent = `Editar serie ${tipoDocumento}`;
      const nombre = seriesActuales[0]?.serie || '';
      const corrMax = Math.max(0, ...seriesActuales.map(s => parseInt(s.correlativo, 10) || 0));
      $('serieSerie').value = nombre;
      $('serieCorrelativo').value = corrMax;
      const todasActivas = seriesActuales.every(s => String(s.activo) === '1');
      if (tg) tg.checked = todasActivas;
      if (wrap) wrap.classList.remove('hidden');
      if (btnElim) btnElim.classList.remove('hidden');
    } else {
      $('modalSerieTitle').textContent = `Nueva serie ${tipoDocumento}`;
      $('serieSerie').value = '';
      $('serieCorrelativo').value = 1;
      if (tg) tg.checked = true;
      if (wrap) wrap.classList.add('hidden');
      if (btnElim) btnElim.classList.add('hidden');
    }

    _serieActualizarPreview();
    openModal('modalSerie');
  }

  async function guardarSerieZona() {
    const idZona = $('serieZonaId')?.value;
    const tipoDocumento = $('serieTipo')?.value;
    const tipoOrig = $('serieTipoOriginal')?.value;
    const nombre = ($('serieSerie')?.value || '').trim();
    const correlativo = parseInt($('serieCorrelativo')?.value || '1', 10) || 1;
    const tg = $('serieEstadoToggle');
    const activo = tg ? (tg.checked ? '1' : '0') : '1';

    if (!nombre) { toast('Nombre de serie requerido', 'error'); return; }
    if (!idZona) { toast('Zona no encontrada', 'error'); return; }

    const estZona = (cfgData.estaciones || []).filter(e => e.idZona === idZona && String(e.activo) === '1');
    if (!estZona.length) { toast('La zona no tiene estaciones activas', 'warn'); return; }

    const seriesExistentes = (cfgData.series || []).filter(s => s.idZona === idZona && s.tipoDocumento === tipoOrig);
    const esEdicion = seriesExistentes.length > 0;

    closeModal('modalSerie');
    toast('Guardando serie...', 'info');

    // OPTIMISTA: actualizar cfgData.series localmente
    const backup = (cfgData.series || []).slice();
    const promesas = [];

    let creadas = 0, actualizadas = 0;
    for (const e of estZona) {
      const existente = seriesExistentes.find(s => s.idEstacion === e.idEstacion);
      if (existente) {
        // Actualizar nombre/activo (NO sobreescribir correlativo si es mayor al ingresado)
        const nuevoCorr = parseInt(existente.correlativo, 10) >= correlativo
          ? existente.correlativo
          : correlativo;
        existente.serie = nombre;
        existente.tipoDocumento = tipoDocumento;
        existente.correlativo = nuevoCorr;
        existente.activo = activo;
        promesas.push(API.post('actualizarSerie', {
          idSerie: existente.idSerie,
          serie: nombre,
          tipoDocumento,
          correlativo: nuevoCorr,
          activo
        }));
        actualizadas++;
      } else {
        // Crear nueva fila para esta estación (también en modo edición:
        // completa la cobertura si la zona tiene estaciones sin esta serie)
        const tmp = {
          idSerie: 'SER_TMP' + Date.now() + '_' + e.idEstacion,
          idEstacion: e.idEstacion,
          idZona,
          tipoDocumento,
          serie: nombre,
          correlativo: esEdicion ? 1 : correlativo, // estación nueva siempre arranca en 1
          activo,
          _tmp: true
        };
        cfgData.series.push(tmp);
        promesas.push(API.post('crearSerie', {
          idEstacion: e.idEstacion,
          idZona,
          tipoDocumento,
          serie: nombre,
          correlativo: tmp.correlativo,
          activo
        }).then(res => {
          if (res?.idSerie) tmp.idSerie = res.idSerie;
          delete tmp._tmp;
        }));
        creadas++;
      }
    }

    renderInfra();

    try {
      await Promise.all(promesas);
      const partes = [];
      if (actualizadas) partes.push(`${actualizadas} actualizada${actualizadas === 1 ? '' : 's'}`);
      if (creadas)      partes.push(`${creadas} creada${creadas === 1 ? '' : 's'} (auto)`);
      toast(`Serie ${tipoDocumento}: ${partes.join(' · ')} ✓`, 'ok');
    } catch(e) {
      console.error('[guardarSerieZona]', e);
      cfgData.series = backup;
      renderInfra();
      toast('Error: ' + (e.message || 'falló sincronización'), 'error');
    }
  }

  async function eliminarSerieZona() {
    const idZona = $('serieZonaId')?.value;
    const tipoDocumento = $('serieTipoOriginal')?.value;
    if (!idZona || !tipoDocumento) return;
    const seriesActuales = (cfgData.series || []).filter(s => s.idZona === idZona && s.tipoDocumento === tipoDocumento);
    if (!seriesActuales.length) return;
    if (!await _modalConfirm(`¿Desactivar la serie ${tipoDocumento} en ${seriesActuales.length} estación(es) de esta zona?\n\nMosExpress dejará de emitir documentos de este tipo. Puedes reactivarla luego.`, { warning: true, titulo: 'Desactivar serie' })) return;
    closeModal('modalSerie');

    const backup = cfgData.series.slice();
    seriesActuales.forEach(s => { s.activo = '0'; });
    renderInfra();
    try {
      await Promise.all(seriesActuales.map(s =>
        API.post('actualizarSerie', { idSerie: s.idSerie, activo: '0' })
      ));
      toast('Serie desactivada', 'ok');
    } catch(e) {
      cfgData.series = backup;
      renderInfra();
      toast('Error: ' + e.message, 'error');
    }
  }

  async function guardarPinEstacion(idEstacion) {
    const inp = $('pin_' + idEstacion);
    const pin = inp?.value || '';
    if (!pin || pin.length < 4) { toast('PIN debe tener al menos 4 dígitos', 'error'); return; }
    try {
      await API.post('actualizarEstacion', { idEstacion, adminPin: pin });
      toast('PIN actualizado', 'ok');
      if (inp) inp.value = '';
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  async function guardarPinWH() {
    const pin  = $('pinWH')?.value || '';
    const conf = $('pinWHConfirm')?.value || '';
    if (!pin || pin.length < 4)  { toast('PIN debe tener al menos 4 dígitos', 'error'); return; }
    if (pin !== conf)             { toast('Los PINs no coinciden', 'error'); return; }
    try {
      await API.post('setConfig', { clave: 'PIN_ADMIN_WH', valor: pin, descripcion: 'PIN administrador warehouseMos' });
      toast('PIN admin warehouseMos actualizado', 'ok');
      const pw = $('pinWH'); if (pw) pw.value = '';
      const pc = $('pinWHConfirm'); if (pc) pc.value = '';
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  // Close modal on backdrop click — usa _validBackdropClose para evitar
  // cierre al arrastrar selección de texto desde un input hasta el backdrop.
  // El handler inline de cada modal (onclick="...") usa la misma protección;
  // este handler global cubre los modales que no la tienen inline.
  document.addEventListener('click', e => {
    if (e.target.classList.contains('modal-backdrop')) {
      if (_validBackdropClose(e, e.target)) {
        e.target.classList.remove('open');
        e.target.classList.add('hidden');
      }
    }
  });

  // Wrapper compat — redirige al nuevo renderizado modernizado
  function _renderCajasDesdeEstado() { _cjRender(); }

  // ════════════════════════════════════════════════════════════
  // ║ MÓDULO CAJAS MODERNIZADO (estilo Bloomberg/trading)       ║
  // ════════════════════════════════════════════════════════════
  let _cjState = {
    fecha: null,
    calMes: null,
    expandido: new Set(),
    livePulseTimer: null,
    elapsedTimer: null,
    tvActivo: false,
    tvAutoTimer: null,
    tkFiltro: 'todos',
    tkCajaFiltro: '',
    tkBuscar: '',
    tkDoc: '',             // [rango] filtro tipo doc: '' | 'NV' | 'B' | 'F'
    tkDesde: '', tkHasta: '',  // [rango] rango de fechas del buscador de tickets
    tkRangoActivo: false,  // [rango] true = usa S._cjTkRangoData; false = día activo
    chunksAnteriores: new Map(),  // idCaja → cantidadTickets para detectar cambios
  };

  function _cjFecha() { return _cjState.fecha || $('cjFecha')?.value || today(); }

  function _cjActualizarFechaUI() {
    const fecha = _cjFecha();
    const lbl = $('cjFechaLabel');
    const badge = $('cjDayBadge');
    const hoy = today();
    const a = new Date(fecha + 'T00:00:00');
    const h = new Date(hoy + 'T00:00:00');
    const diff = Math.round((a - h) / 86400000);
    if (lbl) {
      const txt = a.toLocaleDateString('es-PE', { day:'2-digit', month:'short', year:'2-digit' });
      lbl.textContent = (diff === 0) ? `Hoy · ${txt}` : txt;
    }
    if (badge) {
      let txt = '';
      if (diff === 0)       txt = '🟢 Hoy';
      else if (diff === -1) txt = 'Ayer';
      else if (diff === 1)  txt = 'Mañana';
      else if (diff < 0)    txt = `Hace ${-diff} días`;
      else                  txt = `+${diff} días`;
      badge.textContent = txt;
    }
    // Banner archivo cuando no es hoy
    const banner = $('cjBannerArchivo');
    if (banner) banner.classList.toggle('hidden', diff === 0);
  }

  function cjDia(delta) {
    const cur = _cjFecha();
    const [y, m, d] = cur.split('-').map(Number);
    const dt = new Date(y, m - 1, d);
    dt.setDate(dt.getDate() + delta);
    const nueva = dt.getFullYear() + '-' + String(dt.getMonth()+1).padStart(2,'0') + '-' + String(dt.getDate()).padStart(2,'0');
    _cjState.fecha = nueva;
    const inp = $('cjFecha'); if (inp) inp.value = nueva;
    _finBeep('nav');
    _cjActualizarFechaUI();
    _cjRender();
    _cjAsegurarDia(nueva).then(c => { if (c) _cjRender(); });   // [historial] fuera de 30d → jala
  }
  function cjIrHoy() {
    _cjState.fecha = today();
    const inp = $('cjFecha'); if (inp) inp.value = _cjState.fecha;
    _finBeep('ok');
    _cjActualizarFechaUI();
    _cjRender();
  }
  function cjAbrirCalendario(btn) {
    const dp = $('cjDatepicker');
    if (!dp) return;
    if (!dp.classList.contains('hidden')) { dp.classList.add('hidden'); return; }
    const cur = _cjFecha();
    const d = new Date(cur + 'T00:00:00');
    _cjState.calMes = { y: d.getFullYear(), m: d.getMonth() };
    _cjCalRender();
    _cjCalCargarMes(d.getFullYear(), d.getMonth());   // [calendario] marca días con tickets
    const r = btn.getBoundingClientRect();
    dp.style.left = Math.max(8, Math.min(window.innerWidth - 250, r.left)) + 'px';
    dp.style.top  = (r.bottom + 6) + 'px';
    dp.classList.remove('hidden');
    _finBeep('click');
    setTimeout(() => {
      const closer = e => {
        if (!dp.contains(e.target) && !btn.contains(e.target)) {
          dp.classList.add('hidden');
          document.removeEventListener('click', closer);
        }
      };
      document.addEventListener('click', closer);
    }, 50);
  }
  function cjCalNavMes(delta) {
    if (!_cjState.calMes) return;
    let { y, m } = _cjState.calMes;
    m += delta;
    if (m < 0)  { m = 11; y--; }
    if (m > 11) { m = 0;  y++; }
    _cjState.calMes = { y, m };
    _cjCalRender();
    _cjCalCargarMes(y, m);   // [calendario] marca días con tickets del nuevo mes
  }
  function _cjCalRender() {
    const grid = $('cjCalGrid');
    const lbl  = $('cjCalMesAnio');
    if (!grid || !_cjState.calMes) return;
    const { y, m } = _cjState.calMes;
    const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
    if (lbl) lbl.textContent = `${meses[m]} ${y}`;
    const primero = new Date(y, m, 1);
    let primerDow = primero.getDay();
    primerDow = primerDow === 0 ? 6 : primerDow - 1;
    const ultimo = new Date(y, m + 1, 0).getDate();
    const hoy = today();
    const sel = _cjFecha();
    const mesKey = `${y}-${String(m + 1).padStart(2, '0')}`;
    const diasT = (S._cjCalDias && S._cjCalDias[mesKey]) || {};
    let html = '';
    for (let i = 0; i < primerDow; i++) html += '<button class="log-cal-day empty"></button>';
    for (let dia = 1; dia <= ultimo; dia++) {
      const f = `${y}-${String(m + 1).padStart(2, '0')}-${String(dia).padStart(2, '0')}`;
      const cls = ['log-cal-day'];
      if (f === hoy) cls.push('today');
      if (f === sel) cls.push('selected');
      // [calendario] marca visual: borde si hay tickets ese día + punto ámbar si hay crédito
      const info = diasT[f];
      let extra = '', dot = '';
      if (info && info.n > 0) {
        cls.push('cj-cal-tick');
        if (info.credito) { cls.push('cj-cal-cred'); dot = '<span class="cj-cal-dot"></span>'; }
        const tot = (typeof info.total === 'number') ? info.total.toFixed(0) : info.total;
        extra = ` title="${info.n} ticket${info.n > 1 ? 's' : ''}${info.credito ? ' · con crédito' : ''} · S/ ${tot}"`;
      }
      html += `<button class="${cls.join(' ')}"${extra} onclick="MOS.cjElegirFecha('${f}')">${dia}${dot}</button>`;
    }
    grid.innerHTML = html;
  }
  function cjElegirFecha(f) {
    _cjState.fecha = f;
    const inp = $('cjFecha'); if (inp) inp.value = f;
    $('cjDatepicker')?.classList.add('hidden');
    _finBeep('click');
    _cjActualizarFechaUI();
    _cjRender();
    _cjAsegurarDia(f).then(c => { if (c) _cjRender(); });   // [historial] día fuera de 30d → jala y re-pinta
  }

  // [historial] resta N días a un 'YYYY-MM-DD'
  function _cjFechaMenosDias(fechaStr, n) {
    const [y, m, d] = String(fechaStr).split('-').map(Number);
    const dt = new Date(y, m - 1, d); dt.setDate(dt.getDate() - n);
    return dt.getFullYear() + '-' + String(dt.getMonth() + 1).padStart(2, '0') + '-' + String(dt.getDate()).padStart(2, '0');
  }
  // [historial] al viajar a un día FUERA de la ventana de 30d, jala sus tickets (mos.tickets_dia)
  // y los mergea en el cache. Devuelve true si trajo datos nuevos (para re-pintar).
  async function _cjAsegurarDia(fecha) {
    if (!fecha) return false;
    const limite = _cjFechaMenosDias(today(), 30);
    if (fecha >= limite) return false;                       // dentro de 30d → ya en cache
    if (!S._cjDiasExtra) S._cjDiasExtra = new Set();
    if (S._cjDiasExtra.has(fecha)) return false;             // ya jalado antes
    try {
      // [historial] día COMPLETO: cajas + tickets + KPIs (cierres_caja con fecha) → la vista entera carga
      const d = await API.get('getCierresDia', { fecha });
      S._cjDiasExtra.add(fecha);
      if (!d) return false;
      // [fix bug] guardar en el STORE PERSISTENTE (sobrevive a las recargas de 30d que pisan
      // S._todosTickets/S._todasCajas → antes el día viejo se vaciaba al re-renderizar).
      if (!S._cjHistTickets) S._cjHistTickets = [];
      if (!S._cjHistCajas)   S._cjHistCajas   = [];
      (d.todosTickets || []).forEach(t => S._cjHistTickets.push(t));
      [...(d.abiertas || []), ...(d.cerradas || [])].forEach(c => S._cjHistCajas.push(c));
      _cjMergeHist();
      return true;
    } catch (e) { console.warn('[cj] getCierresDia:', e?.message || e); return false; }
  }
  // [fix bug] re-inyecta el histórico (días fuera de 30d) en los caches vivos, sin duplicar.
  // Se llama tras _cjAsegurarDia y DESPUÉS de cada recarga de cierres_caja (que reescribe los caches).
  function _cjMergeHist() {
    if (S._cjHistTickets && S._cjHistTickets.length) {
      const cache = S._todosTickets || [];
      const ids = new Set(cache.map(t => String(t.idVenta)));
      S._cjHistTickets.forEach(t => { const k = String(t.idVenta); if (!ids.has(k)) { cache.push(t); ids.add(k); } });
      S._todosTickets = cache;
    }
    if (S._cjHistCajas && S._cjHistCajas.length) {
      const cajas = S._todasCajas || [];
      const ids = new Set(cajas.map(c => String(c.idCaja)));
      S._cjHistCajas.forEach(c => { const k = String(c.idCaja); if (!ids.has(k)) { cajas.push(c); ids.add(k); } });
      S._todasCajas = cajas;
    }
  }
  // [calendario] jala qué días del mes tienen tickets (mos.dias_con_tickets) y re-pinta con marcas
  async function _cjCalCargarMes(y, m) {
    const mes = y + '-' + String(m + 1).padStart(2, '0');
    if (!S._cjCalDias) S._cjCalDias = {};
    if (S._cjCalDias[mes]) return;                           // mes ya cacheado
    try {
      const r = await API.get('getDiasConTickets', { mes });
      S._cjCalDias[mes] = (r && r.dias) || (r && r.data && r.data.dias) || {};
      _cjCalRender();
    } catch (e) { console.warn('[cj] dias_con_tickets:', e?.message || e); }
  }

  // ── Render principal ───────────────────────────────────
  function _cjRender() {
    if (!_cjState.fecha) _cjState.fecha = today();
    const inp = $('cjFecha'); if (inp && !inp.value) inp.value = _cjState.fecha;
    _cjActualizarFechaUI();

    const fecha = _cjFecha();
    const esHoy = fecha === today();

    const todas = S._todasCajas || [];
    const tkAll = S._todosTickets || [];

    // Filtrar cajas según la fecha activa (estilo finanzas)
    const cajasDelDia = todas.filter(c => {
      const fa = (c.fechaApertura || '').substring(0, 10);
      const fc = (c.fechaCierre   || '').substring(0, 10);
      // Si es hoy: incluir todas las abiertas (sin cierre) + cerradas de hoy
      if (esHoy) {
        if (c.estado === 'ABIERTA') return true;
        return fc === fecha || fa === fecha;
      }
      // Días pasados: solo las que cerraron (o abrieron) en esa fecha
      return fc === fecha || fa === fecha;
    });
    const abiertas = cajasDelDia.filter(c => c.estado === 'ABIERTA');
    const cerradas = cajasDelDia.filter(c => c.estado !== 'ABIERTA');

    // Tickets del día: filtrar por fecha
    const tkDia = tkAll.filter(t => (t.fecha || '').substring(0, 10) === fecha);
    const tkMes = tkAll.filter(t => {
      const f = (t.fecha || '').substring(0, 10);
      const cutoff = _fechaOffset(fecha, -29);
      return f && f <= fecha && f >= cutoff;
    });

    // Identificar caja líder del día (corona 👑) — la de mayor totalVentas con tickets > 0
    const cajasConVentas = cajasDelDia
      .filter(c => (parseFloat(c.totalVentas) || 0) > 0 && (c.tickets || 0) > 0)
      .sort((a, b) => (parseFloat(b.totalVentas) || 0) - (parseFloat(a.totalVentas) || 0));
    const idCajaLider = cajasConVentas.length > 0 ? String(cajasConVentas[0].idCaja) : null;

    _cjRenderTicker(cajasDelDia, tkDia, esHoy);
    _cjRenderKPIs(cajasDelDia, tkDia, tkMes, fecha);
    _cjRenderCajas(abiertas, cerradas, fecha, esHoy, idCajaLider);
    _cjRenderActividad(tkDia, esHoy);
    _cjRender7d(fecha);
    // [v40.4] Cargar créditos (1 fetch trae 30 días, después renderiza la mano
    // de la fecha activa según el filtro). Cuando el usuario cambie la fecha,
    // _cjRenderManoDelDia se vuelve a invocar sin refetch.
    if (!_cjCreditosState.todosLosGrupos.length) _cjCargarCreditosPendientes();
    else _cjRenderManoDelDia();
    // [v2.41.87] Cargar cobros en vuelo (panel arriba de la baraja)
    _cjCargarEnVuelo(true);

    // Empty state
    const empty = $('cajasEmpty');
    if (empty) empty.classList.toggle('hidden', cajasDelDia.length > 0);

    // Reloj live elapsed (solo si es hoy y hay abiertas)
    _cjStartElapsedTimer(esHoy && abiertas.length > 0);
  }

  // ── TICKER ──────────────────────────────────────────────
  function _cjRenderTicker(cajas, tickets, esHoy) {
    const cont = $('cjTickerContent');
    if (!cont) return;
    const totalDia = cajas.reduce((s, c) => s + (parseFloat(c.totalVentas) || 0), 0);
    const tkCount = tickets.filter(t => t.estado !== 'ANULADO').length;
    const abiertas = cajas.filter(c => c.estado === 'ABIERTA').length;
    const cerradas = cajas.filter(c => c.estado !== 'ABIERTA').length;
    // Buscar última venta
    const tkOrd = tickets.slice().sort((a,b) => (b.fecha+b.hora||'').localeCompare(a.fecha+a.hora||''));
    const ultima = tkOrd[0];
    const ultimoTxt = ultima
      ? `Última venta: ${ultima.hora || '—'} · S/ ${parseFloat(ultima.total||0).toFixed(2)}`
      : 'Sin ventas';
    // Comparación con ayer (solo si esHoy)
    let tendencia = '';
    if (esHoy) {
      const ayer = _fechaOffset(today(), -1);
      const tkAyer = (S._todosTickets || []).filter(t => (t.fecha||'').substring(0,10) === ayer && t.estado !== 'ANULADO');
      const totalAyer = tkAyer.reduce((s,t)=>s+(parseFloat(t.total)||0), 0);
      if (totalAyer > 0) {
        const pct = ((totalDia - totalAyer) / totalAyer) * 100;
        tendencia = pct >= 0
          ? `<span class="cj-ticker-up">▲ ${Math.abs(pct).toFixed(0)}% vs ayer</span>`
          : `<span class="cj-ticker-down">▼ ${Math.abs(pct).toFixed(0)}% vs ayer</span>`;
      }
    }
    // Pieza única que se repite 2× para scroll continuo
    const pieza = `
      <span class="cj-ticker-item ${totalDia >= 0 ? 'cj-ticker-up':'cj-ticker-down'}">${totalDia >= 0 ? '▲':'▼'} S/ ${totalDia.toFixed(2)}</span>
      <span class="cj-ticker-sep">│</span>
      <span class="cj-ticker-item">🧾 ${tkCount} tickets</span>
      <span class="cj-ticker-sep">│</span>
      <span class="cj-ticker-item cj-ticker-up">🟢 ${abiertas} abiertas</span>
      <span class="cj-ticker-sep">│</span>
      <span class="cj-ticker-item">⚫ ${cerradas} cerradas</span>
      <span class="cj-ticker-sep">│</span>
      <span class="cj-ticker-item">${ultimoTxt}</span>
      ${tendencia ? '<span class="cj-ticker-sep">│</span>' + tendencia : ''}
      <span class="cj-ticker-sep">│</span>
    `;
    cont.innerHTML = pieza + pieza; // 2× para scroll continuo
  }

  // ── KPIs ─────────────────────────────────────────────────
  function _cjRenderKPIs(cajas, tkDia, tkMes, fecha) {
    const totalDia = cajas.reduce((s, c) => s + (parseFloat(c.totalVentas) || 0), 0);
    _animateCount('cajasKpiVentas', totalDia, { prefix: 'S/ ' });

    // Barra proporcional efectivo / virtual / mixto / crédito
    const ef = cajas.reduce((s, c) => s + (parseFloat(c.efectivo) || 0), 0);
    const vi = cajas.reduce((s, c) => {
      const bm = c.byMetodo || {};
      // Sumar todo lo que no sea EFECTIVO ni POR_COBRAR/CREDITO ni ANULADO
      let total = 0;
      Object.keys(bm).forEach(k => {
        const ku = String(k || '').toUpperCase();
        if (ku === 'EFECTIVO' || ku === 'POR_COBRAR' || ku === 'CREDITO' || ku === 'ANULADO') return;
        total += parseFloat(bm[k]) || 0;
      });
      return s + total;
    }, 0);
    const totalCobrado = ef + vi;
    const efPct = totalCobrado > 0 ? (ef / totalCobrado * 100) : 50;
    const viPct = totalCobrado > 0 ? (vi / totalCobrado * 100) : 50;
    const setW = (id, p) => { const el = $(id); if (el) el.style.width = p.toFixed(1) + '%'; };
    setW('cjPagoBarEf', efPct);
    setW('cjPagoBarVi', viPct);
    _setText('cjEfectivoMonto', 'S/ ' + ef.toFixed(2));
    _setText('cjVirtualMonto',  'S/ ' + vi.toFixed(2));
    _setText('cjEfectivoPct',   efPct.toFixed(0) + '%');
    _setText('cjVirtualPct',    viPct.toFixed(0) + '%');

    // Lógica basada en formaPago (definiciones selladas del negocio):
    //   EFECTIVO/VIRTUAL/MIXTO = COBRADO (dinero recibido)
    //   POR_COBRAR             = pendiente de cajero (vendedor emitió, no cobrado)
    //   CREDITO                = deuda formal aprobada por admin
    //   ANULADO                = descartado, no cuenta
    const fp = t => String(t.metodo || t.formaPago || '').toUpperCase();
    const esAnul    = t => fp(t) === 'ANULADO' || t.estado === 'ANULADO';
    const esPorCob  = t => fp(t) === 'POR_COBRAR' && !esAnul(t);
    const esCred    = t => fp(t) === 'CREDITO' && !esAnul(t);
    const esCobrado = t => !esAnul(t) && !esPorCob(t) && !esCred(t);

    const tkOk    = tkDia.filter(esCobrado).length;
    const tkPorCb = tkDia.filter(esPorCob).length;
    const tkCred  = tkDia.filter(esCred).length;
    const tkAnul  = tkDia.filter(esAnul).length;
    _setText('cjVentasSub',
      tkOk + ' cobrados · ' + tkPorCb + ' por cobrar · ' + tkCred + ' a crédito · ' + tkAnul + ' anulado' + (tkAnul !== 1 ? 's' : '')
    );
    _setText('cjTkCobrados',  tkOk);
    _setText('cjTkPorCobrar', tkPorCb);
    _setText('cjTkCredito',   tkCred);
    _setText('cjTkAnulados',  tkAnul);

    // Hoy / 30d (no contar anulados)
    const hoyTotal = tkDia.filter(t => !esAnul(t)).length;
    const mesTotal = tkMes.filter(t => !esAnul(t)).length;
    _setText('cajasKpiTicketsHoy', hoyTotal);
    _setText('cajasKpiTicketsMes', mesTotal);

    // Tipos doc (NV/B/F) — tipoDoc puede ser corto o largo
    let nvH = 0, bH = 0, fH = 0;
    tkDia.forEach(t => {
      if (esAnul(t)) return;
      const tp = String(t.tipo || t.tipoDoc || '').toUpperCase();
      if (tp === 'NV' || tp === 'NOTA_DE_VENTA') nvH++;
      else if (tp === 'B' || tp === 'BOLETA') bH++;
      else if (tp === 'F' || tp === 'FACTURA') fH++;
    });
    _setText('cajasKpiNV', nvH);
    _setText('cajasKpiBoleta', bH);
    _setText('cajasKpiFactura', fH);

    // Comparación vs ayer
    const ayer = _fechaOffset(fecha, -1);
    const tkAyer = (S._todosTickets || []).filter(t =>
      (t.fecha || '').substring(0, 10) === ayer && t.estado !== 'ANULADO');
    const totalAyer = tkAyer.reduce((s, t) => s + (parseFloat(t.total) || 0), 0);
    const cmp = $('cjVentasComparaAyer');
    if (cmp) {
      if (totalAyer > 0) {
        const pct = ((totalDia - totalAyer) / totalAyer) * 100;
        cmp.classList.remove('hidden');
        cmp.classList.toggle('up', pct >= 0);
        cmp.classList.toggle('down', pct < 0);
        cmp.innerHTML = (pct >= 0 ? '▲ +' : '▼ ') + Math.abs(pct).toFixed(0) + '% vs ayer';
      } else { cmp.classList.add('hidden'); }
    }
  }

  // ── CARDS DE CAJAS ───────────────────────────────────────
  function _cjRenderCajas(abiertas, cerradas, fecha, esHoy, idCajaLider) {
    const grid = $('cjCajasGrid');
    if (!grid) return;
    const sub = $('cjCajasSub');
    if (sub) {
      const total = abiertas.length + cerradas.length;
      sub.textContent = total > 0
        ? `${total} caja${total !== 1 ? 's' : ''} ${esHoy ? 'hoy' : 'en este día'}`
        : (esHoy ? 'Sin actividad todavía' : 'Sin actividad');
    }
    _setText('cjPillActivas',  '🟢 ' + abiertas.length + ' abiertas');
    _setText('cjPillCerradas', '⚫ ' + cerradas.length + ' cerradas');

    // [sin caja] tickets del día SIN caja asignada (artefactos de transición / errores) →
    // se agrupan en una "baraja cerrada" (pila apilada) al frente, para detectarlos de un vistazo.
    const sinCaja = (S._todosTickets || []).filter(t =>
      (t.fecha || '').substring(0, 10) === fecha && !String(t.idCaja || '').trim() && String(t.estado || '') !== 'ANULADO');
    const deckHtml = sinCaja.length ? _cjBuildDeckSinCaja(sinCaja) : '';

    if (!abiertas.length && !cerradas.length && !sinCaja.length) {
      grid.innerHTML = '<p class="text-slate-500 text-xs text-center py-6 col-span-full">Sin cajas en esta fecha</p>';
      return;
    }
    // Baraja "sin caja" al frente (si hay), luego activas, luego cerradas. Corona 👑 a la líder.
    grid.innerHTML = deckHtml + [
      ...abiertas.map(c => _cjBuildCajaCard(c, true,  fecha, String(c.idCaja) === idCajaLider)),
      ...cerradas.map(c => _cjBuildCajaCard(c, false, fecha, String(c.idCaja) === idCajaLider))
    ].join('');

    // Detectar tickets nuevos (flash en card de la caja correspondiente)
    if (esHoy) _cjDetectarTicketsNuevos(abiertas);

    // [v2.42.00] Pegar manojo de postits (cobros en vuelo) sobre el cuadro de
    // cada caja activa. Llamamos después del render porque necesita los nodos
    // .cj-caja-card en el DOM. _cjPintarPostitsManojos itera _cjCreditosState.enVuelo
    // y monta/desmonta el manojo según la caja destino.
    try { _cjPintarPostitsManojos(); } catch(_){}
  }

  // [sin caja] "baraja cerrada": pila de cartas apiladas (vista isométrica desde una
  // esquina). Cuantos más tickets sin caja, más capas se apilan. Tocá → visor filtrado.
  function _cjBuildDeckSinCaja(tickets) {
    const n = tickets.length;
    const total = tickets.reduce((s, t) => s + (parseFloat(t.total) || 0), 0);
    const capas = Math.min(Math.max(n - 1, 0), 6);   // hasta 6 capas de fondo
    let capasHtml = '';
    for (let i = capas; i >= 1; i--) capasHtml += `<div class="cj-deck-capa" style="--i:${i}"></div>`;
    return `
      <div class="cj-deck cj-deck-sincaja" onclick="MOS.cjVerTicketsSinCaja()"
           title="${n} ticket${n > 1 ? 's' : ''} sin caja asignada — tocá para revisar">
        ${capasHtml}
        <div class="cj-deck-front">
          <div class="cj-deck-badge">⚠</div>
          <div class="cj-deck-ico">🃏</div>
          <div class="cj-deck-title">Sin caja asignada</div>
          <div class="cj-deck-count">${n} ticket${n > 1 ? 's' : ''}</div>
          <div class="cj-deck-total">S/ ${total.toFixed(2)}</div>
          <div class="cj-deck-hint">tocá para revisar</div>
        </div>
      </div>`;
  }
  function cjVerTicketsSinCaja() {
    _finBeep('click');
    _cjState.tkCajaFiltro = '__SINCAJA__';
    _cjState.tkFiltro = 'todos';
    _cjState.tkBuscar = '';
    const inp = $('cjTkBuscar'); if (inp) inp.value = '';
    _setText('cjModalTicketsTitulo', 'Tickets sin caja asignada');
    _setText('cjModalTicketsSubtitulo', _cjFecha() + ' · ⚠ sin caja (revisar)');
    _cjState.tkVendedor = '';
    _cjTkResetRango(_cjFecha());
    openModal('cjModalTickets');
    _cjTkRenderFiltrosBtns();
    _cjTkRenderVendedoresBtns();
    _cjTkRender();
  }

  // [v2.41.91] Bloque "Balance en vivo" — solo en cajas ABIERTAS.
  // Muestra el efectivo esperado calculado (lo que el cajero debería tener
  // en mano), separación virtual/crédito/por_cobrar, y celebra hitos.
  function _cjBuildBalanceLive(c) {
    const inicial = parseFloat(c.montoInicial) || 0;
    const efectivo = parseFloat(c.efectivo) || 0;
    const entradas = parseFloat(c.entradas) || 0;
    const salidas = parseFloat(c.salidas) || 0;
    const esperado = parseFloat(c.efectivoEsperado) || (inicial + efectivo + entradas - salidas);

    // Hitos S/ 500, 1k, 2k, 3k → emojis crecientes
    const hitos = [
      { mark: 3000, emoji: '🏆', label: '3K+' },
      { mark: 2000, emoji: '🔥', label: '2K+' },
      { mark: 1000, emoji: '⭐', label: '1K+' },
      { mark:  500, emoji: '💪', label: '500+' }
    ];
    const hitoAlcanzado = hitos.find(h => esperado >= h.mark);
    const proximoHito = hitos.slice().reverse().find(h => esperado < h.mark);
    const progresoPct = proximoHito ? Math.min(100, (esperado / proximoHito.mark) * 100) : 100;

    // Anomalías
    const totalVentas = parseFloat(c.totalVentas) || 0;
    const anulados = c.anulados || 0;
    const tickets = Math.max(1, c.tickets || 0);
    const ratioAnul = anulados / tickets;
    const alertas = [];
    if (ratioAnul >= 0.20 && anulados >= 3) alertas.push({ icon: '⚠', txt: anulados + ' anulaciones (' + Math.round(ratioAnul*100) + '%) — revisar' });
    if (salidas > entradas + 100) alertas.push({ icon: '💸', txt: 'Egresos > ingresos por S/ ' + (salidas - entradas).toFixed(0) });

    return `
    <div class="cj-balance-live">
      <div class="cj-balance-live-row">
        <span class="cj-balance-live-lbl">💚 ESPERADO EN CAJA</span>
        <span class="cj-balance-live-monto" data-monto="${esperado.toFixed(2)}">S/ ${esperado.toFixed(2)}</span>
      </div>
      <div class="cj-balance-live-detail">
        <span>S/ ${inicial.toFixed(0)} inicial</span>
        ${efectivo > 0 ? `<span>+ S/ ${efectivo.toFixed(0)} ventas</span>` : ''}
        ${entradas > 0 ? `<span>+ S/ ${entradas.toFixed(0)} ing</span>` : ''}
        ${salidas > 0 ? `<span>− S/ ${salidas.toFixed(0)} egr</span>` : ''}
      </div>
      ${hitoAlcanzado || proximoHito ? `
      <div class="cj-balance-hitos">
        ${hitoAlcanzado ? `<span class="cj-balance-hito-actual">${hitoAlcanzado.emoji} ${hitoAlcanzado.label}</span>` : ''}
        ${proximoHito ? `
          <div class="cj-balance-hito-progress" title="Próximo hito: S/ ${proximoHito.mark}">
            <div class="cj-balance-hito-progress-fill" style="width:${progresoPct}%"></div>
          </div>
          <span class="cj-balance-hito-prox">${proximoHito.emoji} ${proximoHito.label}</span>
        ` : ''}
      </div>` : ''}
      ${alertas.length ? `
      <div class="cj-balance-alertas">
        ${alertas.map(a => `<div class="cj-balance-alerta"><span>${a.icon}</span><span>${a.txt}</span></div>`).join('')}
      </div>` : ''}
    </div>`;
  }

  function _cjBuildCajaCard(c, esActiva, fecha, esLider) {
    const idAttr = String(c.idCaja).replace(/'/g, '&#39;');
    const elapsed = _cajaElapsed(c.fechaApertura);
    const total = parseFloat(c.totalVentas) || 0;
    const tickets = c.tickets || 0;
    const anulados = c.anulados || 0;
    const sinCobrar = c.sinCobrar || 0;
    const ef = parseFloat(c.efectivo) || 0;

    // Métodos: separar virtual / mixto / credito desde byMetodo
    const bm = c.byMetodo || {};
    let mVi = 0, mMx = 0, mCr = 0;
    Object.keys(bm).forEach(k => {
      const ku = String(k || '').toUpperCase();
      const v = parseFloat(bm[k]) || 0;
      if (ku === 'EFECTIVO' || ku === 'ANULADO') return;
      if (ku === 'POR_COBRAR' || ku === 'CREDITO') mCr += v;
      else if (ku.startsWith('MIXTO')) mMx += v;
      else mVi += v;
    });
    const totalCobrado = ef + mVi + mMx;
    const efPct = totalCobrado > 0 ? (ef / totalCobrado * 100) : 0;
    const viPct = totalCobrado > 0 ? (mVi / totalCobrado * 100) : 0;
    const mxPct = totalCobrado > 0 ? (mMx / totalCobrado * 100) : 0;
    const totalConCredito = totalCobrado + mCr;
    const crPct = totalConCredito > 0 ? (mCr / totalConCredito * 100) : 0;

    // Salud: 100 base, descuenta % anulados, % crédito alto, sin movimiento
    const tkSafe = Math.max(1, tickets);
    let salud = 100;
    salud -= Math.min(40, (anulados / tkSafe) * 100 * 2); // anulados: -2 por cada %
    if (total > 0 && mCr / Math.max(1, total) > 0.30) salud -= 15; // crédito > 30%
    salud = Math.max(0, Math.round(salud));
    const saludCls = salud >= 80 ? '' : (salud >= 60 ? 'warn' : 'bad');

    // Sparkline de tickets por hora (12 barras: 7am-19h)
    const tkList = c.ticketsList || [];
    const horas = new Array(13).fill(0);
    tkList.forEach(t => {
      if (t.estado === 'ANULADO') return;
      const h = parseInt(String(t.hora || '0').split(':')[0], 10);
      const idx = Math.max(0, Math.min(12, h - 7));
      horas[idx] += (parseFloat(t.total) || 0);
    });
    const maxH = Math.max.apply(null, horas.concat([1]));
    const horaActual = new Date().getHours();
    const sparkBars = horas.map((v, i) => {
      const h = Math.max(2, (v / maxH) * 28);
      const realHora = i + 7;
      const cls = v === 0 ? 'zero' : (esActiva && realHora === horaActual ? 'now' : '');
      return `<div class="cj-spark-bar ${cls}" style="height:${h}px" title="${realHora}h: S/ ${v.toFixed(2)}"></div>`;
    }).join('');

    // Iniciales del cajero
    const ini = (c.vendedor || '?').split(/\s+/).map(p => p[0] || '').slice(0, 2).join('').toUpperCase();
    const safeNombre = String(c.vendedor || '').replace(/'/g, '&#39;');

    // Banderas de alerta
    const sinMov = esActiva && tickets === 0 && _cajaMinutosDesdeApertura(c.fechaApertura) > 30;
    const claseEstado = esActiva
      ? (sinMov ? 'alerta' : 'activa')
      : 'cerrada';

    // Botones. [v41.3] Cierre forzado solo para admin/master en cajas ABIERTAS.
    const _esAdmin = _esAdminOMaster();
    const btnCerrarForzado = esActiva && _esAdmin
      ? `<button onclick="event.stopPropagation();MOS.cjCerrarCajaForzado('${idAttr}','${safeNombre}')" class="cj-caja-btn cj-caja-btn-danger" title="Cerrar caja forzadamente (admin)">🔒 Cerrar caja</button>`
      : '';
    const btnActiva = esActiva ? `
      <button onclick="event.stopPropagation();MOS.cjVerTicketsCaja('${idAttr}')" class="cj-caja-btn cj-caja-btn-primary" title="Ver tickets de esta caja">🧾 Tickets</button>
      <button onclick="event.stopPropagation();MOS.cjAbrirTurno('${idAttr}')" class="cj-caja-btn" title="Ver turno completo">📊 Turno</button>
      ${btnCerrarForzado}` : `
      <button onclick="event.stopPropagation();MOS.cjVerTicketsCaja('${idAttr}')" class="cj-caja-btn cj-caja-btn-primary">🧾 Tickets del turno</button>
      <button onclick="event.stopPropagation();MOS.cjAbrirTurno('${idAttr}')" class="cj-caja-btn" title="Ver turno completo">📜 Ver cierre</button>`;

    return `
    <div class="cj-caja-card ${claseEstado} ${esLider ? 'cj-caja-card-lider' : ''}" id="cjcard-${idAttr}" data-idcaja="${idAttr}" data-tickets="${tickets}" onclick="MOS.cjToggleCajaDetail('${idAttr}')">
      ${esLider ? '<div class="cj-caja-corona" title="Líder del día — caja con mayor venta">👑</div>' : ''}
      <div class="cj-caja-head">
        <span class="cj-caja-status-dot ${esActiva ? 'live' : 'off'}"></span>
        <div class="cj-caja-titulo">${esLider ? '🏆' : '📍'} ${c.zona || c.estacion || c.idCaja}</div>
        <span class="cj-caja-badge ${esActiva ? 'live' : 'cerrada'}">${esActiva ? 'LIVE' : 'CERRADA'}</span>
        <button class="cj-caja-toggle ${_cjState.expandido.has(idAttr) ? 'open' : ''}" onclick="event.stopPropagation();MOS.cjToggleCajaDetail('${idAttr}')">▾</button>
      </div>
      <div class="cj-caja-meta">
        <div class="cj-caja-avatar">${ini}</div>
        <div class="cj-caja-meta-cuerpo">
          <div class="cj-caja-meta-nombre">${c.vendedor || '—'}</div>
          <div class="cj-caja-meta-sub">${(c.fechaApertura || '').substring(11, 16)} → ${esActiva ? 'ahora' : (c.fechaCierre || '').substring(11, 16)}</div>
        </div>
        <span class="cj-caja-elapsed" data-elapsed-id="${idAttr}" data-fecha="${c.fechaApertura}" data-cierre="${c.fechaCierre || ''}">${elapsed}</span>
      </div>
      <div class="cj-caja-hero">
        <div>
          <div class="cj-caja-hero-monto">S/ ${total.toFixed(2)}</div>
          <div class="cj-caja-hero-sub">${tickets} tickets · ${anulados > 0 ? `<span style="color:#fca5a5">${anulados} anul</span> · ` : ''}${sinCobrar > 0 ? `<span style="color:#fcd34d">${sinCobrar} créd</span>` : '0 créd'}</div>
        </div>
        <div class="cj-caja-salud" title="Salud de la caja: ${salud}/100">
          <div class="cj-caja-salud-num ${saludCls}">${salud}</div>
          <div class="cj-caja-salud-lbl">SALUD</div>
          <div class="cj-caja-salud-bar"><div class="cj-caja-salud-bar-fill" style="width:${salud}%"></div></div>
        </div>
      </div>
      ${esActiva ? _cjBuildBalanceLive(c) : ''}
      <div class="cj-caja-pago-bar">
        ${efPct > 0 ? `<div class="cj-caja-pago-bar-ef" style="width:${efPct}%">${efPct >= 12 ? '💵' : ''}</div>` : ''}
        ${viPct > 0 ? `<div class="cj-caja-pago-bar-vi" style="width:${viPct}%">${viPct >= 12 ? '📱' : ''}</div>` : ''}
        ${mxPct > 0 ? `<div class="cj-caja-pago-bar-mx" style="width:${mxPct}%">${mxPct >= 12 ? '🔀' : ''}</div>` : ''}
        ${crPct > 0 ? `<div class="cj-caja-pago-bar-cr" style="width:${crPct}%">${crPct >= 12 ? '📋' : ''}</div>` : ''}
      </div>
      <div class="cj-caja-pago-leg">
        ${ef > 0 ? `<span class="cj-caja-pago-leg-item"><span style="width:8px;height:8px;border-radius:50%;background:#34d399"></span>S/ ${ef.toFixed(0)}</span>` : ''}
        ${mVi > 0 ? `<span class="cj-caja-pago-leg-item"><span style="width:8px;height:8px;border-radius:50%;background:#22d3ee"></span>S/ ${mVi.toFixed(0)}</span>` : ''}
        ${mMx > 0 ? `<span class="cj-caja-pago-leg-item"><span style="width:8px;height:8px;border-radius:50%;background:#a5b4fc"></span>S/ ${mMx.toFixed(0)}</span>` : ''}
        ${mCr > 0 ? `<span class="cj-caja-pago-leg-item"><span style="width:8px;height:8px;border-radius:50%;background:#fb923c"></span>S/ ${mCr.toFixed(0)}</span>` : ''}
      </div>
      <div class="cj-spark">${sparkBars}</div>
      <div class="cj-spark-axis"><span>7h</span><span>13h</span><span>19h</span></div>
      <div class="cj-caja-actions">
        ${btnActiva}
      </div>
      <div class="cj-caja-detail ${_cjState.expandido.has(idAttr) ? '' : 'hidden'}" id="cjdetail-${idAttr}">
        ${_cjBuildDetalleHtml(c)}
      </div>
    </div>`;
  }

  function _cjBuildDetalleHtml(c) {
    const tkList = (c.ticketsList || []).slice(0, 30);
    const exList = (c.extrasList || []);
    if (!tkList.length && !exList.length) return '<div class="text-xs text-slate-500 italic">Sin tickets ni movimientos</div>';
    const ticketsHtml = tkList.length ? `
      <div class="cj-caja-detail-head">${tkList.length} ticket${tkList.length!==1?'s':''}</div>
      ${tkList.map(t => {
        const an = t.estado === 'ANULADO';
        return `<div class="flex items-center gap-2 py-1.5 border-b border-slate-800/40 ${an?'opacity-50':''}">
          <span class="text-[10px] font-mono text-slate-400">${t.correlativo||'—'}</span>
          <span class="text-[10px] text-slate-500 flex-1 min-w-0 truncate">${t.clienteNom||t.clienteDoc||'—'}</span>
          <span class="text-[10px] ${an?'line-through text-slate-600':'text-slate-300 font-bold'}">S/ ${parseFloat(t.total||0).toFixed(2)}</span>
          <span class="text-[9px] text-slate-500">${(t.metodo||'').substring(0,3)}</span>
        </div>`;
      }).join('')}
    ` : '';
    const extrasHtml = exList.length ? `
      <div class="cj-caja-detail-head" style="margin-top:10px">Movimientos extra</div>
      ${exList.map(ex => {
        const idEx = String(ex.idExtra || '').replace(/'/g, '&#39;');
        const colorCls = ex.tipo === 'INGRESO' || ex.tipo === 'INGRESO_VIRTUAL' ? 'text-emerald-400' : 'text-red-400';
        const sigArr = ex.tipo === 'INGRESO' || ex.tipo === 'INGRESO_VIRTUAL' ? '▲' : '▼';
        const sigMon = ex.tipo === 'INGRESO' || ex.tipo === 'INGRESO_VIRTUAL' ? '+' : '-';
        return `<div class="flex items-center justify-between gap-2 py-1 text-[10px]">
          <span class="${colorCls} flex-1 min-w-0 truncate">${sigArr} ${ex.concepto || ex.tipo}</span>
          <span class="${colorCls} font-bold">${sigMon}S/ ${parseFloat(ex.monto||0).toFixed(2)}</span>
          ${idEx ? `<button onclick="event.stopPropagation();MOS.cjHistorialExtra('${idEx}')" class="text-[11px] opacity-50 hover:opacity-100" title="Ver historial">📜</button>` : ''}
        </div>`;
      }).join('')}
    ` : '';
    return ticketsHtml + extrasHtml;
  }

  function cjToggleCajaDetail(idCaja) {
    const id = String(idCaja);
    if (_cjState.expandido.has(id)) _cjState.expandido.delete(id);
    else _cjState.expandido.add(id);
    const safe = id.replace(/'/g, '&#39;');
    const det = document.getElementById('cjdetail-' + safe);
    const tog = document.querySelector(`#cjcard-${safe} .cj-caja-toggle`);
    if (det) det.classList.toggle('hidden');
    if (tog) tog.classList.toggle('open');
    _finBeep('click');
  }

  // Helper: minutos desde apertura
  function _cajaMinutosDesdeApertura(fechaApertura) {
    if (!fechaApertura) return 0;
    return Math.floor((Date.now() - new Date(fechaApertura).getTime()) / 60000);
  }

  // ── Reloj live: actualiza elapsed cada segundo ────────
  function _cjStartElapsedTimer(activar) {
    if (_cjState.elapsedTimer) {
      clearInterval(_cjState.elapsedTimer);
      _cjState.elapsedTimer = null;
    }
    if (!activar) return;
    _cjState.elapsedTimer = setInterval(() => {
      document.querySelectorAll('[data-elapsed-id]').forEach(el => {
        const fecha = el.dataset.fecha;
        const cierre = el.dataset.cierre;
        if (cierre) return; // solo activas
        if (fecha) el.textContent = _cajaElapsed(fecha);
      });
    }, 1000);
  }

  // ── Detectar tickets nuevos por caja → cha-ching + popup ───
  function _cjDetectarTicketsNuevos(abiertas) {
    abiertas.forEach(c => {
      const id = String(c.idCaja);
      const previo = _cjState.chunksAnteriores.get(id);
      const actualTk = c.tickets || 0;
      const actualMonto = parseFloat(c.totalVentas) || 0;
      if (previo !== undefined && actualTk > (previo.tk || 0)) {
        const deltaMonto = Math.max(0, actualMonto - (previo.monto || 0));
        const deltaTk = actualTk - (previo.tk || 0);
        _cjEfectoVentaNueva(id, deltaMonto, deltaTk);
      }
      _cjState.chunksAnteriores.set(id, { tk: actualTk, monto: actualMonto });
    });
  }

  // ── Efecto registradora ¡cha-ching! ──────────────────
  function _cjEfectoVentaNueva(idCaja, deltaMonto, deltaTk) {
    const safe = String(idCaja).replace(/'/g, '&#39;');
    const card = document.getElementById('cjcard-' + safe);
    if (!card) return;
    // 1) Sonido dinero
    _finBeep('dinero');
    // 2) Vibración + glow
    card.classList.remove('cj-vibrate');
    void card.offsetWidth;
    card.classList.add('cj-vibrate');
    setTimeout(() => card.classList.remove('cj-vibrate'), 700);
    // 3) Popup +S/ XX flotante saliendo del hero
    const hero = card.querySelector('.cj-caja-hero');
    if (hero) {
      const pop = document.createElement('div');
      pop.className = 'cj-pop-venta';
      const txt = deltaMonto > 0
        ? `+S/ ${deltaMonto.toFixed(2)}`
        : `+${deltaTk} ticket${deltaTk!==1?'s':''}`;
      pop.innerHTML = `<span class="cj-pop-emoji">💸</span><span>${txt}</span>`;
      hero.appendChild(pop);
      setTimeout(() => pop.remove(), 2000);
    }
    // 4) Pulso del monto del card (countup animado)
    const monto = card.querySelector('.cj-caja-hero-monto');
    if (monto) {
      monto.classList.remove('cj-monto-pulse');
      void monto.offsetWidth;
      monto.classList.add('cj-monto-pulse');
      setTimeout(() => monto.classList.remove('cj-monto-pulse'), 900);
    }
    // 5) Pulso del KPI grande del día también
    const kpi = $('cajasKpiVentas');
    if (kpi) {
      kpi.classList.remove('cj-monto-pulse');
      void kpi.offsetWidth;
      kpi.classList.add('cj-monto-pulse');
    }
    // 6) Pulso de la barra de pago global
    const pagoBar = document.querySelector('.fin-pago-bar');
    if (pagoBar) {
      pagoBar.classList.remove('cj-bar-pulse');
      void pagoBar.offsetWidth;
      pagoBar.classList.add('cj-bar-pulse');
    }
  }

  // ── Pulso del dot polling ──────────────────────
  function _cjPulsoPoll() {
    const dot = $('cjPollDot');
    if (!dot) return;
    dot.classList.add('active');
    setTimeout(() => dot.classList.remove('active'), 1300);
  }

  // ── RANKING: deprecado — la corona 👑 va al card de la caja líder ──
  // (Eliminado: el card de "Ranking del día" + duplicado en TV strip)

  function cjScrollToCaja(idCaja) {
    const safe = String(idCaja).replace(/'/g, '&#39;');
    const card = document.getElementById('cjcard-' + safe);
    if (card) {
      card.scrollIntoView({ behavior: 'smooth', block: 'center' });
      card.classList.remove('flash');
      void card.offsetWidth;
      card.classList.add('flash');
      _finBeep('nav');
    }
  }

  // ── ACTIVIDAD POR HORA (timeline horizontal con barras) ─────
  function _cjRenderActividad(tickets, esHoy) {
    const cont = $('cjActividad');
    if (!cont) return;
    const fp2 = t => String(t.metodo || t.formaPago || '').toUpperCase();
    const esAnul2 = t => fp2(t) === 'ANULADO' || t.estado === 'ANULADO';

    // Acumular por hora (6h-22h = 17 filas)
    const horaIni = 6, horaFin = 22;
    const horas = {};
    for (let h = horaIni; h <= horaFin; h++) horas[h] = { total: 0, count: 0 };
    tickets.forEach(t => {
      if (esAnul2(t)) return;
      const h = parseInt(String(t.hora || '0').split(':')[0], 10);
      if (h >= horaIni && h <= horaFin) {
        horas[h].total += (parseFloat(t.total) || 0);
        horas[h].count += 1;
      }
    });
    const horasArr = Object.keys(horas).map(h => ({ h: parseInt(h, 10), ...horas[h] }));
    const max = Math.max.apply(null, horasArr.map(x => x.total).concat([1]));
    const totalGen = horasArr.reduce((s, x) => s + x.total, 0);
    if (totalGen === 0) {
      cont.innerHTML = '<p class="text-slate-500 text-xs italic text-center py-8">Sin actividad en esta fecha</p>';
      _setText('cjActividadPico', '—');
      return;
    }

    // Hora pico
    const pico = horasArr.slice().sort((a, b) => b.total - a.total)[0];
    const picoTxt = (pico && pico.total > 0)
      ? `🔥 Pico: ${String(pico.h).padStart(2, '0')}h · S/ ${pico.total.toFixed(0)}`
      : '—';
    _setText('cjActividadPico', picoTxt);
    _setText('cjActividadPicoTV', picoTxt);

    const horaActual = new Date().getHours();
    const html = `<div class="cj-actividad-grid">${
      horasArr.map(x => {
        const pct = x.total === 0 ? 0 : Math.max(2, (x.total / max) * 100);
        const isNow = esHoy && x.h === horaActual;
        const cls = x.total === 0 ? 'zero' : (isNow ? 'now' : '');
        const rowCls = isNow ? 'cj-actividad-row now' : 'cj-actividad-row';
        const horaCls = isNow ? 'cj-actividad-hora now' : 'cj-actividad-hora';
        const monto = x.total > 0 ? 'S/ ' + x.total.toFixed(0) : '';
        return `
          <div class="${horaCls}">${String(x.h).padStart(2, '0')}h</div>
          <div class="cj-actividad-bar-track">
            <div class="cj-actividad-bar-fill ${cls}" style="width:${pct}%">
              <span class="cj-actividad-bar-monto">${monto}</span>
            </div>
          </div>
          <div class="cj-actividad-tickets ${rowCls}">
            <span class="cj-actividad-tickets-num">${x.count}</span> tk
          </div>`;
      }).join('')
    }</div>`;
    cont.innerHTML = html;
    const tv = $('cjActividadTV');
    if (tv) tv.innerHTML = html;
  }

  // ── ÚLTIMOS 7 DÍAS (mini-row + chart) ───────────────────
  function _cjRender7d(fechaActiva) {
    const tkAll = S._todosTickets || [];
    const cajasAll = S._todasCajas || [];
    // 7 días terminando en fechaActiva
    const dias = [];
    for (let i = 6; i >= 0; i--) {
      const f = _fechaOffset(fechaActiva, -i);
      dias.push({ fecha: f, total: 0, count: 0, cajas: 0 });
    }
    const fp3 = t => String(t.metodo || t.formaPago || '').toUpperCase();
    const esAnul3 = t => fp3(t) === 'ANULADO' || t.estado === 'ANULADO';
    tkAll.forEach(t => {
      const f = (t.fecha || '').substring(0, 10);
      const dia = dias.find(d => d.fecha === f);
      if (!dia) return;
      if (esAnul3(t)) return;
      dia.total += (parseFloat(t.total) || 0);
      dia.count += 1;
    });
    cajasAll.forEach(c => {
      const fa = (c.fechaApertura || '').substring(0, 10);
      const fc = (c.fechaCierre   || '').substring(0, 10);
      const dia = dias.find(d => d.fecha === fa || d.fecha === fc);
      if (dia) dia.cajas++;
    });
    const totalSemana = dias.reduce((s, d) => s + d.total, 0);
    ['cj7dTotal', 'cj7dTotalTV'].forEach(id => {
      const pill = $(id);
      if (pill) {
        pill.textContent = totalSemana > 0 ? 'S/ ' + totalSemana.toFixed(0) : 'S/ 0';
        pill.classList.toggle('up', totalSemana > 0);
        pill.classList.remove('down');
      }
    });
    _setText('cj7dSubtitulo', `Total 7d: S/ ${totalSemana.toFixed(2)}`);

    const max = Math.max.apply(null, dias.map(d => d.total).concat([1]));
    const hoy = today();
    const miniHtml = dias.map(d => {
      const dt = new Date(d.fecha + 'T00:00:00');
      const dia = dt.toLocaleDateString('es-PE', { weekday: 'short' }).slice(0, 3);
      const h = Math.max(6, (d.total / max) * 30);
      const cls = ['cj-7d-mini-day'];
      if (d.fecha === hoy) cls.push('today');
      if (d.total > 0) cls.push('has-data');
      return `<button class="${cls.join(' ')}" onclick="MOS.cjElegirFecha('${d.fecha}')" title="${d.fecha} · S/ ${d.total.toFixed(2)} · ${d.count} tk">
        <div class="cj-7d-mini-bar" style="height:${h}px"></div>
        <div class="cj-7d-mini-lbl">${dia}</div>
      </button>`;
    }).join('');
    ['cj7dMiniRow', 'cj7dMiniRowTV'].forEach(id => {
      const el = $(id); if (el) el.innerHTML = miniHtml;
    });

    const labels = dias.map(d => {
      const dt = new Date(d.fecha + 'T00:00:00');
      return dt.toLocaleDateString('es-PE', { weekday: 'short', day: 'numeric' });
    });
    const opts = {
      type: 'bar',
      data: {
        labels,
        datasets: [
          { label: 'Ventas',  data: dias.map(d => d.total), backgroundColor: 'rgba(34,211,238,0.55)', borderRadius: 4 },
          { label: 'Tickets', data: dias.map(d => d.count), backgroundColor: 'rgba(168,85,247,0.55)', borderRadius: 4, yAxisID: 'y1' }
        ]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: { legend: { labels: { color: '#64748b', boxWidth: 10, font: { size: 9 } } } },
        scales: {
          x: { grid: { color: '#1e293b' }, ticks: { color: '#64748b', font: { size: 9 } } },
          y: { position: 'left', grid: { color: '#1e293b' }, ticks: { color: '#64748b', callback: v => 'S/' + v, font: { size: 9 } } },
          y1: { position: 'right', grid: { display: false }, ticks: { color: '#a855f7', font: { size: 9 } } }
        }
      }
    };
    try { renderChart('chartCajasBars', opts); } catch (_) {}
    if ($('chartCajasBarsTV')) {
      try { renderChart('chartCajasBarsTV', opts); } catch (_) {}
    }
  }

  // ════════════════════════════════════════════════════════
  // [v40.4] CRÉDITOS — MANO DE CARTAS estilo poker hand
  // Una sola mano de la fecha activa. Cartas peeking + shuffle ciclico.
  // Click → mesa overlay. Click carta → detalle con FAB enviar.
  // ════════════════════════════════════════════════════════
  let _cjCreditosState = {
    todosLosGrupos: [],            // [{fecha, tickets, ...}]  cache 30d desde backend
    ticketsActivos: [],            // tickets de la fecha actualmente visible
    fechaActiva:    null,          // fecha actualmente visible
    shuffleTimer:   null,          // setInterval para barajar
    shuffleIdx:     0,             // qué carta está al frente
    detalleTicket:  null,          // ticket en overlay detalle
    asignarCtx:     null,
    asignarCaja:    null,
    asignarMetodo:  'EFECTIVO',
    asignarTTL:     1,             // [v2.41.86] tiempo límite (1/2/4/6h)
    asignarMensaje: '',            // [v2.41.87] mensaje opcional al cajero
    // [v41] Set de idVenta ya vistos en renders previos. Las cartas con id que
    // no esté aquí se marcan como nuevas y se animan con cj-carta-nueva.
    idsVistos:      new Set(),
    // [v2.41.87] Cobros en vuelo + recientes para panel admin
    enVuelo:        [],
    recientes:      [],
    enVueloLastFetch: 0,
    enVueloTick:    0,             // forzar reactividad countdown live
    // [v2.42.00] Cache cajas abiertas para asignación instantánea
    cajasAbiertasCache:     [],
    cajasAbiertasCacheTs:   0      // ms epoch del último fetch (TTL 30s)
  };
  // [v2.41.87] Tick reactivo cada 30s para countdown en cobros en vuelo
  setInterval(() => {
    _cjCreditosState.enVueloTick++;
    const cont = document.getElementById('cjEnVueloPanel');
    if (cont && !cont.classList.contains('hidden')) {
      _cjRenderEnVuelo();
    }
  }, 30000);

  // ════════════════════════════════════════════════════════════
  // [v2.41.87] COBROS EN VUELO — Panel admin con countdown live,
  // cancelar y reasignar. Se renderiza arriba de la baraja de
  // créditos pendientes en Cajas.
  // ════════════════════════════════════════════════════════════
  async function _cjCargarEnVuelo(silent) {
    try {
      const r = await API.get('meCobrosEnVuelo', {});
      const d = (r && r.data) ? r.data : (r || {});
      _cjCreditosState.enVuelo = d.enVuelo || [];
      _cjCreditosState.recientes = d.recientes || [];
      _cjCreditosState.enVueloLastFetch = Date.now();
      _cjRenderEnVuelo();
      // [v2.42.00] Re-pintar postits encima de cada cuadro de caja
      try { _cjPintarPostitsManojos(); } catch(_){}
    } catch(e) {
      if (!silent) console.warn('[enVuelo] error:', e?.message || e);
    }
  }

  // [v2.42.00] Precarga cajas abiertas + cache 30s. Lo llamamos al abrir la
  // mesa de créditos para que cuando el admin haga click en "Asignar a caja"
  // los chips de cajeros aparezcan instantáneo. Sin esta precarga, el modal
  // muestra spinner ~1.5s mientras el GAS responde.
  async function _cjPrecargarCajasAbiertas(forzar) {
    const ahora = Date.now();
    const fresca = (ahora - (_cjCreditosState.cajasAbiertasCacheTs || 0)) < 30000;
    if (!forzar && fresca && _cjCreditosState.cajasAbiertasCache.length) {
      return _cjCreditosState.cajasAbiertasCache;
    }
    try {
      const r = await API.post('meCajasAbiertas', {});
      const lista = (r && r.data) ? r.data : (r || []);
      _cjCreditosState.cajasAbiertasCache    = Array.isArray(lista) ? lista : [];
      _cjCreditosState.cajasAbiertasCacheTs  = ahora;
      return _cjCreditosState.cajasAbiertasCache;
    } catch(e) {
      console.warn('[precargaCajas] error:', e?.message || e);
      return _cjCreditosState.cajasAbiertasCache || [];
    }
  }

  // ════════════════════════════════════════════════════════════
  // [v2.42.00] POSTITS MANOJO — los cobros en vuelo aparecen como
  // un manojo de postits rotados, pegados con un pin sobre el cuadro
  // de la caja activa del cajero asignado. Hover endereza + agranda,
  // click abre modal mini con acciones admin (Reasignar/Cancelar).
  // ════════════════════════════════════════════════════════════
  function _cjPostitColorClass(cobro) {
    try {
      const t = new Date(cobro.fechaVencimiento).getTime();
      const minMs = t - Date.now();
      if (isNaN(minMs)) return 'cj-postit-warn';
      if (minMs <= 30 * 60000)      return 'cj-postit-critical';  // <30min rojo
      if (minMs <= 2  * 60 * 60000) return 'cj-postit-warn';      // 30min-2h ámbar
      return 'cj-postit-ok';                                       // >2h verde
    } catch(_) { return 'cj-postit-warn'; }
  }

  function _cjPostitRestante(cobro) {
    try {
      const t = new Date(cobro.fechaVencimiento).getTime();
      const diffMin = Math.floor((t - Date.now()) / 60000);
      if (isNaN(diffMin)) return '';
      if (diffMin <= 0) return 'vencido';
      if (diffMin < 60) return diffMin + 'm';
      const h = Math.floor(diffMin / 60), m = diffMin % 60;
      return h + 'h' + (m > 0 ? ' ' + m + 'm' : '');
    } catch(_) { return ''; }
  }

  function _cjPintarPostitsManojos(opts) {
    opts = opts || {};
    const enVuelo = _cjCreditosState.enVuelo || [];
    // Agrupar por cajaDestino
    const porCaja = {};
    for (const c of enVuelo) {
      const id = String(c.cajaDestino || '');
      if (!id) continue;
      if (!porCaja[id]) porCaja[id] = [];
      porCaja[id].push(c);
    }
    // Iterar todos los cards de caja en pantalla y montar/desmontar el manojo
    const cards = document.querySelectorAll('.cj-caja-card');
    cards.forEach(card => {
      const idCaja = card.dataset.idcaja;
      if (!idCaja) return;
      // Asegurar contenedor manojo
      let manojo = card.querySelector('.cj-postit-manojo');
      const cobros = porCaja[idCaja] || [];
      if (!cobros.length) {
        if (manojo) { try { manojo.remove(); } catch(_){} }
        return;
      }
      if (!manojo) {
        manojo = document.createElement('div');
        manojo.className = 'cj-postit-manojo';
        manojo.setAttribute('aria-label', 'Cobros en vuelo asignados');
        card.appendChild(manojo);
        // El manojo no debe disparar el toggle del card
        manojo.addEventListener('click', (ev) => { ev.stopPropagation(); });
      }
      // Render postits: rotación variable + offset apilado tipo abanico
      const N = cobros.length;
      const _esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
      let html = `<div class="cj-postit-pin" title="${N} cobro${N>1?'s':''} en vuelo">📌</div>`;
      // Render del más reciente al fondo, primero arriba para que al hacer fan-out se vea
      cobros.forEach((c, i) => {
        const colorCls = _cjPostitColorClass(c);
        const restTxt  = _cjPostitRestante(c);
        // Ángulo y offset estables por idCobro (hash simple)
        const seed = (String(c.idCobro || i)).split('').reduce((a, ch) => a + ch.charCodeAt(0), 0);
        const rotDeg  = (seed % 13) - 6;             // -6..+6
        const offX    = (seed % 7);                  // 0..6 px
        const offY    = i * 8;                       // apilado vertical 8px
        const reasignBadge = (c.reasignaciones > 0) ? `<span class="cj-postit-reasig" title="Reasignado ${c.reasignaciones}×">↺${c.reasignaciones}</span>` : '';
        const optBadge = c._optimistic ? '<span class="cj-postit-opt" title="Enviando…">⌛</span>' : '';
        html += `<button type="button"
                   class="cj-postit ${colorCls} ${c._optimistic ? 'cj-postit-optimistic' : ''}"
                   data-idcobro="${_esc(c.idCobro)}"
                   data-idventa="${_esc(c.idVenta)}"
                   style="--rot:${rotDeg}deg; --offx:${offX}px; --offy:${offY}px; --zi:${100 - i};"
                   onclick="event.stopPropagation();MOS._cjAbrirPostitModal('${_esc(c.idCobro)}')"
                   title="${_esc(c.cliente || 'VARIOS')} · S/ ${parseFloat(c.monto || 0).toFixed(2)} → ${_esc(c.vendedorDest || '')}">
          <div class="cj-postit-cliente">${_esc((c.cliente || 'VARIOS').substring(0, 14))}</div>
          <div class="cj-postit-monto">S/ ${parseFloat(c.monto || 0).toFixed(2)}</div>
          <div class="cj-postit-foot">
            <span class="cj-postit-tiempo">⏱ ${_esc(restTxt)}</span>
            ${reasignBadge}${optBadge}
          </div>
        </button>`;
      });
      manojo.innerHTML = html;
      // Animación de aterrizaje si es nuevo (postit optimista nuevo)
      if (opts.optimisticId) {
        const nuevo = manojo.querySelector(`[data-idcobro="${opts.optimisticId}"]`);
        if (nuevo) {
          nuevo.classList.add('cj-postit-landing');
          try { _finBeep?.('whoosh') || _finBeep?.('tap'); } catch(_){}
          setTimeout(() => { try { nuevo.classList.remove('cj-postit-landing'); } catch(_){} }, 700);
        }
      }
    });
  }

  // Modal mini con acciones admin sobre un postit
  function _cjAbrirPostitModal(idCobro) {
    const cobro = (_cjCreditosState.enVuelo || []).find(c => String(c.idCobro) === String(idCobro));
    if (!cobro) { toast('Cobro no encontrado', 'warn'); return; }
    try { _finBeep?.('expand') || _finBeep?.('tap'); } catch(_){}
    let backdrop = document.getElementById('cjPostitModal');
    if (!backdrop) {
      backdrop = document.createElement('div');
      backdrop.id = 'cjPostitModal';
      backdrop.className = 'cj-postit-modal-backdrop';
      backdrop.addEventListener('click', (ev) => { if (ev.target === backdrop) _cjCerrarPostitModal(); });
      document.body.appendChild(backdrop);
    }
    const _esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
    const restTxt = _cjPostitRestante(cobro);
    const colorCls = _cjPostitColorClass(cobro);
    const msg = cobro.mensajeAdmin ? `<div class="cj-postit-modal-msg">💬 "${_esc(cobro.mensajeAdmin)}"</div>` : '';
    backdrop.innerHTML = `
      <div class="cj-postit-modal ${colorCls}" role="dialog" aria-modal="true">
        <div class="cj-postit-modal-head">
          <div class="cj-postit-modal-flecha">✈</div>
          <div class="cj-postit-modal-titulo">
            <strong>${_esc(cobro.cliente || 'VARIOS')}</strong>
            <span>→ ${_esc(cobro.vendedorDest || 'cajero')}</span>
          </div>
          <button class="cj-postit-modal-close" onclick="MOS._cjCerrarPostitModal()" aria-label="Cerrar">✕</button>
        </div>
        <div class="cj-postit-modal-monto">S/ ${parseFloat(cobro.monto || 0).toFixed(2)}</div>
        <div class="cj-postit-modal-meta">
          <span>📋 ${_esc(cobro.correlativo || '')}</span>
          <span>⏱ ${_esc(restTxt)}</span>
        </div>
        ${msg}
        <div class="cj-postit-modal-actions">
          <button class="cj-postit-modal-btn cj-postit-modal-btn-ghost" onclick="MOS._cjCerrarPostitModal()">Cerrar</button>
          <button class="cj-postit-modal-btn cj-postit-modal-btn-reasig" onclick="MOS.cjReasignarCobro('${_esc(cobro.idCobro)}')">
            <span>↺</span> Reasignar
          </button>
          <button class="cj-postit-modal-btn cj-postit-modal-btn-cancel" onclick="MOS.cjCancelarCobro('${_esc(cobro.idCobro)}')">
            <span>✕</span> Cancelar
          </button>
        </div>
      </div>`;
    requestAnimationFrame(() => backdrop.classList.add('is-open'));
  }

  function _cjCerrarPostitModal() {
    const b = document.getElementById('cjPostitModal');
    if (!b) return;
    b.classList.remove('is-open');
    setTimeout(() => { try { b.remove(); } catch(_){} }, 200);
    try { _finBeep?.('collapse') || _finBeep?.('tap'); } catch(_){}
  }

  // ════════════════════════════════════════════════════════════
  // [v2.42.00] MODAL CUSTOM Reasignar — reemplaza prompt() nativo
  // ════════════════════════════════════════════════════════════
  async function _cjModalReasignar(cobro) {
    return new Promise(async (resolve) => {
      const cajas = await _cjPrecargarCajasAbiertas();
      const validas = (cajas || []).filter(c => String(c.idCaja) !== String(cobro.cajaDestino));
      if (!validas.length) { resolve(null); toast('No hay otra caja abierta', 'warn'); return; }
      const _esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
      let backdrop = document.createElement('div');
      backdrop.className = 'cj-modal-action-backdrop';
      backdrop.innerHTML = `
        <div class="cj-modal-action cj-modal-action-reasig">
          <div class="cj-modal-action-head">
            <span class="cj-modal-action-ico">↺</span>
            <div class="cj-modal-action-titulo">
              <strong>Reasignar cobro</strong>
              <span>${_esc(cobro.cliente || 'VARIOS')} · S/ ${parseFloat(cobro.monto || 0).toFixed(2)}</span>
            </div>
            <button class="cj-modal-action-close" data-close>✕</button>
          </div>
          <div class="cj-modal-action-body">
            <div class="cj-modal-action-label">Mover de <strong>${_esc(cobro.vendedorDest || '')}</strong> a:</div>
            <div class="cj-modal-action-cajas">
              ${validas.map((c, i) => `
                <button class="cj-modal-action-caja" data-caja="${_esc(c.idCaja)}" style="animation-delay:${i*50}ms">
                  <div class="cj-modal-action-caja-avatar">👤</div>
                  <div class="cj-modal-action-caja-info">
                    <div class="cj-modal-action-caja-nom">${_esc(c.vendedor)}</div>
                    <div class="cj-modal-action-caja-sub">${_esc(c.estacion || '')}${c.zona ? ' · ' + _esc(c.zona) : ''}</div>
                  </div>
                  <span class="cj-modal-action-caja-check">→</span>
                </button>
              `).join('')}
            </div>
          </div>
          <div class="cj-modal-action-footer">
            <button class="cj-modal-action-btn cj-modal-action-btn-ghost" data-close>Cancelar</button>
          </div>
        </div>`;
      backdrop.addEventListener('click', (ev) => {
        const t = ev.target;
        if (t === backdrop || (t.closest && t.closest('[data-close]'))) {
          backdrop.classList.remove('is-open');
          setTimeout(() => { try { backdrop.remove(); } catch(_){} }, 200);
          resolve(null);
          return;
        }
        const cajaBtn = t.closest && t.closest('[data-caja]');
        if (cajaBtn) {
          const id = cajaBtn.dataset.caja;
          const elegida = validas.find(c => String(c.idCaja) === String(id));
          cajaBtn.classList.add('is-selected');
          try { _finBeep?.('success'); } catch(_){}
          setTimeout(() => {
            backdrop.classList.remove('is-open');
            setTimeout(() => { try { backdrop.remove(); } catch(_){} }, 200);
            resolve(elegida);
          }, 180);
        }
      });
      document.body.appendChild(backdrop);
      requestAnimationFrame(() => backdrop.classList.add('is-open'));
      try { _finBeep?.('expand') || _finBeep?.('tap'); } catch(_){}
    });
  }

  // ════════════════════════════════════════════════════════════
  // [v2.42.00] MODAL CUSTOM Cancelar — reemplaza prompt() nativo
  // ════════════════════════════════════════════════════════════
  function _cjModalCancelarCobro(cobro) {
    return new Promise((resolve) => {
      const _esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
      const backdrop = document.createElement('div');
      backdrop.className = 'cj-modal-action-backdrop';
      backdrop.innerHTML = `
        <div class="cj-modal-action cj-modal-action-cancel">
          <div class="cj-modal-action-head">
            <span class="cj-modal-action-ico">⊘</span>
            <div class="cj-modal-action-titulo">
              <strong>Cancelar cobro asignado</strong>
              <span>${_esc(cobro.cliente || 'VARIOS')} · S/ ${parseFloat(cobro.monto || 0).toFixed(2)}</span>
            </div>
            <button class="cj-modal-action-close" data-close>✕</button>
          </div>
          <div class="cj-modal-action-body">
            <div class="cj-modal-action-warn">
              ⚠ El ticket vuelve a estado <strong>CRÉDITO</strong> y el cajero pierde la asignación. Esta acción queda en auditoría.
            </div>
            <label class="cj-modal-action-label">Razón (opcional · queda en log)</label>
            <textarea class="cj-modal-action-textarea" maxlength="180" rows="3"
                      placeholder="Cliente ya no vendrá hoy / asignación errónea / etc."></textarea>
          </div>
          <div class="cj-modal-action-footer">
            <button class="cj-modal-action-btn cj-modal-action-btn-ghost" data-close>Cerrar</button>
            <button class="cj-modal-action-btn cj-modal-action-btn-danger" data-confirm>
              ⊘ Sí, cancelar
            </button>
          </div>
        </div>`;
      backdrop.addEventListener('click', (ev) => {
        const t = ev.target;
        if (t === backdrop || (t.closest && t.closest('[data-close]'))) {
          backdrop.classList.remove('is-open');
          setTimeout(() => { try { backdrop.remove(); } catch(_){} }, 200);
          resolve(null);
        } else if (t.closest && t.closest('[data-confirm]')) {
          const ta = backdrop.querySelector('.cj-modal-action-textarea');
          const razon = ta ? ta.value.trim() : '';
          try { _finBeep?.('warn') || _finBeep?.('tap'); } catch(_){}
          backdrop.classList.remove('is-open');
          setTimeout(() => { try { backdrop.remove(); } catch(_){} }, 200);
          resolve({ razon });
        }
      });
      document.body.appendChild(backdrop);
      requestAnimationFrame(() => backdrop.classList.add('is-open'));
      try { _finBeep?.('expand') || _finBeep?.('tap'); } catch(_){}
    });
  }

  function _cjRestanteTxt(cobro) {
    if (!cobro || !cobro.fechaVencimiento) return '';
    const t = new Date(cobro.fechaVencimiento).getTime();
    if (isNaN(t)) return '';
    const diffMs = t - Date.now();
    if (diffMs <= 0) return '⏰ vencido';
    const min = Math.floor(diffMs / 60000);
    if (min < 60) return min + ' min';
    const h = Math.floor(min / 60);
    const m = min % 60;
    return h + 'h ' + (m > 0 ? m + 'm' : '');
  }
  function _cjUrgenciaClase(cobro) {
    if (!cobro || !cobro.fechaVencimiento) return 'ok';
    const t = new Date(cobro.fechaVencimiento).getTime();
    if (isNaN(t)) return 'ok';
    const diffMin = (t - Date.now()) / 60000;
    if (diffMin <= 5) return 'critical';
    if (diffMin <= 15) return 'warn';
    return 'ok';
  }

  function _cjRenderEnVuelo() {
    const cont = document.getElementById('cjEnVueloPanel');
    if (!cont) return;
    const enVuelo = _cjCreditosState.enVuelo || [];
    const recientes = _cjCreditosState.recientes || [];
    if (!enVuelo.length && !recientes.length) {
      cont.classList.add('hidden');
      cont.innerHTML = '';
      return;
    }
    cont.classList.remove('hidden');
    const _esc = (s) => _escapeHtml(String(s || ''));
    const cardVuelo = (c) => {
      const u = _cjUrgenciaClase(c);
      const restante = _cjRestanteTxt(c);
      const reasignBadge = c.reasignaciones > 0 ? `<span class="cj-vuelo-reasignado" title="Reasignado ${c.reasignaciones} vez(es)">↺ ${c.reasignaciones}</span>` : '';
      const mensaje = c.mensajeAdmin ? `<div class="cj-vuelo-msg">💬 "${_esc(c.mensajeAdmin)}"</div>` : '';
      return `<div class="cj-vuelo-card cj-vuelo-${u}">
        <div class="cj-vuelo-head">
          <div class="cj-vuelo-cliente">
            <span class="cj-vuelo-flecha">✈</span>
            <strong>${_esc(c.cliente || 'VARIOS')}</strong>
            <span class="cj-vuelo-flecha-to">→</span>
            <span class="cj-vuelo-cajero">${_esc(c.vendedorDest)}</span>
            ${reasignBadge}
          </div>
          <span class="cj-vuelo-monto">S/ ${parseFloat(c.monto || 0).toFixed(2)}</span>
        </div>
        <div class="cj-vuelo-meta">
          <span class="cj-vuelo-metodo">${c.metodoSug === 'EFECTIVO' ? '💵' : c.metodoSug === 'VIRTUAL' ? '📱' : '🔀'} ${_esc(c.metodoSug)}</span>
          <span class="cj-vuelo-corr">${_esc(c.correlativo)}</span>
          <span class="cj-vuelo-tiempo cj-vuelo-tiempo-${u}">⏱ ${restante}</span>
        </div>
        ${mensaje}
        <div class="cj-vuelo-actions">
          <button onclick="MOS.cjReasignarCobro('${_esc(c.idCobro)}')" class="cj-vuelo-btn cj-vuelo-btn-reasignar">↺ Reasignar</button>
          <button onclick="MOS.cjCancelarCobro('${_esc(c.idCobro)}')" class="cj-vuelo-btn cj-vuelo-btn-cancelar">✕ Cancelar</button>
        </div>
      </div>`;
    };
    // [v2.41.90] Hora en formato HH:mm de la fecha de resolución
    const _horaRes = (iso) => {
      try {
        const d = new Date(iso);
        if (isNaN(d.getTime())) return '';
        return d.toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit', hour12: false });
      } catch(_) { return ''; }
    };
    // [v2.41.90] Cuánto hace que se resolvió ("hace 5min", "hace 1h 12min")
    const _haceCuanto = (iso) => {
      try {
        const ms = Date.now() - new Date(iso).getTime();
        if (isNaN(ms) || ms < 0) return '';
        const mins = Math.floor(ms / 60000);
        if (mins < 1) return 'ahora mismo';
        if (mins < 60) return 'hace ' + mins + 'min';
        const h = Math.floor(mins / 60);
        const m = mins % 60;
        return 'hace ' + h + 'h' + (m ? ' ' + m + 'min' : '');
      } catch(_) { return ''; }
    };
    const cardReciente = (c) => {
      const estTxt = c.estado === 'COBRADO' ? '✓ COBRADO'
        : c.estado === 'EXPIRADO' ? '⏰ Expirado'
        : c.estado === 'CANCELADO_ADMIN' ? '⊘ Cancelado'
        : c.estado === 'RECHAZADO' ? '✗ Rechazado'
        : c.estado === 'REASIGNADO' ? '↺ Reasignado'
        : c.estado;
      const estClass = c.estado === 'COBRADO' ? 'reciente-ok'
        : c.estado === 'EXPIRADO' || c.estado === 'CANCELADO_ADMIN' ? 'reciente-warn'
        : 'reciente-info';
      const hora = _horaRes(c.fechaRes);
      const hace = _haceCuanto(c.fechaRes);
      return `<div class="cj-vuelo-reciente ${estClass}">
        <span class="cj-vuelo-reciente-estado">${estTxt}</span>
        <strong>${_esc(c.cliente || 'VARIOS')}</strong>
        <span class="cj-vuelo-reciente-monto">S/ ${parseFloat(c.monto || 0).toFixed(2)}</span>
        <span class="cj-vuelo-reciente-cajero">👤 ${_esc(c.vendedorDest)}</span>
        ${hora ? `<span class="cj-vuelo-reciente-hora" title="${_esc(hace)}">🕐 ${hora}</span>` : ''}
      </div>`;
    };
    // [v2.41.90] Separar cobrados de últimas 4h del resto (no esconder en details)
    const ahora = Date.now();
    const _esCobroRecienteHoy = (c) => {
      try {
        const t = new Date(c.fechaRes).getTime();
        return c.estado === 'COBRADO' && (ahora - t) < 4 * 60 * 60 * 1000;
      } catch(_) { return false; }
    };
    const cobradosHoy = recientes.filter(_esCobroRecienteHoy);
    const otrosRecientes = recientes.filter(c => !_esCobroRecienteHoy(c));
    let html = '';
    if (enVuelo.length) {
      html += `<div class="cj-vuelo-section">
        <div class="cj-vuelo-section-titulo">
          ✈ Cobros en vuelo · <strong>${enVuelo.length}</strong>
          <button onclick="MOS._cjCargarEnVuelo()" class="cj-vuelo-refresh" title="Refrescar">↻</button>
        </div>
        <div class="cj-vuelo-list">
          ${enVuelo.map(cardVuelo).join('')}
        </div>
      </div>`;
    }
    // [v2.41.96] Cobrados hoy YA NO se muestran en este panel — el user pidió
    // que aparezcan en la mesa de póker (baraja de créditos) con sello visual
    // de "COBRADO" para que la auditoría sea natural sin un panel separado.
    // Exponemos un set de idVenta cobrados para que _cjPintarCartasMano los
    // marque con sello dorado.
    try {
      window._cjCobradosHoyIdsVenta = new Set(cobradosHoy.map(c => String(c.idVenta || '')));
      window._cjCobradosHoyData = {};
      cobradosHoy.forEach(c => {
        window._cjCobradosHoyData[String(c.idVenta || '')] = {
          cliente: c.cliente || 'VARIOS',
          cajero: c.vendedorDest,
          fechaRes: c.fechaRes,
          monto: c.monto,
          horaTxt: _horaRes(c.fechaRes)
        };
      });
      // Re-pintar la mesa si está abierta (para que aparezcan los nuevos cobrados)
      const mesa = document.getElementById('modalMesaCreditos');
      if (mesa && !mesa.classList.contains('hidden') && typeof cjRepartirMano === 'function') {
        setTimeout(() => { try { cjRepartirMano(); } catch(_) {} }, 100);
      }
    } catch(_) {}
    if (otrosRecientes.length) {
      html += `<div class="cj-vuelo-section">
        <details class="cj-vuelo-recientes-wrap">
          <summary class="cj-vuelo-section-titulo cj-vuelo-section-recientes">
            🕒 Otros recientes · ${otrosRecientes.length} <span class="cj-vuelo-section-hint">click para expandir</span>
          </summary>
          <div class="cj-vuelo-recientes-list">
            ${otrosRecientes.map(cardReciente).join('')}
          </div>
        </details>
      </div>`;
    }
    cont.innerHTML = html;
  }

  // [v2.42.00] Cancelar cobro asignado — modal custom moderno + auth admin.
  // Optimista: cierra modal inmediato, fire-and-forget al backend, rollback si falla.
  async function cjCancelarCobro(idCobro) {
    if (!idCobro) return;
    const cobro = (_cjCreditosState.enVuelo || []).find(c => String(c.idCobro) === String(idCobro));
    if (!cobro) { toast('Cobro no encontrado', 'error'); return; }
    // Cerrar modal del postit antes de abrir el custom
    try { _cjCerrarPostitModal(); } catch(_){}
    // Modal custom de razón (reemplaza prompt nativo)
    const res = await _cjModalCancelarCobro(cobro);
    if (!res) return;
    const auth = await pedirAuth({
      accion: 'CANCELAR_COBRO_ASIGNADO',
      refDocumento: idCobro,
      contexto: 'Cancelar cobro · vuelve a CRÉDITO'
    });
    if (!auth) return;
    // Optimista: quitar postit inmediato
    _cjCreditosState.enVuelo = (_cjCreditosState.enVuelo || []).filter(c => c.idCobro !== idCobro);
    try { _cjPintarPostitsManojos(); } catch(_){}
    try { _finBeep?.('remove') || _finBeep?.('tap'); } catch(_){}
    toast('⊘ Cobro cancelado · ticket vuelve a CRÉDITO', 'ok', 4000);
    try {
      await API.post('meCancelarCobroAsignado', {
        idCobro: idCobro,
        razon:   res.razon || '',
        adminAuth: { nombre: auth.nombre, rol: auth.rol, via: 'PIN_8DIG' }
      });
      // Refresh definitivo
      _cjCargarEnVuelo();
      _cjCargarCreditosPendientes();
    } catch(e) {
      toast('⚠ Error cancelando: ' + (e.message || e) + ' · refresca', 'error', 6000);
      _cjCargarEnVuelo();   // re-fetch para restaurar estado real
    }
  }

  // [v2.42.00] Reasignar cobro a otra caja — modal custom (sin prompt nativo)
  // + optimista + auth admin + rollback en error.
  async function cjReasignarCobro(idCobro) {
    if (!idCobro) return;
    const cobro = (_cjCreditosState.enVuelo || []).find(c => String(c.idCobro) === String(idCobro));
    if (!cobro) { toast('Cobro no encontrado', 'error'); return; }
    try { _cjCerrarPostitModal(); } catch(_){}
    // Modal custom selector de caja (reemplaza prompt nativo + lista numerada)
    const nuevaCaja = await _cjModalReasignar(cobro);
    if (!nuevaCaja) return;
    const auth = await pedirAuth({
      accion: 'REASIGNAR_COBRO_ASIGNADO',
      refDocumento: idCobro,
      contexto: `Reasignar a ${nuevaCaja.vendedor}`
    });
    if (!auth) return;
    // Optimista: actualizar el postit en memoria (cambia cajaDestino + vendedorDest)
    const cobroIdx = (_cjCreditosState.enVuelo || []).findIndex(c => c.idCobro === idCobro);
    const cobroSnap = cobroIdx >= 0 ? { ..._cjCreditosState.enVuelo[cobroIdx] } : null;
    if (cobroIdx >= 0) {
      _cjCreditosState.enVuelo[cobroIdx] = {
        ..._cjCreditosState.enVuelo[cobroIdx],
        cajaDestino:  nuevaCaja.idCaja,
        vendedorDest: nuevaCaja.vendedor,
        reasignaciones: (_cjCreditosState.enVuelo[cobroIdx].reasignaciones || 0) + 1
      };
      try { _cjPintarPostitsManojos({ optimisticId: idCobro }); } catch(_){}
    }
    try { _finBeep?.('success'); } catch(_){}
    toast('↺ Reasignado a ' + nuevaCaja.vendedor, 'ok', 4000);
    try {
      await API.post('meReasignarCobroAsignado', {
        idCobro:     idCobro,
        cajaDestino: nuevaCaja.idCaja,
        adminAuth:   { nombre: auth.nombre, rol: auth.rol, via: 'PIN_8DIG' }
      });
      _cjCargarEnVuelo();
    } catch(e) {
      // Rollback al snapshot
      if (cobroSnap && cobroIdx >= 0) {
        _cjCreditosState.enVuelo[cobroIdx] = cobroSnap;
        try { _cjPintarPostitsManojos(); } catch(_){}
      }
      toast('⚠ Error reasignando: ' + (e.message || e), 'error', 6000);
      _cjCargarEnVuelo();
    }
  }

  async function _cjCargarCreditosPendientes() {
    // [v41.9] Mostrar skeleton mientras se carga si NO hay datos previos.
    // Si ya hay grupos cargados (refresh silencioso cada 20s), no perturbar la UI.
    const mano = $('cjCreditosMano');
    const yaHayData = _cjCreditosState.todosLosGrupos.length > 0;
    if (mano && !yaHayData) {
      mano.classList.remove('hidden');
      _cjPintarSkeleton();
    }
    try {
      const r = await API.post('meGetCreditosPendientes', { diasAtras: 365 });   // [créditos] no perder créditos viejos (mayo etc.)
      const d = (r && r.data) ? r.data : (r || {});
      _cjCreditosState.todosLosGrupos = d.grupos || [];
      _cjRenderManoDelDia();
    } catch(e) {
      console.warn('[creditos] error cargando:', e?.message || e);
      // Si falló y no había data previa, ocultar la baraja (mejor que dejar skeleton infinito)
      if (mano && !yaHayData) mano.classList.add('hidden');
    }
  }

  // [v41.9] Skeleton mientras carga: 3 cartas placeholder en abanico con shimmer.
  // Reusa las posiciones data-pos del fan-out real, así la transición a las cartas
  // reales es continua (sin "salto" de layout).
  function _cjPintarSkeleton() {
    const cont = $('cjManoContenedor');
    if (!cont) return;
    cont.innerHTML = [0, 1, 2].map(pos => `
      <div class="cj-carta-mano cj-carta-skeleton" data-pos="${pos}">
        <div class="cj-skel-head">
          <span class="cj-skel-line cj-skel-w60"></span>
          <span class="cj-skel-line cj-skel-w35 cj-skel-tall"></span>
        </div>
        <span class="cj-skel-line cj-skel-w30 cj-skel-thin"></span>
        <div class="cj-skel-sep"></div>
        <span class="cj-skel-line cj-skel-w90"></span>
        <span class="cj-skel-line cj-skel-w75"></span>
        <span class="cj-skel-line cj-skel-w85"></span>
        <span class="cj-skel-line cj-skel-w70"></span>
        <div class="cj-skel-spinner"></div>
      </div>
    `).join('');
  }

  function _cjFmtFechaCorta(yyyyMmDd) {
    if (!yyyyMmDd) return '—';
    // [v41.8 FIX] Antes usaba toISOString() (UTC) → en Lima (UTC-5), ventas
    // de las 19:00 quedaban marcadas como del día siguiente UTC y se veían
    // como "Ayer". Ahora usa today() global que computa fecha LOCAL.
    const hoyLoc = today();
    const z = n => String(n).padStart(2,'0');
    const dAyer = new Date(); dAyer.setDate(dAyer.getDate() - 1);
    const ayerLoc = `${dAyer.getFullYear()}-${z(dAyer.getMonth()+1)}-${z(dAyer.getDate())}`;
    if (yyyyMmDd === hoyLoc) return 'Hoy';
    if (yyyyMmDd === ayerLoc) return 'Ayer';
    const parts = yyyyMmDd.split('-');
    const meses = ['ene','feb','mar','abr','may','jun','jul','ago','sep','oct','nov','dic'];
    return parts[2] + ' ' + meses[parseInt(parts[1],10)-1];
  }

  // Renderiza la mano de cartas para la fecha que está activa en el filtro de cajas
  function _cjRenderManoDelDia() {
    const fechaActiva = $('cjFecha')?.value || today();
    const grupo = _cjCreditosState.todosLosGrupos.find(g => g.fecha === fechaActiva);
    const mano = $('cjCreditosMano');
    if (!mano) return;

    if (!grupo || !grupo.tickets || !grupo.tickets.length) {
      mano.classList.add('hidden');
      _cjCreditosState.ticketsActivos = [];
      _cjCreditosState.fechaActiva = null;
      _cjStopShuffle();
      return;
    }
    mano.classList.remove('hidden');
    // [v41] Solo resetear shuffleIdx si cambió la fecha activa. Si solo es un
    // refresh (mismo día, nuevos tickets), preservar el progreso del shuffle.
    const fechaCambia = _cjCreditosState.fechaActiva !== fechaActiva;
    _cjCreditosState.fechaActiva = fechaActiva;
    _cjCreditosState.ticketsActivos = grupo.tickets;
    if (fechaCambia) _cjCreditosState.shuffleIdx = 0;
    // Si el idx quedó fuera de rango (porque desaparecieron cartas), normalizar
    if (_cjCreditosState.shuffleIdx >= grupo.tickets.length) {
      _cjCreditosState.shuffleIdx = 0;
    }

    _cjPintarCartasMano();

    // Arrancar shuffle automático cada 4s (solo si hay >= 2 cartas)
    _cjStopShuffle();
    if (grupo.tickets.length >= 2) {
      _cjCreditosState.shuffleTimer = setInterval(_cjShuffleStep, 4000);
    }
  }

  // Limpia el nombre de producto: quita la parte parentética redundante "(nombre repetido)"
  // que se ve en los datos (ej. "ALSABOR SALSA INGLESA (ALSABOR SALSA INGLESA)").
  function _cjLimpiarNombreItem(nombre) {
    const s = String(nombre || '').trim();
    return s.replace(/\s*\([^)]*\)\s*$/, '').trim();
  }

  // Genera el resumen voucher de items para mostrar en la cara de la carta.
  // Formato: "1× IDEAL LECHE CREMOSITA ........ S/ 4.20"
  // Trunca el nombre a 16 chars para que entre. Si hay más items, "+N más" al final.
  function _cjResumenItemsVoucher(items, max, nombreMaxChars) {
    if (!items || !items.length) {
      return `<div class="cj-carta-items"><div class="cj-carta-items-mas">sin productos</div></div>`;
    }
    const top = items.slice(0, max);
    const restantes = items.length - top.length;
    const filas = top.map(it => {
      const nombre = _esc(_cjLimpiarNombreItem(it.nombre).substring(0, nombreMaxChars || 16));
      const cant = parseFloat(it.cantidad) || 0;
      const sub = parseFloat(it.subtotal) || 0;
      // Formateo de cantidad: enteros sin decimales, granel con 1-2 decimales
      const cantStr = Number.isInteger(cant) ? String(cant) : cant.toFixed(2).replace(/\.?0+$/, '');
      return `<div class="cj-carta-items-item">
        <span class="cj-carta-items-cant">${cantStr}×</span>
        <span class="cj-carta-items-nom">${nombre}</span>
        <span class="cj-carta-items-sub">${sub.toFixed(2)}</span>
      </div>`;
    }).join('');
    const mas = restantes > 0
      ? `<div class="cj-carta-items-mas">+${restantes} más…</div>`
      : '';
    return `<div class="cj-carta-items">${filas}${mas}</div>`;
  }

  function _cjPintarCartasMano() {
    const cont = $('cjManoContenedor');
    if (!cont) return;
    const tickets = _cjCreditosState.ticketsActivos;
    const idxFront = _cjCreditosState.shuffleIdx;
    const N = tickets.length;
    const idsVistos = _cjCreditosState.idsVistos;
    const esPrimerRender = idsVistos.size === 0;
    const cartas = tickets.map((t, i) => {
      const pos = (i - idxFront + N) % N;
      const posAttr = pos >= 5 ? '5+' : String(pos);
      const asigBadge = t.asignado
        ? `<span class="cj-carta-asignado-badge">✈</span>`
        : '';
      const cliente = _esc((t.cliente || 'VARIOS').toUpperCase());
      const doc = t.clienteDoc && t.clienteDoc !== '66666'
        ? `<div class="cj-carta-doc">${_esc(t.clienteDoc)}</div>` : '';
      const esNuevo = !esPrimerRender && !idsVistos.has(t.idVenta);
      const claseNueva = esNuevo ? ' cj-carta-nueva' : '';
      return `<div class="cj-carta-mano${claseNueva}" data-pos="${posAttr}" data-idx="${i}">
        ${asigBadge}
        <div class="cj-carta-head">
          <span class="cj-carta-cliente">${cliente}</span>
          <span class="cj-carta-monto">S/${parseFloat(t.total).toFixed(2)}</span>
        </div>
        ${doc}
        <div class="cj-carta-sep"></div>
        ${_cjResumenItemsVoucher(t.items, 4, 15)}
        <div class="cj-carta-meta">${_esc(t.correlativo)}</div>
      </div>`;
    }).join('');
    cont.innerHTML = cartas;
    tickets.forEach(t => idsVistos.add(t.idVenta));
    if (!esPrimerRender && cont.querySelector('.cj-carta-nueva')) {
      try { _finBeep?.('alert'); } catch(_){}
      try { if (navigator.vibrate) navigator.vibrate([30, 60, 30]); } catch(_){}
    }
  }

  function _cjShuffleStep() {
    const tickets = _cjCreditosState.ticketsActivos;
    if (!tickets || tickets.length < 2) return;
    // Si el overlay de mesa o detalle está abierto, pausar shuffle
    const mesa = $('modalMesaCartas'); const det = $('modalDetalleCarta');
    if ((mesa && !mesa.classList.contains('hidden')) || (det && !det.classList.contains('hidden'))) return;
    _cjCreditosState.shuffleIdx = (_cjCreditosState.shuffleIdx + 1) % tickets.length;
    _cjPintarCartasMano();
  }

  function _cjStopShuffle() {
    if (_cjCreditosState.shuffleTimer) {
      clearInterval(_cjCreditosState.shuffleTimer);
      _cjCreditosState.shuffleTimer = null;
    }
  }

  // Click en la mano → repartir TODAS las cartas en la mesa, agrupadas por
  // fecha. La sección "Hoy" se destaca con badge brillante. Los días anteriores
  // van debajo en orden cronológico inverso, así el admin puede cobrar un
  // crédito viejo sin tener que cambiar el filtro de fecha del módulo.
  function cjRepartirMano() {
    const grupos = _cjCreditosState.todosLosGrupos || [];
    if (!grupos.length) return;
    try { _finBeep?.('click'); } catch(_){}

    const hoyStr = today();
    const totalTickets = grupos.reduce((s, g) => s + (g.tickets ? g.tickets.length : 0), 0);
    const totalMonto = grupos.reduce((s, g) => s + (parseFloat(g.total) || 0), 0);

    const lblF = $('cjMesaFechaLabel');
    if (lblF) lblF.textContent = `Todos · ${totalTickets} ticket${totalTickets === 1 ? '' : 's'}`;
    const lblS = $('cjMesaSubtitulo');
    if (lblS) lblS.textContent = `S/ ${totalMonto.toFixed(2)} pendientes en ${grupos.length} día${grupos.length === 1 ? '' : 's'} · tocá una carta para ver detalle`;

    // Días ordenados: hoy primero, luego los más recientes
    const ordenados = grupos.slice().sort((a, b) => {
      if (a.fecha === hoyStr) return -1;
      if (b.fecha === hoyStr) return 1;
      return b.fecha.localeCompare(a.fecha);
    });

    const grid = $('cjMesaGrid');
    if (!grid) return;

    let cartaGlobalIdx = 0; // animation-delay continuo entre secciones

    // [v2.42.09] Cobrados hoy YA NO van en sección separada. En su lugar la
    // carta original (que SIGUE en el grupo "Hoy ACTIVOS") cambia de fondo
    // a verde + sello COBRADO encima. User pidió "mismo ticket, mismo lugar,
    // otro color de fondo y sello cobrado".
    const cobradosIds = window._cjCobradosHoyIdsVenta || new Set();
    const cobradosData = window._cjCobradosHoyData || {};

    grid.innerHTML = ordenados.map(g => {
      const esHoy = g.fecha === hoyStr;
      const fechaLbl = _cjFmtFechaCorta(g.fecha);
      const diasAtras = _cjDiasDesde(g.fecha);
      const subFecha = esHoy
        ? '🔥 ACTIVOS'
        : (diasAtras === 1 ? 'ayer' : `hace ${diasAtras} días`);
      const tickets = g.tickets || [];
      const totalDia = parseFloat(g.total || 0);

      const cartas = tickets.map(t => {
        const asig = t.asignado;
        const asigClass = asig ? 'is-asignada' : '';
        const asigBadge = asig
          ? `<span class="cj-carta-asignado-badge" style="position:relative; top:0; right:0; margin-bottom:8px; display:inline-block;">✈ ${_esc(asig.vendedorDest)}</span>`
          : '';
        const cliente = _esc((t.cliente || 'VARIOS').toUpperCase());
        const delay = (cartaGlobalIdx++) * 60;
        // [v2.42.09] Si el ticket fue cobrado hoy via cobro asignado, aplicar
        // clase cobrada (fondo verde + sello) en su lugar original sin
        // separarlo del grupo. _cjCobradosHoyIdsVenta es Set poblado por
        // _cjCargarEnVuelo a partir de los recientes COBRADO de últimas 4h.
        const esCobrado = cobradosIds.has(String(t.idVenta));
        const cobrInfo = esCobrado ? cobradosData[String(t.idVenta)] : null;
        const cobradoClass = esCobrado ? 'cj-mesa-carta-cobrada' : '';
        const selloCobrado = esCobrado
          ? `<div class="cj-carta-sello-cobrado">✓ COBRADO</div>`
          : '';
        const metaCobrado = esCobrado && cobrInfo
          ? ` · 👤 ${_esc(cobrInfo.cajero || '—')} · 🕐 ${_esc(cobrInfo.horaTxt || '')}`
          : '';
        return `<div class="cj-mesa-carta ${asigClass} ${cobradoClass}"
                     style="animation-delay: ${delay}ms"
                     onclick="MOS.cjAbrirDetalleCarta('${_esc(t.idVenta)}')">
          ${selloCobrado}
          ${asigBadge}
          <div class="cj-carta-head">
            <span class="cj-carta-cliente">${cliente}</span>
            <span class="cj-carta-monto">S/${parseFloat(t.total).toFixed(2)}</span>
          </div>
          ${t.clienteDoc && t.clienteDoc !== '66666' ? `<div class="cj-carta-doc">${_esc(t.clienteDoc)}</div>` : ''}
          <div class="cj-carta-sep"></div>
          ${_cjResumenItemsVoucher(t.items, 6, 22)}
          <div class="cj-carta-meta">${_esc(t.correlativo)} · ${_esc(t.vendedor)}${metaCobrado}</div>
        </div>`;
      }).join('');

      return `<section class="cj-mesa-grupo ${esHoy ? 'cj-mesa-grupo-hoy' : ''}">
        <header class="cj-mesa-grupo-head">
          <div class="cj-mesa-grupo-titulo">
            <span class="cj-mesa-grupo-emoji">${esHoy ? '🌟' : '📅'}</span>
            <span class="cj-mesa-grupo-fecha">${_esc(fechaLbl)}</span>
            <span class="cj-mesa-grupo-sub">${subFecha}</span>
          </div>
          <div class="cj-mesa-grupo-stats">
            <span class="cj-mesa-grupo-cuenta">${tickets.length} ticket${tickets.length === 1 ? '' : 's'}</span>
            <span class="cj-mesa-grupo-monto">S/ ${totalDia.toFixed(2)}</span>
          </div>
        </header>
        <div class="cj-mesa-grupo-cartas">${cartas}</div>
      </section>`;
    }).join('');

    const modal = $('modalMesaCartas');
    if (modal) modal.classList.remove('hidden');
  }

  // Días enteros entre la fecha dada (yyyy-MM-dd) y hoy. >0 si es pasada.
  function _cjDiasDesde(yyyyMmDd) {
    if (!yyyyMmDd) return 0;
    try {
      const [y, m, d] = yyyyMmDd.split('-').map(Number);
      const ayer = new Date(y, m - 1, d);
      const hoy = new Date();
      const ms = (new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate())) - ayer;
      return Math.round(ms / (1000 * 60 * 60 * 24));
    } catch(_) { return 0; }
  }

  function cjCerrarMesa(ev) {
    if (ev && ev.target && ev.target.id !== 'modalMesaCartas') return;
    const modal = $('modalMesaCartas');
    if (modal) modal.classList.add('hidden');
  }

  // Abre el detalle de una carta específica — busca por idVenta en todos los grupos
  // (la mesa ahora muestra cartas de varias fechas, no solo del día activo).
  function cjAbrirDetalleCarta(idVentaOrIdx) {
    let t = null;
    // Compatibilidad: si recibe número, asume idx del ticketsActivos viejo
    if (typeof idVentaOrIdx === 'number') {
      t = _cjCreditosState.ticketsActivos[idVentaOrIdx];
    } else {
      const idV = String(idVentaOrIdx);
      for (const g of (_cjCreditosState.todosLosGrupos || [])) {
        const found = (g.tickets || []).find(x => String(x.idVenta) === idV);
        if (found) { t = found; break; }
      }
      // Fallback al array de la fecha activa
      if (!t) t = (_cjCreditosState.ticketsActivos || []).find(x => String(x.idVenta) === idV);
    }
    if (!t) return;
    _cjCreditosState.detalleTicket = t;
    try { _finBeep?.('click'); } catch(_){}

    const cont = $('cjDetalleContenido');
    if (cont) {
      // [v41] Listado completo de items del ticket
      const itemsHtml = (t.items && t.items.length)
        ? `<div class="cj-det-items">
             <div class="cj-det-items-titulo">🛒 Productos (${t.items.length})</div>
             ${t.items.map(it => {
                const nombre = _esc((it.nombre || '').substring(0, 38));
                const cant = parseFloat(it.cantidad) || 0;
                const sub = parseFloat(it.subtotal) || 0;
                return `<div class="cj-det-item-row">
                  <span class="cj-det-item-cant">${cant}×</span>
                  <span class="cj-det-item-nombre">${nombre}</span>
                  <span class="cj-det-item-sub">S/ ${sub.toFixed(2)}</span>
                </div>`;
             }).join('')}
           </div>`
        : '';
      cont.innerHTML = `
        <span class="cj-detalle-corner">🃏</span>
        <span class="cj-detalle-corner-br">🃏</span>
        <div class="cj-det-cliente">${_esc((t.cliente || 'VARIOS').toUpperCase())}</div>
        ${t.clienteDoc ? `<div class="cj-det-doc">${_esc(t.clienteDoc)}</div>` : ''}
        <div class="cj-det-monto">S/ ${parseFloat(t.total).toFixed(2)}</div>
        <div class="cj-det-row">
          <span class="cj-det-row-label">📄 Ticket</span>
          <span class="cj-det-row-val">${_esc(t.correlativo)}</span>
        </div>
        <div class="cj-det-row">
          <span class="cj-det-row-label">🕐 Emitido</span>
          <span class="cj-det-row-val">${_esc(t.fechaISO)}</span>
        </div>
        <div class="cj-det-row">
          <span class="cj-det-row-label">👤 Cajero original</span>
          <span class="cj-det-row-val">${_esc(t.vendedor)}</span>
        </div>
        <div class="cj-det-row">
          <span class="cj-det-row-label">💼 Caja origen</span>
          <span class="cj-det-row-val">${_esc(t.idCaja || '—')}</span>
        </div>
        ${itemsHtml}
        ${t.obs ? `<div class="cj-det-obs">📝 ${_esc(t.obs)}</div>` : ''}
        ${t.asignado ? `<div class="cj-det-asignado-banner">
          ✈ Ya asignado a <strong>${_esc(t.asignado.vendedorDest)}</strong>
          (${_esc(t.asignado.cajaDestino)}) — esperando confirmación
        </div>` : ''}
      `;
    }
    // El botón FAB se oculta si ya está asignado
    const fab = $('cjDetalleFloating');
    if (fab) fab.style.display = t.asignado ? 'none' : '';
    const modal = $('modalDetalleCarta');
    if (modal) modal.classList.remove('hidden');
  }

  function cjCerrarDetalleCarta(ev) {
    if (ev && ev.target && ev.target.id !== 'modalDetalleCarta') return;
    const modal = $('modalDetalleCarta');
    if (modal) modal.classList.add('hidden');
    _cjCreditosState.detalleTicket = null;
  }

  // [v2.41.56] Panel INLINE de asignar caja — se despliega DENTRO del modal
  // detalle (no modal apilado que quedaba atrás). Animación slide-down con
  // sonidos, cards de cajas con glow, optimismo al confirmar.
  function cjAbrirAsignarDesdeDetalle() {
    const t = _cjCreditosState.detalleTicket;
    if (!t) return;
    cjAbrirAsignar(t.idVenta);
  }

  async function cjAbrirAsignar(idVenta) {
    // Buscar el ticket en el state — busca en TODOS los grupos (no solo activo)
    let ticket = null;
    for (const g of (_cjCreditosState.todosLosGrupos || [])) {
      ticket = (g.tickets || []).find(t => String(t.idVenta) === String(idVenta));
      if (ticket) break;
    }
    if (!ticket) { toast('Ticket no encontrado', 'error'); return; }
    if (ticket.asignado) { toast('Este ticket ya está asignado', 'warn'); return; }

    _cjCreditosState.asignarCtx = ticket;
    _cjCreditosState.asignarCaja = null;
    _cjCreditosState.asignarMetodo = ''; // [v2.41.90] ya no se usa

    // Sonido apertura panel
    try { _finBeep?.('expand') || _finBeep?.('click'); } catch(_){}

    // Ocultar el FAB mientras el panel está abierto
    const fab = $('cjDetalleFloating');
    if (fab) fab.style.display = 'none';

    // Insertar panel inline dentro del modal detalle si no existe
    let panel = $('cjAsignarInlinePanel');
    if (!panel) {
      const card = document.querySelector('#modalDetalleCarta .cj-detalle-card');
      if (!card) return;
      panel = document.createElement('div');
      panel.id = 'cjAsignarInlinePanel';
      panel.className = 'cj-asignar-inline';
      card.appendChild(panel);
    }
    panel.innerHTML = `
      <div class="cj-asignar-inline-head">
        <span style="font-size:22px">✈</span>
        <div>
          <div class="cj-asignar-inline-titulo">Enviar cobro a caja</div>
          <div class="cj-asignar-inline-sub">${_esc(ticket.cliente || 'VARIOS')} · S/ ${parseFloat(ticket.total).toFixed(2)}</div>
        </div>
        <button onclick="MOS.cjCerrarAsignar()" class="cj-asignar-inline-close" title="Cerrar">✕</button>
      </div>
      <div class="cj-asignar-inline-section">
        <label class="cj-asignar-inline-label">
          <span class="cj-asignar-inline-step">1</span>
          <span>¿A qué caja enviar?</span>
        </label>
        <div id="cjAsignarCajas" class="cj-asignar-inline-cajas">
          <div class="cj-asignar-inline-loading">
            <div class="cj-asignar-inline-spin"></div>
            <span>Buscando cajas abiertas…</span>
          </div>
        </div>
      </div>
      <!-- [v2.41.90] Paso 2: tiempo límite (antes había selector de método
           pero el cajero igual lo elige al cobrar — quitamos para evitar
           confusión cuando el admin marca VIRTUAL y el cajero deja EFECTIVO) -->
      <div class="cj-asignar-inline-section">
        <label class="cj-asignar-inline-label">
          <span class="cj-asignar-inline-step">2</span>
          <span>Tiempo límite para cobrar</span>
        </label>
        <div class="cj-asignar-inline-ttls">
          <button data-ttl="1" onclick="MOS.cjSetTTLAsignar(1)" class="cj-asignar-ttl-btn is-active">
            <span class="cj-asignar-ttl-num">1h</span>
            <span class="cj-asignar-ttl-lbl">por defecto</span>
          </button>
          <button data-ttl="2" onclick="MOS.cjSetTTLAsignar(2)" class="cj-asignar-ttl-btn">
            <span class="cj-asignar-ttl-num">2h</span>
            <span class="cj-asignar-ttl-lbl">relajado</span>
          </button>
          <button data-ttl="4" onclick="MOS.cjSetTTLAsignar(4)" class="cj-asignar-ttl-btn">
            <span class="cj-asignar-ttl-num">4h</span>
            <span class="cj-asignar-ttl-lbl">media jornada</span>
          </button>
          <button data-ttl="6" onclick="MOS.cjSetTTLAsignar(6)" class="cj-asignar-ttl-btn">
            <span class="cj-asignar-ttl-num">6h</span>
            <span class="cj-asignar-ttl-lbl">todo el turno</span>
          </button>
        </div>
      </div>
      <!-- [v2.41.87] Mensaje opcional al cajero (140 chars) -->
      <div class="cj-asignar-inline-section">
        <label class="cj-asignar-inline-label">
          <span class="cj-asignar-inline-step">3</span>
          <span>Mensaje al cajero (opcional)</span>
        </label>
        <input id="cjAsignarMensaje" type="text" maxlength="140" placeholder="ej: cliente paga exacto, recoge antes de las 4pm..."
               oninput="MOS._cjOnMensajeAsignar(this.value)"
               class="cj-asignar-inline-msg" />
      </div>
      <p class="cj-asignar-inline-hint">💡 El cajero recibirá <strong>push + impresión física del ticket</strong> y elige al cobrar si es efectivo · virtual · mixto. El monto entra como <strong>INGRESO ADICIONAL</strong> a su caja. <strong>Si no se cobra en el tiempo elegido, el ticket vuelve automáticamente a estado CRÉDITO.</strong></p>
      <div class="cj-asignar-inline-footer">
        <button onclick="MOS.cjCerrarAsignar()" class="cj-btn cj-btn-secondary">Cancelar</button>
        <button id="cjAsignarOkBtn" onclick="MOS.cjConfirmarAsignar()" class="cj-btn cj-btn-primary" disabled>
          ✈ Enviar a cajero
        </button>
      </div>`;

    // Trigger animación entrar (force reflow)
    panel.classList.remove('is-open');
    void panel.offsetWidth;
    panel.classList.add('is-open');

    // [v2.42.00] Render desde cache si está caliente (instant). Si no hay cache,
    // mostrar skeleton + fetch en background. Refrescar siempre en background
    // para detectar cajeros que abrieron caja mientras tanto.
    const cajasDiv = $('cjAsignarCajas');
    const _pintarCajas = (lista) => {
      if (!cajasDiv) return;
      if (!lista.length) {
        cajasDiv.innerHTML = '<div class="cj-asignar-inline-empty">⚠ No hay cajas abiertas.<br><span class="text-xs opacity-70">Pedile a un cajero que abra caja primero.</span></div>';
      } else {
        cajasDiv.innerHTML = lista.map((c, i) => `
          <button class="cj-asignar-caja-btn"
                  style="animation-delay:${i*60}ms"
                  onclick="MOS.cjSetCajaAsignar('${_esc(c.idCaja)}')"
                  data-caja="${_esc(c.idCaja)}">
            <div class="cj-asignar-caja-avatar">👤</div>
            <div class="cj-asignar-caja-info">
              <div class="cj-asignar-caja-vendedor">${_esc(c.vendedor)}</div>
              <div class="cj-asignar-caja-meta">${_esc(c.estacion)}${c.zona ? ' · ' + _esc(c.zona) : ''}</div>
            </div>
            <div class="cj-asignar-caja-check">✓</div>
          </button>
        `).join('');
      }
    };
    if (cajasDiv) {
      const cache = _cjCreditosState.cajasAbiertasCache || [];
      const fresca = (Date.now() - (_cjCreditosState.cajasAbiertasCacheTs || 0)) < 30000;
      if (cache.length && fresca) {
        _pintarCajas(cache);                            // instantáneo
        _cjPrecargarCajasAbiertas(true).then(_pintarCajas).catch(()=>{}); // refresco background
      } else {
        _cjPrecargarCajasAbiertas(true).then(_pintarCajas).catch(e => {
          if (cajasDiv) cajasDiv.innerHTML = '<div class="cj-asignar-inline-empty" style="color:#fca5a5">⚠ Error: ' + _esc(e.message || e) + '</div>';
        });
      }
    }
    // [v2.41.90] Removido cjSetMetodoAsignar — el método lo elige el cajero
    cjSetTTLAsignar(1); // [v2.41.86] Default 1h
    _cjCreditosState.asignarMensaje = ''; // [v2.41.87] limpiar mensaje
    const inpMsg = document.getElementById('cjAsignarMensaje');
    if (inpMsg) inpMsg.value = '';
    _cjUpdAsignarOkBtn();

    // [v2.41.88] Scroll dentro de la carta (ahora tiene overflow-y) hasta el
    // footer del panel — así el botón "Enviar a cajero" queda visible aunque
    // el ticket tenga muchísimos productos.
    setTimeout(() => {
      try {
        const card = document.querySelector('#modalDetalleCarta .cj-detalle-card');
        if (card) {
          card.scrollTo({ top: card.scrollHeight, behavior: 'smooth' });
        } else {
          panel.scrollIntoView({ behavior: 'smooth', block: 'end' });
        }
      } catch(_){}
    }, 150);
  }

  function cjCerrarAsignar(ev) {
    // Soporta clicks fuera (legacy del modal viejo) y close button
    if (ev && ev.target && ev.target.id === 'modalAsignarCobro') {
      const oldModal = $('modalAsignarCobro');
      if (oldModal) oldModal.classList.add('hidden');
    }
    const panel = $('cjAsignarInlinePanel');
    if (panel) {
      panel.classList.remove('is-open');
      panel.classList.add('is-closing');
      setTimeout(() => { try { panel.remove(); } catch(_){} }, 320);
    }
    const fab = $('cjDetalleFloating');
    const t = _cjCreditosState.detalleTicket;
    if (fab && t && !t.asignado) fab.style.display = '';
    _cjCreditosState.asignarCtx = null;
    try { _finBeep?.('collapse') || _finBeep?.('tap'); } catch(_){}
  }

  function cjSetMetodoAsignar(metodo) {
    _cjCreditosState.asignarMetodo = metodo;
    document.querySelectorAll('.cj-asignar-metodo-btn').forEach(b => {
      b.classList.toggle('is-active', b.dataset.metodo === metodo);
    });
    _cjUpdAsignarOkBtn();
  }

  function cjSetCajaAsignar(idCaja) {
    _cjCreditosState.asignarCaja = idCaja;
    document.querySelectorAll('.cj-asignar-caja-btn').forEach(b => {
      b.classList.toggle('is-active', b.dataset.caja === idCaja);
    });
    _cjUpdAsignarOkBtn();
    try { _finBeep?.('tap'); } catch(_){}
  }

  function _cjUpdAsignarOkBtn() {
    const btn = $('cjAsignarOkBtn');
    if (!btn) return;
    // [v2.41.90] Solo requiere caja destino — el método ya no se elige aquí
    btn.disabled = !_cjCreditosState.asignarCaja;
  }

  // [v2.41.86] Setea el TTL del cobro (1h default · 2h · 4h · 6h)
  function cjSetTTLAsignar(horas) {
    _cjCreditosState.asignarTTL = parseInt(horas, 10) || 1;
    document.querySelectorAll('.cj-asignar-ttl-btn').forEach(b => {
      b.classList.toggle('is-active', parseInt(b.dataset.ttl, 10) === _cjCreditosState.asignarTTL);
    });
    try { _finBeep?.('tap'); } catch(_){}
  }

  // [v2.41.87] Captura mensaje opcional al cajero
  function _cjOnMensajeAsignar(v) {
    _cjCreditosState.asignarMensaje = String(v || '').substring(0, 140);
  }

  // [v2.42.00] Asignación OPTIMISTA — cerrar modal + volar carta + pegar
  // postit fantasma en el cuadro del cajero INSTANTE. Llamada en background.
  // Si el backend rechaza: rollback (devolver carta a la mesa) + toast rojo.
  async function cjConfirmarAsignar() {
    const ctx = _cjCreditosState.asignarCtx;
    const cajaDest = _cjCreditosState.asignarCaja;
    if (!ctx || !cajaDest) return;
    const horasTTL = parseInt(_cjCreditosState.asignarTTL, 10) || 1;
    const mensajeAdmin = (_cjCreditosState.asignarMensaje || '').trim();
    // Snapshot para rollback
    const cajaInfo = (_cjCreditosState.cajasAbiertasCache || []).find(c => String(c.idCaja) === String(cajaDest)) || {};
    const cajeroNom = cajaInfo.vendedor || 'cajero';
    // 1. Cerrar panel + modal detalle inmediato
    try { _finBeep?.('success'); } catch(_){}
    toast('✈ Enviado a ' + cajeroNom + ` · vence en ${horasTTL}h`, 'success', 3500);
    cjCerrarAsignar();
    setTimeout(() => {
      const det = $('modalDetalleCarta');
      if (det) det.classList.add('hidden');
      _cjCreditosState.detalleTicket = null;
    }, 200);
    // 2. Volar carta de la mesa + agregar postit OPTIMISTA al manojo del cajero
    const cartaEl = document.querySelector('.cj-mesa-carta[onclick*="' + ctx.idVenta + '"]');
    const optimisticId = 'CB-OPT-' + Date.now();
    const optimisticCobro = {
      idCobro: optimisticId,
      idVenta: ctx.idVenta,
      cajaDestino: cajaDest,
      vendedorDest: cajeroNom,
      cliente: ctx.cliente || 'VARIOS',
      monto: ctx.total,
      correlativo: ctx.correlativo || '',
      metodoSug: '',
      horasTTL: horasTTL,
      mensajeAdmin: mensajeAdmin,
      reasignaciones: 0,
      fechaVencimiento: new Date(Date.now() + horasTTL * 3600000).toISOString(),
      _optimistic: true
    };
    _cjCreditosState.enVuelo = [optimisticCobro, ...(_cjCreditosState.enVuelo || [])];
    try { _cjPintarPostitsManojos({ optimisticId, cartaOrigen: cartaEl }); } catch(_){}
    if (cartaEl) {
      cartaEl.classList.add('cj-credito-fly');
      setTimeout(() => { try { cartaEl.remove(); } catch(_){} }, 800);
    }
    // 3. Fire-and-forget al backend
    try {
      const r = await API.post('meAsignarCobroCajero', {
        idVenta:        ctx.idVenta,
        cajaDestino:    cajaDest,
        metodoSugerido: '',
        horasTTL:       horasTTL,
        mensajeAdmin:   mensajeAdmin,
        localId:        optimisticId   // idempotencia anti-retry (path directo Supabase)
      });
      const d = (r && r.data) ? r.data : (r || {});
      // [cutover cobro-ME] en el path directo el push lo dispara el front (fan-out a los
      // equipos del cajero, principal+companion). En GAS el push ya lo hace el backend.
      if (d && d.via === 'directo' && d.cajeroDestino && !d.idempotente) {
        try { API.enviarPushSB(d.pushTitulo, d.pushCuerpo, { soloUsuarios: [d.cajeroDestino], incluirCompanions: true }); } catch(_) {}
      }
      // Reemplazar el postit optimista por el real (matchear por idVenta)
      _cjCreditosState.enVuelo = (_cjCreditosState.enVuelo || []).filter(c => c.idCobro !== optimisticId);
      // Refrescar para traer el cobro real con su idCobro definitivo
      setTimeout(() => {
        _cjCargarCreditosPendientes();
        _cjCargarEnVuelo();
      }, 400);
    } catch(e) {
      // ROLLBACK: quitar postit optimista + restaurar carta en mesa + toast rojo
      _cjCreditosState.enVuelo = (_cjCreditosState.enVuelo || []).filter(c => c.idCobro !== optimisticId);
      try { _cjPintarPostitsManojos(); } catch(_){}
      try { _finBeep?.('error') || _finBeep?.('tap'); } catch(_){}
      toast('⚠ No se pudo asignar: ' + (e.message || e) + ' · refresca y reintenta', 'error', 6500);
      setTimeout(() => _cjCargarCreditosPendientes(), 300);
    }
  }

  // Helper de escape (existe en MOS? si no, fallback)
  function _esc(s) { return String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }

  // ── MODAL TICKETS (compartido cajas + finanzas-style) ─
  function cjVerTodosTickets(filtroInicial) {
    _finBeep('click');
    _cjState.tkCajaFiltro = '';
    _cjState.tkFiltro = (filtroInicial === 'ventas') ? 'ventas' : 'todos';
    _cjState.tkBuscar = '';
    const inp = $('cjTkBuscar'); if (inp) inp.value = '';
    // [rename] el título refleja la fecha real (no siempre "del día")
    const f = _cjFecha();
    const dLabel = (f === today()) ? 'de hoy'
      : ('del ' + new Date(f + 'T00:00:00').toLocaleDateString('es-PE', { day: '2-digit', month: 'long' }));
    _setText('cjModalTicketsTitulo', 'Tickets ' + dLabel);
    _setText('cjModalTicketsSubtitulo', f + ' · buscá por rango de fechas, tipo o vendedor');
    // [rango] arranca en el día activo (desde=hasta=f); el usuario puede abrir un rango
    _cjTkResetRango(f);
    openModal('cjModalTickets');
    _cjTkRenderFiltrosBtns();
    _cjTkRenderVendedoresBtns();
    _cjTkRender();
    _cjAsegurarDia(f).then(c => { if (c) { _cjTkRenderVendedoresBtns(); _cjTkRender(); } });   // por si el día no estaba cargado
  }
  // [rango] resetea el buscador al día 'f' (desde=hasta=f, sin rango activo)
  function _cjTkResetRango(f) {
    _cjState.tkDesde = f; _cjState.tkHasta = f; _cjState.tkRangoActivo = false; _cjState.tkDoc = '';
    const dd = $('cjTkDesde'), dh = $('cjTkHasta'), inf = $('cjTkRangoInfo');
    if (dd) dd.value = f; if (dh) dh.value = f; if (inf) inf.textContent = '';
  }
  function _cjTkHoyRango() { _finBeep('click'); _cjTkResetRango(_cjFecha()); _cjTkRenderFiltrosBtns(); _cjTkRenderVendedoresBtns(); _cjTkRender(); }
  // [rango] aplica el rango de fechas: si desde≠hasta (o fuera del día activo) jala tickets_rango
  async function _cjTkAplicarRango() {
    const dd = $('cjTkDesde'), dh = $('cjTkHasta'), inf = $('cjTkRangoInfo');
    let desde = (dd && dd.value) || _cjFecha();
    let hasta = (dh && dh.value) || _cjFecha();
    if (hasta < desde) { const t = desde; desde = hasta; hasta = t; if (dd) dd.value = desde; if (dh) dh.value = hasta; }
    _cjState.tkDesde = desde; _cjState.tkHasta = hasta;
    if (desde === hasta) {
      // un solo día → usa el cache (lo aseguramos) sin traer rango
      _cjState.tkRangoActivo = false;
      if (inf) inf.textContent = '';
      _cjState.fecha = desde; _cjActualizarFechaUI();
      const c = await _cjAsegurarDia(desde);
      _cjTkRenderVendedoresBtns(); _cjTkRender();
      if (c) { _cjTkRenderVendedoresBtns(); _cjTkRender(); }
      return;
    }
    // rango real → tickets_rango
    if (inf) inf.textContent = '⏳ buscando…';
    _finBeep('nav');
    const r = await API.get('getTicketsRango', { desde, hasta });
    const tks = (r && r.todosTickets) || (r && r.data && r.data.todosTickets) || [];
    S._cjTkRangoData = tks;
    _cjState.tkRangoActivo = true;
    if (inf) inf.textContent = `${tks.length} en el rango`;
    _cjTkRenderFiltrosBtns(); _cjTkRenderVendedoresBtns(); _cjTkRender();
  }
  function cjVerTicketsCaja(idCaja) {
    _finBeep('click');
    const c = (S._todasCajas || []).find(x => String(x.idCaja) === String(idCaja));
    _cjState.tkCajaFiltro = String(idCaja);
    _cjState.tkFiltro = 'todos';
    _cjState.tkBuscar = '';
    const inp = $('cjTkBuscar'); if (inp) inp.value = '';
    _setText('cjModalTicketsTitulo', 'Tickets de Caja · ' + (c?.vendedor || '—'));
    _setText('cjModalTicketsSubtitulo', (c?.zona || c?.estacion || '') + ' · ' + (c?.idCaja || ''));
    _cjState.tkVendedor = '';   // [v2.43.387] reset del filtro de vendedor al abrir otra caja
    _cjTkResetRango(_cjFecha());
    openModal('cjModalTickets');
    _cjTkRenderFiltrosBtns();
    _cjTkRenderVendedoresBtns();
    _cjTkRender();
  }

  function _cjTkRenderFiltrosBtns() {
    const wrap = $('cjTkFiltros');
    if (!wrap) return;
    const filtros = [
      { key: 'todos',      label: 'Todos' },
      { key: 'ventas',     label: '💰 Cobrado' },
      { key: 'efectivo',   label: '💵 Efectivo' },
      { key: 'virtual',    label: '📱 Virtual' },
      { key: 'mixto',      label: '🔀 Mixto' },
      { key: 'por_cobrar', label: '⏳ Por cobrar' },
      { key: 'credito',    label: '📋 Crédito' },
      { key: 'anulado',    label: '❌ Anulado' },
    ];
    let html = filtros.map(f => {
      const active = f.key === _cjState.tkFiltro;
      const cls = active ? 'log-icon-btn active' : 'log-icon-btn';
      return `<button onclick="MOS._cjTkSetFiltro('${f.key}')" class="${cls}" style="padding:5px 10px;font-size:11px;width:auto;height:auto">${f.label}</button>`;
    }).join('');
    // [tipo doc] chips NV / Boleta / Factura (eje independiente del método → se combinan)
    const docs = [{ k: 'NV', l: '📄 NV' }, { k: 'B', l: '🧾 Boleta' }, { k: 'F', l: '📑 Factura' }];
    html += '<span style="width:1px;height:18px;background:#1e293b;margin:0 4px;display:inline-block"></span>';
    html += docs.map(d => {
      const active = _cjState.tkDoc === d.k;
      return `<button onclick="MOS._cjTkSetDoc('${d.k}')" class="log-icon-btn ${active ? 'active' : ''}" style="padding:5px 10px;font-size:11px;width:auto;height:auto">${d.l}</button>`;
    }).join('');
    wrap.innerHTML = html;
  }
  function _cjTkSetFiltro(key) {
    _cjState.tkFiltro = key;
    _finBeep('click');
    _cjTkRenderFiltrosBtns();
    _cjTkRender();
  }

  // [v2.43.387] Chips por VENDEDOR — saber quién emitió cada ticket dentro de la caja
  // (una caja puede tener varios: p.ej. Sergio + Fernando). Se combina con el filtro de
  // método y la búsqueda; la suma viva (cjTkConteo) refleja la intersección. Si la caja
  // tiene un solo vendedor, la fila se oculta (no aporta).
  function _cjTkVendNombre(t) { return (String(t.vendedor || '').trim() || '—'); }
  function _cjTkRenderVendedoresBtns() {
    const wrap = $('cjTkVendedores');
    if (!wrap) return;
    let base = _cjTkFuente();   // [rango] respeta rango/día activo + caja + tipo doc
    const esAnul = t => String(t.metodo || t.formaPago || '').toUpperCase() === 'ANULADO' || t.estado === 'ANULADO';
    const map = new Map();
    base.forEach(t => {
      const v = _cjTkVendNombre(t);
      if (!map.has(v)) map.set(v, { n: 0, tot: 0 });
      const e = map.get(v); e.n++; if (!esAnul(t)) e.tot += parseFloat(t.total) || 0;
    });
    if (map.size <= 1) { wrap.classList.add('hidden'); _cjState.tkVendedor = ''; wrap.innerHTML = ''; return; }
    wrap.classList.remove('hidden');
    const vends = Array.from(map.entries()).sort((a, b) => b[1].tot - a[1].tot);
    const ini = n => (n && n !== '—' ? n.trim()[0].toUpperCase() : '?');
    const col = n => { let h = 0; for (let i = 0; i < n.length; i++) h = (h * 31 + n.charCodeAt(i)) & 0xffff; return `hsl(${h % 360},55%,45%)`; };
    const chip = (key, label, color, sub, active, icon) =>
      `<button onclick="MOS._cjTkSetVendedor(this.dataset.v)" data-v="${_escapeHtml(String(key))}" class="log-icon-btn ${active ? 'active' : ''}" style="padding:4px 9px 4px 4px;font-size:11px;width:auto;height:auto;display:inline-flex;align-items:center;gap:6px">
         <span style="width:20px;height:20px;border-radius:50%;background:${color};color:#fff;display:inline-flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;flex-shrink:0">${icon}</span>
         <span>${_escapeHtml(label)}${sub ? ` <span style="opacity:.55">${sub}</span>` : ''}</span>
       </button>`;
    let html = chip('', 'Todos', '#475569', '', !_cjState.tkVendedor, '👥');
    html += vends.map(([v, e]) => chip(v, v, col(v), `S/${e.tot.toFixed(0)}`, _cjState.tkVendedor === v, ini(v))).join('');
    wrap.innerHTML = html;
  }
  function _cjTkSetVendedor(v) {
    _cjState.tkVendedor = (_cjState.tkVendedor === v) ? '' : v;   // toggle → re-click deselecciona
    _finBeep('click');
    _cjTkRenderVendedoresBtns();
    _cjTkRender();
  }

  // [rango] fuente base del buscador: rango de fechas (S._cjTkRangoData) o el día activo,
  // ya filtrada por caja (o __SINCAJA__) y por tipo de documento (NV/B/F). SIN vendedor/método/búsqueda.
  function _cjTkFuente() {
    let base;
    if (_cjState.tkRangoActivo && Array.isArray(S._cjTkRangoData)) {
      base = S._cjTkRangoData.slice();
    } else {
      const fecha = _cjFecha();
      base = (S._todosTickets || []).filter(t => (t.fecha || '').substring(0, 10) === fecha);
    }
    if (_cjState.tkCajaFiltro === '__SINCAJA__') base = base.filter(t => !String(t.idCaja || '').trim());
    else if (_cjState.tkCajaFiltro) base = base.filter(t => String(t.idCaja || '') === _cjState.tkCajaFiltro);
    if (_cjState.tkDoc) base = base.filter(t => String(t.tipo || '').toUpperCase() === _cjState.tkDoc);
    return base;
  }
  function _cjTkSetDoc(d) {
    _cjState.tkDoc = (_cjState.tkDoc === d) ? '' : d;   // toggle
    _finBeep('click');
    _cjTkRenderFiltrosBtns(); _cjTkRenderVendedoresBtns(); _cjTkRender();
  }

  function _cjTkApplyFiltro(tickets) {
    const f = _cjState.tkFiltro;
    const fp = t => String(t.metodo || t.formaPago || '').toUpperCase();
    const esAnul   = t => fp(t) === 'ANULADO' || t.estado === 'ANULADO';
    const esPorCob = t => fp(t) === 'POR_COBRAR' && !esAnul(t);
    const esCred   = t => fp(t) === 'CREDITO' && !esAnul(t);
    const esEf     = t => fp(t) === 'EFECTIVO';
    const esVi     = t => fp(t) === 'VIRTUAL';
    const esMx     = t => fp(t).startsWith('MIXTO');
    const esCob    = t => !esAnul(t) && !esPorCob(t) && !esCred(t);
    if (f === 'todos')      return tickets;
    if (f === 'ventas')     return tickets.filter(esCob);
    if (f === 'efectivo')   return tickets.filter(t => esEf(t) && !esAnul(t));
    if (f === 'virtual')    return tickets.filter(t => esVi(t) && !esAnul(t));
    if (f === 'mixto')      return tickets.filter(t => esMx(t) && !esAnul(t));
    if (f === 'por_cobrar') return tickets.filter(esPorCob);
    if (f === 'credito')    return tickets.filter(esCred);
    if (f === 'anulado')    return tickets.filter(esAnul);
    return tickets;
  }

  function _cjTkRender() {
    const list = $('cjTkList');
    const conteo = $('cjTkConteo');
    if (!list) return;
    let todos = _cjTkFuente();   // [rango] día activo o rango de fechas + filtro caja + tipo doc
    // [v2.43.387] Filtro por vendedor (chips de persona) — se combina con método + búsqueda
    if (_cjState.tkVendedor) {
      todos = todos.filter(t => _cjTkVendNombre(t) === _cjState.tkVendedor);
    }
    // Buscar
    const q = ($('cjTkBuscar')?.value || _cjState.tkBuscar || '').trim().toLowerCase();
    if (q) {
      todos = todos.filter(t => {
        const cli = (t.clienteNom || t.cliente || '').toLowerCase();
        const doc = (t.clienteDoc || '').toLowerCase();
        const corr = (t.correlativo || '').toLowerCase();
        return cli.includes(q) || doc.includes(q) || corr.includes(q);
      });
    }
    // Filtro de método
    const lista = _cjTkApplyFiltro(todos);
    const esAnul2 = t => String(t.metodo || t.formaPago || '').toUpperCase() === 'ANULADO' || t.estado === 'ANULADO';
    const totalF = lista.reduce((s,t)=> s + (esAnul2(t) ? 0 : (parseFloat(t.total)||0)), 0);
    if (conteo) conteo.textContent = lista.length + ' tk · S/ ' + totalF.toFixed(2);
    if (!lista.length) {
      list.innerHTML = '<div class="px-4 py-10 text-center text-slate-500 text-sm italic">Sin tickets con este filtro</div>';
      return;
    }
    const docLabel = { 'BOLETA': 'BOL', 'NOTA_DE_VENTA': 'NV', 'FACTURA': 'FAC', 'NV': 'NV', 'B': 'BOL', 'F': 'FAC' };
    const metodoChip = t => {
      const fp = String(t.metodo || t.formaPago || '').toUpperCase();
      if (fp === 'ANULADO')        return { txt: 'ANULADO',     cls: 'tk-chip-anul' };
      if (fp === 'EFECTIVO')       return { txt: '💵 Efectivo', cls: 'tk-chip-ef'   };
      if (fp === 'VIRTUAL')        return { txt: '📱 Virtual',  cls: 'tk-chip-vi'   };
      if (fp === 'POR_COBRAR')     return { txt: '⏳ Por cobrar', cls: 'tk-chip-pc' };
      if (fp === 'CREDITO')        return { txt: '📋 Crédito',  cls: 'tk-chip-cr'   };
      if (fp.startsWith('MIXTO'))  return { txt: '🔀 Mixto',    cls: 'tk-chip-mx'   };
      return { txt: fp || '—', cls: 'tk-chip-other' };
    };
    list.innerHTML = lista.map(t => {
      const an = esAnul2(t);
      const met = metodoChip(t);
      const corr = t.correlativo || (t.idVenta || '').split('-').pop() || '—';
      const cliN = (t.clienteNom || t.cliente || '').trim();
      const cliD = (t.clienteDoc || '').trim();
      const tieneCliente = !!(cliN || cliD);
      const cabecera = tieneCliente
        ? `<div class="tk-cli-nombre">👤 ${_escapeHtml(cliN || 'Sin nombre')}</div>${cliD ? `<div class="tk-cli-doc">${_escapeHtml(cliD)}</div>` : ''}`
        : `<div class="tk-cli-nombre tk-cli-nombre-anon">— Cliente sin registrar —</div>`;
      const tipo = docLabel[t.tipo || t.tipoDoc] || (t.tipo || t.tipoDoc || '');
      const idVentaSafe = _escAttrJs(t.idVenta || '');
      return `<div class="tk-row tk-row-clickable ${an?'tk-row-anul':''} ${met.cls}" onclick="MOS.cjAbrirAccionesTicket('${idVentaSafe}')">
        <div class="tk-cli">${cabecera}</div>
        <div class="tk-meta">
          <span class="tk-meta-corr">${_escapeHtml(tipo)} ${_escapeHtml(corr)}</span>
          ${_cjState.tkRangoActivo && t.fecha ? `<span class="tk-meta-hora" style="color:#38bdf8;font-weight:700">· 📅 ${(t.fecha || '').substring(5)}</span>` : ''}
          ${t.vendedor ? `<span class="tk-meta-vend">· ${_escapeHtml(t.vendedor)}</span>` : ''}
          ${t.hora ? `<span class="tk-meta-hora">· ${t.hora}</span>` : ''}
        </div>
        <div class="tk-monto-col">
          <div class="tk-monto ${an?'tk-monto-anul':''}">S/ ${parseFloat(t.total||0).toFixed(2)}</div>
          <span class="tk-chip ${met.cls}">${met.txt}</span>
        </div>
        <div class="tk-row-cog" title="Acciones">⚙️</div>
      </div>`;
    }).join('');
  }

  // ════════════════════════════════════════════════════════════
  // ACCIONES SOBRE TICKETS — modal contextual editable
  // Estado, helpers, handlers de cada modal secundario.
  // ════════════════════════════════════════════════════════════
  const _tkAcc = {
    idVenta: null,
    ticket: null,
    cobrar: { metodo: 'EFECTIVO', cajaSel: '', cajas: [] },
    cambiarFP: { nueva: '' },
    convCPE: { tipo: 'BOLETA', clienteOK: false },
    baja: { motivo: '' }
  };

  // Buscar el ticket en cualquier estado (cajas o finanzas)
  function _tkBuscarTicket(idVenta) {
    const id = String(idVenta);
    // Cajas
    const enCajas = (S._todosTickets || []).find(t => String(t.idVenta) === id);
    if (enCajas) return _tkNormalizar(enCajas, 'cajas');
    // Finanzas
    const enFin = (_finPL?.detalleTickets || []).find(t => String(t.idVenta) === id);
    if (enFin) return _tkNormalizar(enFin, 'finanzas');
    return null;
  }

  // Normaliza para que ambos shapes (cajas vs finanzas) compartan campos
  function _tkNormalizar(t, fuente) {
    return {
      idVenta:    String(t.idVenta || ''),
      correlativo: t.correlativo || '',
      tipoDoc:    t.tipoDoc || t.tipo || '',
      formaPago:  String(t.formaPago || t.metodo || '').toUpperCase(),
      total:      parseFloat(t.total || 0),
      cliente:    (t.cliente || t.clienteNombre || t.clienteNom || '').trim(),
      clienteDoc: (t.clienteDoc || t.clienteDocumento || '').trim(),
      vendedor:   t.vendedor || '',
      hora:       t.hora || '',
      fecha:      t.fecha || '',
      idCaja:     t.idCaja || '',
      obs:        t.obs || '',
      nfEstado:   t.nfEstado || t.NF_Estado || '',
      _fuente:    fuente
    };
  }

  // Abre el menú contextual de acciones para un ticket
  async function cjAbrirAccionesTicket(idVenta) {
    const t = _tkBuscarTicket(idVenta);
    if (!t) { toast('Ticket no encontrado', 'error'); return; }

    const rol = (S.session?.rol || '').toLowerCase();
    if (rol !== 'master' && rol !== 'admin') {
      toast('Solo admin/master pueden editar tickets', 'error');
      return;
    }

    _tkAcc.idVenta = t.idVenta;
    _tkAcc.ticket  = t;

    const tit = $('tkAccTitulo');
    const sub = $('tkAccSubtitulo');
    if (tit) tit.textContent = (t.correlativo || t.idVenta) + ' · S/ ' + t.total.toFixed(2);
    if (sub) {
      const cli = t.cliente || (t.clienteDoc ? t.clienteDoc : '— sin cliente —');
      sub.textContent = `${t.tipoDoc || ''} · ${t.formaPago} · ${cli}`;
    }
    _tkAccBuildMenu(t);
    openModal('modalTkAcciones');
    _tkCargarDetalle(t.idVenta);   // [Rep#4] llena la sección de detalle (async, Supabase-first)
  }

  // Construye el menú según el estado del ticket
  function _tkAccBuildMenu(t) {
    const body = $('tkAccBody');
    if (!body) return;

    const fp = t.formaPago;
    const esAnulado = fp === 'ANULADO';
    const esPorCobrar = fp === 'POR_COBRAR';
    const esCredito   = fp === 'CREDITO';
    const esCobrado   = !esAnulado && !esPorCobrar && !esCredito;
    const esNV        = (t.tipoDoc === 'NOTA_DE_VENTA' || t.tipoDoc === 'NV');
    const esCPE       = (t.tipoDoc === 'BOLETA' || t.tipoDoc === 'FACTURA');
    const cpeEmitido  = esCPE && t.nfEstado === 'EMITIDO';

    const btns = [];
    const btn = (cls, emoji, tit, sub, accion) => {
      btns.push(`<button class="tk-acc-btn ${cls}" onclick="MOS._tkAccion('${accion}')">
        <span class="tk-acc-emoji">${emoji}</span>
        <span class="tk-acc-txt">
          <div class="tk-acc-tit">${tit}</div>
          <div class="tk-acc-sub">${sub}</div>
        </span>
      </button>`);
    };

    if (esAnulado) {
      btn('', '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-3px"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8" rx="1"/><circle cx="18" cy="11.5" r="1" fill="currentColor"/></svg>', 'Imprimir ticket', 'Reimprime el comprobante en la impresora que elijas', 'imprimir');
      btn('', '📜', 'Ver historial', 'Ver todos los cambios del ticket', 'historial');
      body.innerHTML = `<p class="text-[11px] text-slate-500 italic px-2 py-2">Ticket anulado · solo lectura.</p>${btns.join('')}${_tkDetalleContainerHtml()}`;
      return;
    }

    // 💵 Cobrar (si está pendiente o crédito)
    if (esPorCobrar || esCredito) {
      btn('tk-acc-btn-ok', '💵', 'Cobrar' + (esCredito ? ' deuda' : ' pendiente'),
          'Crea ingreso en caja receptora · marca como cobrado', 'cobrar');
    }

    // 📋 Aprobar como crédito (solo si está POR_COBRAR)
    if (esPorCobrar) {
      btn('tk-acc-btn-warn', '📋', 'Aprobar como crédito',
          'Pasa de "por cobrar" a "crédito formal"', 'aprobarCredito');
    }

    // 🔄 Cambiar forma de pago (corrección sin afectar caja)
    if (esCobrado) {
      btn('', '🔄', 'Cambiar forma de pago',
          'Corrige errores de tipeo · NO mueve dinero entre cajas', 'cambiarFP');
    }

    // 👤 Editar cliente — SOLO Nota de Venta. Un CPE (boleta/factura) NO cambia de titular fiscal tras
    // mintear el correlativo (regla SUNAT, me.editar_cliente SQL 271 H7) → para corregir: anular y reemitir.
    // Antes el botón salía con `!cpeEmitido` → aparecía en boletas PENDIENTES y el backend lo rechazaba (toast rojo).
    if (esNV) {
      btn('', '👤', 'Editar cliente', 'Cambiar DNI/RUC y nombre del NV', 'editarCliente');
    } else if (esCPE && !esAnulado) {
      btn('tk-acc-btn-warn', '🔒', 'Editar cliente — solo Nota de Venta',
          'Boleta/Factura no cambian de titular · para corregir: anula y reemite', 'editarClienteCPEInfo');
    }

    // 📑 Convertir NV → CPE (solo NV)
    if (esNV && !esAnulado) {
      btn('', '📑', 'Convertir a Boleta/Factura',
          'Emite CPE retroactivo en SUNAT', 'convertirCPE');
    }

    // 📋 Baja del CPE (solo CPE emitido)
    if (cpeEmitido) {
      btn('tk-acc-btn-danger', '📋', 'Baja del CPE',
          'Comunica baja a SUNAT (irreversible)', 'bajaCPE');
    }

    // ❌ Anular venta interna (siempre disponible si no anulado)
    btn('tk-acc-btn-danger', '❌', 'Anular venta',
        'Marca el ticket como anulado internamente', 'anular');

    // 🖨 Imprimir ticket — siempre (reimpresión por la impresora que elija el admin)
    btn('tk-acc-btn-ok', '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-3px"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8" rx="1"/><circle cx="18" cy="11.5" r="1" fill="currentColor"/></svg>', 'Imprimir ticket',
        'Reimprime el comprobante en la impresora que elijas', 'imprimir');

    // 📜 Historial — siempre
    btn('', '📜', 'Ver historial',
        'Ver todos los cambios de este ticket', 'historial');

    // 📜 Historial cliente — solo si hay clienteDoc
    if (t.clienteDoc) {
      btn('', '👥', 'Historial del cliente',
          (t.cliente || t.clienteDoc) + ' · cambios sobre este cliente', 'historialCli');
    }

    body.innerHTML = (btns.join('') || '<p class="text-xs text-slate-500 italic">Sin acciones disponibles.</p>') + _tkDetalleContainerHtml();
  }
  // [Reparación #4 · Etapa 1] Contenedor de la sección "detalle del ticket" (scrollable, se llena async).
  function _tkDetalleContainerHtml() {
    return `<div id="tkAccDetalle" class="tk-acc-detalle">
      <div class="tk-acc-det-hdr">🧾 Detalle del ticket</div>
      <div class="tk-acc-det-body"><div class="text-[11px] text-slate-400 px-1 py-2">Cargando…</div></div>
    </div>`;
  }

  // Routing del menú contextual
  function _tkAccion(accion) {
    const t = _tkAcc.ticket;
    if (!t) return;
    closeModal('modalTkAcciones');
    if (accion === 'cobrar')          return _tkCobrarOpen(t);
    if (accion === 'cambiarFP')       return _tkCambiarFPOpen(t);
    if (accion === 'aprobarCredito')  return _tkAprobarCredOpen(t);
    if (accion === 'convertirCPE')    return _tkConvertirOpen(t);
    if (accion === 'bajaCPE')         return _tkBajaOpen(t);
    if (accion === 'editarCliente')   return _tkEditarClienteOpen(t);
    if (accion === 'editarClienteCPEInfo') {
      _modalConfirm(
        'Una boleta o factura ya tiene su correlativo SUNAT minteado, por eso el titular fiscal (DNI/RUC + nombre) NO se puede cambiar.\n\nPara corregir el cliente: ANULA este comprobante (dar de baja en SUNAT) y emite uno nuevo con los datos correctos.\n\nLas Notas de Venta sí se editan libremente.',
        { warning: true, titulo: '🔒 Cliente de CPE no editable', okText: 'Entendido' }
      );
      return;
    }
    if (accion === 'anular')          return _tkAnularSimple(t);
    if (accion === 'historial')       return _tkHistorialOpen(t);
    if (accion === 'historialCli')    return _tkHistorialClienteOpen(t);
    if (accion === 'imprimir')        return _tkImprimir(t);
  }

  function _tkNum(x) { const n = Number(x); return Number.isFinite(n) ? n : 0; }
  // [Reparación #4 · Etapa 1] Carga + render del DETALLE del ticket en la sección del modal.
  // Supabase-first (mos.me_detalle_venta) con fallback GAS. Cachea en _tkAcc.detalle para la impresión.
  async function _tkCargarDetalle(idVenta) {
    const host = document.getElementById('tkAccDetalle');
    if (!host) return;
    const body = host.querySelector('.tk-acc-det-body');
    try {
      const r = await API.get('meDetalleVenta', { idVenta });
      const data = (r && r.data) || r || {};
      const items = Array.isArray(data.items) ? data.items : [];
      _tkAcc.detalle = data;   // cache del detalle mostrado (la impresión va por el Edge ticket-comprobante)
      if (!body) return;
      if (!items.length) { body.innerHTML = `<div class="text-[11px] text-slate-400 px-1 py-2">Sin líneas para este ticket.</div>`; return; }
      const filas = items.map(it => {
        const cant = _tkNum(it.cantidad), sub = _tkNum(it.subtotal);
        const nom = _esc(String(it.nombre || it.sku || '—').replace(/\s*\(.*\)\s*$/, ''));   // recorta "(canónico)" duplicado
        return `<div class="tk-acc-det-row">
          <span class="tk-acc-det-q">${cant}×</span>
          <span class="tk-acc-det-n">${nom}</span>
          <span class="tk-acc-det-s">S/ ${sub.toFixed(2)}</span>
        </div>`;
      }).join('');
      const tot = _tkNum(data.total) || items.reduce((s, it) => s + _tkNum(it.subtotal), 0);  // [R1] fallback Σsubtotal (path GAS no trae total)
      body.innerHTML = `<div class="tk-acc-det-list">${filas}</div>
        <div class="tk-acc-det-tot"><span>Total (${items.length} ít.)</span><b>S/ ${tot.toFixed(2)}</b></div>`;
    } catch (e) {
      if (body) body.innerHTML = `<div class="text-[11px] text-rose-400 px-1 py-2">No se pudo cargar el detalle.</div>`;
    }
  }

  // [Reparación #4 · Etapa 1] Imprime (reimprime) el ticket: elige impresora + arma ESC/POS client-side +
  // lo manda por la Edge `imprimir` (PrintNode, cero GAS). Optimista con feedback.
  async function _tkImprimir(t) {
    try {
      const printerId = await abrirPrinterPicker({
        titulo: 'Imprimir ticket', subtitulo: (t.correlativo || t.idVenta),
        filtroTipo: 'TICKET', flowKey: 'venta_ticket'
      });
      if (!printerId) return;   // canceló
      toast('Enviando a impresora…', 'info', 1500);
      // [Reparación #9] Comprobante CENTRALIZADO por Edge ticket-comprobante (empresa + IGV + QR + leyenda),
      // mismo formato que el ticket original. Reemplaza el builder client-side pobre (_tkBuildEscPos).
      await API.imprimirComprobante(t.idVenta, printerId, { reimpresion: true });
      try { _opsBeep && _opsBeep('ok'); } catch (_) {}
      toast('🖨 Ticket enviado a impresión', 'success');
    } catch (e) {
      try { _opsBeep && _opsBeep('error'); } catch (_) {}
      toast('No se pudo imprimir: ' + (e && (e.message || e)), 'error');
    }
  }

  // [Review R1] _tkBuildEscPos ELIMINADO — código muerto. La impresión del ticket va por API.imprimirComprobante
  // (Edge ticket-comprobante, formato centralizado con empresa/IGV/QR/leyenda). No re-cablear un builder inferior.

  // ──────────────────────────────────────────────────────────
  // COBRAR PENDIENTE / DEUDA
  // ──────────────────────────────────────────────────────────
  async function _tkCobrarOpen(t) {
    _tkAcc.cobrar = { metodo: 'EFECTIVO', cajaSel: '', cajas: [] };
    $('tkCobrarTitulo').textContent = (t.formaPago === 'CREDITO' ? 'Cobrar deuda' : 'Cobrar pendiente');
    $('tkCobrarSubtitulo').textContent = (t.correlativo || t.idVenta) + ' · ' + t.formaPago;
    $('tkCobrarCliente').textContent = t.cliente || '— sin cliente —';
    $('tkCobrarRef').textContent     = (t.tipoDoc || '') + ' ' + (t.correlativo || t.idVenta);
    $('tkCobrarMonto').textContent   = 'S/ ' + t.total.toFixed(2);
    $('tkCobrarObs').value           = '';
    $('tkCobrarMonEf').value = '';
    $('tkCobrarMonVi').value = '';
    $('tkCobrarMixto').classList.add('hidden');
    $('tkCobrarMixtoHint').textContent = '';
    $('tkCobrarCajas').innerHTML = '<div class="text-xs text-slate-500 italic px-2 py-3">Cargando cajas abiertas...</div>';

    // Marcar EFECTIVO por default
    _tkCobrarSetMetodo('EFECTIVO');
    openModal('modalTkCobrar');

    try {
      const data = await API.get('meCajasAbiertas');
      _tkAcc.cobrar.cajas = Array.isArray(data) ? data : [];
      _tkCobrarRenderCajas();
    } catch(e) {
      $('tkCobrarCajas').innerHTML = `<div class="text-xs text-rose-400 px-2 py-2">Error: ${e.message}</div>`;
    }
  }

  function _tkCobrarRenderCajas() {
    const c = $('tkCobrarCajas');
    if (!c) return;
    const cajas = _tkAcc.cobrar.cajas || [];
    if (!cajas.length) {
      c.innerHTML = '<div class="text-xs text-amber-400 italic px-2 py-2">No hay cajas abiertas. Abre una caja en MosExpress primero.</div>';
      return;
    }
    c.innerHTML = cajas.map(k => `
      <label class="tk-caja-radio" data-id="${k.idCaja}">
        <input type="radio" name="tkCobrarCaja" value="${k.idCaja}" onchange="MOS._tkCobrarSetCaja('${k.idCaja}')">
        <div class="tk-caja-vend">${k.vendedor || k.idCaja}</div>
        <div class="tk-caja-zona">${k.zona || ''}</div>
      </label>
    `).join('');
    // Auto-seleccionar la única caja si solo hay una
    if (cajas.length === 1) {
      const r = c.querySelector('input[type="radio"]');
      if (r) { r.checked = true; _tkCobrarSetCaja(cajas[0].idCaja); }
    }
  }

  function _tkCobrarSetCaja(id) {
    _tkAcc.cobrar.cajaSel = id;
    document.querySelectorAll('#tkCobrarCajas .tk-caja-radio').forEach(el => {
      el.classList.toggle('tk-caja-active', el.dataset.id === id);
    });
  }

  function _tkCobrarSetMetodo(met) {
    _tkAcc.cobrar.metodo = met;
    ['Ef','Vi','Mx'].forEach(k => {
      const b = $('tkCobrarBtn' + k);
      if (b) b.classList.remove('tk-cob-mbtn-active');
    });
    const map = { 'EFECTIVO':'Ef', 'VIRTUAL':'Vi', 'MIXTO':'Mx' };
    const b = $('tkCobrarBtn' + map[met]);
    if (b) b.classList.add('tk-cob-mbtn-active');
    $('tkCobrarMixto').classList.toggle('hidden', met !== 'MIXTO');
    if (met === 'MIXTO') _tkCobrarValidarMixto();
  }

  function _tkCobrarValidarMixto() {
    const t = _tkAcc.ticket;
    const ef = parseFloat($('tkCobrarMonEf').value || 0);
    const vi = parseFloat($('tkCobrarMonVi').value || 0);
    const total = t ? t.total : 0;
    const sum = ef + vi;
    const hint = $('tkCobrarMixtoHint');
    if (!hint) return;
    if (Math.abs(sum - total) < 0.01) {
      hint.textContent = `✓ Suma S/ ${sum.toFixed(2)} = total`;
      hint.style.color = '#6ee7b7';
    } else {
      hint.textContent = `Suma S/ ${sum.toFixed(2)} · falta/sobra S/ ${(total - sum).toFixed(2)}`;
      hint.style.color = '#fcd34d';
    }
  }

  async function _tkCobrarConfirmar() {
    const t = _tkAcc.ticket;
    if (!t) return;
    const c = _tkAcc.cobrar;
    if (!c.cajaSel)  { toast('Selecciona la caja receptora', 'error'); return; }
    if (!c.metodo)   { toast('Selecciona forma de pago', 'error'); return; }

    let metodoFinal = c.metodo;
    let monEf, monVi;
    if (c.metodo === 'MIXTO') {
      monEf = parseFloat($('tkCobrarMonEf').value || 0);
      monVi = parseFloat($('tkCobrarMonVi').value || 0);
      if (Math.abs((monEf + monVi) - t.total) > 0.01) {
        toast('La suma EFE+VIR debe igualar el total', 'error'); return;
      }
      metodoFinal = `MIXTO (EFE:${monEf.toFixed(2)}/VIR:${monVi.toFixed(2)})`;
    }

    const btn = $('tkCobrarBtnOK');
    if (btn) { btn.disabled = true; btn.textContent = 'Procesando...'; }
    try {
      const r = await API.post('meCobrarCredito', {
        idVenta:       t.idVenta,
        cajaReceptora: c.cajaSel,
        metodo:        metodoFinal,
        montoEfectivo: monEf,
        montoVirtual:  monVi,
        obs:           $('tkCobrarObs').value || ''
      });
      toast('✓ Cobrado · ingreso registrado', 'success');
      closeModal('modalTkCobrar');
      await _cajasRefreshSilencioso?.();
      if (S.view === 'finanzas') finCargar?.();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = '✓ Confirmar cobro'; }
    }
  }

  // ──────────────────────────────────────────────────────────
  // CAMBIAR FORMA DE PAGO (corrección)
  // ──────────────────────────────────────────────────────────
  function _tkCambiarFPOpen(t) {
    _tkAcc.cambiarFP.nueva = '';
    $('tkCambiarFPSub').textContent  = (t.correlativo || t.idVenta);
    $('tkCambiarFPActual').textContent = t.formaPago;
    $('tkCambiarFPMotivo').value = '';

    // Opciones (excluye la actual)
    const opciones = [
      { v: 'EFECTIVO', txt: '💵 Efectivo' },
      { v: 'VIRTUAL',  txt: '📱 Virtual'  },
      { v: 'POR_COBRAR', txt: '⏳ Por cobrar' },
      { v: 'CREDITO',  txt: '📋 Crédito' }
    ].filter(o => o.v !== t.formaPago);
    $('tkCambiarFPOpciones').innerHTML = opciones.map(o =>
      `<button class="tk-cob-mbtn" onclick="MOS._tkCambiarFPSel('${o.v}')" id="tkCambiarFPOp_${o.v}">${o.txt}</button>`
    ).join('');
    openModal('modalTkCambiarFP');
    _tkCambiarFPValidar();   // arranca deshabilitado (sin forma ni motivo)
  }

  function _tkCambiarFPSel(v) {
    _tkAcc.cambiarFP.nueva = v;
    document.querySelectorAll('#tkCambiarFPOpciones .tk-cob-mbtn').forEach(b => b.classList.remove('tk-cob-mbtn-active'));
    const b = $('tkCambiarFPOp_' + v);
    if (b) b.classList.add('tk-cob-mbtn-active');
    _tkCambiarFPValidar();
  }

  // [UX 500x] Gate in-form: el botón solo se habilita con forma seleccionada + motivo>=3.
  // Evita el toast rojo post-submit "Motivo obligatorio" (no intuitivo).
  function _tkCambiarFPValidar() {
    const motivo = ($('tkCambiarFPMotivo')?.value || '').trim();
    const ok = !!_tkAcc.cambiarFP.nueva && motivo.length >= 3;
    const btn = $('tkCambiarFPBtn');
    if (btn) {
      btn.disabled = !ok;
      btn.classList.toggle('opacity-40', !ok);
      btn.classList.toggle('cursor-not-allowed', !ok);
    }
    return ok;
  }

  async function _tkCambiarFPConfirmar() {
    const t = _tkAcc.ticket;
    const nueva = _tkAcc.cambiarFP.nueva;
    if (!nueva) { toast('Selecciona la nueva forma de pago', 'error'); return; }
    const motivo = ($('tkCambiarFPMotivo').value || '').trim();
    if (motivo.length < 3) { toast('Motivo obligatorio (mín. 3 caracteres)', 'error'); return; }
    try {
      await API.post('meEditarFormaPago', {
        idVenta: t.idVenta, formaPagoNueva: nueva, motivo
      });
      toast('✓ Forma de pago actualizada', 'success');
      closeModal('modalTkCambiarFP');
      await _cajasRefreshSilencioso?.();
      if (S.view === 'finanzas') finCargar?.();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  // ──────────────────────────────────────────────────────────
  // APROBAR COMO CREDITO (POR_COBRAR → CREDITO)
  // ──────────────────────────────────────────────────────────
  function _tkAprobarCredOpen(t) {
    $('tkAprobarCredSub').textContent = (t.correlativo || t.idVenta) + ' · S/ ' + t.total.toFixed(2);
    $('tkAprobarCredObs').value = '';
    openModal('modalTkAprobarCred');
  }

  async function _tkAprobarCredConfirmar() {
    const t = _tkAcc.ticket;
    const obs = ($('tkAprobarCredObs').value || '').trim();
    if (obs.length < 3) { toast('Motivo obligatorio (mín. 3 caracteres)', 'error'); return; }
    try {
      await API.post('meAprobarComoCredito', { idVenta: t.idVenta, motivo: obs });
      toast('✓ Aprobado como crédito', 'success');
      closeModal('modalTkAprobarCred');
      await _cajasRefreshSilencioso?.();
      if (S.view === 'finanzas') finCargar?.();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  // ──────────────────────────────────────────────────────────
  // CONVERTIR NV → CPE (boleta/factura retroactivo)
  // ──────────────────────────────────────────────────────────
  function _tkConvertirOpen(t) {
    _tkAcc.convCPE = { tipo: 'BOLETA', clienteOK: false };
    $('tkConvSub').textContent = (t.correlativo || t.idVenta) + ' · S/ ' + t.total.toFixed(2);
    $('tkConvDoc').value      = t.clienteDoc || '';
    $('tkConvNombre').value   = t.cliente || '';
    $('tkConvDireccion').value = '';
    $('tkConvSerie').value     = '';
    $('tkConvClienteInfo').classList.add('hidden');
    _tkConvSetTipo('BOLETA');
    openModal('modalTkConvertirCPE');
  }

  function _tkConvSetTipo(tipo) {
    _tkAcc.convCPE.tipo = tipo;
    ['Bol','Fac'].forEach(k => {
      const b = $('tkConvBtn' + k);
      if (b) b.classList.remove('tk-cob-mbtn-active');
    });
    const b = $('tkConvBtn' + (tipo === 'BOLETA' ? 'Bol' : 'Fac'));
    if (b) b.classList.add('tk-cob-mbtn-active');
    const seriePh = tipo === 'BOLETA' ? 'B001' : 'F001';
    $('tkConvSerie').placeholder = 'ej: ' + seriePh;
  }

  function _tkConvDocChange() {
    _tkAcc.convCPE.clienteOK = false;
    $('tkConvClienteInfo').classList.add('hidden');
  }

  async function _tkConvBuscarCliente() {
    const doc = ($('tkConvDoc').value || '').trim();
    if (!doc) { toast('Ingresa DNI o RUC', 'error'); return; }
    if (doc.length !== 8 && doc.length !== 11) {
      toast('DNI debe tener 8 dígitos · RUC 11 dígitos', 'error'); return;
    }
    const info = $('tkConvClienteInfo');
    if (info) {
      info.classList.remove('hidden');
      info.innerHTML = '<span class="text-slate-400">🔎 Consultando...</span>';
    }
    try {
      const r = await API.get('meConsultarCliente', { doc });
      const nombre = r?.nombre || r?.razon_social || '';
      const direccion = r?.direccion || '';
      if (!nombre) {
        info.innerHTML = '<span class="text-amber-400">⚠ No encontrado en RENIEC/SUNAT — puedes ingresar manualmente</span>';
        _tkAcc.convCPE.clienteOK = false;
        return;
      }
      $('tkConvNombre').value    = nombre;
      $('tkConvDireccion').value = direccion;
      info.innerHTML = `<div class="text-emerald-400 font-bold">✓ ${nombre}</div>` +
                       (direccion ? `<div class="text-slate-400">${direccion}</div>` : '');
      _tkAcc.convCPE.clienteOK = true;
    } catch(e) {
      info.innerHTML = '<span class="text-rose-400">Error: ' + e.message + '</span>';
    }
  }

  async function _tkConvertirConfirmar() {
    const t = _tkAcc.ticket;
    const tipo = _tkAcc.convCPE.tipo;
    const doc  = ($('tkConvDoc').value || '').trim();
    const nom  = ($('tkConvNombre').value || '').trim();
    const dir  = ($('tkConvDireccion').value || '').trim();
    const ser  = ($('tkConvSerie').value || '').trim();

    if (tipo === 'BOLETA' && doc.length !== 8) { toast('Boleta requiere DNI de 8 dígitos', 'error'); return; }
    if (tipo === 'FACTURA' && doc.length !== 11) { toast('Factura requiere RUC de 11 dígitos', 'error'); return; }
    if (!nom) { toast('Falta nombre/razón social', 'error'); return; }
    if (tipo === 'FACTURA' && !dir) { toast('Factura requiere dirección', 'error'); return; }
    if (!ser) { toast('Ingresa la serie', 'error'); return; }

    if (!await _modalConfirm(`¿Emitir ${tipo} en SUNAT para ${nom}?\n\nLa NV original quedará anulada.`, { warning: true, titulo: 'Emitir CPE', okText: 'Emitir' })) return;

    const btn = $('tkConvBtnOK');
    if (btn) { btn.disabled = true; btn.textContent = 'Emitiendo...'; }
    try {
      const r = await API.post('meConvertirNVaCPE', {
        idVenta: t.idVenta, tipoDocNuevo: tipo, serie: ser,
        clienteDoc: doc, clienteNom: nom, direccion: dir
      });
      toast('✓ CPE emitido', 'success');
      closeModal('modalTkConvertirCPE');
      await _cajasRefreshSilencioso?.();
      if (S.view === 'finanzas') finCargar?.();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = '📤 Emitir CPE en SUNAT'; }
    }
  }

  // ──────────────────────────────────────────────────────────
  // BAJA DEL CPE (comunicación SUNAT)
  // ──────────────────────────────────────────────────────────
  function _tkBajaOpen(t) {
    _tkAcc.baja = { motivo: '' };
    $('tkBajaSub').textContent = (t.correlativo || t.idVenta) + ' · ' + (t.tipoDoc || '');
    document.querySelectorAll('input[name="tkBajaMotivo"]').forEach(r => r.checked = false);
    $('tkBajaMotivoTxt').value = '';
    $('tkBajaBtnOK').disabled = true;
    openModal('modalTkBajaCPE');
  }

  function _tkBajaSetMotivo(v) {
    _tkAcc.baja.motivo = v;
    if (v) $('tkBajaMotivoTxt').value = '';
    _tkBajaActualizarBoton();
  }

  function _tkBajaActualizarBoton() {
    const radio = _tkAcc.baja.motivo;
    const txt   = ($('tkBajaMotivoTxt').value || '').trim();
    const motivoFinal = radio || txt;
    $('tkBajaBtnOK').disabled = (motivoFinal.length < 3);
    _tkAcc.baja.motivoFinal = motivoFinal;
  }

  async function _tkBajaConfirmar() {
    const t = _tkAcc.ticket;
    const motivo = _tkAcc.baja.motivoFinal || _tkAcc.baja.motivo || ($('tkBajaMotivoTxt').value || '').trim();
    if (!motivo || motivo.length < 3) { toast('Motivo obligatorio', 'error'); return; }
    if (!await _modalConfirm(`¿Comunicar baja del ${t.tipoDoc} ${t.correlativo} a SUNAT?\n\nEsta acción es irreversible.`, { danger: true, titulo: 'Baja CPE SUNAT', okText: 'Enviar baja' })) return;
    const btn = $('tkBajaBtnOK');
    if (btn) { btn.disabled = true; btn.textContent = 'Enviando...'; }
    try {
      const r = await API.post('meBajaCPE', { idVenta: t.idVenta, motivo });
      toast('✓ Baja enviada · ' + (r?.nuevoEstado || 'aceptada'), 'success');
      closeModal('modalTkBajaCPE');
      await _cajasRefreshSilencioso?.();
      if (S.view === 'finanzas') finCargar?.();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = '📤 Enviar baja a SUNAT'; }
    }
  }

  // ──────────────────────────────────────────────────────────
  // EDITAR CLIENTE (modo prompt rápido — solo NV o pre-CPE)
  // ──────────────────────────────────────────────────────────
  // [UX 500x] Modal ÚNICO de editar cliente (antes eran 3 _modalPrompt secuenciales + salía detrás
  // del layout por z-index). Un solo formulario: doc (auto-detecta DNI/RUC/C.E.) + lookup APISPeru
  // (vía Edge, solo DNI/RUC) + nombre + dirección + motivo. Devuelve {doc,nombre,direccion,motivo,tipoDoc} o null.
  function _modalEditarCliente(t) {
    return new Promise((resolve) => {
      const _esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
      const _tipoDe = (d) => {
        d = String(d || '').trim();
        if (!d) return { cod: 0, lbl: 'Sin doc' };
        if (/^\d{8}$/.test(d))  return { cod: 1, lbl: 'DNI' };
        if (/^\d{11}$/.test(d)) return { cod: 6, lbl: 'RUC' };
        return { cod: 4, lbl: 'C.E./Otro' };   // Carné de Extranjería / Pasaporte / otros
      };
      let ext = false;   // [replica ME] Perú (false) / Extranjero (true)
      let _tmr = null;
      const bd = document.createElement('div');
      bd.className = 'mos-modal-generic-backdrop';
      bd.innerHTML = `
        <div class="mos-modal-generic mos-modal-generic-primary" role="dialog" aria-modal="true">
          <div class="mos-modal-generic-head">
            <span class="mos-modal-generic-ico">👤</span><strong>Editar cliente</strong>
            <button class="mos-modal-generic-close" data-cancel>✕</button>
          </div>
          <div class="mos-modal-generic-body" style="display:flex;flex-direction:column;gap:12px;">
            <div style="display:flex;align-items:center;justify-content:space-between;gap:8px;">
              <label class="mos-modal-generic-label" style="margin:0;">Cliente <span id="ec-tipo" style="font-weight:800;color:#818cf8;"></span></label>
              <div style="display:inline-flex;background:#1e293b;border-radius:999px;padding:3px;font-size:11px;font-weight:800;">
                <button id="ec-pe" type="button" style="padding:4px 10px;border-radius:999px;border:0;cursor:pointer;background:#fff;color:#0f172a;">🇵🇪 Perú</button>
                <button id="ec-ex" type="button" style="padding:4px 10px;border-radius:999px;border:0;cursor:pointer;background:transparent;color:#94a3b8;">🌎 Extranjero</button>
              </div>
            </div>
            <div style="position:relative;">
              <label class="mos-modal-generic-label" id="ec-busq-lbl">Buscar: nombre, DNI (8) o RUC (11)</label>
              <div style="display:flex;gap:8px;">
                <div style="position:relative;flex:1;">
                  <input id="ec-busq" class="mos-modal-generic-input" inputmode="text" maxlength="120" value="" placeholder="nombre o documento" style="width:100%;padding-right:34px;" />
                  <button id="ec-x" type="button" title="Limpiar" style="position:absolute;right:6px;top:50%;transform:translateY(-50%);width:22px;height:22px;border:0;border-radius:999px;background:#334155;color:#cbd5e1;cursor:pointer;display:none;line-height:1;">×</button>
                </div>
                <button id="ec-buscar" type="button" class="mos-modal-generic-btn mos-modal-generic-btn-ghost" title="Buscar en RENIEC/SUNAT" style="white-space:nowrap;">🔎</button>
              </div>
              <div id="ec-sugs" style="display:none;position:absolute;left:0;right:0;top:100%;margin-top:4px;background:#0b1220;border:1px solid #1e293b;border-radius:10px;max-height:200px;overflow:auto;z-index:5;"></div>
            </div>
            <div>
              <label class="mos-modal-generic-label">Documento <span style="opacity:.55;">(DNI/RUC/C.E.)</span></label>
              <input id="ec-doc" class="mos-modal-generic-input" inputmode="text" maxlength="15" value="${_esc(t.clienteDoc || '')}" placeholder="documento" />
            </div>
            <div>
              <label class="mos-modal-generic-label">Nombre / Razón social</label>
              <input id="ec-nom" class="mos-modal-generic-input" maxlength="120" value="${_esc(t.cliente || '')}" placeholder="nombre del cliente" />
            </div>
            <div>
              <label class="mos-modal-generic-label">Dirección <span style="opacity:.55;">(opcional)</span></label>
              <input id="ec-dir" class="mos-modal-generic-input" maxlength="160" value="" placeholder="dirección fiscal" />
            </div>
            <div>
              <label class="mos-modal-generic-label">Motivo del cambio <span style="color:#fb7185;font-weight:700;">* (mín. 3)</span></label>
              <input id="ec-mot" class="mos-modal-generic-input" maxlength="180" value="" placeholder="motivo de la corrección" />
            </div>
          </div>
          <div class="mos-modal-generic-foot">
            <button class="mos-modal-generic-btn mos-modal-generic-btn-ghost" data-cancel>Cancelar</button>
            <button id="ec-ok" class="mos-modal-generic-btn mos-modal-generic-btn-ok mos-modal-generic-btn-primary" disabled style="opacity:.4;cursor:not-allowed;" data-ok>Guardar</button>
          </div>
        </div>`;
      const $$ = (id) => bd.querySelector('#' + id);
      const cerrar = (val) => { bd.classList.remove('is-open'); setTimeout(() => { try { bd.remove(); } catch(_){} }, 200); resolve(val); };
      const refTipo = () => { const ti = ext ? { cod:4, lbl:'C.E./Pasaporte' } : _tipoDe($$('ec-doc').value); $$('ec-tipo').textContent = ti.lbl ? '· ' + ti.lbl : ''; return ti; };
      const validar = () => {
        const mot = ($$('ec-mot').value || '').trim();
        const doc = ($$('ec-doc').value || '').trim();
        const nom = ($$('ec-nom').value || '').trim();
        const ok = mot.length >= 3 && (!!doc || !!nom);
        const b = $$('ec-ok'); b.disabled = !ok; b.style.opacity = ok ? '1' : '.4'; b.style.cursor = ok ? 'pointer' : 'not-allowed';
      };
      const cerrarSugs = () => { const s = $$('ec-sugs'); s.style.display = 'none'; s.innerHTML = ''; };
      const pintarSugs = (arr) => {
        const s = $$('ec-sugs');
        if (!arr || !arr.length) { cerrarSugs(); return; }
        s.innerHTML = arr.map(c => `<div class="ec-sug" data-doc="${_esc(c.documento)}" data-nom="${_esc(c.nombre)}" data-dir="${_esc(c.direccion||'')}" style="padding:8px 10px;cursor:pointer;border-bottom:1px solid #1e293b;display:flex;justify-content:space-between;gap:8px;align-items:center;">
            <span style="font-weight:700;color:#e2e8f0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_esc(c.nombre||'(sin nombre)')}</span>
            <span style="font-family:monospace;font-size:11px;color:#64748b;flex-shrink:0;background:#1e293b;padding:1px 6px;border-radius:999px;">${_esc(c.documento)}</span>
          </div>`).join('');
        s.style.display = 'block';
      };
      const onBusq = () => {
        const v = ($$('ec-busq').value || '').trim();
        $$('ec-x').style.display = v ? 'block' : 'none';
        if (ext) { $$('ec-doc').value = v; refTipo(); cerrarSugs(); validar(); return; }   // extranjero: lo tipeado ES el doc
        if (/^\d{8}$/.test(v) || /^\d{11}$/.test(v)) { $$('ec-doc').value = v; refTipo(); cerrarSugs(); validar(); return; }
        if (v.length < 2) { cerrarSugs(); validar(); return; }
        if (_tmr) clearTimeout(_tmr);
        _tmr = setTimeout(async () => { try { pintarSugs(await API.buscarClientesFrecuentes(v)); } catch(_){ cerrarSugs(); } }, 280);
        validar();
      };
      const elegir = (doc, nom, dir) => {
        $$('ec-doc').value = String(doc||'').trim();
        $$('ec-nom').value = String(nom||'').trim();
        if (dir) $$('ec-dir').value = String(dir);
        $$('ec-busq').value = nom || doc; $$('ec-x').style.display = 'block';
        cerrarSugs(); refTipo(); validar();
      };
      const lookup = async () => {
        const doc = ($$('ec-doc').value || '').trim() || ($$('ec-busq').value || '').trim();
        const ti = _tipoDe(doc);
        if (ext || (ti.cod !== 1 && ti.cod !== 6)) return;   // lookup solo DNI/RUC (APISPeru)
        $$('ec-doc').value = doc;
        const bb = $$('ec-buscar'); const prev = bb.textContent; bb.textContent = '…'; bb.disabled = true;
        try {
          const r = await API.get('meConsultarCliente', { doc });
          const nom = r?.nombre || r?.razon_social || '';
          if (nom) { $$('ec-nom').value = nom; $$('ec-busq').value = nom; $$('ec-x').style.display = 'block'; }
          if (r?.direccion) $$('ec-dir').value = r.direccion;
        } catch(_) {}
        bb.textContent = prev; bb.disabled = false; cerrarSugs(); refTipo(); validar();
      };
      const setExt = (on) => {
        ext = on;
        $$('ec-pe').style.background = on ? 'transparent' : '#fff';  $$('ec-pe').style.color = on ? '#94a3b8' : '#0f172a';
        $$('ec-ex').style.background = on ? '#6366f1' : 'transparent'; $$('ec-ex').style.color = on ? '#fff' : '#94a3b8';
        $$('ec-busq-lbl').textContent = on ? 'C.E. / Pasaporte (alfanumérico)' : 'Buscar: nombre, DNI (8) o RUC (11)';
        $$('ec-busq').placeholder = on ? 'N° de C.E. o Pasaporte' : 'nombre o documento';
        $$('ec-buscar').style.display = on ? 'none' : '';
        $$('ec-busq').value = ''; $$('ec-doc').value = ''; $$('ec-nom').value = ''; $$('ec-dir').value = '';
        $$('ec-x').style.display = 'none'; cerrarSugs(); refTipo(); validar();
      };
      bd.addEventListener('click', (ev) => {
        const tt = ev.target;
        if (tt === bd || (tt.closest && tt.closest('[data-cancel]'))) { cerrar(null); return; }
        if (tt.closest && tt.closest('#ec-pe')) { setExt(false); return; }
        if (tt.closest && tt.closest('#ec-ex')) { setExt(true); return; }
        if (tt.closest && tt.closest('#ec-x')) { $$('ec-busq').value=''; $$('ec-doc').value=''; $$('ec-x').style.display='none'; cerrarSugs(); refTipo(); validar(); try{$$('ec-busq').focus();}catch(_){} return; }
        if (tt.closest && tt.closest('#ec-buscar')) { ev.preventDefault(); lookup(); return; }
        const sg = tt.closest && tt.closest('.ec-sug');
        if (sg) { elegir(sg.getAttribute('data-doc'), sg.getAttribute('data-nom'), sg.getAttribute('data-dir')); return; }
        if (tt.closest && tt.closest('[data-ok]')) {
          const ti = refTipo();
          const doc = ($$('ec-doc').value || '').trim(), nom = ($$('ec-nom').value || '').trim();
          const dir = ($$('ec-dir').value || '').trim(), mot = ($$('ec-mot').value || '').trim();
          if (mot.length < 3 || (!doc && !nom)) return;
          try { _finBeep?.('success'); } catch(_){}
          cerrar({ doc, nombre: nom, direccion: dir, motivo: mot, tipoDoc: ti.cod });
        }
      });
      bd.addEventListener('input', (ev) => {
        if (ev.target.id === 'ec-busq') onBusq();
        else { if (ev.target.id === 'ec-doc') refTipo(); validar(); }
      });
      bd.addEventListener('keydown', (ev) => { if (ev.key === 'Escape') cerrar(null); });
      bd.addEventListener('blur', (ev) => { if (!ext && ev.target.id === 'ec-doc') { const ti = _tipoDe(ev.target.value); if (ti.cod === 1 || ti.cod === 6) lookup(); } }, true);
      document.body.appendChild(bd);
      requestAnimationFrame(() => bd.classList.add('is-open'));
      try { _finBeep?.('tap'); } catch(_){}
      setTimeout(() => { refTipo(); validar(); try { $$('ec-busq').focus(); } catch(_){} }, 220);
    });
  }

  async function _tkEditarClienteOpen(t) {
    const r = await _modalEditarCliente(t);
    if (!r) return;
    try {
      await API.post('meEditarCliente', {
        idVenta: t.idVenta,
        clienteDoc: r.doc,
        clienteNom: r.nombre,
        direccion: r.direccion,
        motivo: r.motivo,
        tipoDocCliente: r.tipoDoc   // explícito → soporta C.E. (4) / Pasaporte (7)
      });
      toast('✓ Cliente actualizado', 'success');
      await _cajasRefreshSilencioso?.();
      if (S.view === 'finanzas') finCargar?.();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  // ──────────────────────────────────────────────────────────
  // ANULAR VENTA INTERNA (sin afectar SUNAT)
  // ──────────────────────────────────────────────────────────
  async function _tkAnularSimple(t) {
    if (!await _modalConfirm(`¿Anular ${t.tipoDoc || 'ticket'} ${t.correlativo || t.idVenta}?\n\nMonto: S/ ${t.total.toFixed(2)}\n\nSi tiene CPE emitido, también debes solicitar la baja en SUNAT.`, { danger: true, titulo: 'Anular ticket', okText: 'Anular' })) return;
    try {
      await API.post('anularTicketME', { idVenta: t.idVenta });
      toast('✓ Ticket anulado', 'success');
      await _cajasRefreshSilencioso?.();
      if (S.view === 'finanzas') finCargar?.();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  // ──────────────────────────────────────────────────────────
  // HISTORIAL (timeline) — genérico para ticket/cliente/extra/personal
  // ──────────────────────────────────────────────────────────
  // Abre el modal de historial reusando #modalTkHistorial.
  // opts: { titulo, subtitulo, fetcher: () => Promise<historial[]|{historial:[]}> }
  async function _abrirHistorialGenerico(opts) {
    const tit = document.querySelector('#modalTkHistorial h2');
    if (tit) tit.textContent = opts.titulo || 'Historial';
    $('tkHistSub').textContent = opts.subtitulo || '—';
    $('tkHistBody').innerHTML = '<div class="text-center py-8 text-slate-500 text-xs">Cargando...</div>';
    openModal('modalTkHistorial');
    try {
      const data = await opts.fetcher();
      const hist = Array.isArray(data) ? data : (data?.historial || []);
      _tkHistRender(hist);
    } catch(e) {
      $('tkHistBody').innerHTML = `<div class="text-center py-8 text-rose-400 text-xs">Error: ${e.message}</div>`;
    }
  }

  function _tkHistorialOpen(t) {
    return _abrirHistorialGenerico({
      titulo:    'Historial del ticket',
      subtitulo: t.correlativo || t.idVenta,
      // [#4 Etapa 2 · cero-GAS] Supabase primero (me.historial_venta); GAS solo si no hay token/red.
      fetcher:   async () => (await API.meHistorialVentaDirecto(t.idVenta)) || API.get('meHistorialVenta', { idVenta: t.idVenta })
    });
  }

  function _tkHistorialClienteOpen(t) {
    if (!t.clienteDoc) { toast('El ticket no tiene cliente con documento', 'warning'); return; }
    return _abrirHistorialGenerico({
      titulo:    'Historial · Cliente',
      subtitulo: `${t.cliente || '—'} · ${t.clienteDoc}`,
      fetcher:   async () => (await API.meHistorialClienteDirecto(t.clienteDoc)) || API.get('meHistorialCliente', { doc: t.clienteDoc })
    });
  }

  function cjHistorialExtra(idExtra) {
    if (!idExtra) { toast('Extra sin id — no se puede consultar historial', 'warning'); return; }
    return _abrirHistorialGenerico({
      titulo:    'Historial · Movimiento extra',
      subtitulo: idExtra,
      fetcher:   () => API.get('meHistorialExtra', { idExtra })
    });
  }

  function cfgHistorialPersonal(idPersonal, nombre) {
    if (!idPersonal) return;
    return _abrirHistorialGenerico({
      titulo:    'Historial · Personal',
      subtitulo: (nombre || '—') + ' · ' + idPersonal,
      fetcher:   () => API.get('getHistorialPersonal', { idPersonal })
    });
  }

  function _tkHistRender(hist) {
    const body = $('tkHistBody');
    if (!body) return;
    if (!Array.isArray(hist) || !hist.length) {
      body.innerHTML = '<div class="text-center py-8 text-slate-500 text-xs italic">Sin eventos registrados.<br>Los cambios futuros se irán acumulando aquí.</div>';
      return;
    }
    const ordenada = hist.slice().reverse(); // más reciente arriba
    const fmtFecha = ts => {
      try {
        const d = new Date(ts);
        if (isNaN(d.getTime())) return ts;
        return d.toLocaleString('es-PE', { dateStyle: 'short', timeStyle: 'short' });
      } catch(_) { return ts; }
    };
    const claseAccion = a => {
      const ax = String(a || '').toLowerCase();
      if (ax.includes('crear') || ax.includes('alta')) return 'tk-hist-evt-create';
      if (ax.includes('cobr')) return 'tk-hist-evt-cobrar';
      if (ax.includes('anul') || ax.includes('baja')) return 'tk-hist-evt-anular';
      return 'tk-hist-evt-edit';
    };
    body.innerHTML = ordenada.map(ev => {
      const acc = ev.accion || ev.source || 'cambio';
      const fechaTxt = fmtFecha(ev.timestamp || ev.fecha || '');
      const cambios = Array.isArray(ev.cambios) ? ev.cambios : [];
      const cambiosHtml = cambios.length
        ? `<div class="tk-hist-evt-cambios">
            ${cambios.map(c => `<span class="tk-hist-evt-cambio"><b>${c.campo}</b>: <s>${c.antes || '—'}</s> → <em>${c.despues || '—'}</em></span>`).join('')}
          </div>`
        : '';
      const motivo = ev.motivo ? `<div class="tk-hist-evt-motivo">📝 ${ev.motivo}</div>` : '';
      const admin = ev.autorizadoPor?.nombre
        ? `<div class="tk-hist-evt-admin">PIN ADMIN · ${ev.autorizadoPor.nombre}</div>`
        : '';
      return `<div class="tk-hist-evt ${claseAccion(acc)}">
        <div class="tk-hist-evt-cabecera">
          <span class="tk-hist-evt-accion">${acc}</span>
          <span class="tk-hist-evt-fecha">${fechaTxt}</span>
        </div>
        <div class="tk-hist-evt-user">por ${ev.usuario || '—'}${ev.rol ? ' (' + ev.rol + ')' : ''}</div>
        ${cambiosHtml}
        ${motivo}
        ${admin}
      </div>`;
    }).join('');
  }

  // ── Abrir turno externo ─────────────────────────
  function cjAbrirTurno(idCaja) {
    _finBeep('click');
    window.open('./turno.html?idCaja=' + idCaja + '&api=' + encodeURIComponent(API.getUrl()), '_blank');
  }

  // ── [v41.3] Cerrar caja forzadamente desde MOS (admin/master) ─────
  // Pide PIN admin 8 dígitos, ejecuta el endpoint atómico de ME que:
  //   1. Anula POR_COBRAR de esa caja
  //   2. Calcula montoFinal automático (apertura + efectivo + ingresos - egresos)
  //   3. Marca CERRADA + montoFinal + fechaCierre con LockService
  //   4. Notifica al cajero original que su caja fue cerrada por admin
  // Resuelve el bug histórico de cierres incompletos sin atomicidad.
  async function cjCerrarCajaForzado(idCaja, nombreCajero) {
    _finBeep('click');
    if (!_esAdminOMaster()) {
      toast('Solo admin/master pueden cerrar caja forzadamente', 'error');
      return;
    }
    // Preview rápida: monto inicial + tickets + por cobrar
    const c = (S._todasCajas || []).find(x => String(x.idCaja) === String(idCaja));
    if (!c) { toast('Caja no encontrada', 'error'); return; }
    const preview = [
      `🔒 CERRAR CAJA FORZADAMENTE`,
      ``,
      `Cajero:        ${c.vendedor || '—'}`,
      `Zona/Estación: ${c.zona || c.estacion || '—'}`,
      `Apertura:      ${c.fechaApertura || '—'}`,
      `Monto inicial: S/ ${parseFloat(c.montoInicial || 0).toFixed(2)}`,
      ``,
      `Tickets:       ${c.tickets || 0}`,
      `Efectivo:      S/ ${parseFloat(c.efectivo || 0).toFixed(2)}`,
      `Por cobrar:    ${c.sinCobrar || 0}  ← vuelven a mesa créditos`,
      ``,
      `Efectivo esperado: S/ ${parseFloat(c.efectivoEsperado || 0).toFixed(2)}`,
      ``,
      `Se cerrará en ME y el cajero recibirá un push.`
    ].join('\n');
    if (!await _modalConfirm(preview, { danger: true, titulo: '🔐 Cerrar caja forzado', okText: 'Cerrar caja' })) return;

    // [v2.41.83] AdminAuthModal universal — tier 3 (sin cache, crítico)
    const auth = await pedirAuth({
      accion: 'CIERRE_CAJA_FORZADO',
      refDocumento: idCaja,
      contexto: `Cerrar caja de ${c.vendedor || '?'} (${c.zona || c.estacion || '—'})`
    });
    if (!auth) return;
    const clave = auth.clave;
    // Loading visual: deshabilitar botón
    const cardBtn = document.querySelector(`#cjcard-${idCaja} .cj-caja-btn-danger`);
    if (cardBtn) { cardBtn.disabled = true; cardBtn.textContent = '⌛ Cerrando...'; }
    try {
      const r = await API.post('meCerrarCajaForzado', {
        idCaja:     idCaja,
        claveAdmin: clave,
        motivo:     'Cierre forzado desde MOS/Cajas'
      });
      const d = (r && r.data) ? r.data : (r || {});
      if (!d.autorizado) {
        toast(d.error || 'Clave incorrecta', 'error');
        return;
      }
      try { _finBeep?.('success'); } catch(_){}
      let msg;
      if (d.yaCerrada) {
        // Caja ya estaba cerrada — reportar si se reparó la guía
        msg = d.guiaRegenerada
          ? `✓ Caja ya cerrada · Guía SALIDA_VENTAS regenerada (faltaba del cierre original)`
          : `✓ Caja ya estaba cerrada · Guía ya existía`;
      } else {
        // [v2.42.00] devueltosACredito reemplaza al legacy "anulados"
        const devN = d.devueltosACredito !== undefined ? d.devueltosACredito : (d.anulados || 0);
        const cobN = d.cobrosLiberados || 0;
        msg = [
          `🔒 Caja cerrada por ${d.cerradoPor || 'admin'}`,
          `Monto final: S/ ${parseFloat(d.montoFinal || 0).toFixed(2)}`,
          devN > 0
            ? `${devN} ticket(s) → mesa créditos${cobN ? ` · ${cobN} cobro(s) liberados` : ''}`
            : 'Sin POR_COBRAR pendientes'
        ].join(' · ');
      }
      toast(msg, 'success');
      // [v41.7] Disparar impresión del Ticket Z en la impresora original de
      // la caja. PrintNode_ID quedó guardado al abrir caja en CAJAS col 10.
      // Si no hay impresora asociada o la impresora está offline, avisamos
      // pero el cierre lógico ya quedó hecho.
      if (d.printNodeId) {
        try {
          const rImp = await API.post('imprimirTicketZCierre', {
            idCaja:    d.idCaja || idCaja,
            printerId: d.printNodeId,
            estacion:  d.estacion || ''
          });
          const dImp = (rImp && rImp.data) ? rImp.data : (rImp || {});
          if (dImp.ok) {
            setTimeout(() => toast('🖨 Ticket Z enviado a impresora de ' + (d.estacion || 'la caja'), 'success'), 600);
          } else {
            setTimeout(() => toast('⚠ Cierre OK · impresión falló: ' + (dImp.error || 'PrintNode rechazó'), 'warn'), 600);
          }
        } catch(eImp) {
          setTimeout(() => toast('⚠ Cierre OK · impresión falló: ' + (eImp.message || eImp), 'warn'), 600);
        }
      } else {
        setTimeout(() => toast('⚠ Cierre OK · sin impresora asociada a esta caja', 'warn'), 600);
      }
      // Refrescar lista de cajas para que la caja pase a CERRADA en la UI
      setTimeout(() => _cajasRefreshSilencioso?.(), 400);
    } catch(e) {
      toast('Error: ' + (e.message || e), 'error');
    } finally {
      if (cardBtn) { cardBtn.disabled = false; cardBtn.textContent = '🔒 Cerrar caja'; }
    }
  }

  // ── MODO TV fullscreen ──────────────────────────
  function cjModoTV(activar) {
    if (typeof activar === 'undefined') activar = !_cjState.tvActivo;
    _cjState.tvActivo = activar;
    document.body.classList.toggle('cj-modo-tv', activar);
    if (activar) {
      _finBeep('breakeven');
      try { document.documentElement.requestFullscreen?.(); } catch {}
      // Re-render para llenar el strip TV (Ranking/7d/Actividad duplicados)
      _cjRender();
      // Auto-actualización cada 15s en TV (más agresivo)
      if (_cjState.tvAutoTimer) clearInterval(_cjState.tvAutoTimer);
      _cjState.tvAutoTimer = setInterval(() => {
        if (typeof _cajasRefreshSilencioso === 'function') _cajasRefreshSilencioso();
      }, 15000);
    } else {
      _finBeep('click');
      try { if (document.fullscreenElement) document.exitFullscreen?.(); } catch {}
      if (_cjState.tvAutoTimer) { clearInterval(_cjState.tvAutoTimer); _cjState.tvAutoTimer = null; }
    }
  }

  // Atajo ESC para salir TV
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && _cjState.tvActivo) cjModoTV(false);
    if (S.view === 'cajas') {
      const tag = (document.activeElement?.tagName || '').toLowerCase();
      if (tag === 'input' || tag === 'textarea' || tag === 'select') return;
      if (e.key === 'ArrowLeft')  { e.preventDefault(); cjDia(-1); }
      if (e.key === 'ArrowRight') { e.preventDefault(); cjDia(+1); }
      if (e.key === ' ') { e.preventDefault(); cjIrHoy(); }
    }
  });

  // ── CAJAS ────────────────────────────────────────────────────
  async function loadCajas(force) {
    if (!force && S.loaded['cajas']) return;
    S.loaded['cajas'] = true;

    const loading  = $('cajasLoading');
    const content  = $('cajasContent');

    // Inicializar fecha del módulo si no está
    const inpF = $('cjFecha');
    if (inpF && !inpF.value) inpF.value = today();
    if (!_cjState.fecha) _cjState.fecha = inpF?.value || today();

    // Sonido al entrar al módulo
    _finBeep('nav');

    // [v41] Precarga de créditos pendientes en paralelo al fetch principal.
    // Así cuando se renderice la vista, las cartas ya están listas sin delay.
    if (!_cjCreditosState.todosLosGrupos.length) {
      _cjCargarCreditosPendientes();
    }

    // Datos en cache → render inmediato
    if (S._cajasLoaded && S._todasCajas) {
      loading?.classList.add('hidden');
      content?.classList.remove('hidden');
      _cjRender();
      if (force) _cajasRefreshSilencioso();
      return;
    }

    loading?.classList.remove('hidden');
    content?.classList.add('hidden');

    try {
      const res = await API.get('getCierresCaja', {});
      loading?.classList.add('hidden');
      content?.classList.remove('hidden');

      const { kpis, abiertas = [], cerradas = [], generadoEn, todosTickets: tkAll = [] } = res || {};
      const todayStr = today();
      S._cajasHoy = [
        ...abiertas,
        ...(cerradas || []).filter(c =>
          (c.fechaApertura || '').startsWith(todayStr) ||
          (c.fechaCierre   || '').startsWith(todayStr)
        )
      ];
      S._todasCajas = [...abiertas, ...cerradas];
      S._todosTickets = tkAll;
      _cjMergeHist();   // [fix bug] preservar días históricos jalados (no vaciar al recargar)
      S._cajasGenTs = generadoEn || '';
      S._cajasLoaded = true;

      _cjRender();
      _cjPulsoPoll();

    } catch(e) {
      loading?.classList.add('hidden');
      content?.classList.remove('hidden');
      const empty = $('cajasEmpty');
      empty?.classList.remove('hidden');
      if (empty) empty.innerHTML = `<div class="text-4xl mb-3">⚠️</div><div class="text-red-400 font-medium mb-1">Error al cargar</div><div class="text-xs text-slate-500">${e.message}</div>`;
      S.loaded['cajas'] = false;
    }
  }

  // ── Auto-refresh silencioso de cajas cada 60s ───────────────
  let _cajasRefreshTimer = null;

  // ── Construye el HTML de una card de caja abierta (LEGACY) ──
  // Reemplazado por _cjBuildCajaCard. Si algo aún llama a _buildCajaCard
  // (código viejo), redirigir al nuevo.
  function _buildCajaCard(c) {
    return _cjBuildCajaCard(c, c.estado === 'ABIERTA', _cjFecha());
  }
  function _buildCajaCardLegacy(c) {
    const elapsed   = _cajaElapsed(c.fechaApertura);
    const pctEfect  = c.totalVentas > 0 ? Math.round(c.efectivo / c.totalVentas * 100) : 0;
    const pctOtros  = 100 - pctEfect;
    const metodos   = Object.entries(c.byMetodo || {}).sort((a,b)=>b[1]-a[1])
      .map(([k,v])=>`<span class="text-xs text-slate-400">${k}: <span class="text-slate-200 font-medium">${fmtMoney(v)}</span></span>`).join('');
    const tkList    = c.ticketsList || [];
    const exList    = c.extrasList  || [];

    const estadoBadge = est => {
      if (est==='ANULADO')    return '<span class="badge badge-red" style="font-size:10px">ANULADO</span>';
      if (est==='POR_COBRAR') return '<span class="badge badge-yellow" style="font-size:10px">POR COBRAR</span>';
      if (est==='CREDITO')    return '<span class="badge badge-blue" style="font-size:10px">CRÉDITO</span>';
      return '';
    };
    const metodoBadge = m => {
      const cls = m==='EFECTIVO'?'badge-green':m==='POR_COBRAR'?'badge-yellow':m==='ANULADO'?'badge-red':'badge-blue';
      return `<span class="badge ${cls}" style="font-size:10px">${m}</span>`;
    };
    const ticketRows = tkList.map(t => {
      const an = t.estado==='ANULADO';
      return `<div class="flex items-center gap-2 py-1.5 border-b border-slate-800/60 ${an?'opacity-40':''}">
        <div class="flex-1 min-w-0">
          <div class="flex items-center gap-1.5 flex-wrap">
            <span class="text-xs font-mono ${an?'line-through text-slate-500':'text-slate-200'}">${t.correlativo||t.idVenta}</span>
            ${estadoBadge(t.estado)}
          </div>
          <div class="text-xs text-slate-500 truncate mt-0.5">${t.clienteNom||t.clienteDoc||'Sin cliente'} · <span class="text-slate-600">${t.tipoDoc}</span>${t.hora?' · '+t.hora:''}</div>
        </div>
        <div class="text-right shrink-0">
          <div class="text-sm font-semibold ${an?'line-through text-slate-600':'text-white'}">${fmtMoney(t.total)}</div>
          <div class="mt-0.5">${metodoBadge(t.metodo)}</div>
        </div>
      </div>`;
    }).join('');
    const extraRows = exList.map(ex=>`
      <div class="flex items-center justify-between py-1 text-xs border-b border-slate-800/40 last:border-0">
        <div class="flex items-center gap-1.5">
          <span class="${ex.tipo==='INGRESO'?'text-emerald-400':'text-red-400'} font-bold">${ex.tipo==='INGRESO'?'▲':'▼'}</span>
          <span class="text-slate-300">${ex.concepto||ex.tipo}</span>
          ${ex.hora?`<span class="text-slate-600">${ex.hora}</span>`:''}
        </div>
        <span class="font-semibold ${ex.tipo==='INGRESO'?'text-emerald-400':'text-red-400'}">${ex.tipo==='INGRESO'?'+':'-'}${fmtMoney(ex.monto)}</span>
      </div>`).join('');

    return `
    <div class="card p-4" id="cajacard-${c.idCaja}" style="border-left:3px solid #22c55e">
      <div class="flex items-start justify-between mb-3">
        <div>
          <div class="font-semibold text-white text-base">${c.vendedor||'—'}</div>
          <div class="text-xs text-slate-400">${c.zona||c.estacion||'—'} · <span class="text-emerald-400">⏱ ${elapsed}</span></div>
        </div>
        <span class="badge badge-green">ABIERTA</span>
      </div>
      <div class="grid grid-cols-4 gap-2 mb-3">
        <div class="card-sm p-2 text-center"><div id="cv-total-${c.idCaja}" class="text-base font-bold text-white">${fmtMoney(c.totalVentas)}</div><div class="text-xs text-slate-500">Total</div></div>
        <div class="card-sm p-2 text-center"><div id="cv-tickets-${c.idCaja}" class="text-base font-bold text-emerald-400">${c.tickets}</div><div class="text-xs text-slate-500">Tickets</div></div>
        <div class="card-sm p-2 text-center"><div id="cv-anulados-${c.idCaja}" class="text-base font-bold ${c.anulados>0?'text-red-400':'text-slate-500'}">${c.anulados}</div><div class="text-xs text-slate-500">Anulados</div></div>
        <div class="card-sm p-2 text-center"><div id="cv-porcobrar-${c.idCaja}" class="text-base font-bold ${c.sinCobrar>0?'text-yellow-400':'text-slate-500'}">${c.sinCobrar}</div><div class="text-xs text-slate-500">Por cobrar</div></div>
      </div>
      <div class="mb-2">
        <div class="flex justify-between text-xs text-slate-500 mb-1">
          <span id="cv-barlbl-${c.idCaja}">Efectivo ${pctEfect}%</span><span>Otros ${pctOtros}%</span>
        </div>
        <div class="flex rounded-full overflow-hidden h-1.5" style="background:#1e293b">
          <div id="cv-barefect-${c.idCaja}" style="width:${pctEfect}%;background:#22c55e;transition:width .5s"></div>
          <div id="cv-barotros-${c.idCaja}" style="width:${pctOtros}%;background:#6366f1;transition:width .5s"></div>
        </div>
      </div>
      <div id="cv-metodos-${c.idCaja}" class="flex flex-wrap gap-x-3 gap-y-1 mb-3">${metodos}</div>
      <button id="cajabtn-${c.idCaja}" onclick="MOS.toggleCajaDetail('${c.idCaja}')"
        class="w-full text-xs text-slate-400 py-1.5 rounded-lg border border-slate-800 hover:border-indigo-600 hover:text-indigo-400 transition-all flex items-center justify-center gap-1.5">
        <span id="cajabtn-icon-${c.idCaja}">▼</span>
        <span id="cajabtn-label-${c.idCaja}">Ver ${tkList.length} ticket${tkList.length!==1?'s':''}</span>
      </button>
      <div id="cajadetail-${c.idCaja}" class="hidden mt-3 pt-3 border-t border-slate-800">
        <div class="flex items-center justify-between mb-2">
          <span id="cajatickets-label-${c.idCaja}" class="text-xs font-semibold text-slate-400 uppercase tracking-wide">Tickets (${tkList.length})</span>
        </div>
        ${tkList.length>0?`<div class="mb-4">${ticketRows}</div>`:`<div class="text-xs text-slate-600 mb-4">Sin tickets aún</div>`}
        ${exList.length>0?`<div class="text-xs font-semibold text-slate-400 uppercase tracking-wide mb-2">Movimientos extra (${exList.length})</div><div class="card-sm p-2 mb-4">${extraRows}</div>`:''}
        <div class="card-sm p-3 text-xs">
          <div class="text-xs font-semibold text-slate-400 uppercase tracking-wide mb-2">Arqueo estimado</div>
          <div class="text-xs text-slate-500 mb-1">💵 Físico (en caja)</div>
          <div class="flex justify-between py-0.5"><span class="text-slate-500">Apertura</span><span>${fmtMoney(c.montoInicial)}</span></div>
          <div class="flex justify-between py-0.5"><span class="text-slate-500">+ Ventas efectivo</span><span class="text-emerald-400">+${fmtMoney(c.efectivo)}</span></div>
          ${c.entradas>0?`<div class="flex justify-between py-0.5"><span class="text-slate-500">+ Ingresos extra</span><span class="text-emerald-400">+${fmtMoney(c.entradas)}</span></div>`:''}
          ${c.salidas>0?`<div class="flex justify-between py-0.5"><span class="text-slate-500">- Salidas extra</span><span class="text-red-400">-${fmtMoney(c.salidas)}</span></div>`:''}
          <div class="flex justify-between font-bold border-t border-slate-700 pt-1.5 mt-1 mb-3">
            <span class="text-slate-200">= Esperado físico</span><span class="text-emerald-400">${fmtMoney(c.efectivoEsperado)}</span>
          </div>
          ${c.otros>0?`<div class="text-xs text-slate-500 mb-1">📲 Virtual</div>
          ${Object.entries(c.byMetodo||{}).filter(([k])=>k!=='EFECTIVO').sort((a,b)=>b[1]-a[1]).map(([k,v])=>`<div class="flex justify-between py-0.5"><span class="text-slate-500">${k}</span><span class="text-indigo-400">${fmtMoney(v)}</span></div>`).join('')}
          <div class="flex justify-between font-bold border-t border-slate-700 pt-1.5 mt-1"><span class="text-slate-200">= Total virtual</span><span class="text-indigo-400">${fmtMoney(c.otros)}</span></div>`:''}
        </div>
      </div>
    </div>`;
  }

  // Helper: actualizar texto de un elemento solo si cambió, con flash opcional
  function _setVal(id, newVal, flash) {
    const el = $(id); if (!el) return;
    const str = String(newVal);
    if (el.textContent === str) return;
    el.textContent = str;
    if (flash) { el.classList.remove('val-flash'); el.offsetHeight; el.classList.add('val-flash'); }
  }

  // Smart update de una card de caja abierta (solo toca los valores que cambiaron)
  function _updateCajaCard(c) {
    const card = $('cajacard-' + c.idCaja);
    if (!card) return false; // no existe → hay que crearla
    const pct  = c.totalVentas > 0 ? Math.round(c.efectivo / c.totalVentas * 100) : 0;
    const metosHtml = Object.entries(c.byMetodo || {}).sort((a,b)=>b[1]-a[1])
      .map(([k,v])=>`<span class="text-xs text-slate-400">${k}: <span class="text-slate-200 font-medium">${fmtMoney(v)}</span></span>`).join('');

    _setVal('cv-total-'    + c.idCaja, fmtMoney(c.totalVentas), true);
    _setVal('cv-tickets-'  + c.idCaja, c.tickets, true);
    _setVal('cv-anulados-' + c.idCaja, c.anulados, c.anulados > 0);
    _setVal('cv-porcobrar-'+ c.idCaja, c.sinCobrar, c.sinCobrar > 0);

    const barEf = $('cv-barefect-' + c.idCaja);
    const barOt = $('cv-barotros-' + c.idCaja);
    if (barEf) barEf.style.width = pct + '%';
    if (barOt) barOt.style.width = (100-pct) + '%';
    _setVal('cv-barlbl-'   + c.idCaja, `Efectivo ${pct}%`);

    const metDiv = $('cv-metodos-' + c.idCaja);
    if (metDiv && metDiv.innerHTML !== metosHtml) metDiv.innerHTML = metosHtml;

    // Actualizar elapsed (siempre cambia)
    const cabeceraEl = card.querySelector('.text-xs.text-slate-400');
    if (cabeceraEl) {
      const el = cabeceraEl.querySelector('span.text-emerald-400');
      if (el) el.textContent = '⏱ ' + _cajaElapsed(c.fechaApertura);
    }
    return true;
  }

  // Smart update del historial (filas cerradas)
  function _updateHistorialRow(c) {
    const row = document.querySelector('[data-caja-row="' + c.idCaja + '"]');
    if (!row) return false;
    _setVal('hr-total-'   + c.idCaja, fmtMoney(c.totalVentas), true);
    _setVal('hr-tickets-' + c.idCaja, c.tickets, true);
    return true;
  }

  // [v2.41.91] Snapshot del esperado por caja para detectar cruces de hitos
  if (typeof window._cjBalancePrev === 'undefined') window._cjBalancePrev = {};
  const HITOS_MARKS = [500, 1000, 2000, 3000, 5000];

  function _cjDetectarHitos(abiertasActual) {
    abiertasActual.forEach(c => {
      const id = String(c.idCaja || '');
      if (!id) return;
      const actual = parseFloat(c.efectivoEsperado) || 0;
      const previo = window._cjBalancePrev[id] || 0;
      window._cjBalancePrev[id] = actual;
      // Detectar cruces de hito (sube de previo<H a actual>=H)
      HITOS_MARKS.forEach(mark => {
        if (previo > 0 && previo < mark && actual >= mark) {
          _cjCelebrarHito(c, mark);
        }
      });
      // Animar monto (clase .bump) si cambió
      if (Math.abs(actual - previo) >= 0.01 && previo > 0) {
        setTimeout(() => {
          const card = document.getElementById('cjcard-' + id.replace(/'/g, '&#39;'));
          if (card) {
            const monto = card.querySelector('.cj-balance-live-monto');
            if (monto) {
              monto.classList.remove('bump');
              void monto.offsetWidth; // force reflow
              monto.classList.add('bump');
            }
          }
        }, 100);
      }
    });
  }

  function _cjCelebrarHito(c, mark) {
    try { _finBeep && _finBeep('jackpot'); } catch(_) {
      try { _finBeep && _finBeep('success'); } catch(__) {}
    }
    // Confetti micro en la card del cajero
    setTimeout(() => {
      const card = document.getElementById('cjcard-' + String(c.idCaja || '').replace(/'/g, '&#39;'));
      if (!card) return;
      // 18 partículas de confetti animadas
      for (let i = 0; i < 18; i++) {
        const conf = document.createElement('div');
        conf.className = 'cj-confetti-particle';
        conf.style.left = (50 + (Math.random() - 0.5) * 60) + '%';
        conf.style.background = ['#fbbf24','#34d399','#22d3ee','#ec4899','#a78bfa','#f97316'][i % 6];
        conf.style.setProperty('--dx', ((Math.random() - 0.5) * 220) + 'px');
        conf.style.setProperty('--dy', (140 + Math.random() * 160) + 'px');
        conf.style.animationDelay = (Math.random() * .25) + 's';
        card.appendChild(conf);
        setTimeout(() => { try { conf.remove(); } catch(_){} }, 2400);
      }
    }, 100);
    if (typeof toast === 'function') {
      toast(`🎉 ${c.vendedor || 'Cajero'} cruzó S/ ${mark.toLocaleString('es-PE')}`, 'success');
    }
  }

  async function _cajasRefreshSilencioso() {
    if (!API.isConfigured()) return;
    iconBusy('cajas', true);
    try {
      const res = await API.get('getCierresCaja', {});
      const { abiertas = [], cerradas = [], todosTickets: tkAll = [], generadoEn } = res || {};
      const todayStr = today();
      // Detectar tickets nuevos comparando con cache previo
      const prevIds = new Set((S._todosTickets || []).map(t => t.idVenta));
      const nuevos = (tkAll || []).filter(t => !prevIds.has(t.idVenta));
      S._todosTickets = tkAll;
      S._cajasHoy = [...abiertas, ...(cerradas || []).filter(c =>
        (c.fechaApertura || '').startsWith(todayStr) || (c.fechaCierre || '').startsWith(todayStr))];
      S._todasCajas  = [...abiertas, ...cerradas];
      _cjMergeHist();   // [fix bug] re-inyectar histórico tras la recarga
      S._cajasLoaded = true;
      S._cajasGenTs  = generadoEn || '';
      // [v2.41.91] Detectar cruces de hitos antes de re-renderizar
      _cjDetectarHitos(abiertas);
      if (S.view === 'cajas') {
        _cjRender();
        _cjPulsoPoll();
        const modalTk = $('cjModalTickets');
        if (modalTk && !modalTk.classList.contains('hidden')) _cjTkRender();
        // Sonido sutil si hay tickets nuevos
        if (nuevos.length > 0 && prevIds.size > 0) _finBeep('click');
        // [v41] Refresh paralelo de créditos: si hay uno nuevo, _cjPintarCartasMano
        // lo detecta vía idsVistos y lo anima con cj-carta-nueva.
        _cjCargarCreditosPendientes();
      }
    } catch(e) { console.warn('[CajasRefresh]', e.message); }
    finally { iconBusy('cajas', false); }
  }

  function _startCajasRefresh() {
    _stopCajasRefresh();
    _cajasRefreshSilencioso(); // fetch inmediato
    _cajasRefreshTimer = setInterval(_cajasRefreshSilencioso, 20000);
  }
  function _stopCajasRefresh() {
    if (_cajasRefreshTimer) { clearInterval(_cajasRefreshTimer); _cajasRefreshTimer = null; }
  }

  // ── Charts de cajas ─────────────────────────────────────────
  const _CHART_COLORES = ['#6366f1','#f59e0b','#0ea5e9','#a855f7','#ef4444','#14b8a6','#f97316'];
  let _chartCajasPeriodo      = 7;
  let _chartCajasModalPeriodo = 7;

  function _cajasFiltradas(dias) {
    const todas  = S._todasCajas || [];
    const desde  = _fechaOffset(today(), -dias);
    return todas.filter(c =>
      (c.fechaApertura || '').substring(0, 10) >= desde ||
      (c.fechaCierre   || '').substring(0, 10) >= desde
    );
  }

  // Chart compacto: barras verticales, eje X = cajeros, agrupado por vendedor
  function _renderChartCajasCompacto(dias) {
    const cajas    = _cajasFiltradas(dias);
    const hoy      = today();
    const byVend   = {};
    cajas.forEach(c => {
      const k = c.vendedor || c.idCaja;
      if (!byVend[k]) byVend[k] = { total: 0, active: false };
      byVend[k].total += c.totalVentas;
      if (c.estado === 'ABIERTA') byVend[k].active = true;
    });
    const labels = Object.keys(byVend);
    const data   = labels.map(k => Math.round(byVend[k].total * 100) / 100);
    const colors = labels.map(k => byVend[k].active ? '#22c55e' : '#6366f1');

    renderChart('chartCajasBars', {
      type: 'bar',
      data: { labels, datasets: [{ data, backgroundColor: colors, borderRadius: 5, barThickness: 32 }] },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              title: ctx => ctx[0].label,
              label: ctx => ` S/. ${ctx.raw.toFixed(2)}`,
              afterLabel: ctx => {
                const v    = labels[ctx.dataIndex];
                const cajs = _cajasFiltradas(dias).filter(c => (c.vendedor || c.idCaja) === v);
                const ef   = cajs.reduce((s,c) => s + c.efectivo, 0);
                const virt = cajs.reduce((s,c) => s + c.otros, 0);
                const tk   = cajs.reduce((s,c) => s + c.tickets, 0);
                return [` Efectivo: S/.${ef.toFixed(2)}`, ` Virtual:  S/.${virt.toFixed(2)}`, ` Tickets: ${tk}`];
              }
            }
          }
        },
        scales: {
          y: { ticks: { callback: v => 'S/' + v, font: { size: 10 }, color: '#64748b' }, grid: { color: '#1e293b' } },
          x: { ticks: { font: { size: 11 }, color: '#94a3b8' }, grid: { display: false } }
        }
      }
    });
  }

  // Chart modal: barras apiladas, eje X = fechas (días), por cajero
  function _renderChartCajasModal(dias) {
    const cajas  = _cajasFiltradas(dias);
    const hoy    = today();

    // Generar rango de fechas
    const dates = [];
    for (let d = dias - 1; d >= 0; d--) {
      dates.push(_fechaOffset(today(), -d));
    }

    // Cajas por fecha
    const cajasByDate = {};
    cajas.forEach(c => {
      const f = (c.fechaApertura || c.fechaCierre || '').substring(0, 10);
      if (!cajasByDate[f]) cajasByDate[f] = [];
      cajasByDate[f].push(c);
    });

    // Vendedores únicos
    const vendedores = [...new Set(cajas.map(c => c.vendedor || c.idCaja))];

    const datasets = vendedores.map((v, i) => ({
      label: v,
      data: dates.map(d => {
        const cs = (cajasByDate[d] || []).filter(c => (c.vendedor || c.idCaja) === v);
        return Math.round(cs.reduce((s,c) => s + c.totalVentas, 0) * 100) / 100;
      }),
      backgroundColor: dates.map(d => {
        if (d !== hoy) return _CHART_COLORES[i % _CHART_COLORES.length] + '99';
        const cs = (cajasByDate[d] || []).filter(c => (c.vendedor || c.idCaja) === v);
        return cs.some(c => c.estado === 'ABIERTA') ? '#22c55e' : _CHART_COLORES[i % _CHART_COLORES.length];
      }),
      borderRadius: 3,
      stack: 'cajas'
    }));

    renderChart('chartCajasModal', {
      type: 'bar',
      data: {
        labels: dates.map(d => {
          const day = parseInt(d.substring(8));
          return d === hoy ? day + '*' : String(day);
        }),
        datasets
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { position: 'bottom', labels: { font:{ size:10 }, padding:8, boxWidth:10, color:'#94a3b8' } },
          tooltip: {
            mode: 'index', intersect: false,
            callbacks: {
              title: ctx => {
                const d = dates[ctx[0].dataIndex];
                return d === hoy ? `Hoy ${d}` : d;
              },
              label: ctx => ctx.raw > 0 ? ` ${ctx.dataset.label}: ${fmtMoney(ctx.raw)}` : null,
              footer: ctx => {
                const total = ctx.reduce((s,c) => s + c.raw, 0);
                return total > 0 ? `Total del día: ${fmtMoney(total)}` : '';
              }
            }
          }
        },
        scales: {
          y: { stacked: true, ticks: { callback: v => 'S/' + v, font:{ size:10 }, color:'#64748b' }, grid:{ color:'#1e293b' } },
          x: { stacked: true, ticks: { font:{ size:11 }, color:'#94a3b8' }, grid:{ display:false } }
        }
      }
    });
  }

  function _renderChartMetodosHoy() {
    const hoy      = today();
    const cajasHoy = (S._todasCajas || []).filter(c =>
      (c.fechaApertura || '').startsWith(hoy) || (c.fechaCierre || '').startsWith(hoy)
    );
    const metAcum  = {};
    cajasHoy.forEach(c => Object.entries(c.byMetodo || {}).forEach(([k,v]) => {
      metAcum[k] = (metAcum[k] || 0) + v;
    }));
    const metKeys  = Object.keys(metAcum).sort((a,b) => metAcum[b] - metAcum[a]);
    const totalMet = metKeys.reduce((s,k) => s + metAcum[k], 0);
    if (!metKeys.length) return;

    renderChart('chartCajasMetodo', {
      type: 'doughnut',
      data: {
        labels: metKeys,
        datasets: [{ data: metKeys.map(k => metAcum[k]),
          backgroundColor: _CHART_COLORES, borderWidth: 2, borderColor: '#0f172a', hoverOffset: 6 }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: { callbacks: {
            label: ctx => ` ${ctx.label}: ${fmtMoney(ctx.raw)} (${Math.round(ctx.raw / totalMet * 100)}%)`
          }}
        }
      }
    });

    const det = $('cajasMetodoDetalle');
    if (det) det.innerHTML = metKeys.map((k, i) => `
      <div class="flex items-center justify-between text-xs">
        <div class="flex items-center gap-1.5">
          <span class="inline-block w-2.5 h-2.5 rounded-sm shrink-0" style="background:${_CHART_COLORES[i] || '#64748b'}"></span>
          <span class="text-slate-400">${k}</span>
        </div>
        <div class="flex items-center gap-2">
          <span class="text-slate-500">${Math.round(metAcum[k] / totalMet * 100)}%</span>
          <span class="font-semibold text-white">${fmtMoney(metAcum[k])}</span>
        </div>
      </div>`).join('');
  }

  function setChartCajasPeriodo(dias) {
    _chartCajasPeriodo = dias;
    [7, 30, 90].forEach(d => {
      const el = $('ccp' + d); if (el) el.classList.toggle('active', d === dias);
    });
    _renderChartCajasCompacto(dias);
  }

  function setChartCajasModalPeriodo(dias) {
    _chartCajasModalPeriodo = dias;
    [7, 30, 90].forEach(d => {
      const el = $('ccm' + d); if (el) el.classList.toggle('active', d === dias);
    });
    _renderChartCajasModal(dias);
  }

  function abrirModalHistorialCajas() {
    const modal = $('modalHistorialCajas'); if (!modal) return;
    modal.classList.remove('hidden');
    setTimeout(() => _renderChartCajasModal(_chartCajasModalPeriodo), 50);
  }

  function cerrarModalHistorialCajas() {
    const modal = $('modalHistorialCajas'); if (modal) modal.classList.add('hidden');
  }

  // ── Historial de tickets ────────────────────────────────────
  let _tkFiltroFecha  = 'hoy';
  let _tkFiltroEstado = '';
  let _tkFiltroTipo   = '';
  let _modalTicketId  = null;

  function toggleKpiTickets() {
    const panel = $('cajasTicketsPanel');
    const arrow = $('cajasKpiTicketsArrow');
    if (!panel) return;
    const opening = panel.classList.contains('hidden');
    panel.classList.toggle('hidden', !opening);
    if (arrow) arrow.textContent = opening ? '▲' : '▼';
    if (opening) _renderTicketList();
  }

  function setTicketFiltroFecha(v) {
    _tkFiltroFecha = v;
    ['hoy','semana','mes','todos'].forEach(k => {
      const el = $('tf' + k.charAt(0).toUpperCase() + k.slice(1));
      if (el) el.classList.toggle('active', k === v);
    });
    _renderTicketList();
  }

  function setTicketFiltroEstado(v) {
    _tkFiltroEstado = v;
    _tkFiltroTipo   = '';
    ['All','Com','Pend','Anu'].forEach(k => { const el=$('te'+k); if(el) el.classList.remove('active'); });
    ['NV','B','F'].forEach(k => { const el=$('tt'+k); if(el) el.classList.remove('active'); });
    const map = {'':'All','COMPLETADO':'Com','POR_COBRAR':'Pend','ANULADO':'Anu'};
    const el = $('te' + (map[v] || 'All')); if(el) el.classList.add('active');
    _renderTicketList();
  }

  function setTicketFiltroTipo(v) {
    _tkFiltroTipo   = v;
    _tkFiltroEstado = '';
    ['All','Com','Pend','Anu'].forEach(k => { const el=$('te'+k); if(el) el.classList.remove('active'); });
    ['NV','B','F'].forEach(k => { const el=$('tt'+k); if(el) el.classList.remove('active'); });
    const el = $('tt' + v); if(el) el.classList.add('active');
    _renderTicketList();
  }

  function _renderTicketList() {
    const container = $('cajasTicketsList');
    if (!container) return;
    const hoy    = today();
    const semana = _fechaOffset(today(), -7);
    const mes    = _fechaOffset(today(), -30);
    const desde  = _tkFiltroFecha === 'hoy' ? hoy : _tkFiltroFecha === 'semana' ? semana : _tkFiltroFecha === 'mes' ? mes : '0000-00-00';

    let lista = (S._todosTickets || []).filter(t => {
      if (t.fecha < desde) return false;
      if (_tkFiltroEstado && t.estado !== _tkFiltroEstado) return false;
      if (_tkFiltroTipo   && t.tipo   !== _tkFiltroTipo)   return false;
      return true;
    });

    if (!lista.length) {
      container.innerHTML = '<div class="text-xs text-slate-600 py-4 text-center">Sin tickets para los filtros seleccionados</div>';
      return;
    }

    const metodoBadge = m => {
      const cls = m === 'EFECTIVO' ? 'badge-green' : m === 'POR_COBRAR' ? 'badge-yellow' : m === 'ANULADO' ? 'badge-red' : 'badge-blue';
      return `<span class="badge ${cls}" style="font-size:10px">${m}</span>`;
    };
    const estadoIcon = s => s === 'ANULADO' ? '🚫' : s === 'POR_COBRAR' ? '⏳' : s === 'CREDITO' ? '💳' : '✅';
    const tipoIcon   = t => t === 'F' ? '📋' : t === 'B' ? '📄' : '🧾';

    container.innerHTML = lista.map(t => {
      const anulado = t.estado === 'ANULADO';
      const label   = t.correlativo || t.idVenta;
      const esHoy   = t.fecha === hoy;
      const fechaStr = esHoy ? `hoy ${t.hora}` : `${t.fecha} ${t.hora}`;
      return `
      <div data-ticket-id="${t.idVenta}" class="border-b border-slate-800/60 py-2.5 ${anulado ? 'opacity-50' : ''}">
        <div class="flex items-start justify-between gap-2">
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-1.5 flex-wrap">
              <span class="text-sm">${tipoIcon(t.tipo)}</span>
              <span class="text-xs font-mono font-semibold ${anulado ? 'line-through text-slate-500' : 'text-slate-200'}">${label}</span>
              <span class="text-xs text-slate-600">${fechaStr}</span>
            </div>
            <div class="text-xs text-slate-500 mt-0.5 truncate">
              ${estadoIcon(t.estado)} ${t.vendedor || '—'} · ${t.zona || '—'}
              ${t.clienteNom ? ' · ' + t.clienteNom : t.clienteDoc ? ' · ' + t.clienteDoc : ''}
            </div>
          </div>
          <div class="text-right shrink-0">
            <div class="text-sm font-bold ${anulado ? 'line-through text-slate-600' : 'text-white'}">${fmtMoney(t.total)}</div>
            <div class="mt-0.5">${metodoBadge(t.metodo)}</div>
          </div>
        </div>
        <!-- Botones de acción -->
        ${!anulado ? `
        <div class="flex gap-1.5 mt-1.5">
          <button onclick="MOS.confirmarAnularTicket('${t.idVenta}','${label}')"
            class="text-xs px-2.5 py-1 rounded-md border border-red-900/50 text-red-400 hover:bg-red-900/20 transition-colors">
            🚫 Anular
          </button>
          <button onclick="MOS.abrirModalMetodo('${t.idVenta}','${label}','${t.metodo}',${t.total})"
            class="text-xs px-2.5 py-1 rounded-md border border-slate-700 text-slate-400 hover:border-indigo-600 hover:text-indigo-400 transition-colors">
            💳 Cambiar método
          </button>
        </div>` : ''}
      </div>`;
    }).join('');
  }

  async function confirmarAnularTicket(idVenta, label, desdeModal) {
    if (!idVenta) { toast('ID de ticket inválido', 'error'); return; }
    if (!await _modalConfirm(`¿Anular el ticket ${label}?\n\nEsta acción no se puede deshacer.`, { danger: true, titulo: 'Anular ticket', okText: 'Anular' })) return;
    if (desdeModal) cerrarModalMetodo();
    const id = String(idVenta).trim();
    try {
      await API.post('anularTicketME', { idVenta: id });
      toast('Ticket anulado', 'ok');
      // Actualizar local inmediatamente
      if (S._todosTickets) {
        S._todosTickets.forEach(t => {
          if (String(t.idVenta).trim() === id) { t.metodo = 'ANULADO'; t.estado = 'ANULADO'; }
        });
      }
      _renderTicketList();
      setTimeout(() => _cajasRefreshSilencioso(), 1000);
    } catch(e) { toast(e.message, 'error'); }
  }

  // ── Modal cambiar método (replica flujo ME) ─────────────────
  let _modalTicketTotal  = 0;
  let _modalMetodoSel    = 'EFECTIVO';
  let _modalLabel        = '';

  function abrirModalMetodo(idVenta, label, metodoActual, total) {
    if (!idVenta) { toast('ID de ticket inválido', 'error'); return; }
    _modalTicketId    = String(idVenta).trim();
    _modalLabel       = label || idVenta;
    _modalTicketTotal = parseFloat(total) || 0;
    // Si no viene total buscar en S._todosTickets
    if (!_modalTicketTotal) {
      const tk = (S._todosTickets || []).find(t => String(t.idVenta).trim() === _modalTicketId);
      if (tk) _modalTicketTotal = tk.total;
    }
    _modalMetodoSel = metodoActual === 'POR_COBRAR' ? 'EFECTIVO' : (metodoActual || 'EFECTIVO');
    _renderModalMetodo();
    const modal = $('modalCambiarMetodo');
    if (modal) modal.classList.remove('hidden');
  }

  function _renderModalMetodo() {
    const box = $('modalCambiarMetodoBox');
    if (!box) return;
    const total = _modalTicketTotal;
    const sel   = _modalMetodoSel;

    // Sección dinámica según método seleccionado
    let seccion = '';
    if (sel === 'MIXTO') {
      const virt = parseFloat($('mmVirtual')?.value) || 0;
      const efec = Math.max(0, total - virt);
      const valido = virt > 0 && virt < total;
      seccion = `
        <div class="mt-3 space-y-2">
          <div>
            <label class="lbl text-sky-400">📲 Monto virtual (S/.)</label>
            <input id="mmVirtual" type="number" step="0.10" min="0.01" max="${(total - 0.01).toFixed(2)}"
              placeholder="0.00" value="${virt || ''}"
              oninput="MOS._onMixtoInput()"
              class="inp text-center text-xl font-bold" style="border-color:#7c3aed">
            ${virt > 0 && virt >= total ? '<p class="text-xs text-amber-400 mt-1">El monto virtual cubre el total — usa VIRTUAL</p>' : ''}
          </div>
          <div class="flex justify-between items-center px-1 py-1.5 rounded-lg" style="background:#0d1526">
            <span class="text-sm text-slate-400">💵 Efectivo</span>
            <span class="text-lg font-bold ${efec > 0 ? 'text-emerald-400' : 'text-slate-600'}">S/. ${efec.toFixed(2)}</span>
          </div>
          <button onclick="MOS.aplicarCambioMetodo('MIXTO')" ${!valido ? 'disabled' : ''}
            class="w-full py-3.5 rounded-xl font-bold text-sm transition-all ${valido ? 'bg-purple-600 hover:bg-purple-500 text-white' : 'bg-slate-800 text-slate-600 cursor-not-allowed'}">
            Confirmar MIXTO · S/. ${total.toFixed(2)}
          </button>
        </div>`;
    } else if (sel === 'EFECTIVO') {
      seccion = `
        <div class="mt-3">
          <div class="flex justify-between items-center px-3 py-3 rounded-xl mb-3" style="background:#0d1526">
            <span class="text-slate-400">💵 Cobrar en efectivo</span>
            <span class="text-xl font-bold text-emerald-400">S/. ${total.toFixed(2)}</span>
          </div>
          <button onclick="MOS.aplicarCambioMetodo('EFECTIVO')"
            class="w-full py-3.5 rounded-xl font-bold text-sm bg-emerald-700 hover:bg-emerald-600 text-white transition-all">
            Confirmar EFECTIVO · S/. ${total.toFixed(2)}
          </button>
        </div>`;
    } else { // VIRTUAL
      seccion = `
        <div class="mt-3">
          <div class="flex justify-between items-center px-3 py-3 rounded-xl mb-3" style="background:#0d1526">
            <span class="text-slate-400">📲 Cobro virtual</span>
            <span class="text-xl font-bold text-sky-400">S/. ${total.toFixed(2)}</span>
          </div>
          <button onclick="MOS.aplicarCambioMetodo('VIRTUAL')"
            class="w-full py-3.5 rounded-xl font-bold text-sm bg-sky-700 hover:bg-sky-600 text-white transition-all">
            Confirmar VIRTUAL · S/. ${total.toFixed(2)}
          </button>
        </div>`;
    }

    const metodoBtns = ['EFECTIVO','VIRTUAL','MIXTO'].map(m => {
      const cfg = { EFECTIVO:{icon:'💵',active:'border-emerald-500 text-emerald-400 bg-emerald-900/20'},
                    VIRTUAL: {icon:'📲',active:'border-sky-500 text-sky-400 bg-sky-900/20'},
                    MIXTO:   {icon:'🔀',active:'border-purple-500 text-purple-400 bg-purple-900/20'} }[m];
      const cls = (m === sel) ? cfg.active : 'border-slate-700 text-slate-500 hover:border-slate-500 hover:text-slate-300';
      return `<button onclick="MOS._selMetodo('${m}')"
        class="flex flex-col items-center justify-center gap-1.5 py-4 rounded-xl border-2 transition-all ${cls}">
        <span class="text-xl">${cfg.icon}</span>
        <span class="text-xs font-bold tracking-wide">${m}</span>
      </button>`;
    }).join('');

    box.innerHTML = `
      <div class="flex items-center justify-between mb-3">
        <div>
          <div class="font-semibold text-slate-200">Cambiar método de pago</div>
          <div class="text-xs text-slate-500 mt-0.5 font-mono">${_modalLabel}</div>
        </div>
        <button onclick="MOS.cerrarModalMetodo()" class="text-slate-600 hover:text-slate-300 text-xl leading-none">✕</button>
      </div>

      <!-- Total prominente -->
      <div class="rounded-xl p-3 mb-4 text-center" style="background:#0d1526;border:1px solid #1e293b">
        <div class="text-xs text-slate-500 uppercase tracking-widest mb-1">Total a cobrar</div>
        <div class="text-3xl font-black text-white">S/. ${total.toFixed(2)}</div>
      </div>

      <!-- 3 botones método -->
      <div class="grid grid-cols-3 gap-2">${metodoBtns}</div>

      <!-- Sección dinámica -->
      ${seccion}

      <!-- Anular -->
      <div class="mt-3 pt-3 border-t border-slate-800">
        <button onclick="MOS.confirmarAnularTicket('${_modalTicketId}','${_modalLabel}',true)"
          class="w-full py-2.5 rounded-xl text-sm font-semibold border border-red-900/50 text-red-400 hover:bg-red-900/20 transition-all">
          🚫 Anular ticket
        </button>
      </div>`;
  }

  function _selMetodo(m) {
    _modalMetodoSel = m;
    _renderModalMetodo();
    // Focus en input virtual si es MIXTO
    if (m === 'MIXTO') setTimeout(() => $('mmVirtual')?.focus(), 50);
  }

  function _onMixtoInput() { _renderModalMetodo(); }

  function cerrarModalMetodo() {
    const modal = $('modalCambiarMetodo'); if (modal) modal.classList.add('hidden');
    _modalTicketId = null;
  }

  async function aplicarCambioMetodo(metodo) {
    if (!_modalTicketId) return;
    const id = _modalTicketId;
    cerrarModalMetodo();
    try {
      await API.post('cambiarMetodoME', { idVenta: id, metodo });
      toast('Método actualizado: ' + metodo, 'ok');
      if (S._todosTickets) {
        S._todosTickets.forEach(t => {
          if (String(t.idVenta).trim() === id) { t.metodo = metodo; t.estado = 'COMPLETADO'; }
        });
      }
      _renderTicketList();
      setTimeout(() => _cajasRefreshSilencioso(), 1200);
    } catch(e) { toast(e.message, 'error'); }
  }

  function toggleKpiVentas() {
    const panel = $('cajasKpiDetalle');
    const arrow = $('cajasKpiVentasArrow');
    if (!panel) return;
    const opening = panel.classList.contains('hidden');
    panel.classList.toggle('hidden', !opening);
    if (arrow) arrow.textContent = opening ? '▲' : '▼';
    if (!opening) return; // solo renderiza al abrir

    const cajas = S._cajasHoy || [];
    const body  = $('cajasKpiDetalleBody');
    if (!body) return;

    if (!cajas.length) {
      body.innerHTML = '<div class="text-xs text-slate-500">Sin cajas registradas hoy.</div>';
      return;
    }

    body.innerHTML = cajas.map(c => {
      const esAbierta  = c.estado === 'ABIERTA';
      const badgeCls   = esAbierta ? 'badge-green' : 'badge-gray';
      const badgeTxt   = esAbierta ? 'ABIERTA' : 'CERRADA';
      const horaApert  = (c.fechaApertura || '').substring(11, 16);
      const horaCierre = (c.fechaCierre   || '').substring(11, 16);
      const rango      = horaCierre ? `${horaApert} → ${horaCierre}` : `desde ${horaApert}`;

      // Métodos virtuales (no efectivo)
      const virtuales = Object.entries(c.byMetodo || {}).filter(([k]) => k !== 'EFECTIVO').sort((a,b) => b[1]-a[1]);

      return `
      <div class="border-b border-slate-800 py-3 last:border-0">
        <!-- Cabecera caja -->
        <div class="flex items-center justify-between mb-2">
          <div class="flex items-center gap-2">
            <span class="badge ${badgeCls} text-xs">${badgeTxt}</span>
            <span class="font-medium text-sm text-white">${c.vendedor || '—'}</span>
            <span class="text-xs text-slate-500">${c.zona || c.estacion || ''}</span>
          </div>
          <span class="text-xs text-slate-600">${rango}</span>
        </div>

        <div class="grid grid-cols-1 sm:grid-cols-2 gap-2 text-xs">
          <!-- Físico -->
          <div class="card-sm p-2">
            <div class="text-slate-500 mb-1">💵 Físico</div>
            <div class="flex justify-between py-0.5"><span class="text-slate-500">Apertura</span><span>${fmtMoney(c.montoInicial)}</span></div>
            <div class="flex justify-between py-0.5"><span class="text-slate-500">+ Efectivo ventas</span><span class="text-emerald-400">+${fmtMoney(c.efectivo)}</span></div>
            ${c.entradas > 0 ? `<div class="flex justify-between py-0.5"><span class="text-slate-500">+ Ingresos extra</span><span class="text-emerald-400">+${fmtMoney(c.entradas)}</span></div>` : ''}
            ${c.salidas  > 0 ? `<div class="flex justify-between py-0.5"><span class="text-slate-500">- Salidas extra</span><span class="text-red-400">-${fmtMoney(c.salidas)}</span></div>` : ''}
            <div class="flex justify-between font-bold border-t border-slate-700 pt-1 mt-1">
              <span class="text-slate-300">Esperado físico</span>
              <span class="text-emerald-400">${fmtMoney(c.efectivoEsperado)}</span>
            </div>
          </div>

          <!-- Virtual -->
          <div class="card-sm p-2">
            <div class="text-slate-500 mb-1">📲 Virtual</div>
            ${virtuales.length > 0
              ? virtuales.map(([k,v]) => `<div class="flex justify-between py-0.5"><span class="text-slate-500">${k}</span><span class="text-indigo-400">${fmtMoney(v)}</span></div>`).join('')
              : '<div class="text-slate-600 py-0.5">Sin pagos virtuales</div>'
            }
            ${virtuales.length > 0 ? `
            <div class="flex justify-between font-bold border-t border-slate-700 pt-1 mt-1">
              <span class="text-slate-300">Total virtual</span>
              <span class="text-indigo-400">${fmtMoney(c.otros)}</span>
            </div>` : ''}
          </div>
        </div>

        <!-- Total caja -->
        <div class="flex justify-between items-center mt-2 pt-1">
          <span class="text-xs text-slate-500">Total vendido (efectivo + virtual)</span>
          <span class="font-bold text-white text-sm">${fmtMoney(c.totalVentas)}</span>
        </div>
      </div>`;
    }).join('');
  }

  async function toggleCajaDetail(idCaja) {
    const detail    = $('cajadetail-' + idCaja);
    const iconEl    = $('cajabtn-icon-'  + idCaja);
    const labelEl   = $('cajabtn-label-' + idCaja);
    const headerLbl = $('cajatickets-label-' + idCaja);
    if (!detail) return;

    const opening = detail.classList.contains('hidden');
    detail.classList.toggle('hidden', !opening);

    if (!opening) {
      // Cerrando
      if (iconEl)  iconEl.textContent  = '▼';
      if (labelEl) {
        const rows = detail.querySelectorAll('[data-ticket-row]').length;
        labelEl.textContent = `Ver ${rows || ''} ticket${rows !== 1 ? 's' : ''}`;
      }
      return;
    }

    // Abriendo → refresh silencioso de esta caja
    if (iconEl) { iconEl.innerHTML = '<span class="spin" style="display:inline-block;font-size:13px">↻</span>'; iconEl.style.animation = ''; }
    if (labelEl) labelEl.textContent = 'Actualizando…';

    try {
      const res = await API.get('getCierresCaja', {});
      const { abiertas = [], cerradas = [], todosTickets: tkAll = [],
              kpis, kpisTickets = {}, generadoEn } = res || {};

      // Actualizar estado global silencioso
      S._todosTickets = tkAll;
      const todayStr  = today();
      S._todasCajas   = [...abiertas, ...cerradas];
      _cjMergeHist();   // [fix bug] re-inyectar histórico tras la recarga silenciosa
      S._cajasHoy     = [...abiertas, ...(cerradas || []).filter(c =>
        (c.fechaApertura || '').startsWith(todayStr) || (c.fechaCierre || '').startsWith(todayStr))];

      // KPIs
      const setQ = (id, v) => { const el=$(id); if(el) el.textContent = v; };
      setQ('cajasKpiVentas',     fmtMoney(kpis?.totalDia || 0));
      setQ('cajasKpiTicketsHoy', kpisTickets.hoy?.total || 0);
      setQ('cajasKpiTicketsMes', kpisTickets.mes?.total || 0);
      setQ('cajasKpiNV',         kpisTickets.hoy?.NV    || 0);
      setQ('cajasKpiBoleta',     kpisTickets.hoy?.B     || 0);
      setQ('cajasKpiFactura',    kpisTickets.hoy?.F     || 0);
      const ts = $('cajasTimestamp');
      if (ts) ts.textContent = 'Actualizado: ' + (generadoEn || '—');

      // Actualizar solo el contenido de ESTA caja
      const cajaDatos = [...abiertas, ...cerradas].find(c => c.idCaja === idCaja);
      if (cajaDatos) {
        const tkList = cajaDatos.ticketsList || [];
        const exList = cajaDatos.extrasList  || [];
        _renderCajaTicketRows(idCaja, tkList, exList, cajaDatos);
        const count = tkList.length;
        if (labelEl) labelEl.textContent = `${count} ticket${count !== 1 ? 's' : ''} ▲`;
        if (headerLbl) headerLbl.textContent = `Tickets (${count})`;
      } else {
        if (labelEl) labelEl.textContent = 'Sin datos ▲';
      }
    } catch(e) {
      if (labelEl) labelEl.textContent = 'Error · intentar de nuevo ▲';
      console.warn('[CajaDetail]', e.message);
    } finally {
      if (iconEl) { iconEl.innerHTML = ''; iconEl.style.animation = ''; }
    }
  }

  // Re-renderiza solo las filas de tickets de una caja abierta sin tocar el resto del DOM
  function _renderCajaTicketRows(idCaja, tkList, exList, cajaDatos) {
    const detail = $('cajadetail-' + idCaja);
    if (!detail) return;

    const estadoBadge = est => {
      if (est === 'ANULADO')    return '<span class="badge badge-red" style="font-size:10px">ANULADO</span>';
      if (est === 'POR_COBRAR') return '<span class="badge badge-yellow" style="font-size:10px">POR COBRAR</span>';
      if (est === 'CREDITO')    return '<span class="badge badge-blue" style="font-size:10px">CRÉDITO</span>';
      return '';
    };
    const metodoBadge = m => {
      const cls = m === 'EFECTIVO' ? 'badge-green' : m === 'ANULADO' ? 'badge-red' : m === 'POR_COBRAR' ? 'badge-yellow' : 'badge-blue';
      return `<span class="badge ${cls}" style="font-size:10px">${m}</span>`;
    };

    const ticketRowsHtml = tkList.map(t => {
      const anulado = t.estado === 'ANULADO';
      return `
      <div data-ticket-row="${t.idVenta}" class="flex items-center gap-2 py-1.5 border-b border-slate-800/60 ${anulado ? 'opacity-40' : ''}">
        <div class="flex-1 min-w-0">
          <div class="flex items-center gap-1.5 flex-wrap">
            <span class="text-xs font-mono ${anulado ? 'line-through text-slate-500' : 'text-slate-200'}">${t.correlativo || t.idVenta}</span>
            ${estadoBadge(t.estado)}
          </div>
          <div class="text-xs text-slate-500 truncate mt-0.5">${t.clienteNom || t.clienteDoc || 'Sin cliente'} · <span class="text-slate-600">${t.tipoDoc}</span>${t.hora ? ' · ' + t.hora : ''}</div>
        </div>
        <div class="text-right shrink-0">
          <div class="text-sm font-semibold ${anulado ? 'line-through text-slate-600' : 'text-white'}">${fmtMoney(t.total)}</div>
          <div class="mt-0.5">${metodoBadge(t.metodo)}</div>
        </div>
      </div>`;
    }).join('');

    // Buscar o crear contenedor de rows
    let rowsDiv = detail.querySelector('.caja-ticket-rows');
    if (!rowsDiv) {
      rowsDiv = document.createElement('div');
      rowsDiv.className = 'caja-ticket-rows mb-4';
      detail.insertBefore(rowsDiv, detail.firstChild.nextSibling);
    }

    if (tkList.length > 0) {
      rowsDiv.innerHTML = ticketRowsHtml;
      // Fade-in en toda la lista como confirmación visual
      rowsDiv.style.animation = 'none'; rowsDiv.offsetHeight;
      rowsDiv.style.animation = 'fadeIn .3s ease';
    } else {
      rowsDiv.innerHTML = '<div class="text-xs text-slate-600 mb-4">Sin tickets registrados aún</div>';
    }
  }

  function _cajaElapsed(fechaApertura) {
    if (!fechaApertura) return '—';
    try {
      const inicio = new Date(fechaApertura.replace(' ', 'T'));
      const mins   = Math.floor((Date.now() - inicio.getTime()) / 60000);
      if (mins < 60)  return mins + ' min';
      const h = Math.floor(mins / 60), m = mins % 60;
      return h + 'h ' + (m < 10 ? '0' : '') + m + 'm';
    } catch { return '—'; }
  }


  // ── DISPOSITIVOS CRUD ────────────────────────────────────────
  function _dispActualizarPreview() {
    const nom = ($('dispNombre')?.value || '').trim();
    const app = $('dispApp')?.value || 'mosExpress';
    const ico = _dispIcono(nom);
    const ip = $('dispIconPreview');
    if (ip) ip.textContent = ico;
    const sub = $('modalDispSubtitle');
    if (sub) sub.textContent = nom ? `${app === 'mosExpress' ? 'ME' : 'WH'} · equipo físico` : 'Equipo físico autorizado';
  }

  function _dispPoblarSelectZonas(idZonaSel) {
    const sel = $('dispUltimaZona');
    if (!sel) return;
    sel.innerHTML = '<option value="">— Sin asignar —</option>' +
      (cfgData.zonas || []).filter(z => z.estado === '1' || z.estado === 1)
        .map(z => `<option value="${z.idZona}">${z.nombre}</option>`).join('');
    if (idZonaSel) sel.value = idZonaSel;
  }

  function _dispPoblarSelectEstaciones(idZona, idEstacionSel) {
    const sel = $('dispUltimaEstacion');
    if (!sel) return;
    let estaciones = cfgData.estaciones || [];
    if (idZona) estaciones = estaciones.filter(e => e.idZona === idZona);
    estaciones = estaciones.filter(e => String(e.activo) === '1');
    sel.innerHTML = '<option value="">— Sin asignar —</option>' +
      estaciones.map(e => {
        const ico = { CAJA: '🛒', ALMACEN: '🏭', ENVASADO: '🍶' }[e.tipo] || '📍';
        return `<option value="${e.idEstacion}">${ico} ${e.nombre}</option>`;
      }).join('');
    if (idEstacionSel) sel.value = idEstacionSel;
  }

  function _dispZonaCambio() {
    const idZona = $('dispUltimaZona')?.value || '';
    _dispPoblarSelectEstaciones(idZona, ''); // resetear estación al cambiar zona
  }

  function abrirModalDispositivo(id) {
    const modal = $('modalDispositivo');
    if (!modal) return;
    $('dispId').value = '';
    $('dispIdVisible').value = '';
    $('dispNombre').value = '';
    $('dispApp').value = 'mosExpress';
    $('dispEstado').value = 'ACTIVO';

    const wrap = $('dispEstadoWrap');
    const tg = $('dispEstadoToggle');
    const btnElim = $('dispBtnEliminar');
    const ucWrap = $('dispUltimaConexion');

    if (id) {
      const d = cfgData.dispositivos.find(x => x.ID_Dispositivo === id);
      if (!d) return;
      $('modalDispTitle').textContent = 'Editar Dispositivo';
      $('dispId').value        = d.ID_Dispositivo;
      $('dispIdVisible').value = d.ID_Dispositivo;
      $('dispNombre').value    = d.Nombre_Equipo || '';
      $('dispApp').value       = d.App    || 'mosExpress';
      $('dispEstado').value    = d.Estado || 'ACTIVO';
      const activo = String(d.Estado).toUpperCase() === 'ACTIVO';
      if (tg) tg.checked = activo;
      if (wrap) wrap.classList.remove('hidden');
      if (btnElim) btnElim.classList.remove('hidden');
      $('dispIdVisible').readOnly = true; // no permite cambiar UUID al editar
      // Selectors de ubicación pre-llenados
      _dispPoblarSelectZonas(d.Ultima_Zona || '');
      _dispPoblarSelectEstaciones(d.Ultima_Zona || '', d.Ultima_Estacion || '');
      // Última conexión
      if (ucWrap) {
        ucWrap.classList.remove('hidden');
        const act = _dispActividad(d.Ultima_Conexion);
        $('dispUltimaConexionTexto').innerHTML = `<span style="color:${act.color}">${act.dot} ${act.label}</span>${d.Ultima_Conexion ? ` <span class="text-slate-600 text-[10px]">(${d.Ultima_Conexion})</span>` : ''}`;
        const detalles = [];
        if (d.Ultima_Sesion) detalles.push('👤 ' + d.Ultima_Sesion);
        if (d.Ultima_Zona) {
          const z = cfgData.zonas?.find(x => x.idZona === d.Ultima_Zona);
          detalles.push('🏬 ' + (z?.nombre || d.Ultima_Zona));
        }
        if (d.Ultima_Estacion) {
          const e = cfgData.estaciones?.find(x => x.idEstacion === d.Ultima_Estacion);
          detalles.push('📍 ' + (e?.nombre || d.Ultima_Estacion));
        }
        $('dispUltimaSesion').textContent = detalles.join(' · ');
      }
    } else {
      $('modalDispTitle').textContent = 'Nuevo Dispositivo';
      if (tg) tg.checked = true;
      if (wrap) wrap.classList.add('hidden');
      if (btnElim) btnElim.classList.add('hidden');
      if (ucWrap) ucWrap.classList.add('hidden');
      $('dispIdVisible').readOnly = false;
      _dispPoblarSelectZonas('');
      _dispPoblarSelectEstaciones('', '');
    }
    _dispActualizarPreview();
    openModal('modalDispositivo');
  }

  function cerrarModalDispositivo() {
    closeModal('modalDispositivo');
  }

  function dispCopiarUUID() {
    const uuid = String($('dispIdVisible')?.value || '').trim();
    if (!uuid) { toast('Sin UUID para copiar', 'warn'); return; }
    navigator.clipboard.writeText(uuid).then(() => toast('UUID copiado al portapapeles ✓', 'ok'))
      .catch(() => toast('No se pudo copiar', 'error'));
  }

  async function guardarDispositivo() {
    const idOriginal = $('dispId').value.trim();
    const idNuevo    = ($('dispIdVisible')?.value || '').trim();
    const nombre     = $('dispNombre').value.trim();
    const app        = $('dispApp').value;
    const tg         = $('dispEstadoToggle');
    const estado     = idOriginal ? (tg && tg.checked ? 'ACTIVO' : 'INACTIVO') : 'ACTIVO';
    const idZonaManual     = $('dispUltimaZona')?.value || '';
    const idEstacionManual = $('dispUltimaEstacion')?.value || '';
    if (!nombre) { toast('El nombre del equipo es obligatorio', 'warn'); return; }
    if (!idNuevo) { toast('Pega el UUID del dispositivo', 'warn'); return; }

    // OPTIMISTA
    const list = cfgData.dispositivos;
    const backup = list.slice();
    if (idOriginal) {
      const idx = list.findIndex(x => x.ID_Dispositivo === idOriginal);
      if (idx >= 0) list[idx] = {
        ...list[idx],
        Nombre_Equipo: nombre, App: app, Estado: estado,
        Ultima_Zona: idZonaManual,
        Ultima_Estacion: idEstacionManual
      };
    } else {
      list.push({
        ID_Dispositivo: idNuevo, Nombre_Equipo: nombre, App: app, Estado: estado,
        Ultima_Conexion: '', Ultima_Zona: idZonaManual, Ultima_Estacion: idEstacionManual
      });
    }
    cerrarModalDispositivo();
    renderInfra();

    try {
      if (idOriginal) {
        await API.post('actualizarDispositivo', {
          ID_Dispositivo: idOriginal, Nombre_Equipo: nombre, App: app, Estado: estado,
          Ultima_Zona: idZonaManual, Ultima_Estacion: idEstacionManual
        });
      } else {
        await API.post('crearDispositivo', {
          ID_Dispositivo: idNuevo, Nombre_Equipo: nombre, App: app, Estado: estado,
          Ultima_Zona: idZonaManual, Ultima_Estacion: idEstacionManual
        });
      }
      toast('Dispositivo guardado ✓', 'ok');
    } catch(e) {
      cfgData.dispositivos = backup;
      renderInfra();
      toast(e.message || 'Error al guardar', 'error');
    }
  }

  async function eliminarDispositivo() {
    // 'Eliminar' = bloquear (Estado=INACTIVO)
    const id = $('dispId')?.value;
    if (!id) return;
    const d = cfgData.dispositivos.find(x => x.ID_Dispositivo === id);
    if (!d) return;
    if (!await _modalConfirm(`¿Bloquear el dispositivo "${d.Nombre_Equipo}"?\n\nNo podrá iniciar sesión en ninguna app. Puedes reactivarlo cuando quieras.`, { warning: true, titulo: 'Bloquear dispositivo', okText: 'Bloquear' })) return;
    cerrarModalDispositivo();
    const previo = d.Estado;
    d.Estado = 'INACTIVO';
    renderInfra();
    try {
      await API.post('actualizarDispositivo', { ID_Dispositivo: id, Estado: 'INACTIVO' });
      toast('Dispositivo bloqueado', 'ok');
    } catch(e) {
      d.Estado = previo;
      renderInfra();
      toast(e.message || 'Error', 'error');
    }
  }

  // Aprobar dispositivo: optimista con feedback visual claro.
  // - Nombre por default = el que vino del User-Agent (ej "Windows · Chrome").
  // - Si pasamos { renombrar: true } abre prompt para editarlo.
  // - Animación slide-out del card + sonido + toast inmediato.
  // [v2.43.155] Shield optimista: protege el estado ACTIVO de un dispositivo
  // recién aprobado durante 10s contra el polling de getDispositivos que
  // podría traer aún el estado viejo PENDIENTE_APROBACION del backend.
  // Causa raíz reportada por el usuario: 'aprueba pero vuelve a por aprobar'.
  if (!S._dispShield) S._dispShield = {};

  async function aprobarDispositivo(id, opts) {
    opts = opts || {};
    const d = cfgData.dispositivos.find(x => x.ID_Dispositivo === id);
    if (!d) return;
    let nombre = (d.Nombre_Equipo || '').trim() || ('Dispositivo ' + id.substring(0, 8));
    if (opts.renombrar) {
      const nuevoNombre = await _modalPrompt('Nombre del dispositivo:', nombre, { titulo: 'Renombrar dispositivo', maxlength: 60 });
      if (nuevoNombre === null) return;
      const t = (nuevoNombre || '').trim();
      if (!t) { toast('El nombre no puede estar vacío', 'error'); return; }
      nombre = t;
    }
    // Animación slide-out del card que se está aprobando
    const safeId = String(id).replace(/'/g, '&#39;');
    const card = document.querySelector(`[data-pend-card="${safeId}"]`);
    if (card) {
      card.classList.add('disp-pend-aprobando');
    }
    // Sonido + toast inmediato (optimista)
    try { _finBeep?.('breakeven'); } catch(_){}
    toast(`✓ "${nombre}" aprobado`, 'ok');
    // Aplicar cambio en el modelo local
    const previo = d.Estado;
    d.Estado = 'ACTIVO';
    d.Nombre_Equipo = nombre;
    // [v2.43.155] Activar shield por 10s: el polling NO podrá pisar el estado
    // ACTIVO de este dispositivo hasta que el backend lo confirme.
    S._dispShield[id] = { estado: 'ACTIVO', nombre: nombre, hasta: Date.now() + 10000 };
    // Esperar la animación antes del re-render para que se vea desaparecer
    setTimeout(() => renderInfra(), 320);
    try {
      await API.post('aprobarDispositivoPendiente', {
        ID_Dispositivo: id,
        Nombre_Equipo: nombre
      });
      // [v2.43.345] Red de seguridad generosa (15s): el shield se libera ANTES por confirmación del backend
      // (ver _dispAplicarShield) — este timeout solo cubre el caso de que el backend nunca refleje el cambio.
      // Antes eran 3s fijos: con el dual-write a la sombra la llamada tarda un poco más y el poll podía llegar
      // tras el vencimiento con el valor viejo en vuelo → el card parpadeaba (reaparecía y se iba).
      if (S._dispShield[id]) S._dispShield[id].hasta = Date.now() + 15000;
    } catch(e) {
      // Rollback: quitar shield y restaurar estado previo
      delete S._dispShield[id];
      d.Estado = previo;
      renderInfra();
      toast(e.message || 'Error al aprobar', 'error');
    }
  }
  // [v2.43.155] Aplicar shield a la lista de dispositivos que llega del backend.
  // El polling llama getDispositivos y reemplaza cfgData.dispositivos completo;
  // pasamos el array por este helper antes de asignar para preservar los
  // recién aprobados en estado ACTIVO durante el shield window.
  function _dispAplicarShield(arr) {
    if (!Array.isArray(arr) || !S._dispShield) return arr;
    const ahora = Date.now();
    const expirados = [];
    Object.keys(S._dispShield).forEach(id => {
      const sh = S._dispShield[id];
      if (!sh) { expirados.push(id); return; }
      const idx = arr.findIndex(x => String(x.ID_Dispositivo) === String(id));
      // [v2.43.345] LIBERAR-AL-CONFIRMAR: si el backend YA trae el estado optimista, el cambio está
      // confirmado → soltar el shield (no seguir forzando). Esto evita el parpadeo: el card no reaparece
      // por una respuesta vieja en vuelo (esa NO confirma, así que el shield la sigue tapando) y se suelta
      // recién cuando llega la confirmación real. El timeout es solo red de seguridad.
      if (idx >= 0 && String(arr[idx].Estado).toUpperCase() === String(sh.estado).toUpperCase()) {
        expirados.push(id); return;
      }
      // Red de seguridad: si el backend nunca reflejó el cambio en la ventana, soltar por tiempo.
      if (sh.hasta < ahora) { expirados.push(id); return; }
      // Aún sin confirmar y dentro de ventana → preservar el estado + nombre optimistas.
      if (idx >= 0) arr[idx] = { ...arr[idx], Estado: sh.estado, Nombre_Equipo: sh.nombre };
    });
    expirados.forEach(id => delete S._dispShield[id]);
    return arr;
  }

  // Variante: aprobar pero pidiendo nombre antes (botón ✎ Renombrar).
  function aprobarDispositivoConNombre(id) {
    return aprobarDispositivo(id, { renombrar: true });
  }

  async function rechazarDispositivo(id) {
    const d = cfgData.dispositivos.find(x => x.ID_Dispositivo === id);
    if (!d) return;
    if (!await _modalConfirm(`¿Rechazar este dispositivo?\n\nQuedará bloqueado y no podrá conectarse.`, { danger: true, titulo: 'Rechazar dispositivo', okText: 'Rechazar' })) return;
    const safeId = String(id).replace(/'/g, '&#39;');
    const card = document.querySelector(`[data-pend-card="${safeId}"]`);
    if (card) {
      card.classList.add('disp-pend-rechazando');
    }
    try { _finBeep?.('click'); } catch(_){}
    toast('Dispositivo rechazado', 'warn');
    const previo = d.Estado;
    d.Estado = 'INACTIVO';
    setTimeout(() => renderInfra(), 320);
    try {
      await API.post('rechazarDispositivoPendiente', { ID_Dispositivo: id });
    } catch(e) {
      d.Estado = previo;
      renderInfra();
      toast(e.message || 'Error', 'error');
    }
  }

  // ────────────────────────────────────────────────────────
  // MODAL AUDIO — escucha remota
  // ────────────────────────────────────────────────────────
  let _audioPollTimer = null;
  let _audioReproduciendo = null; // { sesion, chunks, idx }

  async function abrirModalAudio(idDispositivo) {
    const d = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === idDispositivo);
    if (!d) return;
    $('audioModalDeviceId').value = idDispositivo;
    $('audioModalSubtitle').textContent = `${d.Nombre_Equipo || idDispositivo}${d.Ultima_Sesion ? ' · 👤 ' + d.Ultima_Sesion : ''}`;
    $('audioReproductor').classList.add('hidden');
    openModal('modalAudio');
    await audioRefrescarEstado();
    audioListarSesiones();
    if (_audioPollTimer) clearInterval(_audioPollTimer);
    _audioPollTimer = setInterval(audioRefrescarEstado, 10 * 1000);
  }

  // Cerrar modal cancela el poll
  document.addEventListener('mos:modal-cerrado', e => {
    if (e.detail === 'modalAudio' && _audioPollTimer) {
      clearInterval(_audioPollTimer); _audioPollTimer = null;
    }
  });

  async function audioRefrescarEstado() {
    const id = $('audioModalDeviceId')?.value;
    if (!id) return;
    const cont = $('audioEstadoActual');
    if (!cont) return;
    try {
      const data = await API.get('getEstadoAudio', { deviceId: id });
      if (data?.activa) {
        const sesionId = data.sesion.idSesion;
        const ini = data.sesion.inicio ? new Date(data.sesion.inicio) : null;
        const segs = ini ? Math.floor((Date.now() - ini.getTime()) / 1000) : 0;
        const mm = String(Math.floor(segs / 60)).padStart(2, '0');
        const ss = String(segs % 60).padStart(2, '0');
        cont.innerHTML = `<div class="card p-3" style="background:rgba(239,68,68,0.10);border:1px solid #dc2626;">
          <div class="flex items-center justify-between gap-2 flex-wrap">
            <div>
              <div class="text-sm font-bold text-red-300">🔴 Grabando ahora</div>
              <div class="text-[10px] text-slate-500 font-mono">sesión ${sesionId} · ${mm}:${ss}</div>
            </div>
            <button onclick="MOS.audioDetener('${sesionId}')" class="btn-primary text-xs px-3 py-1.5" style="background:#dc2626">⏹️ Detener</button>
          </div>
        </div>`;
      } else {
        cont.innerHTML = `<div class="card p-3" style="background:#0a1424;border:1px solid #1e293b;">
          <div class="flex items-center justify-between gap-2 flex-wrap">
            <div>
              <div class="text-sm font-bold text-slate-300">⏸ Sin grabación activa</div>
              <div class="text-[10px] text-slate-500">El dispositivo está en silencio</div>
            </div>
            <button onclick="MOS.audioIniciar('${id}')" class="btn-primary text-xs px-3 py-1.5" style="background:#dc2626">🎙️ Iniciar escucha</button>
          </div>
        </div>`;
      }
    } catch(_) {
      cont.innerHTML = '<div class="text-center py-3 text-red-400 text-sm">Error consultando estado</div>';
    }
  }

  async function audioIniciar(deviceId) {
    // Cerrar el modal de historial (si está abierto) y enrutar al flotante.
    // Sin confirm — el user ya hizo click en "🎙️ Iniciar escucha", confirmación redundante.
    try { closeModal('modalAudio'); } catch {}
    return _audioFlotanteIniciar(deviceId);
  }

  async function audioDetener(idSesion) {
    try {
      await API.post('detenerEscuchaAudio', { idSesion });
      toast('⏹️ Detenido', 'ok');
      setTimeout(audioRefrescarEstado, 1000);
      setTimeout(audioListarSesiones, 1500);
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  async function audioListarSesiones() {
    const id = $('audioModalDeviceId')?.value;
    if (!id) return;
    const cont = $('audioListaSesiones');
    // Render INMEDIATO desde cache localStorage si existe (TTL 60s)
    const cacheKey = 'mos_audio_sesiones_' + id;
    try {
      const raw = localStorage.getItem(cacheKey);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.data) && (Date.now() - parsed.ts) < 60000) {
          cont.innerHTML = _audioRenderSesiones(parsed.data);
        }
      }
    } catch {}
    try {
      const data = await API.get('getSesionesAudio', { deviceId: id, limit: 20 });
      try { localStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), data })); } catch {}
      if (!Array.isArray(data) || !data.length) {
        cont.innerHTML = '<div class="text-center py-6 text-slate-500 text-sm italic">Sin sesiones todavía</div>';
        return;
      }
      cont.innerHTML = _audioRenderSesiones(data);
      return;
    } catch(e) {
      if (!cont.innerHTML.trim()) cont.innerHTML = '<div class="text-center py-3 text-red-400 text-sm">Error: ' + e.message + '</div>';
      return;
    }
  }

  function _audioRenderSesiones(data) {
    return data.map(s => {
        const fIni = s.inicio ? new Date(s.inicio) : null;
        const fmt = fIni ? fIni.toLocaleString('es-PE', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' }) : '—';
        const dur = s.duracionSeg ? Math.floor(s.duracionSeg / 60) + 'm' + (s.duracionSeg % 60) + 's' : '—';
        const estCl = s.estado === 'ACTIVA' ? 'text-red-400 animate-pulse'
                    : s.estado === 'CERRADA' ? 'text-emerald-400'
                    : 'text-slate-500';
        return `<div class="flex items-center gap-2 p-2 rounded" style="background:#0a1424;border:1px solid #1e293b;">
          <div class="flex-1 min-w-0">
            <div class="text-xs font-medium text-slate-200">${fmt} · <span class="${estCl} text-[10px] uppercase">${s.estado || '—'}</span></div>
            <div class="text-[10px] text-slate-500">por ${s.autorizadoPor || '—'} · ${dur}</div>
          </div>
          <button onclick="MOS.audioReproducir('${s.idSesion}','${(s.autorizadoPor || '').replace(/'/g,"\\'")}','${fmt.replace(/'/g,"\\'")}')"
            class="btn-ghost text-[10px] px-2 py-1" ${s.estado === 'ACTIVA' ? '' : ''}>▶ Reproducir</button>
        </div>`;
      }).join('');
  }

  async function audioReproducir(idSesion, autorizadoPor, fechaTxt) {
    const player = $('audioPlayer');
    const cont = $('audioReproductor');
    const titulo = $('audioReproductorTitulo');
    const info = $('audioReproductorInfo');
    if (!player || !cont) return;
    cont.classList.remove('hidden');
    titulo.textContent = `▶ Sesión ${fechaTxt} · ${autorizadoPor || ''}`;
    info.textContent = 'Cargando chunks...';
    try {
      const chunks = await API.get('getChunksAudioSesion', { idSesion });
      if (!Array.isArray(chunks) || !chunks.length) {
        info.textContent = '⚠ Sesión sin chunks (puede estar arrancando)';
        return;
      }
      info.textContent = `${chunks.length} chunks · cargando primero...`;
      _audioReproduciendo = { chunks, idx: 0, idSesion };
      await _audioCargarYReproducir();
    } catch(e) {
      info.textContent = 'Error: ' + e.message;
    }
  }

  async function _audioCargarYReproducir() {
    if (!_audioReproduciendo) return;
    const { chunks, idx } = _audioReproduciendo;
    if (idx >= chunks.length) {
      $('audioReproductorInfo').textContent = '✓ Reproducción finalizada';
      return;
    }
    const ch = chunks[idx];
    try {
      const data = await API.get('getChunkAudioContent', { fileId: ch.driveFileId });
      if (!data?.base64) throw new Error('Sin contenido');
      const blob = _b64ToBlob(data.base64, data.mimeType || 'audio/webm');
      const url = URL.createObjectURL(blob);
      const player = $('audioPlayer');
      player.src = url;
      player.play().catch(() => {});
      $('audioReproductorInfo').textContent = `Chunk ${idx + 1} / ${chunks.length}`;
      player.onended = () => {
        URL.revokeObjectURL(url);
        if (_audioReproduciendo) {
          _audioReproduciendo.idx++;
          _audioCargarYReproducir();
        }
      };
    } catch(e) {
      $('audioReproductorInfo').textContent = 'Error chunk ' + (idx + 1) + ': ' + e.message;
    }
  }

  function _b64ToBlob(b64, mime) {
    const bin = atob(b64);
    const len = bin.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = bin.charCodeAt(i);
    return new Blob([bytes], { type: mime });
  }

  function audioCerrarReproductor() {
    _audioReproduciendo = null;
    const player = $('audioPlayer');
    if (player) { player.pause(); player.src = ''; }
    $('audioReproductor')?.classList.add('hidden');
  }

  // ────────────────────────────────────────────────────────
  // Audio LIVE (ADMIN) — sin historial, solo activar/detener
  // ────────────────────────────────────────────────────────
  let _audioLivePollTimer = null;

  function _esRolMaster() {
    return String(S.session?.rol || '').toUpperCase() === 'MASTER';
  }

  // Busca dispositivos donde el usuario tiene Ultima_Sesion (sin filtrar por
  // Estado — incluye los aprobados aunque estén offline ahora). Ordena por
  // Ultima_Conexion DESC para que el más reciente quede primero.
  function _buscarDispositivosDeUsuario(nombre) {
    const target = String(nombre || '').trim().toLowerCase();
    if (!target) return [];
    return (cfgData.dispositivos || [])
      .filter(d => {
        // Excluir solo los explícitamente INACTIVO o PENDIENTE
        const est = String(d.Estado || '').toUpperCase();
        if (est === 'INACTIVO' || est === 'PENDIENTE_APROBACION') return false;
        const sesion = String(d.Ultima_Sesion || '').trim().toLowerCase();
        return sesion === target;
      })
      .sort((a, b) => {
        const ta = new Date(a.Ultima_Conexion || 0).getTime() || 0;
        const tb = new Date(b.Ultima_Conexion || 0).getTime() || 0;
        return tb - ta;
      });
  }

  // Refresca cfgData.dispositivos antes de buscar — garantiza data fresh
  async function _refrescarDispositivosFresh() {
    try {
      const data = await API.get('getDispositivos', {});
      if (Array.isArray(data)) cfgData.dispositivos = _dispAplicarShield(data);   // [v2.43.348 fix] shield
    } catch(_) {}
  }

  // Punto de entrada cuando se hace click en 🎙️ desde Personal del Día
  async function abrirEscuchaPorUsuario(nombre) {
    await _refrescarDispositivosFresh();
    const devs = _buscarDispositivosDeUsuario(nombre);
    if (!devs.length) {
      toast(`⚠ ${nombre} no tiene dispositivos registrados con su sesión`, 'warn', 5000);
      return;
    }
    // Advertir si la última conexión es muy vieja
    const masReciente = devs[0];
    const ultMs = new Date(masReciente.Ultima_Conexion || 0).getTime() || 0;
    const minsTranscurridos = (Date.now() - ultMs) / 60000;
    if (minsTranscurridos > 10) {
      const horas = Math.floor(minsTranscurridos / 60);
      const txt = horas > 0 ? `hace ${horas}h` : `hace ${Math.floor(minsTranscurridos)}min`;
      if (!await _modalConfirm(`⚠ Última conexión de ${nombre} fue ${txt}.\n\nLa app puede estar cerrada — el comando de escucha puede no llegar.\n\n¿Iniciar igual?`, { warning: true, titulo: 'Iniciar escucha' })) return;
    }
    if (devs.length === 1) {
      abrirModalAudioRouted(devs[0].ID_Dispositivo);
      return;
    }
    _selectorDispMostrar(nombre, devs, 'audio');
  }

  async function abrirGpsPorUsuario(nombre) {
    await _refrescarDispositivosFresh();
    const devs = _buscarDispositivosDeUsuario(nombre);
    if (!devs.length) {
      toast(`⚠ ${nombre} no tiene dispositivos registrados`, 'warn', 4000);
      return;
    }
    if (devs.length === 1) {
      abrirModalGps(devs[0].ID_Dispositivo);
      return;
    }
    _selectorDispMostrar(nombre, devs, 'gps');
  }

  function _selectorDispMostrar(nombre, devs, modo) {
    const sub = $('selectorDispSubtitle');
    const lista = $('selectorDispLista');
    const verboMap = { audio: 'escuchar', gps: 'ubicar', espia: 'espiar' };
    if (sub) sub.textContent = `${nombre} · ${devs.length} dispositivos · elige cuál ${verboMap[modo] || 'usar'}`;
    if (!lista) return;
    const accionMap = { audio: 'abrirModalAudioRouted', gps: 'abrirModalGps', espia: 'abrirEspiaDispositivo' };
    const icoMap = { audio: '🎙️', gps: '📍', espia: '🕵️' };
    const accentMap = { audio: '#dc2626', gps: '#10b981', espia: '#6366f1' };
    const accion = accionMap[modo] || 'abrirModalAudioRouted';
    const ico = icoMap[modo] || '🎙️';
    const accent = accentMap[modo] || '#dc2626';
    lista.innerHTML = devs.map(d => {
      const act = _personaActividad(d.Ultima_Conexion);
      const idAttr = String(d.ID_Dispositivo).replace(/'/g, '&#39;');
      const ico2 = String(d.Icono || '📱');
      return `<button onclick="MOS.closeModal('modalSelectorDispositivos');MOS.${accion}('${idAttr}')"
        class="w-full flex items-center gap-3 p-3 rounded-lg hover:scale-[1.01] transition-all text-left"
        style="background:#0a1424;border:1px solid #1e293b;">
        <span class="text-2xl shrink-0">${ico2}</span>
        <div class="flex-1 min-w-0">
          <div class="text-sm font-medium text-slate-200 truncate">${d.Nombre_Equipo || idAttr}</div>
          <div class="text-[10px]" style="color:${act.color};">${act.dot} ${act.label} · ${d.App || '—'}${d.Estacion ? ' · ' + d.Estacion : ''}</div>
        </div>
        <span class="shrink-0 w-8 h-8 rounded-full flex items-center justify-center" style="background:rgba(255,255,255,0.05);border:1px solid ${accent};color:${accent};">${ico}</span>
      </button>`;
    }).join('');
    openModal('modalSelectorDispositivos');
  }

  // Click en 🎙️ desde cualquier lado → entra DIRECTO al modo escucha en vivo
  // con widget flotante. Sin modal intrusivo. El historial completo (master)
  // queda accesible desde el flotante con el botón "📋".
  async function abrirModalAudioRouted(idDispositivo) {
    return _audioFlotanteIniciar(idDispositivo);
  }

  // Wrapper que enruta desde Configuración → Infraestructura al flotante
  async function abrirEscuchaDispositivo(idDispositivo) {
    return _audioFlotanteIniciar(idDispositivo);
  }

  // ════════════════════════════════════════════════════════════
  // WIDGET FLOTANTE de escucha en vivo
  // - Persiste entre módulos (mounted en <body>)
  // - Auto-iniciar sesión + auto-streaming de chunks
  // - Click en ⏹️ → detener escucha + remover flotante
  // - Click en 📋 → modal completo con historial (solo master)
  // ════════════════════════════════════════════════════════════
  let _audioFlot = null;
  // _audioFlot: { idSesion, deviceId, nombre, chunks[], idx, audioEl,
  //   inicio, polling, contadorTimer, chunksCargados:Set, prefetched:Map }

  async function _audioFlotanteIniciar(idDispositivo) {
    // Si ya hay un flotante para el mismo dispositivo, no hacer nada
    if (_audioFlot && _audioFlot.deviceId === idDispositivo) {
      toast('Ya estás escuchando este dispositivo', 'info');
      return;
    }
    // Si hay flotante de OTRO dispositivo → swap silencioso (sin confirm — el user clickeó otro)
    if (_audioFlot) await _audioFlotanteDetenerInterno(true);

    const d = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === idDispositivo);
    if (!d) { toast('Dispositivo no encontrado', 'error'); return; }
    const nombre = d.Nombre_Equipo + (d.Ultima_Sesion ? ' · ' + d.Ultima_Sesion : '');

    // Crear el flotante INMEDIATO (UI optimista — el user ve el widget al instante)
    _audioFlotanteCrearDOM(idDispositivo, nombre);
    const subEl = document.querySelector('#audioFlotante .audio-flot-sub');
    if (subEl) subEl.textContent = '⌛ conectando...';

    try {
      // Detectar sesión zombie: ACTIVA pero >35 min de antigüedad sin chunks → cerrar y abrir nueva
      const estado = await API.get('getEstadoAudio', { deviceId: idDispositivo });
      let idSesion = null;
      if (estado?.activa) {
        const ini = estado.sesion?.inicio ? new Date(estado.sesion.inicio).getTime() : 0;
        const edad = Date.now() - ini;
        const esZombie = edad > 35 * 60 * 1000; // 35 min (max es 30, esto da margen)
        if (esZombie) {
          // Cerrar zombie y abrir nueva
          try { await API.post('detenerEscuchaAudio', { idSesion: estado.sesion.idSesion }); } catch {}
          if (subEl) subEl.textContent = '⌛ sesión zombie cerrada · iniciando nueva...';
        } else {
          idSesion = estado.sesion.idSesion;
          if (subEl) subEl.textContent = '🔴 conectando a sesión activa...';
        }
      }
      if (!idSesion) {
        if (subEl && !subEl.textContent.includes('zombie')) subEl.textContent = '⌛ iniciando grabación...';
        const data = await API.post('iniciarEscuchaAudio', {
          deviceId: idDispositivo,
          autorizadoPor: S.session?.nombre || 'admin',
          motivo: 'Escucha en vivo desde MOS'
        });
        idSesion = data.idSesion;
      }
      if (!_audioFlot) return; // user cerró el flotante mientras esperaba
      _audioFlot.idSesion = idSesion;
      const subEl2 = document.querySelector('#audioFlotante .audio-flot-sub');
      if (subEl2) subEl2.textContent = '🔴 esperando primer chunk (~15s)...';

      // Arrancar polling y reproductor
      _audioFlotantePollChunks(); // primer poll inmediato
      _audioFlot.polling = setInterval(_audioFlotantePollChunks, 2500);
      // Watchdogs progresivos: 20s → primer aviso, 45s → recomendación, 90s → autodetener
      _audioFlot.watchdog20 = setTimeout(() => {
        if (!_audioFlot || _audioFlot.chunks.length > 0) return;
        const elS = document.querySelector('#audioFlotante .audio-flot-sub');
        if (elS) elS.innerHTML = '⌛ <span style="color:#fde68a">esperando dispositivo (~5-15s más)...</span>';
      }, 20000);
      _audioFlot.watchdog45 = setTimeout(() => {
        if (!_audioFlot || _audioFlot.chunks.length > 0) return;
        const elS = document.querySelector('#audioFlotante .audio-flot-sub');
        if (elS) elS.innerHTML = '⚠ <span style="color:#fbbf24">App cerrada o sin permiso mic — pedile que abra la app</span>';
      }, 45000);
      _audioFlot.watchdog90 = setTimeout(() => {
        if (!_audioFlot || _audioFlot.chunks.length > 0) return;
        toast('⚠ Sin respuesta del dispositivo · escucha cancelada', 'warn', 6000);
        _audioFlotanteDetenerInterno(true);
      }, 90000);
    } catch(e) {
      const subEl3 = document.querySelector('#audioFlotante .audio-flot-sub');
      if (subEl3) subEl3.textContent = '❌ ' + e.message;
      setTimeout(() => _audioFlotanteCerrarSinDetener(), 3000);
    }
  }

  function _audioFlotanteCrearDOM(deviceId, nombre) {
    if (document.getElementById('audioFlotante')) return;
    // Botón 📋 (ver historial completo) solo para MASTER. Admin no debería
    // ver sesiones pasadas — solo escucha en vivo.
    const btnHist = _esRolMaster()
      ? `<button class="audio-flot-btn" onclick="MOS.abrirModalAudio('${String(deviceId).replace(/'/g,"\\'")}')" title="Ver historial de sesiones">📋</button>`
      : '';
    const fl = document.createElement('div');
    fl.id = 'audioFlotante';
    fl.innerHTML = `
      <div class="audio-flot-mic">🎙️</div>
      <div class="audio-flot-info">
        <div class="audio-flot-nom">${nombre}</div>
        <div class="audio-flot-sub">⌛ iniciando...</div>
        <div class="audio-flot-time" id="audioFlotTime">00:00</div>
        <div class="audio-flot-chunks" id="audioFlotChunks">— chunks</div>
      </div>
      <div class="audio-flot-actions">
        ${btnHist}
        <button class="audio-flot-btn audio-flot-btn-stop" onclick="MOS._audioFlotanteDetener()" title="Detener escucha">⏹</button>
      </div>
      <audio id="audioFlotantePlayer"></audio>`;
    document.body.appendChild(fl);
    _audioFlot = {
      deviceId, nombre,
      idSesion: null,
      chunks: [], idx: 0,
      chunksCargados: new Set(),
      audioEl: document.getElementById('audioFlotantePlayer'),
      inicio: Date.now(),
      polling: null,
      contadorTimer: null,
      prefetched: new Map()
    };
    // Contador
    _audioFlot.contadorTimer = setInterval(() => {
      if (!_audioFlot) return;
      const segs = Math.floor((Date.now() - _audioFlot.inicio) / 1000);
      const mm = String(Math.floor(segs / 60)).padStart(2, '0');
      const ss = String(segs % 60).padStart(2, '0');
      const t = $('audioFlotTime');
      if (t) t.textContent = `${mm}:${ss}`;
    }, 1000);
    // Encadenado: cuando termina un chunk, ir al siguiente
    _audioFlot.audioEl.onended = () => {
      if (!_audioFlot) return;
      _audioFlot.idx++;
      _audioFlotanteReproducirSiguiente();
    };
    // Pre-warm autoplay policy: reproducir un blob silencioso de 100ms para
    // que el browser asocie el user gesture (click 🎙️) con el audio element.
    // Sin esto, cuando llega el primer chunk 15s después, autoplay falla.
    try {
      const silentWebm = 'data:audio/webm;base64,GkXfowEAAAAAAAAfQoaBAUL3gQFC8oEEQvOBCEKChHdlYm1Ch4EEQoWBAhhTgGcBAAAAAAAVkhFNm3RALE27i1OrhBVJqWZTrIHfTbuMU6uEFlSua1OsggEwTbuMU6uEHFO7a1OsggI+7AEAAAAAAACkAAAAAAAAAAAAAAAAAAA=';
      _audioFlot.audioEl.src = silentWebm;
      _audioFlot.audioEl.volume = 0;
      _audioFlot.audioEl.play().then(() => {
        if (_audioFlot && _audioFlot.audioEl) _audioFlot.audioEl.volume = 1;
      }).catch(() => {});
    } catch(_) {}
    // Drag (mover el flotante)
    _audioFlotanteDraggable(fl);
  }

  function _audioFlotanteDraggable(el) {
    let dragging = false, ox = 0, oy = 0, sl = 0, st = 0;
    el.addEventListener('mousedown', e => {
      if (e.target.closest('.audio-flot-btn') || e.target.closest('audio')) return;
      dragging = true;
      const r = el.getBoundingClientRect();
      ox = e.clientX; oy = e.clientY; sl = r.left; st = r.top;
      el.classList.add('dragging');
      el.style.right = 'auto'; el.style.bottom = 'auto';
    });
    document.addEventListener('mousemove', e => {
      if (!dragging) return;
      el.style.left = (sl + e.clientX - ox) + 'px';
      el.style.top  = (st + e.clientY - oy) + 'px';
    });
    document.addEventListener('mouseup', () => { dragging = false; el.classList.remove('dragging'); });
  }

  async function _audioFlotantePollChunks() {
    if (!_audioFlot || !_audioFlot.idSesion) return;
    try {
      const newChunks = await API.get('getChunksAudioSesion', { idSesion: _audioFlot.idSesion });
      if (!Array.isArray(newChunks)) return;
      let added = 0;
      newChunks.forEach(c => {
        if (!_audioFlot.chunksCargados.has(c.driveFileId)) {
          _audioFlot.chunks.push(c);
          _audioFlot.chunksCargados.add(c.driveFileId);
          added++;
        }
      });
      const elC = $('audioFlotChunks');
      if (elC) elC.textContent = `${_audioFlot.chunks.length} chunks · idx ${_audioFlot.idx + 1}`;
      const elS = document.querySelector('#audioFlotante .audio-flot-sub');
      if (elS && _audioFlot.chunks.length > 0) elS.textContent = '🔴 escuchando en vivo';

      // Si el reproductor está pausado y hay chunks por reproducir, arrancar
      if (_audioFlot.audioEl.paused && _audioFlot.idx < _audioFlot.chunks.length) {
        _audioFlotanteReproducirSiguiente();
      }
      // Prefetch de los próximos 2 chunks (para evitar gap entre chunks)
      _audioFlotantePrefetch(_audioFlot.idx + 1);
      _audioFlotantePrefetch(_audioFlot.idx + 2);
    } catch (e) {
      const elS = document.querySelector('#audioFlotante .audio-flot-sub');
      if (elS) elS.textContent = '⚠ ' + e.message;
    }
  }

  async function _audioFlotantePrefetch(idx) {
    if (!_audioFlot) return;
    if (idx >= _audioFlot.chunks.length) return;
    const ch = _audioFlot.chunks[idx];
    if (!ch || _audioFlot.prefetched.has(ch.driveFileId)) return;
    _audioFlot.prefetched.set(ch.driveFileId, 'pending');
    try {
      const data = await API.get('getChunkAudioContent', { fileId: ch.driveFileId });
      if (!data?.base64) throw new Error('vacío');
      _audioFlot.prefetched.set(ch.driveFileId, data);
    } catch {
      _audioFlot.prefetched.delete(ch.driveFileId);
    }
  }

  async function _audioFlotanteReproducirSiguiente() {
    if (!_audioFlot) return;
    const { chunks, idx, audioEl } = _audioFlot;
    if (idx >= chunks.length) {
      const elS = document.querySelector('#audioFlotante .audio-flot-sub');
      if (elS) elS.textContent = '⏳ esperando próximo chunk...';
      return;
    }
    const ch = chunks[idx];
    let data = _audioFlot.prefetched.get(ch.driveFileId);
    if (!data || data === 'pending') {
      try {
        data = await API.get('getChunkAudioContent', { fileId: ch.driveFileId });
        _audioFlot.prefetched.set(ch.driveFileId, data);
      } catch (e) {
        const elS = document.querySelector('#audioFlotante .audio-flot-sub');
        if (elS) elS.textContent = '⚠ chunk ' + (idx + 1) + ' falló';
        // intentar siguiente
        _audioFlot.idx++;
        setTimeout(() => _audioFlotanteReproducirSiguiente(), 500);
        return;
      }
    }
    if (!data?.base64) {
      _audioFlot.idx++;
      setTimeout(() => _audioFlotanteReproducirSiguiente(), 200);
      return;
    }
    const blob = _b64ToBlob(data.base64, data.mimeType || 'audio/webm');
    const url = URL.createObjectURL(blob);
    audioEl.src = url;
    try {
      await audioEl.play();
    } catch (e) {
      // Autoplay policy bloqueó: el usuario debe hacer click manualmente
      const elS = document.querySelector('#audioFlotante .audio-flot-sub');
      if (elS) elS.textContent = '🔇 click el mic para iniciar audio';
      const mic = document.querySelector('#audioFlotante .audio-flot-mic');
      if (mic) {
        mic.style.cursor = 'pointer';
        mic.onclick = () => audioEl.play().catch(() => {});
      }
    }
    URL.revokeObjectURL(url);
    // Iniciar prefetch del próximo
    _audioFlotantePrefetch(idx + 1);
  }

  async function _audioFlotanteDetener() {
    if (!_audioFlot) return;
    if (!await _modalConfirm('¿Detener escucha?', { titulo: 'Detener escucha' })) return;
    await _audioFlotanteDetenerInterno(true);
    toast('⏹️ Escucha detenida', 'ok');
  }

  // Detiene la sesión en server (si remoto=true) y limpia el widget
  async function _audioFlotanteDetenerInterno(remoto) {
    if (!_audioFlot) return;
    const idSesion = _audioFlot.idSesion;
    if (_audioFlot.polling) clearInterval(_audioFlot.polling);
    if (_audioFlot.contadorTimer) clearInterval(_audioFlot.contadorTimer);
    if (_audioFlot.watchdog20) clearTimeout(_audioFlot.watchdog20);
    if (_audioFlot.watchdog45) clearTimeout(_audioFlot.watchdog45);
    if (_audioFlot.watchdog90) clearTimeout(_audioFlot.watchdog90);
    if (_audioFlot.audioEl) { _audioFlot.audioEl.pause(); _audioFlot.audioEl.src = ''; _audioFlot.audioEl.onended = null; }
    const fl = document.getElementById('audioFlotante');
    if (fl) {
      fl.style.transition = 'all 0.3s ease-out';
      fl.style.transform = 'translateY(50px) scale(0.85)';
      fl.style.opacity = '0';
      setTimeout(() => fl.remove(), 320);
    }
    _audioFlot = null;
    if (remoto && idSesion) {
      try { await API.post('detenerEscuchaAudio', { idSesion }); } catch {}
    }
  }

  function _audioFlotanteCerrarSinDetener() {
    const fl = document.getElementById('audioFlotante');
    if (fl) fl.remove();
    if (_audioFlot) {
      if (_audioFlot.polling) clearInterval(_audioFlot.polling);
      if (_audioFlot.contadorTimer) clearInterval(_audioFlot.contadorTimer);
    }
    _audioFlot = null;
  }

  // ════════════════════════════════════════════════════════════
  // ESPÍA — orquestador audio + gps en modal grande + widget mini
  // ════════════════════════════════════════════════════════════
  // _espiaState:
  //   { deviceId, nombre, modalAbierto:bool, gpsPolling, gpsUlt, gpsRangoH }
  // Audio sigue manejado por _audioFlot (estado heredado), pero el widget
  // visible es #espiaFlotante (no #audioFlotante).
  let _espiaState = null;

  // Click en 🕵️ desde Personal del Día / Configuración Personal
  // Abre el modal INMEDIATAMENTE con datos en cache, refresca en background.
  async function abrirEspiaPorUsuario(nombre) {
    let devs = _buscarDispositivosDeUsuario(nombre);
    if (!devs.length) {
      // No hay en cache → buscar fresh (única vez que bloqueamos)
      await _refrescarDispositivosFresh();
      devs = _buscarDispositivosDeUsuario(nombre);
    }
    if (!devs.length) {
      toast(`⚠ ${nombre} no tiene dispositivos con su sesión`, 'warn', 5000);
      return;
    }
    if (devs.length === 1) {
      abrirEspiaDispositivo(devs[0].ID_Dispositivo);
      // Refrescar en background para próximas
      _refrescarDispositivosFresh().catch(() => {});
      return;
    }
    _selectorDispMostrar(nombre, devs, 'espia');
  }

  // ════════════════════════════════════════════════════════════════════
  // [v2.43.57] MODO ESPÍA V2 — WebRTC 4 streams (audio + cámara + screen + GPS)
  // ────────────────────────────────────────────────────────────────────
  // Layout: pantalla grande 70% + sidebar con audio/cámara/GPS.
  // Click cámara mini → swap con bounce. ⌖ → fullscreen.
  // Sincronización: badge color verde<2s, ámbar<5s, rojo>5s.
  // Efectos premium: glow halo, breathing LIVE, waveform real,
  // sonidos WebAudio sintetizados (pop/chime/shimmer/whoosh).
  // ════════════════════════════════════════════════════════════════════
  let _espiaV2 = null;  // { pc, sesionId, deviceId, masterId, streams:{}, pollTimer, focus:'pantalla', tsInicio }

  // Sonidos WebAudio sintetizados (sin samples)
  let _espiaAudioCtx = null;
  function _espiaSfx(tipo) {
    try {
      if (!_espiaAudioCtx) _espiaAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const ctx = _espiaAudioCtx; const t = ctx.currentTime;
      function tone(freq, dur, gainVal, opts) {
        const o = ctx.createOscillator(); const g = ctx.createGain();
        o.type = (opts && opts.type) || 'sine';
        o.frequency.value = freq;
        g.gain.value = gainVal;
        o.connect(g); g.connect(ctx.destination);
        o.start(t + (opts && opts.delay || 0));
        g.gain.exponentialRampToValueAtTime(0.001, t + (opts && opts.delay || 0) + dur);
        o.stop(t + (opts && opts.delay || 0) + dur + .05);
      }
      if (tipo === 'pop')      { tone(440, .08, .12, {type:'triangle'}); }
      else if (tipo === 'chime') {
        tone(880, .15, .12, {type:'sine'});
        tone(1320, .18, .10, {type:'sine', delay:.06});
      }
      else if (tipo === 'shimmer') {
        tone(660, .12, .10, {type:'triangle'});
        tone(990, .15, .08, {type:'triangle', delay:.05});
        tone(1320, .18, .06, {type:'triangle', delay:.10});
      }
      else if (tipo === 'whoosh') {
        const o = ctx.createOscillator(); const g = ctx.createGain();
        o.type='sawtooth'; o.frequency.setValueAtTime(200,t); o.frequency.exponentialRampToValueAtTime(1200,t+.25);
        g.gain.setValueAtTime(.001,t); g.gain.exponentialRampToValueAtTime(.08,t+.05); g.gain.exponentialRampToValueAtTime(.001,t+.3);
        o.connect(g); g.connect(ctx.destination); o.start(t); o.stop(t+.32);
      }
      else if (tipo === 'fail') {
        tone(440, .12, .15, {type:'sawtooth'});
        tone(220, .15, .12, {type:'sawtooth', delay:.08});
      }
    } catch(_){}
  }

  // Punto de entrada — pide clave + crea sesión + abre modal optimista
  async function abrirEspiaV2(idDispositivo) {
    if (!_esMasterSession()) { toast('Solo Master puede usar espía v2', 'error'); return; }
    const d = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === idDispositivo);
    if (!d) { toast('Dispositivo no encontrado', 'error'); return; }
    // [v2.43.79] Limpiar zombis ANTES de mostrar prompt. Modal espiaV2Modal tiene
    // z-index 2147483646 (max int). Si quedó zombi de intento anterior, tapa
    // visualmente al modal de la clave (z-index 1500) y el master ve "nada
    // pasa" al click. Bug reproducido por el user en v2.43.77.
    const zombiModal = document.getElementById('espiaV2Modal');
    if (zombiModal) { console.warn('[espia master] limpiando modal zombi'); zombiModal.remove(); }
    if (_espiaV2 && _espiaV2.deviceId === idDispositivo) {
      toast('Ya estás conectado a este dispositivo', 'info');
      return;
    }
    if (_espiaV2) {
      const ok = await _modalConfirm(`Ya hay sesión activa con ${_espiaV2.nombre}. ¿Cerrarla y abrir nueva?`, { warning: true });
      if (!ok) return;
      _espiaV2Cerrar('cambio');
    }
    // [v2.43.64] Pedir clave admin tier 3 ANTES de crear sesión.
    // Bug histórico: v2.43.59 usaba _modalConfirm con promptInput, pero esa
    // función NO soporta inputs (es solo Sí/No), por eso devolvía true y el
    // regex /^\d{8}$/ fallaba → toast "Operación cancelada o clave inválida".
    // Fix: usar _modalPrompt que sí pinta input password.
    const claveAdmin = await _modalPrompt(
      `Para iniciar monitoreo en vivo de "${d.Nombre_Equipo || idDispositivo}":`,
      '',
      {
        titulo: '🛰️ Autorización Master',
        okText: 'Conectar',
        placeholder: '••••••••',
        inputType: 'password',
        inputMode: 'numeric',
        maxlength: 8
      }
    );
    if (claveAdmin === false || claveAdmin == null) {
      // Cancelado por el user — sin toast estridente
      return;
    }
    if (!/^\d{8}$/.test(String(claveAdmin))) {
      toast('La clave debe ser 8 dígitos (4 globales + 4 personales)', 'warn');
      return;
    }
    _espiaSfx('pop');
    const nombre = d.Ultima_Sesion || d.Nombre_Equipo || idDispositivo;
    _espiaV2 = {
      _claveAdmin: claveAdmin,
      sesionId: null,
      deviceId: idDispositivo,
      nombre: nombre,
      pc: null,
      streams: { audio: null, camara: null, camara2: null, pantalla: null },
      gpsUlt: null,
      pollTimer: null,
      pollIceDesde: 0,
      focus: 'pantalla',
      tsInicio: Date.now(),
      lagMs: 0,
      estado: 'conectando'
    };
    _espiaV2RenderModal();
    // Crear sesión backend
    // [v2.43.66] API.post devuelve d.data DIRECTO (no {ok,data}). Bug histórico
    // documentado en memoria architecture_mos_api_shape.md — caí igual.
    console.log('[espia master] arrancando · deviceId=' + idDispositivo + ' master=' + (S.session?.idPersonal || S.session?.nombre || 'master'));
    try {
      console.log('[espia master] llamando espiaCrearSesion al backend...');
      const _masterId = S.session?.idPersonal || S.session?.nombre || 'master';
      let r = null;
      // [F6 espía · cero-GAS] Supabase-first: mos.espia_crear_sesion + wake push data-only por Edge. Fallback GAS.
      if (window.ESPIA_DIRECTO !== false && API.espiaRpc) {
        try {
          const cr = await API.espiaRpc('espia_crear_sesion', { masterId: _masterId, deviceId: idDispositivo, claveAdmin });
          if (cr && cr.ok && cr.data && cr.data.sesionId) {
            let pushOk = false;
            try {
              const tk = await API.fcmTokenDispositivo(idDispositivo);
              const fcm = (tk && tk.data && tk.data.fcmToken) || '';
              if (fcm) {
                const pr = await API.pushEdge({ op: 'send', tokens: [fcm], silencioso: true,
                  data: { idNotif: 'MOS_ESPIA_INICIAR', action: 'MOS_ESPIA_INICIAR', sesionId: cr.data.sesionId, masterId: _masterId, ttl: String(cr.data.ttl || 600000) } });
                pushOk = !!(pr && pr.ok && pr.data && pr.data.enviados > 0);
              }
            } catch (_) { /* push best-effort */ }
            r = { sesionId: cr.data.sesionId, token: 'sb:' + cr.data.sesionId, ttl: cr.data.ttl, pushOk };
          } else if (cr && cr.ok === false && !/APP_NO_AUTORIZADA/.test(String(cr.error || ''))) {
            // rechazo de negocio (clave mala / EN_VIVO otro master) → mostrar y NO ir a GAS (daría lo mismo).
            toast(cr.error || 'No se pudo iniciar el espía', 'error', 7000);
            _espiaV2Cerrar('error_init');
            return;
          }
        } catch (_) { /* → GAS */ }
      }
      if (!r) {
        r = await API.post('espiaCrearSesion', { masterId: _masterId, deviceId: idDispositivo, claveAdmin });
      }
      console.log('[espia master] respuesta backend:', r);
      if (!r || !r.sesionId) {
        toast('Backend no devolvió sesionId', 'error');
        _espiaV2Cerrar('error_init');
        return;
      }
      _espiaV2.sesionId = r.sesionId;
      _espiaV2.token    = r.token || null; // [v2.43.90] token HMAC
      _espiaV2.ttl      = r.ttl;
      // [v2.43.90] Si los 3 reintentos de FCM fallaron, avisar al master claramente
      // y NO crear el WebRTC — el device no se va a enterar de nada.
      if (r.pushOk === false) {
        toast('No se pudo notificar al dispositivo (FCM falló ' + (r.pushIntentos || 3) + 'x). Revisá tokens y volvé a intentar.', 'error', 9000);
        _espiaV2Cerrar('push_fallo');
        return;
      }
      _espiaV2IniciarPeerConnection();
    } catch(e) {
      // [v2.43.66] Si el backend devuelve 500, fetch ve "Failed to fetch" por CORS
      // (Apps Script no devuelve headers CORS en error). Diferenciamos por code.
      const msg = String(e?.message || 'Error desconocido');
      if (e?.code === 'NETWORK' || /Failed to fetch/i.test(msg)) {
        toast('⚠ Backend rechazó la petición (500). Revisá logs Apps Script o intentá de nuevo.', 'error', 8000);
      } else {
        toast('Error: ' + msg, 'error');
      }
      _espiaV2Cerrar('error_init');
    }
  }

  // [v2.43.90] Helper que inyecta token HMAC automáticamente en cada call.
  // Equivalente al _espiaCliWHPost del cliente. Todas las llamadas del módulo
  // espía pasan por acá.
  // [F6 espía · cero-GAS] acción→RPC Supabase (mos.espia_*). Supabase-first, fallback GAS. Mismo shape {ok,data}.
  const _ESPIA_RPC_MASTER = {
    espiaSync: 'espia_sync', espiaPushBatch: 'espia_push_batch', espiaSubirOferta: 'espia_subir_oferta',
    espiaSubirRespuesta: 'espia_subir_respuesta', espiaSubirRenegRespuesta: 'espia_subir_reneg_respuesta',
    espiaAgregarIce: 'espia_agregar_ice', espiaReportarStreams: 'espia_reportar_streams', espiaCerrarSesion: 'espia_cerrar_sesion'
  };
  async function _espiaApiPost(action, params) {
    const body = Object.assign({}, params || {});
    const rpc = _ESPIA_RPC_MASTER[action];
    if (rpc && window.ESPIA_DIRECTO !== false && API.espiaRpc) {
      // [40x fix] DESEMPAQUETAR .data: el loop master lee d.estado/sdpRespuesta/ice PLANO (GAS API.post ya
      // desempaqueta). Sin esto, vía Supabase quedaban undefined → master colgado (no aplica answer/ICE/cierre).
      try { const out = await API.espiaRpc(rpc, body); if (out) return (out.data !== undefined ? out.data : out); } catch (_) { /* → GAS */ }
    }
    const token = _espiaV2?.token;
    if (token && body.token === undefined) body.token = token;
    return await API.post(action, body);
  }

  async function _espiaV2IniciarPeerConnection() {
    if (!_espiaV2) return;
    // [v2.43.90] Pedir iceServers al backend (TURN si configurado).
    // Sin TURN, ~10% de redes con NAT simétrico no conectan jamás.
    let iceServers = [{ urls: ['stun:stun.l.google.com:19302', 'stun:stun1.l.google.com:19302'] }];
    try {
      const cfg = await API.post('espiaConfig', {});
      if (Array.isArray(cfg?.iceServers) && cfg.iceServers.length) {
        iceServers = cfg.iceServers;
        if (cfg.tieneTurn) console.log('[espia master] TURN disponible');
      }
    } catch(eC) { console.warn('[espia master] espiaConfig fallo (uso STUN local):', eC?.message); }
    if (!_espiaV2) return;
    const pc = new RTCPeerConnection({ iceServers });
    _espiaV2.pc = pc;
    // [v2.43.90] Watchdog ICE failed → cierre graceful tras 30s
    _espiaV2._iceFailedDesde = 0;
    _espiaV2._iceWatchdogTimer = setInterval(() => {
      if (!_espiaV2 || !_espiaV2._iceFailedDesde) return;
      if (Date.now() - _espiaV2._iceFailedDesde > 30000) {
        console.warn('[espia master] ICE failed >30s · cerrando');
        toast('Conexión perdida con el dispositivo', 'warn');
        _espiaV2Cerrar('ice_failed_persistente');
      }
    }, 5000);
    // [v2.43.90] Timeout 45s en estado "conectando" — si el device no acepta
    // permisos o el WebRTC no completa, mostrar mensaje claro en vez de spinner eterno.
    _espiaV2._timeoutConectando = setTimeout(() => {
      if (!_espiaV2) return;
      if (_espiaV2.estado === 'live' || pc.connectionState === 'connected') return;
      toast('El dispositivo no respondió en 45s. Posibles causas: permisos no aceptados, pantalla apagada, sin red.', 'warn', 10000);
      _espiaV2Cerrar('timeout_conectando');
    }, 45000);
    // Track recibido: asignar al video/audio element del modal
    // [v2.43.77] Identificación robusta de pantalla. Antes solo miraba si
    // track.label contenía 'screen'/'display' — falla cuando Chrome devuelve
    // labels como 'web-contents-media-stream://...' o nombre de ventana →
    // se trataba como cámara y 'pantalla' quedaba esperando para siempre.
    // Fix: usar track.getSettings().displaySurface (solo existe en
    // getDisplayMedia tracks) + fallback al label.
    // [v2.43.91] Identificación robusta de tracks. Tres niveles de evidencia:
    //   1. trackTipoMap recibido por DataChannel 'gps' (mensaje __meta)
    //   2. track.contentHint propagado vía SDP ('detail'=pantalla, 'motion'=cam)
    //   3. fallback heurístico por label (legacy)
    // El primer track que llega puede no tener mapping todavía → asignamos por
    // contentHint y reasignamos cuando llegue el __meta. Por eso guardamos
    // referencias a ev.streams[0] junto al trackId para poder rebalancear.
    _espiaV2._tracksRecibidos = _espiaV2._tracksRecibidos || [];
    pc.ontrack = (ev) => {
      const stream = ev.streams[0];
      const track  = ev.track;
      const info = { trackId: track.id, stream, kind: track.kind, contentHint: track.contentHint };
      // [v2.43.99] Dedup por trackId — si llega el mismo track 2 veces (raro
      // pero posible en renegs largas), actualizar en lugar de duplicar.
      const idx = _espiaV2._tracksRecibidos.findIndex(t => t.trackId === info.trackId);
      if (idx >= 0) _espiaV2._tracksRecibidos[idx] = info;
      else _espiaV2._tracksRecibidos.push(info);
      _espiaV2AsignarTrack(info);
      _espiaSfx('chime');
      _espiaV2RenderModal();
    };
    // [v2.43.81] DataChannel STUB del lado master para forzar m=application
    // en el SDP offer. Sin esto, el cliente WH creaba un DataChannel 'gps'
    // pero el SDP no lo negociaba → readyState quedaba 'connecting' eterno.
    try {
      const stubDc = pc.createDataChannel('master-stub', { negotiated: false, ordered: true });
      stubDc.onopen = () => console.log('[espia master] stub DC abierto');
    } catch(eS) { console.warn('[espia master] no se pudo crear stub DC:', eS.message); }
    // [v2.43.90] ICE recovery + tracking de failed para watchdog 30s
    pc.oniceconnectionstatechange = () => {
      console.log('[espia master] ICE state:', pc.iceConnectionState);
      if (!_espiaV2) return;
      if (pc.iceConnectionState === 'failed') {
        if (!_espiaV2._iceFailedDesde) _espiaV2._iceFailedDesde = Date.now();
        try { pc.restartIce(); } catch(eRi) { console.warn('[espia master] restartIce fallo:', eRi.message); }
      } else if (pc.iceConnectionState === 'connected' || pc.iceConnectionState === 'completed') {
        _espiaV2._iceFailedDesde = 0;
      }
    };
    // DataChannel para GPS (device → master)
    pc.ondatachannel = (ev) => {
      const dc = ev.channel;
      console.log('[espia master] datachannel recibido:', dc.label);
      if (dc.label === 'gps') {
        dc.onmessage = (msg) => {
          try {
            const data = JSON.parse(msg.data);
            if (data && data.__meta === 'trackMap' && data.map) {
              _espiaV2AplicarTrackMap(data.map);
              return;
            }
            // [v2.43.100] Capabilities: el cliente describe su plataforma
            // (PC/móvil/tablet) para que el modal adapte UI sin adivinar.
            if (data && data.__meta === 'capabilities' && data.caps) {
              _espiaV2.capabilities = data.caps;
              console.log('[espia master] capabilities recibidas:', data.caps);
              _espiaV2AutoFocus();
              _espiaV2RenderModal();
              return;
            }
            // [v2.43.104] Visibility del cliente — pantalla bloqueada / desbloqueada
            if (data && data.__meta === 'visibility') {
              _espiaV2.deviceVisible = !!data.visible;
              _espiaV2._tsCambioVisibilidad = Date.now(); // usado para overlay timeout
              console.log('[espia master] device visibility:', data.visible ? 'visible' : 'hidden');
              _espiaV2RenderModal();
              return;
            }
            _espiaV2.gpsUlt = data;
            _espiaV2RenderGpsMini();
          } catch(_){}
        };
      }
    };
    // [v2.43.90] ICE batch — cola con flush cada 250ms vía espiaPushBatch
    _espiaV2._iceQueue = [];
    pc.onicecandidate = (ev) => {
      if (!_espiaV2 || !ev.candidate) return;
      const c = ev.candidate.toJSON ? ev.candidate.toJSON() : ev.candidate;
      _espiaV2._iceQueue.push(c);
    };
    _espiaV2._iceFlushTimer = setInterval(async () => {
      if (!_espiaV2 || !_espiaV2._iceQueue.length) return;
      const batch = _espiaV2._iceQueue.splice(0, _espiaV2._iceQueue.length);
      try {
        await _espiaApiPost('espiaPushBatch', {
          sesionId: _espiaV2.sesionId, lado: 'master',
          ice: batch.map(c => ({ ice: c }))
        });
      } catch(_){}
    }, 250);
    pc.onconnectionstatechange = () => {
      const st = pc.connectionState;
      if (!_espiaV2) return;
      _espiaV2.estado = st;
      if (st === 'connected') {
        _espiaSfx('chime');
        _espiaV2.estado = 'live';
        // [v2.43.90] Cancelar timeout 45s "conectando..." — ya conectó
        if (_espiaV2._timeoutConectando) {
          clearTimeout(_espiaV2._timeoutConectando);
          _espiaV2._timeoutConectando = null;
        }
        _espiaV2RenderModal();
      } else if (st === 'failed' || st === 'disconnected') {
        _espiaSfx('fail');
        _espiaV2.estado = st;
        _espiaV2RenderModal();
      }
    };
    // [v2.43.70] Guards defensivos contra cierre del modal durante awaits.
    const offer = await pc.createOffer({ offerToReceiveAudio: true, offerToReceiveVideo: true });
    if (!_espiaV2) return;
    await pc.setLocalDescription(offer);
    if (!_espiaV2) return;
    await _espiaApiPost('espiaSubirOferta', { sesionId: _espiaV2.sesionId, sdp: JSON.stringify(offer) });
    if (!_espiaV2) return;
    // Polling de respuesta + ICE del device
    _espiaV2.pollTimer = setInterval(_espiaV2Poll, 600);
  }

  // [v2.43.89 REFACTOR] BATCH SYNC — antes 3-4 round-trips Apps Script por tick,
  // ahora 1 con espiaSync. Devuelve respuesta inicial + reneg oferta + ICE del
  // device + estado en una sola llamada. Más rápido, menos cuota, menos races.
  async function _espiaV2Poll() {
    if (!_espiaV2 || !_espiaV2.sesionId) return;
    if (_espiaV2._pollEnCurso) return;
    _espiaV2._pollEnCurso = true;
    try {
      const t0 = Date.now();
      if (!_espiaV2.pc) return;

      const pc = _espiaV2.pc;
      const necesitaRespuesta = !pc.remoteDescription &&
                                !_espiaV2._settingAnswer &&
                                pc.signalingState === 'have-local-offer';
      const puedeReneg = pc.signalingState === 'stable' && !_espiaV2._renegEnCurso;

      // [v2.43.90] Backoff exponencial — saltamos ticks ante errores consecutivos
      if (_espiaV2._ticksAEsperar > 0) { _espiaV2._ticksAEsperar--; return; }

      // 1 sola llamada al backend que devuelve TODO lo que el master necesita
      let d;
      try {
        d = await _espiaApiPost('espiaSync', {
          sesionId: _espiaV2.sesionId,
          lado: 'master',
          iceDesde: _espiaV2.pollIceDesde || 0,
          necesito: {
            sdpRespuesta:    necesitaRespuesta,
            sdpRenegOferta:  puedeReneg,
            ice:             true
          }
        });
        if (_espiaV2 && _espiaV2._consErrores > 0) _espiaV2._consErrores = 0;
      } catch(eS) {
        if (_espiaV2) {
          _espiaV2._consErrores = (_espiaV2._consErrores || 0) + 1;
          _espiaV2._ticksAEsperar = Math.min(14, Math.pow(2, _espiaV2._consErrores) - 1);
        }
        throw eS;
      }
      if (!_espiaV2) return;
      if (!d) return;

      // (1) Cierre remoto — el device cerró por su lado o TTL expiró
      if (d.estado === 'CERRADA') {
        console.log('[espia master] backend reporta CERRADA · cerrando UI', d);
        // [v2.43.93] UX honesto — toast con causa probable antes de cerrar
        const motivo = d.motivoFin || 'desconocido';
        let mensaje = 'El dispositivo cerró la sesión';
        if (/ice_failed/i.test(motivo)) {
          mensaje = '⚠ Conexión imposible (NAT/firewall). Configurá TURN en Properties para redes móviles/corporativas.';
        } else if (/page_unload/i.test(motivo)) {
          mensaje = 'El usuario cerró la app en el dispositivo.';
        } else if (/connection_/i.test(motivo)) {
          mensaje = '⚠ La conexión WebRTC falló (' + motivo + '). Probablemente NAT simétrico sin TURN.';
        }
        toast(mensaje, 'warn', 8000);
        _espiaV2Cerrar('device_cerro');
        return;
      }

      // (2) Respuesta del handshake inicial
      if (necesitaRespuesta && d.sdpRespuesta) {
        _espiaV2._settingAnswer = true;
        try {
          if (_espiaV2 && !pc.remoteDescription && pc.signalingState === 'have-local-offer') {
            await pc.setRemoteDescription(JSON.parse(d.sdpRespuesta));
          }
        } catch(e) { console.warn('[espia] respuesta inválida', e?.message); }
        finally { if (_espiaV2) _espiaV2._settingAnswer = false; }
      }
      if (!_espiaV2) return;

      // (3) ICE candidates del device (batched).
      // [v2.43.93] addIceCandidate requiere remoteDescription previo. Si el
      // cliente sube ICE antes que el answer (ICE gathering empieza apenas
      // setLocalDescription dispara), los candidates llegan acá pero pc.remoteDescription
      // es null → se PERDÍAN silenciosos. Encolamos hasta tener remoteDescription.
      if (d.ice?.length) {
        if (!pc.remoteDescription) {
          _espiaV2._iceQueueAplicar = (_espiaV2._iceQueueAplicar || []).concat(d.ice);
          console.log('[espia master] ICE encolado · ' + d.ice.length + ' (sin remoteDescription aún)');
        } else {
          for (const c of d.ice) {
            try { await pc.addIceCandidate(c.ice); }
            catch(eC) { console.warn('[espia master] addIceCandidate fallo:', eC?.message); }
          }
        }
        if (_espiaV2 && d.tsMax) _espiaV2.pollIceDesde = d.tsMax;
      }
      // Drenar cola si ya tenemos remoteDescription (fue seteada en esta iter o anterior)
      if (_espiaV2 && pc.remoteDescription && _espiaV2._iceQueueAplicar?.length) {
        const cola = _espiaV2._iceQueueAplicar;
        _espiaV2._iceQueueAplicar = [];
        for (const c of cola) {
          try { await pc.addIceCandidate(c.ice); }
          catch(eC) { console.warn('[espia master] addIceCandidate cola fallo:', eC?.message); }
        }
        console.log('[espia master] ICE drenado · ' + cola.length + ' aplicados tras setRemoteDescription');
      }

      // (4) Renegociación: device subió oferta nueva (ej. agregó pantalla)
      if (_espiaV2 && puedeReneg && d.sdpRenegOferta) {
        _espiaV2._renegEnCurso = true;
        try {
          if (pc.signalingState !== 'stable') {
            // state cambió mientras esperábamos — descartar
          } else {
            const ofertaStr = d.sdpRenegOferta;
            const yaProcesada = _espiaV2._ultimaOfertaProcesada === ofertaStr;
            if (yaProcesada && _espiaV2._ultimaAnswerSinSubir) {
              // Subida de respuesta falló antes → solo reintentar subida
              console.log('[espia master] retry subida answer (no reprocesar)');
              await _espiaApiPost('espiaSubirRenegRespuesta', {
                sesionId: _espiaV2.sesionId,
                sdp: _espiaV2._ultimaAnswerSinSubir
              });
              _espiaV2._ultimaAnswerSinSubir = null;
            } else if (!yaProcesada) {
              console.log('[espia master] reneg offer detectada · procesando');
              await pc.setRemoteDescription(JSON.parse(ofertaStr));
              const newAnswer = await pc.createAnswer();
              await pc.setLocalDescription(newAnswer);
              const answerStr = JSON.stringify(newAnswer);
              _espiaV2._ultimaOfertaProcesada = ofertaStr;
              _espiaV2._ultimaAnswerSinSubir = answerStr;
              await _espiaApiPost('espiaSubirRenegRespuesta', {
                sesionId: _espiaV2.sesionId, sdp: answerStr
              });
              _espiaV2._ultimaAnswerSinSubir = null;
              console.log('[espia master] reneg answer enviada · pantalla negociada ✓');
            }
          }
        } catch(eR) {
          console.warn('[espia master reneg]', eR?.message);
        } finally {
          if (_espiaV2) _espiaV2._renegEnCurso = false;
        }
      }

      // Tracking de lag visible en el badge
      if (_espiaV2) {
        _espiaV2.lagMs = Date.now() - t0;
        _espiaV2RenderSyncBadge();
      }
    } catch(e) {
      console.warn('[espia poll]', e?.message || e);
    } finally {
      if (_espiaV2) _espiaV2._pollEnCurso = false;
    }
  }

  // [v2.43.97] Asigna un track recibido a streams[tipo].
  // Tipos posibles: audio | pantalla | camara | camara2 (smartphone dual-cam)
  function _espiaV2AsignarTrack(info) {
    if (!_espiaV2) return;
    let tipo;
    if (info.kind === 'audio') {
      tipo = 'audio';
    } else {
      // 1) Mapping explícito del DataChannel (incluye 'camara2')
      const mapeado = _espiaV2._trackTipoMap?.[info.trackId];
      if (mapeado) tipo = mapeado;
      // 2) contentHint vía SDP
      else if (info.contentHint === 'detail') tipo = 'pantalla';
      else if (info.contentHint === 'motion') {
        // si ya hay camara, el siguiente motion es camara2 (dual smartphone)
        tipo = _espiaV2.streams.camara ? 'camara2' : 'camara';
      }
      // 3) Default
      else if (_espiaV2.streams.camara && !_espiaV2.streams.pantalla) tipo = 'pantalla';
      else if (_espiaV2.streams.camara) tipo = 'camara2';
      else tipo = 'camara';
    }
    _espiaV2.streams[tipo] = info.stream;
    console.log('[espia ontrack] trackId=' + String(info.trackId).substring(0,8) + ' contentHint=' + (info.contentHint || '?') + ' → tipo=' + tipo);
    _espiaV2ActualizarStream(tipo, info.stream);
    // [v2.43.98] Si focus actual no tiene stream y este sí, hacer focus
    if (tipo !== 'audio') _espiaV2AutoFocus();
    _espiaApiPost('espiaReportarStreams', {
      sesionId: _espiaV2.sesionId,
      streams: {
        audio:    !!_espiaV2.streams.audio,
        camara:   !!_espiaV2.streams.camara,
        camara2:  !!_espiaV2.streams.camara2,
        pantalla: !!_espiaV2.streams.pantalla
      }
    }).catch(()=>{});
  }

  // [v2.43.98 FIX BUG #1] Two-pass apply atómico (mejor que el de v2.43.92).
  // Antes el loop podía borrar un slot recién asignado por otro track:
  //   trackA → camara2 (limpia camara donde estaba)
  //   trackB → camara  (limpia camara2 que acabamos de poner a trackA)
  //   → trackA perdido.
  // Pass 1 construye state objetivo. Pass 2 asigna de una vez. Los tracks NO
  // mencionados en el map preservan su slot previo por heurística/contentHint.
  function _espiaV2AplicarTrackMap(map) {
    if (!_espiaV2 || !map) return;
    _espiaV2._trackTipoMap = Object.assign({}, _espiaV2._trackTipoMap, map);
    const videos = (_espiaV2._tracksRecibidos || []).filter(t => t.kind === 'video');
    if (!videos.length) return;

    // Early exit: map vacío → nada que aplicar
    if (Object.keys(map).length === 0) return;

    const nuevoEstado = { camara: null, camara2: null, pantalla: null };
    // Pass 1a: aplicar mapping explícito (tiene prioridad)
    videos.forEach(t => {
      const tipoNuevo = map[t.trackId];
      if (tipoNuevo && ['camara', 'camara2', 'pantalla'].indexOf(tipoNuevo) >= 0) {
        nuevoEstado[tipoNuevo] = t.stream;
      }
    });
    // Pass 1b: tracks sin mapping → preservar su slot previo si está libre
    videos.forEach(t => {
      if (map[t.trackId]) return;
      ['camara', 'camara2', 'pantalla'].forEach(slot => {
        if (_espiaV2.streams[slot] === t.stream && !nuevoEstado[slot]) {
          nuevoEstado[slot] = t.stream;
        }
      });
    });
    // Pass 1c: tracks sin mapping cuyo slot previo está ocupado → cualquier slot libre
    // Sin este pass, un map parcial que mueve trackA al slot de trackB perdía trackB.
    videos.forEach(t => {
      if (map[t.trackId]) return;
      if (['camara','camara2','pantalla'].some(slot => nuevoEstado[slot] === t.stream)) return;
      const slotLibre = ['camara2', 'camara', 'pantalla'].find(slot => !nuevoEstado[slot]);
      if (slotLibre) nuevoEstado[slotLibre] = t.stream;
    });

    const cambio = nuevoEstado.camara   !== _espiaV2.streams.camara   ||
                   nuevoEstado.camara2  !== _espiaV2.streams.camara2  ||
                   nuevoEstado.pantalla !== _espiaV2.streams.pantalla;
    if (cambio) {
      // Pass 2: asignación atómica
      _espiaV2.streams.camara   = nuevoEstado.camara;
      _espiaV2.streams.camara2  = nuevoEstado.camara2;
      _espiaV2.streams.pantalla = nuevoEstado.pantalla;
      _espiaV2AutoFocus();
      console.log('[espia trackMap] reasignado · camara=' + !!_espiaV2.streams.camara + ' camara2=' + !!_espiaV2.streams.camara2 + ' pantalla=' + !!_espiaV2.streams.pantalla);
      _espiaV2RenderModal();
    }
  }

  // [v2.43.100] AutoFocus respeta capabilities.
  // En móvil donde tienePantalla=false, jamás vamos a tener stream de pantalla,
  // así que no tiene sentido siquiera intentar dejar focus en 'pantalla'.
  function _espiaV2AutoFocus() {
    if (!_espiaV2) return;
    if (_espiaV2.streams[_espiaV2.focus]) return;
    const caps = _espiaV2.capabilities;
    const orden = (caps && caps.tienePantalla === false)
      ? ['camara', 'camara2'] // móvil: pantalla no aplica nunca
      : ['pantalla', 'camara', 'camara2'];
    const primero = orden.find(k => !!_espiaV2.streams[k]);
    if (primero && primero !== _espiaV2.focus) {
      console.log('[espia focus] auto-switch · ' + _espiaV2.focus + ' → ' + primero);
      _espiaV2.focus = primero;
    }
  }

  function _espiaV2Cerrar(motivo) {
    if (!_espiaV2) return;
    try { _espiaSfx('whoosh'); } catch(_){}
    if (_espiaV2.pollTimer) clearInterval(_espiaV2.pollTimer);
    // [v2.43.90] Limpiar TODOS los timers nuevos
    try { clearInterval(_espiaV2._iceFlushTimer); } catch(_){}
    try { clearInterval(_espiaV2._iceWatchdogTimer); } catch(_){}
    try { clearTimeout(_espiaV2._timeoutConectando); } catch(_){}
    try { clearTimeout(_espiaV2._renderTimeout); } catch(_){}
    // Flush final ICE pendientes
    if (_espiaV2._iceQueue?.length && _espiaV2.sesionId && _espiaV2.token) {
      _espiaApiPost('espiaPushBatch', {
        sesionId: _espiaV2.sesionId, lado: 'master',
        ice: _espiaV2._iceQueue.map(c => ({ ice: c }))
      }).catch(()=>{});
    }
    try { _espiaV2.pc?.close(); } catch(_){}
    Object.values(_espiaV2.streams).forEach(s => {
      try { s?.getTracks().forEach(t => t.stop()); } catch(_){}
    });
    if (_espiaV2.sesionId) {
      _espiaApiPost('espiaCerrarSesion', { sesionId: _espiaV2.sesionId, motivo: motivo || 'manual', lado: 'master' }).catch(()=>{});
    }
    const modal = document.getElementById('espiaV2Modal');
    if (modal) {
      modal.style.animation = 'espiaV2Out .3s ease-out forwards';
      setTimeout(() => modal.remove(), 300);
    }
    _espiaV2 = null;
  }

  function _espiaV2RenderModal() {
    if (!_espiaV2) return;
    // [v2.43.98] Auto-focus defensivo antes de render — por si llegamos acá
    // con focus en slot vacío (race entre RenderModal y AsignarTrack).
    _espiaV2AutoFocus();
    const html = `<div id="espiaV2Modal" style="position:fixed;inset:0;background:rgba(0,0,0,.78);backdrop-filter:blur(10px);z-index:2147483646;display:flex;align-items:center;justify-content:center;padding:24px;animation:espiaV2In .35s cubic-bezier(.34,1.56,.64,1)">
      <div style="width:100%;max-width:1280px;height:88vh;background:linear-gradient(180deg,#0a1424,#070d18);border:1px solid rgba(99,102,241,.4);border-radius:18px;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 30px 70px -10px rgba(99,102,241,.4),0 0 0 1px rgba(99,102,241,.15) inset"
        onclick="event.stopPropagation()">
        <!-- HEADER -->
        <div style="padding:14px 20px;border-bottom:1px solid #1e293b;background:linear-gradient(135deg,rgba(99,102,241,.15),rgba(99,102,241,.03));display:flex;align-items:center;gap:14px;flex-shrink:0">
          <div id="espiaV2Live" class="espia-live-dot" style="display:flex;align-items:center;gap:8px">
            <span style="width:10px;height:10px;border-radius:50%;background:${_espiaV2.estado === 'live' ? '#10b981' : '#f59e0b'};animation:espiaBreath 2s ease-in-out infinite;box-shadow:0 0 10px ${_espiaV2.estado === 'live' ? '#10b981' : '#f59e0b'}"></span>
            <span style="font-size:11px;font-weight:900;color:${_espiaV2.estado === 'live' ? '#10b981' : '#f59e0b'};letter-spacing:.5px">${_espiaV2.estado === 'live' ? 'EN VIVO' : 'CONECTANDO'}</span>
          </div>
          ${(() => {
            // [v2.43.100] Badge de plataforma — el cliente reporta vía DataChannel
            const c = _espiaV2.capabilities;
            if (!c) return '';
            const meta = c.plataforma === 'mobile' ? { icon: '📱', color: '244,114,182' }
                       : c.plataforma === 'tablet' ? { icon: '📲', color: '139,92,246' }
                       : { icon: '🖥️', color: '14,165,233' };
            return `<div style="font-size:10px;font-weight:800;padding:4px 10px;border-radius:20px;background:rgba(${meta.color},.15);color:rgba(${meta.color},1);border:1px solid rgba(${meta.color},.4);display:flex;align-items:center;gap:5px"
                title="${_escapeHtml(c.modelo || '')} · ${c.camsTotales || 0} cam · pantalla=${c.tienePantalla ? 'sí' : 'no'}">
                ${meta.icon} ${_escapeHtml((c.modelo || c.plataforma).toUpperCase())}
              </div>`;
          })()}
          <div style="flex:1;min-width:0">
            <div style="font-size:13px;font-weight:700;color:#e2e8f0;display:flex;align-items:center;gap:6px">
              👤 ${_escapeHtml(_espiaV2.nombre)}
            </div>
            <div style="font-size:10px;color:#94a3b8;margin-top:1px">${_escapeHtml(_espiaV2.deviceId)}</div>
          </div>
          <div id="espiaV2SyncBadge" style="font-size:10px;font-weight:700;padding:4px 10px;border-radius:20px;background:rgba(16,185,129,.15);color:#10b981;border:1px solid rgba(16,185,129,.4)">
            sync OK · ${_espiaV2.lagMs}ms
          </div>
          <button onclick="MOS.cerrarEspiaV2()" style="background:rgba(248,113,113,.15);border:1px solid rgba(248,113,113,.4);color:#fca5a5;border-radius:8px;padding:6px 12px;font-size:14px;font-weight:900;cursor:pointer">✕</button>
        </div>
        <!-- BODY -->
        <div style="flex:1;display:flex;gap:14px;padding:14px;overflow:hidden">
          <!-- Stream grande -->
          ${(() => {
            // [v2.43.97] Label dinámico según focus actual
            const meta = {
              pantalla: { icon: '🖥️', label: 'PANTALLA DEL DISPOSITIVO', color: '16,185,129', glow: '#10b98155' },
              camara:   { icon: '📷', label: 'CÁMARA TRASERA',            color: '99,102,241', glow: '#6366f155' },
              camara2:  { icon: '📸', label: 'CÁMARA FRONTAL',            color: '244,114,182', glow: '#f472b655' }
            }[_espiaV2.focus] || { icon: '📷', label: 'CÁMARA', color: '99,102,241', glow: '#6366f155' };
            return `<div id="espiaV2Big" style="flex:1;background:#020617;border-radius:12px;overflow:hidden;position:relative;border:2px solid rgba(${meta.color},.5);box-shadow:0 0 30px -10px ${meta.glow};transition:border-color .3s,box-shadow .3s">
            <div id="espiaV2BigLabel" style="position:absolute;top:10px;left:12px;font-size:10px;font-weight:800;color:#fff;background:rgba(0,0,0,.65);padding:4px 10px;border-radius:6px;z-index:5;backdrop-filter:blur(4px)">
              ${meta.icon} ${meta.label}
            </div>`;
          })()}
            <button onclick="MOS._espiaV2Fullscreen()" style="position:absolute;top:10px;right:10px;background:rgba(0,0,0,.5);border:1px solid rgba(255,255,255,.2);color:#fff;border-radius:6px;padding:5px 9px;font-size:13px;cursor:pointer;z-index:5;backdrop-filter:blur(4px);transition:background .15s"
                    onmouseover="this.style.background='rgba(99,102,241,.5)'"
                    onmouseout="this.style.background='rgba(0,0,0,.5)'"
                    title="Fullscreen">⌖</button>
            <video id="espiaV2BigVideo" autoplay playsinline muted=false
                   style="width:100%;height:100%;object-fit:contain;background:#000"></video>
            ${!_espiaV2.streams[_espiaV2.focus] ? `
              <div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:linear-gradient(135deg,#0f172a,#0a1424);color:#64748b">
                <div style="width:50px;height:50px;border:3px solid rgba(99,102,241,.3);border-top-color:#6366f1;border-radius:50%;animation:espiaSpin 1s linear infinite"></div>
                <div style="margin-top:14px;font-size:11px;color:#94a3b8;font-weight:600">Conectando ${_espiaV2.focus}…</div>
              </div>` : ''}
            ${(() => {
              // [v2.43.104] Overlay standby SOLO si el device reportó hidden hace <2 min.
              // Después de 2 min de hidden sin recuperar, mostrar mensaje degradado
              // ('probablemente no va a volver') en vez del "esperando reanudación" eterno.
              if (_espiaV2.deviceVisible !== false) return '';
              const hidd = _espiaV2._tsCambioVisibilidad ? (Date.now() - _espiaV2._tsCambioVisibilidad) : 0;
              const segs = Math.floor(hidd / 1000);
              const muyLargo = hidd > 120000; // 2 min
              return `<div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:rgba(2,6,23,.78);backdrop-filter:blur(8px);color:#e2e8f0;z-index:10">
                <div style="font-size:48px;margin-bottom:8px">${muyLargo ? '⚠️' : '🌙'}</div>
                <div style="font-size:16px;font-weight:800;color:${muyLargo ? '#f59e0b' : '#a5b4fc'};letter-spacing:.3px">${muyLargo ? 'STANDBY PROLONGADO' : 'DISPOSITIVO EN STANDBY'}</div>
                <div style="margin-top:10px;font-size:11px;color:#94a3b8;max-width:280px;text-align:center;line-height:1.5">${muyLargo
                  ? 'Pantalla bloqueada hace +' + Math.floor(segs/60) + 'min. Probablemente los tracks fueron liberados por el SO.<br>Tendrás que reiniciar el espía.'
                  : 'El usuario bloqueó la pantalla o cambió de app.<br>El stream se reanudará al volver.'}</div>
                <div style="margin-top:14px;display:flex;align-items:center;gap:8px;font-size:9px;color:#64748b">
                  <span style="width:6px;height:6px;border-radius:50%;background:${muyLargo ? '#ef4444' : '#f59e0b'};animation:espiaBreath 1.5s ease-in-out infinite"></span>
                  ${muyLargo ? 'sin señal del device' : 'esperando reanudación (' + segs + 's)'}
                </div>
              </div>`;
            })()}
          </div>
          <!-- Sidebar -->
          <div style="width:260px;display:flex;flex-direction:column;gap:10px;flex-shrink:0">
            <!-- Audio card -->
            <div id="espiaV2AudioCard" style="background:#0f172a;border:1px solid rgba(34,211,238,.3);border-radius:10px;padding:11px;box-shadow:0 0 18px -8px #22d3ee44">
              <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
                <div style="font-size:9px;font-weight:800;color:#22d3ee;text-transform:uppercase;letter-spacing:.5px">🎤 AUDIO</div>
                <button onclick="MOS._espiaV2ToggleMute()" id="espiaV2MuteBtn" style="background:none;border:0;color:#94a3b8;cursor:pointer;font-size:13px" title="Silenciar">🔊</button>
              </div>
              <canvas id="espiaV2Wave" width="232" height="40" style="width:100%;height:40px;background:#000;border-radius:6px"></canvas>
              <div id="espiaV2AudioInfo" style="font-size:9px;color:#94a3b8;margin-top:5px;font-family:monospace">esperando…</div>
              <audio id="espiaV2AudioEl" autoplay></audio>
            </div>
            <!-- Mini card (el OTRO stream — click swap) -->
            <!-- [v2.43.91] El mini ahora muestra el stream que NO es el focus.
                 Si focus=pantalla → mini=cámara. Si focus=cámara → mini=pantalla.
                 Antes el mini era SIEMPRE cámara → al hacer swap a focus=cámara,
                 grande y mini mostraban lo mismo (cámara) y "pantalla" desaparecía. -->
            ${(() => {
              // [v2.43.97/98] Mini = siguiente en el ciclo. Si solo hay 1 video,
              // no renderizar el mini (sería redundante: grande y mini iguales).
              const orden = ['pantalla', 'camara', 'camara2'];
              const disponibles = orden.filter(k => !!_espiaV2.streams[k]);
              if (disponibles.length <= 1) return '';
              const idxActual = disponibles.indexOf(_espiaV2.focus);
              const siguienteKey = disponibles[(idxActual + 1) % disponibles.length] || disponibles[0];
              const metaPorTipo = {
                pantalla: { icon: '🖥️', label: 'PANTALLA',     color: '16,185,129' },
                camara:   { icon: '📷', label: 'CÁMARA TRASERA', color: '99,102,241' },
                camara2:  { icon: '📸', label: 'CÁMARA FRONTAL', color: '244,114,182' }
              };
              const meta = metaPorTipo[siguienteKey] || metaPorTipo.camara;
              const stream = _espiaV2.streams[siguienteKey];
              const totalMostrable = disponibles.length;
              return `<div id="espiaV2MiniCard" onclick="MOS._espiaV2Swap()" style="background:#0f172a;border:1px solid rgba(${meta.color},.3);border-radius:10px;padding:11px;cursor:pointer;transition:all .25s;box-shadow:0 0 18px -8px rgba(${meta.color},.28)"
                onmouseover="this.style.transform='translateY(-2px)';this.style.boxShadow='0 4px 24px -6px rgba(${meta.color},.55)'"
                onmouseout="this.style.transform='translateY(0)';this.style.boxShadow='0 0 18px -8px rgba(${meta.color},.28)'">
                <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
                  <div style="font-size:9px;font-weight:800;color:rgba(${meta.color},.95);text-transform:uppercase;letter-spacing:.5px">${meta.icon} ${meta.label}</div>
                  <span style="font-size:8px;color:#64748b">${totalMostrable > 2 ? (disponibles.indexOf(siguienteKey)+1) + '/' + totalMostrable + ' · ' : ''}click=swap</span>
                </div>
                <video id="espiaV2MiniVideo" autoplay playsinline muted
                       style="width:100%;height:90px;object-fit:cover;background:#000;border-radius:6px"></video>
                ${!stream ? `
                  <div style="position:relative;margin-top:-90px;height:90px;display:flex;align-items:center;justify-content:center;background:#020617;border-radius:6px">
                    <div style="width:24px;height:24px;border:2px solid rgba(${meta.color},.3);border-top-color:rgba(${meta.color},1);border-radius:50%;animation:espiaSpin 1s linear infinite"></div>
                  </div>` : ''}
              </div>`;
            })()}
            <!-- [v2.43.102] Cards 'no soportada' — solo en móviles donde tiene sentido -->
            ${(() => {
              const c = _espiaV2.capabilities;
              if (!c) return '';
              const cards = [];
              // PANTALLA solo se muestra como "no soportada" en móvil/tablet.
              // En desktop sin pantalla la causa real es probablemente otra
              // (user rechazó, o no la pidió), no que la API falte.
              if (c.tienePantalla === false && c.esMobile) {
                cards.push({ icon: '🖥️', label: 'PANTALLA', motivo: 'No disponible en móviles (limitación del navegador)' });
              }
              // 2DA CÁMARA: solo en móvil. En desktop no es algo que se espera.
              // [v2.43.107] Mensaje específico según dualFallReason del cliente
              if (c.esMobile && c.dualIntentado) {
                const ca = c.camsAbiertas || 0;
                if (ca < 2) {
                  const motivos = {
                    'hardware_single_cam':       'Este dispositivo solo tiene 1 cámara',
                    'deviceids_opacos':          'El navegador oculta el ID de la 2da cámara (faltan permisos)',
                    'browser_no_permite_concurrent': 'El navegador no permite usar las 2 cámaras a la vez',
                    'browser_devolvio_misma_cam': 'El navegador devolvió la misma cámara al pedir la otra',
                  };
                  const motivo = motivos[c.dualFallReason]
                              || (c.dualFallReason?.startsWith('excepcion:') ? ('Error: ' + c.dualFallReason.substring(10)) : null)
                              || 'No se pudo abrir la 2da cámara';
                  cards.push({ icon: '📸', label: '2DA CÁMARA', motivo });
                }
              }
              return cards.map(card => `
                <div style="background:#0a0f1e;border:1px dashed rgba(100,116,139,.4);border-radius:10px;padding:11px;opacity:.65">
                  <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px">
                    <div style="font-size:9px;font-weight:800;color:#64748b;text-transform:uppercase;letter-spacing:.5px">${card.icon} ${card.label}</div>
                    <span style="font-size:8px;color:#475569">⛔ N/D</span>
                  </div>
                  <div style="font-size:9px;color:#64748b;line-height:1.4">${card.motivo}</div>
                </div>`).join('');
            })()}
            <!-- GPS mini -->
            <div style="background:#0f172a;border:1px solid rgba(236,72,153,.3);border-radius:10px;padding:11px;box-shadow:0 0 18px -8px #ec489944">
              <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px">
                <div style="font-size:9px;font-weight:800;color:#ec4899;text-transform:uppercase;letter-spacing:.5px">📍 GPS</div>
                <span id="espiaV2GpsDot" style="width:6px;height:6px;border-radius:50%;background:#475569"></span>
              </div>
              <div id="espiaV2GpsInfo" style="font-size:9px;color:#94a3b8;font-family:monospace;line-height:1.5">esperando…</div>
              <div id="espiaV2GpsMap" style="margin-top:6px;height:80px;background:#020617;border-radius:6px;display:flex;align-items:center;justify-content:center;color:#475569;font-size:20px">🗺️</div>
              <!-- [v2.43.72] Fallback: si GPS en vivo no llega, ver último registrado -->
              <button onclick="MOS.verUltimaUbicacionDispositivo('${_espiaV2.deviceId}')"
                style="margin-top:8px;width:100%;background:linear-gradient(135deg,rgba(59,130,246,.15),rgba(14,165,233,.10));border:1px solid rgba(59,130,246,.45);color:#93c5fd;border-radius:8px;padding:6px 8px;font-size:9px;font-weight:800;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:4px;letter-spacing:.3px;transition:all .2s"
                onmouseover="this.style.background='linear-gradient(135deg,rgba(59,130,246,.25),rgba(14,165,233,.18))'"
                onmouseout="this.style.background='linear-gradient(135deg,rgba(59,130,246,.15),rgba(14,165,233,.10))'"
                title="Si el GPS en vivo no llega, mostrar la última ubicación conocida desde el historial">
                🗺 ÚLTIMA UBICACIÓN
              </button>
            </div>
            <!-- Stats -->
            <div style="background:rgba(15,23,42,.5);border:1px solid #1e293b;border-radius:8px;padding:8px 10px;font-size:9px;color:#64748b;font-family:monospace;margin-top:auto">
              <div>sesión: ${(_espiaV2.sesionId || '—').slice(0,20)}</div>
              <div>estado: <span style="color:#a5b4fc">${_espiaV2.estado}</span></div>
            </div>
          </div>
        </div>
      </div>
      <style>
        @keyframes espiaV2In { from { opacity:0; transform:scale(.96) } to { opacity:1; transform:scale(1) } }
        @keyframes espiaV2Out { to { opacity:0; transform:scale(.96) } }
        @keyframes espiaBreath { 0%,100% { transform:scale(1);opacity:.85 } 50% { transform:scale(1.3);opacity:1 } }
        @keyframes espiaSpin { to { transform:rotate(360deg) } }
        #espiaV2Modal .espia-live-dot { transition:all .3s }
      </style>
    </div>`;
    const old = document.getElementById('espiaV2Modal');
    if (old) old.remove();
    document.body.insertAdjacentHTML('beforeend', html);
    // [v2.43.92] Cancelar setTimeout previo si renderModal corre múltiples veces
    // rápido (ej. cascada de ontrack + onconnectionstatechange + trackMap).
    // Sin esto, N setTimeouts se acumulan haciendo trabajo redundante.
    if (_espiaV2._renderTimeout) clearTimeout(_espiaV2._renderTimeout);
    _espiaV2._renderTimeout = setTimeout(() => {
      if (!_espiaV2) return;
      _espiaV2ActualizarStream(_espiaV2.focus, _espiaV2.streams[_espiaV2.focus]);
      // [v2.43.97] Mini = siguiente en ciclo de los disponibles
      const orden = ['pantalla', 'camara', 'camara2'];
      const disp = orden.filter(k => !!_espiaV2.streams[k]);
      if (disp.length >= 2) {
        const idx = disp.indexOf(_espiaV2.focus);
        const sigKey = disp[(idx + 1) % disp.length];
        _espiaV2ActualizarStream(sigKey, _espiaV2.streams[sigKey], 'espiaV2MiniVideo');
      }
      _espiaV2VincularAudio();
      _espiaV2DibujarWaveform();
      _espiaV2RenderGpsMini();
    }, 30);
  }

  function _espiaV2ActualizarStream(tipoFocus, stream, elementId) {
    if (!stream) return;
    const el = document.getElementById(elementId || 'espiaV2BigVideo');
    if (el && el.srcObject !== stream) el.srcObject = stream;
  }
  function _espiaV2VincularAudio() {
    if (!_espiaV2?.streams.audio) return;
    const a = document.getElementById('espiaV2AudioEl');
    if (a) a.srcObject = _espiaV2.streams.audio;
  }
  function _espiaV2DibujarWaveform() {
    if (!_espiaV2?.streams.audio) return;
    try {
      if (!_espiaAudioCtx) _espiaAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const ctx = _espiaAudioCtx;
      const src = ctx.createMediaStreamSource(_espiaV2.streams.audio);
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256;
      src.connect(analyser);
      const canvas = document.getElementById('espiaV2Wave');
      if (!canvas) return;
      const cctx = canvas.getContext('2d');
      const buf = new Uint8Array(analyser.frequencyBinCount);
      function draw() {
        if (!_espiaV2 || !document.getElementById('espiaV2Wave')) return;
        analyser.getByteFrequencyData(buf);
        cctx.fillStyle = '#000';
        cctx.fillRect(0, 0, canvas.width, canvas.height);
        const barW = canvas.width / buf.length;
        for (let i = 0; i < buf.length; i++) {
          const h = (buf[i] / 255) * canvas.height;
          const grad = cctx.createLinearGradient(0, canvas.height, 0, 0);
          grad.addColorStop(0, '#06b6d4');
          grad.addColorStop(1, '#22d3ee');
          cctx.fillStyle = grad;
          cctx.fillRect(i * barW, canvas.height - h, barW - 1, h);
        }
        // dB approx
        const promedio = buf.reduce((s, v) => s + v, 0) / buf.length;
        const info = document.getElementById('espiaV2AudioInfo');
        if (info) info.textContent = `${Math.round(promedio)} dB · live`;
        requestAnimationFrame(draw);
      }
      draw();
    } catch(_){}
  }
  function _espiaV2RenderGpsMini() {
    const info = document.getElementById('espiaV2GpsInfo');
    const dot = document.getElementById('espiaV2GpsDot');
    const mapBox = document.getElementById('espiaV2GpsMap');
    if (!info) return;
    const g = _espiaV2?.gpsUlt;
    if (!g) { info.textContent = 'esperando…'; if (dot) dot.style.background = '#475569'; return; }
    info.innerHTML = `lat ${g.lat?.toFixed(5)}<br>lng ${g.lng?.toFixed(5)}<br>vel ${(g.speed*3.6 || 0).toFixed(1)} km/h<br>acc ${g.acc?.toFixed(0)}m`;
    if (dot) {
      dot.style.background = '#10b981';
      dot.style.animation = 'espiaBreath 1s';
      setTimeout(() => { if (dot) dot.style.animation = ''; }, 1000);
    }
    // [v2.43.94] Google Maps embed sin API key (output=embed). UI limpia,
    // sin chip de "reportar problema" que tapaba el croquis en OSM embed.
    // No requiere billing ni Script Properties extra.
    if (mapBox && g.lat != null && g.lng != null) {
      const lat = g.lat, lng = g.lng;
      const src = `https://maps.google.com/maps?q=${lat.toFixed(6)},${lng.toFixed(6)}&hl=es&z=17&output=embed`;
      const linkAmplio = `https://www.google.com/maps?q=${lat.toFixed(6)},${lng.toFixed(6)}&z=17`;
      const iframe = mapBox.querySelector('iframe');
      if (!iframe) {
        mapBox.innerHTML = `<iframe src="${src}" style="border:0;width:100%;height:100%;border-radius:6px" loading="lazy" referrerpolicy="no-referrer"></iframe>
          <a href="${linkAmplio}" target="_blank" rel="noopener"
             style="position:absolute;top:4px;right:4px;background:rgba(15,23,42,.92);color:#a5b4fc;font-size:9px;font-weight:700;padding:3px 7px;border-radius:5px;text-decoration:none;border:1px solid #1e293b;backdrop-filter:blur(4px);z-index:5">ampliar ↗</a>`;
        mapBox.style.position = 'relative';
        mapBox.style.height = '150px';   // más alto: 110 → 150
        mapBox.style.background = '#020617';
        mapBox.style.borderRadius = '6px';
        mapBox.style.overflow = 'hidden';
        mapBox.style.fontSize = '';
        mapBox.style.color = '';
      } else if (Math.abs(parseFloat(iframe.dataset.lastLat || 0) - lat) > 0.0002 ||
                 Math.abs(parseFloat(iframe.dataset.lastLng || 0) - lng) > 0.0002) {
        // Refrescar src solo si movió >20m (evita reload constante por jitter)
        iframe.src = src;
        iframe.dataset.lastLat = lat;
        iframe.dataset.lastLng = lng;
        // Actualizar también el link de ampliar
        const link = mapBox.querySelector('a');
        if (link) link.href = linkAmplio;
      }
    }
  }
  function _espiaV2RenderSyncBadge() {
    const b = document.getElementById('espiaV2SyncBadge');
    if (!b || !_espiaV2) return;
    const lag = _espiaV2.lagMs;
    let color = '#10b981', bg = 'rgba(16,185,129,.15)', border = 'rgba(16,185,129,.4)', txt = 'sync OK';
    if (lag > 2000) { color = '#f59e0b'; bg = 'rgba(245,158,11,.15)'; border = 'rgba(245,158,11,.4)'; txt = 'sync lento'; }
    if (lag > 5000) { color = '#ef4444'; bg = 'rgba(239,68,68,.15)'; border = 'rgba(239,68,68,.4)'; txt = 'sync mal'; }
    b.style.color = color; b.style.background = bg; b.style.borderColor = border;
    b.textContent = `${txt} · ${lag}ms`;
  }
  function _espiaV2Swap() {
    if (!_espiaV2) return;
    _espiaSfx('shimmer');
    const caps = _espiaV2.capabilities;
    const ordenBase = (caps && caps.tienePantalla === false)
      ? ['camara', 'camara2']
      : ['pantalla', 'camara', 'camara2'];
    const disponibles = ordenBase.filter(k => !!_espiaV2.streams[k]);
    if (disponibles.length <= 1) {
      _espiaV2RenderModal();
      return;
    }
    const idxActual = disponibles.indexOf(_espiaV2.focus);
    const siguiente = disponibles[(idxActual + 1) % disponibles.length];
    _espiaV2.focus = siguiente;
    _espiaV2RenderModal();
  }
  function _espiaV2ToggleMute() {
    const a = document.getElementById('espiaV2AudioEl');
    const btn = document.getElementById('espiaV2MuteBtn');
    if (!a) return;
    a.muted = !a.muted;
    if (btn) btn.textContent = a.muted ? '🔇' : '🔊';
    _espiaSfx('pop');
  }
  function _espiaV2Fullscreen() {
    _espiaSfx('whoosh');
    const wrap = document.getElementById('espiaV2Big');
    if (!wrap) return;
    if (!document.fullscreenElement) {
      wrap.requestFullscreen?.().catch(() => {});
    } else {
      document.exitFullscreen?.();
    }
  }
  function cerrarEspiaV2() { _espiaV2Cerrar('manual'); }

  // ════════════════════════════════════════════════════════════════════
  // [v2.43.61] TIMELINE BUFFER HISTÓRICO — Reproduce chunks subidos del device
  // ════════════════════════════════════════════════════════════════════
  async function abrirTimelineBufferEspia(deviceId) {
    if (!_esMasterSession()) { toast('Solo Master', 'error'); return; }
    try { _opsBeep && _opsBeep('tac'); } catch(_){}
    const dispositivo = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === deviceId);
    const nombre = dispositivo?.Ultima_Sesion || dispositivo?.Nombre_Equipo || deviceId;
    // Modal optimista — abrir con loader y traer chunks
    const html = `<div id="espiaTimelineModal" style="position:fixed;inset:0;background:rgba(0,0,0,.75);backdrop-filter:blur(8px);z-index:2147483645;display:flex;align-items:center;justify-content:center;padding:24px;animation:espiaV2In .3s cubic-bezier(.34,1.56,.64,1)">
      <div style="width:100%;max-width:1100px;height:84vh;background:linear-gradient(180deg,#0a1424,#070d18);border:1px solid rgba(168,85,247,.4);border-radius:16px;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 30px 70px -10px rgba(168,85,247,.35)"
           onclick="event.stopPropagation()">
        <div style="padding:14px 20px;border-bottom:1px solid #1e293b;background:linear-gradient(135deg,rgba(168,85,247,.15),rgba(168,85,247,.03));display:flex;align-items:center;gap:14px;flex-shrink:0">
          <div style="font-size:22px">📼</div>
          <div style="flex:1;min-width:0">
            <div style="font-size:14px;font-weight:800;color:#c084fc;letter-spacing:.5px">TIMELINE BUFFER HISTÓRICO</div>
            <div style="font-size:11px;color:#94a3b8;margin-top:2px">${_escapeHtml(nombre)} · últimas 12h</div>
          </div>
          <select id="espiaTimelineTipo" onchange="MOS._espiaTimelineRecargar()" style="background:#0f172a;border:1px solid #334155;color:#cbd5e1;border-radius:6px;padding:5px 8px;font-size:11px">
            <option value="">Todos</option>
            <option value="audio_video">Audio + Cámara</option>
            <option value="screen">Pantalla</option>
          </select>
          <button onclick="MOS.cerrarTimelineEspia()" style="background:rgba(248,113,113,.15);border:1px solid rgba(248,113,113,.4);color:#fca5a5;border-radius:8px;padding:6px 12px;font-size:14px;cursor:pointer">✕</button>
        </div>
        <div id="espiaTimelinePlayer" style="flex:1;display:flex;align-items:center;justify-content:center;background:#020617;position:relative">
          <video id="espiaTimelineVideo" controls autoplay style="max-width:100%;max-height:100%;display:none"></video>
          <div id="espiaTimelinePlaceholder" style="text-align:center;color:#475569">
            <div style="font-size:48px;margin-bottom:12px">📼</div>
            <div style="font-size:13px;color:#94a3b8">Selecciona un chunk del timeline ↓</div>
          </div>
        </div>
        <div style="background:#0f172a;border-top:1px solid #1e293b;padding:14px 20px;min-height:140px;max-height:160px;overflow-y:auto;flex-shrink:0">
          <div id="espiaTimelineLista" style="display:flex;gap:8px;flex-wrap:wrap;align-items:flex-start">
            <div style="color:#64748b;font-size:11px;display:flex;align-items:center;gap:8px">
              <span style="width:16px;height:16px;border:2px solid rgba(168,85,247,.3);border-top-color:#c084fc;border-radius:50%;animation:espiaSpin .8s linear infinite"></span>
              Cargando chunks…
            </div>
          </div>
        </div>
      </div>
    </div>`;
    document.body.insertAdjacentHTML('beforeend', html);
    window._espiaTimelineState = { deviceId, chunks: [], filtroTipo: '' };
    await _espiaTimelineCargar(deviceId, '');
  }
  function cerrarTimelineEspia() {
    const m = document.getElementById('espiaTimelineModal');
    if (m) { m.style.animation = 'espiaV2Out .25s ease-out forwards'; setTimeout(() => m.remove(), 250); }
    window._espiaTimelineState = null;
  }
  async function _espiaTimelineCargar(deviceId, tipoFiltro) {
    try {
      const r = await API.post('espiaListarChunks', {
        deviceId, tipo: tipoFiltro || '',
        desde: Date.now() - 12 * 3600000,
        hasta: Date.now()
      });
      // [v2.43.66] API.post desempaqueta — r es directo el data
      const chunks = (r && r.chunks) || [];
      window._espiaTimelineState.chunks = chunks;
      _espiaTimelineRenderLista();
    } catch(e) {
      const lista = document.getElementById('espiaTimelineLista');
      if (lista) lista.innerHTML = `<div style="color:#f87171;font-size:11px">⚠ Error: ${_escapeHtml(e.message)}</div>`;
    }
  }
  function _espiaTimelineRecargar() {
    const tipoEl = document.getElementById('espiaTimelineTipo');
    const tipo = tipoEl ? tipoEl.value : '';
    if (window._espiaTimelineState) {
      window._espiaTimelineState.filtroTipo = tipo;
      _espiaTimelineCargar(window._espiaTimelineState.deviceId, tipo);
    }
  }
  function _espiaTimelineRenderLista() {
    const lista = document.getElementById('espiaTimelineLista');
    if (!lista) return;
    const st = window._espiaTimelineState;
    if (!st || !st.chunks.length) {
      lista.innerHTML = `<div style="color:#475569;font-size:11px;display:flex;align-items:center;gap:8px">
        🌙 No hay chunks del rango. (¿El device tuvo sesión espía activa?)
      </div>`;
      return;
    }
    lista.innerHTML = st.chunks.map(c => {
      const fecha = new Date(c.ts);
      const hh = String(fecha.getHours()).padStart(2,'0');
      const mm = String(fecha.getMinutes()).padStart(2,'0');
      const dd = String(fecha.getDate()).padStart(2,'0');
      const mo = String(fecha.getMonth()+1).padStart(2,'0');
      const icon = c.tipo === 'screen' ? '🖥️' : '🎤📷';
      const color = c.tipo === 'screen' ? '#a5b4fc' : '#22d3ee';
      return `<button onclick="MOS._espiaTimelineReproducir('${c.fileId}','${_escapeHtml(c.nombre)}')"
        style="background:#1e293b;border:1px solid ${color}55;color:#cbd5e1;border-radius:8px;padding:8px 11px;font-size:10px;cursor:pointer;display:flex;flex-direction:column;align-items:flex-start;gap:3px;transition:all .15s;min-width:108px;text-align:left"
        onmouseover="this.style.background='${color}22';this.style.borderColor='${color}'"
        onmouseout="this.style.background='#1e293b';this.style.borderColor='${color}55'">
        <div style="font-size:13px">${icon}</div>
        <div style="font-weight:700;color:${color}">${dd}/${mo} ${hh}:${mm}</div>
        <div style="opacity:.7;font-size:9px">${c.tamMB}MB</div>
      </button>`;
    }).join('');
  }
  function _espiaTimelineReproducir(fileId, nombre) {
    try { _opsBeep && _opsBeep('tac'); } catch(_){}
    const v = document.getElementById('espiaTimelineVideo');
    const ph = document.getElementById('espiaTimelinePlaceholder');
    if (!v) return;
    // Drive iframe preview en lugar de src directo (auth + streaming).
    // Reemplazamos el video por iframe del preview de Drive.
    const player = document.getElementById('espiaTimelinePlayer');
    if (player) {
      player.innerHTML = `<iframe src="https://drive.google.com/file/d/${fileId}/preview"
        style="width:100%;height:100%;border:0" allow="autoplay"></iframe>
        <div style="position:absolute;top:8px;left:12px;background:rgba(0,0,0,.65);color:#fff;padding:4px 10px;border-radius:6px;font-size:10px;backdrop-filter:blur(4px)">▶ ${_escapeHtml(nombre)}</div>`;
    }
  }

  // Inicia espía (audio + gps) y abre el modal grande SIN bloquear.
  async function abrirEspiaDispositivo(idDispositivo) {
    const d = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === idDispositivo);
    if (!d) { toast('Dispositivo no encontrado', 'error'); return; }
    const nombre = d.Ultima_Sesion || d.Nombre_Equipo || idDispositivo;

    // 1) Si ya hay otra sesión activa, confirmar switch
    if (_espiaState && _espiaState.deviceId !== idDispositivo) {
      if (!await _modalConfirm(`Ya estás espiando a ${_espiaState.nombre}.\n\n¿Detener esa sesión y empezar a espiar a ${nombre}?\n\nSi dices NO, seguirás espiando a ${_espiaState.nombre}.`, { warning: true, titulo: 'Cambiar de objetivo', okText: 'Sí, cambiar' })) return;
      _espiaDetenerTodo(true); // sin await — limpieza en background
    }

    // 2) Marcar state
    _espiaState = {
      deviceId: idDispositivo,
      nombre,
      modalAbierto: false,
      gpsPolling: null,
      gpsUlt: null,
      gpsRangoH: 24,
      _avisosTimers: []
    };

    // 3) Abrir modal INMEDIATO (feedback visual sin esperar API)
    _espiaModalAbrir();

    // 4) Mostrar avisos según diagnóstico inicial (conexión vieja, etc)
    _espiaActualizarAvisos();

    // 5) Iniciar audio + gps en paralelo (sin bloquear UI)
    _espiaIniciarAudio(idDispositivo);
    _espiaIniciarGps(idDispositivo);
  }

  // ── AVISOS dentro del modal: en lugar de confirms bloqueantes ──
  function _espiaActualizarAvisos() {
    if (!_espiaState) return;
    const cont = $('espiaAvisos');
    if (!cont) return;
    const avisos = [];
    const d = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === _espiaState.deviceId);
    // 1) Última conexión
    const ultMs = new Date(d?.Ultima_Conexion || 0).getTime() || 0;
    const mins = ultMs ? (Date.now() - ultMs) / 60000 : Infinity;
    if (!ultMs) {
      avisos.push({
        nivel: 'error', ico: '📡',
        titulo: 'Sin reportes de conexión',
        detalle: 'Este dispositivo nunca ha reportado heartbeat — puede no estar registrado correctamente.'
      });
    } else if (mins > 60) {
      const horas = Math.floor(mins / 60);
      avisos.push({
        nivel: 'error', ico: '📡',
        titulo: `App parece cerrada (hace ${horas}h)`,
        detalle: 'El comando de escucha puede no llegar hasta que abra la app o reciba un push.'
      });
    } else if (mins > 10) {
      avisos.push({
        nivel: 'warn', ico: '📡',
        titulo: `Última conexión hace ${Math.floor(mins)} min`,
        detalle: 'La app puede estar en background — el comando podría tardar.'
      });
    }
    // 2) Audio sin chunks tras 30s = sin permiso
    if (_audioFlot && _audioFlot.deviceId === _espiaState.deviceId &&
        _audioFlot.idSesion && _audioFlot.chunks.length === 0 &&
        (Date.now() - _audioFlot.inicio) > 30000) {
      avisos.push({
        nivel: 'warn', ico: '🎙️',
        titulo: 'Audio sin permiso o app cerrada',
        detalle: 'No se reciben chunks. Verifica que el dispositivo tenga permiso de micrófono concedido.'
      });
    }
    // 3) GPS sin reportes
    if (_espiaState.gpsRevisado && !_espiaState.gpsUlt) {
      avisos.push({
        nivel: 'warn', ico: '📍',
        titulo: 'GPS desconectado',
        detalle: 'El dispositivo no ha reportado ubicación todavía. Pídele que abra la app.'
      });
    }
    cont.innerHTML = avisos.map(a => `
      <div class="espia-aviso espia-aviso-${a.nivel}">
        <span class="espia-aviso-ico">${a.ico}</span>
        <div class="espia-aviso-cuerpo">
          <div class="espia-aviso-titulo">${a.titulo}</div>
          <div class="espia-aviso-detalle">${a.detalle}</div>
        </div>
      </div>`).join('');
    // Re-evaluar cada 10s mientras el modal está abierto
    if (_espiaState.modalAbierto) {
      clearTimeout(_espiaState._avisosNextTimer);
      _espiaState._avisosNextTimer = setTimeout(() => {
        if (_espiaState && _espiaState.modalAbierto) _espiaActualizarAvisos();
      }, 10000);
    }
  }

  function _espiaModalAbrir() {
    if (!_espiaState) return;
    const sub = $('espiaModalSubtitle');
    if (sub) {
      const d = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === _espiaState.deviceId);
      sub.textContent = `${_espiaState.nombre}${d?.Nombre_Equipo ? ' · ' + d.Nombre_Equipo : ''}`;
    }
    const dev = $('espiaModalDeviceId');
    if (dev) dev.value = _espiaState.deviceId;
    const btnHist = $('espiaModalBtnHist');
    if (btnHist) btnHist.classList.toggle('hidden', !_esRolMaster());
    // Esconder widget instantáneamente (sin animación de salida)
    const w = document.getElementById('espiaFlotante');
    if (w) w.style.display = 'none';
    openModal('modalEspia');
    _espiaState.modalAbierto = true;
    // Refrescar avisos cada vez que abrimos (puede haber cambiado el estado)
    _espiaActualizarAvisos();
  }

  // Cierra modal pero mantiene audio/gps corriendo → muestra widget
  function _espiaModalMinimizar() {
    if (!_espiaState) {
      try { closeModal('modalEspia'); } catch {}
      return;
    }
    closeModal('modalEspia');
    _espiaState.modalAbierto = false;
    clearTimeout(_espiaState._avisosNextTimer);
    _espiaWidgetMontar();
  }

  // Detiene audio + gps + remueve widget + cierra modal
  // Cierre INMEDIATO de UI; las llamadas API se hacen en background.
  async function _espiaDetenerTodo(silencioso) {
    if (!silencioso) {
      const nom = _espiaState?.nombre || 'el usuario';
      if (!await _modalConfirm(`🛑 DETENER el espionaje de ${nom}?\n\nSe cierra el audio y el rastreo GPS.\nEl indicador del widget desaparece.\n\nSi solo querés minimizar (seguir grabando en background), usá el botón ▾ del modal.`, { warning: true, titulo: 'Detener espionaje', okText: 'Detener todo' })) return;
    }
    if (!_espiaState && !document.getElementById('espiaFlotante') && !_audioFlot) return;

    const idSesion = _audioFlot?.idSesion;
    // 1) Limpiar estado / timers SÍNCRONO (UI responde de inmediato)
    if (_espiaState?.gpsPolling) clearInterval(_espiaState.gpsPolling);
    if (_espiaState?._avisosNextTimer) clearTimeout(_espiaState._avisosNextTimer);
    if (_audioFlot) {
      if (_audioFlot.polling) clearInterval(_audioFlot.polling);
      if (_audioFlot.contadorTimer) clearInterval(_audioFlot.contadorTimer);
      if (_audioFlot.watchdog20) clearTimeout(_audioFlot.watchdog20);
      if (_audioFlot.watchdog45) clearTimeout(_audioFlot.watchdog45);
      if (_audioFlot.watchdog90) clearTimeout(_audioFlot.watchdog90);
      if (_audioFlot.audioEl) { _audioFlot.audioEl.pause(); _audioFlot.audioEl.src = ''; _audioFlot.audioEl.onended = null; }
    }
    // 2) Cerrar modal y widget INMEDIATO
    try { closeModal('modalEspia'); } catch {}
    const w = document.getElementById('espiaFlotante');
    if (w) {
      w.style.transition = 'all 0.18s ease-out';
      w.style.transform = 'translateY(20px) scale(0.92)';
      w.style.opacity = '0';
      setTimeout(() => w.remove(), 180);
    }
    _audioFlot = null;
    _espiaState = null;
    if (!silencioso) toast('🛑 Espía detenido', 'ok');
    // 3) Avisar al server en background (sin bloquear UI)
    if (idSesion) {
      API.post('detenerEscuchaAudio', { idSesion }).catch(() => {});
    }
  }

  // ── Audio dentro del modal espía (sin crear el #audioFlotante viejo)
  async function _espiaIniciarAudio(idDispositivo) {
    // Reusar la maquinaria existente pero apuntar el audio al player del modal
    const dDisp = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === idDispositivo);
    if (!dDisp) return;
    const nombre = dDisp.Ultima_Sesion || dDisp.Nombre_Equipo || idDispositivo;

    // Si ya había _audioFlot de otro device, parar
    if (_audioFlot) await _audioFlotanteDetenerInterno(true);

    _espiaActualizarAudioSub('⌛ enviando comando...');

    let cmd;
    try {
      cmd = await API.post('iniciarEscuchaAudio', {
        deviceId: idDispositivo,
        autorizadoPor: S.session?.nombre || 'admin',
        razon: 'Espía remoto desde panel'
      });
    } catch(e) {
      _espiaActualizarAudioSub('⚠ ' + e.message);
      return;
    }
    if (!cmd?.idSesion) {
      _espiaActualizarAudioSub('⚠ Sin idSesion');
      return;
    }

    // Setup _audioFlot (mismo formato que el flotante viejo, pero el audio
    // element apunta al player del modal espía)
    const player = document.getElementById('espiaPlayerLive');
    _audioFlot = {
      deviceId: idDispositivo,
      nombre,
      idSesion: cmd.idSesion,
      chunks: [], idx: 0,
      chunksCargados: new Set(),
      audioEl: player,
      inicio: Date.now(),
      polling: null,
      contadorTimer: null,
      prefetched: new Map(),
      muted: false,
      origenEspia: true
    };
    // Encadenado al terminar
    if (player) {
      player.onended = () => {
        if (!_audioFlot) return;
        _audioFlot.idx++;
        _audioFlotanteReproducirSiguiente();
        _espiaActualizarAudioVista();
      };
    }
    // Pre-warm autoplay
    try {
      const silentWebm = 'data:audio/webm;base64,GkXfowEAAAAAAAAfQoaBAUL3gQFC8oEEQvOBCEKChHdlYm1Ch4EEQoWBAhhTgGcBAAAAAAAVkhFNm3RALE27i1OrhBVJqWZTrIHfTbuMU6uEFlSua1OsggEwTbuMU6uEHFO7a1OsggI+7AEAAAAAAACkAAAAAAAAAAAAAAAAAAA=';
      if (player) {
        player.src = silentWebm;
        player.volume = 0;
        player.play().then(() => {
          if (player) player.volume = _audioFlot?.muted ? 0 : 1;
        }).catch(() => {});
      }
    } catch(_) {}

    _espiaActualizarAudioSub('🔴 sesión iniciada · esperando chunks');
    _espiaActualizarAudioVista();

    // Contador
    _audioFlot.contadorTimer = setInterval(() => {
      if (!_audioFlot) return;
      const segs = Math.floor((Date.now() - _audioFlot.inicio) / 1000);
      const mm = String(Math.floor(segs / 60)).padStart(2, '0');
      const ss = String(segs % 60).padStart(2, '0');
      const t = $('espiaModalAudioTime');
      if (t) t.textContent = `${mm}:${ss}`;
      _espiaWidgetUpdate();
    }, 1000);

    // Polling de chunks
    setTimeout(_audioFlotantePollChunks, 800);
    _audioFlot.polling = setInterval(() => {
      _audioFlotantePollChunks();
      _espiaActualizarAudioVista();
    }, 2500);
  }

  function _espiaActualizarAudioSub(txt) {
    const el = $('espiaModalAudioSub');
    if (el) el.textContent = txt;
    const subW = document.querySelector('#espiaFlotante .espia-flot-sub');
    if (subW) subW.textContent = txt;
  }
  function _espiaActualizarAudioVista() {
    if (!_audioFlot) return;
    const c = $('espiaModalAudioChunks');
    if (c) c.textContent = `${_audioFlot.chunks.length} chunks · idx ${_audioFlot.idx + 1}`;
    if (_audioFlot.chunks.length > 0) {
      const sub = $('espiaModalAudioSub');
      if (sub) sub.textContent = _audioFlot.muted ? '🔇 muteado · grabación activa' : '🔴 escuchando en vivo';
    }
    _espiaWidgetUpdate();
    // Re-evaluar avisos: el primer chunk recibido limpia el aviso "sin permiso"
    if (_audioFlot.chunks.length === 1) _espiaActualizarAvisos();
  }

  // Toggle mute (no detiene grabación, solo silencia reproducción local)
  function _espiaToggleMute() {
    if (!_audioFlot || !_audioFlot.audioEl) return;
    _audioFlot.muted = !_audioFlot.muted;
    _audioFlot.audioEl.muted = _audioFlot.muted;
    const btn = $('espiaModalBtnMute');
    if (btn) btn.innerHTML = _audioFlot.muted ? '🔊 Quitar mute' : '🔇 Mutear';
    const ico = $('espiaModalMicIcon');
    if (ico) {
      ico.textContent = _audioFlot.muted ? '🔇' : '🎙️';
      ico.classList.toggle('muted', _audioFlot.muted);
    }
    _espiaActualizarAudioVista();
    _espiaWidgetUpdate();
  }

  // Abre el modal viejo de historial (solo master)
  function _espiaAbrirHistorial() {
    if (!_espiaState) return;
    abrirModalAudio(_espiaState.deviceId);
  }

  // ── GPS dentro del modal espía
  async function _espiaIniciarGps(idDispositivo) {
    if (_espiaState?.gpsPolling) clearInterval(_espiaState.gpsPolling);
    // Primer refresh sin bloquear; luego polling cada 15s
    _espiaGpsRefresh();
    if (!_espiaState) return;
    _espiaState.gpsPolling = setInterval(_espiaGpsRefresh, 15000);
  }

  async function _espiaGpsRefresh() {
    if (!_espiaState) return;
    const id = _espiaState.deviceId;
    const info = $('espiaModalGpsInfo');
    const mapa = $('espiaModalGpsMapa');
    const cantEl = $('espiaModalGpsPuntos');
    try {
      const ult = await API.get('getUltimaUbicacionDispositivo', { deviceId: id });
      const hist = await API.get('getUbicacionesDispositivo', { deviceId: id, horas: _espiaState.gpsRangoH });
      if (_espiaState) _espiaState.gpsRevisado = true;
      if (!ult) {
        if (info) info.innerHTML = '<span class="text-amber-400">⚠ Sin ubicación reportada</span>';
        const sub = $('espiaModalGpsSub');
        if (sub) sub.textContent = 'Sin reportes';
        _espiaActualizarAvisos();
        return;
      }
      _espiaState.gpsUlt = ult;
      const fecha = ult.timestamp ? new Date(ult.timestamp) : null;
      const mins = fecha ? Math.floor((Date.now() - fecha.getTime()) / 60000) : null;
      const fmt = fecha ? fecha.toLocaleString('es-PE', { hour:'2-digit', minute:'2-digit' }) : '—';
      const fresh = mins !== null && mins < 5;
      const dot = fresh ? '🟢' : (mins < 60 ? '🟡' : '🔴');
      const bat = ult.bateria !== '' && ult.bateria !== undefined ? ` · 🔋${ult.bateria}%` : '';
      if (info) {
        info.innerHTML = `<div class="text-white font-bold">${dot} ${fmt}${bat}</div>
          <div class="text-[10px] text-slate-400 mt-0.5">📍 ${parseFloat(ult.lat).toFixed(6)}, ${parseFloat(ult.lng).toFixed(6)} · ~${Math.round(ult.accuracy)}m</div>`;
      }
      const subM = $('espiaModalGpsSub');
      if (subM) {
        const txt = fresh ? '🟢 en vivo' : (mins < 60 ? `hace ${mins}min` : `hace ${Math.floor(mins/60)}h`);
        subM.textContent = txt;
      }
      const lnk = $('espiaModalGpsMaps');
      if (lnk) {
        lnk.href = `https://www.google.com/maps?q=${ult.lat},${ult.lng}`;
        lnk.classList.remove('hidden');
      }
      if (cantEl) cantEl.textContent = (Array.isArray(hist) ? hist.length : 0) + ' puntos · ' + _espiaState.gpsRangoH + 'h';
      if (mapa && (!mapa.dataset.lastLat || mapa.dataset.lastLat !== String(ult.lat) || mapa.dataset.lastLng !== String(ult.lng))) {
        mapa.innerHTML = `<iframe width="100%" height="100%" frameborder="0"
          src="https://maps.google.com/maps?q=${ult.lat},${ult.lng}&z=16&output=embed"
          style="border:none;"></iframe>`;
        mapa.dataset.lastLat = String(ult.lat);
        mapa.dataset.lastLng = String(ult.lng);
      }
      _espiaWidgetUpdate();
      _espiaActualizarAvisos();
    } catch(e) {
      if (info) info.innerHTML = '<span class="text-red-400">Error: ' + e.message + '</span>';
    }
  }

  function _espiaGpsRangoCambiar(horas) {
    if (!_espiaState) return;
    _espiaState.gpsRangoH = horas;
    _espiaGpsRefresh();
  }

  // ── Widget flotante mini ─────────────────────────────────
  function _espiaWidgetMontar() {
    if (!_espiaState) return;
    let w = document.getElementById('espiaFlotante');
    if (w) { w.style.display = 'flex'; _espiaWidgetUpdate(); return; }
    w = document.createElement('div');
    w.id = 'espiaFlotante';
    w.innerHTML = `
      <div class="espia-flot-emoji" data-open-modal="1">🕵️</div>
      <div class="espia-flot-info" data-open-modal="1">
        <div class="espia-flot-nom"></div>
        <div class="espia-flot-sub">⌛</div>
      </div>
      <div class="espia-flot-icons">
        <div class="espia-flot-ico espia-flot-ico-mic" title="Click: mutear / quitar mute (audio sigue grabando)">🎙️</div>
        <div class="espia-flot-ico espia-flot-ico-gps" title="Click: ver GPS en modal">📍</div>
        <button class="espia-flot-stop" title="Detener todo">×</button>
      </div>`;
    document.body.appendChild(w);

    // Handlers nativos de click para los controles (mic / gps / stop)
    w.querySelector('.espia-flot-ico-mic').addEventListener('click', e => {
      e.stopPropagation();
      _espiaToggleMute();
    });
    w.querySelector('.espia-flot-ico-gps').addEventListener('click', e => {
      e.stopPropagation();
      _espiaModalAbrir();
      setTimeout(() => {
        const sec = document.getElementById('espiaSecGps');
        if (sec) sec.scrollIntoView({ behavior: 'smooth', block: 'start' });
        _espiaGpsRefresh();
      }, 120);
    });
    w.querySelector('.espia-flot-stop').addEventListener('click', e => {
      e.stopPropagation();
      _espiaDetenerTodo(false);
    });

    // Drag SOLO sobre el cuerpo (no controles). Click sobre cuerpo abre modal.
    let pStart = null, moved = false;
    const onDown = e => {
      // Si el pointerdown fue sobre un control, no iniciar drag (sus handlers click nativos manejan)
      if (e.target.closest('.espia-flot-ico') || e.target.closest('.espia-flot-stop')) return;
      pStart = { x: e.clientX, y: e.clientY };
      moved = false;
      w.setPointerCapture?.(e.pointerId);
      w.classList.add('dragging');
      w.style.right = 'auto'; w.style.bottom = 'auto';
      const r = w.getBoundingClientRect();
      w.dataset._sl = String(r.left);
      w.dataset._st = String(r.top);
    };
    const onMove = e => {
      if (!pStart) return;
      const dx = e.clientX - pStart.x, dy = e.clientY - pStart.y;
      if (!moved && (Math.abs(dx) > 5 || Math.abs(dy) > 5)) moved = true;
      if (moved) {
        const sl = parseFloat(w.dataset._sl || 0);
        const st = parseFloat(w.dataset._st || 0);
        w.style.left = (sl + dx) + 'px';
        w.style.top  = (st + dy) + 'px';
      }
    };
    const onUp = () => {
      if (!pStart) return;
      const wasMoved = moved;
      pStart = null; moved = false;
      w.classList.remove('dragging');
      // Click puro sobre cuerpo (sin drag) → abre modal
      if (!wasMoved) _espiaModalAbrir();
    };
    w.addEventListener('pointerdown', onDown);
    w.addEventListener('pointermove', onMove);
    w.addEventListener('pointerup', onUp);
    w.addEventListener('pointercancel', () => { pStart = null; moved = false; w.classList.remove('dragging'); });

    _espiaWidgetUpdate();
  }

  function _espiaWidgetUpdate() {
    const w = document.getElementById('espiaFlotante');
    if (!w || !_espiaState) return;
    const nom = w.querySelector('.espia-flot-nom');
    if (nom) nom.textContent = _espiaState.nombre;
    const mic = w.querySelector('.espia-flot-ico-mic');
    if (mic) {
      const live = !!(_audioFlot && _audioFlot.chunks.length > 0);
      const muted = !!(_audioFlot && _audioFlot.muted);
      mic.classList.toggle('live', live && !muted);
      mic.classList.toggle('muted', muted);
      mic.textContent = muted ? '🔇' : '🎙️';
    }
    const gps = w.querySelector('.espia-flot-ico-gps');
    if (gps && _espiaState.gpsUlt) {
      const fecha = new Date(_espiaState.gpsUlt.timestamp || 0).getTime();
      const mins = (Date.now() - fecha) / 60000;
      gps.classList.toggle('fresh', mins < 5);
      gps.classList.toggle('stale', mins >= 60);
    }
    const sub = w.querySelector('.espia-flot-sub');
    if (sub) {
      const segs = _audioFlot ? Math.floor((Date.now() - _audioFlot.inicio) / 1000) : 0;
      const mm = String(Math.floor(segs / 60)).padStart(2, '0');
      const ss = String(segs % 60).padStart(2, '0');
      const gpsTxt = _espiaState.gpsUlt ? '· 📍' : '';
      sub.textContent = `${mm}:${ss} ${gpsTxt}`;
    }
  }

  // Cuando cierran el modal por backdrop o ESC y hay sesión activa, mantener
  // el flujo: el handler espiaModal ya llama a _espiaModalMinimizar.
  // Ningún cleanup adicional necesario — _espiaState se limpia en _espiaDetenerTodo.

  async function _abrirModalAudioLive(idDispositivo) {
    const d = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === idDispositivo);
    if (!d) return;
    $('audioLiveDeviceId').value = idDispositivo;
    $('audioLiveSubtitle').textContent = `${d.Nombre_Equipo || idDispositivo}${d.Ultima_Sesion ? ' · 👤 ' + d.Ultima_Sesion : ''}`;
    openModal('modalAudioLive');
    await _audioLiveRefrescar();
    if (_audioLivePollTimer) clearInterval(_audioLivePollTimer);
    _audioLivePollTimer = setInterval(_audioLiveRefrescar, 10 * 1000);
  }

  async function _audioLiveRefrescar() {
    const id = $('audioLiveDeviceId')?.value;
    if (!id) return;
    const cont = $('audioLiveEstadoActual');
    if (!cont) return;
    try {
      const data = await API.get('getEstadoAudio', { deviceId: id });
      if (data?.activa) {
        const sesionId = data.sesion.idSesion;
        const ini = data.sesion.inicio ? new Date(data.sesion.inicio) : null;
        const segs = ini ? Math.floor((Date.now() - ini.getTime()) / 1000) : 0;
        const mm = String(Math.floor(segs / 60)).padStart(2, '0');
        const ss = String(segs % 60).padStart(2, '0');
        cont.innerHTML = `<div class="card p-3" style="background:rgba(239,68,68,0.10);border:1px solid #dc2626;">
          <div class="flex items-center justify-between gap-2 flex-wrap">
            <div>
              <div class="text-sm font-bold text-red-300">🔴 Grabando ahora</div>
              <div class="text-[10px] text-slate-500 font-mono">${mm}:${ss} · auto-stop a 30:00</div>
            </div>
            <button onclick="MOS._audioLiveDetener('${sesionId}')" class="btn-primary text-xs px-3 py-1.5" style="background:#dc2626">⏹️ Detener</button>
          </div>
          <p class="text-[10px] text-slate-500 mt-2">El audio se está guardando para revisión posterior por el master.</p>
        </div>`;
      } else {
        cont.innerHTML = `<div class="card p-3" style="background:#0a1424;border:1px solid #1e293b;">
          <div class="flex items-center justify-between gap-2 flex-wrap">
            <div>
              <div class="text-sm font-bold text-slate-300">⏸ Sin grabación activa</div>
              <div class="text-[10px] text-slate-500">Inicia la escucha cuando lo necesites</div>
            </div>
            <button onclick="MOS._audioLiveIniciar('${id}')" class="btn-primary text-xs px-3 py-1.5" style="background:#dc2626">🎙️ Iniciar</button>
          </div>
        </div>`;
      }
    } catch(_) {
      cont.innerHTML = '<div class="text-center py-3 text-red-400 text-sm">Error consultando estado</div>';
    }
  }

  async function _audioLiveIniciar(deviceId) {
    if (!await _modalConfirm('¿Iniciar escucha?\n\nEl dispositivo grabará en chunks de 15s. Auto-detiene a los 30 min.', { warning: true, titulo: 'Iniciar escucha en vivo', okText: 'Iniciar' })) return;
    try {
      await API.post('iniciarEscuchaAudio', {
        deviceId,
        autorizadoPor: S.session?.nombre || 'admin',
        motivo: 'Escucha en vivo desde MOS'
      });
      toast('🎙️ Comando enviado', 'ok');
      setTimeout(_audioLiveRefrescar, 1500);
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  async function _audioLiveDetener(idSesion) {
    try {
      await API.post('detenerEscuchaAudio', { idSesion });
      toast('⏹️ Detenido', 'ok');
      setTimeout(_audioLiveRefrescar, 1000);
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    }
  }

  // Cancelar poll cuando se cierra el live
  document.addEventListener('mos:modal-cerrado', e => {
    if (e.detail === 'modalAudioLive' && _audioLivePollTimer) {
      clearInterval(_audioLivePollTimer); _audioLivePollTimer = null;
    }
  });

  // ────────────────────────────────────────────────────────
  // MODAL GPS — ubicación + mapa Google
  // ────────────────────────────────────────────────────────
  async function abrirModalGps(idDispositivo) {
    const d = (cfgData.dispositivos || []).find(x => x.ID_Dispositivo === idDispositivo);
    if (!d) return;
    $('gpsModalDeviceId').value = idDispositivo;
    $('gpsModalSubtitle').textContent = `${d.Nombre_Equipo || idDispositivo}${d.Ultima_Sesion ? ' · 👤 ' + d.Ultima_Sesion : ''}`;
    openModal('modalGps');
    await gpsCargar(24);
  }

  async function gpsCargar(horas) {
    const id = $('gpsModalDeviceId')?.value;
    if (!id) return;
    const info = $('gpsInfo');
    const mapa = $('gpsMapa');
    const cantEl = $('gpsCantidadPuntos');
    info.innerHTML = '<div class="text-center py-4 text-slate-500 text-sm">Cargando ubicación...</div>';
    mapa.innerHTML = '';
    try {
      const ult = await API.get('getUltimaUbicacionDispositivo', { deviceId: id });
      const hist = await API.get('getUbicacionesDispositivo', { deviceId: id, horas });
      if (!ult) {
        info.innerHTML = '<div class="text-center py-4 text-amber-400 text-sm">⚠ Este dispositivo nunca ha reportado ubicación</div>';
        return;
      }
      const fecha = ult.timestamp ? new Date(ult.timestamp) : null;
      const mins = fecha ? Math.floor((Date.now() - fecha.getTime()) / 60000) : null;
      const fmt = fecha ? fecha.toLocaleString('es-PE') : '—';
      const fresh = mins !== null && mins < 10;
      const dot = fresh ? '🟢' : (mins < 60 ? '🟢' : (mins < 60 * 24 ? '🟡' : '🔴'));
      const bat = ult.bateria !== '' && ult.bateria !== undefined ? `🔋 ${ult.bateria}%` : '';
      info.innerHTML = `<div class="flex items-center justify-between gap-2 flex-wrap">
        <div>
          <div class="text-sm font-bold text-white">${dot} Última ubicación · ${fmt}</div>
          <div class="text-[11px] text-slate-400 mt-1">📍 ${parseFloat(ult.lat).toFixed(6)}, ${parseFloat(ult.lng).toFixed(6)} · precisión ~${Math.round(ult.accuracy)}m ${bat}</div>
          ${ult.usuarioLogueado ? `<div class="text-[11px] text-slate-500 mt-0.5">👤 ${ult.usuarioLogueado}</div>` : ''}
        </div>
        <a href="https://www.google.com/maps?q=${ult.lat},${ult.lng}" target="_blank" class="btn-ghost text-xs">🗺️ Abrir en Maps</a>
      </div>`;

      cantEl.textContent = (Array.isArray(hist) ? hist.length : 0) + ' puntos en ' + horas + 'h';

      // Embed Google Maps con iframe (sin API key)
      const lat = parseFloat(ult.lat);
      const lng = parseFloat(ult.lng);
      mapa.innerHTML = `<iframe width="100%" height="100%" frameborder="0"
        src="https://maps.google.com/maps?q=${lat},${lng}&z=16&output=embed"
        style="border:none;"></iframe>`;
    } catch(e) {
      info.innerHTML = '<div class="text-center py-4 text-red-400 text-sm">Error: ' + e.message + '</div>';
    }
  }

  // Compat con código viejo (renderDispositivos eliminado)
  async function toggleEstadoDispositivo(id, nuevoEstado) {
    const d = cfgData.dispositivos.find(x => x.ID_Dispositivo === id);
    if (d) d.Estado = nuevoEstado;
    renderInfra();
    try {
      await API.post('actualizarDispositivo', { ID_Dispositivo: id, Estado: nuevoEstado });
      toast(nuevoEstado === 'ACTIVO' ? 'Dispositivo activado' : 'Dispositivo desactivado', 'ok');
    } catch(e) {
      if (d) d.Estado = nuevoEstado === 'ACTIVO' ? 'INACTIVO' : 'ACTIVO';
      renderInfra();
      toast(e.message || 'Error', 'error');
    }
  }

  // ── PWA Install ──────────────────────────────────────────────
  let _installPrompt = null;
  window.addEventListener('beforeinstallprompt', e => {
    e.preventDefault();
    _installPrompt = e;
    const btn = document.getElementById('installAppBtn');
    if (btn) btn.classList.remove('hidden');
  });
  window.addEventListener('appinstalled', () => {
    _installPrompt = null;
    const btn = document.getElementById('installAppBtn');
    if (btn) btn.classList.add('hidden');
  });

  function installPWA() {
    if (!_installPrompt) { toast('La app ya está instalada o el navegador no lo permite', 'info'); return; }
    _installPrompt.prompt();
    _installPrompt.userChoice.then(r => {
      if (r.outcome === 'accepted') toast('App instalada correctamente', 'ok');
      _installPrompt = null;
    });
    closeAvatarMenu();
  }

  // ── Avatar dropdown (fixed, fuera del sidebar) ───────────────
  // ── SVG traveling border + dot en sidebar avatar ─────────
  function _initAvatarTrigSvg() {
    const outer   = document.getElementById('avatarTrigOuter');
    const svg     = document.getElementById('avatarTrigSvg');
    const bRect   = document.getElementById('avatarTrigBorderRect');
    const bBase   = document.getElementById('avatarTrigBaseRect');
    const dotPath = document.getElementById('avatarTrigRectPath');
    if (!outer || !svg || !bRect || !dotPath) return;

    const W = outer.offsetWidth;
    const H = outer.offsetHeight;
    if (!W || !H) return;

    const pad = 3, rx = 11;
    const svgW = W + pad * 2, svgH = H + pad * 2;
    svg.setAttribute('viewBox', `0 0 ${svgW} ${svgH}`);

    // Rect coords (button area offset by pad)
    [bRect, bBase].forEach(el => {
      el.setAttribute('x',      pad);
      el.setAttribute('y',      pad);
      el.setAttribute('width',  W);
      el.setAttribute('height', H);
      el.setAttribute('rx',     rx);
      el.setAttribute('ry',     rx);
    });

    // Perimeter → dasharray para segmento viajero
    const perim = Math.round(2 * (W + H) - 8 * rx + 2 * Math.PI * rx);
    const seg   = 72;
    bRect.style.strokeDasharray  = `${seg} ${perim - seg}`;
    bRect.style.strokeDashoffset = '0';

    // Inyectar keyframe con perimeter correcto
    const kfId = 'mos-trig-kf';
    let kfEl = document.getElementById(kfId);
    if (!kfEl) { kfEl = document.createElement('style'); kfEl.id = kfId; document.head.appendChild(kfEl); }
    kfEl.textContent = `@keyframes travelBorder{from{stroke-dashoffset:0}to{stroke-dashoffset:${-perim}}}`;
    bRect.style.animation = 'travelBorder 3s linear infinite';

    // Path para el punto verde (sigue el mismo rectángulo)
    const x = pad, y = pad;
    const d = `M ${x+rx} ${y} L ${x+W-rx} ${y} Q ${x+W} ${y} ${x+W} ${y+rx} ` +
              `L ${x+W} ${y+H-rx} Q ${x+W} ${y+H} ${x+W-rx} ${y+H} ` +
              `L ${x+rx} ${y+H} Q ${x} ${y+H} ${x} ${y+H-rx} ` +
              `L ${x} ${y+rx} Q ${x} ${y} ${x+rx} ${y} Z`;
    dotPath.setAttribute('d', d);
  }

  // Re-calcula al cambiar ancho del sidebar (hover tablet)
  (function _watchSidebarResize() {
    const sidebar = document.getElementById('sidebar');
    if (!sidebar || typeof ResizeObserver === 'undefined') return;
    let _trig;
    new ResizeObserver(() => {
      clearTimeout(_trig);
      _trig = setTimeout(_initAvatarTrigSvg, 60);
    }).observe(sidebar);
  })();

  // ── Clave admin global en avatar menu (sessionStorage) ──
  function _segEsAdmin(rol) {
    const r = String(rol || '').toUpperCase();
    return r === 'MASTER' || r === 'ADMIN' || r === 'ADMINISTRADOR';
  }
  async function _segCachearGlobalEnLogin(rol, pinAdmin) {
    if (!_segEsAdmin(rol)) return;
    try {
      const data = await API.get('getClaveAdminGlobal', { pinAdmin });
      if (data?.autorizado && data.pin) {
        sessionStorage.setItem('mos_admin_global_pin', data.pin);
        sessionStorage.setItem('mos_admin_global_dias', String(data.diasParaProximaRotacion ?? ''));
        sessionStorage.setItem('mos_admin_global_vencida', data.vencida ? '1' : '0');
      }
    } catch(_) { /* tolerar */ }
  }
  function _segActualizarCacheLocal(data) {
    if (!data || !data.pin) return;
    sessionStorage.setItem('mos_admin_global_pin', data.pin);
    sessionStorage.setItem('mos_admin_global_dias', String(data.diasParaProximaRotacion ?? ''));
    sessionStorage.setItem('mos_admin_global_vencida', data.vencida ? '1' : '0');
  }
  function _segLimpiarCacheLocal() {
    sessionStorage.removeItem('mos_admin_global_pin');
    sessionStorage.removeItem('mos_admin_global_dias');
    sessionStorage.removeItem('mos_admin_global_vencida');
  }
  function _segPintarEnAvatarMenu() {
    const box      = $('avMenuClaveBox');
    const loginBox = $('avMenuClaveLogin');
    if (!box || !loginBox) return;
    const rolOk = _segEsAdmin(S.session?.rol);
    const pin = sessionStorage.getItem('mos_admin_global_pin');
    if (!rolOk) {
      box.classList.add('hidden');
      loginBox.classList.add('hidden');
      return;
    }
    if (pin) {
      // Tenemos clave cacheada — mostrar bloque visible
      loginBox.classList.add('hidden');
      box.classList.remove('hidden');
      const elPin = $('avMenuClavePin');
      if (elPin) elPin.textContent = pin.split('').join(' ');
      const dias = parseInt(sessionStorage.getItem('mos_admin_global_dias') || '0', 10);
      const vencida = sessionStorage.getItem('mos_admin_global_vencida') === '1';
      const elDias = $('avMenuClaveDias');
      if (elDias) {
        if (vencida) {
          elDias.textContent = '⚠ Vencida';
          elDias.style.color = '#f87171';
        } else if (dias <= 5) {
          elDias.textContent = dias + 'd';
          elDias.style.color = '#fbbf24';
        } else {
          elDias.textContent = dias + 'd';
          elDias.style.color = '#94a3b8';
        }
      }
      // Click solo activo para MASTER (admin/administrador no tienen acceso a config)
      const esMaster = String(S.session?.rol || '').toUpperCase() === 'MASTER';
      box.onclick = esMaster
        ? () => { try { nav('config'); setCfgTab('seguridad'); } catch(_){} closeAvatarMenu(); }
        : null;
      box.style.cursor = esMaster ? 'pointer' : 'default';
      box.title = esMaster ? 'Tocar para ir al panel de seguridad' : 'Solo el master puede modificarla';
    } else {
      // Sin caché — mostrar input para autenticar
      box.classList.add('hidden');
      loginBox.classList.remove('hidden');
      const inp = $('avMenuClaveLoginPin');
      if (inp) inp.value = '';
      const err = $('avMenuClaveLoginErr');
      if (err) err.textContent = '';
    }
  }

  async function av_consultarClaveDesdeMenu() {
    const inp = $('avMenuClaveLoginPin');
    const err = $('avMenuClaveLoginErr');
    const pin = String(inp?.value || '').trim();
    if (!/^\d{4}$/.test(pin)) {
      if (err) err.textContent = 'PIN debe tener 4 dígitos';
      return;
    }
    if (err) err.textContent = '';

    // 🚀 OPTIMISTA: mostrar YA el bloque revelado con skeleton shimmer en
    // lugar de dejar al user mirando el botón sin respuesta. El fetch
    // corre en background; al llegar se reemplaza el skeleton por la clave.
    const box      = $('avMenuClaveBox');
    const loginBox = $('avMenuClaveLogin');
    const elPin    = $('avMenuClavePin');
    const elDias   = $('avMenuClaveDias');
    if (box && loginBox) {
      loginBox.classList.add('hidden');
      box.classList.remove('hidden');
      if (elPin)  elPin.innerHTML = '<span class="cg-skel-pin"></span>';
      if (elDias) { elDias.textContent = '···'; elDias.style.color = '#475569'; }
      box.onclick = null; box.style.cursor = 'default';
    }

    try {
      const data = await API.get('getClaveAdminGlobal', { pinAdmin: pin });
      if (!data?.autorizado) {
        // PIN malo → volver al input con error
        if (box) box.classList.add('hidden');
        if (loginBox) loginBox.classList.remove('hidden');
        if (err) err.textContent = data?.error || 'PIN incorrecto';
        if (inp) inp.value = '';
        return;
      }
      _segActualizarCacheLocal(data);
      _segPintarEnAvatarMenu();
    } catch(e) {
      console.error('[av_consultarClaveDesdeMenu]', e);
      // Error de red → volver al input con error
      if (box) box.classList.add('hidden');
      if (loginBox) loginBox.classList.remove('hidden');
      if (err) err.textContent = e?.message || 'Sin conexión';
    }
  }

  function toggleAvatarMenu() {
    const menu = $('avatarMenu');
    if (!menu) return;
    if (!menu.classList.contains('hidden')) {
      menu.classList.add('hidden');
      return;
    }
    // Pintar clave global si aplica
    _segPintarEnAvatarMenu();
    // Buscar trigger visible: sidebar en desktop, botón mobile en móvil
    let trigger = document.querySelector('.avatar-trigger');
    if (!trigger || trigger.getBoundingClientRect().width === 0) {
      trigger = $('avatarMobBtn') || $('sessionAvatarMob');
    }
    if (trigger) {
      const rect   = trigger.getBoundingClientRect();
      const menuW  = 205;
      const midY   = window.innerHeight / 2;
      menu.style.top    = '0px'; // temporal para medir
      menu.style.left   = '0px';
      menu.style.right  = 'auto';
      menu.style.bottom = 'auto';
      menu.classList.remove('hidden');
      const menuH = menu.offsetHeight;
      if (rect.top < midY) {
        // trigger en mitad superior (header mobile) → abre DEBAJO alineado a la DERECHA del botón
        const rightOffset = window.innerWidth - rect.right;
        menu.style.right = Math.max(8, rightOffset) + 'px';
        menu.style.left  = 'auto';
        menu.style.top   = (rect.bottom + 8) + 'px';
      } else {
        // trigger en mitad inferior (sidebar) → abre ENCIMA alineado a la IZQUIERDA
        menu.style.left  = Math.max(8, rect.left) + 'px';
        menu.style.right = 'auto';
        menu.style.top   = Math.max(8, rect.top - menuH - 8) + 'px';
      }
    } else {
      menu.classList.remove('hidden');
    }
    setTimeout(() => document.addEventListener('click', _closeAvatarOnOutside, { once: true }), 0);
  }
  function closeAvatarMenu() {
    const menu = $('avatarMenu');
    if (menu) menu.classList.add('hidden');
  }
  function _closeAvatarOnOutside(e) {
    const menu = $('avatarMenu');
    const wrap = $('avatarWrap');
    const mobTrigger = $('sessionAvatarMob');
    if (menu && !menu.contains(e.target) &&
        (!wrap || !wrap.contains(e.target)) &&
        (!mobTrigger || !mobTrigger.contains(e.target))) {
      closeAvatarMenu();
    }
  }

  // ═══════════════════════════════════════════════════════════════
  // [v2.41.92] CENTRO TRIBUTARIO — IGV a favor + IGV emitido + Renta
  // ═══════════════════════════════════════════════════════════════
  const _tribState = { mes: null, anio: null, data: null, busy: false };

  async function _loadTributario() {
    _finBeep && _finBeep('nav');
    // Inicializar selector de mes (12 meses hacia atrás)
    const sel = $('tribMesSelect');
    if (sel && !sel.options.length) {
      const hoy = new Date();
      for (let i = 0; i < 12; i++) {
        const d = new Date(hoy.getFullYear(), hoy.getMonth() - i, 1);
        const m = d.getMonth() + 1, a = d.getFullYear();
        const nombres = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
        const opt = document.createElement('option');
        opt.value = m + '|' + a;
        opt.textContent = nombres[d.getMonth()] + ' ' + a;
        if (i === 0) opt.selected = true;
        sel.appendChild(opt);
      }
    }
    await tribCargar();
  }

  async function tribCargar() {
    if (_tribState.busy) return;
    const sel = $('tribMesSelect');
    const parts = (sel?.value || '').split('|');
    const mes  = parseInt(parts[0], 10) || (new Date().getMonth() + 1);
    const anio = parseInt(parts[1], 10) || new Date().getFullYear();
    const esMismoMes = _tribState.data && _tribState.mes === mes && _tribState.anio === anio;
    _tribState.mes = mes; _tribState.anio = anio;
    _tribState.busy = true;

    // [v2.41.93] Si ya tenemos data precargada del mismo mes (de boot),
    // renderizar al instante y refrescar en background — sensación instantánea.
    if (esMismoMes) {
      _tribRender(_tribState.data);
      $('tribLoading').classList.add('hidden');
      $('tribContent').classList.remove('hidden');
      // Refresh silencioso en bg
      iconBusy('tributario', true);
      try {
        const res = await API.post('tribResumenMes', { mes, anio });
        const d = (res && res.data) ? res.data : (res || {});
        _tribState.data = d;
        _tribRender(d);
      } catch(_) {}
      finally { iconBusy('tributario', false); _tribState.busy = false; }
      return;
    }

    // Sin cache: loading visible
    $('tribLoading').classList.remove('hidden');
    $('tribContent').classList.add('hidden');
    iconBusy('tributario', true);

    try {
      const res = await API.post('tribResumenMes', { mes, anio });
      const d = (res && res.data) ? res.data : (res || {});
      _tribState.data = d;
      _tribRender(d);
      $('tribLoading').classList.add('hidden');
      $('tribContent').classList.remove('hidden');
    } catch(e) {
      console.error('[Tributario] cargar:', e);
      $('tribLoading').textContent = '❌ Error cargando: ' + (e.message || e);
    } finally {
      iconBusy('tributario', false);
      _tribState.busy = false;
    }
  }

  function _tribFmtSoles(n) {
    return 'S/ ' + (parseFloat(n) || 0).toLocaleString('es-PE', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  }

  function _tribCountUp(el, target) {
    if (!el) return;
    const start = parseFloat(el.dataset.cur || 0);
    const duration = 800;
    const t0 = performance.now();
    function step(t) {
      const p = Math.min(1, (t - t0) / duration);
      const e = 1 - Math.pow(1 - p, 3); // ease-out cubic
      const v = start + (target - start) * e;
      el.textContent = _tribFmtSoles(v);
      if (p < 1) requestAnimationFrame(step);
      else el.dataset.cur = target;
    }
    requestAnimationFrame(step);
  }

  function _tribRender(d) {
    if (!d) return;
    const nombres = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
    $('tribSub').textContent = 'Balance de ' + nombres[d.mes - 1] + ' ' + d.anio + ' · día ' + d.diaActual + ' de ' + d.ultimoDia;

    // KPI principales con countUp
    _tribCountUp($('tribIGVFavor'), d.igvFavor);
    _tribCountUp($('tribIGVPagar'), d.igvEmitido);
    $('tribIGVFavorSub').textContent = (d.guiasConIGV || 0) + ' de ' + (d.guiasMes || 0) + ' guías con IGV recuperable' +
                                      (d.guiasSinFoto > 0 ? ' · ' + d.guiasSinFoto + ' s/foto' : '');
    $('tribIGVPagarSub').textContent = (d.cpeEmitidos || 0) + ' / ' + (d.cpeTotal || 0) + ' CPE emitidos';

    const pctFavor = d.guiasMes > 0 ? (d.guiasConIGV / d.guiasMes) * 100 : 0;
    const pctPagar = d.cpeTotal > 0 ? (d.cpeEmitidos / d.cpeTotal) * 100 : 0;
    $('tribIGVFavorBar').style.width = pctFavor.toFixed(0) + '%';
    $('tribIGVPagarBar').style.width = pctPagar.toFixed(0) + '%';

    // Balance neto
    const balanceEl = $('tribBalanceNeto');
    _tribCountUp(balanceEl, Math.abs(d.balanceNetoIGV));
    balanceEl.classList.toggle('positivo', d.balanceNetoIGV >= 0);
    balanceEl.classList.toggle('negativo', d.balanceNetoIGV < 0);
    balanceEl.classList.remove('bump'); void balanceEl.offsetWidth; balanceEl.classList.add('bump');
    if (d.balanceNetoIGV < 0) {
      $('tribBalanceSub').innerHTML = '✨ <strong>Crédito fiscal a favor</strong> · arrastrable al mes siguiente';
    } else {
      const fecha = new Date(d.fechaVencimiento);
      const fStr = fecha.toLocaleDateString('es-PE', { day: 'numeric', month: 'short', year: 'numeric' });
      $('tribBalanceSub').innerHTML = 'Vence: <strong>' + fStr + '</strong> · faltan ' + d.diasParaVencer + ' días';
    }
    $('tribPeriodoBar').style.width = (d.pctMes || 0) + '%';

    // Mini cards
    $('tribVentas').textContent = _tribFmtSoles(d.totalVentas);
    $('tribVentasSub').textContent = 'Renta MYPE 1.5%: ' + _tribFmtSoles(d.rentaMensual);
    $('tribCPEStatus').textContent = (d.cpeEmitidos || 0) + ' emitidos';
    $('tribCPESub').textContent = (d.cpePendientes || 0) + ' pendientes · ' + (d.cpeErrores || 0) + ' error';

    // [v2.42.11] Alertas accionables — cada una con monto en juego + botón directo
    const alertas = (d.cpeErrores || 0) + (d.guiasIlegibles || 0) + (d.guiasSinFoto || 0);
    if (alertas > 0) {
      $('tribAlertCard').style.display = '';
      $('tribAlertCount').textContent = alertas;
      const partes = [];
      // Estimación de IGV perdido por guías sin foto / ilegibles
      // (proporcional al ratio promedio del mes)
      const igvPromedioPorGuia = (d.guiasConIGV > 0) ? (d.igvFavor / d.guiasConIGV) : 0;
      if (d.cpeErrores > 0)    partes.push('🔴 ' + d.cpeErrores + ' CPE error');
      if (d.guiasIlegibles > 0) {
        const perdidaEstim = (d.guiasIlegibles * igvPromedioPorGuia).toFixed(0);
        partes.push('🔴 ' + d.guiasIlegibles + ' ilegibles · puedes recuperar ~S/ ' + perdidaEstim);
      }
      if (d.guiasSinFoto > 0) {
        const perdidaEstim = (d.guiasSinFoto * igvPromedioPorGuia).toFixed(0);
        partes.push('🟡 ' + d.guiasSinFoto + ' s/foto · ~S/ ' + perdidaEstim + ' en juego');
      }
      $('tribAlertSub').textContent = partes.join(' · ');
    } else {
      $('tribAlertCard').style.display = 'none';
    }

    // [v2.42.11] Proyección de cierre de mes — solo si NO es fin de mes
    const proy = _tribCalcProyeccion(d);
    let proyEl = $('tribProyeccion');
    if (!proyEl && proy && d.pctMes < 95) {
      // Crear el elemento si no existe (primera vez)
      const after = $('tribAlertCard') || $('tribIGVFavor')?.closest('section');
      if (after) {
        proyEl = document.createElement('div');
        proyEl.id = 'tribProyeccion';
        proyEl.style.cssText = 'background:linear-gradient(135deg,rgba(99,102,241,.15),rgba(79,70,229,.05));border:1px solid rgba(99,102,241,.4);border-radius:14px;padding:14px 16px;margin:10px 0;display:flex;align-items:center;gap:14px;animation:scaleIn .35s cubic-bezier(.34,1.56,.64,1)';
        after.parentNode.insertBefore(proyEl, after.nextSibling);
      }
    }
    if (proyEl) {
      if (!proy || d.pctMes >= 95) {
        proyEl.style.display = 'none';
      } else {
        proyEl.style.display = 'flex';
        const signo = proy.balanceNetoProy >= 0 ? 'pagar' : 'a favor';
        const color = proy.balanceNetoProy >= 0 ? '#fbbf24' : '#34d399';
        proyEl.innerHTML = `
          <span style="font-size:28px">🔮</span>
          <div style="flex:1">
            <div style="font-size:11px;font-weight:900;color:#a5b4fc;text-transform:uppercase;letter-spacing:.05em">Proyección fin de mes</div>
            <div style="font-size:13px;color:#cbd5e1;margin-top:2px">
              Al ritmo actual (${d.pctMes.toFixed(0)}% del mes) cierras con
              <strong style="color:${color}">S/ ${Math.abs(proy.balanceNetoProy).toFixed(0)}</strong> IGV ${signo}
            </div>
            <div style="font-size:10px;color:#94a3b8;margin-top:1px">
              Compras proy. S/ ${proy.igvFavorProy.toFixed(0)} · Ventas proy. S/ ${proy.igvEmitidoProy.toFixed(0)} · Faltan ${proy.diasRestantes} día${proy.diasRestantes === 1 ? '' : 's'}
            </div>
          </div>`;
      }
    }
  }

  // [v2.42.10] Estado del filtro del detalle IGV a favor
  const _tribIGVFiltro = { estado: 'TODOS' }; // TODOS · PROCESADO · SIN_IGV · ILEGIBLE · SIN_FOTO

  async function tribAbrirIGVFavor() {
    const cont = $('tribIGVFavorList');
    cont.innerHTML = '<div class="text-slate-500 text-xs">Cargando guías...</div>';
    const det = cont.closest('details'); if (det) det.open = true;
    // [v2.42.12] Si ya tenemos precarga del mes actual, usar instant
    if (_tribIGVFavorPrecargado && _tribIGVFavorPrecargado.mes === _tribState.mes
        && _tribIGVFavorPrecargado.anio === _tribState.anio) {
      _tribIGVFavorListaCache = _tribIGVFavorPrecargado.lista;
      _tribRenderIGVFavorDetalle(_tribIGVFavorPrecargado.lista);
      // Aún así refrescar en background por si hubo cambios desde la precarga
      _tribFetchIGVFavor(true);
      return;
    }
    await _tribFetchIGVFavor(false);
  }

  // [v2.42.12] Fetch separado para reusar entre precarga y abrir manual.
  // El bug: el backend tribIGVFavorMes devuelve directo {ok,data:{guias:[]}},
  // pero API.post desempaqueta d.data → frontend recibe {guias:[]} directo.
  // Antes leíamos res?.data?.guias (undefined) cuando debe ser res?.guias.
  async function _tribFetchIGVFavor(silent) {
    const cont = $('tribIGVFavorList');
    try {
      const res = await API.post('tribIGVFavorMes', { mes: _tribState.mes, anio: _tribState.anio });
      // [v2.42.12 fix] res ya es el data desempaquetado (API.post hace return d.data)
      const lista = (res?.guias) || (res?.data?.guias) || [];
      _tribIGVFavorListaCache = lista;
      // Actualizar precarga global
      _tribIGVFavorPrecargado = { mes: _tribState.mes, anio: _tribState.anio, lista };
      if (cont) _tribRenderIGVFavorDetalle(lista);
    } catch(e) {
      if (!silent && cont) {
        cont.innerHTML = '<div class="text-red-400 text-xs">❌ ' + (e.message || e) + '</div>';
      }
    }
  }

  // [v2.42.12] Precarga del IGV a favor — se llena al iniciar sesión Admin
  // o al cambiar de mes en el panel. Permite que al abrir el detalle no
  // espere el roundtrip a WH.
  let _tribIGVFavorPrecargado = null;

  let _tribIGVFavorListaCache = [];

  function _tribRenderIGVFavorDetalle(lista) {
    const cont = $('tribIGVFavorList');
    if (!cont) return;
    if (!lista.length) {
      cont.innerHTML = '<div class="text-slate-500 text-xs italic">Sin guías de ingreso proveedor en este mes</div>';
      return;
    }
    // Aplicar filtro
    const filtro = _tribIGVFiltro.estado;
    const filtrada = lista.filter(g => {
      if (filtro === 'TODOS') return true;
      if (filtro === 'PROCESADO')  return g.ocrEstado === 'PROCESADO' && g.igvRecuperable > 0;
      if (filtro === 'SIN_IGV')    return g.ocrEstado === 'SIN_IGV';
      if (filtro === 'ILEGIBLE')   return g.ocrEstado === 'ILEGIBLE' || g.ocrEstado === 'NO_COMPROBANTE' || (g.tieneFoto && !g.ocrEstado);
      if (filtro === 'SIN_FOTO')   return !g.tieneFoto;
      return true;
    });

    // Contadores por estado para los chips
    let cTodo = lista.length, cProc = 0, cSinIGV = 0, cIleg = 0, cSinFoto = 0;
    lista.forEach(g => {
      if (g.ocrEstado === 'PROCESADO' && g.igvRecuperable > 0) cProc++;
      else if (g.ocrEstado === 'SIN_IGV') cSinIGV++;
      else if (g.ocrEstado === 'ILEGIBLE' || g.ocrEstado === 'NO_COMPROBANTE' || (g.tieneFoto && !g.ocrEstado)) cIleg++;
      else if (!g.tieneFoto) cSinFoto++;
    });

    // Chips de filtro
    const mkChip = (key, label, count, color) => {
      const active = filtro === key;
      const bg = active ? color : 'rgba(71,85,105,.3)';
      const tc = active ? '#0f172a' : color;
      return `<button onclick="MOS._tribSetIGVFiltro('${key}')"
        style="background:${bg};color:${tc};border:1px solid ${color};padding:4px 10px;border-radius:99px;font-size:10.5px;font-weight:800;cursor:pointer;transition:all .15s;display:inline-flex;align-items:center;gap:4px;margin-right:4px;margin-bottom:4px"
        title="${label}">
        ${label} <span style="opacity:.8">·</span> <span style="font-weight:900">${count}</span>
      </button>`;
    };
    const chipsHtml = `<div style="margin-bottom:8px;padding-bottom:8px;border-bottom:1px solid rgba(71,85,105,.3)">
      ${mkChip('TODOS',     'Todos',         cTodo,    '#64748b')}
      ${mkChip('PROCESADO', '🟢 Con IGV',    cProc,    '#10b981')}
      ${mkChip('SIN_IGV',   '⊘ Sin IGV',     cSinIGV,  '#94a3b8')}
      ${mkChip('ILEGIBLE',  '🔴 Ilegibles',  cIleg,    '#ef4444')}
      ${mkChip('SIN_FOTO',  '⚪ Sin foto',   cSinFoto, '#f59e0b')}
    </div>`;

    if (!filtrada.length) {
      cont.innerHTML = chipsHtml + '<div class="text-slate-500 text-xs italic text-center py-4">Sin guías con este filtro</div>';
      return;
    }

    // Agrupar por proveedor (razonSocial > idProveedor)
    const grupos = {};
    filtrada.forEach(g => {
      const key = (g.razonSocial && g.razonSocial.trim()) || g.idProveedor || '(Sin proveedor)';
      if (!grupos[key]) grupos[key] = { nombre: key, ruc: g.rucEmisor || '', items: [], totalIGV: 0, totalDoc: 0 };
      grupos[key].items.push(g);
      grupos[key].totalIGV += g.igvRecuperable || 0;
      grupos[key].totalDoc += g.total || 0;
      if (!grupos[key].ruc && g.rucEmisor) grupos[key].ruc = g.rucEmisor;
    });
    // Sort grupos por totalIGV desc (más relevante arriba)
    const ordenados = Object.values(grupos).sort((a, b) => b.totalIGV - a.totalIGV);

    const gruposHtml = ordenados.map(grupo => {
      const itemsHtml = grupo.items.map(g => {
        const estCls = g.ocrEstado === 'PROCESADO' ? 'trib-row-est-ok'
                     : g.ocrEstado === 'SIN_IGV'   ? 'trib-row-est-info'
                     : (g.ocrEstado === 'ILEGIBLE' || g.ocrEstado === 'NO_COMPROBANTE') ? 'trib-row-est-error'
                     : 'trib-row-est-warn';
        const estTxt = g.ocrEstado === 'PROCESADO' ? '🟢 ' + (g.confidence || 0) + '%'
                     : g.ocrEstado === 'SIN_IGV'   ? '⊘ sin IGV'
                     : g.ocrEstado === 'ILEGIBLE'  ? '🔴 ilegible'
                     : g.ocrEstado === 'NO_COMPROBANTE' ? '🔴 no es comprob.'
                     : g.tieneFoto ? '🟡 procesando' : '⚪ s/foto';
        // Thumbnail clickeable si hay foto
        const fotoHtml = g.urlFoto
          ? `<button onclick="MOS.tribAbrirFotoComprobante('${_escapeHtml(g.urlFoto)}','${_escapeHtml(g.idGuia)}')"
                style="background:none;border:none;cursor:pointer;padding:0;flex-shrink:0"
                title="Ver comprobante">
              <img src="${_escapeHtml(g.urlFoto)}" alt="📄"
                   style="width:36px;height:48px;object-fit:cover;border-radius:6px;border:1px solid #334155;background:#0f172a"
                   loading="lazy"
                   onerror="this.style.display='none'">
            </button>`
          : `<span style="width:36px;height:48px;display:flex;align-items:center;justify-content:center;background:#1e293b;border-radius:6px;border:1px solid #334155;flex-shrink:0;font-size:18px;color:#475569">📄</span>`;
        const fechaCmp = g.fechaComprobante || (g.fecha ? new Date(g.fecha).toLocaleDateString('es-PE') : '');
        const serieNum = (g.serie || '') + (g.numero ? '-' + g.numero : '');
        return `<div class="trib-row" style="padding:8px 10px;gap:10px">
          ${fotoHtml}
          <div class="trib-row-data" style="flex:1;min-width:0">
            <div style="font-weight:700;font-size:12px;color:#e2e8f0">${_escapeHtml(g.idGuia)}</div>
            <div style="font-size:10px;color:#94a3b8;display:flex;gap:6px;align-items:center;flex-wrap:wrap">
              <span>${_escapeHtml(fechaCmp)}</span>
              ${serieNum ? `<span>· <span style="font-family:monospace">${_escapeHtml(serieNum)}</span></span>` : ''}
              ${g.total > 0 ? `<span>· Doc S/ ${g.total.toFixed(2)}</span>` : ''}
            </div>
          </div>
          <div style="text-align:right;flex-shrink:0">
            <div style="font-weight:900;font-size:13px;color:${g.igvRecuperable > 0 ? '#34d399' : '#475569'}">
              ${g.igvRecuperable > 0 ? _tribFmtSoles(g.igvRecuperable) : '—'}
            </div>
            <div class="${estCls}" style="font-size:9.5px;margin-top:2px">${estTxt}</div>
          </div>
          ${g.tieneFoto ? `<button class="trib-btn-mini" title="Re-procesar OCR" onclick="MOS.tribReprocesarOCR('${_escapeHtml(g.idGuia)}')">↻</button>` : ''}
        </div>`;
      }).join('');

      return `<div style="margin-bottom:12px;border:1px solid #1e293b;border-radius:10px;overflow:hidden;background:rgba(15,23,42,.4)">
        <div style="padding:8px 12px;background:linear-gradient(135deg,rgba(16,185,129,.12),rgba(5,150,105,.05));border-bottom:1px solid #1e293b;display:flex;align-items:center;gap:10px">
          <div style="flex:1;min-width:0">
            <div style="font-weight:900;font-size:13px;color:#f1f5f9">🏢 ${_escapeHtml(grupo.nombre)}</div>
            <div style="font-size:10px;color:#94a3b8">
              ${grupo.ruc ? `RUC ${_escapeHtml(grupo.ruc)} · ` : ''}${grupo.items.length} documento${grupo.items.length === 1 ? '' : 's'}
            </div>
          </div>
          <div style="text-align:right">
            <div style="font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:.05em">IGV total</div>
            <div style="font-weight:900;font-size:14px;color:#34d399">${_tribFmtSoles(grupo.totalIGV)}</div>
          </div>
        </div>
        <div style="padding:4px">${itemsHtml}</div>
      </div>`;
    }).join('');

    cont.innerHTML = chipsHtml + gruposHtml;
  }

  function _tribSetIGVFiltro(estado) {
    _tribIGVFiltro.estado = estado;
    _tribRenderIGVFavorDetalle(_tribIGVFavorListaCache);
  }

  // [v2.42.10] Overlay para ver el comprobante en grande con zoom
  function tribAbrirFotoComprobante(url, idGuia) {
    if (!url) return;
    _finBeep && _finBeep('tap');
    let overlay = document.getElementById('tribFotoOverlay');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.id = 'tribFotoOverlay';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,.92);display:flex;align-items:center;justify-content:center;padding:16px;backdrop-filter:blur(8px);cursor:pointer';
      overlay.onclick = (e) => { if (e.target === overlay || e.target.classList.contains('trib-foto-close')) overlay.remove(); };
      document.body.appendChild(overlay);
    }
    overlay.innerHTML = `
      <button class="trib-foto-close" style="position:absolute;top:20px;right:20px;background:rgba(255,255,255,.15);color:#fff;width:44px;height:44px;border-radius:50%;border:none;font-size:18px;cursor:pointer;font-weight:800">✕</button>
      <div style="position:absolute;top:20px;left:20px;background:rgba(0,0,0,.6);color:#fff;padding:8px 14px;border-radius:99px;font-size:12px;font-weight:700">📄 ${_escapeHtml(idGuia || 'Comprobante')}</div>
      <img src="${_escapeHtml(url)}" alt="Comprobante"
           style="max-width:95vw;max-height:90vh;object-fit:contain;border-radius:8px;box-shadow:0 30px 60px rgba(0,0,0,.7)"
           onerror="this.parentElement.innerHTML='<div style=color:#fca5a5;font-weight:700>⚠ No se pudo cargar la foto</div>'">`;
  }

  async function tribAbrirIGVEmitido() {
    const cont = $('tribIGVEmitidoList');
    cont.innerHTML = '<div class="text-slate-500 text-xs">Cargando CPE...</div>';
    const det = cont.closest('details'); if (det) det.open = true;
    try {
      // [TRAZABILIDAD cero-GAS] PRIMERO Supabase (me.cpe_trazabilidad): estado fiscal completo, sin GAS.
      // Rango del mes seleccionado. Si no hay token/red → fallback al endpoint GAS (tribIGVEmitidoMes).
      const _mm = String(_tribState.mes).padStart(2, '0');
      const _desde = `${_tribState.anio}-${_mm}-01`;
      const _ult = new Date(_tribState.anio, _tribState.mes, 0).getDate();
      const _hasta = `${_tribState.anio}-${_mm}-${String(_ult).padStart(2, '0')}`;
      let lista = null, _viaSupa = false;
      try {
        const sup = await API.cpeTrazabilidad(_desde, _hasta);
        if (sup && sup.ok && Array.isArray(sup.cpe)) { lista = sup.cpe; _viaSupa = true; }
      } catch (_) {}
      if (lista === null) {
        const res = await API.post('tribIGVEmitidoMes', { mes: _tribState.mes, anio: _tribState.anio });
        lista = (res?.cpe) || (res?.data?.cpe) || [];
      }
      if (!lista.length) {
        cont.innerHTML = '<div class="text-slate-500 text-xs italic">Sin CPE emitidos este mes</div>';
        return;
      }
      cont.innerHTML = (_viaSupa ? '<div class="text-[10px] text-emerald-400/70 mb-1 px-1">⚡ trazado directo de Supabase</div>' : '') + lista.map(c => {
        const _est = String(c.nfEstado || '');
        const _rech = _est === 'RECHAZADO' || _est === 'RECHAZADO_SUNAT' || _est === 'ERROR';
        const estCls = _est === 'EMITIDO' ? 'trib-row-est-ok' : _rech ? 'trib-row-est-error' : 'trib-row-est-warn';
        // [TRAZABILIDAD] distinguir aceptado-NubeFact (firmado/generado) de aceptado-SUNAT (CDR). Las filas de
        // Supabase traen las banderas; las de GAS caen al estado plano.
        let estTxt;
        if (_viaSupa) {
          if (c.aceptadoSunat) estTxt = '🟢 aceptado SUNAT';
          else if (_rech) estTxt = '🔴 rechazado SUNAT' + (c.sunatDesc ? ' · ' + _escapeHtml(String(c.sunatDesc).slice(0, 40)) : '');
          else if (c.aceptadoNubefact) estTxt = '🟡 en NubeFact · pendiente SUNAT';
          else estTxt = '⚪ sin emitir';
        } else {
          estTxt = _est === 'EMITIDO' ? '🟢 emitido' : _est === 'RECHAZADO_SUNAT' ? '🔴 rechazado SUNAT'
                 : _est === 'ERROR' ? '🔴 error' : _est === 'PENDIENTE' ? '🟡 pendiente' : '⚪ ' + (_est || 'sin estado');
        }
        const _refLocal = c.refLocal || '';
        const _noEmitido = _est !== 'EMITIDO';
        return `<div class="trib-row">
          <span class="trib-row-icon">${c.tipo === 'FACTURA' ? '📋' : '🧾'}</span>
          <div class="trib-row-data">
            <strong>${_escapeHtml(c.correlativo)}</strong> · ${_escapeHtml(c.cliente || 'sin cliente')}
            <br><small>${(new Date(c.fecha)).toLocaleString('es-PE')} · ${_escapeHtml(c.tipo)}${c.enlaceCdr ? ' · <a href="'+_escapeHtml(c.enlaceCdr)+'" target="_blank" style="color:#34d399">CDR</a>' : ''}${c.enlacePdf ? ' · <a href="'+_escapeHtml(c.enlacePdf)+'" target="_blank" style="color:#60a5fa">PDF</a>' : ''}</small>
          </div>
          <span class="trib-row-monto">${_tribFmtSoles(c.total)}</span>
          <span class="${estCls}" style="font-size:10.5px">${estTxt}</span>
          ${_noEmitido ? `<button class="trib-btn-mini" onclick="MOS.tribReintentarCPE('${_escapeHtml(c.idVenta)}', '${_escapeHtml(c.correlativo)}', '${_escapeHtml(c.tipo)}', '${_escapeHtml(_refLocal)}')">🔄</button>` : ''}
        </div>`;
      }).join('');
    } catch(e) {
      cont.innerHTML = '<div class="text-red-400 text-xs">❌ ' + (e.message || e) + '</div>';
    }
  }

  async function tribReprocesarOCR(idGuia) {
    const auth = await pedirAuth({ accion: 'TRIBUTARIO_REPROCESAR_OCR', refDocumento: idGuia });
    if (!auth) return;
    toast('🔄 Reprocesando OCR de ' + idGuia + '...', 'info');
    try {
      // [Lote3-A · fix A4-MOS] API.post lanza si ok:false → llegar acá ES éxito.
      // Antes exigía res.ok && res.data (ambos undefined tras desempaquetar) →
      // mostraba "OCR falló" en operaciones EXITOSAS. `res` ES el data ya desempaquetado.
      const res = await API.post('tribReprocesarOCR', { idGuia });
      const d = (res && res.data) ? res.data : (res || {});
      toast('✓ OCR ' + (d.estado || 'reprocesado') + (d.igvRecuperable > 0 ? ' · IGV ' + _tribFmtSoles(d.igvRecuperable) : ''), 'success');
      _finBeep && _finBeep('success');
    } catch(e) {
      toast('OCR falló: ' + (e.message || e), 'warn');
    } finally {
      tribCargar(); // refresh siempre
    }
  }

  async function tribReintentarCPE(idVenta, correlativo, tipoDoc, refLocal) {
    const auth = await pedirAuth({ accion: 'TRIBUTARIO_REINTENTAR_CPE', refDocumento: idVenta });
    if (!auth) return;
    toast('🔄 Consultando estado en SUNAT...', 'info');
    try {
      // [RECONCILIACIÓN cero-GAS] PRIMERO el Edge (operacion=consultar → me.set_cpe_nf): re-consulta el
      // estado SUNAT real y lo persiste, SIN GAS. Requiere correlativo+tipo+refLocal (los pasa la fila de
      // trazabilidad de Supabase). Si no vienen (fila vieja de GAS) o el Edge no responde → fallback GAS.
      let hecho = false;
      if (correlativo && tipoDoc && refLocal) {
        const r = await API.cpeReconciliar({ correlativo, tipoDoc, refLocal });
        if (r && r.ok) {
          toast('✓ CPE ' + (r.estado || 'consultado') + (r.aceptada ? ' · aceptado SUNAT' : (r.sunatDesc ? ' · ' + r.sunatDesc : '')), 'success');
          _finBeep && _finBeep('success'); hecho = true;
        } else if (r && r.ok === false && r.error) {
          toast('SUNAT/NubeFact: ' + r.error, 'warn'); hecho = true;
        }
        // r === null → infra (sin token/red) → cae a GAS abajo
      }
      if (!hecho) {
        const res = await API.post('tribReintentarCPE', { idVenta });
        const d = (res && res.data) ? res.data : (res || {});
        toast('✓ CPE ' + (d.nuevoEstado || d.estado || 'reconciliado') + (d.aceptada ? ' · aceptado SUNAT' : ''), 'success');
        _finBeep && _finBeep('success');
      }
    } catch(e) {
      toast('Reintento falló: ' + (e.message || e), 'warn');
    } finally {
      tribAbrirIGVEmitido();
    }
  }

  async function tribReconciliarCPEs() {
    const auth = await pedirAuth({ accion: 'TRIBUTARIO_RECONCILIAR_TODOS', refDocumento: 'mes-actual' });
    if (!auth) return;
    toast('🔄 Reconciliando todos los CPE pendientes con NubeFact/SUNAT...', 'info');
    try {
      // [500x-2b · cero-GAS] PRIMERO Supabase: jala los pendientes (cpe_trazabilidad) e itera el Edge
      // consultar por cada uno (API.cpeReconciliar → set_cpe_nf), sin GAS. Fallback a GAS si no hay token.
      const _mm = String(_tribState.mes).padStart(2, '0');
      const _desde = `${_tribState.anio}-${_mm}-01`;
      const _ult = new Date(_tribState.anio, _tribState.mes, 0).getDate();
      const _hasta = `${_tribState.anio}-${_mm}-${String(_ult).padStart(2, '0')}`;
      let viaSupa = false, emitidos = 0, rechazados = 0, sinCambio = 0;
      const sup = await API.cpeTrazabilidad(_desde, _hasta);
      if (sup && sup.ok && Array.isArray(sup.cpe)) {
        const pend = sup.cpe.filter(c => !c.aceptadoSunat && String(c.nfEstado || '').toUpperCase().indexOf('BAJA') !== 0 && c.nfEstado !== 'RECHAZADO' && c.refLocal && c.correlativo);
        for (const c of pend) {
          const r = await API.cpeReconciliar({ correlativo: c.correlativo, tipoDoc: c.tipo, refLocal: c.refLocal });
          if (r === null) { viaSupa = false; break; }          // sin token/red → caer a GAS
          viaSupa = true;
          if (r.ok && r.estado === 'EMITIDO') emitidos++;
          else if (r.ok && r.estado === 'RECHAZADO') rechazados++;
          else sinCambio++;
        }
        if (viaSupa || pend.length === 0) { viaSupa = true; }
      }
      if (!viaSupa) {
        const res = await API.post('tribReconciliarCPEs', {});
        const stats = res?.data || res || {};
        emitidos = stats.emitidos || 0; rechazados = stats.rechazados || 0; sinCambio = stats.sin_cambio || 0;
      }
      toast('✓ ' + emitidos + ' emitidos · ' + rechazados + ' rechazados · ' + sinCambio + ' sin cambio' + (viaSupa ? ' ⚡' : ''), 'success');
      _finBeep && _finBeep('success');
      tribAbrirIGVEmitido();
    } catch(e) { toast('Error: ' + (e.message || e), 'error'); }
  }

  // [v2.42.11] Exportar a Excel — descarga CSV (compatible con Excel) con
  // 2 secciones: COMPRAS (IGV a favor del mes) y VENTAS (CPE emitidos).
  // Sin requerir librerías extras — genera el archivo en el cliente.
  async function tribExportarExcel() {
    if (!_tribState.mes || !_tribState.anio) {
      toast('Selecciona un mes primero', 'warning');
      return;
    }
    const nombreMes = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'][_tribState.mes - 1];
    toast('📥 Generando Excel...', 'info', 3000);
    try {
      _finBeep && _finBeep('tap');
      // Cargar compras (IGV a favor) y ventas (CPE emitidos) en paralelo
      const [resCompras, resVentas] = await Promise.all([
        API.post('tribIGVFavorMes',   { mes: _tribState.mes, anio: _tribState.anio }),
        API.post('tribIGVEmitidoMes', { mes: _tribState.mes, anio: _tribState.anio })
      ]);
      const compras = (resCompras?.data?.guias || []);
      const ventas  = (resVentas?.cpe || resVentas?.data?.cpe || []);
      // Construir CSV con BOM UTF-8 para que Excel respete acentos
      const sep = ';';   // Excel ES suele esperar punto y coma
      const esc = (v) => {
        const s = String(v == null ? '' : v).replace(/"/g, '""');
        return /[";\n]/.test(s) ? '"' + s + '"' : s;
      };
      let csv = '﻿'; // BOM UTF-8
      // Sección compras
      csv += 'COMPRAS - IGV A FAVOR · ' + nombreMes + ' ' + _tribState.anio + '\n';
      csv += ['Fecha','Guia','RUC Emisor','Razón Social','Serie','Número','Total Doc','IGV Recuperable','Estado OCR','Confidence'].map(esc).join(sep) + '\n';
      let totalCompras = 0, totalIGVFavor = 0;
      compras.forEach(g => {
        const fecha = g.fechaComprobante || (g.fecha ? new Date(g.fecha).toLocaleDateString('es-PE') : '');
        csv += [
          fecha, g.idGuia, g.rucEmisor, g.razonSocial,
          g.serie, g.numero, g.total, g.igvRecuperable,
          g.ocrEstado, g.confidence
        ].map(esc).join(sep) + '\n';
        totalCompras  += parseFloat(g.total) || 0;
        totalIGVFavor += parseFloat(g.igvRecuperable) || 0;
      });
      csv += ['','','','','','TOTAL', totalCompras.toFixed(2), totalIGVFavor.toFixed(2),'',''].map(esc).join(sep) + '\n';
      csv += '\n\n';
      // Sección ventas
      csv += 'VENTAS - CPE EMITIDOS · ' + nombreMes + ' ' + _tribState.anio + '\n';
      csv += ['Fecha','Tipo Doc','Correlativo','RUC/DNI Cliente','Razón Social','Total','IGV Emitido','Estado SUNAT','Vendedor'].map(esc).join(sep) + '\n';
      let totalVentas = 0, totalIGVEmitido = 0;
      ventas.forEach(v => {
        const fecha = v.fecha || '';
        const igvCalc = v.igv != null ? parseFloat(v.igv) : (parseFloat(v.total) || 0) * 0.18 / 1.18;
        csv += [
          fecha, v.tipoDoc, v.correlativo, v.docCliente,
          v.nombreCliente, v.total, igvCalc.toFixed(2),
          v.estadoSUNAT || v.nfEstado || '', v.vendedor
        ].map(esc).join(sep) + '\n';
        totalVentas    += parseFloat(v.total) || 0;
        totalIGVEmitido += igvCalc;
      });
      csv += ['','','','','TOTAL', totalVentas.toFixed(2), totalIGVEmitido.toFixed(2),'',''].map(esc).join(sep) + '\n';
      csv += '\n\n';
      // Resumen tributario
      csv += 'RESUMEN TRIBUTARIO\n';
      csv += ['IGV a favor (compras)','S/ ' + totalIGVFavor.toFixed(2)].map(esc).join(sep) + '\n';
      csv += ['IGV emitido (ventas)', 'S/ ' + totalIGVEmitido.toFixed(2)].map(esc).join(sep) + '\n';
      csv += ['IGV neto (a pagar)',   'S/ ' + (totalIGVEmitido - totalIGVFavor).toFixed(2)].map(esc).join(sep) + '\n';
      csv += ['Total compras',        'S/ ' + totalCompras.toFixed(2)].map(esc).join(sep) + '\n';
      csv += ['Total ventas',         'S/ ' + totalVentas.toFixed(2)].map(esc).join(sep) + '\n';
      csv += ['Renta MYPE 1.5%',      'S/ ' + (totalVentas * 0.015).toFixed(2)].map(esc).join(sep) + '\n';
      // Descargar
      const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `tributario_${_tribState.anio}-${String(_tribState.mes).padStart(2,'0')}.csv`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      _finBeep && _finBeep('success');
      toast(`✓ Excel listo · ${compras.length} compras · ${ventas.length} ventas`, 'success', 6000);
    } catch(e) {
      _finBeep && _finBeep('error');
      toast('Error generando Excel: ' + (e.message || e), 'error');
    }
  }

  // [v2.42.11] Proyección de cierre de mes basado en ritmo actual.
  // Si vamos al 71% del mes con S/ 1000 de IGV, proyectamos 1000/0.71 = 1408.
  function _tribCalcProyeccion(d) {
    if (!d || !d.pctMes || d.pctMes <= 0) return null;
    const factor = 100 / d.pctMes;
    return {
      igvFavorProy:    (d.igvFavor || 0)   * factor,
      igvEmitidoProy:  (d.igvEmitido || 0) * factor,
      balanceNetoProy: (d.balanceNetoIGV || 0) * factor,
      ventasProy:      (d.totalVentas || 0) * factor,
      pctMes:          d.pctMes,
      diasRestantes:   (d.ultimoDia || 30) - (d.diaActual || 0)
    };
  }

  // [v2.41.94] OCR masivo retroactivo del mes — procesa todas las fotos
  // de boletas/facturas de proveedor sin OCR. Muestra progress y stats.
  async function tribOCRMasivo() {
    const auth = await pedirAuth({ accion: 'TRIBUTARIO_OCR_MASIVO', refDocumento: _tribState.mes + '/' + _tribState.anio });
    if (!auth) return;
    if (!await _modalConfirm('¿Procesar con Claude todas las fotos de boletas/facturas SIN OCR del mes ' + _tribState.mes + '/' + _tribState.anio + '?\n\nPuede tardar 1-2 minutos (30 guías ≈ 60s).', { warning: true, titulo: 'OCR masivo del mes', okText: 'Procesar' })) return;
    toast('🤖 Procesando OCR del mes... esperá 1-2 min', 'info');
    try {
      const res = await API.post('tribOCRMasivo', {
        mes: _tribState.mes, anio: _tribState.anio, soloSinProcesar: true
      });
      const s = res?.data || res || {};
      if (s.ok || s.procesadas !== undefined) {
        toast('✓ OCR: ' + (s.procesadas || 0) + ' procesadas · ' + (s.conIGV || 0) + ' con IGV (' + _tribFmtSoles(s.totalIGVRecuperado || 0) + ')' +
              (s.sinIGV ? ' · ' + s.sinIGV + ' sin IGV' : '') +
              (s.ilegibles ? ' · ' + s.ilegibles + ' ilegibles' : '') +
              (s.errores ? ' · ' + s.errores + ' errores' : ''), 'success');
        _finBeep && _finBeep('success');
      } else {
        toast('OCR masivo falló: ' + (res?.error || 'sin detalle'), 'warn');
      }
      tribCargar(); // refresh KPIs con el IGV nuevo
      // [v2.42.10] Si el detalle IGV a favor está abierto, refrescar también
      const detalle = document.querySelector('#tribIGVFavorList');
      const det = detalle && detalle.closest('details');
      if (det && det.open) {
        setTimeout(() => tribAbrirIGVFavor(), 400);
      }
    } catch(e) { toast('Error: ' + (e.message || e), 'error'); }
  }

  async function tribLimpiarHuerfanas() {
    const auth = await pedirAuth({ accion: 'TRIBUTARIO_LIMPIAR_HUERFANAS', refDocumento: 'global' });
    if (!auth) return;
    if (!await _modalConfirm('¿Marcar las filas con correlativo "undefined-*" como HUERFANA_LIMPIADA?', { warning: true, titulo: 'Limpiar huérfanas' })) return;
    try {
      const res = await API.post('tribLimpiarVentasHuerfanas', {});
      const n = res?.limpiadas || res?.data?.limpiadas || 0;
      toast('🧹 ' + n + ' filas huérfanas marcadas', 'success');
      _finBeep && _finBeep('success');
    } catch(e) { toast('Error: ' + (e.message || e), 'error'); }
  }

  // [v2.41.93] Histórico 12 meses con chart de barras dual + stats agregados
  async function tribAbrirHistorico() {
    // Construir modal
    let modal = $('tribHistModal');
    if (modal) modal.remove();
    modal = document.createElement('div');
    modal.id = 'tribHistModal';
    modal.className = 'trib-hist-modal';
    modal.innerHTML = `
      <div class="trib-hist-card">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
          <h2 style="font-size:1.2rem;font-weight:900;color:#f1f5f9">📊 Histórico 12 meses</h2>
          <button onclick="document.getElementById('tribHistModal').remove()" style="background:transparent;border:none;color:#94a3b8;font-size:1.5rem;cursor:pointer">✕</button>
        </div>
        <div id="tribHistContent">
          <div class="text-center py-8 text-slate-500 text-sm">
            <svg class="w-6 h-6 animate-spin mx-auto mb-2" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"></path></svg>
            Cargando histórico (12 meses)...
          </div>
        </div>
      </div>`;
    // Click outside cierra
    modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
    document.body.appendChild(modal);
    _finBeep && _finBeep('expand');

    try {
      const res = await API.post('tribHistorico12meses', {});
      const data = (res?.data || res) || [];
      if (!data.length) {
        $('tribHistContent').innerHTML = '<div class="text-slate-500 text-center py-6">Sin datos para mostrar</div>';
        return;
      }
      // Stats agregados
      const totalFavor   = data.reduce((s, m) => s + (m.igvFavor || 0), 0);
      const totalEmitido = data.reduce((s, m) => s + (m.igvEmitido || 0), 0);
      const totalNeto    = totalEmitido - totalFavor;
      const totalVentas  = data.reduce((s, m) => s + (m.ventas || 0), 0);
      const totalRenta   = data.reduce((s, m) => s + (m.renta || 0), 0);
      const promVentas   = data.length > 0 ? totalVentas / data.length : 0;

      // Max bar para escalar
      const maxBar = Math.max(...data.map(m => Math.max(m.igvFavor || 0, m.igvEmitido || 0)), 1);

      const barsHTML = data.map(m => {
        const wF = Math.round(((m.igvFavor   || 0) / maxBar) * 100);
        const wP = Math.round(((m.igvEmitido || 0) / maxBar) * 100);
        return `<div class="trib-hist-bar-row">
          <div class="trib-hist-bar-mes">${m.label} ${String(m.anio).slice(-2)}</div>
          <div class="trib-hist-bar-cont">
            <div class="trib-hist-bar-favor" style="width:${wF}%" title="IGV a favor: ${_tribFmtSoles(m.igvFavor)}"></div>
            <div class="trib-hist-bar-pagar" style="width:${wP}%" title="IGV a pagar: ${_tribFmtSoles(m.igvEmitido)}"></div>
          </div>
          <div class="trib-hist-bar-val">
            ${_tribFmtSoles(m.balance)}<br><small>${_tribFmtSoles(m.ventas)}</small>
          </div>
        </div>`;
      }).join('');

      $('tribHistContent').innerHTML = `
        <div class="trib-hist-grid">
          <div class="trib-hist-stat">
            <div class="trib-hist-stat-lbl">IGV pagado total</div>
            <div class="trib-hist-stat-val" style="color:#fbbf24">${_tribFmtSoles(totalNeto)}</div>
          </div>
          <div class="trib-hist-stat">
            <div class="trib-hist-stat-lbl">Ventas total</div>
            <div class="trib-hist-stat-val">${_tribFmtSoles(totalVentas)}</div>
          </div>
          <div class="trib-hist-stat">
            <div class="trib-hist-stat-lbl">Renta total</div>
            <div class="trib-hist-stat-val" style="color:#34d399">${_tribFmtSoles(totalRenta)}</div>
          </div>
        </div>
        <div class="trib-hist-chart">
          ${barsHTML}
          <div class="trib-hist-leg">
            <div class="trib-hist-leg-item"><span class="trib-hist-leg-dot" style="background:#34d399"></span>IGV favor</div>
            <div class="trib-hist-leg-item"><span class="trib-hist-leg-dot" style="background:#fbbf24"></span>IGV emitido</div>
            <div class="trib-hist-leg-item"><span style="color:#cbd5e1">Balance neto · Ventas mes</span></div>
          </div>
        </div>
        <p style="font-size:11px;color:#64748b;text-align:center;margin-top:8px">
          Promedio mensual de ventas: <strong style="color:#cbd5e1">${_tribFmtSoles(promVentas)}</strong>
        </p>`;
    } catch(e) {
      $('tribHistContent').innerHTML = '<div class="text-red-400 text-center py-6">❌ ' + (e.message || e) + '</div>';
    }
  }

  // [v2.41.93] Toggle panel ayuda
  function tribToggleAyuda() {
    const p = $('tribAyuda');
    if (p) p.classList.toggle('hidden');
    _finBeep && _finBeep('click');
  }

  // [v2.41.93] Pre-carga al boot — corre en background al login
  async function _tribPrecargarBoot() {
    try {
      iconBusy('tributario', true);
      const res = await API.post('tribResumenMes', {});
      // [Lote3-A · fix M0a-MOS] API.post YA desempaqueta d.data → res = {mes, anio, ...}.
      // Antes `if (res && res.data)` saltaba TODO el bloque → el badge de alertas
      // tributarias (CPE/OCR) nunca aparecía al login + se perdía la precarga.
      const d = (res && res.data) ? res.data : res;   // tolera ambas formas
      if (d && d.mes) {
        _tribState.data = d;
        _tribState.mes  = d.mes;
        _tribState.anio = d.anio;
        // [v2.42.12] Precargar también la lista de IGV a favor del mes para que
        // el detalle abra instantáneo (sin esperar el roundtrip a WH al hacer
        // click en "Ver detalle"). Silent + fire-and-forget: no bloquea el login.
        _tribFetchIGVFavor(true);
        // Badge: si hay alertas (errores CPE u OCR), mostrar en nav
        const alertas = (d.cpeErrores || 0) + (d.guiasIlegibles || 0);
        const badge = $('tribNavBadge');
        if (badge) {
          if (alertas > 0) {
            badge.textContent = String(alertas);
            badge.classList.remove('hidden');
            badge.title = alertas + ' CPE/OCR requieren atención';
          } else {
            badge.classList.add('hidden');
          }
        }
      }
    } catch(e) {
      console.warn('[Tributario precarga]', e.message);
    } finally {
      iconBusy('tributario', false);
    }
  }

  async function _loadFinanzas() {
    const inp = $('finFecha');
    const hoy = today();
    // Al ABRIR el módulo siempre arrancamos en hoy (la fecha quedaba
    // pegada al último día que vio el usuario y el label se mostraba
    // como "—" cuando _finPL traía datos de otro día).
    if (inp) inp.value = hoy;
    const fecha = hoy;
    _finBeep('nav');
    _finUpdateBadge(fecha);  // label "🟢 Hoy · ..." al instante
    // Si los datos precargados (_finPL) son del MISMO día que hoy, los
    // pintamos al vuelo. Si son de otro día, ignoramos y refrescamos.
    // _finPL viene marcado (ver finCargar). Si no coincide con hoy → refrescar.
    if (_finPL && (_finPL._fechaStamp === fecha || _finPL.fecha === fecha)) {
      _finRender(_finPL, fecha);
      const hasta  = fecha;
      const desde7 = _fechaOffset(fecha, -6);
      try {
        const rango = await API.get('getFinanzasRango', { desde: desde7, hasta });
        _finRender7d(rango);
      } catch(_) {}
      _finPrefetchAdyacentes(fecha);
      _finStartPolling();
      return;
    }
    await finCargar();
    _finStartPolling();
  }

  // [v2.41.78] POLLING UNIFICADO — un solo intervalo cada 30s mientras
  // estamos en vista Finanzas. Antes había DOS pollings (30s + 60s) que
  // causaban 3-4 requests/min innecesarios + el parpadeo característico.
  // Ahora 1 solo refresca P&L + dispara refresh side-effects (liq) solo
  // cada 2 ticks (60s) para mantener la misma cadencia de antes en lo
  // accesorio.
  let _finPollInt = null;
  let _finPollTickCount = 0;
  function _finStartPolling() {
    _finStopPolling();
    _finPollTickCount = 0;
    _finPollInt = setInterval(() => {
      if (S.view !== 'finanzas') { _finStopPolling(); return; }
      _finPollTickCount++;
      // Refresh silencioso del día visible — sin animación. finCargar usa
      // hash rápido para detectar cambios y _finRenderPersonal usa diff
      // minimal → no parpadea si nada cambió.
      try { finCargar({ animate: false, _silent: true }); } catch(_){}
      // Cada 2 ticks (60s) refresca también liquidaciones pendientes —
      // antes esto lo hacía _finanzasRefreshSilencioso a 60s, ahora se
      // hace en el mismo tren del polling 30s. Evita duplicar intervals.
      if (_finPollTickCount % 2 === 0) {
        try {
          API.get('getLiquidacionesPendientesSemana', {}).then(r => {
            if (r) {
              try { _liqSaveCache('pendientes', r); } catch(_){}
              if (S.view === 'config' && S.cfgTab === 'personal') {
                try { _cfgRenderMeCajeros(); } catch {}
              }
            }
          }).catch(() => {});
        } catch(_){}
      }
    }, 30000);
  }
  function _finStopPolling() {
    if (_finPollInt) { clearInterval(_finPollInt); _finPollInt = null; }
    _finPollTickCount = 0;
  }

  // ── Sync / Update ────────────────────────────────────────────
  function syncApp()           { if (window._SWControl) window._SWControl.sync(); }
  function applyPendingUpdate(){ if (window._SWControl) window._SWControl.applyPending(); }

  // ════════════════════════════════════════════════════════════
  // LIQUIDACIONES v2 — pagos acumulados día a día
  // Modelo: cada día con presencia es una liquidación pendiente.
  // Admin selecciona días → "Pagar" → genera batch LIQ-XXXX por persona.
  // ════════════════════════════════════════════════════════════
  // ── [v2.41.72] Constantes y helpers compartidos ──────────────
  const Z_MODAL_BACKDROP = 9400;   // .modal-backdrop (estándar)
  const Z_MODAL_OVERLAY  = 9500;   // modales sobre otro modal (anular sobre detalle)
  const Z_MODAL_CRITICAL = 9700;   // alertas críticas (sobre todo)

  // Parser unificado de respuestas API — algunas devuelven array directo,
  // otras { ok, data }. Centraliza el unwrap.
  function _liqParseResp(res) {
    if (Array.isArray(res)) return res;
    if (res && Array.isArray(res.data)) return res.data;
    if (res && res.data && typeof res.data === 'object') return res.data;
    return res || {};
  }

  // localStorage safe con toast de aviso si falla (quota/private mode)
  function _liqLsSet(key, val) {
    try { localStorage.setItem(key, val); return true; }
    catch(e) {
      try { toast('💾 No se pudo guardar cache local (' + (e.name || 'error') + ')', 'warn', 4000); } catch(_){}
      return false;
    }
  }

  // Formato fecha corta con guard (B9)
  function _liqFmtFechaCortaSafe(fecha) {
    if (typeof _liqFmtFechaCorta === 'function') return _liqFmtFechaCorta(fecha);
    return String(fecha || '—');
  }

  // Validación rango fechas (B3)
  function _liqValidarRango(desde, hasta) {
    const re = /^\d{4}-\d{2}-\d{2}$/;
    if (!re.test(String(desde)) || !re.test(String(hasta))) return false;
    if (desde > hasta) return false;
    return true;
  }

  // AbortController activo por petición (B1)
  let _liqAbortCtrl = null;
  function _liqAbortPrevious() {
    if (_liqAbortCtrl) {
      try { _liqAbortCtrl.abort(); } catch(_){}
    }
    _liqAbortCtrl = new AbortController();
    return _liqAbortCtrl.signal;
  }

  const _liqState = {
    tab: 'pendientes',
    desde: null,
    hasta: null,
    pendientes: [],            // array de { idPersonal, dias[], total, ... }
    pagadas: [],               // array de batches
    seleccion: {},             // { idPersonal: Set<fecha> }
    expandidos: {},            // { idPersonal: bool }
    currentPagoDet: null
  };

  // ── Cache localStorage por pestaña ──────────────────────────
  const LIQ_CACHE_PFX = 'mos_liq_';
  const LIQ_CACHE_TTL = 30 * 60 * 1000;
  function _liqLoadCache(key) {
    try {
      const raw = localStorage.getItem(LIQ_CACHE_PFX + key);
      if (!raw) return null;
      const p = JSON.parse(raw);
      if (Date.now() - (p.ts || 0) > LIQ_CACHE_TTL) return null;
      return p.data;
    } catch { return null; }
  }
  function _liqSaveCache(key, data) {
    // [v2.41.72-B8] Usar helper con toast si falla quota/private mode
    _liqLsSet(LIQ_CACHE_PFX + key, JSON.stringify({ ts: Date.now(), data }));
  }
  // Pre-cargar al iniciar sesión y persistir
  // Prefetch de TODAS las tablas del módulo Configuraciones para que
  // cualquier tab abra al instante. Se ejecuta al autenticar y guarda
  // los resultados en cfgData / state cache → cuando el usuario abre la
  // pestaña, renderCfgTab encuentra datos listos y solo refresca en bg.
  function _prefetchConfigModulos() {
    if (!S.session) return;
    // Notificaciones (catálogo)
    API.get('getNotificacionesConfig', {}).then(r => {
      const arr = Array.isArray(r) ? r : ((r && r.data) || []);
      _notifState.items = arr;
      _notifState.cargado = true;
    }).catch(() => {});
    // Categorías
    API.get('getCategorias', {}).then(r => {
      if (Array.isArray(r)) cfgData.categorias = r;
    }).catch(() => {});
    // Personal (de PERSONAL_MASTER)
    API.get('getPersonalMaster', {}).then(r => {
      if (Array.isArray(r)) cfgData.personalMaster = r;
    }).catch(() => {});
    // Dispositivos (infraestructura)
    API.get('getDispositivos', {}).then(r => {
      if (Array.isArray(r)) cfgData.dispositivos = _dispAplicarShield(r);
    }).catch(() => {});
    // Zonas + Estaciones + Impresoras (infra)
    API.get('getZonas',     {}).then(r => { if (Array.isArray(r)) cfgData.zonas = r; }).catch(() => {});
    API.get('getEstaciones',{}).then(r => { if (Array.isArray(r)) cfgData.estaciones = r; }).catch(() => {});
    API.get('getImpresoras',{}).then(r => { if (Array.isArray(r)) cfgData.impresoras = r; }).catch(() => {});
  }

  function _prefetchLiquidaciones() {
    if (!S.session) return;
    iconBusy('finanzas', true);
    // ── v2: precarga del nuevo modelo (Pendientes + Pagadas) ──
    // Guarda en localStorage (mos_liq2_*) para que liqOpen pinte al instante.
    // Inline el prefijo porque _LIQ_CACHE_PFX se declara más abajo (const en TDZ).
    try {
      API.get('getLiquidacionesPendientes', {}).then(r => {
        const arr = Array.isArray(r) ? r : ((r && r.data) || []);
        try { localStorage.setItem('mos_liq2_pendientes', JSON.stringify({ ts: Date.now(), data: arr })); } catch(_){}
      }).catch(() => {});
      API.get('getLiquidacionesPagadas', {}).then(r => {
        const arr = Array.isArray(r) ? r : ((r && r.data) || []);
        try { localStorage.setItem('mos_liq2_pagadas', JSON.stringify({ ts: Date.now(), data: arr })); } catch(_){}
      }).catch(() => {});
    } catch(_){}
    Promise.all([
      API.get('getLiquidacionesPendientesSemana', {}).then(r => {
        if (r) {
          _liqSaveCache('pendientes', r);
          // Encadenar prefetch de detalles de cada persona en background
          if (r.personal && r.personal.length) {
            setTimeout(() => _prefetchDetallesLiq(r.personal), 1500);
          }
        }
      }).catch(() => {}),
      API.get('getLiquidacionesEmitidas', { estado: 'PENDIENTE' }).then(r => {
        _liqSaveCache('emitidas', r || []);
      }).catch(() => {}),
      API.get('getLiquidacionesEmitidas', { estado: 'PAGADA' }).then(r => {
        _liqSaveCache('pagadas', r || []);
      }).catch(() => {}),
      // Histórico: sin filtro (todas las emitidas, paginadas server-side)
      API.get('getLiquidacionesEmitidas', {}).then(r => {
        _liqSaveCache('historico', r || []);
      }).catch(() => {})
    ]).finally(() => iconBusy('finanzas', false));
  }

  // ════════════════════════════════════════════════════════════
  // LIQUIDACIONES v2 — implementación
  // ════════════════════════════════════════════════════════════
  function _liqMoney(n) { return 'S/' + (parseFloat(n) || 0).toFixed(2); }
  function _liqFmtFecha(s) {
    if (!s) return '';
    try {
      const d = new Date(String(s).substring(0, 10) + 'T12:00:00');
      return d.toLocaleDateString('es-PE', { day: '2-digit', month: 'short' });
    } catch { return String(s); }
  }
  function _liqFmtFechaLarga(s) {
    if (!s) return '';
    try {
      const d = new Date(String(s).substring(0, 10) + 'T12:00:00');
      return d.toLocaleDateString('es-PE', { weekday: 'short', day: '2-digit', month: 'short' });
    } catch { return String(s); }
  }
  function _liqRolIco(rol) {
    const r = String(rol || '').toUpperCase();
    if (r === 'CAJERO' || r === 'VENDEDOR') return '🛒';
    if (r === 'ALMACENERO')                  return '🏭';
    if (r === 'ENVASADOR')                   return '🏷';
    return '👤';
  }

  // SFX reusados — usa el motor del módulo Evaluación si está disponible
  function _liqSfx(tipo) {
    if (typeof _evalSfx === 'function') _evalSfx(tipo);
  }
  function _liqRipple(ev) {
    if (typeof _evalRipple === 'function') _evalRipple(ev);
  }
  function _liqConfetti(x, y, color) {
    if (typeof _evalConfetti === 'function') _evalConfetti(x, y, color);
  }

  // Cache localStorage para apertura optimista
  const _LIQ_CACHE_PFX = 'mos_liq2_';
  const _LIQ_CACHE_TTL = 30 * 60 * 1000;
  function _liqCacheKey(tab) { return _LIQ_CACHE_PFX + tab; }
  function _liqCacheLoad(tab) {
    try {
      const raw = localStorage.getItem(_liqCacheKey(tab));
      if (!raw) return null;
      const p = JSON.parse(raw);
      if (Date.now() - (p.ts || 0) > _LIQ_CACHE_TTL) return null;
      return p.data;
    } catch { return null; }
  }
  function _liqCacheSave(tab, data) {
    // [v2.41.72-B8] usar helper con feedback
    _liqLsSet(_liqCacheKey(tab), JSON.stringify({ ts: Date.now(), data }));
  }
  function _liqCacheClear() {
    try {
      localStorage.removeItem(_liqCacheKey('pendientes'));
      localStorage.removeItem(_liqCacheKey('pagadas'));
    } catch(_){}
  }

  async function liqOpen() {
    _liqState.tab = 'pendientes';
    // [B2 + B7] Restaurar selección y filtro persistente del usuario
    _liqState.seleccion = _liqLoadSeleccion();
    _liqState.filtroPersonas = _liqLoadFiltroPersonas();
    _liqState.expandidos = {};
    // ⚡ Materializado: backend lee directo de LIQUIDACIONES_DIA, podemos
    // pedir 30 días sin penalización
    var hoy = _liqHoy();
    _liqState.hasta = hoy;
    _liqState.desde = _liqOffset(hoy, -29);
    openModal('modalLiquidaciones');
    _liqSfx('open');
    _liqSetSyncState('idle');
    _liqRenderRangoPresets();
    // Pintar desde cache instantáneamente si existe
    const cached = _liqCacheLoad('pendientes');
    if (cached) {
      _liqState.pendientes = cached;
      _liqRenderPendientes();
      _liqUpdatePayBar();
    }
    await liqLoadCurrent();
    // 🚀 Prefetch Historial (pagadas) en background — al cambiar tab será
    // instantáneo. No bloquea la UI del tab actual.
    _liqPrefetchTab('pagadas');
    // [v2.41.58] Polling background cada 30s mientras el modal esté abierto
    _liqStartPolling();
  }

  // [v2.41.74] Indicador visual de sincronización (header dot)
  function _liqSetSyncState(estado) {
    const el = document.getElementById('liqSyncDot');
    if (!el) return;
    el.classList.remove('is-loading', 'is-error');
    if (estado === 'loading') { el.classList.add('is-loading'); el.textContent = 'sync'; el.title = 'Refrescando datos…'; }
    else if (estado === 'error') { el.classList.add('is-error'); el.textContent = 'err'; el.title = 'Error al sincronizar — reintenta con ↻'; }
    else { el.textContent = 'live'; el.title = 'Sincronizado · auto-refresh cada 30s'; }
  }

  // [v2.41.58] Polling bg 30s — refresca SOLO el tab actual sin parpadeo.
  // El render tiene guard interno por tab → si user cambió de tab durante
  // el fetch, la respuesta vieja se descarta. Cada respuesta repinta solo
  // si la firma de datos cambió (anti-flicker).
  let _liqPollInt = null;
  let _liqEscHandler = null;
  function _liqStartPolling() {
    _liqStopPolling();
    _liqPollInt = setInterval(() => {
      const modal = document.getElementById('modalLiquidaciones');
      if (!modal || modal.classList.contains('hidden')) {
        _liqStopPolling();
        return;
      }
      // Silent refresh: re-fetch tab actual sin animación
      liqLoadCurrent();
      // También refresh vetadas si está cargado
      if (_liqState.vetadas) _liqCargarVetadas();
    }, 30000);
    // [v2.41.72-B10] Escape key también para de polling sin esperar el check
    _liqEscHandler = (e) => {
      if (e.key === 'Escape' || e.keyCode === 27) {
        const modal = document.getElementById('modalLiquidaciones');
        if (modal && !modal.classList.contains('hidden')) {
          liqClose();
        }
      }
    };
    document.addEventListener('keydown', _liqEscHandler);
  }
  function _liqStopPolling() {
    if (_liqPollInt) { clearInterval(_liqPollInt); _liqPollInt = null; }
    if (_liqEscHandler) { document.removeEventListener('keydown', _liqEscHandler); _liqEscHandler = null; }
    if (_liqAbortCtrl) { try { _liqAbortCtrl.abort(); } catch(_){} _liqAbortCtrl = null; }
  }

  // Prefetch silencioso del tab no activo. Si ya hay cache fresh o state
  // poblado, no hace nada. Si falla, no muestra error — solo deja el tab
  // sin cache (cuando el user vaya, hará fetch normal).
  function _liqPrefetchTab(tab) {
    try {
      // Si ya tenemos el state poblado, no re-fetch
      if (tab === 'pendientes' && _liqState.pendientes && _liqState.pendientes.length) return;
      if (tab === 'pagadas'   && _liqState.pagadas    && _liqState.pagadas.length)    return;
      // Si hay cache fresh, hidratar state y no fetch
      const cached = _liqCacheLoad(tab);
      if (cached) {
        if (tab === 'pendientes') _liqState.pendientes = cached;
        else if (tab === 'pagadas') _liqState.pagadas = cached;
        return;
      }
      // Fetch silencioso — no bloquea
      const params = tab === 'pendientes'
        ? { desde: _liqState.desde, hasta: _liqState.hasta }
        : { desde: _liqOffset(_liqHoy(), -89), hasta: _liqHoy() };
      const endpoint = tab === 'pendientes' ? 'getLiquidacionesPendientes' : 'getLiquidacionesPagadas';
      const ms = tab === 'pendientes' ? 15000 : 30000;
      _liqFetchConTimeout(endpoint, params, ms).then(res => {
        const arr = _liqParseResp(res);
        const list = Array.isArray(arr) ? arr : (arr.data || []);
        if (tab === 'pendientes') _liqState.pendientes = list;
        else if (tab === 'pagadas') _liqState.pagadas = list;
        _liqCacheSave(tab, list);
      }).catch(err => {
        // [v2.41.72-B5] Log silencioso pero visible en consola — antes era
        // catch(()=>{}) y el prefetch fallaba sin rastro alguno.
        console.warn('[liqPrefetchTab ' + tab + '] fallo:', err && err.message || err);
      });
    } catch(_) { /* tolerar */ }
  }

  // Cargar más días: extender el rango hacia atrás (acumular días viejos)
  async function liqCargarMasDias() {
    _liqSfx('tap');
    const hoy = _liqHoy();
    const diasActuales = _diff(_liqState.desde, _liqState.hasta);
    const nuevoDesde = diasActuales < 7  ? _liqOffset(hoy, -13)
                     : diasActuales < 20 ? _liqOffset(hoy, -29)
                     :                     _liqOffset(hoy, -59);
    // [B3] Validar rango antes de fetch
    if (!_liqValidarRango(nuevoDesde, hoy)) {
      toast('📅 Rango inválido', 'warn', 3000);
      return;
    }
    _liqState.desde = nuevoDesde;
    _liqState.hasta = hoy;
    // [B4] Invalidar cache del rango anterior para forzar fresh
    try { _liqCacheClear(); } catch(_){}
    await liqLoadCurrent();
    toast(`📅 Mostrando últimos ${_diff(nuevoDesde, hoy) + 1} días`, 'info');
  }
  function _diff(d1, d2) {
    try {
      const a = new Date(d1 + 'T12:00:00').getTime();
      const b = new Date(d2 + 'T12:00:00').getTime();
      return Math.round((b - a) / 86400000);
    } catch { return 0; }
  }

  function liqClose() {
    _liqState.seleccion = {};
    _liqStopPolling();
    closeModal('modalLiquidaciones');
  }

  function liqSetTab(tab) {
    if (_liqState.tab === tab) return;
    _liqState.tab = tab;
    _liqState.seleccion = {};
    document.querySelectorAll('#modalLiquidaciones .liq-tab').forEach(el => {
      el.classList.toggle('active', el.dataset.liqtab === tab);
    });
    // [v2.41.38] Mostrar/ocultar barra de filtro por persona según tab
    const filtroBar = document.getElementById('liqFiltroBar');
    if (filtroBar) filtroBar.style.display = (tab === 'pendientes') ? 'block' : 'none';
    _liqUpdatePayBar();
    _liqSfx('switch');

    // 🚀 INSTANTÁNEO: si ya tenemos data en state (prefetched o cacheado),
    // pintar de una vez SIN esperar fetch. Antes el cambio de tab Historial→
    // Pendientes "se colgaba" 10-15s esperando getLiquidacionesPendientes
    // aunque la data ya estuviera en cache localStorage.
    const body = $('liqBody');
    if (body) body.dataset._hasCache = '';
    let pintadoInstantaneo = false;
    if (tab === 'pendientes') {
      const datos = (_liqState.pendientes && _liqState.pendientes.length)
        ? _liqState.pendientes
        : _liqCacheLoad('pendientes');
      if (datos) {
        _liqState.pendientes = datos;
        _liqRenderPendientes();
        if (body) body.dataset._hasCache = '1';
        pintadoInstantaneo = true;
      }
    } else if (tab === 'pagadas') {
      const datos = (_liqState.pagadas && _liqState.pagadas.length)
        ? _liqState.pagadas
        : _liqCacheLoad('pagadas');
      if (datos) {
        _liqState.pagadas = datos;
        _liqRenderPagadas();
        if (body) body.dataset._hasCache = '1';
        pintadoInstantaneo = true;
      }
    }

    // [v2.41.39] Si NO se pintó instantáneo, limpiar el body para evitar
    // que se vea data del tab anterior mientras se hace el fetch.
    if (!pintadoInstantaneo && body) {
      body.innerHTML = '<div class="text-xs text-slate-500 italic text-center py-6">Cargando...</div>';
    }

    // Fetch fresco (en background si pintamos instantáneamente, foreground si no)
    liqLoadCurrent();

    // Prefetch del tab opuesto para que la siguiente navegación también
    // sea instantánea.
    const opuesto = tab === 'pendientes' ? 'pagadas' : (tab === 'pagadas' ? 'pendientes' : null);
    if (opuesto) _liqPrefetchTab(opuesto);
  }

  function liqRefresh() {
    _liqSfx('tap');
    liqLoadCurrent();
  }

  // ── Rango de fechas ──
  function _liqHoy() {
    const d = new Date();
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  }
  function _liqOffset(fecha, dias) {
    const d = new Date(fecha + 'T12:00:00');
    d.setDate(d.getDate() + dias);
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  }
  function _liqLunes(fecha) {
    const d = new Date(fecha + 'T12:00:00');
    const dia = d.getDay() || 7; // dom=7
    d.setDate(d.getDate() - (dia - 1));
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  }
  function _liqRangoPreset(preset, soloSetState) {
    const hoy = _liqHoy();
    let desde = hoy, hasta = hoy;
    if (preset === 'hoy') { desde = hoy; hasta = hoy; }
    else if (preset === 'semana')   { desde = _liqLunes(hoy); hasta = _liqOffset(desde, 6); }
    else if (preset === 'quincena') { desde = _liqOffset(hoy, -14); hasta = hoy; }
    else if (preset === 'mes') {
      const d = new Date(hoy + 'T12:00:00');
      desde = d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-01';
      hasta = hoy;
    }
    _liqState.desde = desde;
    _liqState.hasta = hasta;
    if (!soloSetState) {
      _liqSyncRangoInputs();
      _liqSfx('tap');
      liqLoadCurrent();
    }
  }
  function liqSetRangoPreset(preset) { _liqRangoPreset(preset); }
  function _liqSyncRangoInputs() {
    const d = $('liqRangoDesde'); if (d) d.value = _liqState.desde || '';
    const h = $('liqRangoHasta'); if (h) h.value = _liqState.hasta || '';
  }
  function _liqLeerRangoInputs() {
    const d = $('liqRangoDesde');
    const h = $('liqRangoHasta');
    // [v2.41.72-B3] Validar formato + orden antes de aceptar
    const dv = d && d.value;
    const hv = h && h.value;
    if (dv && hv && !_liqValidarRango(dv, hv)) {
      toast('📅 Rango inválido (desde > hasta o formato incorrecto)', 'warn', 4000);
      // Restaurar valores previos en los inputs
      _liqSyncRangoInputs();
      return false;
    }
    if (dv) _liqState.desde = dv;
    if (hv) _liqState.hasta = hv;
    return true;
  }

  // Helper: race API.get contra un timeout para que la UI no se quede eternamente cargando
  function _liqFetchConTimeout(endpoint, params, ms) {
    return Promise.race([
      API.get(endpoint, params || {}),
      new Promise((_, reject) => setTimeout(() => reject(new Error('Timeout — el backend está tardando demasiado')), ms || 60000))
    ]);
  }

  // ── Carga + render ──
  async function liqLoadCurrent() {
    const body = $('liqBody');
    if (!body) return;
    const tabActual = _liqState.tab;
    // Si NO hay cache previo pintado, mostrar skeleton premium con shimmer.
    // Si SÍ hay → no parpadeo.
    if (!_liqState.pendientes || !_liqState.pendientes.length) {
      if (tabActual === 'pendientes' && !body.dataset._hasCache) {
        body.innerHTML = `
          <div class="liq-skel-stage">
            <div class="liq-skel-row"></div>
            <div class="liq-skel-row" style="animation-delay: 0.12s"></div>
            <div class="liq-skel-row" style="animation-delay: 0.24s"></div>
            <div class="liq-skel-row" style="animation-delay: 0.36s"></div>
            <div class="liq-skel-stage-hint">
              <span class="liq-skel-hint-dot"></span>
              Sincronizando liquidaciones...
            </div>
          </div>`;
      } else if (tabActual === 'pagadas' && !body.dataset._hasCache) {
        body.innerHTML = `
          <div class="liq-skel-stage">
            <div class="liq-skel-card"></div>
            <div class="liq-skel-card" style="animation-delay: 0.14s"></div>
            <div class="liq-skel-card" style="animation-delay: 0.28s"></div>
            <div class="liq-skel-stage-hint">
              <span class="liq-skel-hint-dot"></span>
              Cargando historial de pagos...
            </div>
          </div>`;
      }
    }
    // [v2.41.72-B1] Token único por llamada. Si otra llamada se dispara
    // (polling + click manual), solo la última gana — evita race conditions
    // donde una respuesta vieja pinta sobre datos frescos del mismo tab.
    const _myToken = (window._liqLoadToken = (window._liqLoadToken || 0) + 1);
    _liqSetSyncState('loading');
    try {
      if (tabActual === 'pendientes') {
        const res = await _liqFetchConTimeout('getLiquidacionesPendientes', { desde: _liqState.desde, hasta: _liqState.hasta }, 15000);
        if (_liqState.tab !== tabActual || _myToken !== window._liqLoadToken) return;
        const arr = _liqParseResp(res);
        const list = Array.isArray(arr) ? arr : (arr.data || []);
        _liqState.pendientes = list;
        _liqCacheSave('pendientes', list);
        body.dataset._hasCache = '1';
        _liqRenderPendientes();
      } else if (tabActual === 'pagadas') {
        const res = await _liqFetchConTimeout('getLiquidacionesPagadas', { desde: _liqOffset(_liqHoy(), -89), hasta: _liqHoy() }, 30000);
        if (_liqState.tab !== tabActual || _myToken !== window._liqLoadToken) return;
        const arr = _liqParseResp(res);
        const list = Array.isArray(arr) ? arr : (arr.data || []);
        _liqState.pagadas = list;
        _liqCacheSave('pagadas', list);
        _liqRenderPagadas();
      } else if (tabActual === 'resumen') {
        _liqRenderResumen();
      }
    } catch(e) {
      _liqSetSyncState('error');
      // Si ya había datos pintados (de cache), mantenerlos y solo mostrar toast
      if (body.dataset._hasCache) {
        toast('⚠ ' + (e.message || 'Error de red, mostrando cache'), 'error');
      } else {
        body.innerHTML = `<div class="text-center py-10">
          <div class="text-3xl mb-2 opacity-50">⚠</div>
          <div class="text-sm text-rose-400 mb-2">${e.message || e}</div>
          <button onclick="MOS.liqRefresh()" class="btn-primary btn-ripple text-xs px-4 py-2 mt-2">↻ Reintentar</button>
        </div>`;
      }
      _liqUpdatePayBar();
      return;
    }
    _liqSetSyncState('idle');
    _liqUpdatePayBar();
  }

  // ── Render PENDIENTES ──
  function _liqRenderPendientes() {
    const body = $('liqBody');
    if (!body) return;
    const all = _liqState.pendientes || [];
    // [v2.41.38] Renderizar chips de personas SIEMPRE (aunque haya 0 después de filtrar)
    _liqRenderFiltroChips(all);
    if (!all.length) {
      body.innerHTML = `<div class="liq-empty">
        <div class="liq-empty-emoji">🎉</div>
        <div class="text-sm">Todo al día</div>
        <div class="text-xs text-slate-600 mt-1">No hay liquidaciones pendientes.</div>
        <div class="text-[10px] text-slate-700 mt-3">¿Primera vez con el módulo? Ve a <strong>📊 Resumen</strong> → <strong>🔧 Inicializar Liquidación Diaria</strong></div>
      </div>`;
      return;
    }
    // [v2.41.38] Aplicar filtro de personas si hay activo
    const filtroSel = _liqState.filtroPersonas;
    const list = (filtroSel && filtroSel.size > 0)
      ? all.filter(p => filtroSel.has(p.idPersonal))
      : all;
    // [500x] contar nombres repetidos en TODO el set (no solo el filtrado) para el chip 🔗
    _liqDupNames = {};
    (all || []).forEach(p => {
      const n = String(p.nombre || '').toLowerCase().trim().normalize('NFD').replace(/[̀-ͯ]/g, '');
      if (n) _liqDupNames[n] = (_liqDupNames[n] || 0) + 1;
    });
    if (!list.length) {
      body.innerHTML = `<div class="liq-empty">
        <div class="liq-empty-emoji">🔍</div>
        <div class="text-sm">Sin resultados para el filtro</div>
        <div class="text-xs text-slate-600 mt-1">Toca el chip para quitar el filtro</div>
      </div>`;
      return;
    }
    const totalGeneral = list.reduce((s, p) => s + p.total, 0);
    const totalDias = list.reduce((s, p) => s + p.cantidadDias, 0);
    // [v2.41.74] Estado de selección global → botón ☑ TODOS / ✕ Limpiar
    let totalSel = 0;
    list.forEach(p => {
      const sel = _liqState.seleccion[p.idPersonal];
      if (sel && sel.size) totalSel += sel.size;
    });
    const todoSeleccionado = totalSel === totalDias && totalDias > 0;
    const btnGlobal = todoSeleccionado
      ? `<button class="liq-select-all-global" onclick="MOS._liqDeseleccionarTodoRango()" title="Limpiar selección">✕ Limpiar selección (${totalSel})</button>`
      : `<button class="liq-select-all-global" onclick="MOS._liqSeleccionarTodoRango()" title="Seleccionar todos los días visibles">☑ Marcar TODOS los días (${totalDias})</button>`;
    body.innerHTML = `
      <div class="flex items-center justify-between gap-2 mb-3 pb-2 border-b border-slate-800 flex-wrap">
        <div class="text-xs text-slate-400">
          <strong class="text-amber-400">${list.length}</strong> persona${list.length !== 1 ? 's' : ''} ·
          <strong class="text-amber-400">${totalDias}</strong> día${totalDias !== 1 ? 's' : ''}
        </div>
        ${btnGlobal}
        <div class="text-right ml-auto">
          <div class="text-[10px] uppercase text-slate-500 tracking-wider">Adeudado total</div>
          <div class="text-lg font-bold" style="color:#fbbf24">${_liqMoney(totalGeneral)}</div>
        </div>
      </div>
      ${list.map((p, i) => _liqCardPersona(p, i)).join('')}
    `;
  }

  // [v2.41.74] Selección global — marcar/limpiar TODOS los días visibles
  function _liqSeleccionarTodoRango() {
    const all = _liqState.pendientes || [];
    const filtroSel = _liqState.filtroPersonas;
    const list = (filtroSel && filtroSel.size > 0) ? all.filter(p => filtroSel.has(p.idPersonal)) : all;
    list.forEach(p => {
      _liqState.seleccion[p.idPersonal] = new Set(p.dias.map(d => d.fecha));
    });
    _liqSaveSeleccion();
    _liqSfx('add');
    _liqRenderPendientes();
    _liqUpdatePayBar();
  }
  function _liqDeseleccionarTodoRango() {
    _liqState.seleccion = {};
    _liqSaveSeleccion();
    _liqSfx('remove');
    _liqRenderPendientes();
    _liqUpdatePayBar();
  }

  // [v2.41.74] Render chips presets de rango (siempre visibles)
  function _liqRenderRangoPresets() {
    const cont = document.getElementById('liqRangoPresets');
    if (!cont) return;
    const hoy = _liqHoy();
    const presets = [
      { id: 'hoy',      label: '📅 Hoy',     desde: hoy, hasta: hoy },
      { id: 'semana',   label: '📆 Semana',  desde: _liqLunes(hoy), hasta: _liqOffset(_liqLunes(hoy), 6) },
      { id: 'quincena', label: '🗓 15 días', desde: _liqOffset(hoy, -14), hasta: hoy },
      { id: 'mes30',    label: '📊 30 días', desde: _liqOffset(hoy, -29), hasta: hoy },
      { id: 'mes',      label: '📅 Mes',     desde: (function(){ const d = new Date(hoy + 'T12:00:00'); return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-01'; })(), hasta: hoy }
    ];
    cont.innerHTML = presets.map(p => {
      const isAct = _liqState.desde === p.desde && _liqState.hasta === p.hasta;
      return `<div class="liq-rango-preset-chip${isAct ? ' is-active' : ''}"
                   onclick="MOS._liqAplicarRangoPreset('${p.id}')">${p.label}</div>`;
    }).join('');
  }
  function _liqAplicarRangoPreset(id) {
    const hoy = _liqHoy();
    let desde = hoy, hasta = hoy;
    if (id === 'hoy') { desde = hoy; hasta = hoy; }
    else if (id === 'semana')   { desde = _liqLunes(hoy); hasta = _liqOffset(desde, 6); }
    else if (id === 'quincena') { desde = _liqOffset(hoy, -14); hasta = hoy; }
    else if (id === 'mes30')    { desde = _liqOffset(hoy, -29); hasta = hoy; }
    else if (id === 'mes') {
      const d = new Date(hoy + 'T12:00:00');
      desde = d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-01';
      hasta = hoy;
    }
    if (_liqState.desde === desde && _liqState.hasta === hasta) return;
    _liqState.desde = desde; _liqState.hasta = hasta;
    _liqSfx('tap');
    try { _liqCacheClear(); } catch(_){}
    _liqRenderRangoPresets();
    liqLoadCurrent();
  }

  // [v2.41.38] Render chips de filtro por persona — multi-select.
  // Muestra avatar (iniciales) + nombre + badge con N días.
  function _liqRenderFiltroChips(all) {
    // [v2.41.74] Re-render rango presets si cambió
    _liqRenderRangoPresets();
    const cont = document.getElementById('liqFiltroChips');
    if (!cont) return;
    if (_liqState.tab !== 'pendientes' || !all.length) {
      cont.innerHTML = '';
      cont.style.display = 'none';
      return;
    }
    cont.style.display = 'flex';
    _liqState.filtroPersonas = _liqState.filtroPersonas || new Set();
    const sel = _liqState.filtroPersonas;
    // Ordenar por mayor cantidad de días primero
    const ordenadas = [...all].sort((a, b) => b.cantidadDias - a.cantidadDias);
    const iniciales = (nom) => {
      const partes = String(nom || '').trim().split(/\s+/);
      return ((partes[0]?.[0] || '?') + (partes[1]?.[0] || '')).toUpperCase();
    };
    const chips = ordenadas.map(p => {
      const isAct = sel.has(p.idPersonal);
      const idEsc = _escapeHtml(p.idPersonal).replace(/'/g, "\\'");
      return `<div class="liq-chip-persona${isAct ? ' is-active' : ''}"
                   onclick="MOS._liqToggleFiltroPersona('${idEsc}')"
                   title="${_escapeHtml(p.nombre)} · ${p.cantidadDias} día(s) · ${_liqMoney(p.total)}">
                <span class="liq-chip-avatar">${_escapeHtml(iniciales(p.nombre))}</span>
                <span class="liq-chip-nombre">${_escapeHtml(p.nombre.split(' ')[0] || p.nombre)}</span>
                <span class="liq-chip-badge">${p.cantidadDias}</span>
              </div>`;
    }).join('');
    const clearBtn = sel.size > 0
      ? `<div class="liq-chip-clear" onclick="MOS._liqLimpiarFiltroPersonas()" title="Quitar filtro">✕ limpiar (${sel.size})</div>`
      : '';
    cont.innerHTML = chips + clearBtn;
  }

  // [B7] Persistir filtroPersonas en localStorage para sobrevivir polling
  function _liqSaveFiltroPersonas() {
    try {
      const arr = Array.from(_liqState.filtroPersonas || []);
      _liqLsSet('mos_liq_filtro_personas', JSON.stringify(arr));
    } catch(_){}
  }
  function _liqLoadFiltroPersonas() {
    try {
      const raw = localStorage.getItem('mos_liq_filtro_personas');
      if (!raw) return new Set();
      return new Set(JSON.parse(raw));
    } catch(_) { return new Set(); }
  }
  function _liqToggleFiltroPersona(idPersonal) {
    _liqState.filtroPersonas = _liqState.filtroPersonas || new Set();
    if (_liqState.filtroPersonas.has(idPersonal)) {
      _liqState.filtroPersonas.delete(idPersonal);
    } else {
      _liqState.filtroPersonas.add(idPersonal);
    }
    _liqSaveFiltroPersonas();
    try { _liqSfx('tap'); } catch(_){}
    _liqRenderPendientes();
  }

  function _liqLimpiarFiltroPersonas() {
    _liqState.filtroPersonas = new Set();
    _liqSaveFiltroPersonas();
    try { _liqSfx('tap'); } catch(_){}
    _liqRenderPendientes();
  }

  let _liqDupNames = {};   // [500x] nombre normalizado → # de filas, para el chip 🔗 en Liquidaciones
  function _liqCardPersona(p, idx) {
    const expandido = _liqState.expandidos[p.idPersonal] !== false; // default abierto
    const sel = _liqState.seleccion[p.idPersonal] || new Set();
    const selDias = sel.size || 0;
    const todoSelec = selDias === p.dias.length && selDias > 0;
    const subtotalSel = p.dias.filter(d => sel.has(d.fecha)).reduce((s,d) => s + d.totalDia, 0);
    const ico = _liqRolIco(p.rol);
    const cardCls = selDias > 0 ? ' has-selection' : '';
    // [500x · chip 🔗 en Liquidaciones] el mismo nombre en >1 fila (mismo movido de zona / dos
    // personas) → el admin decide antes de pagar. Nombre escapado (XSS).
    const _lqNorm = String(p.nombre || '').toLowerCase().trim().normalize('NFD').replace(/[̀-ͯ]/g, '');
    const _lqN = _liqDupNames[_lqNorm] || 0;
    const dupChip = _lqN > 1
      ? `<span class="badge-rol" style="background:rgba(245,158,11,.14);color:#fbbf24;border:1px solid rgba(245,158,11,.4)" title="⚠ &quot;${_escapeHtml(p.nombre)}&quot; aparece en ${_lqN} filas (¿mismo movido de zona? ¿dos personas?). Decide antes de pagar: sanción-base o pagar ambas.">🔗 ${_lqN}× ⚠</span>`
      : '';
    return `
      <div class="liq-pers-card${cardCls}" data-pers="${p.idPersonal}" style="--i:${Math.min(idx, 18)}">
        <div class="flex items-center gap-3 cursor-pointer" onclick="MOS._liqTogglePersona('${p.idPersonal}', event)">
          <span style="font-size:22px">${ico}</span>
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-2 flex-wrap">
              <div class="font-semibold text-slate-100 text-sm truncate">${_escapeHtml(p.nombre)}</div>
              <span class="text-[10px] uppercase tracking-wider text-slate-500">${_escapeHtml(p.rol)}</span>
              ${dupChip}
            </div>
            <div class="text-xs text-slate-500 mt-0.5">
              <strong class="text-amber-400">${p.cantidadDias}</strong> día(s) sin pagar
              ${selDias > 0 ? ` · <strong style="color:#34d399">${selDias} seleccionado(s)</strong>` : ''}
            </div>
          </div>
          <div class="text-right">
            ${selDias > 0
              ? `<div class="text-[10px] uppercase text-emerald-400 font-bold tracking-wider">Seleccionado</div>
                 <div class="text-base font-bold" style="color:#34d399">${_liqMoney(subtotalSel)}</div>
                 <div class="text-[10px] text-slate-500">de ${_liqMoney(p.total)}</div>`
              : `<div class="text-[10px] uppercase text-slate-500 font-bold tracking-wider">Total</div>
                 <div class="text-base font-bold" style="color:#fbbf24">${_liqMoney(p.total)}</div>`
            }
          </div>
          <span style="color:#64748b;font-size:14px;transition:transform .25s">${expandido ? '▾' : '▸'}</span>
        </div>
        ${expandido ? `
          <div class="mt-2 pt-2 border-t border-slate-800">
            <label class="flex items-center gap-2 text-xs text-slate-400 cursor-pointer mb-2 select-none">
              <input type="checkbox" class="liq-check-master" ${todoSelec ? 'checked' : ''}
                     onchange="MOS._liqToggleAll('${p.idPersonal}', this.checked)">
              <span>Seleccionar todos los días</span>
            </label>
            ${p.dias.map(d => _liqDiaRow(p.idPersonal, d, sel.has(d.fecha))).join('')}
          </div>
        ` : ''}
      </div>`;
  }

  function _liqDiaRow(idPersonal, d, isSelected) {
    const fechaCorta = _liqFmtFechaLarga(d.fecha);
    const audCls = d.auditado ? 'aud-ok' : 'no-aud';
    const sel = isSelected ? ' selected' : '';
    // Línea sub: componentes del totalDia
    const partes = [];
    if (d.montoBase    > 0) partes.push(`base ${d.montoBase.toFixed(2)}`);
    if (d.pagoEnvasado > 0) partes.push(`env ${d.pagoEnvasado.toFixed(2)}`);
    if (d.bonoMeta     > 0) partes.push(`<span style="color:#34d399">+meta ${d.bonoMeta.toFixed(2)}</span>`);
    if (d.sancion      > 0) partes.push(`<span style="color:#f87171">−san ${d.sancion.toFixed(2)}</span>`);
    return `
      <div class="liq-dia-row ${audCls}${sel}" data-row-key="${idPersonal}|${d.fecha}">
        <input type="checkbox" class="liq-check" ${isSelected ? 'checked' : ''}
               onchange="MOS._liqToggleDia('${idPersonal}', '${d.fecha}', this.checked, event)">
        <div class="flex-1 min-w-0">
          <div class="text-xs text-slate-200 font-medium">${fechaCorta}
            ${d.auditado ? '<span class="text-[9px] text-emerald-400 ml-1">✓ auditado</span>' : '<span class="text-[9px] text-amber-400 ml-1">⚠ sin auditar</span>'}
          </div>
          ${partes.length ? `<div class="text-[10px] text-slate-500 mt-0.5">${partes.join(' · ')}</div>` : ''}
        </div>
        <div class="text-right shrink-0">
          <div class="text-sm font-bold text-amber-400">${_liqMoney(d.totalDia)}</div>
        </div>
        <button onclick="event.stopPropagation();MOS._liqEditarDia('${idPersonal}', '${d.fecha}')"
                class="text-xs px-2 py-1 rounded transition-all hover:scale-110 liq-btn-edit-tip"
                style="background:rgba(99,102,241,.1);color:#a5b4fc;border:1px solid rgba(99,102,241,.3)"
                aria-label="Auditar y recomputar este día">✏</button>
        <button onclick="event.stopPropagation();MOS._liqConfirmarVetar('${idPersonal}', '${d.fecha}')"
                class="liq-btn-vetar"
                title="Vetar: quita este día de pendientes (no paga, no computa). Reversible.">💸</button>
      </div>`;
  }

  function _liqTogglePersona(idPersonal, ev) {
    // Si el click fue en un input/button interno, no togglear
    if (ev && ev.target.closest('input, button')) return;
    _liqState.expandidos[idPersonal] = !(_liqState.expandidos[idPersonal] !== false); // toggle
    _liqSfx(_liqState.expandidos[idPersonal] ? 'expand' : 'collapse');
    _liqRenderPendientes();
  }

  // [B2] Persistir selección en localStorage para sobrevivir polling 30s
  function _liqSaveSeleccion() {
    try {
      const obj = {};
      Object.keys(_liqState.seleccion || {}).forEach(k => {
        obj[k] = Array.from(_liqState.seleccion[k] || []);
      });
      _liqLsSet('mos_liq_seleccion', JSON.stringify(obj));
    } catch(_){}
  }
  function _liqLoadSeleccion() {
    try {
      const raw = localStorage.getItem('mos_liq_seleccion');
      if (!raw) return {};
      const obj = JSON.parse(raw);
      const out = {};
      Object.keys(obj).forEach(k => { out[k] = new Set(obj[k] || []); });
      return out;
    } catch(_) { return {}; }
  }
  function _liqToggleDia(idPersonal, fecha, checked, ev) {
    if (!_liqState.seleccion[idPersonal]) _liqState.seleccion[idPersonal] = new Set();
    const set = _liqState.seleccion[idPersonal];
    if (checked) set.add(fecha); else set.delete(fecha);
    _liqSaveSeleccion();
    if (set.size === 0) delete _liqState.seleccion[idPersonal];
    _liqSfx('tap');
    _liqRenderPendientes();
    _liqUpdatePayBar();
  }

  function _liqToggleAll(idPersonal, checked) {
    const p = _liqState.pendientes.find(x => x.idPersonal === idPersonal);
    if (!p) return;
    if (checked) {
      _liqState.seleccion[idPersonal] = new Set(p.dias.map(d => d.fecha));
    } else {
      delete _liqState.seleccion[idPersonal];
    }
    _liqSfx(checked ? 'add' : 'remove');
    _liqRenderPendientes();
    _liqUpdatePayBar();
  }

  function _liqUpdatePayBar() {
    const bar = $('liqPayBar');
    if (!bar) return;
    if (_liqState.tab !== 'pendientes') { bar.classList.add('hidden'); return; }
    let totalSel = 0;
    let personasSel = 0;
    let diasSel = 0;
    Object.keys(_liqState.seleccion).forEach(idP => {
      const sel = _liqState.seleccion[idP];
      if (!sel || !sel.size) return;
      const p = _liqState.pendientes.find(x => x.idPersonal === idP);
      if (!p) return;
      personasSel++;
      p.dias.forEach(d => { if (sel.has(d.fecha)) { totalSel += d.totalDia; diasSel++; } });
    });
    if (diasSel === 0) { bar.classList.add('hidden'); return; }
    bar.classList.remove('hidden');
    $('liqPaySubtitle').textContent = `${diasSel} día(s) · ${personasSel} persona(s)`;
    $('liqPayTotal').textContent = _liqMoney(totalSel);
  }

  // ── Editar día (re-auditar) ──
  // OPTIMISTA: abrimos el modal Auditar al instante usando los datos que ya
  // tenemos del state (pendiente). Después fetch real en background y
  // re-renderizamos las secciones del modal con la data fresca.
  // [v2.43.386] UNIFICADO con Personal del día: el ÚNICO gate de vetar es la clave
  // admin (pedirAuth dentro de _liqVetarDia, sin cache). Se quitó el mini-modal de
  // confirmación previo para que AMBOS lados muestren exactamente lo mismo: un solo
  // modal de clave. (Antes: box "¿Vetar?" + clave = doble paso, inconsistente con
  // Finanzas que solo confirmaba sin clave.)
  function _liqConfirmarVetar(idPersonal, fecha) {
    return _liqVetarDia(idPersonal, fecha);
  }

  // [v2.41.31] Vetar/Desvetar inline desde lista pendientes ─────────
  // Optimista: la fila se desintegra al instante. Backend marca VETADA.
  // Si falla, restauramos local + warn.
  async function _liqVetarDia(idPersonal, fecha) {
    _liqSfx('tap');
    // [v2.41.83] AdminAuthModal (antes solo confirm()) — tier 2 cache 5min
    const persona = (_liqState.pendientes || []).find(x => x.idPersonal === idPersonal);
    const nomP = persona ? persona.nombre : idPersonal;
    const auth = await pedirAuth({
      accion: 'VETAR_LIQUIDACION',
      allowCache: false,   // [v2.43.386] clave SIEMPRE (sin el cache 5min que la saltaba)
      refDocumento: idPersonal + '|' + fecha,
      contexto: `Vetar día de ${nomP} · ${fecha}`
    });
    if (!auth) return;
    // Animación de salida en la fila
    const row = document.querySelector(`.liq-dia-row[data-row-key="${idPersonal}|${fecha}"]`);
    if (row) {
      row.classList.add('liq-row-vetando');
    }
    // Optimista: quitar del state local
    const p = (_liqState.pendientes || []).find(x => x.idPersonal === idPersonal);
    if (!p) return;
    const diaIdx = p.dias.findIndex(d => d.fecha === fecha);
    if (diaIdx < 0) return;
    const diaSnapshot = p.dias[diaIdx];
    const personaIdx = _liqState.pendientes.indexOf(p);

    setTimeout(() => {
      p.dias.splice(diaIdx, 1);
      p.total = Math.round(p.dias.reduce((s, d) => s + d.totalDia, 0) * 100) / 100;
      p.cantidadDias = p.dias.length;
      if (!p.dias.length) {
        _liqState.pendientes.splice(personaIdx, 1);
      }
      _liqRenderPendientes();
    }, 280);

    // [v2.41.50] FIX: API.post devuelve d.data (no d). Si vetarLiquidacionDia
    // responde {ok:true}, API.post resuelve con undefined → la rama
    // "if(!res||!res.ok)" lanzaba falso negativo "Backend no respondió".
    // Solución: confiar en que API.post resuelve → éxito; .catch → error real
    // (e.message trae el error key del backend: YA_PAGADA, NO_ENCONTRADA…).
    // [B1] Marcar mutación reciente (60s) — el polling chequea esto y pasa
    // _refresh=true para no traer cache stale del backend.
    window._liqLastMutationTs = Date.now();
    try {
      await API.post('vetarLiquidacionDia', {
        idPersonal, fecha, claveAdmin: (auth && auth.clave) || '',
        localId: 'L' + Date.now() + Math.random().toString(36).slice(2, 8)
      });
      toast(`💸 Vetada · ${_liqFmtFechaCortaSafe(fecha)}`, 'info', 2500);
      // [B15] Invalidar cache cruzado de Finanzas
      try { localStorage.removeItem('mos_fin_resum_' + fecha); } catch(_){}
      if (S.view === 'finanzas' && typeof finCargar === 'function') {
        try { finCargar({ animate: false, _silent: true }); } catch(_){}
      }
    } catch(e) {
      const errKey = (e && e.message) || 'sin_respuesta';
      let msg;
      if (errKey === 'YA_PAGADA') msg = 'Esta liquidación ya está PAGADA — no se puede vetar.';
      else if (errKey === 'NO_ENCONTRADA') msg = `No encontrada en hoja: ${fecha} para ${idPersonal}. Toca el lápiz primero para materializar.`;
      else msg = `No se pudo vetar: ${errKey}`;
      toast(msg, 'warn', 6000);
      // Rollback
      if (!_liqState.pendientes.includes(p)) _liqState.pendientes.push(p);
      if (!p.dias.find(d => d.fecha === fecha)) p.dias.push(diaSnapshot);
      p.total = Math.round(p.dias.reduce((s, d) => s + d.totalDia, 0) * 100) / 100;
      p.cantidadDias = p.dias.length;
      _liqRenderPendientes();
    }
  }

  async function _liqDesvetarDia(idPersonal, fecha) {
    _liqSfx('tap');
    // [v2.41.83] AdminAuthModal (antes click directo sin clave) — tier 1 cache 10min
    const vetada = (_liqState.vetadas || []).find(v => v.idPersonal === idPersonal && v.fecha === fecha);
    const auth = await pedirAuth({
      accion: 'DESVETAR_LIQUIDACION',
      allowCache: false,   // [v2.43.386] clave SIEMPRE (consistente con vetar)
      refDocumento: idPersonal + '|' + fecha,
      contexto: `Desvetar ${vetada ? vetada.nombre : idPersonal} · ${fecha}`
    });
    if (!auth) return;
    try {
      await API.post('desvetarLiquidacionDia', {
        idPersonal, fecha, claveAdmin: (auth && auth.clave) || '',
        localId: 'L' + Date.now() + Math.random().toString(36).slice(2, 8)
      });
      toast(`💵 Desvetada · ${fecha}`, 'ok', 2500);
      _liqState.vetadas = (_liqState.vetadas || []).filter(v =>
        !(v.idPersonal === idPersonal && v.fecha === fecha));
      _liqRenderVetadas();
      // [B5] Invalidar TODOS los caches + forzar refresh pendientes para que
      // la persona desvetada vuelva a aparecer al instante (sin esperar polling).
      try { _liqCacheClear(); } catch(_){}
      try { localStorage.removeItem('mos_fin_resum_' + fecha); } catch(_){}
      try { liqLoadCurrent(); } catch(_){}
      // [B14] Notificar a Finanzas si está abierto
      if (S.view === 'finanzas' && typeof finCargar === 'function') {
        try { finCargar({ animate: false, _silent: true }); } catch(_){}
      }
    } catch(e) {
      toast('No se pudo desvetar: ' + ((e && e.message) || 'error'), 'warn', 4000);
    }
  }

  async function _liqCargarVetadas() {
    // [B6] Mostrar loading mientras carga vetadas (antes silencioso)
    const cont = document.getElementById('liqVetadasBody');
    if (cont && !_liqState.vetadas?.length) {
      cont.innerHTML = '<div class="text-xs text-slate-500 italic text-center py-4"><span class="inline-block animate-spin">⌛</span> Cargando vetadas…</div>';
    }
    try {
      const res = await API.get('getLiquidacionesVetadas', {});
      if (res?.ok) {
        _liqState.vetadas = res.data || [];
        _liqRenderVetadas();
      } else if (cont) {
        cont.innerHTML = '<div class="text-xs text-rose-400 italic text-center py-4">Error cargando vetadas</div>';
      }
    } catch(e) {
      if (cont) cont.innerHTML = '<div class="text-xs text-rose-400 italic text-center py-4">⚠ ' + (e.message || 'error') + '</div>';
    }
  }

  function _liqRenderVetadas() {
    const cont = document.getElementById('liqVetadasBody');
    if (!cont) return;
    const list = _liqState.vetadas || [];
    if (!list.length) {
      cont.innerHTML = '<div class="text-xs text-slate-500 italic text-center py-4">Sin liquidaciones vetadas</div>';
      return;
    }
    cont.innerHTML = list.map(v => {
      const fechaCorta = _liqFmtFechaLarga ? _liqFmtFechaLarga(v.fecha) : v.fecha;
      return `
        <div class="liq-dia-row" style="opacity:.75;position:relative">
          <span class="liq-stamp vetado" style="top:50%;right:60px">Vetado</span>
          <span style="font-size:18px;flex-shrink:0">🚫</span>
          <div class="flex-1 min-w-0">
            <div class="text-xs text-slate-300 font-medium">${_esc(v.nombre)}</div>
            <div class="text-[10px] text-slate-500 mt-0.5">${_esc(v.rol)} · ${fechaCorta}</div>
          </div>
          <div class="text-right shrink-0">
            <div class="text-sm font-bold text-slate-500" style="text-decoration:line-through">${_liqMoney(v.totalDia)}</div>
          </div>
          <button onclick="MOS._liqDesvetarDia('${v.idPersonal}', '${v.fecha}')"
                  class="liq-btn-desvetar"
                  title="Desvetar — vuelve a la lista de pendientes">🔓</button>
        </div>`;
    }).join('');
  }

  function _liqToggleVetadasPanel() {
    const panel = document.getElementById('liqVetadasPanel');
    if (!panel) return;
    const abierto = panel.style.display !== 'none';
    if (abierto) {
      panel.style.display = 'none';
    } else {
      panel.style.display = 'block';
      _liqCargarVetadas();
    }
  }

  async function _liqEditarDia(idPersonal, fecha) {
    _liqSfx('tap');
    _evalState.fecha = fecha;

    // 1. Construir resumen sintético desde _liqState.pendientes (instantáneo)
    const p = _liqState.pendientes.find(x => x.idPersonal === idPersonal);
    const dia = p ? p.dias.find(d => d.fecha === fecha) : null;
    if (p && dia) {
      const tarifa = parseFloat(dia.tarifaEnvasado) || 0.10;
      const envasados = tarifa > 0 ? Math.round(dia.pagoEnvasado / tarifa) : 0;
      const synth = {
        idPersonal: p.idPersonal,
        nombre:     p.nombre,
        rol:        p.rol,
        appOrigen:  p.appOrigen,
        fecha:      fecha,
        presente:   true,
        auditado:   !!dia.auditado,
        evaluacionesCount: dia.evaluacionesCount || 0,
        montoBase:    dia.montoBase || 0,
        pagoEnvasado: dia.pagoEnvasado || 0,
        bonoMeta:     dia.bonoMeta || 0,
        sancion:      dia.sancion || 0,
        totalDia:     dia.totalDia || 0,
        scoreFinal:   dia.scoreFinal || 0,
        tarifaEnvasado: tarifa,
        unidadesEnvasadas: envasados,
        kpis: {
          auditoriasHechas: 0,
          metaAuditorias: 30,
          envasados: envasados,
          ventasReales: 0,
          metaVenta: 0,
          auditPct: 0
        },
        manual: { limpiezaPct: 0, limpiezaProfPct: 0, checksAcum: {} },
        sancionesDetalle: [],
        aplicaComision: true,
        aplicaBonoMeta: true,
        bonusScore: 0
      };
      // Reemplazar resumenes con el sintético + cualquier otro previo
      const otros = (_evalState.resumenes || []).filter(r => r.idPersonal !== idPersonal);
      _evalState.resumenes = [...otros, synth];
    }

    // 2. Abrir modal Auditar AL INSTANTE (sin esperar fetch)
    abrirAuditar(idPersonal);

    // 3. Fetch real en background → reemplazar datos sintéticos
    try {
      const res = await API.get('getResumenTodosDia', { fecha });
      if (Array.isArray(res)) {
        _evalState.resumenes = res;
        const r = res.find(x => x.idPersonal === idPersonal);
        if (r) {
          _evalState.auditR = r;
          // Re-pintar las secciones internas del modal Auditar
          try { if (typeof _renderAuditKpis === 'function') _renderAuditKpis(r); } catch(_){}
          try { if (typeof _renderAuditChecklist === 'function') _renderAuditChecklist(r.rol); } catch(_){}
          try { if (typeof _renderAuditLiquidacion === 'function') _renderAuditLiquidacion(); } catch(_){}
          // [v2.41.32] SYNC: recomputar la fila en LIQUIDACIONES_DIA y reflejar
          // en _liqState.pendientes para que el lápiz, pendientes y resumen
          // de personal del día muestren EL MISMO monto siempre.
          try {
            await API.post('recomputarLiquidacionDia', {
              idPersonal, fecha,
              localId: 'L' + Date.now() + Math.random().toString(36).slice(2, 8)
            });
            // Actualizar la fila local con los valores correctos del resumen vivo
            const pLocal = (_liqState.pendientes || []).find(x => x.idPersonal === idPersonal);
            if (pLocal) {
              const diaLocal = pLocal.dias.find(d => d.fecha === fecha);
              if (diaLocal) {
                diaLocal.montoBase    = parseFloat(r.montoBase)    || 0;
                diaLocal.pagoEnvasado = parseFloat(r.pagoEnvasado) || 0;
                diaLocal.bonoMeta     = parseFloat(r.bonoMeta)     || 0;
                diaLocal.sancion      = parseFloat(r.sancion)      || 0;
                diaLocal.totalDia     = parseFloat(r.totalDia)     || 0;
                diaLocal.auditado     = !!r.auditado;
                diaLocal.evaluacionesCount = parseInt(r.evaluacionesCount) || 0;
                diaLocal.tarifaEnvasado    = parseFloat(r.tarifaEnvasado)  || 0;
                // Recalcular total persona
                pLocal.total = Math.round(pLocal.dias.reduce((s, d) => s + d.totalDia, 0) * 100) / 100;
                _liqRenderPendientes();
              }
            }
            // [B14] Notificar a Finanzas si está abierto + invalidar su cache
            try { localStorage.removeItem('mos_fin_resum_' + fecha); } catch(_){}
            if (S.view === 'finanzas' && typeof finCargar === 'function') {
              try { finCargar({ animate: false, _silent: true }); } catch(_){}
            }
          } catch(eRec) {
            // [B13] Toast claro si recompute falla (antes era silencioso)
            toast('⚠ No se pudo recomputar el día: ' + ((eRec && eRec.message) || 'error'), 'warn', 5000);
          }
        }
      }
    } catch(_){}
  }

  // [v2.41.32] Recalcular liquidaciones de los últimos N días (backfill).
  // Útil cuando hay desincronización vieja entre la hoja LIQUIDACIONES_DIA
  // y los cálculos en vivo (ej: por un fix de lógica posterior a la creación).
  async function liqRecalcularRango() {
    if (!await _modalConfirm('¿Recalcular liquidaciones de los últimos 30 días?\n\nPuede tardar 20-60 segundos.', { titulo: 'Recalcular 30 días', okText: 'Recalcular' })) return;
    toast('🔄 Recalculando 30 días... esto demora', 'info', 30000);
    try {
      const res = await API.post('backfillLiquidacionesDia', {
        dias: 30,
        localId: 'L' + Date.now() + Math.random().toString(36).slice(2, 8)
      });
      if (res?.ok) {
        toast(`✓ Recalculadas — refrescando lista...`, 'ok', 3000);
        setTimeout(() => liqRefresh && liqRefresh(), 800);
      } else {
        toast('Error recalculando: ' + (res?.error || 'sin respuesta'), 'warn');
      }
    } catch(e) {
      toast('Sin conexión o timeout', 'warn');
    }
  }

  // ── Confirmar pago (modal) ──
  function liqAbrirConfirmacion() {
    // Validar selección
    const items = [];
    let total = 0;
    Object.keys(_liqState.seleccion).forEach(idP => {
      const sel = _liqState.seleccion[idP];
      if (!sel || !sel.size) return;
      const p = _liqState.pendientes.find(x => x.idPersonal === idP);
      if (!p) return;
      const dias = p.dias.filter(d => sel.has(d.fecha));
      const subtotal = dias.reduce((s,d) => s + d.totalDia, 0);
      items.push({ idPersonal: idP, nombre: p.nombre, rol: p.rol, dias, subtotal });
      total += subtotal;
    });
    if (!items.length) { toast('Selecciona al menos un día', 'error'); _liqSfx('error'); return; }
    // Render desglose
    $('liqConfirmSubtitle').textContent = `${items.length} persona(s) · 1 batch por persona`;
    $('liqConfirmTotal').textContent = _liqMoney(total);
    $('liqConfirmDetalle').innerHTML = items.map(it => `
      <div class="rounded-lg p-2" style="background:rgba(15,23,42,.5);border:1px solid #1e293b">
        <div class="flex items-center justify-between mb-1">
          <div class="text-sm font-semibold text-slate-200">${_liqRolIco(it.rol)} ${it.nombre}</div>
          <div class="text-sm font-bold text-amber-400">${_liqMoney(it.subtotal)}</div>
        </div>
        <div class="text-[10px] text-slate-500">
          ${it.dias.map(d => `${_liqFmtFechaLarga(d.fecha)} ${_liqMoney(d.totalDia)}`).join(' · ')}
        </div>
      </div>
    `).join('');
    $('liqConfirmComentario').value = '';
    openModal('modalLiqConfirmar');
    _liqSfx('open');
  }

  // [v2.41.72-B11] Lock anti-doble-click: si ya se está procesando un pago,
  // no permitir disparar otro.
  let _liqPayLock = false;
  async function liqConfirmarPago(ev) {
    if (_liqPayLock) { try { toast('⏳ Ya se está procesando el pago…', 'info', 2000); } catch(_){} return; }
    _liqPayLock = true;
    if (ev) _liqRipple(ev);
    const btn = $('liqConfirmBtn');
    if (btn) { btn.disabled = true; btn.textContent = '⏳ Procesando...'; }
    const imprimir = $('liqConfirmImprimir').checked;
    const comentario = $('liqConfirmComentario').value || '';
    const pagadoPor = (S.session && S.session.nombre) || 'admin';

    // Acumular pagos por persona (1 batch por persona)
    const personas = Object.keys(_liqState.seleccion)
      .map(idP => {
        const sel = _liqState.seleccion[idP];
        if (!sel || !sel.size) return null;
        const p = _liqState.pendientes.find(x => x.idPersonal === idP);
        if (!p) return null;
        const fechas = p.dias.filter(d => sel.has(d.fecha)).map(d => d.fecha);
        return {
          idPersonal: idP,
          nombre: p.nombre,
          rol: p.rol,
          appOrigen: p.appOrigen,
          fechas
        };
      })
      .filter(Boolean);

    if (!personas.length) { toast('Selección vacía', 'error'); if (btn) { btn.disabled = false; btn.textContent = '💸 Confirmar y pagar'; } return; }

    // Si va a imprimir → primero PREVIEW del ticket, luego pedir impresora
    let printerId = null;
    let _ticketEscpos = null;   // [v2.43.377] se captura ANTES del removal optimista (montos intactos)
    if (imprimir) {
      closeModal('modalLiqConfirmar');
      // [v2.41.74] Preview ASCII antes de elegir impresora
      const seguir = await _liqAbrirPreviewTicket(personas, comentario, pagadoPor);
      if (!seguir) {
        // User canceló desde preview → no liberar lock todavía: igual proceder con pago sin imprimir
        toast('Pago se registrará sin imprimir', 'info', 3000);
      } else {
        printerId = await _liqElegirImpresora();
        if (!printerId) {
          toast('Pago se registró sin imprimir', 'info');
        } else {
          // El ascii del print = el MISMO del preview (pendientes aún intactos aquí).
          try {
            const ascii = _liqGenerarTicketAscii(personas, comentario, pagadoPor);
            _ticketEscpos = '\x1b\x40\x1b\x74\x10' + ascii + '\n\n\n\n\x1d\x56\x00';
          } catch (_) {}
        }
      }
    }

    // [v2.41.71] OPTIMISTA INMEDIATO — antes del loop:
    //   1. Quitar días pagados del state local + repaint
    //   2. Cerrar modal
    //   3. Sonido + confetti
    //   4. POSTs en PARALELO (Promise.allSettled) no en serie → 3x más rápido
    //   5. Toast final con resumen
    const personasSnap = JSON.parse(JSON.stringify(personas)); // por si revert
    personas.forEach(persona => {
      const pLocal = _liqState.pendientes.find(x => x.idPersonal === persona.idPersonal);
      if (!pLocal) return;
      const setFechas = new Set(persona.fechas);
      pLocal.dias = pLocal.dias.filter(d => !setFechas.has(d.fecha));
      pLocal.cantidadDias = pLocal.dias.length;
      pLocal.total = Math.round(pLocal.dias.reduce((s, d) => s + d.totalDia, 0) * 100) / 100;
    });
    _liqState.pendientes = _liqState.pendientes.filter(p => p.cantidadDias > 0);
    _liqState.seleccion = {};
    _liqRenderPendientes();
    closeModal('modalLiqConfirmar');
    // [v2.41.74] Sonido cash distintivo (sustituye success genérico) + animación ticket si se imprimió
    _liqSfx('cash');
    try {
      const r = btn?.getBoundingClientRect();
      const cx = r ? r.left + r.width/2 : window.innerWidth/2;
      const cy = r ? r.top  + r.height/2 : window.innerHeight/2;
      _liqConfetti(cx, cy, '#fbbf24');
      if (printerId) _liqTicketFly(cx, cy, Math.min(personas.length, 3));
    } catch(_){}
    toast(`💸 Procesando ${personas.length} pago(s)…`, 'info', 3000);

    // POSTs PARALELOS — Promise.allSettled para no abortar si uno falla
    const results = await Promise.allSettled(personas.map(persona =>
      API.post('marcarPagos', {
        idPersonal: persona.idPersonal,
        fechas: persona.fechas,
        nombre: persona.nombre,
        rol: persona.rol,
        appOrigen: persona.appOrigen,
        pagadoPor,
        comentario,
        // [v2.43.377] El front imprime por la Edge `imprimir` (cero-GAS, preview==print).
        // marcarPagos ya NO imprime (evita ticket GAS distinto + fallos silenciosos).
        imprimir: false,
        printerId: ''
      }).then(res => ({ ok: true, persona, res }))
        .catch(e => ({ ok: false, persona, error: e.message || String(e) }))
    ));

    const okList  = results.filter(r => r.status === 'fulfilled' && r.value.ok).map(r => r.value);
    const errList = results.filter(r => r.status === 'fulfilled' && !r.value.ok).map(r => r.value);
    const totalPagado = okList.reduce((s, r) => s + (parseFloat(r.res.total) || 0), 0);

    if (okList.length) {
      toast(`✓ ${okList.length} pago(s) registrado(s) · ${_liqMoney(totalPagado)}`, 'ok', 5000);
      // [v2.43.377] Imprimir el comprobante por la Edge `imprimir` (cero-GAS). El contenido
      // es EXACTAMENTE el del preview (capturado antes del removal) → lo que ves es lo que sale.
      if (printerId && _ticketEscpos) {
        try {
          await API.imprimirTicketEdge(parseInt(printerId, 10), 'Comprobante de pago', _ticketEscpos);
          toast('🖨 Comprobante enviado a la impresora', 'ok', 3000);
        } catch (ePr) {
          toast('⚠ Pago OK, pero no se pudo imprimir: ' + ((ePr && ePr.message) || ePr), 'warn', 6000);
        }
      }
    }
    if (errList.length) {
      // Restaurar al state los que fallaron
      errList.forEach(({ persona, error }) => {
        toast(`Error con ${persona.nombre}: ${error}`, 'error', 6000);
        const snap = personasSnap.find(p => p.idPersonal === persona.idPersonal);
        if (snap) {
          let pLocal = _liqState.pendientes.find(x => x.idPersonal === snap.idPersonal);
          if (!pLocal) {
            pLocal = { idPersonal: snap.idPersonal, nombre: snap.nombre, rol: snap.rol,
                       appOrigen: snap.appOrigen, dias: [], total: 0, cantidadDias: 0 };
            _liqState.pendientes.push(pLocal);
          }
          snap.fechas.forEach(f => {
            if (!pLocal.dias.find(d => d.fecha === f)) {
              pLocal.dias.push({ fecha: f, totalDia: 0, montoBase: 0, pagoEnvasado: 0 });
            }
          });
          pLocal.cantidadDias = pLocal.dias.length;
        }
      });
      _liqRenderPendientes();
    }

    // Invalidar cache + fetch fresco en bg
    _liqCacheClear();
    liqLoadCurrent();

    if (btn) { btn.disabled = false; btn.textContent = '💸 Confirmar y pagar'; }
    _liqPayLock = false;
  }

  // [v2.41.74] Preview ASCII del ticket — abre modal con texto monoespaciado
  // que aproxima cómo se imprimirá. Devuelve Promise<boolean>.
  let _liqPreviewResolve = null;
  function _liqAbrirPreviewTicket(personas, comentario, pagadoPor) {
    return new Promise(resolve => {
      _liqPreviewResolve = resolve;
      const pre = document.getElementById('liqPreviewTicketContent');
      const sub = document.getElementById('liqPreviewSubtitle');
      if (pre) pre.textContent = _liqGenerarTicketAscii(personas, comentario, pagadoPor);
      if (sub) {
        const n = personas.length;
        const td = personas.reduce((s, p) => s + (p.fechas?.length || 0), 0);
        sub.textContent = `${n} ticket(s) · ${td} día(s)`;
      }
      openModal('modalLiqPreviewTicket');
      _liqSfx('open');
    });
  }
  function _liqCerrarPreview(seguir) {
    closeModal('modalLiqPreviewTicket');
    _liqSfx(seguir ? 'tap' : 'tap');
    if (_liqPreviewResolve) {
      const r = _liqPreviewResolve;
      _liqPreviewResolve = null;
      r(!!seguir);
    }
  }
  // [v2.43.380] Comprobante de pago 80mm (W=48) con DESGLOSE REAL por día:
  // base · comisión por ventas · envasado · +bono · −descuento → total. Lo que ves en el
  // preview es EXACTO lo que se imprime (la Edge `imprimir` recibe este mismo texto).
  function _liqGenerarTicketAscii(personas, comentario, pagadoPor) {
    const W = 48; // 80mm
    const linea = (c) => (c || '-').repeat(W);
    const centrar = (s) => { s = String(s || ''); if (s.length >= W) return s.slice(0, W); return ' '.repeat(Math.floor((W - s.length) / 2)) + s; };
    const dosCol = (izq, der) => {
      izq = String(izq || ''); der = String(der || '');
      const max = W - der.length - 1;
      if (izq.length > max) izq = izq.slice(0, max);
      return izq + ' '.repeat(Math.max(1, W - izq.length - der.length)) + der;
    };
    const fmtMon = (n) => 'S/' + (Math.round((n || 0) * 100) / 100).toFixed(2);
    const num = (n) => (Math.round((parseFloat(n) || 0) * 100) / 100).toFixed(2);
    const fmtFecha = (f) => { try { const d = new Date(f + 'T12:00:00'); return d.toLocaleDateString('es-PE', { weekday:'short', day:'2-digit', month:'2-digit' }); } catch { return f; } };
    let out = '';
    personas.forEach((per, idx) => {
      if (idx > 0) out += '\n' + linea('=') + '\n\n';
      out += centrar('INVERSIONES MOS') + '\n';
      out += centrar('Comprobante de pago') + '\n';
      out += linea('=') + '\n';
      out += dosCol('Persona:', per.nombre || '') + '\n';
      out += dosCol('Rol:', per.rol || '') + '\n';
      out += dosCol('Pagado por:', pagadoPor || '-') + '\n';
      out += dosCol('Emitido:', new Date().toLocaleString('es-PE', { day:'2-digit', month:'2-digit', year:'2-digit', hour:'2-digit', minute:'2-digit' })) + '\n';
      out += linea('-') + '\n';
      out += 'DETALLE POR DIA:\n';
      // cada concepto en SU línea (solo si existe); comentario debajo, multilínea.
      const num0 = (n) => { n = parseFloat(n) || 0; return Number.isInteger(n) ? ('' + n) : num(n); };
      const compLine = (label, monto, signo) => dosCol('  ' + label, (signo || '') + 'S/' + num(monto)) + '\n';
      const motivoLines = (motivo) => {
        const t = String(motivo || '').trim(); if (!t) return '';
        const palabras = t.split(/\s+/); let buf = '', out2 = '';
        palabras.forEach(w => { if (buf && (buf + ' ' + w).length > (W - 4)) { out2 += '    ' + buf + '\n'; buf = w; } else buf += (buf ? ' ' : '') + w; });
        if (buf) out2 += '    ' + buf + '\n';
        return out2;
      };
      const pState = _liqState.pendientes.find(x => x.idPersonal === per.idPersonal);
      let subtotal = 0;
      (per.fechas || []).forEach(f => {
        const d = pState ? pState.dias.find(x => x.fecha === f) : null;
        const m = d ? (parseFloat(d.totalDia) || 0) : 0;
        subtotal += m;
        out += '\n' + dosCol(fmtFecha(f), fmtMon(m)) + '\n';
        if (d) {
          const base = parseFloat(d.montoBase) || 0, env = parseFloat(d.pagoEnvasado) || 0, com = parseFloat(d.bonoMeta) || 0;
          const bon = parseFloat(d.bonificacion) || 0, san = parseFloat(d.sancion) || 0, uds = parseFloat(d.productosEnvasados) || 0;
          if (base > 0) out += compLine('Base diaria', base);
          if (env > 0)  out += compLine('Pago envasado' + (uds > 0 ? ' (' + num0(uds) + ' uds)' : ''), env);
          if (com > 0)  out += compLine('Comision por ventas', com);
          if (bon > 0)  { out += compLine('Bonificacion', bon, '+'); out += motivoLines(d.bonificacionMotivo); }
          if (san > 0)  { out += compLine('Descuento', san, '-');     out += motivoLines(d.sancionMotivo); }
        }
      });
      out += linea('-') + '\n';
      out += dosCol('TOTAL A PAGAR', fmtMon(subtotal)) + '\n';
      if (comentario) {
        out += linea('-') + '\n' + 'Comentario:\n';
        const words = String(comentario).split(/\s+/); let buf = '  ';
        words.forEach(w => { if ((buf + ' ' + w).length > W) { out += buf + '\n'; buf = '  ' + w; } else buf += (buf.trim() ? ' ' : '') + w; });
        if (buf.trim()) out += buf + '\n';
      }
      out += linea('=') + '\n';
      out += centrar('Gracias') + '\n';
    });
    return out;
  }

  // [v2.41.74] Animación "ticket impreso" — papel sale flotando del centro
  function _liqTicketFly(originX, originY, count) {
    count = count || 1;
    for (let i = 0; i < count; i++) {
      const el = document.createElement('div');
      el.className = 'liq-ticket-fly';
      const x = (originX != null ? originX : window.innerWidth / 2) - 45 + (i * 12 - count * 6);
      const y = (originY != null ? originY : window.innerHeight / 2) - 65;
      el.style.left = x + 'px';
      el.style.top  = y + 'px';
      el.style.animationDelay = (i * 0.12) + 's';
      document.body.appendChild(el);
      setTimeout(() => { try { el.remove(); } catch(_){} }, 1700 + i * 120);
    }
  }

  // ── Elegir impresora — reusa el modal modalSelPrinterLiq del audit ──
  function _liqElegirImpresora() {
    return abrirPrinterPicker({
      titulo: '🖨 Imprimir liquidación',
      subtitulo: `Pago de liquidación · ${(_liqState.tab === 'pendientes' ? 'pendientes' : 'reimpresión')}`,
      filtroTipo: 'TICKET'
    });
  }

  // [v2.41.82] PrinterPicker UNIVERSAL — selector de impresora reusable
  // por todos los flujos (liquidación, costos guía, etiquetas, batches).
  // Devuelve una Promise<printerId | null>. Verifica el estado fresh
  // antes de resolver (verificarImpresoraAhora) para evitar enviar jobs
  // a impresoras que cambiaron de estado entre listar y elegir.
  //
  // opts:
  //   titulo:    string  ('🖨 Imprimir X')
  //   subtitulo: string  (contexto del job: 'Guía G-0042 · S/450')
  //   filtroTipo: 'TICKET' | 'ADHESIVO' | 'ZPL' | undefined (todos)
  //   filtroZona: idZona  (si undefined, usa zona del admin si está set)
  //   verify:    bool (true por default — verifica antes de resolver)
var _pPickState = { filtroZona: null, filtroTipo: null, mostrarTodas: false };
  async function abrirPrinterPicker(opts) {
    opts = opts || {};
    // [v2.43.3] Memoria de última impresora por tipo de flow.
    // Si opts.flowKey está dado y hay impresora cacheada online → usar directo.
    // Si opts.flowKey === '__skipCache' → ignorar memoria (admin quiere elegir).
    const _LSKEY = opts.flowKey ? 'mos_lastPrinter_' + opts.flowKey : null;
    // [Reparación picker] MOS es el panel admin y puede estar REMOTO (lejos de la impresora, ej. en casa) →
    // SIEMPRE mostrar el picker para que el admin elija. Solo se reusa la última impresora si un flow lo pide
    // explícitamente con opts.autoUsarUltima (hoy ninguno lo hace → todos los flujos muestran el picker).
    if (_LSKEY && opts.autoUsarUltima === true && opts.flowKey !== '__skipCache') {
      try {
        const cachedId = localStorage.getItem(_LSKEY);
        if (cachedId) {
          // [2026-06-18 fix] BLOQUEANTE: verificar que la impresora cacheada siga ONLINE
          // ANTES de reusarla. Antes esto era fire-and-forget (en bg) y además leía el
          // campo equivocado (r.data.estado, que no existe → la condición nunca cumplía),
          // así que una impresora cacheada rota/desactivada (ej. el duplicado "POS-80C (copy 1)"
          // de ZONA-02) recibía el job igual y quedaba en error. Ahora: si no está ONLINE
          // (offline, error, ID_INVALIDO porque se desactivó del catálogo, etc.) limpiamos
          // la caché y caemos al picker — que solo muestra impresoras activas.
          // API.get desempaqueta d.data → r ES el estado {state,online,reason,...} de la Edge `printers`.
          let okOnline = false, razon = '';
          try {
            const r = await API.get('verificarImpresoraAhora', { printerId: cachedId });
            const d = r || {};
            okOnline = (d.online === true) || (String(d.state || '').toUpperCase() === 'ONLINE');
            razon = d.reason || '';
          } catch (_) { okOnline = false; razon = 'no se pudo verificar'; }
          if (okOnline) {
            // Toast optimista + retornar (ya verificada ONLINE).
            try { _toast?.('info', '🖨 Usando última impresora · tap para cambiar'); } catch(_){}
            try { _opsBeep?.('tac'); } catch(_){}
            return cachedId;
          }
          // Cacheada NO disponible → olvidarla y forzar elección manual.
          try { localStorage.removeItem(_LSKEY); } catch(_){}
          try { _toast?.('info', '🖨 La última impresora no está lista — elige otra' + (razon ? ' (' + razon + ')' : '')); } catch(_){}
        }
      } catch(_){}
    }
    return new Promise(resolve => {
      // Setear título/subtítulo dinámicos
      const tit = document.getElementById('liqPrintTitle');
      const sub = document.getElementById('liqPrintSubtitle');
      if (tit) tit.textContent = opts.titulo || '🖨 Elegir impresora';
      if (sub) sub.textContent = opts.subtitulo || '—';

      // Setear filtros iniciales
      _pPickState.filtroTipo = opts.filtroTipo || null;
      _pPickState.filtroZona = opts.filtroZona !== undefined
        ? opts.filtroZona
        : ((S.session && S.session.idZona) || null);
      _pPickState.mostrarTodas = !_pPickState.filtroZona;

      // Botón filtro tipo visible solo si NO se está forzando uno específico
      const btnTipo = document.getElementById('ppFiltTipoBtn');
      if (btnTipo) btnTipo.classList.toggle('hidden', !!opts.filtroTipo);

      _pPickActualizarBotones();

      // Hook: el resolve se llama cuando _liqEnviarPrint es invocado o se cierra
      const prevSend = MOS._liqEnviarPrint;
      MOS._liqEnviarPrint = async function(printerId, btnEl, ev) {
        // Verify on-click — fresh state antes de cerrar el modal
        if (opts.verify !== false) {
          if (btnEl) { btnEl.classList.add('sending'); }
          try {
            const r = await API.get('verificarImpresoraAhora', { printerId });
            // [v2.42.04 fix] API.get devuelve d.data — r ya es el estado
            const d = r || {};
            if (d.state && d.state !== 'ONLINE') {
              // Estado cambió entre listar y elegir — bloquear
              try { _evalSfx && _evalSfx('error'); } catch(_){}
              if (btnEl) btnEl.classList.remove('sending');
              toast(`🖨 ${d.reason || 'No disponible'} · refrescando…`, 'error', 5000);
              if (typeof _liqLoadPrinters === 'function') _liqLoadPrinters(true);
              return;
            }
          } catch(eV) {
            console.warn('[PrinterPicker] verify falló — siguiendo con la elección:', eV);
          }
        }
        MOS._liqEnviarPrint = prevSend;
        closeModal('modalSelPrinterLiq');
        // [v2.43.3] Guardar elección para recordar próxima vez si flowKey existe
        if (_LSKEY) {
          try { localStorage.setItem(_LSKEY, String(printerId)); } catch(_){}
        }
        resolve(parseInt(printerId, 10));
      };
      // Listener cancelación
      const backdrop = document.getElementById('modalSelPrinterLiq');
      const closeBtns = backdrop ? backdrop.querySelectorAll('button[onclick*="closeModal"]') : [];
      closeBtns.forEach(b => b.addEventListener('click', function once() {
        MOS._liqEnviarPrint = prevSend;
        resolve(null);
        b.removeEventListener('click', once);
      }, { once: true }));
      openModal('modalSelPrinterLiq');
      if (typeof _liqLoadPrinters === 'function') _liqLoadPrinters(false);
    });
  }

  // Toggle filtro zona (mi zona ↔ todas)
  function _pPickToggleFiltroZona() {
    _pPickState.mostrarTodas = !_pPickState.mostrarTodas;
    _pPickActualizarBotones();
    if (typeof _liqLoadPrinters === 'function') _liqLoadPrinters(false);
  }
  function _pPickToggleFiltroTipo() {
    // Cycle: null → TICKET → ADHESIVO → ZPL → null
    const tipos = [null, 'TICKET', 'ADHESIVO', 'ZPL'];
    const idx = tipos.indexOf(_pPickState.filtroTipo);
    _pPickState.filtroTipo = tipos[(idx + 1) % tipos.length];
    _pPickActualizarBotones();
    if (typeof _liqLoadPrinters === 'function') _liqLoadPrinters(false);
  }
  function _pPickActualizarBotones() {
    const btnZ = document.getElementById('ppFiltZonaBtn');
    const btnT = document.getElementById('ppFiltTipoBtn');
    if (btnZ) {
      btnZ.textContent = _pPickState.mostrarTodas ? '🌐 todas las zonas' : '📍 mi zona';
      btnZ.style.background = _pPickState.mostrarTodas ? 'rgba(168,85,247,.18)' : 'rgba(99,102,241,.18)';
      btnZ.style.borderColor = _pPickState.mostrarTodas ? 'rgba(168,85,247,.4)' : 'rgba(99,102,241,.4)';
      btnZ.style.color = _pPickState.mostrarTodas ? '#d8b4fe' : '#c4b5fd';
    }
    if (btnT) {
      btnT.textContent = _pPickState.filtroTipo
        ? (_pPickState.filtroTipo === 'TICKET' ? '🧾 tickets'
         : _pPickState.filtroTipo === 'ADHESIVO' ? '🏷 adhesivos'
         : '📄 ZPL')
        : '🧾 todos los tipos';
    }
  }
  // Filtra una lista de impresoras según _pPickState. La consume _liqRenderPrinters.
  function _pPickAplicarFiltros(lista) {
    if (!Array.isArray(lista)) return [];
    return lista.filter(p => {
      if (_pPickState.filtroTipo && String(p.tipo || '').toUpperCase() !== _pPickState.filtroTipo) return false;
      if (!_pPickState.mostrarTodas && _pPickState.filtroZona && p.idZona !== _pPickState.filtroZona) return false;
      return true;
    });
  }

  // ── Render PAGADAS ──
  function _liqRenderPagadas() {
    const body = $('liqBody');
    if (!body) return;
    const list = _liqState.pagadas || [];
    if (!list.length) {
      body.innerHTML = `<div class="liq-empty">
        <div class="liq-empty-emoji">💰</div>
        <div class="text-sm">Sin pagos en este rango</div>
      </div>`;
      return;
    }
    const total = list.reduce((s, b) => s + b.total, 0);
    body.innerHTML = `
      <div class="flex items-center justify-between mb-3 pb-2 border-b border-slate-800">
        <div class="text-xs text-slate-400"><strong class="text-emerald-400">${list.length}</strong> pago(s) registrados</div>
        <div class="text-right">
          <div class="text-[10px] uppercase text-slate-500 tracking-wider">Total pagado</div>
          <div class="text-lg font-bold" style="color:#34d399">${_liqMoney(total)}</div>
        </div>
      </div>
      ${list.map((b, i) => _liqCardBatch(b, i)).join('')}
    `;
  }
  function _liqCardBatch(b, idx) {
    const fecha = b.pagadoTs ? new Date(b.pagadoTs).toLocaleString('es-PE', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit' }) : '—';
    const ico = _liqRolIco(b.rol);
    // [v2.41.74] Sello visual según estado
    const anulada = !!b.anulada;
    const stamp = anulada
      ? '<span class="liq-stamp anulado">Anulado</span>'
      : '<span class="liq-stamp pagado">Pagado</span>';
    const cardCls = anulada ? 'liq-batch-card anulada' : 'liq-batch-card';
    return `
      <div class="${cardCls}" style="--i:${Math.min(idx,15)}" onclick="MOS._liqAbrirPagoDet('${b.idPago}', ${idx})">
        ${stamp}
        <div class="flex items-center gap-3">
          <span style="font-size:18px">${ico}</span>
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-2 flex-wrap">
              <span class="text-sm font-semibold text-slate-200">${b.nombre}</span>
              <span class="text-[10px] font-mono text-slate-500">${b.idPago}</span>
            </div>
            <div class="text-[10px] text-slate-500 mt-0.5">
              ${b.cantidadDias} día(s) · ${fecha} · pagó <strong>${b.pagadoPor}</strong>
            </div>
          </div>
          <div class="text-right">
            <div class="text-base font-bold" style="color:#34d399">${_liqMoney(b.total)}</div>
          </div>
        </div>
      </div>`;
  }

  // [v2.41.55] OPTIMISTA: abrir modal al instante con datos del listado local,
  // pintar skeleton para días, y completar al llegar el fetch. Antes el await
  // bloqueaba el openModal → percibido como lentitud.
  async function _liqAbrirPagoDet(idPago, idx) {
    _liqSfx('open');
    // 1) Datos optimistas desde el listado local de pagadas
    const local = (typeof idx === 'number' ? (_liqState.pagadas || [])[idx] : null)
              || (_liqState.pagadas || []).find(p => p.idPago === idPago);
    const cantDias = local ? local.cantidadDias : 0;
    const titleEl = $('liqPagoDetTitle');
    const subEl   = $('liqPagoDetSubtitle');
    const bodyEl  = $('liqPagoDetBody');
    if (titleEl) titleEl.textContent = local
      ? `${_liqRolIco(local.rol)} ${local.nombre} · ${local.idPago}`
      : `Cargando · ${idPago}`;
    if (subEl) subEl.textContent = local
      ? `${cantDias} día(s) · pagó ${local.pagadoPor} · ${new Date(local.pagadoTs).toLocaleString('es-PE')}`
      : 'Cargando detalle…';
    if (bodyEl) {
      const skeleton = Array.from({ length: Math.max(cantDias, 3) }, () =>
        `<div class="rounded-lg p-2" style="background:rgba(15,23,42,.4);border:1px solid #1e293b">
          <div class="flex items-center justify-between">
            <div class="alm-skel-line w-50" style="height:14px"></div>
            <div class="alm-skel-line w-30" style="height:14px"></div>
          </div>
          <div class="alm-skel-line w-75 mt-2" style="height:10px"></div>
        </div>`
      ).join('');
      bodyEl.innerHTML = skeleton + (local ? `
        <div class="mt-2 pt-2 border-t border-slate-800 flex items-center justify-between">
          <span class="text-sm font-bold text-slate-300">TOTAL</span>
          <span class="text-lg font-bold" style="color:#fbbf24">${_liqMoney(local.total)}</span>
        </div>` : '');
    }
    openModal('modalLiqPagoDet');

    // 2) Fetch real en background y reemplaza el body
    try {
      const res = await API.get('getPagoDetalle', { idPago });
      const d = res && res.data ? res.data : res;
      if (!d) return;
      _liqState.currentPagoDet = d;
      if (titleEl) titleEl.textContent = `${_liqRolIco(d.rol)} ${d.nombre} · ${d.idPago}`;
      if (subEl)   subEl.textContent = `${d.cantidadDias} día(s) · pagó ${d.pagadoPor} · ${new Date(d.pagadoTs).toLocaleString('es-PE')}`;
      if (bodyEl) {
        bodyEl.innerHTML = d.dias.map(dia => {
          const partes = [];
          if (dia.montoBase    > 0) partes.push(`base ${dia.montoBase.toFixed(2)}`);
          if (dia.pagoEnvasado > 0) partes.push(`env ${dia.pagoEnvasado.toFixed(2)}`);
          if (dia.bonoMeta     > 0) partes.push(`+meta ${dia.bonoMeta.toFixed(2)}`);
          if (dia.bonificacion > 0) partes.push(`+bono ${dia.bonificacion.toFixed(2)}`);
          if (dia.sancion      > 0) partes.push(`−san ${dia.sancion.toFixed(2)}`);
          return `<div class="rounded-lg p-2" style="background:rgba(15,23,42,.4);border:1px solid #1e293b">
            <div class="flex items-center justify-between">
              <span class="text-sm text-slate-200">${_liqFmtFechaLarga(dia.fecha)}</span>
              <span class="text-sm font-bold text-amber-400">${_liqMoney(dia.totalDia)}</span>
            </div>
            ${partes.length ? `<div class="text-[10px] text-slate-500 mt-0.5">${partes.join(' · ')}</div>` : ''}
          </div>`;
        }).join('') + `<div class="mt-2 pt-2 border-t border-slate-800 flex items-center justify-between">
          <span class="text-sm font-bold text-slate-300">TOTAL</span>
          <span class="text-lg font-bold" style="color:#fbbf24">${_liqMoney(d.total)}</span>
        </div>`;
      }
    } catch(e) {
      if (bodyEl) bodyEl.innerHTML = `<div class="text-rose-400 text-sm py-4">Error cargando detalle: ${e.message}</div>`;
    }
  }

  // [v2.41.73-B10] Lock anti-doble-click en reimpresión
  let _liqReimpLock = false;
  async function liqReimprimirPago() {
    if (_liqReimpLock) { try { toast('⏳ Ya se está reimprimiendo…', 'info', 2000); } catch(_){} return; }
    _liqReimpLock = true;
    const d = _liqState.currentPagoDet;
    if (!d) { _liqReimpLock = false; return; }
    closeModal('modalLiqPagoDet');
    const printerId = await _liqElegirImpresora();
    if (!printerId) { _liqReimpLock = false; return; }
    try {
      const res = await API.post('imprimirTicketPago', { idPago: d.idPago, printerId });
      _liqSfx('success');
      toast('✓ Reimpresión enviada · job ' + (res.printJobId || ''), 'ok');
    } catch(e) {
      _liqSfx('error');
      toast('Error: ' + e.message, 'error');
    } finally {
      _liqReimpLock = false;
    }
  }

  // [v2.41.83] Migrado a AdminAuthModal universal — antes usaba un modal
  // custom modalLiqAnular con keypad propio. Ahora un solo modal unificado.
  // Reusa _liqEjecutarAnular pero ya con la clave validada.
  async function liqAnularPago() {
    const d = _liqState.currentPagoDet;
    if (!d) return;
    _liqSfx('open');
    const auth = await pedirAuth({
      accion: 'ANULAR_PAGO',
      refDocumento: d.idPago,
      contexto: `Anular pago ${d.idPago} · ${d.nombre} · ${_liqMoney(d.total)}`
    });
    if (!auth) return;
    await _liqEjecutarAnular(d.idPago, auth.clave);
  }

  function _liqAbrirModalAnular(d) {
    let modal = document.getElementById('modalLiqAnular');
    if (!modal) {
      modal = document.createElement('div');
      modal.id = 'modalLiqAnular';
      modal.className = 'modal-overlay';
      // [v2.41.70] Estilos inline garantizan que el modal aparezca POR ENCIMA
      // del nav inferior (z-30) y de cualquier otro overlay. Sin esto, modal
      // quedaba en z-0 y el nav lo tapaba.
      // [v2.41.73-B9] z-index DINÁMICO: lee el z-index efectivo del modal
      // padre visible y suma 100. Antes era 9500 fijo → si ya había un
      // overlay z=9600 (ej. impresora), el modal anular quedaba detrás.
      let zParent = 9400;
      try {
        const visibles = Array.from(document.querySelectorAll('.modal-backdrop, [class*="modal-overlay"]'))
          .filter(el => el !== modal && (el.classList.contains('open') || (el.style.display && el.style.display !== 'none')));
        visibles.forEach(el => {
          const z = parseInt(window.getComputedStyle(el).zIndex, 10);
          if (!isNaN(z) && z > zParent) zParent = z;
        });
      } catch(_){}
      const zDinamico = Math.max(9500, zParent + 100);
      modal.style.cssText = 'position:fixed;inset:0;background:rgba(2,6,23,.85);' +
        'z-index:' + zDinamico + ';display:flex;align-items:center;justify-content:center;' +
        'padding:16px;backdrop-filter:blur(4px);';
      modal.onclick = (ev) => { if (ev.target === modal) _liqCerrarModalAnular(); };
      document.body.appendChild(modal);
    }
    // Si ya existía oculto, mostrar
    modal.style.display = 'flex';
    modal.classList.remove('hidden');
    modal.innerHTML = `
      <div class="modal-box" onclick="event.stopPropagation()" style="max-width:380px;padding:0;overflow:hidden;background:#0f172a;border-radius:14px;box-shadow:0 24px 64px rgba(0,0,0,.6);width:100%">
        <div style="background:linear-gradient(135deg,#7f1d1d,#450a0a);padding:18px 20px;text-align:center;color:#fff">
          <div style="font-size:28px;margin-bottom:6px">↺</div>
          <div style="font-size:13px;font-weight:900;text-transform:uppercase;letter-spacing:.04em">Anular pago</div>
          <div style="font-size:11px;opacity:.8;margin-top:4px">${_esc(d.idPago)}</div>
        </div>
        <div style="padding:16px 20px">
          <div style="background:rgba(248,113,113,.08);border:1px solid rgba(248,113,113,.3);border-radius:10px;padding:10px 12px;margin-bottom:14px">
            <div style="font-weight:800;color:#f1f5f9;font-size:13px">${_esc(d.nombre)}</div>
            <div style="font-size:11px;color:#94a3b8;margin-top:2px">${d.cantidadDias} día(s) · <span style="color:#fbbf24;font-weight:800">${_liqMoney(d.total)}</span></div>
            <div style="font-size:10px;color:#fca5a5;margin-top:6px">⚠ Los días volverán a Pendientes y la guía se anulará.</div>
          </div>
          <label style="font-size:11px;color:#94a3b8;font-weight:700;text-transform:uppercase;letter-spacing:.05em;display:block;margin-bottom:6px">
            🔑 Clave admin (8 dígitos)
          </label>
          <input id="liqAnularInput" type="password" inputmode="numeric" pattern="[0-9]*" maxlength="8" autocomplete="off"
                 placeholder="••••••••"
                 style="width:100%;padding:14px;border:2px solid #334155;border-radius:10px;background:#0f172a;color:#f1f5f9;font-size:22px;text-align:center;letter-spacing:.5em;font-family:ui-monospace,monospace;font-weight:900"
                 oninput="this.value=this.value.replace(/[^0-9]/g,'').slice(0,8); if(this.value.length===8) MOS._liqConfirmarAnular();">
          <div id="liqAnularError" style="font-size:11px;color:#fca5a5;margin-top:8px;min-height:14px;text-align:center"></div>
          <div style="display:flex;gap:10px;margin-top:14px">
            <button onclick="MOS._liqCerrarModalAnular()" class="cj-btn cj-btn-secondary" style="flex:1;padding:12px;border-radius:10px;border:none;background:#334155;color:#cbd5e1;font-weight:900;cursor:pointer">Cancelar</button>
            <button id="liqAnularOk" onclick="MOS._liqConfirmarAnular()" class="cj-btn cj-btn-primary" style="flex:1;padding:12px;border-radius:10px;border:none;background:linear-gradient(135deg,#dc2626,#7f1d1d);color:#fff;font-weight:900;cursor:pointer">
              ↺ Anular
            </button>
          </div>
        </div>
      </div>`;
    modal.classList.remove('hidden');
    setTimeout(() => { try { document.getElementById('liqAnularInput')?.focus(); } catch(_){} }, 50);
  }
  function _liqCerrarModalAnular() {
    const m = document.getElementById('modalLiqAnular');
    if (m) { m.style.display = 'none'; m.classList.add('hidden'); }
  }
  async function _liqConfirmarAnular() {
    const d = _liqState.currentPagoDet;
    if (!d) return;
    const inp = document.getElementById('liqAnularInput');
    const err = document.getElementById('liqAnularError');
    if (!inp) return;
    const clave = String(inp.value || '').trim();
    if (!clave || clave.length < 4) {
      if (err) err.textContent = 'Ingresa la clave (mín 4 dígitos)';
      inp.focus();
      return;
    }
    if (err) err.textContent = '';
    const btn = document.getElementById('liqAnularOk');
    if (btn) { btn.disabled = true; btn.textContent = '⏳ Anulando...'; }
    await _liqEjecutarAnular(d.idPago, clave);
  }

  async function _liqEjecutarAnular(idPago, claveAdmin) {
    // [v2.41.58] OPTIMISTA: mover el batch de pagadas → quitar visual al instante.
    // Si falla, revertir.
    const pagSnap = (_liqState.pagadas || []).find(p => p.idPago === idPago);
    const idxSnap = pagSnap ? (_liqState.pagadas || []).indexOf(pagSnap) : -1;
    const fechaAfectada = pagSnap?.pagadoTs ? new Date(pagSnap.pagadoTs).toISOString().slice(0, 10) : null;
    if (pagSnap) {
      _liqState.pagadas = (_liqState.pagadas || []).filter(p => p.idPago !== idPago);
      if (_liqState.tab === 'pagadas') _liqRenderPagadas();
    }
    try {
      const res = await API.post('anularPago', { idPago, claveAdmin });
      if (res && res.autorizado === false) {
        // Revertir
        if (pagSnap && idxSnap >= 0) {
          _liqState.pagadas.splice(idxSnap, 0, pagSnap);
          if (_liqState.tab === 'pagadas') _liqRenderPagadas();
        }
        const err = document.getElementById('liqAnularError');
        if (err) err.textContent = res.error || 'Clave incorrecta';
        const btn = document.getElementById('liqAnularOk');
        if (btn) { btn.disabled = false; btn.textContent = '↺ Anular'; }
        _liqSfx('error');
        return;
      }
      _liqSfx('remove');
      _liqCerrarModalAnular();
      closeModal('modalLiqPagoDet');
      toast(`↺ Pago ${idPago} anulado · ${res.anuladas || 0} día(s) volvieron a Pendientes`, 'ok', 4500);
      // Invalidar cache Liq + Finanzas para forzar fetch fresco
      try { _liqCacheClear(); } catch(_){}
      if (fechaAfectada) {
        try { localStorage.removeItem('mos_fin_resum_' + fechaAfectada); } catch(_){}
      }
      // Refresh ambas listas en bg
      await liqLoadCurrent();
      _liqPrefetchTab('pendientes');
      // Notificar a Finanzas si está abierto → repaint del Personal del Día
      if (S.view === 'finanzas' && typeof finCargar === 'function') {
        try { finCargar({ animate: false }); } catch(_){}
      }
    } catch(e) {
      // Revertir
      if (pagSnap && idxSnap >= 0) {
        _liqState.pagadas.splice(idxSnap, 0, pagSnap);
        if (_liqState.tab === 'pagadas') _liqRenderPagadas();
      }
      const err = document.getElementById('liqAnularError');
      if (err) err.textContent = 'Error: ' + (e.message || e);
      const btn = document.getElementById('liqAnularOk');
      if (btn) { btn.disabled = false; btn.textContent = '↺ Anular'; }
      _liqSfx('error');
    }
  }

  // ── Render RESUMEN ──
  // [v2.41.75] Resumen ahora usa state local primero → INSTANT.
  // Fetch en background solo si el state está vacío o cache localStorage está stale.
  function _liqRenderResumen() {
    const body = $('liqBody');
    if (!body) return;
    // 1) Pintar inmediato desde state local o cache
    function pintar(pendArr, pagArr) {
      const totalPend = pendArr.reduce((s,p) => s + p.total, 0);
      const totalPag  = pagArr.reduce( (s,b) => s + b.total, 0);
      const personasPend = pendArr.length;
      const totalDiasPend = pendArr.reduce((s,p) => s + p.cantidadDias, 0);
      const totalBatches  = pagArr.length;
      body.innerHTML = `
        <div class="grid grid-cols-2 gap-3 mb-4">
          <div class="rounded-xl p-4" style="background:linear-gradient(135deg,rgba(251,191,36,.08),rgba(251,191,36,.02));border:1px solid rgba(251,191,36,.3)">
            <div class="text-[10px] uppercase tracking-wider text-amber-400 font-bold">📋 Pendientes</div>
            <div class="text-2xl font-bold mt-1" style="color:#fbbf24">${_liqMoney(totalPend)}</div>
            <div class="text-xs text-slate-500 mt-1">${personasPend} persona(s) · ${totalDiasPend} día(s)</div>
          </div>
          <div class="rounded-xl p-4" style="background:linear-gradient(135deg,rgba(34,197,94,.08),rgba(34,197,94,.02));border:1px solid rgba(34,197,94,.3)">
            <div class="text-[10px] uppercase tracking-wider text-emerald-400 font-bold">💰 Pagadas</div>
            <div class="text-2xl font-bold mt-1" style="color:#34d399">${_liqMoney(totalPag)}</div>
            <div class="text-xs text-slate-500 mt-1">${totalBatches} batch(es)</div>
          </div>
        </div>`;
    }
    const pendLocal = _liqState.pendientes || _liqCacheLoad('pendientes') || null;
    const pagLocal  = _liqState.pagadas    || _liqCacheLoad('pagadas')    || null;
    if (pendLocal && pagLocal) {
      pintar(pendLocal, pagLocal);
    } else {
      // Sin state ni cache → skeleton mientras llega
      body.innerHTML = `<div class="liq-skel-stage">
        <div class="liq-skel-card"></div>
        <div class="liq-skel-card" style="animation-delay:.12s"></div>
      </div>`;
    }
    // 2) Refresh silencioso en bg si state está vacío o cache vieja
    if (!pendLocal || !pagLocal) {
      _liqSetSyncState('loading');
      Promise.all([
        _liqFetchConTimeout('getLiquidacionesPendientes', { desde: _liqState.desde, hasta: _liqState.hasta }, 15000).catch(() => []),
        _liqFetchConTimeout('getLiquidacionesPagadas',    { desde: _liqOffset(_liqHoy(), -89), hasta: _liqHoy() }, 30000).catch(() => [])
      ]).then(([pend, pag]) => {
        const pendArr = Array.isArray(pend) ? pend : ((pend && pend.data) || []);
        const pagArr  = Array.isArray(pag)  ? pag  : ((pag  && pag.data)  || []);
        _liqState.pendientes = pendArr;
        _liqState.pagadas    = pagArr;
        _liqCacheSave('pendientes', pendArr);
        _liqCacheSave('pagadas',    pagArr);
        if (_liqState.tab === 'resumen') pintar(pendArr, pagArr);
        _liqSetSyncState('idle');
      }).catch(() => _liqSetSyncState('error'));
    }
  }

  // Backfill / Inicializar LIQUIDACIONES_DIA
  async function _liqBackfillDia(ev) {
    if (ev && typeof _liqRipple === 'function') _liqRipple(ev);
    const btn = ev?.target?.closest('button');
    if (btn) { btn.disabled = true; btn.textContent = '⏳ Procesando 30 días... (~90s)'; }
    try {
      const res = await Promise.race([
        API.post('backfillLiquidacionesDia', { dias: 30 }),
        new Promise((_, rej) => setTimeout(() => rej(new Error('Timeout — vuelve a intentar, los días que se alcanzaron ya están guardados')), 120000))
      ]);
      _liqSfx('success');
      try {
        const r = btn?.getBoundingClientRect();
        if (r) _liqConfetti(r.left + r.width/2, r.top + r.height/2, '#a78bfa');
      } catch(_){}
      toast(res?.msg || '✓ Inicialización completada', 'ok');
      _liqCacheClear();
      // Recarga pendientes con los datos materializados
      if (_liqState.tab === 'pendientes' || _liqState.tab === 'resumen') {
        await liqLoadCurrent();
      }
    } catch(e) {
      _liqSfx('error');
      toast('Error: ' + (e.message || e), 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = '🔧 Inicializar / Reconstruir Liquidación Diaria'; }
    }
  }

  async function _liqMigrar(ev) {
    if (ev) _liqRipple(ev);
    try {
      const res = await API.post('migrarLiquidacionesV2', {});
      _liqSfx('success');
      toast(res.msg || `✓ Migrados ${res.migradas || 0} días`, 'ok');
      liqLoadCurrent();
    } catch(e) {
      _liqSfx('error');
      toast('Error migrando: ' + e.message, 'error');
    }
  }

