  // ════════════════════════════════════════════════════════════
  // MÓDULO FINANZAS
  // ════════════════════════════════════════════════════════════
  let _finPL = null;  // último P&L cargado
  let _finBloqueados = { porNombre: {}, fecha: null };  // {nombre.lower: {dispositivos:[...]}} para overlay de rejas persistente
  let _finanzasRefreshTimer = null;

  // ── Cache localStorage ────────────────────────────────────
  const FIN_CACHE_PFX = 'mos_fin_';
  const FIN_CACHE_TTL = 30 * 60 * 1000;  // 30 min
  function _finLoadCache(key) {
    try {
      const raw = localStorage.getItem(FIN_CACHE_PFX + key);
      if (!raw) return null;
      const p = JSON.parse(raw);
      if (Date.now() - (p.ts || 0) > FIN_CACHE_TTL) return null;
      return p.data;
    } catch { return null; }
  }
  function _finSaveCache(key, data) {
    try { localStorage.setItem(FIN_CACHE_PFX + key, JSON.stringify({ ts: Date.now(), data })); } catch {}
  }
  function _finFlash() {
    const v = $('view-finanzas');
    if (!v) return;
    v.classList.remove('alm-flash');
    void v.offsetWidth;
    v.classList.add('alm-flash');
  }

  // [v2.41.78] Actualiza badges del nav Finanzas según estado del día:
  //   • Cajas abiertas → rojo (alerta)
  //   • Liquidaciones pendientes (>0) → amarillo (default)
  //   • Sin pendientes, alguien LIVE → verde con pulso
  //   • Nada → oculto
  function _finUpdateNavBadge(opts) {
    opts = opts || {};
    const sels = ['#finNavBadgeSidebar', '#finNavBadgeBnav'];
    const cajasAbiertas = parseInt(opts.cajasAbiertas) || 0;
    const liqPend       = parseInt(opts.liqPendientes) || 0;
    const live          = !!opts.live;
    sels.forEach(s => {
      const el = document.querySelector(s);
      if (!el) return;
      el.classList.remove('is-live', 'is-alert', 'is-info');
      if (cajasAbiertas > 0) {
        el.textContent = cajasAbiertas > 99 ? '99+' : String(cajasAbiertas);
        el.classList.add('is-alert');
        el.classList.remove('hidden');
        el.title = `${cajasAbiertas} caja(s) abiertas`;
      } else if (liqPend > 0) {
        el.textContent = liqPend > 99 ? '99+' : String(liqPend);
        el.classList.add('is-info');
        el.classList.remove('hidden');
        el.title = `${liqPend} liquidación(es) pendiente(s)`;
      } else if (live) {
        el.textContent = '●';
        el.classList.add('is-live');
        el.classList.remove('hidden');
        el.title = 'Operadores activos ahora';
      } else {
        el.classList.add('hidden');
      }
    });
  }

  // [v2.41.78] Lazy-render de charts Chart.js para evitar bloquear el
  // main thread. Antes renderChart() era síncrono → 200-400ms de freeze
  // al cargar Finanzas (charts 7d + waterfall). Ahora difiere a
  // requestIdleCallback (o setTimeout fallback) → el resto del UI pinta
  // primero, charts aparecen 1-2 frames después sin bloquear.
  // Dedup por id: si llega otra config para el mismo chart antes de
  // que se renderice, gana la última (cancela la previa pendiente).
  const _finChartPending = {};
  function _finChartDeferred(id, config) {
    if (_finChartPending[id]) {
      try { (_finChartPending[id].cancel || (() => {}))(); } catch(_){}
    }
    const run = () => {
      delete _finChartPending[id];
      try { renderChart(id, config); } catch(_){}
    };
    if (typeof window.requestIdleCallback === 'function') {
      const handle = window.requestIdleCallback(run, { timeout: 800 });
      _finChartPending[id] = { cancel: () => window.cancelIdleCallback && window.cancelIdleCallback(handle) };
    } else {
      const t = setTimeout(run, 16);
      _finChartPending[id] = { cancel: () => clearTimeout(t) };
    }
  }
  // Hidratar PL del día actual al cargar el script
  (function _finHidratar() {
    const f = today();
    const cached = _finLoadCache('pl_' + f);
    if (cached) { cached._fechaStamp = f; _finPL = cached; }
  })();

  // [v2.41.78] DEPRECATED el setInterval 60s — ahora todo polling vive
  // en _finStartPolling (30s, único, activo solo en vista Finanzas).
  // Mantenemos la función para el "fetch inmediato al autenticar" que
  // hidrata _finPL desde el login (precarga). Si el user entra a Finanzas
  // antes de que llegue, ya tiene cache; si no, el polling 30s lo
  // refrescará al entrar.
  function _startFinanzasRefresh() {
    _stopFinanzasRefresh();
    _finanzasRefreshSilencioso(); // fetch inmediato post-login (hidrata _finPL)
    // ANTES: setInterval cada 60s — eliminado. _finStartPolling (30s) cubre el rol.
  }
  function _stopFinanzasRefresh() {
    if (_finanzasRefreshTimer) { clearInterval(_finanzasRefreshTimer); _finanzasRefreshTimer = null; }
  }
  // [v2.41.78] Hash rápido de P&L — sustituye JSON.stringify (10KB+ por
  // llamada → CPU spike cada polling). Solo combina los campos que
  // realmente importan para detectar "cambio relevante".
  function _finHashPL(pl) {
    if (!pl) return '';
    const k = [
      pl.ventasNetas, pl.ventasBrutas, pl.tickets, pl.ticketsAnulados,
      pl.efectivo, pl.virtual, pl.credito,
      pl.costoVentas, pl.margenBruto, pl.utilidadNeta,
      pl.unidades, pl.skus, pl.ticketProm, pl.margenProm,
      pl.gastoPersonal, pl.gastoOtros, pl.gastoFijo, pl.gastoVariable,
      (pl.personalDetalle || []).length,
      (pl.gastos || []).length
    ];
    // Sumar también una huella de personalDetalle (suma de totales y
    // nombres) para captar cambios en cards individuales.
    let pdSig = 0;
    (pl.personalDetalle || []).forEach((p, i) => {
      pdSig += (parseFloat(p.totalDia) || 0) * (i + 1);
    });
    k.push(Math.round(pdSig * 100));
    return k.join('|');
  }

  // [v2.41.78] Detección de cambios relevantes entre dos P&L —
  // dispara efectos visuales/sonoros cuando algo importante pasa
  // (venta nueva, ticket anulado, caja nueva, gasto agregado).
  function _finDetectarCambios(plOld, plNew) {
    if (!plOld || !plNew) return null;
    const out = {};
    const dVentas = (parseFloat(plNew.ventasNetas) || 0) - (parseFloat(plOld.ventasNetas) || 0);
    const dTickets = (parseInt(plNew.tickets) || 0) - (parseInt(plOld.tickets) || 0);
    const dAnulados = (parseInt(plNew.anulados) || 0) - (parseInt(plOld.anulados) || 0);
    const dCajas = (parseInt(plNew.cajasAbiertas) || 0) - (parseInt(plOld.cajasAbiertas) || 0);
    if (dVentas > 0.01 && dTickets > 0) { out.ventaNueva = { monto: dVentas, count: dTickets }; }
    if (dAnulados > 0) out.ticketAnulado = { count: dAnulados };
    if (dCajas > 0) out.cajaAbierta = { count: dCajas };
    if (dCajas < 0) out.cajaCerrada = { count: -dCajas };
    return Object.keys(out).length ? out : null;
  }
  function _finCelebrarCambios(cambios) {
    if (!cambios || S.view !== 'finanzas') return;
    if (cambios.ventaNueva) {
      // Flash + bounce del KPI ventas + sonido cash
      const card = document.getElementById('finKpiVentas')?.closest('.alm-card') ||
                   document.getElementById('finKpiVentas');
      if (card) {
        card.classList.remove('fin-kpi-flash');
        void card.offsetWidth;
        card.classList.add('fin-kpi-flash');
        setTimeout(() => card.classList.remove('fin-kpi-flash'), 1200);
      }
      try { _finBeep('agregar'); } catch(_){}
      try {
        toast(`💸 +${cambios.ventaNueva.count} venta${cambios.ventaNueva.count > 1 ? 's' : ''} · S/${cambios.ventaNueva.monto.toFixed(2)}`, 'ok', 3000);
      } catch(_){}
    }
    if (cambios.ticketAnulado) {
      try { _finBeep('eliminar'); } catch(_){}
    }
    if (cambios.cajaAbierta) {
      try { _finBeep('importar'); } catch(_){}
      try { toast(`🛒 ${cambios.cajaAbierta.count} caja${cambios.cajaAbierta.count > 1 ? 's' : ''} abierta${cambios.cajaAbierta.count > 1 ? 's' : ''}`, 'info', 3000); } catch(_){}
    }
    if (cambios.cajaCerrada) {
      try { _finBeep('ok'); } catch(_){}
    }
  }

  async function _finanzasRefreshSilencioso() {
    if (!S.session) return;
    if (document.visibilityState !== 'visible') return;
    iconBusy('finanzas', true);
    try {
      const fecha  = $('finFecha')?.value || today();
      const pl     = await API.get('getFinanzasDia', { fecha });
      // [v2.41.78] Hash rápido en vez de JSON.stringify costoso
      const changedPL = _finHashPL(pl) !== _finHashPL(_finPL);
      // Detectar y celebrar cambios relevantes (venta nueva, caja, anulado)
      const cambios = _finDetectarCambios(_finPL, pl);
      if (pl) pl._fechaStamp = fecha;
      _finPL = pl;
      _finSaveCache('pl_' + fecha, pl);
      if (S.view === 'finanzas') {
        // Pulso del dot indicando refresh silencioso exitoso
        _finPulsoPoll();
        if (changedPL) { _finRender(pl, fecha); _finFlash(); }
        // [v2.41.78] Celebrar cambios DESPUÉS del render (cards ya pintados)
        if (cambios) _finCelebrarCambios(cambios);
        const hasta  = fecha;
        const desde7 = _fechaOffset(fecha, -6);
        const rango  = await API.get('getFinanzasRango', { desde: desde7, hasta });
        _finSaveCache('rango_' + fecha, rango);
        _finRender7d(rango);
      }
      // Refresh también las liquidaciones pendientes (cambian con jornadas auto)
      API.get('getLiquidacionesPendientesSemana', {}).then(r => {
        if (r) {
          _liqSaveCache('pendientes', r);
          // Si el user está en Config → Personal, refrescar el card ME
          if (S.view === 'config' && S.cfgTab === 'personal') {
            try { _cfgRenderMeCajeros(); } catch {}
          }
        }
      }).catch(() => {});
    } catch(_) { /* silencioso */ }
    iconBusy('finanzas', false);
  }

  // ════════════════════════════════════════════════════════════
  // Race-safe token: invalida respuestas obsoletas si el user
  // navega rápido entre días. Solo la última request gana.
  // ════════════════════════════════════════════════════════════
  let _finGenId = 0;
  let _finUltimaFecha = null;

  async function finCargar(opts) {
    opts = opts || {};
    const inpF = $('finFecha');
    if (inpF && !inpF.value) inpF.value = today();
    const fecha = inpF?.value || today();
    const myGen = ++_finGenId;
    const fechaPrev = _finUltimaFecha;
    _finUltimaFecha = fecha;

    // Animar slide si se pidió y hay cambio real de fecha
    const dir = opts.dir;
    const animate = !!opts.animate;
    const slide = $('finSlideContent');
    if (animate && slide && fechaPrev && fechaPrev !== fecha) {
      slide.classList.remove('fin-slide-snap');
      slide.classList.add(dir > 0 ? 'fin-slide-out-left' : 'fin-slide-out-right');
      _finBeep('nav');
      // esperar fade-out antes de pintar lo nuevo
      await new Promise(r => setTimeout(r, 220));
      slide.classList.add('fin-slide-snap');
      slide.classList.remove('fin-slide-out-left', 'fin-slide-out-right');
      slide.classList.add(dir > 0 ? 'fin-slide-in-right' : 'fin-slide-in-left');
      // forzar reflow para que el snap aplique
      void slide.offsetWidth;
      slide.classList.remove('fin-slide-snap');
      requestAnimationFrame(() => {
        slide.classList.remove('fin-slide-in-left', 'fin-slide-in-right');
      });
    }

    _finUpdateBadge(fecha);

    // Marcar inmediatamente la fecha del listado de Personal para que
    // cualquier paint async pendiente (de la fecha previa) sea ignorado.
    // Si la fecha CAMBIÓ, además limpiar el DOM ya — no queremos que el
    // usuario vea el personal del día anterior parado mientras carga.
    const personalCont = $('finPersonalList');
    if (personalCont) {
      const prevFecha = personalCont.dataset.fecha;
      personalCont.dataset.fecha = fecha;
      if (prevFecha && prevFecha !== fecha) {
        personalCont.dataset._lastHtml = ''; // reset anti-flicker
        // [v2.41.58] Skeleton SIEMPRE al cambiar fecha — no dejar info stale.
        // Antes solo mostraba 2 cards skeleton, ahora algo más informativo.
        personalCont.innerHTML = `
          <div class="text-center text-xs text-slate-500 py-3" style="opacity:.7">
            <div class="inline-block animate-spin" style="font-size:14px">⌛</div>
            Cargando ${_formatFechaCorta(fecha)}…
          </div>
          <div class="fin-skel" style="height: 64px;"></div>
          <div class="fin-skel" style="height: 64px;"></div>
          <div class="fin-skel" style="height: 64px;"></div>`;
      }
    }

    // [v2.41.58] Si es refresh silencioso del polling 30s y la fecha NO cambió,
    // NO mostrar skeleton ni invalidar cache — actualizar in-place al final.
    const esSilent = !!opts._silent;

    // 1. Pintar desde cache local si existe (instantáneo) — sino, RESET visual
    //    completo. Evita que el user vea datos del día anterior mezclados con
    //    el nuevo (Personal, Gastos, break-even bar quedaban stale).
    if (!esSilent) {
      const cachedPL = _finLoadCache('pl_' + fecha);
      if (cachedPL) {
        cachedPL._fechaStamp = fecha;
        _finPL = cachedPL;
        try { _finRender(cachedPL, fecha); } catch {}
      } else {
        _finMostrarSkeleton(true);
        _finPL = null;
      }
      const cachedRango = _finLoadCache('rango_' + fecha);
      if (cachedRango) { try { _finRender7d(cachedRango); } catch {} }
    }

    // 2. Fetch fresco en background — actualiza cuando responda
    if (!esSilent) iconBusy('finanzas', true);
    try {
      const pl = await API.get('getFinanzasDia', { fecha });
      // Race check: si el user navegó a otra fecha, descartar esta respuesta
      if (myGen !== _finGenId) return;
      if (pl) pl._fechaStamp = fecha; // stamp para detectar mismatch al reabrir
      _finPL = pl;
      _finSaveCache('pl_' + fecha, pl);

      // Cargar lista de dispositivos bloqueados (encarcelados) para pintar
      // overlay persistente de rejas en cards. Fallback silencioso si falla.
      try {
        const rB = await API.get('getDispositivosBloqueados', { agruparPorNombre: true });
        if (myGen !== _finGenId) return;
        // [Lote3-A · fix A3-MOS] API.get YA desempaqueta d.data → rB = {lista, porNombre}.
        // Antes se exigía rB.ok && rB.data (ambos undefined) → el overlay de rejas NUNCA
        // se pintaba: el admin no veía qué dispositivos estaban bloqueados.
        _finBloqueados = { porNombre: (rB && rB.porNombre) || {}, fecha };
      } catch(_) { _finBloqueados = { porNombre: {}, fecha }; }

      if (!esSilent) _finMostrarSkeleton(false);
      _finRender(pl, fecha);
      if (!esSilent) _finBeep('ok');

      const hasta  = fecha;
      const desde7 = _fechaOffset(fecha, -6);
      const rango  = await API.get('getFinanzasRango', { desde: desde7, hasta });
      if (myGen !== _finGenId) return;
      _finSaveCache('rango_' + fecha, rango);
      _finRender7d(rango);

      // Prefetch ±1 día en background (idle) — para navegación instantánea
      _finPrefetchAdyacentes(fecha);
    } catch(e) {
      if (myGen !== _finGenId) return; // race: ya no nos importa este error
      if (!esSilent) _finMostrarSkeleton(false);
      // Silencioso: no toast en polling background (evita spam si red flota)
      if (!esSilent && !_finPL) toast('Error Finanzas: ' + e.message, 'error');
    } finally {
      if (myGen === _finGenId && !esSilent) iconBusy('finanzas', false);
    }
  }

  // [v2.41.78] Debounce navegación de días — evita salto múltiple en double-click
  let _finDiaLock = false;
  function finDia(delta) {
    if (_finDiaLock) return;
    _finDiaLock = true;
    setTimeout(() => { _finDiaLock = false; }, 260); // tiempo del slide
    const inp = $('finFecha');
    if (!inp) return;
    const cur = inp.value || today();
    const d = new Date(cur + 'T00:00:00');
    d.setDate(d.getDate() + delta);
    inp.value = d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
    finCargar({ animate: true, dir: delta });
  }

  function finIrHoy() {
    const inp = $('finFecha');
    if (!inp) return;
    const cur = inp.value;
    const hoy = today();
    if (cur === hoy) {
      // pulso del badge
      const b = $('finDayBadge');
      if (b) { b.classList.add('fin-day-pulse'); setTimeout(() => b.classList.remove('fin-day-pulse'), 280); }
      return;
    }
    const dir = (cur && cur > hoy) ? -1 : 1;
    inp.value = hoy;
    finCargar({ animate: true, dir });
  }

  // ── Badge "Hoy / Ayer / Hace N días / +N días" ──
  function _finUpdateBadge(fecha) {
    const el = $('finDayBadge');
    const lbl = $('finFechaLabel');
    const hoy = today();
    const a = new Date(fecha + 'T00:00:00');
    const h = new Date(hoy + 'T00:00:00');
    const diff = Math.round((a - h) / 86400000);
    if (el) {
      el.classList.remove('fin-day-hoy', 'fin-day-ayer', 'fin-day-past', 'fin-day-futuro');
      let txt = '';
      if (diff === 0)       { txt = '🟢 Hoy';        el.classList.add('fin-day-hoy'); }
      else if (diff === -1) { txt = 'Ayer';          el.classList.add('fin-day-ayer'); }
      else if (diff === 1)  { txt = 'Mañana';        el.classList.add('fin-day-futuro'); }
      else if (diff < 0)    { txt = `Hace ${-diff} días`;   el.classList.add('fin-day-past'); }
      else                  { txt = `+${diff} días`; el.classList.add('fin-day-futuro'); }
      el.textContent = txt;
      el.classList.add('fin-day-pulse');
      setTimeout(() => el.classList.remove('fin-day-pulse'), 280);
    }
    if (lbl) {
      const d = new Date(fecha + 'T00:00:00');
      const txt = d.toLocaleDateString('es-PE', { day:'2-digit', month:'short', year:'2-digit' });
      lbl.textContent = (diff === 0) ? `Hoy · ${txt}` : txt;
    }
  }

  // ── Comparación vs ayer (para el card de Ventas) ────────────
  function _finRenderComparaAyer(pl, fecha) {
    const el = $('finVentasComparaAyer');
    if (!el) return;
    try {
      const ayer = _fechaOffset(fecha, -1);
      const cached = _finLoadCache('pl_' + ayer);
      const ventasAyer = cached ? parseFloat(cached.ventasNetas || 0) : 0;
      const ventasHoy = parseFloat(pl.ventasNetas || 0);
      if (!ventasAyer || !cached) {
        el.classList.add('hidden');
        return;
      }
      const diff = ventasHoy - ventasAyer;
      const pct = ventasAyer > 0 ? (diff / ventasAyer * 100) : 0;
      el.classList.remove('hidden', 'up', 'down');
      if (diff >= 0) {
        el.classList.add('up');
        el.innerHTML = '▲ +' + Math.abs(pct).toFixed(0) + '% vs ayer';
      } else {
        el.classList.add('down');
        el.innerHTML = '▼ ' + Math.abs(pct).toFixed(0) + '% vs ayer';
      }
    } catch { el.classList.add('hidden'); }
  }

  // ── Confetti al cruzar break-even ─────────────────────────
  function _finConfetiBE() {
    const canvas = $('finBEConfetti');
    const card = $('finBECardWrap');
    if (!canvas || !card) return;
    const rect = card.getBoundingClientRect();
    canvas.width = rect.width;
    canvas.height = rect.height;
    canvas.classList.remove('hidden');
    const ctx = canvas.getContext('2d');
    const colores = ['#34d399', '#fbbf24', '#a5b4fc', '#22d3ee', '#f472b6', '#facc15'];
    const piezas = [];
    for (let i = 0; i < 80; i++) {
      piezas.push({
        x: Math.random() * canvas.width,
        y: -10 - Math.random() * 40,
        vx: (Math.random() - 0.5) * 4,
        vy: 2 + Math.random() * 4,
        rot: Math.random() * 360,
        vRot: (Math.random() - 0.5) * 12,
        size: 6 + Math.random() * 6,
        color: colores[Math.floor(Math.random() * colores.length)],
        forma: Math.random() > 0.5 ? 'rect' : 'circle'
      });
    }
    let frames = 0;
    const tick = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      piezas.forEach(p => {
        p.vy += 0.15; // gravedad
        p.x += p.vx;
        p.y += p.vy;
        p.rot += p.vRot;
        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate((p.rot * Math.PI) / 180);
        ctx.fillStyle = p.color;
        if (p.forma === 'rect') ctx.fillRect(-p.size/2, -p.size/2, p.size, p.size * 0.4);
        else { ctx.beginPath(); ctx.arc(0, 0, p.size/2, 0, Math.PI*2); ctx.fill(); }
        ctx.restore();
      });
      frames++;
      if (frames < 180) requestAnimationFrame(tick);
      else { ctx.clearRect(0, 0, canvas.width, canvas.height); canvas.classList.add('hidden'); }
    };
    tick();
  }

  // ── Datepicker del header de Finanzas ─────────────────────
  let _finCalState = null;
  function finAbrirCalendario(btn) {
    const dp = $('finDatepicker');
    if (!dp) return;
    if (!dp.classList.contains('hidden')) { dp.classList.add('hidden'); return; }
    const cur = $('finFecha')?.value || today();
    const d = new Date(cur + 'T00:00:00');
    _finCalState = { y: d.getFullYear(), m: d.getMonth() };
    _finCalRender();
    const r = btn.getBoundingClientRect();
    dp.style.left = Math.max(8, Math.min(window.innerWidth - 250, r.left)) + 'px';
    dp.style.top  = (r.bottom + 6) + 'px';
    dp.classList.remove('hidden');
    setTimeout(() => {
      const closer = e => {
        if (!dp.contains(e.target) && !btn.contains(e.target)) {
          dp.classList.add('hidden');
          document.removeEventListener('click', closer);
        }
      };
      document.addEventListener('click', closer);
    }, 50);
  }
  function finCalNavMes(delta) {
    if (!_finCalState) return;
    let { y, m } = _finCalState;
    m += delta;
    if (m < 0)  { m = 11; y--; }
    if (m > 11) { m = 0; y++; }
    _finCalState = { y, m };
    _finCalRender();
  }
  function _finCalRender() {
    const grid = $('finCalGrid');
    const lbl  = $('finCalMesAnio');
    if (!grid || !_finCalState) return;
    const { y, m } = _finCalState;
    const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
    if (lbl) lbl.textContent = `${meses[m]} ${y}`;
    const primero = new Date(y, m, 1);
    let primerDow = primero.getDay();
    primerDow = primerDow === 0 ? 6 : primerDow - 1;
    const ultimo = new Date(y, m + 1, 0).getDate();
    const hoy = today();
    const sel = $('finFecha')?.value || hoy;
    let html = '';
    for (let i = 0; i < primerDow; i++) html += '<button class="log-cal-day empty"></button>';
    for (let dia = 1; dia <= ultimo; dia++) {
      const f = `${y}-${String(m + 1).padStart(2, '0')}-${String(dia).padStart(2, '0')}`;
      const cls = ['log-cal-day'];
      if (f === hoy) cls.push('today');
      if (f === sel) cls.push('selected');
      html += `<button class="${cls.join(' ')}" onclick="MOS.finElegirFecha('${f}')">${dia}</button>`;
    }
    grid.innerHTML = html;
  }
  function finElegirFecha(f) {
    const inp = $('finFecha');
    if (!inp) return;
    const prev = inp.value;
    inp.value = f;
    $('finDatepicker')?.classList.add('hidden');
    finCargar({ animate: true, dir: f > prev ? 1 : -1 });
  }

  // Ir a una fecha específica desde el mini-row de 7 días
  function finIrAFecha(f) {
    const inp = $('finFecha');
    if (!inp) return;
    const prev = inp.value || today();
    if (f === prev) return;
    inp.value = f;
    finCargar({ animate: true, dir: f > prev ? 1 : -1 });
  }

  // ── Indicador visual del polling silencioso ─────────────
  function _finPulsoPoll() {
    const dot = $('finPollDot');
    if (!dot) return;
    dot.classList.add('active');
    setTimeout(() => dot.classList.remove('active'), 1300);
  }

  // ── Skeleton on/off — reset visual completo de TODO ──
  // Cuando el user navega a un día sin caché, evita ver datos del día anterior.
  // Pinta shimmer en KPIs + Personal + Gastos + break-even bar.
  function _finMostrarSkeleton(on) {
    const slide = $('finSlideContent');
    if (slide) slide.classList.toggle('fin-skel-on', !!on);
    if (!on) return;

    // Lists
    const pl = $('finPersonalList');
    if (pl) pl.innerHTML = `
      <div class="fin-skel" style="height: 64px;"></div>
      <div class="fin-skel" style="height: 64px;"></div>
      <div class="fin-skel" style="height: 64px;"></div>`;
    const gl = $('finGastosList');
    if (gl) gl.innerHTML = `
      <div class="fin-skel" style="height: 28px;"></div>
      <div class="fin-skel" style="height: 28px;"></div>`;
    const cat = $('finGastosCateg');
    if (cat) cat.innerHTML = '';

    // Totales que se actualizan fuera del countup (textContent directo)
    const totGastos = $('finGastosTotal');
    if (totGastos) totGastos.textContent = 'S/ —';
    const totPer = $('finPersonalTotal');
    if (totPer) { totPer.textContent = 'S/ —'; totPer.dataset._anim = '0'; }

    // Reset data-attrs de los KPIs con countup → próxima animación arranca de 0
    ['finKpiVentas','finKpiCosto','finKpiGastos','finKpiUtil','finBECostosFijos']
      .forEach(id => { const el = $(id); if (el) { el.dataset._anim = '0'; el.textContent = 'S/ —'; } });

    // Break-even bar y línea — colapsar a 0
    const bar = $('finBEBarVentas');
    if (bar) { bar.style.width = '0%'; bar.dataset._beAnim = '0'; }
    const lin = $('finBELinea');
    if (lin) lin.style.left = '0%';
    const beMeta = $('finBEMeta');
    if (beMeta) beMeta.innerHTML = 'Meta: <span class="_beNum">—</span>';
    const beVent = $('finBEVentas');
    if (beVent) beVent.innerHTML = 'Ventas: <span class="_bevNum">—</span>';
    const beMC = $('finBEMargenC');
    if (beMC) beMC.textContent = '—%';
    const beBadge = $('finBEBadge');
    if (beBadge) {
      beBadge.textContent = '...';
      beBadge.className = 'text-xs font-bold px-2 py-0.5 rounded-full bg-slate-800 text-slate-500';
    }

    // KPI textos no-numéricos
    const tk = $('finKpiTickets');     if (tk) tk.textContent = '— tickets';
    const mb = $('finKpiMargenB');     if (mb) mb.textContent = 'Margen bruto —%';
    const pe = $('finKpiPersonas');    if (pe) pe.textContent = '— personas';
    const mn = $('finKpiMargenN');     if (mn) mn.textContent = 'Margen neto —%';
    const ef = $('finKpiEfectivo');    if (ef) ef.textContent = 'S/ —';
    const vi = $('finKpiVirtual');     if (vi) vi.textContent = 'S/ —';
    const cr = $('finKpiCredito');     if (cr) cr.textContent = 'S/ —';
    const cs = $('finKpiCreditoSub');  if (cs) cs.textContent = '— tickets POR_COBRAR';
    const an = $('finKpiAnulados');    if (an) an.textContent = '— tickets';
    const un = $('finKpiUnidades');    if (un) un.textContent = '—';
    const sk = $('finKpiSkus');        if (sk) sk.textContent = '—';
    const tp = $('finKpiTicketProm');  if (tp) tp.textContent = '—';
    const mp = $('finKpiMargenProm');  if (mp) mp.textContent = '—';
    const me = $('finKpiMargenEstim'); if (me) me.textContent = '';
  }

  // ── Prefetch ±1 día en background (no espera) ──
  function _finPrefetchAdyacentes(fecha) {
    const target = [
      _fechaOffset(fecha, -1),
      _fechaOffset(fecha, +1),
    ];
    // setTimeout para esperar que el navegador esté idle
    setTimeout(() => {
      target.forEach(f => {
        if (_finLoadCache('pl_' + f)) return; // ya cacheado
        API.get('getFinanzasDia', { fecha: f })
          .then(pl => _finSaveCache('pl_' + f, pl))
          .catch(() => {});
      });
    }, 800);
  }

  // ════════════════════════════════════════════════════════════
  // Sonidos de Finanzas — SIEMPRE suenan (efectos de UI son parte
  // de la interacción, no se mutean desde la app).
  // ════════════════════════════════════════════════════════════
  let _finAudioCtx = null;

  function _finBeep(tipo) {
    try {
      if (!_finAudioCtx) _finAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const ctx = _finAudioCtx;
      const t0 = ctx.currentTime;
      const tone = (freq, dur, gain, type, t) => {
        const o = ctx.createOscillator();
        const g = ctx.createGain();
        o.connect(g); g.connect(ctx.destination);
        o.type = type || 'sine';
        o.frequency.setValueAtTime(freq, t);
        g.gain.setValueAtTime(gain, t);
        g.gain.exponentialRampToValueAtTime(0.0001, t + dur);
        o.start(t); o.stop(t + dur + 0.02);
      };
      const sweep = (f1, f2, dur, gain, type, t) => {
        const o = ctx.createOscillator();
        const g = ctx.createGain();
        o.connect(g); g.connect(ctx.destination);
        o.type = type || 'sine';
        o.frequency.setValueAtTime(f1, t);
        o.frequency.exponentialRampToValueAtTime(f2, t + dur);
        g.gain.setValueAtTime(gain, t);
        g.gain.exponentialRampToValueAtTime(0.0001, t + dur);
        o.start(t); o.stop(t + dur + 0.02);
      };
      switch (tipo) {
        case 'nav':         // tic agudo (cambio día)
          sweep(1800, 900, 0.05, 0.05, 'sine', t0);
          break;
        case 'ok':          // ding suave (acción confirmada)
          tone(1320, 0.18, 0.04, 'sine', t0);
          break;
        case 'veto':        // tono grave descendente + eco (rejas cayendo)
          sweep(880, 220, 0.32, 0.10, 'sawtooth', t0);
          tone(160, 0.30, 0.06, 'sine', t0 + 0.10);
          break;
        case 'rehab':       // tres notas ascendentes (campana liberadora)
          [523.25, 659.25, 783.99].forEach((f, i) =>
            tone(f, 0.20, 0.08, 'triangle', t0 + i * 0.08));
          break;
        case 'bloquear':    // chasquido de cerrojo: dos thuds graves rápidos
          sweep(420, 90, 0.08, 0.12, 'square', t0);
          sweep(380, 80, 0.10, 0.10, 'square', t0 + 0.09);
          break;
        case 'desbloquear': // cerrojo abriéndose: thud + ascenso ligero
          sweep(180, 90, 0.08, 0.10, 'square', t0);
          sweep(440, 880, 0.12, 0.06, 'triangle', t0 + 0.10);
          break;
        case 'agregar':     // chink moneda (gasto/jornada agregado)
          tone(880, 0.06, 0.06, 'triangle', t0);
          tone(1320, 0.12, 0.05, 'triangle', t0 + 0.04);
          break;
        case 'eliminar':    // whoosh corto descendente
          sweep(660, 220, 0.14, 0.06, 'sine', t0);
          break;
        case 'importar':    // cascada: 5 chinks rápidos ascendentes
          [659, 740, 880, 988, 1175].forEach((f, i) =>
            tone(f, 0.07, 0.045, 'triangle', t0 + i * 0.045));
          break;
        case 'audit':       // dos notas estables (auditando)
          tone(880, 0.10, 0.05, 'sine', t0);
          tone(1108, 0.14, 0.05, 'sine', t0 + 0.10);
          break;
        case 'breakeven':   // ¡fanfare! C-E-G-C celebración
          [523.25, 659.25, 783.99, 1046.5].forEach((f, i) =>
            tone(f, 0.28, 0.09, 'triangle', t0 + i * 0.10));
          break;
        case 'kpi-up':      // sutil tono ascendente (KPI mejora)
          sweep(660, 990, 0.10, 0.04, 'sine', t0);
          break;
        case 'kpi-down':    // sutil tono descendente (KPI empeora)
          sweep(660, 440, 0.12, 0.04, 'sine', t0);
          break;
        case 'error':       // buzz grave (acción bloqueada/falló)
          tone(220, 0.14, 0.10, 'square', t0);
          tone(180, 0.16, 0.08, 'square', t0 + 0.10);
          break;
        case 'click':       // click neutral
          tone(2000, 0.025, 0.04, 'sine', t0);
          break;
        case 'dinero':      // ¡cha-ching! caja registradora
          // Pulso metálico + 3 notas brillantes ascendentes
          tone(2400, 0.04, 0.08, 'square', t0);           // klick metálico
          tone(1046.5, 0.10, 0.10, 'triangle', t0 + 0.02); // C6
          tone(1318.5, 0.12, 0.10, 'triangle', t0 + 0.08); // E6
          tone(1568.0, 0.18, 0.12, 'triangle', t0 + 0.14); // G6
          // Cola sutil aguda como el "ting" de cajón
          tone(2637.0, 0.20, 0.05, 'sine', t0 + 0.18);    // E7 alto
          break;
        default:
          tone(1320, 0.18, 0.04, 'sine', t0);
      }
    } catch {}
  }

  // Reemplaza el HTML de un card específico tras una acción (vetar/rehabilitar)
  // sin tocar el resto. Evita parpadeo y mantiene el botón actualizado a su
  // nuevo estado (💸 ↔ 💵).
  function _finReemplazarCardJornada(idJornada, fecha, idMega) {
    if (!_finPL || !Array.isArray(_finPL.personalDetalle)) return;
    // [100x · A4b] localizar por idMega (único). idJornada está VACÍO en las filas de la
    // mega tabla → find/selector por idJornada matcheaba la PRIMERA card → reemplazaba la
    // equivocada. El mismo criterio que finVetarPago (v2.43.382).
    const clave = idMega || idJornada || '__nope__';
    const p = _finPL.personalDetalle.find(x =>
      (idMega && String(x.idPersonal) === String(idMega)) || (idJornada && String(x.idJornada) === String(idJornada)));
    if (!p) return;
    let ev = null;
    try {
      const raw = localStorage.getItem('mos_fin_resum_' + fecha);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed.data)) {
          ev = parsed.data.find(r =>
            (r.idPersonal && r.idPersonal === p.idPersonal) ||
            (String(r.nombre || '').toLowerCase().trim() === String(p.nombre || '').toLowerCase().trim())
          );
        }
      }
    } catch {}
    const cards = document.querySelectorAll('.eval-card');
    for (const c of cards) {
      // Match por botón vetar O rehabilitar que contenga la clave (idMega)
      if (c.querySelector(`button[onclick*="finVetarPago"][onclick*="${clave}"]`) ||
          c.querySelector(`button[onclick*="finRehabilitarPago"][onclick*="${clave}"]`)) {
        const wrap = document.createElement('div');
        wrap.innerHTML = _finRenderPersonalCard(p, ev || null, fecha).trim();
        const nuevo = wrap.firstElementChild;
        if (nuevo) c.replaceWith(nuevo);
        return;
      }
    }
  }


  // ── Atajos de teclado en la vista Finanzas ──
  document.addEventListener('keydown', e => {
    // Ignorar si el foco está en input/textarea
    const tag = (document.activeElement?.tagName || '').toLowerCase();
    if (tag === 'input' || tag === 'textarea' || tag === 'select') return;
    // Solo si la vista Finanzas está visible
    const view = $('view-finanzas');
    if (!view || view.classList.contains('hidden')) return;
    if (e.key === 'ArrowLeft')  { e.preventDefault(); finDia(-1); }
    else if (e.key === 'ArrowRight') { e.preventDefault(); finDia(1); }
    else if (e.key === ' ') { e.preventDefault(); finIrHoy(); }
  });

  function _finRender(pl, fecha, opts) {
    opts = opts || {};
    const skipPersonal = !!opts.skipPersonal;
    const fmt  = v => 'S/ ' + parseFloat(v || 0).toFixed(2);
    const pct  = v => parseFloat(v || 0).toFixed(1) + '%';

    // [v2.41.78] Actualizar badge del nav Finanzas con datos en vivo.
    // Solo cuando pintamos HOY (no días pasados/futuros).
    try {
      const hoy = today();
      if (fecha === hoy) {
        const cajasAbiertas = parseInt(pl.cajasAbiertas) || 0;
        // Liq pendientes lo leemos del cache si está
        let liqPend = 0;
        try {
          const raw = localStorage.getItem('mos_liq2_pendientes');
          if (raw) {
            const p = JSON.parse(raw);
            liqPend = ((p.data && p.data.length) || 0);
          }
        } catch(_){}
        // "live" si alguien tiene Ultima_Conexion en últimos 5min
        let live = false;
        try {
          if (Array.isArray(pl.personalDetalle)) {
            for (const p of pl.personalDetalle) {
              const ultCx = _finBuscarActividadPersonal(p, null);
              if (ultCx) {
                const t = _parseTsUtc(ultCx);
                if (!isNaN(t) && Date.now() - t < 5 * 60 * 1000) { live = true; break; }
              }
            }
          }
        } catch(_){}
        _finUpdateNavBadge({ cajasAbiertas, liqPendientes: liqPend, live });
      } else {
        _finUpdateNavBadge({}); // ocultar si vemos días pasados
      }
    } catch(_){}

    // KPI cards — los montos animan countup
    _animateCount('finKpiVentas', pl.ventasNetas, { prefix: 'S/ ' });
    _setText('finKpiTickets', pl.tickets + ' ticket' + (pl.tickets !== 1 ? 's' : '') +
             (pl.anulados ? ' · ' + pl.anulados + ' anulado' + (pl.anulados > 1 ? 's' : '') : ''));
    _animateCount('finKpiCosto', pl.costoVentas, { prefix: 'S/ ' });
    _setText('finKpiMargenB', 'Margen bruto ' + pct(pl.margenBrutoPct));
    // Barra del margen bruto (visual)
    const margenBarFill = $('finMargenBarFill');
    if (margenBarFill) {
      const mb = Math.max(0, Math.min(parseFloat(pl.margenBrutoPct || 0), 100));
      margenBarFill.style.width = mb.toFixed(1) + '%';
      margenBarFill.style.background = mb >= 30
        ? 'linear-gradient(90deg, #10b981, #34d399)'
        : (mb >= 15 ? 'linear-gradient(90deg, #f59e0b, #fbbf24)'
                    : 'linear-gradient(90deg, #dc2626, #f87171)');
    }
    _animateCount('finKpiGastos', pl.totalGastos, { prefix: 'S/ ' });
    _setText('finKpiPersonas', pl.personas + ' persona' + (pl.personas !== 1 ? 's' : ''));
    _animateCount('finKpiUtil', pl.utilidadNeta, { prefix: 'S/ ' });
    _setText('finKpiMargenN', 'Margen neto ' + pct(pl.margenNetoPct));

    // ── Métodos de pago: barra proporcional efectivo/virtual ──
    const ef = parseFloat(pl.cobradoEfectivo || 0);
    const vi = parseFloat(pl.cobradoVirtual || 0);
    const totalCobrado = ef + vi;
    _setText('finKpiEfectivo', fmt(ef));
    _setText('finKpiVirtual',  fmt(vi));
    const efPct = totalCobrado > 0 ? (ef / totalCobrado * 100) : 50;
    const viPct = totalCobrado > 0 ? (vi / totalCobrado * 100) : 50;
    const barEf = $('finPagoBarEf');
    const barVi = $('finPagoBarVi');
    if (barEf) barEf.style.width = efPct.toFixed(1) + '%';
    if (barVi) barVi.style.width = viPct.toFixed(1) + '%';
    _setText('finPagoPctEf', efPct.toFixed(0) + '%');
    _setText('finPagoPctVi', viPct.toFixed(0) + '%');

    // Crédito + Anulados (slim)
    _setText('finKpiCredito',  fmt(pl.creditoOtorgado || 0));
    _setText('finKpiCreditoSub', (pl.creditos || 0) + ' ticket' + (pl.creditos === 1 ? '' : 's') + ' por cobrar');
    _setText('finKpiAnulados', (pl.anulados || 0) + ' ticket' + (pl.anulados === 1 ? '' : 's'));

    // Comparación vs ayer (Ventas)
    _finRenderComparaAyer(pl, fecha);

    // KPI Productos vendidos
    _setText('finKpiUnidades',   pl.unidadesVendidas ?? '—');
    _setText('finKpiSkus',       pl.skusDistintos    ?? '—');
    _setText('finKpiTicketProm', pl.ticketPromedio   ? 'S/ ' + parseFloat(pl.ticketPromedio).toFixed(2) : '—');

    // Margen Promedio + estimados
    const margenProm = parseFloat(pl.margenPromedioPct || 0);
    const defaultMargen = parseFloat(pl.defaultMargenUsado || 20);
    const cantEstim = parseInt(pl.cantidadEstimados || 0);
    const margenEl = $('finKpiMargenProm');
    if (margenEl) {
      margenEl.textContent = (pl.itemsVendidos > 0 ? margenProm.toFixed(1) + '%' : '—');
      // Color: si margen >= default → emerald; si < default → ámbar
      margenEl.style.color = pl.itemsVendidos > 0
        ? (margenProm >= defaultMargen ? '#34d399' : '#fbbf24')
        : '#475569';
    }
    const estimEl = $('finKpiMargenEstim');
    if (estimEl) {
      if (cantEstim > 0) {
        estimEl.textContent = `${cantEstim} SKU${cantEstim === 1 ? '' : 's'} estim. al ${defaultMargen}%`;
      } else {
        estimEl.textContent = pl.itemsVendidos > 0 ? '✓ todos con costo real' : '';
      }
    }

    // ⚠ inline junto a "Productos Vendidos" si hay SKUs sin costo
    const sinCostoIcon = $('finSinCostoAlerta');
    if (sinCostoIcon) sinCostoIcon.classList.toggle('hidden', !(pl.productosSinCosto?.length));

    // ── BREAK-EVEN dramático ─────────────────────────────
    const beCard  = $('finBECardWrap');
    const beMeta  = $('finBEMeta');
    const beVent  = $('finBEVentas');
    const beFalta = $('finBEFaltaTxt');
    const beEmoji = $('finBEEmoji');
    const beEstado = $('finBEEstado');
    const beResLabel = $('finBEResultadoLabel');
    if (pl.breakEvenVentas) {
      if (beMeta) beMeta.textContent = 'Meta: S/ ' + parseFloat(pl.breakEvenVentas).toFixed(2);
    } else {
      if (beMeta) beMeta.textContent = 'Meta: —';
    }
    if (beVent) beVent.textContent = 'Ventas: S/ ' + parseFloat(pl.ventasNetas || 0).toFixed(2);
    _animateCount('finBECostosFijos', pl.costosFijos, { prefix: 'S/ ' });
    _setText('finBEMargenC', pct(pl.margenContribPct));

    // Barra: ventas como % de la meta. Si supera, llena al 100% y el marker
    // cae más allá del meta-line. Si no, marker en proporción.
    const barV = $('finBEBarVentas');
    const linBE = $('finBELinea');
    const marker = $('finBEMarker');
    const ventasN = parseFloat(pl.ventasNetas || 0);
    const meta = parseFloat(pl.breakEvenVentas || 0);
    const escala = Math.max(meta * 1.2, ventasN * 1.05, 1); // escala dinámica para que el marker se vea
    const fillPctNew = Math.min((ventasN / escala) * 100, 100);
    const metaPct    = meta > 0 ? Math.min((meta / escala) * 100, 100) : 0;
    const oldFillPct = parseFloat(barV?.dataset?._beAnim) || 0;
    if (barV) {
      barV.style.width = fillPctNew.toFixed(1) + '%';
      barV.dataset._beAnim = String(fillPctNew);
    }
    if (linBE) linBE.style.left = metaPct.toFixed(1) + '%';
    if (marker) marker.style.left = fillPctNew.toFixed(1) + '%';

    // Estado dramático: alcanzado / cerca / lejos
    if (beCard) {
      beCard.classList.toggle('alcanzado', !!pl.superaBreakEven);
      beCard.classList.toggle('lejos', !pl.superaBreakEven && ventasN < meta * 0.5 && meta > 0);
    }
    if (beEmoji) beEmoji.textContent = pl.superaBreakEven ? '🎉' : (ventasN < meta * 0.5 ? '⚠️' : '⚖️');
    if (beEstado) {
      if (!meta) beEstado.textContent = 'Sin datos suficientes';
      else if (pl.superaBreakEven) beEstado.textContent = '🚀 Cubriste costos · ¡estás ganando!';
      else if (ventasN < meta * 0.5) beEstado.textContent = '⚠ Falta mucho · ' + (Math.round((ventasN/meta)*100)) + '% de la meta';
      else beEstado.textContent = '⏳ A buen ritmo · ' + (Math.round((ventasN/meta)*100)) + '% de la meta';
    }
    if (beFalta) {
      const falta = Math.max(0, meta - ventasN);
      if (pl.superaBreakEven) beFalta.textContent = '✓ Excedente: S/ ' + (ventasN - meta).toFixed(2);
      else if (meta > 0) beFalta.textContent = 'Faltan S/ ' + falta.toFixed(2);
      else beFalta.textContent = '—';
    }
    if (beResLabel) beResLabel.textContent = pl.utilidadNeta >= 0 ? '✓ UTILIDAD NETA' : '✗ PÉRDIDA NETA';

    // Confetti + sonido al CRUZAR break-even (de no superar a superar)
    if (beCard && pl.superaBreakEven && oldFillPct > 0 && fillPctNew >= 100 &&
        !beCard.dataset._celebrado) {
      // Marcar para no repetir confetti hasta nuevo render con cambio
      beCard.dataset._celebrado = '1';
      _finBeep('breakeven');
      _finConfetiBE();
      setTimeout(() => { delete beCard.dataset._celebrado; }, 8000);
    }
    // Pulso de atención al moverse significativamente
    if (Math.abs(fillPctNew - oldFillPct) > 2 && oldFillPct > 0 && beCard) {
      beCard.style.transition = 'box-shadow 0.4s ease-out';
      beCard.style.boxShadow = pl.superaBreakEven
        ? '0 0 32px rgba(52,211,153,0.55)'
        : '0 0 32px rgba(251,191,36,0.45)';
      setTimeout(() => { beCard.style.boxShadow = ''; }, 700);
    }

    // Waterfall + pill de Utilidad Neta
    _finRenderWaterfall(pl);
    const wPill = $('finWaterUtil');
    if (wPill) {
      wPill.textContent = (pl.utilidadNeta >= 0 ? '+' : '') + 'S/ ' + parseFloat(pl.utilidadNeta || 0).toFixed(2);
      wPill.classList.toggle('up', pl.utilidadNeta >= 0);
      wPill.classList.toggle('down', pl.utilidadNeta < 0);
    }

    // Personal list
    if (!skipPersonal) {
      _finRenderPersonal(pl, fecha);
    } else {
      const tot = $('finPersonalTotal');
      if (tot) _animateCount(tot, pl.gastoPersonal || 0, { prefix: 'S/ ' });
    }
    // Subtítulo del card Personal
    const persSub = $('finPersonalSub');
    if (persSub) {
      const n = pl.personas || 0;
      persSub.textContent = n > 0 ? `${n} persona${n !== 1 ? 's' : ''} hoy` : 'Sin personal todavía';
    }

    // Gastos list (con modo slim cuando no hay)
    _finRenderGastos(pl, fecha);
  }

  function _finRenderWaterfall(pl) {
    const labels = ['Ventas', 'Costo V.', 'Util. Bruta', 'Personal', 'Gastos', 'Util. Neta'];
    // Floating bars [min, max]
    const utilBruta = pl.utilidadBruta;
    const utilNeta  = pl.utilidadNeta;
    const gastosOtros = pl.gastoOtros;
    const gastoPer  = pl.gastoPersonal;

    const data = [
      [0, pl.ventasNetas],                               // Ventas
      [utilBruta, pl.ventasNetas],                        // Costo V. (baja desde ventas)
      [0, utilBruta],                                     // Util Bruta (resultado)
      [utilBruta - gastoPer, utilBruta],                  // Personal (baja)
      [utilBruta - gastoPer - gastosOtros, utilBruta - gastoPer], // Gastos (baja)
      [0, utilNeta]                                       // Util Neta (resultado final)
    ];
    const colors = [
      '#10b981','#f87171','#34d399','#f59e0b','#fb923c',
      utilNeta >= 0 ? '#818cf8' : '#f87171'
    ];

    _finChartDeferred('finChartWaterfall', {
      type: 'bar',
      data: {
        labels,
        datasets: [{ data, backgroundColor: colors, borderRadius: 5, borderSkipped: false }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: { legend: { display: false },
          tooltip: {
            callbacks: {
              label: ctx => {
                const [min, max] = ctx.raw;
                return 'S/ ' + Math.abs(max - min).toFixed(2);
              }
            }
          }
        },
        scales: {
          x: { grid: { color: '#1e293b' }, ticks: { color: '#64748b', font: { size: 11 } } },
          y: { grid: { color: '#1e293b' }, ticks: { color: '#64748b',
               callback: v => 'S/' + v.toFixed(0) } }
        }
      }
    });
  }

  function _finRender7d(rango) {
    if (!rango || !rango.serie) return;
    const labels = rango.serie.map(d => {
      const dt = new Date(d.fecha + 'T00:00:00');
      return dt.toLocaleDateString('es-PE', { weekday:'short', day:'numeric' });
    });
    const ventas  = rango.serie.map(d => d.ventasNetas);
    const costos  = rango.serie.map(d => d.costoVentas);
    const gastos  = rango.serie.map(d => d.totalGastos);
    const util    = rango.serie.map(d => d.utilidadNeta);

    const totalUtil = rango.totales?.utilidadNeta || 0;
    const pill = $('fin7dTotal');
    if (pill) {
      pill.textContent = (totalUtil >= 0 ? '+' : '') + 'S/ ' + totalUtil.toFixed(2);
      pill.classList.toggle('up', totalUtil >= 0);
      pill.classList.toggle('down', totalUtil < 0);
    }
    _setText('fin7dSubtitulo', `Tendencia · S/ ${rango.totales?.ventasNetas?.toFixed(2) || '0'} en ventas`);

    // Mini bars row (drill-down rápido por día)
    const miniRow = $('fin7dMiniRow');
    if (miniRow) {
      const hoy = today();
      const maxAbs = Math.max.apply(null, util.map(u => Math.abs(u || 0)).concat([1]));
      miniRow.innerHTML = rango.serie.map((d, i) => {
        const u = d.utilidadNeta || 0;
        const h = Math.max(8, Math.min(28, Math.abs(u) / maxAbs * 28));
        const dt = new Date(d.fecha + 'T00:00:00');
        const dia = dt.toLocaleDateString('es-PE', { weekday:'short' });
        const cls = ['fin-7d-mini-day'];
        if (d.fecha === hoy) cls.push('today');
        if (u > 0) cls.push('profit-up');
        else if (u < 0) cls.push('profit-down');
        return `<button class="${cls.join(' ')}" onclick="MOS.finIrAFecha('${d.fecha}')" title="${d.fecha} · S/ ${u.toFixed(2)}">
          <div class="fin-7d-mini-bar" style="height:${h}px"></div>
          <div class="fin-7d-mini-lbl">${dia.slice(0,3)}</div>
        </button>`;
      }).join('');
    }

    _finChartDeferred('finChart7d', {
      type: 'bar',
      data: {
        labels,
        datasets: [
          { label: 'Ventas',    data: ventas, backgroundColor: 'rgba(16,185,129,.5)',  borderRadius: 4 },
          { label: 'Costo V.',  data: costos, backgroundColor: 'rgba(248,113,113,.5)', borderRadius: 4 },
          { label: 'Gastos',    data: gastos, backgroundColor: 'rgba(245,158,11,.5)',  borderRadius: 4 },
          { label: 'Util.Neta', data: util,   backgroundColor: 'rgba(129,140,248,.85)',borderRadius: 4, type: 'line', tension: 0.35, pointRadius: 4, fill: false }
        ]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: { legend: { labels: { color: '#64748b', boxWidth: 10, font: { size: 11 } } } },
        scales: {
          x: { stacked: false, grid: { color: '#1e293b' }, ticks: { color: '#64748b', font: { size: 10 } } },
          y: { grid: { color: '#1e293b' }, ticks: { color: '#64748b', callback: v => 'S/'+v } }
        }
      }
    });
  }

  // Clasifica rol en POS (cajero/vendedor) vs ALMACEN (almacenero/envasador) vs OTRO
  function _finClasificarRol(rol) {
    const r = String(rol || '').toUpperCase().trim();
    if (r === 'CAJERO' || r === 'VENDEDOR') return 'POS';
    if (r === 'ALMACENERO' || r === 'ENVASADOR') return 'ALMACEN';
    return 'OTRO';
  }

  function _finRenderPersonal(pl, fecha) {
    const cont = $('finPersonalList');
    const tot  = $('finPersonalTotal');
    if (!cont) return;
    // Guard de fecha: si pl es para otro día que el currently displayed,
    // descartamos. Pasaba que el render con datos cached del día previo
    // se aplicaba arriba del fresh, dejando cards stale por una visita.
    if (pl && pl._fechaStamp && pl._fechaStamp !== fecha) return;
    // Stamp del contenedor: cualquier pint posterior verifica que aún
    // estemos en la misma fecha antes de tocar el DOM.
    cont.dataset.fecha = fecha;
    if (typeof _evalState !== 'undefined' && _evalState && fecha) {
      _evalState.fecha = fecha;
    }
    if (tot) _animateCount(tot, pl.gastoPersonal || 0, { prefix: 'S/ ' });
    if (!pl.personalDetalle || !pl.personalDetalle.length) {
      cont.innerHTML = '<p class="text-slate-500 text-xs">Sin registros — usa "+ Jornada" o "⬇ Cajas"</p>';
      return;
    }

    // Agrupar por área (POS / ALMACEN / OTRO) — no confunde los KPIs
    const grupos = { POS: [], ALMACEN: [], OTRO: [] };
    pl.personalDetalle.forEach(p => {
      grupos[_finClasificarRol(p.rol)].push(p);
    });

    const cacheKey = 'mos_fin_resum_' + fecha;
    let cachedResumenes = null;
    try {
      const raw = localStorage.getItem(cacheKey);
      if (raw) {
        const pCache = JSON.parse(raw);
        if (Date.now() - (pCache.ts || 0) < 30 * 60 * 1000) cachedResumenes = pCache.data;
      }
    } catch {}

    function _renderGrupo(arr, titulo, icono, area, byNombre, byIdPersonal) {
      if (!arr.length) return '';
      // Subtotal REAL = totalDia del resumen si existe (incluye envasado +
      // bono meta − sanción). Fallback a p.monto (jornal base) cuando no
      // hay resumen todavía. Así el header del grupo cuadra con las cards.
      // VETADOS quedan FUERA (no reciben pago).
      const subtotal = arr.reduce((s, p) => {
        if (p.vetada) return s;
        const ev = byIdPersonal[p.idPersonal] || byNombre[String(p.nombre || '').toLowerCase().trim()] || null;
        const real = (ev && typeof ev.totalDia === 'number') ? ev.totalDia : (parseFloat(p.monto) || 0);
        return s + real;
      }, 0);
      return `
        <div class="fin-pers-group" data-area="${area}">
          <div class="fin-pers-group-hdr">
            <span class="fin-pers-group-ico">${icono}</span>
            <span class="fin-pers-group-tit">${titulo}</span>
            <span class="fin-pers-group-count">${arr.length}</span>
            <span class="fin-pers-group-sub">S/ ${subtotal.toFixed(2)}</span>
          </div>
          <div class="fin-pers-group-list">
            ${(() => {
              // [zona] dentro del área, ordenar por zona y separar con un divisor
              // cuando hay >1 zona (si es una sola, no mete ruido).
              const _zonaDe = (p) => { const ev = byIdPersonal[p.idPersonal] || byNombre[String(p.nombre || '').toLowerCase().trim()] || null; return String(p.zona || (ev && ev.zona) || '').trim(); };
              const zonas = new Set(arr.map(_zonaDe).filter(Boolean));
              const multi = zonas.size > 1;
              const ordenado = multi ? arr.slice().sort((a, b) => _zonaDe(a).localeCompare(_zonaDe(b))) : arr;
              let lastZ = null;
              return ordenado.map(p => {
                const ev = byIdPersonal[p.idPersonal] || byNombre[String(p.nombre || '').toLowerCase().trim()] || null;
                let div = '';
                if (multi) { const z = _zonaDe(p) || '—'; if (z !== lastZ) { lastZ = z; div = `<div style="grid-column:1/-1;font-size:11px;font-weight:700;color:#94a3b8;letter-spacing:.3px;margin:6px 2px 0">📍 ${_escapeHtml(z)}</div>`; } }
                return div + _finRenderPersonalCard(p, ev, fecha, area);
              }).join('');
            })()}
          </div>
        </div>`;
    }

    function _pintarConResumenes(resumenes) {
      // Si la fecha cambió mientras este paint estaba pendiente, abortar.
      if (cont.dataset.fecha !== fecha) return;
      const byNombre = {};
      const byIdPersonal = {};
      const arr = Array.isArray(resumenes) ? resumenes : [];
      arr.forEach(r => {
        const n = String(r.nombre || '').toLowerCase().trim();
        if (n) byNombre[n] = r;
        if (r.idPersonal) byIdPersonal[r.idPersonal] = r;
      });

      _evalState.resumenes = arr;
      _evalState.fecha = fecha;
      _evalState.byNombre = byNombre;
      _evalState.byIdPersonal = byIdPersonal;

      // [v2.41.46] Propagar VETADA desde LIQUIDACIONES_DIA → personalDetalle.
      // ÚNICA fuente de verdad: ev.liqEstado. Si no es 'VETADA', el card
      // NO debe estar enmallado, sin importar marcas históricas en
      // p.fuente='ELIMINADA' (legacy de cuando vetar llamaba eliminarJornada).
      pl.personalDetalle.forEach(p => {
        const ev = byIdPersonal[p.idPersonal] || byNombre[String(p.nombre || '').toLowerCase().trim()] || null;
        if (ev && ev.liqEstado) {
          // Backend tiene liqEstado → es autoritativo
          p.vetada = (ev.liqEstado === 'VETADA');
          if (!p.vetada && p.fuente === 'ELIMINADA') {
            // Limpiar marca histórica para que el render no la mire
            p.fuente = 'AUTO_RECOV';
          }
        }
      });

      // ── Total general REAL + propagación a KPIs del P&L ──
      // Antes pl.gastoPersonal venía del backend basado solo en JORNADAS.
      // Aquí re-calculamos totalReal con totalDia de los resúmenes (incluye
      // envasado + bono meta − sanción, excluye vetados) y ESCALAMOS hacia
      // arriba: Gasto Personal, Gastos totales, Costos Fijos, Utilidad
      // Neta, Margen Neto y Punto de Equilibrio TODOS se reconectan al
      // valor en vivo. Sin esto el break-even quedaba "frío".
      if (arr.length > 0) {
        let totalReal = 0;
        ['POS','ALMACEN','OTRO'].forEach(area => {
          (grupos[area] || []).forEach(p => {
            if (p.vetada) return; // vetados no cuentan
            const ev = byIdPersonal[p.idPersonal] || byNombre[String(p.nombre || '').toLowerCase().trim()] || null;
            const real = (ev && typeof ev.totalDia === 'number') ? ev.totalDia : (parseFloat(p.monto) || 0);
            totalReal += real;
          });
        });
        if (tot) _animateCount(tot, totalReal, { prefix: 'S/ ' });

        // Propagar al objeto pl + re-render de los KPIs dependientes
        try {
          if (typeof _finPL !== 'undefined' && _finPL && pl === _finPL) {
            const r2 = n => Math.round(n * 100) / 100;
            const gastosFijos = parseFloat(_finPL.gastosFijos) || 0;
            const gastosVariables = parseFloat(_finPL.totalGastos) - (parseFloat(_finPL.gastoPersonal) || 0) - (parseFloat(_finPL.gastosFijos) || 0);
            const otrosGastos = parseFloat(_finPL.totalGastos || 0) - (parseFloat(_finPL.gastoPersonal) || 0);
            // ── Actualizar campos derivados ──
            _finPL.gastoPersonal = r2(totalReal);
            _finPL.totalGastos   = r2(totalReal + otrosGastos);
            _finPL.costosFijos   = r2(totalReal + gastosFijos);
            const ventasNetas = parseFloat(_finPL.ventasNetas) || 0;
            const utilidadBruta = parseFloat(_finPL.utilidadBruta);
            _finPL.utilidadNeta  = r2((isFinite(utilidadBruta) ? utilidadBruta : 0) - _finPL.totalGastos);
            _finPL.margenNetoPct = ventasNetas > 0 ? r2(_finPL.utilidadNeta / ventasNetas * 100) : 0;
            const costoVentas = parseFloat(_finPL.costoVentas) || 0;
            const margenContrib = ventasNetas > 0 ? (ventasNetas - costoVentas) / ventasNetas : 0;
            _finPL.breakEvenVentas = margenContrib > 0 ? r2(_finPL.costosFijos / margenContrib) : null;
            _finPL.breakEvenPct = (_finPL.breakEvenVentas && ventasNetas > 0)
              ? r2(Math.min(_finPL.breakEvenVentas / ventasNetas * 100, 100)) : 0;
            _finPL.superaBreakEven = _finPL.breakEvenVentas !== null && ventasNetas >= _finPL.breakEvenVentas;

            // Re-render solo KPIs (skipPersonal preserva los cards que ya pintamos)
            try { _finRender(_finPL, fecha, { skipPersonal: true }); } catch(_){}
          }
        } catch(_){}
      }

      let html = '';
      html += _renderGrupo(grupos.POS,     'POS · Cajeros',        '🛒', 'POS',     byNombre, byIdPersonal);
      html += _renderGrupo(grupos.ALMACEN, 'Almacén',              '🏭', 'ALMACEN', byNombre, byIdPersonal);
      html += _renderGrupo(grupos.OTRO,    'Otros',                '👤', 'OTRO',    byNombre, byIdPersonal);
      const finalHtml = html || '<p class="text-slate-500 text-xs">Sin registros</p>';
      // Anti-flicker: si el HTML es idéntico al ya pintado, no re-escribir
      // el DOM (evita el "parpadeo" en navegación de fechas y al re-paint
      // cuando cache==fresh).
      if (cont.dataset._lastHtml === finalHtml) return;
      cont.dataset._lastHtml = finalHtml;
      cont.innerHTML = finalHtml;
    }

    _pintarConResumenes(cachedResumenes);

    // [v2.41.62] FAST: lectura plana de LIQUIDACIONES_DIA (10-20× más rápido
    // que getResumenTodosDia que recompute todo). La UI muestra los valores
    // YA persistidos (totalDia, bonificacion, sancion, estado, etc.) sin
    // depender del recompute pesado. El recompute completo (con kpis live)
    // solo se hace al abrir auditoría individual.
    // [v2.41.78] Hash rápido en vez de JSON.stringify de los resúmenes.
    API.get('getPersonalDiaFast', { fecha: fecha }).then(resumenes => {
      if (cont.dataset.fecha !== fecha) return; // ya no estamos en esta fecha
      const arr = Array.isArray(resumenes) ? resumenes : ((resumenes && resumenes.data) || []);
      try { localStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), data: arr })); } catch {}
      // [ext] cargar duplicados (mismo nombre en >1 zona hoy) para el chip 🔗; re-pinta una vez si hay.
      try {
        API.accesosDuplicados && API.accesosDuplicados({ fecha }).then(d => {
          const nd = (d && typeof d === 'object' && !Array.isArray(d)) ? d : {};
          const changed = JSON.stringify(nd) !== JSON.stringify(_finDuplicados);
          _finDuplicados = nd;
          if (changed && Object.keys(nd).length && cont.dataset.fecha === fecha) {
            try { _pintarConResumenes(_evalState.resumenes || arr); } catch(_){}
          }
        }).catch(() => {});
      } catch(_){}
      const _hashRes = (xs) => {
        if (!Array.isArray(xs)) return '';
        return xs.map(r => [r.idPersonal || r.nombre, r.totalDia, r.bonificacion, r.sancion, r.liqEstado, r.evaluacionesCount].join(',')).join('|');
      };
      if (_hashRes(cachedResumenes) !== _hashRes(arr)) {
        _pintarConResumenes(arr);
      } else {
        _evalState.resumenes = arr;
        _evalState.fecha = fecha;
      }
    }).catch(() => { /* si falla, queda lo del cache o sin score */ });
  }

  // Busca la Ultima_Conexion para una persona del Día (vendedor ME virtual o operador real).
  // Estrategia: probar todas las fuentes y devolver la fecha MÁS RECIENTE encontrada.
  // Un usuario puede tener varios dispositivos (laptop + móvil + tablet) — la idea
  // es ver su "live" general sin importar en qué dispositivo esté activo.
  //
  // Fuentes consultadas (todas se evalúan, gana la más reciente):
  //   A. PERSONAL_MASTER (personalMOS + personal) por idPersonal o nombre
  //   B. DISPOSITIVOS por Ultima_Sesion === nombre (cualquier match)
  //   C. DISPOSITIVOS por Ultima_Sesion contains primer nombre (Javier matchea "Javier Vasquez")
  function _finBuscarActividadPersonal(p, ev) {
    const idP = (ev && ev.idPersonal) || p.idPersonal || '';
    const nomBruto = String(p.nombre || (ev && ev.nombre) || '').trim();
    if (!nomBruto && !idP) return null;

    // Normalizador: lowercase + collapse múltiples espacios + trim
    const norm = s => String(s || '').toLowerCase().replace(/\s+/g, ' ').trim();
    const nomNorm = norm(nomBruto);
    const primerNombre = nomNorm.split(' ')[0]; // "javier" de "javier vasquez"

    const personasMaster = [
      ...(cfgData.personalMOS || []),
      ...(cfgData.personal || [])
    ];

    // Acumulador del timestamp más reciente encontrado (en cualquier fuente)
    let mejorIso = null;
    let mejorMs  = -Infinity;
    const _consider = (iso) => {
      if (!iso) return;
      const t = _parseTsUtc(iso);
      if (!isNaN(t) && t > mejorMs) { mejorMs = t; mejorIso = iso; }
    };

    // A. PERSONAL_MASTER por idPersonal
    if (idP) {
      const m = personasMaster.find(x => String(x.idPersonal) === String(idP));
      if (m) _consider(m.Ultima_Conexion || m.ultimaConexion || null);
    }

    // A2. PERSONAL_MASTER por nombre (combinado o solo) con tolerancia
    if (nomNorm) {
      const matches = personasMaster.filter(x => {
        const nomCompleto = norm((x.nombre || '') + ' ' + (x.apellido || ''));
        const soloNombre  = norm(x.nombre || '');
        if (!nomCompleto && !soloNombre) return false;
        return nomCompleto === nomNorm
            || soloNombre  === nomNorm
            || nomCompleto.startsWith(nomNorm + ' ')
            || nomNorm.startsWith(soloNombre + ' ')
            || nomCompleto === primerNombre
            || soloNombre  === primerNombre;
      });
      matches.forEach(m => _consider(m.Ultima_Conexion || m.ultimaConexion || null));
    }

    // B. DISPOSITIVOS por Ultima_Sesion — cualquier dispositivo cuyo último login
    //    matchee con el nombre buscado. Tomamos cualquiera que matchee, gana el más reciente.
    if (nomNorm && Array.isArray(cfgData.dispositivos)) {
      for (const d of cfgData.dispositivos) {
        const sesNorm = norm(d.Ultima_Sesion || '');
        if (!sesNorm) continue;
        const matchea =
          sesNorm === nomNorm ||                         // match exacto
          sesNorm.startsWith(nomNorm + ' ') ||           // "javier vasquez" empieza con "javier "
          nomNorm.startsWith(sesNorm + ' ') ||           // "javier vasquez" buscado, sesion "javier"
          (primerNombre && sesNorm === primerNombre) ||  // sesion === primer nombre buscado
          (primerNombre && sesNorm.startsWith(primerNombre + ' ')); // sesion empieza con primer nombre
        if (!matchea) continue;
        _consider(d.Ultima_Conexion);
      }
    }

    return mejorIso;
  }

  // [ext] duplicados del día (mismo nombre normalizado en >1 fila/zona) → data del chip 🔗
  let _finDuplicados = {};
  function _finRenderPersonalCard(p, ev, fecha, area) {
    // [v2.41.46] Única fuente de verdad: LIQUIDACIONES_DIA.estado (propagado
    // a p.vetada en _pintarConResumenes). Si por fallback no hay liqEstado
    // todavía, usar p.vetada del backend. NO mirar p.fuente='ELIMINADA'
    // (marca histórica del flujo viejo eliminarJornada).
    const esVetada = !!p.vetada;
    // ¿Tiene dispositivos encarcelados? Lookup por nombre (lowercased + trim).
    const nLowCard = String(p.nombre || '').toLowerCase().trim();
    const bloqInfo = (_finBloqueados && _finBloqueados.porNombre)
      ? _finBloqueados.porNombre[nLowCard] : null;
    const esBloqueado = !!(bloqInfo && bloqInfo.dispositivos && bloqInfo.dispositivos.length);
    // [ext] chip 🔗: el mismo nombre aparece en >1 fila/zona hoy → el admin decide
    // (fantasma / mismo movido → sanción-base / dos personas → pagar ambas).
    // [100x] clave SIN tildes para casar con mos._norm_nom del backend (lower+trim+unaccent);
    // si no, "Andrés" (JS) ≠ "andres" (SQL) → el chip no aparecía.
    const _dupKey  = nLowCard.normalize('NFD').replace(/[̀-ͯ]/g, '');
    const _dupInfo = _finDuplicados && (_finDuplicados[_dupKey] || _finDuplicados[nLowCard]);
    const dupChip = (_dupInfo && _dupInfo.length > 1)
      ? `<span class="badge-rol" style="background:rgba(245,158,11,.14);color:#fbbf24;border:1px solid rgba(245,158,11,.4);animation:finPillPulse 2s ease-in-out infinite" title="⚠ &quot;${_escapeHtml(p.nombre)}&quot; está en ${_dupInfo.length} filas hoy (${_dupInfo.map(d => _escapeHtml(d.zona || '—') + ' S/' + (parseFloat(d.venta) || 0).toFixed(0)).join(' · ')}). Decide: ¿fantasma? ¿mismo movido (sanción-base)? ¿dos personas (pagar ambas)?">🔗 ${_dupInfo.length} zonas ⚠</span>`
      : '';
    const esPOS = (area || _finClasificarRol(p.rol)) === 'POS';
    const score = ev ? (ev.scoreFinal || 0) : null;
    const scoreClass = score !== null ? _evalScoreClass(score) : '';
    const rolClass = _evalRolBadgeClass(p.rol || (ev && ev.rol));
    const evalCount = ev ? (ev.evaluacionesCount || 0) : 0;
    const kpiTxt = ev ? _evalKpiSummary(ev, p.rol) : '';
    // Vetado: NO recibe pago, NO se audita, NO entra a la liquidación
    const totalDia = esVetada ? 0 : ((ev && ev.totalDia) ? ev.totalDia : (parseFloat(p.monto) || 0));
    const idForEval = esVetada ? '' : ((ev && ev.idPersonal) || p.idPersonal || '');
    // [v2.43.376 · una sola fuente] id_personal de la MEGA TABLA (mos.liquidaciones_dia, vía
    // getPersonalDiaFast) para vetar/desvetar — el MISMO que usa la pestaña Liquidación.
    const idMega = (ev && ev.idPersonal) || p.idPersonal || '';
    const fuenteTag = p.fuente === 'AUTO_VENTA' ? '<span class="fin-tag fin-tag-green ml-1" title="Detectado por venta">auto</span>'
                    : p.fuente === 'AUTO_LOGIN' ? '<span class="fin-tag fin-tag-green ml-1" title="Detectado por sesión">auto</span>'
                    : p.fuente === 'AUTO_CAJAS' ? '<span class="fin-tag fin-tag-green ml-1" title="Importado de cajas">auto</span>'
                    : '';
    // Indicador online: dot pulsante sobre el avatar si Ultima_Conexion < 5min
    const ultCx = _finBuscarActividadPersonal(p, ev);
    const act = _personaActividad(ultCx);
    const isFresh = act.minutos < 5;
    const dotPulse = isFresh ? '<span class="fin-pers-dot-pulse" title="🔴 LIVE — '+act.label+'"></span>' : '';
    const ringCls = isFresh ? ' fin-pers-avatar-live' : '';
    const innerScore = score !== null
      ? `<div class="eval-score-circle ${scoreClass}" style="--score:${score};"><span>${score}%</span></div>`
      : `<div class="w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold" style="background:rgba(100,116,139,.15);color:#94a3b8">—</div>`;
    const scoreCircle = `<div class="fin-pers-avatar-wrap${ringCls}" style="position:relative;flex-shrink:0;"
      title="${isFresh ? '🟢 ' + act.label : (ultCx ? '⚫ ' + act.label : '')}"
      >${innerScore}${dotPulse}</div>`;
    // [v2.41.50] PAGADA = liquidación ya cerrada → sello verde no editable
    const esPagada = !esVetada && (ev && ev.liqEstado === 'PAGADA') || (p.liqEstado === 'PAGADA');
    const vetadaCls = esVetada ? ' fin-vetada-card' : '';
    const pagadaCls = esPagada ? ' fin-pagada-card' : '';
    const bloqCls   = esBloqueado ? ' fin-bloq-card' : '';
    const vetadaOverlay = esVetada
      ? `<div class="fin-vetada-overlay">
           <div class="fin-vetada-stripe"></div>
           <div class="fin-vetada-badge">💸 VETADA · S/ 0.00</div>
         </div>`
      : '';
    const pagadaOverlay = esPagada
      ? `<div class="fin-pagada-overlay">
           <div class="fin-pagada-stripe"></div>
           <div class="fin-pagada-sello">✓ PAGADA · S/ ${parseFloat((ev && ev.totalDia) || p.monto || 0).toFixed(2)}</div>
         </div>`
      : '';
    // Overlay de rejas persistente: si el usuario tiene devices encarcelados.
    // Se renderiza dentro del template (no como inyección DOM temporal) para
    // sobrevivir cualquier re-render del card. Combinable con veto.
    const bloqOverlay = esBloqueado
      ? `<div class="fin-rejas-overlay fin-rejas-persist">
           <div class="fin-rejas-bars">
             <div class="fin-rejas-bar"></div>
             <div class="fin-rejas-bar"></div>
             <div class="fin-rejas-bar"></div>
             <div class="fin-rejas-bar"></div>
             <div class="fin-rejas-bar"></div>
             <div class="fin-rejas-bar"></div>
           </div>
           <div class="fin-rejas-badge">🔒 BLOQUEADO · ${bloqInfo.dispositivos.length} disp.</div>
           <div class="fin-rejas-sub">${_escapeHtml(p.nombre)}</div>
         </div>`
      : '';
    return `
      <div class="eval-card${vetadaCls}${pagadaCls}${bloqCls}" data-id="${idForEval}" style="position:relative;">
        ${vetadaOverlay}
        ${pagadaOverlay}
        ${bloqOverlay}
        <div class="flex items-center gap-3">
          ${scoreCircle}
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-2 mb-1 flex-wrap">
              <div class="font-semibold text-slate-100 text-sm truncate">${_escapeHtml(p.nombre)}</div>
              <span class="badge-rol ${rolClass}">${_escapeHtml(p.rol || (ev && ev.rol) || '—')}</span>
              ${ev && ev.virtual ? '<span class="badge-rol badge-rol-default" title="Detectado del sistema">⚡ del sistema</span>' : ''}
              ${fuenteTag}
              ${dupChip}
            </div>
            ${kpiTxt ? `<div class="text-xs text-slate-500 mb-1">${kpiTxt}</div>` : ''}
            <div class="flex items-center gap-2 flex-wrap">
              ${evalCount > 0
                ? `<span class="audit-count-pill">${evalCount} auditoría${evalCount !== 1 ? 's' : ''}</span>`
                : `<span class="audit-count-pill" style="background:rgba(245,158,11,.12);color:#fbbf24;border-color:rgba(245,158,11,.3)">⚠ Sin auditar</span>`}
              ${(() => {
                // [v2.41.77] Pill de última actividad visible siempre.
                // Verde <5min (LIVE), verde claro <60min, amarillo <24h, naranja <7d, rojo +7d.
                if (!ultCx) return '<span class="audit-count-pill" style="background:rgba(100,116,139,.12);color:#94a3b8;border-color:rgba(100,116,139,.3)" title="Sin actividad registrada">⚫ sin actividad</span>';
                const bg = `rgba(${act.color === '#10b981' ? '16,185,129' : act.color === '#fbbf24' ? '251,191,36' : act.color === '#f97316' ? '249,115,22' : '239,68,68'},.14)`;
                const bd = `rgba(${act.color === '#10b981' ? '16,185,129' : act.color === '#fbbf24' ? '251,191,36' : act.color === '#f97316' ? '249,115,22' : '239,68,68'},.4)`;
                const pulse = isFresh ? ' style="animation:finPillPulse 1.4s ease-in-out infinite"' : '';
                return `<span class="audit-count-pill"${pulse} style="background:${bg};color:${act.color};border-color:${bd}" title="Última actividad detectada">${act.dot} ${_escapeHtml(act.label)}</span>`;
              })()}
              <span class="text-xs text-slate-400">Pago día: <strong class="text-amber-400">S/ ${parseFloat(totalDia).toFixed(2)}</strong></span>
            </div>
            ${(() => {
              // [v2.41.66] Mostrar motivos de bonificación/sanción debajo del pago
              const bon = ev && parseFloat(ev.bonificacion) || 0;
              const san = ev && parseFloat(ev.sancion) || 0;
              const bonMot = (ev && ev.bonificacionMotivo) || '';
              const sanMot = (ev && ev.sancionMotivo) || '';
              const partes = [];
              if (bon > 0) partes.push(`<span style="color:#34d399;font-weight:700">🎁 +S/${bon.toFixed(2)}</span>${bonMot ? `<span style="color:#94a3b8"> · ${_escapeHtml(bonMot.substring(0, 60))}</span>` : ''}`);
              if (san > 0) partes.push(`<span style="color:#f87171;font-weight:700">⚠ -S/${san.toFixed(2)}</span>${sanMot ? `<span style="color:#94a3b8"> · ${_escapeHtml(sanMot.substring(0, 60))}</span>` : ''}`);
              return partes.length
                ? `<div class="text-[11px] mt-1" style="line-height:1.3">${partes.join(' · ')}</div>`
                : '';
            })()}
          </div>
          <div class="flex flex-col gap-1 shrink-0 items-end">
            <div class="flex gap-1 mb-0.5">
              <button onclick="event.stopPropagation();MOS.abrirEspiaPorUsuario('${_escAttrJs(p.nombre || '')}')"
                class="w-7 h-7 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                style="background:rgba(99,102,241,0.18);border:1px solid rgba(99,102,241,0.5);color:#a5b4fc;font-size:11px;"
                title="Espiar a ${_escapeHtml(p.nombre)} (audio + GPS)">🕵️</button>
            </div>
            ${idForEval ? `<button onclick="MOS.abrirAuditar('${idForEval}')" class="btn-primary text-xs whitespace-nowrap px-3 py-1.5">Auditar</button>` : ''}
            <div class="flex gap-1 mt-1">
              ${esBloqueado
                ? `<button onclick="event.stopPropagation();MOS.finLiberarDispositivosUsuario('${_escAttrJs(p.nombre || '')}')"
                    class="w-7 h-7 rounded-md flex items-center justify-center hover:scale-110 transition-all"
                    style="background:rgba(34,197,94,0.18);border:1px solid rgba(34,197,94,0.55);color:#86efac;font-size:12px;position:relative;z-index:10;"
                    title="🔓 Liberar dispositivo(s) bloqueado(s) — requiere clave admin">🔓</button>`
                : `<button onclick="event.stopPropagation();MOS.finBloquearUsuario('${_escAttrJs(p.nombre || '')}','${(ev && ev.appOrigen) || p.appOrigen || ''}','${(ev && ev.idPersonal) || p.idPersonal || ''}')"
                    class="w-7 h-7 rounded-md flex items-center justify-center hover:scale-110 transition-all"
                    style="background:rgba(245,158,11,0.12);border:1px solid rgba(245,158,11,0.5);color:#fbbf24;font-size:12px;position:relative;z-index:10;"
                    title="🔒 Bloquear dispositivo (pantalla de candado en su tablet/celular)">🔒</button>`}
              ${esVetada
                ? `<button onclick="event.stopPropagation();MOS.finRehabilitarPago('${p.idJornada || ''}','${fecha}','${_escAttrJs(p.nombre || '')}','${idMega}')"
                    class="w-7 h-7 rounded-md flex items-center justify-center hover:scale-110 transition-all"
                    style="background:rgba(34,197,94,0.15);border:1px solid rgba(34,197,94,0.55);color:#86efac;font-size:12px;position:relative;z-index:10;"
                    title="💵 Rehabilitar pago (revierte el veto y restaura el monto)">💵</button>`
                : `<button onclick="event.stopPropagation();MOS.finVetarPago('${p.idJornada || ''}','${fecha}','${_escAttrJs(p.nombre || '')}','${idMega}')"
                    class="w-7 h-7 rounded-md flex items-center justify-center hover:scale-110 transition-all"
                    style="background:rgba(168,85,247,0.12);border:1px solid rgba(168,85,247,0.5);color:#c084fc;font-size:12px;position:relative;z-index:10;"
                    title="💸 Vetar del pago de hoy (sigue operando, pero no se contará en gastos)">💸</button>`}
            </div>
          </div>
        </div>
      </div>`;
  }

  function _finRenderGastos(pl, fecha) {
    const listEl  = $('finGastosList');
    const categEl = $('finGastosCateg');
    const totEl   = $('finGastosTotal');
    const subEl   = $('finGastosSub');
    if (!listEl) return;
    const totalGastos = parseFloat(pl.gastoOtros || 0);
    if (totEl) totEl.textContent = 'S/ ' + totalGastos.toFixed(2);

    const cantidad = (pl.gastosDetalle || []).length;
    const tieneGastos = cantidad > 0;

    // Modo SLIM cuando no hay gastos: card mínimo, sub-text invitando
    if (!tieneGastos) {
      if (subEl) subEl.textContent = 'Sin gastos hoy · click en + para agregar';
      listEl.classList.add('hidden');
      categEl?.classList.add('hidden');
      listEl.innerHTML = '';
      if (categEl) categEl.innerHTML = '';
      return;
    }

    // Modo EXPANDIDO con gastos
    if (subEl) subEl.textContent = `${cantidad} gasto${cantidad !== 1 ? 's' : ''} registrado${cantidad !== 1 ? 's' : ''}`;
    listEl.classList.remove('hidden');
    categEl?.classList.remove('hidden');

    if (categEl) {
      const cats = pl.gastosByCategoria || {};
      const keys = Object.keys(cats);
      categEl.innerHTML = keys.length ? keys.map(cat => `
        <div class="flex justify-between text-xs">
          <span class="text-slate-400">${cat}</span>
          <span class="text-slate-200 font-semibold">S/ ${cats[cat].toFixed(2)}</span>
        </div>`).join('') : '';
    }
    const tagColor = t => t === 'FIJO' ? 'fin-tag-amber' : 'fin-tag-green';
    listEl.innerHTML = '<div class="border-t border-slate-800 pt-2 mt-1">' +
      pl.gastosDetalle.map(g => `
        <div class="fin-row">
          <div>
            <div class="text-slate-200 text-sm">${g.descripcion || '—'}</div>
            <div class="text-xs text-slate-500">${g.categoria || ''} <span class="fin-tag ${tagColor(g.tipo)} ml-1">${g.tipo||'VAR'}</span> ${g.comprobante ? '· ' + g.comprobante : ''}</div>
          </div>
          <div class="flex items-center gap-2 shrink-0">
            <span class="text-amber-400 font-semibold text-sm">S/ ${parseFloat(g.monto||0).toFixed(2)}</span>
            <button class="fin-del" onclick="MOS.finEliminarGasto('${g.idGasto || ''}','${fecha}')" title="Eliminar">×</button>
          </div>
        </div>`).join('') +
      '</div>';
  }

  // ── Modales ──────────────────────────────────────────────────
  function finAbrirModalGasto() {
    const f = $('finFecha')?.value || today();
    const inp = $('finGastoFecha'); if (inp) inp.value = f;
    const m = $('modalFinGasto'); if (m) { m.classList.remove('hidden'); m.classList.add('open'); }
  }

  function finAbrirModalJornada() {
    const f = $('finFecha')?.value || today();
    const inp = $('finJorFecha'); if (inp) inp.value = f;
    const m = $('modalFinJornada'); if (m) { m.classList.remove('hidden'); m.classList.add('open'); }
  }

  function cerrarModalFin(id) {
    const m = $(id); if (m) { m.classList.add('hidden'); m.classList.remove('open'); }
  }

  async function finGuardarGasto() {
    const monto = parseFloat($('finGastoMonto')?.value);
    const desc  = $('finGastoDesc')?.value?.trim();
    const categ = $('finGastoCateg')?.value;
    const tipo  = $('finGastoTipo')?.value;
    const fecha = $('finGastoFecha')?.value;
    const comp  = $('finGastoComp')?.value?.trim();
    if (!monto || monto <= 0) { _finBeep('error'); toast('Ingresa un monto válido', 'error'); return; }
    if (!desc)                { _finBeep('error'); toast('Ingresa una descripción', 'error'); return; }
    // Sonido optimista al click confirmar
    _finBeep('agregar');
    try {
      await API.post('registrarGasto', {
        fecha, categoria: categ, tipo, descripcion: desc,
        monto, comprobante: comp, registradoPor: S.session?.nombre || ''
      });
      cerrarModalFin('modalFinGasto');
      toast(`💰 Gasto registrado · S/ ${parseFloat(monto).toFixed(2)} · ${desc}`, 'ok', 4000);
      finCargar();
    } catch(e) {
      _finBeep('error');
      toast('Error: ' + e.message, 'error');
    }
  }

  async function finGuardarJornada() {
    const nombre = $('finJorNombre')?.value?.trim();
    const monto  = parseFloat($('finJorMonto')?.value);
    const fecha  = $('finJorFecha')?.value;
    const rol    = $('finJorRol')?.value?.trim();
    const zona   = $('finJorZona')?.value?.trim();
    const obs    = $('finJorObs')?.value?.trim();
    if (!nombre)             { toast('Ingresa el nombre del trabajador', 'error'); return; }
    if (!monto || monto <= 0){ toast('Ingresa un jornal válido', 'error'); return; }
    try {
      await API.post('registrarJornada', {
        fecha, nombre, rol, zona, montoJornal: monto, observacion: obs,
        appOrigen: 'MOS', registradoPor: S.session?.nombre || ''
      });
      cerrarModalFin('modalFinJornada');
      toast('Jornada registrada', 'ok');
      finCargar();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  async function finEliminarGasto(idGasto, fecha) {
    if (!idGasto) return;
    if (!await _modalConfirm('¿Eliminar este gasto?', { danger: true, titulo: 'Eliminar gasto', okText: 'Eliminar' })) return;
    try {
      await API.post('eliminarGasto', { idGasto });
      toast('Gasto eliminado', 'ok');
      finCargar();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  // Veto de pago — la persona sigue operando, pero no se cuenta su jornada en esta fecha.
  // El card NO se elimina: queda con efecto vetada (violeta + tachado + badge). Si el sistema
  // detecta actividad POSTERIOR al veto (nuevo ticket/sesión), reaparece automáticamente.
  // [v2.41.45] SIMPLIFICADO — vetar = SOLO cambiar estado en LIQUIDACIONES_DIA.
  // Antes había 2 flujos confusos (eliminarJornada + vetarLiquidacionDia).
  // Ahora ambos botones (🚫 Liquidaciones y 💸 Personal Día) hacen exactamente
  // lo mismo: marcar VETADA en la hoja. Una fuente de verdad. Cero confusión.
  async function finVetarPago(idJornada, fecha, nombre, idMega) {
    const fechaTxt = _formatFechaCorta(fecha);
    // [v2.43.386] Vetar = retiene pago (DINERO) → exige clave admin SIEMPRE (sin cache),
    // EL MISMO gate que el lado de Liquidaciones. Antes era _modalConfirm sin clave →
    // inconsistente ("uno pide clave y otro no").
    const _vAuth = await pedirAuth({
      accion: 'VETAR_LIQUIDACION', allowCache: false,
      refDocumento: (idMega || idJornada || '') + '|' + fecha,
      contexto: `Vetar pago de ${nombre || 'esta persona'} · ${fechaTxt}`
    });
    if (!_vAuth) return;

    // SONIDO OPTIMISTA: dispara INMEDIATO al confirmar (sincronizado con el click).
    // Si después falla el back, sonará 'error'.
    _finBeep('veto');

    // [v2.43.382] Localizar la card por idMega (confiable y único). idJornada está vacío en
    // estas filas → [onclick*=""] matcheaba cualquier card (cruce de overlay).
    const _claveCardV = idMega || idJornada || '__nope__';
    const card = Array.from(document.querySelectorAll('.eval-card')).find(el => {
      return !!el.querySelector(`button[onclick*="finVetarPago"][onclick*="${_claveCardV}"]`);
    });

    let pagoEliminado = 0;
    if (_finPL && Array.isArray(_finPL.personalDetalle)) {
      const idx = _finPL.personalDetalle.findIndex(p => (idMega && String(p.idPersonal) === String(idMega)) || (idJornada && String(p.idJornada) === String(idJornada)));
      if (idx >= 0) {
        const p = _finPL.personalDetalle[idx];
        const resKey = 'mos_fin_resum_' + fecha;
        let ev = null;
        try {
          const raw = localStorage.getItem(resKey);
          if (raw) {
            const parsed = JSON.parse(raw);
            if (Array.isArray(parsed.data)) {
              ev = parsed.data.find(r =>
                (r.idPersonal && r.idPersonal === p.idPersonal) ||
                (String(r.nombre || '').toLowerCase().trim() === String(p.nombre || '').toLowerCase().trim())
              );
            }
          }
        } catch {}
        pagoEliminado = (ev && ev.totalDia) ? parseFloat(ev.totalDia) : (parseFloat(p.monto) || 0);
        // Marcar como vetada en _finPL (no remover del array → el card persiste en próximos render)
        p.vetada = true;
        p.monto = 0;
        p.fuente = 'ELIMINADA';
        p.vetoTs = Date.now();
        // Recalcular P&L local
        _finPL.personas = Math.max(0, (_finPL.personas || 1) - 1);
        _finPL.gastoPersonal = Math.max(0, (parseFloat(_finPL.gastoPersonal) || 0) - pagoEliminado);
        _finPL.totalGastos   = Math.max(0, (parseFloat(_finPL.totalGastos) || 0) - pagoEliminado);
        _finPL.utilidadNeta  = (parseFloat(_finPL.utilidadNeta) || 0) + pagoEliminado;
        _finPL.costosFijos   = Math.max(0, (parseFloat(_finPL.costosFijos) || 0) - pagoEliminado);
        const ventas = parseFloat(_finPL.ventasNetas) || 0;
        const costoV = parseFloat(_finPL.costoVentas) || 0;
        const mc = ventas > 0 ? (ventas - costoV) / ventas : 0;
        _finPL.margenContribPct = ventas > 0 ? +(mc * 100).toFixed(2) : 0;
        _finPL.breakEvenVentas  = mc > 0 ? +(_finPL.costosFijos / mc).toFixed(2) : null;
        _finPL.breakEvenPct     = (_finPL.breakEvenVentas && ventas > 0)
          ? +Math.min(_finPL.breakEvenVentas / ventas * 100, 100).toFixed(2) : 0;
        _finPL.superaBreakEven  = _finPL.breakEvenVentas !== null && ventas >= _finPL.breakEvenVentas;
        _finPL.margenNetoPct    = ventas > 0 ? +(_finPL.utilidadNeta / ventas * 100).toFixed(2) : 0;
      }
    }

    // Aplicar efecto vetada al card (in-place, sin re-render)
    if (card) _aplicarVetadaOverlay(card, nombre, pagoEliminado);

    // Re-render solo KPIs (skipPersonal preserva el card y su animación)
    if (_finPL) {
      try { _finRender(_finPL, fecha, { skipPersonal: true }); } catch {}
    }

    // [v2.41.45] ÚNICA acción: vetar en LIQUIDACIONES_DIA. Sin eliminarJornada.
    // El render del Personal del Día lee el estado VETADA desde la hoja
    // (cruce backend en getResumenTodosDia) → overlay aparece consistente.
    const persona = (_finPL?.personalDetalle || []).find(p => (idMega && String(p.idPersonal) === String(idMega)) || (idJornada && String(p.idJornada) === String(idJornada)));
    // [v2.43.376 · una sola fuente] idPersonal de la MEGA TABLA (lo pasa la card desde
    // ev.idPersonal = getPersonalDiaFast/liquidaciones_dia) — el MISMO id que usa Liquidación.
    const idPersonal = idMega || persona?.idPersonal;
    if (!idPersonal) {
      toast('No se puede vetar: persona sin idPersonal', 'warn');
      _finBeep('error');
      return;
    }
    // [v2.41.52] FIX OPTIMISMO: API.post devuelve d.data (undefined si backend
    // retorna {ok:true} sin data). El check viejo "if(!r||r.ok===false)" caía
    // en falso negativo, revertía el overlay y daba sensación de no-optimista.
    // Ahora: si await resuelve = éxito. Errores reales caen al catch(e) via
    // _fetch que tira throw cuando d.ok=false. (e.message = error key).
    try {
      await API.post('vetarLiquidacionDia', {
        idPersonal: idPersonal,
        fecha: fecha, claveAdmin: (_vAuth && _vAuth.clave) || '',
        localId: 'L' + Date.now() + Math.random().toString(36).slice(2, 8)
      });
      // Mantener el overlay aplicado y P&L local
      if (persona) persona.vetada = true;
      // Invalidar cache local del Personal Día y Liquidaciones
      try {
        const resKey = 'mos_fin_resum_' + fecha;
        const raw = localStorage.getItem(resKey);
        if (raw) {
          const parsed = JSON.parse(raw);
          if (Array.isArray(parsed.data)) {
            parsed.data.forEach(rr => {
              if (rr.idPersonal === idPersonal) rr.vetada = true;
            });
            localStorage.setItem(resKey, JSON.stringify(parsed));
          }
        }
      } catch(_){}
      try { _liqCacheClear && _liqCacheClear(); } catch(_){}
      // Optimista en liq state
      try {
        if (_liqState && Array.isArray(_liqState.pendientes)) {
          const pLocal = _liqState.pendientes.find(x => x.idPersonal === idPersonal);
          if (pLocal) {
            pLocal.dias = pLocal.dias.filter(d => d.fecha !== fecha);
            pLocal.cantidadDias = pLocal.dias.length;
            pLocal.total = Math.round(pLocal.dias.reduce((s, d) => s + d.totalDia, 0) * 100) / 100;
            if (!pLocal.dias.length) {
              _liqState.pendientes = _liqState.pendientes.filter(p => p !== pLocal);
            }
          }
        }
      } catch(_){}
      toast(`💸 Vetado · ${nombre || ''} · -S/ ${pagoEliminado.toFixed(2)} · ahora aparece 💵 para rehabilitar`, 'ok', 4500);
      // Reemplazar card tras animación
      setTimeout(() => _finReemplazarCardJornada(idJornada, fecha, idMega), 720);
    } catch(e) {
      _finBeep('error');
      if (card) {
        const ov = card.querySelector('.fin-vetada-overlay');
        if (ov) ov.remove();
        card.classList.remove('fin-vetada-card');
      }
      const errKey = (e && e.message) || 'error';
      let msg;
      if (errKey === 'YA_PAGADA') msg = 'Esta liquidación ya está PAGADA — no se puede vetar.';
      else msg = 'No se pudo vetar: ' + errKey;
      toast(msg, 'error', 5000);
      // Rollback del P&L local (revertir el descuento ya aplicado)
      if (persona) {
        persona.vetada = false;
        persona.monto = pagoEliminado;
        persona.fuente = persona.fuente === 'ELIMINADA' ? 'MANUAL' : persona.fuente;
        delete persona.vetoTs;
        if (_finPL) {
          _finPL.personas = (_finPL.personas || 0) + 1;
          _finPL.gastoPersonal = (parseFloat(_finPL.gastoPersonal) || 0) + pagoEliminado;
          _finPL.totalGastos   = (parseFloat(_finPL.totalGastos) || 0) + pagoEliminado;
          _finPL.utilidadNeta  = (parseFloat(_finPL.utilidadNeta) || 0) - pagoEliminado;
          _finPL.costosFijos   = (parseFloat(_finPL.costosFijos) || 0) + pagoEliminado;
          try { _finRender(_finPL, fecha, { skipPersonal: true }); } catch {}
        }
      }
    }
  }

  function _formatFechaCorta(fecha) {
    if (!fecha) return 'hoy';
    const hoy = (typeof today === 'function') ? today() : new Date().toISOString().slice(0, 10);
    if (fecha === hoy) return 'hoy (' + fecha + ')';
    try {
      const d = new Date(fecha + 'T00:00:00');
      return d.toLocaleDateString('es-PE', { day: '2-digit', month: 'long', year: 'numeric' });
    } catch { return fecha; }
  }

  // Aplica overlay vetada al card (violeta + tachado + badge "💸 VETADA")
  function _aplicarVetadaOverlay(card, nombre, monto) {
    if (!card || card.querySelector('.fin-vetada-overlay')) return;
    card.classList.add('fin-vetada-card');
    card.style.position = 'relative';
    const ov = document.createElement('div');
    ov.className = 'fin-vetada-overlay';
    ov.innerHTML = `
      <div class="fin-vetada-stripe"></div>
      <div class="fin-vetada-badge">💸 VETADA · -S/ ${parseFloat(monto || 0).toFixed(2)}</div>`;
    card.appendChild(ov);
    // Pulso violeta breve
    card.style.transition = 'box-shadow 0.4s, transform 0.4s';
    card.style.boxShadow = '0 0 24px rgba(168,85,247,0.45)';
    setTimeout(() => { card.style.boxShadow = ''; }, 700);
  }

  // Alias por compatibilidad con código viejo
  const finEliminarJornada = finVetarPago;

  // Rehabilita el veto: animación de "rejas suben" del overlay vetada,
  // restaura monto, recalcula KPIs locales, y persiste en GAS.
  async function finRehabilitarPago(idJornada, fecha, nombre, idMega) {
    const fechaTxt = _formatFechaCorta(fecha);
    // [v2.43.386] Rehabilitar = restituye pago (DINERO) → clave admin SIEMPRE, EL MISMO
    // gate que Liquidaciones (antes _modalConfirm sin clave).
    const _dAuth = await pedirAuth({
      accion: 'DESVETAR_LIQUIDACION', allowCache: false,
      refDocumento: (idMega || idJornada || '') + '|' + fecha,
      contexto: `Rehabilitar pago de ${nombre || 'esta persona'} · ${fechaTxt}`
    });
    if (!_dAuth) return;

    // SONIDO OPTIMISTA: dispara INMEDIATO al confirmar.
    _finBeep('rehab');

    // [v2.43.382] Localizar la card por idMega (id de la mega tabla, confiable y único por
    // persona). Antes usaba idJornada que en estas filas está VACÍO → [onclick*=""] matcheaba
    // CUALQUIER card → quitaba el enmallado de la equivocada (Jorgenis seguía enmallado).
    const _claveCard = idMega || idJornada || '__nope__';
    const card = Array.from(document.querySelectorAll('.eval-card')).find(el => {
      return !!el.querySelector(`button[onclick*="finRehabilitarPago"][onclick*="${_claveCard}"]`);
    });

    // Calcular monto a restaurar (mejor desde PERSONAL_MASTER cache, fallback p.monto)
    let montoRestaurar = 0;
    let pTarget = null;
    if (_finPL && Array.isArray(_finPL.personalDetalle)) {
      pTarget = _finPL.personalDetalle.find(p => (idMega && String(p.idPersonal) === String(idMega)) || (idJornada && String(p.idJornada) === String(idJornada)));
      if (pTarget) {
        // Si el cache tiene resumen con totalDia, usarlo
        const resKey = 'mos_fin_resum_' + fecha;
        try {
          const raw = localStorage.getItem(resKey);
          if (raw) {
            const parsed = JSON.parse(raw);
            if (Array.isArray(parsed.data)) {
              const ev = parsed.data.find(r =>
                (r.idPersonal && r.idPersonal === pTarget.idPersonal) ||
                (String(r.nombre || '').toLowerCase().trim() === String(pTarget.nombre || '').toLowerCase().trim())
              );
              if (ev && ev.totalDia) montoRestaurar = parseFloat(ev.totalDia);
            }
          }
        } catch {}
        if (!montoRestaurar) {
          // Buscar montoBase en personal (cfgData o S._cajeros)
          try {
            const personal = (S._personal || []).concat(cfgData?.personal || []);
            const match = personal.find(x =>
              (x.idPersonal && x.idPersonal === pTarget.idPersonal) ||
              String(x.nombre || '').toLowerCase().trim() === String(pTarget.nombre || '').toLowerCase().trim()
            );
            if (match) montoRestaurar = parseFloat(match.montoBase || 0);
          } catch {}
        }
      }
    }

    // Animación: rejas/overlay suben con fade-out
    if (card) {
      const ov = card.querySelector('.fin-vetada-overlay');
      if (ov) {
        ov.style.transition = 'transform 0.45s cubic-bezier(0.4,0,0.2,1), opacity 0.4s ease-out, filter 0.4s';
        ov.style.transform = 'translateY(-100%)';
        ov.style.opacity = '0';
        ov.style.filter = 'blur(3px)';
        setTimeout(() => ov.remove(), 460);
      }
      card.classList.remove('fin-vetada-card');
      // Pulso verde breve indica rehabilitación
      card.style.transition = 'box-shadow 0.4s, transform 0.4s';
      card.style.boxShadow = '0 0 28px rgba(34,197,94,0.5)';
      setTimeout(() => { card.style.boxShadow = ''; }, 800);
    }

    // Update _finPL en memoria (revertir veto)
    if (pTarget) {
      pTarget.vetada = false;
      pTarget.fuente = 'MANUAL';
      pTarget.monto = montoRestaurar || pTarget.monto || 0;
      delete pTarget.vetoTs;
      // Recalcular P&L local (suma de vuelta el monto)
      const m = parseFloat(pTarget.monto) || 0;
      _finPL.personas = (parseInt(_finPL.personas, 10) || 0) + 1;
      _finPL.gastoPersonal = (parseFloat(_finPL.gastoPersonal) || 0) + m;
      _finPL.totalGastos   = (parseFloat(_finPL.totalGastos) || 0) + m;
      _finPL.utilidadNeta  = (parseFloat(_finPL.utilidadNeta) || 0) - m;
      _finPL.costosFijos   = (parseFloat(_finPL.costosFijos) || 0) + m;
      const ventas = parseFloat(_finPL.ventasNetas) || 0;
      const costoV = parseFloat(_finPL.costoVentas) || 0;
      const mc = ventas > 0 ? (ventas - costoV) / ventas : 0;
      _finPL.margenContribPct = ventas > 0 ? +(mc * 100).toFixed(2) : 0;
      _finPL.breakEvenVentas  = mc > 0 ? +(_finPL.costosFijos / mc).toFixed(2) : null;
      _finPL.breakEvenPct     = (_finPL.breakEvenVentas && ventas > 0)
        ? +Math.min(_finPL.breakEvenVentas / ventas * 100, 100).toFixed(2) : 0;
      _finPL.superaBreakEven  = _finPL.breakEvenVentas !== null && ventas >= _finPL.breakEvenVentas;
      _finPL.margenNetoPct    = ventas > 0 ? +(_finPL.utilidadNeta / ventas * 100).toFixed(2) : 0;
    }

    // Re-render KPIs sin tocar el card (preserva animación)
    if (_finPL) {
      try { _finRender(_finPL, fecha, { skipPersonal: true }); } catch {}
    }

    // [v2.41.45] ÚNICA acción: desvetar en LIQUIDACIONES_DIA.
    // [v2.43.376 · una sola fuente] idPersonal de la MEGA TABLA (lo pasa la card).
    const persona = (_finPL?.personalDetalle || []).find(p => (idMega && String(p.idPersonal) === String(idMega)) || (idJornada && String(p.idJornada) === String(idJornada)));
    const idPersonal = idMega || persona?.idPersonal;
    if (!idPersonal) {
      toast('No se puede rehabilitar: persona sin idPersonal', 'warn');
      _finBeep('error');
      return;
    }
    // [v2.41.52] Mismo fix: confiar en resolve = éxito.
    try {
      await API.post('desvetarLiquidacionDia', {
        idPersonal: idPersonal,
        fecha: fecha, claveAdmin: (_dAuth && _dAuth.clave) || '',
        localId: 'L' + Date.now() + Math.random().toString(36).slice(2, 8)
      });
      if (persona) persona.vetada = false;
      // Invalidar cache local
      try {
        const resKey = 'mos_fin_resum_' + fecha;
        const raw = localStorage.getItem(resKey);
        if (raw) {
          const parsed = JSON.parse(raw);
          if (Array.isArray(parsed.data)) {
            parsed.data.forEach(rr => {
              if (rr.idPersonal === idPersonal) rr.vetada = false;
            });
            localStorage.setItem(resKey, JSON.stringify(parsed));
          }
        }
      } catch(_){}
      try { _liqCacheClear && _liqCacheClear(); } catch(_){}
      toast(`💵 Rehabilitado · ${nombre || ''} · +S/ ${parseFloat(montoRestaurar || 0).toFixed(2)} · ahora aparece 💸 para vetar`, 'ok', 4500);
      setTimeout(() => _finReemplazarCardJornada(idJornada, fecha, idMega), 480);
    } catch(e) {
      _finBeep('error');
      toast('Error: ' + e.message + ' — recargando...', 'error');
      finCargar();
    }
  }

  // ════════════════════════════════════════════════════════════
  // BLOQUEO DE DISPOSITIVO — pantalla de candado en ME / WH
  // Visualmente: efecto de rejas cayendo sobre la card.
  // ════════════════════════════════════════════════════════════
  async function finBloquearUsuario(nombre, appOrigen, idPersonal) {
    if (!nombre) return;
    const apoyo = (appOrigen || '').toLowerCase().indexOf('warehouse') >= 0
      ? 'tablet/celular WH'
      : 'POS de MosExpress';
    // [v2.41.83] AdminAuthModal (antes solo confirm()) — tier 2 cache 5min
    const auth = await pedirAuth({
      accion: 'BLOQUEAR_DISPOSITIVO',
      refDocumento: nombre,
      contexto: `Encarcelar dispositivos de ${nombre} (${apoyo}). Aparecerá candado en <30s.`
    });
    if (!auth) return;

    _finBeep('bloquear');

    // Aplicar overlay temporal inmediato (luego el re-render lo hace persistente)
    const allCards = document.querySelectorAll('.eval-card');
    const cardsTarget = Array.from(allCards).filter(el => {
      const btn = el.querySelector(`button[onclick*="finBloquearUsuario"][onclick*="${nombre.replace(/'/g, '&#39;')}"]`);
      return !!btn;
    });
    cardsTarget.forEach(c => _aplicarRejasOverlay(c, nombre));

    try {
      const r = await API.post('bloquearDispositivosDeUsuario', {
        nombre,
        appOrigen: appOrigen || 'mosExpress',
        bloqueadoPor: auth.nombre || S.session?.nombre || 'admin',
        claveAdmin: auth.clave,
        motivo: 'bloqueo_desde_personal_dia'
      });
      if (r && r.ok !== false) {
        const n = r.data?.cantidad || 0;
        if (n > 0) {
          toast(`🔒 ${nombre} · ${n} dispositivo(s) encarcelado(s) · pantalla candado en <30s`, 'ok', 5000);
          // Actualizar state local inmediatamente para que el re-render persista
          const nLow = String(nombre).toLowerCase().trim();
          _finBloqueados.porNombre = _finBloqueados.porNombre || {};
          _finBloqueados.porNombre[nLow] = {
            nombre,
            // [v2.42.04 fix] r ya es data desempaquetado (API.post)
            dispositivos: r?.bloqueados || []
          };
          // Re-render del personal para pintar overlay persistente
          if (_finPL) _finRenderPersonal(_finPL, _finPL._fechaStamp || $('finFecha')?.value || today());
        } else {
          toast(`⚠ ${nombre} no tenía dispositivos activos para encarcelar`, 'warning');
          cardsTarget.forEach(c => {
            const ov = c.querySelector('.fin-rejas-overlay:not(.fin-rejas-persist)');
            if (ov) ov.remove();
          });
        }
      } else {
        throw new Error(r?.error || 'No se pudo bloquear');
      }
    } catch(e) {
      _finBeep('error');
      cardsTarget.forEach(c => {
        const ov = c.querySelector('.fin-rejas-overlay:not(.fin-rejas-persist)');
        if (ov) ov.remove();
      });
      toast('Error: ' + e.message, 'error');
    }
  }

  // Libera todos los dispositivos encarcelados de un usuario. Requiere clave
  // admin de 8 dígitos por cada dispositivo (más seguro: cada UUID es una
  // decisión independiente). En la práctica son 1-2 devices máximo por
  // usuario, así que la fricción es aceptable.
  async function finLiberarDispositivosUsuario(nombre) {
    if (!nombre) return;
    const nLow = String(nombre).toLowerCase().trim();
    const info = _finBloqueados?.porNombre?.[nLow];
    if (!info || !info.dispositivos?.length) {
      toast('No hay dispositivos bloqueados para ' + nombre, 'warning');
      return;
    }
    const devices = info.dispositivos;
    // [v2.41.83] AdminAuthModal universal (antes prompt() nativo).
    // Una sola clave para liberar todos los devices del usuario (la clave
    // se reutiliza en el loop interno).
    const auth = await pedirAuth({
      accion: 'LIBERAR_DISPOSITIVO_BLOQUEADO',
      refDocumento: nombre,
      contexto: `Liberar ${devices.length} dispositivo(s) de ${nombre}`
    });
    if (!auth) return;
    _finBeep('bloquear');
    let liberados = 0, fallados = 0, errMsg = '';
    for (const d of devices) {
      try {
        const r = await API.post('liberarDispositivoBloqueado', {
          deviceId: d.deviceId,
          claveAdmin: auth.clave,
          motivo: 'liberacion_desde_personal_dia'
        });
        if (r?.ok && r.data?.autorizado && !r.data?.error) {
          liberados++;
        } else {
          fallados++;
          errMsg = r?.data?.error || r?.error || 'desconocido';
        }
      } catch(e) { fallados++; errMsg = e.message; }
    }
    if (liberados > 0) {
      toast(`🔓 ${liberados} dispositivo(s) liberado(s) · pueden operar en <30s`, 'ok', 5000);
      // Limpiar state local y re-render
      delete _finBloqueados.porNombre[nLow];
      if (_finPL) _finRenderPersonal(_finPL, _finPL._fechaStamp || $('finFecha')?.value || today());
    }
    if (fallados > 0) {
      toast(`❌ ${fallados} no se pudo liberar: ${errMsg}`, 'error', 6000);
    }
  }

  // Pinta el overlay de rejas sobre un card (con animación de caída)
  function _aplicarRejasOverlay(card, nombre) {
    if (!card || card.querySelector('.fin-rejas-overlay')) return;
    const rect = card.getBoundingClientRect();
    const ov = document.createElement('div');
    ov.className = 'fin-rejas-overlay';
    ov.innerHTML = `
      <div class="fin-rejas-bars">
        <div class="fin-rejas-bar"></div>
        <div class="fin-rejas-bar" style="animation-delay:60ms"></div>
        <div class="fin-rejas-bar" style="animation-delay:120ms"></div>
        <div class="fin-rejas-bar" style="animation-delay:180ms"></div>
        <div class="fin-rejas-bar" style="animation-delay:240ms"></div>
        <div class="fin-rejas-bar" style="animation-delay:300ms"></div>
      </div>
      <div class="fin-rejas-badge">🔒 BLOQUEADO</div>
      <div class="fin-rejas-sub">${nombre}</div>`;
    card.style.position = 'relative';
    card.appendChild(ov);
    // Pulso del card
    card.style.transition = 'box-shadow 0.4s, transform 0.4s';
    card.style.boxShadow = '0 0 24px rgba(245,158,11,0.55)';
    setTimeout(() => { card.style.boxShadow = ''; }, 800);
  }

  async function finImportarCajas() {
    const fecha = $('finFecha')?.value || today();
    try {
      const res = await API.post('importarJornadasDesdeCajas', {
        fecha, montoDefault: 0, registradoPor: S.session?.nombre || ''
      });
      toast(res.importados > 0
        ? res.importados + ' jornada(s) importada(s) desde cajas'
        : 'Sin cajas nuevas para importar este día', 'ok');
      if (res.importados > 0) finCargar();
    } catch(e) { toast('Error importando cajas: ' + e.message, 'error'); }
  }

  // ── Editor de costo inline (desde alerta sin costo) ─────────
  let _finEditSku = null;

  function finEditarCostoSku(sku) {
    _finEditSku = sku;
    _setText('finCostoEditorSku', sku);
    const inp = $('finCostoEditorInput');
    if (inp) { inp.value = ''; }
    $('finCostoEditorWrap')?.classList.remove('hidden');
    inp?.focus();
  }

  function finCerrarCostoEditor() {
    _finEditSku = null;
    $('finCostoEditorWrap')?.classList.add('hidden');
  }

  // ── Editor de margen default global ──────────────────────
  function finAbrirEditorMargenDefault() {
    const inp = $('finMargenDefaultInput');
    const cur = parseFloat(_finPL?.defaultMargenUsado) || 20;
    if (inp) inp.value = cur;
    // Mostrar impacto del día actual
    const impEl = $('finMargenDefaultImpacto');
    if (impEl && _finPL) {
      const estim = parseFloat(_finPL.costoVentasEstimado || 0);
      const real  = parseFloat(_finPL.costoVentasReal || 0);
      const cantEstim = parseInt(_finPL.cantidadEstimados || 0);
      if (cantEstim === 0) {
        impEl.textContent = '✅ Hoy todos los productos vendidos tienen costo real asignado. Este default no afectó nada.';
      } else {
        impEl.innerHTML = `Hoy hay <b>${cantEstim} SKU${cantEstim === 1 ? '' : 's'}</b> sin precio costo. Se estimó <b class="text-amber-400">S/ ${estim.toFixed(2)}</b> de costo de venta usando este margen (vs <b>S/ ${real.toFixed(2)}</b> real). Cambiar el % afectará la utilidad mostrada inmediatamente al guardar.`;
      }
    }
    openModal('modalMargenDefault');
  }
  function finCerrarEditorMargenDefault() { closeModal('modalMargenDefault'); }

  async function finGuardarMargenDefault() {
    const v = parseFloat($('finMargenDefaultInput')?.value);
    if (isNaN(v) || v < 0 || v >= 100) {
      toast('Margen debe ser 0-99', 'error');
      if (typeof _evalSfx === 'function') _evalSfx('error');
      return;
    }
    // OPTIMISTA: feedback inmediato
    if (typeof _evalSfx === 'function') _evalSfx('success');
    try {
      const btn = $('finMargenDefaultSaveBtn');
      if (btn && typeof _evalConfetti === 'function') {
        const r = btn.getBoundingClientRect();
        _evalConfetti(r.left + r.width/2, r.top + r.height/2, '#fbbf24');
      }
    } catch(_){}
    toast(`Margen default ${v}% guardado ✓`, 'ok');
    finCerrarEditorMargenDefault();
    // Patch local _finPL.defaultMargenUsado y re-render solo el KPI de margen
    // (sin esperar a finCargar completo, que tarda 3-5s).
    try {
      if (_finPL) {
        _finPL.defaultMargenUsado = v;
        // Re-pintar el KPI de margen promedio si está visible
        const estimEl = $('finKpiMargenEstim');
        if (estimEl && _finPL.cantidadEstimados) {
          estimEl.textContent = `${_finPL.cantidadEstimados} SKU${_finPL.cantidadEstimados === 1 ? '' : 's'} estim. al ${v}%`;
        }
        // Refrescar el badge de color comparando margen real vs nuevo default
        const margenEl = $('finKpiMargenProm');
        if (margenEl && typeof _finPL.margenPromedioPct === 'number') {
          const real = parseFloat(_finPL.margenPromedioPct);
          margenEl.style.color = real >= v ? '#34d399' : '#fbbf24';
        }
      }
    } catch(_){}
    // Backend: el setConfig YA se guardó. Pidamos un refresh suave en bg
    // (sin animaciones de skeleton, solo actualiza si difiere).
    try {
      API.post('setConfig', { clave: 'finMargenDefault', valor: String(v) }).catch(() => {});
    } catch(_){}
    // Fetch fresh en bg para validar (Finanzas recalcula con el nuevo margen)
    setTimeout(() => {
      try {
        const fecha = $('finFecha')?.value || today();
        API.get('getFinanzasDia', { fecha }).then(pl => {
          if (pl) {
            pl._fechaStamp = fecha;
            _finPL = pl;
            _finSaveCache && _finSaveCache('pl_' + fecha, pl);
            if (S.view === 'finanzas' && typeof _finRender === 'function') {
              _finRender(pl, fecha);
            }
          }
        }).catch(() => {});
      } catch(_){}
    }, 100);
  }

  async function finGuardarCostoSku() {
    if (!_finEditSku) return;
    const costo = parseFloat($('finCostoEditorInput')?.value);
    if (!costo || costo <= 0) { toast('Ingresa un costo válido', 'error'); return; }
    try {
      await API.post('actualizarCostoPorSku', { sku: _finEditSku, precioCosto: costo });
      finCerrarCostoEditor();
      toast('Costo actualizado', 'ok');
      finCargar();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  // ── Modal Productos Vendidos ─────────────────────────────────
  let _finProdFiltroSinCosto = false;
  let _finProdEditSku = null;

  function finAbrirModalProductos() {
    const m = $('finModalProductos');
    if (!m) return;
    m.classList.remove('hidden'); m.classList.add('open');
    _finProdFiltroSinCosto = false;
    _finRenderProductos();
  }

  function finToggleFiltroSinCosto() {
    _finProdFiltroSinCosto = !_finProdFiltroSinCosto;
    const btn = $('finProdBtnSinCosto');
    if (btn) {
      btn.classList.toggle('bg-amber-900/40', _finProdFiltroSinCosto);
      btn.classList.toggle('text-amber-200', _finProdFiltroSinCosto);
    }
    _finRenderProductos();
  }

  function _finRenderProductos() {
    const pl = _finPL;
    if (!pl) return;
    const fmtM = v => 'S/ ' + parseFloat(v || 0).toFixed(2);
    const todos = pl.detalleProductos || [];
    const haySinCosto = todos.some(p => p.sinCosto);
    const btn = $('finProdBtnSinCosto');
    if (btn) btn.classList.toggle('hidden', !haySinCosto);

    // [v2.41.79] Alerta prominente si >50% del COSTO total es estimado.
    // Margen del día no es confiable → admin debe llenar precioCosto.
    const costoReal      = parseFloat(pl.costoVentasReal     || 0);
    const costoEstimado  = parseFloat(pl.costoVentasEstimado || 0);
    const costoTotal     = costoReal + costoEstimado;
    const pctEstimado    = costoTotal > 0 ? (costoEstimado / costoTotal) * 100 : 0;
    const skusSinCosto   = todos.filter(p => p.sinCosto).length;
    const alertWrap = $('finProdAlerta');
    if (alertWrap) {
      if (pctEstimado > 50 || (skusSinCosto > 0 && skusSinCosto / Math.max(1, todos.length) > 0.5)) {
        alertWrap.innerHTML = `
          <div class="fin-prod-alerta-grande">
            <div class="flex items-center gap-2">
              <span style="font-size:22px">⚠</span>
              <div class="flex-1">
                <div class="text-sm font-bold text-amber-300">Margen del día NO confiable</div>
                <div class="text-[11px] text-amber-200/80 mt-0.5">
                  ${skusSinCosto} de ${todos.length} SKU(s) sin costo real ·
                  ${pctEstimado.toFixed(0)}% del costo es estimado al ${(pl.defaultMargenUsado||20)}%
                </div>
              </div>
            </div>
          </div>`;
        alertWrap.classList.remove('hidden');
      } else {
        alertWrap.innerHTML = '';
        alertWrap.classList.add('hidden');
      }
    }

    const lista = _finProdFiltroSinCosto ? todos.filter(p => p.sinCosto) : todos;
    const conteo = $('finProdConteo');
    if (conteo) conteo.textContent = lista.length + ' de ' + todos.length + ' SKUs';
    const tbody = $('finProdTableBody');
    if (!tbody) return;
    tbody.innerHTML = lista.map(p => {
      const alertBadge = p.sinCosto
        ? `<span class="text-amber-400 font-bold" title="Sin costo canónico">⚠</span>` : '';
      // [v2.41.80] Cada fila es un GRUPO por skuBase. Cantidad = unidades base.
      // cantPresent = cuántas presentaciones/líneas distintas se agruparon.
      const cantPresent = parseFloat(p.cantPresent || 0);
      const cantUds     = parseFloat(p.cantidad || 0);
      // Mostrar "Nuds (Mpres)" si N != M (significa que hubo presentaciones)
      const cantStr = cantUds !== cantPresent
        ? `<strong>${cantUds}</strong><span class="text-[10px] text-slate-500 ml-1">uds · ${cantPresent} pres.</span>`
        : `<strong>${cantUds}</strong>`;
      const costoUnitStr = p.sinCosto
        ? `<span class="text-amber-400/60">—</span>`
        : `<span title="Costo canónico (por unidad base)">${fmtM(p.costoUnit)}</span>`;
      const costoTotalStr = p.sinCosto
        ? `<span class="text-amber-400/60">—</span>`
        : `<span title="${cantUds} uds × ${fmtM(p.costoUnit)}">${fmtM(p.costoTotal)}</span>`;
      const editBtn = p.sinCosto
        ? `<button onclick="MOS.finEditarCostoProd('${p.sku}')" class="text-amber-400 hover:text-amber-200 px-1" title="Asignar costo canónico">✎</button>`
        : `<button onclick="MOS.finEditarCostoProd('${p.sku}')" class="text-slate-600 hover:text-slate-300 px-1" title="Editar costo canónico">✎</button>`;
      return `<tr class="hover:bg-slate-800/30 transition-colors">
        <td class="px-3 py-2">
          <div class="flex items-start gap-1.5">
            ${alertBadge}
            <div>
              <div class="text-slate-200 text-xs leading-snug">${p.nombre || p.sku}</div>
              <div class="font-mono text-slate-500 text-xs">${p.sku}</div>
            </div>
          </div>
        </td>
        <td class="px-2 py-2 text-right text-slate-200 whitespace-nowrap">${cantStr}</td>
        <td class="px-2 py-2 text-right text-slate-400 whitespace-nowrap hidden sm:table-cell">${fmtM(p.precio)}</td>
        <td class="px-2 py-2 text-right whitespace-nowrap hidden sm:table-cell">${costoUnitStr}</td>
        <td class="px-2 py-2 text-right whitespace-nowrap">${costoTotalStr}</td>
        <td class="px-1 py-2">${editBtn}</td>
      </tr>`;
    }).join('') || '<tr><td colspan="6" class="px-4 py-8 text-center text-slate-500">Sin datos</td></tr>';
  }

  function finEditarCostoProd(sku) {
    _finProdEditSku = sku;
    _setText('finProdCostoSku', sku);
    const inp = $('finProdCostoInput');
    if (inp) { inp.value = ''; inp.focus(); }
    $('finProdCostoWrap')?.classList.remove('hidden');
  }
  function finCerrarCostoProd() {
    _finProdEditSku = null;
    $('finProdCostoWrap')?.classList.add('hidden');
  }
  async function finGuardarCostoProd() {
    if (!_finProdEditSku) return;
    const costo = parseFloat($('finProdCostoInput')?.value);
    if (!costo || costo <= 0) { toast('Ingresa un costo válido', 'error'); return; }
    try {
      await API.post('actualizarCostoPorSku', { sku: _finProdEditSku, precioCosto: costo });
      finCerrarCostoProd();
      toast('Costo actualizado', 'ok');
      await finCargar(); // refresca _finPL
      _finRenderProductos();
    } catch(e) { toast('Error: ' + e.message, 'error'); }
  }

  // ── Modal Tickets del Día ─────────────────────────────────────
  let _finTicketFiltro = 'todos';

  const _FIN_FILTROS = [
    { key: 'todos',      label: 'Todos' },
    { key: 'ventas',     label: '💰 Cobrado' },
    { key: 'efectivo',   label: '💵 Efectivo' },
    { key: 'virtual',    label: '📱 Virtual' },
    { key: 'mixto',      label: '🔀 Mixto' },
    { key: 'por_cobrar', label: '⏳ Por cobrar' },
    { key: 'credito',    label: '📋 Crédito' },
    { key: 'anulado',    label: '❌ Anulado' },
    { key: 'boleta',     label: 'Boleta' },
    { key: 'nota',       label: 'Nota' },
    { key: 'factura',    label: 'Factura' },
  ];

  function finAbrirModalTickets(filtroInicial) {
    // SONIDO OPTIMISTA: dispara INMEDIATO antes de cualquier DOM op
    _finBeep('click');
    const m = $('finModalTickets');
    if (!m) return;
    m.classList.remove('hidden'); m.classList.add('open');
    const f = String(filtroInicial || '').toUpperCase();
    _finTicketFiltro = (f === 'CREDITO' || f === 'POR_COBRAR') ? 'credito'
                     : (f === 'ANULADO' || f === 'ANULADOS') ? 'anulado'
                     : (f === 'VENTAS' || f === 'COBRADO') ? 'ventas'
                     : 'todos';
    _finRenderFiltrosBtns();
    _finRenderTickets();
  }

  function finSetTicketFiltro(key) {
    _finTicketFiltro = key;
    _finRenderFiltrosBtns();
    _finRenderTickets();
  }

  function _finRenderFiltrosBtns() {
    const wrap = $('finTicketFiltros');
    if (!wrap) return;
    wrap.innerHTML = _FIN_FILTROS.map(f => {
      const active = f.key === _finTicketFiltro;
      const cls = active
        ? 'text-xs px-2.5 py-1 rounded-full bg-indigo-600 text-white font-semibold'
        : 'text-xs px-2.5 py-1 rounded-full bg-slate-800 text-slate-400 hover:text-slate-200 hover:bg-slate-700';
      return `<button onclick="MOS.finSetTicketFiltro('${f.key}')" class="${cls} transition-colors">${f.label}</button>`;
    }).join('');
  }

  function _finApplyTicketFiltro(tickets) {
    const f = _finTicketFiltro;
    // Definiciones selladas (FormaPago):
    //   EFECTIVO/VIRTUAL/MIXTO = COBRADO (dinero recibido)
    //   POR_COBRAR             = pendiente de cajero (vendedor emitió)
    //   CREDITO                = deuda formal aprobada por admin
    //   ANULADO                = descartado
    const fp = t => String(t.formaPago || '').toUpperCase();
    const esAnulado   = t => fp(t) === 'ANULADO' || t.estado === 'ANULADO';
    const esPorCobrar = t => fp(t) === 'POR_COBRAR' && !esAnulado(t);
    const esCredito   = t => fp(t) === 'CREDITO' && !esAnulado(t);
    const esEfectivo  = t => fp(t) === 'EFECTIVO';
    const esVirtual   = t => fp(t) === 'VIRTUAL';
    const esMixto     = t => fp(t).startsWith('MIXTO');
    const esCobrado   = t => !esAnulado(t) && !esPorCobrar(t) && !esCredito(t);

    if (f === 'todos')      return tickets;
    if (f === 'ventas')     return tickets.filter(esCobrado);
    if (f === 'efectivo')   return tickets.filter(t => esEfectivo(t) && !esAnulado(t));
    if (f === 'virtual')    return tickets.filter(t => esVirtual(t) && !esAnulado(t));
    if (f === 'mixto')      return tickets.filter(t => esMixto(t) && !esAnulado(t));
    if (f === 'por_cobrar') return tickets.filter(esPorCobrar);
    if (f === 'credito')    return tickets.filter(esCredito);
    if (f === 'anulado')    return tickets.filter(esAnulado);
    if (f === 'boleta')     return tickets.filter(t => t.tipoDoc === 'BOLETA');
    if (f === 'nota')       return tickets.filter(t => t.tipoDoc === 'NOTA_DE_VENTA');
    if (f === 'factura')    return tickets.filter(t => t.tipoDoc === 'FACTURA');
    return tickets;
  }

  function _finRenderTickets() {
    const pl = _finPL;
    if (!pl) return;
    const fmtM = v => 'S/ ' + parseFloat(v || 0).toFixed(2);
    const todos = pl.detalleTickets || [];
    const lista = _finApplyTicketFiltro(todos);
    // Total considera ANULADO por formaPago O por estado (defensivo)
    const esAnul = t => String(t.formaPago || '').toUpperCase() === 'ANULADO' || t.estado === 'ANULADO';
    const totalFiltrado = lista.reduce((s, t) => s + (esAnul(t) ? 0 : (parseFloat(t.total) || 0)), 0);
    const conteo = $('finTicketConteo');
    if (conteo) conteo.textContent = lista.length + ' ticket' + (lista.length !== 1 ? 's' : '') +
      (lista.length < todos.length ? ' · Total: ' + fmtM(totalFiltrado) : '');
    const list = $('finTicketList');
    if (!list) return;

    const docLabel = { 'BOLETA': 'BOL', 'NOTA_DE_VENTA': 'NV', 'FACTURA': 'FAC' };
    // Chip de método según FormaPago — POR_COBRAR y CREDITO ahora separados
    const metodoChip = t => {
      const fp = String(t.formaPago || '').toUpperCase();
      if (fp === 'ANULADO')        return { txt: 'ANULADO',     cls: 'tk-chip-anul' };
      if (fp === 'EFECTIVO')       return { txt: '💵 Efectivo', cls: 'tk-chip-ef'   };
      if (fp === 'VIRTUAL')        return { txt: '📱 Virtual',  cls: 'tk-chip-vi'   };
      if (fp === 'POR_COBRAR')     return { txt: '⏳ Por cobrar', cls: 'tk-chip-pc' };
      if (fp === 'CREDITO')        return { txt: '📋 Crédito',  cls: 'tk-chip-cr'   };
      if (fp.startsWith('MIXTO'))  return { txt: '🔀 Mixto',    cls: 'tk-chip-mx', sub: fp.replace('MIXTO ', '') };
      return { txt: fp || '—', cls: 'tk-chip-other' };
    };

    if (!lista.length) {
      list.innerHTML = '<div class="px-4 py-10 text-center text-slate-500 text-sm italic">Sin tickets con este filtro</div>';
      return;
    }

    list.innerHTML = lista.map(t => {
      const anulado = esAnul(t);
      const met = metodoChip(t);
      const corr = t.correlativo || (t.idVenta || '').split('-').pop() || '—';
      // Cliente: el backend puede devolver `cliente`/`clienteNombre` y `clienteDoc`
      const cliNombre = (t.cliente || t.clienteNombre || '').trim();
      const cliDoc    = (t.clienteDoc || t.clienteDocumento || '').trim();
      const tieneCliente = !!(cliNombre || cliDoc);
      const cabecera = tieneCliente
        ? `<div class="tk-cli-nombre">👤 ${cliNombre || 'Sin nombre'}</div>
           ${cliDoc ? `<div class="tk-cli-doc">${cliDoc}</div>` : ''}`
        : `<div class="tk-cli-nombre tk-cli-nombre-anon">— Cliente sin registrar —</div>`;
      const corrTxt = `${docLabel[t.tipoDoc] || ''} ${corr}`;
      const idVentaSafe = String(t.idVenta || '').replace(/'/g, "\\'");
      return `<div class="tk-row tk-row-clickable ${anulado ? 'tk-row-anul' : ''} ${met.cls}" onclick="MOS.cjAbrirAccionesTicket('${idVentaSafe}')">
        <div class="tk-cli">
          ${cabecera}
        </div>
        <div class="tk-meta">
          <span class="tk-meta-corr">${corrTxt}</span>
          ${t.vendedor ? `<span class="tk-meta-vend">· ${t.vendedor}</span>` : ''}
          ${t.hora ? `<span class="tk-meta-hora">· ${t.hora}</span>` : ''}
          ${t.obs ? `<span class="tk-meta-obs" title="${t.obs.replace(/"/g,'&quot;')}">📝</span>` : ''}
        </div>
        <div class="tk-monto-col">
          <div class="tk-monto ${anulado ? 'tk-monto-anul' : ''}">${fmtM(t.total)}</div>
          <span class="tk-chip ${met.cls}">${met.txt}</span>
        </div>
        <div class="tk-row-cog" title="Acciones">⚙️</div>
      </div>`;
    }).join('');
  }

  // Helpers
  function _setText(id, val) { const el = $(id); if (el) el.textContent = val; }

  // ── Animación countup: pasa de un número a otro suavemente ──
  // Lee el número anterior del data-attr y anima hasta el nuevo.
  // prefix/suffix = strings fijos (ej. 'S/ ', '%'). decimals = decimales.
  // Si el cambio es ≥ 1% del valor o > S/ 1, agrega flash visual.
  function _animateCount(id, newVal, opts) {
    const el = typeof id === 'string' ? $(id) : id;
    if (!el) return;
    opts = opts || {};
    const prefix   = opts.prefix || '';
    const suffix   = opts.suffix || '';
    const decimals = (opts.decimals !== undefined) ? opts.decimals : 2;
    const duration = opts.duration || 600;
    const flashCol = opts.flashCol || '';
    const newNum   = parseFloat(newVal) || 0;
    const oldNum   = parseFloat(el.dataset._anim) || 0;
    el.dataset._anim = String(newNum);
    const fmt = n => prefix + n.toFixed(decimals) + suffix;
    if (Math.abs(newNum - oldNum) < 0.005) {
      el.textContent = fmt(newNum);
      return;
    }
    const t0 = performance.now();
    function step(t) {
      const k = Math.min(1, (t - t0) / duration);
      // easeOutCubic
      const e = 1 - Math.pow(1 - k, 3);
      const cur = oldNum + (newNum - oldNum) * e;
      el.textContent = fmt(cur);
      if (k < 1) requestAnimationFrame(step);
      else el.textContent = fmt(newNum);
    }
    requestAnimationFrame(step);
    // Flash visual
    const significant = Math.abs(newNum - oldNum) > Math.max(1, Math.abs(oldNum) * 0.01);
    if (significant) {
      const orig = el.style.transition;
      const origBg = el.style.boxShadow;
      const isUp = newNum > oldNum;
      const color = flashCol || (isUp ? 'rgba(52,211,153,0.55)' : 'rgba(248,113,113,0.55)');
      el.style.transition = 'box-shadow 0.25s ease-out, transform 0.25s ease-out';
      el.style.boxShadow = '0 0 18px ' + color;
      el.style.transform = 'scale(1.04)';
      setTimeout(() => {
        el.style.boxShadow = origBg;
        el.style.transform = '';
        setTimeout(() => { el.style.transition = orig; }, 280);
      }, 380);
    }
  }

  function _fechaOffset(fechaStr, dias) {
    const d = new Date(fechaStr + 'T00:00:00');
    d.setDate(d.getDate() + dias);
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  }

