  let _pushMsgHandlerSet = false;

  async function _pushInit(nombre, rol, askPermission = false) {
    console.log('[Push] init — firebase:', !!window.firebase, '| Notification:', typeof Notification !== 'undefined' ? Notification.permission : 'N/A', '| ask:', askPermission);
    if (!window.firebase || !('Notification' in window) || !('serviceWorker' in navigator)) {
      console.warn('[Push] requisitos no cumplidos, saliendo');
      return;
    }

    if (!firebase.apps.length) firebase.initializeApp(_PUSH_CONFIG);
    const messaging = firebase.messaging();

    // Handler de primer plano — registrar UNA sola vez, independiente de si getToken falla
    if (!_pushMsgHandlerSet) {
      _pushMsgHandlerSet = true;
      messaging.onMessage(async payload => {
        const t = payload.notification?.title || '';
        const b = payload.notification?.body  || '';
        toast('🔔 ' + t + (b ? ': ' + b : ''), 'ok', 8000);
        // Optimismo: si la notif es de dispositivos o sesiones, refrescar Configuración
        // para mostrar el cambio al instante (sin esperar el polling de 30s).
        const tLow = (t + ' ' + b).toLowerCase();
        if (tLow.includes('dispositivo') || tLow.includes('inició sesión') || tLow.includes('inicio sesion')) {
          try {
            const data = await API.get('getDispositivos', {});
            if (Array.isArray(data)) {
              cfgData.dispositivos = _dispAplicarShield(data);   // [v2.43.348 fix] shield en refresh por push
              if (S.cfgTab === 'infra') renderInfra();
              if (S.cfgTab === 'personal') renderPersonal();
            }
          } catch(_) {}
        }
        try {
          const reg = await navigator.serviceWorker.ready;
          reg.showNotification(t, {
            body: b,
            icon:  'https://levo19.github.io/MOS/icons/icon-192.png',
            badge: 'https://levo19.github.io/MOS/icons/icon-192.png',
            vibrate: [200, 100, 200],
            tag: 'mos-push'
          });
        } catch(_) {}
      });
    }

    try {
      const permission = askPermission
        ? await Notification.requestPermission()
        : Notification.permission;
      console.log('[Push] permission:', permission);
      if (permission !== 'granted') return;

      const swReg = await navigator.serviceWorker.ready;
      console.log('[Push] SW activo:', swReg.active?.scriptURL);
      const token = await messaging.getToken({ vapidKey: _PUSH_VAPID, serviceWorkerRegistration: swReg });
      console.log('[Push] token obtenido:', token ? token.substring(0,20)+'...' : 'null');
      if (!token) return;

      // [F6 push · cero-GAS] Registro directo a Supabase (mos.push_tokens). Aditivo al GAS.
      if (API.registrarPushTokenSB) {
        API.registrarPushTokenSB({ token, usuario: nombre, appOrigen: 'MOS',
          dispositivo: navigator.userAgent.substring(0, 150) }).catch(() => {});
      }
      // Guardar token en GAS
      API.post('registrarPushToken', {
        token, usuario: nombre, appOrigen: 'MOS',
        dispositivo: navigator.userAgent.substring(0, 150)
      }).catch(() => {});

      // Notificar ingreso a MOS — SOLO los MASTER lo ven (admins no se enteran de otros admins)
      const hora = new Date().toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit' });
      // [F6 push dispatch · cero-GAS] select(soloRolesMaster) + Edge; si falla (null) → GAS.
      API.enviarPushSB('👤 ' + nombre + ' ingresó a MOS', (rol || '') + ' · ' + hora, { soloRolesMaster: true, excluirUsuario: nombre })
        .then(r => { if (!r) return API.post('enviarPushNotif', { titulo: '👤 ' + nombre + ' ingresó a MOS', cuerpo: (rol || '') + ' · ' + hora, soloRolesMaster: true, excluirUsuario: nombre }); })
        .catch(() => {});

      console.log('[Push] token registrado en GAS ✅');
    } catch(e) {
      console.error('[Push] ERROR:', e.message);
      // No mostrar toast de error en session restore (solo en acción del usuario)
      if (askPermission) toast('Push error: ' + e.message, 'error');
    }
  }

