  // Helper: resuelve checklist de un rol (CONFIG_MOS override → fallback default)
  function _evalChecklistDe(rol) {
    const ROL = String(rol || '').toUpperCase();
    if (!_evalState.rolItems) {
      _evalState.rolItems = {};
      const cfg = cfgData.config || {};
      ['CAJERO','VENDEDOR','ALMACENERO','ENVASADOR'].forEach(r => {
        const k = 'evalChecklist' + r;
        const raw = cfg[k];
        let arr = null;
        if (raw) {
          try { arr = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch(_){}
        }
        _evalState.rolItems[r] = (Array.isArray(arr) && arr.length) ? arr : _evalState.rolItemsDefault[r];
      });
    }
    return _evalState.rolItems[ROL] || _evalState.rolItems.CAJERO;
  }

  function _evalScoreClass(score) {
    if (score >= 85) return 'eval-score-high';
    if (score >= 60) return 'eval-score-mid';
    return 'eval-score-low';
  }

  function _evalRolBadgeClass(rol) {
    rol = String(rol || '').toUpperCase();
    if (rol === 'CAJERO' || rol === 'VENDEDOR') return 'badge-rol-cajero';
    if (rol === 'ALMACENERO')                    return 'badge-rol-almacen';
    if (rol === 'ENVASADOR')                     return 'badge-rol-envasador';
    return 'badge-rol-default';
  }

  async function loadEvaluacion() {
    const lbl = $('evalFechaLbl');
    if (lbl) lbl.textContent = 'Hoy ' + new Date(_evalState.fecha + 'T00:00:00').toLocaleDateString('es-PE', { day: '2-digit', month: 'long', year: 'numeric' });
    await refreshEvaluacion();
    _ensureLiqDefaults();
  }

  async function refreshEvaluacion() {
    const list = $('evalListPersonal');
    if (list) list.innerHTML = '<div class="skel h-24 rounded-xl"></div><div class="skel h-24 rounded-xl"></div><div class="skel h-24 rounded-xl"></div>';
    try {
      const res = await API.get('getResumenTodosDia', { fecha: _evalState.fecha });
      _evalState.resumenes = Array.isArray(res) ? res : [];
      _renderEvalLista();
      _renderLiqDropdown();
    } catch (e) {
      if (list) list.innerHTML = `<p class="text-sm text-red-400 text-center py-6">Error: ${e.message}</p>`;
    }
  }

  function evalSetApp(app) {
    _evalState.appFilter = app;
    document.querySelectorAll('#evalAppFilter .eval-pill').forEach(b => {
      b.classList.toggle('active', b.dataset.app === app);
    });
    _renderEvalLista();
  }

  function _renderEvalLista() {
    const list = $('evalListPersonal');
    if (!list) return;
    const filtered = _evalState.resumenes.filter(r =>
      _evalState.appFilter === 'all' || r.appOrigen === _evalState.appFilter
    );
    if (!filtered.length) {
      list.innerHTML = '<p class="text-sm text-slate-500 text-center py-8">No hay personal para mostrar.</p>';
      return;
    }
    // Ordenar por appOrigen y rol
    filtered.sort((a, b) => (a.appOrigen || '').localeCompare(b.appOrigen || '') || (a.rol || '').localeCompare(b.rol || ''));

    list.innerHTML = filtered.map(r => {
      const score = r.scoreFinal || 0;
      const scoreClass = _evalScoreClass(score);
      const rolClass = _evalRolBadgeClass(r.rol);
      const evalCount = r.evaluacionesCount || 0;
      const kpiTxt = _evalKpiSummary(r);
      const totalDia = (r.totalDia || r.montoBase || 0).toFixed(2);
      return `
        <div class="eval-card" data-id="${r.idPersonal}">
          <div class="flex items-center gap-3">
            <div class="eval-score-circle ${scoreClass}" style="--score:${score}">
              <span>${score}%</span>
            </div>
            <div class="flex-1 min-w-0">
              <div class="flex items-center gap-2 mb-1 flex-wrap">
                <div class="font-semibold text-slate-100 text-sm truncate">${r.nombre}</div>
                <span class="badge-rol ${rolClass}">${r.rol || ''}</span>
                ${r.virtual ? '<span class="badge-rol badge-rol-default" title="Detectado de MosExpress (no en master)">⚡ del sistema</span>' : ''}
              </div>
              <div class="text-xs text-slate-500 mb-1">${kpiTxt}</div>
              <div class="flex items-center gap-2 flex-wrap">
                ${evalCount > 0
                  ? `<span class="audit-count-pill">${evalCount} auditoría${evalCount !== 1 ? 's' : ''} hoy</span>`
                  : `<span class="audit-count-pill" style="background:rgba(245,158,11,.12);color:#fbbf24;border-color:rgba(245,158,11,.3)">⚠ Sin auditar</span>`}
                <span class="text-xs text-slate-400">Pago día: <strong class="text-amber-400">S/${totalDia}</strong></span>
              </div>
            </div>
            <div class="flex flex-col gap-1 shrink-0 items-end">
              <div class="flex gap-1">
                <button onclick="event.stopPropagation();MOS.abrirEspiaPorUsuario('${String(r.nombre || '').replace(/'/g,'&#39;')}')"
                  class="w-7 h-7 rounded-full flex items-center justify-center hover:scale-110 transition-all"
                  style="background:rgba(99,102,241,0.18);border:1px solid rgba(99,102,241,0.5);color:#a5b4fc;font-size:11px;"
                  title="Espiar a ${r.nombre} (audio + GPS)">🕵️</button>
              </div>
              <button onclick="MOS.abrirAuditar('${r.idPersonal}')" class="btn-primary text-xs whitespace-nowrap">Auditar</button>
            </div>
          </div>
        </div>`;
    }).join('');
  }

  function _evalKpiSummary(r, rolOverride) {
    const k = r.kpis || {};
    // rolOverride (de p.rol en PERSONAL_MASTER) tiene prioridad sobre r.rol
    // (de la detección auto en el resumen), porque PERSONAL_MASTER es la
    // fuente de verdad — un ENVASADOR sigue siendo ENVASADOR aunque toque
    // ME un rato. Esto evita "Ventas S/0.00" en cards de almacén.
    const rol = String(rolOverride || r.rol || '').toUpperCase();
    const auditTxt = `${k.auditoriasHechas || 0}/${k.metaAuditorias || 30} aud.`;
    if (rol === 'CAJERO' || rol === 'VENDEDOR') {
      return `Ventas S/${(k.ventasReales || 0).toFixed(2)} · ${auditTxt}`;
    }
    if (rol === 'ENVASADOR') {
      const tar = parseFloat(r.tarifaEnvasado) || 0;
      const uds = parseFloat(k.envasados) || 0;
      const pago = uds * tar;
      return tar > 0 && uds > 0
        ? `🏷 ${uds} uds · S/${pago.toFixed(2)} · ${auditTxt}`
        : `🏷 ${uds} uds envasadas · ${auditTxt}`;
    }
    if (rol === 'ALMACENERO') {
      const uds = parseFloat(k.envasados) || 0;
      return uds > 0
        ? `🏷 ${uds} uds envasadas · ${auditTxt}`
        : `📋 ${auditTxt}`;
    }
    return auditTxt;
  }

  // ── Modal Auditar ────────────────────────────────────────────
  async function abrirAuditar(idPersonal) {
    let r = _evalState.resumenes.find(x => x.idPersonal === idPersonal);
    // Si no está en _evalState (módulo Evaluaciones nunca abierto), hidratar
    // desde cache de Cierre/Finanzas, y si tampoco, fetch directo.
    if (!r) {
      try {
        const raw = localStorage.getItem('mos_fin_resum_' + _evalState.fecha);
        if (raw) {
          const parsed = JSON.parse(raw);
          if (Array.isArray(parsed?.data)) _evalState.resumenes = parsed.data;
        }
      } catch {}
      r = _evalState.resumenes.find(x => x.idPersonal === idPersonal);
    }
    if (!r) {
      try {
        const fresh = await API.get('getResumenTodosDia', { fecha: _evalState.fecha });
        if (Array.isArray(fresh)) {
          _evalState.resumenes = fresh;
          try { localStorage.setItem('mos_fin_resum_' + _evalState.fecha, JSON.stringify({ ts: Date.now(), data: fresh })); } catch {}
        }
      } catch {}
      r = _evalState.resumenes.find(x => x.idPersonal === idPersonal);
    }
    if (!r) { toast('Personal no encontrado', 'error'); return; }
    // Override del rol desde PERSONAL_MASTER (la card lo expone). Si
    // existe, gana sobre r.rol (que puede venir de auto-detección).
    try {
      const card = document.querySelector(`.eval-card[data-id="${idPersonal}"]`);
      const badge = card?.querySelector('.badge-rol');
      const rolReal = badge?.textContent?.trim();
      if (rolReal && rolReal !== '—' && rolReal !== '⚡ del sistema') {
        r.rol = rolReal;
      }
    } catch(_){}
    // Título contextual: emoji + área según rol
    const rolU = String(r.rol || '').toUpperCase();
    const tituloIco = (rolU === 'CAJERO' || rolU === 'VENDEDOR') ? '🛒'
                    : rolU === 'ALMACENERO' ? '🏭'
                    : rolU === 'ENVASADOR'  ? '🏷'
                    : '🎯';
    const areaApp = (rolU === 'CAJERO' || rolU === 'VENDEDOR') ? 'MosExpress · POS'
                  : (rolU === 'ALMACENERO' || rolU === 'ENVASADOR') ? 'warehouseMos · Almacén'
                  : '';
    $('auditTitle').textContent = `${tituloIco} Auditar ${r.rol || ''} · ${r.nombre}`;
    const evalCount = r.evaluacionesCount || 0;
    const contexto = evalCount > 0
      ? `${evalCount} auditoría${evalCount !== 1 ? 's' : ''} · continuando...`
      : 'primera auditoría del día';
    // [v2.43.374] Día PROMINENTE: el ajuste (bono/sanción) se aplica a ESTE día. Evita
    // el bug "lo puse el lunes pero era del domingo" (la auditoría usa r.fecha del card).
    const _diaTxt = (() => {
      try { return new Date((r.fecha || _evalState.fecha) + 'T00:00:00')
              .toLocaleDateString('es-PE', { weekday: 'long', day: '2-digit', month: 'long' }); }
      catch (_) { return r.fecha || ''; }
    })();
    $('auditSubtitle').innerHTML = `📅 <strong style="color:#fbbf24">${_diaTxt}</strong>`
      + (areaApp ? ` · ${areaApp}` : '') + ` · ${contexto}`;
    $('auditIdPersonal').value = r.idPersonal;
    $('auditRol').value = r.rol || '';
    $('auditComentario').value = '';

    // Pre-cargar acumulado del día (MAX/OR) para que el admin continúe, no empiece de cero
    const limpAcum = Math.round(((r.manual && r.manual.limpiezaPct) || 0) / 10) * 10;
    const limpProfAcum = Math.round(((r.manual && r.manual.limpiezaProfPct) || 0) / 10) * 10;
    $('auditLimpieza').value = String(limpAcum);
    $('auditLimpiezaProf').value = String(limpProfAcum);
    updateRateSlider('auditLimpieza', 'auditLimpiezaVal');
    updateRateSlider('auditLimpiezaProf', 'auditLimpiezaProfVal');

    // Pre-marcar checks ya cumplidos en evaluaciones previas
    _evalState.auditChecks = Object.assign({}, (r.manual && r.manual.checksAcum) || {});

    $('auditTogComision').classList.add('on');
    $('auditTogMeta').classList.add('on');
    // [v2.41.60] Mostrar bonificacion/sancion ACTUALES de LIQUIDACIONES_DIA
    // como prellenado en el modal. Admin ve lo que ya está y decide mantener
    // o cambiar. Si valor previo era sanción, abrir en pestaña sanción;
    // si era bonificación, abrir en bonificación; si ambos > 0, sanción.
    // [v2.41.63] _ajusteTocado: tracker para diferenciar "admin no tocó el
    // ajuste" (preservar bon/san en LIQUIDACIONES_DIA) vs "admin lo editó
    // explícitamente a 0/vacío" (resetear). Sin esto, borrar el 44 no funcionaba.
    _evalState.auditAjusteTocado = false;
    // [v2.43.373] limpiar los dos campos independientes (se prellenan abajo con los
    // valores actuales de LIQUIDACIONES_DIA vía getLiqDiaBonSan).
    ['auditBonifMonto','auditBonifMotivoInp','auditSancionMonto','auditSancionMotivoInp'].forEach(id => {
      const el = $(id); if (el) el.value = '';
    });
    _evalState.auditR = r;
    _renderAuditKpis(r);
    _renderAuditChecklist(r.rol);
    _renderAuditLiquidacion();
    openModal('modalAuditar');
    // [v2.41.64] BUG FIX race condition: si abrías audit OP002, cerrabas,
    // y antes que llegara el fetch abrías OP001, el fetch viejo de OP002
    // escribía "44" sobre el modal de OP001 (que tenía bon=0 → no entraba
    // a la rama de limpieza). Guard con token: solo aplicar el prefill si
    // el modal sigue mostrando ESTE idPersonal.
    _evalState.auditPrevBon = 0;
    _evalState.auditPrevSan = 0;
    _evalState.auditFetchToken = (_evalState.auditFetchToken || 0) + 1;
    const _myToken = _evalState.auditFetchToken;
    const _myIdPersonal = idPersonal;
    const _myFecha = _evalState.fecha;
    (async () => {
      try {
        const resp = await API.get('getLiqDiaBonSan', {
          idPersonal: _myIdPersonal,
          fecha: _myFecha
        });
        // GUARDS: si el modal cambió a otro personal/fecha, o ya hay otro
        // fetch en vuelo más nuevo, descartar este resultado.
        if (_myToken !== _evalState.auditFetchToken) return;
        if (!_evalState.auditR || _evalState.auditR.idPersonal !== _myIdPersonal) return;
        if (_evalState.fecha !== _myFecha) return;

        const d = (resp && resp.data) || resp || {};
        const bonAct = parseFloat(d.bonificacion) || 0;
        const sanAct = parseFloat(d.sancion) || 0;
        const bonMotAct = String(d.bonificacionMotivo || '');
        const sanMotAct = String(d.sancionMotivo || '');
        // Capturar valores previos para calcular delta en guardarAuditoria
        _evalState.auditPrevBon = bonAct;
        _evalState.auditPrevSan = sanAct;
        _evalState.auditPrevBonMot = bonMotAct;
        _evalState.auditPrevSanMot = sanMotAct;
        // [v2.43.373] Prellenar los DOS campos independientes con los valores
        // actuales (monto + motivo limpio de cada uno). Pueden estar ambos.
        const _setVal = (id, v) => { const el = $(id); if (el) el.value = v; };
        _setVal('auditBonifMonto',     bonAct > 0 ? bonAct.toFixed(2) : '');
        _setVal('auditBonifMotivoInp', bonAct > 0 ? bonMotAct : '');
        _setVal('auditSancionMonto',     sanAct > 0 ? sanAct.toFixed(2) : '');
        _setVal('auditSancionMotivoInp', sanAct > 0 ? sanMotAct : '');
        _renderAuditLiquidacion();
      } catch(_){}
    })();
  }

  // Actualiza visualmente el slider con el valor + track dorado proporcional
  function updateRateSlider(slId, valId) {
    const sl = $(slId);
    const lbl = $(valId);
    if (!sl) return;
    const v = parseFloat(sl.value) || 0;
    if (lbl) lbl.textContent = v + '%';
    // Track dorado proporcional (Webkit no soporta progress nativo)
    sl.style.background = `linear-gradient(90deg, #c9a227 0%, #ffd700 ${v}%, #1e293b ${v}%, #1e293b 100%)`;
  }

  function _renderAuditKpis(r) {
    const cont = $('auditKpis');
    if (!cont) return;
    const k = r.kpis || {};
    const rol = String(r.rol || '').toUpperCase();
    const auditMeta = k.metaAuditorias || 30;
    let rows = [];

    if (rol === 'CAJERO' || rol === 'VENDEDOR') {
      // POS — punto 1: meta diaria COMPARTIDA de la zona. La meta es del EQUIPO, así
      // que se muestra la venta total de la ZONA vs la meta (no la individual), para
      // que cuadre con la comisión (que se calcula sobre el excedente de la zona).
      const metaZona  = parseFloat(k.metaVenta) || 0;
      const ventaZona = parseFloat(k.ventaZona) || 0;
      const ventaYo   = parseFloat(k.ventasReales) || 0;
      const zonaNom   = k.zonaPrincipal ? ` · zona ${k.zonaPrincipal}` : '';
      if (metaZona > 0) {
        const pct = Math.min(100, (ventaZona / metaZona) * 100);
        rows.push(_kpiRow(
          `🎯 Meta diaria${zonaNom}`,
          `S/${ventaZona.toFixed(2)} / S/${metaZona.toFixed(0)}`,
          pct
        ));
      } else {
        rows.push(_kpiRow('🎯 Meta diaria', '⚠ Sin meta configurada · ver Infra', 0));
      }
      // POS — punto 2: auditorías de productos
      rows.push(_kpiRow('📋 Auditorías de productos', `${k.auditoriasHechas || 0}/${auditMeta}`, k.auditPct || 0));
      // POS — punto 3: comisión por ventas (5% del excedente de ZONA, repartido
      // proporcional a lo que vendió cada uno). Se muestra su aporte para que el
      // reparto sea transparente. Sale de la mega tabla (bono_meta), NO de GAS.
      const comi = parseFloat(k.comision) || 0;
      if (comi > 0) {
        rows.push(_kpiRow('💰 Comisión por ventas', `S/${comi.toFixed(2)} · tu venta S/${ventaYo.toFixed(0)}`, Math.min(100, k.ventasPct || 0)));
      }
    } else if (rol === 'ALMACENERO' || rol === 'ENVASADOR') {
      // Almacén — punto 1: auditorías
      rows.push(_kpiRow('📋 Auditorías diarias', `${k.auditoriasHechas || 0}/${auditMeta}`, k.auditPct || 0));
      // Almacén — punto 2: unidades envasadas + pago calculado (línea única)
      const envasados = parseFloat(k.envasados) || 0;
      const tarifa = parseFloat(r.tarifaEnvasado) || 0;
      const pagoEnvasado = parseFloat(r.pagoEnvasado) || (envasados * tarifa);
      const tipoEnv = envasados > 0
        ? `${envasados} uds × S/${tarifa.toFixed(2)} = S/${pagoEnvasado.toFixed(2)}`
        : `${envasados} uds`;
      rows.push(_kpiRow('🏷 Envasado del día', tipoEnv, Math.min(100, envasados / 5)));
    } else {
      rows.push(_kpiRow('Actividad del día', `${k.auditoriasHechas || 0}/${auditMeta}`, k.auditPct || 0));
    }

    // Score final y total estimado del día (info)
    rows.push(_kpiRow('🎯 Score acumulado', `${r.scoreFinal || 0}%`, r.scoreFinal || 0));
    cont.innerHTML = rows.join('');
  }

  function _kpiRow(label, val, pct) {
    return `<div class="audit-kpi-row" style="flex-direction:column;align-items:stretch;gap:4px">
      <div class="flex items-center justify-between">
        <span class="audit-kpi-label">${label}</span>
        <span class="audit-kpi-val">${val}</span>
      </div>
      <div class="audit-kpi-bar"><div style="width:${Math.min(100, pct)}%"></div></div>
    </div>`;
  }

  // ── Impresión liquidación 80mm desde modal Auditar ────────────
  // Abre selector de impresora (cacheado), agrupa por zona/app y envía
  // el job a PrintNode. La data del personal se hidrata server-side desde
  // getResumenDia para garantizar consistencia con liquidación semanal.
  async function imprimirLiquidacionDia() {
    const r = _evalState.auditR;
    if (!r) { _evalSfx('error'); toast('Abre primero una auditoría', 'error'); return; }
    const sub = $('liqPrintSubtitle');
    // [v2.41.49] Usar r.fecha (la fecha REAL del resumen abierto), no
    // _evalState.fecha (global que cambia al navegar entre días).
    if (sub) sub.textContent = `${r.nombre || ''} · ${r.rol || ''} · ${r.fecha || _evalState.fecha}`;
    openModal('modalSelPrinterLiq');
    _evalSfx('open');
    await _liqLoadPrinters(false);
  }

  async function _liqLoadPrinters(forceRefresh) {
    const cont = $('liqPrinterList');
    if (!cont) return;
    // [v2.41.82] Aplicar filtros del PrinterPicker antes de renderizar
    const _render = (rawList) => {
      const lista = (typeof _pPickAplicarFiltros === 'function')
        ? _pPickAplicarFiltros(rawList)
        : rawList;
      // Actualizar contador
      const cnt = document.getElementById('ppCount');
      if (cnt) {
        const tot = (rawList || []).length;
        cnt.textContent = lista.length === tot ? `${tot} impresora${tot !== 1 ? 's' : ''}` : `${lista.length} de ${tot}`;
      }
      _liqRenderPrinters(lista);
    };
    if (!forceRefresh && _evalState.pnPrinters && _evalState.pnPrinters.length) {
      _render(_evalState.pnPrinters);
      return;
    }
    cont.innerHTML = `<div class="text-center text-xs text-slate-500 py-8">
      <div class="inline-block animate-spin">⏳</div> Consultando PrintNode...
    </div>`;
    try {
      const data = await API.get('listarImpresorasPN', {});
      _evalState.pnPrinters = Array.isArray(data) ? data : (data && data.data) || [];
      _render(_evalState.pnPrinters);
    } catch(e) {
      cont.innerHTML = `<div class="text-center text-xs text-rose-400 py-8">
        ⚠ Error: ${(e && e.message) || e}
      </div>`;
    }
  }

  function _liqRenderPrinters(list) {
    const cont = $('liqPrinterList');
    if (!cont) return;
    if (!list || !list.length) {
      cont.innerHTML = `<div class="text-center text-xs text-slate-500 py-8">
        <div class="text-3xl mb-2 opacity-50">🖨</div>
        No hay impresoras registradas en el catálogo MOS.<br>
        <span class="text-[10px]">Configúralas en Infraestructura → Impresoras.</span>
      </div>`;
      return;
    }
    // Agrupación: 📍 Zona (nombre) → 🏷 Estación (nombre) → impresoras
    // Solo viene catálogo activo (filtrado en backend).
    const zonas = {}; // { zonaKey: { label, estaciones: { estKey: { label, printers[] } }, sinEst: [] } }
    list.forEach(p => {
      const zonaKey = p.idZona || '_sin_zona';
      const zonaLbl = p.zonaNombre || p.idZona || '(sin zona)';
      if (!zonas[zonaKey]) zonas[zonaKey] = { label: zonaLbl, estaciones: {}, sinEst: [] };
      if (p.idEstacion) {
        const estKey = p.idEstacion;
        const estLbl = p.estacionNombre || p.idEstacion;
        if (!zonas[zonaKey].estaciones[estKey]) {
          zonas[zonaKey].estaciones[estKey] = { label: estLbl, printers: [] };
        }
        zonas[zonaKey].estaciones[estKey].printers.push(p);
      } else {
        zonas[zonaKey].sinEst.push(p);
      }
    });

    const pCard = (p, idx) => {
      // [v2.41.81] Estado semántico — deshabilita la card si NO está ONLINE
      // y muestra la razón específica del problema (sin papel, PC apagada,
      // ID inválido, etc.) en vez del genérico "offline" anterior.
      const stateOk = p.state === 'ONLINE' || (p.online === true && !p.state);
      const offClass    = stateOk ? '' : 'printer-card-disabled';
      const dotColor    = stateOk ? '#34d399'
                        : (p.color === 'orange'  ? '#f97316'
                        :  p.color === 'yellow'  ? '#fbbf24'
                        :  '#f87171');
      const dotCls      = stateOk ? 'printer-dot-online' : '';
      const tagTxt      = stateOk ? 'online'
                        : (p.icon ? (p.icon + ' ' + (p.reason || p.state || 'problema')) : (p.reason || 'offline'));
      const tagCls      = stateOk ? 'text-emerald-400 font-semibold'
                        : (p.color === 'orange'  ? 'text-orange-400'
                        :  p.color === 'yellow'  ? 'text-amber-400'
                        :  'text-rose-400');
      const tagHtml     = `<span class="text-[9px] ${tagCls} ml-1">${_escapeHtml(tagTxt)}</span>`;
      // Línea sub: tipo · nombre PrintNode crudo · PC (con estado de la PC si offline)
      const tipoIco = p.tipo === 'ADHESIVO' ? '🏷' : '🧾';
      const compTag = p.computer
        ? '· 💻 ' + p.computer + (p.computerState && p.computerState !== 'connected' ? ' <span class="text-orange-400">(desconectada)</span>' : '')
        : '';
      const subMeta = [
        tipoIco + ' ' + (p.tipo || 'TICKET'),
        p.nombrePN && p.nombrePN !== p.nombre ? '· ' + p.nombrePN : '',
        compTag
      ].filter(Boolean).join(' ');
      const onClick = stateOk
        ? `onclick="MOS._liqEnviarPrint(${p.id}, this, event)"`
        : `onclick="event.preventDefault();MOS._liqAvisarImpresoraNoLista(${p.id || 'null'}, '${_escapeHtml(p.reason || p.state || 'No disponible').replace(/'/g, '&#39;')}')"`;
      return `<button ${onClick}
                      class="printer-card btn-ripple w-full text-left rounded-lg p-2 ${offClass}"
                      title="${_escapeHtml(p.reason || tagTxt)}"
                      style="background:linear-gradient(135deg,#060d1f,#0a1428);border:1px solid ${stateOk ? '#1e293b' : 'rgba(239,68,68,.35)'};
                             animation: checklistItemIn .35s cubic-bezier(.34,1.56,.64,1) backwards;
                             animation-delay:${idx*40}ms">
        <div class="flex items-center gap-2">
          <span class="${dotCls}" style="width:10px;height:10px;border-radius:999px;background:${dotColor};box-shadow:0 0 8px ${dotColor}"></span>
          <span class="text-sm text-slate-100 font-semibold flex-1">${p.nombre}</span>
          ${tagHtml}
        </div>
        ${subMeta ? `<div class="text-[10px] text-slate-500 mt-1 pl-4">${subMeta}</div>` : ''}
      </button>`;
    };

    const html = Object.keys(zonas)
      .sort((a,b) => zonas[a].label.localeCompare(zonas[b].label))
      .map(zk => {
        const z = zonas[zk];
        // Estaciones de esta zona, ordenadas alfabéticamente
        let printerIdx = 0;
        const estHtml = Object.keys(z.estaciones)
          .sort((a,b) => z.estaciones[a].label.localeCompare(z.estaciones[b].label))
          .map(ek => {
            const e = z.estaciones[ek];
            const items = e.printers
              .sort((a,b) => (b.online?1:0) - (a.online?1:0) || String(a.nombre||'').localeCompare(String(b.nombre||'')))
              .map(p => pCard(p, printerIdx++))
              .join('');
            return `<div class="mb-2">
              <div class="text-[10px] font-semibold tracking-wider text-amber-400/70 mb-1 pl-1 flex items-center gap-1">
                <span>🏷</span><span>${e.label}</span>
                <span class="text-[9px] text-slate-600 ml-auto">${e.printers.length} imp.</span>
              </div>
              <div class="space-y-1">${items}</div>
            </div>`;
          }).join('');
        // Impresoras de la zona sin estación asignada
        const sinEstHtml = z.sinEst.length ? `<div class="mb-2">
          <div class="text-[10px] font-semibold tracking-wider text-slate-500 mb-1 pl-1">
            (sin estación asignada)
          </div>
          <div class="space-y-1">${z.sinEst.sort((a,b) => (b.online?1:0) - (a.online?1:0)).map(p => pCard(p, printerIdx++)).join('')}</div>
        </div>` : '';

        return `<div class="rounded-lg p-2"
                     style="background:rgba(251,191,36,.03);border:1px solid rgba(251,191,36,.12)">
          <div class="text-[11px] font-bold uppercase tracking-wider text-amber-300 mb-2 px-1 flex items-center gap-1">
            <span>📍</span><span>${z.label}</span>
          </div>
          ${estHtml}${sinEstHtml}
        </div>`;
      }).join('');
    cont.innerHTML = html;
  }

  // [v2.41.81] Aviso al tocar una impresora no-ONLINE en el modal de selección.
  // Le explica al admin POR QUÉ no puede imprimir ahora con la razón concreta.
  function _liqAvisarImpresoraNoLista(printerId, razon) {
    try { _evalSfx && _evalSfx('error'); } catch(_){}
    toast(`🖨 No puedo imprimir: ${razon}`, 'error', 5000);
  }

  // [v2.43.375] Ticket de liquidación armado en el FRONT (cero-GAS) → Edge `imprimir`.
  // Orden CRONOLÓGICO (datos → asistencia → logros → ajustes → total). Comentarios
  // COMPLETOS en varias líneas (nunca cortados). Español profesional con acentos
  // (codepage WPC1252 + Latin-1). Sin emojis (el térmico no los muestra).
  function _buildTicketLiquidacionESCPOS(r, fecha) {
    const W = 48;
    const rep = (ch, n) => ch.repeat(Math.max(0, n));
    // Conserva acentos/ñ (Latin-1, 0x80–0xFF); solo descarta lo que el térmico no puede (emojis, etc.).
    const norm = (s) => String(s == null ? '' : s).normalize('NFC').replace(/[^\x20-\xFF]/g, '');
    const pe = (s, w) => { s = norm(s).slice(0, w); return s + rep(' ', w - s.length); };
    const ps = (s, w) => { s = norm(s); return rep(' ', Math.max(0, w - s.length)) + s; };
    const money = (n) => 'S/' + (parseFloat(n) || 0).toFixed(2);
    const amtP = (n, w) => ps(money(n), w);
    const amtN = (n, w) => { const v = parseFloat(n) || 0; return ps((v < 0 ? '-' : '') + 'S/' + Math.abs(v).toFixed(2), w); };
    const SEP = rep('=', W) + '\n', SEPd = rep('-', W) + '\n';
    const hdr = (s) => { const x = ' ' + s + ' '; const l = Math.floor((W - x.length) / 2); return rep('=', Math.max(0, l)) + x + rep('=', Math.max(0, W - x.length - l)) + '\n'; };
    // Comentario COMPLETO, indentado, partido por PALABRAS en varias líneas (nunca corta una palabra).
    const wrapInd = (s, ind) => {
      const t = norm(s).trim(); if (!t) return '';
      const max = W - ind.length; const palabras = t.split(/\s+/); let linea = '', out = '';
      for (const w of palabras) {
        if (linea && (linea.length + 1 + w.length) > max) { out += ind + linea + '\n'; linea = w; }
        else { linea = linea ? (linea + ' ' + w) : w; }
        while (linea.length > max) { out += ind + linea.slice(0, max) + '\n'; linea = linea.slice(max); } // palabra larguísima
      }
      if (linea) out += ind + linea + '\n';
      return out;
    };
    const rolU = String(r.rol || '').toUpperCase();
    const esPos = (rolU === 'CAJERO' || rolU === 'VENDEDOR');
    const esAlm = (rolU === 'ALMACENERO' || rolU === 'ENVASADOR');
    const k = r.kpis || {};
    const bonMeta = parseFloat(r.bonoMeta) || 0;
    const bonif   = parseFloat(r.bonificacion) || 0;
    const sanc    = parseFloat(r.sancion) || 0;
    const bonMot  = r.bonificacionMotivo || '';
    const sanMot  = r.sancionMotivo || '';
    const horaIng = r.horaIngreso || r.hora_ingreso || (k && k.horaIngreso) || '';
    const ultCon  = r.ultimaConexion || r.ultima_conexion || '';

    let t = '';
    // init + codepage WPC1252 (table 16) → acentos/ñ correctos en el térmico.
    t += '\x1b\x40\x1b\x74\x10';
    t += '\x1b\x61\x01\x1b\x21\x30' + norm('LIQUIDACIÓN DEL DÍA') + '\n\x1b\x21\x00';
    t += norm('Inversiones MOS · Personal') + '\n\x1b\x61\x00' + SEP;
    // 1) DATOS
    t += pe('Fecha', 12) + ': ' + norm(fecha) + '\n';
    t += pe('Personal', 12) + ': ' + norm(r.nombre) + '\n';
    t += pe('Rol', 12) + ': ' + norm(r.rol || '') + '\n';
    if (k.zonaPrincipal || r.zona) t += pe('Zona', 12) + ': ' + norm(k.zonaPrincipal || r.zona) + '\n';
    t += pe('Auditado', 12) + ': ' + (r.auditado ? ((r.evaluacionesCount || 0) + ' vez(ces)') : 'No') + '\n';
    // 2) ASISTENCIA (cronológico: ingreso → última conexión)
    if (horaIng || ultCon) {
      t += SEPd;
      if (horaIng) t += pe('Ingreso', 12) + ': ' + norm(horaIng) + '\n';
      if (ultCon)  t += pe('Últ. conex.', 12) + ': ' + norm(ultCon) + '\n';
    }
    t += SEP;
    // 3) LIQUIDACIÓN (desglose, cada concepto con su comentario completo)
    t += '\x1b\x21\x10' + hdr('LIQUIDACIÓN') + '\x1b\x21\x00';
    t += pe('Base diaria', W - 12) + amtP(r.montoBase, 12) + '\n';
    if (esPos) {
      t += pe('Comisión por ventas', W - 12) + amtP(bonMeta, 12) + '\n';
      const vc = parseFloat(r.ventaCobrada ?? k.ventasReales) || 0;
      const mz = parseFloat(r.metaZona ?? k.metaVenta) || 0;
      if (vc > 0 || mz > 0) t += wrapInd('Vendió ' + money(vc) + ' · meta de zona ' + money(mz), '  ');
    } else if (esAlm) {
      const uds = parseFloat(r.productosEnvasados ?? k.envasados) || 0;
      const tar = parseFloat(r.tarifaEnvasado) || 0.10;
      t += pe('Pago por envasado', W - 12) + amtP(r.pagoEnvasado, 12) + '\n';
      if (uds > 0) t += wrapInd(uds + ' unidades × ' + money(tar), '  ');
    }
    if (bonif > 0) {
      t += '\x1b\x45\x01' + pe('Bonificación (+)', W - 12) + amtP(bonif, 12) + '\x1b\x45\x00\n';
      t += wrapInd('Motivo: ' + (bonMot || 'sin especificar'), '   ');
    }
    if (sanc > 0) {
      t += '\x1b\x45\x01' + pe('Sanción / descuento (-)', W - 12) + amtN(-sanc, 12) + '\x1b\x45\x00\n';
      t += wrapInd('Motivo: ' + (sanMot || 'sin especificar'), '   ');
    }
    t += SEPd + '\x1b\x21\x30' + pe('TOTAL A PAGAR', W / 2) + amtP(r.totalDia, W / 2 - 4) + '\n\x1b\x21\x00' + SEPd;
    // 4) AUDITORÍAS (cuota del día)
    const aud = parseFloat(r.auditoriasHechas ?? k.auditoriasHechas) || 0;
    const mAud = parseFloat(r.metaAuditorias ?? k.metaAuditorias) || 30;
    t += pe('Auditorías del día', W - 12) + ps(aud + ' / ' + mAud, 12) + '\n';
    t += SEPd;
    t += '\n' + pe('Firma del personal', 20) + ' ' + rep('_', W - 22) + '\n\n';
    t += pe('V°B° administración', 20) + ' ' + rep('_', W - 22) + '\n\n';
    t += '\x1b\x61\x01\x1b\x45\x01--- FIN ---\x1b\x45\x00\n' + norm('Impreso desde MOS') + '\n';
    t += '\n\n\n\n\x1d\x56\x00';
    return t;
  }

  async function _liqEnviarPrint(printerId, btnEl, ev) {
    const r = _evalState.auditR;
    if (!r) { _evalSfx('error'); toast('Falta resumen', 'error'); return; }
    _evalSfx('print');
    if (ev) _evalRipple(ev);
    // Marcar la card como "enviando" + pulse en el botón de imprimir del modal
    if (btnEl) btnEl.classList.add('sending');
    const printBtn = $('auditPrintBtn');
    if (printBtn) printBtn.classList.add('printing');
    try {
      // [v2.43.375] cero-GAS: armamos el ESC/POS en el front (multilínea) y lo mandamos
      // a la Edge `imprimir` (relay a PrintNode). Antes iba por GAS imprimirLiquidacionDia.
      const fechaImp = r.fecha || _evalState.fecha;
      const _ticket = _buildTicketLiquidacionESCPOS(r, fechaImp);
      const res = await API.imprimirTicketEdge(parseInt(printerId, 10),
        'Liquidacion ' + (r.nombre || '') + ' ' + fechaImp, _ticket);
      _evalSfx('success');
      // Confetti dorado desde el botón clickeado
      try {
        const rect = (btnEl || $('liqPrinterList')).getBoundingClientRect();
        _evalConfetti(rect.left + rect.width/2, rect.top + rect.height/2, '#fbbf24');
      } catch(_){}
      toast(`✓ Liquidación enviada · S/${(parseFloat(r.totalDia) || 0).toFixed(2)}`, 'ok');
      closeModal('modalSelPrinterLiq');
    } catch(e) {
      _evalSfx('error');
      toast('Error: ' + ((e && e.message) || e), 'error');
      _liqRenderPrinters(_evalState.pnPrinters || []);
    } finally {
      if (btnEl) btnEl.classList.remove('sending');
      if (printBtn) printBtn.classList.remove('printing');
    }
  }

  // ── Liquidación en vivo dentro del modal Auditar ──────────────
  // Recalcula base + bonos + envasado − sanción y lo muestra como
  // desglose profesional. Se reactiva ante:
  // [v2.41.51] Toggle entre sanción (-) y bonificación (+). Aplica a todos
  // los roles. Cambia el color del input y el signo.
  // [v2.43.373] Handler de los dos campos de ajuste (bonif/sanción): marca tocado y
  // refresca la liquidación en vivo del modal.
  function _auditAjusteInput() {
    _evalState.auditAjusteTocado = true;
    _renderAuditLiquidacion();
  }
  // _auditSetAjuste: legacy (el toggle único ya no existe). Se conserva como no-op
  // defensivo por si quedó alguna referencia; no manipula DOM eliminado.
  function _auditSetAjuste(tipo, userInitiated) {
    if (tipo !== 'sancion' && tipo !== 'bonificacion') tipo = 'sancion';
    _evalState.auditAjusteTipo = tipo;
    // [v2.41.63] Si el user hizo click manual en el toggle, marcar tocado
    if (userInitiated === true) _evalState.auditAjusteTocado = true;
    const tog = document.getElementById('auditAjusteToggle');
    const sig = document.getElementById('auditAjusteSigno');
    const inp = document.getElementById('auditAjusteMonto');
    const mot = document.getElementById('auditAjusteMotivo');
    const hint = document.getElementById('auditAjusteHint');
    if (tog) {
      tog.querySelectorAll('button[data-tipo]').forEach(b => {
        const activo = b.dataset.tipo === tipo;
        if (tipo === 'sancion') {
          b.style.background = activo ? 'rgba(248,113,113,.25)' : 'rgba(15,23,42,.5)';
          b.style.color      = activo ? '#fca5a5' : '#94a3b8';
          b.style.borderColor= activo ? 'rgba(248,113,113,.55)' : 'rgba(148,163,184,.2)';
        } else {
          b.style.background = activo ? 'rgba(34,197,94,.22)' : 'rgba(15,23,42,.5)';
          b.style.color      = activo ? '#86efac' : '#94a3b8';
          b.style.borderColor= activo ? 'rgba(34,197,94,.55)' : 'rgba(148,163,184,.2)';
        }
      });
    }
    if (tipo === 'sancion') {
      if (sig) { sig.textContent = '−S/'; sig.style.color = '#f87171'; }
      if (inp) inp.style.borderColor = 'rgba(248,113,113,.3)';
      if (mot) {
        mot.placeholder = 'Motivo de la sanción (ej: falta de aseo, incumplimiento)';
        mot.style.borderColor = 'rgba(248,113,113,.2)';
      }
      if (hint) hint.textContent = 'descuenta del total';
    } else {
      if (sig) { sig.textContent = '+S/'; sig.style.color = '#34d399'; }
      if (inp) inp.style.borderColor = 'rgba(34,197,94,.35)';
      if (mot) {
        mot.placeholder = 'Motivo de la bonificación (ej: esfuerzo extra, día complicado)';
        mot.style.borderColor = 'rgba(34,197,94,.25)';
      }
      if (hint) hint.textContent = 'suma al total';
    }
    if (typeof _renderAuditLiquidacion === 'function') _renderAuditLiquidacion();
  }

  //   - cambios en sanción (input)
  //   - toggle de comisión (afecta bono score)
  //   - toggle de meta (afecta bono meta)
  function _renderAuditLiquidacion() {
    const wrap  = $('auditLiquidacionWrap');
    const lines = $('auditLiquidacionLines');
    const totEl = $('auditLiquidacionTotal');
    if (!wrap || !lines || !totEl) return;
    const r = _evalState.auditR;
    if (!r) return;

    const rol = String(r.rol || '').toUpperCase();
    const esPos = (rol === 'CAJERO' || rol === 'VENDEDOR');
    const esAlm = (rol === 'ALMACENERO' || rol === 'ENVASADOR');

    const base       = parseFloat(r.montoBase)    || 0;
    const bonoMeta   = parseFloat(r.bonoMeta)     || 0;
    const pagoEnv    = parseFloat(r.pagoEnvasado) || 0;
    // [v2.43.373] Dos campos independientes: bonificación (+) y sanción (−), coexisten.
    const _num = (id) => Math.max(0, parseFloat(String($(id)?.value || '').replace(',', '.')) || 0);
    const bonificacion = _num('auditBonifMonto');
    const sancion      = _num('auditSancionMonto');

    const togMeta = $('auditTogMeta');
    const aplicaMeta = togMeta ? togMeta.classList.contains('on') : true;
    const metaEf  = aplicaMeta ? bonoMeta : 0;

    const items = [];
    items.push(['💵 Base diaria', base, false]);
    if (esPos) {
      items.push(['🎯 Bono por meta', metaEf, false, !aplicaMeta ? 'meta desactivada' : (bonoMeta === 0 ? 'meta no lograda' : '')]);
    } else if (esAlm) {
      items.push(['🏷 Pago envasado', pagoEnv, false]);
    }
    if (bonificacion > 0) items.push(['🎁 Bonificación', bonificacion, false]);
    if (sancion > 0) items.push(['⚠ Sanción del día', sancion, true]);

    lines.innerHTML = items.map(([lbl, val, neg, note]) => {
      const signo = neg ? '−' : '';
      const color = neg ? '#f87171'
                       : lbl.indexOf('Bonificación') === 0 ? '#34d399'
                       : (val > 0 ? '#e2e8f0' : '#64748b');
      const noteHtml = note ? `<span class="text-[9px] text-slate-500 ml-1">(${note})</span>` : '';
      return `<div class="flex items-center justify-between">
        <span class="text-slate-400">${lbl}${noteHtml}</span>
        <span style="color:${color};font-variant-numeric:tabular-nums">${signo}S/${val.toFixed(2)}</span>
      </div>`;
    }).join('');

    const total = Math.max(0, base + metaEf + (esAlm ? pagoEnv : 0) + bonificacion - sancion);
    const totalStr = `S/${total.toFixed(2)}`;
    const cambio = totEl.textContent !== totalStr;
    totEl.textContent = totalStr;
    if (sancion > 0 && (base + metaEf + (esAlm ? pagoEnv : 0) + bonificacion - sancion) < 0) {
      totEl.style.color = '#f87171';
      totEl.title = 'Sanción excede el total, se trunca a S/0.00';
    } else {
      totEl.style.color = '#fbbf24';
      totEl.title = '';
    }
    // Bump animado + tick sonoro al cambiar el total
    if (cambio && _evalState.auditR) {
      totEl.classList.remove('bumping');
      // Reflow forzado para reiniciar la animación
      void totEl.offsetWidth;
      totEl.classList.add('bumping');
      _evalSfx('tap');
      setTimeout(() => totEl.classList.remove('bumping'), 500);
    }
  }

  function _renderAuditChecklist(rol) {
    const cont = $('auditControlList');
    if (!cont) return;
    const items = _evalChecklistDe(rol);
    cont.innerHTML = items.map((txt, i) => {
      const key = 'c' + i;
      const checked = !!_evalState.auditChecks[key];
      return `
        <div class="audit-check-row${checked ? ' checked' : ''}" data-key="${key}" onclick="MOS.auditToggleCheck('${key}')">
          <div class="audit-check-box"></div>
          <span>${txt}</span>
        </div>`;
    }).join('');
  }

  // ============================================================
  // ── SFX + efectos del módulo Evaluación ──────────────────────
  // Sonidos sintetizados (sin assets externos) + confetti + ripple
  // ============================================================
  let _evalAudioCtx = null;
  function _evalSfx(tipo) {
    try {
      if (!_evalAudioCtx) _evalAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const ctx = _evalAudioCtx; const t = ctx.currentTime;
      function tone(freq, dur, gainVal, opts) {
        const o = ctx.createOscillator(); const g = ctx.createGain();
        o.type = (opts && opts.type) || 'sine';
        o.frequency.setValueAtTime(freq, t + (opts?.delay || 0));
        if (opts?.glide) o.frequency.exponentialRampToValueAtTime(opts.glide, t + (opts?.delay || 0) + dur);
        g.gain.setValueAtTime(gainVal, t + (opts?.delay || 0));
        g.gain.exponentialRampToValueAtTime(0.0001, t + (opts?.delay || 0) + dur);
        o.connect(g); g.connect(ctx.destination);
        o.start(t + (opts?.delay || 0)); o.stop(t + (opts?.delay || 0) + dur + 0.01);
      }
      switch (tipo) {
        case 'tap':     tone(1400, .035, .04, { type:'triangle' }); break;
        case 'click':   tone(1100, .04,  .05); tone(1500, .03, .03, { delay:.02 }); break;
        case 'pop':     tone(900,  .06,  .05, { type:'sine', glide: 380 }); break;
        case 'add':     tone(700,  .05,  .05); tone(1050, .06, .05, { delay:.05 }); tone(1400, .07, .04, { delay:.10 }); break;
        case 'remove':  tone(420,  .12,  .055, { type:'sawtooth', glide: 180 }); break;
        case 'drag':    tone(620,  .04,  .03, { type:'triangle' }); break;
        case 'drop':    tone(880,  .07,  .045); tone(660, .08, .04, { delay:.04 }); break;
        case 'switch':  tone(800,  .04,  .04, { type:'triangle' }); tone(1100, .04, .04, { delay:.04, type:'triangle' }); break;
        case 'success': tone(660,  .08,  .06); tone(990, .08, .06, { delay:.08 }); tone(1320, .12, .065, { delay:.16 }); break;
        // [v2.41.74] 'cash' — sonido caja registradora para pagos
        case 'cash':    tone(1320, .05, .07, { type:'square' }); tone(1760, .05, .07, { delay:.06, type:'square' }); tone(880, .06, .05, { delay:.13, type:'triangle' }); tone(1320, .14, .06, { delay:.22, type:'sine' }); tone(990, .12, .05, { delay:.30, type:'sine' }); break;
        case 'print':   tone(440,  .15,  .04, { type:'sawtooth' }); tone(880, .18, .045, { delay:.05, type:'sawtooth' }); break;
        case 'error':   tone(220,  .22,  .07, { type:'square', glide: 140 }); break;
        case 'open':    tone(520,  .06,  .04); tone(780, .08, .045, { delay:.04 }); break;
      }
    } catch(_){}
  }
  // Expone módulo para que otros sitios reutilicen
  function _evalRipple(ev) {
    try {
      const el = ev.currentTarget;
      if (!el || !el.classList || !el.classList.contains('btn-ripple')) return;
      const rect = el.getBoundingClientRect();
      const size = Math.max(rect.width, rect.height);
      const r = document.createElement('span');
      r.className = 'ripple';
      r.style.width = r.style.height = size + 'px';
      r.style.left = (ev.clientX - rect.left - size/2) + 'px';
      r.style.top  = (ev.clientY - rect.top  - size/2) + 'px';
      el.appendChild(r);
      setTimeout(() => { try { r.remove(); } catch(_){} }, 600);
    } catch(_){}
  }
  function _evalConfetti(originX, originY, color) {
    try {
      const count = 26;
      const colors = color
        ? [color]
        : ['#fbbf24', '#fde68a', '#34d399', '#60a5fa', '#a78bfa', '#f472b6'];
      for (let i = 0; i < count; i++) {
        const el = document.createElement('div');
        el.className = 'confetti-burst';
        const angle = (Math.PI * 2 * i) / count + (Math.random()*0.4 - 0.2);
        const dist  = 80 + Math.random()*160;
        const dx    = Math.cos(angle) * dist;
        const dy    = Math.sin(angle) * dist + 60; // sesgo a caer
        el.style.left = originX + 'px';
        el.style.top  = originY + 'px';
        el.style.background = colors[i % colors.length];
        el.style.setProperty('--dx',  dx + 'px');
        el.style.setProperty('--dy',  dy + 'px');
        el.style.setProperty('--rot', (360 + Math.random()*720) + 'deg');
        el.style.setProperty('--dur', (1 + Math.random()*0.8) + 's');
        document.body.appendChild(el);
        setTimeout(() => { try { el.remove(); } catch(_){} }, 2000);
      }
    } catch(_){}
  }

  // ============================================================
  // ── EDITOR DE CHECKLISTS (modalEvalChecklists) ───────────────
  // ============================================================
  // Estado del editor: copia mutable de _evalState.rolItems
  // que se commitea a CONFIG_MOS al pulsar "Guardar todos".
  const _checklistEditor = {
    rolActivo: 'CAJERO',
    items: { CAJERO: [], VENDEDOR: [], ALMACENERO: [], ENVASADOR: [] },
    dirty: false
  };

  async function abrirEditorChecklists(ev) {
    if (ev) _evalRipple(ev);
    _evalState.rolItems = null;
    ['CAJERO','VENDEDOR','ALMACENERO','ENVASADOR'].forEach(r => _evalChecklistDe(r));
    ['CAJERO','VENDEDOR','ALMACENERO','ENVASADOR'].forEach(r => {
      _checklistEditor.items[r] = (_evalState.rolItems[r] || []).slice();
    });
    _checklistEditor.rolActivo = 'CAJERO';
    _checklistEditor.dirty = false;
    _renderChecklistEditor();
    openModal('modalEvalChecklists');
    _evalSfx('open');
  }

  function _renderChecklistEditor() {
    // Tabs activas
    document.querySelectorAll('#checklistTabs .checklist-tab').forEach(b => {
      b.classList.toggle('active', b.dataset.rol === _checklistEditor.rolActivo);
    });
    const cont = $('checklistItems');
    if (!cont) return;
    const list = _checklistEditor.items[_checklistEditor.rolActivo] || [];
    if (!list.length) {
      cont.innerHTML = `<div class="text-center text-xs text-slate-500 py-8">
        <div class="text-3xl mb-2 opacity-50">📋</div>
        Sin ítems. Añade el primero abajo o restaura los por defecto.
      </div>`;
      return;
    }
    cont.innerHTML = list.map((txt, i) => `
      <div class="checklist-item-row" draggable="true" data-idx="${i}"
           style="animation-delay: ${i * 35}ms"
           ondragstart="MOS._checklistDragStart(event,${i})"
           ondragover="MOS._checklistDragOver(event)"
           ondrop="MOS._checklistDrop(event,${i})"
           ondragend="MOS._checklistDragEnd(event)">
        <span class="checklist-handle" title="Arrastra para reordenar">⋮⋮</span>
        <input type="text" class="checklist-item-input" value="${String(txt).replace(/"/g,'&quot;')}"
               oninput="MOS._checklistEditItem(${i}, this.value)">
        <button class="checklist-del" onclick="MOS._checklistDelItem(${i})" title="Eliminar">✕</button>
      </div>
    `).join('');
  }

  function checklistSetRol(rol) {
    const nuevo = String(rol || 'CAJERO').toUpperCase();
    if (_checklistEditor.rolActivo === nuevo) return;
    _checklistEditor.rolActivo = nuevo;
    _renderChecklistEditor();
    _evalSfx('switch');
  }

  function checklistAddItem(ev) {
    const inp = $('checklistNewItem');
    if (!inp) return;
    const val = String(inp.value || '').trim();
    if (!val) { inp.focus(); _evalSfx('error'); return; }
    _checklistEditor.items[_checklistEditor.rolActivo].push(val);
    _checklistEditor.dirty = true;
    inp.value = '';
    _renderChecklistEditor();
    _evalSfx('add');
    if (ev) _evalRipple(ev);
    // Scroll al final para mostrar el ítem recién añadido
    requestAnimationFrame(() => {
      const items = $('checklistItems');
      if (items) items.lastElementChild?.scrollIntoView({ behavior:'smooth', block:'nearest' });
    });
    inp.focus();
  }

  function _checklistEditItem(idx, val) {
    const list = _checklistEditor.items[_checklistEditor.rolActivo];
    if (list && list[idx] !== undefined) {
      list[idx] = String(val || '');
      _checklistEditor.dirty = true;
    }
  }

  function _checklistDelItem(idx) {
    const list = _checklistEditor.items[_checklistEditor.rolActivo];
    if (!list || list[idx] === undefined) return;
    _evalSfx('remove');
    // Animar la salida antes de borrar
    const row = document.querySelector(`.checklist-item-row[data-idx="${idx}"]`);
    if (row) {
      row.classList.add('removing');
      setTimeout(() => {
        list.splice(idx, 1);
        _checklistEditor.dirty = true;
        _renderChecklistEditor();
      }, 260);
    } else {
      list.splice(idx, 1);
      _checklistEditor.dirty = true;
      _renderChecklistEditor();
    }
  }

  // Drag & drop reorder
  let _dragIdx = null;
  function _checklistDragStart(ev, idx) {
    _dragIdx = idx;
    try { ev.dataTransfer.effectAllowed = 'move'; ev.dataTransfer.setData('text/plain', String(idx)); } catch(_){}
    ev.currentTarget.classList.add('dragging');
    _evalSfx('drag');
  }
  function _checklistDragOver(ev) { ev.preventDefault(); try { ev.dataTransfer.dropEffect = 'move'; } catch(_){} }
  function _checklistDrop(ev, dstIdx) {
    ev.preventDefault();
    const src = _dragIdx;
    if (src === null || src === dstIdx) return;
    const list = _checklistEditor.items[_checklistEditor.rolActivo];
    const [moved] = list.splice(src, 1);
    list.splice(dstIdx, 0, moved);
    _checklistEditor.dirty = true;
    _renderChecklistEditor();
    _evalSfx('drop');
    // Highlight visual al ítem recién soltado
    requestAnimationFrame(() => {
      const row = document.querySelector(`.checklist-item-row[data-idx="${dstIdx}"]`);
      if (row) {
        row.classList.add('dropping');
        setTimeout(() => row.classList.remove('dropping'), 400);
      }
    });
  }
  function _checklistDragEnd(ev) {
    _dragIdx = null;
    document.querySelectorAll('.checklist-item-row.dragging').forEach(r => r.classList.remove('dragging'));
  }

  function checklistResetRol() {
    const rol = _checklistEditor.rolActivo;
    const def = _evalState.rolItemsDefault[rol] || [];
    _checklistEditor.items[rol] = def.slice();
    _checklistEditor.dirty = true;
    _renderChecklistEditor();
    _evalSfx('pop');
    toast(`Checklist de ${rol} restaurada al default`, 'info');
  }

  async function guardarChecklists(ev) {
    if (ev) _evalRipple(ev);
    const btn = $('checklistSaveBtn');
    if (btn) { btn.disabled = true; btn.textContent = 'Guardando...'; }
    try {
      const pares = ['CAJERO','VENDEDOR','ALMACENERO','ENVASADOR'].map(r => ({
        clave: 'evalChecklist' + r,
        valor: JSON.stringify(_checklistEditor.items[r] || [])
      }));
      await Promise.all(pares.map(p =>
        API.post('setConfig', { clave: p.clave, valor: p.valor })
      ));
      // Propagar a la sesión actual: pisar _evalState.rolItems y limpiar cfg cache
      _evalState.rolItems = {
        CAJERO:     _checklistEditor.items.CAJERO.slice(),
        VENDEDOR:   _checklistEditor.items.VENDEDOR.slice(),
        ALMACENERO: _checklistEditor.items.ALMACENERO.slice(),
        ENVASADOR:  _checklistEditor.items.ENVASADOR.slice()
      };
      try {
        if (cfgData.config) {
          cfgData.config.evalChecklistCAJERO     = JSON.stringify(_evalState.rolItems.CAJERO);
          cfgData.config.evalChecklistVENDEDOR   = JSON.stringify(_evalState.rolItems.VENDEDOR);
          cfgData.config.evalChecklistALMACENERO = JSON.stringify(_evalState.rolItems.ALMACENERO);
          cfgData.config.evalChecklistENVASADOR  = JSON.stringify(_evalState.rolItems.ENVASADOR);
        }
      } catch(_){}
      _checklistEditor.dirty = false;
      _evalSfx('success');
      // Confetti centrado en el botón guardar
      try {
        const btnRect = $('checklistSaveBtn').getBoundingClientRect();
        _evalConfetti(btnRect.left + btnRect.width/2, btnRect.top + btnRect.height/2);
      } catch(_){}
      toast('✓ Checklists guardados — aplicado a la próxima auditoría', 'ok');
      closeModal('modalEvalChecklists');
    } catch(e) {
      _evalSfx('error');
      toast('Error guardando: ' + (e.message || e), 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = '💾 Guardar todos'; }
    }
  }

  function auditToggleCheck(key) {
    _evalState.auditChecks[key] = !_evalState.auditChecks[key];
    const row = document.querySelector(`#auditControlList .audit-check-row[data-key="${key}"]`);
    if (row) row.classList.toggle('checked', !!_evalState.auditChecks[key]);
  }

  function auditCheckAll() {
    document.querySelectorAll('#auditControlList .audit-check-row').forEach(row => {
      const k = row.dataset.key;
      _evalState.auditChecks[k] = true;
      row.classList.add('checked');
    });
  }

  function auditToggle(id) {
    const el = $(id);
    if (el) el.classList.toggle('on');
    _evalSfx('switch');
    // Recalcula liquidación al vuelo
    if (id === 'auditTogComision' || id === 'auditTogMeta') _renderAuditLiquidacion();
  }

  function cerrarAuditar() { closeModal('modalAuditar'); }

  async function guardarAuditoria() {
    const idPersonal = $('auditIdPersonal').value;
    const rol = $('auditRol').value;
    if (!idPersonal || !rol) { toast('Datos incompletos', 'error'); return; }

    // Construir checklist completo: incluye TRUE y FALSE para todos los items del rol
    const items = _evalChecklistDe(rol);
    const checksFull = {};
    items.forEach((_, i) => {
      const k = 'c' + i;
      checksFull[k] = !!_evalState.auditChecks[k];
    });

    // [v2.41.51] Ajuste: SANCIÓN (descuenta) o BONIFICACIÓN (suma)
    // [v2.41.65] Aceptar tanto "." como "," como separador decimal (es-PE).
    // parseFloat("8,9") = 8 (mal). Normalizamos coma → punto antes.
    // [v2.43.373] Bonificación (+) y Sanción (−) INDEPENDIENTES: se leen de sus dos
    // campos y COEXISTEN. Motivo = solo el comentario limpio (sin tag gráfico ni fusión).
    const _ajNum = (id) => Math.max(0, parseFloat(String($(id)?.value || '').replace(',', '.')) || 0);
    const bonificacion       = _ajNum('auditBonifMonto');
    const bonificacionMotivo = String($('auditBonifMotivoInp')?.value || '').trim();
    const sancion            = _ajNum('auditSancionMonto');
    const sancionMotivo      = String($('auditSancionMotivoInp')?.value || '').trim();
    const bonificacionMotivoFinal = bonificacionMotivo;
    const sancionMotivoFinal = sancionMotivo;
    // ajusteTipo=null → el backend (set_bonificacion_sancion soloTipo=null) setea AMBOS.
    const ajusteTipo = null;

    const comentarioBase = $('auditComentario').value || '';
    let comentarioFinal = comentarioBase;
    if (sancion > 0) {
      comentarioFinal += (comentarioFinal ? '\n' : '') + `⚠ Sanción S/${sancion.toFixed(2)}${sancionMotivoFinal ? ' — ' + sancionMotivoFinal : ''}`;
    }
    if (bonificacion > 0) {
      comentarioFinal += (comentarioFinal ? '\n' : '') + `🎁 Bonificación S/${bonificacion.toFixed(2)}${bonificacionMotivoFinal ? ' — ' + bonificacionMotivoFinal : ''}`;
    }

    // [v2.41.66] BUG FIX: usar r.fecha (fecha del card auditado) — no
    // _evalState.fecha (global mutable). Si el user navegó días o el polling
    // refrescó, _evalState.fecha podría ser hoy mientras el audit es de
    // otro día. Igual al fix de v2.41.49 para imprimir liquidación.
    const fechaAudit = (_evalState.auditR && _evalState.auditR.fecha) || _evalState.fecha;
    const params = {
      idPersonal,
      rol,
      fecha: fechaAudit,
      limpiezaPct: parseFloat($('auditLimpieza').value) || 0,
      limpiezaProfPct: parseFloat($('auditLimpiezaProf').value) || 0,
      controlChecks: JSON.stringify(checksFull),
      comentario: comentarioFinal,
      sancion: sancion,
      sancionMotivo: sancionMotivoFinal,
      bonificacion: bonificacion,
      bonificacionMotivo: bonificacionMotivoFinal,
      evaluadoPor: S.session?.nombre || '',
      aplicaComision: $('auditTogComision').classList.contains('on'),
      aplicaBonoMeta: $('auditTogMeta').classList.contains('on'),
      // [v2.43.373] siempre se envían AMBOS (bonif + sanción) como fuente de verdad;
      // ajusteTipo=null → el backend setea los dos (no preserva nada del previo).
      _ajusteTocado: true,
      ajusteTipo: ajusteTipo
    };

    // PREDICTIVO: cerrar modal + toast inmediato; sync en background
    closeModal('modalAuditar');
    toast('Auditoría registrada ✓', 'ok');
    // Optimistic: update local state visualmente antes de confirmar servidor
    const r = _evalState.resumenes.find(x => x.idPersonal === idPersonal);
    if (r) {
      r.evaluacionesCount = (r.evaluacionesCount || 0) + 1;
      r.manual = r.manual || {};
      const newLimp = parseFloat(params.limpiezaPct) || 0;
      const newLimpProf = parseFloat(params.limpiezaProfPct) || 0;
      if (newLimp > (r.manual.limpiezaPct || 0))     r.manual.limpiezaPct = newLimp;
      if (newLimpProf > (r.manual.limpiezaProfPct || 0)) r.manual.limpiezaProfPct = newLimpProf;
      r.manual.checksAcum = Object.assign({}, r.manual.checksAcum || {});
      Object.keys(checksFull).forEach(k => { if (checksFull[k]) r.manual.checksAcum[k] = true; });

      // ── [v2.43.373] Optimistic update — AMBOS campos (bonif + sanción) se
      // reemplazan con lo que el modal tiene (los dos son independientes y se
      // envían siempre). El backend recibe ambos y setea los dos.
      r.sancion = Math.round(sancion * 100) / 100;
      r.sancionMotivo = sancionMotivoFinal;
      r.sancionesDetalle = sancion > 0 ? [{
        hora: new Date().toTimeString().slice(0,5), monto: sancion, motivo: sancionMotivo
      }] : [];
      r.bonificacion = Math.round(bonificacion * 100) / 100;
      r.bonificacionMotivo = bonificacionMotivoFinal;
      r.bonificacionesDetalle = bonificacion > 0 ? [{
        hora: new Date().toTimeString().slice(0,5), monto: bonificacion, motivo: bonificacionMotivo
      }] : [];
      // Bono meta efectivo: si admin desactivó el toggle, queda en 0
      const baseV = parseFloat(r.montoBase) || 0;
      const envV  = parseFloat(r.pagoEnvasado) || 0;
      const aplicaMeta = !!params.aplicaBonoMeta;
      if (!aplicaMeta) r.bonoMeta = 0;
      const metaEf = aplicaMeta ? (parseFloat(r.bonoMeta) || 0) : 0;
      r.totalDia = Math.max(0, Math.round((baseV + envV + metaEf + (parseFloat(r.bonificacion)||0) - (parseFloat(r.sancion)||0)) * 100) / 100);
      r.evaluacionesCount = (parseInt(r.evaluacionesCount) || 0) + 1;
      r.auditado = true;
      r.liqEstado = r.liqEstado || 'PENDIENTE';

      _renderEvalLista();
      // [v2.41.64] Actualizar también la card de Personal del Día — ese render
      // viene de getPersonalDiaFast (no getResumenTodosDia). Para que se vea
      // al instante: invalidar cache local + repaint con _evalState.resumenes
      // actualizado, y forzar refetch en bg.
      // [v2.41.66] Usar r.fecha (la fecha REAL del card) — no _evalState.fecha
      try {
        const f = r.fecha || _evalState.fecha;
        // Persistir cambios optimistas en cache local
        try {
          localStorage.setItem('mos_fin_resum_' + f, JSON.stringify({ ts: Date.now(), data: _evalState.resumenes }));
        } catch {}
        if (typeof _finPL !== 'undefined' && _finPL && typeof _finRenderPersonal === 'function') {
          const cont = $('finPersonalList');
          if (cont) cont.dataset._lastHtml = '';
          _finRenderPersonal(_finPL, f);
        }
        // [v2.41.65] Marcar mutación reciente para que el polling 30s
        // refresque con _refresh=true (bypass cache backend 60s) durante 90s.
        window._finLastMutationTs = Date.now();
        // [v2.41.65] FLASH verde sobre el card editado — feedback visual instantáneo
        setTimeout(() => {
          try {
            const cards = document.querySelectorAll('#finPersonalList .eval-card');
            for (const c of cards) {
              if (c.dataset.id === idPersonal) {
                c.classList.add('fin-card-audit-flash');
                setTimeout(() => c.classList.remove('fin-card-audit-flash'), 1100);
                break;
              }
            }
          } catch(_){}
        }, 50);
      } catch(_){}
      // Beep optimista de éxito
      try { _finBeep && _finBeep('ok'); } catch(_){}
    }

    // [v2.41.67] FIRE-AND-FORGET: la UI ya está optimista (modal cerrado, card
    // actualizado, beep ok). El POST a backend va sin await. Si falla, polling
    // 30s lo detecta y un toast warn aparece. Sin esto la pantalla "guardando..."
    // tardaba 2-5s incluso con optimismo aplicado.
    const f = fechaAudit;
    API.post('crearEvaluacion', params)
      .then(() => {
        // Background: refresh con datos frescos del backend
        try { localStorage.removeItem('mos_fin_resum_' + f); } catch {}
        try { localStorage.removeItem('mos_evals_' + f); } catch {}
        refreshEvaluacion().catch(() => {});
        API.get('getPersonalDiaFast', { fecha: f, _refresh: 'true' })
          .then(fresh => {
            const arr = Array.isArray(fresh) ? fresh : ((fresh && fresh.data) || []);
            if (arr.length && typeof _finPL !== 'undefined' && _finPL) {
              _evalState.resumenes = arr;
              try { localStorage.setItem('mos_fin_resum_' + f, JSON.stringify({ ts: Date.now(), data: arr })); } catch {}
              const cont = $('finPersonalList');
              if (cont) cont.dataset._lastHtml = '';
              if (typeof _finRenderPersonal === 'function') _finRenderPersonal(_finPL, f);
            }
            if (S.view === 'finanzas' && typeof finCargar === 'function') {
              setTimeout(() => { try { finCargar({ animate: false, _silent: true }); } catch(_){} }, 200);
            }
          })
          .catch(() => {});
      })
      .catch(e => {
        // Falla del backend tras optimismo: aviso al usuario + refresh full
        toast('⚠ Backend rechazó el audit: ' + (e.message || 'error') + ' · refrescando', 'warn', 6000);
        refreshEvaluacion().catch(() => {});
        try {
          if (typeof _finPL !== 'undefined' && _finPL && S.view === 'finanzas') {
            finCargar({ animate: false });
          }
        } catch(_){}
      });
  }

  // ── Liquidación ──────────────────────────────────────────────
  function _renderLiqDropdown() {
    const sel = $('liqPersona');
    if (!sel) return;
    sel.innerHTML = '<option value="">— elegir persona —</option>'
      + _evalState.resumenes.map(r =>
          `<option value="${r.idPersonal}">${r.nombre} · ${r.rol}</option>`
        ).join('');
  }

  function _ensureLiqDefaults() {
    const inp = $('liqFechaInicio');
    if (inp && !inp.value) {
      // Default: lunes de la semana actual
      const d = new Date();
      const day = d.getDay() || 7; // domingo=7
      d.setDate(d.getDate() - day + 1);
      inp.value = d.toISOString().substring(0, 10);
    }
  }

  // ── Config de metas y bonos ──────────────────────────────────
  async function abrirConfigEval() {
    openModal('modalConfigEval');
    try {
      const res = await API.get('getConfig', {});
      const cfg = res || {};
      $('cfgMetaCajero').value     = cfg.evalMetaCajero     || 2000;
      $('cfgMetaEnvasador').value  = cfg.evalMetaEnvasador  || 500;
      $('cfgMetaAlmacenero').value = cfg.evalMetaAlmacenero || 15;
      $('cfgMetaAuditorias').value = cfg.evalMetaAuditorias || 30;
      $('cfgBonoMetaBase').value   = cfg.evalBonoMetaBase   || 8;
      $('cfgBonoMetaDoble').value  = cfg.evalBonoMetaDoble  || 15;
    } catch(e) {
      $('cfgMetaCajero').value = 2000;
      $('cfgMetaEnvasador').value = 500;
      $('cfgMetaAlmacenero').value = 15;
      $('cfgMetaAuditorias').value = 30;
      $('cfgBonoMetaBase').value = 8;
      $('cfgBonoMetaDoble').value = 15;
    }
  }

  async function guardarConfigEval() {
    const btn = $('cfgEvalSaveBtn');
    if (btn) { btn.disabled = true; btn.textContent = 'Guardando...'; }
    const pares = [
      ['evalMetaCajero',     $('cfgMetaCajero').value],
      ['evalMetaEnvasador',  $('cfgMetaEnvasador').value],
      ['evalMetaAlmacenero', $('cfgMetaAlmacenero').value],
      ['evalMetaAuditorias', $('cfgMetaAuditorias').value],
      ['evalBonoMetaBase',   $('cfgBonoMetaBase').value],
      ['evalBonoMetaDoble',  $('cfgBonoMetaDoble').value]
    ];
    try {
      await Promise.all(pares.map(([clave, valor]) =>
        API.post('setConfig', { clave, valor: String(valor || '') })
      ));
      toast('Configuración guardada ✓', 'ok');
      closeModal('modalConfigEval');
      refreshEvaluacion().catch(() => {});
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = 'Guardar'; }
    }
  }

  function abrirLiquidacion() {
    const id = $('liqPersona')?.value;
    const fechaInicio = $('liqFechaInicio')?.value;
    if (!id) { toast('Elige una persona', 'error'); return; }
    if (!fechaInicio) { toast('Elige fecha inicio (lunes)', 'error'); return; }
    const url = `liquidacion.html?id=${encodeURIComponent(id)}&inicio=${encodeURIComponent(fechaInicio)}`;
    window.open(url, '_blank');
  }

  // ============================================================
  // ── MODAL Producto-Proveedor (cotización) ─────────────────────
  // ============================================================
  const _ppState = { editando: null };

  function abrirModalProvProducto(idPP) {
    const idProv = S.provSelId;
    if (!idProv) { toast('Selecciona primero un proveedor', 'error'); return; }
    const elModal = $('modalProvProducto');
    if (!elModal) { toast('Modal no disponible — recarga la app', 'error'); return; }
    _ppState.editando = idPP;
    const setVal = (id, v) => { const el = $(id); if (el) el.value = v; };
    const setTxt = (id, v) => { const el = $(id); if (el) el.textContent = v; };
    setTxt('ppModalTitle', idPP ? '📦 Editar cotización' : '📦 Nueva cotización');
    setVal('ppId', idPP || '');
    setVal('ppBuscar', '');
    setVal('ppSkuBase', '');
    setVal('ppCodigoBarra', '');
    if ($('ppBuscarRes')) $('ppBuscarRes').style.display = 'none';
    $('ppSeleccionado')?.classList.add('hidden');
    setVal('ppPrecio', '');
    setVal('ppMinimo', '');
    setVal('ppDiasEntrega', '');
    setVal('ppUnidadesBulto', '');
    setVal('ppNotas', '');
    $('ppBtnEliminar')?.classList.toggle('hidden', !idPP);

    // Pre-poblar desde cache local (ya está enriquecido) ANTES de abrir → evita parpadeo
    if (idPP) {
      const cache = (S.provProductos && S.provProductos[idProv]) || [];
      const pp = cache.find(x => x.idPP === idPP);
      if (pp) {
        $('ppSkuBase').value     = pp.skuBase || '';
        $('ppCodigoBarra').value = pp.codigoBarra || '';
        $('ppPrecio').value      = pp.precioReferencia || '';
        $('ppMinimo').value         = pp.minimoCompra || '';
        $('ppDiasEntrega').value    = pp.diasEntrega || '';
        if ($('ppUnidadesBulto')) $('ppUnidadesBulto').value = pp.unidadesPorBulto || '';
        $('ppNotas').value       = pp.notas || '';
        $('ppSeleccionado').textContent = `${pp.descripcion || pp.skuBase} (SKU ${pp.skuBase}${pp.codigoBarra ? ' · ▌' + pp.codigoBarra : ''})`;
        $('ppSeleccionado').classList.remove('hidden');
      }
    }
    openModal('modalProvProducto');
  }

  // Búsqueda de productos: debounced + persistente (no muestra/oculta en cada tecla)
  let _ppBuscarTimer = null;
  function ppBuscar() {
    if (_ppBuscarTimer) clearTimeout(_ppBuscarTimer);
    _ppBuscarTimer = setTimeout(_ppBuscarRender, 180);
  }
  function _ppBuscarRender() {
    const raw = ($('ppBuscar').value || '').trim();
    const resBox = $('ppBuscarRes');
    if (!resBox) return;
    if (!raw) { resBox.style.display = 'none'; resBox.innerHTML = ''; return; }
    const qn = _norm(raw);
    const palabras = qn.split(/\s+/).filter(Boolean);
    const canonicos = (S.productos || []).filter(p => {
      const f = parseFloat(p.factorConversion);
      return !p.factorConversion || f === 1;
    });
    const scored = canonicos.map(p => {
      const haystack = _norm((p.descripcion || '') + ' ' + (p.codigoBarra || '') + ' ' + (p.skuBase || p.idProducto || '') + ' ' + (p.marca || ''));
      let s = 0, ok = true;
      palabras.forEach(w => { if (haystack.indexOf(w) >= 0) s++; else ok = false; });
      return { p, score: s, ok };
    }).filter(x => x.ok).sort((a, b) => b.score - a.score).slice(0, 10);
    // Mantener resBox VISIBLE (no togglear display) — solo cambiar contenido para evitar reflow visible
    resBox.style.display = 'block';
    if (!scored.length) {
      resBox.innerHTML = '<div class="pn-result text-slate-500 italic">Sin resultados</div>';
      return;
    }
    resBox.innerHTML = scored.map(({ p }) => {
      const sku = p.skuBase || p.idProducto;
      const cb  = p.codigoBarra || '';
      const safeDesc = (p.descripcion || sku).replace(/'/g, "\\'");
      return `<div class="pn-result" onclick="MOS.ppSeleccionar('${sku}', '${cb}', '${safeDesc}')">
        <div class="text-slate-200 font-medium">${p.descripcion || sku}</div>
        <div class="text-slate-500 text-xs" style="font-family:monospace">SKU ${sku}${cb ? ' · ▌' + cb : ''}</div>
      </div>`;
    }).join('');
  }

  function ppSeleccionar(sku, cb, desc) {
    $('ppSkuBase').value     = sku;
    $('ppCodigoBarra').value = cb;
    $('ppSeleccionado').textContent = `${desc} (SKU ${sku}${cb ? ' · ▌' + cb : ''})`;
    $('ppSeleccionado').classList.remove('hidden');
    $('ppBuscarRes').style.display = 'none';
    $('ppBuscar').value = desc;
  }

  async function guardarProvProducto() {
    const idProveedor = S.provSelId;
    const idPP        = $('ppId').value;
    const skuBase     = $('ppSkuBase').value;
    const codigoBarra = $('ppCodigoBarra').value;
    if (!skuBase) { toast('Selecciona un producto', 'error'); return; }
    const params = {
      idProveedor,
      skuBase,
      codigoBarra,
      descripcion: ($('ppSeleccionado').textContent || '').split(' (')[0],
      precioReferencia: parseFloat($('ppPrecio').value) || 0,
      minimoCompra:     parseFloat($('ppMinimo').value) || 0,
      diasEntrega:      parseInt($('ppDiasEntrega').value) || 0,
      unidadesPorBulto: parseInt($('ppUnidadesBulto')?.value) || 1,
      notas:            $('ppNotas').value
    };

    // OPTIMISTIC: actualizar cache local + cerrar modal de inmediato
    S.provProductos = S.provProductos || {};
    if (!S.provProductos[idProveedor]) S.provProductos[idProveedor] = [];
    if (idPP) {
      const idx = S.provProductos[idProveedor].findIndex(x => x.idPP === idPP);
      if (idx >= 0) Object.assign(S.provProductos[idProveedor][idx], params, { idPP });
    } else {
      const tmpId = 'PP_TMP_' + Date.now();
      S.provProductos[idProveedor].push(Object.assign({ idPP: tmpId, _tmp: true }, params));
    }
    closeModal('modalProvProducto');
    toast(idPP ? 'Cotización actualizada ✓' : 'Cotización agregada ✓', 'ok');
    _renderProvProductos();

    // Sync en background
    try {
      if (idPP) {
        await API.post('actualizarProductoProveedor', Object.assign({ idPP }, params));
      } else {
        await API.post('agregarProductoProveedor', params);
        // Refrescar para obtener idPP real del servidor
        const lista = await API.get('getProveedorProductos', { idProveedor });
        const items = Array.isArray(lista) ? lista : (lista && lista.data) || [];
        S.provProductos[idProveedor] = items;
        _renderProvProductos();
      }
    } catch(e) {
      toast('Error de sincronización: ' + e.message, 'error');
      // Revertir: re-fetch
      try {
        const lista = await API.get('getProveedorProductos', { idProveedor });
        const items = Array.isArray(lista) ? lista : (lista && lista.data) || [];
        S.provProductos[idProveedor] = items;
        _renderProvProductos();
      } catch(_){}
    }
  }

  // Eliminar desde el botón 🗑️ de cada card (sin abrir modal)
  async function eliminarProvProductoRapido(idPP) {
    if (!idPP) return;
    if (!await _modalConfirm('¿Eliminar este producto del catálogo del proveedor?', { danger: true, titulo: 'Eliminar del catálogo', okText: 'Eliminar' })) return;
    const idProveedor = S.provSelId;
    // OPTIMISTIC
    if (S.provProductos && S.provProductos[idProveedor]) {
      S.provProductos[idProveedor] = S.provProductos[idProveedor].filter(x => x.idPP !== idPP);
    }
    _renderProvProductos();
    toast('Eliminado', 'ok');
    try {
      await API.post('eliminarProductoProveedor', { idPP });
    } catch(e) { toast('Error de sincronización: ' + e.message, 'error'); }
  }

  // Jalar productos del proveedor desde el histórico de guías de WH
  async function jalarProductosProveedor() {
    const idProveedor = S.provSelId;
    if (!idProveedor) return;
    if (!await _modalConfirm('¿Importar al catálogo todos los productos comprados a este proveedor según las guías cerradas?\n\nNo borra nada — solo agrega los que falten y actualiza precios.', { titulo: 'Jalar catálogo desde guías', okText: 'Importar' })) return;
    const btn = $('btnJalarProds');
    if (btn) { btn.disabled = true; btn.textContent = '⏳ Jalando…'; }
    try {
      const res = await API.post('jalarProductosProveedor', { idProveedor });
      const data = (res && res.data) ? res.data : res;
      if (!data) throw new Error('Sin datos');
      const lineas = [
        '✓ ' + (data.creados || 0)      + ' creados',
        '↻ ' + (data.actualizados || 0) + ' actualizados',
        '— ' + (data.totalGuias || 0)   + ' guías analizadas'
      ].join(' · ');
      toast(lineas, 'ok');
      // Refresh productos del proveedor
      const lista = await API.get('getProveedorProductos', { idProveedor });
      S.provProductos[idProveedor] = Array.isArray(lista) ? lista : (lista && lista.data) || [];
      _renderProvProductos();
    } catch(e) {
      toast('Error: ' + e.message, 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.innerHTML = '⬇️ Jalar'; }
    }
  }

  async function eliminarProvProducto() {
    const idPP = $('ppId').value;
    if (!idPP) return;
    if (!await _modalConfirm('¿Eliminar esta cotización?', { danger: true, titulo: 'Eliminar cotización', okText: 'Eliminar' })) return;
    const idProveedor = S.provSelId;

    // OPTIMISTIC
    if (S.provProductos && S.provProductos[idProveedor]) {
      S.provProductos[idProveedor] = S.provProductos[idProveedor].filter(x => x.idPP !== idPP);
    }
    closeModal('modalProvProducto');
    toast('Eliminada', 'ok');
    _renderProvProductos();

    try {
      await API.post('eliminarProductoProveedor', { idPP });
    } catch(e) { toast('Error de sincronización: ' + e.message, 'error'); }
  }

  // ============================================================
  // ── PROMOCIONES (vista completa, no modal) ────────────────────
  // ============================================================
  const _promoState = { lista: [], editando: null, comboItems: [] };

  // Helper: stepper +/- para inputs numéricos
  function numStep(id, delta, step) {
    const el = $(id);
    if (!el) return;
    const stp = step || 1;
    const cur = parseFloat(el.value) || 0;
    let nuevo = cur + (delta * stp);
    if (nuevo < 0) nuevo = 0;
    // Redondear según el step para evitar errores de floating point
    if (stp < 1) nuevo = Math.round(nuevo * 100) / 100;
    el.value = nuevo;
    el.dispatchEvent(new Event('input', { bubbles: true }));
  }

  const PROMO_CACHE_KEY = 'mos_promo_cache';
  function _promoLoadCache() {
    try {
      const raw = localStorage.getItem(PROMO_CACHE_KEY);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (Date.now() - (parsed.ts || 0) > 86400000) return null; // 24h
      return parsed.data;
    } catch { return null; }
  }
  function _promoSaveCache(data) {
    try { localStorage.setItem(PROMO_CACHE_KEY, JSON.stringify({ ts: Date.now(), data })); } catch {}
  }

  async function loadPromociones() {
    $('promoListView').classList.remove('hidden');
    // Render cache primero (instantáneo) — usa cache si existe, sino lista actual del estado
    const cached = _promoLoadCache();
    if (cached) {
      _promoState.lista = cached;
    }
    // Render SIEMPRE al entrar a la vista (incluso si lista ya tenía data del init startup)
    if (_promoState.lista && _promoState.lista.length) {
      _renderPromoLista();
    } else {
      $('promoLista').innerHTML = '<div class="skel h-12 rounded-lg"></div><div class="skel h-12 rounded-lg mt-2"></div>';
    }
    // Fetch fresco
    _promoState.lastError = null;
    try {
      const lista = await API.get('getPromociones', {});
      const fresh = Array.isArray(lista) ? lista : (lista && lista.data) || [];
      console.log('[loadPromociones] respuesta GAS:', fresh.length, 'promociones', fresh);
      _promoState.lista = fresh;
      _promoState.lastFetch = Date.now();
      _promoSaveCache(fresh);
      _renderPromoLista();  // SIEMPRE re-renderizar después del fetch
    } catch(e) {
      console.error('[loadPromociones] error API:', e);
      _promoState.lastError = e && e.message ? e.message : String(e);
      toast('Error cargando promociones: ' + _promoState.lastError, 'error');
      if (!cached) _promoState.lista = [];
      _renderPromoLista();
    }
  }

  // Forzar refetch limpiando cache local
  function _promoForzarRefresh() {
    try { localStorage.removeItem(PROMO_CACHE_KEY); } catch {}
    _promoState.lista = [];
    toast('Cache limpiado, recargando…', 'info');
    loadPromociones();
  }

  // Refresh silencioso periódico
  let _promoRefreshTimer = null;
  function _startPromoRefresh() {
    if (_promoRefreshTimer) clearInterval(_promoRefreshTimer);
    _promoRefreshTimer = setInterval(() => {
      // Solo refresh si la vista está activa
      if (S.currentView === 'promociones') loadPromociones().catch(() => {});
    }, 120000);
  }

  // Compat: si alguien llama el viejo método, redirige a nav
  function abrirModalPromociones() { nav('promociones'); }

  function _renderPromoLista() {
    const cont = $('promoLista');
    const cnt  = $('promosCount');
    if (cnt) cnt.textContent = _promoState.lista.length;
    if (!_promoState.lista.length) {
      const hora = _promoState.lastFetch ? new Date(_promoState.lastFetch).toLocaleTimeString() : '—';
      const errMsg = _promoState.lastError
        ? `<div class="text-xs text-rose-400 mb-2">⚠ Error: ${_promoState.lastError}</div><div class="text-xs text-slate-500 mb-3">Revisa que el GAS esté desplegado como Nueva versión.</div>`
        : `<div class="text-xs text-slate-500 mb-3">El servidor respondió 0 promociones (verificado a las ${hora}).<br>Si tienes una registrada en la hoja PROMOCIONES de MosExpress, esto puede deberse a:<br>· GAS sin redesplegar con el último fix<br>· ME_SS_ID apunta a otro spreadsheet</div>`;
      cont.innerHTML = `
        <div class="text-center py-8">
          ${errMsg}
          <button class="btn-ghost text-xs" onclick="MOS._promoForzarRefresh()">🔄 Limpiar cache y reintentar</button>
        </div>
      `;
      return;
    }
    cont.innerHTML = _promoState.lista.map(p => {
      let nombre, tipoLabel, tipoIcon;
      if (p.tipo === 'COMBO') {
        nombre = `Combo de ${(p.items || []).length} producto${(p.items || []).length !== 1 ? 's' : ''}`;
        tipoLabel = `Precio combo: S/${p.valorPromo.toFixed(2)}`;
        tipoIcon = '🛒';
      } else {
        const prod = (S.productos || []).find(pr => (pr.skuBase || pr.idProducto) === p.skuBase);
        nombre = prod ? prod.descripcion : p.skuBase;
        if (p.tipo === 'GRUPO') {
          tipoLabel = `Lleva ${p.cantMin} por S/${(p.cantMin * p.valorPromo).toFixed(2)} (c/u S/${p.valorPromo.toFixed(2)})`;
          tipoIcon = '📦';
        } else {
          tipoLabel = `-${p.valorPromo}% desde ${p.cantMin} uds`;
          tipoIcon = '%';
        }
      }
      const activaCls = p.activa ? 'border-purple-500/40 bg-purple-500/5' : 'border-slate-700 bg-slate-900/40 opacity-60';
      const idRef = p.idPromo || p.skuBase || '';
      return `
        <div class="cursor-pointer p-3 rounded-lg border ${activaCls} hover:border-purple-400 transition-colors" onclick="MOS.promoEditar('${idRef}')">
          <div class="flex items-center justify-between gap-3">
            <div class="min-w-0 flex-1">
              <div class="text-sm font-semibold text-slate-100 truncate">${tipoIcon} ${nombre}</div>
              <div class="text-xs text-purple-300 mt-0.5">${tipoLabel}</div>
              ${p.descripcion ? `<div class="text-xs text-slate-500 mt-0.5">${p.descripcion}</div>` : ''}
            </div>
            <button type="button" class="toggle-sw shrink-0 ${p.activa ? 'on' : ''}"
                    onclick="event.stopPropagation();MOS.promoToggleActiva('${idRef}')"
                    title="${p.activa ? 'Desactivar' : 'Activar'}">
              <span class="toggle-sw-knob"></span>
            </button>
          </div>
        </div>`;
    }).join('');
  }

  // Toggle inline: activar/desactivar promoción sin abrir form (optimista)
  async function promoToggleActiva(idRef) {
    const p = _promoState.lista.find(x => (x.idPromo === idRef) || (x.skuBase === idRef));
    if (!p) return;
    const nuevoEstado = !p.activa;

    // OPTIMISTIC: cambiar en cache local + re-render
    p.activa = nuevoEstado;
    _promoSaveCache(_promoState.lista);
    _renderPromoLista();
    toast(nuevoEstado ? 'Promoción activada ✓' : 'Promoción desactivada', 'ok');

    // Sync en background
    try {
      await API.post('actualizarPromocion', {
        idPromo: p.idPromo,
        skuBase: p.skuBase,
        activa: nuevoEstado
      });
    } catch(e) {
      // Revertir
      p.activa = !nuevoEstado;
      _promoSaveCache(_promoState.lista);
      _renderPromoLista();
      toast('Error: ' + e.message, 'error');
    }
  }

  function _hoyISO() {
    const d = new Date();
    return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
  }

  function promoNuevoForm() {
    _promoState.editando = null;
    _promoState.comboItems = [];
    // Abrir modal flotante
    openModal('modalPromoEdit');
    $('promoBtnEliminar').classList.add('hidden');
    $('promoIdEdit').value = '';
    $('promoBuscar').value = '';
    $('promoSkuBase').value = '';
    $('promoBuscarRes').style.display = 'none';
    $('promoBuscarRes').innerHTML = '';
    $('promoSeleccionado').classList.add('hidden');
    $('promoComboBuscar').value = '';
    $('promoComboRes').style.display = 'none';
    $('promoComboItems').innerHTML = '';
    document.querySelector('input[name="promoTipo"][value="GRUPO"]').checked = true;
    promoSetTipo('GRUPO');
    $('promoCantMin').value = '';
    $('promoValor').value = '';
    const cp = $('promoComboPrecio'); if (cp) cp.value = '';
    $('promoDesc').value = '';
    // Vigencia por defecto: hoy
    $('promoFDesde').value = _hoyISO();
    $('promoFHasta').value = '';
    $('promoTogActiva').classList.add('on');
    $('promoError').style.display = 'none';
  }

  function promoEditar(idRef) {
    const p = _promoState.lista.find(x => (x.idPromo === idRef) || (x.skuBase === idRef));
    if (!p) return;
    _promoState.editando = p.idPromo || p.skuBase;
    promoNuevoForm();
    $('promoBtnEliminar').classList.remove('hidden');
    $('promoIdEdit').value = p.idPromo || p.skuBase;
    document.querySelector('input[name="promoTipo"][value="' + p.tipo + '"]').checked = true;
    promoSetTipo(p.tipo);

    if (p.tipo === 'COMBO') {
      _promoState.comboItems = (p.items || []).slice();
      _renderPromoComboItems();
      $('promoComboPrecio').value = p.valorPromo || 0;
    } else {
      $('promoSkuBase').value = p.skuBase;
      const prod = (S.productos || []).find(pr => (pr.skuBase || pr.idProducto) === p.skuBase);
      $('promoSeleccionadoNombre').textContent = prod ? `${prod.descripcion} (${p.skuBase})` : p.skuBase;
      $('promoSeleccionado').classList.remove('hidden');
      $('promoCantMin').value = p.cantMin;
      // Modo: si TOTAL, mostrar cantMin × valorPromo (lo que el usuario originalmente escribió)
      const modo = String(p.valorModo || 'UNITARIO').toUpperCase();
      if (p.tipo === 'GRUPO' && modo === 'TOTAL') {
        $('promoValor').value = (p.cantMin * p.valorPromo).toFixed(2);
        promoSetModo('TOTAL');
      } else {
        $('promoValor').value = p.valorPromo;
        if (p.tipo === 'GRUPO') promoSetModo('UNITARIO');
      }
    }
    $('promoDesc').value    = p.descripcion || '';
    $('promoFDesde').value  = p.vigenciaDesde ? String(p.vigenciaDesde).substring(0, 10) : '';
    $('promoFHasta').value  = p.vigenciaHasta ? String(p.vigenciaHasta).substring(0, 10) : '';
    $('promoTogActiva').classList.toggle('on', !!p.activa);
    promoActualizarEjemplo();
  }

  function promoVolverLista() {
    closeModal('modalPromoEdit');
  }

  function promoSetTipo(tipo) {
    const esCombo = tipo === 'COMBO';
    const esGrupo = tipo === 'GRUPO';
    $('promoSeccionUnico').classList.toggle('hidden', esCombo);
    $('promoSeccionCombo').classList.toggle('hidden', !esCombo);
    $('promoSeccionValor').classList.toggle('hidden', esCombo);
    $('promoSeccionPrecioCombo').classList.toggle('hidden', !esCombo);
    // Toggle modo solo visible en GRUPO
    const modoBox = $('promoModoBox');
    if (modoBox) modoBox.style.display = esGrupo ? '' : 'none';
    // Chips rápidos según tipo
    ['GRUPO','PORCENTAJE','COMBO'].forEach(t => {
      const row = $('promoQuick' + t);
      if (row) row.classList.toggle('hidden', t !== tipo);
    });
    if (tipo === 'GRUPO') {
      const modo = $('promoModoUnit')?.classList.contains('active') ? 'UNITARIO' : 'TOTAL';
      $('promoValorLbl').textContent = modo === 'TOTAL' ? 'Precio TOTAL del grupo *' : 'Precio UNITARIO en promo *';
    } else if (tipo === 'PORCENTAJE') {
      $('promoValorLbl').textContent = '% Descuento *';
    }
    promoActualizarEjemplo();
  }

  // Auto-llena descripción y opcionalmente cantidad mínima desde un chip
  function promoQuickFill(label, descripcion, cantMin) {
    const descEl = $('promoDesc');
    if (descEl) descEl.value = descripcion;
    if (typeof cantMin === 'number' && cantMin > 0) {
      const cm = $('promoCantMin');
      if (cm) {
        cm.value = cantMin;
        cm.dispatchEvent(new Event('input', { bubbles: true }));
      }
    }
    promoActualizarEjemplo();
  }

  function promoSetModo(modo) {
    const esTotal = modo === 'TOTAL';
    $('promoModoUnit').classList.toggle('active', !esTotal);
    $('promoModoTotal').classList.toggle('active', esTotal);
    $('promoValorLbl').textContent = esTotal ? 'Precio TOTAL del grupo *' : 'Precio UNITARIO en promo *';
    promoActualizarEjemplo();
  }

  function promoActualizarEjemplo() {
    const tipo = document.querySelector('input[name="promoTipo"]:checked')?.value;
    const ej = $('promoEjemplo');
    if (!ej) return;
    if (tipo === 'COMBO') {
      const precio = parseFloat($('promoComboPrecio').value) || 0;
      const items = _promoState.comboItems || [];
      if (!items.length || !precio) { ej.textContent = ''; return; }
      ej.textContent = `Ejemplo: ${items.length} producto${items.length !== 1 ? 's' : ''} juntos = S/${precio.toFixed(2)}`;
      return;
    }
    const cant = parseFloat($('promoCantMin').value) || 0;
    const val  = parseFloat($('promoValor').value) || 0;
    if (!cant || !val) { ej.textContent = ''; return; }
    if (tipo === 'GRUPO') {
      const modoTotal = $('promoModoTotal')?.classList.contains('active');
      const total = modoTotal ? val : (cant * val);
      const unit  = modoTotal ? (cant > 0 ? val / cant : 0) : val;
      ej.textContent = `Ejemplo: lleva ${cant} y paga S/${total.toFixed(2)} en total (S/${unit.toFixed(2)} c/u)`;
    } else {
      ej.textContent = `Ejemplo: comprando ${cant}+ unidades, ${val}% de descuento sobre el subtotal`;
    }
  }

  // ── COMBO: agregar productos ─────────────────────────────────
  function promoComboBuscar() {
    const raw = ($('promoComboBuscar').value || '').trim();
    const resBox = $('promoComboRes');
    if (!raw) { resBox.style.display = 'none'; resBox.innerHTML = ''; return; }
    const qn = _norm(raw);
    const palabras = qn.split(/\s+/).filter(Boolean);
    const canonicos = (S.productos || []).filter(p => {
      const f = parseFloat(p.factorConversion);
      return !p.factorConversion || f === 1;
    });
    const scored = canonicos.map(p => {
      const haystack = _norm((p.descripcion || '') + ' ' + (p.codigoBarra || '') + ' ' + (p.skuBase || p.idProducto || '') + ' ' + (p.marca || ''));
      let s = 0, ok = true;
      palabras.forEach(w => { if (haystack.indexOf(w) >= 0) s++; else ok = false; });
      return { p, score: s, ok };
    }).filter(x => x.ok).sort((a, b) => b.score - a.score).slice(0, 8);
    if (!scored.length) {
      resBox.innerHTML = '<div class="pn-result text-slate-500 italic">Sin resultados</div>';
      resBox.style.display = 'block';
      return;
    }
    resBox.innerHTML = scored.map(({ p }) => {
      const sku = p.skuBase || p.idProducto;
      const safeDesc = (p.descripcion || sku).replace(/'/g, "\\'");
      return `<div class="pn-result" onclick="MOS.promoComboAgregar('${sku}', '${safeDesc}')">
        <div class="text-slate-200 font-medium">${p.descripcion || sku}</div>
        <div class="text-slate-500 text-xs" style="font-family:monospace">SKU ${sku}</div>
      </div>`;
    }).join('');
    resBox.style.display = 'block';
  }

  function promoComboAgregar(sku, descripcion) {
    const existing = _promoState.comboItems.find(x => x.skuBase === sku);
    if (existing) { existing.cantidad = (parseFloat(existing.cantidad) || 0) + 1; }
    else _promoState.comboItems.push({ skuBase: sku, descripcion, cantidad: 1 });
    _renderPromoComboItems();
    $('promoComboBuscar').value = '';
    $('promoComboRes').style.display = 'none';
    promoActualizarEjemplo();
  }

  function promoComboCerrarRes() {
    $('promoComboRes').style.display = 'none';
  }

  function _renderPromoComboItems() {
    const cont = $('promoComboItems');
    if (!cont) return;
    if (!_promoState.comboItems.length) {
      cont.innerHTML = '<p class="text-xs text-slate-500 italic py-2">Aún no hay productos. Búscalos arriba.</p>';
      return;
    }
    cont.innerHTML = _promoState.comboItems.map((it, i) => `
      <div class="promo-combo-item">
        <span class="desc">${it.descripcion}</span>
        <input class="qty" type="number" min="1" step="1" value="${it.cantidad}" onchange="MOS.promoComboCambiarQty(${i}, this.value)">
        <span class="rm" onclick="MOS.promoComboQuitar(${i})" title="Quitar">×</span>
      </div>
    `).join('');
  }

  function promoComboCambiarQty(idx, val) {
    if (!_promoState.comboItems[idx]) return;
    _promoState.comboItems[idx].cantidad = Math.max(1, parseInt(val) || 1);
  }

  function promoComboQuitar(idx) {
    _promoState.comboItems.splice(idx, 1);
    _renderPromoComboItems();
    promoActualizarEjemplo();
  }

