  // ════════════════════════════════════════════════════════════
  var _audAdmRows = [];      // últimas filas cargadas (para export)
  var _audAdmCatalogo = null; // catálogo de acciones para el select

  async function abrirAuditoriaAdmin() {
    openModal('modalAuditoriaAdmin');
    const body  = document.getElementById('audAdmBody');
    const stats = document.getElementById('audAdmStats');
    const totLbl= document.getElementById('audAdmTotal');
    if (body) body.innerHTML = `<div class="text-center py-8 text-xs text-slate-500"><span class="inline-block animate-spin">⌛</span> Cargando…</div>`;

    // Cargar catálogo de acciones la primera vez (para poblar el select)
    if (!_audAdmCatalogo) {
      try {
        const cat = await API.get('getAuthCatalogo', {});
        _audAdmCatalogo = (cat && cat.data) || {};
        const sel = document.getElementById('audAdmFiltroAccion');
        if (sel) {
          const cur = sel.value;
          const opts = Object.keys(_audAdmCatalogo)
            .sort()
            .map(k => `<option value="${k}">${_audAdmCatalogo[k].label || k}</option>`)
            .join('');
          sel.innerHTML = `<option value="">Todas las acciones</option>` + opts;
          sel.value = cur;
        }
      } catch(_){}
    }

    const params = {
      limit:     parseInt(document.getElementById('audAdmFiltroLimit')?.value, 10) || 100,
      accion:    document.getElementById('audAdmFiltroAccion')?.value || '',
      appOrigen: document.getElementById('audAdmFiltroApp')?.value || ''
    };
    try {
      const r = await API.get('getAuditoriaAdmin', params);
      // [v2.42.04 fix] r ya es el array de rows (API.get desempaqueta d.data)
      let rows = Array.isArray(r) ? r : [];
      // Filtro tier (local porque el endpoint no lo soporta)
      const filtroTier = document.getElementById('audAdmFiltroTier')?.value;
      if (filtroTier) {
        rows = rows.filter(x => parseInt(x.tier, 10) === parseInt(filtroTier, 10));
      }
      _audAdmRows = rows;
      _audAdmRenderStats(rows);
      _audAdmRenderTabla(rows);
      if (totLbl) totLbl.textContent = `${rows.length} acción${rows.length !== 1 ? 'es' : ''} · MOS + ME + WH unificado`;
    } catch(e) {
      if (body) body.innerHTML = `<div class="text-rose-400 text-xs py-6 text-center">⚠ ${_escapeHtml(e.message || String(e))}</div>`;
    }
  }
  function _audAdmRenderStats(rows) {
    const cont = document.getElementById('audAdmStats');
    if (!cont) return;
    if (!rows.length) { cont.innerHTML = ''; return; }
    // KPIs: total, cache_hit rate, tier3 count, admins únicos, tiempo prom
    const total = rows.length;
    const cacheHits = rows.filter(r => parseInt(r.cache_hit, 10) === 1).length;
    const cacheHitPct = total > 0 ? Math.round(cacheHits / total * 100) : 0;
    const tier3 = rows.filter(r => parseInt(r.tier, 10) === 3).length;
    const admins = new Set(rows.map(r => r.nombreAutoriza)).size;
    const tiempos = rows.map(r => parseInt(r.tiempo_verify_ms, 10) || 0).filter(t => t > 0);
    const tiempoProm = tiempos.length ? Math.round(tiempos.reduce((a,b) => a+b, 0) / tiempos.length) : 0;
    cont.innerHTML = `
      <div class="rounded-lg p-2" style="background:rgba(168,85,247,.08);border:1px solid rgba(168,85,247,.3)">
        <div class="text-[9px] uppercase tracking-wider text-purple-300 font-bold">Total</div>
        <div class="text-lg font-bold text-white">${total}</div>
      </div>
      <div class="rounded-lg p-2" style="background:rgba(16,185,129,.08);border:1px solid rgba(16,185,129,.3)">
        <div class="text-[9px] uppercase tracking-wider text-emerald-300 font-bold">Cache hits</div>
        <div class="text-lg font-bold text-white">${cacheHits} <span class="text-xs text-emerald-300">(${cacheHitPct}%)</span></div>
      </div>
      <div class="rounded-lg p-2" style="background:rgba(239,68,68,.08);border:1px solid rgba(239,68,68,.3)">
        <div class="text-[9px] uppercase tracking-wider text-rose-300 font-bold">Tier 3 críticas</div>
        <div class="text-lg font-bold text-white">${tier3}</div>
      </div>
      <div class="rounded-lg p-2" style="background:rgba(99,102,241,.08);border:1px solid rgba(99,102,241,.3)">
        <div class="text-[9px] uppercase tracking-wider text-indigo-300 font-bold">Tiempo prom</div>
        <div class="text-lg font-bold text-white">${tiempoProm}ms</div>
      </div>`;
  }
  function _audAdmRenderTabla(rows) {
    const cont = document.getElementById('audAdmBody');
    if (!cont) return;
    if (!rows.length) {
      cont.innerHTML = `<div class="text-center text-xs text-slate-500 py-8">
        <div class="text-3xl mb-2 opacity-50">🔐</div>
        Sin registros con los filtros actuales
      </div>`;
      return;
    }
    const tierBadge = (t) => {
      const n = parseInt(t, 10);
      if (n === 1) return '<span class="aud-tier aud-tier-1" title="Tier 1 · rutina">T1</span>';
      if (n === 2) return '<span class="aud-tier aud-tier-2" title="Tier 2 · sensible">T2</span>';
      if (n === 3) return '<span class="aud-tier aud-tier-3" title="Tier 3 · crítica">T3</span>';
      return '<span class="aud-tier aud-tier-x">—</span>';
    };
    const appBadge = (a) => {
      const ap = String(a || '').toUpperCase();
      if (ap === 'MOS') return '<span class="aud-app aud-app-mos">MOS</span>';
      if (ap === 'MOSEXPRESS') return '<span class="aud-app aud-app-me">ME</span>';
      if (ap === 'WAREHOUSEMOS') return '<span class="aud-app aud-app-wh">WH</span>';
      return `<span class="aud-app aud-app-x">${_escapeHtml(a || '?')}</span>`;
    };
    const fmtFecha = (f) => {
      try {
        const d = new Date(f);
        if (isNaN(d.getTime())) return String(f || '');
        return d.toLocaleString('es-PE', { day:'2-digit', month:'2-digit', year:'2-digit', hour:'2-digit', minute:'2-digit', second:'2-digit' });
      } catch(_) { return String(f || ''); }
    };
    const fmtMs = (ms) => {
      const n = parseInt(ms, 10) || 0;
      if (!n) return '<span class="text-slate-600">—</span>';
      if (n < 1000) return n + 'ms';
      return (n / 1000).toFixed(1) + 's';
    };
    cont.innerHTML = `
      <table class="w-full text-xs aud-tabla">
        <thead class="sticky top-0" style="background:rgba(15,23,42,.95);z-index:1">
          <tr class="text-slate-500 text-left text-[10px] uppercase tracking-wider">
            <th class="px-2 py-2">Fecha</th>
            <th class="px-2 py-2">App</th>
            <th class="px-2 py-2">Acción</th>
            <th class="px-2 py-2">Tier</th>
            <th class="px-2 py-2">Admin</th>
            <th class="px-2 py-2 text-right">⌛</th>
            <th class="px-2 py-2">Ref</th>
          </tr>
        </thead>
        <tbody>
          ${rows.map(r => {
            const cacheIco = parseInt(r.cache_hit, 10) === 1 ? '⚡' : '🔑';
            const cacheTip = parseInt(r.cache_hit, 10) === 1 ? 'Caché reutilizado' : 'Clave fresca ingresada';
            return `<tr class="border-t border-slate-800 hover:bg-slate-900/40">
              <td class="px-2 py-1.5 text-slate-400 whitespace-nowrap text-[10.5px]">${_escapeHtml(fmtFecha(r.fecha))}</td>
              <td class="px-2 py-1.5">${appBadge(r.appOrigen)}</td>
              <td class="px-2 py-1.5 text-slate-200 font-mono text-[10.5px]">${_escapeHtml(r.accion || '')}</td>
              <td class="px-2 py-1.5">${tierBadge(r.tier)} <span title="${cacheTip}">${cacheIco}</span></td>
              <td class="px-2 py-1.5 text-slate-300 truncate" style="max-width:140px">${_escapeHtml(r.nombreAutoriza || '?')}</td>
              <td class="px-2 py-1.5 text-right text-slate-500">${fmtMs(r.tiempo_verify_ms)}</td>
              <td class="px-2 py-1.5 text-slate-500 font-mono text-[10px] truncate" style="max-width:160px" title="${_escapeHtml(r.refDocumento || '')}">${_escapeHtml(r.refDocumento || '')}</td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>`;
  }
  function _audAdmExportCSV() {
    if (!_audAdmRows.length) { toast('Sin datos para exportar', 'warn'); return; }
    const headers = ['idAccion','fecha','accion','refDocumento','idPersonalAutoriza','nombreAutoriza','appOrigen','dispositivo','detalle','tier','cache_hit','tiempo_verify_ms','deviceId'];
    const lines = [headers.join(',')];
    _audAdmRows.forEach(r => {
      const row = headers.map(h => {
        const v = (r[h] !== undefined && r[h] !== null) ? String(r[h]) : '';
        return '"' + v.replace(/"/g, '""') + '"';
      });
      lines.push(row.join(','));
    });
    const csv = lines.join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    const fecha = new Date().toISOString().slice(0, 10);
    a.href = url; a.download = `auditoria_admin_${fecha}.csv`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    URL.revokeObjectURL(url);
    toast('✓ CSV descargado · ' + _audAdmRows.length + ' filas', 'ok');
  }

  // [v2.41.76] Diagnóstico cierre nocturno ────────────────────
  async function abrirCronStatus() {
    openModal('modalCronStatus');
    const body = $('cronStatusBody');
    if (!body) return;
    body.innerHTML = `<div class="text-center py-8 text-xs text-slate-500"><span class="inline-block animate-spin">⌛</span> Consultando estado…</div>`;
    try {
      const res = await API.get('getCronStatus', {});
      const d = (res && res.data) || res || {};
      _renderCronStatus(d);
    } catch(e) {
      body.innerHTML = `<div class="text-rose-400 text-xs py-6 text-center">⚠ ${_escapeHtml(e.message || String(e))}</div>`;
    }
  }
  function _renderCronStatus(d) {
    const body = $('cronStatusBody');
    if (!body) return;
    const cn = d.cierreNocturno || {};
    const trgOK = cn.trigger_instalado;
    const ultima = cn.ultima_corrida;
    const ultimas = cn.ultimas_5 || [];
    const cardTrigger = `
      <div class="rounded-xl p-3 mb-3" style="background:rgba(15,23,42,.6);border:1px solid ${trgOK ? 'rgba(34,197,94,.4)' : 'rgba(239,68,68,.5)'}">
        <div class="flex items-center gap-2 mb-2">
          <span style="font-size:18px">${trgOK ? '✅' : '❌'}</span>
          <span class="text-sm font-bold ${trgOK ? 'text-emerald-300' : 'text-rose-300'}">
            Trigger ${trgOK ? 'INSTALADO' : 'NO INSTALADO'}
          </span>
        </div>
        <div class="text-[11px] text-slate-400 space-y-1">
          <div>Hora programada: <strong>${cn.hora_programada || '—'}</strong></div>
          <div>Timezone script: <strong>${cn.tz_script || '—'}</strong></div>
          <div>Hora actual script: <strong>${cn.ahora_script || '—'}</strong></div>
          <div>Total corridas registradas: <strong>${cn.total_corridas || 0}</strong></div>
        </div>
        ${!trgOK ? `<div class="text-[11px] text-rose-300 mt-2">⚠ Toca "🔧 Reinstalar trigger 23h" abajo para activar el cron.</div>` : ''}
      </div>`;
    let cardUltima = '';
    if (ultima) {
      const totalCerrado = (parseInt(ultima.wh_cerradas) || 0) + (parseInt(ultima.me_cerradas) || 0);
      const totalErr = (parseInt(ultima.wh_errores) || 0) + (parseInt(ultima.me_errores) || 0) + (parseInt(ultima.dev_errores) || 0);
      cardUltima = `
        <div class="rounded-xl p-3 mb-3" style="background:linear-gradient(135deg,rgba(99,102,241,.08),rgba(99,102,241,.02));border:1px solid rgba(99,102,241,.3)">
          <div class="text-[10px] uppercase tracking-wider text-indigo-300 font-bold mb-1">Última corrida</div>
          <div class="text-sm text-slate-200">${_escapeHtml(String(ultima.ts_inicio || '—'))}</div>
          <div class="text-[11px] text-slate-400 mt-1">
            WH: <strong>${ultima.wh_cerradas || 0}</strong> cerradas · ${ultima.wh_omitidas || 0} admin omit ·
            ME: <strong>${ultima.me_cerradas || 0}</strong> cajas ·
            Dev: <strong>${ultima.dev_marcados || 0}</strong> forzados<br>
            Duración: ${ultima.duracion_ms || 0}ms · Total cerrado: <strong>${totalCerrado}</strong>${totalErr > 0 ? ` · <span class="text-rose-300">⚠ ${totalErr} errores</span>` : ''}
          </div>
        </div>`;
    } else {
      cardUltima = `
        <div class="rounded-xl p-3 mb-3" style="background:rgba(239,68,68,.05);border:1px solid rgba(239,68,68,.3)">
          <div class="text-sm font-bold text-rose-300 mb-1">⚠ Sin corridas registradas</div>
          <div class="text-[11px] text-slate-400">
            La tabla CIERRE_NOCT_LOG está vacía. El trigger ${trgOK ? 'está instalado pero nunca corrió' : 'NO está instalado'}.
            ${trgOK ? 'Espera a las 23:00 Lima o ejecuta manualmente con el botón abajo.' : 'Reinstala el trigger primero.'}
          </div>
        </div>`;
    }
    let historial = '';
    if (ultimas.length > 0) {
      historial = `
        <div class="rounded-xl p-3" style="background:rgba(15,23,42,.4);border:1px solid #1e293b">
          <div class="text-[10px] uppercase tracking-wider text-slate-500 font-bold mb-2">Últimas ${ultimas.length} corridas</div>
          <div class="space-y-1">
            ${ultimas.map(r => {
              const cerr = (parseInt(r.wh_cerradas)||0) + (parseInt(r.me_cerradas)||0);
              const err  = (parseInt(r.wh_errores)||0) + (parseInt(r.me_errores)||0) + (parseInt(r.dev_errores)||0);
              return `<div class="flex items-center justify-between text-[11px] py-1 border-b border-slate-800">
                <span class="text-slate-400">${_escapeHtml(String(r.ts_inicio || ''))}</span>
                <span class="text-slate-300">${cerr} cerradas · ${r.dev_marcados || 0} forz${err > 0 ? ` · <span class="text-rose-400">${err} err</span>` : ''}</span>
              </div>`;
            }).join('')}
          </div>
        </div>`;
    }
    let triggers = '';
    if (d.triggers && d.triggers.length) {
      triggers = `
        <details class="mt-3 text-[11px]">
          <summary class="text-slate-500 cursor-pointer">▸ Todos los triggers instalados (${d.triggers.length})</summary>
          <div class="mt-2 space-y-1 pl-3">
            ${d.triggers.map(t => `<div class="text-slate-400">${_escapeHtml(t.handler)} <span class="text-slate-600">· ${_escapeHtml(t.type)}</span></div>`).join('')}
          </div>
        </details>`;
    }
    body.innerHTML = cardTrigger + cardUltima + historial + triggers;
  }
  async function cronReinstalarTrigger() {
    if (!await _modalConfirm('¿Reinstalar trigger 23h?\n\nBorra el actual y crea uno nuevo.', { warning: true, titulo: 'Reinstalar trigger' })) return;
    try {
      const res = await API.get('setupCierreNocturnoTrigger', {});
      toast(res?.mensaje || '✓ Trigger reinstalado', 'ok', 4000);
      abrirCronStatus();
    } catch(e) {
      toast('Error: ' + (e.message || e), 'error');
    }
  }
  async function cronEjecutarAhora() {
    if (!await _modalConfirm('¿Ejecutar cierre nocturno AHORA?\n\nCerrará sesiones WH + cajas ME + forzará logout en dispositivos.', { danger: true, titulo: 'Cierre nocturno manual', okText: 'Ejecutar ahora' })) return;
    const btn = event && event.target;
    if (btn) { btn.disabled = true; btn.textContent = '⏳ Ejecutando…'; }
    try {
      const res = await API.get('cierreNocturnoTodos', {});
      const r = (res && res.data) || res || {};
      const total = (r.wh?.cerradas || 0) + (r.me?.cerradas || 0) + (r.devices?.marcados || 0);
      toast(`✓ Cierre ejecutado · ${total} elementos`, 'ok', 5000);
      abrirCronStatus();
    } catch(e) {
      toast('Error: ' + (e.message || e), 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = '▶ Ejecutar ahora'; }
    }
  }

  // ═══════════════════════════════════════════════════════════════════════
  // [RIZ · CAPA 4] MÓDULO ZONA (Reposición Inteligente por Zona) — FRONTEND
  // 100% Supabase (RPCs me.zona_* vía API.zona.*). Gated por flag mos_zona_modulo:
  // loadZona() solo se invoca al navegar a 'zona', y el nav que la abre está oculto
  // si el flag está OFF (default) → con el flag OFF la app es IDÉNTICA a hoy.
  //
  // PLACEHOLDERS Capa 5: la sugerencia IA del card es texto local determinista
  // (la IA real del Edge /functions/ia llega en Capa 5); la impresión 80mm del
  // ticket diario / lista de compras también es Capa 5.
  // ═══════════════════════════════════════════════════════════════════════

  // WebAudio iOS-safe — reusa el patrón _catSfx pero dedicado a Zona (resume en gesto).
  let _zonaAudioCtx = null;
  function _zonaSfx(tipo) {
    try {
      if (!_zonaAudioCtx) _zonaAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const ctx = _zonaAudioCtx;
      if (ctx.state === 'suspended') { try { ctx.resume(); } catch(_){} }   // iOS: requiere gesto
      const t = ctx.currentTime;
      function tone(freq, dur, gainVal, opts) {
        const o = ctx.createOscillator(); const g = ctx.createGain();
        o.type = (opts && opts.type) || 'sine';
        o.frequency.setValueAtTime(freq, t + (opts && opts.delay || 0));
        if (opts && opts.glide) o.frequency.exponentialRampToValueAtTime(opts.glide, t + (opts.delay || 0) + dur);
        g.gain.setValueAtTime(gainVal, t + (opts && opts.delay || 0));
        g.gain.exponentialRampToValueAtTime(0.0001, t + (opts && opts.delay || 0) + dur);
        o.connect(g); g.connect(ctx.destination);
        o.start(t + (opts && opts.delay || 0)); o.stop(t + (opts && opts.delay || 0) + dur + 0.01);
      }
      switch (tipo) {
        case 'tick':    tone(1300, .035, .035, { type:'triangle' }); break;
        case 'ok':      tone(660, .08, .06); tone(990, .09, .06, { delay:.08 }); break;
        case 'error':   tone(220, .22, .07, { type:'square', glide:140 }); break;
        case 'pop':     tone(880, .05, .04, { type:'triangle' }); break;
      }
    } catch(_){}
  }
  function _zonaVibrar(patron) { if (_zonaReduce()) return; if (navigator.vibrate) { try { navigator.vibrate(patron); } catch(_){} } }
  // [RIZ UX] ¿el usuario pidió menos movimiento? → no animar ni vibrar.
  function _zonaReduce() {
    try { return !!(window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches); } catch (_) { return false; }
  }
  // [RIZ UX] Ripple táctil sutil en una card/botón de zona (transform/opacity → 60fps).
  function _zonaRipple(ev, host) {
    if (_zonaReduce()) return;
    try {
      const h = host || (ev && ev.currentTarget);
      if (!h) return;
      const rect = h.getBoundingClientRect();
      const size = Math.max(rect.width, rect.height) * 0.65;
      const x = (ev && ev.clientX != null) ? ev.clientX : (rect.left + rect.width / 2);
      const y = (ev && ev.clientY != null) ? ev.clientY : (rect.top + rect.height / 2);
      const r = document.createElement('span');
      r.className = 'zona-ripple';
      r.style.width = r.style.height = size + 'px';
      r.style.left = (x - rect.left - size / 2) + 'px';
      r.style.top  = (y - rect.top  - size / 2) + 'px';
      if (getComputedStyle(h).position === 'static') h.style.position = 'relative';
      h.appendChild(r);
      setTimeout(() => { try { r.remove(); } catch (_) {} }, 620);
    } catch (_) {}
  }
  // [RIZ UX] Count-up de un KPI (de 0 → valor) usando rAF. Respeta reduced-motion (pinta directo).
  function _zonaCountUp(el, target) {
    if (!el) return;
    const end = Number(target);
    if (!isFinite(end)) { el.textContent = (target == null ? '—' : target); return; }
    if (_zonaReduce() || end === 0) { el.textContent = String(end); return; }
    const dur = 620, t0 = (performance && performance.now) ? performance.now() : Date.now();
    const ease = (x) => 1 - Math.pow(1 - x, 3);   // easeOutCubic
    function frame(now) {
      const p = Math.min(1, ((now || Date.now()) - t0) / dur);
      el.textContent = String(Math.round(end * ease(p)));
      if (p < 1) requestAnimationFrame(frame);
      else el.textContent = String(end);
    }
    requestAnimationFrame(frame);
  }

  // Helpers de presentación
  function _zonaNum(v) { const n = Number(v); return isFinite(n) ? n : 0; }

  // [MEJORA 2] Formato de cantidad según unidad/granel del item.
  //  · esGranel → admite decimales y usa la unidad legible (ej. "12.5 kg").
  //  · NO granel → entero + "un" (ej. "12 un").
  // El segundo arg es el item (o {esGranel,unidad}); el tercero opcional oculta el sufijo (solo número).
  const _ZONA_UNI_LBL = { KGM:'kg', GRM:'g', LTR:'L', MLT:'ml', NIU:'un', UND:'un', UN:'un', '':'un' };
  function _zonaUniLbl(item) {
    if (!item) return 'un';
    const u = String(item.unidad || '').toUpperCase().trim();
    if (_ZONA_UNI_LBL[u] != null) return _ZONA_UNI_LBL[u];
    return u ? u.toLowerCase() : 'un';
  }
  // Redondea/formatea un número crudo: granel → hasta 2 decimales sin ceros sobrantes; entero → redondeo.
  function _zonaFmtNumRaw(valor, esGranel) {
    const n = _zonaNum(valor);
    if (esGranel) {
      const r = Math.round(n * 100) / 100;
      return (Math.abs(r % 1) < 1e-9) ? String(Math.round(r)) : String(r);
    }
    return String(Math.round(n));
  }
  // Devuelve "valor unidad" (ej. "12.5 kg" / "12 un"). soloNum=true → solo el número formateado.
  function _zonaFmtCant(valor, item, soloNum) {
    const esGranel = !!(item && item.esGranel);
    const num = _zonaFmtNumRaw(valor, esGranel);
    if (soloNum) return num;
    return num + ' ' + _zonaUniLbl(item);
  }
  // step de input/stepper según granel (0.1 para granel, 1 para unidades enteras).
  function _zonaStepAttr(item) { return (item && item.esGranel) ? '0.1' : '1'; }
  // Parser tolerante del input manual (acepta coma decimal); entero si no es granel; nunca negativo.
  function _zonaParseCant(raw, esGranel) {
    let n = parseFloat(String(raw == null ? '' : raw).replace(',', '.'));
    if (!isFinite(n)) n = 0;
    if (!esGranel) n = Math.round(n);
    else n = Math.round(n * 100) / 100;
    return Math.max(0, n);
  }
  // Clasificación BCG → estilos. clase: 'estrella'|'vaca'|'interro'|'perro'.
  const _ZONA_BCG = {
    estrella: { ico:'⭐', cls:'bcg-estrella', tendLbl:'▲ subiendo', tendCls:'zt-asc' },
    vaca:     { ico:'🐄', cls:'bcg-vaca',     tendLbl:'≈ estable',  tendCls:'zt-est' },
    interro:  { ico:'❓', cls:'bcg-interro',  tendLbl:'▲ subiendo', tendCls:'zt-asc' },
    perro:    { ico:'🐕', cls:'bcg-perro',    tendLbl:'▼ bajando',  tendCls:'zt-desc' }
  };
  // Mapea tendencia cruda ('asc'|'desc'|'est'|'nula') a etiqueta/clase de badge.
  function _zonaTendBadge(tend) {
    switch (String(tend || '').toLowerCase()) {
      case 'asc':  case 'ascendente':  return { lbl:'↑ ASCENDENTE', cls:'zt-asc' };
      case 'desc': case 'descendente': return { lbl:'↓ DESCENDENTE', cls:'zt-desc' };
      case 'nula': case 'cero':        return { lbl:'∅ SIN ROTAR',   cls:'zt-nula' };
      default:                          return { lbl:'≈ ESTABLE',     cls:'zt-est' };
    }
  }
  // Deriva el cuadrante BCG si el backend no lo manda (informativo): crecimiento × volumen.
  function _zonaBCGClase(p) {
    if (p.bcg) return String(p.bcg).toLowerCase();
    const tend = String(p.tendencia || '').toLowerCase();
    const volAlto = !!p._volAlto;   // el panel marca _volAlto vs mediana de la zona
    if (tend === 'nula' || tend === 'cero') return 'perro';
    const sube = (tend === 'asc' || tend === 'ascendente');
    if (sube) return volAlto ? 'estrella' : 'interro';
    if (tend === 'desc' || tend === 'descendente') return volAlto ? 'vaca' : 'perro';
    return volAlto ? 'vaca' : 'interro';   // estable
  }
  // Normaliza un item crudo del backend (me.zona_panel) al shape que consume el render.
  // El backend emite tendencia/bcg en MAYÚSCULAS (CRECIENTE/DECRECIENTE/ESTABLE/NULA ·
  // ESTRELLA/VACA/INTERROGANTE/PERRO) y el vencimiento como objeto {fecha,dias}. El render usa
  // tendencia normalizada (asc/desc/est/nula), clave BCG corta (interro, no interrogante) y
  // diasVencimiento plano. Mapeamos aquí (una sola fuente) en lugar de salpicar el render con ??.
  const _ZONA_TEND_MAP = { CRECIENTE:'asc', DECRECIENTE:'desc', ESTABLE:'est', NULA:'nula',
                           ASCENDENTE:'asc', DESCENDENTE:'desc', CERO:'nula' };
  const _ZONA_BCG_MAP  = { ESTRELLA:'estrella', VACA:'vaca', INTERROGANTE:'interro', PERRO:'perro' };
  function _zonaNormItem(it) {
    if (!it || typeof it !== 'object') return it;
    const p = Object.assign({}, it);
    const tUp = String(p.tendencia || '').toUpperCase();
    p.tendencia = _ZONA_TEND_MAP[tUp] || (p.tendencia != null ? String(p.tendencia).toLowerCase() : 'est');
    const bUp = String(p.bcg || '').toUpperCase();
    p.bcg = _ZONA_BCG_MAP[bUp] || (p.bcg != null ? String(p.bcg).toLowerCase() : '');
    // vencimientoProximo:{fecha,dias} → diasVencimiento plano (lo que lee _zonaVencBadge).
    if (p.vencimientoProximo && p.vencimientoProximo.dias != null) p.diasVencimiento = p.vencimientoProximo.dias;
    // El panel no trae volumen; rotacion (sort/BCG bubbles) = volumen si vino, si no 0. Marcamos _volAlto solo si hay dato.
    p.rotacion = (p.volumen != null) ? _zonaNum(p.volumen) : (p.rotacion != null ? _zonaNum(p.rotacion) : 0);
    // [MEJORA 4] rotacionCero del backend → boolean limpio (acepta bool/'1'/'true'/1).
    if (p.rotacionCero != null) {
      const rc = p.rotacionCero;
      p.rotacionCero = (rc === true || rc === 1 || rc === '1' || String(rc).toLowerCase() === 'true');
    }
    return p;
  }

  // Badge de vencimiento por días restantes (criterio de alertas_operativas).
  function _zonaVencBadge(dias) {
    if (dias == null || !isFinite(Number(dias))) return null;
    const d = Number(dias);
    if (d > 30) return { dot:'ok',   txt:'Vence en ' + d + ' días' };
    if (d >= 8) return { dot:'warn', txt:'Vence en ' + d + ' días' };
    return { dot:'crit', txt:'Vence en ' + d + ' días ⚠' };
  }

  // ── Carga del módulo ──────────────────────────────────────────────────
  async function loadZona(force) {
    // Guard duro: si el flag está OFF, NO cargar nada (defensa extra al gate del nav).
    let on = false;
    try { on = !!(API.zona && API.zona.moduloOn && API.zona.moduloOn()); } catch (_) { on = false; }
    if (!on) {
      const lista = $('zonaLista');
      if (lista) lista.innerHTML = '<div class="text-center py-16 text-slate-500">Módulo no habilitado</div>';
      return;
    }
    // 1) Cargar el selector de zonas (reusa getZonas → array {idZona,nombre,activo})
    try {
      if (!S.zonaList.length) {
        const zs = await API.get('getZonas', {}).catch(() => []);
        S.zonaList = Array.isArray(zs) ? zs.filter(z => z && (z.activo === '1' || z.activo === true || z.activo == null)) : [];
      }
    } catch (_) { S.zonaList = S.zonaList || []; }
    _zonaPoblarSelector();
    if (!S.zonaActual && S.zonaList.length) S.zonaActual = S.zonaList[0].idZona || S.zonaList[0].id || S.zonaList[0].nombre;
    // [ASEGURAR DATA] "Log de errores" SOLO visible para master (read-only, diagnóstico de stock).
    try {
      const esMaster = (S.session && (S.session.rol || '').toLowerCase() === 'master');
      const btn = $('zonaBtnLogErrores');
      if (btn) btn.classList.toggle('hidden', !esMaster);
    } catch (_) {}
    _zonaInstalarRipple();
    await _zonaCargarPanel(force);
  }
  // [RIZ UX] Delegado único: ripple táctil al presionar cards/botones de la lista (no rompe onclicks).
  let _zonaRippleInstalado = false;
  function _zonaInstalarRipple() {
    if (_zonaRippleInstalado) return;
    const cont = $('zonaLista');
    if (!cont) return;
    _zonaRippleInstalado = true;
    cont.addEventListener('pointerdown', (ev) => {
      try {
        const t = ev.target && ev.target.closest('.zona-btn-pedir,.zona-btn-sec,.zona-card');
        if (t && !t.disabled) _zonaRipple(ev, t);
      } catch (_) {}
    }, { passive: true });
  }

  function _zonaPoblarSelector() {
    const sel = $('zonaSelector');
    if (!sel) return;
    if (!S.zonaList.length) { sel.innerHTML = '<option value="">(sin zonas)</option>'; return; }
    sel.innerHTML = S.zonaList.map(z => {
      const id = z.idZona || z.id || z.nombre;
      const nm = z.nombre || id;
      return `<option value="${_esc(String(id))}">${_esc(String(nm))}</option>`;
    }).join('');
    if (S.zonaActual) sel.value = S.zonaActual;
  }

  // Escape simple para atributos/texto en templates (reusa CSS.escape donde haga falta).
  function _esc(s) { return String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

  async function _zonaCargarPanel(force) {
    const lista = $('zonaLista');
    if (lista && (force || !S.zonaProductos.length)) {
      // [RIZ UX] Skeleton de cards con shimmer (en vez de spinner pelado): silueta real de una zona-card.
      lista.innerHTML = _zonaSkelCards(4);
    }
    try {
      const r = await API.zona.panel({ zona: S.zonaActual });
      if (!r || r.ok === false) throw new Error((r && r.error) || 'Panel sin datos');
      const data = r.data || r;
      // El backend (mos.zona_panel → me.zona_panel) devuelve { items:[...] } (NO `productos`) y NO trae kpis.
      // Normalizamos cada item al shape que consume el render y derivamos los KPIs de los items (única fuente).
      const items = Array.isArray(data.items) ? data.items : (Array.isArray(data.productos) ? data.productos : (Array.isArray(data) ? data : []));
      S.zonaProductos = items.map(_zonaNormItem);
      S.zonaKpis = null;   // sin kpis del backend → _zonaPintarKpis los deriva de los items
      // [RIZ live] El panel lee TABLAS VIVAS (me.stock_zonas / wh.stock) en cada fetch. La frescura HONESTA
      // es el momento de ESTE fetch exitoso — NO el heartbeat del sync GAS de respaldo (r._fresh), que mide
      // la sombra y puede estar ~1.5h viejo aunque el dato mostrado sea de hace 1s. Ignoramos r._fresh para el chip.
      S.zonaFresh = (r._fresh !== false);   // (legacy, solo informativo; no gobierna el chip)
      S.zonaUltimoFetch = Date.now();
      _zonaPintarFresh();
      _zonaPintarKpis(true);   // count-up animado al cargar
      renderZona();
      // [RIZ · TRASLADO VERIFICADO] refrescar el badge del botón "🚚 Guías" (pendientes) + cache de verificadas.
      _trasCargarBadge();
      _trasCargarResumen();
    } catch (e) {
      if (lista) lista.innerHTML = `<div class="text-center py-12 text-red-400 text-sm">No se pudo cargar el panel de zona.<br><span class="text-slate-500">${_esc(e.message || String(e))}</span></div>`;
      // No relanzar: loadView ya marca loaded=false vía su catch si throw; acá preferimos no romper.
    }
  }

  // ── [RIZ live] AUTO-REFRESH del panel (comunicación casi instantánea) ────────
  // DECISIÓN: POLLING (no Supabase Realtime). Es el patrón ya probado en MOS (almacén/config/finanzas),
  // robusto, sin canales/RLS-realtime/reconexión que mantener, y suficiente para "casi al instante".
  // Realtime sobre me.stock_zonas/wh.stock daría latencia menor pero a cambio de complejidad y otra
  // superficie de fallo — no lo justifica el caso (admin mirando un panel). Documentado aquí a propósito.
  //
  // El loop:
  //   · corre SOLO en la vista 'zona' (loadView lo arranca/detiene) y SOLO con la pestaña visible;
  //   · cada ZONA_AUTO_MS re-fetcha API.zona.panel y hace un DIFF SUAVE (solo re-renderiza si cambió algo),
  //     preservando scroll y SIN parpadeo (no toca el skeleton; no resetea filtros/búsqueda);
  //   · se PAUSA si hay un modal de zona abierto o un ajuste inline en curso (no pisar lo que el admin escribe);
  //   · al volver el foco (visibilitychange→visible) dispara un refresco inmediato.
  const ZONA_AUTO_MS = 25 * 1000;
  let _zonaAutoTimer = null;
  let _zonaVisHandler = null;
  let _zonaRefrescando = false;
  function _zonaIniciarAutoRefresh() {
    _zonaTickFreshStart();
    if (_zonaAutoTimer) clearInterval(_zonaAutoTimer);
    _zonaAutoTimer = setInterval(() => { _zonaAutoRefrescar(); }, ZONA_AUTO_MS);
    if (!_zonaVisHandler) {
      _zonaVisHandler = () => {
        if (document.visibilityState === 'visible' && S.view === 'zona') _zonaAutoRefrescar();
      };
      document.addEventListener('visibilitychange', _zonaVisHandler);
    }
  }
  function _zonaDetenerAutoRefresh() {
    if (_zonaAutoTimer) { clearInterval(_zonaAutoTimer); _zonaAutoTimer = null; }
    _zonaTickFreshStop();
    // El visibilitychange handler es barato y chequea S.view==='zona' → lo dejamos registrado una vez.
  }
  // ¿Hay un modal de zona abierto o un ajuste inline activo? → no auto-refrescar (no pisar edición).
  function _zonaHayEdicionAbierta() {
    try {
      const ids = ['modalZonaBCG','modalZonaLotes','modalZonaSug','modalZonaEsp','modalZonaGuias','modalZonaLog','modalZonaKardex','modalZona','modalZonaCart'];
      for (const id of ids) { const el = $(id); if (el && el.classList.contains('open')) return true; }
      // Ajuste inline (stepper): el input solo existe en el DOM mientras la celda está en edición.
      if (document.querySelector('.zona-step-input')) return true;
      // Edición por código de barra: el disclosure colapsado deja el body con display:none pero NO borra
      // su innerHTML → no basta con la presencia del input. Pedimos un .zona-cod-body VISIBLE (offsetParent).
      const bodies = document.querySelectorAll('.zona-cod-body');
      for (let i = 0; i < bodies.length; i++) {
        const b = bodies[i];
        if (b.offsetParent !== null && b.querySelector('.zona-cod-input')) return true;
      }
    } catch (_) {}
    return false;
  }
  // Refresco silencioso: re-fetcha el panel y aplica diff suave. NO muestra skeleton, NO resetea filtros.
  async function _zonaAutoRefrescar() {
    if (!S.session) return;
    if (S.view !== 'zona') return;
    if (document.visibilityState !== 'visible') return;
    if (_zonaRefrescando) return;
    if (_zonaHayEdicionAbierta()) return;   // pausa mientras el admin edita
    let on = false;
    try { on = !!(API.zona && API.zona.moduloOn && API.zona.moduloOn()); } catch (_) { on = false; }
    if (!on) return;
    _zonaRefrescando = true;
    try {
      const r = await API.zona.panel({ zona: S.zonaActual });
      if (!r || r.ok === false) return;   // silencioso: no romper la vista por un fallo de polling
      // El admin pudo haber cambiado de zona / abierto un modal mientras esperábamos → descartar.
      if (S.view !== 'zona' || _zonaHayEdicionAbierta()) return;
      const data = r.data || r;
      const items = Array.isArray(data.items) ? data.items : (Array.isArray(data.productos) ? data.productos : (Array.isArray(data) ? data : []));
      const nuevos = items.map(_zonaNormItem);
      // Frescura SIEMPRE se actualiza ante un fetch exitoso (el dato es de AHORA, haya cambiado o no).
      S.zonaUltimoFetch = Date.now();
      S.zonaFresh = (r._fresh !== false);
      const cambio = JSON.stringify(nuevos) !== JSON.stringify(S.zonaProductos);
      if (cambio) {
        S.zonaProductos = nuevos;
        S.zonaKpis = null;
        renderZona();               // diff barato: innerHTML completo pero solo si HUBO cambio → sin parpadeo en el caso común
        _zonaPintarKpis(false);     // sin count-up en el refresco (evita "saltos" de número)
        _zonaPulsoRefresco();       // pulso sutil de "se actualizó"
        _trasCargarBadge();         // el badge de guías también puede haber cambiado
        _trasCargarResumen();
      }
      _zonaPintarFresh();           // siempre repintar el chip "actualizado hace Xs"
    } catch (_) {
      // silencioso — el próximo tick reintenta; el chip seguirá mostrando la última hora buena
    } finally {
      _zonaRefrescando = false;
    }
  }
  // Pulso sutil al refrescar (anillo en el chip de frescura). Respeta reduced-motion.
  function _zonaPulsoRefresco() {
    if (_zonaReduce()) return;
    const dot = $('zonaFreshDot');
    if (!dot) return;
    try { dot.classList.remove('zona-fresh-pulse'); void dot.offsetWidth; dot.classList.add('zona-fresh-pulse'); } catch (_) {}
  }

  // [RIZ live] Chip de frescura HONESTO: mide la antigüedad del último fetch EXITOSO del panel
  // (que lee tablas vivas), NO el heartbeat del sync GAS de respaldo. Verde si el dato es de hace
  // <2 min (live), ámbar si está envejeciendo (>2 min, p.ej. tab en background largo). Texto humano
  // "actualizado hace Xs/Xm". Se repinta cada 5s mediante _zonaTickFreshStart (sin re-fetchar).
  function _zonaPintarFresh() {
    const dot = $('zonaFreshDot'), lbl = $('zonaFreshLbl');
    const ts = S.zonaUltimoFetch || 0;
    if (!ts) {
      if (dot) dot.className = 'zona-fresh-dot';
      if (lbl) lbl.textContent = '—';
      return;
    }
    const seg = Math.max(0, Math.round((Date.now() - ts) / 1000));
    const stale = seg > 120;   // >2 min sin refresco exitoso → ámbar (no "retraso", solo "envejeciendo")
    if (dot) dot.className = 'zona-fresh-dot' + (stale ? ' stale' : '');
    if (lbl) lbl.textContent = 'actualizado ' + _zonaHaceLbl(seg);
  }
  // "hace Xs / hace Xm / hace Xh" humano y corto.
  function _zonaHaceLbl(seg) {
    if (seg < 5)   return 'recién';
    if (seg < 60)  return 'hace ' + seg + 's';
    const m = Math.round(seg / 60);
    if (m < 60)    return 'hace ' + m + ' min';
    const h = Math.round(m / 60);
    return 'hace ' + h + ' h';
  }
  // Tick visual del chip (solo texto/color, sin red). Arranca con el auto-refresh y muere al salir de zona.
  // [LOG ERRORES] Estado del módulo: items cargados + filtro de TIPO activo (chips clickeables).
  //   _zonaLogState.tipo: null = todos · '0' = Otro (sin clasificar) · '1'..'5' = taxonomía.
  let _zonaLogState = { items: [], tipo: null, tab: null };
  // [LOG ERRORES · PESTAÑAS] Dos vistas que reparten las filas según QUIÉN ACTÚA (no por tipo):
  //   · SIS (🔧 Sistémico)  = requiere intervención de CÓDIGO/CONFIG del master →
  //        fila VIVA (esVivo===true · regresión activa, fuga de HOY) OR TIPO 5 (factor, config que él setea).
  //   · OPE (📋 Operativo)  = se resuelve CONTANDO/AUDITANDO (trabajo del operador) → todo lo demás:
  //        cicatrices históricas T1/T2/T3 (esVivo=false, ya sellado en código), T4 (sin ancla), y Otro/null.
  //   NOTA: el reparto por tipo (legacy) quedó OBSOLETO; ahora la pestaña la decide _zonaLogTabDeItem por fila.
  const ZONA_LOG_TABS = {
    SIS: { lbl: '🔧 Sistémico', cls: 'sis' },
    OPE: { lbl: '📋 Operativo', cls: 'ope' }
  };
  const _ZONA_LOG_TAB_LS = 'mosZonaLogTab';
  // [REGLA DE PESTAÑA · por fila] Sistémico = fuga VIVA (regresión activa) O config (factor, T5);
  //   Operativo = todo lo demás (histórico ya sellado + ancla + sin clasificar). Espeja la decisión del dueño.
  function _zonaLogTabDeItem(it) {
    if (!it) return 'OPE';
    if (it.esVivo === true) return 'SIS';
    if (_zonaLogTipoKey(it) === 5) return 'SIS';
    return 'OPE';
  }
  // Taxonomía de TIPOS — única fuente de verdad para color/nombre/glifo en el frontend (espeja mos._recon_tipo_etiqueta).
  //   cat: categoría de quién lo resuelve → 'SIS' (sistémico/código, lo persigue el master) ·
  //        'OPE' (operativo, se arregla contando/auditando) · 'CFG' (config, se setea una vez).
  //   def: leyenda explicativa (definición · causa · quién lo arregla · qué hacer). Español neutral peruano.
  const ZONA_LOG_TIPOS = {
    1: { nombre: 'Stock congelado',        glifo: '🧊', cls: 't1', cat: 'SIS',
         def: 'El stock guardado se quedó pegado en un valor viejo: el kardex registró movimientos pero el saldo no los siguió. Causa: una escritura de stock que no se aplicó. Lo persigue el master; si reincide, hay que hallar qué escritura falló en el código.' },
    2: { nombre: 'Kardex inconsistente',   glifo: '📕', cls: 't2', cat: 'SIS',
         def: 'La suma de los movimientos del kardex no cuadra con el saldo guardado. Causa: un movimiento mal escrito o un saldo recalculado fuera de orden. Lo persigue el master; se corrige en el código (no recontando).' },
    3: { nombre: 'Salida sin descuento',   glifo: '🚚', cls: 't3', cat: 'SIS',
         def: 'Salió producto del origen (una guía/despacho) pero el stock del origen no se descontó. Causa: una salida que no disparó el descuento. Es crítico (suele reincidir); lo persigue el master y se corrige en el código.' },
    4: { nombre: 'Sin ancla',              glifo: '⚓', cls: 't4', cat: 'OPE',
         def: 'El producto nunca fue auditado (contado físicamente), así que no hay un punto de partida confiable para validar el stock. Lo arregla el operador: cuenta físico y ancla ese conteo. No es un error de código.' },
    5: { nombre: 'Factor sin configurar',  glifo: '⚙️', cls: 't5', cat: 'CFG',
         def: 'Falta configurar el factor de conversión del producto (ej. cuántas unidades trae una caja), por eso no se puede calcular el stock teórico. Se setea una sola vez en el catálogo y deja de aparecer.' },
    0: { nombre: 'Otro',                   glifo: '•',  cls: 't0', cat: 'OPE',
         def: 'Diferencia común o saldo negativo sin un patrón claro de las categorías anteriores. Suele ser operativo: revisar el conteo físico y el historial del producto. Si se repite con el mismo producto, avisar al master.' }
  };
  // Etiqueta legible de la categoría (para badges y leyenda).
  const ZONA_LOG_CAT = {
    SIS: { lbl: 'SISTÉMICO · código',  cls: 'cat-sis', quien: 'Lo persigue el master (no debe reincidir)' },
    OPE: { lbl: 'OPERATIVO · contar',  cls: 'cat-ope', quien: 'Lo arregla el operador auditando' },
    CFG: { lbl: 'CONFIG · una vez',    cls: 'cat-cfg', quien: 'Se setea una sola vez en el catálogo' }
  };
  function _zonaLogTipoKey(it) { const t = (it && it.tipoError != null) ? Number(it.tipoError) : 0; return (t >= 1 && t <= 5) ? t : 0; }

  let _zonaTickFreshTimer = null;
  function _zonaTickFreshStart() {
    if (_zonaTickFreshTimer) clearInterval(_zonaTickFreshTimer);
    _zonaTickFreshTimer = setInterval(() => {
      if (S.view !== 'zona') return;   // defensa: no tocar el DOM fuera de la vista
      _zonaPintarFresh();
    }, 5000);
  }
  function _zonaTickFreshStop() {
    if (_zonaTickFreshTimer) { clearInterval(_zonaTickFreshTimer); _zonaTickFreshTimer = null; }
  }

  // [RIZ UX] Pinta los KPIs con count-up (0→valor). animar=false (re-pintado tras ajuste) → directo.
  function _zonaPintarKpis(animar) {
    const k = S.zonaKpis || {};
    const set = (id, v) => {
      const el = $(id);
      if (!el) return;
      if (animar) _zonaCountUp(el, v);
      else el.textContent = (v == null ? '—' : v);
    };
    set('zKpiFaltan',  k.faltan  != null ? k.faltan  : _zonaContar(p => _zonaNum(p.brecha) > 0));
    set('zKpiAlmacen', k.almacen != null ? k.almacen : _zonaSumar(p => Math.min(_zonaNum(p.brecha), Math.max(0, _zonaNum(p.stockAlmacen)))));
    set('zKpiExterno', k.externo != null ? k.externo : _zonaContar(p => _zonaNum(p.brecha) - Math.max(0, _zonaNum(p.stockAlmacen)) > 0));
    set('zKpiCero',    k.cero    != null ? k.cero    : _zonaContar(_zonaEsRotCero));
  }
  // [RIZ UX] HTML de N cards skeleton con shimmer (silueta de una zona-card real).
  function _zonaSkelCards(n) {
    let out = '';
    for (let i = 0; i < n; i++) {
      out += `<div class="zona-skel-card" style="--i:${i}">
        <div class="zona-skel-row"><span class="skel zona-skel-title"></span><span class="skel zona-skel-badge"></span></div>
        <div class="zona-skel-metrics"><span class="skel"></span><span class="skel"></span><span class="skel"></span><span class="skel"></span></div>
        <div class="skel zona-skel-line"></div>
        <div class="zona-skel-row"><span class="skel zona-skel-btn"></span><span class="skel zona-skel-btn2"></span></div>
      </div>`;
    }
    return out;
  }
  function _zonaContar(fn) { try { return S.zonaProductos.filter(fn).length; } catch(_) { return 0; } }
  function _zonaSumar(fn)  { try { return S.zonaProductos.reduce((a,p)=>a+Math.max(0,fn(p)),0); } catch(_) { return 0; } }

  // ── Render de cards ────────────────────────────────────────────────────
  function renderZona() {
    const cont = $('zonaLista');
    if (!cont) return;
    const f = S._zonaFiltros;
    let arr = S.zonaProductos.slice();

    // Filtros
    if (f.q) {
      const q = f.q.toLowerCase();
      arr = arr.filter(p => (String(p.descripcion||p.nombre||'').toLowerCase().indexOf(q) >= 0) || (String(p.skuBase||'').toLowerCase().indexOf(q) >= 0));
    }
    if (f.brecha) arr = arr.filter(p => _zonaNum(p.brecha) > 0);
    const tendActivas = Object.keys(f.tend).filter(k => f.tend[k]);
    if (tendActivas.length) {
      arr = arr.filter(p => {
        // [MEJORA 4] La chip "∅ Sin rotar" (nula) filtra por item.rotacionCero (no por tendencia).
        if (_zonaEsRotCero(p)) return tendActivas.indexOf('nula') >= 0;
        const t = String(p.tendencia||'').toLowerCase();
        const norm = (t === 'ascendente') ? 'asc' : (t === 'descendente') ? 'desc' : (t === 'estable') ? 'est' : (t === 'cero') ? 'nula' : t;
        return tendActivas.indexOf(norm) >= 0;
      });
    }
    if (f.kpi === 'faltan')  arr = arr.filter(p => _zonaNum(p.brecha) > 0);
    if (f.kpi === 'almacen') arr = arr.filter(p => _zonaNum(p.brecha) > 0 && _zonaNum(p.stockAlmacen) > 0);
    if (f.kpi === 'externo') arr = arr.filter(p => (_zonaNum(p.brecha) - Math.max(0, _zonaNum(p.stockAlmacen))) > 0);
    if (f.kpi === 'cero')    arr = arr.filter(_zonaEsRotCero);

    // Orden
    if (f.orden === 'brecha')    arr.sort((a,b) => _zonaNum(b.brecha) - _zonaNum(a.brecha));
    else if (f.orden === 'rotacion') arr.sort((a,b) => _zonaNum(b.rotacion) - _zonaNum(a.rotacion));
    else if (f.orden === 'az')    arr.sort((a,b) => String(a.descripcion||a.nombre||'').localeCompare(String(b.descripcion||b.nombre||'')));
    else if (f.orden === 'tendencia') arr.sort((a,b) => _zonaTendRank(b.tendencia) - _zonaTendRank(a.tendencia));

    const stats = $('zonaStats');
    if (stats) stats.textContent = `${arr.length} de ${S.zonaProductos.length} productos`;

    if (!arr.length) {
      cont.innerHTML = `<div class="text-center py-16 text-slate-500"><div class="text-4xl mb-3">🏪</div><div class="font-medium">Sin productos para mostrar</div><div class="text-xs mt-1">Ajusta los filtros</div></div>`;
      return;
    }

    // [GRUPOS COLAPSABLES] Dos grupos apilados, manteniendo el orden/filtros ya aplicados DENTRO de cada uno:
    //  (1) ROTADO: lo que rotó en 4 sem (ALMACEN=despachado · ZONA=vendido) — lo importante, arriba.
    //  (2) PARADO: en universo por tener stock pero SIN rotación en 4 sem (candidatos a anular/no reponer).
    // Fuente de verdad = item.grupo del backend ('ROTADO'/'PARADO'); fallback tolerante a item.rotacionCero/rotacion.
    const esAlmacen = _esZonaAlmacen({ idZona: S.zonaActual,
      nombre: ((S.zonaList || []).find(x => (x.idZona || x.id || x.nombre) === S.zonaActual) || {}).nombre });
    let rotados = arr.filter(p => !_zonaEsGrupoParado(p));
    const parados = arr.filter(p =>  _zonaEsGrupoParado(p));
    // [RIZ #1] Filtro "del día" — SOLO al grupo ROTADO. En modo 'dia' restringimos a la tanda del día activo
    //   (skuBases que trae me.zona_ticket_dia para esa fecha → coincide exactamente con el ticket impreso).
    //   El set se carga async (toggle/flechas); aquí usamos el cache. Si aún no está, no filtra (muestra todo).
    const diaModo = (S._zonaDiaFiltro && S._zonaDiaFiltro.modo === 'dia');
    if (diaModo && S._zonaDiaSet) {
      const set = S._zonaDiaSet;
      rotados = rotados.filter(p => set.has(String(p.skuBase || p.idProducto || '')));
    }
    const grpRot = {
      key: 'ROTADO', cls: 'is-rotado', ico: esAlmacen ? '🚚' : '🛒',
      lbl: esAlmacen ? 'Despachados · últimas 4 sem' : 'Vendidos · últimas 4 sem',
      arr: rotados,
      esRotado: true, esAlmacen: esAlmacen
    };
    const grpPar = {
      key: 'PARADO', cls: 'is-parado', ico: '🧊',
      lbl: esAlmacen ? 'En stock sin despachar (4 sem)' : 'En stock sin vender (4 sem)',
      arr: parados
    };
    let html = '';
    html += _zonaGrupoHtml(grpRot);
    html += _zonaGrupoHtml(grpPar);
    cont.innerHTML = html;
    // [RIZ UX] Stagger de entrada: solo las primeras ~20 cards reciben delay incremental
    // (cap para no demorar con 800 items; el resto aparece directo vía CSS nth-child).
    // Recorremos solo .zona-card (el separador no anima) para que el índice de delay sea correcto.
    if (!_zonaReduce()) {
      const cards = cont.querySelectorAll('.zona-card'), cap = Math.min(20, cards.length);
      for (let i = 0; i < cap; i++) { try { cards[i].style.setProperty('--i', i); } catch (_) {} }
    }
    // [RIZ CARRITO] el FAB/badge reflejan el carrito de la zona tras cada render (cards reconstruidos).
    try { _zonaCarritoSync(); } catch (_) {}
    // [RIZ #4] En ALMACEN, completar las cards con sus proveedores reales (1 RPC batch, no bloqueante).
    if (esAlmacen) { try { _zonaProvCargarVisibles(); } catch (_) {} }
  }
  // ¿El item es "rotación cero"? Fuente de verdad = backend item.rotacionCero (bool).
  // Fallback tolerante (datos viejos sin el campo): rotacion===0.
  function _zonaEsRotCero(p) {
    if (p && p.grupo != null) return String(p.grupo).toUpperCase() === 'PARADO';   // fuente nueva (176): grupo
    if (p && p.rotacionCero != null) return !!p.rotacionCero;
    // sin grupo ni rotacionCero: usa volumen (176) o rotacion (legado) — 0 ⇒ no rotó.
    const vol = (p && p.volumen != null) ? _zonaNum(p.volumen) : _zonaNum(p && p.rotacion);
    return vol === 0;
  }
  // ── [GRUPOS COLAPSABLES] ──────────────────────────────────────────────────
  // ¿El item va al grupo PARADO? Fuente de verdad = item.grupo del backend ('ROTADO'/'PARADO').
  // Fallback tolerante a datos viejos: usa rotacionCero/rotacion (la antigua semántica "sin rotación").
  function _zonaEsGrupoParado(p) {
    if (p && p.grupo != null) return String(p.grupo).toUpperCase() === 'PARADO';
    return _zonaEsRotCero(p);
  }
  // Clave de localStorage del estado colapsado por (zona, grupo) — recuerda la preferencia entre refrescos.
  function _zonaGrpLsKey(grpKey) { return 'rizGrp_' + (S.zonaActual || '_') + '_' + grpKey; }
  function _zonaGrupoColapsado(grpKey) {
    try { return localStorage.getItem(_zonaGrpLsKey(grpKey)) === '1'; } catch (_) { return false; }
  }
  // HTML de un grupo (encabezado clickeable + cuerpo con sus cards). Si está vacío tras filtros → se colapsa
  // y muestra "0" elegante. El chevron rota al colapsar (clase .collapsed en head y body).
  function _zonaGrupoHtml(g) {
    const n = g.arr.length;
    // Un grupo vacío arranca colapsado siempre (no estorba); si tiene items respeta la preferencia guardada.
    const colapsado = (n === 0) ? true : _zonaGrupoColapsado(g.key);
    const colCls = colapsado ? ' collapsed' : '';
    const chev = `<svg class="zona-grp-chev" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="6 9 12 15 18 9"></polyline></svg>`;
    const body = n
      ? g.arr.map(_zonaCardHtml).join('')
      : `<div class="zona-grp-empty">Sin productos en este grupo</div>`;
    // [RIZ #1+#2] El grupo ROTADO lleva el control "Todos | Día" + flechas + ícono imprimir, al lado del contador.
    const ctrl = g.esRotado ? _zonaDiaControlHtml() : '';
    return `<div class="zona-grp" data-grp="${g.key}">`
      + `<div class="zona-grp-head ${g.cls}${colCls}" role="button" tabindex="0" aria-expanded="${colapsado ? 'false' : 'true'}" `
      +      `onclick="MOS.zonaToggleGrupo('${g.key}')" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();MOS.zonaToggleGrupo('${g.key}');}">`
      +   chev
      +   `<span class="zona-grp-ico" aria-hidden="true">${g.ico}</span>`
      +   `<span class="zona-grp-lbl">${_esc(g.lbl)}</span>`
      +   `<span class="zona-grp-count">${n}</span>`
      +   ctrl
      + `</div>`
      + `<div class="zona-grp-body${colCls}">${body}</div>`
      + `</div>`;
  }
  // [RIZ #1+#2] Control del grupo ROTADO: segmento "Todos | Día" + flechas ◀ ▶ + día activo + ícono imprimir.
  //   Todos los onclick hacen stopPropagation para NO disparar el colapso del grupo. Triple feedback en cada acción.
  function _zonaDiaControlHtml() {
    const modo = (S._zonaDiaFiltro && S._zonaDiaFiltro.modo) || 'todos';
    const enDia = modo === 'dia';
    const stop = 'event.stopPropagation();';
    const seg = `<div class="zona-dia-seg" role="group" aria-label="Filtro del día">`
      + `<button type="button" class="zona-dia-segbtn${enDia ? '' : ' on'}" aria-pressed="${enDia ? 'false' : 'true'}" `
      +   `onclick="${stop}MOS.zonaDiaModo('todos')" title="Mostrar todo el grupo">Todos</button>`
      + `<button type="button" class="zona-dia-segbtn${enDia ? ' on' : ''}" aria-pressed="${enDia ? 'true' : 'false'}" `
      +   `onclick="${stop}MOS.zonaDiaModo('dia')" title="Solo la tanda de un día (igual que el ticket)">Día</button>`
      + `</div>`;
    const nav = enDia
      ? `<div class="zona-dia-nav">`
        + `<button type="button" class="zona-dia-arrow" aria-label="Día anterior" onclick="${stop}MOS.zonaDiaNav(-1)" title="Día anterior">◀</button>`
        + `<span class="zona-dia-lbl" title="Día activo de la partición (anclado al lunes)">${_esc(_zonaDiaLabel())}</span>`
        + `<button type="button" class="zona-dia-arrow" aria-label="Día siguiente" onclick="${stop}MOS.zonaDiaNav(1)" title="Día siguiente">▶</button>`
        + `</div>`
      : '';
    const print = `<button type="button" class="zona-dia-print" aria-label="Imprimir ticket" `
      + `onclick="${stop}MOS.zonaImprimirTicketGrupo()" title="${enDia ? 'Imprimir el ticket de este día (80mm)' : 'Imprimir el ticket de hoy (80mm)'}">🖨️</button>`;
    return `<div class="zona-dia-ctrl" onclick="event.stopPropagation();">${seg}${nav}${print}</div>`;
  }
  // [RIZ #1] Cambiar modo Todos/Día. En 'dia' cargamos la tanda del backend (coincide con el ticket) y re-render.
  async function zonaDiaModo(modo) {
    if (!S._zonaDiaFiltro) S._zonaDiaFiltro = { modo: 'todos', offset: 0 };
    if (S._zonaDiaFiltro.modo === modo) { _zonaSfx('tick'); _zonaVibrar(10); return; }
    S._zonaDiaFiltro.modo = modo;
    if (modo === 'todos') S._zonaDiaFiltro.offset = 0;   // resetear al salir
    _zonaSfx('pop'); _zonaVibrar(15);
    if (modo === 'dia') { await _zonaDiaCargarSet(); }
    renderZona();
  }
  // [RIZ #1] Navegar días (◀ −1 / ▶ +1). Recarga la tanda de la nueva fecha y re-render.
  //   Límites razonables: la ventana del panel es "últimas 4 semanas" (28d) → permitimos −28..0
  //   (no hay tanda histórica más vieja que eso, ni futura: mañana+ no tiene ventas/despachos aún).
  //   Si el offset ya está en el tope y se intenta pasar → tick + no-op (no recarga ni re-render inútil).
  async function zonaDiaNav(delta) {
    if (!S._zonaDiaFiltro) S._zonaDiaFiltro = { modo: 'dia', offset: 0 };
    const MIN = -28, MAX = 0;
    const cur = S._zonaDiaFiltro.offset || 0;
    const next = Math.max(MIN, Math.min(MAX, cur + (delta < 0 ? -1 : 1)));
    if (next === cur) { try { _zonaSfx('tick'); _zonaVibrar(8); } catch (_) {} return; }   // ya en el tope
    S._zonaDiaFiltro.offset = next;
    _zonaSfx('tick'); _zonaVibrar(delta < 0 ? [12, 8] : 14);
    await _zonaDiaCargarSet();
    renderZona();
  }
  // Colapsa/expande un grupo (acordeón). Persiste en localStorage. Triple feedback táctil (SFX + vibración).
  function zonaToggleGrupo(grpKey) {
    const wrap = document.querySelector('.zona-grp[data-grp="' + grpKey + '"]');
    if (!wrap) return;
    const head = wrap.querySelector('.zona-grp-head');
    const bodyEl = wrap.querySelector('.zona-grp-body');
    if (!head || !bodyEl) return;
    const colapsar = !head.classList.contains('collapsed');
    head.classList.toggle('collapsed', colapsar);
    bodyEl.classList.toggle('collapsed', colapsar);
    head.setAttribute('aria-expanded', colapsar ? 'false' : 'true');
    try { localStorage.setItem(_zonaGrpLsKey(grpKey), colapsar ? '1' : '0'); } catch (_) {}
    try { _zonaSfx('tick'); _zonaVibrar(12); } catch (_) {}
  }
  function _zonaTendRank(t) { t = String(t||'').toLowerCase(); if (t==='asc'||t==='ascendente') return 3; if (t==='est'||t==='estable') return 2; if (t==='desc'||t==='descendente') return 1; return 0; }

  function _zonaCardHtml(p) {
    const sku   = String(p.skuBase || p.idProducto || '');
    const safe  = _esc(sku);
    const nm    = _esc(p.descripcion || p.nombre || sku);
    const stockRaw = _zonaNum(p.stockZona != null ? p.stockZona : p.stock);
    const esp   = _zonaNum(p.esperada != null ? p.esperada : p.esperado);
    // [MEJORA 3] El backend YA corrige la brecha para negativos (=esperada). La usamos tal cual.
    const negativo = !!p.stockNegativo;
    const brecha = (p.brecha != null) ? _zonaNum(p.brecha) : Math.max(0, esp - Math.max(0, stockRaw));
    const alm   = _zonaNum(p.stockAlmacen != null ? p.stockAlmacen : p.almacen);
    const bcg   = _zonaBCGClase(p);
    const bcgInfo = _ZONA_BCG[bcg] || _ZONA_BCG.vaca;
    const tend  = _zonaTendBadge(p.tendencia);
    const picos = Array.isArray(p.picos) ? p.picos.slice(-4) : [];
    // [FIX] stock negativo (almacén o zona) = ERROR → cuenta como 0 para pedido/compra.
    // El display de `alm` sigue mostrando el valor real (negativo incluido), pero NO infla la compra.
    const almPos   = Math.max(0, alm);
    const pedirAlm = Math.min(brecha, almPos);
    const externo  = Math.max(0, brecha - almPos);
    const uni      = _zonaUniLbl(p);
    // [MEJORA 2] cantidades formateadas según granel/unidad.
    const fStock  = _zonaFmtCant(stockRaw, p, true);
    const fEsp    = _zonaFmtCant(esp, p, true);
    const fAlm    = _zonaFmtCant(alm, p, true);
    const fBrecha = _zonaFmtCant(brecha, p, true);
    // [RIZ #4] En ámbito ALMACEN la 4ª métrica "Almacén" es REDUNDANTE (ya estás viendo el almacén): se
    //   reemplaza por la lista de proveedores REALES del canónico (lazy-load por card vía mos.zona_proveedores).
    const esAlmacenCard = _esZonaAlmacen({ idZona: S.zonaActual,
      nombre: ((S.zonaList || []).find(x => (x.idZona || x.id || x.nombre) === S.zonaActual) || {}).nombre });
    // [MEJORA 5] multi-código de barra.
    const codigos = Array.isArray(p.codigos) ? p.codigos : [];
    // [SPLIT/ROTCERO] códigos del almacén (solo lectura) + flag rotación-cero.
    const codigosAlm = Array.isArray(p.codigosAlmacen) ? p.codigosAlmacen : [];
    const rotCero = _zonaEsRotCero(p);

    // [MEJORA 1] Sparkline CLICKABLE → modal "¿por qué esperado=X?"
    const maxP = Math.max(1, ...picos.map(_zonaNum));
    const spark = picos.length
      ? `<div class="zona-spark zona-spark-click" onclick="MOS.zonaVerEsperado('${safe}')" title="¿Por qué esperado = ${_esc(fEsp)}? (toca para ver)">${picos.map((v,i) => `<div class="zona-spark-bar${i === picos.length-1 ? ' last' : ''}" style="height:${Math.max(3, Math.round(_zonaNum(v)/maxP*24))}px" title="${_zonaFmtCant(v, p)}"></div>`).join('')}<span class="zona-spark-lbl">${picos.map(v => _zonaFmtNumRaw(v, p.esGranel)).join(' ')} →</span></div>`
      : '';

    // Vencimiento
    const venc = _zonaVencBadge(p.diasVencimiento != null ? p.diasVencimiento : p.dias_venc);
    const vencHtml = venc
      ? `<div class="zona-venc"><span class="zona-venc-dot ${venc.dot}"></span>${_esc(venc.txt)}<span class="zona-venc-link" onclick="MOS.zonaVerLotes('${safe}')">ver historial lotes</span></div>`
      : '';

    // [MEJORA 3] Badge rojo de alerta si el stock es negativo.
    const alertaNeg = negativo
      ? `<div class="zona-alerta-neg">⚠ Stock negativo — corregir/contar</div>`
      : '';

    // Sugerencia IA (placeholder Capa 5 — texto local determinista)
    // [MEJORA 3] Con negativo NO decir "te faltan N" (eso es un error de conteo, no una compra).
    let ia = '';
    if (negativo) {
      ia = `⚠ Stock negativo (revisar dónde se originó). Para estar listo necesitas ${fEsp}.`;
    } else if (brecha > 0) {
      ia = `Te faltan ${fBrecha} para estar listo.`;
      if (pedirAlm > 0) ia += ` Almacén cubre ${_zonaFmtCant(pedirAlm, p)} → pídelos.`;
      if (externo > 0)  ia += ` Los ${_zonaFmtCant(externo, p)} restantes van a tu lista del lunes.`;
    } else if (bcg === 'perro') {
      ia = 'Sin rotación: considera promocionar, mover a góndola o rematar.';
    } else {
      ia = 'Stock al día. Sin acción necesaria.';
    }

    // Acciones según cuadrante
    let acciones;
    if (bcg === 'perro' && brecha <= 0 && !negativo) {
      // [RIZ · CAPA 5] Acciones reales (decisión auditable, NO mutan stock/dinero). El botón de la decisión
      // vigente queda resaltado (data del panel: p.accionPerro). Optimista + idempotente backend.
      const acc = String(p.accionPerro || '').toUpperCase();
      const on = (k) => acc === k ? ' zona-accion-on' : '';
      acciones = `<button class="zona-btn-sec${on('PROMOCIONAR')}" onclick="MOS.zonaAccionPerro('${safe}','PROMOCIONAR')">Promocionar</button>
                  <button class="zona-btn-sec${on('GONDOLA')}" onclick="MOS.zonaAccionPerro('${safe}','GONDOLA')">Mover a góndola</button>
                  <button class="zona-btn-sec${on('REMATAR')}" onclick="MOS.zonaAccionPerro('${safe}','REMATAR')">Rematar</button>`;
    } else {
      // [RIZ CARRITO] "Pedir" YA NO envía de inmediato: AGREGA al carrito flotante de la zona. La cantidad
      // sugerida inicial = brecha (lo que falta); el admin la ajusta con +/− en el carrito. Re-agregar un
      // ya-pedido está permitido (requisito D). Cantidad sugerida = brecha (no limitada por almacén; el
      // almacén puede no cubrir y se pide igual — el ticket de almacén marca el "debe").
      const sugerir = brecha > 0 ? brecha : 0;
      const enCarrito = _zonaCarritoCant(sku);
      // [RIZ CARRITO · FIX D] El botón refleja 3 estados VISUALMENTE distintos:
      //   1) en carrito (aún no enviado)  → "🛒 En carrito (N) · +"  (clase zona-en-carrito)
      //   2) ya pedido hoy/ayer (persistido en me.zona_pedido_log, llega en p.pedidoEstado) → "✓ Pedido hoy · re-pedir"
      //      (clase zona-pedido-ok) — DISTINTO de no-pedido, pero un tap RE-AGREGA al carrito (re-pedir permitido).
      //   3) sin pedir → "Pedir N a almacén" / "Agregar al pedido".
      const pedLbl = (p.pedidoEstado && p.pedidoEstado.etiqueta) ? String(p.pedidoEstado.etiqueta) : '';
      let btnLbl, btnCls;
      if (enCarrito > 0) {
        btnLbl = '🛒 En carrito (' + _esc(_zonaFmtCant(enCarrito, p)) + ') · +';
        btnCls = ' zona-en-carrito';
      } else if (pedLbl) {
        btnLbl = '✓ ' + _esc(pedLbl) + ' · re-pedir';
        btnCls = ' zona-pedido-ok';
      } else {
        btnLbl = sugerir > 0 ? 'Pedir ' + _esc(_zonaFmtCant(sugerir, p)) + ' a almacén' : 'Agregar al pedido';
        btnCls = '';
      }
      acciones = `<button class="zona-btn-pedir${btnCls}" id="zPedir-${safe}" onclick="MOS.zonaPedirAlmacen('${safe}', ${sugerir})">${btnLbl}</button>
                  <button class="zona-btn-sec" ${externo > 0 ? '' : 'disabled'} onclick="MOS.zonaAgregarLista('${safe}', ${externo})">+ Lista compras${externo > 0 ? ' (' + _esc(_zonaFmtCant(externo, p)) + ')' : ''}</button>`;
    }

    // [RIZ CARRITO] estado "Pedido hoy/ayer" persistido (me.zona_pedido_log, ventana 7 días). El panel lo
    // devuelve en p.pedidoEstado:{etiqueta,...}; lo mostramos como chip en el card (sobrevive a refrescos).
    const pedEstado = (p.pedidoEstado && p.pedidoEstado.etiqueta)
      ? `<div class="zona-ped-estado"><span class="zona-ped-ico">📦</span>${_esc(p.pedidoEstado.etiqueta)}</div>`
      : '';

    // [MEJORA 5] disclosure "ver códigos (N)" → expande item.codigos[] (zona, editable).
    const codDisc = codigos.length
      ? `<div class="zona-cod-disc" id="zCodDisc-${safe}" onclick="MOS.zonaToggleCodigos('${safe}')"><span class="zona-cod-caret" id="zCodCaret-${safe}">▸</span> ver códigos (${codigos.length})</div>
         <div class="zona-cod-body" id="zCodBody-${safe}" style="display:none"></div>`
      : '';

    // [MEJORA 3] disclosure "ver códigos almacén (N)" → expande item.codigosAlmacen[] (solo lectura).
    const codAlmDisc = codigosAlm.length
      ? `<div class="zona-cod-disc zona-cod-disc-alm" id="zAlmDisc-${safe}" onclick="MOS.zonaToggleCodigosAlmacen('${safe}')"><span class="zona-cod-caret" id="zAlmCaret-${safe}">▸</span> ver códigos almacén (${codigosAlm.length})</div>
         <div class="zona-cod-body" id="zAlmBody-${safe}" style="display:none"></div>`
      : '';

    // [ROTCERO] Chip + hint para cards sin rotación (secundarias, no "rotas").
    const rotCeroChip = rotCero
      ? `<span class="zona-rotcero-chip" title="Sin rotación en la ventana">∅ sin rotación</span>`
      : '';
    const rotCeroHint = (rotCero && !negativo)
      ? `<div class="zona-rotcero-hint">Considera <b>anular</b> o <b>promocionar</b> este producto.</div>`
      : '';

    return `<div class="zona-card ${bcgInfo.cls}${negativo ? ' zona-neg' : ''}${rotCero ? ' zona-rotcero' : ''}" id="zcard-${safe}" data-sku="${safe}">
      <div class="zona-card-top">
        <div class="zona-card-name">${nm}</div>
        <div class="flex items-center gap-2">
          ${rotCeroChip}
          <span class="zona-tend-badge ${tend.cls}">${tend.lbl}</span>
          <span class="zona-bcg-badge" title="BCG: ${bcg}">${bcgInfo.ico}</span>
        </div>
      </div>
      ${alertaNeg}
      <div class="zona-metrics${esAlmacenCard ? ' zona-metrics-3' : ''}">
        <div><div class="zona-metric-lbl">Stock${esAlmacenCard ? ' almacén' : ' zona'}</div><div class="zona-metric-val${negativo ? ' brecha-pos' : ''}" id="zStock-${safe}">${_esc(fStock)}<span class="zona-edit-ico" onclick="MOS.zonaAjusteInline('${safe}')">✎</span><span class="zona-edit-ico" title="Historial de movimientos" onclick="MOS.${esAlmacenCard ? 'zonaVerKardexAlmacen' : 'zonaVerKardex'}('${safe}')">🕘</span></div></div>
        <div><div class="zona-metric-lbl">Esperado <span class="zona-metric-uni">(global)</span></div><div class="zona-metric-val">${_esc(fEsp)}</div></div>
        <div><div class="zona-metric-lbl">Brecha</div><div class="zona-metric-val ${brecha > 0 ? 'brecha-pos' : 'brecha-zero'}" id="zBrecha-${safe}">${brecha > 0 ? '▲ ' + _esc(fBrecha) : '✓ 0'}</div></div>
        ${esAlmacenCard ? '' : `<div><div class="zona-metric-lbl">Almacén</div><div class="zona-metric-val${alm < 0 ? ' brecha-pos' : ''}">${_esc(fAlm)}<span class="zona-edit-ico" title="Historial almacén" onclick="MOS.zonaVerKardexAlmacen('${safe}')">🕘</span></div></div>`}
      </div>
      ${esAlmacenCard ? `<div class="zona-prov" id="zProv-${safe}" data-sku="${safe}">${_zonaProvBlockHtml(sku)}</div>` : ''}
      ${codDisc}
      ${codAlmDisc}
      ${spark}
      ${vencHtml}
      ${rotCeroHint}
      ${pedEstado}
      <div class="zona-ia">💡 ${_esc(ia)}</div>
      <div class="zona-actions">${acciones}</div>
    </div>`;
  }

  // ══ [RIZ #4 · PROVEEDORES POR CANÓNICO] (solo ALMACEN) ════════════════════════════════════════════════════
  // Reemplaza la métrica redundante "Almacén" por la lista de proveedores REALES del canónico (sku_base),
  // agrupando todos los códigos del grupo y ocultando "PROVEEDOR DESCONOCIDO". Lazy: el render pinta el estado
  // del cache (cargando / lista / hint "sin proveedor"); _zonaProvCargarVisibles dispara UNA sola RPC batch
  // por todos los skus visibles tras el render (no encarece el panel: 1 llamada para todas las cards).
  function _zonaProvBlockHtml(sku) {
    const entry = S._zonaProvCache && S._zonaProvCache[sku];
    if (entry === undefined) {
      // aún no cargado → placeholder discreto (se completa solo tras _zonaProvCargarVisibles).
      return `<span class="zona-prov-lbl">🏷 Proveedores</span><span class="zona-prov-loading">cargando…</span>`;
    }
    return _zonaProvListHtml(entry);
  }
  function _zonaProvListHtml(lista) {
    const arr = Array.isArray(lista) ? lista : [];
    if (!arr.length) {
      return `<span class="zona-prov-lbl">🏷 Proveedores</span><span class="zona-prov-none">sin proveedor registrado</span>`;
    }
    const chips = arr.map(pv => {
      const nm = _esc(String(pv.nombre || '').trim());
      const pr = _zonaNum(pv.precioRef);
      const de = _zonaNum(pv.diasEntrega);
      const extras = [];
      if (pr > 0) extras.push('S/ ' + _zonaFmtNumRaw(pr, false));
      if (de > 0) extras.push(de + 'd');
      const tip = extras.length ? ` title="${_esc(extras.join(' · '))}"` : '';
      const extraHtml = extras.length ? `<span class="zona-prov-extra">${_esc(extras.join(' · '))}</span>` : '';
      return `<span class="zona-prov-chip"${tip}>${nm}${extraHtml}</span>`;
    }).join('');
    return `<span class="zona-prov-lbl">🏷 Proveedores</span><span class="zona-prov-chips">${chips}</span>`;
  }
  // Carga (batch, 1 RPC) los proveedores de todos los skus de ALMACEN visibles que aún no estén en cache,
  // y refresca solo sus bloques en el DOM (sin re-render completo). Tolerante: si falla, deja los placeholders.
  async function _zonaProvCargarVisibles() {
    try {
      const nodes = Array.prototype.slice.call(document.querySelectorAll('.zona-prov[data-sku]'));
      if (!nodes.length) return;
      if (!S._zonaProvCache) S._zonaProvCache = {};
      const pend = [];
      nodes.forEach(n => { const sk = n.getAttribute('data-sku'); if (sk && S._zonaProvCache[sk] === undefined && pend.indexOf(sk) < 0) pend.push(sk); });
      if (!pend.length) return;   // todo cacheado → nada que pedir
      const r = await API.zona.proveedores({ skus: pend });
      const data = (r && r.data) || r || {};
      const provs = (data && data.proveedores) || {};
      // Marcar todos los pedidos como resueltos (los que no vinieron → [] = sin proveedor).
      pend.forEach(sk => { S._zonaProvCache[sk] = Array.isArray(provs[sk]) ? provs[sk] : []; });
      // Refrescar solo los bloques en el DOM (las cards pueden haber cambiado; consultamos por sku actual).
      Array.prototype.slice.call(document.querySelectorAll('.zona-prov[data-sku]')).forEach(n => {
        const sk = n.getAttribute('data-sku');
        if (sk && S._zonaProvCache[sk] !== undefined) n.innerHTML = _zonaProvListHtml(S._zonaProvCache[sk]);
      });
    } catch (e) {
      try { console.warn('[RIZ] _zonaProvCargarVisibles:', e && (e.message || e)); } catch (_) {}
    }
  }
  // Compat / re-tap manual: recarga proveedores de un sku puntual (fuerza refetch) y repinta su bloque.
  async function zonaToggleProveedores(sku) {
    _zonaSfx('tick'); _zonaVibrar(10);
    if (!S._zonaProvCache) S._zonaProvCache = {};
    delete S._zonaProvCache[sku];
    try {
      const r = await API.zona.proveedores({ sku });
      const data = (r && r.data) || r || {};
      const provs = (data && data.proveedores) || {};
      S._zonaProvCache[sku] = Array.isArray(provs[sku]) ? provs[sku] : [];
      // Buscar por data-sku (no por id, para evitar mismatch de escape entre _esc/_zonaEsc en skus raros).
      Array.prototype.slice.call(document.querySelectorAll('.zona-prov[data-sku]')).forEach(n => {
        if (n.getAttribute('data-sku') === String(sku)) n.innerHTML = _zonaProvListHtml(S._zonaProvCache[sku]);
      });
    } catch (_) {}
  }

  // [MEJORA 5] Renderiza la fila de un código dentro del disclosure (lista + editar por código).
  // [192] Fila minimal por código: SOLO el código + su stock + input set-absoluto. SIN nombres/descripciones
  // (la card ya tiene el nombre grande; muchos equivalentes no tienen nombre propio → ruido). Chip "equiv"
  // discreto para distinguir el código equivalente del canónico.
  function _zonaCodRowHtml(sku, c, item) {
    const safe = _esc(sku);
    const cb   = String(c.codBarra != null ? c.codBarra : (c.codigoBarra != null ? c.codigoBarra : ''));
    const cbSafe = _zonaEsc(cb);
    const cbAttr = _esc(cb);
    const st   = _zonaFmtCant(c.stock, item, true);
    const equiv = c.esEquivalente ? '<span class="zona-cod-equiv" title="Código equivalente">equiv</span>' : '';
    const step = _zonaStepAttr(item);
    const cid = 'zCodIn-' + safe + '-' + _zonaCodKey(cb);
    return `<div class="zona-cod-row">
      <div class="zona-cod-info">
        <div class="zona-cod-cb">${cbAttr} ${equiv}</div>
        <div class="zona-cod-st">stock <b>${_esc(st)}</b></div>
      </div>
      <div class="zona-cod-edit">
        <input type="number" inputmode="decimal" step="${step}" class="zona-cod-input" id="${cid}" value="${_esc(_zonaFmtCant(c.stock, item, true))}">
        <button class="zona-mini-btn zona-mini-cero" onclick="MOS.zonaCodCero('${safe}','${cbSafe}')" title="Poner en cero">Cero</button>
        <button class="zona-mini-btn zona-mini-ok" onclick="MOS.zonaCodGuardar('${safe}','${cbSafe}')" title="Guardar">✓</button>
      </div>
    </div>`;
  }
  // Clave DOM-safe para un código de barra (puede traer caracteres raros).
  function _zonaCodKey(cb) { return String(cb).replace(/[^A-Za-z0-9]/g, '_'); }

  // ── Selector / filtros / orden ─────────────────────────────────────────
  function zonaCambiarZona(idZona) {
    S.zonaActual = idZona; S.zonaProductos = [];
    // [RIZ #1] Resetear el filtro "del día" al cambiar de ámbito (el set cacheado es por zona+fecha).
    S._zonaDiaFiltro = { modo: 'todos', offset: 0 }; S._zonaDiaSet = null; S._zonaDiaSetKey = null;
    _zonaCargarPanel(true);
  }
  function zonaRefrescar() { _zonaCargarPanel(true); }
  function zonaSetOrden(v) { S._zonaFiltros.orden = v; renderZona(); }
  function zonaFiltrar()   { S._zonaFiltros.q = ($('zonaSearch') && $('zonaSearch').value || '').trim(); renderZona(); }
  function zonaToggleKpi(kpi) {
    const f = S._zonaFiltros;
    f.kpi = (f.kpi === kpi) ? null : kpi;
    document.querySelectorAll('#zonaKpis .zona-kpi').forEach(el => el.classList.toggle('active', el.dataset.kpi === f.kpi));
    _zonaSfx('tick'); _zonaVibrar(15);
    renderZona();
  }
  function zonaToggleTend(t) {
    const f = S._zonaFiltros;
    f.tend[t] = !f.tend[t];
    document.querySelectorAll('.zona-chip-f[data-tend]').forEach(el => el.classList.toggle('active', !!f.tend[el.dataset.tend]));
    _zonaSfx('tick'); _zonaVibrar(15);
    renderZona();
  }
  function zonaToggleFiltro(name) {
    const f = S._zonaFiltros;
    if (name === 'brecha') f.brecha = !f.brecha;
    document.querySelectorAll('.zona-chip-f[data-filtro]').forEach(el => { if (el.dataset.filtro === name) el.classList.toggle('active', f[name]); });
    _zonaSfx('tick'); _zonaVibrar(15);
    renderZona();
  }

  // ── Ajuste inline de stock (✎) — [MEJORA 4] input manual + "Cero" + stepper ──
  //   optimista + dual-write + revertir+shake. Decimales si esGranel.
  function zonaAjusteInline(sku) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    if (!p) return;
    // [192 · MULTI-CÓDIGO] Si el producto tiene >1 código en el grupo (canónico + equivalentes), editar un
    // "total global" es ilógico (el set-absoluto único corrompería la suma → escribiría sólo un código). El ✎
    // NO abre el stepper global: despliega DIRECTO el ajuste por código (set-absoluto por cada barra).
    const codigosG = Array.isArray(p.codigos) ? p.codigos : [];
    if (codigosG.length > 1) {
      _zonaSfx('tick'); _zonaVibrar(15);
      _zonaAbrirCodigos(sku);   // abre el desglose (no togglea: siempre lo deja abierto)
      try { const body = $('zCodBody-' + _zonaSkuId(sku)); if (body) body.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); } catch (_) {}
      return;
    }
    const cell = $('zStock-' + _zonaSkuId(sku));
    if (!cell) return;
    const cur = _zonaNum(p.stockZona != null ? p.stockZona : p.stock);
    const step = _zonaStepAttr(p);
    const val  = _zonaFmtCant(cur, p, true);
    const e    = _zonaEsc(sku);
    // Stepper + input numérico manual + botón "Cero" + confirmar. El input es la fuente de verdad.
    cell.innerHTML = `<span class="zona-stepper">
        <button class="zona-step-btn" onclick="MOS.zonaStep('${e}',-1)">−</button>
        <input type="number" inputmode="decimal" step="${step}" min="0" class="zona-step-input" id="zStep-${e}" value="${_esc(val)}" onkeydown="if(event.key==='Enter')MOS.zonaConfirmarAjuste('${e}')">
        <button class="zona-step-btn" onclick="MOS.zonaStep('${e}',1)">+</button>
        <button class="zona-step-btn zona-step-cero" onclick="MOS.zonaCero('${e}')" title="Poner en cero">0</button>
        <button class="zona-step-btn" style="background:#16a34a;border-color:#16a34a" onclick="MOS.zonaConfirmarAjuste('${e}')">✓</button>
      </span>`;
    const inp = $('zStep-' + sku);
    if (inp) { try { inp.focus(); inp.select(); } catch(_){} }
    _zonaSfx('tick'); _zonaVibrar(15);
  }
  function _zonaSkuId(sku) { return String(sku); }
  function _zonaEsc(s) { return String(s).replace(/'/g, "\\'"); }
  function _zonaLeerStep(sku, p) {
    const v = $('zStep-' + sku);
    return v ? _zonaParseCant(v.value, !!(p && p.esGranel)) : 0;
  }
  function zonaStep(sku, delta) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    const v = $('zStep-' + sku);
    if (!v) return;
    const esGranel = !!(p && p.esGranel);
    let n = _zonaParseCant(v.value, esGranel);
    const paso = esGranel ? 0.5 : 1;
    n = Math.max(0, esGranel ? Math.round((n + delta * paso) * 100) / 100 : n + delta);
    v.value = _zonaFmtNumRaw(n, esGranel);
    _zonaSfx('tick');
    _zonaVibrar(20);
  }
  // [MEJORA 4] botón "Cero": setea 0 al instante en el input del stepper.
  function zonaCero(sku) {
    const v = $('zStep-' + sku);
    if (v) { v.value = '0'; try { v.focus(); } catch(_){} }
    _zonaSfx('tick'); _zonaVibrar(20);
  }
  // ¿La zona activa es el ALMACÉN? (ajuste → wh.stock vía mos.almacen_crear_ajuste; ZONA → me.stock_zonas).
  function _zonaEsAlmacen() {
    return _esZonaAlmacen({ idZona: S.zonaActual,
      nombre: ((S.zonaList || []).find(x => (x.idZona || x.id || x.nombre) === S.zonaActual) || {}).nombre });
  }
  // localId/idAjuste ESTABLE por gesto de ajuste de un código (idempotencia dura en backend).
  function _zonaAjusteLocalId(cb) {
    const amb = _zonaEsAlmacen() ? 'ALM' : (S.zonaActual || 'Z');
    return 'RIZAJ_' + amb + '_' + String(cb).replace(/[^A-Za-z0-9]/g, '') + '_' +
      Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 8);
  }
  // Aplica el ajuste de UN código según el ámbito (ZONA → SET-ABSOLUTO me.stock_zonas ; ALMACEN → DELTA wh.stock).
  // Devuelve la respuesta cruda de la RPC (o null/throw si falló). El conteo `nuevo` es ABS en la unidad de ESE código.
  async function _zonaAplicarAjusteCodigo(cb, nuevo, localId) {
    if (_zonaEsAlmacen()) {
      return API.zona.almacenAjustar({ zona: S.zonaActual, codProducto: String(cb), conteo: nuevo, idAjuste: localId });
    }
    return API.zona.ajustarStock({ zona: S.zonaActual, codBarra: String(cb), nuevo, localId });
  }
  async function zonaConfirmarAjuste(sku) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    if (!p) return;
    // [MULTI-CÓDIGO] Si el producto tiene >1 código en esta zona/almacén, el stepper único corrompería la suma
    // (escribiría sólo el canónico). Abrir el desglose por código para que el admin cuente cada uno en persona.
    const codigos = Array.isArray(p.codigos) ? p.codigos : [];
    if (codigos.length > 1) {
      _zonaSfx('tick'); _zonaVibrar(20);
      toast('Este producto tiene ' + codigos.length + ' códigos. Cuenta cada uno por separado.', 'info');
      zonaToggleCodigos(sku);   // expande el desglose (abre si está cerrado); inputs por código + ✓ por código
      // re-pintar el stepper a su valor original (no aplicar el set único que rompería la suma).
      _zonaActualizarBotonCard(sku);
      renderZona();
      try { const body = $('zCodBody-' + _zonaSkuId(sku)); if (body) body.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); } catch (_) {}
      return;
    }
    const nuevo = _zonaLeerStep(sku, p);
    const antes = _zonaNum(p.stockZona != null ? p.stockZona : p.stock);
    const card  = $('zcard-' + sku);
    // El código a tocar: si hay 1 código en el desglose, ese; si no, se deja que el backend resuelva el canónico
    // (ZONA) — para ALMACÉN necesitamos el código concreto, así que usamos el único de codigos[] si existe.
    const cbUnico = codigos.length === 1
      ? String(codigos[0].codBarra != null ? codigos[0].codBarra : codigos[0].codigoBarra)
      : null;
    // localId ESTABLE por gesto en vuelo (idempotencia dura backend): un doble-tap / reintento del MISMO ajuste
    // reusa el id → el backend dedupea (no duplica fila de ajuste/movimiento). Se libera al confirmar.
    const localId = p._ajLocalId || (p._ajLocalId = _zonaAjusteLocalId(cbUnico || sku));
    // OPTIMISTA: actualizar memoria + re-render del card al instante
    if (codigos.length === 1) codigos[0].stock = nuevo;
    if (p.stockZona != null) p.stockZona = nuevo; else p.stock = nuevo;
    p.stockNegativo = (nuevo < 0);   // editar a >=0 limpia la alerta (ya no es negativo)
    if (p.esperada != null || p.esperado != null) {
      const esp = _zonaNum(p.esperada != null ? p.esperada : p.esperado);
      p.brecha = Math.max(0, esp - nuevo);
    }
    renderZona();
    _zonaSfx('ok'); _zonaVibrar(30);
    toast('Stock ajustado a ' + _zonaFmtCant(nuevo, p), 'ok');
    // BACKGROUND: ZONA → SET-ABSOLUTO me.stock_zonas ; ALMACEN → DELTA wh.stock (ver api.js cabecera RIZ).
    try {
      let r;
      if (cbUnico) {
        // código concreto conocido (único del desglose) → ruta por código (ZONA o ALMACEN).
        r = await _zonaAplicarAjusteCodigo(cbUnico, nuevo, localId);
      } else if (_zonaEsAlmacen()) {
        // ALMACÉN sin código en el desglose: no podemos resolver el canónico server-side de WH → no aplicar.
        throw new Error('Sin código de almacén para ajustar');
      } else {
        // ZONA sin desglose: el backend resuelve el canónico del skuBase (comportamiento histórico).
        r = await API.zona.ajustarStock({ zona: S.zonaActual, skuBase: sku, nuevo, localId });
      }
      if (r == null || r.ok === false) throw new Error((r && r.error) || 'sin commit');
      delete p._ajLocalId;   // gesto confirmado → liberar el id (un nuevo conteo usará otro)
      _zonaPintarKpis();
    } catch (e) {
      // ROLLBACK + shake
      delete p._ajLocalId;   // fallo → liberar el id; un reintento manual cuenta como gesto nuevo
      if (codigos.length === 1) codigos[0].stock = antes;
      if (p.stockZona != null) p.stockZona = antes; else p.stock = antes;
      p.stockNegativo = (antes < 0);
      if (p.esperada != null || p.esperado != null) {
        const esp = _zonaNum(p.esperada != null ? p.esperada : p.esperado);
        p.brecha = Math.max(0, esp - antes);
      }
      renderZona();
      const c2 = $('zcard-' + sku);
      if (c2) { c2.classList.remove('shake'); void c2.offsetWidth; c2.classList.add('shake'); }
      _zonaSfx('error'); _zonaVibrar([120,40,120]);
      toast('No se pudo ajustar: ' + (e.message || e), 'error');
    }
  }

  // ── [MEJORA 5] Multi-código: disclosure + editar stock por codBarra ───────
  // Abre el desglose por código SIEMPRE (no togglea). Usado por el ✎ en multi-código → muestra el ajuste por
  // código directo (sin stepper global). Idempotente: si ya está abierto, lo deja abierto (re-pinta).
  function _zonaAbrirCodigos(sku) {
    const body = $('zCodBody-' + _zonaSkuId(sku));
    if (!body) return;
    const abierto = body.style.display !== 'none' && body.innerHTML.trim() !== '';
    if (!abierto) zonaToggleCodigos(sku);
  }
  function zonaToggleCodigos(sku) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    if (!p) return;
    const body  = $('zCodBody-' + _zonaSkuId(sku));
    const caret = $('zCodCaret-' + _zonaSkuId(sku));
    if (!body) return;
    const abierto = body.style.display !== 'none' && body.innerHTML.trim() !== '';
    if (abierto) {
      body.style.display = 'none';
      if (caret) caret.textContent = '▸';
      _zonaSfx('tick');
      return;
    }
    const codigos = Array.isArray(p.codigos) ? p.codigos : [];
    body.innerHTML = codigos.length
      ? `<div class="zona-cod-hint">El <b>Esperado ${_esc(_zonaFmtCant(_zonaNum(p.esperada != null ? p.esperada : p.esperado), p, true))}</b> es global del producto (no por código).</div>`
        + codigos.map(c => _zonaCodRowHtml(sku, c, p)).join('')
      : '<div class="zona-cod-hint">Sin códigos individuales.</div>';
    body.style.display = '';
    if (caret) caret.textContent = '▾';
    _zonaSfx('pop'); _zonaVibrar(20);
  }
  // [MEJORA 3] disclosure de códigos del ALMACÉN (solo lectura — el stock de almacén es de WH).
  function zonaToggleCodigosAlmacen(sku) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    if (!p) return;
    const body  = $('zAlmBody-' + _zonaSkuId(sku));
    const caret = $('zAlmCaret-' + _zonaSkuId(sku));
    if (!body) return;
    const abierto = body.style.display !== 'none' && body.innerHTML.trim() !== '';
    if (abierto) {
      body.style.display = 'none';
      if (caret) caret.textContent = '▸';
      _zonaSfx('tick');
      return;
    }
    const cods = Array.isArray(p.codigosAlmacen) ? p.codigosAlmacen : [];
    body.innerHTML = cods.length
      ? `<div class="zona-cod-hint">Stock en <b>almacén central</b> (solo lectura — se gestiona desde WH).</div>`
        + cods.map(c => _zonaAlmRowHtml(c, p)).join('')
      : '<div class="zona-cod-hint">Sin códigos en almacén.</div>';
    body.style.display = '';
    if (caret) caret.textContent = '▾';
    _zonaSfx('pop'); _zonaVibrar(20);
  }
  // [MEJORA 3] Fila de un código de almacén (solo lectura, sin inputs de edición).
  function _zonaAlmRowHtml(c, item) {
    const cb   = String(c.codBarra != null ? c.codBarra : (c.codigoBarra != null ? c.codigoBarra : ''));
    const cbAttr = _esc(cb);
    const desc = _esc(c.descripcion || cb);
    const st   = _zonaFmtCant(c.stock, item, true);
    const equiv = c.esEquivalente ? '<span class="zona-cod-equiv" title="Código equivalente">equiv</span>' : '';
    return `<div class="zona-cod-row zona-cod-row-ro">
      <div class="zona-cod-info">
        <div class="zona-cod-desc">${desc} ${equiv}</div>
        <div class="zona-cod-cb">${cbAttr}</div>
      </div>
      <div class="zona-cod-alm-st"><span class="zona-cod-alm-lbl">almacén</span><b>${_esc(st)}</b></div>
    </div>`;
  }
  function _zonaCodFind(p, cb) {
    const codigos = Array.isArray(p.codigos) ? p.codigos : [];
    return codigos.find(c => String(c.codBarra != null ? c.codBarra : c.codigoBarra) === String(cb));
  }
  function zonaCodCero(sku, cb) {
    const inp = $('zCodIn-' + _zonaSkuId(sku) + '-' + _zonaCodKey(cb));
    if (inp) { inp.value = '0'; try { inp.focus(); } catch(_){} }
    _zonaSfx('tick'); _zonaVibrar(20);
  }
  async function zonaCodGuardar(sku, cb) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    if (!p) return;
    const c = _zonaCodFind(p, cb);
    if (!c) return;
    const inp = $('zCodIn-' + _zonaSkuId(sku) + '-' + _zonaCodKey(cb));
    const nuevo = inp ? _zonaParseCant(inp.value, !!p.esGranel) : 0;
    const antes = _zonaNum(c.stock);
    const card  = $('zcard-' + sku);
    // OPTIMISTA: actualizar el código + recomputar el global (suma de códigos) + re-render.
    c.stock = nuevo;
    _zonaRecalcGlobal(p);
    renderZona();
    // re-abrir el disclosure (renderZona lo cierra) para que se vea el efecto.
    zonaToggleCodigos(sku);
    _zonaSfx('ok'); _zonaVibrar(30);
    toast('Código ajustado a ' + _zonaFmtCant(nuevo, p), 'ok');
    // localId estampado en el código mientras dura el gesto → un reintento del MISMO gesto reusa el id (idempotente).
    const localId = c._ajLocalId || (c._ajLocalId = _zonaAjusteLocalId(cb));
    try {
      // ZONA → SET-ABSOLUTO me.stock_zonas (por código) ; ALMACEN → DELTA wh.stock (por código). Idempotente.
      const r = await _zonaAplicarAjusteCodigo(String(cb), nuevo, localId);
      if (r == null || r.ok === false) throw new Error((r && r.error) || 'sin commit');
      delete c._ajLocalId;   // gesto confirmado → liberar el id (un nuevo conteo del mismo código usará otro)
      _zonaPintarKpis();
    } catch (e) {
      // ROLLBACK + shake
      c.stock = antes;
      _zonaRecalcGlobal(p);
      renderZona();
      const c2 = $('zcard-' + sku);
      if (c2) { c2.classList.remove('shake'); void c2.offsetWidth; c2.classList.add('shake'); }
      _zonaSfx('error'); _zonaVibrar([120,40,120]);
      toast('No se pudo ajustar el código: ' + (e.message || e), 'error');
    }
  }
  // Recalcula el stock global del producto (suma de sus códigos) + brecha/negativo derivados.
  function _zonaRecalcGlobal(p) {
    const codigos = Array.isArray(p.codigos) ? p.codigos : [];
    if (codigos.length) {
      const suma = codigos.reduce((a, c) => a + _zonaNum(c.stock), 0);
      const round = p.esGranel ? Math.round(suma * 100) / 100 : Math.round(suma);
      if (p.stockZona != null) p.stockZona = round; else p.stock = round;
    }
    const stock = _zonaNum(p.stockZona != null ? p.stockZona : p.stock);
    p.stockNegativo = (stock < 0);
    if (p.esperada != null || p.esperado != null) {
      const esp = _zonaNum(p.esperada != null ? p.esperada : p.esperado);
      p.brecha = Math.max(0, esp - stock);
    }
  }

  // ── [MEJORA 1] Modal "¿Por qué esperado = X?" (explica picos × 1.2) ───────
  function zonaVerEsperado(sku) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    if (!p) return;
    const tit = $('zonaEspTitulo');
    if (tit) tit.textContent = (p.descripcion || p.nombre || sku);
    const picos = Array.isArray(p.picos) ? p.picos.slice(-4) : [];
    const esp = _zonaNum(p.esperada != null ? p.esperada : p.esperado);
    const picoUltima = picos.length ? _zonaNum(picos[picos.length - 1]) : 0;
    const body = $('zonaEspBody');
    if (body) {
      const maxP = Math.max(1, ...picos.map(_zonaNum));
      const labelsSem = (n) => ['hace 3 sem', 'hace 2 sem', 'sem pasada', 'última sem'].slice(Math.max(0, 4 - n));
      const lbls = labelsSem(picos.length);
      const barras = picos.length
        ? picos.map((v, i) => {
            const val = _zonaNum(v);
            const h = Math.max(6, Math.round(val / maxP * 130));
            const last = (i === picos.length - 1);
            return `<div class="zona-esp-col${last ? ' last' : ''}">
              <div class="zona-esp-bval">${_esc(_zonaFmtCant(val, p, true))}</div>
              <div class="zona-esp-bar" style="height:${h}px;animation-delay:${i*90}ms"></div>
              <div class="zona-esp-blbl">${_esc(lbls[i] || ('sem ' + (i+1)))}</div>
            </div>`;
          }).join('')
        : '<div class="text-slate-500 text-sm py-6 text-center">Sin historial de picos para este producto.</div>';
      const calc = picos.length
        ? `<div class="zona-esp-calc">
             <div class="zona-esp-formula">Esperado = redondear( pico de la última semana × 1.2 )</div>
             <div class="zona-esp-nums">= redondear( <b>${_esc(_zonaFmtCant(picoUltima, p, true))}</b> × 1.2 )
               = redondear( <b>${_esc(_zonaFmtNumRaw(picoUltima * 1.2, p.esGranel))}</b> )
               = <b class="zona-esp-res">${_esc(_zonaFmtCant(esp, p, true))}</b></div>
             <div class="zona-esp-why">El pico es el día de mayor venta de cada semana. Reponemos un 20% extra de colchón sobre el mejor día reciente.</div>
           </div>`
        : `<div class="zona-esp-calc"><div class="zona-esp-nums">Esperado actual: <b class="zona-esp-res">${_esc(_zonaFmtCant(esp, p, true))}</b></div></div>`;
      body.innerHTML = `<div class="zona-esp-bars">${barras}</div>${calc}`;
    }
    openModal('modalZonaEsp');
    _zonaSfx('pop'); _zonaVibrar(20);
  }
  function zonaCerrarEsperado() { closeModal('modalZonaEsp'); }

  // ══ [RIZ CARRITO] Pedido a almacén por CARRITO (un paquete = un pickup con N líneas) ════════════════════
  //   "Pedir" en el card YA NO envía: AGREGA al carrito flotante de la zona. El carrito (modal) permite
  //   editar cantidad (+/−), quitar, vaciar y "Enviar pedido" (manda TODO en un solo paquete idempotente).
  //   El estado "Pedido hoy/ayer" persiste en Supabase (me.zona_pedido_log) y el panel lo devuelve.

  // mapa carrito de la zona activa (se crea perezosamente). Clave = skuBase.
  function _zonaCart() {
    const z = S.zonaActual || '_';
    if (!S._zonaCarrito[z]) S._zonaCarrito[z] = {};
    return S._zonaCarrito[z];
  }
  function _zonaCarritoCant(sku) { const c = _zonaCart()[String(sku)]; return c ? _zonaNum(c.cantidad) : 0; }
  function _zonaCarritoNItems() { return Object.keys(_zonaCart()).length; }

  // AGREGAR (o sumar la sugerencia a) un producto al carrito. cantidad = brecha sugerida (puede ser 0 → mete 1
  // como mínimo accionable para que el admin lo vea en el carrito y ajuste). Re-agregar suma la sugerencia.
  function zonaPedirAlmacen(sku, cantidad) {
    sku = String(sku);
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    if (!p) return;
    const esGranel = !!p.esGranel;
    let add = _zonaNum(cantidad);
    if (!(add > 0)) add = esGranel ? 0.5 : 1;   // si no hay brecha, agrega 1 unidad accionable
    const cart = _zonaCart();
    const ya = cart[sku] ? _zonaNum(cart[sku].cantidad) : 0;
    const nueva = esGranel ? Math.round((ya + add) * 100) / 100 : (ya + add);
    cart[sku] = { sku, nombre: String(p.descripcion || p.nombre || sku), cantidad: nueva, esGranel };
    // feedback inmediato + actualizar SOLO el botón de este card (sin re-render completo, preserva scroll).
    _zonaSfx('pop'); _zonaVibrar([40,30,40]);
    const btn = $('zPedir-' + sku);
    const card = $('zcard-' + sku);
    if (btn) {
      btn.classList.remove('zona-pedido-ok');
      btn.classList.add('zona-en-carrito');
      btn.innerHTML = '🛒 En carrito (' + _esc(_zonaFmtCant(nueva, p)) + ') · +';
      btn.setAttribute('onclick', `MOS.zonaPedirAlmacen('${_zonaEsc(sku)}', ${(p.brecha != null ? _zonaNum(p.brecha) : 0)})`);
    }
    if (card) { card.classList.remove('pulse-ok'); void card.offsetWidth; card.classList.add('pulse-ok'); }
    toast('Agregado al pedido', 'ok');
    _zonaCarritoSync();   // refrescar FAB/badge + (si está abierto) el cuerpo del carrito
  }

  // Refresca el FAB flotante (visible solo con >=1 ítem) + badge + cuerpo del modal si está abierto.
  function _zonaCarritoSync() {
    const n = _zonaCarritoNItems();
    const fab = $('zonaCartFab'), badge = $('zonaCartBadge');
    if (fab) {
      fab.classList.toggle('hidden', !(n > 0 && S.view === 'zona'));
      if (n > 0) { fab.classList.remove('zona-cart-bump'); void fab.offsetWidth; fab.classList.add('zona-cart-bump'); }
    }
    if (badge) badge.textContent = String(n);
    const modal = $('modalZonaCart');
    if (modal && modal.classList.contains('open')) _zonaCarritoRender();
  }

  function zonaCarritoAbrir() {
    if (!_zonaCarritoNItems()) { toast('Carrito vacío', 'info'); return; }
    const zt = $('zonaCartZona');
    if (zt) { const zo = (S.zonaList || []).find(x => (x.idZona || x.id || x.nombre) === S.zonaActual); zt.textContent = 'Zona ' + ((zo && zo.nombre) || S.zonaActual || ''); }
    _zonaCarritoRender();
    openModal('modalZonaCart');
    _zonaSfx('pop'); _zonaVibrar(20);
  }
  function zonaCarritoCerrar() { closeModal('modalZonaCart'); }

  function _zonaCarritoRender() {
    const body = $('zonaCartBody');
    if (!body) return;
    const cart = _zonaCart();
    const skus = Object.keys(cart);
    const enviar = $('zonaCartEnviar'), vaciar = $('zonaCartVaciar');
    if (!skus.length) {
      body.innerHTML = '<div class="zona-cart-empty">🛒 Tu pedido está vacío.<br>Agrega productos desde los cards.</div>';
      if (enviar) enviar.disabled = true;
      if (vaciar) vaciar.disabled = true;
      return;
    }
    if (enviar) enviar.disabled = false;
    if (vaciar) vaciar.disabled = false;
    body.innerHTML = skus.map(sku => {
      const it = cart[sku];
      const e = _zonaEsc(sku);
      const step = it.esGranel ? '0.5' : '1';
      const val = _zonaFmtNumRaw(_zonaNum(it.cantidad), it.esGranel);
      return `<div class="zona-cart-row" id="zCartRow-${_esc(sku)}">
        <button class="zona-cart-del" onclick="MOS.zonaCarritoQuitar('${e}')" title="Quitar">🗑</button>
        <div class="zona-cart-info">
          <div class="zona-cart-nm">${_esc(it.nombre)}</div>
          <div class="zona-cart-hint">${_esc(sku)}</div>
        </div>
        <div class="zona-cart-stepper">
          <button class="zona-cart-step" onclick="MOS.zonaCarritoStep('${e}',-1)">−</button>
          <input type="number" inputmode="decimal" step="${step}" min="0" class="zona-cart-qty" id="zCartQty-${_esc(sku)}" value="${_esc(val)}" onchange="MOS.zonaCarritoSet('${e}', this.value)">
          <button class="zona-cart-step" onclick="MOS.zonaCarritoStep('${e}',1)">+</button>
        </div>
      </div>`;
    }).join('');
  }

  function zonaCarritoStep(sku, delta) {
    sku = String(sku);
    const cart = _zonaCart();
    const it = cart[sku];
    if (!it) return;
    const paso = it.esGranel ? 0.5 : 1;
    let n = _zonaNum(it.cantidad) + delta * paso;
    n = Math.max(0, it.esGranel ? Math.round(n * 100) / 100 : n);
    if (n <= 0) { zonaCarritoQuitar(sku); return; }   // bajar a 0 = quitar
    it.cantidad = n;
    const inp = $('zCartQty-' + sku);
    if (inp) inp.value = _zonaFmtNumRaw(n, it.esGranel);
    _zonaSfx('tick'); _zonaVibrar(15);
    _zonaActualizarBotonCard(sku);
  }
  function zonaCarritoSet(sku, valor) {
    sku = String(sku);
    const cart = _zonaCart();
    const it = cart[sku];
    if (!it) return;
    let n = _zonaParseCant(valor, !!it.esGranel);
    n = Math.max(0, n);
    if (n <= 0) { zonaCarritoQuitar(sku); return; }
    it.cantidad = n;
    _zonaSfx('tick'); _zonaVibrar(15);
    _zonaActualizarBotonCard(sku);
  }
  function zonaCarritoQuitar(sku) {
    sku = String(sku);
    const cart = _zonaCart();
    delete cart[sku];
    _zonaSfx('tick'); _zonaVibrar([20,20]);
    const row = $('zCartRow-' + sku);
    if (row) row.remove();
    _zonaActualizarBotonCard(sku);
    _zonaCarritoSync();
  }
  function zonaCarritoVaciar() {
    const cart = _zonaCart();
    const skus = Object.keys(cart);
    skus.forEach(s => delete cart[s]);
    _zonaSfx('tick'); _zonaVibrar([30,30]);
    skus.forEach(_zonaActualizarBotonCard);
    _zonaCarritoSync();
    toast('Pedido vaciado', 'info');
  }
  // Repinta el botón del card de un sku según su estado actual en el carrito (sin re-render completo).
  function _zonaActualizarBotonCard(sku) {
    sku = String(sku);
    const btn = $('zPedir-' + sku);
    if (!btn) return;
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    const enCarrito = _zonaCarritoCant(sku);
    const brecha = p ? (p.brecha != null ? _zonaNum(p.brecha) : 0) : 0;
    const pedLbl = (p && p.pedidoEstado && p.pedidoEstado.etiqueta) ? String(p.pedidoEstado.etiqueta) : '';
    btn.classList.remove('zona-en-carrito', 'zona-pedido-ok');
    if (enCarrito > 0) {
      btn.classList.add('zona-en-carrito');
      btn.innerHTML = '🛒 En carrito (' + _esc(p ? _zonaFmtCant(enCarrito, p) : enCarrito) + ') · +';
    } else if (pedLbl) {
      // ya pedido (persistido) y sin nada en el carrito → estado "Pedido hoy/ayer", re-pedir con un tap.
      btn.classList.add('zona-pedido-ok');
      btn.innerHTML = '✓ ' + _esc(pedLbl) + ' · re-pedir';
    } else {
      btn.innerHTML = brecha > 0 ? 'Pedir ' + _esc(p ? _zonaFmtCant(brecha, p) : brecha) + ' a almacén' : 'Agregar al pedido';
    }
    btn.setAttribute('onclick', `MOS.zonaPedirAlmacen('${_zonaEsc(sku)}', ${brecha})`);
  }

  // ENVIAR el carrito = UN paquete (un pickup con N líneas). Idempotente por localId del paquete (el reenvío
  // del MISMO carrito no duplica en wh.pickups). Optimista: cierra el modal + toast; si falla, reabre.
  async function zonaCarritoEnviar() {
    if (S._zonaCarritoEnviando) return;       // lock anti doble-tap
    const cart = _zonaCart();
    const skus = Object.keys(cart);
    if (!skus.length) { toast('Carrito vacío', 'info'); return; }
    const items = skus.map(s => ({ skuBase: s, cantidad: _zonaNum(cart[s].cantidad) })).filter(x => x.cantidad > 0);
    if (!items.length) { toast('Sin cantidades válidas', 'error'); return; }
    // localId estable del PAQUETE → idempotencia (reenvío = mismo pickup, no duplica).
    const localId = 'RIZCART_' + (S.zonaActual || 'Z') + '_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 8);
    S._zonaCarritoEnviando = true;
    const enviar = $('zonaCartEnviar');
    if (enviar) { enviar.disabled = true; enviar.textContent = 'Enviando…'; }
    _zonaSfx('ok'); _zonaVibrar([80,60,80]);
    try {
      const r = await API.zona.pedirAlmacen({ zona: S.zonaActual, items, localId });
      if (r == null || r.ok === false) throw new Error((r && r.error) || 'sin commit');
      // ÉXITO: vaciar carrito de la zona + cerrar modal + refrescar panel (trae pedidoEstado persistido).
      skus.forEach(s => delete cart[s]);
      closeModal('modalZonaCart');
      toast('Pedido enviado a almacén (' + items.length + ' producto' + (items.length > 1 ? 's' : '') + ')', 'ok');
      _zonaCarritoSync();
      skus.forEach(_zonaActualizarBotonCard);
      setTimeout(() => { _zonaAutoRefrescar(); }, 700);
    } catch (e) {
      _zonaSfx('error'); _zonaVibrar([120,40,120]);
      toast('No se pudo enviar, reintenta', 'error');
    } finally {
      S._zonaCarritoEnviando = false;
      if (enviar) { enviar.disabled = false; enviar.textContent = 'Enviar pedido'; }
    }
  }

  // + Lista compras: [Capa 5] cableado a mos.zona_lista_compras (lectura). La RPC arma/lee la lista
  // de compra externa de la semana; mostramos confirmación con el conteo real. Optimista + rollback de toast.
  // Semana ISO-8601 en formato `IYYY-"W"IW` (idéntico al to_char de Postgres que espera me.zona_lista_compras).
  // Week 1 = la que contiene el primer jueves del año; lunes es el primer día. Devuelve p.ej. "2026-W25".
  function _zonaSemanaISO(d) {
    const dt = new Date(d || Date.now());
    // normalizar a medianoche UTC del día (evita corrimientos por TZ/horario)
    const t = new Date(Date.UTC(dt.getFullYear(), dt.getMonth(), dt.getDate()));
    // jueves de esta semana (ISO: lunes=1..domingo=7); el año del jueves es el año ISO
    const day = t.getUTCDay() || 7;            // domingo(0) → 7
    t.setUTCDate(t.getUTCDate() + 4 - day);     // mover al jueves de la semana
    const isoYear = t.getUTCFullYear();
    const yearStart = new Date(Date.UTC(isoYear, 0, 1));
    const week = Math.ceil((((t - yearStart) / 86400000) + 1) / 7);
    return isoYear + '-W' + String(week).padStart(2, '0');
  }

  async function zonaAgregarLista(sku, cantidad) {
    _zonaSfx('pop'); _zonaVibrar(20);
    toast('Agregado a lista de compras (' + _zonaNum(cantidad) + ')', 'ok');
    // BACKGROUND: confirmar contra la lista real de la semana (lectura). Si falla, solo logueamos (el optimista ya cerró).
    try {
      // ⚠ me.zona_lista_compras EXIGE `semana` en formato ISO `IYYY-"W"IW` (== to_char de Postgres);
      //   sin él devolvía ok:false y la lista nunca se armaba/persistía. Lo calculamos aquí.
      const r = await API.zona.listaCompras({ zona: S.zonaActual, semana: _zonaSemanaISO() });
      const data = (r && r.data) || r || {};
      const items = Array.isArray(data.items) ? data.items : (Array.isArray(data.productos) ? data.productos : (Array.isArray(data) ? data : []));
      if (items.length) toast('Lista del lunes: ' + items.length + ' producto(s) por comprar', 'info');
    } catch (e) {
      try { console.warn('[RIZ] zonaAgregarLista listaCompras:', e && (e.message || e)); } catch (_) {}
    }
  }

  // ══ [RIZ · CAPA 5] IMPRESIÓN 80mm (Edge riz-print → PrintNode) ══════════
  // Reusa el PrinterPicker universal para elegir impresora (memoria por flowKey), luego dispara la
  // Edge. Optimista: toast "enviado a impresora" + sonido print. Si falla, toast rojo + shake del botón.
  // Fecha de HOY en TZ Perú como 'YYYY-MM-DD' (NO toISOString → eso es UTC y a las <19:00 local
  // devolvería el día equivocado). en-CA + timeZone:'America/Lima' produce 'YYYY-MM-DD' nativo.
  function _zonaFechaHoy() {
    try { return new Date().toLocaleDateString('en-CA', { timeZone: 'America/Lima' }); }
    catch (_) { const d = new Date(); return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0'); }
  }

  // ══ [RIZ #1 · FILTRO "DEL DÍA"] partición diaria del ticket (espeja me.zona_ticket_dia) ══════════════════
  // La fecha activa = HOY (TZ Perú) + offset días. Trabajamos siempre con un Date "calendario" (medianoche
  // local Perú) para evitar corrimientos UTC: tomamos los componentes Y/M/D de Perú y construimos un Date
  // local con esos números (NO new Date(isoString), que interpretaría UTC).
  function _zonaHoyPeru() {
    // 'YYYY-MM-DD' en TZ Lima → Date local con esos componentes (medianoche local, sin corrimiento UTC).
    const s = _zonaFechaHoy();                       // 'YYYY-MM-DD' (Perú)
    const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
    if (m) return new Date(+m[1], +m[2] - 1, +m[3]);
    const d = new Date(); return new Date(d.getFullYear(), d.getMonth(), d.getDate());
  }
  // Fecha activa del filtro = hoy Perú + offset días (Date calendario local).
  function _zonaDiaActiva() {
    const base = _zonaHoyPeru();
    const off = (S._zonaDiaFiltro && S._zonaDiaFiltro.offset) || 0;
    return new Date(base.getFullYear(), base.getMonth(), base.getDate() + off);
  }
  // 'YYYY-MM-DD' de un Date calendario (sin TZ — ya son componentes locales Perú).
  function _zonaFechaStr(d) {
    return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
  }
  // Etiqueta amable del día activo, ej. "vie 19 jun". Si offset 0 → "hoy", −1 → "ayer", +1 → "mañana".
  function _zonaDiaLabel() {
    const d = _zonaDiaActiva();
    const off = (S._zonaDiaFiltro && S._zonaDiaFiltro.offset) || 0;
    const dias = ['dom', 'lun', 'mar', 'mié', 'jue', 'vie', 'sáb'];
    const mes  = ['ene', 'feb', 'mar', 'abr', 'may', 'jun', 'jul', 'ago', 'sep', 'oct', 'nov', 'dic'];
    const base = dias[d.getDay()] + ' ' + d.getDate() + ' ' + mes[d.getMonth()];
    if (off === 0) return base + ' · hoy';
    if (off === -1) return base + ' · ayer';
    if (off === 1) return base + ' · mañana';
    return base;
  }
  // Set de skuBase (Set<string>) de la TANDA del día activo, traída del backend (me.zona_ticket_dia) para que
  // el filtro COINCIDA EXACTAMENTE con lo que imprime el ticket de ese día (misma partición anclada al lunes).
  // Cache por (zona, fecha). Devuelve null si no se pudo cargar (el render entonces no filtra → muestra todo).
  async function _zonaDiaCargarSet() {
    const zona = S.zonaActual, fecha = _zonaFechaStr(_zonaDiaActiva());
    const key = String(zona) + '|' + fecha;
    if (S._zonaDiaSetKey === key && S._zonaDiaSet) return S._zonaDiaSet;
    try {
      const r = await API.zona.ticketDia({ zona, fecha });
      const data = (r && r.data) || r || {};
      const set = new Set();
      const lotes = Array.isArray(data.lotes) ? data.lotes : [];
      lotes.forEach(lo => (Array.isArray(lo.items) ? lo.items : []).forEach(it => {
        const sk = String(it.skuBase || it.sku || '');
        if (sk) set.add(sk);
      }));
      S._zonaDiaSetKey = key; S._zonaDiaSet = set;
      return set;
    } catch (e) {
      try { console.warn('[RIZ] _zonaDiaCargarSet:', e && (e.message || e)); } catch (_) {}
      return null;
    }
  }

  async function _zonaImprimirFlow(tipo, label, fechaExplicita) {
    // [RIZ #2 · doble-tap] Guard de re-entrancia: el ícono 🖨️ del grupo (y los botones de lista) son
    //   pequeños y táctiles → un doble-tap rápido podía disparar DOS jobs (sobre todo cuando la impresora
    //   está cacheada online y abrirPrinterPicker resuelve sin abrir modal). Bloqueamos hasta que el flujo
    //   actual termine. No es dinero, pero evita doble ticket / desperdicio de papel y confusión.
    if (S._zonaPrintBusy) { try { _zonaSfx('tick'); } catch (_) {} return; }
    S._zonaPrintBusy = true;
    try {
    let printerId = null;
    // [2026-06-19 fix impresora-por-ámbito] La memoria de "última impresora" DEBE ser por ZONA,
    // no global por tipo de flow. Antes flowKey='riz_'+tipo era único para todo el ecosistema:
    // si estabas en ALMACÉN imprimías a la impresora que quedó cacheada de ZONA-02 (y como estaba
    // online, abrirPrinterPicker la reusaba sin preguntar). Ahora la clave incluye la zona activa
    // → cada ámbito (ALMACÉN, ZONA-01, ZONA-02…) recuerda SU propia impresora; al cambiar de zona
    // se vuelve a preguntar (o se preselecciona la de esa zona).
    const zonaKey = String(S.zonaActual || 'sin-zona');
    try {
      printerId = await abrirPrinterPicker({
        titulo: '🖨 ' + label,
        subtitulo: 'Zona ' + (S.zonaActual || ''),
        filtroTipo: 'TICKET',
        filtroZona: S.zonaActual,
        flowKey: 'riz_' + tipo + '_' + zonaKey
      });
    } catch (_) { printerId = null; }
    if (!printerId) return;   // usuario canceló
    // OPTIMISTA
    _zonaSfx('ok'); _zonaVibrar(30);
    toast('🖨️ ' + label + ' enviado a impresora', 'ok');
    try {
      // [2026-06-19 fix ticket vacío] Reforzar pasando fecha/semana de HOY (TZ Perú). El RPC ya defaultea
      // a hoy si falta (supabase/184), pero mandarlo explícito evita depender del default y es a prueba de
      // futuros cambios de la Edge. ticket_diario → fecha; lista_compras → semana ISO actual.
      // [RIZ #2] ticket_diario: si el filtro está en "Día X" se imprime ESE día (fechaExplicita); en "Todos"
      //   se imprime HOY por defecto (NO los 177 — evita desperdicio de papel). lista_compras → semana actual.
      const extra = tipo === 'ticket_diario'
        ? { fecha: fechaExplicita || _zonaFechaHoy() }
        : { semana: _zonaSemanaISO() };
      const r = await API.zona.imprimir({ tipo, zona: S.zonaActual, printerId, ...extra });
      if (!r || r.ok === false) throw new Error((r && r.error) || 'sin respuesta');
    } catch (e) {
      _zonaSfx('error'); _zonaVibrar([120,40,120]);
      toast('No se pudo imprimir: ' + (e && (e.message || e)), 'error');
    }
    } finally { S._zonaPrintBusy = false; }
  }
  function zonaImprimirTicket() { return _zonaImprimirFlow('ticket_diario', 'Ticket del día'); }
  function zonaImprimirLista()  { return _zonaImprimirFlow('lista_compras', 'Lista compras'); }

  // ════════════ [P1d] VISTA PICKUP ACUMULADO POR ZONA + HISTORIAL POR DÍA ════════════
  // Lee wh.zona_pickup_detalle (100% Supabase) → la lista única de la zona con, por producto,
  // lo pendiente + el desglose por día (cuánto pidió cada cierre). En vivo.
  function _zpkNum(n){ n = parseFloat(n) || 0; return Number.isInteger(n) ? (''+n) : (''+(Math.round(n*1000)/1000)); }
  function _zpkDiaLbl(f){ try { const d = new Date(String(f).slice(0,10)+'T12:00:00'); return d.toLocaleDateString('es-PE',{weekday:'short',day:'2-digit',timeZone:'America/Lima'}); } catch(_) { return String(f||''); } }
  let _zpkLast = { zona: '', modo: 'pickup', data: null };   // [v2.43.379] para imprimir el rezagado
  async function zonaAbrirPickup(){
    const zona = S.zonaActual;
    if (!zona) return;
    _zpkRender(zona, null, true, 'pickup');
    try {
      const r = await API.zona.pickupDetalle({ zona });
      if (!r || r.ok === false) throw new Error((r && r.error) || 'sin datos');
      _zpkLast = { zona, modo: 'pickup', data: r };
      _zpkRender(zona, r, false, 'pickup');
    } catch (e) { _zpkRender(zona, { _error: String(e && e.message || e) }, false, 'pickup'); }
  }
  // [v2.43.379] Rezagado de la semana pasada (lo NO despachado) — misma vista detallada
  // con historial, para reclamos + botón de imprimir (80mm).
  async function zonaAbrirRezagado(zonaArg){
    const zona = zonaArg || S.zonaActual || (_zpkLast && _zpkLast.zona);
    if (!zona) return;
    _zpkRender(zona, null, true, 'rezagado');
    try {
      const r = await API.zona.rezagadoDetalle({ zona });
      if (!r || r.ok === false) throw new Error((r && r.error) || 'sin datos');
      _zpkLast = { zona, modo: 'rezagado', data: r };
      _zpkRender(zona, r, false, 'rezagado');
    } catch (e) { _zpkRender(zona, { _error: String(e && e.message || e) }, false, 'rezagado'); }
  }
  function zonaCerrarPickup(){
    const ov = document.getElementById('zonaPickupOverlay');
    if (ov) { ov.classList.remove('zpk-in'); setTimeout(() => { try { ov.remove(); } catch(_){} }, 220); }
  }
  function zonaPickupToggle(sku){
    try {
      const el = document.querySelector('#zonaPickupOverlay .zpk-item[data-sku="' + (window.CSS && CSS.escape ? CSS.escape(String(sku)) : String(sku)) + '"]');
      if (el) el.classList.toggle('zpk-open');
    } catch(_){}
  }
  function zonaPickupFiltrar(q){
    q = String(q || '').toLowerCase().trim();
    document.querySelectorAll('#zonaPickupOverlay .zpk-item').forEach(el => {
      const n = ((el.querySelector('.zpk-name') || {}).textContent || '').toLowerCase();
      el.style.display = (!q || n.indexOf(q) >= 0) ? '' : 'none';
    });
  }
  // [Reparación #8] Nombre del CANÓNICO por skuBase desde el catálogo de MOS (S.productos, factor=1 activo) —
  // robusto ante un `nombre` viejo guardado en el pickup (mostraba "TRIPACK"/"25"). Prefiere el canónico real
  // (sin codigoProductoBase) y, ante varios factor=1 mal marcados, el nombre más largo. Memoizado por tamaño.
  let _zpkCanonMap = null, _zpkCanonLen = -1;
  function _zpkCanonName(sku, fb) {
    const ps = Array.isArray(S.productos) ? S.productos : [];
    if (_zpkCanonMap === null || _zpkCanonLen !== ps.length) {
      _zpkCanonMap = {}; const score = {};
      ps.forEach(p => {
        const activo = !(p.estado === false || String(p.estado) === '0');
        const esBase = (parseFloat(p.factorConversion || 1) === 1) && activo && p.skuBase;
        if (!esBase) return;
        const nm = p.descripcion || p.nombre || ''; if (!nm) return;
        const k = String(p.skuBase).trim().toUpperCase();
        const sc = (p.codigoProductoBase ? 0 : 100000) + nm.length;
        if (score[k] === undefined || sc > score[k]) { score[k] = sc; _zpkCanonMap[k] = nm; }
      });
      _zpkCanonLen = ps.length;
    }
    return _zpkCanonMap[String(sku || '').trim().toUpperCase()] || fb || sku;
  }
  function _zpkRender(zona, r, loading, modo){
    modo = modo || 'pickup';
    const esRez = modo === 'rezagado';
    let ov = document.getElementById('zonaPickupOverlay');
    if (!ov) {
      ov = document.createElement('div');
      ov.id = 'zonaPickupOverlay'; ov.className = 'zpk-overlay';
      ov.onclick = (e) => { if (e.target === ov) zonaCerrarPickup(); };
      document.body.appendChild(ov);
      requestAnimationFrame(() => ov.classList.add('zpk-in'));
    }
    let body;
    if (loading) body = '<div class="zpk-skel"></div><div class="zpk-skel"></div><div class="zpk-skel"></div><div class="zpk-skel"></div>';
    else if (r && r._error) body = '<div class="zpk-empty">No se pudo cargar · ' + _esc(r._error) + '</div>';
    else {
      const items = (r && r.items) || [];
      if (!items.length) body = '<div class="zpk-empty">Sin pendientes en esta zona 🎉</div>';
      else body = items.map(it => {
        const sol = parseFloat(it.solicitado) || 0, desp = parseFloat(it.despachado) || 0, pend = parseFloat(it.pendiente) || 0;
        const pct = sol > 0 ? Math.min(100, Math.round(desp / sol * 100)) : 0;
        const hist = ((it.historial || []).map(h => {
          const esDesp = h.tipo === 'despacho';
          const cant = (h.cant != null ? h.cant : h.pedido);   // compat con shape viejo
          return `<div class="zpk-hrow ${esDesp ? 'is-desp' : 'is-ped'}">
              <span class="zpk-hdate">${_zpkDiaLbl(h.fecha)}</span>
              <span class="zpk-hsrc">${esDesp ? '🏭 despachó a zona' : '🛒 pidió (cierre)'}</span>
              <span class="zpk-hped">${esDesp ? '−' : '+'}${_zpkNum(cant)}</span>
            </div>`;
        }).join('')) || '<div class="zpk-hrow zpk-hempty">sin desglose por día</div>';
        return `<div class="zpk-item" data-sku="${_esc(it.skuBase)}">
            <div class="zpk-headrow" onclick="MOS.zonaPickupToggle('${_esc(it.skuBase)}')">
              <div class="zpk-info">
                <div class="zpk-name">${_esc(_zpkCanonName(it.skuBase, it.nombre))}</div>
                <div class="zpk-bar"><span style="width:${pct}%"></span></div>
              </div>
              <div class="zpk-qty"><b>${_zpkNum(pend)}</b><small>pend</small></div>
              <span class="zpk-chev">▾</span>
            </div>
            <div class="zpk-hist">
              <div class="zpk-htitle">${_zpkNum(sol)} pedido · ${_zpkNum(desp)} despachado · <b>${_zpkNum(pend)} pendiente</b></div>
              ${hist}
            </div>
          </div>`;
      }).join('');
    }
    if (esRez && !loading && !(r && r._error) && r && r.sin_rezagado) {
      body = '<div class="zpk-empty">Sin rezagado de la semana pasada 🎉<br><small>todo se despachó</small></div>';
    }
    const total = (r && r.total_pendiente) || 0, nItems = (r && r.total_items) || 0;
    const showKpis = !loading && !(r && r._error);
    const bucketLbl = (r && r.bucket) ? _zpkDiaLbl(r.bucket) : '';
    // [v2.43.379] header + acciones según modo (pickup en vivo ↔ rezagado semana pasada)
    const titulo = esRez ? `📦 ${_esc(zona)}` : `🛒 ${_esc(zona)}`;
    const subt = esRez
      ? `<span class="zpk-rez-dot"></span> Rezagado semana pasada${bucketLbl ? ' · ' + bucketLbl : ''}`
      : `<span class="zpk-live"></span> Pickup acumulado · en vivo`;
    const accion = esRez
      ? `<button class="zpk-act zpk-act-print" onclick="MOS.zonaImprimirRezagado()">🖨 Imprimir</button>
         <button class="zpk-act" onclick="MOS.zonaAbrirPickup()">↩ Esta semana</button>`
      : `<button class="zpk-act zpk-act-rez" onclick="MOS.zonaAbrirRezagado('${_esc(zona)}')">📦 Rezagado semana pasada</button>`;
    ov.innerHTML = `<div class="zpk-card${esRez ? ' zpk-rez-mode' : ''}" onclick="event.stopPropagation()">
        <div class="zpk-top">
          <div><div class="zpk-zona">${titulo}</div><div class="zpk-subt">${subt}</div></div>
          <button class="zpk-x" onclick="MOS.zonaCerrarPickup()" aria-label="Cerrar">✕</button>
        </div>
        ${showKpis ? `<div class="zpk-kpis"><div><b>${nItems}</b><small>productos</small></div><div><b>${_zpkNum(total)}</b><small>uds ${esRez ? 'no despachadas' : 'pendientes'}</small></div></div>` : ''}
        ${showKpis ? `<div class="zpk-actions">${accion}</div>` : ''}
        ${showKpis && !(r && r.sin_rezagado) ? `<input class="zpk-search" placeholder="🔎 Buscar producto…" oninput="MOS.zonaPickupFiltrar(this.value)" autocomplete="off">` : ''}
        <div class="zpk-list">${body}</div>
      </div>`;
  }
  // [v2.43.379] Imprime el rezagado (80mm, todo el ancho) por la Edge `imprimir` (cero-GAS).
  async function zonaImprimirRezagado(){
    const d = _zpkLast && _zpkLast.data;
    if (!d || !(d.items || []).length) { toast('Nada que imprimir', 'warn'); return; }
    let printerId = null;
    try { printerId = await _liqElegirImpresora(); } catch(_) {}
    if (!printerId) return;
    try {
      const escpos = _buildRezagadoTicket80mm(_zpkLast.zona, d);
      await API.imprimirTicketEdge(parseInt(printerId, 10), 'Rezagado ' + _zpkLast.zona, escpos);
      try { _liqConfetti(window.innerWidth/2, window.innerHeight/3, '#fbbf24'); } catch(_){}
      toast('🖨 Rezagado enviado a la impresora', 'ok', 3000);
    } catch (e) {
      toast('⚠ No se pudo imprimir: ' + ((e && e.message) || e), 'error', 6000);
    }
  }
  // Ticket 80mm PROFESIONAL: usa todo el ancho (W=48). Formato "20.5x  Nombre del producto",
  // y si el nombre es largo, continúa en 1-2 renglones indentados. Español con acentos (WPC1252).
  function _buildRezagadoTicket80mm(zona, d){
    const W = 48;
    const rep = (ch, n) => ch.repeat(Math.max(0, n));
    const norm = (s) => String(s == null ? '' : s).normalize('NFC').replace(/[^\x20-\xFF]/g, '');
    const ctr = (s) => { s = norm(s); const l = Math.floor((W - s.length) / 2); return rep(' ', Math.max(0, l)) + s + '\n'; };
    const SEP = rep('=', W) + '\n', SEPd = rep('-', W) + '\n';
    const qty = (n) => { n = parseFloat(n) || 0; return (Number.isInteger(n) ? ('' + n) : ('' + (Math.round(n * 100) / 100))) + 'x'; };
    // wrap del nombre a partir de la 2da línea, indentado bajo el nombre (col del qty + 2)
    const wrapNombre = (qtyStr, nombre) => {
      const ind = rep(' ', qtyStr.length + 2);
      const max1 = W - (qtyStr.length + 2);          // ancho disponible en la 1ra línea
      const palabras = norm(nombre).split(/\s+/).filter(Boolean);
      let linea = '', out = '', primera = true;
      const flush = () => { out += (primera ? (qtyStr + '  ') : ind) + linea + '\n'; primera = false; linea = ''; };
      for (const w of palabras) {
        const cap = primera ? max1 : (W - ind.length);
        if (linea && (linea.length + 1 + w.length) > cap) flush();
        linea = linea ? (linea + ' ' + w) : w;
        while (linea.length > (primera ? max1 : (W - ind.length))) { // palabra larguísima
          const cap2 = primera ? max1 : (W - ind.length);
          out += (primera ? (qtyStr + '  ') : ind) + linea.slice(0, cap2) + '\n'; primera = false; linea = linea.slice(cap2);
        }
      }
      if (linea) flush();
      return out;
    };
    const items = (d.items || []);
    let t = '\x1b\x40\x1b\x74\x10';                  // init + codepage WPC1252
    t += '\x1b\x61\x01\x1b\x21\x30' + norm('LISTA DE COMPRA') + '\n\x1b\x21\x00';
    t += norm('Rezagado · ' + zona) + '\n';
    if (d.bucket) t += norm('Semana del ' + d.bucket) + '\n';
    t += '\x1b\x61\x00' + SEP;
    t += norm('Lo que NO se despachó la semana pasada:') + '\n' + SEPd;
    items.forEach(it => {
      const nom = _zpkCanonName(it.skuBase, it.nombre);
      t += wrapNombre(qty(it.pendiente), nom);
    });
    t += SEPd;
    t += '\x1b\x45\x01' + norm('TOTAL: ' + (items.length) + ' productos · ' + qty(d.total_pendiente) + ' uds') + '\x1b\x45\x00\n';
    t += '\x1b\x61\x01' + norm('Impreso desde MOS') + '\n';
    t += '\n\n\n\n\x1d\x56\x00';
    return t;
  }
  // [RIZ #2] Imprime el ticket desde el ÍCONO del grupo ROTADO. Respeta el filtro "del día":
  //   · modo 'dia'   → imprime el ticket del día activo (fecha = día seleccionado).
  //   · modo 'todos' → imprime HOY (default), no el universo entero.
  function zonaImprimirTicketGrupo() {
    const enDia = S._zonaDiaFiltro && S._zonaDiaFiltro.modo === 'dia';
    const fecha = enDia ? _zonaFechaStr(_zonaDiaActiva()) : _zonaFechaHoy();
    const label = enDia ? ('Ticket ' + _zonaDiaLabel().replace(/ · .*/, '')) : 'Ticket de hoy';
    return _zonaImprimirFlow('ticket_diario', label, fecha);
  }

  // ══ [RIZ · CAPA 5] PANEL DE SUGERENCIAS CON IA REAL (Edge /functions/ia) ══
  // Arma un PROMPT con los NÚMEROS DETERMINÍSTICOS de cada producto (la IA NO inventa cantidades:
  // solo redacta en lenguaje natural). Si la IA falla, deja el texto local determinista de fallback.
  // Estructura el prompt para que devuelva JSON {urgente:[],ajustar:[],cero:[]} de strings cortos.
  function _zonaPromptSugerencias() {
    // Tomamos hasta 30 productos relevantes (brecha>0 o rotación cero) para no inflar tokens.
    const arr = S.zonaProductos.filter(p => {
      const t = String(p.tendencia || '').toLowerCase();
      return _zonaNum(p.brecha) > 0 || t === 'nula' || t === 'cero';
    }).slice(0, 30);
    const datos = arr.map(p => {
      const sku = String(p.skuBase || p.idProducto || '');
      const stock = _zonaNum(p.stockZona != null ? p.stockZona : p.stock);
      const esp = _zonaNum(p.esperada != null ? p.esperada : p.esperado);
      const brecha = (p.brecha != null) ? _zonaNum(p.brecha) : Math.max(0, esp - Math.max(0, stock));
      const alm = _zonaNum(p.stockAlmacen != null ? p.stockAlmacen : p.almacen);
      return {
        producto: String(p.descripcion || p.nombre || sku),
        stockZona: stock, esperada: esp, brecha,
        stockAlmacen: alm,
        pedirAlmacen: Math.min(brecha, Math.max(0, alm)),
        externo: Math.max(0, brecha - Math.max(0, alm)),
        tendencia: String(p.tendencia || 'est'),
        bcg: _zonaBCGClase(p)
      };
    });
    return { arr, datos };
  }
  async function zonaAbrirSugerencias() {
    const body = $('zonaSugBody');
    const ztit = $('zonaSugZona');
    if (ztit) { const zo = S.zonaList.find(x => (x.idZona || x.id || x.nombre) === S.zonaActual); ztit.textContent = (zo && zo.nombre) || S.zonaActual || 'Zona'; }
    openModal('modalZonaSug');
    _zonaSfx('pop'); _zonaVibrar(20);
    // [MEJORA 6] Estado "pensando" claro (la IA del Edge tarda 2-4s, es normal).
    if (body) body.innerHTML = `<div class="zona-thinking">
        <span class="zona-think-ico">💡</span>
        <span class="zona-think-txt">Pensando</span>
        <span class="zona-think-dots"><i></i><i></i><i></i></span>
      </div>
      <div class="text-center text-xs text-slate-600 mb-3">La IA analiza tu zona (puede tardar unos segundos)…</div>
      <div class="skel h-16 rounded-lg mb-2"></div><div class="skel h-16 rounded-lg"></div>`;
    const { datos } = _zonaPromptSugerencias();
    // Fallback local determinista (si IA falla o no hay productos).
    const renderLocal = () => {
      if (!body) return;
      if (!datos.length) { body.innerHTML = '<div class="text-center py-8 text-emerald-400 text-sm">✓ Todo al día. Sin sugerencias.</div>'; return; }
      const urg = datos.filter(d => d.brecha > 0).map(d => `• ${_esc(d.producto)}: faltan ${d.brecha}${d.pedirAlmacen > 0 ? ` — pide ${d.pedirAlmacen} a almacén` : ''}${d.externo > 0 ? `, ${d.externo} a lista del lunes` : ''}.`);
      const cero = datos.filter(d => d.bcg === 'perro').map(d => `• ${_esc(d.producto)}: sin rotación — promociona / góndola / remate.`);
      body.innerHTML =
        (urg.length ? `<div class="zona-sug-grp"><div class="zona-sug-h">🔴 URGENTE (${urg.length})</div>${urg.join('<br>')}</div>` : '') +
        (cero.length ? `<div class="zona-sug-grp"><div class="zona-sug-h">⚫ ROTACIÓN CERO (${cero.length})</div>${cero.join('<br>')}</div>` : '');
    };
    if (!datos.length) { renderLocal(); return; }
    // IA real: la IA SOLO redacta; los números van crudos en el prompt.
    const system = 'Eres un asistente de reposición de tienda. Recibes datos NUMÉRICOS exactos por producto (stock en zona, stock objetivo "esperada", brecha, stock de almacén, cuánto pedir a almacén, cuánto comprar externo, tendencia, clasificación BCG). NUNCA inventes ni cambies cantidades: usa EXACTAMENTE los números dados. Redacta en español neutral (tuteo), conciso y accionable. Responde SOLO un JSON válido con la forma {"urgente":["..."],"ajustar":["..."],"cero":["..."]} donde cada string es una línea corta para el admin. urgente=productos con brecha>0; ajustar=tendencia decreciente que conviene reducir; cero=rotación nula (BCG perro). No agregues texto fuera del JSON.';
    const userMsg = 'Datos de la zona (JSON):\n' + JSON.stringify(datos) + '\n\nGenera las sugerencias.';
    try {
      const d = await API.zona.ia({
        system,
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 2048,
        messages: [{ role: 'user', content: userMsg }]
      });
      const txt = (d && d.content && d.content[0] && d.content[0].text) || '';
      let parsed = null;
      try { parsed = JSON.parse(txt.replace(/^```json\s*/i, '').replace(/```\s*$/,'').trim()); } catch (_) { parsed = null; }
      if (!parsed || typeof parsed !== 'object') throw new Error('respuesta IA no parseable');
      if (!body) return;
      const grp = (titulo, cls, arr2) => (Array.isArray(arr2) && arr2.length)
        ? `<div class="zona-sug-grp"><div class="zona-sug-h">${titulo}</div>${arr2.map(s => '• ' + _esc(String(s))).join('<br>')}</div>` : '';
      const html = grp('🔴 URGENTE', '', parsed.urgente) + grp('🟡 AJUSTAR', '', parsed.ajustar) + grp('⚫ ROTACIÓN CERO', '', parsed.cero);
      body.innerHTML = html || '<div class="text-center py-8 text-emerald-400 text-sm">✓ Sin sugerencias.</div>';
      _zonaSfx('pop');
    } catch (e) {
      try { console.warn('[RIZ] IA sugerencias falló, uso fallback local:', e && (e.message || e)); } catch (_) {}
      renderLocal();
    }
  }
  function zonaCerrarSugerencias() { closeModal('modalZonaSug'); }

  // ── Historial de lotes (FIFO) ────────────────────────────────────────────
  async function zonaVerLotes(sku) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    const tit = $('zonaLotesTitulo');
    if (tit) tit.textContent = (p && (p.descripcion || p.nombre)) || sku;
    const body = $('zonaLotesBody');
    if (body) body.innerHTML = '<div class="skel h-16 rounded-lg mb-2"></div><div class="skel h-16 rounded-lg"></div>';
    openModal('modalZonaLotes');
    _zonaSfx('pop'); _zonaVibrar(20);
    try {
      const r = await API.zona.lotesHistorial({ zona: S.zonaActual, skuBase: sku });
      const data = (r && r.data) || r || [];
      // Backend me.zona_lotes_historial devuelve data.items (NO data.lotes). Cada lote trae diasRestantes (NO diasVencimiento).
      const lotes = Array.isArray(data.items) ? data.items : (Array.isArray(data.lotes) ? data.lotes : (Array.isArray(data) ? data : []));
      if (!body) return;
      if (!lotes.length) { body.innerHTML = '<div class="text-center py-8 text-slate-500 text-sm">Sin lotes registrados</div>'; return; }
      let total = 0;
      body.innerHTML = lotes.map((l, i) => {
        const rest = _zonaNum(l.cantRestante != null ? l.cantRestante : l.restan);
        total += rest;
        const venc = _zonaVencBadge(l.diasRestantes != null ? l.diasRestantes : l.diasVencimiento);
        const ing = _esc(l.fechaIngreso || l.ingreso || '—');
        const ve  = _esc(l.fechaVencimiento || l.vence || '—');
        return `<div class="zona-card ${i === 0 ? 'bcg-estrella' : ''}" style="animation-delay:${i*60}ms;margin-bottom:.5rem">
          <div class="flex items-center justify-between">
            <div class="font-semibold text-slate-100 text-sm">Lote ${_esc(l.idLote || l.lote || (i+1))}${i === 0 ? ' <span class="text-xs text-amber-300">(se vende primero)</span>' : ''}</div>
            ${venc ? `<span class="zona-venc-dot ${venc.dot}"></span>` : ''}
          </div>
          <div class="text-xs text-slate-400 mt-1">ingresó ${ing} · vence ${ve} · restan ${rest}un</div>
        </div>`;
      }).join('') + `<div class="text-xs text-slate-400 mt-2 pt-2" style="border-top:1px solid #1e293b">Total en zona: ${total}un</div>`;
    } catch (e) {
      if (body) body.innerHTML = `<div class="text-center py-8 text-red-400 text-sm">${_esc(e.message || String(e))}</div>`;
    }
  }
  function zonaCerrarLotes() { closeModal('modalZonaLotes'); }

  // ══ [ASEGURAR DATA] Log de errores de stock (SOLO master) — read-only ════════════════════════════════
  //   Lee mos.stock_diferencias_listar (real vs teórico), agrupa por ámbito, ordena por |dif| desc.
  //   Cada fila → abre el historial del producto (zona usa zona_kardex; almacén usa almacen_kardex).
  async function zonaAbrirLogErrores() {
    const body = $('zonaLogBody');
    const chips = $('zonaLogChips');
    const tabs = $('zonaLogTabs');
    if (chips) chips.innerHTML = '';
    if (tabs) tabs.innerHTML = '';
    if (body) body.innerHTML = '<div class="skel h-16 rounded-lg mb-2"></div><div class="skel h-16 rounded-lg"></div>';
    openModal('modalZonaLog');
    _zonaSfx('pop'); _zonaVibrar([30,20,30]);
    // Pestaña activa recordada (localStorage). Default SIS (lo primero que el master quiere ver). Filtro de chip se resetea.
    let tab0 = null;
    try { tab0 = localStorage.getItem(_ZONA_LOG_TAB_LS); } catch (_) {}
    if (tab0 !== 'SIS' && tab0 !== 'OPE') tab0 = 'SIS';
    _zonaLogState = { items: [], tipo: null, tab: tab0 };   // reset filtro de chip al reabrir; conserva pestaña
    try {
      // [RIZ UX] Solo diferencias ABIERTAS (las REVISADAS/RESUELTAS quedan archivadas y no son ruido).
      //   La RPC mos.stock_diferencias_listar acepta p.estado (supabase/141 §3) → filtramos en origen.
      const r = await API.zona.diferencias({ estado: 'ABIERTA' });
      if (!r || r.ok === false) throw new Error((r && r.error) || 'Sin datos');
      const data = (r && r.data) || r || {};
      const items = Array.isArray(data.items) ? data.items : (Array.isArray(data) ? data : []);
      _zonaLogState.items = items;
      _zonaLogPintarTabs();
      _zonaLogPintarChips();
      _zonaLogRender();
    } catch (e) {
      if (body) body.innerHTML = `<div class="text-center py-8 text-red-400 text-sm">${_esc(e.message || String(e))}</div>`;
    }
  }
  // Items que pertenecen a la pestaña activa (SIS/OPE). Es el universo sobre el que operan chips + render.
  function _zonaLogItemsTab() {
    const items = _zonaLogState.items || [];
    const tab = _zonaLogState.tab || 'SIS';
    return items.filter(it => _zonaLogTabDeItem(it) === tab);
  }
  // [PESTAÑAS] Dos botones (Sistémico/Operativo) con su propio contador. Recuerda la activa en localStorage.
  function _zonaLogPintarTabs() {
    const cont = $('zonaLogTabs');
    if (!cont) return;
    const items = _zonaLogState.items || [];
    const por = { SIS: 0, OPE: 0 };
    items.forEach(it => { por[_zonaLogTabDeItem(it)]++; });
    const orden = ['SIS', 'OPE'];
    cont.innerHTML = orden.map(k => {
      const meta = ZONA_LOG_TABS[k];
      const on = (_zonaLogState.tab || 'SIS') === k;
      return `<button class="zona-log-tab ${meta.cls}${on ? ' on' : ''}" onclick="MOS.zonaLogCambiarTab('${k}')" aria-pressed="${on}">
        <span class="zona-log-tab-lbl">${meta.lbl} <b>${por[k]}</b></span>
        <span class="zona-log-tab-cnt">${k === 'SIS' ? 'fugas vivas + config · master' : 'a contar/auditar · operador'}</span>
      </button>`;
    }).join('');
  }
  function zonaLogCambiarTab(tab) {
    if (tab !== 'SIS' && tab !== 'OPE') return;
    if (_zonaLogState.tab === tab) return;
    _zonaSfx('pop'); _zonaVibrar([20,15,20]);
    _zonaLogState.tab = tab;
    _zonaLogState.tipo = null;                 // al cambiar de pestaña, el filtro de chip se resetea
    try { localStorage.setItem(_ZONA_LOG_TAB_LS, tab); } catch (_) {}
    _zonaLogPintarTabs();
    _zonaLogPintarChips();
    _zonaLogRender();
  }
  // Contador por tipo arriba + chips clickeables (filtro), DENTRO de la pestaña activa.
  function _zonaLogPintarChips() {
    const chips = $('zonaLogChips');
    if (!chips) return;
    const items = _zonaLogItemsTab();                 // chips operan sobre la pestaña activa, no sobre todo
    const cont = {}; items.forEach(it => { const k = _zonaLogTipoKey(it); cont[k] = (cont[k] || 0) + 1; });
    // Chips = tipos REALMENTE presentes en la pestaña activa (el reparto ya no es por tipo fijo). "Todos" siempre.
    //   Orden canónico 1·2·3·4·5·0; solo se pintan los que tengan ≥1 fila (filtro abajo). Así el dueño ve,
    //   p.ej. dentro de Operativo, cuántas cicatrices 🧊/📕 quedan por contar.
    const orden = [1, 2, 3, 4, 5, 0].filter(t => cont[t]);
    let html = `<button class="zona-log-chip chip-all${_zonaLogState.tipo == null ? ' on' : ''}" onclick="MOS.zonaLogFiltrar(null)">Todos <b>${items.length}</b></button>`;
    orden.forEach(t => {
      const n = cont[t] || 0;
      if (!n) return;
      const meta = ZONA_LOG_TIPOS[t];
      const cat = ZONA_LOG_CAT[meta.cat] || {};
      const on = String(_zonaLogState.tipo) === String(t);
      // Chip = grupo (filtro + ⓘ). El glifo ⓘ abre la leyenda de ESE tipo; el resto del chip filtra.
      html += `<span class="zona-log-chipwrap">
        <button class="zona-log-chip ${meta.cls} ${cat.cls || ''}${on ? ' on' : ''}" onclick="MOS.zonaLogFiltrar('${t}')" title="${_esc(meta.nombre)} — ${_esc((cat.lbl || '').replace(/·.*/, '').trim())}">${meta.glifo} ${_esc(meta.nombre)} <b>${n}</b></button>
        <button class="zona-log-info-btn ${cat.cls || ''}" onclick="event.stopPropagation();MOS.zonaLogLeyenda('${t}')" title="¿Qué es este error?" aria-label="¿Qué es ${_esc(meta.nombre)}?">ⓘ</button>
      </span>`;
    });
    chips.innerHTML = html;
  }
  function zonaLogFiltrar(tipo) {
    _zonaSfx('tick'); _zonaVibrar(15);
    // toggle: si ya estaba activo el mismo tipo → vuelve a "todos".
    _zonaLogState.tipo = (tipo == null || String(_zonaLogState.tipo) === String(tipo)) ? null : String(tipo);
    _zonaLogPintarChips();
    _zonaLogRender();
  }
  function _zonaLogRender() {
    const body = $('zonaLogBody');
    if (!body) return;
    const total = (_zonaLogState.items || []).length;
    if (!total) { body.innerHTML = '<div class="text-center py-10 text-emerald-300 text-sm">✓ Sin diferencias de stock detectadas</div>'; return; }
    const all = _zonaLogItemsTab();                  // universo = pestaña activa (Sistémico/Operativo)
    if (!all.length) {
      const esSis = (_zonaLogState.tab || 'SIS') === 'SIS';
      const ope = (_zonaLogState.items || []).filter(it => _zonaLogTabDeItem(it) === 'OPE').length;
      // Empty-state POSITIVO para Sistémico: el caso sano de hoy (0 vivos + 0 config). Empuja a Operativo.
      body.innerHTML = esSis
        ? `<div class="text-center py-10 px-4">
             <div class="text-emerald-300 text-base font-semibold mb-1">✓ Sin bugs vivos — el sistema está sano</div>
             <div class="text-slate-400 text-sm">No hay fugas activas ni config pendiente.${ope ? ` Lo histórico se resuelve <b>contando</b> (pestaña <b>📋 Operativo</b>, ${ope}).` : ' Tampoco queda nada por contar.'}</div>
           </div>`
        : `<div class="text-center py-10 text-emerald-300 text-sm">✓ Sin pendientes operativos (a contar) hoy</div>`;
      return;
    }
    const items = (_zonaLogState.tipo == null) ? all : all.filter(it => String(_zonaLogTipoKey(it)) === String(_zonaLogState.tipo));
    if (!items.length) { body.innerHTML = '<div class="text-center py-10 text-slate-500 text-sm">Sin diferencias de este tipo</div>'; return; }
    // Agrupar por ámbito; dentro de cada grupo el backend ya ordena por |dif| desc.
    const grupos = { ALMACEN: [], ZONA: [] };
    items.forEach(it => { (grupos[String(it.ambito || '').toUpperCase()] || (grupos.ZONA)).push(it); });
    let idx = 0;
    const seccion = (amb, titulo) => {
      const arr = grupos[amb] || [];
      if (!arr.length) return '';
      let s = `<div class="zona-log-group-title">${_esc(titulo)} · ${arr.length}</div>`;
      s += arr.map(it => {
        const tk = _zonaLogTipoKey(it);
        const meta = ZONA_LOG_TIPOS[tk];
        const aviso = (tk === 3 || tk === 5);            // filas-aviso: real/teorico/dif = 0 → no mostrar números de stock
        const dif = _zonaNum(it.diferencia);
        const ambCls = amb === 'ALMACEN' ? 'almacen' : 'zona';
        const ambLbl = amb === 'ALMACEN' ? 'ALMACÉN' : (it.zonaId || 'ZONA');
        const sign = dif > 0 ? '+' : '';
        const cb = _zonaEsc(String(it.codBarra || ''));
        const delay = (idx++) * 30;
        const badge = `<span class="zona-log-tipo ${meta.cls}" title="${_esc(meta.nombre)}">${meta.glifo} ${_esc(meta.nombre)}</span>`;
        // [TRIPWIRE] VIVO: descuadre sistémico (1/2/3) con causa RECIENTE (≤3 días) = una vía de
        //   escritura volvió a fugar → el master debe investigar HOY. Histórico = residuo viejo.
        const esVivoSis = (it.esVivo === true) && (tk === 1 || tk === 2 || tk === 3);
        const vivoBadge = esVivoSis
          ? `<span class="zona-log-vivo" title="Causa reciente (≤3 días): regresión VIVA — investigar hoy">🚨 VIVO</span>`
          : '';
        const nums = aviso ? '' : `<div class="zona-log-nums">real <b>${_esc(String(it.real))}</b> · teórico <b>${_esc(String(it.teorico))}</b></div>`;
        const difCol = aviso ? '<div class="zona-log-dif aviso">⚠</div>' : `<div class="zona-log-dif ${dif >= 0 ? 'pos' : 'neg'}">${sign}${_esc(String(dif))}</div>`;
        return `<div class="zona-log-row" style="animation-delay:${delay}ms" onclick="MOS.zonaLogVerHistorial('${amb}','${cb}')">
          <span class="zona-log-amb ${ambCls}">${_esc(ambLbl)}</span>
          <div class="zona-log-info">
            <div class="zona-log-name">${_esc(it.descripcion || it.codBarra)} ${badge}${vivoBadge}</div>
            ${nums}
            <div class="zona-log-hip">${_esc(it.motivoHipotesis || '')}</div>
          </div>
          ${difCol}
        </div>`;
      }).join('');
      return s;
    };
    body.innerHTML = (seccion('ALMACEN', '📦 Almacén') + seccion('ZONA', '🏪 Zona')) || '<div class="text-center py-10 text-slate-500 text-sm">Sin diferencias</div>';
  }
  function zonaCerrarLogErrores() { closeModal('modalZonaLog'); }
  // ── [LEYENDA] Catálogo de TIPOS de error: definición + causa + categoría + quién lo arregla ──
  //   Abre el modal-leyenda con TODOS los tipos. Si se pasa un tipo, se resalta y se hace scroll a él.
  //   Solo visualización (read-only): no toca cálculos ni escrituras.
  function zonaLogLeyenda(tipo) {
    _zonaSfx('pop'); _zonaVibrar([20,15,20]);
    const body = $('zonaLogLeyendaBody');
    if (body) {
      const orden = [1, 2, 3, 4, 5, 0];
      const focus = (tipo != null && tipo !== '') ? String(tipo) : null;
      body.innerHTML = orden.map(t => {
        const meta = ZONA_LOG_TIPOS[t];
        if (!meta) return '';
        const cat = ZONA_LOG_CAT[meta.cat] || {};
        const sel = (focus != null && String(t) === focus) ? ' is-focus' : '';
        return `<div id="zonaLeyTipo-${t}" class="zona-ley-card ${meta.cls} ${cat.cls || ''}${sel}">
          <div class="zona-ley-head">
            <span class="zona-ley-glifo">${meta.glifo}</span>
            <span class="zona-ley-nombre">${_esc(t === 0 ? 'Otro / sin clasificar' : ('TIPO ' + t + ' · ' + meta.nombre))}</span>
            <span class="zona-ley-cat ${cat.cls || ''}">${_esc(cat.lbl || '')}</span>
          </div>
          <div class="zona-ley-def">${_esc(meta.def || '')}</div>
          <div class="zona-ley-quien">👤 ${_esc(cat.quien || '')}</div>
        </div>`;
      }).join('');
      // [TRIPWIRE] Nota del badge VIVO (solo aplica a sistémicos 1/2/3).
      body.innerHTML += `<div class="zona-ley-card cat-sis" style="border-style:dashed;">
        <div class="zona-ley-head">
          <span class="zona-ley-glifo">🚨</span>
          <span class="zona-ley-nombre">Badge <b>VIVO</b></span>
          <span class="zona-ley-cat cat-sis">RECIENTE · investigar hoy</span>
        </div>
        <div class="zona-ley-def">Aparece en los sistémicos (tipos 1, 2 y 3) cuando su causa ocurrió hace ≤3 días: una vía de escritura volvió a fugar HOY. Sin el badge = histórico (residuo viejo ya sellado, se arregla auditando).</div>
        <div class="zona-ley-quien">👤 VIVO = el master investiga el código el mismo día.</div>
      </div>`;
    }
    openModal('modalZonaLogLeyenda');
    // Scroll suave al tipo enfocado (si vino desde un chip concreto).
    if (tipo != null && tipo !== '') {
      const el = $('zonaLeyTipo-' + tipo);
      if (el && el.scrollIntoView) { try { el.scrollIntoView({ block: 'nearest', behavior: 'smooth' }); } catch (_) { el.scrollIntoView(); } }
    }
  }
  function zonaCerrarLogLeyenda() { closeModal('modalZonaLogLeyenda'); }
  // Desde una fila del log → historial del producto (por código). ZONA usa la zona actual; ALMACEN va al kardex WH.
  function zonaLogVerHistorial(ambito, codBarra) {
    _zonaSfx('tick'); _zonaVibrar(15);
    if (String(ambito).toUpperCase() === 'ALMACEN') _zonaVerKardexCore('ALMACEN', { codBarra });
    else _zonaVerKardexCore('ZONA', { codBarra, zona: S.zonaActual });
  }

  // ══ [ASEGURAR DATA] Historial de movimientos (kardex) — read-only ════════════════════════════════════
  //   zonaVerKardex(sku)        → mos.zona_kardex_historial({zona, skuBase})
  //   zonaVerKardexAlmacen(sku) → mos.almacen_kardex_historial({skuBase})
  //   Ambos pintan el MISMO modal (modalZonaKardex), estilo WH: icono por tipo, color, saldo a la derecha.
  function zonaVerKardex(sku) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    const nm = (p && (p.descripcion || p.nombre)) || sku;
    _zonaVerKardexCore('ZONA', { skuBase: sku, zona: S.zonaActual, _nombre: nm });
  }
  function zonaVerKardexAlmacen(sku) {
    const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
    const nm = (p && (p.descripcion || p.nombre)) || sku;
    _zonaVerKardexCore('ALMACEN', { skuBase: sku, _nombre: nm });
  }
  // [RIZ #3] Estado del modal kardex: data raíz (=Total) + pestañas por código (data.porCodigo). El front pinta
  //   una pestaña por código del grupo + "Total" (el combinado de raíz, que cuadra con el stock del grupo).
  //   Producto de 1 solo código → porCodigo viene null → SIN pestañas (vista directa, como antes).
  const _zonaKardexEstado = { esAlm: false, data: null, tabs: [], activa: 'TOTAL' };
  async function _zonaVerKardexCore(ambito, params) {
    const esAlm = String(ambito).toUpperCase() === 'ALMACEN';
    const tit = $('zonaKardexTitulo'); if (tit) tit.textContent = params._nombre || params.skuBase || params.codBarra || 'Producto';
    const ico = $('zonaKardexIco');    if (ico) ico.textContent = esAlm ? '📦' : '🏪';
    const sub = $('zonaKardexSub');    if (sub) sub.textContent = esAlm ? 'Kardex de almacén (movimientos reales)' : ('Kardex de zona ' + (params.zona || ''));
    const tabsEl = $('zonaKardexTabs'); if (tabsEl) tabsEl.innerHTML = '';
    const body = $('zonaKardexBody');
    if (body) body.innerHTML = '<div class="skel h-12 rounded-lg mb-2"></div><div class="skel h-12 rounded-lg mb-2"></div><div class="skel h-12 rounded-lg"></div>';
    openModal('modalZonaKardex');
    _zonaSfx('pop'); _zonaVibrar(20);
    try {
      const q = {};
      if (params.codBarra != null) q.codBarra = String(params.codBarra);
      if (params.skuBase != null && params.codBarra == null) q.skuBase = String(params.skuBase);
      if (!esAlm) q.zona = params.zona;
      const r = esAlm ? await API.zona.almacenKardex(q) : await API.zona.kardexHistorial(q);
      if (!r || r.ok === false) throw new Error((r && r.error) || 'Sin historial');
      const data = (r && r.data) || r || {};
      _zonaKardexEstado.esAlm = esAlm;
      _zonaKardexEstado.data = data;
      // [RIZ #3] Construir pestañas: "Total" + una por código (porCodigo), canónico primero, equivalentes después.
      _zonaKardexEstado.tabs = _zonaKardexConstruirTabs(data);
      _zonaKardexEstado.activa = 'TOTAL';
      if (!body) return;
      _zonaKardexRenderTabs();
      _zonaKardexRenderTab('TOTAL', true);
    } catch (e) {
      if (body) body.innerHTML = `<div class="text-center py-8 text-red-400 text-sm">${_esc(e.message || String(e))}</div>`;
    }
  }
  // [RIZ #3] Lista de pestañas a partir de la respuesta. Total siempre; por código sólo si porCodigo trae >1.
  function _zonaKardexConstruirTabs(data) {
    const tabs = [{ id: 'TOTAL', etiqueta: 'Total', esTotal: true, data: data }];
    const pc = data && data.porCodigo;
    if (pc && typeof pc === 'object') {
      const ents = Object.keys(pc).map(k => ({ k, e: pc[k] }));
      // canónico (esEquivalente=false) primero, luego equivalentes; estable por código.
      ents.sort((a, b) => (a.e.esEquivalente === b.e.esEquivalente) ? String(a.k).localeCompare(String(b.k)) : (a.e.esEquivalente ? 1 : -1));
      ents.forEach(({ k, e }) => {
        tabs.push({ id: k, etiqueta: e.esEquivalente ? '≈ ' + k : k, esEquivalente: !!e.esEquivalente, esTotal: false, data: e });
      });
    }
    return tabs;
  }
  function _zonaKardexRenderTabs() {
    const tabsEl = $('zonaKardexTabs');
    if (!tabsEl) return;
    const tabs = _zonaKardexEstado.tabs || [];
    // 1 sola pestaña (Total) = producto de 1 código → no se muestra barra de pestañas (vista directa).
    if (tabs.length <= 1) { tabsEl.innerHTML = ''; tabsEl.style.display = 'none'; return; }
    tabsEl.style.display = '';
    tabsEl.innerHTML = tabs.map(t => {
      const act = (t.id === _zonaKardexEstado.activa) ? ' is-active' : '';
      const eqCls = t.esEquivalente ? ' is-equiv' : (t.esTotal ? ' is-total' : '');
      const d = t.data || {};
      // El punto rojo del tab marca descuadre: ZONA usa d.cuadra; ALMACÉN usa d.cuadraStock (SQL 196).
      const cuadra = !(d.cuadra === false || d.cuadraStock === false);
      const dot = t.esTotal ? '' : `<span class="zona-kardex-tab-dot${cuadra ? '' : ' nocuadra'}"></span>`;
      return `<button class="zona-kardex-tab${act}${eqCls}" onclick="MOS.zonaKardexTab('${_esc(String(t.id))}')">${dot}${_esc(t.etiqueta)}</button>`;
    }).join('');
  }
  // [RIZ #3] Cambiar de pestaña (sin re-fetch: porCodigo ya trae movimientos completos por código).
  function zonaKardexTab(id) {
    if (!_zonaKardexEstado.tabs || _zonaKardexEstado.activa === id) return;
    _zonaSfx('tick'); _zonaVibrar(12);
    _zonaKardexEstado.activa = id;
    _zonaKardexRenderTabs();
    _zonaKardexRenderTab(id, false);
  }
  // Pinta el encabezado (stock chip) + las filas de la pestaña activa.
  function _zonaKardexRenderTab(id, primera) {
    const body = $('zonaKardexBody');
    if (!body) return;
    const esAlm = _zonaKardexEstado.esAlm;
    const tab = (_zonaKardexEstado.tabs || []).find(t => t.id === id) || (_zonaKardexEstado.tabs || [])[0];
    const d = (tab && tab.data) || {};
    const movs = Array.isArray(d.movimientos) ? d.movimientos : [];
    _zonaKardexPintarStock(esAlm, d, movs, tab);
    if (!movs.length) { body.innerHTML = '<div class="text-center py-8 text-slate-500 text-sm">Sin movimientos registrados</div>'; return; }
    body.innerHTML = movs.map((m, i) => _zonaKardexRowHtml(m, i, esAlm)).join('');
    if (!primera) body.scrollTop = 0;
  }
  // [RIZ KARDEX] Encabezado con STOCK ACTUAL (chip) — permite verificar visualmente que el saldo corrido cuadra.
  //   `d` es la unidad mostrada (Total = raíz; pestaña = porCodigo[cod]). El cuadre es por unidad.
  function _zonaKardexPintarStock(esAlm, d, movs, tab) {
    const sub = $('zonaKardexSub');
    if (!sub) return;
    // [RIZ #1/#3] STOCK ACTUAL autoritativo:
    //   · ALMACÉN → d.stockReal = wh.stock.cantidad_disponible (SQL 196) — la MISMA verdad que muestra la app WH
    //     (getHistorialStock usa wh.stock en vivo). NO usamos el saldo del último movimiento: puede divergir de
    //     wh.stock (stock fijado sin movimiento; grupos multi-código donde el "Total" tomaba el saldo de un solo
    //     código). Si no hay fila en wh.stock (stockReal null) caemos al saldo del último mov como referencia.
    //   · ZONA → stockZonas (reconstruido) como antes.
    let stock = null;
    if (!esAlm && d && d.stockZonas != null) stock = _zonaNum(d.stockZonas);
    else if (esAlm && d && d.stockReal != null) stock = _zonaNum(d.stockReal);
    else if (Array.isArray(movs) && movs.length && movs[0] && movs[0].saldo != null) stock = _zonaNum(movs[0].saldo); // movs[0] = más reciente (DESC)
    let base = esAlm ? 'Kardex de almacén (movimientos reales)' : ('Kardex de zona ' + ((_zonaKardexEstado.data && _zonaKardexEstado.data.zona) || S.zonaActual || ''));
    // Etiqueta de la unidad mostrada (Total vs código concreto) cuando hay pestañas.
    if (tab && !tab.esTotal && tab.id) base += ' · código ' + (tab.esEquivalente ? '(equivalente) ' : '') + tab.id;
    else if (tab && tab.esTotal && (_zonaKardexEstado.tabs || []).length > 1) base += ' · todos los códigos';
    if (stock == null) { sub.innerHTML = _esc(base); return; }
    const neg = stock < 0;
    // [RIZ #1/#3] cuadra = ¿el saldo del último movimiento coincide con el stock real?
    //   · ALMACÉN → d.cuadraStock (SQL 196): false marca que la reconstrucción NO empata con wh.stock (auditar).
    //     null (sin movimientos, o sin fila en wh.stock) → no afirmamos cuadre (no mostramos el sello).
    //   · ZONA → d.cuadra como antes.
    let cuadra = true, mostrarCuadra = true;
    if (esAlm) {
      if (d && d.cuadraStock === false) cuadra = false;
      else if (!d || d.cuadraStock == null) mostrarCuadra = false;   // sin base para afirmar/negar el cuadre
    } else {
      cuadra = !(d && d.cuadra === false);
    }
    const stockTxt = _esc(String(_zonaFmtNumRaw(stock, false)));
    const chipCls = 'zona-kardex-stockchip' + (neg ? ' neg' : '') + (cuadra ? '' : ' nocuadra');
    const cuadraTxt = !mostrarCuadra ? '' : (cuadra ? '✓ cuadra' : '⚠ revisar');
    const cuadraHtml = cuadraTxt ? ` <span class="zona-kardex-stockok">${cuadraTxt}</span>` : '';
    sub.innerHTML = `${_esc(base)} · <span class="${chipCls}">📦 stock actual: <b>${stockTxt}</b>${cuadraHtml}</span>`;
  }
  function _zonaKardexRowHtml(m, i, esAlm) {
    const esIng = !!m.esIngreso;
    const op    = String(m.tipoOperacion || '').toUpperCase();
    const fuente = String(m.fuente || '').toLowerCase();
    // [RIZ UX · REGLA DE COLORES] verde=ingreso/INC, rojo=salida/DEC, NARANJA=venta del día AÚN NO reconciliada
    //   con la guía de cierre (estado='ABIERTA' o pendiente=true → el día no se ha cerrado todavía).
    //   El glifo distingue el tipo (🔍 auditoría, ✎ ajuste, ⏳ venta pendiente, ▲/▼ entrada/salida); el COLOR
    //   sigue el signo del delta salvo el naranja de los pendientes (ver mos.zona_kardex_historial).
    const abierta = String(m.estado || '').toUpperCase() === 'ABIERTA' || m.pendiente === true;
    const sgnCls  = esIng ? 'ing' : 'sal';                 // color por signo (verde/rojo)
    const colorCls = abierta ? 'pend' : sgnCls;            // naranja si la venta no está reconciliada
    let icoTxt = esIng ? '▲' : '▼';
    if (op.indexOf('AUDITORIA') >= 0) { icoTxt = '🔍'; }
    else if (fuente === 'ajuste' || op.indexOf('AJUSTE') >= 0) { icoTxt = '✎'; }
    if (abierta) icoTxt = '⏳';                            // venta pendiente de reconciliar (día abierto)
    const delta = _zonaNum(m.cantidad);
    const saldo = (m.saldo == null ? null : _zonaNum(m.saldo));
    const saldoNeg = (esAlm && saldo != null && saldo < 0);   // almacén en rojo si negativo
    const fecha = _esc(_zonaKardexFecha(m.fecha));
    const usr   = _esc(m.usuario || '—');
    const guia  = m.idGuia ? (' · ' + _esc(String(m.idGuia))) : '';
    // [RIZ #3] Las filas "no aplicadas" son el TICKET CRUDO de un día YA reconciliado por su guía de cierre
    //   (la guía es la que suma al saldo). Etiqueta clara para que el admin no crea que se descuadra ni
    //   que se cuenta dos veces — es el mismo movimiento mostrado para auditoría, NO resta del saldo.
    const aplic = (m.aplicado === false)
      ? ' <span class="zona-kardex-info" title="Ticket ya reconciliado por la guía de cierre del día — no resta del saldo (se muestra solo para auditoría).">ⓘ ya contado en la guía</span>'
      : '';
    const pendTag = abierta ? ' <span class="zona-kardex-pend-tag">⏳ sin reconciliar</span>' : '';
    // [KARDEX ENRIQUECIDO] LOTE en INGRESOS (atable) + DESTINO (zona·quién) en SALIDAS.
    //   · idLote viene de mos.almacen_kardex_historial (lote creado por el ingreso, FIFO). Si null → sin chip.
    //   · zona/destino sólo en salidas (wh.guias.id_zona). En el kardex de ZONA la zona es la propia → no se repite.
    const loteChip = (esIng && m.idLote)
      ? `<span class="zona-kardex-lote">🏷 ${_esc(String(m.idLote))}${m.loteVencimiento ? ` · vence ${_esc(_zonaKardexFechaCorta(m.loteVencimiento))}` : ''}</span>`
      : '';
    const zonaDest = (!esIng && esAlm && m.zona)
      ? `<div class="zona-kardex-destino">→ <b>${_esc(String(m.zona))}</b>${(m.usuario && m.usuario !== '—') ? ` · por ${_esc(m.usuario)}` : ''}</div>`
      : '';
    // [RIZ #5] Estilo WH: timeline con rail + nodo (glifo por tipo), monto grande arriba-derecha, fecha+hora,
    //   chip de tipo, "por <usuario>", y el saldo como pill discreto a la derecha. Jerarquía visual clara.
    return `<div class="zona-kardex-row is-${colorCls}" style="animation-delay:${i*30}ms">
      <span class="zona-kardex-node ${colorCls}">${icoTxt}</span>
      <div class="zona-kardex-mid">
        <div class="zona-kardex-head">
          <span class="zona-kardex-tipo ${colorCls}">${_esc(m.tipo || (esIng ? 'INGRESO' : 'SALIDA'))}</span>
          <span class="zona-kardex-delta ${colorCls}">${esIng ? '+' : '−'}${_esc(String(delta))}</span>
        </div>
        <div class="zona-kardex-meta">${fecha}${(usr && usr !== '—') ? ' · por ' + usr : ''}${guia}${aplic}${pendTag}</div>
        ${zonaDest}
        ${loteChip ? `<div class="zona-kardex-lotewrap">${loteChip}</div>` : ''}
        ${saldo != null ? `<div class="zona-kardex-saldo${saldoNeg ? ' neg' : ''}">Saldo <b>${_esc(String(saldo))}</b></div>` : ''}
      </div>
    </div>`;
  }
  // Fecha + hora en TZ Perú (el dueño pidió ver la hora). timeZone explícita → no depende de la config del equipo.
  function _zonaKardexFecha(f) {
    if (!f) return '—';
    try { const d = new Date(f); if (!isNaN(d)) return d.toLocaleDateString('es-PE', { day:'2-digit', month:'2-digit', year:'2-digit', timeZone:'America/Lima' }) + ' ' + d.toLocaleTimeString('es-PE', { hour:'2-digit', minute:'2-digit', hour12:false, timeZone:'America/Lima' }); } catch (_) {}
    return String(f).slice(0, 16).replace('T', ' ');
  }
  // Fecha corta (sólo día) para el vencimiento del lote.
  function _zonaKardexFechaCorta(f) {
    if (!f) return '—';
    try { const d = new Date(f); if (!isNaN(d)) return d.toLocaleDateString('es-PE', { day:'2-digit', month:'2-digit', year:'2-digit', timeZone:'America/Lima' }); } catch (_) {}
    return String(f).slice(0, 10);
  }
  function zonaCerrarKardex() { closeModal('modalZonaKardex'); }

  // ── Matriz BCG (modal 2×2 con burbujas) ──────────────────────────────────
  function zonaAbrirBCG() {
    const z = $('zonaBCGZona');
    if (z) { const zo = S.zonaList.find(x => (x.idZona || x.id || x.nombre) === S.zonaActual); z.textContent = (zo && zo.nombre) || S.zonaActual || 'Zona'; }
    const buckets = { estrella: [], vaca: [], interro: [], perro: [] };
    const maxVol = Math.max(1, ...S.zonaProductos.map(p => _zonaNum(p.rotacion)));
    S.zonaProductos.forEach(p => {
      const cls = _zonaBCGClase(p);
      if (buckets[cls]) buckets[cls].push(p);
    });
    const pintar = (id, cls, list) => {
      const el = $(id);
      if (!el) return;
      if (!list.length) { el.innerHTML = '<span class="text-xs text-slate-600">—</span>'; return; }
      el.innerHTML = list.map((p, i) => {
        const sku = String(p.skuBase || p.idProducto || '');
        const vol = _zonaNum(p.rotacion);
        const size = Math.max(22, Math.round(22 + (vol / maxVol) * 24));   // 22..46px
        const nm = (p.descripcion || p.nombre || sku);
        return `<span class="zona-bubble bub-${cls}" style="min-width:${size}px;height:${size}px;animation-delay:${i*70}ms" title="${_esc(nm)} · rot ${vol}" onclick="MOS.zonaBCGTapProducto('${_zonaEsc(sku)}')">${_esc(String(nm).slice(0,8))}</span>`;
      }).join('');
    };
    pintar('bcgEstrella','estrella', buckets.estrella);
    pintar('bcgVaca',    'vaca',     buckets.vaca);
    pintar('bcgInterro', 'interro',  buckets.interro);
    pintar('bcgPerro',   'perro',    buckets.perro);
    openModal('modalZonaBCG');
    _zonaSfx('pop'); _zonaVibrar(20);
  }
  function zonaCerrarBCG() { closeModal('modalZonaBCG'); }
  // [RIZ · CAPA 5] Acción BCG-perro REAL (Promocionar / Mover a góndola / Rematar). Es una DECISIÓN del admin
  // sobre stock muerto: NO toca inventario ni caja (el diseño RIZ informa, no muta). Persiste en
  // me.zona_accion_perro (auditable, idempotente por localId). Optimista: resalta el botón al instante +
  // sonido/vibración; si el backend falla, revierte el resalte + toast rojo. La decisión vuelve en el panel
  // (p.accionPerro) en el próximo refresh.
  const _ZONA_ACCION_LBL = { PROMOCIONAR:'Promocionar', GONDOLA:'Mover a góndola', REMATAR:'Rematar' };
  async function zonaAccionPerro(sku, accion) {
    accion = String(accion || '').toUpperCase();
    const lbl = _ZONA_ACCION_LBL[accion] || accion;
    if (!_ZONA_ACCION_LBL[accion]) { toast('Acción no válida', 'error'); return; }
    const card = $('zcard-' + sku);
    // Capturar la decisión PREVIA del modelo (para rollback exacto si el backend falla).
    let prevAccion = null;
    try { const pp = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku); prevAccion = (pp && pp.accionPerro) ? String(pp.accionPerro).toUpperCase() : null; } catch (_) {}
    // OPTIMISTA: resaltar el botón elegido (y apagar los hermanos) dentro de la card.
    let prevOn = null;
    try {
      if (card) {
        const btns = card.querySelectorAll('.zona-actions .zona-btn-sec');
        btns.forEach(b => { if (b.classList.contains('zona-accion-on')) prevOn = b; b.classList.remove('zona-accion-on'); });
        const map = { PROMOCIONAR:0, GONDOLA:1, REMATAR:2 };
        const idx = map[accion];
        if (btns[idx]) btns[idx].classList.add('zona-accion-on');
        card.classList.remove('pulse-ok'); void card.offsetWidth; card.classList.add('pulse-ok');
      }
    } catch (_) {}
    _zonaSfx('ok'); _zonaVibrar([60,40,60]);
    toast(lbl + ' marcado', 'ok');
    // Reflejar en el modelo local para que un re-render intermedio no lo pierda.
    try { const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku); if (p) p.accionPerro = accion; } catch (_) {}
    // BACKGROUND: persistir. localId estable por (zona,sku,accion) → reintento del mismo gesto dedupea.
    try {
      const localId = 'ACC-' + (S.zonaActual || '') + '-' + sku + '-' + accion;
      const r = await API.zona.marcarAccion({ zona: S.zonaActual, skuBase: sku, accion, localId });
      if (!r || r.ok === false) throw new Error((r && r.error) || 'sin respuesta');
    } catch (e) {
      // ROLLBACK: revertir resalte + restaurar el previo.
      try {
        if (card) {
          card.querySelectorAll('.zona-actions .zona-btn-sec').forEach(b => b.classList.remove('zona-accion-on'));
          if (prevOn) prevOn.classList.add('zona-accion-on');
          card.classList.remove('pulse-ok'); void card.offsetWidth; card.classList.add('shake');
          setTimeout(() => { try { card.classList.remove('shake'); } catch (_) {} }, 500);
        }
        const p = S.zonaProductos.find(x => String(x.skuBase || x.idProducto) === sku);
        if (p) p.accionPerro = prevAccion;
      } catch (_) {}
      _zonaSfx('error'); _zonaVibrar([120,40,120]);
      toast('No se pudo marcar ' + lbl + ', reintenta', 'error');
    }
  }
  // Compat: por si quedó algún onclick viejo a zonaPlaceholder (ya no se genera) → no-op informativo.
  function zonaPlaceholder(nombre) { _zonaSfx('pop'); toast(String(nombre || 'Acción'), 'info'); }
  function zonaBCGTapProducto(sku) {
    _zonaSfx('tick');
    zonaCerrarBCG();
    const card = $('zcard-' + sku);
    if (card) { card.scrollIntoView({ behavior:'smooth', block:'center' }); card.classList.remove('pulse-ok'); void card.offsetWidth; card.classList.add('pulse-ok'); }
  }
  // Tap en un cuadrante → filtra el módulo a esa tendencia aproximada.
  function zonaBCGFiltrarCuadrante(cuad) {
    const f = S._zonaFiltros;
    f.tend = {};
    if (cuad === 'estrella' || cuad === 'interro') f.tend.asc = true;
    else if (cuad === 'perro') f.tend.nula = true;
    else if (cuad === 'vaca')  f.tend.est = true;
    document.querySelectorAll('.zona-chip-f[data-tend]').forEach(el => el.classList.toggle('active', !!f.tend[el.dataset.tend]));
    zonaCerrarBCG();
    renderZona();
    _zonaSfx('tick');
  }

  // ══════════════════════════════════════════════════════════════════════
  // [RIZ · TRASLADO VERIFICADO] GUÍAS — FRONTEND (solo MOSTRAR · escaneo de recepción vive en ME)
  // El almacén emite guías de ENTRADA hacia la zona. MOS NO escanea: solo MUESTRA las guías guía-por-guía,
  // agrupadas por DÍA, con filtros (todas/pendientes/verificadas/con diferencia/operario). Cada card abre un
  // DETALLE con las DISCREPANCIAS primero (enviado vs escaneado, lo que falta/sobra) y luego el resto.
  // El admin puede marcar "✓ Verificado" (resuelve la guía como revisada/COMPLETA · idempotente backend).
  // Fuente: mos.zona_traslados_pendientes (guías sin verificar) + mos.zona_traslados_resumen (verificadas).
  // ══════════════════════════════════════════════════════════════════════

  // Carga pendientes + resumen y actualiza SOLO el badge del botón "🚚 Guías" (la lista ya no vive en la vista).
  async function _trasCargarBadge() {
    try {
      const r = await API.zona.trasladosPendientes({ zona: S.zonaActual });
      const data = (r && r.data) || r || {};
      const items = Array.isArray(data.items) ? data.items : [];
      S._trasPend = items;
      _trasPintarBadge();
    } catch (e) {
      try { console.warn('[RIZ] trasladosPendientes:', e && (e.message || e)); } catch (_) {}
    }
  }
  // Badge rojo con el conteo de guías pendientes (oculto si no hay).
  function _trasPintarBadge() {
    const badge = $('zonaGuiasBadge');
    if (!badge) return;
    const n = Array.isArray(S._trasPend) ? S._trasPend.length : 0;
    if (n > 0) { badge.textContent = n > 99 ? '99+' : String(n); badge.style.display = ''; }
    else { badge.style.display = 'none'; }
  }
  // Carga el resumen (verificadas) y refresca el badge desde ambas fuentes.
  async function _trasCargarResumen() {
    try {
      const r = await API.zona.trasladosResumen({ zona: S.zonaActual });
      S._trasResumen = (r && r.data) || r || {};
    } catch (e) {
      try { console.warn('[RIZ] trasladosResumen:', e && (e.message || e)); } catch (_) {}
    }
  }
  // Etiqueta legible de antigüedad (espeja me._edad_lbl del backend).
  function _trasEdadLbl(seg) {
    seg = _zonaNum(seg);
    if (seg < 60)    return 'recién';
    if (seg < 3600)  return 'hace ' + Math.floor(seg/60) + ' min';
    if (seg < 86400) return 'hace ' + Math.floor(seg/3600) + ' h';
    return 'hace ' + Math.floor(seg/86400) + ' d';
  }

  // ── [Reparación #3] Normalización: 3 universos en una lista uniforme, con `origen`. ─────────────────────
  //   • WAREHOUSE pendiente  = despacho de almacén (wh.guias SALIDA_ZONA) aún sin recibir → estado PENDIENTE.
  //   • WAREHOUSE verificada = fila 'WH:' en zona_traslado_verificacion (recibida en ME) → COMPLETO/INCOMPLETO + DIFF.
  //   • INTERNAL = guía interna de la zona (me.guias_cabecera, ids G-…) → INFORMATIVA, sin estado/diff.
  // La regla de pendiente/sobró/faltó SOLO aplica a origen='WAREHOUSE' (lo que entra despachado de almacén).
  function _trasGuiasUnificadas() {
    const out = [];
    // 1) Despachos de almacén pendientes de recibir (diff-eligible, aún sin escanear en ME).
    const pend = Array.isArray(S._trasPend) ? S._trasPend : [];
    pend.forEach(it => out.push({
      idGuia: String(it.idGuia || ''),
      origen: 'WAREHOUSE',
      tipoGuia: String(it.tipoGuia || 'SALIDA_ZONA'),
      estado: 'PENDIENTE',
      fecha: it.fecha || null,
      lineas: _zonaNum(it.lineas),
      totalEnviado: _zonaNum(it.totalEnviado),
      totalEscaneado: 0,
      totalDif: 0,
      operario: String(it.vendedor || '—'),
      edadLbl: String(it.edadLbl || ''),
      detalle: Array.isArray(it.detalle) ? it.detalle : null,
      verificada: false
    }));
    // 2) Verificadas de ALMACÉN = solo filas 'WH:' (las internas/BASELINE NO van acá, se listan informativas abajo).
    const verifs = (S._trasResumen && Array.isArray(S._trasResumen.verificaciones)) ? S._trasResumen.verificaciones : [];
    verifs.filter(v => String(v.idGuia || '').indexOf('WH:') === 0).forEach(v => out.push({
      idGuia: String(v.idGuia || ''),
      origen: 'WAREHOUSE',
      tipoGuia: String(v.tipoGuia || 'SALIDA_ZONA'),
      estado: String(v.estado || 'COMPLETO'),
      fecha: v.fechaGuia || v.verificadoTs || null,
      lineas: _zonaNum(v.lineasOk) + _zonaNum(v.lineasDif),
      totalEnviado: _zonaNum(v.totalEnviado),
      totalEscaneado: _zonaNum(v.totalEscaneado),
      totalDif: _zonaNum(v.totalDif),
      operario: String(v.usuario || '—'),
      edadLbl: String(v.edadLbl || ''),
      detalle: Array.isArray(v.detalle) ? v.detalle : null,
      verificada: true
    }));
    // 3) Guías internas de la zona (informativas, sin estado/diff).
    const internas = Array.isArray(S._trasInternas) ? S._trasInternas : [];
    internas.forEach(it => out.push({
      idGuia: String(it.idGuia || ''),
      origen: 'INTERNAL',
      tipoGuia: String(it.tipoGuia || ''),
      estado: 'INFO',
      fecha: it.fecha || null,
      lineas: _zonaNum(it.lineas),
      totalEnviado: _zonaNum(it.totalEnviado),
      totalEscaneado: 0,
      totalDif: 0,
      operario: String(it.vendedor || '—'),
      edadLbl: String(it.edadLbl || ''),
      detalle: Array.isArray(it.detalle) ? it.detalle : null,
      verificada: false
    }));
    return out;
  }
  // [Reparación #3] Etiqueta amigable por tipo+origen (en vez del id crudo, que confunde).
  function _trasGuiaLabel(g) {
    const t = String((g && g.tipoGuia) || '').toUpperCase();
    const id = String((g && g.idGuia) || '').replace(/^WH:/, '');
    if (g && g.origen === 'WAREHOUSE') {
      return /^GPCK/i.test(id) ? '📥 Despacho de almacén (pickup)' : '📥 Despacho de almacén';
    }
    const map = {
      'ENTRADA_ALMACEN':      '📥 Ingreso de almacén (manual)',
      'ENTRADA_TRASLADO':     '↪ Traslado recibido',
      'ENTRADA_LIBRE':        '✚ Ingreso manual',
      'SALIDA_VENTAS':        '🛒 Salida por ventas',
      'SALIDA_VENTA':         '🛒 Salida por ventas',
      'SALIDA_MOVIMIENTO':    '↦ Traslado enviado',
      'SALIDA_JEFA':          '🔑 Salida autorizada',
      'SALIDA_DEVOLUCION_WH': '↩ Devolución a almacén'
    };
    return map[t] || ('📦 ' + ((g && g.tipoGuia) || 'Guía interna'));
  }
  // [Reparación #3] Carga las guías internas de la zona (informativas).
  async function _trasCargarInternas() {
    try {
      const r = await API.zona.guiasInternas({ zona: S.zonaActual });
      const data = (r && r.data) || r || {};
      S._trasInternas = Array.isArray(data.items) ? data.items : [];
    } catch (e) {
      try { console.warn('[RIZ] guiasInternas:', e && (e.message || e)); } catch (_) {}
    }
  }
  // Clave de día (YYYY-MM-DD en TZ local) y etiqueta legible para el encabezado de grupo.
  function _trasDiaKey(fecha) {
    const d = fecha ? new Date(fecha) : null;
    if (!d || isNaN(d.getTime())) return '0000-00-00';
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  }
  function _trasDiaLbl(key, fecha) {
    if (key === '0000-00-00') return 'Sin fecha';
    const hoy = _trasDiaKey(new Date());
    const ayer = _trasDiaKey(new Date(Date.now() - 86400000));
    if (key === hoy)  return 'Hoy';
    if (key === ayer) return 'Ayer';
    const d = new Date(fecha);
    try { return d.toLocaleDateString('es-PE', { weekday:'short', day:'2-digit', month:'short' }); }
    catch (_) { return key; }
  }

  // ── Modal "🚚 Guías" ────────────────────────────────────────────────────────────────────────────────────
  function trasAbrirGuias() {
    _zonaSfx('pop'); _zonaVibrar(20);
    S._guiasFiltro = S._guiasFiltro || 'todas';
    S._guiasOperario = '';
    S._guiaSel = null;
    const tit = $('zonaGuiasZona');
    if (tit) { const zo = S.zonaList.find(x => (x.idZona || x.id || x.nombre) === S.zonaActual); tit.textContent = (zo && zo.nombre) || S.zonaActual || 'Zona'; }
    openModal('modalZonaGuias');
    _trasMostrarLista();
    // refrescar datos al abrir (por si cambió algo desde el último panel).
    Promise.all([_trasCargarBadge(), _trasCargarResumen(), _trasCargarInternas()]).then(() => { _trasPintarBadge(); _trasRenderGuias(); _trasPoblarOperarios(); });
  }
  function trasCerrarGuias() { closeModal('modalZonaGuias'); S._guiaSel = null; }
  function trasRefrescarGuias() { _zonaSfx('tick'); _zonaVibrar(15); trasAbrirGuias(); }

  // Muestra la vista lista (oculta la de detalle) + repinta.
  function _trasMostrarLista() {
    S._guiaSel = null;
    const lst = $('zonaGuiasLista'), det = $('zonaGuiasDetalle'), fil = $('zonaGuiasFiltros');
    if (lst) lst.style.display = '';
    if (det) det.style.display = 'none';
    if (fil) fil.style.display = '';
    _trasRenderGuias();
  }

  // Filtros (estado + operario).
  function trasGuiasFiltrar(f) {
    S._guiasFiltro = f;
    document.querySelectorAll('#zonaGuiasFiltros .zona-guias-chip').forEach(el => el.classList.toggle('active', el.dataset.gf === f));
    _zonaSfx('tick'); _zonaVibrar(12);
    _trasRenderGuias();
  }
  function trasGuiasSetOperario(v) { S._guiasOperario = String(v || ''); _trasRenderGuias(); }
  function _trasPoblarOperarios() {
    const sel = $('zonaGuiasOperario');
    if (!sel) return;
    const ops = Array.from(new Set(_trasGuiasUnificadas().map(g => g.operario).filter(x => x && x !== '—'))).sort();
    const prev = S._guiasOperario || '';
    sel.innerHTML = '<option value="">Operario: todos</option>' + ops.map(o => `<option value="${_esc(o)}">${_esc(o)}</option>`).join('');
    sel.value = prev;
  }

  // Render de la lista: aplica filtros, agrupa por día, pinta cards.
  function _trasRenderGuias() {
    const host = $('zonaGuiasLista');
    if (!host) return;
    const f = S._guiasFiltro || 'todas';
    const op = S._guiasOperario || '';
    let arr = _trasGuiasUnificadas();
    if (f === 'pendientes')  arr = arr.filter(g => g.estado === 'PENDIENTE');
    if (f === 'verificadas') arr = arr.filter(g => g.verificada);
    if (f === 'incompletas') arr = arr.filter(g => g.estado === 'INCOMPLETO');
    if (op) arr = arr.filter(g => g.operario === op);
    if (!arr.length) {
      host.innerHTML = `<div class="text-center py-12 text-slate-500 text-sm"><div class="text-3xl mb-2">📭</div>Sin guías en este filtro</div>`;
      return;
    }
    // agrupar por día (fecha de la guía), días más recientes arriba.
    const grupos = {};
    arr.forEach(g => { const k = _trasDiaKey(g.fecha); (grupos[k] = grupos[k] || []).push(g); });
    const keys = Object.keys(grupos).sort((a, b) => b.localeCompare(a));
    host.innerHTML = keys.map(k => {
      const lbl = _trasDiaLbl(k, grupos[k][0].fecha);
      const cards = grupos[k].map(_trasGuiaCardHtml).join('');
      return `<div class="zona-guias-daygrp">
        <div class="zona-guias-dayhdr"><span class="zona-guias-daylbl">${_esc(lbl)}</span><span class="zona-guias-dayline"></span><span class="zona-guias-daycount">${grupos[k].length} guía(s)</span></div>
        ${cards}
      </div>`;
    }).join('');
  }
  // Card de una guía. [Rep#3] título = etiqueta amigable (no el id). estados/diff SOLO para almacén.
  function _trasGuiaCardHtml(g) {
    const idJs = _zonaEsc(g.idGuia);
    const label = _trasGuiaLabel(g);
    let cls, lbl;
    if (g.origen === 'INTERNAL')         { cls = 'base'; lbl = 'ℹ informativa'; }
    else if (g.estado === 'PENDIENTE')   { cls = 'pend'; lbl = '⏳ pendiente de recibir'; }
    else if (g.estado === 'INCOMPLETO')  { cls = 'warn'; lbl = '⚠ con diferencia'; }
    else if (g.estado === 'BASELINE')    { cls = 'base'; lbl = '• base'; }
    else                                 { cls = 'ok';   lbl = '✓ verificada'; }
    // dif sobró/faltó SOLO en despachos de almacén YA verificados (recibidos en ME).
    const difTxt = (g.origen === 'WAREHOUSE' && g.verificada && _zonaNum(g.totalDif) !== 0) ? ` · dif ${_zonaNum(g.totalDif)}` : '';
    const cant = g.origen === 'WAREHOUSE' ? 'enviado' : 'cant';
    return `<div class="zona-guia-card ${cls}" onclick="MOS.trasVerGuia('${idJs}')">
      <div class="zona-guia-card-top">
        <span class="zona-guia-id">${_esc(label)}</span>
        <span class="zona-guia-estado ${cls}">${lbl}</span>
      </div>
      <div class="zona-guia-sub">${_zonaNum(g.lineas)} producto(s) · ${cant} ${_zonaNum(g.totalEnviado)}${difTxt}</div>
      <div class="zona-guia-meta">👤 ${_esc(g.operario)} · ${_esc(g.edadLbl || '')}</div>
    </div>`;
  }

  // ── Detalle de una guía: discrepancias primero, luego el resto ──────────────────────────────────────────
  async function trasVerGuia(idGuia) {
    idGuia = String(idGuia || '');
    _zonaSfx('tick'); _zonaVibrar(15);
    const lst = $('zonaGuiasLista'), det = $('zonaGuiasDetalle'), fil = $('zonaGuiasFiltros');
    if (lst) lst.style.display = 'none';
    if (fil) fil.style.display = 'none';
    if (det) { det.style.display = ''; det.innerHTML = `<button class="zona-guia-back" onclick="MOS.trasGuiasVolver()">‹ Volver a la lista</button><div class="skel h-24 rounded-lg mb-2"></div><div class="skel h-16 rounded-lg"></div>`; }
    const guia = _trasGuiasUnificadas().find(g => g.idGuia === idGuia);
    S._guiaSel = guia || { idGuia, estado: 'PENDIENTE', verificada: false };
    // Si la guía tiene detalle (verificada con escaneo) lo usamos; si no, pedimos las líneas enviadas a la RPC.
    let detalle = guia && Array.isArray(guia.detalle) ? guia.detalle : null;
    if (!detalle) {
      try {
        const r = await API.zona.trasladoGuia({ idGuia });
        const data = (r && r.data) || r || {};
        const lineas = Array.isArray(data.lineas) ? data.lineas : [];
        // sin escaneo (MOS no escanea): mostramos lo ENVIADO; escaneado/dif = 0, estado OK informativo.
        detalle = lineas.map(l => ({ codBarra: l.codBarra, descripcion: l.descripcion, enviado: _zonaNum(l.enviado), escaneado: 0, dif: _zonaNum(l.enviado), estado: 'PENDIENTE', lote: l.lote || null, venc: l.venc || null }));
      } catch (e) { detalle = []; }
    }
    // [fix nombres verificación] rellenar descripciones vacías (códigos que la RPC no resolvió) desde
    // Supabase (mos.nombres_por_codigos: catálogo + equivalencias) → la pantalla deja de mostrar el código pelado.
    await _trasResolverNombres(detalle);
    _trasRenderDetalle(S._guiaSel, detalle);
  }
  // Resuelve los nombres canónicos de los códigos cuya descripción llegó vacía (o ES el propio código).
  async function _trasResolverNombres(detalle) {
    try {
      if (!Array.isArray(detalle) || !detalle.length) return;
      const faltan = detalle.filter(d => {
        const cod = String(d.codBarra || '');
        const desc = String(d.descripcion || '').trim();
        return cod && (!desc || desc === cod);
      }).map(d => String(d.codBarra));
      if (!faltan.length) return;
      const mapa = await API.zona.nombresPorCodigos([...new Set(faltan)]);
      if (!mapa || typeof mapa !== 'object') return;
      detalle.forEach(d => { const cod = String(d.codBarra || ''); if (mapa[cod]) d.descripcion = mapa[cod]; });
    } catch (_) { /* nunca romper el render por un fallo de nombres */ }
  }
  function trasGuiasVolver() { _zonaSfx('tick'); _zonaVibrar(12); _trasMostrarLista(); }

  // Formato corto y legible del vencimiento (date-only, sin desfase UTC). '' si no hay.
  function _trasVencLbl(v) {
    if (!v) return '';
    const s = String(v).slice(0, 10);                 // 'YYYY-MM-DD' (date-only del backend)
    const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
    if (!m) return '';
    const d = new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));   // local, sin UTC shift
    if (isNaN(d.getTime())) return '';
    try { return d.toLocaleDateString('es-PE', { day: '2-digit', month: 'short', year: '2-digit' }); }
    catch (_) { return s; }
  }

  function _trasRenderDetalle(g, detalle) {
    const host = $('zonaGuiasDetalle');
    if (!host) return;
    g = g || {};
    detalle = Array.isArray(detalle) ? detalle : [];
    // [Reparación #3] La comparación sobró/faltó SOLO aplica a despachos de almacén YA verificados
    // (recibidos por escaneo en ME). Pendientes de almacén e internas = lista informativa (env/cant).
    const esDiff = (g.origen === 'WAREHOUSE' && g.verificada);
    // ── Clasificación en 3 secciones (NO cambia la comparación: solo agrupa por estado/dif) ──────────────────
    //   OK     → enviado == escaneado (dif 0). Verde.
    //   FALTA  → enviado > escaneado (llegó de menos). Rojo.
    //   SOBRA  → escaneado > enviado o no estaba en la guía (llegó de más / inesperado). Ámbar.
    const claseDe = (d) => {
      const dif = _zonaNum(d.dif);
      if (esDiff && String(d.estado) === 'FALTA') return 'falta';
      if (esDiff && String(d.estado) === 'SOBRA') return 'sobra';
      if (esDiff && String(d.estado) === 'OK')    return 'ok';
      // solo almacén-verificado deriva falta/sobra; pendiente/interna = informativo (ok).
      if (esDiff) return dif > 0 ? 'falta' : (dif < 0 ? 'sobra' : 'ok');
      return 'ok';
    };
    const grpFalta = detalle.filter(d => claseDe(d) === 'falta');
    const grpSobra = detalle.filter(d => claseDe(d) === 'sobra');
    const grpOk    = detalle.filter(d => claseDe(d) === 'ok');

    // Fila de un producto: codBarra siempre visible + lote/venc (donde exista) + números env/esc/dif.
    const filaHtml = (d) => {
      const dif = _zonaNum(d.dif);
      const cls = claseDe(d);
      const cod = String(d.codBarra || '');
      const desc = String(d.descripcion || cod || '—');
      // si la descripción ES el código (sin catálogo), no repetir el código abajo.
      const codLinea = (cod && cod !== desc)
        ? `<span class="tras-det-cod">🏷 ${_esc(cod)}</span>` : '';
      const lote = (d.lote != null && String(d.lote).trim() !== '') ? String(d.lote).trim() : '';
      const vencTxt = _trasVencLbl(d.venc);
      const loteVenc = (lote || vencTxt)
        ? `<span class="tras-det-lote">${lote ? '📦 Lote ' + _esc(lote) : ''}${(lote && vencTxt) ? ' · ' : ''}${vencTxt ? '⏱ Vto ' + _esc(vencTxt) : ''}</span>` : '';
      const meta = (codLinea || loteVenc) ? `<div class="tras-det-meta">${codLinea}${loteVenc}</div>` : '';
      const difTxt = !esDiff ? ((g.origen === 'WAREHOUSE' ? 'env ' : 'cant ') + _zonaNum(d.enviado))
        : (dif === 0 ? '✓ ok' : (cls === 'falta' ? 'falta ' + dif : 'sobra ' + Math.abs(dif)));
      const nums = esDiff
        ? `env ${_zonaNum(d.enviado)} · esc ${_zonaNum(d.escaneado)} <b class="tras-det-dif">${difTxt}</b>`
        : `<b class="tras-det-dif">${difTxt}</b>`;
      return `<div class="tras-det-row ${cls}">
        <div class="tras-det-main">
          <span class="tras-det-desc">${_esc(desc)}</span>
          ${meta}
        </div>
        <span class="tras-det-nums">${nums}</span>
      </div>`;
    };

    // cabecera + estado [Rep#3] etiqueta amigable; "verificada" solo aplica a almacén.
    const label = _trasGuiaLabel(g);
    let estCls, estLbl;
    if (g.origen === 'INTERNAL')             { estCls = 'base'; estLbl = 'ℹ Informativa (guía interna)'; }
    else if (g.estado === 'PENDIENTE')       { estCls = 'pend'; estLbl = '⏳ Pendiente de recibir de almacén'; }
    else if (g.estado === 'INCOMPLETO')      { estCls = 'warn'; estLbl = '⚠ Verificada · con diferencia'; }
    else if (g.estado === 'BASELINE')        { estCls = 'base'; estLbl = '• Baseline (arranque)'; }
    else                                     { estCls = 'ok';   estLbl = '✓ Verificada · completa'; }
    const head = `<div class="zona-guia-det-hdr">
      <div class="zona-guia-card-top"><span class="zona-guia-id">${_esc(label)}</span><span class="zona-guia-estado ${estCls}">${estLbl}</span></div>
      <div class="zona-guia-sub">👤 ${_esc(g.operario || '—')} · ${_esc(g.edadLbl || '')}</div>
      <div class="zona-guia-meta" style="font-size:9px;opacity:.6">🔖 ${_esc(g.idGuia)}</div>
      <div class="zona-guia-meta">${esDiff ? 'enviado' : (g.origen === 'WAREHOUSE' ? 'enviado' : 'cant')} ${_zonaNum(g.totalEnviado)}${esDiff ? ' · escaneado ' + _zonaNum(g.totalEscaneado) + ' · dif ' + _zonaNum(g.totalDif) : ''}</div>`
      + (esDiff
        ? `<div class="tras-det-chips">
             <span class="tras-det-chip ok">✓ OK ${grpOk.length}</span>
             <span class="tras-det-chip falta">⚠ Faltan ${grpFalta.length}</span>
             <span class="tras-det-chip sobra">➕ Sobran ${grpSobra.length}</span>
           </div>` : '')
      + `</div>`;

    // ── Cuerpo: 3 secciones (almacén verificado) o lista informativa (pendiente/interna). ────────────────────
    let cuerpo = '';
    const seccion = (cls, ico, titulo, arr) => arr.length
      ? `<div class="zona-guia-discr-lbl ${cls}">${ico} ${titulo} (${arr.length})</div>` + arr.map(filaHtml).join('')
      : '';
    if (esDiff) {
      cuerpo += seccion('alert', '⚠', 'Faltan', grpFalta);
      cuerpo += seccion('sobra', '➕', 'Sobran / no esperados', grpSobra);
      cuerpo += seccion('ok', '✓', 'OK', grpOk);
      if (!grpFalta.length && !grpSobra.length) {
        // todo cuadró: aviso claro arriba de la sección OK.
        cuerpo = `<div class="zona-guia-discr-lbl ok">✓ Sin discrepancias · todo coincide</div>` + cuerpo;
      }
    } else {
      // Pendiente de almacén / guía interna: una sola lista informativa.
      const tituloLista = (g.origen === 'WAREHOUSE') ? 'Productos despachados (' : 'Productos de la guía (';
      cuerpo += `<div class="zona-guia-discr-lbl" style="color:#94a3b8">${tituloLista}${detalle.length})</div>` + detalle.map(filaHtml).join('');
    }
    if (!detalle.length) cuerpo = '<div class="text-center py-6 text-slate-500 text-sm">Sin líneas en esta guía</div>';
    // [Rep#3] Sin botón "marcar verificado": la recepción (con su diff) se hace por ESCANEO en ME.
    // Para despachos de almacén pendientes mostramos una nota; las internas no necesitan acción.
    const accion = (g.origen === 'WAREHOUSE' && g.estado === 'PENDIENTE')
      ? `<div class="text-xs text-slate-500 mt-3 text-center">📲 Este despacho se recibe por <b>escaneo en ME</b>. Al recibirlo aparecerá acá con su comparación (sobró/faltó).</div>`
      : '';
    host.innerHTML = `<button class="zona-guia-back" onclick="MOS.trasGuiasVolver()">‹ Volver a la lista</button>${head}${cuerpo}${accion}`;
  }

  // ── "✓ Verificado": el admin marca la guía pendiente como revisada/COMPLETA (optimista + idempotente). ───
  // MOS no escanea; "verificado" registra la guía aceptándola tal cual (escaneado = enviado → COMPLETO).
  async function trasMarcarVerificado(idGuia) {
    idGuia = String(idGuia || '');
    if (!idGuia) return;
    const btn = $('trasVerifBtn');
    if (btn) { btn.disabled = true; btn.textContent = 'Verificando…'; }
    try {
      // jalar las líneas enviadas para aceptar la guía tal cual (escaneado = enviado).
      const rg = await API.zona.trasladoGuia({ idGuia });
      const dg = (rg && rg.data) || rg || {};
      const lineas = Array.isArray(dg.lineas) ? dg.lineas : [];
      const escaneados = lineas.map(l => ({ codBarra: String(l.codBarra), cantidad: _zonaNum(l.enviado) }))
                               .filter(e => e.codBarra && e.cantidad > 0);
      const r = await API.zona.trasladoCerrar({ idGuia, escaneados });
      if (!r || r.ok === false) throw new Error((r && r.error) || 'No se pudo verificar');
      _zonaSfx('ok'); _zonaVibrar([80,60,80]);
      toast(r.dedup ? 'Esta guía ya estaba verificada' : 'Guía marcada como verificada', 'success');
      // refrescar fuentes y volver a la lista.
      await Promise.all([_trasCargarBadge(), _trasCargarResumen()]);
      _trasPintarBadge();
      _trasMostrarLista();
      _trasPoblarOperarios();
    } catch (e) {
      _zonaSfx('error'); _zonaVibrar([120,40,120]);
      toast('No se pudo verificar: ' + (e && (e.message || e)), 'error');
      if (btn) { btn.disabled = false; btn.textContent = '✓ Marcar verificado'; }
    }
  }

  // ══════════════════════════════════════════════════════════════
  // FACTURACIÓN CPE — 100% Supabase (fac.* vía wrappers mos.fac_*)
  // ══════════════════════════════════════════════════════════════
  function _facRpc(fn, p) { return API._sb.rpc(fn, { p: p || {} }, 'mos'); } // wrappers en schema mos
  function _facAdmin() { try { return _esAdminOMaster(); } catch (_) { return false; } }
  function _facMsg(x) { return Array.isArray(x) ? x.join(' · ') : (x && typeof x === 'object' ? JSON.stringify(x) : (x == null ? '' : String(x))); }
  function _facNewLocalId() { return 'MOSFAC-' + ((typeof crypto!=='undefined' && crypto.randomUUID) ? crypto.randomUUID() : (Date.now()+'-'+Math.random().toString(16).slice(2))); }

  async function _loadFacturacion() {
    if (!S.fac) S.fac = { tipo: 'BOLETA', items: [], cfg: null };
    if (!_facAdmin()) {
      ['facPanelEmitir','facPanelHistorial','facPanelConfig'].forEach(id => { const e=$(id); if(e) e.innerHTML='<div class="text-sm text-amber-400 p-4">Solo administradores pueden facturar.</div>'; });
      const chip=$('facEstadoChip'); if(chip) chip.textContent='solo admin';
      return;
    }
    const hoy = new Date().toISOString().slice(0,10);
    const hd=$('facHistDesde'), hh=$('facHistHasta'); if(hd&&!hd.value) hd.value=hoy; if(hh&&!hh.value) hh.value=hoy;
    if (!S.fac.items.length) S.fac.items=[{desc:'',cant:1,precio:0,tig:1}];
    if (!S.fac.pendingLocalId) S.fac.pendingLocalId = _facNewLocalId();  // estable por comprobante (anti doble-emisión)
    facSetTipo(S.fac.tipo); facRenderItems(); setFacTab('emitir'); _facCargarEstadoChip();
  }

  async function _facCargarEstadoChip() {
    const chip=$('facEstadoChip'); if(!chip) return;
    try {
      const r = await _facRpc('fac_get_config', {}); S.fac.cfg=r;
      const on = r && r.flag_on, real = r && r.activo && r.tiene_nubefact;
      chip.textContent = real ? '🟢 Emite real' : (on ? '🟡 Modo prueba (STUB)' : '⚪ Inactivo');
      chip.className = 'fac-chip ' + (real ? 'bg-emerald-900 text-emerald-300' : on ? 'bg-amber-900 text-amber-300' : 'bg-slate-800 text-slate-400');
    } catch(e){ chip.textContent='⚪ sin conexión'; }
  }

  function setFacTab(tab) {
    if (S.fac) S.fac.tab = tab;
    ['emitir','historial','config'].forEach(t => {
      const b=$('facTab'+t.charAt(0).toUpperCase()+t.slice(1)); if(b) b.classList.toggle('active', t===tab);
      const p=$('facPanel'+t.charAt(0).toUpperCase()+t.slice(1)); if(p) p.classList.toggle('hidden', t!==tab);
    });
    if (tab==='historial') facCargarHistorial();
    if (tab==='config' && _facAdmin()) facRenderConfig();
  }

  function facSetTipo(t) {
    S.fac.tipo = t;
    ['BOLETA','FACTURA'].forEach(x => { const b=$('facTipo'+x); if(b) b.classList.toggle('active', x===t); });
    const dir=$('facCliDir'); if(dir) dir.placeholder = (t==='FACTURA') ? 'Dirección fiscal (requerida)' : 'Dirección (opcional)';
  }
  function facDocInput() { /* visual; el tipo real se deriva por longitud al emitir */ }

  function facAddItem() { _facReadInputs(); S.fac.items.push({desc:'',cant:1,precio:0,tig:1}); facRenderItems(); }
  function facDelItem(i) { _facReadInputs(); S.fac.items.splice(i,1); if(!S.fac.items.length) S.fac.items.push({desc:'',cant:1,precio:0,tig:1}); facRenderItems(); }
  function _facReadInputs() {
    S.fac.items.forEach((it,i) => {
      const d=$('facItDesc'+i), c=$('facItCant'+i), p=$('facItPrec'+i), g=$('facItIgv'+i);
      if(d) it.desc=d.value; if(c) it.cant=parseFloat(c.value)||0; if(p) it.precio=parseFloat(p.value)||0; if(g) it.tig=parseInt(g.value)||1;
    });
  }
  function facItemInput() { _facReadInputs(); facCalcTotal(); }
  function facRenderItems() {
    const cont=$('facItems'); if(!cont) return;
    cont.innerHTML = S.fac.items.map((it,i) => '' +
      '<div class="fac-itemrow">' +
        '<input id="facItDesc'+i+'" class="fac-inp" placeholder="Descripción" value="'+_escapeHtml(it.desc||'')+'" oninput="MOS.facItemInput()">' +
        '<input id="facItCant'+i+'" class="fac-inp text-center" type="number" min="0" step="0.001" value="'+it.cant+'" oninput="MOS.facItemInput()">' +
        '<input id="facItPrec'+i+'" class="fac-inp text-center" type="number" min="0" step="0.01" value="'+it.precio+'" oninput="MOS.facItemInput()">' +
        '<select id="facItIgv'+i+'" class="fac-inp" onchange="MOS.facItemInput()">' +
          '<option value="1"'+(it.tig==1?' selected':'')+'>Gravado</option>' +
          '<option value="9"'+(it.tig==9?' selected':'')+'>Exonerado</option>' +
          '<option value="11"'+(it.tig==11?' selected':'')+'>Inafecto</option>' +
        '</select>' +
        '<button onclick="MOS.facDelItem('+i+')" class="text-slate-500 hover:text-red-400" title="Quitar">✕</button>' +
      '</div>').join('');
    facCalcTotal();
  }
  function facCalcTotal() {
    let total=0, igv=0;
    S.fac.items.forEach(it => {
      const sub = Math.round((it.cant||0)*(it.precio||0)*100)/100; total += sub;
      if (it.tig==1) igv += sub - Math.round(sub/1.18*100)/100;
    });
    total = Math.round(total*100)/100; igv = Math.round(igv*100)/100;
    const t=$('facTotal'); if(t) t.textContent='S/ '+total.toFixed(2);
    const gi=$('facIgvInfo'); if(gi) gi.textContent = igv>0 ? '(IGV S/ '+igv.toFixed(2)+')' : '';
    return total;
  }

  async function facLookup() {
    const doc = (($('facCliDoc')||{}).value||'').replace(/\D/g,'');
    if (doc.length!==8 && doc.length!==11) { toast('DNI (8) o RUC (11) para buscar', 'warn'); return; }
    toast('🔎 Consultando...', 'info');
    try {
      const r = await _facRpc('fac_consultar_documento', { numero: doc });
      if (r && r.ok) { $('facCliNombre').value = r.nombre||''; if (r.direccion) $('facCliDir').value = r.direccion; toast('✓ '+(r.nombre||''), 'success'); }
      else toast('No encontrado'+(r&&r.motivo?(' ('+r.motivo+')'):'')+'. Completá a mano.', 'warn');
    } catch(e){ toast('Lookup falló: '+(e.message||e), 'error'); }
  }

  async function facEmitir() {
    if (!_facAdmin()) { toast('Solo administradores', 'error'); return; }
    _facReadInputs();
    const tipo = S.fac.tipo;
    const doc = (($('facCliDoc')||{}).value||'').replace(/\D/g,'');
    const nombre = (($('facCliNombre')||{}).value||'').trim();
    const dir = (($('facCliDir')||{}).value||'').trim();
    const email = (($('facCliEmail')||{}).value||'').trim();
    const items = S.fac.items.filter(it => (it.desc||'').trim() && it.cant>0 && it.precio>0);
    if (!items.length) { toast('Agregá al menos un ítem (descripción, cantidad y precio)', 'warn'); return; }
    if (tipo==='FACTURA') {
      if (doc.length!==11) { toast('Factura requiere RUC (11 dígitos)', 'warn'); return; }
      if (!dir) { toast('Factura requiere dirección fiscal', 'warn'); return; }
    }
    const tdoc = doc.length===11 ? '6' : (doc.length===8 ? '1' : '0');
    const itemsNF = items.map(it => {
      const sub = Math.round(it.cant*it.precio*100)/100;
      const vu = it.tig==1 ? Math.round(it.precio/1.18*100)/100 : it.precio;
      return { sku:'', nombre: it.desc.trim(), cantidad: it.cant, precio: it.precio, subtotal: sub, valor_unitario: vu, tipo_igv: it.tig, unidad_medida:'NIU' };
    });
    const total = Math.round(itemsNF.reduce((a,b)=>a+b.subtotal,0)*100)/100;
    // local_id ESTABLE por comprobante: un reintento (fallo de red) reusa el mismo → dedup, NO doble emisión.
    if (!S.fac.pendingLocalId) S.fac.pendingLocalId = _facNewLocalId();
    const localId = S.fac.pendingLocalId;
    const payload = { tipo_doc: tipo, cliente:{ tipo:tdoc, doc, nombre: nombre||'CLIENTE ANONIMO', direccion:dir, email }, items: itemsNF, total, local_id: localId, origen:'MANUAL', creado_por: (S.session&&S.session.nombre)||'MOS' };

    const btn=$('facEmitirBtn'); if(btn){ btn.disabled=true; btn.textContent='Emitiendo...'; }
    try {
      const r = await _facRpc('fac_emitir_cpe', payload);
      if (!r || r.status!=='success') {
        const err = _facMsg(r&&(r.error||r.errores)) || 'sin respuesta';
        toast(err==='FAC_DESACTIVADO' ? 'Facturación desactivada (falta prender flag / pegar token)' : ('No se emitió: '+err), err==='FAC_DESACTIVADO'?'warn':'error');
        facRenderResultado({ error: err });   // mismo local_id se conserva para reintento (dedup)
      } else {
        toast('✓ '+r.correlativo+' · '+r.estado+(r.dedup?' (ya existía)':''), 'success', 6000);
        try{_finBeep&&_finBeep('success');}catch(_){}
        facRenderResultado(r);
        S.fac.items=[{desc:'',cant:1,precio:0,tig:1}]; facRenderItems();
        ['facCliDoc','facCliNombre','facCliDir','facCliEmail'].forEach(id=>{const e=$(id); if(e) e.value='';});
        S.fac.pendingLocalId = _facNewLocalId();   // nuevo id para el PRÓXIMO comprobante
      }
    } catch(e){ toast('Error: '+(e.message||e), 'error'); facRenderResultado({ error: String(e.message||e) }); }
    finally { if(btn){ btn.disabled=false; btn.textContent='Emitir comprobante'; } }
  }

  function facRenderResultado(r) {
    const box=$('facResultado'); if(!box) return; box.classList.remove('hidden');
    if (r.error) { box.innerHTML='<div class="fac-card" style="border-color:#7f1d1d"><span class="text-red-400 text-sm">✕ '+_escapeHtml(_facMsg(r.error))+'</span></div>'; return; }
    const real = r.estado==='EMITIDO';
    const pdf = (r.pdf && String(r.pdf).indexOf('http')===0) ? '<a href="'+_escapeHtml(String(r.pdf))+'" target="_blank" rel="noopener" class="fac-btn-sec inline-block mt-2">📄 Ver PDF</a>' : '';
    box.innerHTML = '<div class="fac-card" style="border-color:'+(real?'#065f46':'#92400e')+'">' +
      '<div class="font-black text-lg text-slate-100">'+_escapeHtml(String(r.correlativo||''))+'</div>' +
      '<div class="text-sm '+(real?'text-emerald-400':'text-amber-400')+'">'+(real?'🟢 Emitido a SUNAT':'🟡 '+_escapeHtml(String(r.estado||'')))+' · Total S/ '+Number(r.total||0).toFixed(2)+'</div>' +
      (r.errores?'<div class="text-xs text-red-400 mt-1">'+_escapeHtml(_facMsg(r.errores))+'</div>':'') + pdf + '</div>';
  }

  async function facCargarHistorial() {
    if (!_facAdmin()) return;
    const cont=$('facHistLista'); if(!cont) return; cont.innerHTML='Cargando...';
    try {
      const r = await _facRpc('fac_listar', { desde: ($('facHistDesde')||{}).value, hasta: ($('facHistHasta')||{}).value });
      const list = (r&&r.comprobantes)||[];
      if (!list.length) { cont.innerHTML='<div class="text-slate-500 text-sm">Sin comprobantes en el rango.</div>'; return; }
      cont.innerHTML = list.map(c => {
        const real=c.estado==='EMITIDO', baja=c.estado==='BAJA';
        const pdf = (c.pdf && String(c.pdf).indexOf('http')===0) ? '<a href="'+_escapeHtml(String(c.pdf))+'" target="_blank" rel="noopener" class="fac-btn-sec" style="padding:4px 9px;font-size:11px">PDF</a>' : '';
        const anularBtn = (real && !baja) ? '<button onclick="MOS.facAnular(\''+encodeURIComponent(String(c.id))+'\')" class="fac-btn-sec" style="padding:4px 9px;font-size:11px;background:#7f1d1d">Anular</button>' : '';
        const chipCls = real?'bg-emerald-900 text-emerald-300':baja?'bg-slate-700 text-slate-400':'bg-amber-900 text-amber-300';
        return '<div class="fac-card mb-2 flex items-center justify-between gap-2 flex-wrap">' +
          '<div><div class="font-bold text-slate-100">'+_escapeHtml(String(c.correlativo))+' <span class="fac-chip '+chipCls+'">'+_escapeHtml(String(c.estado))+'</span></div>' +
          '<div class="text-xs text-slate-500">'+_escapeHtml(String(c.cliente_nombre||'—'))+' · S/ '+Number(c.total||0).toFixed(2)+' · '+_escapeHtml(String(c.app||''))+'</div></div>' +
          '<div class="flex gap-1">'+pdf+anularBtn+'</div></div>';
      }).join('');
    } catch(e){ if(cont) cont.innerHTML='<div class="text-red-400 text-sm">Error: '+_escapeHtml(String(e.message||e))+'</div>'; }
  }

  async function facAnular(id) {
    try { id = decodeURIComponent(id); } catch(_){}
    if (!_facAdmin()) { toast('Solo administradores', 'error'); return; }
    const motivo = await _modalPrompt('Motivo de la baja (SUNAT):', '', { titulo:'Anular comprobante', okText:'Anular', placeholder:'Ej: error en datos del cliente' });
    if (motivo===null) return;
    const auth = await pedirAuth({ accion:'FAC_ANULAR', refDocumento:id }); if(!auth) return;
    toast('Anulando...', 'info');
    try {
      const r = await _facRpc('fac_anular', { id, motivo: motivo||'Anulación', clave_admin: auth.clave });
      if (r && r.status==='success') { toast('✓ Comprobante dado de baja', 'success'); facCargarHistorial(); }
      else toast('No se pudo anular: '+((r&&r.error)||'?'), 'error');
    } catch(e){ toast('Error: '+(e.message||e), 'error'); }
  }

  async function facRenderConfig() {
    const box=$('facConfigBody'); if(!box) return; box.innerHTML='Cargando…';
    let cfg;
    try { cfg = await _facRpc('fac_get_config', {}); S.fac.cfg=cfg; } catch(e){ box.innerHTML='<span class="text-red-400">Error: '+_escapeHtml(String(e.message||e))+'</span>'; return; }
    const series=(cfg&&cfg.series)||{};
    const seriesRows = Object.keys(series).map(s => '<div class="flex items-center gap-2 mb-1"><span class="font-mono text-slate-300" style="width:64px">'+s+'</span><span class="text-xs text-slate-500">próximo '+series[s].proximo+'</span>' +
      '<input id="facAlin_'+s+'" class="fac-inp" style="width:90px" type="number" min="0" placeholder="'+series[s].correlativo+'">' +
      '<button onclick="MOS.facAlinear(\''+s+'\')" class="fac-btn-sec" style="padding:4px 9px;font-size:11px">Fijar</button></div>').join('');
    box.innerHTML =
      '<div class="mb-3"><span class="text-xs '+(cfg.tiene_nubefact?'text-emerald-400':'text-amber-400')+'">'+(cfg.tiene_nubefact?'🟢 Token NubeFact cargado':'⚠ Falta token NubeFact')+'</span> · estado: <b>'+(cfg.activo?'emite real':'STUB')+'</b> · flag: <b>'+(cfg.flag_on?'ON':'OFF')+'</b></div>' +
      '<label class="fac-lbl">RUTA NubeFact (URL)</label>' +
      '<input id="facCfgRuta" class="fac-inp w-full mb-2" placeholder="'+(cfg.ruta_set?'•••• (configurada — vacío conserva)':'https://api.nubefact.com/api/v1/...')+'">' +
      '<label class="fac-lbl">TOKEN NubeFact</label>' +
      '<input id="facCfgToken" class="fac-inp w-full mb-2" placeholder="'+(cfg.tiene_nubefact?'•••• (vacío conserva)':'pegá el token')+'">' +
      '<label class="fac-lbl">Header de auth (plantilla · {token} = el token)</label>' +
      '<input id="facCfgAuth" class="fac-inp w-full mb-2" value="'+_escapeHtml(cfg.auth_header||'')+'">' +
      '<div class="grid grid-cols-2 gap-2 mb-2"><div><label class="fac-lbl">URL lookup DNI</label><input id="facCfgLkDni" class="fac-inp w-full" placeholder="API DNI…"></div>' +
      '<div><label class="fac-lbl">URL lookup RUC</label><input id="facCfgLkRuc" class="fac-inp w-full" placeholder="API RUC…"></div></div>' +
      '<label class="fac-lbl">TOKEN lookup</label><input id="facCfgLkTok" class="fac-inp w-full mb-2" placeholder="'+(cfg.tiene_lookup?'•••• (conservar)':'token apis.net.pe…')+'">' +
      '<label class="flex items-center gap-2 mb-3 text-sm text-slate-300"><input id="facCfgActivo" type="checkbox" '+(cfg.activo?'checked':'')+'> Emitir de verdad (desmarcado = STUB demo)</label>' +
      '<button onclick="MOS.facGuardarConfig()" class="fac-btn-pri">Guardar conexión</button>' +
      '<hr class="border-slate-800 my-4"><label class="fac-lbl">Series activas</label>' +
      '<div class="flex gap-2 mb-2"><input id="facSerB" class="fac-inp" style="width:90px" value="'+_escapeHtml(cfg.serie_boleta||'')+'" placeholder="B001">' +
      '<input id="facSerF" class="fac-inp" style="width:90px" value="'+_escapeHtml(cfg.serie_factura||'')+'" placeholder="F001">' +
      '<button onclick="MOS.facGuardarSeries()" class="fac-btn-sec">Guardar series</button></div>' +
      '<label class="fac-lbl" style="margin-top:12px">Numeración (alinear al último nº del sistema viejo)</label>' + (seriesRows||'<span class="text-slate-500 text-xs">sin series</span>');
  }

  async function facGuardarConfig() {
    const auth = await pedirAuth({ accion:'FAC_CONFIG' }); if(!auth) return;
    const p = {
      nubefact_ruta: (($('facCfgRuta')||{}).value||'').trim(),
      nubefact_token: (($('facCfgToken')||{}).value||'').trim(),
      auth_header: (($('facCfgAuth')||{}).value||'').trim(),
      lookup_url_dni: (($('facCfgLkDni')||{}).value||'').trim(),
      lookup_url_ruc: (($('facCfgLkRuc')||{}).value||'').trim(),
      lookup_token: (($('facCfgLkTok')||{}).value||'').trim(),
      activo: !!($('facCfgActivo')||{}).checked,
      clave_admin: auth.clave
    };
    try { const r=await _facRpc('fac_set_config', p); if(r&&r.status==='success'){ toast('✓ Conexión guardada','success'); facRenderConfig(); _facCargarEstadoChip(); } else toast('No se guardó: '+((r&&r.error)||'?'),'error'); }
    catch(e){ toast('Error: '+(e.message||e),'error'); }
  }
  async function facGuardarSeries() {
    const auth = await pedirAuth({ accion:'FAC_SERIES' }); if(!auth) return;
    try { const r=await _facRpc('fac_set_series',{ boleta:(($('facSerB')||{}).value||'').trim().toUpperCase(), factura:(($('facSerF')||{}).value||'').trim().toUpperCase(), clave_admin: auth.clave });
      if(r&&r.status==='success'){ toast('✓ Series guardadas','success'); facRenderConfig(); _facCargarEstadoChip(); } else toast('Inválido: '+((r&&r.error)||'?'),'error'); }
    catch(e){ toast('Error: '+(e.message||e),'error'); }
  }
  async function facAlinear(serie) {
    const inp=$('facAlin_'+serie); const num=parseInt(inp&&inp.value,10); if(isNaN(num)){ toast('Poné un número','warn'); return; }
    if(!await _modalConfirm('¿Fijar '+serie+' en '+num+'? (el próximo será '+(num+1)+')',{warning:true,titulo:'Alinear numeración',okText:'Fijar'})) return;
    const auth = await pedirAuth({ accion:'FAC_ALINEAR' }); if(!auth) return;
    try { const r=await _facRpc('fac_alinear',{ serie, numero:num, clave_admin: auth.clave }); if(r&&r.status==='success'){ toast('✓ '+serie+' → próximo '+r.proximo,'success'); facRenderConfig(); } else toast('No se pudo: '+((r&&r.error)||'?'),'error'); }
    catch(e){ toast('Error: '+(e.message||e),'error'); }
  }

